INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۱لْحَمْدُ لِلهِ رَبِّ ۱لْعَـٰلَمِيـنَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 2, '۰لرَّحْمَـٰنِ ۱لرَّحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 3, 'مَلِكِ يَوْمِ ۱لدِّيـنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 4, 'إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِيـنُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 5, 'èهْدِنَا ۰لصِّرَ؛طَ ۰لْمُسْتَقِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 6, 'صِرَ؛طَ ۰لذِينَ أَنْعَمْتَ عَلَيْهِمْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (1, 7, 'غَيْرۣ ۱لْمَغْضُوبِ عَلَيْهِمْ وَلاَ ۰لضَّآلِّينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓـم؋ّٓؐ ذَ؛لِژَ ۰لْكِتَــٰــبُ لاَ رَيْبَؐ فِيهِ هُديً لِّلْمُتَّقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 2, '۰لذِينَ يُومِنُونَ بِالْغَيْــبِ وَيُقِيمُونَ ۰لصَّلَوٰةَ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 3, 'وَالذِينَ يُومِنُونَ بِمَآ ٱُنزۣلَ إِلَيْژَ وَمَآ ٱُنزۣلَ مِن قَـبْلِژَ وَبِالاَخِرَةِ هُمْ يُوقِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 4, 'ٱُوْلَئِژَ عَلَيٰ هُديً مِّن رَّبِّهِمْؐ وَٱُوْلَئِكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 5, 'إِنَّ ۰لذِينَ كَفَرُواْ سَوَآء٘ عَلَيْهِمُ; ءَآنذَرْتَهُمُ; أَمْ لَمْ تُنذِرْهُمْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 6, 'خَتَمَ ۰للَّهُ عَلَيٰ قُلُوبِهِمْ وَعَلَيٰ سَمْعِهِمْؐ وَعَلَيٰٓ أَبْصۭــٰرۣهِمْ غِشَــٰوَةٌؐ وَلَهُمْ عَذَاب٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 7, 'وَمِنَ ۰لنَّاسِ مَنْ يَّقُولُ ءَامَنَّا بِاللَّهِ وَبِالْيَوْمِ ۱لاَخِرۣ وَمَا هُم بِمُومِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 8, 'يُخَــٰدِعُونَ ۰للَّهَ وَالذِينَ ءَامَنُواْؐ وَمَا يُخَــٰدِعُونَ إِلٓاَّ أَنفُسَهُمْ وَمَا يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 9, 'فِى قُلُوبِهِم مَّرَضٌؐ فَزَادَهُمُ ۴للَّهُ مَرَضاًؐ وَلَهُمْ عَذَاببب٘ اَلِيمُۢ بِمَا كَانُواْ يُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 10, 'وَإِذَا قِيلَ لَهُمْ لاَ تُفْسِدُواْ فِى ۱لاَرْضِ قَالُوٓاْ إِنَّمَا نَحْنُ مُصْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 11, 'أَلٓاَ إِنَّهُمْ هُمُ ۴لْمُفْسِدُونَ وَچَكِن لاَّ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 12, 'وَإِذَا قِيلَ لَهُمُ; ءَامِنُواْ كَمَآ ءَامَنَ ۰لنَّاسُ قَالُوٓاْ أَنُومِنُ كَمَآ ءَامَنَ ۰لسُّفَهَآءُؐ اَ۬لٓاَ إِنَّهُمْ هُمُ ۴لسُّفَهَآءُ وَچَكِن لاَّ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 13, 'وَإِذَا لَقُواْ ۴لذِينَ ءَامَنُواْ قَالُوٓاْ ءَامَنَّاؐ وَإِذَا خَلَوۣاْ اِلَيٰ شَيَـٰطِينِهِمْ قَالُوٓاْ إِنَّا مَعَكُمُ; إِنَّمَا نَحْنُ مُسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 14, '۰للَّهُ يَسْتَهْزۣﻯُٔ بِهِمْ وَيَمُـدُّهُمْ فِى طُـغْـيَــٰنِهِمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 15, 'ﭐُوْلَئِكَ 4 ۰لذِيـنَ "شْتَرَوُاْ ۴لضَّچَلَةَ بِالْهُدۭيٰ فَمَا رَبِحَت تِّجَــٰرَتُهُمْ وَمَا كَانُواْ مُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 16, 'مَثَلُهُمْ كَمَثَلِ ۱ﻟ﮲ ''سْتَوْقَدَ نَاراً فَلَمَّآ أَضَآءَتْ مَا حَوْلَهُؐ„ ذَهَــبَ ۰للَّهُ بِنُورۣهِمْ وَتَرَكَهُمْ فِى ظُلُمَــٰــتٍ لاَّ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 17, 'صُمّٛ بُكْم٘ عُمْيٌ فَهُمْ لاَ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 18, 'أَوْ كَصَيِّبٍ مِّنَ ۰لسَّمَآءِ فِيهِ ظُلُمَـٰتٌ وَرَعْدٌ وَبَرْقٌؐ يَجْعَلُونَ أَصَــٰبِعَهُمْ فِىٓ ءَاذَانِهِم مِّـنَ ۰لصَّوَ؛عِقِ حَذَرَ ۰لْمَوْتِؐ وَاللَّهُ مُحِيطٛ بِالْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 19, 'يَكَادُ ۴لْبَرْقُ يَخْطَفُ أَبْصَـٰرَهُمْؐ كُلَّمَآ أَضَآءَ لَهُم مَّشَوْاْ فِيهِؐ وَإِذَآ أَظْلَمَ عَلَيْهِمْ قَامُواْؐ وَلَوْ شَآءَ ۰للَّهُ لَذَهَــبَ بِسَمْعِهِمْ وَأَبْصۭـٰرۣهِمُؐ; إِنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 20, 'يَـٰٓأَيُّهَا ۰لنَّاسُ ۶عْبُدُواْ رَبَّكُمُ ۴ﻟ﮲ خَلَقَكُمْ وَالذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 21, '۰ﻟ﮲ جَعَلَ لَكُمُ ۴لاَرْضَ فِرَ؛شاً وَالسَّمَآءَ بِنَآءً وَأَنزَلَ مِنَ ۰لسَّمَآءِ مَآءً فَأَخْرَجَ بِهِ” مِنَ ۰لثَّمَرَ؛تِ رۣزْقاً لَّكُمْؐ فَلاَ تَجْعَلُواْ لِلهِ أَندَاداً وَأَنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 22, 'وَإِن كُنتُمْ فِى رَيْــبٍ مِّمَّا نَزَّلْنَا عَلَيٰ 5 عَبْدِنَا فَاتُواْ بِسُورَةٍ مِّن مِّثْلِهِؐ/ وَادْعُواْ شُهَدَآءَكُم مِّن دُونِ ۱للَّهِ إِن كُنتُمْ صَـٰدِقِـينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 23, 'فَإِن لَّمْ تَفْعَلُواْ وَلَن تَفْعَلُــواْ فَاتَّقُواْ ۴لنَّـارَ ۰لتِى وَقُودُهَا ۰لنَّاسُ وَالْحِجَارَةُؐ ٱُعِـدَّتْ لِلْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 24, 'وَبَشِّرۣ ۱لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ أَنَّ لَهُمْ جَنَّـٰــتٍ تَجْرۣﻯ مِن تَحْتِهَا ۰لاَنْهَــٰرُؐ كُلَّمَا رُزۣقُواْ مِنْهَا مِن ثَمَرَةٍ رّۣزْقاً قَالُواْ هَـٰذَا ۰ﻟ﮲ رُزۣقْنَا مِن قَـبْلُؐ وَٱُتُواْ بِهِ” مُتَشَـٰبِهاًؐ وَلَهُمْ فِيهَآ أَزْوَ؛جٌ مُّطَهَّرَةٌؐ وَهُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 25, '© إِنَّ ۰للَّهَ لاَ يَسْتَحْـىِ“ أَنْ يَّضْرۣبَ مَثَلًا مَّا بَعُوضَةً فَمَا فَوْقَهَاؐ فَأَمَّا ۰لذِينَ ءَامَنُواْ فَيَعْلَمُونَ أَنَّهُ ۴لْحَقُّ مِن رَّبِّهِمْؐ وَأَمَّا ۰لذِينَ كَفَرُواْ فَيَقُولُونَ مَاذَآ أَرَادَ ۰للَّهُ بِهَـٰذَا مَثَلًؐا يُضِلُّ بِهِ” كَثِيراً وَيَهْدِى بِهِ” كَثِيراًؐ وَمَا يُضِلُّ بِهِ“ إِلاَّ ۰لْفَــٰسِقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 26, '۰لذِيـنَ يَنقُضُونَ عَهْدَ ۰للَّهِ مِنۢ بَعْدِ مِيثَـٰقِهِ” وَيَقْطَعُونَ مَآ أَمَرَ۰للَّهُ بِهِ“ أَنْ يُّوصَلَ وَيُفْسِدُونَ فِى ۱لاَرْضِؐ ﭐُوْلَئِكَ هُمُ ۴لْخَــٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 27, 'كَيْفَ تَكْفُرُونَ بِاللَّهِ وَكُنتُمُ; أَمْوَ؛تاً فَأَحْيۭاكُمْ ثُمَّ يُمِيتُكُمْؐ ثُمَّ يُحْيِيكُمْ ثُمَّ إِلَيْهِ 6 تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 28, 'هُوَ ۰ﻟ﮲ خَلَقَ لَكُم مَّا فِى ۱لاَرْضِ جَمِيعاًؐ ثُمَّ "سْتَوۭيٰٓ إِلَي ۰لسَّمَآءِ فَسَوّۭيٰهُنَّ سَبْعَ سَمَــٰوَ؛تٍؐ وَهُوَ بِكُلِّ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 29, 'وَإِذْ قَالَ رَبُّكَ لِلْمَلَئِكَةِ إِنِّـﻰ جَاعِلٌ فِى ۱لاَرْضِ خَلِيفَةًؐ قَالُوٓاْ أَتَجْعَلُ فِيهَا مَنْ يُّفْسِدُ فِيهَا وَيَسْفِكُ ۴لدِّمَآءَ وَنَحْنُ نُسَبِّحُ بِحَمْدِكَ وَنُقَدِّسُ لَكَؐ قَالَ إِنِّيَ أَعْلَمُ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 30, 'وَعَلَّمَ ءَادَمَ ۰لاَسْمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمْ عَلَي ۰لْمَلَئِكَةِ فَقَالَ أَنۢبِـُٔونِـى بِأَسْمَآءِ هَـٰٓؤُلٓاَءِ ان كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 31, 'قَالُواْ سُبْحَــٰنَكَ لاَ عِلْمَ لَنَآ إِلاَّ مَا عَلَّمْتَنَآ إِنَّكَ أَنتَ ۰لْعَلِيمُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 32, 'قَالَ يَـٰٓــَٔادَمُ أَنۢبِـيؔهُم بِأَسْمَآئِهِمْؐ فَلَمَّآ أَنۢبَأَهُم بِأَسْمَآئِهِمْ قَالَ أَلَمَ اَقُل لَّكُمُ; إِنِّيَ أَعْلَمُ غَيْــبَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضِ وَأَعْلَمُ مَا تُبْدُونَ وَمَا كُنتُمْ تَكْتُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 33, 'وَإِذْ قُلْنَا لِلْمَلَئِكَةِ ۹سْجُدُواْ ءَلِادَمَ فَسَجَدُوٓاْؐ إِلٓاَّ إِبْلِيسَ أَبۭيٰ وَاسْتَكْبَرَ وَكَانَ مِنَ ۰لْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 34, 'وَقُلْنَا يَـٰٓــَٔادَمُ ۶سْكُنَ اَنــتَ وَزَوْجُكَ ۰لْجَنَّةَ وَكُلاَ مِنْهَا رَغَداٗ حَيْــثُ ﺷِﻴْٔـﺘُـمَاؐ وَلاَ تَقْرَبَا هَـٰذِهِ ۱لشَّجَرَةَ فَتَكُونَا مِنَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 35, 'فَأَزَلَّهُمَا ۰لشَّيْطَـٰنُ عَنْهَا فَأَخْرَجَهُمَا 7 مِمَّا كَانَا فِيهِؐ وَقُلْنَا "هْبِطُواْؐ بَعْضُكُمْ لِبَعْـضٖ عَدُوٌّؐ وَلَكُمْ فِى ۱لاَرْضِ مُسْتَقَرٌّ وَمَتَــٰع٘ اِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 36, 'فَتَلَقّۭيٰٓ ءَادَمُ مِن رَّبِّهِ” كَلِمَـٰــتٍ فَتَابببَ عَلَيْهِؐ إِنَّهُ„ هُوَ ۰لتَّوَّابُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 37, 'قُلْنَا "هْبِطُواْ مِنْهَا جَمِيعاًؐ فَإِمَّا يَاتِيَنَّكُم مِّنِّى هُديً فَمَن تَبِعَ هُدۭايَ فَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 38, 'وَالذِينَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَـٰتِنَآ ٱُوْلَئِكَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 39, 'يَــٰبَنِىٓ إِسْرَآءِيلَ ۸ذْكُرُواْ نِعْمَتِـيَ ۰لتِىٓ أَنْعَمْـتُ عَلَيْكُمْ وَأَوْفُواْ بِعَهْدِﻯٓ ٱُوفِ بِعَهْدِكُمْ وَإِيَّـٰيَ فَارْهَبُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 40, 'وَءَامِنُواْ بِمَآ أَنزَلْــتُ مُصَدِّقاً لِّمَا مَعَكُمْ وَلاَ تَكُونُوٓاْ أَوَّلَ كَافِرۣۢ بِهِؐ/ وَلاَ تَشْتَرُواْ بِـَٔايَـٰتِى ثَمَناً قَلِيلًا وَإِيَّـٰيَ فَاتَّقُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 41, '¥ وَلاَ تَلْبِسُواْ ۴لْحَقَّ بِالْبَـٰطِلِ وَتَكْتُمُواْ ۴لْحَقَّ وَأَنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 42, 'وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَارْكَعُواْ مَعَ ۰لرَّ؛كِعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 43, 'أَتَامُرُونَ ۰لنَّاسَ بِالْبِرّۣ وَتَنسَوْنَ أَنفُسَكُمْ وَأَنتُمْ تَتْلُونَ ۰لْكِتَــٰــبَؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 44, 'وَاسْتَعِينُواْ بِالصَّبْرۣ وَالصَّلَوٰةِؐ وَإِنَّهَا لَكَبِيرَة٘ اِلاَّ عَلَي ۰لْخَــٰشِعِيـنَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 45, '۰لذِينَ 8 يَظُنُّونَ أَنَّهُم مُّچَقُواْ رَبِّهِمْ وَأَنَّهُمُ; إِلَيْهِ رَ؛جِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 46, 'يَـٰبَنِىٓ إِسْرَآءِيلَ ۸ذْكُرُواْ نِعْمَتِيَ ۰لتِىٓ أَنْعَمْــتُ عَلَيْكُمْ وَأَنِّـى فَضَّلْتُكُمْ عَلَي ۰لْعَــٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 47, 'وَاتَّقُواْ يَوْماً لاَّ تَجْزۣى نَفْس٘ عَن نَّفْسٍ شَيْــٔاً وَلاَ يُقْبَلُ مِنْهَا شَفَــٰعَةٌ وَلاَ يُوخَذُ مِنْهَا عَدْلٌ وَلاَ هُمْ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 48, 'وَإِذْ نَجَّيْنَـٰكُم مِّـنَ —الِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ۰لْعَذَابببِ يُذَبِّحُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْؐ وَفِى ذَ؛لِكُم بَلٓاَءٌ مِّن رَّبِّكُمْ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 49, 'وَإِذْ فَرَقْنَا بِكُمُ ۴ڤْبَحْرَ فَأَنجَيْنَـٰكُمْ وَأَغْرَقْنَآ ءَالَ فِرْعَوْنَ وَأَنتُمْ تَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 50, 'وَإِذْ وَ؛عَدْنَا مُوسۭيٰٓ أَرْبَعِينَ لَيْلَةً ثُمَّ "تَّخَذتُّمُ ۴لْعِجْلَ مِنۢ بَعْدِهِ” وَأَنتُمْ ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 51, 'ثُمَّ عَفَوْنَا عَنكُم مِّنۢ بَعْدِ ذَ؛لِكَ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 52, 'وَإِذَ —اتَيْنَا مُوسَي ۰لْكِتَــٰــبَؐ وَالْفُرْقَانَ لَعَلَّكُمْ تَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 53, 'وَإِذْ قَالَ مُوسۭيٰ لِقَوْمِهِ” يَـٰقَوْمِ إِنَّكُمْ ظَلَمْتُمُ; أَنفُسَكُم بِاتِّخَاذِكُمُ ۴لْعِجْلَ فَتُوبُوٓاْ إِلَيٰ بَارۣئِكُمْ فَاقْتُلُوٓاْ أَنفُسَكُمْؐ ذَ؛لِكُمْ خَيْرٌ لَّكُمْ عِندَ بَارۣئِكُمْؐ فَتَابببَ عَلَيْكُمُؐ; إِنَّهُ„ هُوَ ۰لتَّوَّابببُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 54, 'وَإِذْ قُلْتُمْ يَـٰمُوسۭيٰ 9 لَن نُّومِنَ لَكَ حَتَّيٰ نَرَي ۰للَّهَ جَهْرَةً فَأَخَذَتْكُمُ ۴لصَّـٰعِقَةُ وَأَنتُمْ تَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 55, 'ثُمَّ بَعَثْنَــٰكُم مِّنۢ بَعْدِ مَوْتِكُمْ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 56, 'وَظَلَّلْنَا عَلَيْكُمُ ۴لْغَمَـٰمَ وَأَنزَلْنَا عَلَيْكُمُ ۴لْمَنَّ وَالسَّلْوۭيٰؐ كُلُواْ مِن طَيِّبَــٰــتِ مَا رَزَقْنَـٰكُمْؐ وَمَا ظَلَمُونَاؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 57, 'وَإِذْ قُلْنَا ۸دْخُلُواْ هَـٰذِهِ ۱لْقَرْيَةَ فَكُلُواْ مِنْهَا حَيْثُ شِيؔتُمْ رَغَداً وَادْخُلُواْ ۴لْبَابببَ سُجَّداً وَقُولُواْ حِطَّةٌ يُغْفَرْ لَكُمْ خَطَـٰيۭـٰكُمْؐ وَسَنَزۣيدُ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 58, 'فَبَدَّلَ ۰لذِينَ ظَلَمُواْ قَوْلٗا غَيْرَ ۰ﻟ﮲ قِيلَ لَهُمْ فَأَنزَلْنَا عَلَي ۰لذِينَ ظَلَمُواْ رۣجْزاً مِّنَ ۰لسَّمَآءِ بِمَا كَانُواْ يَفْسُقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 59, '© وَإِذِ ''سْتَسْقۭيٰ مُوسۭيٰ لِقَوْمِهِ” فَقُلْنَا "ضْرۣب بِّعَصَاكَ ۰لْحَجَـرَؐ فَانفَجَرَتْ مِنْهُ èثْنَتَا عَشْرَةَ عَيْناًؐ قَدْ عَلِمَ كُلُّ ٱُنَاسٍ مَّشْرَبَهُمْؐ كُلُواْ وَاشْرَبُواْ مِن رّۣزْقِ ۱للَّهِؐ وَلاَ تَعْثَوْاْ فِى ۱لاَرْضِ مُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 60, 'وَإِذْ قُلْتُمْ يَـٰمُوسۭيٰ لَن نَّصْبِرَ عَلَيٰ طَعَامٍ وَ؛حِدٍ فَادْعُ لَنَا رَبَّكَ يُخْرۣجْ لَنَا مِمَّا تُنۢبِــتُ ۴لاَرْضُ مِنۢ بَقْلِهَا وَقِثَّآئِهَا وَفُومِهَا وَعَدَسِهَا وَبَصَلِهَاؐ قَالَ أَتَسْتَبْدِلُونَ 10 ۰ﻟ﮲ هُوَ أَدْنۭيٰ بِاﻟ﮲ هُوَ خَيْر٘ؐ ''هْبِطُواْ مِصْراً فَإِنَّ لَكُم مَّا سَأَلْتُمْؐ وَضُرۣبَــتْ عَلَيْهِمُ ۴لذِّلَّةُ وَالْمَسْكَنَةُ وَبَآءُو بِغَضَــبٍ مِّنَ ۰للَّهِؐ ذَ؛لِكَ بِأَنَّهُمْ كَانُواْ يَكْفُرُونَ بِـَٔايَــٰــتِ ۱للَّهِ وَيَقْتُلُونَ ۰لنَّبِيٓــٕﯧنَ بِغَيْرۣ ۱لْحَقﱢّؐ ذَ؛لِكَ بِمَا عَصَواْ وَّكَانُواْ يَعْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 61, 'إِنَّ ۰لذِينَ ءَامَنُواْ وَالذِينَ هَادُواْ وَالنَّصَـٰرۭيٰ وَالصَّـٰبِينَ مَنَ —امَنَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَعَمِلَ صَـٰڤِحاً فَلَهُمُ; أَجْرُهُمْ عِندَ رَبِّهِمْ وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 62, 'وَإِذَ اَخَذْنَا مِيثَـــٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ۴لطُّورَؐ خُذُواْ مَآ ءَاتَيْنَـٰكُم بِقُوَّةٍ وَاذْكُرُواْ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 63, 'ثُمَّ تَوَلَّيْتُم مِّنۢ بَعْدِ ذَ؛لِكَؐ فَلَوْلاَ فَضْلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ لَكُنتُم مِّنَ ۰لْخَــٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 64, 'وَلَقَدْ عَلِمْتُمُ ۴لذِينَ "عْتَدَوْاْ مِنكُمْ فِى ۱لسَّبْــتِ فَقُلْنَا لَهُمْ كُونُواْ قِرَدَةٗ خَـٰسِـِٕينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 65, 'فَجَعَلْنَـٰهَا نَكَـٰلًا لِّمَا بَيْنَ يَدَيْهَا وَمَا خَلْفَهَا وَمَوْعِظَةً لِّلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 66, 'وَإِذْ قَالَ مُوسۭيٰ لِقَوْمِهِ“ إِنَّ ۰للَّهَ يَامُرُكُمُ; أَن تَذْبَحُواْ بَقَرَةًؐ قَـالُوٓاْ أَتَتَّخِذُنَا هُزُؤاًؐ قَالَ أَعُوذُ بِاللَّهِ أَنَ اَكُونَ مِنَ ۰لْجَــٰهِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 67, '11 قَالُواْ ۶دْعُ لَنَا رَبَّژَ يُبَيِّن لَّنَا مَا هِيَؐ قَالَ إِنَّهُ„ يَقُولُ إِنَّهَا بَقَرَةٌ لاَّ فَارۣضٌ وَلاَ بِكْر٘ؐ عَوَانٛ بَيْنَ ذَ؛لِژَؐ فَافْعَلُواْ مَا تُومَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 68, 'قَالُواْ ۶دْعُ لَنَا رَبَّژَ يُبَيِّن لَّنَا مَا لَوْنُهَاؐ قَالَ إِنَّهُ„ يَقُولُ إِنَّهَا بَقَرَةٌ صَفْرَآءُ فَاقِعٌ لَّوْنُهَاؐ تَسُرُّ ۴لنَّــٰظِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 69, 'قَالُواْ ۶دْعُ لَنَا رَبَّژَ يُبَيِّن لَّنَا مَا هِيَ إِنَّ ۰لْبَقَرَ تَشَــٰبَهَ عَلَيْنَا وَإِنَّآ إِن شَآءَ ۰للَّهُ لَمُهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 70, 'قَالَ إِنَّهُ„ يَقُولُ إِنَّهَا بَقَرَةٌ لاَّ ذَلُولٌ تُثِيرُ ۴لاَرْضَ وَلاَ تَسْقِى ۱لْحَرْثثثَؐ مُسَلَّمَةٌ لاَّ شِيَةَ فِيهَاؐ قَالُواْ ۴چَـنَ جِيؔــتَ بِالْحَقﱢّؐ فَذَبَحُوهَا وَمَا كَادُواْ يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 71, 'وَإِذْ قَتَلْتُمْ نَفْساً فَادَّ؛رَﹻتُمْ فِيهَاؐ وَاللَّهُ مُخْرۣجٌ مَّا كُنتُمْ تَكْتُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 72, 'فَقُلْنَا "ضْرۣبُوهُ بِبَعْضِهَاؐ كَذَ؛لِژَ يُحْىِ ۱للَّهُ ۴لْمَوْتۭيٰ وَيُرۣيكُمُ; ءَايَــٰتِهِ” لَعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 73, 'ثُمَّ قَسَــتْ قُلُوبُكُم مِّنۢ بَعْدِ ذَ؛لِژَ فَهِيَ كَالْحِجَارَةِ أَوَ اَشَدُّ قَسْوَةًؐ وَإِنَّ مِنَ ۰لْحِجَارَةِ لَمَا يَتَفَجَّرُ مِنْهُ ۴لاَنْهَـٰرُؐ وَإِنَّ مِنْهَا لَمَا يَشَّقَّقُ فَيَخْرُجُ مِنْهُ ۴لْمَآءُؐ وَإِنَّ مِنْهَا لَمَا يَهْبِطُ مِنْ خَشْيَةِ ۱للَّهِؐ وَمَا ۰للَّهُ بِغَـٰفِلٖ عَمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 74, 'أَفَتَطْمَعُونَ أَنْ يُّومِنُواْ لَكُمْ وَقَدْ كَانَ فَرۣيقٌ مِّنْهُمْ يَسْمَعُونَ كَچَمَ ۰للَّهِ ثُمَّ يُحَـرّۣفُونَهُ„ مِنۢ بَعْدِ مَا 12 عَقَلُوهُ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 75, '¤ وَإِذَا لَقُواْ ۴لذِينَ ءَامَنُواْ قَالُوٓاْ ءَامَنَّاؐ وَإِذَا خَلاَ بَعْضُهُمُ; إِلَيٰ بَعْضٍ قَالُوٓاْ أَتُحَدِّثُونَهُم بِمَا فَتَحَ ۰للَّهُ عَلَيْكُمْ ڤِيُحَآجُّوكُم بِهِ” عِندَ رَبِّكُمُؐ; أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 76, 'أَوَلاَ يَعْلَمُونَ أَنَّ ۰للَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 77, 'وَمِنْهُمُ; ٱُمِّيُّونَ لاَ يَعْلَمُونَ ۰لْكِتَـٰبَ إِلٓاَّ أَمَانِيَّؐ وَإِنْ هُمُ; إِلاَّ يَظُنُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 78, 'فَوَيْلٌ لِّلذِينَ يَكْتُبُونَ ۰لْكِتَـٰبَ بِأَيْدِيهِمْ ثُمَّ يَقُولُونَ هَـٰذَا مِنْ عِندِ ۱للَّهِ لِيَشْتَرُواْ بِهِ” ثَمَناً قَلِيلًؐا فَوَيْلٌ لَّهُم مِّمَّا كَتَبَــتَ اَيْدِيهِمْؐ وَوَيْلٌ لَّهُم مِّمَّا يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 79, 'وَقَالُواْ لَن تَمَسَّنَا ۰لنَّارُ إِلٓاَّ أَيَّاماً مَّعْدُودَةًؐ قُلَ اَتَّخَذتُّمْ عِندَ ۰للَّهِ عَهْداً فَلَنْ يُّخْلِفَ ۰للَّهُ عَهْدَهُؐ; أَمْ تَقُولُونَ عَلَي ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 80, 'بَلۭيٰ مَن كَسَبَ سَيِّيؕةً وَ أَحَـٰطَــتْ بِهِ” خَطِيٓــَٔــٰتُهُ„ فَٱُوْلَئِكَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَــٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 81, 'وَالذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَــٰــتِ ٱُوْلَئِكَ أَصْحَـٰبُ ۴لْجَنَّةِ هُمْ فِيهَا خَــٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 82, 'وَإِذَ اَخَذْنَا مِيثَـٰقَ بَنِىٓ إِسْرَآءِيلَ لاَ تَعْبُدُونَ إِلاَّ ۰للَّهَؐ وَبِالْوَ؛لِدَيْنِ إِحْسَـٰناً وَذى ۱لْقُرْبۭيٰ وَالْيَتَـٰمۭيٰ وَالْمَسَـٰكِينِؐ وَقُولُواْ لِلنَّاسِ حُسْناًؐ 1 وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ ثُمَّ تَوَلَّيْتُمُ; إِلاَّ قَلِيلًا مِّنكُمْ وَأَنتُم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 83, 'وَإِذَ اَخَذْنَا مِيثَــٰقَكُمْ لاَ تَسْفِكُونَ دِمَآءَكُمْ وَلاَ تُخْرۣجُونَ أَنفُسَكُم مِّن دِيۭـٰرۣكُمْ ثُمَّ أَقْرَرْتُمْ وَأَنتُمْ تَشْهَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 84, 'ثُمَّ أَنتُمْ هَـٰٓؤُلآَءِ تَقْتُلُونَ أَنفُسَكُمْ وَتُخْرۣجُونَ فَرۣيقاً مِّنكُم مِّـن دِيۭـٰرۣهِمْ تَظَّـٰهَرُونَ عَلَيْهِم بِالِاثْمِ وَالْعُدْوَ؛نِؐ  وَإِنْ يَّاتُوكُمُ; ٱُسَـٰرۭيٰ تُفَــٰدُوهُمْ وَهُوَ مُحَـرَّم٘ عَلَيْكُمُ; إِخْرَاجُهُمُؐ; أَفَتُومِنُونَ بِبَعْضِ ۱لْكِتَـٰبِ وَتَكْفُرُونَ بِبَعْضٍؐ فَمَا جَزَآءُ مَنْ يَّـفْعَلُ ذَ؛لِكَ مِنكُمُ; إِلاَّ خِزْيٌ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَيَوْمَ ۰لْقِيَـٰمَةِ يُرَدُّونَ إِلَـيٰٓ أَشَدِّ ۱لْعَذَابببِؐ وَمَا ۰للَّهُ بِغَــٰفِلٖ عَمَّا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 85, 'ٱُوْلَئِكَ ۰لذِينَ "شْتَرَوُاْ ۴لْحَيَوٰةَ ۰لدُّنْيۭا بِالاَخِرَةِ فَلاَ يُخَفَّفُ عَنْهُمُ ۴لْعَذَابُ وَلاَ هُمْ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 86, 'وَلَقَدَ —اتَيْنَا مُوسَي ۰لْكِتَــٰــبَ وَقَفَّيْنَا مِنۢ بَعْدِهِ” بِالرُّسُلِؐ وَءَاتَيْنَا عِيسَي "بْنَ مَرْيَمَ ۰لْبَيِّنَــٰــتِ وَأَيَّدْنَــٰهُ بِرُوحِ ۱لْقُدُسِؐ أَفَكُلَّمَا جَآءَكُمْ رَسُولٛ بِمَا لاَ تَهْوۭيٰٓ أَنفُسُكُمُ èسْتَكْبَرْتُمْؐ فَفَرۣيقاً كَذَّبْتُمْؐ وَفَرۣيقاً تَقْتُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 87, '14 وَقَالُواْ قُلُوبُنَا غُلْفٛؐ بَل لَّعَنَهُمُ ۴للَّهُ بِكُفْرۣهِمْ فَقَلِيلًا مَّا يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 88, 'وَلَمَّا جَآءَهُمْ كِتَـٰبٌ مِّنْ عِندِ ۱للَّهِ مُصَدِّقٌ لِّمَا مَعَهُمْ وَكَانُواْ مِن قَبْلُ يَسْتَفْتِحُونَ عَلَي ۰لذِينَ كَفَرُواْؐ فَلَمَّا جَآءَهُم مَّا عَرَفُواْ كَفَرُواْ بِهِؐ/ فَلَعْنَةُ ۴للَّهِ عَلَي ۰لْكۭــٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 89, 'بِيسَمَا "شْتَرَوْاْ بِهِ“ أَنفُسَهُمُ; أَنْ يَّكْفُرُواْ بِمَآ أَنزَلَ ۰للَّهُ بَغْياٗ اَنْ يُّنَزّۣلَ ۰للَّهُ مِن فَضْلِهِ” عَلَيٰ مَنْ يَّشَآءُ مِنْ عِبَادِهِؐ/ فَبَآءُو بِغَضَبٖ عَلَيٰ غَضَبٍؐ وَلِلْكۭـٰفِـرۣينَ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 90, 'وَإِذَا قِيلَ لَهُمُ; ءَامِنُواْ بِمَآ أَنزَلَ ۰للَّهُ قَالُواْ نُومِنُ بِمَآ ٱُنزۣلَ عَلَيْنَا وَيَكْفُرُونَ بِمَا وَرَآءَهُؐ„ وَهُوَ ۰لْحَقُّ مُصَدِّقاً لِّمَا مَعَهُمْؐ قُلْ فَلِمَ تَقْتُلُونَ أَنۢبِيؕآءَ ۰للَّهِ مِن قَبْلُ إِننن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 91, '© وَلَقَدْ جَآءَكُم مُّوسۭيٰ بِالْبَيِّنَـٰــتِ ثُمَّ "تَّخَذتُّمُ ۴لْعِجْلَ مِنۢ بَعْدِهِ” وَأَنتُمْ ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 92, 'وَإِذَ اَخَذْنَا مِيثَـٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ۴لطُّورَؐ خُذُواْ مَآ ءَاتَيْنَــٰكُم بِقُوَّةٍ وَاسْمَعُواْؐ قَالُواْ سَمِعْنَا وَعَصَيْنَاؐ وَٱُشْرۣبُواْ فِى قُلُوبِهِمُ ۴لْعِجْلَ بِكُفْرۣهِمْؐ قُلْ بِيسَمَا يَامُرُكُم بِهِ“ إِيمَـٰنُكُمُ; إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 93, 'قُلِ اِن كَانَتْ لَكُمُ ۴لدَّارُ 15 ۴لاَخِرَةُ عِندَ ۰للَّهِ خَالِصَةً مِّن دُونِ ۱لنَّاسِ فَتَمَنَّوُاْ ۴لْمَوْتَ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 94, 'وَلَنْ يَّتَمَنَّوْهُ أَبَداَۢ بِمَا قَدَّمَــتَ اَيْدِيهِمْؐ وَاللَّهُ عَلِيمٛ بِالظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 95, 'وَلَتَجِدَنَّهُمُ; أَحْرَصَ ۰لنَّاسِ عَلَيٰ حَيَوٰةٍؐ وَمِنَ ۰لذِينَ أَشْرَكُواْ يَوَدُّ أَحَدُهُمْ لَوْ يُعَمَّرُ أَلْفَ سَنَةٍؐ وَمَا هُوَ بِمُزَحْزۣحِهِ” مِنَ ۰لْعَذَابببِ أَنْ يُّعَمَّرَؐ وَاللَّهُ بَصِيرٛ بِمَا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 96, 'قُلْ مَن كَانَ عَدُوّاً لِّجِبْرۣيلَ فَإِنَّهُ„ نَزَّلَهُ„ عَلَيٰ قَلْبِكَ بِإِذْنِ ۱للَّهِ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِ وَهُديً وَبُشْرۭيٰ لِلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 97, 'مَن كَانَ عَدُوّاً لِّلهِ وَمَلَئِكَتِهِ” وَرُسُلِهِ” وَجِبْرۣيلَ وَمِيكَـٰٓئِلَ فَإِنَّ ۰للَّهَ عَدُوٌّ لِّلْكۭــٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 98, 'وَلَقَدَ اَنزَلْنَآ إِلَيْكَ ءَايَــٰــتٙ بَيِّنَــٰــتٍؐ وَمَا يَكْفُرُ بِهَآ إِلاَّ ۰لْفَــٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 99, 'أَوَكُلَّمَا عَــٰهَدُواْ عَهْداً نَّبَذَهُ„ فَرۣيقٌ مِّنْهُمؐ بَلَ اَكْثَرُهُمْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 100, 'وَلَمَّا جَآءَهُمْ رَسُولٌ مِّنْ عِندِ ۱للَّهِ مُصَدِّقٌ لِّمَا مَعَهُمْ نَبَذَ فَرۣيقٌ مِّنَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ كِتَــٰــبَ ۰للَّهِ وَرَآءَ ظُهُورۣهِمْ كَأَنَّهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 101, 'وَاتَّبَعُواْ مَا تَتْلُواْ ۴لشَّيَـٰطِينُ عَلَيٰ مُلْكِ سُلَيْمَـٰنَؐ وَمَا كَفَرَ سُلَيْمَـٰنُؐ وَچَكِنَّ ۰لشَّيَـٰطِينَ كَفَرُواْ يُعَلِّمُونَ 16 ۰لنَّاسَ ۰ڤسِّحْرَ وَمَآ ٱُنزۣلَ عَلَي ۰لْمَلَكَيْنِ بِبَابِـلَ هَارُوتتتَ وَمَارُوتتتَؐ وَمَا يُعَلِّمَـٰنِ مِنَ اَحَدٖ حَتَّيٰ يَقُولآَ إِنَّمَا نَحْنُ فِتْنَةٌ فَلاَ تَكْفُرْؐ فَيَتَعَلَّمُونَ مِنْهُمَا مَا يُفَرّۣقُونَ بِهِ” بَيْنَ ۰لْمَرْءِ وَزَوْجِهِؐ/ وَمَا هُم بِضَآرّۣينَ بِهِ” مِنَ اَحَدٖ اِلاَّ بِإِذْنِ ۱للَّهِؐ وَيَتَعَلَّمُونَ مَا يَضُرُّهُمْ وَلاَ يَنفَعُهُمْؐ وَلَقَدْ عَلِمُواْ لَمَـنِ ۳شْتَرۭيٰهُ مَا لَهُ„ فِى ۱لاَخِرَةِ مِنْ خَچَقٍؐ وَلَبِيسَ مَا شَرَوْاْ بِهِ“ أَنفُسَهُمْ لَوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 102, 'وَلَوَ اَنَّهُمُ; ءَامَنُواْ وَاتَّقَوْاْ لَمَثُوبَةٌ مِّنْ عِندِ ۱للَّهِ خَيْرٌ لَّوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 103, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَقُولُواْ رَ؛عِنَا وَقُولُواْ ۶نظُرْنَا وَاسْمَعُواْؐ وَلِلْكۭـٰفِرۣينَ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 104, 'مَّا يَوَدُّ ۴لذِينَ كَفَرُواْ مِنَ اَهْلِ ۱لْكِتَــٰــبِ وَلاَ ۰لْمُشْرۣكِينَ أَنْ يُّنَزَّلَ عَلَيْكُم مِّنْ خَيْرٍ مِّن رَّبِّكُمْؐ وَاللَّهُ يَخْتَصُّ بِرَحْمَتِهِ” مَنْ يَّشَآءُؐ وَاللَّهُ ذُو ۴لْفَضْلِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 105, '¥ مَا نَنسَخْ مِنَ —ايَةٖ اَوْ نُنسِهَا نَاتتتِ بِخَـيْرٍ مِّنْهَآ أَوْ مِثْلِهَآؐ أَلَمْ تَعْلَمَ اَنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 106, 'اَلَمْ تَعْلَمَ اَنَّ ۰للَّهَ لَهُ„ مُلْكُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضِ وَمَا لَكُم مِّن دُونِ ۱للَّهِ مِنْ وَّلِيٍّ وَلاَ نَصِيرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 107, 'اَمْ تُرۣيدُونَ أَن تَسْـَٔلُواْ رَسُولَكُمْ كَمَا 17 سُئِلَ مُوسۭيٰ مِن قَبْلُؐ وَمَنْ يَّتَبَدَّلِ ۱لْكُفْرَ بِالِايمَـٰنِ فَقَد ضَّلَّ سَوَآءَ ۰لسَّبِيلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 108, 'وَدَّ كَثِيرٌ مِّنَ اَهْلِ ۱لْكِتَــٰــبِ لَوْ يَرُدُّونَكُم مِّنۢ بَعْدِ إِيمَــٰنِكُمْ كُفَّاراٗؐ حَسَداً مِّنْ عِندِ أَنفُسِهِم مِّنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ۴لْحَقُّؐ فَاعْفُواْ وَاصْفَحُواْ حَتَّيٰ يَاتِيَ ۰للَّهُ بِأَمْرۣهِؐ“ إِنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 109, 'وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَمَا تُقَدِّمُواْ لَأِنفُسِكُم مِّنْ خَيْرٍ تَجِدُوهُ عِندَ ۰للَّهِؐ إِنَّ ۰للَّهَ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 110, 'وَقَالُواْ لَنْ يَّدْخُلَ ۰لْجَنَّةَ إِلاَّ مَن كَانَ هُوداٗ اَوْ نَصَـٰرۭيٰؐ تِلْكَ أَمَانِيُّهُمْؐ قُلْ هَاتُواْ بُرْهَــٰنَكُمُ; إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 111, 'بَلۭيٰ مَنَ اَسْلَمَ وَجْهَهُ„ لِلهِ وَهُوَ مُحْسِنٌ فَلَهُ; أَجْرُهُ„ عِندَ رَبِّهِ” وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 112, 'وَقَالَــتِ ۱لْيَهُودُ لَيْسَــتِ ۱لنَّصَـٰرۭيٰ عَلَيٰ شَيْءٍ وَقَالَــتِ ۱لنَّصَـٰرۭيٰ لَيْسَــتِ ۱لْيَهُودُ عَلَيٰ شَيْءٍ وَهُمْ يَتْلُونَ ۰لْكِتَــٰــبَؐ كَذَ؛لِكَ قَالَ ۰لذِينَ لاَ يَعْلَمُونَ مِثْلَ قَوْلِهِمْؐ فَاللَّهُ يَحْكُمُ بَيْنَهُمْ يَوْمَ ۰لْقِيَــٰمَةِ فِيمَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 113, 'وَمَنَ اَظْلَمُ مِمَّن مَّنَعَ مَسَـٰجِدَ ۰للَّهِ أَنْ يُّذْكَرَ 18 فِيهَا "سْمُهُ„ وَسَعۭيٰ فِى خَرَابِهَآؐ ٱُوْلَئِكَ مَا كَانَ لَهُمُ; أَنْ يَّدْخُلُوهَآ إِلاَّ خَآئِـفِينَؐ لَهُمْ فِى ۱لدُّنْيۭا خِزْيٌؐ وَلَهُمْ فِى ۱لاَخِرَةِ عَذَاب٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 114, 'وَلِلهِ ۱لْمَشْرۣقُ وَالْمَغْرۣبُؐ فَأَيْنَمَا تُوَلُّواْ فَثَمَّ وَجْهُ ۴للَّهِؐ إِنَّ ۰للَّهَ وَ؛سِع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 115, 'وَقَالُواْ ۵تَّخَذَ ۰للَّهُ وَلَداًؐ سُبْحَــٰنَهُؐ„ بَل لَّهُ„ مَا فِى ۱لسَّمَــٰوَ؛تتتِ وَالاَرْضِؐ كُلٌّ لَّهُ„ قَــٰنِتُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 116, 'بَدِيعُ ۴لسَّمَــٰوَ؛تتتِ وَالاَرْضِؐ وَإِذَا قَضۭيٰٓ أَمْراً فَإِنَّمَا يَقُولُ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 117, 'وَقَالَ ۰لذِينَ لاَ يَعْلَمُونَ لَوْلاَ يُكَلِّمُنَا ۰للَّهُ أَوْ تَاتِينَآ ءَايَةٌؐ كَذَ؛لِكَ قَالَ ۰لذِينَ مِن قَبْلِهِم مِّثْلَ قَوْلِهِمْؐ تَشَــٰبَهَــتْ قُلُوبُهُمْؐ قَدْ بَـيَّنَّا ۰لاَيَــٰــتِ لِقَوْمٍ يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 118, 'إِنَّآ أَرْسَلْنَـٰكَ بِالْحَقِّ بَشِيراً وَنَذِيراًؐ وَلاَ تَسْـَٔلْ عَنَ اَصْحَــٰــبِ ۱لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 119, 'وَلَن تَرْضۭيٰ عَنكَ ۰لْيَهُودُ وَلاَ ۰لنَّصَـٰرۭيٰ حَتَّيٰ تَتَّبِعَ مِلَّتَهُمْؐ قُلِ اِنَّ هُدَي ۰للَّهِ هُوَ ۰لْهُدۭيٰؐ وَلَـئِنِ ''تَّبَعْتَ أَهْوَآءَهُم بَعْدَ ۰ﻟ﮲ جَآءَكَ مِنَ ۰لْعِلْمِ مَا لَكَ مِنَ ۰للَّهِ مِنْ وَّلِيٍّ وَلاَ نَصِيرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 120, '۱لذِينَ ءَاتَيْنَـٰهُمُ ۴لْكِتَــٰــبَ يَتْلُونَهُ„ حَقَّ تِچَوَتِهِ“ ٱُوْلَئِكَ يُومِنُونَ بِهِؐ” وَمَنْ يَّكْفُرْ بِهِ” فَٱُوْلَئِژَ هُمُ ۴لْخَــٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 121, '19 يَـٰبَنِىٓ إِسْرَآءِيلَ ۸ذْكُرُواْ نِعْمَتِيَ ۰لتِىٓ أَنْعَمْــتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَي ۰لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 122, 'وَاتَّقُواْ يَوْماً لاَّ تَجْزۣى نَفْس٘ عَن نَّفْسٍ شَيْــٔاً وَلاَ يُقْبَلُ مِنْهَا عَدْلٌ وَلاَ تَنفَعُهَا شَفَــٰعَةٌ وَلاَ هُمْ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 123, '© وَإِذِ ''بْتَلۭيٰٓ إِبْرَ؛هِـيمَ رَبُّهُ„ بِكَلِمَــٰــتٍ فَأَتَمَّهُنَّؐ قَالَ إِنِّى جَاعِلُكَ لِلنَّاسِ إِمَاماًؐ قَالَ وَمِن ذُرّۣيَّتِىؐ قَالَ لاَ يَنَالُ عَهْدِيَ ۰لظَّــٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 124, 'وَإِذْ جَعَلْنَا ۰لْبَيْــتَ مَثَابَةً لِّلنَّاسِ وَأَمْناً وَاتَّخَذُواْ مِن مَّقَامِ إِبْرَ؛هِيمَ مُصَلّيًؐ وَعَهِدْنَآ إِلَيٰٓ إِبْرَ؛هِيمَ وَإِسْمَـٰعِيلَ أَن طَهِّرَا بَيْتِيَ لِلطَّآئِفِينَ وَالْعَـٰكِفِينَ وَالرُّكَّعِ ۱لسُّجُودِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 125, 'وَإِذْ قَالَ إِبْرَ؛هِيمُ رَبببِّ ''جْعَلْ هَـٰذَا بَلَداٗ —امِناً وَارْزُقَ اَهْلَهُ„ مِنَ ۰لثَّمَرَ؛تِ مَنَ —امَنَ مِنْهُم بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ قَالَ وَمَن كَفَرَ فَٱُمَتِّعُهُ„ قَلِيلًا ثُمَّ أَضْطَرُّهُ; إِلَيٰ عَذَابببِ ۱لنّۭارۣؐ وَبِيسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 126, 'وَإِذْ يَرْفَـعُ إِبْرَ؛هِيمُ ۴لْقَوَاعِدَ مِنَ ۰لْبَيْــتِ وَإِسْمَــٰعِيلُؐ رَبَّنَا تَقَبَّلْ مِنَّآ إِنَّكَ أَنــتَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 127, 'رَبَّنَا وَاجْعَلْنَا مُسْلِمَيْنِ لَكَ وَمِن ذُرّۣيَّتِنَآ ٱُمَّةً مُّسْلِمَةً لَّكَؐ وَأَرۣنَا مَنَاسِكَنَاؐ وَتُــبْ عَلَيْنَآؐ إِنَّكَ أَنــتَ ۰لتَّوَّابببُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 128, 'رَبَّـنَا 20 وَابْعَــثْ فِيهِمْ رَسُولًا مِّنْهُمْ يَتْلُواْ عَلَيْهِمُ; ءَايَـٰتِكَ وَيُعَلِّمُهُمُ ۴لْكِتَــٰــبَ وَالْحِكْمَةَ وَيُزَكِّيهِمُؐ; إِنَّكَ أَنتَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 129, 'وَمَنْ يَّرْغَــبُ عَن مِّلَّةِ إِبْرَ؛هِيمَ إِلاَّ مَن سَفِهَ نَفْسَهُؐ„ وَلَقَدِ ''صْطَفَيْنَـٰهُ فِى ۱لدُّنْيۭاؐ وَإِنَّهُ„ فِى ۱لاَخِرَةِ لَمِنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 130, 'إِذْ قَالَ لَهُ„ رَبُّهُ; أَسْلِمْؐ قَالَ أَسْلَمْــتُ لِرَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 131, 'وَأَوْصۭيٰ بِهَآ إِبْرَ؛هِيمُ بَنِيهِؐ وَيَعْقُوبُ يَـٰبَنِيَّ إِنَّ ۰للَّهَ "صْطَفۭيٰ لَكُمُ ۴لدِّينَ فَلاَ تَمُوتُنَّ إِلاَّ وَأَنتُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 132, 'أَمْ كُنتُمْ شُهَدَآءَ اۭذْ حَضَرَ يَعْقُوبببَ ۰لْمَوْتتتُ إِذْ قَالَ لِبَنِيهِ مَا تَعْبُدُونَ مِنۢ بَعْدِىؐ قَالُواْ نَعْبُدُإِچَهَكَ وَإِچَهَ ءَابَآئِكَ إِبْرَ؛هِيمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ إِچَهاً وَ؛حِداً وَنَحْنُ لَهُ„ مُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 133, 'تِلْكَ ٱُمَّةٌ قَدْ خَلَــتْؐ لَهَا مَا كَسَبَــتْؐ وَلَكُم مَّا كَسَبْتُمْؐ وَلاَ تُسْـَٔلُونَ عَمَّا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 134, 'وَقَالُواْ كُونُواْ هُوداٗ اَوْ نَصَـٰرۭيٰ تَهْتَدُواْؐ قُلْ بَلْ مِلَّةَ إِبْرَ؛هِيمَ حَنِيفاًؐ وَمَا كَانَ مِنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 135, 'قُولُوٓاْ ءَامَنَّا بِاللَّهِ وَمَآ ٱُنزۣلَ إِلَيْنَاوَمَآ ٱُنزۣلَ إِلَيٰٓ إِبْرَ؛هِيمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبَ وَالاَسْبَاطِ وَمَآٱُوتِيَ مُوسۭيٰ وَعِيسۭيٰ وَمَآ ٱُوتِيَ ۰لنَّبِيٓــُٔونَ 21 مِن رَّبِّهِمْ لاَ نُفَرّۣقُ بَيْنَ أَحَدٍ مِّنْهُمْ وَنَحْنُ لَهُ„ مُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 136, 'فَإِنَ —امَنُواْ بِمِثْلِ مَآ ءَامَنتُم بِهِ” فَقَدِ ''هْتَدَواْؐ وَّإِن تَوَلَّوْاْ فَإِنَّمَا هُمْ فِى شِقَاقٍؐ فَسَيَكْفِيكَهُمُ ۴للَّهُؐ وَهُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 137, 'صِبْغَةَ ۰للَّهِؐ وَمَنَ اَحْسَنُ مِنَ ۰للَّهِ صِبْغَةًؐ وَنَحْنُ لَهُ„ عَـٰبِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 138, 'قُلَ اَتُحَآجُّونَنَا فِى ۱للَّهِ وَهُوَ رَبُّنَا وَرَبُّكُمْ وَلَنَآ أَعْمَــٰلُنَا وَلَكُمُ; أَعْمَــٰلُكُمْؐ وَنَحْنُ لَهُ„ مُخْلِصُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 139, 'أَمْ يَقُولُونَ إِنَّ إِبْرَ؛هِيمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبببَ وَالاَسْبَاطَ كَانُواْ هُوداٗ اَوْ نَصَـٰرۭيٰؐ قُلَ —آنتُمُ; أَعْلَمُ أَمِ ۱للَّهُؐ وَمَنَ اَظْلَمُ مِمَّن كَتَمَ شَهَـٰدَةٗ عِندَهُ„ مِنَ ۰للَّهِؐ وَمَا ۰للَّهُ بِغَـٰفِلٖ عَمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 140, 'تِلْكَ ٱُمَّةٌ قَدْ خَلَــتْؐ لَهَا مَا كَسَبَــتْؐ وَلَكُم مَّا كَسَبْتُمْؐ وَلاَ تُسْـَٔلُونَ عَمَّا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 141, '¤ سَيَقُولُ ۴لسُّفَهَآءُ مِنَ ۰لنَّاسِ مَا وَلّۭيٰهُمْ عَن قِـبْلَتِهِمُ ۴لتِى كَانُواْ عَلَيْهَاؐ قُل لِّلهِ ۱لْمَشْرۣقُ وَالْمَغْرۣبببُؐ يَهْدِى مَنْ يَّشَآءُ ﹹلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 142, 'وَكَذَ؛لِژَ جَعَلْنَــٰكُمُ; ٱُمَّةً وَسَطاًؐ لِّتَكُونُواْ شُهَدَآءَ عَلَي ۰لنَّاسِ وَيَكُونَ ۰لرَّسُولُ عَلَيْكُمْ شَهِيداًؐ وَمَا جَعَلْنَا ۰لْقِبْلَةَ ۰لتِى كُنــتَ عَلَيْهَآ إِلاَّ 22 لِنَعْلَمَ مَنْ يَّتَّبِعُ ۴لرَّسُولَ مِمَّنْ يَّنقَلِــبُ عَلَيٰ عَقِبَيْهِؐ وَإِن كَانَــتْ لَكَبِيرَةٗ اِلاَّ عَلَي ۰لذِينَ هَدَي ۰للَّهُؐ وَمَا كَانَ ۰للَّهُ لِيُضِيعَ إِيمَــٰنَكُمُؐ; إِنَّ ۰للَّهَ بِالنَّاسِ لَرَءُوفٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 143, 'قَدْ نَرۭيٰ تَقَلُّـــبَ وَجْهِكَ فِى ۱لسَّمَآءِ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضۭيٰهَاؐ فَوَلِّ وَجْهَژَ شَطْرَ ۰لْمَسْجِدِ ۱لْحَرَامِؐ وَحَيْــثُ مَا كُنتُمْ فَوَلُّواْ وُجُوهَكُمْ شَطْرَهُؐ„ وَإِنَّ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ لَيَعْلَمُونَ أَنَّهُ ۴لْحَقُّ مِن رَّبِّهِمْؐ وَمَا ۰للَّهُ بِغَـٰفِلٖ عَمَّا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 144, 'وَلَـئِنَ اَتَيْــتَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَـــٰــبَ بِكُلِّ ءَايَةٍ مَّا تَبِعُواْ قِبْلَتَكَؐ وَمَآ أَنــتَ بِتَابِعٍ قِبْلَتَهُمْؐ وَمَا بَعْضُهُم بِتَابِعٍ قِبْلَةَ بَعْضٍؐ وَلَـئِنِ ''تَّبَعْتَ أَهْوَآءَهُم مِّنۢ بَعْدِ مَا جَآءَكَ مِنَ ۰لْعِلْمِ إِنَّژَ إِذاً لَّمِنَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 145, '۰لذِينَ ءَاتَيْنَـٰهُمُ ۴لْكِتَـٰــبَ يَعْرۣفُونَهُ„ كَمَا يَعْرۣفُونَ أَبْنَآءَهُمْؐ وَإِنَّ فَرۣيقاً مِّنْهُمْ لَيَكْتُمُونَ ۰لْحَقَّ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 146, '۰لْحَقُّ مِن رَّبِّكَؐ فَلاَ تَكُونَنَّ مِنَ ۰لْمُمْتَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 147, 'وَلِكُلٍّ وۣجْهَة٘ هُوَ مُوَلِّيهَا فَاسْتَبِقُواْ ۴لْخَيْرَ؛تِؐ أَيْنَ مَا تَكُونُواْ يَاتتتِ بِكُمُ ۴للَّهُ جَمِيعاٗؐ اِنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 148, 'وَمِنْ حَيْــثُ خَرَجْــتَ فَوَلِّ وَجْهَكَ 2 شَطْرَ ۰لْمَسْجِدِ ۱لْحَرَامِؐ وَإِنَّهُ„ لَلْحَقُّ مِن رَّبِّكَؐ وَمَا ۰للَّهُ بِغَــٰفِلٖ عَمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 149, 'وَمِنْ حَيْــثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ۰لْمَسْجِدِ ۱لْحَرَامِؐ وَحَيْــثُ مَا كُنتُمْ فَوَلُّواْ وُجُوهَكُمْ شَطْرَهُ„ لِيَ۬لاَّ يَكُونَ لِلنَّاسِ عَلَيْكُمْ حُجَّة٘ اِلاَّ ۰لذِينَ ظَلَمُواْ مِنْهُمْ فَلاَ تَخْشَوْهُمْ وَاخْشَوْنِىؐ وَلُءِتِمَّ نِعْمَتِى عَلَيْكُمْ وَلَعَلَّكُمْ تَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 150, 'كَمَآ أَرْسَلْنَا فِيكُمْ رَسُولًا مِّنكُمْ يَتْلُواْ عَلَيْكُمُ; ءَايَـٰتِنَا وَيُزَكِّيكُمْ وَيُعَلِّمُكُمُ ۴لْكِتَــٰــبَ وَالْحِكْمَةَ وَيُعَلِّمُكُم مَّا لَمْ تَكُونُواْ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 151, 'فَاذْكُرُونِىٓ أَذْكُرْكُمْ وَاشْكُرُواْ لِى وَلاَ تَكْفُرُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 152, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ èسْتَعِينُواْ بِالصَّبْرۣ وَالصَّلَوٰةِؐ إِنَّ ۰للَّهَ مَعَ ۰لصَّـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 153, 'وَلاَ تَقُولُواْ لِمَنْ يُّقْتَلُ فِى سَبِيلِ ۱للَّهِ أَمْوَ؛تٛؐ بَـلَ اَحْيَآءٌؐ وَچَكِن لاَّ تَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 154, 'وَلَنَبْلُوَنَّكُم بِشَىْءٍ مِّنَ ۰لْخَوْفِ وَالْجُوعِ وَنَقْصٍ مِّنَ ۰لاَمْوَ؛لِ وَالاَنفُسِ وَالثَّمَرَ؛تتتِؐ وَبَشِّرۣ ۱لصَّـٰبِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 155, '۰لذِينَ إِذَآ أَصَـٰبَتْهُم مُّصِيبَةٌ قَالُوٓاْ إِنَّا لِلهِ وَإِنَّآ إِلَيْهِ رَ؛جِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 156, 'ٱُوْلَئِكَ عَلَيْهِمْ صَلَوَ؛تٌ مِّن رَّبِّهِمْ وَرَحْمَةٌؐ وَٱُوْلَئِكَ هُمُ ۴لْمُهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 157, '© إِنَّ ۰لصَّفَا 24 وَالْمَرْوَةَ مِن شَعَــٰٓئِـرۣ ۱للَّهِؐ فَمَنْ حَجَّ ۰لْبَيْــتَ أَوۣ ''عْتَمَرَ فَلاَ جُنَاحَ عَلَيْهِ أَنْ يَّطَّوَّفَ بِهِمَاؐ وَمَن تَطَوَّعَ خَيْراً فَإِنَّ ۰للَّهَ شَاكِر٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 158, 'اِنَّ ۰لذِينَ يَكْتُمُونَ مَآ أَنزَلْنَا مِنَ ۰لْبَيِّنَـٰــتِ وَالْهُدۭيٰ مِنۢ بَعْدِ مَا بَيَّنَّــٰهُ لِلنَّاسِ فِى ۱لْكِتَــٰــبِ ٱُوْلَئِژَ يَلْعَنُهُمُ ۴للَّهُ وَيَلْعَنُهُمُ ۴لچَّعِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 159, 'إِلاَّ ۰لذِينَ تَابُواْ وَأَصْلَحُواْ وَبَيَّنُواْ فَٱُوْلَئِكَ أَتُوبببُ عَلَيْهِمْ وَأَنَا ۰لتَّوَّابببُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 160, 'إِنَّ ۰لذِينَ كَفَرُواْ وَمَاتُواْ وَهُمْ كُفَّار٘ ۷وْلَئِكَ عَلَيْهِمْ لَعْنَةُ ۴للَّهِ وَالْمَلَئِكَةِ وَالنَّاسِ أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 161, 'خَـٰلِدِينَ فِيهَاؐ لاَ يُخَفَّفُ عَنْهُمُ ۴لْعَذَابببُ وَلاَ هُمْ يُنظَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 162, 'وَإِچَهُكُمُ; إِچَهٌ وَ؛حِدٌؐ لٓاَّ إِچَهَ إِلاَّ هُوَؐ ۰لرَّحْمَـٰنُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 163, 'إِنَّ فِى خَلْقِ ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضِ وَاخْتِچَــفِ ۱ليْلِ وَالنَّهۭارۣ وَالْفُلْكِ ۱لتِى تَجْرۣى فِى ۱ڤْبَحْرۣ بِمَا يَنفَعُ ۴لنَّاسَ وَمَآ أَنزَلَ ۰للَّهُ مِنَ ۰لسَّمَآءِ مِن مَّآءٍ فَأَحْيۭا بِهِ ۱لاَرْضَ بَعْدَ مَوْتِهَا وَبَــثَّ فِيهَا مِن كُلِّ دَآبَّةٍ وَتَصْرۣيفِ ۱لرّۣيَـٰحِ وَالسَّحَابببِ ۱لْمُسَخَّرۣ بَيْنَ ۰لسَّمَآءِ وَالاَرْضِ ﺀَلاَيَـٰــتٍ لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 164, 'وَمِنَ ۰لنَّاسِ مَنْ يَّتَّخِذُ مِن دُونِ ۱للَّهِ أَندَاداً يُحِبُّونَهُمْ كَحُبِّ ۱للَّهِؐ وَالذِينَ 25 ءَامَنُوٓاْ أَشَدُّ حُبّاً لِّلهِؐ وَلَوْ تَرَي ۰لذِينَ ظَلَمُوٓاْ إِذْ يَرَوْنَ ۰لْعَذَابببَ أَنَّ ۰لْقُوَّةَ لِلهِ جَمِيعاً وَأَنَّ ۰للَّهَ شَدِيدُ ۴لْعَذَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 165, 'إِذْ تَبَرَّأَ ۰لذِينَ ۸تُّبِعُواْ مِنَ ۰لذِينَ "تَّبَعُواْ وَرَأَوُاْ ۴لْعَذَابببَ وَتَقَطَّعَــتْ بِهِمُ ۴لاَسْبَــٰــبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 166, 'وَقَالَ ۰لذِينَ "تَّبَعُواْ لَوَ اَنَّ لَنَا كَرَّةً فَنَتَبَرَّأَ مِنْهُمْ كَمَا تَبَرَّءُواْ مِنَّاؐ كَذَ؛لِكَ يُرۣيهِمُ ۴للَّهُ أَعْمَــٰلَهُمْ حَسَرَ؛تتتٖ عَلَيْهِمْؐ وَمَا هُم بِخَـٰرۣجِينَ مِنَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 167, 'يَـٰٓأَيُّهَا ۰لنَّاسُ كُلُواْ مِمَّا فِى ۱لاَرْضِ حَچَلًا طَيِّباًؐ وَلاَ تَتَّبِعُواْ خُطْوَ؛تِ ۱لشَّيْطَـٰنِؐ إِنَّهُ„ لَكُمْ عَدُوٌّ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 168, 'اِنَّمَا يَامُرُكُم بِالسُّوٓءِ وَاڤْفَحْشَآءِ وَأَن تَقُولُواْ عَلَي ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 169, 'وَإِذَا قِيلَ لَهُمُ èتَّبِعُواْ مَآ أَنزَلَ ۰للَّهُ قَالُواْ بَلْ نَتَّبِعُ مَآ أَلْفَيْنَا عَلَيْهِ ءَابَآءَنَآؐ أَوَلَوْ كَانَ ءَابَآؤُهُمْ لاَ يَعْقِلُونَ شَيْــٔـاً وَلاَ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 170, 'وَمَثَلُ ۴لذِينَ كَفَرُواْ كَمَثَلِ ۱ﻟ﮲ يَنْعِقُ بِمَا لاَ يَسْمَعُ إِلاَّ دُعَآءً وَنِدَآءًؐ صُمّٛ بُكْم٘ عُمْـيٌ فَهُمْ لاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 171, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ كُلُواْ مِن طَيِّبَـٰــتِ مَا رَزَقْنَـٰكُمْ وَاشْكُرُواْ لِلهِ إِن كُنتُمُ; إِيَّاهُ تَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 172, 'إِنَّمَا حَرَّمَ عَلَيْكُمُ ۴لْمَيْتَةَ وَالدَّمَ وَلَحْمَ ۰لْخِنزۣيـرۣ 26 وَمَآ ٱُهِلَّ بِهِ” لِغَيْرۣ ۱للَّهِؐ فَمَنُ ۶ضْطُرَّ غَيْرَ بَاغٍ وَلاَ عَادٍ فَلآَ إِثْمَ عَلَيْهِؐ إِنَّ ۰للَّهَ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 173, 'اِنَّ ۰لذِينَ يَكْتُمُونَ مَآ أَنزَلَ ۰للَّهُ مِنَ ۰لْكِتَـٰــبِ وَيَشْتَرُونَ بِهِ” ثَمَناً قَلِيلٗا ۷وْلَئِكَ مَا يَاكُلُونَ فِى بُطُونِهِمُ; إِلاَّ ۰لنَّارَ وَلاَ يُكَلِّمُهُمُ ۴للَّهُ يَوْمَ ۰لْقِيَـٰمَةِ وَلاَ يُزَكِّيهِمْؐ وَلَهُمْ عَذَاب٘ اَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 174, '۷وْلَئِژَ ۰لذِينَ "شْتَرَوُاْ ۴لضَّچَلَةَ بِالْهُدۭيٰ وَالْعَذَابببَ بِالْمَغْفِرَةِ فَمَآ أَصْبَرَهُمْ عَلَي ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 175, 'ذَ؛لِكَ بِأَنننَّ ۰للَّهَ نَزَّلَ ۰لْكِتَـٰــبَ بِالْحَقﱢّؐ وَإِنَّ ۰لذِينَ "خْتَلَفُواْ فِى ۱لْكِتَـٰــبِ لَفِى شِقَاقٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 176, '¥ لَّيْسَ ۰لْبِرُّ أَن تُوَلُّواْ وُجُوهَكُمْ قِبَلَ ۰لْمَشْرۣقِ وَالْمَغْرۣبببِؐ وَچَكِنِ ۱لْبِرُّ مَنَ —امَنَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَالْمَلَئِكَةِ وَالْكِتَــٰــبِ وَالنَّبِيٓــٕـﯧنَ وَءَاتَي ۰لْمَالَ عَلَيٰ حُبِّهِ” ذَوۣى ۱لْقُرْبۭيٰ وَالْيَتَـٰمۭيٰ وَالْمَسَـٰكِينَ وَابْنَ ۰لسَّبِيلِ وَالسَّآئِـلِينَ وَفِى ۱لرّۣقَابببِ وَأَقَامَ ۰لصَّلَوٰةَ وَءَاتَي ۰لزَّكَوٰةَؐ وَالْمُوفُونَ بِعَهْدِهِمُ; إِذَا عَـٰهَدُواْؐ وَالصَّـٰبِرۣينَ فِى ۱لْبَأْسَآءِ وَالضَّرَّآءِ وَحِيــنَ ۰لْبَأْسِؐ ٱُوْلَئِكَ ۰لذِيــنَ صَدَقُواْؐ وَٱُوْلَئِكَ هُمُ ۴لْمُتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 177, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ كُتِبَ عَلَيْكُمُ 27 ۴لْقِصَاصُ فِى ۱لْقَتْلَيؐ ۰لْحُرُّ بِالْحُرّۣ وَالْعَبْدُ بِالْعَبْدِ وَالاُنثۭيٰ بِالاُنثۭيٰؐ فَمَــنْ عُفِيَ لَهُ„ مِنَ اَخِيهِ شَىْءٌ فَاتِّبَاعٛ بِالْمَعْرُوفِ وَأَدَآء٘ اِلَيْهِ بِإِحْسَـٰنٍؐ ذَ؛لِكَ تَخْفِيفٌ مِّن رَّبِّكُمْ وَرَحْمَةٌؐ فَمَنِ ''عْتَدۭيٰ بَعْدَ ذَ؛لِژَ فَلَهُ„ عَذَاببب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 178, 'وَلَكُمْ فِى ۱لْقِصَاصِ حَيَوٰةٌ يَـٰٓٱُوْلِى ۱لاَلْبَــٰــبِ لَعَلَّكُمْ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 179, 'كُتِــبَ عَلَيْكُمُ; إِذَا حَضَرَ أَحَدَكُمُ ۴لْمَوْتتتُ إِن تَرَكَ خَيْراٗؐ ۱لْوَصِيَّةُ لِلْوَ؛لِدَيْنِ وَ الاَقْرَبِينَ بِالْمَعْرُوفِؐ حَقّاٗ عَلَي ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 180, 'فَمَنۢ بَدَّلَهُ„ بَعْدَ مَا سَمِعَهُ„ فَإِنَّمَآ إِثْمُهُ„ عَلَي ۰لذِينَ يُبَدِّلُونَهُؐ; إِنَّ ۰للَّهَ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 181, 'فَمَنْ خَافَ مِن مُّوصٍ جَنَفاٗ اَوۣ اِثْماً فَأَصْلَحَ بَيْنَهُمْ فَلآَ إِثْمَ عَلَيْهِؐ إِنَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 182, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ كُتِــبَ عَلَيْكُمُ ۴لصِّيَامُ كَمَا كُتِــبَ عَلَي ۰لذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 183, 'أَيَّاماً مَّعْدُودَ؛تٍؐ فَمَــن كَانَ مِنكُم مَّرۣيضاٗ اَوْ عَلَيٰ سَفَرٍ فَعِدَّةٌ مِّنَ اَيَّامٖ ۷خَرَؐ وَعَلَي ۰لذِينَ يُطِيقُونَهُ„ فِدْيَةُ طَعَامِ مَسَـٰكِينَؐ فَمَن تَطَوَّعَ خَيْراً فَهُوَ خَيْرٌ لَّهُؐ„ وَأَن تَصُومُواْ خَيْرٌ لَّكُمُ; إِن كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 184, 'شَهْرُ رَمَضَانَ 28 ۰ﻟـذِىٓ ٱُنزۣلَ فِيهِ ۱لْقُرْءَانُ هُديً لِّلنَّاسِ وَبَيِّنَــٰــتٍ مِّنَ ۰لْهُدۭيٰ وَالْفُرْقَانِؐ فَمَن شَهِدَ مِنكُمُ ۴لشَّهْرَ فَلْيَصُمْهُؐ وَمَن كَانَ مَرۣيضاٗ اَوْ عَلَيٰ سَفَرٍ فَعِدَّةٌ مِّنَ اَيَّامٖ ۷خَرَؐ يُرۣيدُ ۴للَّهُ بِكُمُ ۴لْيُسْرَ وَلاَ يُرۣيدُ بِـكُمُ ۴لْعُسْرَؐ وَلِتُكْمِلُواْ ۴لْعِدَّةَ وَلِتُكَـبِّـرُواْ ۴للَّهَ عَلَيٰ مَـــا هَدۭيٰكُمْ وَلَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 185, 'وَإِذَا سَأَلَكَ عِبَادِى عَنِّى فَإِنِّى قَرۣيب٘ؐ ۷جِيــبُ دَعْوَةَ ۰لدَّاعِ“ إِذَا دَعَانِؐ” فَلْيَسْتَجِيبُواْ لِى وَلْيُومِنُواْ بِيَ لَعَلَّهُمْ يَرْشُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 186, 'ٱُحِلَّ لَكُمْ لَيْلَةَ ۰لصِّيَامِ ۱لرَّفَــثُ إِلَيٰ نِسَآئِكُمْؐ هُنَّ لِـبَاسٌ لَّكُمْ وَأَنتُمْ لِبَاسٌ لَّهُنَّؐ عَلِمَ ۰للَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ فَتَابببَ عَلَيْكُمْ وَعَفَا عَنكُمْؐ فَاچَنَ بَـٰشِرُوهُنَّؐ وَابْتَغُواْ مَا كَتَبَ ۰للَّهُ لَكُمْؐ وَكُلُواْ وَاشْرَبُواْ حَتَّيٰ يَتَبَيَّنَ لَكُمُ ۴لْخَيْطُ ۴لاَبْيَضُ مِنَ ۰لْخَيْطِ ۱لاَسْوَدِ مِنَ ۰لْفَجْـرۣؐ ثُمَّ أَتِمُّواْ ۴لصِّيَامَ إِلَي ۰ليْلِؐ وَلاَ تُبَــٰشِرُوهُنَّ وَأَنتُمْ عَــٰكِفُونَ فِى ۱لْمَسَـٰجِدِؐ تِلْكَ حُدُودُ ۴للَّهِؐ فَلاَ تَقْرَبُوهَاؐ كَذَ؛لِكَ يُبَيِّنُ ۴للَّهُ ءَايَـٰتِهِ” لِلنَّاسِ لَعَلَّهُمْ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 187, 'وَلاَ تَاكُلُوٓاْ أَمْوَ؛لَكُم بَيْنَكُم بِالْبَــٰطِلِ وَتُدْلُواْ بِهَآ إِلَي ۰لْحُكَّامِ لِتَاكُلُواْ فَرۣيقاً مِّنَ اَمْوَ؛لِ 29 ۱لنَّاسِ بِالِاثْمِ وَأَنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 188, '© يَسْـَٔلُونَكَ عَنِ ۱لاَهِلَّةِؐ قُلْ هِيَ مَوَ؛قِيــتُ لِلنَّاسِ وَالْحَجﱢّؐ وَلَيْسَ ۰لْـبِرُّ بِأَن تَاتُواْ ۴لْبُيُوتتتَ مِن ظُهُورۣهَاؐ وَچَكِنِ ۱لْبِرُّ مَنِ ''تَّقۭيٰؐ وَاتُواْ ۴لْبُيُوتتتَ مِنَ اَبْوَ؛بِهَاؐ وَاتَّقُواْ ۴للَّهَ لَعَلَّكُمْ تُفْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 189, 'وَقَـٰتِلُواْ فِى سَبِيلِ ۱للَّهِ ۱لذِينَ يُقَــٰتِلُونَكُمْ وَلاَ تَعْتَدُوٓاْؐ إِنَّ ۰للَّهَ لاَ يُحِــبُّ ۴لْمُعْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 190, 'وَاقْتُلُوهُمْ حَيْــثُ ثَقِفْتُمُوهُمْ وَأَخْرۣجُوهُم مِّنْ حَيْــثُ أَخْرَجُوكُمْؐ وَالْفِتْنَةُ أَشَدُّ مِنَ ۰لْقَتْلِؐ وَلاَ تُقَــٰتِلُوهُمْ عِندَ ۰لْمَسْجِدِ ۱لْحَرَامِ حَتَّيٰ يُقَـٰتِلُوكُمْ فِيهِؐ فَإِن قَـٰتَلُوكُمْ فَاقْتُلُوهُمْؐ كَذَ؛لِژَ جَزَآءُ ۴لْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 191, 'فَإِنِ ''نتَهَوْاْ فَإِنَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 192, 'وَقَـٰتِلُوهُمْ حَتَّــيٰ لاَ تَكُونَ فِتْنَةٌ وَيَكُونَ ۰لدِّينُ لِلهِؐ فَإِنِ ''نتَهَوْاْ فَلاَ عُدْوَ؛نَ إِلاَّ عَلَي ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 193, '۰لشَّهْرُ ۴لْحَرَامُ بِالشَّهْرۣ ۱لْحَرَامِ وَالْحُرُمَــٰــتُ قِصَاصٌؐ فَمَنِ ''عْتَدۭيٰ عَلَيْكُمْ فَاعْتَدُواْ عَلَيْهِ بِمِثْلِ مَا "عْتَدۭيٰ عَلَيْكُمْؐ وَاتَّقُواْ ۴للَّهَ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ مَعَ ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 194, 'وَأَنفِقُواْ فِى سَبِيلِ ۱للَّهِ وَلاَ تُلْقُواْ بِأَيْدِيكُمُ; إِلَي ۰لتَّهْلُكَةِ وَأَحْسِنُوٓاْؐ إِنَّ ۰للَّهَ يُحِــبُّ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 195, 'وَأَتِمُّواْ ۴لْحَجَّ وَالْعُمْرَةَ لِلهِؐ فَإِنُ 0 ۷حْصِرْتُمْ فَمَا "سْتَيْسَرَ مِنَ ۰لْهَدْيِؐ وَلاَ تَحْلِقُواْ رُءُوسَكُمْ حَتَّيٰ يَبْلُغَ ۰لْهَدْيُ مَحِلَّهُؐ„ فَمَن كَانَ مِنكُم مَّرۣيضاٗ اَوْ بِهِ“ أَذيً مِّن رَّأْسِهِ” فَفِدْيَةٌ مِّن صِيَامٖ اَوْ صَدَﻗَﺔٖ اَوْ نُسُكٍؐ فَإِذَآ أَمِنتُمْ فَمَن تَمَتَّعَ بِالْعُمْرَةِ إِلَي ۰لْحَجِّ فَمَا "سْتَيْسَرَ مِنَ ۰لْهَدْيِؐ  فَمَن لَّمْ يَجِدْ فَصِيَامُ ثَـچَثَةِ أَيَّامٍ فِى ۱لْحَجِّ وَسَبْعَةٖ اِذَا رَجَعْتُمْ تِلْكَ عَشَرَةٌ كَامِلَةٌؐ ذَ؛لِكَ لِمَن لَّمْ يَكُنَ اَهْلُهُ„ حَاضِرۣى ۱لْمَسْجِدِ ۱لْحَرَامِؐ وَاتَّقُواْ ۴للَّهَ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 196, '۱لْحَجُّ أَشْهُرٌ مَّعْلُومَــٰــتٌؐ فَمَن فَرَضَ فِيهِنَّ ۰لْحَجَّ فَلاَ رَفَـثَ وَلاَ فُسُوقَ وَلاَ جِدَالَ فِى ۱لْحَجﱢّؐ وَمَا تَفْعَلُواْ مِنْ خَيْرٍ يَعْلَمْهُ ۴للَّهُؐ وَتَزَوَّدُواْؐ فَإِنَّ خَيْرَ ۰لزَّادِ ۱لتَّقْوۭيٰؐ وَاتَّقُونِ يَـٰٓٱُوْلِى ۱لاَلْبَـٰـــبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 197, 'لَيْسَ عَلَيْكُمْ جُنَاح٘ اَن تَـبْتَغُواْ فَضْلًا مِّن رَّبِّكُمْؐ فَإِذَآ أَفَضْتُم مِّنْ عَرَفَــٰــتٍ فَاذْكُرُواْ ۴للَّهَ عِندَ ۰لْمَشْعَرۣ ۱لْحَرَامِؐ وَاذْكُرُوهُ كَمَا هَدۭيٰكُمْ وَإِن كُنتُم مِّن قَبْلِهِ” لَمِنَ ۰لضَّآلِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 198, 'ثُمَّ أَفِيضُواْ مِنْ حَيْــثُ أَفَاضَ ۰لنَّاسُؐ وَاسْتَغْفِرُواْ ۴للَّهَؐ إِنَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 199, 'فَإِذَا قَضَيْتُم مَّنَـٰسِكَكُمْ فَاذْكُرُواْ ۴للَّهَ كَذِكْرۣكُمُ; 1 ءَابَآءَكُمُ; أَوَ اَشَدَّ ذِكْراًؐ فَمِنَ ۰لنَّاسِ مَنْ يَّقُولُ رَبَّنَآ ءَاتِنَا فِى ۱لدُّنْيۭا وَمَا لَهُ„ فِى ۱لاَخِرَةِ مِنْ خَچَقٍؐ وَمِنْهُم مَّنْ يَّقُولُ رَبَّنَآ ءَاتِنَا فِى ۱لدُّنْيۭا حَسَنَةً وَفِى ۱لاَخِرَةِ حَسَنَةً وَقِنَا عَذَابَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 200, 'ٱُوْلَئِژَ لَهُمْ نَصِيــبٌ مِّمَّا كَسَبُواْؐ وَاللَّهُ سَرۣيعُ ۴لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 201, '¤ وَاذْكُرُواْ ۴للَّهَ فِىٓ أَيَّامٍ مَّعْدُودَ؛تتتٍؐ فَمَن تَعَجَّلَ فِى يَوْمَيْنِ فَلآَ إِثْمَ عَلَيْهِؐ وَمَن تَأَخَّرَ فَلآَ إِثْمَ عَلَيْهِ لِمَنِ ''تَّقۭيٰؐ وَاتَّقُواْ ۴للَّهَ وَاعْلَمُوٓاْ أَنَّكُمُ; إِلَيْهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 202, 'وَمِنَ ۰لنَّاسِ مَنْ يُّعْجِبُژَ قَوْلُهُ„ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَيُشْهِدُ ۴للَّهَ عَلَيٰ مَا فِى قَلْبِهِ” وَهُوَ أَلَدُّ ۴لْخِصَامِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 203, 'وَإِذَا تَوَلّۭيٰ سَعۭيٰ فِى ۱لاَرْضِ لِيُفْسِدَ فِيهَا وَيُهْلِكَ ۰لْحَرْثثثَ وَالنَّسْلَؐ وَاللَّهُ لاَ يُحِبُّ ۴لْفَسَادَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 204, 'وَإِذَا قِيلَ لَهُ èتَّقِ ۱للَّهَ أَخَذَتْهُ ۴لْعِزَّةُ بِالِاثْمِ فَحَسْبُهُ„ جَهَنَّمُؐ وَلَبِيسَ ۰لْمِهَادُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 205, 'وَمِنَ ۰لنَّاسِ مَنْ يَّشْرۣى نَفْسَهُ èبْتِغَآءَ مَرْضَاتتتِ ۱للَّهِؐ وَاللَّهُ رَءُوفٛ بِالْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 206, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ ۶دْخُلُواْ فِى ۱لسَّلْمِ كَآفَّةًؐ وَلاَ تَتَّبِعُواْ خُطْوَ؛تتتِ ۱لشَّيْطَـٰنِؐ إِنَّهُ„ لَكُمْ عَدُوٌّ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 207, 'فَإِن زَلَلْتُم مِّنۢ بَعْدِ مَا جَآءَتْكُمُ 2 ۴لْبَيِّنَــٰــتُ فَاعْلَمُوٓاْ أَنَّ ۰للَّهَ عَزۣيز٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 208, 'هَلْ يَنظُرُونَ إِلٓاَّ أَنْ يَّاتِيَهُمُ ۴للَّهُ فِى ظُلَلٍ مِّنَ ۰لْغَمَـٰمِؐ وَالْمَلَئِكَةُ وَقُضِيَ ۰لاَمْرُؐ وَإِلَي ۰للَّهِ تُرْجَعُ ۴لاُمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 209, 'سَلْ بَنِىٓ إِسْرَآءِيلَ كَمَ —اتَيْنَـٰهُم مِّنَ —ايَةٙ بَيِّنَةٍؐ وَمَنْ يُّبَدِّلْ نِعْمَةَ ۰للَّهِ مِنۢ بَعْدِ مَا جَآءَتْهُ فَإِنَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 210, 'زُيِّنَ لِلذِينَ كَفَرُواْ ۴لْحَيَوٰةُ ۴لدُّنْيۭا وَيَسْخَرُونَ مِنَ ۰لذِينَ ءَامَنُواْؐ وَالذِينَ "تَّقَوْاْ فَوْقَهُمْ يَوْمَ ۰لْقِيَـٰمَةِؐ وَاللَّهُ يَرْزُقُ مَنْ يَّشَآءُ بِغَيْرۣ حِسَابببٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 211, 'كَانَ ۰لنَّاسُ ٱُمَّةً وَ؛حِدَةً فَبَعَــثَ ۰للَّهُ ۴لنَّبِيٓــٕـﯧنَ مُبَشِّرۣينَ وَمُنذِرۣينَ وَأَنزَلَ مَعَهُمُ ۴لْكِتَـٰــبَ بِالْحَقِّ ڤِيَحْكُمَ بَيْنَ ۰لنَّاسِ فِيمَا "خْتَلَفُواْ فِيهِؐ وَمَا "خْتَلَفَ فِيهِ إِلاَّ ۰لذِينَ ٱُوتُوهُؐ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ۴لْبَيِّنَـٰــتُ بَغْياَۢ بَيْنَهُمْؐ فَهَدَي ۰للَّهُ ۴لذِينَ ءَامَنُواْ لِمَا "خْتَلَفُواْ فِيهِ مِنَ ۰لْحَقِّ بِإِذْنِهِؐ” وَاللَّهُ يَهْدِى مَنْ يَّشَآءُ ﹹلَيٰ صِرَ؛طٍ مُّسْتَقِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 212, 'اَمْ حَسِبْتُمُ; أَن تَدْخُلُواْ ۴لْجَنَّةَ وَلَمَّا يَاتِكُم مَّثَلُ ۴لذِينَ خَلَوْاْ مِن قَـبْلِكُم مَّسَّتْهُمُ ۴لْبَأْسَآءُ وَالضَّرَّآءُ وَزُلْزۣلُواْ حَتَّيٰ يَقُولُ ۴لرَّسُولُ وَالذِينَ ءَامَنُواْ مَعَهُ„ مَتۭيٰ نَصْرُ ۴للَّهِؐ أَلآَ إِنَّ نَصْرَ ۰للَّهِ قَرۣيــبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 213, 'يَسْـَٔلُونَكَ مَاذَا يُنفِقُونَؐ قُلْ مَآ أَنفَقْتُم مِّنْ خَيْرٍ فَلِلْوَ؛لِدَيْنِ وَالاَقْرَبِينَ وَالْيَتَـٰمۭيٰ وَالْمَسَـٰكِينِ وَابْنِ ۱لسَّبِيلِؐ وَمَا تَفْعَلُواْ مِنْ خَيْرٍ فَإِنَّ ۰للَّهَ بِهِ” عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 214, 'كُتِــبَ عَلَيْكُمُ ۴لْقِتَالُ وَهُوَ كُرْهٌ لَّكُمْؐ وَعَسۭيٰٓ أَن تَكْرَهُواْ شَيْـٔاً وَهُوَ خَيْرٌ لَّكُمْؐ وَعَسۭيٰٓ أَن تُحِبُّواْ شَيْـٔاً وَهُوَ شَرٌّ لَّكُمْؐ وَاللَّهُ يَعْلَمُؐ وَأَنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 215, 'يَسْـَٔلُونَكَ عَنِ ۱لشَّهْرۣ ۱لْحَرَامِ قِتَالٍ فِيهِؐ قُلْ قِتَالٌ فِيهِ كَبِيرٌؐ وَصَدّﹲ عَن سَبِيلِ ۱للَّهِ وَكُفْرٛ بِهِ” وَالْمَسْجِدِ ۱لْحَرَامِ وَإِخْرَاجُ أَهْلِهِ” مِنْهُ أَكْبَرُ عِندَ ۰للَّهِؐ وَالْفِتْنَةُ أَكْبَرُ مِنَ ۰لْقَتْلِؐ وَلاَ يَزَالُونَ يُقَــٰتِلُونَكُمْ حَتَّيٰ يَرُدُّوكُمْ عَن دِينِكُمُ; إِنِ ''سْتَطَــٰعُواْؐ وَمَنْ يَّرْتَدِدْ مِنكُمْ عَن دِينِهِ” فَيَمُــتْ وَهُوَ كَافِرٌ فَٱُوْلَئِژَ حَبِطَــتَ اَعْمَـٰلُهُمْ فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَٱُوْلَئِژَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَــٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 216, 'إِنَّ ۰لذِينَ ءَامَنُواْ وَالذِينَ هَاجَرُواْ وَجَـٰهَدُواْ فِى سَبِيلِ ۱للَّهِ ٱُوْلَئِژَ يَرْجُونَ رَحْمَتَ ۰للَّهِؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 217, '© يَسْـَٔلُونَژَ عَنِ ۱لْخَمْرۣ وَالْمَيْسِرۣؐ قُلْ فِيهِمَآ إِثْمٌ كَبِيرٌ وَمَنَــٰفِعُ لِلنَّاسِؐ وَإِثْمُهُمَآ أَكْبَرُ مِن نَّفْعِهِمَاؐ وَيَسْـَٔلُونَژَ 4 مَاذَا يُنفِقُونَ قُلِ ۱لْعَفْوَؐ كَذَ؛لِژَ يُبَيِّنُ ۴للَّهُ لَكُمُ ۴لاَيَــٰــتِ لَعَلَّكُمْ تَتَفَكَّرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 218, 'فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَيَسْــَٔلُونَژَ عَنِ ۱لْيَتَــٰمۭيٰ قُلِ اِصْڦَحٌ لَّهُمْ خَيْرٌؐ وَإِن تُخَالِطُوهُمْ فَإِخْوَ؛نُكُمْؐ وَاللَّهُ يَعْلَمُ ۴لْمُفْسِدَ مِنَ ۰ڤْمُصْلِحِؐ وَلَوْ شَآءَ ۰للَّهُ لَأَعْنَتَكُمُؐ; إِنَّ ۰للَّهَ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 219, 'وَلاَ تَنكِحُواْ ۴لْمُشْرۣكَـٰــتِ حَتَّيٰ يُومِنَّؐ وَلَأَمَةٌ مُّومِنَة٘ خَيْرٌ مِّن مُّشْرۣكَةٍ وَلَوَ اَعْجَبَتْكُمْؐ وَلاَ تُنكِحُواْ ۴لْمُشْرۣكِينَ حَتَّيٰ يُومِنُواْؐ وَلَعَبْدٌ مُّومِن٘ خَيْرٌ مِّن مُّشْرۣژٍ وَلَوَ اَعْجَبَكُمُؐ; ٱُوْلَئِژَ يَدْعُونَ إِلَي ۰لنّۭارۣؐ وَاللَّهُ يَدْعُوٓاْ إِلَي ۰لْجَنَّةِ وَالْمَغْفِرَةِ بِإِذْنِهِؐ” وَيُبَيِّنُ ءَايَـٰتِهِ” لِلنَّاسِ لَعَلَّهُمْ يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 220, 'وَيَسْـَٔلُونَژَ عَنِ ۱ڤْمَحِيضِ قُلْ هُوَ أَذيًؐ فَاعْتَزۣلُواْ ۴لنِّسَآءَ فِى ۱ڤْمَحِيضِؐ وَلاَ تَقْرَبُوهُنَّ حَتَّيٰ يَطْهُرْنَؐ فَإِذَا تَطَهَّرْنَ فَاتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمُ ۴للَّهُؐ إِنَّ ۰للَّهَ يُحِــبُّ ۴لتَّوَّ؛بِينَ وَيُحِــبُّ ۴لْمُتَطَهِّرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 221, 'نِسَآؤُكُمْ حَرْثثثٌ لَّكُمْ فَاتُواْ حَرْثَكُمُ; أَنّۭيٰ شِيؔتُمْؐ وَقَدِّمُواْ لَأِنفُسِكُمْؐ وَاتَّقُواْ ۴للَّهَؐ وَاعْلَمُوٓاْ أَنَّكُم مُّچَقُوهُؐ وَبَشِّرۣ ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 222, 'وَلاَ تَجْعَلُواْ ۴للَّهَ عُرْضَةً لَأِّيْمَـٰنِكُمُؐ; أَن تَبَرُّواْ وَتَتَّقُواْ وَتُصْلِحُواْ بَيْنَ 5 ۰لنَّاسِؐ وَاللَّهُ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 223, 'لاَّ يُوَ۬اخِذُكُمُ ۴للَّهُ بِاللَّغْوۣ فِىٓ أَيْمَـٰنِكُمْؐ وَچَكِنْ يُّوَ۬اخِذُكُم بِمَا كَسَبَــتْ قُلُوبُكُمْؐ وَاللَّهُ غَفُور٘ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 224, 'لِّلذِينَ يُولُونَ مِن نِّسَآئِهِمْ تَرَبُّصُ أَرْبَعَةِ أَشْهُرٍؐ فَإِن فَآءُو فَإِنَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 225, 'وَإِنْ عَزَمُواْ ۴لطَّچَقَ فَإِنَّ ۰للَّهَ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 226, 'وَالْمُطَلَّقَـٰتُ يَتَرَبَّصْنَ بِأَنفُسِهِنَّ ثَـچَثَةَ قُرُوٓءٍؐ وَلاَ يَحِلُّ لَهُنَّ أَنْ يَّكْتُمْنَ مَا خَلَقَ ۰للَّهُ فِىٓ أَرْحَامِهِنَّ إِن كُنَّ يُومِنَّ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ وَبُعُولَتُهُنَّ أَحَقُّ بِرَدِّهِنَّ فِى ذَ؛لِكَ إِنَ اَرَادُوٓاْ إِصْڦَحاًؐ وَلَهُنَّ مِثْلُ ۴ﻟ﮲ عَلَيْهِنَّ بِالْمَعْرُوفِؐ وَلِلرّۣجَالِ عَلَيْهِنَّ دَرَجَةٌؐ وَاللَّهُ عَزۣيز٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 227, '۱لطَّچَقُ مَرَّتَـٰنِؐ فَإِمْسَاكٛ بِمَعْرُوفٖ اَوْ تَسْرۣيحٛ بِإِحْسَـٰنٍؐ وَلاَ يَحِلُّ لَكُمُ; أَن تَاخُذُواْ مِمَّآ ءَاتَيْتُمُوهُنَّ شَيْـٔاٗ اِلٓاَّ أَنْ يَّخَافَآ أَلاَّ يُقِيمَا حُدُودَ ۰للَّهِؐ فَإِنْ خِفْتُمُ; أَلاَّ يُقِيمَا حُدُودَ ۰للَّهِ فَلاَ جُنَاحَ عَلَيْهِمَا فِيمَا "فْتَدَتْ بِهِؐ” تِلْكَ حُدُودُ ۴للَّهِؐ فَلاَ تَعْتَدُوهَاؐ وَمَنْ يَّتَعَدَّ حُدُودَ ۰للَّهِ فَٱُوْلَئِكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 228, 'فَإِن طَلَّقَهَا فَلاَ تَحِلُّ لَهُ„ مِنۢ بَعْدُ حَتَّيٰ تَنكِحَ زَوْجاٗ غَيْرَهُؐ„ فَإِن 6 طَلَّقَهَا فَلاَ جُنَاحَ عَلَيْهِمَآ أَنْ يَّتَرَاجَعَآ إِن ظَنَّآ أَنْ يُّقِيمَا حُدُودَ ۰للَّهِؐ وَتِلْكَ حُدُودُ ۴للَّهِ يُبَيِّنُهَا لِقَوْمٍ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 229, 'وَإِذَا طَلَّقْتُمُ ۴لنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٖ اَوْ سَرّۣحُوهُنَّ بِمَعْرُوفٍؐ وَلاَ تُمْسِكُوهُنَّ ضِرَاراً لِّتَعْتَدُواْؐ وَمَنْ يَّفْعَلْ ذَ؛لِكَ فَقَد ظَّلَمَ نَفْسَهُؐ, وَلاَ تَتَّخِذُوٓاْ ءَايَـٰــتِ ۱للَّهِ هُزُؤاًؐ وَاذْكُرُواْ نِعْمَــتَ ۰للَّهِ عَلَيْكُمْ وَمَآ أَنزَلَ عَلَيْكُم مِّنَ ۰لْكِتَــٰــبِ وَالْحِكْمَةِ يَعِظُكُم بِهِؐ” وَاتَّقُواْ ۴للَّهَؐ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ بِكُلِّ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 230, 'وَإِذَا طَلَّقْتُمُ ۴لنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَلاَ تَعْضُلُوهُنَّ أَنْ يَّنكِحْنَ أَزْوَ؛جَهُنَّ إِذَا تَرَ؛ضَوْاْ بَيْنَهُم بِالْمَعْرُوفِؐ ذَ؛لِكَ يُوعَظُ بِهِ” مَـن كَانَ مِنكُمْ يُومِنُ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ ذَ؛لِكُمُ; أَزْكۭيٰ لَكُمْ وَأَطْهَرُؐ وَاللَّهُ يَعْلَمُؐ وَأَنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 231, '¥ وَالْوَ؛لِدَ؛تُ يُرْضِعْنَ أَوْچَدَهُنَّ حَوْلَيْنِ كَامِلَيْنِؐ لِمَنَ اَرَادَ أَنْ يُّتِمَّ ۰لرَّضَـٰعَةَؐ وَعَلَي ۰لْمَوْلُودِ لَهُ„ رۣزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِؐ لاَ تُكَلَّفُ نَفْس٘ اِلاَّ وُسْعَهَاؐ لاَ تُضَآرَّ وَ؛لِدَةٛ بِوَلَدِهَا وَلاَ مَوْلُودٌ لَّهُ„ بِوَلَدِهِؐ” وَعَلَي ۰لْوَارۣثثثِ مِثْلُ ذَ؛لِكَؐ فَإِنَ اَرَادَا فِصَالٗا 7 عَن تَرَاضٍ مِّنْهُمَا وَتَشَاوُرٍ فَلاَ جُنَاحَ عَلَيْهِمَاؐ وَإِنَ اَرَدتُّمُ; أَن تَسْتَرْضِعُوٓاْ أَوْچَدَكُمْ فَلاَ جُنَاحَ عَلَيْكُمُ; إِذَا سَلَّمْتُم مَّآ ءَاتَيْتُم بِالْمَعْرُوفِؐ وَاتَّقُواْ ۴للَّهَؐ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 232, 'وَالذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَ؛جاً يَتَرَبَّصْنَ بِأَنفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْراًؐ فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَلاَ جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ بِالْمَعْرُوفِؐ وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 233, 'وَلاَ جُنَاحَ عَلَيْكُمْ فِيمَا عَرَّضْتُم بِهِ” مِنْ خِطْبَةِ ۱لنِّسَآءِ اَ۬وَ اَكْنَنتُمْ فِىٓ أَنفُسِكُمْؐ عَلِمَ ۰للَّهُ أَنَّكُمْ سَتَذْكُرُونَهُنَّ وَچَكِن لاَّ تُوَاعِدُوهُنَّ سِرّاٗؐ اِلٓاَّ أَن تَقُولُواْ قَوْلًا مَّعْرُوفاًؐ  وَلاَ تَعْزۣمُواْ عُقْدَةَ ۰لنِّكَاحِ حَتَّيٰ يَـبْلُغَ ۰لْكِتَــٰــبُ أَجَلَهُؐ, وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ يَعْلَمُ مَا فِىٓ أَنفُسِكُمْ فَاحْذَرُوهُؐ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ غَفُور٘ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 234, 'لاَّ جُنَاحَ عَلَيْكُمُ; إِن طَلَّقْتُمُ ۴لنِّسَآءَ مَا لَمْ تَمَسُّوهُنَّ أَوْ تَفْرۣضُواْ لَهُنَّ فَرۣيضَةًؐ وَمَتِّعُوهُنَّ عَلَي ۰لْمُوسِعِ قَدْرُهُ„ وَعَلَي ۰لْمُقْتِرۣ قَدْرُهُ„ مَتَــٰعاَۢ بِالْمَعْرُوفِؐ حَقّاٗ عَلَي ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 235, 'وَإِن طَلَّقْتُمُوهُنَّ مِن قَبْلِ أَن تَمَسُّوهُنَّ وَقَدْ فَرَضْتُمْ لَهُنَّ 8 فَرۣيضَةً فَنِصْفُ مَا فَرَضْتُمُ; إِلٓاَّ أَنْ يَّعْفُونَ أَوْ يَعْفُوَاْ ۰ﻟ﮲ بِيَدِهِ” عُقْدَةُ ۴لنِّكَاحِؐ وَأَن تَعْفُوٓاْ أَقْرَبُ لِلتَّقْوۭيٰؐ وَلاَ تَنسَوُاْ ۴لْفَضْلَ بَيْنَكُمُؐ; إِنَّ ۰للَّهَ بِمَا تَعْمَلُونَ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 236, 'حَـٰفِظُواْ عَلَي ۰لصَّلَوَ؛تِ وَالصَّلَوٰةِ ۱لْوُسْطۭيٰ وَقُومُواْ لِلهِ قَــٰنِتِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 237, 'فَـإِنْ خِفْتُمْ فَرۣجَالٗا اَوْرُكْبَاناًؐ فَإِذَآ أَمِنتُمْ فَاذْكُرُواْ ۴للَّهَ كَمَا عَلَّمَكُم مَّا لَمْ تَكُونُواْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 238, 'وَالذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَ؛جاً وَصِيَّةٌ لَأِّزْوَ؛جِهِم مَّتَــٰعاٗ اِلَي ۰لْحَوْلِ غَيْرَ إِخْرَاجٍؐ فَإِنْ خَرَجْنَ فَلاَ جُنَاحَ عَلَيْكُمْ فِى مَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ مِن مَّعْرُوفٍؐ وَاللَّهُ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 239, 'وَلِلْمُطَلَّقَــٰــتِ مَتَــٰعٛ بِالْمَعْرُوفِؐ حَقّاٗ عَلَي ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 240, 'كَذَ؛لِكَ يُبَيِّنُ ۴للَّهُ لَكُمُ; ءَايَــٰتِهِ” لَعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 241, '© أَلَمْ تَرَ إِلَي ۰لذِينَ خَرَجُواْ مِن دِيۭـٰرۣهِمْ وَهُمُ; ٱُلُوف٘ حَذَرَ ۰لْمَوْتتتِ فَقَالَ لَهُمُ ۴للَّهُ مُوتُواْ ثُمَّ أَحْيۭاهُمُؐ’ إِنَّ ۰للَّهَ لَذُو فَضْلٖ عَلَي ۰لنَّاسِؐ وَچَكِنَّ أَكْثَرَ ۰لنَّاسِ لاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 242, 'وَقَــٰتِلُواْ فِى سَبِيـلِ ۱للَّهِ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 243, 'مَّن ذَا ۰ﻟ﮲ يُقْرۣضُ ۴للَّهَ قَرْضاٗ حَسَناً فَيُضَـٰعِفُهُ„ لَهُ; أَضْعَافاً 9 كَثِيرَةًؐ وَاللَّهُ يَقْبِضُ وَيَبْصُطُؐ وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 244, 'أَلَمْ تَرَ إِلَي ۰لْمَلِإَ مِنۢ بَنِىٓ إِسْرَآءِيلَ مِنۢ بَعْدِ مُوسۭيٰٓ إِذْ قَالُواْ لِنَبِىٓءٍ لَّهُمُ èبْعَــثْ لَنَا مَلِكاً نُّقَــٰتِلْ فِى سَبِيلِ ۱للَّهِؐ قَالَ هَلْ عَسِيتُمُ; إِن كُتِــبَ عَلَيْكُمُ ۴لْقِتَالُ أَلاَّ تُقَــٰتِلُواْؐ قَالُواْ وَمَا لَنَآ أَلاَّ نُقَــٰتِلَ فِى سَبِيلِ ۱للَّهِ وَقَدُ ۷خْرۣجْنَا مِن دِيۭـٰرۣنَا وَأَبْنَآئِنَاؐ فَلَمَّا كُتِــبَ عَلَيْهِمُ ۴لْقِتَالُ تَوَلَّوۣاْ اِلاَّ قَلِيلًا مِّنْهُمْؐ وَاللَّهُ عَلِيمٛ بِالظَّــٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 245, 'وَقَالَ لَهُمْ نَبِيٓــُٔهُمُ; إِنَّ ۰للَّهَ قَدْ بَعَــثَ لَكُمْ طَالُوتَ مَلِكاًؐ قَالُوٓاْ أَنّۭيٰ يَكُونُ لَهُ ۴لْمُلْكُ عَلَيْنَا وَنَحْنُ أَحَقُّ بِالْمُلْكِ مِنْهُ وَلَمْ يُوتتتَ سَعَةً مِّنَ ۰لْمَالِؐ قَالَ إِنَّ ۰للَّهَ "صْطَفۭيٰهُ عَلَيْكُمْ وَزَادَهُ„ بَسْطَةً فِى ۱لْعِلْمِ وَالْجِسْمِؐ وَاللَّهُ يُوتِى مُلْكَهُ„ مَنْ يَّشَآءُؐ وَاللَّهُ وَ؛سِع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 246, 'وَقَالَ لَهُمْ نَبِيٓـُٔهُمُ; إِنَّ ءَايَةَ مُلْكِهِ“ أَنْ يَّاتِيَكُمُ ۴لتَّابُوتتتُ فِيهِ سَكِينَةٌ مِّن رَّبِّكُمْ وَبَقِيَّةٌ مِّمَّا تَرَكَ ءَالُ مُوسۭيٰ وَءَالُ هَــٰرُونَ تَحْمِلُهُ ۴لْمَلَئِكَةُؐ إِنَّ فِى ذَ؛لِكَ ءَلاَيَةً لَّكُمُ; إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 247, 'فَلَمَّا فَصَلَ طَالُوتتتُ بِالْجُنُودِ قَالَ إِنَّ ۰للَّهَ مُبْتَلِيكُم بِنَهَرٍ فَمَن شَرۣبببَ مِنْهُ فَلَيْسَ مِنِّى 40 وَمَن لَّمْ يَطْعَمْهُ فَإِنَّهُ„ مِنِّيَ إِلاَّ مَنِ ''غْتَرَفَ غَرْفَةَۢ بِيَدِهِؐ” فَشَرۣبُواْ مِنْهُ إِلاَّ قَلِيلًا مِّنْهُمْؐ فَلَمَّا جَاوَزَهُ„ هُوَ وَالذِينَ ءَامَنُواْ مَعَهُ„ قَالُواْ لاَ طَاقَةَ لَنَا ۰لْيَوْمَ بِجَالُوتتتَ وَجُنُودِهِؐ” قَالَ ۰لذِينَ يَظُنُّونَ أَنَّهُم مُّچَقُواْ ۴للَّهِ كَم مِّن فِيؕةٍ قَلِيلَةٖ غَلَبَتْ فِيؕةً كَثِيرَةَۢ بِإِذْنِ ۱للَّهِؐ وَاللَّهُ مَعَ ۰لصَّــٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 248, 'وَلَمَّا بَرَزُواْ لِجَالُوتتتَ وَجُنُودِهِ” قَالُواْ رَبَّنَآ أَفْرۣغْ عَلَيْنَا صَبْراً وَثَبِّــتَ اَقْدَامَنَا وَانصُرْنَا عَلَي ۰لْقَوْمِ ۱لْكۭـٰفِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 249, 'فَهَزَمُوهُم بِإِذْنِ ۱للَّهِؐ وَقَتَلَ دَاوُﹼدُ جَالُوتتتَ وَءَاتۭيٰهُ ۴للَّهُ ۴لْمُلْژَ وَالْحِكْمَةَ وَعَلَّمَهُ„ مِمَّا يَشَآءُؐ وَلَوْلاَ دِفَــٰعُ ۴للَّهِ ۱لنَّاسَ بَعْضَهُم بِبَعْضٍ لَّفَسَدَتتتِ ۱لاَرْضُؐ وَچَكِنَّ ۰للَّهَ ذُو فَضْلٖ عَلَي ۰لْعَــٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 250, 'تِلْكَ ءَايَـٰــتُ ۴للَّهِ نَتْلُوهَا عَلَيْكَ بِالْحَقﱢّؐ وَإِنَّكَ لَمِنَ ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 251, '¤ تِلْكَ ۰لرُّسُلُؐ فَضَّلْنَا بَعْضَهُمْ عَلَيٰ بَعْضٍؐ مِّنْهُم مَّن كَلَّمَ ۰للَّهُؐ وَرَفَعَ بَعْضَهُمْ دَرَجَــٰــتٍؐ وَءَاتَيْنَا عِيسَي "بْنَ مَرْيَمَ ۰لْبَيِّنَــٰــتِ وَأَيَّدْنَــٰهُ بِرُوحِ ۱لْقُدُسِؐ وَلَوْ شَآءَ ۰للَّهُ مَا "قْتَتَلَ ۰لذِينَ مِنۢ بَعْدِهِم مِّنۢ بَعْدِ مَا جَآءَتْهُمُ ۴لْبَيِّنَـٰــتُؐ وَچَكِنِ ''خْتَلَفُواْؐ 41 فَمِنْهُم مَّنَ —امَنَ وَمِنْهُم مَّن كَفَرَؐ وَلَوْ شَآءَ ۰للَّهُ مَا "قْتَتَلُواْؐ وَچَكِنَّ ۰للَّهَ يَفْعَلُ مَا يُرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 252, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ أَنفِقُواْ مِمَّا رَزَقْنَــٰكُم مِّن قَبْلِ أَنْ يَّاتِيَ يَوْمٌ لاَّ بَيْعٌ فِيهِ وَلاَ خُلَّةٌ وَلاَ شَفَــٰعَةٌؐ وَالْكَـٰفِرُونَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 253, '۰للَّهُ لآَ إِچَهَ إِلاَّ هُوَؐ ۰لْحَيُّ ۴لْقَيُّومُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 254, 'لاَ تَاخُذُهُ„ سِنَةٌ وَلاَ نَوْمٌؐ لَّهُ„ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ مَن ذَا ۰ﻟ﮲ يَشْفَعُ عِندَهُ; إِلاَّ بِإِذْنِهِؐ” يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْؐ وَلاَ يُحِيطُونَ بِشَىْءٍ مِّنْ عِلْمِهِ“ إِلاَّ بِمَا شَآءَؐ وَسِعَ كُرْسِيُّهُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضَؐ وَلاَ يَـُٔودُهُ„ حِفْظُهُمَاؐ وَهُوَ ۰لْعَلِيُّ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 255, 'لآَ إِكْرَاهَ فِى ۱لدِّينِؐ قَد تَّبَيَّنَ ۰لرُّشْدُ مِنَ ۰لْغَيﱢّؐ فَمَنْ يَّكْفُرْ بِالطَّـٰغُوتتتِ وَيُومِنۢ بِاللَّهِ فَقَدِ ''سْتَمْسَكَ بِالْعُرْوَةِ ۱لْوُثْقۭيٰ لاَ "نفِصَامَ لَهَاؐ وَاللَّهُ سَمِيع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 256, '۱للَّهُ وَلِيُّ ۴لذِينَ ءَامَنُواْ يُخْرۣجُهُم مِّنَ ۰لظُّلُمَــٰــتِ إِلَي ۰لنُّورۣؐ وَالذِينَ كَفَرُوٓاْ أَوْلِيَآؤُهُمُ ۴لطَّــٰغُوتتتُ يُخْرۣجُونَهُم مِّنَ ۰لنُّورۣ إِلَي ۰لظُّلُمَــٰــتِؐ ٱُوْلَئِكَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 257, 'أَلَمْ تَرَ إِلَي ۰ﻟ﮲ حَآجَّ إِبْرَ؛هِيمَ فِى رَبِّهِ“ 42 أَنَ —اتۭيٰهُ ۴للَّهُ ۴لْمُلْكَ إِذْ قَالَ إِبْرَ؛هِيمُ رَبِّيَ ۰ﻟ﮲ يُحْىِ” وَيُمِيتُؐ قَالَ أَنَآ ٱُحْىِ” وَٱُمِيــتُؐ قَالَ إِبْرَ؛هِيمُ فَإِنَّ ۰للَّهَ يَاتِى بِالشَّمْسِ مِنَ ۰لْمَشْرۣقِ فَاتتتِ بِهَا مِنَ ۰لْمَغْرۣبِ فَبُهِــتَ ۰ﻟ﮲ كَفَرَؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 258, 'أَوْ كَاﻟ﮲ مَرَّ عَلَيٰ قَرْيَةٍ وَهِيَ خَاوۣيَة٘ عَلَيٰ عُرُوشِهَاؐ قَالَ أَنّۭيٰ يُحْىِ” هَـٰذِهِ ۱للَّهُ بَعْدَ مَوْتِهَا فَأَمَاتَهُ ۴للَّهُ مِاْيؕةَ عَامٍ ثُمَّ بَعَثَهُؐ„ قَالَ كَمْ لَبِثْــتَؐ قَالَ لَبِثْــتُ يَوْماٗ اَوْ بَعْضَ يَوْمٍؐ قَالَ بَل لَّبِثْــتَ مِاْيؕةَ عَامٍؐ فَانظُرۣ اِلَيٰ طَعَامِكَ وَشَرَابِكَ لَمْ يَتَسَنَّهْؐ وَانظُرۣ اِلَيٰ حِمۭارۣكَؐ وَلِنَجْعَلَكَ ءَايَةً لِّلنَّاسِؐ وَانظُرۣ اِلَي ۰لْعِظَـٰمِ كَيْفَ نُنشِرُهَا ثُمَّ نَكْسُوهَا لَحْماًؐ فَلَمَّا تَبَيَّنَ لَهُ„ قَالَ أَعْلَمُ أَنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 259, 'وَإِذْ قَالَ إِبْرَ؛هِيمُ رَبببِّ أَرۣنِى كَيْفَ تُحْىِ ۱لْمَوْتۭيٰؐ قَالَ أَوَلَمْ تُومِنؐ قَالَ بَلۭيٰ وَچَكِن لِّيَطْمَئِنَّ قَلْبِىؐ قَالَ فَخُذَ اَرْبَعَةً مِّنَ ۰لطَّيْرۣ فَصُرْهُنَّ إِلَيْكَ ثُمَّ "جْعَلْ عَلَيٰ كُلِّ جَـبَلٍ مِّنْهُنَّ جُزْءاً ثُمَّ ۸دْعُهُنَّ يَاتِينَكَ سَعْياًؐ وَاعْلَمَ اَنَّ ۰للَّهَ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 260, 'مَّثَلُ ۴لذِينَ يُنفِقُونَ أَمْوَ؛لَهُمْ فِى سَبِيلِ ۱للَّهِ كَمَثَلِ حَبَّةٖ اَنۢبَتَــتْ سَبْعَ سَنَابِلَؐ 4 فِى كُلِّ سُنۢبُلَةٍ مِّاْيؕةُ حَبَّةٍؐ وَاللَّهُ يُضَـٰعِفُ لِمَنْ يَّشَآءُؐ وَاللَّهُ وَ؛سِع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 261, '۱لذِينَ يُنفِقُونَ أَمْوَ؛لَهُمْ فِى سَبِيلِ ۱للَّهِ ثُمَّ لاَ يُتْبِعُونَ مَآ أَنفَقُواْ مَنّاً وَلآَ أَذيً لَّهُمُ; أَجْرُهُمْ عِندَ رَبِّهِمْ وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 262, '© قَوْلٌ مَّعْرُوفٌ وَمَغْفِرَة٘ خَيْرٌ مِّن صَدَقَةٍ يَتْبَعُهَآ أَذيًؐ وَاللَّهُ غَنِيّﹲ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 263, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تُبْطِلُواْ صَدَقَــٰتِكُم بِالْمَنِّ وَالاَذۭيٰ كَاﻟ﮲ يُنفِقُ مَالَهُ„ رۣيؕآءَ ۰لنَّاسِ وَلاَ يُومِنُ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ فَمَثَلُهُ„ كَمَثَلِ صَفْوَانٖ عَلَيْهِ تُرَابببٌ فَأَصَابَهُ„ وَابِلٌ فَتَرَكَهُ„ صَلْداًؐ لاَّ يَقْدِرُونَ عَلَيٰ شَيْءٍ مِّمَّا كَسَبُواْؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 264, 'وَمَثَلُ ۴لذِينَ يُنفِقُونَ أَمْوَ؛لَهُمُ èبْتِغَآءَ مَرْضَاتتتِ ۱للَّهِ وَتَثْبِيتاً مِّنَ اَنفُسِهِمْ كَمَثَلِ جَنَّةٙ بِرُبْوَةٖ اَصَابَهَا وَابِلٌ فَــَٔاتَــتُ ۷كْلَهَا ضِعْفَيْنِ فَـإِن لَّمْ يُصِبْهَا وَابِلٌ فَطَلٌّؐ وَاللَّهُ بِمَا تَعْمَلُونَ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 265, 'اَيَوَدُّ أَحَدُكُمُ; أَن تَكُونَ لَهُ„ جَنَّةٌ مِّن نَّخِيلٍ وَأَعْنَــٰــبٍ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَــٰرُ لَهُ„ فِيهَا مِن كُلِّ ۱لثَّمَرَ؛تتتِ وَأَصَابَهُ ۴لْكِبَرُ وَلَهُ„ ذُرّۣيَّةٌ ضُعَفَآءُ فَأَصَابَهَآ 44 إِعْصَارٌ فِيهِ نَارٌ فَاحْتَرَقَــتْؐ كَذَ؛لِكَ يُبَيِّنُ ۴للَّهُ لَكُمُ ۴لاَيَــٰــتِ لَعَلَّكُمْ تَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 266, 'يَــٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ أَنفِقُواْ مِن طَيِّبَــٰــتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ۰لاَرْضِؐ وَلاَ تَيَمَّمُواْ ۴لْخَبِيــثَ مِنْهُ تُنفِقُونَ وَلَسْتُم بِـَٔاخِذِيهِ إِلٓاَّ أَن تُغْمِضُواْ فِيهِؐ وَاعْلَمُوٓاْ أَنَّ ۰للَّهَ غَنِــيّﹲ حَمِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 267, '۱لشَّيْطَـٰنُ يَعِدُكُمُ ۴لْفَقْرَ وَيَامُرُكُم بِاڤْفَحْشَآءِؐ وَاللَّهُ يَعِدُكُم مَّغْفِرَةً مِّنْهُ وَفَضْلًؐا وَاللَّهُ وَ؛سِع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 268, 'يُوتِى ۱لْحِكْمَةَ مَنْ يَّشَآءُؐ وَمَنْ يُّوتتتَ ۰لْحِكْمَةَ فَقَدُ ۷وتِيَ خَيْراً كَثِيراًؐ وَمَا يَذَّكَّرُ إِلٓاَّ ٱُوْلُواْ ۴لاَلْبَــٰــبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 269, 'وَمَآ أَنفَقْتُم مِّن نَّفَقَةٖ اَوْ نَذَرْتُم مِّن نَّذْرٍ فَإِنَّ ۰للَّهَ يَعْلَمُهُؐ„ وَمَا لِلظَّــٰلِمِينَ مِنَ اَنصۭارٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 270, 'اِن تُبْدُواْ ۴لصَّدَقَــٰــتِ فَنِعِمَّا هِيَؐ وَإِن تُخْفُوهَا وَتُوتُوهَا ۰لْفُقَرَآءَ فَهُوَ خَيْرٌ لَّكُمْ وَنُكَفِّرْ عَنكُم مِّن سَيِّـَٔاتِكُمْؐ وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 271, '¥ لَّيْسَ عَلَيْژَ هُدۭيٰهُمْؐ وَچَكِنَّ ۰للَّهَ يَهْدِى مَنْ يَّشَآءُؐ وَمَا تُنفِقُواْ مِنْ خَيْرٍ فَلَأِنفُسِكُمْؐ وَمَا تُنفِقُونَ إِلاَّ "بْتِغَآءَ وَجْهِ ۱للَّهِؐ وَمَا تُنفِقُواْ مِنْ خَيْرٍ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لاَ تُظْلَمُونَؐ 45');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 272, 'لِلْفُقَرَآءِ ۱لذِينَ ٱُحْصِرُواْ فِى سَبِيلِ ۱للَّهِ لاَ يَسْتَطِيعُونَ ضَرْباً فِى ۱لاَرْضِ يَحْسِبُهُمُ ۴لْجَاهِلُ أَغْنِيَآءَ مِنَ ۰لتَّعَفُّفِؐ تَعْرۣفُهُم بِسِيمۭـٰهُمْ لاَ يَسْــَٔلُونَ ۰لنَّاسَ إِلْحَافاًؐ وَمَا تُنفِقُواْ مِنْ خَيْرٍ فَإِنَّ ۰للَّهَ بِهِ” عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 273, '۱لذِينَ يُنفِقُونَ أَمْوَ؛لَهُم بِاليْلِ وَالنَّهۭارۣ سِرّاً وَ عَچَنِيَةً فَلَهُمُ; أَجْرُهُمْ عِندَ رَبِّهِمْ وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 274, '۰لذِينَ يَاكُلُونَ ۰لرّۣبَوٰاْ لاَ يَقُومُونَ إِلاَّ كَمَا يَقُومُ ۴ﻟ﮲ يَتَخَبَّطُهُ ۴لشَّيْطَـٰنُ مِنَ ۰لْمَسﱢّؐ ذَ؛لِكَ بِأَنَّهُمْ قَالُوٓاْ إِنَّمَا ۰لْبَيْعُ مِثْلُ ۴لرّۣبَوٰاْؐ وَأَحَلَّ ۰للَّهُ ۴لْبَيْعَ وَحَرَّمَ ۰لرّۣبَوٰاْؐ فَمَن جَآءَهُ„ مَوْعِظَةٌ مِّن رَّبِّهِ” فَانتَهۭيٰ فَلَهُ„ مَا سَلَفَؐ وَأَمْرُهُ; إِلَي ۰للَّهِؐ وَمَنْ عَادَ فَٱُوْلَئِكَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَــٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 275, 'يَمْحَقُ ۴للَّهُ ۴لرّۣبَوٰاْ وَيُرْبِى ۱لصَّدَقَــٰــتِؐ وَاللَّهُ لاَ يُحِــبُّ كُلَّ كَفّۭار۫ اَثِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 276, 'اِنَّ ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَــٰــتِ وَأَقَامُواْ ۴لصَّلَوٰةَ وَءَاتَوُاْ ۴لزَّكَوٰةَ لَهُمُ; أَجْرُهُمْ عِندَ رَبِّهِمْ وَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 277, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ وَذَرُواْ مَا بَقِيَ مِنَ ۰لرّۣبَوٰٓاْ إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 278, 'فَإِن لَّمْ تَفْعَلُواْ 46 فَاذَنُواْ بِحَرْبببٍ مِّنَ ۰للَّهِ وَرَسُولِهِؐ” وَإِن تُـبْتُمْ فَلَكُمْ رُءُوسُ أَمْوَ؛لِكُمْ لاَ تَظْلِمُونَ وَلاَ تُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 279, 'وَإِن كَانَ ذُو عُسْرَةٍ فَنَظِرَة٘ اِلَيٰ مَيْسُرَةٍؐ وَأَن تَصَّدَّقُواْ خَيْرٌ لَّكُمُ; إِن كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 280, 'وَاتَّقُواْ يَوْماً تُرْجَعُونَ فِيهِ إِلَي ۰للَّهِؐ ثُمَّ تُوَفّۭيٰ كُلُّ نَفْسٍ مَّاكَسَبَــتْ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 281, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ إِذَا تَدَايَنتُم بِدَيْنٖ اِلَيٰٓ أَجَلٍ مُّسَمّيً فَاكْتُبُوهُؐ وَلْيَكْتُــب بَّيْنَكُمْ كَاتِبٛ بِالْعَدْلِؐ وَلاَ يَابببَ كَاتِب٘ اَنْ يَّكْتُــبَؐ كَمَا عَلَّمَهُ ۴للَّهُ فَلْيَكْتُــبْؐ وَلْيُمْلِلِ ۱ﻟ﮲ عَلَيْهِ ۱لْحَقُّ وَلْيَتَّقِ ۱للَّهَ رَبَّهُ„ وَلاَ يَبْخَسْ مِنْهُ شَيْـٔاًؐ فَإِن كَانَ ۰ﻟ﮲ عَلَيْهِ ۱لْحَقُّ سَفِيهاٗ اَوْ ضَعِيفاٗ اَوْ لاَ يَسْتَطِيعُ أَنْ يُّمِلَّ هُوَ فَلْيُمْلِلْ وَلِيُّهُ„ بِالْعَدْلِؐ وَاسْتَشْهِدُواْ شَهِيدَيْنِ مِن رّۣجَالِكُمْؐ فَإِن لَّمْ يَكُونَا رَجُلَيْنِ فَرَجُلٌ وَامْرَأَتَـٰنِ مِمَّن تَرْضَوْنَ مِنَ ۰لشُّهَدَآءِ اَ۬ن تَضِلَّ إِحْدۭيٰهُمَا فَتُذَكِّرَ إِحْدۭيٰهُمَا ۰لاُخْرۭيٰؐ وَلاَ يَابَ ۰لشُّهَدَآءُ ﹹذَا مَا دُعُواْؐ وَلاَ تَسْــَٔـمُوٓاْ أَن تَكْتُبُوهُ صَغِيراٗ اَوْ كَبِيراٗ اِلَيٰٓ أَجَلِهِؐ” ذَ؛لِكُمُ; أَقْسَطُ عِندَ ۰للَّهِ وَأَقْوَمُ لِلشَّهَـٰدَةِ وَأَدْنۭيٰٓ أَلاَّ تَرْتَابُوٓاْ إِلٓاَّ أَن تَكُونَ تِجَــٰرَة٘ 47 حَاضِرَةٌ تُدِيرُونَهَا بَيْنَكُمْ فَلَيْسَ عَلَيْكُمْ جُنَاح٘ اَلاَّ تَكْتُبُوهَاؐ وَأَشْهِدُوٓاْ إِذَا تَبَايَعْتُمْؐ وَلاَ يُضَآرَّ كَاتِــبٌ وَلاَ شَهِيدٌؐ وَإِن تَفْعَلُواْ فَإِنَّهُ„ فُسُوقٛ بِكُمْؐ وَاتَّقُواْ ۴للَّهَؐ وَيُعَلِّمُكُمُ ۴للَّهُؐ وَاللَّهُ بِكُلِّ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 282, '© وَإِن كُنتُمْ عَلَيٰ سَفَرٍ وَلَمْ تَجِدُواْ كَاتِباً فَرۣهَـٰنٌ مَّقْبُوضَةٌؐ فَإِنَ اَمِنَ بَعْضُكُم بَعْضاً فَلْيُوَ۬دِّ ۱ﻟ﮲ ۹وتُمِنَ أَمَـٰنَتَهُؐ„ وَلْيَتَّقِ ۱للَّهَ رَبَّهُؐ„ وَلاَ تَكْتُمُواْ ۴لشَّهَــٰدَةَؐ وَمَنْ يَّكْتُمْهَا فَإِنَّهُ; ءَاثِمٌ قَلْبُهُؐ„ وَاللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 283, 'لِّلهِ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَإِن تُبْدُواْ مَا فِىٓ أَنفُسِكُمُ; أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ۱للَّهُ فَيَغْفِرْ لِمَنْ يَّشَآءُ وَيُعَذِّبببْ مَنْ يَّشَآءُؐ وَاللَّهُ عَلَيٰ كُلِّ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 284, '—امَنَ ۰لرَّسُولُ بِمَآ ٱُنزۣلَ إِلَيْهِ مِن رَّبِّهِ” وَالْمُومِنُونَؐ كُلّﹲ —امَنَ بِاللَّهِ وَمَلَئِكَتِهِ” وَكُتُبِهِ” وَرُسُلِهِؐ” لاَ نُفَرّۣقُ بَيْنَ أَحَدٍ مِّن رُّسُلِهِؐ” وَقَالُواْ سَمِعْنَا وَأَطَعْنَاؐ غُفْرَانَكَ رَبَّنَاؐ وَإِلَيْكَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (2, 285, 'لاَ يُكَلِّفُ ۴للَّهُ نَفْســاٗ اِلاَّ وُسْعَهَاؐ لَهَا مَا كَسَبَــتْؐ وَعَلَيْهَا مَا "كْتَسَبَــتْؐ رَبَّـنَا لاَ تُوَ۬اخِذْنَآ إِن نَّسِينَآ أَوَ اَخْطَأْنَاؐ رَبَّنَا وَلاَ تَحْمِلْ عَلَيْنَآ إِصْراً 48 كَمَا حَمَلْـتَهُ„ عَلَي ۰لذِينَ مِن قَبْلِـنَاؐ رَبَّنَا وَلاَ تُحَمِّلْنَـا مَا لاَ طَاقَةَ لَنَا بِهِؐ” وَاعْفُ عَنَّاؐ وَاغْفِرْ لَنَاؐ وَارْحَمْنَآؐ أَنـتَ مَوْلۭيٰنَا فَانصُرْنَا عَلَي ۰لْقَوْمِ ۱لْكۭـٰفِرۣيـنَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓـم؋ّٓؐ ۰للَّهُ لآَ إِچَهَ إِلاَّ هُوَؐ ۰لْحَيُّ ۴لْقَيُّومُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 2, 'نَزَّلَ عَلَيْكَ ۰لْكِتَــٰــبَ بِالْحَقِّ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِؐ وَأَنزَلَ ۰لتَّوْرۭيٰةَ وَالِانجِيلَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 3, 'مِن قَبْـلُ هُديً لِّلنَّاسِ وَأَنزَلَ ۰لْفُرْقَانَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 4, 'إِنَّ ۰لذِينَ كَفَرُواْ بِـَٔايَــٰــتِ ۱للَّهِ لَهُمْ عَذَابٌ شَدِيدٌؐ وَاللَّهُ عَزۣيزٌ ذُو èنتِقَامٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 5, 'اِنَّ ۰للَّهَ لاَ يَخْفۭيٰ عَلَيْهِ شَىْءٌ فِى ۱لاَرْضِ وَلاَ فِى ۱لسَّمَآءِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 6, 'هُوَ ۰ﻟ﮲ يُصَوّۣرُكُمْ فِى ۱لاَرْحَامِ كَيْفَ يَشَآءُؐ لآَ إِچَهَ إِلاَّ هُوَؐ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 7, 'هُوَ ۰ﻟـذِىٓ أَنزَلَ عَلَيْكَ ۰لْكِتَــٰــبَ مِنْهُؐ ءَايَــٰــتٌ مُّحْكَمَــٰــت٘ هُنَّ ٱُمُّ ۴لْكِتَــٰــبِ وَٱُخَرُ مُتَشَــٰبِهَــٰــتٌؐ فَأَمَّا ۰لذِينَ فِى قُلُوبِهِمْ زَيْغٌ فَيَتَّبِعُونَ مَا تَشَــٰبَهَ مِنْهُ èبْتِغَآءَ ۰لْفِتْنَةِ وَابْتِغَآءَ تَاوۣيلِهِؐ” وَمَا 49 يَعْلَمُ تَاوۣيلَهُ; إِلاَّ ۰للَّهُؐ وَالرَّ؛سِخُونَ فِى ۱لْعِلْمِ يَقُولُونَ ءَامَنَّا بِهِ” كُلٌّ مِّنْ عِندِ رَبِّنَاؐ وَمَا يَذَّكَّرُ إِلٓاَّ ٱُوْلُواْ ۴لاَلْبَــٰــبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 8, 'رَبَّنَا لاَ تُزۣغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَّدُنكَ رَحْمَةٗؐ اِنَّكَ أَنــتَ ۰لْوَهَّابُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 9, 'رَبَّنَآ إِنَّكَ جَامِعُ ۴لنَّاسِ لِيَوْمٍ لاَّ رَيْبَ فِيهِؐ إِنَّ ۰للَّهَ لاَ يُخْلِفُ ۴لْمِيعَادَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 10, 'إِنَّ ۰لذِينَ كَفَرُواْ لَن تُغْنِيَ عَنْهُمُ; أَمْوَ؛لُهُمْ وَلآَ أَوْچَدُهُم مِّنَ ۰للَّهِ شَيْـٔاًؐ وَٱُوْلَئِكَ هُمْ وَقُودُ ۴لنّۭارۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 11, 'كَدَأْبِ ءَالِ فِرْعَوْنَؐ وَالذِينَ مِن قَبْلِهِمْ كَذَّبُواْ بِـَٔايَــٰتِنَا فَأَخَذَهُمُ ۴للَّهُ بِذُنُوبِهِمْؐ وَاللَّهُ شَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 12, 'قُل لِّلذِينَ كَفَرُواْ سَتُغْلَبُونَ وَتُحْشَرُونَ إِلَيٰ جَهَنَّمَؐ وَبِيـسَ ۰لْمِهَادُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 13, 'قَدْ كَانَ لَكُمُ; ءَايَةٌ فِى فِيؕتَيْنِ ''لْتَقَتَاؐ فِيؕةٌ تُقَــٰتِلُ فِى سَبِيـلِ ۱للَّهِ وَٱُخْرۭيٰ كَافِرَةٌ تَرَوْنَهُم مِّثْلَيْهِمْ رَأْيَ ۰لْعَيْنِؐ وَاللَّهُ يُوَ۬يِّدُ بِنَصْرۣهِ” مَنْ يَّشَآءُؐ ﹹنَّ فِى ذَ؛لِكَ لَعِبْرَةً لُءِّوْلِى ۱لاَبْصۭـٰـرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 14, 'زُيِّنَ لِلنَّاسِ حُبُّ ۴لشَّهَوَ؛تتتِ مِنَ ۰لنِّسَآءِ وَالْبَنِينَ وَالْقَنَــٰطِيرۣ ۱لْمُقَنطَرَةِ مِنَ ۰لذَّهَــبِ وَالْفِضَّةِ وَالْخَيْلِ ۱لْمُسَوَّمَةِ وَالاَنْعَــٰمِ وَالْحَرْثِؐ 50 ذَ؛لِژَ مَتَــٰعُ ۴لْحَـيَـوٰةِ ۱لدُّنْـيۭـاؐ وَاللَّهُ عِندَهُ„ حُسْنُ ۴لْمَــَٔـابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 15, '¤ قُلَ اَوْ°نَبِّيؖكُم بِخَيْرٍ مِّن ذَ؛لِكُمْؐ لِلذِينَ "تَّقَوْاْ عِندَ رَبِّهِمْ جَنَّــٰـــتٌ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَــٰرُ خَــٰلِدِينَ فِيهَا وَأَزْوَ؛جٌ مُّطَهَّرَةٌ وَرۣضْوَ؛نٌ مِّنَ ۰للَّهِؐ وَاللَّهُ بَصِيرٛ بِالْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 16, '۱لذِينَ يَقُولُونَ رَبَّنَآ إِنَّنَآ ءَامَنَّا فَاغْفِرْ لَنَا ذُنُوبَنَا وَقِنَا عَذَابَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 17, '۱لصَّــٰبِرۣينَ وَالصَّــٰدِقِينَ وَالْقَــٰنِتِينَ وَالْمُنفِقِينَ وَالْمُسْتَغْفِـرۣينَ بِالاَسْحۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 18, 'شَهِدَ ۰للَّهُ أَنَّهُ„ لآَ إِچَهَ إِلاَّ هُوَ وَالْمَلَئِكَةُ وَٱُوْلُواْ ۴لْعِلْمِ قَآئِماَۢ بِالْقِسْطِؐ لآَ إِچَهَ إِلاَّ هُوَؐ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 19, 'إِنَّ ۰لدِّينَ عِندَ ۰للَّهِ ۱لِاسْچَمُؐ وَمَا "خْتَلَفَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ إِلاَّ مِنۢ بَعْدِ مَا جَآءَهُمُ ۴لْعِلْمُؐ بَغْياَۢ بَيْنَهُمْؐ وَمَنْ يَّكْفُرْ بِـَٔايَــٰــتِ ۱للَّهِ فَإِنَّ ۰للَّهَ سَرۣيعُ ۴لْحِسَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 20, 'فَإِنْ حَآجُّوكَ فَقُلَ اَسْلَمْــتُ وَجْهِيَ لِلهِ وَمَنِ ''تَّبَعَنِؐ” وَقُل لِّلذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ وَالاُمِّيِّـﯧنَ ءَآسْلَمْتُمْؐ فَإِنَ اَسْلَمُواْ فَقَدِ ''هْتَدَواْؐ وَّإِن تَوَلَّوْاْ فَإِنَّمَا عَلَيْكَ ۰لْبَچَغُؐ وَاللَّهُ بَصِيرٛ بِالْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 21, 'إِنَّ ۰لذِينَ يَكْفُرُونَ بِـَٔايَــٰــتِ ۱للَّهِ وَيَقْتُلُونَ ۰لنَّبِيٓــٕـﯧنَ بِغَيْرۣ حَقٍّ وَيَقْتُلُونَ 51 ۰لذِينَ يَامُرُونَ بِالْقِسْطِ مِنَ ۰لنَّاسِ فَبَشِّرْهُم بِعَذَابٖ اَلِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 22, '۷وْلَئِكَ ۰لذِينَ حَبِطَــتَ اَعْمَـٰلُهُمْ فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَمَا لَهُم مِّن نَّــٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 23, 'أَلَمْ تَرَ إِلَي ۰لذِينَ ٱُوتُواْ نَصِيباً مِّنَ ۰لْكِتَــٰــبِ يُدْعَوْنَ إِلَيٰ كِتَــٰــبِ ۱للَّهِ ڤِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلّۭيٰ فَرۣيقٌ مِّنْهُمْ وَهُم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 24, 'ذَ؛لِكَ بِأَنَّهُمْ قَالُواْ لَن تَمَسَّنَا ۰لنَّارُ إِلٓاَّ أَيَّاماً مَّعْدُودَ؛تتتٍ وَغَرَّهُمْ فِى دِينِهِم مَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 25, 'فَكَيْفَ إِذَا جَمَعْنَــٰهُمْ لِيَوْمٍ لاَّ رَيْــبَ فِيهِ وَوُفِّيَــتْ كُلُّ نَفْسٍ مَّا كَسَبَــتْ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 26, 'قُلِ ۱للَّهُمَّ مَـٰلِكَ ۰لْمُلْكِ تُوتِى ۱لْمُلْكَ مَن تَشَآءُ وَتَنزۣعُ ۴لْمُلْژَ مِمَّن تَشَآءُ وَتُعِزُّ مَن تَشَآءُ وَتُذِلُّ مَن تَشَآءُ بِيَدِكَ ۰لْخَيْرُؐ إِنَّكَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 27, 'تُولِـجُ ۴ليْلَ فِى ۱لنَّهۭارۣ وَتُولِـجُ ۴لنَّهَارَ فِى ۱ليْلِ وَتُخْرۣجُ ۴لْحَيَّ مِنَ ۰لْمَيِّــتِ وَتُخْرۣجُ ۴لْمَيِّــتَ مِنَ ۰لْحَيِّ وَتَرْزُقُ مَن تَشَآءُ بِغَيْرۣ حِسَابببٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 28, 'لاَّ يَتَّخِذِ ۱لْمُومِنُونَ ۰لْكۭـٰفِـرۣينَ أَوْلِيَآءَ مِن دُونِ ۱لْمُومِنِينَؐ وَمَنْ يَّفْعَلْ ذَ؛لِكَ فَلَيْسَ مِنَ ۰للَّهِ فِى شَيْءٖ اِلٓاَّ أَن تَـتَّـقُواْ مِنْهُمْ تُـقۭـيٰةًؐ وَيُحَــذِّرُكُـمُ ۴للَّهُ نَـفْـسَهُؐ, 52 وَإِلَي ۰للَّهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 29, 'قُلِ اِن تُخْفُواْ مَا فِى صُدُورۣكُمُ; أَوْ تُبْدُوهُ يَعْلَمْهُ ۴للَّهُؐ وَيَعْلَمُ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَاللَّهُ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 30, 'يَوْمَ تَجِدُ كُلُّ نَفْسٍ مَّا عَمِلَتْ مِنْ خَيْرٍ مُّحْضَراًؐ وَمَا عَمِلَــتْ مِن سُوٓءٍ تَوَدُّ لَوَ اَنَّ بَيْنَهَا وَبَيْنَهُ; أَمَداَۢ بَعِيداًؐ وَيُحَذِّرُكُمُ ۴للَّهُ نَفْسَهُؐ, وَاللَّهُ رَءُوفٛ بِالْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 31, 'قُلِ اِن كُنتُمْ تُحِبُّونَ ۰للَّهَ فَاتَّبِعُونِى يُحْبِبْكُمُ ۴للَّهُ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 32, 'قُلَ اَطِيعُواْ ۴للَّهَ وَالرَّسُولَؐ فَإِن تَوَلَّوْاْ فَإِنَّ ۰للَّهَ لاَ يُحِــبُّ ۴لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 33, '© إِنَّ ۰للَّهَ "صْطَفۭيٰٓ ءَادَمَ وَنُوحاً وَءَالَ إِبْرَ؛هِيمَ وَءَالَ عِمْرَ؛نَ عَلَي ۰لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 34, 'ذُرّۣيَّةَۢ بَعْضُهَا مِنۢ بَعْضٍؐ وَاللَّهُ سَمِيع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 35, 'اِذْ قَالَــتِ ''مْرَأَتتتُ عِمْرَ؛نَ رَبِّ إِنِّى نَذَرْتُ لَكَ مَا فِى بَطْنِى مُحَرَّراً فَتَقَبَّلْ مِنِّيَؐ إِنَّكَ أَنتَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 36, 'فَلَمَّا وَضَعَتْهَا قَالَــتْ رَبببِّ إِنِّى وَضَعْتُهَآ ٱُنثۭيٰ وَاللَّهُ أَعْلَمُ بِمَا وَضَعَــتْؐ وَلَيْسَ ۰لذَّكَرُ كَالاُنثۭيٰؐ وَإِنِّى سَمَّيْتُهَا مَرْيَمَؐ وَإِنِّيَ ٱُعِيذُهَا بِكَ وَذُرّۣيَّتَهَا مِنَ ۰لشَّيْطَـٰنِ ۱لرَّجِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 37, 'فَتَقَبَّلَهَا 5 رَبُّهَا بِقَبُولٖ حَسَنٍ وَأَنۢبَتَهَا نَبَاتاٗ حَسَناًؐ وَكَفَلَهَا زَكَرۣيَّآءُؐ كُلَّمَا دَخَلَ عَلَيْهَا زَكَرۣيَّآءُ ۴ڤْمِحْرَابببَ وَجَدَ عِندَهَا رۣزْقاًؐ قَالَ يَـٰمَرْيَمُ أَنّۭيٰ لَكِ هَـٰذَاؐ قَالَتْ هُوَ مِنْ عِندِ ۱للَّهِؐ إِنَّ ۰للَّهَ يَرْزُقُ مَنْ يَّشَآءُ بِغَيْرۣ حِسَابببٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 38, 'هُنَالِكَ دَعَا زَكَرۣيَّآءُ رَبَّهُؐ, قَالَ رَبببِّ هَــبْ لِى مِن لَّدُنكَ ذُرّۣيَّةً طَيِّبَةٗ اِنَّكَ سَمِيعُ ۴لدُّعَآءِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 39, 'فَنَادَتْهُ ۴لْمَلَئِكَةُ وَهُوَ قَآئِمٌ يُصَلِّى فِى ۱ڤْمِحْرَابِ أَنَّ ۰للَّهَ يُبَشِّرُكَ بِيَحْيۭيٰ مُصَدِّقاَۢ بِكَلِمَةٍ مِّنَ ۰للَّهِ وَسَيِّداً وَحَصُوراً وَنَبِيٓـــٔاً مِّنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 40, 'قَالَ رَبِّ أَنّۭيٰ يَكُونُ لِى غُچَمٌ وَقَدْ بَلَغَنِيَ ۰لْكِبَرُ وَامْرَأَتِى عَاقِرٌؐ قَالَ كَذَ؛لِكَؐ ۰للَّهُ يَفْعَلُ مَا يَشَآءُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 41, 'قَالَ رَبببِّ ''جْعَل لِّيَ ءَايَةًؐ قَالَ ءَايَتُكَ أَلاَّ تُكَلِّمَ ۰لنَّاسَ ثَـچَثَةَ أَيَّامٖ اِلاَّ رَمْزاًؐ وَاذْكُر رَّبَّكَ كَثِيراً وَسَبِّحْ بِالْعَشِيِّ وَالِابْكۭــٰـرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 42, 'وَإِذْ قَالَــتِ ۱لْمَلَئِكَةُ يَــٰمَرْيَمُ إِنَّ ۰للَّهَ "صْطَفۭيٰكِ وَطَهَّرَكِ وَاصْطَفۭيٰكِ عَلَيٰ نِسَآءِ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 43, 'يَــٰمَرْيَمُ ۶قْنُتِى لِرَبِّكِ وَاسْجُدِى وَارْكَعِى مَعَ ۰لرَّ؛كِعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 44, 'ذَ؛لِژَ مِنَ اَنۢبَآءِ ۱لْغَيْــبِ نُوحِيهِ إِلَيْكَؐ وَمَا كُنــتَ لَدَيْهِمُ; إِذْ يُلْقُونَ 54 أَقْـچَـمَهُمُ; أَيُّهُمْ يَكْفُلُ مَرْيَمَؐ وَمَا كُنــتَ لَدَيْهِمُ; إِذْ يَخْتَصِمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 45, 'إِذْ قَالَــتِ ۱لْمَلَئِكَةُ يَــٰمَرْيَمُ إِنَّ ۰للَّهَ يُبَشِّرُكِ بِكَلِمَةٍ مِّنْهُؐ èسْمُهُ ۴ڤْمَسِيحُ عِيسَي "بْنُ مَرْيَمَ وَجِيهاً فِى ۱لدُّنْيۭا وَالاَخِرَةِ وَمِنَ ۰لْمُقَرَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 46, 'وَيُكَلِّمُ ۴لنَّاسَ فِى ۱لْمَهْدِ وَكَهْلًؐا وَمِنَ ۰ڤصَّـٰڤِحِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 47, 'قَالَتْ رَبببِّ أَنّۭيٰ يَكُونُ لِى وَلَدٌ وَلَمْ يَمْسَسْنِى بَشَرٌؐ قَالَ كَذَ؛لِكِؐ ۱للَّهُ يَخْلُقُ مَا يَشَآءُؐ ﹹذَا قَضۭـيٰٓ أَمْراً فَإِنَّمَا يَقُولُ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 48, 'وَيُعَلِّمُهُ ۴لْكِتَــٰــبَ وَالْحِكْمَةَ وَالتَّوْرۭيٰةَ وَالِانجِيلَ وَرَسُولٗا اِلَيٰ بَنِىٓ إِسْرَآءِيلَ أَنِّى قَدْ جِيؔتُكُم بِـَٔايَةٍ مِّن رَّبِّكُمُؐ; إِنِّيَ أَخْلُقُ لَكُم مِّـنَ ۰لطِّينِ كَهَيْـَٔةِ ۱لطَّيْرۣ فَأَنفُخُ فِيهِ فَيَــكُونُ طَـٰٓئِــراَۢ بِـإِذْنِ ۱للَّهِؐ وَٱُبْــرۣىُٔ ۴لاَكْــمَــهَ وَالاَبْرَصَ وَٱُحْىِ ۱لْمَوْتۭيٰ بِإِذْنِ ۱للَّهِؐ وَٱُنَبِّيؖكُم بِمَا تَاكُلُونَ وَمَا تَدَّخِرُونَ فِى بُيُوتِكُمُؐ; إِنَّ فِى ذَ؛لِكَ ءَلاَيَةً لَّكُمُ; إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 49, 'وَمُصَدِّقاً لِّمَا بَيْنَ يَدَيَّ مِنَ ۰لتَّوْرۭيٰةِ وَ لُءِحِلَّ لَكُم بَعْضَ ۰ﻟ﮲ حُرّۣمَ عَلَيْكُمْؐ وَجِيؔتُكُم بِـــَٔايَةٍ مِّن رَّبِّكُمْؐ فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 50, 'إِنَّ ۰للَّهَ رَبِّى وَرَبُّكُمْ فَاعْبُدُوهُؐ 55 هَـٰذَا صِرَ؛طٌ مُّسْتَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 51, '¥ فَلَمَّآ أَحَسَّ عِيسۭيٰ مِنْهُمُ ۴لْكُفْرَ قَالَ مَنَ اَنصَارۣيَ إِلَي ۰للَّهِؐ قَالَ ۰لْحَوَارۣيُّونَ نَحْنُ أَنصَارُ ۴للَّهِؐ ءَامَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 52, 'رَبَّـنَـآ ءَامَنَّا بِمَــآ أَنزَلْــتَ وَاتَّبَعْنَا ۰لرَّسُولَ فَاكْتُبْنَا مَعَ ۰لشَّـٰهِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 53, 'وَمَكَرُواْ وَمَكَرَ ۰للَّهُؐ وَاللَّهُ خَيْرُ ۴لْمَـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 54, 'إِذْ قَالَ ۰للَّهُ يَـٰعِيسۭيٰٓ إِنِّى مُتَوَفِّيكَ وَرَافِعُكَ إِلَيَّ وَمُطَهِّرُكَ مِنَ ۰لذِينَ كَفَرُواْؐ وَجَاعِلُ ۴لذِينَ "تَّبَعُوكَ فَوْقَ ۰لذِينَ كَفَرُوٓاْ إِلَيٰ يَوْمِ ۱لْقِيَــٰمَةِؐ ثُمَّ إِلَيَّ مَرْجِعُكُمْ فَأَحْكُمُ بَيْنَكُمْ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 55, 'فَأَمَّا ۰لذِينَ كَفَرُواْ فَٱُعَذِّبُهُمْ عَذَاباً شَدِيداً فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَمَا لَهُم مِّن نَّــٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 56, 'وَأَمَّا ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ فَنُوَفِّيهِمُ; ٱُجُورَهُمْؐ وَاللَّهُ لاَ يُحِــبُّ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 57, 'ذَ؛لِكَ نَتْلُوهُ عَلَيْكَ مِنَ ۰لاَيَــٰــتِ وَالذِّكْرۣ ۱لْحَكِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 58, 'إِنَّ مَثَلَ عِيسۭيٰ عِندَ ۰للَّهِ كَمَثَلِ ءَادَمَؐ خَلَقَهُ„ مِن تُرَابببٍ ثُمَّ قَالَ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 59, '۴لْحَقُّ مِن رَّبِّژَؐ فَلاَ تَكُن مِّنَ ۰لْمُمْتَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 60, 'فَمَنْ حَآجَّكَ فِيهِ مِنۢ بَعْدِ مَا جَآءَكَ مِنَ ۰لْعِلْمِ فَقُلْ تَعَالَوْاْ نَدْعُ 56 أَبْنَآءَنَا وَأَبْنَآءَكُمْ وَنِسَآءَنَا وَنِسَآءَكُمْ وَأَنفُسَنَا وَأَنفُسَكُمْ ثُمَّ نَبْتَهِلْ فَنَجْعَل لَّعْنَــتَ ۰للَّهِ عَلَي ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 61, 'إِنَّ هَــٰذَا لَهُوَ ۰لْقَصَصُ ۴لْحَقُّؐ وَمَا مِنِ اِچَهٖ اِلاَّ ۰للَّهُؐ وَإِنَّ ۰للَّهَ لَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 62, 'فَإِن تَوَلَّوْاْ فَإِنَّ ۰للَّهَ عَلِيمٛ بِالْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 63, 'قُلْ يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ تَعَالَوۣاْ اِلَيٰ كَلِمَةٍ سَوَآءٙ بَيْنَنَا وَبَيْنَكُمُ; أَلاَّ نَعْبُدَ إِلاَّ ۰للَّهَ وَلاَ نُشْرۣژَ بِهِ” شَيْـٔاً وَلاَ يَتَّخِذَ بَعْضُنَا بَعْضاٗ اَرْبَاباً مِّن دُونِ ۱للَّهِؐ فَإِن تَوَلَّوْاْ فَقُولُواْ ۵شْهَدُواْ بِأَنَّا مُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 64, 'يَـٰٓأَهْلَ ۰لْكِتَـــٰـــبِ لِمَ تُحَآجُّونَ فِىٓ إِبْرَ؛هِيمَؐ وَمَآ ٱُنزۣلَــتِ ۱لتَّوْرۭيٰةُ وَالِانجِيلُ إِلاَّ مِنۢ بَعْدِهِؐ“ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 65, 'هَآنتُمْ هَـٰٓؤُلآَءِ حَـٰجَجْتُمْ فِيمَا لَكُم بِهِ” عِلْمٌ فَلِمَ تُحَآجُّونَ فِيمَا لَيْسَ لَكُم بِهِ” عِلْمٌؐ وَاللَّهُ يَعْلَمُؐ وَأَنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 66, 'مَا كَانَ إِبْرَ؛هِيمُ يَهُودِيّاً وَلاَ نَصْرَانِيّاً وَچَكِن كَانَ حَنِيفاً مُّسْلِماًؐ وَمَا كَانَ مِنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 67, 'إِنَّ أَوْلَي ۰لنَّاسِ بِإِبْرَ؛هِيمَ لَلذِينَ "تَّبَعُوهُ وَهَـٰذَا ۰لنَّبِىٓءُ وَالذِينَ ءَامَنُواْؐ وَاللَّهُ وَلِيُّ ۴لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 68, 'وَدَّتتت طَّآئِفَةٌ مِّنَ اَهْلِ ۱لْكِتَــٰــبِ لَوْ يُضِلُّونَكُمْؐ 57 وَمَا يُضِلُّونَ إِلٓاَّ أَنفُسَهُمْ وَمَا يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 69, 'يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ لِمَ تَكْفُرُونَ بِـَٔايَــٰــتِ ۱للَّهِ وَأَنتُمْ تَشْهَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 70, 'يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ لِمَ تَلْبِسُونَ ۰لْحَقَّ بِالْبَـٰطِلِ وَتَكْتُمُونَ ۰لْحَقَّ وَأَنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 71, 'وَقَالَــت طَّآئِفَةٌ مِّنَ اَهْلِ ۱لْكِتَـٰــبِ ءَامِنُواْ بِاﻟـذِىٓ ٱُنزۣلَ عَلَي ۰لذِينَ ءَامَنُواْ وَجْهَ ۰لنَّهۭارۣ وَاكْفُرُوٓاْ ءَاخِرَهُ„ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 72, 'وَلاَ تُومِنُوٓاْ إِلاَّ لِمَن تَـبِعَ دِينَكُمْؐ قُلِ اِنَّ ۰لْهُدۭيٰ هُدَي ۰للَّهِ أَنْ يُّوتۭيٰٓ أَحَدٌ مِّثْلَ مَآ ٱُوتِيتُمُ; أَوْ يُحَآجُّوكُمْ عِندَ رَبِّكُمْؐ قُلِ اِنَّ ۰لْفَضْلَ بِيَدِ ۱للَّهِؐ يُوتِيهِ مَنْ يَّشَآءُؐ وَاللَّهُ وَ؛سِع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 73, 'يَخْتَصُّ بِرَحْمَتِهِ” مَنْ يَّشَآءُؐ وَاللَّهُ ذُو ۴لْفَضْلِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 74, '© وَمِنَ اَهْلِ ۱لْكِتَـٰــبِ مَنِ اِن تَامَنْهُ بِقِنطۭارٍ يُوَ۬دِّهِ“ إِلَيْكَؐ وَمِنْهُم مَّنِ اِن تَامَنْهُ بِدِينۭارٍ لاَّ يُوَ۬دِّهِ“ إِلَيْكَ إِلاَّ مَا دُمْــتَ عَلَيْهِ قَآئِماًؐ ذَ؛لِكَ بِأَنَّهُمْ قَالُواْ لَيْسَ عَلَيْنَا فِى ۱لاُمِّيِّـﯧنَ سَبِيلٌؐ وَيَقُولُونَ عَلَي ۰للَّهِ ۱لْكَذِبببَ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 75, 'بَلۭيٰ مَنَ اَوْفۭيٰ بِعَهْدِهِ” وَاتَّقۭيٰ فَإِنَّ ۰للَّهَ يُحِــبُّ ۴لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 76, 'إِنَّ ۰لذِينَ يَشْتَرُونَ بِعَهْدِ ۱للَّهِ وَأَيْمَـٰنِهِمْ ثَمَناً قَلِيلٗا ۷وْلَئِكَ لاَ خَچَقَ لَهُمْ 58 فِى ۱لاَخِرَةِ وَلاَ يُكَلِّمُهُمُ ۴للَّهُ وَلاَ يَنظُرُ إِلَيْهِمْ يَوْمَ ۰لْقِيَــٰمَةِ وَلاَ يُزَكِّيهِمْؐ وَلَهُمْ عَذَاببب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 77, 'وَإِنَّ مِنْهُمْ لَفَرۣيقاً يَلْوُﹼنَ أَلْسِنَتَهُم بِالْكِتَـــٰــبِ ڤِتَحْسِبُوهُ مِنَ ۰لْكِتَــٰــبِ وَمَا هُوَ مِنَ ۰لْكِتَــٰــبِؐ وَيَقُولُونَ هُوَ مِنْ عِندِ ۱للَّهِؐ وَمَا هُوَ مِنْ عِندِ ۱للَّهِؐ وَيَقُولُونَ عَلَي ۰للَّهِ ۱لْكَذِبببَ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 78, 'مَا كَانَ لِبَشَر۫ اَنْ يُّوتِيَهُ ۴للَّهُ ۴لْكِتَــٰــبَ وَالْحُكْمَ وَالنُّبُوٓءَةَ ثُمَّ يَقُولَ لِلنَّاسِ كُونُواْ عِبَاداً لِّى مِن دُونِ ۱للَّهِ وَچَكِن كُونُواْ رَبَّـٰنِيِّـﯧنَ بِمَا كُنتُمْ تَعْلَمُونَ ۰لْكِتَـٰــبَ وَبِمَا كُنتُمْ تَدْرُسُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 79, 'وَلاَ يَامُرُكُمُ; أَن تَتَّخِذُواْ ۴لْمَلَئِكَةَ وَالنَّبِيٓــٕﯧنَ أَرْبَاباٗؐ اَيَامُرُكُم بِالْكُفْرۣ بَعْدَ إِذَ اَنتُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 80, 'وَإِذَ اَخَذَ ۰للَّهُ مِيثَـٰقَ ۰لنَّبِيٓــٕـﯧنَ لَمَآ ءَاتَيْنَــٰكُم مِّن كِتَــٰــبٍ وَحِكْمَةٍ ثُمَّ جَآءَكُمْ رَسُولٌ مُّصَدِّقٌ لِّمَا مَعَكُمْ لَتُومِنُنَّ بِهِ” وَلَتَنصُرُنَّهُؐ,  قَالَ ءَآقْرَرْتُمْ وَأَخَذتُّمْ عَلَيٰ ذَ؛لِكُمُ; إِصْرۣىؐ قَالُوٓاْ أَقْرَرْنَاؐ قَالَ فَاشْهَدُواْ وَأَنَا مَعَكُم مِّنَ ۰لشَّـٰهِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 81, 'فَمَن تَوَلّۭيٰ بَعْدَ ذَ؛لِژَ فَٱُوْلَئِژَ هُمُ ۴لْفَــٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 82, 'أَفَغَيْرَ دِينِ ۱للَّهِ تَبْغُونَ وَلَهُ; أَسْلَمَ مَن فِى 59 ۱لسَّمَــٰوَ؛تتتِ وَالاَرْضِ طَوْعاً وَكَرْهـاًؐ وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 83, 'قُلَ —امَنَّا بِاللَّهِ وَمَآ ٱُنزۣلَ عَلَيْنَا وَمَآ ٱُنزۣلَ عَلَيٰٓ إِبْرَ؛هِيمَ وَإِسْمَــٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبببَ وَالاَسْبَاطِ وَمَآ ٱُوتِيَ مُوسۭيٰ وَعِيسۭيٰ وَالنَّبِيٓــُٔونَ مِن رَّبِّهِمْ لاَ نُفَرّۣقُ بَيْنَ أَحَدٍ مِّنْهُمْ وَنَحْنُ لَهُ„ مُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 84, 'وَمَنْ يَّبْتَغِ غَيْرَ ۰لِاسْچَمِ دِيناً فَلَـنْ يُّقْبَلَ مِنْهُؐ وَهُوَ فِى ۱لاَخِرَةِ مِنَ ۰لْخَــٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 85, 'كَيْفَ يَهْدِى ۱للَّهُ قَوْماً كَفَرُواْ بَعْدَ إِيمَــٰنِهِمْ وَشَهِدُوٓاْ أَنَّ ۰لرَّسُولَ حَقٌّ وَجَآءَهُمُ ۴لْبَيِّنَــٰــتُؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 86, 'ٱُوْلَئِكَ جَزَآؤُهُمُ; أَنَّ عَلَيْهِمْ لَعْنَةَ ۰للَّهِ وَالْمَلَئِكَةِ وَالنَّاسِ أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 87, 'خَـٰلِدِينَ فِيهَا لاَ يُخَفَّفُ عَنْهُمُ ۴لْعَذَابببُ وَلاَ هُمْ يُنظَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 88, 'إِلاَّ ۰لذِينَ تَابُواْ مِنۢ بَعْدِ ذَ؛لِكَ وَأَصْلَحُواْ فَإِنَّ ۰للَّهَ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 89, 'اِنَّ ۰لذِينَ كَفَرُواْ بَعْدَ إِيمَــٰنِهِمْ ثُمَّ "زْدَادُواْ كُفْراً لَّن تُقْبَلَ تَوْبَتُهُمْؐ وَٱُوْلَئِكَ هُمُ ۴لضَّآلُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 90, 'إِنَّ ۰لذِينَ كَفَرُواْ وَمَاتُواْ وَهُمْ كُفَّارٌ فَلَنْ يُّقْبَلَ مِنَ اَحَدِهِم مِّــلْ ﺀُ ۴لاَرْضِ ذَهَباً وَلَوۣ ''فْتَدۭيٰ بِهِؐ“ ٱُوْلَئِژَ لَهُمْ عَذَاببب٘ اَلِيمٌؐ وَمَا لَهُم مِّن نَّـــٰصِرۣينَؐ 60');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 91, '¤ لَن تَنَالُواْ ۴لْبِرَّ حَتَّيٰ تُنفِقُواْ مِمَّا تُحِبُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 92, 'وَمَا تُنفِقُواْ مِن شَيْءٍ فَإِنَّ ۰للَّهَ بِهِ” عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 93, 'كُلُّ ۴لطَّعَامِ كَانَ حِلًاّ لِّبَنِىٓ إِسْرَآءِيلَ إِلاَّ مَا حَرَّمَ إِسْرَآءِيلُ عَلَيٰ نَفْسِهِ” مِن قَبْلِ أَن تُنَزَّلَ ۰لتَّوْرۭيٰةُؐ قُلْ فَاتُواْ بِالتَّوْرۭيٰةِ فَاتْلُوهَآ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 94, 'فَمَنِ ''فْتَرۭيٰ عَلَي ۰للَّهِ ۱لْكَذِبببَ مِنۢ بَعْدِ ذَ؛لِكَ فَٱُوْلَئِكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 95, 'قُلْ صَدَقَ ۰للَّهُؐ فَاتَّبِعُواْ مِلَّةَ إِبْرَ؛هِيمَ حَنِيفاًؐ وَمَا كَانَ مِنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 96, 'إِنَّ أَوَّلَ بَيْــتٍ وُضِعَ لِلنَّاسِ لَلذِى بِبَكَّةَ مُبَــٰرَكاً وَهُديً لِّلْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 97, 'فِيهِ ءَايَــٰــتٛ بَيِّنَــٰــتٌؐ مَّقَامُ إِبْرَ؛هِيمَؐ وَمَن دَخَلَهُ„ كَانَ ءَامِناًؐ وَلِلهِ عَلَي ۰لنَّاسِ حَجُّ ۴لْبَيْــتِ مَنِ ''سْتَطَاعَ إِلَيْهِ سَبِيلًؐاوَمَن كَفَرَ فَإِنَّ ۰للَّهَ غَنِــيّﹲ عَنِ ۱لْعَــٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 98, 'قُلْ يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ لِمَ تَكْفُرُونَ بِـَٔايَــٰــتِ ۱للَّهِ وَاللَّهُ شَهِيد٘ عَلَيٰ مَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 99, 'قُلْ يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ لِمَ تَصُدُّونَ عَن سَبِيلِ ۱للَّهِ مَنَ —امَنَ تَـبْغُونَهَا عِوَجاً وَأَنتُمْ شُهَدَآءُؐ وَمَا ۰للَّهُ بِغَــٰفِلٖ عَمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 100, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ إِن تُطِيعُواْ فَرۣيقاً مِّنَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ يَرُدُّوكُم بَعْدَ إِيمَــٰنِكُمْ كۭــٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 101, '61 وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلۭيٰ عَلَيْكُمُ; ءَايَــٰــتُ ۴للَّهِ وَفِيكُمْ رَسُولُهُؐ, وَمَنْ يَّعْتَصِم بِاللَّهِ فَقَدْ هُدِيَ إِلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 102, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ حَقَّ تُـقۭاتِهِؐ” وَلاَ تَمُوتُنَّ إِلاَّ وَأَنتُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 103, 'وَاعْتَصِمُواْ بِحَبْلِ ۱للَّهِ جَمِيعاًؐ وَلاَ تَفَرَّقُواْؐ وَاذْكُرُواْ نِعْمَــتَ ۰للَّهِ عَلَيْكُمُ; إِذْ كُنتُمُ; أَعْدَآءً فَأَلَّفَ بَيْنَ قُلُوبِكُمْ فَأَصْبَحْتُم بِنِعْمَتِهِ“ إِخْوَ؛ناًؐ وَكُنتُمْ عَلَيٰ شَفَا حُفْرَةٍ مِّنَ ۰لنّۭارۣ فَأَنقَذَكُم مِّنْهَاؐ كَذَ؛لِكَ يُبَيِّنُ ۴للَّهُ لَكُمُ; ءَايَــٰتِهِ” لَعَلَّكُمْ تَـهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 104, 'وَلْتَكُن مِّنكُمُ; ٱُمَّةٌ يَدْعُونَ إِلَي ۰لْخَيْرۣ وَيَامُرُونَ بِالْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ۱لْمُنكَرۣؐ وَٱُوْلَئِكَ هُمُ ۴ڤْمُفْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 105, 'وَلاَ تَكُونُواْ كَالذِينَ تَفَرَّقُواْ وَاخْتَلَفُواْ مِنۢ بَعْدِ مَا جَآءَهُمُ ۴لْبَيِّنَــٰــتُؐ وَٱُوْلَئِژَ لَهُمْ عَذَاببب٘ عَظِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 106, 'يَوْمَ تَبْيَضُّ وُجُوهٌ وَتَسْوَدُّ وُجُوهٌؐ فَأَمَّا ۰لذِينَ "سْوَدَّتتتْ وُجُوهُهُمُ; أَكَفَرْتُم بَعْدَ إِيمَــٰنِكُمْ فَذُوقُواْ ۴لْعَذَابببَ بِمَا كُنتُمْ تَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 107, 'وَأَمَّا ۰لذِينَ "بْيَضَّــتْ وُجُوهُهُمْ فَفِى رَحْمَةِ ۱للَّهِؐ هُمْ فِيهَا خَــٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 108, '62 تِلْكَ ءَايَــٰــتُ ۴للَّهِ نَتْلُوهَا عَلَيْكَ بِالْحَقﱢّؐ وَمَا ۰للَّهُ يُرۣيدُ ظُلْماً لِّلْعَــٰلَمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 109, 'وَلِلهِ مَا فِى ۱لسَّمَــٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَإِلَي ۰للَّهِ تُرْجَعُ ۴لاُمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 110, 'كُنتُمْ خَيْرَ ٱُمَّةٖ ۷خْرۣجَــتْ لِلنَّاسِ تَامُرُونَ بِالْمَعْرُوفِ وَتَنْهَوْنَ عَنِ ۱لْمُنكَرۣ وَتُومِنُونَ بِاللَّهِؐ وَلَوَ —امَنَ أَهْلُ ۴لْكِتَــٰــبِ لَكَانَ خَيْراً لَّهُمؐ مِّنْهُمُ ۴لْمُومِنُونَؐ وَأَكْثَرُهُمُ ۴لْفَــٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 111, 'لَنْ يَّضُرُّوكُمُؐ; إِلٓاَّ أَذيًؐ وَإِنْ يُّقَــٰتِلُوكُمْ يُوَلُّوكُمُ ۴لاَدْبَــٰرَؐ ثُمَّ لاَ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 112, 'ضُرۣبَــتْ عَلَيْهِمُ ۴لذِّلَّةُ أَيْنَ مَا ثُقِفُوٓاْؐ إِلاَّ بِحَبْلٍ مِّنَ ۰للَّهِ وَحَبْلٍ مِّنَ ۰لنَّاسِ وَبَآءُو بِغَضَبٍ مِّنَ ۰للَّهِؐ وَضُرۣبَــتْ عَلَيْهِمُ ۴لْمَسْكَنَةُؐ ذَ؛لِكَ بِأَنَّهُمْ كَانُواْ يَكْفُرُونَ بِـَٔايَــٰــتِ ۱للَّهِ وَيَقْتُلُونَ ۰لاَنۢبِيؕآءَ بِغَيْرۣ حَق؊ّؐ ذَ؛لِكَ بِمَا عَصَواْ وَّكَانُواْ يَعْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 113, '© لَيْسُواْ سَوَآءًؐ مِّنَ اَهْلِ ۱لْكِتَــٰــبِ ٱُمَّةٌ قَآئِمَةٌ يَتْلُونَ ءَايَــٰــتِ ۱للَّهِ ءَانَآءَ ۰ليْلِ وَهُمْ يَسْجُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 114, 'يُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَيَامُرُونَ بِالْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ۱لْمُنكَرۣ وَيُسَــٰرۣعُونَ فِى ۱لْخَيْرَ؛تِؐ وَٱُوْلَئِكَ مِنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 115, 'وَمَا تَفْعَلُواْ مِنْ خَيْرٍ فَلَن تُكْفَرُوهُؐ 6 وَاللَّهُ عَلِيمٛ بِالْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 116, 'إِنَّ ۰لذِينَ كَفَرُواْ لَن تُغْنِيَ عَنْهُمُ; أَمْوَ؛لُهُمْ وَلآَ أَوْچَدُهُم مِّنَ ۰للَّهِ شَيْـٔاًؐ وَٱُوْلَئِژَ أَصْحَــٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 117, 'مَثَلُ مَا يُنفِقُونَ فِى هَـٰذِهِ ۱لْحَيَوٰةِ ۱لدُّنْيۭا كَمَثَلِ رۣيحٍ فِيهَا صِرّﹲ اَصَابَتْ حَرْثَ قَوْمٍ ظَلَمُوٓاْ أَنفُسَهُمْ فَأَهْلَكَتْهُؐ وَمَا ظَلَمَهُمُ ۴للَّهُؐ وَچَكِنَ اَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 118, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَتَّخِذُواْ بِطَانَةً مِّن دُونِكُمْ لاَ يَالُونَكُمْ خَبَالًا وَدُّواْ مَا عَنِتُّمْؐ قَدْ بَدَتِ ۱لْبَغْضَآءُ مِنَ اَفْوَ؛هِهِمْ وَمَا تُخْفِى صُدُورُهُمُ; أَكْبَرُؐ قَدْ بَيَّنَّا لَكُمُ ۴لاَيَــٰــتِ إِن كُنتُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 119, 'هَآنتُمُ; ٱُوْلآَءِ تُحِبُّونَهُمْ وَلاَ يُحِبُّونَكُمْ وَتُومِنُونَ بِالْكِتَــٰــبِ كُلِّهِؐ” وَإِذَا لَقُوكُمْ قَالُوٓاْ ءَامَنَّاؐ وَإِذَا خَلَوْاْ عَضُّواْ عَلَيْكُمُ ۴لاَنَامِلَ مِنَ ۰لْغَيْظِؐ قُلْ مُوتُواْ بِغَيْظِكُمُؐ; إِنَّ ۰للَّهَ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 120, 'إِن تَمْسَسْكُمْ حَسَنَةٌ تَسُؤْهُمْؐ وَإِن تُصِبْكُمْ سَيِّيؕةٌ يَفْرَحُواْ بِهَاؐ وَإِن تَصْبِرُواْ وَتَتَّقُواْ لاَ يَضِرْكُمْ كَيْدُهُمْ شَيْـٔاٗؐ اِنَّ ۰للَّهَ بِمَا يَعْمَلُونَ مُحِيطٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 121, 'وَإِذْ غَدَوْتتتَ مِنَ اَهْلِژَ 64 تُبَوّۣىُٔ ۴لْمُومِنِينَ مَقَــٰعِدَ لِلْقِتَالِؐ وَاللَّهُ سَمِيع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 122, 'اِذْ هَمَّــت طَّآئِفَتَـٰنِ مِنكُمُ; أَن تَفْشَلاَ وَاللَّهُ وَلِيُّهُمَاؐ وَعَلَي ۰للَّهِ فَلْيَتَوَكَّلِ ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 123, 'وَلَقَدْ نَصَرَكُمُ ۴للَّهُ بِبَدْرٍ وَأَنتُمُ; أَذِلَّةٌؐ فَاتَّقُواْ ۴للَّهَ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 124, 'إِذْ تَقُولُ لِلْمُومِنِينَ أَلَـنْ يَّكْفِيَكُمُ; أَنْ يُّمِدَّكُمْ رَبُّكُم بِثَچَثَةِ ءَاچَفٍ مِّنَ ۰لْمَلَئِكَةِ مُنزَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 125, 'بَلۭيٰٓ إِن تَصْبِرُواْ وَتَتَّقُواْ وَيَاتُوكُم مِّن فَوْرۣهِمْ هَـٰذَا يُمْدِدْكُمْ رَبُّكُم بِخَمْسَةِ ءَاچَفٍ مِّنَ ۰لْمَلَئِكَةِ مُسَوَّمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 126, 'وَمَا جَعَلَهُ ۴للَّهُ إِلاَّ بُشْرۭيٰ لَكُمْ وَلِتَطْمَئِنَّ قُلُوبُكُم بِهِؐ” وَمَا ۰لنَّصْرُ إِلاَّ مِنْ عِندِ ۱للَّهِ ۱لْعَزۣيزۣ ۱لْحَكِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 127, 'لِيَقْطَعَ طَرَفاً مِّنَ ۰لذِينَ كَفَرُوٓاْ أَوْ يَكْبِتَهُمْ فَيَنقَلِبُواْ خَآئِبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 128, 'لَيْسَ لَكَ مِـنَ ۰لاَمْرۣ شَىْء٘ اَوْ يَتُوبببَ عَلَيْهِمُ; أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 129, 'وَلِلهِ مَا فِى ۱لسَّمَــٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ يَغْفِرُ لِمَنْ يَّشَآءُ وَيُعَذِّبُ مَنْ يَّشَآءُؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 130, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَاكُلُواْ ۴لرّۣبَوٰٓاْ أَضْعَــٰفاً مُّضَــٰعَفَةًؐ وَاتَّقُواْ ۴للَّهَ لَعَلَّكُمْ تُفْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 131, 'وَاتَّقُواْ ۴لنَّارَ ۰لتِىٓ ٱُعِدَّتْ لِلْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 132, '65 وَأَطِيعُواْ ۴للَّهَ وَالرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 133, '¥ سَارۣعُوٓاْ إِلَيٰ مَغْفِرَةٍ مِّن رَّبِّكُمْ وَجَنَّةٖ عَرْضُهَا ۰لسَّمَــٰوَ؛تتتُ وَالاَرْضُ ٱُعِدَّتتتْ لِلْمُتَّقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 134, '۰لذِينَ يُنفِقُونَ فِى ۱لسَّرَّآءِ وَالضَّرَّآءِ وَالْكَـٰظِمِيـنَ ۰لْغَيْظَ وَالْعَافِيـنَ عَنِ ۱لنَّاسِؐ وَاللَّهُ يُحِــبُّ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 135, 'وَالذِينَ إِذَا فَعَلُواْ فَـٰحِشَةٗ اَوْ ظَلَمُوٓاْ أَنفُسَهُمْ ذَكَرُواْ ۴للَّهَ فَاسْتَغْفَرُواْ لِذُنُوبِهِمْؐ وَمَنْ يَّغْفِرُ ۴لذُّنُوبَ إِلاَّ ۰للَّهُؐ وَلَمْ يُصِرُّواْ عَلَيٰ مَا فَعَلُواْ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 136, 'ٱُوْلَئِژَ جَزَآؤُهُم مَّغْفِرَةٌ مِّن رَّبِّهِمْ وَجَنَّــٰــتٌ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَــٰرُ خَـٰلِدِينَ فِـيهَاؐ وَنِعْمَ أَجْرُ ۴لْعَــٰمِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 137, 'قَدْ خَلَــتْ مِن قَبْلِكُمْ سُنَنٌؐ فَسِيرُواْ فِى ۱لاَرْضِ فَانظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لْمُكَذِّبِـينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 138, 'هَـٰذَا بَيَانٌ لِّلنَّاسِ وَهُديً وَمَوْعِظَةٌ لِّلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 139, 'وَلاَ تَهِنُواْ وَلاَ تَحْزَنُواْ وَأَنتُمُ ۴لاَعْلَوْنَ إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 140, 'إِنْ يَّمْسَسْكُمْ قَرْحٌ فَقَدْ مَسَّ ۰لْقَوْمَ قَرْحٌ مِّثْلُهُؐ, وَتِلْكَ ۰لاَيَّامُ نُدَاوۣلُهَا بَيْنَ ۰لنَّاسِؐ وَلِيَعْلَمَ ۰للَّهُ ۴لذِينَ ءَامَنُواْ وَيَتَّخِذَ مِنكُمْ شُهَـدَآءَؐ وَاللَّهُ لاَ يُحِبُّ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 141, '66 وَڤِيُمَحِّصَ ۰للَّهُ ۴لذِينَ ءَامَنُواْ وَيَمْحَقَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 142, 'أَمْ حَسِبْتُمُ; أَن تَدْخُلُواْ ۴لْجَنَّةَ وَلَمَّا يَعْلَمِ ۱للَّهُ ۴لذِينَ جَــٰهَدُواْ مِنكُمْ وَيَعْلَمَ ۰لصَّــٰبِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 143, 'وَلَقَدْ كُنتُمْ تَمَنَّوْنَ ۰لْمَوْتتتَ مِن قَبْلِ أَن تَلْقَوْهُ فَقَدْ رَأَيْتُمُوهُ وَأَنتُمْ تَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 144, 'وَمَا مُحَمَّد٘ اِلاَّ رَسُولٌ قَدْ خَلَــتْ مِن قَبْلِهِ ۱لرُّسُلُؐ أَفَإِيْن مَّاتتتَ أَوْ قُتِلَ "نقَلَبْتُمْ عَلَيٰٓ أَعْقَــٰبِكُمْؐ وَمَنْ يَّنقَلِبْ عَلَيٰ عَقِبَيْهِ فَلَنْ يَّضُرَّ۰للَّهَ شَيْـــٔـاًؐ وَسَيَجْزۣى ۱للَّهُ ۴لشَّـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 145, 'وَمَا كَانَ لِنَفْس؉ اَن تَمُوتتتَ إِلاَّ بِإِذْنِ ۱للَّهِؐ كِتَــٰباً مُّوَ۬جَّلًؐا وَمَنْ يُّرۣدْ ثَوَابببَ ۰لدُّنْيۭا نُوتِهِ” مِنْهَاؐ وَمَنْ يُّرۣدْ ثَوَابببَ ۰لاَخِرَةِ نُوتِهِ” مِنْهَاؐ وَسَنَجْزۣى ۱لشَّــٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 146, 'وَكَأَيِّن مِّن نَّبِىٓءٍ قُتِلَؐ مَعَهُ„ رۣبِّيُّونَ كَثِيرٌؐ فَمَا وَهَنُواْ لِمَآ أَصَابَهُمْ فِى سَبِيلِ ۱للَّهِ وَمَا ضَعُفُواْ وَمَا "سْتَكَانُواْؐ وَاللَّهُ يُحِبُّ ۴لصَّـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 147, 'وَمَا كَانَ قَوْلَهُمُ; إِلٓاَّ أَن قَالُواْ رَبَّنَــا "غْفِرْ لَنَا ذُنُوبَنَا وَإِسْرَافَنَا فِىٓ أَمْرۣنَا وَثَبِّــتَ اَقْدَامَنَا وَانصُرْنَا عَلَي ۰لْقَوْمِ ۱لْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 148, 'فَــَٔاتۭيٰهُمُ ۴للَّهُ ثَوَابببَ ۰لدُّنْيۭا وَحُسْنَ ثَوَابببِ ۱لاَخِرَةِؐ وَاللَّهُ يُحِبُّ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 149, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ 67 إِن تُطِيعُواْ ۴لذِينَ كَفَرُواْ يَرُدُّوكُمْ عَلَيٰٓ أَعْقَــٰبِكُمْ فَتَنقَلِبُواْ خَــٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 150, 'بَلِ ۱للَّهُ مَوْلۭيٰكُمْؐ وَهُوَ خَيْرُ ۴لنَّــٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 151, 'سَنُلْقِى فِى قُلُوبببِ ۱لذِينَ كَفَرُواْ ۴لرُّعْــبَ بِمَآ أَشْرَكُواْ بِاللَّهِ مَا لَمْ يُنَزّۣلْ بِهِ” سُلْطَـٰناًؐ وَمَأْوۭيٰهُمُ ۴لنَّارُؐ وَبِيسَ مَثْوَي ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 152, 'وَلَقَدْ صَدَقَكُمُ ۴للَّهُ وَعْدَهُ; إِذْ تَحُسُّونَهُم بِإِذْنِهِؐ” حَتَّيٰٓ إِذَا فَشِلْتُمْ وَتَنَــٰزَعْتُمْ فِى ۱لاَمْرۣ وَعَصَيْتُم مِّـنۢ بَعْدِ مَآ أَرۭيٰكُم مَّا تُحِبُّونَؐ مِنكُم مَّنْ يُّرۣيدُ ۴لدُّنْيۭا وَمِنكُم مَّنْ يُّرۣيدُ ۴لاَخِرَةَؐ ثُمَّ صَرَفَكُمْ عَنْهُمْ لِيَبْتَلِيَكُمْؐ وَلَقَدْ عَفَا عَنكُمْؐ وَاللَّهُ ذُو فَضْلٖ عَلَي ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 153, '© إِذْ تُصْعِدُونَ وَلاَ تَلْوُﹼنَ عَلَيٰٓ أَحَدٍ وَالرَّسُولُ يَدْعُوكُمْ فِىٓ ٱُخْرۭيٰكُمْ فَأَثَــٰبَكُمْ غَمّاَۢ بِغَمٍّ لِّكَيْلاَ تَحْزَنُواْ عَلَيٰ مَا فَاتَكُمْ وَلاَ مَآ أَصَـٰبَكُمْؐ وَاللَّهُ خَبِيرٛ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 154, 'ثُمَّ أَنزَلَ عَلَيْكُم مِّنۢ بَعْدِ ۱لْغَمِّ أَمَنَةً نُّعَاساً يَغْشۭيٰ طَآئِفَةً مِّنكُمْؐ وَطَآئِفَةٌ قَدَ اَهَمَّتْهُمُ; أَنفُسُهُمْ يَظُنُّونَ بِاللَّهِ غَيْرَ۰لْحَقِّ ظَنَّ ۰لْجَــٰهِلِيَّةِؐ يَقُولُونَ هَل لَّنَا مِنَ ۰لاَمْرۣ مِن شَيْءٍؐ قُلِ اِنَّ ۰لاَمْرَ كُلَّهُ„ لِلهِؐ يُخْفُونَ فِىٓ أَنفُسِهِم مَّـا 68 لاَ يُبْدُونَ لَكَؐ يَقُولُونَ لَوْ كَانَ لَنَا مِنَ ۰لاَمْرۣ شَىْءٌ مَّا قُتِلْنَا هَــٰهُنَاؐ قُل لَّوْ كُنتُمْ فِى بُيُوتِكُمْ لَبَرَزَ ۰لذِينَ كُتِــبَ عَلَيْهِمُ ۴لْقَتْلُ إِلَيٰ مَضَاجِعِهِمْ وَلِيَبْتَلِيَ ۰للَّهُ مَا فِى صُدُورۣكُمْ وَڤِيُمَحِّصَ مَا فِى قُلُوبِكُمْؐ وَاللَّهُ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 155, 'إِنَّ ۰لذِينَ تَوَلَّوْاْ مِنكُمْ يَوْمَ "لْتَقَي ۰لْجَمْعَـٰنِ إِنَّمَا "سْتَزَلَّهُمُ ۴لشَّيْطَـٰنُ بِبَعْضِ مَا كَسَبُواْؐ وَلَقَدْ عَفَا ۰للَّهُ عَنْهُمُؐ; إِنَّ ۰للَّهَ غَفُور٘ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 156, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَكُونُواْ كَالذِينَ كَفَرُواْ وَقَالُواْ لِإِخْوَ؛نِهِمُ; إِذَا ضَرَبُواْ فِى ۱لاَرْضِ أَوْ كَانُواْ غُزّيً لَّوْ كَانُواْ عِندَنَا مَا مَاتُواْ وَمَا قُتِلُواْ لِيَجْعَلَ ۰للَّهُ ذَ؛لِكَ حَسْرَةً فِى قُلُوبِهِمْؐ وَاللَّهُ يُحْىِ” وَيُمِيتُؐ وَاللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 157, 'وَلَـئِن قُتِلْتُمْ فِى سَبِيلِ ۱للَّهِ أَوْ مِتُّمْ لَمَغْفِرَةٌ مِّنَ ۰للَّهِ وَرَحْمَة٘ خَيْرٌ مِّمَّا تَجْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 158, 'وَلَـئِن مِّتُّمُ; أَوْ قُتِلْتُمْ لِإَ لَي ۰للَّهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 159, 'فَبِمَا رَحْمَةٍ مِّنَ ۰للَّهِ لِنــتَ لَهُمْؐ وَلَوْ كُنــتَ فَظّاٗ غَلِيظَ ۰لْقَلْــبِ لاَنفَضُّواْ مِنْ حَوْلِژَؐ فَاعْفُ عَنْهُمْ وَاسْتَغْفِرْ لَهُمْ وَشَاوۣرْهُمْ فِى ۱لاَمْرۣؐ فَإِذَا عَزَمْــتَ فَتَوَكَّلْ عَلَي ۰للَّهِؐ 69 إِنَّ ۰للَّهَ يُحِــبُّ ۴لْمُتَوَكِّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 160, 'إِنْ يَّنصُرْكُمُ ۴للَّهُ فَلاَ غَالِــبَ لَكُمْؐ وَإِنْ يَّخْذُلْكُمْ فَمَن ذَا ۰ﻟ﮲ يَنصُرُكُم مِّنۢ بَعْدِهِؐ” وَعَلَي ۰للَّهِ فَلْيَتَوَكَّلِ ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 161, 'وَمَا كَانَ لِنَبِىٓءٖ اَنْ يُّغَلَّؐ وَمَنْ يَّغْلُلْ يَاتتتِ بِمَا غَلَّ يَوْمَ ۰لْقِيَــٰمَةِؐ ثُمَّ تُوَفّۭيٰ كُلُّ نَفْسٍ مَّا كَسَبَــتْ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 162, 'أَفَمَنِ ''تَّبَعَ رۣضْوَ؛نَ ۰للَّهِ كَمَنۢ بَـآءَ بِسَخَطٍ مِّنَ ۰للَّهِ وَمَأْوۭيٰهُ جَهَنَّمُؐ وَبِيسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 163, 'هُمْ دَرَجَــٰــت٘ عِندَ ۰للَّهِؐ وَاللَّهُ بَصِيرٛ بِمَا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 164, 'لَقَدْ مَنَّ ۰للَّهُ عَلَي ۰لْمُومِنِينَ إِذْ بَعَــثَ فِيهِمْ رَسُولًا مِّنَ اَنفُسِهِمْ يَتْلُواْ عَلَيْهِمُ; ءَايَــٰتِهِ” وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ۴لْكِتَــٰــبَ وَالْحِكْمَةَ وَإِن كَانُواْ مِن قَـبْلُ لَفِى ضَچَلٍ مُّبِــيـنٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 165, 'اَوَلَمَّآ أَصَــٰبَتْكُم مُّصِيبَةٌ قَدَ اَصَبْتُم مِّثْلَيْهَا قُلْتُمُ; أَنّۭيٰ هَـٰذَاؐ قُلْ هُوَ مِنْ عِندِ أَنفُسِكُمُؐ; إِنَّ ۰للَّهَ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 166, 'وَمَآ أَصَـٰبَكُمْ يَوْمَ "لْتَقَي ۰لْجَمْعَـٰنِ فَبِإِذْنِ ۱للَّهِ وَلِيَعْلَمَ ۰لْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 167, 'وَلِيَعْلَمَ ۰لذِينَ نَافَقُواْؐ وَقِيلَ لَهُمْ تَعَالَوْاْ قَــٰتِلُواْ فِى سَبِيلِ ۱للَّهِ أَوۣ ''دْفَعُواْؐ قَالُواْ لَوْ نَعْلَمُ قِتَالًا لاَّتَّبَعْنَــٰكُمْؐ هُمْ لِلْكُفْرۣ يَوْمَئِـذٖ اَقْرَبببُ 70 مِنْهُمْ لِلِايمَـٰنِؐ يَقُولُونَ بِأَفْوَ؛هِهِم مَّا لَيْسَ فِى قُلُوبِهِمْؐ وَاللَّهُ أَعْلَمُ بِمَا يَكْتُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 168, '۰لذِينَ قَالُواْ لِإِخْوَ؛نِهِمْ وَقَعَدُواْ لَوَ اَطَاعُونَا مَا قُتِلُواْؐ قُلْ فَادْرَءُواْ عَنَ اَنفُسِكُمُ ۴لْمَوْتتتَ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 169, 'وَلاَ تَحْسِبَنَّ ۰لذِينَ قُتِلُواْ فِى سَبِيـلِ ۱للَّهِ أَمْوَ؛تاٚؐ بَلَ اَحْيَآء٘ؐ عِندَ رَبِّهِمْ يُرْزَقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 170, 'فَرۣحِينَ بِمَآ ءَاتۭيٰهُمُ ۴للَّهُ مِن فَضْلِهِ” وَيَسْتَبْشِرُونَ بِالذِينَ لَمْ يَلْحَقُواْ بِهِم مِّنْ خَلْفِهِمُ; أَلاَّ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 171, '¤ يَسْتَبْشِرُونَ بِنِعْمَةٍ مِّنَ ۰للَّهِ وَفَضْلٍ وَأَنَّ ۰للَّهَ لاَ يُضِيعُ أَجْرَ ۰لْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 172, '۰لذِينَ "سْتَجَابُواْ لِلهِ وَالرَّسُولِ مِنۢ بَعْدِ مَآ أَصَابَهُمُ ۴لْقَرْحُؐ لِلذِينَ أَحْسَنُواْ مِنْهُمْ وَاتَّقَوَاْ اَجْر٘ عَظِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 173, '۱لذِينَ قَالَ لَهُمُ ۴لنَّاسُ إِنَّ ۰لنَّاسَ قَدْ جَمَعُواْ لَكُمْ فَاخْشَوْهُمْ فَزَادَهُمُ; إِيمَــٰناًؐ وَقَالُواْ حَسْبُنَا ۰للَّهُ وَنِعْمَ ۰لْوَكِيلُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 174, 'فَانقَلَبُواْ بِنِعْمَةٍ مِّنَ ۰للَّهِ وَفَضْلٍ لَّمْ يَمْسَسْهُمْ سُوٓءٌ وَاتَّبَعُواْ رۣضْوَ؛نَ ۰للَّهِؐ وَاللَّهُ ذُو فَضْلٖ عَظِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 175, 'اِنَّمَا ذَ؛لِكُمُ ۴لشَّيْطَـٰنُ يُخَوّۣفُ أَوْلِيَآءَهُ„ فَلاَ تَخَافُوهُمْؐ 71 وَخَافُونِ إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 176, 'وَلاَ يُحْزۣنژَ ۰لذِينَ يُسَـٰرۣعُونَ فِى ۱لْكُفْرۣؐ إِنَّهُمْ لَنْ يَّضُرُّواْ ۴للَّهَ شَيْـٔاًؐ يُرۣيدُ ۴للَّهُ أَلاَّ يَجْعَلَ لَهُمْ حَظّاً فِى ۱لاَخِرَةِؐ وَلَهُمْ عَذَاب٘ عَظِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 177, 'اِنَّ ۰لذِينَ "شْتَرَوُاْ ۴لْكُفْرَ بِالِايمَـٰنِ لَنْ يَّضُرُّواْ ۴للَّهَ شَيْـٔاًؐ وَلَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 178, 'وَلاَ يَحْسِبَنَّ ۰لذِينَ كَفَرُوٓاْ أَنَّمَا نُمْلِى لَهُمْ خَيْرٌ لَأِّنفُسِهِمُؐ; إِنَّمَا نُمْلِى لَهُمْ لِيَزْدَادُوٓاْ إِثْماًؐ وَلَهُمْ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 179, 'مَّا كَانَ ۰للَّهُ لِيَذَرَ ۰لْمُومِنِينَ عَلَيٰ مَآ أَنتُمْ عَلَيْهِ حَتَّيٰ يَمِيزَ ۰لْخَبِيــثَ مِنَ ۰لطَّيِّــبِؐ وَمَا كَانَ ۰للَّهُ لِيُطْلِعَكُمْ عَلَي ۰لْغَيْــبِؐ وَچَكِنَّ ۰للَّهَ يَجْتَبِى مِن رُّسُلِهِ” مَنْ يَّشَآءُؐ فَــَٔامِنُواْ بِاللَّهِ وَرُسُلِهِؐ” وَإِن تُومِنُواْ وَتَتَّقُواْ فَلَكُمُ; أَجْر٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 180, 'وَلاَ يَحْسِبَنَّ ۰لذِينَ يَبْخَلُونَ بِمَآ ءَاتۭيٰهُمُ ۴للَّهُ مِن فَضْلِهِ” هُوَ خَيْراً لَّهُمؐ بَلْ هُوَ شَرٌّ لَّهُمْؐ سَيُطَوَّقُونَ مَا بَخِلُواْ بِهِ” يَوْمَ ۰لْقِيَــٰمَةِؐ وَلِلهِ مِيرَ؛ثثثُ ۴لسَّمَــٰوَ؛تتتِ وَالاَرْضِؐ وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 181, 'لَّقَدْ سَمِعَ ۰للَّهُ قَوْلَ ۰لذِينَ قَالُوٓاْ إِنَّ ۰للَّهَ فَقِيرٌ وَنَحْنُ أَغْنِيَآءُؐ سَنَكْتُــبُ مَا قَالُواْ وَقَتْلَهُمُ ۴لاَنۢبِيؕآءَ بِغَيْرۣ حَقٍّ 72 وَنَقُولُ ذُوقُواْ عَذَابَ ۰لْحَرۣيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 182, 'ذَ؛لِژَ بِمَا قَدَّمَــتَ اَيْدِيكُمْ وَأَنَّ ۰للَّهَ لَيْسَ بِظَچَّمٍ لِّلْعَبِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 183, '۱لذِينَ قَالُوٓاْ إِنَّ ۰للَّهَ عَهِدَ إِلَيْنَـآ أَلاَّ نُومِنَ لِرَسُولٖ حَتَّيٰ يَاتِيَنَا بِقُرْبَانٍ تَاكُلُهُ ۴لنَّارُؐ قُلْ قَدْ جَآءَكُمْ رُسُلٌ مِّن قَبْلِى بِالْبَيِّنَــٰــتِ وَبِاﻟ﮲ قُلْتُمْ فَلِمَ قَتَلْتُمُوهُمُ; إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 184, 'فَإِن كَذَّبُوكَ فَقَدْ كُذِّبببَ رُسُلٌ مِّن قَبْلِكَ جَآءُو بِالْبَيِّنَــٰــتِ وَالزُّبُرۣ وَالْكِتَــٰــبِ ۱لْمُنِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 185, 'كُلُّ نَفْسٍ ذَآئِقَةُ ۴لْمَوْتتتِؐ وَإِنَّمَا تُوَفَّوْنَ ٱُجُورَكُمْ يَوْمَ ۰لْقِيَــٰمَةِؐ فَمَن زُحْزۣحَ عَنِ ۱لنّۭارۣ وَٱُدْخِلَ ۰لْجَنَّةَ فَقَدْ فَازَؐ وَمَــا ۰لْحَيَوٰةُ ۴لدُّنْيۭآ إِلاَّ مَتَــٰعُ ۴لْغُرُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 186, '© لَتُبْلَوُنَّ فِىٓ أَمْوَ؛لِكُمْ وَأَنفُسِكُمْ وَلَتَسْمَعُنَّ مِنَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ مِن قَـبْلِكُمْ وَمِنَ ۰لذِينَ أَشْرَكُوٓاْ أَذيً كَثِيراًؐ وَإِن تَصْبِرُواْ وَتَتَّقُواْ فَــإِنَّ ذَ؛لِكَ مِنْ عَزْمِ ۱لاُمُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 187, 'وَإِذَ اَخَذَ ۰للَّهُ مِيثَـٰقَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ لَتُبَيِّنُنَّهُ„ لِلنَّاسِ وَلاَ تَكْتُمُونَهُ„ فَنَبَذُوهُ وَرَآءَ ظُهُورۣهِمْ وَاشْتَرَوْاْ بِهِ” ثَمَناً قَلِيلًؐا فَبِيسَ مَا يَشْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 188, 'لاَ يَحْسِبَنَّ ۰لذِينَ يَفْرَحُونَ بِمَآ أَتَواْ وَّيُحِبُّونَ أَنْ يُّحْمَدُواْ 7 بِمَا لَمْ يَفْعَلُواْ فَلاَ تَحْسِبَنَّهُم بِمَفَازَةٍ مِّنَ ۰لْعَذَابِؐ وَلَهُمْ عَذَاببب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 189, 'وَلِلهِ مُلْكُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضِؐ وَاللَّهُ عَلَيٰ كُلِّ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 190, 'اِنَّ فِى خَلْقِ ۱لسَّمَــٰوَ؛تتتِ وَالاَرْضِ وَاخْتِچَـفِ ۱ليْلِ وَالنَّهۭارۣ ءَلاَيَــٰــتٍ لُءِّوْلِى ۱لاَلْبَــٰــبِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 191, '۱لذِينَ يَذْكُرُونَ ۰للَّهَ قِيَــٰماً وَقُعُوداً وَعَلَيٰ جُنُوبِهِمْ وَيَتَفَكَّرُونَ فِى خَلْقِ ۱لسَّمَــٰوَ؛تتتِ وَالاَرْضِؐ رَبَّـنَـا مَا خَلَقْــتَ هَــٰذَا بَــٰطِلًا سُبْحَــٰنَكَؐ فَقِنَا عَذَابببَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 192, 'رَبَّنَآ إِنَّكَ مَن تُدْخِلِ ۱لنَّارَ فَقَدَ اَخْزَيْتَهُؐ, وَمَا لِلظَّــٰلِمِينَ مِنَ اَنصۭارٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 193, 'رَّبَّنَآ إِنَّنَا سَمِعْنَا مُنَادِياً يُنَادِى لِلِايمَـٰنِ أَنَ —امِنُواْ بِرَبِّكُمْ فَــَٔامَنَّاؐ رَبَّـنَـا فَاغْفِرْ لَنَا ذُنُوبَنَــا وَكَفِّرْ عَنَّا سَيِّـَٔاتِنَا وَتَوَفَّنَا مَعَ ۰لاَبْرۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 194, 'رَبَّنَا وَءَاتِنَــا مَا وَعَدتَّنَا عَلَيٰ رُسُلِكَ وَلاَ تُخْزۣنَا يَوْمَ ۰لْقِيَــٰمَةِؐ إِنَّژَ لاَ تُخْلِفُ ۴لْمِيعَادَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 195, 'فَاسْتَجَابببَ لَهُمْ رَبُّهُمُ; أَنِّى لآَ ٱُضِيعُ عَمَلَ عَــٰمِلٍ مِّنكُم مِّن ذَكَر۫ اَوُ ۷نثۭيٰؐ بَعْضُكُم مِّنۢ بَعْضٍؐ فَالذِينَ هَاجَرُواْ وَٱُخْرۣجُواْ مِن دِيۭـٰرۣهِمْ وَٱُوذُواْ فِى سَبِيلِى وَقَــٰتَلُواْ وَقُتِلُواْ لُءَكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلُءَدْخِلَنَّهُمْ جَنَّــٰــتٍ تَجْرۣى مِن 74 تَحْتِهَـا ۰لاَنْهَــٰرُ ثَوَاباً مِّنْ عِندِ ۱للَّهِؐ وَاللَّهُ عِندَهُ„ حُسْنُ ۴لثَّوَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 196, 'لاَ يَغُرَّنَّكَ تَقَلُّــبُ ۴لذِينَ كَفَرُواْ فِى ۱لْبِچَدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 197, 'مَتَــٰعٌ قَلِيلٌؐ ثُمَّ مَأْوۭيٰهُمْ جَهَنَّمُؐ وَبِيسَ ۰لْمِهَادُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 198, 'چَكِنِ ۱لذِينَ "تَّقَوْاْ رَبَّهُمْ لَهُمْ جَنَّــٰــتٌ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَــٰرُ خَـٰلِدِينَ فِـيهَا نُزُلًا مِّنْ عِندِ ۱للَّهِؐ وَمَا عِندَ ۰للَّهِ خَيْرٌ لِّلاَبْرۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 199, 'وَإِنَّ مِنَ اَهْلِ ۱لْكِتَــٰــبِ لَمَنْ يُّومِنُ بِاللَّهِ وَمَآ ٱُنزۣلَ إِلَيْكُمْ وَمَـآ ٱُنزۣلَ إِلَيْهِمْ خَــٰشِعِينَ لِلهِؐ لاَ يَشْتَرُونَ بِـَٔايَــٰــتِ ۱للَّهِ ثَمَنـاً قَلِيلٗؐا ۷وْلَئِكَ لَهُمُ; أَجْرُهُمْ عِندَ رَبِّهِمُؐ; إِنَّ ۰للَّهَ سَرۣيعُ ۴لْحِسَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (3, 200, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ èصْبِرُواْ وَصَابِرُواْ وَرَابِطُواْ وَاتَّقُواْ ۴للَّهَ لَعَلَّكُمْ تُفْلِحُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا ۰لنَّاسُ èتَّقُواْ رَبَّكُمُ ۴ﻟ﮲ خَلَقَكُم مِّن نَّـفْسٍ وَ؛حِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَــثَّ مِنْهُمَا رۣجَالًا كَثِيراً وَنِسَآءًؐ وَاتَّقُواْ ۴للَّهَ ۰ﻟ﮲ تَسَّآءَلُونَ 75 بِهِ” وَالاَرْحَامَؐ إِنَّ ۰للَّهَ كَانَ عَلَيْكُمْ رَقِيباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 2, 'وَءَاتُواْ ۴لْيَتَــٰمۭيٰٓ أَمْوَ؛لَهُمْؐ وَلاَ تَتَبَدَّلُواْ ۴لْخَبِيــثَ بِالطَّيِّــبِؐ وَلاَ تَاكُلُوٓاْ أَمْوَ؛لَهُمُ; إِلَـيٰٓ أَمْوَ؛لِكُمُؐ; إِنَّهُ„ كَانَ حُوباً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 3, 'وَإِنْ خِفْتُمُ; أَلاَّ تُقْسِطُواْ فِى ۱لْيَتَــٰمۭيٰ فَانكِحُواْ مَــا طَابَ لَكُم مِّنَ ۰لنِّسَآءِ مَثْنۭـيٰ وَثُـچَـــثَ وَرُبَــٰعَؐ فَإِنْ خِفْتُمُ; أَلاَّ تَعْدِلُواْ فَوَ؛حِدَةٗ اَوْ مَا مَلَكَــتَ اَيْمَــٰنُكُمْؐ ذَ؛لِكَ أَدْنۭـيٰٓ أَلاَّ تَعُولُواْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 4, 'وَءَاتُواْ ۴لنِّسَآءَ صَدُقَــٰتِهِنَّ نِحْلَةًؐ فَــإِن طِبْنَ لَكُمْ عَن شَيْءٍ مِّنْهُ نَفْساً فَكُلُوهُؐ هَنِيٓـٔاً مَّرۣيٓــٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 5, 'وَلاَ تُوتُواْ ۴لسُّفَهَآءَ امْوَ؛لَكُمُ ۴لتِـى جَعَلَ ۰للَّهُ لَكُمْ قِيَماًؐ وَارْزُقُوهُمْ فِيـهَا وَاكْسُوهُمْ وَقُولُواْ لَهُمْ قَوْلًا مَّعْرُوفاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 6, '¥ وَابْتَلُواْ ۴لْيَتَــٰمۭيٰ حَتَّيٰٓ إِذَا بَلَغُواْ ۴لنِّكَاحَ فَإِنَ —انَسْتُم مِّنْهُمْ رُشْداً فَادْفَعُوٓاْ إِلَيْهِمُ; أَمْوَ؛لَهُمْ وَلاَ تَاكُلُوهَآ إِسْرَافاً وَبِدَاراٗ اَنْ يَّكْبَرُواْؐ وَمَن كَانَ غَنِيّاً فَلْيَسْتَعْفِفْؐ وَمَن كَانَ فَقِيراً فَلْيَاكُلْ بِالْمَعْرُوفِؐ فَإِذَا دَفَعْتُمُ; إِلَيْهِمُ; أَمْوَ؛لَهُمْ فَأَشْهِدُواْ عَلَيْهِمْؐ وَكَفۭيٰ بِاللَّهِ حَسِـيبـاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 7, '76 لِّلرّۣجَالِ نَصِيبٌ مِّمَّا تَرَكَ ۰لْوَ؛لِدَ؛نِ وَالاَقْرَبُونَ وَلِلنِّسَـآءِ نَصِيبٌ مِّمَّا تَرَكَ ۰لْوَ؛لِدَ؛نِ وَالاَقْرَبُونَ مِمَّا قَلَّ مِنْهُ أَوْ كَثُرَؐ نَصِيباً مَّفْرُوضاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 8, 'وَإِذَا حَضَرَ ۰لْقِسْمَةَ ٱُوْلُواْ ۴لْقُرْبۭيٰ وَالْيَتَــٰمۭـيٰ وَالْمَسَـٰكِينُ فَارْزُقُوهُم مِّنْهُؐ وَقُولُواْ لَهُمْ قَوْلًا مَّعْرُوفاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 9, 'وَلْيَخْشَ ۰لذِينَ لَوْ تَرَكُواْ مِنْ خَلْفِهِمْ ذُرّۣيَّـةً ضِعَــٰفاٗ خَافُواْ عَلَيْهِمْؐ فَلْيَتَّقُواْ ۴للَّهَ وَلْيَقُولُواْ قَوْلًا سَدِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 10, 'اِنَّ ۰لذِينَ يَاكُلُونَ أَمْوَ؛لَ ۰لْيَتَــٰمۭيٰ ظُلْمـاٗ اِنَّمَا يَاكُلُونَ فِى بُطُونِهِمْ نَاراًؐ وَسَيَصْلَوْنَ سَعِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 11, 'يُوصِيكُمُ ۴للَّهُ فِىٓ أَوْچَدِكُمْؐ لِلذَّكَرۣ مِثْلُ حَظِّ ۱لاُنثَيَيْنِؐ فَإِن كُنَّ نِسَآءً فَوْقَ "ثْنَتَيْنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَؐ وَإِن كَانَــتْ وَ؛حِدَةٌ فَلَهَا ۰لنِّصْفُؐ وَلَأِبَوَيْهِ لِكُلِّ وَ؛حِدٍ مِّنْهُمَا ۰لسُّدُسُ مِمَّا تَرَكَ إِن كَانَ لَهُ„ وَلَدٌؐ فَإِن لَّمْ يَكُن لَّهُ„ وَلَدٌ وَوَرۣثَهُ; أَبَوَ؛هُ فَلُءِمِّهِ ۱لثُّلُــثُؐ فَإِن كَانَ لَهُ; إِخْوَةٌ فَلُءِمِّهِ ۱لسُّدُسُؐ مِنۢ بَعْدِ وَصِيَّةٍ يُوصِى بِهَآ أَوْ دَيْنٖؐ —ابَآؤُكُمْ وَأَبْنَآؤُكُمْ لاَ تَدْرُونَ أَيُّهُمُ; أَقْرَبببُ لَكُمْ نَفْعاًؐ فَرۣيضَةً 77 مِّنَ ۰للَّهِؐ إِنَّ ۰للَّهَ كَانَ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 12, 'وَلَكُمْ نِصْفُ مَا تَرَكَ أَزْوَ؛جُكُمُ; إِن لَّمْ يَكُن لَّهُنَّ وَلَدٌؐ فَإِن كَانَ لَهُنَّ وَلَدٌ فَلَكُمُ ۴لرُّبُعُ مِمَّا تَرَكْنَ مِنۢ بَعْدِ وَصِيَّةٍ يُوصِينَ بِهَآ أَوْ دَيْنٍؐ وَلَهُنَّ ۰لرُّبُعُ مِمَّا تَرَكْتُمُ; إِن لَّمْ يَكُن لَّكُمْ وَلَدٌؐ فَإِن كَانَ لَكُمْ وَلَدٌ فَلَهُنَّ ۰لثُّمُنُ مِمَّا تَرَكْتُم مِّنۢ بَعْدِ وَصِيَّةٍ تُوصُونَ بِهَآ أَوْ دَيْنٍؐ وَإِن كَانَ رَجُلٌ يُورَثُ كَچَلَةٗ اَوۣ ''مْرَأَةٌ وَلَهُ; أَخ٘ اَوُ ۷خْــتٌ فَلِكُلِّ وَ؛حِدٍ مِّنْهُمَا ۰لسُّدُسُؐ فَـإِن كَانُوٓاْ أَكْثَرَ مِن ذَ؛لِكَ فَهُمْ شُرَكَآءُ فِى ۱لثُّلُــثِ مِنۢ بَعْدِ وَصِيَّةٍ يُوصِى بِهَآ أَوْ دَيْنٖ غَيْرَ مُضَآرّؐ؊ وَصِيَّةً مِّنَ ۰للَّهِؐ وَاللَّهُ عَلِيم٘ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 13, '© تِلْكَ حُدُودُ ۴للَّهِؐ وَمَنْ يُّطِعِ ۱للَّهَ وَرَسُولَهُ„ نُدْخِلْهُ جَنَّــٰــتٍ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَـٰرُ خَــٰلِدِينَ فِيهَاؐ وَذَ؛لِكَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 14, 'وَمَنْ يَّعْصِ ۱للَّهَ وَرَسُولَهُ„ وَيَتَعَدَّ حُدُودَهُ„ نُدْخِلْهُ نَاراٗ خَـٰلِداً فِيهَاؐ وَلَهُ„ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 15, 'وَالـــتِى يَاتِينَ ۰ڤْفَـٰحِشَةَ مِن نِّسَآئِكُمْ فَاسْتَشْهِدُواْ عَلَيْهِنَّ أَرْبَعَةً مِّنكُمْؐ فَإِن شَهِدُواْ فَأَمْسِكُوهُنَّ فِى ۱لْبُيُوتِ حَتَّيٰ يَتَوَفّۭيٰهُنَّ ۰لْمَوْتتتُ أَوْ يَجْعَلَ ۰للَّهُ 78 لَهُنَّ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 16, 'وَالذَ؛نِ يَاتِيَــٰنِهَا مِنكُمْ فَــَٔاذُوهُمَاؐ فَإِن تَابَــا وَأَصْلَحَا فَأَعْرۣضُواْ عَنْهُمَآؐ إِنَّ ۰للَّهَ كَانَ تَوَّاباً رَّحِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 17, 'اِنَّمَا ۰لتَّوْبَةُ عَلَي ۰للَّهِ لِلذِينَ يَعْمَلُونَ ۰لسُّوٓءَ بِجَهَــٰلَةٍ ثُــمَّ يَتُوبُونَ مِن قَرۣيــبٍؐ فَٱُوْلَئِكَ يَتُوبببُ ۴للَّهُ عَلَيْهِمْؐ وَكَانَ ۰للَّهُ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 18, 'وَلَيْسَــتِ ۱لتَّوْبَةُ لِلذِينَ يَعْمَلُونَ ۰لسَّيِّـَٔاتتتِ حَتَّيٰٓ إِذَا حَضَرَ أَحَدَهُمُ ۴لْمَوْتتتُ قَالَ إِنِّى تُبْــتُ ۴چَـنَ وَلاَ ۰لذِينَ يَمُوتُونَ وَهُمْ كُفَّار٘ؐ ۷وْلَئِكَ أَعْتَدْنَا لَهُمْ عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 19, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ يَحِلُّ لَكُمُ; أَن تَرۣثُواْ ۴لنِّسَـآءَ كَرْهاًؐ وَلاَ تَعْضُلُوهُنَّ لِتَذْهَبُواْ بِبَعْضِ مَآ ءَاتَيْتُمُوهُنَّ إِلٓاَّ أَنْ يَّاتِينَ بِفَـٰحِشَةٍ مُّبَيِّنَةٍؐ  وَعَاشِرُوهُنَّ بِالْمَعْرُوفِؐ فَإِن كَرۣهْتُمُوهُنَّ فَعَسۭيٰٓ أَن تَكْرَهُواْ شَيْــٔاً وَيَجْعَلَ ۰للَّهُ فِيهِ خَيْراً كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 20, 'وَإِنَ اَرَدتُّمُ èسْتِبْدَالَ زَوْجٍ مَّكَانَ زَوْجٍ وَءَاتَيْتُمُ; إِحْدۭيٰهُنَّ قِنطَاراً فَلاَ تَاخُذُواْ مِنْهُ شَيْـٔاٗؐ اَتَاخُذُونَهُ„ بُهْتَــٰناً وَإِثْماً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 21, 'وَكَيْفَ تَاخُذُونَهُ„ وَقَدَ اَفْضۭيٰ بَعْضُكُمُ; إِلَيٰ بَعْضٍ وَأَخَذْنَ مِنكُم مِّيثَــٰقاٗ غَلِيظاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 22, '79 وَلاَ تَنكِحُواْ مَا نَكَحَ ءَابَآؤُكُم مِّنَ ۰لنِّسَآءِ الاَّ مَا قَدْ سَلَفَؐ إِنَّهُ„ كَانَ فَـٰحِشَةً وَمَقْتاًؐ وَسَآءَ سَبِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 23, 'حُرّۣمَتْ عَلَيْكُمُ; ٱُمَّهَـٰتُكُمْ وَبَنَاتُكُمْ وَأَخَوَ؛تُكُمْ وَعَمَّــٰتُكُمْ وَخَــٰچَتُكُمْ وَبَنَاتتتُ ۴لاَخِ وَبَنَاتتتُ ۴لاُخْــتِؐ وَٱُمَّهَــٰتُكُمُ ۴لــتِىٓ أَرْضَعْنَكُمْ وَأَخَوَ؛تُكُم مِّنَ ۰لرَّضَـٰعَةِؐ وَٱُمَّهَــٰــتُ نِسَآئِكُمْ وَرَبَــٰٓئِبُكُمُ ۴لــتِى فِى حُجُورۣكُم مِّن نِّسَآئِكُمُ ۴لــتِى دَخَلْتُم بِهِنَّؐ فَإِن لَّمْ تَكُونُواْ دَخَلْتُم بِهِنَّ فَلاَ جُنَاحَ عَلَيْكُمْؐ وَحَلَئِلُ أَبْنَآئِكُمُ ۴لذِينَ مِنَ اَصْچَبِكُمْؐ وَأَن تَجْمَعُواْ بَيْنَ ۰لاُخْتَيْنِ إِلاَّ مَا قَدْ سَلَفَؐ إِنَّ ۰للَّهَ كَانَ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 24, '¤ وَاڤْمُحْصَنَــٰــتُ مِنَ ۰لنِّسَـآءِ الاَّ مَا مَلَكَــتَ اَيْمَــٰنُكُمْؐ كِتَــٰــبَ ۰للَّهِ عَلَيْكُمْؐ وَأَحَلَّ لَكُم مَّا وَرَآءَ ذَ؛لِكُمُ; أَن تَـبْتَغُواْ بِأَمْوَ؛لِكُم مُّحْصِنِينَ غَيْرَ مُسَـٰفِحِينَؐ فَمَا "سْتَمْتَعْتُم بِهِ” مِنْهُنَّ فَــَٔاتُوهُنَّ ٱُجُورَهُنَّ فَرۣيضَةًؐ وَلاَ جُنَاحَ عَلَيْكُمْ فِيمَا تَرَ؛ضَيْتُم بِهِ” مِنۢ بَعْدِ ۱لْفَرۣيضَةِؐ إِنَّ ۰للَّهَ كَانَ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 25, 'وَمَن لَّمْ يَسْتَطِعْ مِنكُمْ طَوْلٗا اَنْ يَّنكِحَ ۰ڤْمُحْصَنَــٰــتِ ۱لْمُومِنَــٰــتِ فَمِن مَّا مَلَكَــتَ 80 اَيْمَــٰنُكُم مِّن فَتَيَــٰتِكُمُ ۴لْمُومِنَــٰــتِؐ وَاللَّهُ أَعْلَمُ بِإِيمَــٰنِكُمؐ بَعْضُكُم مِّـنۢ بَعْضٍؐ فَانكِحُوهُنَّ بِـإِذْنِ أَهْلِهِنَّؐ وَءَاتُوهُنَّ ٱُجُورَهُنَّ بِالْمَعْرُوفِ مُحْصَنَــٰــتٖ غَيْرَ مُسَــٰفِحَــٰــتٍ وَلاَ مُتَّخِذَ؛تتتِ أَخْدَانٍؐ فَإِذَآ ٱُحْصِنَّ فَـإِنَ اَتَيْنَ بِفَـٰحِشَةٍ فَعَلَيْهِنَّ نِصْفُ مَا عَلَي ۰ڤْمُحْصَنَــٰــتِ مِــنَ ۰لْعَذَابببِؐ ذَ؛لِكَ لِمَنْ خَشِيَ ۰لْعَنَــتَ مِنكُمْؐ وَأَن تَصْبِرُواْ خَيْرٌ لَّكُمْؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 26, 'يُرۣيدُ ۴للَّهُ لِيُبَيِّـنَ لَكُمْ وَيَهْدِيَكُمْ سُنَنَ ۰لذِينَ مِن قَبْلِكُمْ وَيَتُوبببَ عَلَيْكُمْؐ وَاللَّهُ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 27, 'وَاللَّهُ يُرۣيدُ أَنْ يَّتُوبببَ عَلَيْكُمْؐ وَيُرۣيدُ ۴لذِينَ يَتَّبِعُونَ ۰لشَّهَوَ؛تتتِ أَن تَــمِيلُواْ مَيْلٗا عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 28, 'يُرۣيدُ ۴للَّهُ أَنْ يُّخَفِّفَ عَنكُمْؐ وَخُلِقَ ۰لِانسَـٰنُ ضَعِيفاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 29, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَاكُلُوٓاْ أَمْوَ؛لَكُم بَيْنَكُم بِالْبَــٰطِلِؐ إِلٓاَّ أَن تَكُونَ تِجَــٰرَة٘ عَن تَرَاضٍ مِّنكُمْؐ وَلاَ تَقْتُلُوٓاْ أَنفُسَكُمُؐ; إِنَّ ۰للَّهَ كَانَ بِكُمْ رَحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 30, 'وَمَنْ يَّفْعَلْ ذَ؛لِكَ عُدْوَ؛ناً وَظُلْماً فَسَوْفَ نُصْلِيهِ نَاراًؐ وَكَانَ ذَ؛لِكَ عَلَي ۰للَّهِ يَسِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 31, 'اِن تَجْتَنِبُواْ كَبَآئِرَ مَا تُنْهَوْنَ عَنْهُ نُكَفِّرْ عَنكُمْ سَيِّــَٔاتِكُمْ وَنُدْخِلْكُم 81 مَّدْخَلًا كَرۣيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 32, 'وَلاَ تَتَمَنَّوْاْ مَا فَضَّلَ ۰للَّهُ بِهِ” بَعْضَكُمْ عَلَيٰ بَعْضٍؐ لِّلـرّۣجَالِ نَصِيــبٌ مِّمَّا "كْتَسَبُواْؐ وَلِلنِّسَآءِ نَصِيــبٌ مِّمَّا "كْتَسَبْنَؐ وَسْـَٔلُواْ ۴للَّهَ مِن فَضْلِهِؐ“ إِنَّ ۰للَّهَ كَانَ بِكُلِّ شَيْءٖ عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 33, 'وَلِكُلٍّ جَعَلْنَا مَوَ؛لِيَ مِمَّا تَرَكَؐ ۰لْوَ؛لِدَ؛نِ وَالاَقْرَبُونَؐ وَالذِينَ عَـٰقَدَتتتَ اَيْمَـٰنُكُمْ فَــَٔاتُوهُمْ نَصِيبَهُمُؐ; إِنَّ ۰للَّهَ كَانَ عَلَيٰ كُلِّ شَيْءٍ شَهِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 34, '۱لرّۣجَالُ قَوَّ؛مُونَ عَلَي ۰لنِّسَآءِ بِـمَــا فَضَّلَ ۰للَّهُ بَعْضَهُمْ عَلَيٰ بَعْضٍ وَ بِمَآ أَنفَقُواْ مِنَ اَمْوَ؛لِهِــمْؐ فَاڤصَّـٰڤِحَـٰــتُ قَــٰنِتَــٰــت٘ حَــٰفِظَــٰــتٌ لِّلْغَيْــبِ بِمَا حَفِظَ ۰للَّهُؐ وَالـــتِى تَخَافُونَ نُشُوزَهُنَّ فَعِظُوهُنَّ وَاهْجُرُوهُنَّ فِى ۱لْمَضَاجِعِ وَاضْرۣبُوهُنَّؐ فَإِنَ اَطَعْنَكُمْ فَلاَ تَبْغُواْ عَلَيْهِنَّ سَبِيلٗؐا اِنَّ ۰للَّهَ كَانَ عَلِيّاً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 35, 'وَإِنْ خِفْتُمْ شِقَاقَ بَيْنِهِمَا فَابْعَثُواْ حَكَماً مِّنَ اَهْلِهِ” وَحَكَماً مِّنَ اَهْلِهَآ إِنْ يُّرۣيدَآ إِصْڦَحاً يُوَفِّقِ ۱للَّهُ بَيْنَهُمَآؐ إِنَّ ۰للَّهَ كَانَ عَلِيماٗ خَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 36, '© وَاعْبُدُواْ ۴للَّهَؐ وَلاَ تُشْرۣكُواْ بِهِ” شَيْـــٔاًؐ وَبِالْوَ؛لِدَيْنِ إِحْسَـٰناً وَبِذِى ۱لْقُرْبۭـيٰ وَالْيَتَـٰمۭيٰ وَالْمَسَـٰكِينِ وَالْجۭارۣ ذى ۱لْقُرْبۭيٰ وَالْجۭارۣ ۱لْجُنُبِ 82 وَاڤصَّـٰحِــبِ بِالْجَنۢــبِ وَابْنِ ۱لسَّبِيلِ وَمَا مَلَكَــتَ اَيْمَــٰنُكُمُؐ; إِنَّ ۰للَّهَ لاَ يُحِــبُّ مَن كَانَ مُخْتَالًا فَخُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 37, '۱لذِينَ يَبْخَلُونَ وَيَامُرُونَ ۰لنَّاسَ بِاڤْبُخْلِ وَيَكْتُمُونَ مَآ ءَاتۭيٰهُمُ ۴للَّهُ مِن فَضْلِهِؐ” وَأَعْتَدْنَا لِلْكۭـٰفِرۣينَ عَذَاباً مُّهِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 38, 'وَالذِينَ يُنفِقُونَ أَمْوَ؛لَهُمْ رۣيؕآءَ ۰لنَّاسِ وَلاَ يُومِنُونَ بِاللَّهِ وَلاَ بِالْيَوْمِ ۱لاَخِرۣؐ وَمَنْ يَّكُنِ ۱لشَّيْطَـٰنُ لَهُ„ قَرۣيناً فَسَآءَ قَرۣيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 39, 'وَمَاذَا عَلَيْهِمْ لَوَ —امَنُواْ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَأَنفَقُواْ مِمَّا رَزَقَهُمُ ۴للَّهُؐ وَكَانَ ۰للَّهُ بِهِمْ عَلِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 40, 'اِنَّ ۰للَّهَ لاَ يَظْلِمُ مِثْقَالَ ذَرَّةٍؐ وَإِن تَكُ حَسَنَةٌ يُضَـٰعِفْهَا وَيُوتِ مِن لَّدُنْهُ أَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 41, 'فَكَيْفَ إِذَا جِيؔنَا مِن كُلِّ ٱُمَّةٙ بِشَهِيدٍ وَجِيؔنَــا بِكَ عَلَيٰ هَـٰٓؤُلآَءِ شَهِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 42, 'يَوْمَئِذٍ يَوَدُّ ۴لذِينَ كَفَرُواْ وَعَصَوُاْ ۴لرَّسُولَ لَوْ تَسَّوّۭيٰ بِهِمُ ۴لاَرْضُ وَلاَ يَكْتُمُونَ ۰للَّهَ حَدِيثاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 43, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَقْرَبُواْ ۴لصَّلَوٰةَ وَأَنتُمْ سُكَـٰرۭيٰ حَتَّيٰ تَعْلَمُواْ مَا تَقُولُونَ وَلاَ جُنُباٗ اِلاَّ عَابِـرۣى سَبِيلٖ حَتَّيٰ تَغْتَسِلُواْؐ وَإِن كُنتُم مَّرْضۭيٰٓ أَوْ عَلَيٰ سَفَر۫ اَوْ جَآءَ احَـدٌ 8 مِّنكُم مِّنَ ۰لْغَآئِطِ أَوْ چَمَسْتُمُ ۴لنِّسَآءَ فَلَمْ تَجِدُواْ مَآءً فَتَيَمَّمُواْ صَعِيداً طَيِّبـاً فَامْسَحُواْ بِوُجُوهِكُمْ وَأَيْدِيكُمُؐ; إِنَّ ۰للَّهَ كَانَ عَفُوّاٗ غَفُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 44, 'اَلَمْ تَرَ إِلَي ۰لذِينَ ٱُوتُواْ نَصِيباً مِّـنَ ۰لْكِتَــٰــبِ يَشْتَرُونَ ۰لضَّچَلَةَ وَيُرۣيدُونَ أَن تَضِلُّواْ ۴لسَّبِـيـلَؐ وَاللَّهُ أَعْلَمُ بِأَعْدَآئِكُمْؐ وَكَفۭيٰ بِاللَّهِ وَلِيّاً وَكَفۭيٰ بِاللَّهِ نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 45, 'مِّنَ ۰لذِينَ هَادُواْ يُحَرّۣفُونَ ۰لْكَلِمَ عَن مَّوَاضِعِهِ” وَيَقُولُونَ سَمِعْنَا وَعَصَيْنَا وَاسْمَعْ غَيْرَ مُسْمَعٍ وَرَ؛عِنَا لَيّــاَۢ بِأَلْسِنَتِهِمْ وَطَعْناً فِى ۱لدِّينِؐ وَلَوَ اَنَّهُمْ قَالُواْ سَمِعْنَا وَأَطَعْنَا وَاسْمَعْ وَانظُرْنَا لَكَانَ خَيْراً لَّهُمْ وَأَقْوَمَؐ وَچَكِن لَّعَنَهُمُ ۴للَّهُ بِكُفْرۣهِمْ فَلاَ يُومِنُونَ إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 46, 'يَـٰٓأَيُّهَا ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ ءَامِنُواْ بِمَا نَزَّلْنَا مُصَدِّقاً لِّمَا مَعَكُم مِّن قَـبْلِ أَن نَّطْمِسَ وُجُوهاً فَنَرُدَّهَا عَلَيٰٓ أَدْبۭــٰرۣهَآ أَوْ نَلْعَنَهُمْ كَمَا لَعَنَّآ أَصْحَــٰــبَ ۰لسَّبْــتِؐ وَكَانَ أَمْرُ ۴للَّهِ مَفْعُولٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 47, 'اِنَّ ۰للَّهَ لاَ يَغْفِرُ أَنْ يُّشْرَكَ بِهِؐ” وَيَغْفِرُ مَا دُونَ ذَ؛لِكَ لِمَنْ يَّشَآءُؐ وَمَنْ يُّشْرۣژْ بِاللَّهِ فَقَدِ ''فْتَرۭيٰٓ إِثْماٗ عَظِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 48, 'اَلَمْ تَرَ إِلَي ۰لذِينَ يُزَكُّونَ أَنفُسَهُمؐ 84 بَلِ ۱للَّهُ يُزَكِّى مَنْ يَّشَآءُؐ وَلاَ يُظْلَمُونَ فَتِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 49, '۶نظُرْ كَيْفَ يَفْتَرُونَ عَلَـي ۰للَّهِ ۱لْكَذِبَ وَكَفۭيٰ بِهِ“ إِثْماً مُّبِيناٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 50, 'اَلَمْ تَرَ إِلَي ۰لذِينَ ٱُوتُواْ نَصِيباً مِّنَ ۰لْكِتَــٰــبِ يُومِنُونَ بِالْجِبْــتِ وَالطَّــٰغُوتِ وَيَقُولُونَ لِلذِينَ كَفَرُواْ هَـٰٓؤُلآَءِ اَ۬هْدۭيٰ مِنَ۰لذِينَ ءَامَنُواْ سَبِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 51, '۷وْلَئِكَ ۰لذِينَ لَعَنَهُمُ ۴للَّهُؐ وَمَنْ يَّلْعَنِ ۱للَّهُ فَلَن تَجِدَ لَهُ„ نَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 52, 'اَمْ لَهُمْ نَصِيبٌ مِّنَ ۰لْمُلْكِ فَإِذاً لاَّ يُوتُونَ ۰لنَّاسَ نَقِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 53, 'اَمْ يَحْسُدُونَ ۰لنَّاسَ عَلَيٰ مَآ ءَاتۭيٰهُمُ ۴للَّهُ مِن فَضْلِهِؐ” فَقَدَ —اتَيْنَـآ ءَالَ إِبْرَ؛هِيمَ ۰لْكِتَــٰــبَ وَالْحِكْمَةَ وَءَاتَيْنَــٰهُم مُّلْكاٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 54, 'فَمِنْهُم مَّنَ —امَنَ بِهِ” وَمِنْهُم مَّن صَدَّ عَنْهُؐ وَكَفۭيٰ بِجَهَنَّمَ سَعِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 55, 'اِنَّ ۰لذِينَ كَفَرُواْ بِـَٔايَــٰتِنَا سَوْفَ نُصْلِيهِمْ نَاراًؐ كُلَّمَا نَضِجَتْ جُلُودُهُم بَدَّلْنَــٰـهُمْ جُلُوداٗ غَيْرَهَا لِيَذُوقُواْ ۴لْعَذَابَؐ إِنَّ ۰للَّهَ كَانَ عَزۣيزاٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 56, 'وَالذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَــٰــتِ سَنُدْخِلُهُمْ جَنَّــٰــتٍ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَــٰرُ خَــٰلِدِينَ 85 فِيهَآ أَبَداًؐ لَّهُمْ فِيهَآ أَزْوَ؛جٌ مُّطَهَّرَةٌؐ وَنُدْخِلُهُمْ ظِلًاّ ظَلِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 57, '¥ اِنَّ ۰للَّهَ يَامُرُكُمُ; أَن تُوَ۬دُّواْ ۴لاَمَــٰنَــٰــتِ إِلَـيٰٓ أَهْلِهَا وَإِذَا حَكَمْتُم بَيْنَ ۰لنَّاسِ أَن تَحْكُمُواْ بِالْعَدْلِؐ إِنَّ ۰للَّهَ نِعِمَّا يَعِظُكُم بِهِؐ“ إِنَّ ۰للَّهَ كَانَ سَمِيعاَۢ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 58, 'يَـٰٓـأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ أَطِيعُواْ ۴للَّهَ وَأَطِيعُواْ ۴لرَّسُـولَ وَٱُوْلِى ۱لاَمْرۣ مِنكُمْؐ فَإِن تَنَــٰزَعْتُمْ فِى شَيْءٍ فَرُدُّوهُ إِلَي ۰للَّهِ وَالرَّسُولِ إِن كُنتُمْ تُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ ذَ؛لِكَ خَيْرٌ وَأَحْسَنُ تَاوۣيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 59, 'اَلَمْ تَرَ إِلَي ۰لذِينَ يَزْعُمُونَ أَنَّهُمُ; ءَامَنُواْ بِمَآ ٱُنزۣلَ إِلَيْكَ وَمَـآ ٱُنزۣلَ مِن قَبْلِكَ يُرۣيدُونَ أَنْ يَّتَحَاكَمُوٓاْ إِلَي ۰لطَّــٰغُوتتتِ وَقَدُ ۷مِرُوٓاْ أَنْ يَّكْفُرُواْ بِهِؐ” وَيُرۣيدُ ۴لشَّيْطَـٰنُ أَنْ يُّضِلَّهُمْ ضَچَلٚا بَعِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 60, 'وَإِذَا قِيلَ لَهُمْ تَعَالَوۣاْ اِلَـيٰ مَآ أَنزَلَ ۰للَّهُ وَإِلَي ۰لرَّسُولِ رَأَيْتَ ۰لْمُنَــٰفِقِيـنَ يَصُدُّونَ عَنكَ صُدُوداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 61, 'فَكَيْفَ إِذَآ أَصَـٰبَتْهُم مُّصِيبَةٛ بِمَا قَدَّمَتَ اَيْدِيهِمْ ثُمَّ جَآءُوكَ يَحْلِفُونَ بِاللَّهِ إِنَ اَرَدْنَآ إِلٓاَّ إِحْسَــٰناً وَتَوْفِيقاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 62, '۷وْلَئِكَ ۰لذِينَ يَعْلَمُ ۴للَّهُ 86 مَا فِى قُلُوبِهِمْ فَأَعْرۣضْ عَنْهُمْ وَعِظْهُمْ وَقُل لَّهُمْ فِىٓ أَنفُسِهِمْ قَوْلٚا بَلِيغاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 63, 'وَمَآ أَرْسَلْنَا مِن رَّسُولٖ اِلاَّ لِيُطَاعَ بِإِذْنِ ۱للَّهِؐ وَلَوَ اَنَّهُمُ; إِذ ظَّلَمُوٓاْ أَنفُسَهُمْ جَآءُوكَ فَاسْتَغْفَرُواْ ۴للَّهَ وَاسْتَغْفَرَ لَهُمُ ۴لرَّسُولُ لَوَجَدُواْ ۴للَّهَ تَوَّاباً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 64, 'فَلاَ وَرَبِّكَ لاَ يُومِنُونَ حَتَّيٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لاَ يَجِدُواْ فِىٓ أَنفُسِهِمْ حَرَجاً مِّمَّا قَضَيْتَ وَيُسَلِّمُواْ تَسْلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 65, 'وَلَوَ اَنَّا كَتَبْنَا عَلَيْهِمُ; أَنُ ۶قْتُلُوٓاْ أَنفُسَكُمُ; أَوُ ۶خْرُجُواْ مِن دِيۭـٰرۣكُم مَّا فَعَلُوهُ إِلاَّ قَلِيلٌ مِّنْهُمْؐ وَلَوَ اَنَّهُمْ فَعَلُواْ مَا يُوعَظُونَ بِهِ” لَكَانَ خَيْراً لَّهُمْ وَأَشَدَّ تَثْبِيتاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 66, 'وَإِذاً ءَلاَّتَيْنَــٰهُم مِّن لَّدُنَّآ أَجْراٗ عَظِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 67, 'وَلَهَدَيْنَــٰهُمْ صِرَ؛طاً مُّسْتَقِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 68, 'وَمَنْ يُّطِعِ ۱للَّهَ وَالرَّسُولَ فَٱُوْلَئِكَ مَعَ ۰لذِينَ أَنْعَمَ ۰للَّهُ عَلَيْهِم مِّنَ ۰لنَّبِيٓــٕـﯧنَ وَالصِّدِّيقِينَ وَالشُّهَدَآءِ وَاڤصَّـٰڤِحِينَؐ وَحَسُنَ ٱُوْلَئِكَ رَفِيقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 69, 'ذَ؛لِكَ ۰لْفَضْلُ مِنَ ۰للَّهِؐ وَكَفۭيٰ بِاللَّهِ عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 70, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ خُذُواْ حِذْرَكُمْ فَانفِرُواْ ثُبَاتٖ اَوۣ ''نفِرُواْ جَمِيعاًؐ 87');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 71, 'وَإِنَّ مِنكُمْ لَمَن لَّيُبَطِّيؕنَّؐ فَإِنَ اَصَـٰبَتْكُم مُّصِيبَةٌ قَالَ قَدَ اَنْعَمَ ۰للَّهُ عَلَيَّ إِذْ لَمَ اَكُن مَّعَهُمْ شَهِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 72, 'وَلَئِنَ اَصَــٰبَكُمْ فَضْلٌ مِّنَ ۰للَّهِ لَيَقُولَنَّ كَأَن لَّمْ يَكُنۢ بَيْنَكُمْ وَبَيْنَهُ„ مَوَدَّةٌ يَـٰلَيْتَنِى كُنــتُ مَعَهُمْ فَأَفُوزَ فَوْزاٗ عَظِيمــاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 73, '© فَلْيُقَــٰتِـلْ فِى سَبِيلِ ۱للَّهِ ۱لذِينَ يَشْرُونَ ۰لْحَيَوٰةَ ۰لدُّنْيۭـا بِالاَخِرَةِؐ وَمَنْ يُّقَــٰتِـلْ فِى سَبِيلِ ۱للَّهِ فَيُقْتَلَ اَوْ يَغْلِبْ فَسَوْفَ نُوتِيهِ أَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 74, 'وَمَا لَكُمْ لاَ تُقَــٰتِلُونَ فِى سَبِيلِ ۱للَّهِ وَالْمُسْتَضْعَفِينَ مِنَ ۰لرّۣجَالِ وَالنِّسَآءِ وَالْوۣلْدَ؛نِ ۱لذِينَ يَقُولُونَ رَبَّنَآ أَخْرۣجْنَا مِنْ هَـٰذِهِ ۱لْقَرْيَةِ ۱لظَّالِمِ أَهْلُهَــا وَاجْعَل لَّنَا مِن لَّدُنكَ وَلِيّاً وَاجْعَل لَّنَا مِن لَّدُنكَ نَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 75, '۱لذِينَ ءَامَنُواْ يُقَــٰتِلُونَ فِى سَبِيلِ ۱للَّهِؐ وَالذِينَ كَفَرُواْ يُقَــٰتِلُونَ فِى سَبِيلِ ۱لطَّـٰغُوتِؐ فَقَــٰتِلُوٓاْ أَوْلِيَآءَ ۰لشَّيْطَـٰنِؐ إِنَّ كَيْدَ ۰لشَّيْطَـٰنِ كَانَ ضَعِيفاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 76, 'اَلَمْ تَرَ إِلَي ۰لذِينَ قِيلَ لَهُمْ كُفُّوٓاْ أَيْدِيَكُمْ وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ فَلَمَّا كُتِــبَ عَلَيْهِمُ ۴لْقِتَالُ إِذَا فَرۣيقٌ مِّنْهُمْ 88 يَخْشَوْنَ ۰لنَّاسَ كَخَشْيَةِ ۱للَّهِ أَوَ اَشَدَّ خَشْيَةًؐ وَقَالُواْ رَبَّـنَـا لِمَ كَتَبْــتَ عَلَيْنَا ۰لْقِتَالَ لَوْلآَ أَخَّرْتَنَآ إِلَـيٰٓ أَجَلٍ قَرۣيبٍؐ قُلْ مَتَــٰعُ ۴لدُّنْيۭا قَلِيلٌؐ وَالاَخِرَةُ خَيْرٌ لِّمَنِ ''تَّقۭيٰؐ وَلاَ تُظْلَمُونَ فَتِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 77, 'اَيْنَمَا تَكُونُواْ يُدْرۣككُّمُ ۴لْمَوْتُ وَلَوْ كُنتُمْ فِى بُرُوجٍ مُّشَيَّدَةٍؐ وَإِن تُصِبْهُمْ حَسَنَةٌ يَقُولُواْ هَـٰذِهِ” مِنْ عِندِ ۱للَّهِؐ وَإِن تُصِبْهُمْ سَيِّيؕةٌ يَقُولُواْ هَـٰذِهِ” مِنْ عِندِكَؐ قُلْ كُلٌّ مِّنْ عِندِ ۱للَّهِؐ فَمَالِ هَـٰٓؤُلآَءِ ۱لْقَوْمِ لاَ يَكَادُونَ يَفْقَهُونَ حَدِيثاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 78, 'مَّآ أَصَابَكَ مِنْ حَسَنَةٍ فَمِنَ ۰للَّهِؐ وَمَآ أَصَابَكَ مِن سَيِّيؕةٍ فَمِن نَّفْسِكَؐ وَأَرْسَلْنَــٰــكَ لِلنَّاسِ رَسُولًؐا وَكَفۭـيٰ بِاللَّهِ شَهِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 79, 'مَّنْ يُّطِعِ ۱لرَّسُولَ فَقَدَ اَطَاعَ ۰للَّهَؐ وَمَن تَوَلّۭـيٰ فَمَآ أَرْسَلْنَـٰكَ عَلَيْهِمْ حَفِيظــاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 80, 'وَيَقُولُونَ طَاعَةٌؐ فَإِذَا بَرَزُواْ مِنْ عِندِكَ بَيَّتَ طَآئِـفَةٌ مِّنْهُمْ غَيْرَ ۰ﻟ﮲ تَقُولُؐ وَاللَّهُ يَكْتُبُ مَا يُبَيِّتُونَؐ فَأَعْرۣضْ عَنْهُمْ وَتَوَكَّلْ عَلَي ۰للَّهِؐ وَكَفۭيٰ بِاللَّهِ وَكِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 81, 'اَفَلاَ يَتَدَبَّرُونَ ۰لْقُرْءَانَؐ وَلَوْ كَانَ مِنْ عِندِ غَيْرۣ ۱للَّهِ لَوَجَدُواْ فِيهِ 89 ''خْتِچَفاً كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 82, 'وَإِذَا جَآءَهُمُ; أَمْرٌ مِّنَ ۰لاَمْنِ أَوۣ ۱لْخَوْفِ أَذَاعُواْ بِهِؐ” وَلَوْ رَدُّوهُ إِلَي ۰لرَّسُولِ وَإِلَيٰٓ ٱُوْلِى ۱لاَمْرۣ مِنْهُمْ لَعَلِمَهُ ۴لذِينَ يَسْتَنۢبِطُونَهُ„ مِنْهُمْؐ وَلَوْلاَ فَضْلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ لاَتَّبَعْتُمُ ۴لشَّيْطَـٰنَ إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 83, 'فَقَــٰتِلْ فِى سَبِيلِ ۱للَّهِؐ لاَ تُكَلَّفُ إِلاَّ نَفْسَكَؐ وَحَرّۣضِ ۱لْمُومِنِينَؐ عَسَي ۰للَّهُ أَنْ يَّكُفَّ بَأْسَ ۰لذِينَ كَفَرُواْؐ وَاللَّهُ أَشَدُّ بَأْساً وَأَشَدُّ تَنكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 84, 'مَّنْ يَّشْفَعْ شَفَــٰعَةٗ حَسَنَةً يَكُن لَّهُ„ نَصِيبٌ مِّنْهَاؐ وَمَنْ يَّشْفَعْ شَفَــٰعَةً سَيِّيؕةً يَكُن لَّهُ„ كِفْلٌ مِّنْهَاؐ وَكَانَ ۰للَّهُ عَلَيٰ كُلِّ شَيْءٍ مُّقِيتـاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 85, 'وَإِذَا حُيِّيتُم بِتَحِيَّةٍ فَحَيُّواْ بِأَحْسَـنَ مِنْهَآ أَوْ رُدُّوهَآؐ إِنَّ ۰للَّهَ كَانَ عَلَيٰ كُلِّ شَيْءٖ حَسِيبـاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 86, '¤ ۱للَّهُ لآَ إِچَهَ إِلاَّ هُوَؐ ڤَيَجْمَعَنَّكُمُ; إِلَيٰ يَوْمِ ۱لْقِيَــٰمَةِ لاَ رَيْبَ فِيهِؐ وَمَنَ اَصْدَقُ مِنَ ۰للَّهِ حَدِيثاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 87, 'فَمَا لَكُمْ فِى ۱لْمُنَــٰفِقِينَ فِيؕتَيْنِ وَاللَّهُ أَرْكَسَهُم بِمَا كَسَبُوٓاْؐ أَتُرۣيدُونَ أَن تَهْدُواْ مَنَ اَضَلَّ ۰للَّهُؐ وَمَنْ يُّضْلِلِ ۱للَّهُ فَلَن تَجِدَ لَهُ„ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 88, 'وَدُّواْ لَوْ تَكْفُرُونَ 90 كَمَا كَفَرُواْ فَتَكُونُونَ سَوَآءًؐ فَلاَ تَتَّخِذُواْ مِنْهُمُ; أَوْلِيَآءَ حَتَّيٰ يُهَاجِرُواْ فِى سَبِيلِ ۱للَّهِؐ فَإِن تَوَلَّوْاْ فَخُذُوهُمْ وَاقْتُلُوهُمْ حَيْثُ وَجَدتُّمُوهُمْ وَلاَ تَتَّخِذُواْ مِنْهُمْ وَلِيّاً وَلاَ نَصِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 89, 'اِلاَّ ۰لذِينَ يَصِلُونَ إِلَيٰ قَوْمٙ بَيْنَكُمْ وَبَيْنَهُم مِّيثَـٰق٘ اَوْ جَآءُوكُمْؐ حَصِرَتتتْ صُدُورُهُمُ; أَنْ يُّقَــٰتِلُوكُمُ; أَوْ يُقَــٰتِلُواْ قَوْمَهُمْؐ وَلَوْ شَآءَ ۰للَّهُ لَسَلَّطَهُمْ عَلَيْكُمْ فَلَقَــٰتَلُوكُمْؐ فَإِنِ ''عْتَزَلُوكُمْ فَلَمْ يُقَــٰتِلُوكُمْ وَأَلْقَوۣاْ اِلَيْكُمُ ۴لسَّلَمَ فَمَا جَعَلَ ۰للَّهُ لَكُمْ عَلَيْهِمْ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 90, 'سَتَجِدُونَ ءَاخَرۣينَ يُرۣيدُونَ أَنْ يَّامَنُوكُمْ وَيَامَنُواْ قَوْمَهُمْ كُلَّ مَا رُدُّوٓاْ إِلَي ۰لْفِتْنَةِ ٱُرْكِسُواْ فِيهَاؐ فَإِن لَّمْ يَعْتَزۣلُوكُمْ وَيُلْقُوٓاْ إِلَيْكُمُ ۴لسَّلَمَ وَيَكُفُّوٓاْ أَيْـدِيَـهُمْ فَخُذُوهُمْ وَاقْتُلُوهُمْ حَـيْـثُ ثَقِفْتُمُوهُمْؐ وَٱُوْلَئِكُمْ جَعَلْنَا لَكُمْ عَلَيْهِمْ سُلْطَــٰنـاً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 91, 'وَمَا كَانَ لِمُومِنٖ اَنْ يَّقْتُلَ مُومِناٗؐ اِلاَّ خَطَـٔاًؐ وَمَن قَتَلَ مُومِناٗ خَطَـٔاً فَتَحْرۣيرُ رَقَبَةٍ مُّومِنَةٍ وَدِيَةٌ مُّسَلَّمَة٘ اِلَـيٰٓ أَهْلِهِ“ إِلٓاَّ أَنْ يَّصَّدَّقُواْؐ فَإِن كَانَ مِن قَوْمٖ عَدُوٍّ لَّكُمْ 91 وَهُوَ مُومِنٌ فَتَحْرۣيرُ رَقَبَةٍ مُّومِنَةٍؐ وَإِن كَانَ مِن قَوْمٙ بَيْنَكُمْ وَبَيْنَهُم مِّيثَـٰقٌ فَدِيَةٌ مُّسَلَّمَة٘ اِلَـيٰٓ أَهْلِهِ” وَتَحْرۣيرُ رَقَـبَةٍ مُّومِنَةٍؐ  فَمَن لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ تَوْبَةً مِّنَ ۰للَّهِؐ وَكَانَ ۰للَّهُ عَلِيمـاٗ حَكِيمـاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 92, 'وَمَنْ يَّقْتُلْ مُومِناً مُّتَعَمِّداً فَجَزَآؤُهُ„ جَهَنَّمُ خَــٰلِداً فِيهَا وَغَضِبَ ۰للَّهُ عَلَيْهِ وَلَعَنَهُ„ وَأَعَدَّ لَهُ„ عَذَاباٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 93, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ إِذَا ضَرَبْتُمْ فِى سَبِيلِ ۱للَّهِ فَتَبَيَّنُواْؐ وَلاَ تَقُـولُواْ لِمَنَ اَلْقۭيٰٓ إِلَيْكُمُ ۴لسَّلَمَ لَسْــتَ مُومِناً تَبْتَغُونَ عَرَضَ ۰لْحَيَوٰةِ ۱لدُّنْيۭا فَعِندَ ۰للَّهِ مَغَانِمُ كَثِيرَةٌؐ كَذَ؛لِكَ كُنتُم مِّن قَـبْلُ فَمَنَّ ۰للَّهُ عَلَيْكُمْؐ فَتَبَيَّنُوٓاْؐ إِنَّ ۰للَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 94, 'لاَّ يَسْتَوۣى ۱لْقَــٰعِدُونَ مِنَ ۰لْمُومِنِينَ غَيْرَ ٱُوْلِى ۱لضَّرَرۣ وَاڤْمُجَــٰهِدُونَ فِى سَبِيلِ ۱للَّهِ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْؐ فَضَّلَ ۰للَّهُ ۴ڤْمُجَــٰهِدِينَ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْ عَلَي ۰لْقَــٰعِدِينَ دَرَجَةًؐ وَكُلًاّ وَعَدَ ۰للَّهُ ۴لْحُسْنۭيٰؐ وَفَضَّلَ ۰للَّهُ ۴ڤْمُجَــٰهِدِينَ عَلَي ۰لْقَــٰعِدِينَ أَجْراٗ عَظِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 95, 'دَرَجَــٰــتٍ مِّنْهُ وَمَغْفِرَةً وَرَحْمَةًؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماٗؐ 92');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 96, 'اِنَّ ۰لذِينَ تَوَفّۭيٰهُمُ ۴لْمَلَئِكَةُ ظَالِـمِىٓ أَنفُسِهِـمْ قَالُواْ فِيمَ كُنتُمْؐ قَالُواْ كُنَّا مُسْتَضْعَفِينَ فِى ۱لاَرْضِؐ قَالُوٓاْ أَلَمْ تَكُنَ اَرْضُ ۴للَّهِ وَ؛سِعَةً فَتُهَاجِرُواْ فِيهَاؐ فَٱُوْلَئِكَ مَأْوۭيٰهُمْ جَهَنَّمُ وَسَآءَتتتْ مَصِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 97, 'اِلاَّ ۰لْمُسْتَضْعَفِينَ مِنَ ۰لرّۣجَالِ وَالنِّسَآءِ وَالْوۣلْدَ؛نِ لاَ يَسْتَطِيعُونَ حِيلَةً وَلاَ يَهْتَدُونَ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 98, 'فَٱُوْلَئِكَ عَسَي ۰للَّهُ أَنْ يَّعْفُوَ عَنْهُمْؐ وَكَانَ ۰للَّهُ عَفُوّاٗ غَفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 99, '© وَمَنْ يُّهَاجِرْ فِى سَبِيلِ ۱للَّهِ يَجِدْ فِى ۱لاَرْضِ مُرَ؛غَماً كَثِيراً وَسَعَةًؐ وَمَنْ يَّخْرُجْ مِنۢ بَيْتِهِ” مُهَاجِراٗ اِلَي ۰للَّهِ وَرَسُولِهِ” ثُمَّ يُدْرۣكْهُ ۴لْمَوْتتتُ فَقَدْ وَقَعَ أَجْرُهُ„ عَلَي ۰للَّهِؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 100, 'وَإِذَا ضَرَبْتُمْ فِى ۱لاَرْضِ فَلَيْسَ عَلَيْكُمْ جُنَاح٘ اَن تَقْصُرُواْ مِنَ ۰لصَّلَوٰةِ إِنْ خِفْتُمُ; أَنْ يَّـفْتِنَكُمُ ۴لذِينَ كَفَرُوٓاْؐ إِنَّ ۰لْكۭـٰفِرۣينَ كَانُواْ لَكُمْ عَدُوّاً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 101, 'وَإِذَا كُنــتَ فِيهِمْ فَأَقَمْـــتَ لَهُمُ ۴لصَّلَوٰةَ فَلْتَـقُـمْ طَـآئِفَةٌ مِّنْهُم مَّعَكَ وَلْيَاخُذُوٓاْ أَسْلِحَتَهُمْؐ فَإِذَا سَجَدُواْ فَلْيَكُونُواْ مِنْ 9 وَّرَآئِكُمْؐ وَلْتَاتتتِ طَآئِفَة٘ ۷خْرۭيٰ لَمْ يُصَلُّواْ فَلْيُصَلُّواْ مَعَژَ وَلْيَاخُذُواْ حِذْرَهُمْ وَأَسْلِحَتَهُمْؐ وَدَّ ۰لذِينَ كَفَرُواْ لَــوْ تَغْفُلُونَ عَنَ اَسْلِحَتِكُمْ وَأَمْتِعَتِكُمْ فَيَمِيلُونَ عَلَيْكُم مَّيْلَةً وَ؛حِدَةًؐ وَلاَ جُنَاحَ عَلَيْكُمُ; إِن كَانَ بِكُمُ; أَذيً مِّن مَّطَرٖ اَوْ كُنتُم مَّرْضۭيٰٓ أَن تَضَعُوٓاْ أَسْلِحَتَكُمْؐ وَخُذُواْ حِذْرَكُمُؐ; إِنَّ ۰للَّهَ أَعَدَّ لِلْكۭـٰفِـرۣينَ عَذَاباً مُّهِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 102, 'فَإِذَا قَضَيْتُمُ ۴لصَّلَوٰةَ فَاذْكُرُواْ ۴للَّهَ قِيَــٰماً وَقُعُوداً وَعَلَيٰ جُنُوبِكُمْؐ فَإِذَا "طْمَأْنَنتُمْ فَأَقِيمُواْ ۴لصَّلَوٰةَؐ إِنَّ ۰لصَّلَوٰةَ كَانَــتْ عَلَي ۰لْمُومِنِينَ كِتَــٰباً مَّوْقُوتاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 103, 'وَلاَ تَهِنُواْ فِى ''بْتِغَـآءِ ۱لْقَوْمِؐ إِن تَكُونُواْ تَالَمُونَ فَإِنَّهُمْ يَالَمُونَ كَمَا تَالَمُونَ وَتَرْجُونَ مِنَ ۰للَّهِ مَا لاَ يَرْجُونَؐ وَكَانَ ۰للَّهُ عَلِيماٗ حَكِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 104, 'اِنَّآ أَنزَلْنَآ إِلَيْكَ ۰لْكِتَــٰــبَ بِالْحَقِّ ڤِتَحْكُمَ بَيْنَ ۰لنَّاسِ بِمَآ أَرۭيٰژَ ۰للَّهُؐ وَلاَ تَكُن لِّلْخَآئِنِينَ خَصِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 105, 'وَاسْتَغْفِـرۣ ۱للَّهَؐ إِنَّ ۰للَّهَ كَانَ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 106, 'وَلاَ تُجَــٰدِلْ عَنِ ۱لذِينَ يَخْتَانُونَ أَنفُسَهُمُؐ; إِنَّ ۰للَّهَ لاَ يُحِــبُّ مَن كَانَ خَوَّاناٗ اَثِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 107, '94 يَسْتَخْفُونَ مِنَ ۰لنَّاسِ وَلاَ يَسْتَخْفُونَ مِنَ ۰للَّهِ وَهُوَ مَعَهُمُ; إِذْ يُبَيِّتُونَ مَا لاَ يَرْضۭيٰ مِنَ ۰لْقَوْلِؐ وَكَانَ ۰للَّهُ بِمَا يَعْمَلُونَ مُحِيطاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 108, 'هَآنتُمْ هَـٰٓؤُلآَءِ جَـٰدَلْتُمْ عَنْهُمْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا فَمَنْ يُّجَــٰدِلُ ۴للَّهَ عَنْهُمْ يَوْمَ ۰لْقِيَــٰمَةِ أَم مَّنْ يَّكُونُ عَلَيْهِمْ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 109, 'وَمَنْ يَّعْمَلْ سُوٓءاٗ اَوْ يَظْلِمْ نَفْسَهُ„ ثُمَّ يَسْتَغْفِـرۣ ۱للَّهَ يَجِدِ ۱للَّهَ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 110, 'وَمَنْ يَّكْسِــبِ اِثْماً فَإِنَّمَا يَكْسِبُهُ„ عَلَيٰ نَـفْسِهِؐ” وَكَانَ ۰للَّهُ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 111, 'وَمَنْ يَّكْسِــبْ خَطِيٓــَٔةٗ اَوۣ اِثْماً ثُمَّ يَرْمِ بِهِ” بَرۣيٓــٔاً فَقَدِ ''حْتَمَلَ بُهْتَـٰناً وَإِثْماً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 112, 'وَلَوْلاَ فَضْلُ ۴للَّهِ عَلَيْكَ وَرَحْمَتُهُ„ لَهَمَّــت طَّآئِفَةٌ مِّنْهُمُ; أَنْ يُّضِلُّوژَؐ وَمَا يُضِلُّونَ إِلٓاَّ أَنفُسَهُمْ وَمَا يَضُرُّونَكَ مِن شَيْءٍؐ وَأَنزَلَ ۰للَّهُ عَلَيْكَ ۰لْكِتَــٰــبَ وَالْحِكْمَةَ وَعَلَّمَكَ مَا لَمْ تَكُن تَعْلَمُؐ وَكَانَ فَضْلُ ۴للَّهِ عَلَيْكَ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 113, '¥ لاَّ خَيْرَ فِى كَثِيرٍ مِّن نَّجْوۭيٰهُمُ; إِلاَّ مَنَ اَمَرَ بِصَدَقَةٖ اَوْ مَعْرُوفٖ اَوۣ اِصْڦَحٙ بَيْـنَ ۰لنَّاسِؐ وَمَنْ يَّـفْعَلْ ذَ؛لِكَ "بْتِغَآءَ مَرْضَاتتتِ ۱للَّهِ فَسَوْفَ نُوتِيهِ 95 أَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 114, 'وَمَنْ يُّشَاقِقِ ۱لرَّسُولَ مِنۢ بَعْدِ مَا تَبَيَّنَ لَهُ ۴لْهُدۭيٰ وَيَتَّبِعْ غَيْرَ سَبِيلِ ۱لْمُومِنِينَ نُوَلِّهِ” مَا تَوَلّۭيٰ وَنُصْلِهِ” جَهَنَّمَؐ وَسَآءَتتتْ مَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 115, 'اِنَّ ۰للَّهَ لاَ يَغْفِرُ أَنْ يُّشْرَژَ بِهِؐ” وَيَغْفِرُ مَا دُونَ ذَ؛لِكَ لِمَنْ يَّشَآءُؐ وَمَنْ يُّشْرۣژْ بِاللَّهِ فَقَد ضَّلَّ ضَچَلٚا بَعِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 116, 'اِنْ يَّدْعُونَ مِن دُونِهِ“ إِلٓاَّ إِنَــٰثاً وَإِنْ يَّدْعُونَ إِلاَّ شَيْطَــٰناً مَّرۣيداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 117, 'لَّعَنَهُ ۴للَّهُؐ وَقَالَ لَأَتَّخِذَنَّ مِنْ عِبَادِژَ نَصِيباً مَّفْرُوضاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 118, 'وَلُءَضِلَّنَّهُمْ وَلُءَمَنِّيَنَّهُمْ وَءَلاَمُرَنَّهُمْ فَلَيُبَتِّكُنَّ ءَاذَانَ ۰لاَنْعَــٰمِ وَءَلاَمُرَنَّهُمْ فَلَيُغَيِّرُنَّ خَلْـقَ ۰للَّهِؐ وَمَنْ يَّتَّخِذِ ۱لشَّيْطَـٰنَ وَلِيّاً مِّن دُونِ ۱للَّهِ فَقَدْ خَسِرَ خُسْرَاناً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 119, 'يَعِدُهُمْ وَيُمَنِّيهِمْؐ وَمَــا يَعِدُهُمُ ۴لشَّيْطَـٰنُ إِلاَّ غُرُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 120, '۷وْلَئِژَ مَأْوۭيٰهُمْ جَهَنَّمُؐ وَلاَ يَجِدُونَ عَنْهَا مَحِيصاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 121, 'وَالذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ سَنُدْخِلُهُمْ جَنَّــٰــتٍ تَجْرۣى مِـن تَحْتِهَا ۰لاَنْهَــٰرُ خَـٰلِدِينَ فِيهَآ أَبَداًؐ وَعْدَ ۰للَّهِ حَقّاًؐ وَمَنَ اَصْدَقُ مِنَ ۰للَّهِ قِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 122, 'لَّيْسَ بِأَمَانِيِّكُمْ وَلآَ أَمَانِيِّ أَهْلِ ۱لْكِتَــٰــبِؐ 96 مَنْ يَّعْمَلْ سُوٓءاً يُجْزَ بِهِ” وَلاَ يَجِدْ لَهُ„ مِن دُونِ ۱للَّهِ وَلِيّاً وَلاَ نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 123, 'وَمَنْ يَّعْمَلْ مِنَ ۰ڤصَّـٰڤِحَــٰــتِ مِن ذَكَر۫ اَوُ ۷نثۭيٰ وَهُوَ مُومِنٌ فَٱُوْلَئِكَ يَدْخُلُونَ ۰لْجَنَّةَ وَلاَ يُظْلَمُونَ نَقِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 124, 'وَمَنَ اَحْسَنُ دِيناً مِّمَّنَ اَسْلَمَ وَجْهَهُ„ لِلهِ وَهُوَ مُحْسِنٌ وَاتَّبَعَ مِلَّةَ إِبْرَ؛هِيمَ حَنِيفاًؐ وَاتَّخَذَ ۰للَّهُ إِبْرَ؛هِيمَ خَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 125, 'وَلِلهِ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَكَانَ ۰للَّهُ بِكُلِّ شَيْءٍ مُّحِيطاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 126, 'وَيَسْتَفْتُونَكَ فِى ۱لنِّسَآءِؐ قُلِ ۱للَّهُ يُفْتِيكُمْ فِيهِنَّ وَمَا يُتْلۭيٰ عَلَيْكُمْ فِى ۱لْكِتَــٰــبِ فِى يَتَــٰمَي ۰لنِّسَآءِ ۱لــتِى لاَ تُوتُونَهُنَّ مَا كُتِــبَ لَهُنَّ وَتَرْغَبُونَ أَن تَنكِحُوهُنَّ وَالْمُسْتَضْعَفِينَ مِنَ ۰لْوۣلْدَ؛نِ وَأَن تَقُومُواْ لِلْيَتَــٰمۭيٰ بِالْقِسْطِؐ وَمَا تَفْعَلُواْ مِنْ خَيْرٍ فَإِنَّ ۰للَّهَ كَانَ بِهِ” عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 127, 'وَإِنِ ''مْرَأَة٘ خَافَــتْ مِنۢ بَعْلِهَا نُشُوزاٗ اَوۣ اِعْرَاضاً فَلاَ جُنَاحَ عَلَيْهِمَآ أَنْ يَّصَّـٰلَحَا بَيْنَهُمَا صُڤْحاًؐ وَاڤصُّلْحُ خَيْرٌؐ وَٱُحْضِرَتِ ۱لاَنفُسُ ۴ڤشُّحَّؐ وَإِن تُحْسِنُواْ وَتَتَّقُواْ فَإِنَّ ۰للَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 128, 'وَلَن تَسْتَطِيعُوٓاْ أَن تَعْدِلُواْ بَيْنَ ۰لنِّسَآءِ وَلَوْ حَرَصْتُمْؐ 97 فَلاَ تَمِيلُواْ كُلَّ ۰لْمَيْلِ فَتَذَرُوهَا كَالْمُعَلَّقَةِؐ وَإِن تُصْڤِحُواْ وَتَتَّقُواْ فَإِنَّ ۰للَّهَ كَانَ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 129, '© وَإِنْ يَّتَفَرَّقَــا يُغْنِ ۱للَّهُ كُلًاّ مِّن سَعَتِهِؐ” وَكَانَ ۰للَّهُ وَ؛سِعاٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 130, 'وَلِلهِ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَلَقَدْ وَصَّيْنَا ۰لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ مِن قَبْلِكُمْ وَإِيَّاكُمُ; أَنِ ''تَّقُواْ ۴للَّهَؐ وَإِن تَكْفُرُواْ فَإِنَّ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَكَانَ ۰للَّهُ غَنِيّاٗ حَمِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 131, 'وَلِلهِ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَكَفۭيٰ بِاللَّهِ وَكِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 132, 'اِنْ يَّشَأْ يُذْهِبْكُمُ; أَيُّهَا ۰لنَّاسُ وَيَاتتتِ بِــَٔاخَرۣينَؐ وَكَانَ ۰للَّهُ عَلَيٰ ذَ؛لِژَ قَدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 133, 'مَّن كَانَ يُرۣيدُ ثَوَابببَ ۰لدُّنْيۭا فَعِندَ ۰للَّهِ ثَوَابببُ ۴لدُّنْيۭا وَالاَخِـرَةِؐ وَكَانَ ۰للَّهُ سَمِيعاَۢ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 134, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ كُونُواْ قَوَّ؛مِينَ بِالْقِسْطِ شُهَدَآءَ لِلهِ وَلَوْ عَلَـيٰٓ أَنفُسِكُمُ; أَوۣ ۱لْوَ؛لِدَيْنِ وَالاَقْرَبِينَؐ إِنْ يَّكُنْ غَنِيّاٗ اَوْ فَقِيراً فَاللَّهُ أَوْلۭيٰ بِهِمَا فَلاَ تَتَّبِعُواْ ۴لْهَوۭيٰٓ أَننن تَعْدِلُواْؐ وَإِن تَلْوُﹽاْ أَوْ تُعْرۣضُواْ فَإِنَّ ۰للَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 135, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ 98 ءَامِنُواْ بِاللَّهِ وَرَسُولِهِ” وَالْكِتَــٰــبِ ۱ﻟ﮲ نَزَّلَ عَلَيٰ رَسُولِهِ” وَالْكِتَــٰــبِ ۱ﻟـذِىٓ أَنزَلَ مِن قَـبْلُؐ وَمَنْ يَّكْفُرْ بِاللَّهِ وَمَلَئِكَتِهِ” وَكُتُبِهِ” وَرُسُلِهِ” وَالْيَوْمِ ۱لاَخِرۣ فَقَد ضَّلَّ ضَچَلٚا بَعِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 136, 'اِنَّ ۰لذِينَ ءَامَنُواْ ثُمَّ كَفَرُواْ ثُمَّ ءَامَنُواْ ثُمَّ كَفَرُواْ ثُمَّ "زْدَادُواْ كُفْراً لَّمْ يَكُنِ ۱للَّهُ لِيَغْفِرَ لَهُمْ وَلاَ لِيَهْدِيَهُمْ سَبِيلٚؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 137, 'بَشِّرۣ ۱لْمُنَــٰفِقِيـنَ بِأَنَّ لَهُمْ عَذَاباٗ اَلِيماٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 138, '۱لذِينَ يَتَّخِذُونَ ۰لْكۭــٰفِرۣينَ أَوْلِيَآءَ مِن دُونِ ۱لْمُومِنِينَؐ أَيَبْتَغُونَ عِندَهُمُ ۴لْعِزَّةَ فَإِنَّ ۰لْعِزَّةَ لِلهِ جَمِيعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 139, 'وَقَدْ نُزّۣلَ عَلَيْكُمْ فِى ۱لْكِتَــٰــبِ أَنِ اِذَا سَمِعْتُمُ; ءَايَــٰــتِ ۱للَّهِ يُكْفَرُ بِهَا وَيُسْتَهْزَٱُ بِهَا فَلاَ تَقْعُدُواْ مَعَهُمْ حَتَّيٰ يَخُوضُواْ فِى حَـدِيــثٖ غَيْرۣهِؐ“ إِنَّكُمُ; إِذاً مِّثْلُهُـمُؐ; إِنَّ ۰للَّهَ جَامِعُ ۴لْمُنَــٰفِقِينَ وَالْكۭـٰفِـرۣينَ فِى جَهَنَّمَ جَمِيعاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 140, '۱لذِينَ يَتَرَبَّصُونَ بِكُمْ فَإِن كَانَ لَكُمْ فَتْحٌ مِّنَ ۰للَّهِ قَالُوٓاْ أَلَمْ نَكُن مَّعَكُمْ وَإِن كَانَ لِلْكۭـٰفِرۣينَ نَصِيبٌ قَالُوٓاْ أَلَمْ نَسْتَحْوۣذْ عَلَيْكُمْ وَنَمْنَعْكُم مِّنَ ۰لْمُومِنِينَؐ فَاللَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ۰لْقِيَــٰمَةِؐ 99 وَلَنْ يَّجْعَلَ ۰للَّهُ لِلْكۭـٰـفۣرۣينَ عَلَي ۰لْمُومِنِينَ سَبِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 141, 'اِنَّ ۰لْمُنَــٰفِقِينَ يُخَــٰدِعُونَ ۰للَّهَ وَهُوَ خَــٰدِعُهُمْؐ وَإِذَا قَـامُوٓاْ إِلَي ۰لصَّلَوٰةِ قَامُواْ كُسَالۭيٰ يُرَآءُونَ ۰لنَّاسَ وَلاَ يَذْكُرُونَ ۰للَّهَ إِلاَّ قَلِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 142, 'مُّذَبْذَبِينَ بَيْنَ ذَ؛لِكَ لآَ إِلَيٰ هَـٰٓؤُلآَءِ وَلآَ إِلَيٰ هَـٰٓؤُلآَءِؐ وَمَنْ يُّضْلِلِ ۱للَّهُ فَلَن تَجِدَ لَهُ„ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 143, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ لاَ تَتَّخِذُواْ ۴لْكۭـٰفِـرۣينَ أَوْلِيَآءَ مِن دُونِ ۱لْمُومِنِينَؐ أَتُرۣيدُونَ أَن تَجْعَلُواْ لِلهِ عَلَيْكُمْ سُلْطَـٰناً مُّبِيناٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 144, 'اِنَّ ۰لْمُنَــٰفِقِينَ فِى ۱لدَّرَكِ ۱لاَسْفَلِ مِنَ ۰لنّۭارۣ وَلَن تَجِدَ لَهُمْ نَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 145, 'اِلاَّ ۰لذِينَ تَابُواْ وَأَصْڤَحُواْ وَاعْتَصَمُواْ بِاللَّهِ وَأَخْلَصُواْ دِينَهُمْ لِلهِ فَٱُوْلَئِكَ مَعَ ۰لْمُومِنِينَؐ وَسَوْفَ يُوتِ ۱للَّهُ ۴لْمُومِنِينَ أَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 146, 'مَّا يَفْعَلُ ۴للَّهُ بِعَذَابِكُمُ; إِن شَكَرْتُمْ وَءَامَنتُمْؐ وَكَانَ ۰للَّهُ شَاكِراٗ عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 147, '¤ لاَّ يُحِــبُّ ۴للَّهُ ۴لْجَهْرَ بِالسُّوٓءِ مِنَ ۰لْقَوْلِ إِلاَّ مَن ظُلِمَؐ وَكَانَ ۰للَّهُ سَمِيعاٗ عَلِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 148, 'اِن تُبْدُواْ خَيْراٗ اَوْ تُخْفُوهُ أَوْ تَعْفُواْ عَن سُوٓءٍ فَإِنَّ ۰للَّهَ كَانَ عَفُوّاً قَدِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 149, '100 اِنَّ ۰لذِينَ يَكْفُرُونَ بِاللَّهِ وَرُسُلِهِ” وَيُرۣيدُونَ أَنْ يُّـفَرّۣقُواْ بَيْنَ ۰للَّهِ وَرُسُلِهِ” وَيَقُولُونَ نُومِنُ بِـبَعْضٍ وَنَكْفُرُ بِبَعْضٍ وَيُرۣيدُونَ أَنْ يَّتَّخِذُواْ بَيْنَ ذَ؛لِكَ سَبِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 150, '۷وْلَئِكَ هُمُ ۴لْكَـٰفِرُونَ حَقّاًؐ وَأَعْتَدْنَا لِلْكۭـٰفِرۣينَ عَذَاباً مُّهِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 151, 'وَالذِينَ ءَامَنُواْ بِاللَّهِ وَرُسُلِهِ” وَلَمْ يُفَرّۣقُواْ بَيْنَ أَحَدٍ مِّنْهُمُ; ٱُوْلَئِژَ سَوْفَ نُوتِيهِمُ; ٱُجُورَهُمْؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 152, 'يَسْـَٔلُژَ أَهْلُ ۴لْكِتَــٰــبِ أَن تُنَزّۣلَ عَلَيْهِمْ كِتَــٰباً مِّنَ ۰لسَّمَآءِؐ فَقَدْ سَأَلُواْ مُوسۭيٰٓ أَكْبَرَ مِن ذَ؛لِكَ فَقَالُوٓاْ أَرۣنَا ۰للَّهَ جَهْرَةً فَأَخَذَتْهُمُ ۴لصَّــٰعِقَةُ بِظُلْمِهِمْؐ ثُمَّ "تَّخَذُواْ ۴لْعِجْلَ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ۴لْبَيِّنَــٰــتُ فَعَفَوْنَا عَن ذَ؛لِژَؐ وَءَاتَيْنَا مُوسۭيٰ سُلْطَــٰناً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 153, 'وَرَفَعْنَا فَوْقَهُمُ ۴لطُّورَ بِمِيثَـٰقِهِمْؐ وَقُلْنَا لَهُمُ ۶دْخُلُواْ ۴لْبَابَ سُجَّداًؐ وَقُلْنَا لَهُمْ لاَ تَعَدُّواْ فِى ۱لسَّبْــتِؐ وَأَخَذْنَا مِنْهُم مِّيثَــٰقاٗ غَلِيظاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 154, 'فَبِمَا نَقْضِهِم مِّيثَــٰقَهُمْ وَكُفْرۣهِم بِـَٔايَــٰــتِ ۱للَّهِ وَقَتْلِهِمُ ۴لاَنۢبِيؕآءَ بِغَيْرۣ حَقٍّ وَقَوْلِهِمْ قُلُوبُنَا غُلْفٛ بَلْ طَبَعَ ۰للَّهُ عَلَيْهَا بِكُفْرۣهِمْ فَلاَ يُومِنُونَ إِلاَّ 101 قَلِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 155, 'وَبِكُفْرۣهِمْ وَقَوْلِهِمْ عَلَيٰ مَرْيَمَ بُهْتَــٰناٗ عَظِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 156, 'وَقَوْلِهِمُ; إِنَّا قَتَلْنَا ۰ڤْمَسِيحَ عِيسَي "بْنَ مَرْيَمَ رَسُولَ ۰للَّهِؐ  وَمَا قَتَلُوهُ وَمَا صَلَبُوهُ وَچَكِن شُبِّهَ لَهُمْؐ وَإِنَّ ۰لذِينَ "خْتَلَفُواْ فِيهِ لَفِى شَژٍّ مِّنْهُؐ مَا لَهُم بِهِ” مِنْ عِلْمٖؐ اِلاَّ "تِّبَاعَ ۰لظَّنﱢّؐ وَمَا قَتَلُوهُ يَقِيناٚؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 157, 'بَل رَّفَعَهُ ۴للَّهُ إِلَيْهِؐ وَكَانَ ۰للَّهُ عَزۣيزاٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 158, 'وَإِن مِّنَ اَهْلِ ۱لْكِتَــٰــبِ إِلاَّ لَيُومِنَنَّ بِهِ” قَبْلَ مَوْتِهِ” وَيَوْمَ ۰لْقِيَــٰمَةِ يَكُونُ عَلَيْهِمْ شَهِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 159, 'فَبِظُلْمٍ مِّنَ ۰لذِينَ هَادُواْ حَرَّمْنَا عَلَيْهِمْ طَيِّبَــٰــتٖ ۷حِلَّــتْ لَهُمْ وَبِصَدِّهِمْ عَن سَبِيلِ ۱للَّهِ كَثِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 160, 'وَأَخْذِهِمُ ۴لرّۣبَوٰاْ وَقَدْ نُهُواْ عَنْهُ وَأَكْلِهِمُ; أَمْوَ؛لَ ۰لنَّاسِ بِالْبَــٰطِلِؐ وَأَعْتَدْنَا لِلْكۭـٰفِرۣينَ مِنْهُمْ عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 161, 'چَّكِنِ ۱لرَّ؛سِخُونَ فِى ۱لْعِلْمِ مِنْهُمْ وَالْمُومِنُونَ يُومِنُونَ بِمَآ ٱُنزۣلَ إِلَيْژَ وَمَآ ٱُنزۣلَ مِن قَبْلِژَ وَالْمُقِيمِينَ ۰لصَّلَوٰةَؐ وَالْمُوتُونَ ۰لزَّكَوٰةَ وَالْمُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ ٱُوْلَئِكَ سَنُوتِيهِمُ; أَجْراٗ عَظِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 162, 'اِنَّـآ أَوْحَيْنَآ إِلَيْژَ كَمَآ أَوْحَيْنَآ إِلَيٰ نُوحٍ وَالنَّبِيٓــٕـﯧنَ مِنۢ بَعْدِهِؐ” 102 وَأَوْحَـيْـنَـآ إِلَـيٰٓ إِبْرَ؛هِـيـمَ وَإِسْمَــٰعِيـلَ وَإِسْحَـٰقَ وَيَعْقُوبَ وَالاَسْبَاطِ وَعِيسۭيٰ وَأَيُّوبببَ وَيُونُسَ وَهَــٰرُونَ وَسُلَيْمَـٰنَؐ وَءَاتَيْنَا دَاوُﹼدَ زَبُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 163, 'وَرُسُلًا قَدْ قَصَصْنَــٰهُمْ عَلَيْژَ مِن قَـبْلُ وَرُسُلًا لَّمْ نَقْصُصْهُمْ عَلَيْژَؐ وَكَلَّمَ ۰للَّهُ مُوسۭـيٰ تَكْلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 164, 'رُّسُلًا مُّبَشِّرۣينَ وَمُنذِرۣينَ لِيَ۬لاَّ يَكُونَ لِلنَّاسِ عَلَي ۰للَّهِ حُجَّةٛ بَعْدَ ۰لرُّسُلِؐ وَكَانَ ۰للَّهُ عَزۣيزاٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 165, '© چَّكِنِ ۱للَّهُ يَشْهَدُ بِمَآ أَنزَلَ إِلَيْژَؐ أَنزَلَهُ„ بِعِلْمِهِ” وَالْمَلَئِكَةُ يَشْهَدُونَؐ وَكَفۭيٰ بِاللَّهِ شَهِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 166, 'اِنَّ ۰لذِينَ كَفَرُواْ وَصَدُّواْ عَن سَبِيلِ ۱للَّهِ قَد ضَّلُّواْ ضَچَلَۢا بَعِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 167, 'اِنَّ ۰لذِينَ كَفَرُواْ وَظَلَمُواْ لَمْ يَكُنِ ۱للَّهُ لِيَغْفِرَ لَهُمْ وَلاَ لِيَهْدِيَهُمْ طَرۣيقاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 168, 'اِلاَّ طَرۣيقَ جَهَنَّمَ خَــٰلِدِينَ فِيهَآ أَبَداًؐ وَكَانَ ذَ؛لِكَ عَلَي ۰للَّهِ يَسِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 169, 'يَـٰٓأَيُّهَا ۰لنَّاسُ قَدْ جَآءَكُمُ ۴لرَّسُولُ بِالْحَـقِّ مِن رَّبِّكُمْ فَــَٔامِنُواْ خَيْراً لَّكُمْؐ وَإِن تَكْفُرُواْ فَإِنَّ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضِؐ وَكَانَ ۰للَّهُ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 170, 'يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ لاَ تَغْلُواْ فِى دِينِكُمْ وَلاَ تَقُولُواْ 10 عَلَي ۰للَّهِ إِلاَّ ۰لْحَقَّؐ إِنَّمَا ۰لْمَسِيحُ عِيسَي "بْنُ مَرْيَمَ رَسُولُ ۴للَّهِ وَكَلِمَتُهُؐ; أَلْقۭيٰهَـآ إِلَيٰ مَرْيَمَ وَرُوحٌ مِّنْهُؐ فَــَٔامِنُواْ بِاللَّهِ وَرُسُلِهِؐ” وَلاَ تَقُولُواْ ثَـچَثَة٘ؐ ''نتَهُواْ خَيْراً لَّكُمُؐ; إِنَّمَا ۰للَّهُ إِچَهٌ وَ؛حِدٌؐ سُبْحَـٰنَهُ; أَنْ يَّكُونَ لَهُ„ وَلَدٌؐ لَّهُ„ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِؐ وَكَفۭيٰ بِاللَّهِ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 171, 'لَّنْ يَّسْتَنكِفَ ۰لْمَسِيحُ أَنْ يَّكُونَ عَبْداً لِّلهِ وَلاَ ۰لْمَلَئِكَةُ ۴لْمُقَرَّبُونَؐ وَمَنْ يَّسْتَنكِفْ عَنْ عِبَادَتِهِ” وَيَسْتَكْبِرْ فَسَيَحْشُرُهُمُ; إِلَيْهِ جَمِيعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 172, 'فَأَمَّا ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ فَيُوَفِّيهِمُ; ٱُجُورَهُمْ وَيَزۣيدُهُم مِّن فَضْلِهِؐ” وَأَمَّا ۰لذِينَ "سْتَنكَفُواْ وَاسْتَكْبَرُواْ فَيُعَذِّبُهُمْ عَذَاباٗ اَلِيماً وَلاَ يَجِدُونَ لَهُم مِّن دُونِ ۱للَّهِ وَلِيّاً وَلاَ نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 173, 'يَـٰٓأَيُّهَا ۰لنَّاسُ قَدْ جَآءَكُم بُرْهَـٰنٌ مِّن رَّبِّكُمْ وَأَنزَلْنَآ إِلَيْكُمْ نُوراً مُّبِينـاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 174, 'فَأَمَّـا ۰لذِينَ ءَامَنُواْ بِاللَّهِ وَاعْتَـصَـمُــواْ بِهِ” فَسَيُدْخِلُهُمْ فِى رَحْمَةٍ مِّنْهُ وَفَضْلٍ وَيَهْدِيهِمُ; إِلَيْهِ صِرَ؛طـاً مُّسْتَقِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (4, 175, 'يَسْتَفْتُونَكَؐ قُلِ ۱للَّهُ يُفْتِيكُمْ 104 فِى ۱لْكَــچَــلَــةِؐ إِنِ ''مْرُؤ٘اْ هَلَـــكَ لَـيْـسَ لَــهُ„ وَلَــدٌ وَلَــهُ; ٱُخْـتٌ فَلَـهَـا نِصْفُ مَا تَرَكَؐ وَهُـوَ يَرۣثُهَآ إِن لَّــمْ يَكُن لَّهَـا وَلَدٌؐ فَإِن كَانَـتَـا "ثْنَتَـيْـنِ فَلَهُمَـا ۰لثُّلُثَـٰنِ مِمَّا تَرَكَؐ وَإِن كَانُوٓاْ إِخْوَةً رّۣجَـالًا وَنِـسَـآءً فَلِلذَّكَرۣ مِثْلُ حَظِّ ۱لاُنثَيَيْنِؐ يُبَيِّنُ ۴للَّهُ لَكُمُ; أَن تَضِلُّواْؐ وَاللَّهُ بِكُـلِّ شَيْءٖ عَلِيــمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓـأَيُّهَـا ۰لذِينَ ءَامَنُوٓاْ أَوْفُواْ بِالْعُقُودِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 2, 'ٱُحِلَّــتْ لَكُم بَهِيمَةُ ۴لاَنْعَــٰمِ إِلاَّ مَا يُتْلۭيٰ عَلَيْكُمْ غَيْرَ مُحِلِّى ۱لصَّيْدِ وَأَنتُمْ حُرُم٘ؐ اِنَّ ۰للَّهَ يَحْكُمُ مَا يُرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 3, 'يَـٰٓأَيُّهَا ۰لذِيـنَ ءَامَنُواْ لاَ تُحِلُّواْ شَعَــٰٓئِرَ ۰للَّهِ وَلاَ ۰لشَّهْرَ ۰لْحَرَامَ وَلاَ ۰لْهَدْيَ وَلاَ ۰لْقَـلَئِدَ وَلآَ ءَآمِّينَ ۰لْبَيْــتَ ۰لْحَرَامَ يَبْتَغُونَ فَضْلًا مِّن رَّبِّهِمْ وَرۣضْوَ؛ناًؐ وَإِذَا حَلَلْتُمْ فَاصْطَادُواْؐ وَلاَ يَجْرۣمَنَّكُمْ شَنَـَٔانُ قَوْمٖ اَن صَدُّوكُمْ عَنِ ۱ڤْمَسْجِدِ ۱لْحَرَامِ أَن تَعْتَدُواْؐ وَتَعَاوَنُواْ عَلَي ۰لْبِـرّۣ وَالتَّقْوۭيٰؐ 105 وَلاَ تَعَـاوَنُـواْ عَلَي ۰لِاثْـمِ وَالْعُـدْوَ؛نِؐ وَاتَّـقُـواْ ۴للَّهَؐ إِنَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 4, '¥ حُرّۣمَــتْ عَلَيْكُمُ ۴لْمَيْتَةُ وَالدَّمُ وَلَحْمُ ۴لْخِنزۣيرۣ وَمَآ ٱُهِلَّ لِغَـيْرۣ ۱للَّهِ بِهِ” وَاڤْمُنْخَـنِـقَـةُ وَالْمَـوْقُـوذَةُ وَالْمُتَرَدِّيَةُ وَاڤنَّطِيحَةُ وَمَآ أَكَلَ ۰لسَّبُعُ إِلاَّ مَـا ذَكَّيْتُــمْ وَمَا ذُبِحَ عَلَي ۰لنُّصُــبِ وَأَن تَسْتَقْسِمُواْ بِالاَزْچَــمِؐ ذَ؛لِــكُــمْ فِسْق٘ؐ ۱لْيَـوْمَ يَئِـسَ ۰لذِينَ كَفَرُواْ مِن دِينِكُمْؐ فَلاَ تَخْشَوْهُــمْ وَاخْشَوْنِؐ ۱لْيَوْمَ أَكْمَلْــتُ لَكُمْ دِينَكُمْ وَأَتْمَمْــتُ عَلَيْكُمْ نِعْمَتِى وَرَضِـيـــتُ لَكُـمُ ۴لِاسْچَـمَ دِينـاًؐ فَمَنُ ۶ضْـطُــرَّ فِى مَخْمَصَـةٖ غَيْرَ مُتَجَانِـفٍ لِإِّثْـمٍ فَإِنَّ ۰للَّهَ غَـفُـورٌ رَّحِـيـمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 5, 'يَسْــَٔلُونَكَ مَاذَآ ٱُحِلَّ لَهُمْؐ قُلُ ۷حِلَّ لَكُمُ ۴لطَّيِّبَــٰــتُ وَمَــا عَلَّمْتُم مِّنَ ۰لْجَوَارۣحِ مُكَلِّبِينَ تُعَلِّمُونَهُنَّ مِمَّا عَلَّمَكُمُ ۴للَّهُؐ فَكُلُواْ مِمَّآ أَمْسَكْنَ عَلَيْكُمْ وَاذْكُرُواْ èسْمَ ۰للَّهِ عَلَيْهِؐ وَاتَّقُواْ ۴للَّهَؐ إِنَّ ۰للَّهَ سَرۣيعُ ۴لْحِـسَـابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 6, '۱لْيَـوْمَ ٱُحِـلَّ لَكُـمُ ۴لطَّيِّبَــٰــتُ وَطَعَامُ ۴لذِينَ ٱُوتُواْ ۴لْكِتَــٰــبَ حِلٌّ لَّكُمْ وَطَعَامُكُمْ حِـلٌّ لَّهُــمْ وَاڤْمُحْصَنَــٰــتُ مِنَ ۰لْمُومِنَــٰــتِ وَاڤْمُحْصَنَــٰــتُ مِنَ ۰لـذِينَ 106 ٱُوتُواْ ۴لْكِتَــٰــبَ مِن قَـبْلِكُمُ; إِذَآ ءَاتَيْتُمُوهُنَّ ٱُجُورَهُنَّ مُحْصِنِيـنَ غَيْرَ مُسَـٰفِحِيـنَ وَلاَ مُتَّخِـذِىٓ أَخْدَانٍؐ وَمَنْ يَّكْفُرْ بِالِايمَـٰنِ فَقَدْ حَبِطَ عَمَلُهُ„ وَهُوَ فِى ۱لاَخِرَةِ مِنَ ۰لْخَــٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 7, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُوٓاْ إِذَا قُمْتُـمُ; إِلَي ۰لصَّلَــوٰةِ فَاغْسِلُواْ وُجُوهَكُمْ وَأَيْدِيَكُمُ; إِلَي ۰لْمَرَافِقِ وَامْسَحُواْ بِرُءُوسِكُمْؐ وَأَرْجُلَكُمُ; إِلَي ۰لْكَعْبَيْنِؐ وَإِن كُنتُمْ جُنُبــاً فَاطَّهَّرُواْؐ وَإِن كُنتُم مَّرْضۭيٰٓ أَوْ عَلَيٰ سَفَـر۫ اَوْ جَـآءَ احَدٌ مِّنكُم مِّنَ ۰لْغَآئِطِ أَوْ چَمَسْتُمُ ۴لنِّسَـآءَ فَلَمْ تَجِدُواْ مَآءً فَتَيَمَّمُواْ صَعِيداً طَيِّباً فَامْسَحُواْ بِوُجُوهِكُمْ وَأَيْدِيكُم مِّنْهُؐ مَا يُرۣيدُ ۴للَّهُ لِيَجْعَلَ عَلَيْكُم مِّنْ حَرَجٍؐ وَچَكِنْ يُّرۣيــدُ لِيُطَهِّرَكُمْ وَلِيُتِمَّ نِعْمَتَهُ„ عَلَيْكُمْ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 8, 'وَاذْكُرُواْ نِعْمَةَ ۰للَّهِ عَلَيْكُمْ وَمِيثَــٰقَهُ ۴ﻟ﮲ وَاثَقَكُم بِهِ“ إِذْ قُلْتُمْ سَمِعْنَا وَأَطَعْنَاؐ وَاتَّقُواْ ۴للَّهَؐ إِنَّ ۰للَّهَ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 9, 'يَـٰٓـأَيُّهَا ۰لذِينَ ءَامَنُواْ كُونُواْ قَوَّ؛مِينَ لِلهِ شُهَـدَآءَ بِالْقِـسْـطِؐ وَلاَ يَجْرۣمَـنَّــكُمْ شَنَـــَٔانُ قَــوْمٖ 107 عَلَـيٰٓ أَلاَّ تَعْدِلُواْؐ èعْدِلُواْ هُوَ أَقْـرَبببُ لِلتَّقْوۭيٰؐ وَاتَّقُـواْ ۴للَّهَؐ إِنَّ ۰للَّهَ خَبِيرٛ بِمَــا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 10, 'وَعَدَ ۰للَّهُ ۴لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ لَهُم مَّغْفِرَةٌ وَأَجْر٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 11, 'وَالذِينَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَــٰتِنَآ ٱُوْلَئِكَ أَصْحَــٰــبُ ۴لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 12, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ ۶ذْكُرُواْ نِعْمَــتَ ۰للَّهِ عَلَيْكُمُ; إِذْ هَمَّ قَوْم٘ اَنْ يَّـبْسُطُوٓاْ إِلَيْكُمُ; أَيْدِيَهُمْ فَكَفَّ أَيْدِيَهُمْ عَنكُمْؐ وَاتَّقُواْ ۴للَّهَؐ وَعَلَي ۰للَّهِ فَلْيَتَوَكَّلِ ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 13, '© وَلَقَدَ اَخَذَ ۰للَّهُ مِيثَـٰقَ بَنِىٓ إِسْرَآءِيلَ وَبَعَثْنَا مِنْهُمُ èثْنَىْ عَشَرَ نَقِيبـاًؐ وَقَالَ ۰للَّهُ إِنِّى مَعَكُمْؐ لَـئِـنَ اَقَمْتُمُ ۴لصَّلَوٰةَ وَءَاتَيْتُمُ ۴لزَّكَوٰةَ وَءَامَنتُم بِرُسُلِى وَعَزَّرْتُمُوهُمْ وَأَقْرَضْتُمُ ۴للَّهَ قَرْضاٗ حَسَناً لُءَّكَفِّرَنَّ عَنكُمْ سَيِّــَٔاتِكُمْ وَلُءَدْخِلَنَّكُمْ جَنَّــٰــتٍ تَجْرۣى مِـن تَحْتِهَا ۰لاَنْهَـٰـرُؐ فَمَن كَفَـرَ بَـعْـدَ ذَ؛لِـكَ مِنكُمْ فَقَد ضَّلَّ سَوَآءَ ۰لسَّبِيلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 14, 'فَبِمَا نَقْضِهِم مِّيثَــٰقَهُمْ لَعَنَّــٰهُمْ وَجَعَلْنَا قُلُوبَهُمْ قَــٰسِيَـةً يُحَـرّۣفُونَ ۰لْكَلِـمَ عَن مَّوَاضِعِهِ” وَنَسُـواْ حَظّـاً مِّمَّــا ذُكِّـرُواْ بِهِؐ” وَلاَ تَــزَالُ 108 تَطَّلِعُ عَلَيٰ خَآئِنَةٍ مِّنْهُمُ; إِلاَّ قَلِيلًا مِّنْهُــمْؐ فَاعْــفُ عَنْهُمْ وَاصْفَحِؐ اِنَّ ۰للَّهَ يُحِــبُّ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 15, 'وَمِـنَ ۰لذِيـنَ قَالُوٓاْ إِنَّــا نَصَـٰرۭيٰٓ أَخَذْنَا مِيثَــٰقَهُمْ فَنَسُواْ حَظّاً مِّمَّــا ذُكِّرُواْ بِهِ” فَأَغْرَيْنَا بَيْنَهُمُ ۴لْعَدَ؛وَةَ وَالْبَغْضَآءَ اۭلَيٰ يَوْمِ ۱لْقِيَــٰمَةِؐ وَسَوْفَ يُنَبِّيؖهُمُ ۴للَّهُ بِمَاكَانُواْ يَصْنَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 16, 'يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ قَدْ جَآءَكُمْ رَسُولُنَـا يُبَيِّنُ لَكُمْ كَثِيراً مِّمَّا كُنتُمْ تُخْفُونَ مِنَ ۰لْكِتَــٰــبِ وَيَعْفُواْ عَن كَثِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 17, 'قَدْ جَآءَكُم مِّنَ ۰للَّهِ نُورٌ وَكِتَــٰــبٌ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 18, 'يَهْدِى بِهِ ۱للَّهُ مَـنِ ''تَّبَعَ رۣضْوَ؛نَهُ„ سُبُلَ ۰لسَّچَمِؐ وَيُخْرۣجُـهُم مِّنَ ۰لظُّلُمَــٰــتِ إِلَي ۰لنُّورۣ بِإِذْنِهِؐ” وَيَهْدِيهِمُ; إِلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 19, 'لَّقَدْ كَفَـرَ ۰لذِيـنَ قَالُوٓاْ إِنَّ ۰للَّهَ هُوَ ۰لْمَسِيحُ èبْنُ مَرْيَمَؐ قُـلْ فَمَنْ يَّمْلِــكُ مِنَ ۰للَّهِ شَيْـــٔاٗ اِنَ اَرَادَ أَنْ يُّهْلِــكَ ۰ڤْمَسِيحَ "بْنَ مَرْيَــمَ وَٱُمَّهُ„ وَمَن فِى ۱لاَرْضِ جَمِيعـاًؐ وَلِلهِ مُلْــكُ ۴لسَّمَــٰوَ؛تتتِ وَالاَرْضِ وَمَا بَيْنَهُمَاؐ يَخْلُـقُ مَا يَشَآءُؐ وَاللَّهُ عَلَيٰ كُلِّ شَيْءٍ قَدِيــرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 20, 'وَقَالَــتِ ۱لْيَهُودُ وَالنَّصَــٰرۭيٰ نَحْـنُ أَبْنَــٰٓؤُاْ ۴للَّهِ وَأَحِبَّـٰٓؤُهُؐ, 109 قُلْ فَلِمَ يُعَذِّبُكُم بِذُنُوبِكُمؐ بَلَ اَنتُم بَشَرٌ مِّمَّـنْ خَلَقَؐ يَغْفِرُ لِمَنْ يَّشَآءُ وَيُعَذِّبببُ مَـنْ يَّشَآءُؐ وَلِلهِ مُلْكُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضِ وَمَا بَيْنَهُمَـاؐ وَإِلَيْهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 21, 'يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ قَدْ جَآءَكُمْ رَسُولُنَا يُبَيِّنُ لَكُمْ عَلَيٰ فَتْرَةٍ مِّنَ ۰لرُّسُلِ أَن تَقُولُواْ مَا جَآءَنَــا مِنۢ بَشِيرٍ وَلاَ نَذِيرٍ فَقَدْ جَآءَكُم بَشِيرٌ وَنَذِيرٌؐ وَاللَّهُ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 22, 'وَإِذْ قَالَ مُوسۭيٰ لِقَوْمِهِ” يَــٰقَوْمِ ۹ذْكُرُواْ نِعْمَةَ ۰للَّهِ عَلَيْكُمُ; إِذْ جَعَلَ فِيكُمُ; أَنۢبِيؕـآءَ وَجَعَلَكُم مُّلُوكـاًؐ وَءَاتۭيٰكُم مَّا لَمْ يُوتتتِ أَحَداً مِّنَ ۰لْعَــٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 23, 'يَــٰقَوْمِ ۹دْخُلُواْ ۴لاَرْضَ ۰لْمُقَدَّسَةَ ۰لتِى كَتَــــبَ ۰للَّهُ لَــكُمْؐ وَلاَ تَرْتَدُّواْ عَلَيٰٓ أَدْبۭـٰرۣكُمْ فَتَنقَــلِبُـواْ خَـــٰسِرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 24, 'قَــالُواْ يَــٰمُوسۭيٰٓ إِنَّ فِيهَا قَوْمـاً جَبّۭارۣينَؐ وَإِنَّا لَن نَّدْخُلَهَـا حَتَّـيٰ يَخْرُجُواْ مِنْهَــاؐ فَإِنْ يَّخْرُجُواْ مِنْـهَـا فَإِنَّا دَ؛خِلُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 25, '¤ قَالَ رَجُچَنِ مِنَ ۰لذِينَ يَخَافُونَ أَنْعَمَ ۰للَّهُ عَلَيْهِمَا ۸دْخُلُواْ عَلَيْهِمُ ۴لْبَابببَؐ فَإِذَا دَخَلْتُمُوهُ فَإِنَّكُمْ غَـٰلِبُونَؐ وَعَلَي ۰للَّهِ فَتَوَكَّلُوٓاْ إِن كُنتُــم مُّومِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 26, 'قَــالُواْ يَــٰمُوسۭيٰٓ إِنَّـا لَن 110 نَّدْخُلَهَآ أَبَداً مَّـا دَامُواْ فِيهَا فَاذْهَــبَ اَنتَ وَرَبُّكَ فَقَــٰتِلآَ إِنَّا هَــٰهُنَا قَــٰعِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 27, 'قَالَ رَبِّ إِنِّى لآَ أَمْلِكُ إِلاَّ نَفْسِىؐ وَأَخِىؐ فَافْرُقْ بَيْنَنَـا وَبَيْنَ ۰لْقَوْمِ ۱لْفَــٰسِقِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 28, 'قَالَ فَإِنَّهَا مُحَـرَّمَة٘ عَلَيْهِمُؐ; أَرْبَعِينَ سَنَةً يَتِيهُـونَ فِى ۱لاَرْضِؐ فَلاَ تَاسَ عَلَي ۰لْقَوْمِ ۱لْفَــٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 29, 'وَاتْلُ عَلَيْهِــمْ نَبَأَ "بْنَيَ —ادَمَ بِالْحَقِّ إِذْ قَرَّبَــا قُرْبَاناً فَتُقُبِّلَ مِنَ اَحَدِهِمَا وَلَمْ يُتَقَبَّلْ مِنَ ۰لاَخَرۣؐ قَالَ لَأَقْتُلَنَّــكَؐ قَالَ إِنَّمَا يَتَقَبَّلُ ۴للَّهُ مِنَ ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 30, 'لَـئِنۢ بَسَطْــتَّ إِلَيَّ يَدَكَ لِتَقْتُـلَنِى مَـآ أَنَــا بِبَاسِطٍ يَدِيَ إِلَيْــكَ لَأِقْتُلَــكَؐ إِنِّيَ أَخَافُ ۴للَّهَ رَبَّ ۰لْعَــٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 31, 'إِنِّيَ ٱُرۣيدُ أَن تَبُوٓأَ بِإِثْمِى وَإِثْمِــكَ فَتَكُونَ مِنَ اَصْحَــٰــبِ ۱لنّۭارۣؐ وَذَ؛لِكَ جَزَ×ؤُاْ ۴لظَّـٰلِمِــيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 32, 'فَطَوَّعَــــتْ لَــهُ„ نَفْسُــهُ„ قَتْلَ أَخِيـهِ فَقَتَــلَــهُ„ فَأَصْبَحَ مِـنَ ۰لْخَــٰسِرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 33, 'فَبَعَــــثَ ۰للَّهُ غُرَابــاً يَبْحَــــثُ فِى ۱لاَرْضِ لِيُرۣيَــهُ„ كَيْــفَ يُوَ؛رۣى سَوْءَةَ أَخِيهِؐ قَــالَ يَـٰوَيْلَتۭيٰٓ أَعَجَزْتتتُ أَنَ اَكُونَ مِثْلَ هَـٰذَا ۰لْغُرَابببِ فَٱُوَ؛رۣيَ سَوْءَةَ أَخِى فَأَصْبَحَ مِنَ ۰لنَّــٰدِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 34, 'مِنَ اَجْلِ ذَ؛لِكَؐ كَتَبْنَـا عَلَيٰ 111 بَنِىٓ إِسْرَآءِيلَ أَنَّهُ„ مَن قَتَلَ نَفْساَۢ بِغَيْـرۣ نَفْسٖ اَوْ فَسَادٍ فِى ۱لاَرْضِ فَكَأَنَّمَا قَتَلَ ۰لنَّاسَ جَمِيعـاًؐ وَمَنَ اَحْيۭاهَــا فَكَأَنَّمَآ أَحْيَــا ۰لنَّاسَ جَمِيعاًؐ  وَلَقَدْ جَآءَتْهُمْ رُسُلُنَـا بِالْبَيِّنَــٰــتِ ثُـمَّ إِنَّ كَثِيراً مِّنْهُم بَعْدَ ذَ؛لِــكَ فِى ۱لاَرْضِ لَمُسْرۣفُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 35, 'إِنَّــمَــا جَزَ×ؤُاْ ۴لذِينَ يُحَارۣبُونَ ۰للَّهَ وَرَسُولَهُ„ وَيَسْعَوْنَ فِى ۱لاَرْضِ فَسَــاداٗ اَنْ يُّقَــتَّــلُــوٓاْ أَوْ يُصَــلَّبُــوٓاْ أَوْ تُقَطَّــعَ أَيْدِيهِــــمْ وَأَرْجُلُهُم مِّنْ خِچَفٖ اَوْ يُنفَوْاْ مِنَ ۰لاَرْضِؐ ذَ؛لِــكَ لَهُــمْ خِزْيٌ فِى ۱لدُّنْيۭـاؐ وَلَهُــمْ فِى ۱لاَخِرَةِ عَــذَاب٘ عَظِيــم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 36, 'اِلاَّ ۰لذِينَ تَابُواْ مِن قَــبْـلِ أَن تَقْدِرُواْ عَلَيْهِمْ فَاعْلَمُوٓاْ أَنَّ ۰للَّــهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 37, 'يَـٰٓأَيُّهَــا ۰لذِينَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ وَابْتَغُوٓاْ إِلَيْهِ ۱لْوَسِيلَةَ وَجَــٰهِدُواْ فِى سَبِيـلِــهِ” لَعَلَّــكُــمْ تُفْلِحُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 38, 'إِنَّ ۰لذِيـنَ كَـفَــرُواْ لَوَ اَنَّ لَهُــم مَّــا فِى ۱لاَرْضِ جَمِيعــاً وَمِثْلَهُ„ مَعَهُ„ لِيَفْتَدُواْ بِهِ” مِـنْ عَـذَابببِ يَــوْمِ ۱لْقِيَــٰـمَةِ مَــا تُقُبِّلَ مِنْهُمْؐ وَلَهُمْ عَذَاببب٘ اَلِيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 39, 'يُرۣيدُونَ أَنْ يَّخْــرُجُــواْ مِنَ ۰لنّۭارۣ وَمَـا هُم بِخَــٰرۣجِينَ مِنْهَـاؐ وَلَهُمْ عَذَابٌ مُّقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 40, '112 وَالسَّارۣقُ وَالسَّارۣقَةُ فَاقْطَعُوٓاْ أَيْدِيَهُمَا جَزَآءَۢ بِمَا كَسَبَــا نَكَــٰلًا مِّـنَ ۰للَّهِؐ وَاللَّهُ عَزۣيز٘ حَكِيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 41, 'فَمَـن تَابَ مِـنۢ بَــعْــدِ ظُلْمِهِ” وَأَصْــلَحَ فَــإِنَّ ۰للَّهَ يَتُـوبببُ عَلَــيْــهِؐ إِنَّ ۰للَّــهَ غَفُــورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 42, 'اَلَمْ تَعْلَمَ اَنَّ ۰للَّهَ لَهُ„ مُلْــكُ ۴لسَّمَــٰوَ؛تِ وَالاَرْضِؐ يُعَذِّبببُ مَـنْ يَّشَـآءُ وَيَغْفِرُ لِمَنْ يَّشَــآءُؐ وَاللَّهُ عَلَيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 43, '© يَـٰٓأَيُّهَـا ۰لرَّسُولُ لاَ يُحْزۣنــكَ ۰لذِينَ يُسَــٰرۣعُونَ فِى ۱لْكُفْرۣ مِنَ ۰لذِينَ قَالُـوٓاْ ءَامَنَّـا بِأَفْـوَ؛هِــهِــمْ وَلَمْ تُومِـن قُلُوبُهُـمْؐ وَمِنَ ۰لذِيـنَ هَــادُواْ سَمَّــٰـعُــونَ لِلْكَذِبببِ سَمَّــٰعُــونَ لِقَوْمٖ —اخَرۣيـنَ لَمْ يَاتُوكَؐ يُحَرّۣفُــونَ ۰لْكَــلِــمَ مِـنۢ بَعْدِ مَوَاضِعِــهِ” يَقُولُــونَ إِنُ ۷وتِيتُــمْ هَــٰـذَا فَخُــذُوهُ وَإِن لَّــمْ تُــوتَــوْهُ فَاحْــذَرُواْؐ وَمَـنْ يُّــرۣدِ ۱للَّــهُ فِــتْــنَــتَــهُ„ فَلَـن تَــمْـلِــكَ لَــهُ„ مِـنَ ۰للَّهِ شَــيْـــٔاٗؐ ۷وْلَئِـــكَ ۰لذِينَ لَمْ يُرۣدِ ۱للَّهُ أَنْ يُّطَــهِّــرَ قُلُوبَــهُــمْؐ لَــهُــمْ فِى ۱لدُّنْـيۭــا خِـزْيٌؐ وَلَــهُـمْ فِى ۱لاَخِــرَةِ عَــذَاب٘ عَظِــيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 44, 'سَمَّـــٰعُــونَ لِلْكَذِبببِ أَكَّــٰلُـونَ ڤِڤسُّحْــــتِؐ فَــإِن جَآءُوكككَ فَاحْكُــم بَيْنَهُمُ; أَوَ اَعْرۣضْ عَنْهُـمْؐ وَإِن تُعْـرۣضْ عَنْهُـمْ فَلَـنْ يَّضُرُّوكككَ شَيْـــٔاًؐ 11 وَإِنْ حَكَمْــــتَ فَاحْكُـم بَيْنَهُــم بِالْقِسْـطِؐ إِنَّ ۰للَّهَ يُحِــبُّ ۴لْمُقْسِطِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 45, 'وَكَيْفَ يُحَكِّمُونَــكَ وَعِندَهُمُ ۴لتَّوْرۭيٰةُ فِيهَا حُكْمُ ۴للَّهِ ثُمَّ يَتَوَلَّوْنَ مِنۢ بَعْدِ ذَ؛لِكَؐ وَمَــآ ٱُوْلَئِكَ بِالْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 46, 'إِنَّآ أَنزَلْنَا ۰لتَّوْرۭيٰةَ فِيهَا هُديً وَنُورٌ يَحْكُمُ بِهَـا ۰لنَّبِيٓــُٔونَ ۰لذِيـنَ أَسْلَمُـواْ لِلذِينَ هَـادُواْ وَالرَّبَّـــٰنِيُّـونَ وَالاَحْبَارُ بِمَا ۸سْتُحْفِظُواْ مِن كِتَــٰــبِ ۱للَّهِ وَكَانُواْ عَلَيْهِ شُهَدَآءَؐ فَلاَ تَخْشَـوُاْ ۴لنَّاسَ وَاخْشَـوْنِؐ وَلاَ تَشْتَــرُواْ بِـَٔايَــٰتِى ثَمَنـاً قَلِيلًؐا وَمَن لَّمْ يَحْكُم بِمَـآ أَنزَلَ ۰للَّهُ فَٱُوْلَئِكَ هُمُ ۴لْكَــٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 47, 'وَكَتَبْنَـا عَلَيْهِمْ فِيهَآ أَنَّ ۰لنَّفْـسَ بِالنَّفْسِ وَالْعَيْـنَ بِالْعَيْـنِ وَالاَنـفَ بِالاَنـفِ وَالاُذْنَ بِالاُذْنِ وَالسِّنَّ بِالسِّنِّ وَالْجُرُوحَ قِصَاصٌؐ فَمَن تَصَدَّقَ بِهِ” فَهُوَ كَفَّارَةٌ لَّـهُؐ, وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ۰للَّهُ فَٱُوْلَئِــكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 48, 'وَقَفَّيْنَا عَلَـيٰٓ ءَاثۭـٰرۣهِم بِعِيسَي "بْنِ مَرْيَمَ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِ مِنَ ۰لتَّوْرۭيٰةِؐ وَءَاتَيْنَــٰهُ ۴لِانجِيـلَ فِيهِ هُديً وَنُورٌ وَمُصَدِّقاً لِّمَـا بَيْـنَ يَدَيْهِ مِـنَ ۰لتَّوْرۭيٰـةِ وَهُـديً وَمَوْعِـظَـةً لِّلْمُتَّقِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 49, '114 وَڤْيَحْكُمَ اَهْـلُ ۴لِانجِيلِ بِمَآ أَنزَلَ ۰للَّهُ فِيهِؐ وَمَن لَّمْ يَحْكُم بِمَــآ أَنزَلَ ۰للَّهُ فَٱُوْلَئِــكَ هُمُ ۴لْفَــٰسِقُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 50, 'وَأَنزَلْنَــآ إِلَيْــكَ ۰لْكِتَــٰـــبَ بِالْحَقِّ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِ مِنَ ۰لْكِتَــٰــبِ وَمُهَيْمِناٗ عَلَيْهِؐ فَاحْكُم بَيْنَهُم بِمَآ أَنزَلَ ۰للَّهُ وَلاَ تَتَّبِعَ اَهْوَآءَهُمْ عَمَّا جَآءَكَ مِنَ ۰لْحَقﱢّؐ لِكُلٍّ جَعَلْنَا مِنكُمْ شِرْعَةً وَمِنْهَاجاًؐ وَلَوْ شَآءَ ۰للَّهُ لَجَعَلَكُمُ; ٱُمَّةً وَ؛حِدَةًؐ وَچَكِن لِّيَبْلُوَكُمْ فِى مَآ ءَاتۭيٰكُمْؐ فَاسْتَبِقُواْ ۴لْخَيْرَ؛تتتِؐ إِلَي ۰للَّهِ مَرْجِعُكُمْ جَمِيعاً فَيُنَبِّيؖكُم بِمَا كُنتُمْ فِيهِ تَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 51, '¥ وَأَنُ ۶حْكُم بَيْنَهُم بِمَآ أَنزَلَ ۰للَّهُؐ وَلاَ تَتَّـبِـعَ اَهْوَآءَهُــمْؐ وَاحْــذَرْهُــمُ; أَنْ يَّفْتِنُـوكككَ عَنۢ بَعْضِ مَآ أَنــزَلَ ۰للَّــهُ إِلَيْــكَؐ فَــإِن تَوَلَّوْاْ فَاعْلَـمَ اَنَّمَـا يُرۣيدُ ۴للَّهُ أَنْ يُّصِيبَـهُم بِبَعْضِ ذُنُوبِهِمْؐ وَإِنَّ كَثِيـراً مِّـنَ ۰لنَّـاسِ لَفَــٰسِقُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 52, 'أَفَحُــكْمَ ۰لْجَــٰهِـلِــيَّــةِ يَبْغُـونَؐ وَمَـنَ اَحْسَـنُ مِنَ ۰للَّــهِ حُكْمــاً لِّقَوْمٍ يُوقِــنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 53, 'يَـٰٓـأَيُّـهَـا ۰لذِيـنَ ءَامَـنُـواْ لاَ تَتَّخِـذُواْ ۴لْيَـهُـودَ وَالنَّـصَــٰرۭيٰٓ أَوْلِيَــآءَؐ بَعْضُهُـمُ; أَوْلِيَــآءُ بَعْـضٍؐ وَمَنْ يَّتَوَلَّـهُـم مِّنـكُمْ فَإِنَّــهُ„ مِنْـهُــمُؐ; إِنَّ ۰للَّـهَ لاَ يَـهْـدِى ۱لْقَــوْمَ ۰لظَّــٰلِـمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 54, '115 فَـتَـرَي ۰لــذِيـنَ فِى قُلُــوبِهِــم مَّرَضٌ يُسَــٰرۣعُــونَ فِيهِــمْ يَقُــولُــونَ نَخْشۭـيٰٓ أَن تُصِيـبَــنَــا دَآئِرَةٌؐ فَعَـسَـي ۰للَّـهُ أَنْ يَّـاتِـيَ بِاڤْفَتْحِ أَوَ اَمْرٍ مِّـنْ عِنـدِهِ” فَيُصْبِحُـواْ عَلَـيٰ مَآ أَسَـرُّواْ فِىٓ أَنفُسِــهِــمْ نَــٰدِمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 55, 'يَقُـولُ ۴لذِيـنَ ءَامَنُوٓاْ أَهَـٰٓؤُلآَءِ ۱لـذِينَ أَقْسَـمُـواْ بِاللَّهِ جَهْدَ أَيْمَــٰنِـهِمُ; إِنَّهُمْ لَمَعَكُمْ حَبِطَــتَ اَعْمَــٰلُـهُـمْ فَأَصْبَحُــواْ خَــٰسِــرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 56, 'يَـٰٓأَيُّـهَـا ۰لذِينَ ءَامَـنُـواْ مَنْ يَّـرْتَدِدْ مِنكُمْ عَـن دِينِـهِ” فَسَوْفَ يَاتِى ۱للَّـهُ بِقَـوْمٍ يُحِبُّهُـمْ وَيُحِبُّونَـهُ; أَذِلَّةٖ عَلَي ۰لْـمُـومِـنِـيـنَ أَعِزَّةٖ عَـلَي ۰لْــكۭـٰـفِـرۣيـنَ يُجَــٰهِـدُونَ فِى سَبِيلِ ۱للَّهِ وَلاَ يَخَـافُونَ لَوْمَـةَ ٹــمٍؐ ذَ؛لِــكَ فَضْـلُ ۴للَّــهِ يُوتِيــهِ مَنْ يَّشَآءُؐ وَاللَّهُ وَ؛سِع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 57, 'اِنَّمَـا وَلِيُّــكُمُ ۴للَّــهُ وَرَسُــولُــهُ„ وَالذِينَ ءَامَنُواْ ۴لذِيـنَ يُــقِيمُونَ ۰لصَّــلَــوٰةَ وَيُــوتُــونَ ۰لزَّكَوٰةَ وَهُمْ رَ؛كِعُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 58, 'وَمَنْ يَّتَـوَلَّ ۰للَّهَ وَرَسُولَــهُ„ وَالذِينَ ءَامَــنُــواْ فَــإِنَّ حِزْبببَ ۰للَّــهِ هُــمُ ۴لْغَــٰلِبُـــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 59, 'يَـٰٓـأَيُّهَــا ۰لذِيـنَ ءَامَــنُــواْ لاَ تَتَّخِذُواْ ۴لذِيـنَ "تَّخَذُواْ دِينَــكُــمْ هُــزُؤاً وَلَعِبــاً مِّـنَ ۰لذِينَ ٱُوتُــواْ ۴لْكِتَــٰــبَ مِـن قَبْلِكُمْ وَالْكُفَّــارَ أَوْلِيَــآءَؐ وَاتَّقُــواْ ۴للَّــهَ 116 إِن كُنتُـم مُّومِنِـيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 60, 'وَإِذَا نَادَيْـتُـمُ; إِلَي ۰لصَّلَوٰةِ ''تَّخَذُوهَا هُزُؤاً وَلَـعِبـاًؐ ذَ؛لِــكَ بِأَنَّهُـمْ قَوْمٌ لاَّ يَعْــقِــلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 61, 'قُلْ يَـٰٓـأَهْـلَ ۰لْكِتَــٰــبِ هَـلْ تَنــقِــمُــونَ مِنَّــآ إِلٓاَّ أَنَ —امَنَّـا بِاللَّــهِ وَمَـآ ٱُنــزۣلَ إِلَيْنَـا وَمَــآ ٱُنزۣلَ مِن قَبْلُ وَأَنَّ أَكْـثَــرَكُمْ فَــٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 62, 'قُلْ هَـلُ ۷نَبِّيؖكُم بِشَرٍّ مِّن ذَ؛لِكَ مَثُوبَةٗ عِندَ ۰للَّهِ مَن لَّعَنَهُ ۴للَّهُ وَغَضِــبَ عَلَيْهِ وَجَعَـلَ مِنْهُــمُ ۴لْقِرَدَةَ وَالْخَنَــازۣيرَ وَعَبَــدَ ۰لطَّـــٰغُــوتَؐ ٱُوْلَئِكَ شَرٌّ مَّكَانــاً وَأَضَـلُّ عَن سَوَآءِ ۱لسَّبِيـلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 63, 'وَإِذَا جَآءُوكُمْ قَالُــوٓاْ ءَامَــنَّــا وَقَد دَّخَــلُــواْ بِالْكُفْرۣ وَهُــمْ قَدْ خَــرَجُــواْ بِــــهِؐ” وَاللَّــهُ أَعْلَــمُ بِمَــا كَانُواْ يَكْتُمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 64, 'وَتَرۭيٰ كَثِيراً مِّنْهُــمْ يُسَــٰرۣعُــونَ فِى ۱لِاثْــمِ وَالْعُدْوَ؛نِ وَأَكْلِــهِــمُ ۴ڤسُّحْـتَؐ لَبِيـسَ مَــا كَانُــواْ يَعْمَــلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 65, 'لَوْلاَ يَنْهۭيٰهُــمُ ۴لرَّبَّــٰنِيُّــونَ وَالاَحْبَــارُ عَن قَوْلِهِمُ ۴لِاثْمَ وَأَكْلِهِمُ ۴ڤسُّحْتَؐ لَبِيسَ مَا كَانُواْ يَصْنَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 66, 'وَقَـالَــتِ ۱لْيَهُودُ يَـدُ ۴للَّهِ مَغْلُولَة٘ؐ غُلَّـــتَ اَيْدِيهِــمْ وَلُعِــنُــواْ بِمَا قَــالُواْؐ بَـلْ يَــدَ؛هُ مَبْسُوطَـتَـٰنِ يُنفِقُ كَيْــفَ يَشَآءُؐ وَلَيَزۣيـدَنَّ كَثِيــراً مِّنْهُــم مَّــآ ٱُنــزۣلَ إِلَيْكَ مِن رَّبِّكَ طُغْيَـــٰنــاً وَكُفْــراًؐ 117 وَأَلْقَــيْــنَــا بَيْنَهُــمُ ۴لْــعَــدَ؛وَةَ وَالْبَغْضَــآءَ اۭلَيٰ يَوْمِ ۱لْقِيَــٰـمَــةِؐ كُلَّمَــآ أَوْقَدُواْ نَــاراً ڤِّڤْحَــرْبببِ أَطْــفَــأَهَــا ۰للَّهُؐ وَيَسْعَــــوْنَ فِى ۱لاَرْضِ فَــسَــاداًؐ وَاللَّهُ لاَ يُحِــــبُّ ۴لْــمُــفْــسِــدِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 67, 'وَلَــوَ اَنَّ أَهْلَ ۰لْكِتَــٰــبِ ءَامَنُواْ وَاتَّقَوْاْ لَكَفَّرْنَــا عَنْــهُــمْ سَيِّـــَٔاتِــهِــمْ وَلَأَدْخَلْنَــٰهُـمْ جَنَّــٰــتِ ۱لنَّــعِــيــمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 68, 'وَلَــوَ اَنَّهُــمُ; أَقَامُــواْ ۴لتَّوْرۭيٰةَ وَالِانجِيـلَ وَمَآ ٱُنزۣلَ إِلَيْهِـم مِّن رَّبِّــهِمْ لَأَكَلُــواْ مِن فَوْقِهِـمْ وَمِن تَحْــتِ أَرْجُلِهِــمؐ مِّنْهُــمُ; ٱُمَّةٌ مُّقْتَصِـدَةٌؐ وَكَــثِيـرٌ مِّنْهُمْ سَــآءَ مَا يَعْمَلُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 69, '© يَــٰٓأَيُّهَـا ۰لرَّسُولُ بَلِّغْ مَــآ ٱُنــزۣلَ إِلَيْـكَ مِن رَّبِّكَؐ وَإِن لَّــمْ تَفْــعَـلْ فَــمَــا بَــلَّـغْــــتَ رۣسَاچَتِــهِؐ” وَاللَّــهُ يَعْصِـمُــــكَ مِنَ ۰لــنَّــاسِؐ إِنَّ ۰للَّــهَ لاَ يَــهْــدِى ۱لْقَــوْمَ ۰لْكۭـٰفِـرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 70, 'قُـلْ يَـٰٓأَهْلَ ۰لْكِتَــٰــبِ لَسْتُــمْ عَلَيٰ شَيْءٖ حَتَّيٰ تُقِيمُـواْ ۴لتَّـوْرۭيٰةَ وَالِانجِيلَ وَمَآ ٱُنزۣلَ إِلَيْكُم مِّن رَّبِّكُمْؐ وَلَيَزۣيدَنَّ كَثِيراً مِّنْهُم مَّآ ٱُنزۣلَ إِلَيْــكَ مِن رَّبِّكَ طُغْيَــٰنـاً وَكُفْـراًؐ فَلاَ تَاسَ عَلَي ۰لْقَوْمِ ۱لْكۭــٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 71, 'إِنَّ ۰لذِينَ ءَامَنُواْ وَالـذِيـنَ هَــادُواْ وَالصَّــٰبُـونَ وَالنَّصَــٰرۭيٰ مَـنَ —امَـنَ بِاللَّـهِ وَالْـيَـوْمِ ۱لاَخِــرۣ وَعَمِـلَ صَـٰڤِحــاً 118 فَلاَ خَــوْف٘ عَــلَــيْــهِــمْ وَلاَ هُــمْ يَحْــزَنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 72, 'لَــقَــدَ اَخَذْنَــا مِيثَـٰقَ بَنِىٓ إِسْرَآءِيلَ وَأَرْسَلْنَــآ إِلَيْهِــمْ رُسُــلًؐا كُلَّــمَــا جَآءَهُمْ رَسُولٛ بِمَا لاَ تَهْوۭيٰٓ أَنفُسُهُـمْ فَرۣيقـاً كَـذَّبُــواْ وَفَرۣيقاً يَقْتُلُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 73, 'وَحَسِبُوٓاْ أَلاَّ تَكُونَ فِتْنَةٌ فَعَمُواْ وَصَــمُّـواْ ثُمَّ تَــابببَ ۰للَّهُ عَلَيْهِــمْ ثُــمَّ عَمُواْ وَصَمُّــواْؐ كَثِيــرٌ مِّنْهُمْؐ وَاللَّهُ بَصِيرٛ بِــمَــا يَعْمَــلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 74, 'لَقَدْ كَفَــرَ ۰لذِيـنَ قَــالُــوٓاْ إِنَّ ۰للَّهَ هُــوَ ۰ڤْمَــسِيحُ èبْنُ مَــرْيَــمَؐ وَقَــالَ ۰لْمَسِيحُ يَــٰبَنِىٓ إِسْرَآءِيلَ ۸عْبُدُواْ ۴للَّــهَ رَبِّــــى وَرَبَّكُــمُؐ; إِنَّهُ„ مَنْ يُّشْرۣكككْ بِاللَّهِ فَقَـدْ حَــرَّمَ ۰للَّهُ عَـلَيْــهِ ۱لْجَنَّــةَ وَمَأْوۭيٰهُ ۴لنَّارُؐ وَمَا لِلظَّـٰلِمِينَ مِنَ اَنصۭارٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 75, 'لَّقَدْ كَــفَــرَ ۰لذِينَ قَالُــوٓاْ إِنَّ ۰للَّــهَ ثَــالِــــثُ ثَـچَــثَـةٍؐ وَمَا مِنِ اِچَهٖ اِلٓاَّ إِچَــهٌ وَ؛حِــدٌؐ وَإِن لَّمْ يَنتَــهُــواْ عَمَّا يَقُولُــونَ لَيَمَسَّـنَّ ۰لذِيـنَ كَفَــرُواْ مِنْهُــمْ عَذَاب٘ اَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 76, 'اَفَــلاَ يَتُوبُــونَ إِلَي ۰للَّــهِ وَيَسْتَغْفِرُونَــهُؐ, وَاللَّــهُ غَفُــورٌ رَّحِيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 77, 'مَّا ۰لْمَسِيحُ èبْنُ مَرْيَــمَ إِلاَّ رَسُــولٌ قَدْ خَلَــتْ مِن قَبْــلِــهِ ۱لرُّسُلُؐ وَٱُمُّهُ„ صِدِّيقَــةٌؐ كَانَــا يَاكُچَنِ ۱لطَّــعَــامَؐ ۸نظُرْ كَيْفَ نُبَيِّنُ لَهُمُ ۴لاَيَــٰــتِ ثُــمَّ ۸نظُـرَ اَنّۭيٰ يُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 78, '119 قُـلَ اَتَعْبُـدُونَ مِن دُونِ ۱للَّــهِ مَــا لاَ يَمْــلِــــكُ لَـــكُــمْ ضَـــــرّاً وَلاَ نَفْعــاًؐ وَاللَّــهُ هُــوَ ۰لسَّــمِــيــعُ ۴لْعَــلِــيـــمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 79, 'قُـلْ يَـٰٓأَهْـلَ ۰لْكِــتَـــٰــبِ لاَ تَغْلُــواْ فِى دِينِكُــمْ غَيْرَ ۰لْحَقﱢّؐ وَلاَ تَتَّبِــعُــوٓاْ أَهْــوَآءَ قَوْمٍ قَد ضَّـلُّــواْ مِـن قَبْلُ وَأَضَـلُّـواْ كَثِيراً وَضَـلُّـواْ عَن سَوَآءِ ۱لسَّبِيـلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 80, 'لُعِـنَ ۰لذِيـنَ كَفَــرُواْ مِـنۢ بَنِىٓ إِسْرَآءِيـلَ عَلَـيٰ لِسَانِ دَاوُﹼدَ وَعِيسَي "بْنِ مَرْيَــمَؐ ذَ؛لِــكَ بِمَا عَصَواْ وَّكَــانُــواْ يَعْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 81, 'كَــانُــواْ لاَ يَتَنَاهَوْنَ عَن مُّنكَرٍ فَعَلُوهُؐ لَبِيـسَ مَا كَانُواْ يَفْعَــلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 82, 'تَرۭيٰ كَثِيراً مِّنْهُــمْ يَتَوَلَّوْنَ ۰لذِينَ كَفَرُواْؐ لَبِيـسَ مَــا قَدَّمَــــتْ لَهُــمُ; أَنــفُــسُــهُــمُ; أَن سَخِــطَ ۰للَّهُ عَلَيْــهِــمْ وَفِى ۱لْعَـــذَابِ هُــمْ خَـــٰلِــدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 83, 'وَلَوْ كَانُــواْ يُومِــنُــونَ بِاللَّهِ وَالنَّبِىٓءِ وَمَــآ ٱُنــزۣلَ إِلَيْــهِ مَا "تَّخَــذُوهُــمُ; أَوْلِيَآءَؐ وَچَكِنَّ كَثِيـراً مِّنْهُــــــمْ فَــٰسِقُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 84, '¤ ڤَتَجِدَنَّ أَشَــدَّ ۰لنَّـاسِ عَــدَ؛وَةً لِّلذِينَ ءَامَنُــــواْ ۴لْيَهُودَ وَالذِيـنَ أَشْرَكُــواْؐ وَلَتَجِـدَنَّ أَقْرَبَهُــم مَّــوَدَّةً لِّلــــذِينَ ءَامَنُواْ ۴لذِينَ قَــالُــوٓاْ إِنَّا نَــصَــٰرۭيٰؐ ذَ؛لِــكَ بِــأَنَّ مِنْهُــمْ قِسِّيسِينَ وَرُهْبَانــاً وَأَنَّهُــمْ لاَ يَسْتَكْبِــــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 85, 'وَإِذَا سَمِعُـواْ مَآ ٱُنزۣلَ 120 إِلَي ۰لرَّسُـــولِ تَرۭيٰٓ أَعْيُنَهُمْ تَفِيـضُ مِنَ ۰لدَّمْــعِ مِمَّــا عَرَفُــــواْ مِنَ ۰لْحَقِّ يَقُــولُــونَ رَبَّنَـــآ ءَامَنَّا فَاكْتُبْــنَــــا مَعَ ۰لشَّــٰهِدِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 86, 'وَمَــــا لَنَــــا لاَ نُومِـنُ بِاللَّهِ وَمَا جَآءَنَـــا مِـنَ ۰لْحَقِّ وَنَطْمَــعُ أَنْ يُّدْخِلَنَــا رَبُّنَــا مَعَ ۰لْقَوْمِ ۱ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 87, 'فَأَثَــٰبَــهُــمُ ۴للَّهُ بِمَــــا قَالُواْ جَنَّــٰــتٍ تَجْرۣى مِـن تَحْتِــهَــا ۰لاَنْــهَــٰرُ خَـٰلِدِيـنَ فِيهَــاؐ وَذَ؛لِكَ جَزَآءُ ۴ڤْمُحْسِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 88, 'وَالذِيـنَ كَفَــرُواْ وَكَــذَّبُــواْ بِـــَٔايَـــٰتِــنَــــآ ٱُوْلَئِكَ أَصْحَــٰــبُ ۴لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 89, 'يَـٰٓأَيُّهَــا ۰لذِيـنَ ءَامَنُواْ لاَ تُحَـرّۣمُــــواْ طَـيِّبَــٰــتِ مَــــآ أَحَـلَّ ۰للَّهُ لَكُــمْ وَلاَ تَعْتَــدُوٓاْؐ إِنَّ ۰للَّــهَ لاَ يُحِــــبُّ ۴لْمُعْتَــدِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 90, 'وَكُلُــواْ مِمَّــا رَزَقَكُــمُ ۴للَّهُ حَچَــلًا طَيِّبــــــاًؐ وَاتَّقُــواْ ۴للَّهَ ۰ﻟـذِىٓ أَنتُــم بِهِ” مُومِنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 91, 'لاَ يُوَ۬اخِذُكُــمُ ۴للَّهُ بِاللَّغْوۣ فِىٓ أَيْمَــٰنِكُمْؐ وَچَكِنْ يُّوَ۬اخِذُكُم بِمَــا عَقَّدتُّــمُ ۴لاَيْمَـٰنَؐ فَكَفَّــٰرَتُهُ; إِطْعَامُ عَشَرَةِ مَسَــٰكِيـنَ مِنَ اَوْسَطِ مَا تُطْعِمُونَ أَهْلِيكُــمُ; أَوْ كِسْــوَتُــهُــمُ; أَوْ تَحْرۣيرُ رَقَبَــــةٍؐ فَمَن لَّــــمْ يَجِــدْ فَصِيَــامُ ثَـچَثَةِ أَيَّــــامٍؐ ذَ؛لِــكَ كَفَّــٰرَةُ أَيْمَــٰنِــكُــمُ; إِذَا حَلَفْتُـــــمْؐ وَاحْفَظُــوٓاْ أَيْمَــٰـنَكُــمْؐ كَــذَ؛لِــــكَ يُبَيِّـنُ ۴للَّــهُ لَكُــمُ; ءَايَــٰتِــهِ” 121 لَعَلَّكُــمْ تَشْكُــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 92, 'يَـٰٓأَيُّهَــا ۰لذِيـنَ ءَامَنُوٓاْ إِنَّــمَــا ۰لْخَمْــرُ وَالْمَيْسِــرُ وَالاَنصَــابببُ وَالاَزْچَـــمُ رۣجْـسٌ مِّنْ عَمَلِ ۱لشَّــيْــطَـٰنِ فَاجْتَنِبُــوهُ لَعَلَّكُــمْ تُفْلِحُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 93, 'إِنَّمَـا يُرۣيدُ ۴لشَّيْطَـٰنُ أَنْ يُّوقِــعَ بَيْنَكُــمُ ۴لْعَدَ؛وَةَ وَالْبَغْــضَــآءَ فِى ۱لْخَمْــرۣ وَالْمَيْسِــــرۣ وَيَصُدَّكُمْ عَـن ذِكْرۣ ۱للَّهِ وَعَـنِ ۱لصَّلَوٰةِؐ فَهَلَ اَنتُم مُّنتَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 94, 'وَأَطِيعُــواْ ۴للَّــهَ وَأَطِيعُــواْ ۴لرَّسُــولَ وَاحْذَرُواْؐ فَـــــإِن تَوَلَّيْتُمْ فَاعْلَمُوٓاْ أَنَّمَــا عَلَيٰ رَسُولِنَــا ۰لْبَچَـغُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 95, 'لَيْسَ عَلَي ۰لذِيـنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَــٰــتِ جُنَاحٌ فِيمَا طَعِمُــوٓاْ إِذَا مَا "تَّقَواْ وَّءَامَنُــواْ وَعَمِلُــواْ ۴ڤصَّـٰڤِحَــٰــتِ ثُمَّ "تَّقَواْ وَّءَامَنُواْ ثُمَّ "تَّقَواْ وَّأَحْسَنُواْؐ وَاللَّهُ يُحِــبُّ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 96, 'يَـٰٓأَيُّهَـا ۰لذِينَ ءَامَنُـواْ لَيَبْلُوَنَّكُمُ ۴للَّهُ بِشَىْءٍ مِّـنَ ۰لصَّيْدِ تَنَالُهُ; أَيْدِيكُــمْ وَرۣمَاحُكُــمْ لِيَعْلَــمَ ۰للَّهُ مَـنْ يَّخَافُــهُ„ بِالْغَيْــــبِؐ فَمَنِ ''عْتَدۭيٰ بَعْدَ ذَ؛لِــكَ فَلَهُ„ عَذَاببب٘ اَلِيـمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 97, 'يَـٰٓأَيُّهَا ۰لذِيـنَ ءَامَنُواْ لاَ تَقْتُلُـواْ ۴لصَّيْدَ وَأَنتُمْ حُرُمٌؐ وَمَـن قَتَلَهُ„ مِنكُم مُّتَعَمِّـداً فَجَزَآءُ مِثْلِ مَا قَتَلَ مِنَ ۰لنَّعَمِ يَحْكُـمُ بِهِ” ذَوَا عَدْلٍ مِّنكُــمْ هَدْيــاَۢ بَــٰلِغَ 122 ۰لْكَــعْـبَــةِ أَوْ كَــفَّــٰـرَةُ طَعَــامِ مَسَــٰكِيـنَ أَوْعَــدْلُ ذَ؛لِكَ صِيَامــاً لِّيَـذُوقَ وَبَــالَ أَمْرۣهِؐ” عَفَـا ۰للَّهُ عَمَّا سَلَــفَؐ وَمَنْ عَــادَ فَيَنتَقِــمُ ۴للَّــهُ مِنْــهُؐ وَاللَّــهُ عَزۣيــزٌ ذُو èنتِقَــامٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 98, '۷حِـلَّ لَكُــمْ صَيْدُ ۴ڤْبَحْرۣ وَطَعَامُــهُؐ„ مَتَــٰعاً لَّكُمْ وَلِلسَّيَّارَةِؐ وَحُرّۣمَ عَلَيْكُمْ صَيْــدُ ۴لْبَــرّۣ مَا دُمْتُــمْ حُرُمــاًؐ وَاتَّقُواْ ۴للَّــهَ ۰ﻟـذِىٓ إِلَيْـهِ تُحْشَــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 99, '© جَعَلَ ۰للَّــهُ ۴لْكَعْــبَــةَ ۰لْبَيْــــتَ ۰لْحَــرَامَ قِــيَــٰماً لِّلنَّــاسِ وَالشَّــهْــرَ ۰لْحَــرَامَ وَالْهَــدْيَ وَالْقَـلَئِدَؐ ذَ؛لِـــكَ لِتَعْــلَــمُــوٓاْ أَنَّ ۰للَّـهَ يَعْلَــمُ مَــا فِى ۱لسَّمَـــٰوَ؛تتتِ وَمَـا فِى ۱لاَرْضِ وَأَنَّ ۰للَّهَ بِكُـلِّ شَيْءٖ عَلِيــم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 100, '''عْــلَــمُــوٓاْ أَنَّ ۰للَّهَ شَــدِيــدُ ۴لْــعِــقَــــابِ وَأَنَّ ۰للَّـــهَ غَفُــورٌ رَّحِــيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 101, 'مَّا عَلَي ۰لرَّسُـولِ إِلاَّ ۰لْبَچَغُؐ وَاللَّهُ يَعْلَــــمُ مَا تُبْدُونَ وَمَا تَكْتُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 102, 'قُل لاَّ يَسْتَوۣى ۱لْخَبِيــــثُ وَالطَّيِّــــبُ وَلَوَ اَعْجَبَــكَ كَــثْــرَةُ ۴لْخَبِــيــــثِؐ فَــاتَّــقُــواْ ۴للَّهَ يَـٰٓٱُوْلِى ۱لاَلْبَـــٰــبِ لَعَلَّكُـمْ تُفْلِحُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 103, 'يَـٰٓأَيُّهَا ۰لــذِيـنَ ءَامَــنُــواْ لاَ تَــسْــَٔـلُواْ عَنَ اَشْيَآءَ اۭن تُــبْــدَ لَكُـمْ تَسُؤْكُــمْؐ وَإِن تَسْـَٔلُــواْ عَنْهَــا حِيـنَ يُنَــزَّلُ ۴لْقُرْءَانُ تُبْدَ لَكُــمْ عَفَــا ۰للَّهُ عَنْهَاؐ وَاللَّهُ غَفُــور٘ حَلِــيــــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 104, '12 قَدْ سَأَلَهَــا قَوْمٌ مِّـن قَــبْــلِــكُمْ ثُــمَّ أَصْبَحُواْ بِهَا كۭــٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 105, 'مَـا جَعَـلَ ۰للَّهُ مِـنۢ بَحِيــرَةٍ وَلاَ سَآئِبَــةٍ وَلاَ وَصِيلَــةٍ وَلاَ حَــامٍؐ وَچَكِنَّ ۰لذِيـنَ كَفَـرُواْ يَفْتَرُونَ عَـلَي ۰للَّــهِ ۱لْكَـذِبببَ وَأَكْثَرُهُــمْ لاَ يَــعْــقِلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 106, 'وَإِذَا قِيلَ لَــهُــمْ تَعَالَــوۣاْ اِلَيٰ مَــــآ أَنــــزَلَ ۰للَّهُ وَإِلَي ۰لرَّسُولِ قَالُواْ حَسْبُنَــا مَــا وَجَدْنَــا عَلَيْــهِ ءَابَــآءَنَــآؐ أَوَلَــوْ كَانَ ءَابَــآؤُهُــمْ لاَ يَعْلَمُونَ شَيْــٔـاً وَلاَ يَهْتَــدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 107, 'يَـٰٓأَيُّهَــا ۰لذِينَ ءَامَــنُــواْ عَلَيْكُمُ; أَنفُسَــكُــمْؐ لاَ يَضُــرُّكُــم مَّن ضَلَّ إِذَا "هْتَدَيْتُـمُؐ; إِلَـي ۰للَّهِ مَرْجِعُكُــمْ جَمِيعــاً فَيُنَبِّيؖكُــم بِمَــا كُنــتُــمْ تَعْمَلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 108, 'يَـٰٓأَيُّهَــا ۰لذِيـنَ ءَامَــنُــواْ شَهَـــٰدَةُ بَيْنِكُمُ; إِذَا حَضَــرَ أَحَدَكُــمُ ۴لْمَــوْتتتُ حِيـنَ ۰لْوَصِــيَّــةِ ''ثْنَـٰنِ ذَوَا عَدْلٍ مِّنكُمُ; أَوَ —اخَـرَ؛نِ مِنْ غَيْرۣكُــمُ; إِنَ اَنتُـمْ ضَرَبْــتُــمْ فِى ۱لاَرْضِ فَأَصَــٰبَتْكُم مُّصِيبَــةُ ۴لْمَــوْتتتِؐ تَحْبِسُونَــهُــمَــا مِنۢ بَعْدِ ۱لصَّــلَــوٰةِ فَيُقْسِمَـٰنِ بِاللَّهِ إِنِ ''رْتَــبْــتُــمْ لاَ نَشْتَــرۣى بِــهِ” ثَمَنــاً وَلَــوْ كَــانَ ذَا قُرْبۭيٰؐ وَلاَ نَــكْتُــمُ شَهَـــٰدَةَ ۰للَّهِ إِنَّــــآ إِذاً لَّمِنَ ۰لاَثِمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 109, 'فَإِنْ عُثِــرَ عَلَـيٰٓ أَنَّهُــمَــا "سْتَحَقَّــآ إِثْمــاً 124 فَــَٔاخَرَ؛نِ يَقُومَـٰنِ مَقَامَــهُــمَــا مِـنَ ۰لذِيـنَ ۸سْتُحِـقَّ عَلَيْهِــمُ ۴لاَوْلَيَـٰنِ فَيُقْسِمَـٰنِؐ بِاللَّهِ لَشَهَــٰدَتُنَآ أَحَـقُّ مِن شَهَــٰدَتِهِمَـا وَمَا "عْتَـدَيْــنَــآؐ إِنَّــآ إِذاً لَّـمِـنَ ۰لظَّـٰلِمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 110, 'ذَ؛لِكَ أَدْنۭـيٰٓ أَنْ يَّاتُـواْ بِالشَّــهَــٰـدَةِ عَلَيٰ وَجْــهِــهَــآ أَوْ يَخَافُــوٓاْ أَن تُرَدَّ أَيْمَـٰنٛ بَعْدَ أَيْمَـــٰنِــهِـــمْؐ وَاتَّقُــواْ ۴للَّهَؐ وَاسْمَعُــواْؐ وَاللَّــهُ لاَ يَهْدِى ۱لْقَــوْمَ ۰لْــفَــٰسِقِــيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 111, 'يَوْمَ يَجْمَعُ ۴للَّهُ ۴لرُّسُـلَ فَيَقُولُ مَاذَآ ٱُجِبْتُمْؐ قَالُواْ لاَ عِلْــمَ لَنَــآ إِنَّكَ أَنتَ عَچَّــمُ ۴لْغُيُــوبببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 112, 'إِذْ قَالَ ۰للَّهُ يَــٰعِيسَـي "بْنَ مَرْيَــمَ ۸ذْكُــرْ نِعْمَــتِى عَلَيْــكَ وَعَلَيٰ وَ؛لِدَتِــكَ إِذَ اَيَّدتُّــكَ بِرُوحِ ۱لْقُدُسِ تُكَلِّــمُ ۴لنَّــاسَ فِى ۱لْمَهْدِ وَكَــهْــلًؐا وَإِذْ عَلَّمْتُـكَ ۰لْكِتَــٰــبَ وَالْحِكْمَةَ وَالتَّوْرۭيٰةَ وَالِانجِيلَؐ وَإِذْ تَخْلُقُ مِـنَ ۰لطِّيـنِ كَهَيْــَٔـةِ ۱لطَّيْــرۣ بِــإِذْنِى فَتَنفُخُ فِيهَـا فَتَكُونُ طَـٰٓئِــراَۢ بِــإِذْنِىؐ وَتُــبْــرۣىُٔ ۴لاَكْــمَــهَ وَالاَبْــرَصَ بِــإِذْنِىؐ وَإِذْ تُخْــرۣجُ ۴لْمَــوْتۭـيٰ بِإِذْنِىؐ وَإِذْ كَفَفْتُ بَنِىٓ إِسْرَآءِيـلَ عَـنــكَ إِذْ جِيؔتَهُــم بِــالْبَيِّنَــٰــتِ فَقَالَ ۰لـذِينَ كَفَرُواْ مِنْهُمُ; إِنْ هَــٰذَآإِلاَّ سِحْـرٌ مُّبِيـنٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 113, '¥ وَإِذَ اَوْحَيْــتُ إِلَي ۰لْحَوَارۣيِّـﯧـنَ أَنَ —امِنُـواْ بِى وَبِرَسُولِىؐ قَالُوٓاْ ءَامَــنَّــا وَاشْهَدْ بِأَنَّـنَــا 125 مُسْلِــمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 114, 'إِذْ قَــــالَ ۰لْحَوَارۣيُّــونَ يَــٰعِيسَـي "بْـنَ مَرْيَــمَ هَلْ يَسْتَطِيــعُ رَبُّـكَ أَنْ يُّنَــزّۣلَ عَلَيْــنَــا مَآئِــدَةً مِّـنَ ۰لسَّمَــآءِؐ قَــــالَ "تَّقُواْ ۴للَّهَ إِن كُنتُــم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 115, 'قَــالُواْ نُرۣيدُ أَن نَّاكُـلَ مِنْــهَــا وَتَطْمَئِـنَّ قُلُوبُنَـا وَنَعْلَمَ أَن قَدْ صَدَقْتَــنَــا وَنَكُونَ عَلَيْهَــا مِـنَ ۰لشَّــٰهِدِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 116, 'قَالَ عِيسَـي "بْنُ مَرْيَمَ ۰للَّــهُـمَّ رَبَّــنَــآ أَنــزۣلْ عَلَيْــنَــا مَآئِدَةً مِّـنَ ۰لسَّمَـآءِ تَكُونُ لَنَــا عِيداً لَأِّوَّلِنَا وَءَاخِرۣنَــا وَءَايَةً مِّنــكَؐ وَارْزُقْــنَــاؐ وَأَنــتَ خَيْــرُ ۴لرَّ؛زۣقِــيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 117, 'قَــالَ ۰للَّــهُ إِنِّى مُنَزّۣلُهَا عَلَيْكُــمْ فَمَـنْ يَّكْفُــرْ بَعْدُ مِنكُــمْ فَإِنِّـيَ ٱُعَذِّبُــــهُ„ عَذَابــاً لٓاَّ ٱُعَــذِّبُــهُ; أَحَــداً مِّـنَ ۰لْعَــٰلَمِــيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 118, 'وَإِذْ قَــالَ ۰للَّــهُ يَــٰعِيسَـي "بْنَ مَرْيَــمَ ءَآنـــتَ قُلْــتَ لِلنَّــاسِ ''تَّخِذُونِى وَٱُمِّـيَ إِچَــهَيْنِ مِن دُونِ ۱للَّــهِؐ قَــالَ سُبْحَــٰـنَــــكَ مَا يَكُونُ لِـيَ أَنَ اَقُــولَ مَا لَيْـسَ لِى بِحَق؉ّؐ اِن كُنــتُ قُلْتُهُ„ فَقَدْ عَلِمْتَهُؐ, تَعْلَـمُ مَا فِى نَفْسِى وَلآَ أَعْلَــمُ مَــا فِى نَفْسِــكَؐ إِنَّــكَ أَنـــتَ عَــچَّــمُ۴لْغُــيُــوبببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 119, 'مَــا قُــلْــــتُ لَـهُـــمُ; إِلاَّ مَــآ أَمَــرْتَنِى بِهِ“ أَنُ ۶عْبُــدُواْ ۴للَّــهَ رَبِّى وَرَبَّــكُــمْؐ وَكُــنــــتُ عَلَيْهِمْ شَهِيداً مَّا دُمْــتُ فِيهِمْؐ فَلَــمَّــا تَوَفَّيْتَــنِى كُنــــتَ أَنــــتَ 126 ۰لرَّقِــيــــبَ عَلَــيْــهِــمْؐ وَأَنــــتَ عَلَـيٰ كُـلِّ شَيْءٍ شَهِــيــد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 120, 'اِن تُعَــذِّبْــهُــمْ فَإِنَّهُمْ عِبَادُكككَؐ وَإِن تَغْفِرْ لَهُــمْ فَإِنَّــكَ أَنتَ ۰لْعَزۣيــزُ ۴لْحَكِيــمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 121, 'قَــالَ ۰للَّهُ هَـٰذَا يَوْمَ يَنفَعُ ۴لصَّـٰدِقِينَ صِدْقُهُمْؐ لَهُــمْ جَنَّـــٰــتٌ تَجْرۣى مِـن تَحْتِهَــا ۰لاَنْهَــٰرُ خَـٰلِدِينَ فِيــهَــآ أَبَــــداًؐ رَّضِـيَ ۰للَّهُ عَنْهُمْ وَرَضُواْ عَنْهُؐ ذَ؛لِــكَ ۰لْفَــوْزُ ۴لْعَظِيــمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (5, 122, 'لِلهِ مُلْــكُ ۴لسَّمَــٰوَ؛تتتِ وَالاَرْضِ وَمَا فِيهِـنَّؐ وَهُوَ عَلَيٰ كُـلِّ شَيْءٍ قَدِير٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيــمِ ۱لْحَمْــدُ لِـلهِ ۱ﻟ﮲ خَلَـقَ ۰لسَّمَــٰـوَ؛تِ وَالاَرْضَ وَجَعَلَ ۰لظُّلُمَــٰــتِ وَالنُّــورَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 2, 'ثُــــمَّ ۰لذِيـنَ كَــفَــــرُواْ بِــرَبِّــهِــمْ يَعْــدِلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 3, 'هُــوَ ۰ﻟــ﮲ خَلَقَــكُـــم مِّـن طِينٍ ثُــــمَّ قَضۭـيٰٓ أَجَلًؐا وَأَجَـلٌ مُّسَمّـيٗ عِنــدَهُؐ, ثُــمَّ أَنــتُــمْ تَــمْــتَـــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 4, 'وَهُوَ ۰للَّهُؐ فِى ۱لسَّمَــٰوَ؛تتتِ وَفِى ۱لاَرْضِ يَعْلَــمُ سِرَّكُمْ وَجَهْرَكُــمْ وَيَعْلَــمُ مَــا تَكْــسِبُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 5, 'وَمَــا تَــاتِيهِم مِّـنَ —ايَةٍ مِّنَ —ايَــٰــتِ رَبِّــهِــمُ; إِلاَّ كَانُــواْ عَنْــهَــا مُعْرۣضِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 6, 'فَقَدْ كَــذَّبُــواْ 127 بِالْحَـقِّ لَمَّــا جَــآءَهُمْؐ فَسَوْفَ يَــاتِيــهِمُ; أَنۢبَـٰٓؤُاْ مَــا كَــانُــواْ بِهِ” يَسْتَــهْــزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 7, 'أَلَــمْ يَــرَوْاْ كَــمَ اَهْلَكْنَــا مِن قَبْلِهِــم مِّن قَــرْنٍ مَّكَّنَّــٰهُــمْ فِى ۱لاَرْضِ مَــا لَــمْ نُمَكِّن لَّكُـمْؐ وَأَرْسَلْنَــا ۰لسَّمَــآءَ عَلَيْهِــــم مِّدْرَاراًؐ وَجَعَــلْــنَــا ۰لاَنْهَــٰرَ تَجْرۣى مِـن تَحْــتِـــهِــــــمْ فَأَهْلَكْنَـــٰهُم بِذُنُوبِهِــمْؐ وَأَنشَــأْنَــا مِـنۢ بَعْدِهِــمْ قَرْنــاٗ —اخَـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 8, 'وَلَوْ نَزَّلْنَــا عَلَيْــكَ كِتَــٰباً فِى قِرْطَاسٍ فَلَمَسُوهُ بِأَيْدِيهِــمْ لَقَــالَ ۰لذِيـنَ كَفَرُوٓاْ إِنْ هَــٰذَآ إِلاَّ سِحْـرٌ مُّبِيـنٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 9, 'وَقَالُــواْ لَوْلآَ ٱُنــزۣلَ عَلَيْــهِ مَلَــكٌؐ وَلَوَ اَنزَلْنَــا مَلَكاً لَّقُضِـيَ ۰لاَمْرُ ثُــــمَّ لاَ يُنظَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 10, 'وَلَوْ جَعَلْنَـٰهُ مَلَكـاً لَّجَعَلْنَــٰهُ رَجُلًا وَلَلَبَسْــنَــا عَلَيْهِــم مَّا يَلْبِسُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 11, 'وَلَقَدُ ۶سْتُهْزۣىَٔ بِرُسُـلٍ مِّن قَبْلِـكَ فَحَاقَ بِالذِينَ سَخِرُواْ مِنْهُم مَّــا كَانُــواْ بِهِ” يَسْتَهْــزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 12, 'قُـلْ سِـيرُواْ فِى ۱لاَرْضِ ثُمَّ ۸نظُـرُواْ كَـيْـفَ كَـانَ عَــٰقِبَــةُ ۴لْمُــكَذِّبِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 13, 'قُـل لِّمَن مَّــا فِى ۱لسَّــمَـــٰوَ؛تتتِ وَالاَرْضِ قُل لِّلهِؐ كَتَــبَ عَلَيٰ نَفْسِهِ ۱لرَّحْمَةَؐ ڤَيَجْمَعَنَّكُــمُ; إِلَيٰ يَــوْمِ ۱لْقِيَــٰمَةِ لاَ رَيْبَ فِيهِؐ ۱لذِينَ خَسِرُوٓاْ أَنفُسَهُــمْ فَهُــمْ لاَ يُومِــنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 14, '128 © وَلَهُ„ مَا سَكَنَ فِى ۱ليْلِ وَالنَّهۭــارۣؐ وَهُوَ ۰لسَّمِيــعُ ۴لْعَلِيــمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 15, 'قُـلَ اَغَيْـرَ ۰للَّهِ أَتَّخِذُ وَلِيّــاً فَاطِــرۣ ۱لسَّمَــٰوَ؛تتتِ وَالاَرْضِؐ وَهُــوَ يُطْعِــمُ وَلاَ يُطْعَمُؐ قُـلِ اِنِّيَ ٱُمِــرْتتتُ أَنَ اَكُــونَ أَوَّلَ مَنَ اَسْــلَــمَؐ وَلاَ تَكُـونَـنَّ مِنَ ۰لْمُشْرۣكِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 16, 'قُـلِ اِنِّـيَ أَخَــافُ إِنْ عَصَــيْــــتُ رَبِّى عَذَابببَ يَــوْمٖ عَظِيــمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 17, 'مَّـنْ يُّصْرَفْ عَنْـهُ يَوْمَــئِــذٍ فَــقَــدْ رَحِمَــهُؐ, وَذَ؛لِــكَ ۰لْفَــوْزُ ۴لْمُبِــيـنُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 18, 'وَإِنْ يَّمْسَــسْـكَ ۰للَّهُ بِضُــرٍّ فَلاَ كَاشِفَ لَهُ; إِلاَّ هُوَؐ وَإِنْ يَّــمْسَــسْــــكَ بِخَيْرٍ فَهُوَ عَلَيٰ كُلِّ شَيْءٍ قَدِيــرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 19, 'وَهُوَ ۰لْقَــاهِرُ فَوْقَ عِبَــادِهِؐ” وَهُوَ ۰لْحَكِــيــمُ ۴لْخَبِيــرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 20, 'قُلَ اَيُّ شَيْءٖ اَكْبَــرُ شَهَـٰدَةً قُلِ ۱للَّهُؐ شَهِــيــدٛ بَيْــنِى وَبَيْنَكُــمْؐ وَٱُوحِـيَ إِلَيَّ هَـٰذَا ۰لْقُرْءَانُ لُءِنذِرَكُــم بِهِ” وَمَـنۢ بَلَغَؐ أَئنَّكُمْ لَتَشْهَدُونَ أَنَّ مَعَ ۰للَّهِ ءَالِهَةٗ ۷خْرۭيٰ قُـل لٓاَّ أَشْهَدُؐ قُـلِ اِنَّمَــا هُوَ إِچَهٌ وَ؛حِدٌؐ وَإِنَّنِى بَرۣىٓءٌ مِّمَّا تُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 21, '۰لذِينَ ءَاتَيْنَــٰهُمُ ۴لْكِتَــٰــبَ يَعْرۣفُونَهُ„ كَمَــا يَعْــرۣفُونَ أَبْنَــآءَهُــــمُؐ ۴لذِيـنَ خَسِرُوٓاْ أَنفُسَهُمْ فَهُمْ لاَ يُومِنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 22, 'وَمَـنَ اَظْلَــمُ مِمَّنِ ''فْتَرۭيٰ عَلَي ۰للَّهِ كَذِباٗ اَوْ كَذَّبببَ بِـَٔايَــٰتِهِؐ“ إِنَّهُ„ لاَ يُفْلِحُ 129 ۴لظَّـٰلِمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 23, 'وَيَوْمَ نَحْشُرُهُــمْ جَمِيــعــاً ثُــمَّ نَقُــولُ لِلذِينَ أَشْرَكُوٓاْ أَيْنَ شُرَكَآؤُكُمُ ۴لذِينَ كُنتُمْ تَزْعُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 24, 'ثُــمَّ لَــمْ تَكُن فِتْنَتَهُــمُ; إِلٓاَّ أَن قَالُواْ وَاللَّهِ رَبِّنَــا مَا كُنَّــا مُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 25, '۸نظُرْ كَيْفَ كَذَبُواْ عَلَـيٰٓ أَنفُسِهِمْ وَضَلَّ عَنْهُم مَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 26, 'وَمِنْهُم مَّنْ يَّسْتَمِعُ إِلَيْــكَؐ وَجَعَلْنَا عَلَيٰ قُلُوبِهِمُ; أَكِنَّــةٗ اَنْ يَّـفْــقَــهُــوهُ وَفِىٓ ءَاذَانِــهِــمْ وَقْــراًؐ وَإِنْ يَّــرَوْاْ كُلَّ ءَايَةٍ لاَّ يُومِنُـواْ بِهَاؐ حَتَّيٰٓ إِذَا جَــآءُوكَ يُجَــٰدِلُونَــكَ يَقُــولُ ۴لذِيـنَ كَــفَــرُوٓاْ إِنننْ هَـٰذَآ إِلٓاَّ أَسَـٰــطِــيــــرُ ۴لاَوَّلِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 27, 'وَهُمْ يَنْهَوْنَ عَنْــهُ وَيَنْـَٔــوْنَ عَنْهُؐ وَإِنْ يُّهْــلِــكُــونَ إِلٓاَّ أَنفُسَهُمْ وَمَا يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 28, 'وَلَوْ تَــرۭيٰٓ إِذْ وُقِفُواْ عَــلَي ۰لنّۭــارۣ فَقَالُــواْ يَــٰلَيْتَنَــا نُرَدُّؐ وَلاَ نُكَذِّبببُ بِـَٔايَــٰــتِ رَبِّــنَــا وَنَكُــونُ مِـنَ ۰لْمُومِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 29, 'بَلْ بَــدَا لَهُــم مَّا كَانُــواْ يُخْــفُــونَ مِـن قَبْلُؐ وَلَــوْ رُدُّواْ لَعَــادُواْ لِمَــا نُهُــواْ عَنْــهُؐ وَإِنَّهُمْ لَكَــٰـذِبُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 30, 'وَقَالُوٓاْ إِنْ هِـيَ إِلاَّ حَيَــاتُــنَــا ۰لدُّنْيۭــا وَمَا نَحْـنُ بِمَبْعُوثِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 31, 'وَلَــوْ تَــرۭيٰٓ إِذْ وُقِفُــواْ عَلَيٰ رَبِّهِــمْ قَــالَ أَلَيْـسَ هَـٰذَا بِالْحَـقﱢّؐ 10 قَالُواْ بَلۭيٰ وَرَبِّنَــاؐ قَــالَ فَذُوقُواْ ۴لْعَذَابببَ بِمَا كُنتُــمْ تَكْفُــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 32, 'قَدْ خَسِرَ ۰لذِينَ كَذَّبُواْ بِلِقَــآءِ ۱للَّهِ حَتَّيٰٓ إِذَا جَــآءَتْــهُــمُ ۴لسَّاعَةُ بَغْتَــةً قَالُواْ يَـٰحَسْرَتَنَــا عَلَـيٰ مَا فَرَّطْنَا فِيهَــا وَهُــمْ يَحْمِلُــونَ أَوْزَارَهُــمْ عَلَـيٰ ظُهُورۣهِمُؐ; أَلاَ سَــآءَ مَــا يَــزۣرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 33, 'وَمَا ۰لْحَيَوٰةُ ۴لدُّنْيۭــآ إِلاَّ لَعِــبٌ وَلَهْــوٌؐ وَلَلــدَّارُ ۴لاَخِــرَةُ خَيْــرٌ لِّلذِيـنَ يَتَّقُــونَؐ أَفَــلاَ تَعْقِلُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 34, 'قَدْ نَعْلَــمُ إِنَّــهُ„ ڤَيُحْزۣنُكَ ۰ﻟ﮲ يَقُولُــونَؐ فَإِنَّــهُــمْ لاَ يُكْذِبُونَــــكَؐ وَچَكِنَّ ۰لظَّــٰلِمِـيـنَ بِـَٔايَــٰــتِ ۱للَّهِ يَجْحَــدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 35, 'وَلَقَدْ كُـذِّبَـــــتْ رُسُـلٌ مِّن قَبْــلِـكَ فَصَبَــرُواْ عَلَـيٰ مَا كُذِّبُــواْ وَٱُوذُواْ حَتَّيٰٓ أَتۭيٰــهُــمْ نَصْرُنَــــاؐ وَلاَ مُبَدِّلَ لِكَلِــمَــٰــتِ ۱للَّهِؐ وَلَقَــدْ جَــآءَكككَ مِـن نَّــبَــإِىْ ۱لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 36, 'وَإِن كَانَ كَبُرَ عَلَيْــكَ إِعْرَاضُــهُــــمْ فَإِنِ ''سْتَطَعْــــتَ أَن تَبْتَغِيَ نَفَقاً فِى ۱لاَرْضِ أَوْ سُلَّماً فِى ۱لسَّمَـآءِ فَتَاتِيَهُــم بِـَٔايَــةٍؐ وَلَوْ شَــآءَ ۰للَّهُ لَجَمَعَهُمْ عَلَي ۰لْهُدۭيٰؐ فَلاَ تَكُونَنَّ مِنَ ۰لْجَــٰهِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 37, '¤ إِنَّمَا يَسْتَجِيــبُ ۴لذِينَ يَسْمَعُونَؐ وَالْمَوْتۭـيٰ يَبْعَثُهُــمُ ۴للَّهُؐ ثُمَّ إِلَيْهِ يُرْجَعُـونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 38, 'وَقَالُواْ لَوْلاَ نُزّۣلَ عَلَيْــهِ ءَايَــةٌ مِّن رَّبِّــهِؐ” 11 قُـلِ اِنَّ ۰للَّــهَ قَــــادِر٘ عَلَـيٰٓ أَنْ يُّــنَــزّۣلَ ءَايَةًؐ وَچَكِـنَّ أَكْــثَــرَهُمْ لاَ يَعْــلَــمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 39, 'وَمَــا مِـن دَآبَّــةٍ فِى ۱لاَرْضِ وَلاَ طَـٰٓــئِــرٍ يَطِيــرُ بِجَنَاحَيْهِ إِلٓاَّ ٱُمَــم٘ اَمْثَالُكُـمؐ مَّا فَرَّطْــنَــا فِى ۱لْكِتَـــٰــبِ مِـن شَيْءٍؐ ثُــمَّ إِلَيٰ رَبِّهِــمْ يُحْشَــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 40, 'وَالذِينَ كَــذَّبُــواْ بِـَٔايَــٰتِــنَــا صُــمٌّ وَبُكْمٌ فِى ۱لظُّلُمَـٰــــتِؐ مَـنْ يَّشَــإِ ۱للَّهُ يُضْلِلْــهُؐ وَمَـنْ يَّشَــأْ يَجْعَلْــهُ عَلَـيٰ صِرَ؛طٍ مُّسْتَقِيــمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 41, 'قُلَ اَرَ×يْتَكُــمُ; إِنَ اَتۭيٰكُــمْ عَــذَابُ ۴للَّهِ أَوَ اَتَتْكُــمُ ۴لسَّاعَةُ أَغَيْرَ ۰للَّهِ تَدْعُونَ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 42, 'بَلِ اِيَّاهُ تَــدْعُــونَ فَيَكْشِــفُ مَا تَدْعُــونَ إِلَيْــهِ إِن شَــــــــآءَ وَتَنسَــوْنَ مَا تُشْرۣكُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 43, 'وَلَقَدَ اَرْسَلْنَــــآ إِلَـيٰٓ ٱُمَــمٍ مِّـن قَبْلِكَ فَأَخَــذْنَــٰهُـم بِالْبَأْسَــآءِ وَالضَّــرَّآءِ لَعَلَّــهُــــمْ يَتَضَرَّعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 44, 'فَلَوْلآَ إِذْ جَآءَهُم بَأْسُنَا تَضَــرَّعُــواْؐ وَچَكِـن قَسَــــتْ قُلُوبُهُــــمْ وَزَيَّـنَ لَهُــمُ ۴لشَّيْطَـٰنُ مَــا كَــانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 45, 'فَلَمَّــا نَسُــواْ مَا ذُكِّرُواْ بِهِ” فَتَحْــنَــا عَلَيْهِــمُ; أَبْوَ؛بببَ كُـلِّ شَيْءٖؐ حَتَّـيٰٓ إِذَا فَرۣحُــواْ بِمَــآ ٱُوتُــوٓاْ أَخَذْنَــٰـهُــم بَغْتَــةً فَإِذَا هُم مُّبْلِسُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 46, 'فَقُطِعَ دَابِرُ ۴لْقَوْمِ ۱لذِينَ ظَلَمُواْؐ وَالْحَمْدُ لِلهِ رَبببِّ ۱لْعَــٰلَـمِـينَؐ 12');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 47, 'قُلَ اَرَ×يْتُمُ; إِنَ اَخَذَ ۰للَّهُ سَمْعَكُمْ وَأَبْصَـٰرَكُمْ وَخَتَمَ عَلَيٰ قُلُوبِكُم مَّنِ اِچَه٘ غَيْرُ ۴للَّهِ يَاتِيكُم بِهِؐ ۹نظُرْ كَيْفَ نُصَرّۣفُ ۴لاَيَـٰــتِ ثُمَّ هُمْ يَصْــدِفُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 48, 'قُلَ اَرَ×يْتَكُــــمُ; إِنَ اَتۭيٰكُمْ عَذَابُ ۴للَّهِ بَغْتَةٗ اَوْ جَهْرَةٗ هَلْ يُهْلَــكُ إِلاَّ ۰لْقَــوْمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 49, 'وَمَا نُرْسِلُ ۴لْمُرْسَلِينَ إِلاَّ مُبَشِّرۣينَ وَمُنذِرۣينَؐ فَمَنَ —امَنَ وَأَصْلَحَ فَلاَ خَــوْف٘ عَلَيْهِــمْ وَلاَ هُــمْ يَحْزَنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 50, 'وَالذِينَ كَذَّبُواْ بِـَٔايَــٰتِنَـا يَمَسُّهُمُ ۴لْعَذَابببُ بِمَا كَــانُــواْ يَفْسُقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 51, 'قُل لٓاَّ أَقُولُ لَكُمْ عِندِى خَزَآئِـنُ ۴للَّهِ وَلآَ أَعْلَــمُ ۴لْغَيْــبَ وَلآَ أَقُــولُ لَكُمُ; إِنِّى مَـلَــك٘ؐ اِنَ اَتَّبِــعُ إِلاَّ مَــا يُــوحۭيٰٓ إِلَيَّؐ قُـلْ هَلْ يَسْتَوۣى ۱لاَعْمۭيٰ وَالْبَصِيرُؐ أَفَلاَ تَتَفَــكَّــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 52, 'وَأَنذِرْ بِهِ ۱لذِينَ يَخَافُونَ أَنْ يُّحْشَرُوٓاْ إِلَيٰ رَبِّهِمْ لَيْـسَ لَهُـم مِّن دُونِهِ” وَلِـيٌّ وَلاَ شَفِيعٌ لَّعَلَّهُمْ يَتَّقُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 53, 'وَلاَ تَطْــرُدِ ۱لذِينَ يَدْعُونَ رَبَّهُم بِالْغَدَوٰةِ وَالْعَشِيِّ يُرۣيدُونَ وَجْــهَــهُ„ مَا عَلَيْــكَ مِـنْ حِسَابِهِم مِّن شَيْءٍ وَمَا مِنْ حِسَابِــكَ عَلَيْهِـم مِّن شَيْءٍ فَتَــطْــرُدَهُــمْ فَتَكُــونَ مِـنَ ۰لظَّـٰلِمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 54, 'وَكَذَ؛لِكَ 1 فَتَنَّــــا بَعْضَهُم بِبَعْضٍ لِّيَقُولُوٓاْ أَهَـٰٓؤُلآَءِ مَـنَّ ۰للَّهُ عَلَيْهِــم مِّنۢ بَيْنِنَـآؐ أَلَيْسَ ۰للَّهُ بِأَعْلَمَ بِالشَّــٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 55, 'وَإِذَا جَآءَكككَ ۰لذِينَ يُومِنُونَ بِـَٔايَــٰتِنَــــا فَقُلْ سَچَم٘ عَلَيْكُمْؐ كَتَــــَبَ رَبُّكُــمْ عَلَـيٰ نَفْسِهِ ۱لرَّحْمَةَ أَنَّــهُ„ مَنْ عَمِلَ مِنكُمْ سُوٓءاَۢ بِجَهَــٰلَةٍ ثُــمَّ تَابببَ مِنۢ بَعْدِهِ” وَأَصْلَحَ فَإِنَّهُ„ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 56, 'وَكَذَ؛لِــكَ نُفَصِّلُ ۴لاَيَــٰــتِ وَلِتَسْتَبِيـنَ سَبِيـلَ ۰ڤْمُجْرۣمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 57, 'قُلِ اِنِّى نُهِيــــتُ أَنَ اَعْبُدَ ۰لذِينَ تَدْعُونَ مِن دُونِ ۱للَّهِؐ قُل لٓاَّ أَتَّبِـعُ أَهْــوَآءَكُــــمْؐ قَد ضَّلَلْــــتُ إِذاً وَمَآ أَنَا مِــنَ ۰لْمُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 58, 'قُلِ اِنِّى عَلَيٰ بَــيِّــنَــةٍ مِّن رَّبِّى وَكَذَّبْتُم بِهِؐ” مَا عِندِى مَا تَسْتَعْجِلُونَ بِهِؐ“ إِنننۣ ۱لْحُكْمُ إِلاَّ لِلــهِؐ يَقُــــصُّ ۴لْحَقَّؐ وَهُــوَ خَيْــرُ ۴لْفَــٰصِلِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 59, 'قُـل لَّــوَ اَنَّ عِندِى مَا تَسْتَعْجِلُونَ بِهِ” لَقُضِيَ ۰لاَمْرُ بَيْنِى وَبَيْنَكُمْؐ وَاللَّهُ أَعْلَمُ بِالظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 60, '© وَعِندَهُ„ مَفَاتِحُ ۴لْغَيْــبِ لاَ يَعْلَمُهَآ إِلاَّ هُوَؐ وَيَعْلَمُ مَـا فِى ۱لْبَرّۣ وَاڤْبَحْرۣؐ وَمَـا تَسْقُطُ مِنْ وَّرَقَــةٖ اِلاَّ يَعْلَــمُــهَــا وَلاَ حَبَّــةٍ فِى ظُــلُمَــٰـــتِ ۱لاَرْضِ وَلاَ رَطْــبٍ وَلاَ يَابِـسٖ اِلاَّ فِى كِتَـٰبٍ مُّبِــيـنٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 61, 'وَهُوَ ۰ﻟ﮲ يَتَوَفّۭيٰكُــم بِاليْلِ 14 وَيَعْلَمُ مَا جَرَحْتُم بِالنَّهۭارۣ ثُــمَّ يَبْعَثُكُمْ فِيهِ لِيُقْضۭـيٰٓ أَجَـلٌ مُّسَمّيًؐ ثُمَّ إِلَيْهِ مَرْجِعُكُمْ ثُمَّ يُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَــلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 62, 'وَهُــوَ ۰لْقَاهِــرُ فَوْقَ عِبَــادِهِؐ” وَيُرْسِلُ عَلَيْكُــمْ حَفَظَـةٗؐ حَتَّيٰٓ إِذَا جَــآءَ احَــدَكُــمُ ۴لْمَــوْتتتُ تَوَفَّــتْــهُ رُسُلُنَـا وَهُــمْ لاَ يُفَرّۣطُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 63, 'ثُمَّ رُدُّوٓاْ إِلَـي ۰للَّهِ مَوْلۭيٰهُمُ ۴لْحَقﱢّؐ أَلاَ لَهُ ۴لْحُكْـــمُؐ وَهُوَ أَسْرَعُ ۴لْحَــٰسِبِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 64, 'قُـلْ مَنْ يُّنَجِّيكُم مِّـن ظُلُمَــٰـــتِ ۱لْبَـــرّۣ وَاڤْبَحْرۣ تَدْعُونَهُ„ تَضَرُّعاً وَخُفْيَةً لَّــئِنَ اَنجَيْتَنَا مِنْ هَـٰذِهِ” لَنَكُونَنَّ مِنَ ۰لشَّـٰكِرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 65, 'قُلِ ۱للَّهُ يُنجِيكُم مِّنْهَــا وَمِــن كُلِّ كَرْبٍ ثُــمَّ أَنتُــمْ تُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 66, 'قُلْ هُوَ ۰لْقَادِرُ عَلَيٰٓ أَنْ يَّــبْعَــــثَ عَلَيْكُــمْ عَذَابــاً مِّن فَوْقِــكُــمُ; أَوْ مِـن تَحْــتِ أَرْجُلِــكُمُ; أَوْ يَلْبِسَــكُــمْ شِيَعــاً وَيُذِيـقَ بَعْضَكُــم بَأْسَ بَعْضٖؐ ۶نظُـرْ كَــيْــفَ نُصَــرّۣفُ ۴لاَيَـــٰــتِ لَعَلَّــهُــمْ يَــفْــقَــهُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 67, 'وَكَذَّبببَ بِهِ” قَــوْمُــــكَ وَهُــوَ ۰لْحَقُّؐ قُـل لَّسْــــتُ عَلَيْكُــم بِوَكِيـلٍؐ لِّكُلِّ نَبَإٍ مُّسْتَقَــرٌّؐ وَسَــوْفَ تَــعْــلَــمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 68, 'وَإِذَا رَأَيْــــتَ ۰لذِيـنَ يَخُــوضُــونَ فِىٓ ءَايَـٰــتِــــنَــــا فَأَعْــرۣضْ عَنْــهُــــمْ حَتَّيٰ يَخُوضُــواْ فِى حَدِيــــثٖ غَيْــرۣهِؐ” وَإِمَّــــا 15 يُنسِيَنَّـــكَ ۰لشَّيْطَـٰنُ فَلاَ تَقْعُــدْ بَعْــدَ ۰لذِّكْــرۭيٰ مَعَ ۰لْقَــوْمِ ۱لظَّـٰلِمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 69, 'وَمَا عَلَـي ۰لذِيـنَ يَتَّقُونَ مِـنْ حِسَابِهِــم مِّـن شَيْءٍؐ وَچَكِن ذِكْــرۭيٰ لَعَلَّهُــمْ يَتَّقُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 70, 'وَذَرۣ ۱لذِيـنَ "تَّخَــذُواْ دِينَهُمْ لَعِبــاً وَلَهْواً وَغَرَّتْهُــمُ ۴لْحَيَوٰةُ ۴لدُّنْيۭــاؐ وَذَكِّــرْ بِــهِ“ أَن تُبْسَـلَ نَفْسٛ بِمَــا كَسَــبَــــتْ لَيْـسَ لَهَــا مِن دُونِ ۱للَّــهِ وَلِيٌّ وَلاَ شَفِيعٌؐ وَإِن تَعْـدِلْ كُلَّ عَدْلٍ لاَّ يُوخَــذْ مِنْــهَــآؐ ٱُوْلَئِــكَ ۰لذِينَ ٱُبْسِلُواْ بِمَــا كَسَبُواْ لَهُمْ شَرَابٌ مِّنْ حَمِيمٍ وَعَذَاب٘ اَلِيمٛ بِــمَــا كَانُواْ يَكْفُـرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 71, 'قُـلَ اَنَدْعُواْ مِن دُونِ ۱للَّـهِ مَا لاَ يَنفَعُنَــا وَلاَ يَضُرُّنَــا وَنُرَدُّ عَلَيٰٓ أَعْقَابِنَــا بَعْدَ إِذْ هَدۭيٰنَــا ۰للَّهُ كَاﻟــ﮲ ''سْــتَــهْــوَتْــهُ ۴لشَّيَـٰطِيـنُ فِى ۱لاَرْضِ حَــيْــرَانَؐ لَــهُ; أَصْحَـــٰـــبٌ يَدْعُونَــهُ; إِلَـي ۰لْهُــدَي "يتِنَــاؐ قُـلِ اِنَّ هُدَي ۰للَّــهِ هُــوَ ۰لْهُــدۭيٰ وَٱُمِرْنَا لِنُسْلِمَ لِرَبببِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 72, 'وَأَنَ اَقِيمُواْ ۴لصَّلَوٰةَ وَاتَّــقُــوهُؐ وَهُــوَ ۰ﻟـذِىٓ إِلَيْــهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 73, 'وَهُــوَ ۰ﻟــ﮲ خَلَـقَ ۰لسَّــمَــٰـوَ؛تِ وَالاَرْضَ بِالْحَقﱢّؐ وَيَوْمَ يَقُــولُ كُـنؐ فَــيَــكُــونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 74, 'قَــوْلُــهُ ۴لْحَقُّؐ وَلَــهُ ۴لْمُـلْـــكُؐ يَــوْمَ يُنفَخُ فِى ۱لصُّـورۣؐ عَـٰلِمُ ۴لْغَيْــــبِ وَالشَّهَـٰــدَةِؐ 16 وَهُوَ ۰لْحَكِيــمُ ۴لْخَبِيــرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 75, 'وَإِذْ قَــالَ إِبْرَ؛هِيــمُ لَأِبِيــهِ ءَازَرَ أَتَتَّخِــذُ أَصْنَــامــاٗ —الِهَةٗؐ اِنِّيَ أَرۭيٰــكَ وَقَــوْمَــكَ فِى ضَچَـلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 76, 'وَكَذَ؛لِــكَ نُــرۣىٓ إِبْرَ؛هِــيــمَ مَلَــكُــوتتتَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضِ وَلِيَكُونَ مِنَ ۰لْمُوقِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 77, 'فَلَمَّا جَنَّ عَلَيْهِ ۱ليْلُ رۭءۭا كَوْكَباً قَالَ هَـٰذَا رَبِّىؐ فَلَمَّــآ أَفَلَ قَالَ لآَ ٱُحِــــبُّ ۴لاَفِلِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 78, 'فَــلَــمَّــــا رَءَا ۰لْقَمَرَ بَازۣغــاً قَالَ هَـٰذَا رَبِّىؐ فَلَمَّــآ أَفَلَ قَــــالَ لَئِن لَّــمْ يَهْدِنِى رَبِّى لَأَكُــونَـنَّ مِنَ ۰لْقَــوْمِ ۱لضَّــآلِّـينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 79, 'فَلَمَّــا رَءَا ۰لشَّمْسَ بَازۣغَةً قَالَ هَـٰذَا رَبِّى هَـٰذَآ أَكْبَــرُؐ فَلَمَّــآ أَفَلَــــتْ قَــالَ يَـٰــقَوْمِ إِنِّى بَرۣىٓءٌ مِّمَّــا تُشْــرۣكُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 80, 'إِنِّى وَجَّــهْــــتُ وَجْـهِيَ لِلـذِى فَطَرَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ حَنِيفاًؐ وَمَآ أَنَا مِـنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 81, '¥ وَحَــآجَّــهُ„ قَوْمُهُؐ, قَــالَ أَتُحَـٰٓجُّونِى فِى ۱للَّــهِ وَقَــدْ هَدۭيٰـنِؐ وَلآَ أَخَــافُ مَا تُشْرۣكُــونَ بِهِ“ إِلٓاَّ أَنْ يَّشَــآءَ رَبِّى شَيْـــٔاًؐ وَسِــعَ رَبِّى كُـلَّ شَيْءٖ عِلْمــاٗؐ اَفَلاَ تَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 82, 'وَكَيْفَ أَخَافُ مَـــآ أَشْرَكْتُمْؐ وَلاَ تَخَافُونَ أَنَّكُــمُ; أَشْرَكْتُم بِاللَّهِ مَا لَــمْ يُنَــزّۣلْ بِهِ” عَلَيْكُمْ سُلْطَـٰناًؐ فَأَيُّ ۴لْفَرۣيقَيْنِ أَحَـقُّ بِالاَمْنِ إِن كُنتُــمْ 17 تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 83, '۰لذِينَ ءَامَنُواْ وَلَمْ يَلْبِسُــوٓاْ إِيمَــٰنَهُــم بِظُلْــمٖ ۷وْلَئِكَ لَهُــمُ ۴لاَمْنُ وَهُم مُّهْتَــدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 84, 'وَتِلْكَ حُجَّتُــنَــآ ءَاتَيْنَـٰهَــآ إِبْرَ؛هِيــمَ عَلَـيٰ قَوْمِهِؐ” نَرْفَــعُ دَرَجَـــٰــتِ مَـن نَّشَــــآءُؐ اِ۬نَّ رَبَّــكَ حَكِيــم٘ عَلِيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 85, 'وَوَهَبْنَــا لَــهُ; إِسْحَـٰقَ وَيَعْــقُــوبَؐ كُلٗاّ هَدَيْنَــاؐ وَنُوحــاٗ هَدَيْنَــا مِـن قَـبْلُؐ وَمِـن ذُرّۣيَّتِــهِ” دَاوُﹼدَ وَسُلَيْمَـٰنَ وَأَيُّـوبَ وَيُوسُــفَ وَمُوسۭيٰ وَهَـٰــرُونَؐ وَكَذَ؛لِــكَ نَجْزۣى ۱ڤْمُحْسِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 86, 'وَزَكَرۣيَّــــآءَ وَيَحْيۭيٰ وَعِيسۭيٰ وَإِلْيَاسَؐ كُـلٌّ مِّنَ ۰ڤصَّـٰڤِحِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 87, 'وَإِسْمَــٰعِيـلَ وَالْيَسَعَ وَيُونُـسَ وَلُوطاًؐ وَكُلًاّ فَضَّلْنَا عَلَي ۰لْعَــٰلَمِــيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 88, 'وَمِنَ —ابَــآئِهِــمْ وَذُرّۣيَّــٰتِــهِــمْ وَإِخْوَ؛نِــهِــمْؐ وَاجْتَبَيْنَــٰهُـمْ وَهَدَيْنَــٰـهُمُ; إِلَـيٰ صِــرَ؛طٍ مُّسْتَــقِــيــمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 89, 'ذَ؛لِــكَ هُدَي ۰للَّــهِ يَــهْدِى بِــهِ” مَنْ يَّشَــآءُ مِنْ عِبَــادِهِؐ” وَلَــوَ اَشْرَكُــواْ لَحَبِطَ عَنْهُم مَّا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 90, 'ٱُوْلَئِــكَ ۰لذِينَ ءَاتَيْنَــٰهُمُ ۴لْكِتَــٰـــبَ وَالْحُكْــمَ وَالنُّبُوٓءَةَؐ فَإِنْ يَّكْفُــرْ بِهَــا هَــٰٓؤُلآَءِ فَقَــدْ وَكَّلْنَا بِهَــا قَوْماً لَّيْسُواْ بِهَــا بِكۭـٰفِـرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 91, 'ٱُوْلَئِكَ ۰لــذِينَ هَدَي ۰للَّهُ فَبِهُدۭيٰهُمُ èقْتَدِهْؐ قُل لٓاَّ أَسْـــَٔـلُكُــمْ عَلَيْــهِ أَجْــراٗؐ 18 اِنْ هُوَ إِلاَّ ذِكْــرۭيٰ لِلْعَــٰـلَمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 92, 'وَمَــا قَــدَرُواْ ۴للَّــهَ حَقَّ قَدْرۣهِ“ إِذْ قَالُواْ مَــآ أَنــزَلَ ۰للَّهُ عَلَـيٰ بَشَرٍمِّن شَيْءٍؐ قُـلْ مَنَ اَنــزَلَ ۰لْكِتَــٰـــبَ ۰ﻟ﮲ جَآءَ بِــهِ” مُوسۭيٰ نُوراً وَهُديً لِّلنَّاسِؐ تَجْعَــلُــونَــهُ„ قَرَاطِيسَ تُبْدُونَهَــا وَتُخْفُونَ كَثِيراًؐ وَعُلِّمْتُم مَّا لَمْ تَعْلَمُوٓاْ أَنــتُــمْ وَلآَ ءَابَــآؤُكُــمْ قُـلِ ۱للَّــهُؐ ثُــمَّ ذَرْهُــمْ فِى خَوْضِــهِــــمْ يَلْعَــبُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 93, 'وَهَــٰذَا كِتَــٰـــب٘ اَنزَلْنَــٰـهُ مُبَــٰـرَكككٌ مُّصَـدِّقُ ۴ﻟ﮲ بَيْنَ يَدَيْهِ وَلِتُنذِرَ ٱُمَّ ۰لْقُــرۭيٰ وَمَنْ حَوْلَهَــاؐ وَالذِيـنَ يُومِنُــونَ بِالاَخِرَةِ يُومِنُــونَ بِهِ” وَهُــمْ عَلَيٰ صَلاَتِــهِــمْ يُحَافِظُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 94, 'وَمَـنَ اَظْلَمُ مِمَّـنِ ''فْتَرۭيٰ عَلَي ۰للَّهِ كَذِبــاٗ اَوْ قَــالَ ٱُوحِيَ إِلَيَّ وَلَمْ يُوحَ إِلَيْهِ شَيْءٌ وَمَن قَالَ سَٱُنــزۣلُ مِثْـلَ مَــآ أَنــزَلَ ۰للَّهُؐ وَلَوْ تَرۭيٰٓ إِذِ ۱لظَّـٰلِمُونَ فِى غَمَرَ؛تتتِ ۱لْمَوْتتتِ وَالْمَلَئِكَةُ بَاسِطُوٓاْ أَيْدِيهِمُ; أَخْرۣجُوٓاْ أَنفُسَكُمُؐ ۴لْيَــوْمَ تُجْــزَوْنَ عَـذَابَ ۰لْهُــونِ بِمَــا كُنــتُــمْ تَقُولُونَ عَلَي ۰للَّهِ غَيْــرَ ۰لْحَقِّ وَكُــنــتُــمْ عَـنَ —ايَـٰتِــهِ” تَسْتَكْبِــرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 95, 'وَلَقَدْ جِــيؔــتُــمُــونَــا فُرَ؛دۭيٰ كَمَــــا خَلَقْنَــٰكُمُ; أَوَّلَ مَرَّةٍ وَتَرَكْتُم مَّا خَوَّلْنَــٰكُمْ وَرَآءَ ظُهُورۣكُمْؐ 19 وَمَا نَرۭيٰ مَعَكُمْ شُفَعَآءَكُمُ ۴لذِينَ زَعَمْتُمُ; أَنَّهُمْ فِيكُــمْ شُرَكَــٰٓـؤُاْؐ لَقَــد تَّقَطَّــعَ بَيْنَكُمْ وَضَلَّ عَنكُم مَّــا كُنــتُــمْ تَـزْعُــمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 96, '© إِنَّ ۰للَّهَ فَــٰلِقُ ۴لْحَــــبِّ وَالنَّــوۭيٰؐ يُخْرۣجُ ۴لْحَيَّ مِنَ ۰لْمَيِّــتِ وَمُخْرۣجُ ۴لْمَيِّــتِ مِنَ ۰لْحَيﱢّؐ ذَ؛لِكُمُ ۴للَّهُؐ فَأَنّۭيٰ تُــوفَـكُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 97, 'فَالِقُ ۴لِاصْبَـاحِ وَجَــٰعِـلُ ۴ليْلِ سَكَــنــاًؐ وَالشَّمْـسَ وَالْقَــمَــرَ حُسْبَــٰنـاًؐ ذَ؛لِكَ تَقْدِيــرُ ۴لْعَزۣيــزۣ ۱لْعَلِيــمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 98, 'وَهُــوَ ۰ﻟ﮲ جَــعَـلَ لَكُمُ ۴لنُّجُومَ لِتَـهْــتَـدُواْ بِــهَــا فِى ظُلُمَــٰـــتِ ۱لْبَــرّۣ وَاڤْبَحْــرۣؐ قَــدْ فَصَّلْــنَــا ۰لاَيَــٰـــتِ لِقَــوْمٍ يَعْلَمُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 99, 'وَهُــوَ ۰ﻟـذِىٓ أَنشَـأَكُــــم مِّـن نَّـفْـسٍ وَ؛حِدَةٍ فَمُسْـتَـقَــرٌّ وَمُسْــتَــوْدَعٌؐ قَــدْ فَصَّــلْنَــا ۰لاَيَــٰـــتِ لِقَوْمٍ يَفْقَهُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 100, 'وَهُوَ ۰ﻟـذِىٓ أَنزَلَ مِـنَ ۰لسَّمَــآءِ مَــآءً فَأَخْرَجْــنَــا بِهِ” نَبَـاتَ كُـلِّ شَيْءٍ فَأَخْرَجْــنَــا مِنْهُ خَضِــراً نُّخْرۣجُ مِنْــهُ حَــبّــاً مُّتَرَاكِباً وَمِـنَ ۰لنَّخْلِ مِن طَلْعِهَـا قِنْــوَانٌ دَانِيَــةٌ وَجَــنَّــٰـــتٍ مِّنَ اَعْنَــٰــبٍ وَالزَّيْتُونَ وَالرُّمَّــانَ مُشْتَبِهــاً وَغَيْرَ مُتَشَــٰبِــهٖؐ ۶نظُــرُوٓاْ إِلَـيٰ ثَمَــرۣهِ“ إِذَآ أَثْمَــرَ وَيَنْعِــهِؐ“ إِنَّ فِى ذَ؛لِكُــمْ ءَلاَيَــٰـــتٍ لِّــقَــوْمٍ يُومِــنُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 101, 'وَجَــعَــلُــواْ لِلهِ شُــرَكَــآءَ ۰لْجِنَّ وَخَــلَــقَــهُــــمْؐ 140 وَخَرَّقُواْ لَهُ„ بَنِيـنَ وَبَنَـــٰــتٙ بِغَيْرۣ عِــلْــمٍؐ سُبْحَـــٰنَــهُ„ وَتَعَــٰلۭـيٰ عَمَّــا يَصِفُــونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 102, 'بَدِيــعُ ۴لسَّمَـــٰوَ؛تِ وَالاَرْضِؐ أَنّۭيٰ يَكُونُ لَــهُ„ وَلَدٌ وَلَمْ تَكُن لَّهُ„ صَـٰحِبَةٌؐ وَخَلَقَ كُلَّ شَيْءٍؐ وَهُوَ بِكُلِّ شَيْءٖ عَلِيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 103, 'ذَ؛لِكُــمُ ۴للَّهُ رَبُّكُــمْؐ لآَ إِچَهَ إِلاَّ هُوَؐ خَــٰلِقُ كُـلِّ شَيْءٍؐ فَاعْبُدُوهُؐ وَهُوَ عَلَيٰ كُـلِّ شَيْءٍ وَكِيلٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 104, 'لاَّ تُدْرۣكُهُ ۴لاَبْصَـٰرُؐ وَهُوَ يُدْرۣكككُ ۴لاَبْصَـٰرَؐ وَهُوَ ۰للَّطِيفُ ۴لْخَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 105, 'قَدْ جَآءَكُم بَصَآئِرُ مِن رَّبِّكُمْؐ فَمَنَ اَبْصَرَ فَلِنَفْسِهِ” وَمَنْ عَمِيَ فَعَلَيْهَاؐ وَمَآ أَنَا عَلَيْكُم بِحَفِيظٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 106, 'وَكَذَ؛لِــكَ نُصَرّۣفُ ۴لاَيَـٰــتِ وَلِيَقُولُواْ دَرَسْــتَ وَلِنُبَيِّنَهُ„ لِقَوْمٍ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 107, '"تَّبِعْ مَآ ٱُوحِيَ إِلَيْكَ مِن رَّبِّكَؐ لآَ إِچَهَ إِلاَّ هُوَؐ وَأَعْرۣضْ عَنِ ۱لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 108, 'وَلَوْ شَآءَ ۰للَّهُ مَآ أَشْرَكُواْؐ وَمَا جَعَلْنَــٰـــكَ عَلَيْهِمْ حَفِيظاًؐ وَمَآ أَنــتَ عَلَيْهِم بِوَكِيلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 109, 'وَلاَ تَسُبُّواْ ۴لذِيـنَ يَدْعُونَ مِن دُونِ ۱للَّهِ فَيَسُبُّواْ ۴للَّهَ عَدْواَۢ بِغَيْرۣ عِلْمٍؐ كَذَ؛لِــكَ زَيَّنَّا لِكُلِّ ٱُمَّةٖ عَمَلَهُمْؐ ثُمَّ إِلَيٰ رَبِّهِم مَّرْجِعُهُــمْ فَيُنَبِّيؖهُم بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 110, 'وَأَقْسَمُواْ بِاللَّهِ جَهْدَ 141 أَيْمَـٰنِهِمْ لَـئِـن جَآءَتْهُمُ; ءَايَةٌ لَّيُومِنُـنَّ بِهَاؐ قُـلِ اِنَّمَا ۰لاَيَــٰــتُ عِندَ ۰للَّهِؐ وَمَا يُشْعِرُكُمُؐ; أَنَّهَآ إِذَا جَآءَتتتْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 111, 'وَنُقَلِّــبُ أَفْـِٕدَتَهُمْ وَأَبْصَــٰـرَهُمْ كَــمَــا لَــمْ يُومِنُــواْ بِهِ“ أَوَّلَ مَرَّةٍ وَنَذَرُهُمْ فِى طُغْيَــٰنِهِمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 112, '¤ وَلَوَ اَنَّنَا نَزَّلْنَآ إِلَيْهِمُ ۴لْمَلَئِكَةَ وَكَلَّمَهُمُ ۴لْمَوْتۭيٰ وَحَشَرْنَا عَلَيْهِمْ كُلَّ شَيْءٍ قِبَلًا مَّا كَانُواْ لِيُومِنُوٓاْ إِلٓاَّ أَنْ يَّشَآءَ ۰للَّهُؐ وَچَكِنَّ أَكْثَرَهُمْ يَجْهَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 113, 'وَكَذَ؛لِــكَ جَعَلْنَا لِكُلِّ نَبِىٓءٖ عَدُوّاً شَيَـٰطِيـنَ ۰لِانسِ وَالْجِنِّ يُوحِى بَعْضُهُمُ; إِلَيٰ بَعْضٍ زُخْرُفَ ۰لْقَوْلِ غُرُوراًؐ وَلَوْ شَآءَ رَبُّــكَ مَا فَعَلُوهُؐ فَذَرْهُمْ وَمَا يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 114, 'وَلِتَصْغۭيٰٓ إِلَيْهِ أَفْـِٕدَةُ ۴لذِينَ لاَ يُومِنُــونَ بِالاَخِرَةِ وَلِيَرْضَوْهُ وَلِيَقْتَرۣفُواْ مَا هُم مُّقْتَرۣفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 115, 'أَفَغَيْرَ ۰للَّهِ أَبْتَغِى حَكَماً وَهُوَ ۰ﻟـذِىٓ أَنزَلَ إِلَيْكُمُ ۴لْكِتَــٰـــبَ مُفَصَّلًؐا وَالذِيـنَ ءَاتَيْنَــٰهُمُ ۴لْكِتَــٰــبَ يَعْلَمُونَ أَنَّهُ„ مُنزَلٌ مِّن رَّبِّــكَ بِالْحَـقﱢّؐ فَلاَ تَكُونَنَّ مِنَ ۰لْمُمْتَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 116, 'وَتَــمَّــــتْ كَلِمَــٰــتُ رَبِّكَ صِدْقاً وَعَدْلًؐا لاَّ مُبَدِّلَ لِكَلِمَــٰتِهِؐ” 142 وَهُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 117, 'وَإِن تُطِعَ اَكْثَرَ مَـن فِى ۱لاَرْضِ يُضِلُّوكككَ عَن سَبِيلِ ۱للَّهِؐ إِنْ يَّتَّبِعُونَ إِلاَّ ۰لظَّنَّؐ وَإِنْ هُمُ; إِلاَّ يَخْرُصُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 118, 'إِنَّ رَبَّــكَ هُوَ أَعْلَمُ مَنْ يَّضِلُّ عَن سَبِيلِهِؐ” وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 119, 'فَكُلُواْ مِمَّا ذُكِرَ "سْمُ ۴للَّهِ عَلَيْهِ إِن كُنتُم بِـَٔايَــٰتِهِ” مُومِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 120, 'وَمَا لَكُمُ; أَلاَّ تَاكُلُواْ مِمَّا ذُكِرَ "سْمُ ۴للَّهِ عَلَيْهِ وَقَدْ فَصَّلَ لَكُم مَّا حَرَّمَ عَلَيْكُمُ; إِلاَّ مَا ۸ضْطُرۣرْتُمُ; إِلَيْهِؐ وَإِنَّ كَثِيراً لَّيَضِلُّونَ بِأَهْوَآئِهِم بِغَيْرۣ عِلْمٖؐ اِنَّ رَبَّــكَ هُوَ أَعْلَمُ بِالْمُعْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 121, 'وَذَرُواْ ظَـٰهِرَ ۰لِاثْمِ وَبَاطِنَهُؐ; إِنَّ ۰لذِينَ يَكْسِبُونَ ۰لِاثْمَ سَيُجْزَوْنَ بِمَا كَانُواْ يَقْتَرۣفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 122, 'وَلاَ تَاكُلُواْ مِمَّا لَمْ يُذْكَرۣ ''سْمُ ۴للَّهِ عَلَيْهِ وَإِنَّهُ„ لَفِسْقٌؐ وَإِنَّ ۰لشَّيَـٰطِينَ لَيُوحُونَ إِلَيٰٓ أَوْلِيَآئِهِمْ ڤِيُجَـٰدِلُوكُمْؐ وَإِنننَ اَطَعْتُمُوهُمُ; إِنَّكُمْ لَمُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 123, 'أَوَمَـن كَانَ مَيِّتاً فَأَحْيَيْنَــٰهُ وَجَعَلْنَا لَهُ„ نُوراً يَمْشِى بِهِ” فِى ۱لنَّاسِ كَمَن مَّثَلُهُ„ فِى ۱لظُّلُمَــٰــتِ لَيْسَ بِخَارۣجٍ مِّنْهَاؐ كَذَ؛لِــكَ زُيِّنَ لِلْكۭـٰفِـرۣينَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 124, '14 وَكَذَ؛لِــكَ جَعَلْنَا فِى كُلِّ قَرْيَةٖ اَكَـٰبِرَ مُجْرۣمِيهَا لِيَمْكُرُواْ فِيهَاؐ وَمَا يَمْكُرُونَ إِلاَّ بِأَنفُسِهِمْ وَمَا يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 125, 'وَإِذَا جَآءَتْهُمُ; ءَايَةٌ قَالُواْ لَن نُّومِنَ حَتَّيٰ نُوتۭيٰ مِثْلَ مَآ ٱُوتِـيَ رُسُلُ ۴للَّهِؐ ۱للَّهُ أَعْلَمُ حَيْثُ يَجْعَلُ رۣسَــٰچَتِهِؐ” سَيُصِيــبُ ۴لذِينَ أَجْرَمُواْ صَغَار٘ عِندَ ۰للَّهِ وَعَذَابٌ شَدِيدٛ بِمَا كَانُــواْ يَمْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 126, 'فَمَنْ يُّرۣدِ ۱للَّهُ أَنْ يَّهْدِيَهُ„ يَشْرَحْ صَدْرَهُ„ لِلِاسْچَمِؐ وَمَنْ يُّرۣدَ اَنْ يُّضِلَّهُ„ يَجْعَلْ صَدْرَهُ„ ضَيِّقاٗ حَرۣجاً كَأَنَّمَا يَصَّعَّدُ فِى ۱لسَّمَآءِؐ كَذَ؛لِــكَ يَجْعَلُ ۴للَّهُ ۴لرّۣجْسَ عَـلَي ۰لذِينَ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 127, 'وَهَـٰذَا صِرَ؛طُ رَبِّكَ مُسْتَقِيماًؐ قَدْ فَصَّلْنَا ۰لاَيَـٰــتِ لِقَوْمٍ يَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 128, '© لَهُمْ دَارُ ۴لسَّچَمِ عِندَ رَبِّهِمْؐ وَهُوَ وَلِيُّهُم بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 129, 'وَيَــوْمَ نَحْشُرُهُمْ جَمِيعاً يَـٰمَعْشَرَ ۰لْجِـنِّ قَدِ ''سْتَكْثَرْتُم مِّـنَ ۰لِانسِؐ وَقَالَ أَوْلِيَآؤُهُم مِّنَ ۰لِانسِ رَبَّـنَا "سْتَمْتَعَ بَعْضُنَا بِبَعْضٍ وَبَلَغْنَآ أَجَلَنَا ۰ﻟـذِىٓ أَجَّلْتَ لَنَاؐ قَالَ ۰لنَّارُ مَثْوۭيٰكُمْ خَـٰلِدِينَ فِيهَآ إِلاَّ مَا شَــآءَ ۰للَّهُؐ إِنَّ رَبَّكَ حَكِيــم٘ عَلِيــمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 130, '144 وَكَذَ؛لِــكَ نُوَلِّى بَعْضَ ۰لظَّـٰلِمِينَ بَعْضاَۢ بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 131, 'يَـٰمَعْشَرَ ۰لْجِنِّ وَالِانـسِ أَلَمْ يَاتِكُمْ رُسُلٌ مِّنكُمْ يَقُصُّونَ عَلَيْكُمُ; ءَايَـٰتِى وَيُنذِرُونَكُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَاؐ قَالُواْ شَهِدْنَا عَلَـيٰٓ أَنفُسِنَاؐ وَغَرَّتْهُمُ ۴لْحَيَوٰةُ ۴لدُّنْيۭا وَشَهِدُواْ عَلَـيٰٓ أَنفُسِهِمُ; أَنَّهُمْ كَانُواْ كۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 132, 'ذَ؛لِكَ أَن لَّمْ يَكُن رَّبُّــكَ مُهْلِكَ ۰لْقُرۭيٰ بِظُلْمٍ وَأَهْلُهَا غَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 133, 'وَلِكُلٍّ دَرَجَـٰــتٌ مِّمَّا عَمِلُواْؐ وَمَا رَبُّــكَ بِغَــٰفِلٖ عَمَّا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 134, 'وَرَبُّــكَ ۰لْغَنِيُّ ذُو ۴لرَّحْمَةِؐ إِنْ يَّشَأْ يُذْهِبْكُمْ وَيَسْتَخْلِفْ مِنۢ بَعْدِكُم مَّا يَشَآءُ كَمَآ أَنشَأَكُم مِّن ذُرّۣيَّةِ قَوْمٖ —اخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 135, 'إِنَّ مَا تُوعَدُونَ ءَلاَتتتٍؐ وَمَآ أَنتُم بِمُعْجِزۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 136, 'قُلْ يَــٰقَوْمِ ''عْمَلُواْ عَلَـيٰ مَكَانَتِكُمُ; إِنِّى عَامِـلٌؐ فَسَوْفَ تَعْلَمُونَ مَـن تَكُونُ لَهُ„ عَـٰقِبَةُ ۴لدّۭارۣؐ إِنَّهُ„ لاَ يُفْلِحُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 137, 'وَجَعَلُواْ لِلهِ مِمَّا ذَرَأَ مِـنَ ۰لْحَرْثثثِ وَالاَنْعَــٰمِ نَصِيباً فَقَالُواْ هَــٰذَا لِلهِ بِزَعْمِهِمْ وَهَــٰذَا لِشُرَكَآئِنَاؐ فَمَا كَانَ لِشُرَكَآئِهِمْ فَلاَ يَصِلُ إِلَي ۰للَّهِؐ وَمَا كَانَ لِلهِ فَهُوَ يَصِـلُ إِلَيٰ شُرَكَآئِهِمْؐ 145 سَآءَ مَا يَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 138, 'وَكَذَ؛لِــكَ زَيَّنَ لِكَثِيرٍ مِّنَ ۰لْمُشْرۣكِينَ قَتْلَ أَوْچَدِهِمْ شُرَكَآؤُهُمْ لِيُرْدُوهُمْ وَلِيَلْبِسُواْ عَلَيْهِمْ دِينَهُمْؐ وَلَوْ شَآءَ ۰للَّهُ مَا فَعَلُوهُؐ فَذَرْهُمْ وَمَا يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 139, 'وَقَالُواْ هَـٰذِهِ“ أَنْعَــٰمٌ وَحَرْثثث٘ حِجْرٌ لاَّ يَطْعَمُهَآ إِلاَّ مَـن نَّشَآءُ بِزَعْمِهِمْ وَأَنْعَـٰم٘ حُرّۣمَت ظُّهُورُهَا وَأَنْعَــٰمٌ لاَّ يَذْكُرُونَ "سْمَ ۰للَّهِ عَلَيْهَا "فْتِرَآءٗ عَلَيْهِؐ سَيَجْزۣيهِم بِمَــا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 140, 'وَقَالُواْ مَا فِى بُطُونِ هَـٰذِهِ ۱لاَنْعَــٰمِ خَالِصَةٌ لِّذُكُورۣنَا وَمُحَـرَّم٘ عَلَيٰٓ أَزْوَ؛جِنَاؐ وَإِنْ يَّكُن مَّيْتَةً فَهُمْ فِيهِ شُرَكَآءُؐ سَيَجْزۣيهِمْ وَصْفَهُمُؐ; إِنَّهُ„ حَكِيم٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 141, '¥ قَدْ خَسِرَ ۰لذِينَ قَتَلُوٓاْ أَوْچَدَهُمْ سَفَهاَۢ بِغَيْرۣ عِلْمٍ وَحَرَّمُواْ مَا رَزَقَهُمُ ۴للَّهُ èفْتِرَآءٗ عَلَي ۰للَّهِؐ قَد ضَّلُّواْ وَمَا كَانُواْ مُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 142, 'وَهُوَ ۰ﻟـذِىٓ أَنشَأَ جَنَّــٰــتٍ مَّعْرُوشَــٰــتٍ وَغَيْرَ مَعْرُوشَــٰــتٍ وَالنَّخْلَ وَالزَّرْعَ مُخْتَلِفاٗ ۷كْلُهُ, وَالزَّيْتُونَ وَالرُّمَّانَ مُتَشَــٰبِهاً وَغَيْرَ مُتَشَــٰبِهٍؐ كُلُواْ مِن ثَمَرۣهِ“ إِذَآ أَثْمَرَ وَءَاتُواْ حَقَّهُ„ يَوْمَ حِصَادِهِؐ” وَلاَ تُسْرۣفُوٓاْؐ إِنَّهُ„ لاَ يُحِــبُّ 146 ۴لْمُسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 143, 'وَمِنَ ۰لاَنْعَــٰمِ حَمُولَةً وَفَرْشاًؐ كُلُواْ مِمَّــا رَزَقَكُمُ ۴للَّهُؐ وَلاَ تَتَّبِعُواْ خُطْوَ؛تتتِ ۱لشَّيْطَـٰنِؐ إِنَّهُ„ لَكُمْ عَدُوٌّ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 144, 'ثَمَــٰنِيَةَ أَزْوَ؛جٍؐ مِّـنَ ۰لضَّأْنِ ''ثْنَيْنِ وَمِـنَ ۰لْمَعْزۣ ''ثْنَيْـنِؐ قُلَ —آلذَّكَرَيْنِ حَرَّمَ أَمِ ۱لاُنثَيَيْنِ أَمَّا "شْتَمَلَــتْ عَلَيْهِ أَرْحَامُ ۴لاُنثَيَيْنِؐ نَـبِّـُٔـونِى بِعِلْمٖ اِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 145, 'وَمِنَ ۰لِابِلِ ''ثْنَيْنِ وَمِنَ ۰لْبَقَرۣ ''ثْنَيْنِؐ قُلَ —آلذَّكَرَيْنِ حَرَّمَ أَمِ ۱لاُنثَيَيْنِ أَمَّا "شْتَمَلَــتْ عَلَيْهِ أَرْحَامُ ۴لاُنثَيَيْنِؐ أَمْ كُنتُمْ شُهَدَآءَ اۭذْ وَصّۭيٰكُمُ ۴للَّهُ بِهَـٰذَاؐ فَمَنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَي ۰للَّهِ كَذِباً لِّيُضِلَّ ۰لنَّاسَ بِغَيْرۣ عِلْمٖؐ اِنَّ ۰للَّهَ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 146, 'قُـل لٓاَّ أَجِدُ فِى مَآ ٱُوحِـيَ إِلَيَّ مُحَـرَّماٗ عَلَـيٰ طَاعِمٍ يَطْعَمُهُ; إِلٓاَّ أَنْ يَّكُونَ مَيْتَةٗ اَوْ دَماً مَّسْفُوحاٗ اَوْ لَحْمَ خِنزۣيرٍ فَإِنَّهُ„ رۣجْس٘ؐ اَوْ فِسْقاٗ ۷هِلَّ لِغَـيْـرۣ ۱للَّهِ بِهِؐ” فَمَنُ ۶ضْطُرَّ غَيْرَ بَاغٍ وَلاَ عَادٍ فَإِنَّ رَبَّكَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 147, 'وَعَلَي ۰لذِيـنَ هَادُواْ حَرَّمْنَا كُلَّ ذى ظُفُرٍ وَمِـنَ ۰لْبَقَرۣ وَالْغَنَمِؐ حَرَّمْنَا عَلَيْهِمْ شُحُومَهُمَآ إِلاَّ مَا حَمَلَت ظُّهُورُهُمَآ 147 أَوۣ ۱لْحَوَايۭآ أَوْ مَا "خْتَلَطَ بِعَظْمٍؐ ذَ؛لِــكَ جَزَيْنَـٰهُم بِبَغْيِهِمْؐ وَإِنَّا لَصَـٰدِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 148, 'فَإِن كَذَّبُوكككَ فَقُل رَّبُّكُمْ ذُو رَحْمَةٍ وَ؛سِعَةٍؐ وَلاَ يُرَدُّ بَأْسُهُ„ عَـنِ ۱لْقَوْمِ ۱ڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 149, 'سَيَقُــولُ ۴لذِينَ أَشْرَكُواْ لَوْ شَآءَ ۰للَّهُ مَآ أَشْرَكْنَا وَلآَ ءَابَآؤُنَا وَلاَ حَرَّمْنَا مِن شَيْءٍؐ كَذَ؛لِــكَ كَذَّبَ ۰لذِيـنَ مِن قَبْلِهِمْ حَتَّيٰ ذَاقُواْ بَأْسَنَاؐ قُلْ هَلْ عِندَكُم مِّنْ عِلْمٍ فَتُخْرۣجُوهُ لَنَآؐ إِن تَتَّبِعُونَ إِلاَّ ۰لظَّنَّؐ وَإِنَ اَنتُمُ; إِلاَّ تَخْرُصُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 150, 'قُلْ فَلِلهِ ۱لْحُجَّةُ ۴لْبَــٰلِغَةُؐ فَلَوْ شَآءَ لَهَدۭيٰكُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 151, 'قُـلْ هَلُمَّ شُهَدَآءَكُمُ ۴لذِينَ يَشْهَدُونَ أَنَّ ۰للَّهَ حَرَّمَ هَـٰذَاؐ فَإِن شَهِدُواْ فَلاَ تَشْهَدْ مَعَهُمْؐ وَلاَ تَتَّبِعَ اَهْوَآءَ ۰لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَا وَالذِينَ لاَ يُومِنُونَ بِالاَخِرَةِ وَهُم بِرَبِّهِمْ يَعْدِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 152, '© قُلْ تَعَالَوَاْ اَتْلُ مَا حَرَّمَ رَبُّكُمْ عَلَيْكُمُ; أَلاَّ تُشْرۣكُواْ بِهِ” شَيْـٔاًؐ وَبِالْوَ؛لِدَيْنِ إِحْسَــٰناًؐ وَلاَ تَقْتُلُوٓاْ أَوْچَدَكُم مِّنِ اِمْچَقٍؐ نَّحْنُ نَرْزُقُكُمْ وَإِيَّاهُمْؐ وَلاَ تَقْرَبُواْ ۴لْفَوَ؛حِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَؐ وَلاَ تَقْتُلُواْ ۴لنَّفْسَ ۰لتِى حَرَّمَ ۰للَّهُ إِلاَّ بِالْحَقﱢّؐ ذَ؛لِكُمْ وَصّۭيٰكُم بِهِ” 148 لَعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 153, 'وَلاَ تَقْرَبُواْ مَالَ ۰لْيَتِيمِ إِلاَّ بِالتِى هِيَ أَحْسَنُ حَتَّيٰ يَبْلُغَ أَشُدَّهُؐ, وَأَوْفُواْ ۴لْكَيْلَ وَالْمِيزَانَ بِالْقِسْطِؐ لاَ نُكَلِّفُ نَفْساٗ اِلاَّ وُسْعَهَاؐ وَإِذَا قُلْتُــمْ فَاعْدِلُواْ وَلَوْ كَانَ ذَا قُرْبۭيٰؐ وَبِعَهْدِ ۱للَّهِ أَوْفُواْؐ ذَ؛لِكُمْ وَصّۭيٰكُم بِهِ” لَعَلَّكُمْ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 154, 'وَأَنَّ هَـٰذَا صِرَ؛طِى مُسْتَقِيماً فَاتَّبِعُوهُؐ وَلاَ تَتَّبِعُواْ ۴لسُّبُلَ فَتَفَرَّقَ بِكُمْ عَن سَبِيلِهِؐ” ذَ؛لِكُمْ وَصّۭيٰكُم بِهِ” لَعَلَّكُمْ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 155, 'ثُمَّ ءَاتَيْنَــا مُوسَي ۰لْكِتَــٰــبَ تَمَاماٗ عَلَي ۰ﻟـذِىٓ أَحْسَنَ وَتَفْصِيلًا لِّكُلِّ شَيْءٍ وَهُديً وَرَحْمَةً لَّعَلَّهُم بِلِقَآءِ رَبِّهِمْ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 156, 'وَهَـٰذَا كِتَــٰــب٘ اَنزَلْنَـٰهُ مُبَــٰرَكككٌ فَاتَّبِعُوهُ وَاتَّقُواْ لَعَلَّكُمْ تُرْحَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 157, 'أَن تَقُولُوٓاْ إِنَّمَآ ٱُنزۣلَ ۰لْكِتَــٰــبُ عَلَيٰ طَآئِفَتَيْـنِ مِن قَبْلِنَا وَإِن كُنَّا عَن دِرَاسَتِهِمْ لَغَــٰفِلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 158, 'أَوْ تَقُولُواْ لَوَ اَنَّآ ٱُنزۣلَ عَلَيْنَا ۰لْكِتَــٰــبُ لَكُنَّآ أَهْدۭيٰ مِنْهُمْؐ فَقَدْ جَآءَكُم بَيِّنَةٌ مِّن رَّبِّكُمْ وَهُديً وَرَحْمَةٌؐ فَمَنَ اَظْلَمُ مِمَّن كَذَّبببَ بِـَٔايَــٰــتِ ۱للَّهِ وَصَدَفَ عَنْهَاؐ سَنَجْزۣى ۱لذِيـنَ يَصْدِفُونَ عَنَ —ايَــٰتِنَا 149 سُوٓءَ ۰لْعَذَابِ بِمَا كَانُواْ يَصْدِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 159, 'هَلْ يَنظُرُونَ إِلٓاَّ أَن تَاتِيَهُمُ ۴لْمَلَئِكَةُ أَوْ يَاتِيَ رَبُّــكَ أَوْ يَاتِيَ بَعْضُ ءَايَــٰــتِ رَبِّــكَؐ يَوْمَ يَاتِى بَعْضُ ءَايَــٰــتِ رَبِّــكَ لاَ يَنفَعُ نَفْســاٗ اِيمَــٰنُهَا لَمْ تَكُنَ —امَنَـــتْ مِن قَـبْلُ أَوْ كَسَبَــتْ فِىٓ إِيمَــٰنِهَا خَيْراًؐ قُـلِ ''نتَظِرُوٓاْؐ إِنَّا مُنتَظِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 160, 'إِنَّ ۰لذِيـنَ فَرَّقُواْ دِينَهُمْ وَكَانُواْ شِيَعاً لَّسْــتَ مِنْهُمْ فِى شَيْءٖؐ اِنَّمَآ أَمْرُهُمُ; إِلَــي ۰للَّهِؐ ثُمَّ يُنَبِّيؖهُم بِمَا كَانُواْ يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 161, 'مَـن جَــآءَ بِالْحَسَنَةِ فَلَهُ„ عَشْرُ أَمْثَالِهَاؐ وَمَن جَآءَ بِالسَّيِّيؕةِ فَلاَ يُجْزۭيٰٓ إِلاَّ مِثْلَهَا وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 162, 'قُلِ اِنَّنِى هَدۭيٰنِى رَبِّيَ إِلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 163, 'دِيناً قَيِّماً مِّلَّةَ إِبْرَ؛هِيمَ حَنِيفاًؐ وَمَا كَانَ مِــنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 164, 'قُـلِ اِنَّ صَلاَتِى وَنُسُكِى وَمَحْيۭآىْ وَمَمَاتِيَ لِلهِ رَبِّ ۱لْعَــٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 165, 'لاَ شَرۣيــكَ لَهُؐ, وَبِذَ؛لِــكَ ٱُمِرْتتتُؐ وَأَنَآ أَوَّلُ ۴لْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 166, 'قُـلَ اَغَيْرَ ۰للَّهِ أَبْغِى رَبّاً وَهُوَ رَبُّ كُلِّ شَيْءٍؐ وَلاَ تَكْسِــبُ كُلُّ نَفْـسٖ اِلاَّ عَلَيْهَاؐ وَلاَ تَزۣرُ وَازۣرَةٌ وۣزْرَ ٱُخْرۭيٰؐ ثُمَّ إِلَيٰ رَبِّكُم مَّرْجِعُكُمْ فَيُنَبِّيؖكُم بِمَا 150 كُنتُمْ فِيهِ تَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (6, 167, 'وَهُوَ ۰ﻟ﮲ جَعَلَكُمْ خَلَئِفَ ۰لاَرْضِ وَرَفَعَ بَعْضَكُمْ فَوْقَ بَعْضٍ دَرَجَــٰــتٍ لِّيَبْلُوَكُمْ فِى مَآ ءَاتۭيٰكُمُؐ; إِنَّ رَبَّــكَ سَرۣيعُ ۴لْعِقَابببِؐ وَإِنَّهُ„ لَغَفُورٌ رَّحِيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اَلَٓمِؓـصَٓؐ كِتَــٰــب٘ نزۣلَ إِلَيْــكَ فَلاَ يَكُن فِى صَدْرۣكككَ حَرَجٌ مِّنْهُ لِتُنذِرَ بِهِ” وَذِكْرۭيٰ لِلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 2, '"تَّبِعُواْ مَآ ٱُنزۣلَ إِلَيْكُم مِّن رَّبِّكُمْؐ وَلاَ تَتَّبِعُواْ مِن دُونِهِ“ أَوْلِيَآءَؐ قَلِيلًا مَّا تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 3, 'وَكَم مِّن قَرْيَةٖ اَهْلَكْنَـٰهَا فَجَآءَهَا بَأْسُنَا بَيَــٰتاٗ اَوْ هُمْ قَآئِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 4, '¤ فَمَا كَانَ دَعْوۭيٰهُمُ; إِذْ جَآءَهُم بَأْسُنَآ إِلٓاَّ أَن قَالُوٓاْ إِنَّا كُنَّا ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 5, 'فَلَنَسْـَٔلَنَّ ۰لذِينَ ٱُرْسِلَ إِلَيْهِمْ وَلَنَسْـَٔلَنَّ ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 6, 'فَلَنَقُصَّنَّ عَلَيْهِم بِعِلْمٍؐ وَمَا كُنَّا غَآئِبِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 7, 'وَالْوَزْنُ يَوْمَئِذٖ ۱لْحَقُّؐ فَمَن ثَقُلَــتْ مَوَ؛زۣينُهُ„ فَٱُوْلَئِكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 8, 'وَمَنْ خَفَّــتْ مَوَ؛زۣينُهُ„ فَٱُوْلَئِكَ ۰لذِينَ 151 خَسِرُوٓاْ أَنفُسَهُم بِمَا كَانُواْ بِـَٔايَــٰتِنَا يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 9, 'وَلَقَدْ مَكَّنَّــٰكُمْ فِى ۱لاَرْضِ وَجَعَلْنَا لَكُمْ فِيهَا مَعَــٰيِشَؐ قَلِيلًا مَّا تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 10, 'وَلَقَدْ خَلَقْنَــٰكُمْ ثُمَّ صَوَّرْنَــٰكُمْ ثُمَّ قُلْنَــا لِلْمَلَئِكَةِ ۹سْجُدُواْ ءَلِادَمَ فَسَجَدُوٓاْؐ إِلٓاَّ إِبْلِيسَ لَمْ يَكُن مِّـنَ ۰لسَّـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 11, 'قَالَ مَا مَنَعَــكَ أَلاَّ تَسْجُدَ إِذَ اَمَرْتُــكَؐ قَالَ أَنَا خَيْرٌ مِّنْهُ خَلَقْتَنِى مِن نّۭارٍ وَخَلَقْتَهُ„ مِن طِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 12, 'قَالَ فَاهْبِطْ مِنْهَا فَمَا يَكُونُ لَــكَ أَن تَتَكَبَّرَ فِيهَا فَاخْرُجِ اِنَّــكَ مِنَ ۰لصَّــٰغِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 13, 'قَالَ أَنظِرْنِىٓ إِلَيٰ يَوْمِ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 14, 'قَالَ إِنَّــكَ مِنَ ۰لْمُنظَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 15, 'قَالَ فَبِمَآ أَغْوَيْتَنِى لَأَقْعُدَنَّ لَهُمْ صِرَ؛طَــكَ ۰لْمُسْتَقِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 16, 'ثُمَّ ءَلاَتِيَنَّهُم مِّنۢ بَـيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ وَعَنَ اَيْمَــٰنِهِمْ وَعَن شَمَآئِـلِهِـمْؐ وَلاَ تَجِدُ أَكْثَرَهُمْ شَــٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 17, 'قَالَ ۸خْرُجْ مِنْهَا مَذْءُوماً مَّدْحُوراًؐ لَّمَن تَـبِعَــكَ مِنْهُمْ لَأَمْلَأَنَّ جَهَنَّمَ مِنكُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 18, 'وَيَـٰٓــَٔادَمُ ۶سْكُنَ اَنــتَ وَزَوْجُــكَ ۰لْجَنَّةَ فَكُلاَ مِنْ حَيْـــثُ شِيؔتُمَاؐ وَلاَ تَقْرَبَا هَـٰذِهِ ۱لشَّجَرَةَ فَتَكُونَا مِنَ ۰لظَّــٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 19, '152 فَوَسْوَسَ لَهُمَا ۰لشَّيْطَـٰنُ لِيُبْدِيَ لَهُمَا مَا وُﹼرۣيَ عَنْهُمَا مِن سَوْءَ؛تِهِمَاؐ وَقَالَ مَا نَهۭيٰكُمَا رَبُّكُمَا عَــنْ هَـٰذِهِ ۱لشَّجَرَةِ إِلٓاَّ أَن تَكُونَا مَلَكَيْنِ أَوْ تَكُونَا مِنَ ۰لْخَــٰلِدِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 20, 'وَقَاسَمَهُمَآ إِنِّى لَكُمَا لَمِنَ ۰ڤنَّــٰصِحِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 21, 'فَدَلّۭيٰهُمَا بِغُرُورٍؐ فَلَمَّا ذَاقَا ۰لشَّجَرَةَ بَدَتْ لَهُمَا سَوْءَ؛تُهُمَا وَطَفِقَا يَخْصِفَـٰنِ عَلَيْهِمَا مِنْ وَّرَقِ ۱لْجَنَّةِؐ وَنَادۭيٰهُمَا رَبُّهُمَآ أَلَمَ اَنْهَكُمَا عَن تِلْكُمَا ۰لشَّجَرَةِ وَأَقُـل لَّكُمَآ إِنَّ ۰لشَّيْطَـٰنَ لَكُمَا عَدُوٌّ مُّبِيـنٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 22, 'قَالاَ رَبَّنَا ظَلَمْنَآ أَنفُسَنَا وَإِن لَّمْ تَغْفِرْ لَنَا وَتَرْحَمْنَــا لَنَكُونَنَّ مِنَ ۰لْخَــٰسِرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 23, 'قَالَ "هْبِطُواْؐ بَعْضُكُمْ لِبَعْضٖ عَدُوٌّؐ وَلَكُمْ فِى ۱لاَرْضِ مُسْتَقَرٌّ وَمَتَــٰع٘ اِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 24, 'قَالَ فِيهَا تَحْيَوْنَ وَفِيهَا تَمُوتُونَ وَمِنْهَا تُخْرَجُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 25, 'يَــٰبَنِىٓ ءَادَمَ قَدَ اَنزَلْنَا عَلَيْكُمْ لِبَاساً يُوَ؛رۣى سَوْءَ؛تِكُمْ وَرۣيشاً وَلِبَاسَ ۰لتَّقْوۭيٰؐ ذَ؛لِــكَ خَيْرٌؐ ذَ؛لِــكَ مِنَ —ايَــٰــتِ ۱للَّهِ لَعَلَّهُمْ يَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 26, 'يَــٰبَنِىٓ ءَادَمَ لاَ يَفْتِنَنَّكُمُ ۴لشَّيْطَـٰنُ كَمَآ أَخْرَجَ أَبَوَيْكُم مِّنَ ۰لْجَنَّةِ يَنزۣعُ عَنْهُمَا لِبَاسَهُمَا لِيُرۣيَهُمَا 15 سَوْءَ؛تِهِمَآؐ إِنَّهُ„ يَرۭيٰكُمْ هُوَ وَقَبِيلُهُ„ مِنْ حَيْثُ لاَ تَرَوْنَهُمُؐ; إِنَّا جَعَلْنَا ۰لشَّيَــٰطِينَ أَوْلِيَآءَ لِلذِينَ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 27, 'وَإِذَا فَعَلُواْ فَـٰحِشَةً قَالُواْ وَجَدْنَا عَلَيْهَآ ءَابَآءَنَا وَاللَّهُ أَمَرَنَا بِهَاؐ قُلِ اِنَّ ۰للَّهَ لاَ يَامُرُ بِاڤْفَحْشَآءِؐ اَ۬تَقُولُونَ عَلَــي ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 28, 'قُلَ اَمَرَ رَبِّى بِالْقِسْطِؐ وَأَقِيمُواْ وُجُوهَكُمْ عِندَ كُــلّۣ مَسْجِدٍؐ وَادْعُوهُ مُخْلِصِيــنَ لَهُ ۴لدِّيــنَؐ كَمَا بَدَأَكُمْ تَعُودُونَؐ فَرۣيقاٗ هَدۭيٰؐ وَفَرۣيقاٗ حَــقَّ عَلَيْهِمُ ۴لضَّچَلَةُؐ إِنَّهُمُ èتَّخَذُواْ ۴لشَّيَـٰطِينَ أَوْلِيَآءَ مِن دُونِ ۱للَّهِ وَيَحْسِبُونَ أَنَّهُم مُّهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 29, 'يَـٰبَنِىٓ ءَادَمَ خُذُواْ زۣينَتَكُمْ عِندَ كُــلّۣ مَسْجِدٍ وَكُلُواْ وَاشْرَبُواْؐ وَلاَ تُسْرۣفُوٓاْؐ إِنَّهُ„ لاَ يُحِــبُّ ۴لْمُسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 30, '© قُلْ مَنْ حَرَّمَ زۣينَةَ ۰للَّهِ ۱لتِىٓ أَخْرَجَ لِعِبَادِهِ” وَالطَّيِّبَـٰــتِ مِنَ ۰لرّۣزْقِؐ قُلْ هِيَ لِلذِيــنَ ءَامَنُواْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا خَالِصَةٌ يَوْمَ ۰لْقِيَـٰمَةِؐ كَذَ؛لِــكَ نُفَصِّــلُ ۴لاَيَـٰــتِ لِقَوْمٍ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 31, 'قُـلۣ اِنَّمَا حَرَّمَ رَبِّيَ ۰لْفَوَ؛حِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَ الِاثْمَ وَالْبَغْـيَ بِغَيْرۣ ۱لْحَقِّ وَأَن تُشْرۣكُواْ بِاللَّهِ مَا لَمْ يُنَزّۣلْ بِهِ” سُلْطَـٰناً 154 وَأَن تَقُولُواْ عَلَــي ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 32, 'وَلِكُلِّ ٱُمَّةٖ اَجَلٌؐ فَإِذَا جَآءَ اجَلُهُمْ لاَ يَسْتَـٰخِرُونَ سَاعَةًؐ وَلاَ يَسْتَقْدِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 33, 'يَـٰبَنِىٓ ءَادَمَ إِمَّا يَاتِيَنَّكُمْ رُسُـلٌ مِّنكُمْ يَقُصُّونننَ عَلَيْكُمُ; ءَايَـٰتِى فَمَـنِ ''تَّقۭيٰ وَأَصْلَحَ فَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 34, 'وَالذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَا وَاسْتَكْبَرُواْ عَنْهَآ ٱُوْلَئِكَ أَصْحَـٰبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 35, 'فَمَــنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباٗ اَوْ كَذَّبَ بِـَٔايَـٰتِهِؐ“ ٱُوْلَئِــكَ يَنَالُهُمْ نَصِيبُهُم مِّــنَ ۰لْكِتَـٰــبِؐ حَتَّـيٰٓ إِذَا جَآءَتْهُمْ رُسُلُنَا يَتَوَفَّوْنَهُمْ قَالُوٓاْ أَيْــنَ مَا كُنتُمْ تَدْعُونَ مِن دُونِ ۱للَّهِ قَالُواْ ضَلُّواْ عَنَّاؐ وَشَهِدُواْ عَلَـيٰٓ أَنفُسِهِمُ; أَنَّهُمْ كَانُواْ كۭـٰفِرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 36, 'قَالَ ۸دْخُلُواْ فِىٓ ٱُمَمٍ قَدْ خَلَــتْ مِـن قَـبْلِكُم مِّنَ ۰لْجِنِّ وَالِانـسِ فِى ۱لنّۭارۣؐ كُلَّمَا دَخَلَــتُ ۷مَّةٌ لَّعَنَــتُ ۷خْتَهَاؐ حَتَّـيٰٓ إِذَا "دَّارَكُواْ فِيهَا جَمِيعاً قَالَــتُ ۷خْرۭيٰهُمْ لُءِولۭيٰهُمْ رَبَّنَا هَـٰٓؤُلآَءِ اَ۬ضَلُّونَا فَــَٔاتِهِمْ عَذَاباً ضِعْفاً مِّــنَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 37, 'قَالَ لِكُـلٍّ ضِعْفٌؐ وَچَكِــن لاَّ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 38, 'وَقَالَــتُ ۷ولۭيٰهُمْ لُءِخْرۭيٰهُمْ 155 فَمَا كَانننَ لَكُمْ عَلَيْنَا مِـن فَضْــلٍ فَذُوقُواْ ۴لْعَذَابببَ بِمَا كُنتُمْ تَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 39, 'إِنَّ ۰لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَا وَاسْتَكْبَرُواْ عَنْهَا لاَ تُفَتَّحُ لَهُمُ; أَبْوَ؛بببُ ۴لسَّمَآءِ وَلاَ يَدْخُلُونَ ۰لْجَنَّةَ حَتَّيٰ يَلِجَ ۰لْجَمَـلُ فِى سَمِّ ۱لْخِيَاطِؐ وَكَذَ؛لِكَ نَجْزۣى ۱ڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 40, 'لَهُم مِّـن جَهَنَّمَ مِهَادٌؐ وَمِن فَوْقِهِمْ غَوَاشٍؐ وَكَذَ؛لِــكَ نَجْزۣى ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 41, 'وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ لاَ نُكَلِّفُ نَفْساٗ اِلاَّ وُسْعَهَآؐ ٱُوْلَئِــكَ أَصْحَـٰبُ ۴لْجَنَّةِ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 42, 'وَنَزَعْنَا مَا فِى صُدُورۣهِم مِّـنْ غِلٍّ تَجْرۣى مِــن تَحْتِهِمُ ۴لاَنْهَـٰرُؐ وَقَالُواْ ۴لْحَمْدُ لِلهِ ۱ﻟ﮲ هَدۭيٰنَا لِهَـٰذَاؐ وَمَا كُنَّا لِنَهْتَدِيَ لَوْلآَ أَنْ هَدۭيٰنَا ۰للَّهُؐ لَقَدْ جَآءَتتتْ رُسُلُ رَبِّنَا بِالْحَقﱢّؐ وَنُودُوٓاْ أَن تِلْكُمُ ۴لْجَنَّةُ ٱُورۣثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 43, 'وَنَادۭيييٰٓ أَصْحَـٰــبُ ۴لْجَنَّةِ أَصْحَـٰبَ ۰لنّۭارۣ أَن قَدْ وَجَدْنَا مَا وَعَدَنَارَبُّنَا حَقّاً فَهَلْ وَجَدتُّم مَّا وَعَدَ رَبُّكُمْ حَقّاًؐ قَالُواْ نَعَمْؐ فَأَذَّنَ مُوَ۬ذِّنٛ بَيْنَهُمُ; أَننن لَّعْنَةُ ۴للَّهِ عَلَي ۰لظَّـٰلِمِيـنَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 44, '۰لذِينَ يَصُدُّونَ عَن سَبِيـلِ ۱للَّهِ وَيَبْغُونَهَا 156 عِوَجاً وَهُم بِالاَخِرَةِ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 45, 'وَبَيْنَهُمَا حِجَابببٌؐ وَعَلَــي ۰لاَعْرَافِ رۣجَالٌ يَعْرۣفُونَ كُلَۢاّ بِسِيمۭيٰهُمْؐ وَنَادَوَاْ اَصْحَـٰبَ ۰لْجَنَّةِ أَن سَچَم٘ عَلَيْكُمْؐ لَمْ يَدْخُلُوهَا وَهُمْ يَطْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 46, '¥ وَإِذَا صُرۣفَتَ اَبْصَـٰرُهُمْ تِلْقَآءَ اصْحَـٰــبِ ۱لنّۭارۣ قَالُواْ رَبَّنَا لاَ تَجْعَلْنَا مَعَ ۰لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 47, 'وَنَادۭيٰٓ أَصْحَـٰبُ ۴لاَعْرَافِ رۣجَالًا يَعْرۣفُونَهُم بِسِيمۭيٰهُمْ قَالُواْ مَآ أَغْنۭــيٰ عَنكُمْ جَمْعُكُمْ وَمَا كُنتُمْ تَسْتَكْبِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 48, 'أَهَـٰٓؤُلآَءِ ۱لذِيــنَ أَقْسَمْتُمْ لاَ يَنَالُهُمُ ۴للَّهُ بِرَحْمَةٖؐ ۶دْخُلُواْ ۴لْجَنَّةَ لاَ خَوْف٘ عَلَيْكُمْ وَلآَ أَنتُمْ تَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 49, 'وَنَادۭيييٰٓ أَصْحَـٰبُ ۴لنّۭارۣ أَصْحَـٰبَ ۰لْجَنَّةِ أَنَ اَفِيضُواْ عَلَيْنَا مِــنَ ۰لْمَآءِ اَ۬وْ مِمَّا رَزَقَكُمُ ۴للَّهُؐ قَالُوٓاْ إِنننَّ ۰للَّهَ حَرَّمَهُمَا عَلَــي ۰لْكۭـٰفِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 50, '۰لذِينَ "تَّخَذُواْ دِينَهُمْ لَهْواً وَلَعِباً وَغَرَّتْهُمُ ۴لْحَيَوٰةُ ۴لدُّنْيۭاؐ فَالْيَوْمَ نَنسۭيٰهُمْ كَمَا نَسُواْ لِقَآءَ يَوْمِهِمْ هَـٰذَا وَمَا كَانُواْ بِـَٔايَـٰتِنَا يَجْحَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 51, 'وَلَقَدْ جِيؔنَـٰهُم بِكِتَـٰبٍ فَصَّلْنَـٰهُ عَلَيٰ عِلْمٖ هُديً وَرَحْمَةً لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 52, 'هَـلْ يَنظُرُونَ 157 إِلاَّ تَاوۣيلَهُؐ, يَوْمَ يَاتِى تَاوۣيلُهُ„ يَقُولُ ۴لذِيــنَ نَسُوهُ مِــن قَـبْلُ قَدْ جَآءَتتتْ رُسُلُ رَبِّنَا بِالْحَـقِّ فَهَل لَّنَا مِــن شُفَعَآءَ فَيَشْفَعُواْ لَنَآ أَوْ نُرَدُّ فَنَعْمَلَ غَـيْرَ ۰ﻟ﮲ كُنَّا نَعْمَــلُؐ قَدْ خَسِرُوٓاْ أَنفُسَهُمْ وَضَــلَّ عَنْهُم مَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 53, 'إِنَّ رَبَّكُمُ ۴للَّهُ ۴ﻟ﮲ خَلَقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ فِى سِتَّةِ أَيَّامٍ ثُمَّ "سْتَوۭيٰ عَلَــي ۰لْعَرْشِؐ يُغْشِى ۱ليْــلَ ۰لنَّهَارَ يَطْلُبُهُ„ حَثِيثاً وَالشَّمْسَ وَالْقَمَرَ وَالنُّجُومَ مُسَخَّرَ؛تتتٙ بِأَمْرۣهِؐ“ أَلاَ لَهُ ۴لْخَلْقُ وَالاَمْرُؐ تَبَـٰرَكَ ۰للَّهُ رَبُّ ۴لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 54, '۸دْعُواْ رَبَّكُمْ تَضَرُّعاً وَخُفْيَةٗؐ اِنَّهُ„ لاَ يُحِــبُّ ۴لْمُعْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 55, 'وَلاَ تُفْسِدُواْ فِى ۱لاَرْضضضِ بَعْدَ إِصْڦَحِهَاؐ وَادْعُوهُ خَوْفاً وَطَمَعاٗؐ اِنَّ رَحْمَــتَ ۰للَّهِ قَرۣيبٌ مِّــنَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 56, 'وَهُوَ ۰ﻟ﮲ يُرْسِلُ ۴لرّۣيَـٰحَ نُشُراَۢ بَيْنَ ¢ رَحْمَتِهِؐ” حَتَّيٰٓ إِذَآ أَقَلَّــتْ سَحَاباً ثِقَالًا سُقْنَـٰهُ لِبَلَدٍ مَّيِّــتٍ فَأَنزَلْنَا بِهِ ۱لْمَآءَ فَأَخْرَجْنَا بِهِ” مِــن كُــلّۣ ۱لثَّمَرَ؛تتتِؐ كَذَ؛لِــكَ نُخْرۣجُ ۴لْمَوْتۭــيٰ لَعَلَّكُمْ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 57, 'وَالْبَلَدُ ۴لطَّيِّــبُ يَخْرُجُ نَبَاتُهُ„ بِإِذْنِ رَبِّهِؐ” وَاﻟ﮲ خَبُــثَ لاَ يَخْرُجُ إِلاَّ نَكِداًؐ كَذَ؛لِــكَ نُصَرّۣفُ ۴لاَيَـٰــتِ 158 لِقَوْمٍ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 58, 'لَقَدَ اَرْسَلْنَا نُوحاٗ اِلَيٰ قَوْمِهِ” فَقَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ; إِنِّــيَ أَخَافُ عَلَيْكُمْ عَذَابببَ يَوْمٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 59, 'قَالَ ۰لْمَلُءَ مِن قَوْمِهِ“ إِنَّا لَنَرۭيٰــكَ فِى ضَچَـلٍ مُّبِـينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 60, 'قَالَ يَـٰقَوْمِ لَيْسَ بِى ضَچَلَةٌ وَچَكِنِّى رَسُولٌ مِّن رَّبببِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 61, 'ٱُبَلِّغُكُمْ رۣسَـٰچَــتِ رَبِّى وَأَنصَحُ لَكُمْ وَأَعْلَمُ مِــنَ ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 62, 'أَوَعَجِبْتُمُ; أَننن جَآءَكُمْ ذِكْرٌ مِّن رَّبِّكُمْ عَلَيٰ رَجُــلٍ مِّنكُمْ لِيُنذِرَكُمْ وَلِتَتَّقُواْ وَلَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 63, 'فَكَذَّبُوهُ فَأَنجَيْنَـٰهُ وَالذِيــنَ مَعَهُ„ فِى ۱لْفُلْــكِؐ وَأَغْرَقْنَا ۰لذِيــنَ كَذَّبُواْ بِــَٔايَـٰتِنَآؐ إِنَّهُمْ كَانُواْ قَوْماٗ عَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 64, 'وَإِلَــيٰ عَادٖ اَخَاهُمْ هُوداًؐ قَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ; أَفَــلاَ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 65, 'قَالَ ۰لْمَلُءَ ۴لذِيــنَ كَفَرُواْ مِن قَوْمِهِ“ إِنَّا لَنَرۭيٰــكَ فِى سَفَاهَةٍ وَإِنَّا لَنَظُنُّــكَ مِــنَ ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 66, 'قَالَ يَـٰقَوْمِ لَيْسَ بِى سَفَاهَةٌ وَچَكِنِّى رَسُولٌ مِّن رَّبببِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 67, 'ٱُبَلِّغُكُمْ رۣسَـٰچَــتِ رَبِّى وَأَنَا لَكُمْ نَاصِـح٘ اَمِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 68, '© اَوَعَجِبْتُمُ; أَن 159 جَآءَكُمْ ذِكْرٌ مِّن رَّبِّكُمْ عَلَيٰ رَجُــلٍ مِّنكُمْ لِيُنذِرَكُمْؐ وَاذْكُرُوٓاْ إِذْ جَعَلَكُمْ خُلَفَآءَ مِـنۢ بَعْدِ قَوْمِ نُوحٍ وَزَادَكُمْ فِى ۱لْخَلْـقِ بَصْطَةًؐ فَاذْكُرُوٓاْ ءَالآَءَ ۰للَّهِ لَعَلَّكُمْ تُفْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 69, 'قَالُوٓاْ أَجِيؔتَنَا لِنَعْبُدَ ۰للَّهَ وَحْدَهُ„ وَنَذَرَ مَا كَانَ يَعْبُدُ ءَابَآؤُنَا فَاتِنَا بِمَا تَعِدُنَآ إِننن كُنــتَ مِنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 70, 'قَالَ قَدْ وَقَعَ عَلَيْكُم مِّن رَّبِّكُمْ رۣجْسٌ وَغَضَب٘ؐ اَتُجَـٰدِلُونَنِى فِىٓ أَسْمَآءٍ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّا نَزَّلَ ۰للَّهُ بِهَا مِن سُلْطَـٰنٍؐ فَانتَظِرُوٓاْؐ إِنِّى مَعَكُم مِّــنَ ۰لْمُنتَظِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 71, 'فَأَنجَيْنَـٰهُ وَالذِيــنَ مَعَهُ„ بِرَحْمَةٍ مِّنَّا وَقَطَعْنَا دَابِرَ ۰لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَــا وَمَا كَانُواْ مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 72, 'وَإِلَــيٰ ثَمُودَ أَخَاهُمْ صَـٰڤِحاًؐ قَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ, قَدْ جَآءَتْكُم بَيِّنَةٌ مِّن رَّبِّكُمْؐ هَـٰذِهِ” نَاقَةُ ۴للَّهِ لَكُمُ; ءَايَةًؐ فَذَرُوهَــا تَاكُـلْ فِىٓ أَرْضِ ۱للَّهِؐ وَلاَ تَمَسُّوهَا بِسُوٓءٍ فَيَاخُذَكُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 73, 'وَاذْكُرُوٓاْ إِذْ جَعَلَكُمْ خُلَفَآءَ مِـنۢ بَعْدِ عَادٍ وَبَوَّأَكُمْ فِى ۱لاَرْضضضِ تَتَّخِذُونَ مِــن سُهُولِهَا قُصُوراً 160 وَتَنْحِتُونَ ۰لْجِبَالَ بُيُوتاًؐ فَاذْكُرُوٓاْ ءَالآَءَ ۰للَّهِؐ وَلاَ تَعْثَوْاْ فِى ۱لاَرْضِ مُـفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 74, 'قَالَ ۰لْمَلُءَ ۴لذِيـنَ "سْتَكْبَرُواْ مِن قَوْمِهِ” لِلذِيـنَ ۸سْتُضْعِفُواْ لِمَــنَ —امَـنَ مِنْهُمُ; أَتَعْلَمُونَ أَنَّ صَـٰڤِحاً مُّرْسَلٌ مِّن رَّبِّهِؐ” قَالُوٓاْ إِنَّا بِمَآ ٱُرْسِـلَ بِهِ” مُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 75, 'قَالَ ۰لذِيـنَ "سْتَكْبَرُوٓاْ إِنَّا بِاﻟـذِىٓ ءَامَنتُم بِهِ” كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 76, 'فَعَقَرُواْ ۴لنَّاقَةَ وَعَتَوْاْ عَنَ اَمْرۣ رَبِّهِمْؐ وَقَالُواْ يَـٰصَـٰلِحُ èيتِنَا بِمَا تَعِدُنَآ إِننن كُنــتَ مِنَ ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 77, 'فَأَخَذَتْهُمُ ۴لرَّجْفَةُ فَأَصْبَحُواْ فِى دۭارۣهِمْ جَـٰثِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 78, 'فَتَوَلّۭــيٰ عَنْهُمْ وَقَالَ يَـٰقَوْمِ لَقَدَ اَبْلَغْتُكُمْ رۣسَالَةَ رَبِّى وَنَصَحْــتُ لَكُمْؐ وَچَكِــن لاَّ تُحِبُّونَ ۰ڤنَّـٰصِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 79, 'وَلُوطاٗ اِذْ قَالَ لِقَوْمِهِ“ أَتَاتُونَ ۰ڤْفَـٰحِشَةَ مَا سَبَقَكُم بِهَا مِــنَ اَحَدٍ مِّــنَ ۰لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 80, 'إِنَّكُمْ لَتَاتُونَ ۰لرّۣجَالَ شَهْوَةً مِّــن دُونِ ۱لنِّسَآءِؐ بَــلَ اَنتُمْ قَوْمٌ مُّسْرۣفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 81, 'وَمَاكَانَ جَوَابببَ قَوْمِهِ“ إِلٓاَّ أَن قَالُوٓاْ أَخْرۣجُوهُم مِّن قَرْيَتِكُمُؐ; إِنَّهُمُ; ٱُنَاسٌ يَتَطَهَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 82, 'فَأَنجَيْنَـٰهُ وَأَهْلَهُ; إِلاَّ "مْرَأَتَهُ„ كَانَــتْ مِــنَ ۰لْغَـٰبِرۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 83, '161 وَأَمْطَرْنَا عَلَيْهِم مَّطَراًؐ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴ڤْمُجْرۣمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 84, 'وَإِلَــيٰ مَدْيَــنَ أَخَاهُمْ شُعَيْبــاًؐ قَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ, قَدْ جَآءَتْكُم بَيِّنَةٌ مِّن رَّبِّكُمْؐ فَأَوْفُواْ ۴لْكَيْـلَ وَالْمِيزَانَؐ وَلاَ تَبْخَسُواْ ۴لنَّاسَ أَشْيَآءَهُمْؐ وَلاَ تُفْسِدُواْ فِى ۱لاَرْضِ بَعْدَ إِصْـﭽَحِهَاؐ ذَ؛لِكُمْ خَيْرٌ لَّكُمُ; إِننن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 85, 'وَلاَ تَقْعُدُواْ بِكُــلّۣ صِرَ؛طٍ تُوعِدُونَ وَتَصُدُّونَ عَــن سَبِيـلِ ۱للَّهِ مَــنَ —امَنَ بِهِ” وَتَبْغُونَهَا عِوَجاًؐ وَاذْكُرُوٓاْ إِذْ كُنتُمْ قَلِيلًا فَكَثَّرَكُمْؐ وَانظُرُواْ كَيْفَ كَانننَ عَـٰقِبَةُ ۴لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 86, 'وَإِن كَانننَ طَآئِفَةٌ مِّنكُمُ; ءَامَنُواْ بِاﻟـذِىٓ ٱُرْسِلْــتُ بِهِ” وَطَآئِفَةٌ لَّمْ يُومِنُواْ فَاصْبِرُواْ حَتَّــيٰ يَحْكُمَ ۰للَّهُ بَيْنَنَاؐ وَهُوَ خَيْرُ ۴لْحَـٰكِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 87, '¤ قَالَ ۰لْمَلُءَ ۴لذِينَ "سْتَكْبَرُواْ مِن قَوْمِهِ” لَنُخْرۣجَنَّــكَ يَـٰشُعَيْــبُ وَالذِيــنَ ءَامَنُواْ مَعَــكَ مِن قَرْيَتِنَآ أَوْ لَتَعُودُنَّ فِى مِلَّتِنَاؐ قَالَ أَوَلَوْ كُنَّا كَـٰرۣهِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 88, 'قَدِ ''فْتَرَيْنَا عَلَــي ۰للَّهِ كَذِباٗ اِنننْ عُدْنَا فِى مِلَّتِكُم بَعْدَ إِذْ نَجّۭيٰنَا ۰للَّهُ مِنْهَاؐ وَمَا يَكُونُ لَنَآ أَن نَّعُودَ فِيهَآ إِلٓاَّ أَنْ 162 يَّشَآءَ ۰للَّهُ رَبُّنَاؐ وَسِعَ رَبُّنَا كُــلَّ شَيْءٖ عِلْماٗؐ عَلَــي ۰للَّهِ تَوَكَّلْنَاؐ رَبَّنَا "فْتَحْ بَيْنَنَا وَبَيْنَ قَوْمِنَا بِالْحَقﱢّؐ وَأَنــتَ خَيْرُ ۴ڤْفَـٰتِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 89, 'وَقَالَ ۰لْمَلُءَ ۴لذِيــنَ كَفَرُواْ مِن قَوْمِهِ” لَـئِـنِ ''تَّبَعْتُمْ شُعَيْباٗ اِنَّكُمُ; إِذاً لَّخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 90, 'فَأَخَذَتْهُمُ ۴لرَّجْفَةُ فَأَصْبَحُواْ فِى دۭارۣهِمْ جَـٰثِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 91, '۰لذِيــنَ كَذَّبُواْ شُعَيْباً كَأَن لَّمْ يَغْنَوْاْ فِيهَاؐ ۰لذِيــنَ كَذَّبُواْ شُعَيْباً كَانُواْ هُمُ ۴لْخَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 92, 'فَتَوَلّۭيٰ عَنْهُمْ وَقَالَ يَـٰقَوْمِ لَقَدَ اَبْلَغْتُكُمْ رۣسَـٰچَــتِ رَبِّى وَنَصَحْــتُ لَكُمْؐ فَكَيْفَ ءَاسۭــيٰ عَلَيٰ قَوْمٍ كۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 93, 'وَمَآ أَرْسَلْنَا فِى قَرْيَةٍ مِّن نَّـبِىٓءٖ اِلٓاَّ أَخَذْنَآ أَهْلَهَا بِالْبَأْسَآءِ وَالضَّرَّآءِ لَعَلَّهُمْ يَضَّرَّعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 94, 'ثُمَّ بَدَّلْنَا مَكَانننَ ۰لسَّيِّيؕةِ ۱لْحَسَنَةَ حَتَّــيٰ عَفَواْؐ وَّقَالُواْ قَدْ مَــسَّ ءَابَآءَنَا ۰لضَّرَّآءُ وَالسَّرَّآءُ فَأَخَذْنَـٰهُم بَغْتَةً وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 95, 'وَلَوَ اَنَّ أَهْلَ ۰لْقُرۭيٰٓ ءَامَنُواْ وَاتَّقَوْاْ ڤَفَتَحْنَا عَلَيْهِم بَرَكَـٰــتٍ مِّــنَ ۰لسَّمَآءِ وَالاَرْضِؐ وَچَكِــن كَذَّبُواْ فَأَخَذْنَـٰهُم بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 96, 'أَفَأَمِــنَ أَهْلُ ۴لْقُرۭيٰٓ أَنْ يَّاتِيَهُم بَأْسُنَا بَيَـٰتاً وَهُمْ نَآئِمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 97, 'أَوَ اَمِــنَ أَهْلُ ۴لْقُرۭيٰٓ 16 أَنْ يَّاتِيَهُم بَأْسُنَا ضُحيً وَهُمْ يَلْعَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 98, 'أَفَأَمِنُواْ مَكْرَ ۰للَّهِؐ فَلاَ يَامَــنُ مَكْرَ ۰للَّهِ إِلاَّ ۰لْقَوْمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 99, 'أَوَلَمْ يَهْدِ لِلذِينَ يَرۣثُونَ ۰لاَرْضضضَ مِـنۢ بَعْدِ أَهْلِهَآ أَن لَّوْ نَشَآءُ اَ۬صَبْنَـٰهُم بِذُنُوبِهِمْؐ وَنَطْبَعُ عَلَــيٰ قُلُوبِهِمْ فَهُمْ لاَ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 100, 'تِلْــكَ ۰لْقُرۭيٰ نَقُــصُّ عَلَيْــكَ مِــنَ اَنۢبَآئِهَاؐ وَلَقَدْ جَآءَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰــتِ فَمَا كَانُواْ لِيُومِنُواْ بِمَــا كَذَّبُواْ مِن قَبْلُؐ كَذَ؛لِــكَ يَطْبَعُ ۴للَّهُ عَلَــيٰ قُلُوبببِ ۱لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 101, 'وَمَا وَجَدْنَا لَأِكْثَرۣهِم مِّــنْ عَهْدٍؐ وَإِنْ وَّجَدْنَآ أَكْثَرَهُمْ لَفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 102, 'ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِم مُّوسۭيٰ بِـَٔايَـٰتِنَآ إِلَيٰ فِرْعَوْنَ وَمَلْاَئِهِ” فَظَلَمُواْ بِهَاؐ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 103, 'وَقَالَ مُوسۭيٰ يَـٰفِرْعَوْنُ إِنِّى رَسُولٌ مِّن رَّبِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 104, 'حَقِيــق٘ؐ عَلَيَّ أَن لٓاَّ أَقُولَ عَلَــي ۰للَّهِ إِلاَّ ۰لْحَقَّؐ قَدْ جِيؔتُكُم بِبَيِّنَةٍ مِّن رَّبِّكُمْؐ فَأَرْسِلْ مَعِى بَنِىٓ إِسْرَآءِيلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 105, 'قَالَ إِننن كُنــتَ جِيؔــتَ بِـَٔايَةٍ فَاتِ بِهَآ إِننن كُنــتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 106, 'فَأَلْقۭــيٰ عَصَاهُ فَإِذَا هِــيَ ثُعْبَانٌ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 107, 'وَنَزَعَ يَدَهُ„ 164 فَإِذَا هِــيَ بَــيْضَآءُ لِلنَّـٰظِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 108, 'قَالَ ۰لْمَلُءَ مِــن قَـوْمِ فِرْعَوْنَ إِنننَّ هَـٰذَا ڤَسَـٰحِر٘ عَلِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 109, 'يُرۣيدُ أَنننْ يُّخْرۣجَكُم مِّنَ اَرْضِكُمْؐ فَمَاذَا تَامُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 110, 'قَالُوٓاْ أَرْجِهِ” وَأَخَاهُ وَأَرْسِـلْ فِى ۱لْمَدَآئِـنِ حَـٰشِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 111, 'يَاتُوكككَ بِكُلِّ سَـٰحِر۫ عَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 112, 'وَجَآءَ ۰ڤسَّحَرَةُ فِرْعَوْنَ قَالُوٓاْ إِنننَّ لَنَا لَأَجْراٗ اِن كُنَّا نَحْــنُ ۴لْغَـٰلِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 113, 'قَالَ نَعَمْ وَإِنَّكُمْ لَمِــنَ ۰لْمُقَرَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 114, 'قَالُواْ يَـٰمُوسۭيٰٓ إِمَّآ أَن تُلْقِيَ وَإِمَّآ أَن نَّكُونَ نَحْــنُ ۴لْمُلْقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 115, 'قَالَ أَلْقُواْؐ فَلَمَّآ أَلْقَوْاْ سَحَرُوٓاْ أَعْيُــنَ ۰لنَّاسِ وَاسْتَرْهَبُوهُمْؐ وَجَآءُو بِسِحْر۫ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 116, '© وَأَوْحَيْنَآ إِلَيٰ مُوسۭــيٰٓ أَنَ اَلْقِ عَصَاكَؐ فَإِذَا هِــيَ تَلَقَّفُ مَا يَافِكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 117, 'فَوَقَعَ ۰لْحَقُّ وَبَطَــلَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 118, 'فَغُلِبُواْ هُنَالِــكَ وَانقَلَبُواْ صَـٰغِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 119, 'وَٱُلْقِــيَ ۰ڤسَّحَرَةُ سَـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 120, 'قَالُوٓاْ ءَامَنَّا بِرَبِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 121, 'رَبببِّ مُوسۭيٰ وَهَـٰرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 122, 'قَالَ فِرْعَوْنُ ءَا۬؛مَنتُم بِهِ” قَبْلَ أَنَ —اذَنَ لَكُمُ; إِنننَّ هَـٰذَا لَمَكْرٌ مَّكَرْتُمُوهُ فِى ۱لْمَدِينَةِ لِتُخْرۣجُواْ مِنْهَآ أَهْلَهَا فَسَوْفَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 123, 'لُءَقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِچَفٍ ثُمَّ لُءَصَلِّبَنَّكُمُ; 165 أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 124, 'قَالُوٓاْ إِنَّـآ إِلَيٰ رَبِّنَا مُنقَلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 125, 'وَمَا تَنقِمُ مِنَّآ إِلٓاَّ أَنَ —امَنَّا بِـَٔايَـٰــتِ رَبِّنَا لَمَّا جَآءَتْنَاؐ رَبَّنَآ أَفْرۣغْ عَلَيْنَــا صَبْراً وَتَوَفَّنَا مُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 126, 'وَقَالَ ۰لْمَلُءَ مِــن قَـوْمِ فِرْعَوْنَ أَتَذَرُ مُوسۭيٰ وَقَوْمَهُ„ لِيُفْسِدُواْ فِى ۱لاَرْضِ وَيَذَرَكككَ وَءَالِهَتَــكَؐ قَالَ سَنَقْتُلُ أَبْنَآءَهُمْ وَنَسْتَحْىِ” نِسَآءَهُمْ وَإِنَّا فَوْقَهُمْ قَـٰهِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 127, 'قَالَ مُوسۭيٰ لِقَوْمِهِ ''سْتَعِينُواْ بِاللَّهِ وَاصْبِرُوٓاْؐ إِنننَّ ۰لاَرْضَ لِلهِ يُورۣثُهَا مَنْ يَّشَآءُ مِنْ عِبَادِهِؐ” وَالْعَـٰقِبَةُ لِلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 128, 'قَالُوٓاْ ٱُوذِينَا مِن قَبْلِ أَن تَاتِيَنَا وَمِنۢ بَعْدِ مَا جِيؔتَنَاؐ قَالَ عَسۭيٰ رَبُّكُمُ; أَنْ يُّهْلِــكَ عَدُوَّكُمْ وَيَسْتَخْلِفَكُمْ فِى ۱لاَرْضِ فَـيَنظُرَ كَيْفَ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 129, 'وَلَقَدَ اَخَذْنَآ ءَالَ فِرْعَوْنَ بِالسِّنِينَ وَنَقْصٍ مِّنَ ۰لثَّمَرَ؛تتتِ لَعَلَّهُمْ يَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 130, 'فَإِذَا جَآءَتْهُمُ ۴لْحَسَنَةُ قَالُواْ لَنَا هَـٰذِهِؐ” وَإِن تُصِبْهُمْ سَيِّيؕةٌ يَطَّيَّرُواْ بِمُوسۭيٰ وَمَــن مَّعَهُؐ; أَلآَ إِنَّمَا طَـٰٓئِرُهُمْ عِندَ ۰للَّهِؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 131, 'وَقَالُواْ مَهْمَا تَاتِنَا بِهِ” مِــنَ —ايَةٍ ڤِّتَسْحَرَنَا بِهَا فَمَا نَحْــنُ لَــكَ بِمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 132, '166 فَأَرْسَلْنَا عَلَيْهِمُ ۴لطُّوفَانَ وَالْجَرَادَ وَالْقُمَّلَ وَالضَّفَادِعَ وَالدَّمَ ءَايَـٰــتٍ مُّفَصَّچَــتٍ فَاسْتَكْبَرُواْ وَكَانُواْ قَوْماً مُّجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 133, 'وَلَمَّا وَقَعَ عَلَيْهِمُ ۴لرّۣجْزُ قَالُواْ يَـٰمُوسَــي ۸دْعُ لَنَا رَبَّــكَ بِمَا عَهِدَ عِندَكككَ لَـئِــن كَشَفْــتَ عَنَّا ۰لرّۣجْزَ لَنُومِنَنَّ لَــكَ وَلَنُرْسِلَــنَّ مَعَــكَ بَنِىٓ إِسْرَآءِيلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 134, 'فَلَمَّا كَشَفْنَا عَنْهُمُ ۴لرّۣجْزَ إِلَـيٰٓ أَجَلٖ هُم بَـٰلِغُوهُ إِذَا هُمْ يَنكُثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 135, 'فَانتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَـٰهُمْ فِى ۱لْيَمِّ بِأَنَّهُمْ كَذَّبُواْ بِـَٔايَـٰتِنَا وَكَانُواْ عَنْهَا غَـٰفِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 136, 'وَأَوْرَثْنَا ۰لْقَوْمَ ۰لذِيــنَ كَانُواْ يُسْتَضْعَفُونَ مَشَـٰرۣقَ ۰لاَرْضِ وَمَغَـٰرۣبَهَا ۰لتِى بَـٰرَكْنَا فِيهَاؐ وَتَمَّــتْ كَلِمَةُ رَبِّــكَ ۰لْحُسْنۭــيٰ عَلَيٰ بَنِىٓ إِسْرَآءِيلَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 137, 'بِمَا صَبَرُواْؐ وَدَمَّرْنَا مَا كَانَ يَصْنَعُ فِرْعَوْنُ وَقَوْمُهُ„ وَمَا كَانُواْ يَعْرۣشُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 138, 'وَجَـٰوَزْنَا بِبَنِىٓ إِسْرَآءِيــلَ ۰ڤْبَحْرَ فَأَتَوْاْ عَلَيٰ قَوْمٍ يَعْكُفُونَ عَلَــيٰٓ أَصْنَامٍ لَّهُمْؐ قَالُواْ يَـٰمُوسَي "جْعَــل لَّنَآ إِچَهاً كَمَا لَهُمُ; ءَالِهَةٌؐ قَالَ إِنَّكُمْ قَوْمٌ تَجْهَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 139, 'إِنننَّ هَـٰٓؤُلآَءِ مُتَبَّرٌ مَّا هُمْ فِيهِؐ وَبَـٰطِــلٌ مَّا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 140, '167 قَالَ أَغَيْرَ ۰للَّهِ أَبْغِيكُمُ; إِچَهاً وَهُوَ فَضَّلَكُمْ عَلَــي ۰لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 141, 'وَإِذَ اَنجَيْنَـٰكُم مِّــنَ —الِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ۰لْعَذَابببِ يَقْتُلُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْؐ وَفِى ذَ؛لِكُم بَلآَءٌ مِّن رَّبِّكُمْ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 142, '¥ وَوَ؛عَدْنَا مُوسۭــيٰ ثَـچَثِينَ لَيْلَةً وَأَتْمَمْنَـٰهَا بِعَشْرٍ فَتَمَّ مِيقَـٰــتُ رَبِّهِ“ أَرْبَعِينَ لَيْلَةًؐ وَقَالَ مُوسۭــيٰ لَأِخِيهِ هَـٰرُونَ ۸خْلُفْنِى فِى قَوْمِى وَأَصْلِحْ وَلاَ تَتَّبِعْ سَبِيــلَ ۰لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 143, 'وَلَمَّا جَآءَ مُوسۭــيٰ لِمِيقَـٰتِنَا وَكَلَّمَهُ„ رَبُّهُ„ قَالَ رَبببِّ أَرۣنِىٓ أَنظُرۣ اِلَيْــكَؐ قَالَ لَن تَرۭيٰنِى وَچَكِــنُ ۶نظُرۣ اِلَي ۰لْجَبَلِ فَإِنِ ''سْتَقَرَّ مَكَانَهُ„ فَسَوْفَ تَرۭيٰنِىؐ فَلَمَّا تَجَلّۭيٰ رَبُّهُ„ ڤِڤْجَبَلِ جَعَلَهُ„ دَكّاً وَخَرَّ مُوسۭــيٰ صَعِقاًؐ فَلَمَّآ أَفَاقققَ قَالَ سُبْحَـٰنَكَ تُبْــتُ إِلَيْكَ وَأَنَآ أَوَّلُ ۴لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 144, 'قَالَ يَـٰمُوسۭيٰٓ إِنِّى ''صْطَفَيْتُــكَ عَلَــي ۰لنَّاسِ بِـرۣسَالَتِى وَبِكَچَمِى فَخُذْ مَــآ ءَاتَيْتُــكَ وَكُن مِّنَ ۰لشَّـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 145, 'وَكَتَبْنَا لَهُ„ فِى ۱لاَلْوَاحِ مِــن كُــلّۣ شَيْءٍ مَّوْعِظَةً وَتَفْصِيلًا لِّكُلِّ شَيْءٍؐ فَخُذْهَا بِقُوَّةٍ وَامُرْ قَوْمَــكَ يَاخُذُواْ بِأَحْسَنِهَاؐ سَٱُوْرۣيكُمْ دَارَ ۰لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 146, '168 سَأَصْرۣفُ عَــنَ —ايَـٰتِــيَ ۰لذِيــنَ يَتَكَبَّرُونَ فِى ۱لاَرْضِ بِغَيْرۣ ۱لْحَقِّ وَإِنْ يَّرَوْاْ كُــلَّ ءَايَةٍ لاَّ يُومِنُواْ بِهَاوَإِنْ يَّرَوْاْ سَبِيلَ ۰لرُّشْدِ لاَ يَتَّخِذُوهُ سَبِيلًا وَإِنْ يَّرَوْاْ سَبِيــلَ ۰لْغَــيّۣ يَتَّخِذُوهُ سَبِيلًؐا ذَ؛لِــكَ بِأَنَّهُمْ كَذَّبُواْ بِـَٔايَـٰتِنَاوَكَانُواْ عَنْهَا غَـٰفِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 147, 'وَالذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَا وَلِقَآءِ ۱لاَخِرَةِ حَبِطَــتَ اَعْمَـٰلُهُمْ هَلْ يُجْزَوْنَ إِلاَّ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 148, 'وَاتَّخَذَ قَوْمُ مُوسۭيٰ مِـنۢ بَعْدِهِ” مِــنْ حُلِيِّهِمْ عِجْلًا جَسَداً لَّهُ„ خُوَار٘ؐ اَلَمْ يَرَوَاْ اَنَّهُ„ لاَ يُكَلِّمُهُمْ وَلاَ يَهْدِيهِمْ سَبِيلٗؐا ''تَّخَذُوهُ وَكَانُواْ ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 149, 'وَلَمَّا سُقِطَ فِىٓ أَيْدِيهِمْ وَرَأَوَاْ اَنَّهُمْ قَد ضَّلُّواْ قَالُواْ لَـئِـن لَّمْ يَرْحَمْنَا رَبُّنَا وَيَغْفِرْ لَنَا لَنَكُونَنَّ مِنَ ۰لْخَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 150, 'وَلَمَّا رَجَعَ مُوسۭيٰٓ إِلَيٰ قَوْمِهِ” غَضْبَـٰــنَ أَسِفاً قَالَ بِيسَمَا خَلَفْتُمُونِى مِنۢ بَعْدِيَؐ أَعَجِلْتُمُ; أَمْرَ رَبِّكُمْؐ وَأَلْقَي ۰لاَلْوَاحَ وَأَخَذَ بِرَأْسِ أَخِيهِ يَجُرُّهُ; إِلَيْهِؐ قَالَ "بْنَ ٱُمَّ إِنننَّ ۰لْقَوْمَ "سْتَضْعَفُونِى وَكَادُواْ يَقْتُلُونَنِى فَلاَ تُشْمِــتْ بِــيَ ۰لاَعْدَآءَ وَلاَ تَجْعَلْنِى مَعَ ۰لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 151, 'قَالَ رَبببِّ ''غْفِرْ لِى وَلَأِخِى 169 وَأَدْخِلْنَا فِى رَحْمَتِــكَؐ وَأَنــتَ أَرْحَمُ ۴لرَّ؛حِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 152, 'إِنننَّ ۰لذِينَ "تَّخَذُواْ ۴ڤْعِجْــلَ سَـيَنَالُهُمْ غَضَــبٌ مِّن رَّبِّهِمْ وَذِلَّةٌ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَكَذَ؛لِــكَ نَجْزۣى ۱لْمُفْتَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 153, 'وَالذِينَ عَمِلُواْ ۴لسَّيِّـَٔاتتتِ ثُمَّ تَابُواْ مِنۢ بَعْدِهَا وَءَامَنُوٓاْ إِنَّ رَبَّــكَ مِنۢ بَعْدِهَا لَغَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 154, 'وَلَمَّا سَكَــتَ عَن مُّوسَــي ۰لْغَضَــبُ أَخَذَ ۰لاَلْوَاحَ وَفِى نُسْخَتِهَاهُديً وَرَحْمَةٌ لِّلذِيــنَ هُمْ لِرَبِّهِمْ يَرْهَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 155, 'وَاخْتَارَ مُوسۭــيٰ قَـوْمَهُ„ سَبْعِينَ رَجُلًا لِّمِيقَـٰتِنَاؐ فَلَمَّآ أَخَذَتْهُمُ ۴لرَّجْفَةُ قَالَ رَبِّ لَوْ شِيؔــتَ أَهْلَكْتَهُم مِّــن قَـبْلُ وَإِيَّـٰيَؐ أَتُهْلِكُنَا بِمَا فَعَــلَ ۰لسُّفَهَآءُ مِنَّآؐ إِنْ هِــيَ إِلاَّ فِتْنَتُــكَ تُضِلُّ بِهَا مَــن تَشَآءُ وَتَهْدِى مَــن تَشَآءُؐ اَ۬نــتَ وَلِيُّنَا فَاغْفِرْ لَنَا وَارْحَمْنَا وَأَنــتَ خَيْرُ ۴لْغَـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 156, '© وَاكْتُــبْ لَنَا فِى هَـٰذِهِ ۱لدُّنْيۭا حَسَنَةً وَفِى ۱لاَخِرَةِؐ إِنَّا هُدْنَآ إِلَيْــكَؐ قَالَ عَذَابِيَ ٱُصِيــبُ بِهِ” مَــنَ اَشَآءُؐ وَرَحْمَتِى وَسِعَــتْ كُلَّ شَيْءٍؐ فَسَأَكْتُبُهَا لِلذِيــنَ يَتَّقُونَ وَيُوتُونَ ۰لزَّكَوٰةَ وَالذِيــنَ هُم بِـَٔايَـٰتِنَا يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 157, '۰لذِينَ يَتَّبِعُونَ ۰لرَّسُولَ ۰لنَّبِىٓءَ ۰لاُمِّيَّ ۰ﻟـ﮲ 170 يَجِدُونَهُ„ مَكْتُوباٗ عِندَهُمْ فِى ۱لتَّوْرۭيٰةِ وَالِانجِيلِ يَامُرُهُم بِالْمَعْرُوفِ وَيَنْهۭيٰهُمْ عَـنِ ۱لْمُنكَرۣ وَيُحِــلُّ لَهُمُ ۴لطَّيِّبَـٰــتِ وَيُحَرّۣمُ عَلَيْهِمُ ۴لْخَبَـٰٓئِــثَ وَيَضَعُ عَنْهُمُ; إِصْرَهُمْ وَالاَغْچَلَ ۰لتِى كَانَتْ عَلَيْهِمْؐ فَالذِيــنَ ءَامَنُواْ بِهِ” وَعَزَّرُوهُ وَنَصَرُوهُ وَاتَّبَعُواْ ۴لنُّورَ ۰ﻟـذِىٓ ٱُنزۣلَ مَعَهُ; ٱُوْلَئِــكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 158, 'قُلْ يَـٰٓـأَيُّهَا ۰لنَّاسُ إِنِّى رَسُولُ ۴للَّهِ إِلَيْكُمْ جَمِيعاٗ ۱ﻟ﮲ لَهُ„ مُلْــكُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِؐ لآَ إِچَهَ إِلاَّ هُوَؐ يُحْىِ” وَيُمِيــتُؐ فَـَٔامِنُواْ بِاللَّهِ وَرَسُولِهِ ۱لنَّبِىٓءِ ۱لاُمِّـيِّ ۱ﻟ﮲ يُومِنُ بِاللَّهِ وَكَلِمَـٰتِهِؐ” وَاتَّبِعُوهُ لَعَلَّكُمْ تَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 159, 'وَمِن قَوْمِ مُوسۭيٰٓ ٱُمَّةٌ يَهْدُونَ بِالْحَقِّ وَبِهِ” يَعْدِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 160, 'وَقَطَّعْنَـٰهُمُ èثْنَتَىْ عَشْرَةَ أَسْبَاطاٗ ۷مَماًؐ وَأَوْحَيْنَآ إِلَيٰ مُوسۭيٰٓ إِذِ ''سْتَسْقۭيٰهُ قَوْمُهُ; أَنِ ''ضْرۣببب بِّعَصَاكككَ ۰لْحَجَرَؐ فَانۢبَجَسَــتْ مِنْهُ èثْنَتَا عَشْرَةَ عَيْناًؐ قَدْ عَلِمَ كُــلُّ ٱُنَاسسسٍ مَّشْرَبَهُمْؐ وَظَلَّلْنَا عَلَيْهِمُ ۴لْغَمَـٰمَ وَأَنزَلْنَا عَلَيْهِمُ ۴لْمَنَّ وَالسَّلْوۭيٰؐ كُلُواْ مِــن طَيِّبَـٰــتِ مَا رَزَقْنَـٰكُمْؐ وَمَا ظَلَمُونَاؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 161, '171 وَإِذْ قِيــلَ لَهُمُ ۶سْكُنُواْ هَـٰذِهِ ۱لْقَرْيَةَ وَكُلُواْ مِنْهَا حَيْــثُ شِيؔتُمْ وَقُولُواْ حِطَّةٌ وَادْخُلُواْ ۴لْبَابببَ سُجَّداً تُغْفَرْ لَكُمْ خَطِيٓــَٔــٰتُكُمْؐ سَنَزۣيدُ ۴ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 162, 'فَبَدَّلَ ۰لذِيــنَ ظَلَمُواْ مِنْهُمْ قَوْلٗا غَيْرَ ۰ﻟ﮲ قِيــلَ لَهُمْ فَأَرْسَلْنَا عَلَيْهِمْ رۣجْزاً مِّنَ ۰لسَّمَآءِ بِمَا كَانُواْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 163, 'وَسْـَٔلْهُمْ عَـنِ ۱لْقَرْيَةِ ۱لتِى كَانَــتْ حَاضِرَةَ ۰ڤْبَحْرۣ إِذْ يَعْدُونَ فِى ۱لسَّبْــتِ إِذْ تَاتِيهِمْ حِيتَانُهُمْ يَوْمَ سَبْتِهِمْ شُرَّعاً وَيَوْمَ لاَ يَسْبِتُونَ لاَ تَاتِيهِمْؐ كَذَ؛لِــكَ نَبْلُوهُم بِمَا كَانُواْ يَفْسُقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 164, 'وَإِذْ قَالَــتُ ۷مَّةٌ مِّنْهُمْ لِمَ تَعِظُونَ قَوْماٗ ۱للَّهُ مُهْلِكُهُمُ; أَوْ مُعَذِّبُهُمْ عَذَاباً شَدِيداًؐ قَالُواْ مَعْذِرَة٘ اِلَيٰ رَبِّكُمْ وَلَعَلَّهُمْ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 165, 'فَلَمَّا نَسُواْ مَا ذُكِّرُواْ بِهِ“ أَنجَيْنَا ۰لذِيــنَ يَنْهَوْنَ عَنِ ۱لسُّوٓءِ وَأَخَذْنَا ۰لذِيــنَ ظَلَمُواْ بِعَذَابببٙ بِيـسٙ بِمَا كَانُواْ يَفْسُقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 166, 'فَلَمَّا عَتَوْاْ عَــن مَّا نُهُواْ عَنْهُ قُلْنَا لَهُمْ كُونُواْ قِرَدَةٗ خَـٰسِـٕــينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 167, 'وَإِذْ تَأَذَّنَ رَبُّــكَ لَيَبْعَثَــنَّ عَلَيْهِمُ; إِلَيٰ يَـوْمِ ۱لْقِيَـٰمَةِ مَـنْ يَّسُومُهُمْ سُوٓءَ ۰لْعَذَابببِؐ إِنَّ رَبَّــكَ لَسَرۣيعُ ۴لْعِقَابِؐ وَإِنَّهُ„ 172 لَغَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 168, 'وَقَطَّعْنَـٰهُمْ فِى ۱لاَرْضضضِ ٱُمَماًؐ مِّنْهُمُ ۴ڤصَّـٰڤِحُونَؐ وَمِنْهُمْ دُونَ ذَ؛لِــكَؐ وَبَلَوْنَـٰهُم بِالْحَسَنَـٰــتِ وَالسَّيِّـَٔاتِ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 169, 'فَخَلَفَ مِـنۢ بَعْدِهِمْ خَلْفٌ وَرۣثُــواْ ۴لْكِتَـٰــبَ يَاخُذُونَ عَرَضضضَ هَـٰذَا ۰لاَدْنۭيٰ وَيَقُولُونَ سَيُغْفَرُ لَنَا وَإِنْ يَّاتِهِمْ عَرَضٌ مِّثْلُهُ„ يَاخُذُوهُؐ أَلَمْ يُوخَذْ عَلَيْهِم مِّيثَـٰقُ ۴لْكِتَـٰــبِ أَننن لاَّ يَقُولُواْ عَلَــي ۰للَّهِ إِلاَّ ۰لْحَقَّؐ وَدَرَسُواْ مَا فِيهِؐ وَالدَّارُ ۴لاَخِرَةُ خَيْرٌ لِّلذِينَ يَتَّقُونَؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 170, 'وَالذِينَ يُمَسِّكُونَ بِالْكِتَـٰــبِ وَأَقَامُواْ ۴لصَّلَوٰةَ إِنَّا لاَ نُضِيعُ أَجْرَ۰ڤْمُصْڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 171, '¤ وَإِذْ نَتَقْنَا ۰لْجَبَلَ فَوْقَهُمْ كَأَنَّهُ„ ظُلَّةٌ وَظَنُّوٓاْ أَنَّهُ„ وَاقِعٛ بِهِمْؐ خُذُواْ مَآ ءَاتَيْنَـٰكُم بِقُوَّةٍ وَاذْكُرُواْ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 172, 'وَإِذَ اَخَذَ رَبُّــكَ مِنۢ بَنِىٓ ءَادَمَ مِــن ظُهُورۣهِمْ ذُرّۣيَّـٰتِهِمْ وَأَشْهَدَهُمْ عَلَيٰٓ أَنفُسِهِمُ; أَلَسْــتُ بِرَبِّكُمْ قَالُواْ بَلۭــيٰؐ شَهِدْنَآ أَن تَقُولُواْ يَوْمَ ۰لْقِيَـٰمَةِ إِنَّا كُنَّا عَــنْ هَـٰذَا غَـٰفِلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 173, 'أَوْ تَقُولُوٓاْ إِنَّمَآ أَشْرَكككَ ءَابَآؤُنَا مِن قَـبْلُ وَكُنَّا ذُرّۣيَّةً مِّنۢ بَعْدِهِمُؐ; أَفَتُهْلِكُنَا 17 بِمَا فَعَــلَ ۰لْمُبْطِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 174, 'وَكَذَ؛لِــكَ نُفَصِّــلُ ۴لاَيَـٰــتِ وَلَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 175, 'وَاتْــلُ عَلَيْهِمْ نَبَأَ ۰ﻟـذِىٓ ءَاتَيْنَـٰهُ ءَايَـٰتِنَا فَانسَڤَخَ مِنْهَا فَأَتْبَعَهُ ۴لشَّيْطَـٰنُ فَكَانَ مِــنَ ۰لْغَاوۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 176, 'وَلَوْ شِيؔنَا لَرَفَعْنَـٰهُ بِهَا وَچَكِنَّهُ; أَخْلَدَ إِلَــي ۰لاَرْضِ وَاتَّبَعَ هَوۭيٰهُؐ فَمَثَلُهُ„ كَمَثَـلِ ۱لْكَلْــبِ إِننن تَحْمِــلْ عَلَيْهِ يَلْهَــثَ اَوْ تَتْرُكْهُ يَلْهَــثْؐ ذَ؛لِــكَ مَثَــلُ ۴لْقَوْمِ ۱لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَاؐ فَاقْصُـصِ ۱لْقَصَصَ لَعَلَّهُمْ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 177, 'سَآءَ مَثَلٗا ۱لْقَوْمُ ۴لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَا وَأَنفُسَهُمْ كَانُواْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 178, 'مَنْ يَّهْدِ ۱للَّهُ فَهُوَ ۰لْمُهْتَدِىؐ وَمَـنْ يُّضْلِلْ فَٱُوْلَئِــكَ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 179, 'وَلَقَدْ ذَرَأْنَا لِجَهَنَّمَ كَثِيراً مِّنَ ۰لْجِنِّ وَالِانــسِؐ لَهُمْ قُلُوبٌ لاَّ يَفْقَهُونَ بِهَاؐ وَلَهُمُ; أَعْيُــنٌ لاَّ يُبْصِرُونَ بِهَاؐ وَلَهُمُ; ءَاذَانٌ لاَّ يَسْمَعُونَ بِهَآؐ ٱُوْلَئِــكَ كَالاَنْعَـٰمِ بَلْ هُمُ; أَضَلُّؐ ٱُوْلَئِــكَ هُمُ ۴لْغَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 180, 'وَلِلهِ ۱لاَسْمَآءُ ۴لْحُسْنۭيٰ فَادْعُوهُ بِهَاؐ وَذَرُواْ ۴لذِيــنَ يُڤْحِدُونَ فِىٓ أَسْمَـٰٓئِهِؐ” سَيُجْزَوْنننَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 181, 'وَمِمَّــنْ خَلَقْنَآ ٱُمَّةٌ يَهْدُونَ بِالْحَقِّ وَبِهِ” يَعْدِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 182, '174 وَالذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَا سَنَسْتَدْرۣجُهُم مِّــنْ حَيْــثُ لاَ يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 183, 'وَٱُمْلِى لَهُمُؐ; إِنَّ كَيْدِى مَتِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 184, 'اَوَلَمْ يَتَفَكَّرُواْؐ مَا بِصَـٰحِبِهِم مِّن جِنَّةٖؐ اِنْ هُوَ إِلاَّ نَذِيرٌ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 185, 'اَوَلَمْ يَنظُرُواْ فِى مَلَكُوتتتِ ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا خَلَــقَ ۰للَّهُ مِن شَيْءٍ وَأَنْ عَسۭيٰٓ أَنْ يَّكُونَ قَدِ ''قْتَرَبببَ أَجَلُهُمْؐ فَبِأَيييّۣ حَدِيــثٙ بَعْدَهُ„ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 186, 'مَـنْ يُّضْلِـلِ ۱للَّهُ فَلاَ هَادِيَ لَهُؐ, وَنَذَرُهُمْ فِى طُغْيَـٰنِهِمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 187, 'يَسْـَٔلُونَــكَ عَـنِ ۱لسَّاعَةِ أَيَّانَ مُرْسۭيٰهَاؐ قُـلِ اِنَّمَا عِلْمُهَا عِندَ رَبِّىؐ لاَ يُجَلِّيهَا لِوَقْتِهَآ إِلاَّ هُوَؐ ثَقُلَــتْ فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِؐ لاَ تَاتِيكُمُ; إِلاَّ بَغْتَةًؐ يَسْـَٔلُونَــكَ كَأَنَّــكَ حَفِــيّﹲ عَنْهَاؐ قُـلِ اِنَّمَا عِلْمُهَا عِندَ ۰للَّهِؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 188, '© قُــل لٓاَّ أَمْلِــكُ لِنَفْسِى نَفْعاً وَلاَ ضَرّاٗ اِلاَّ مَا شَآءَ ۰للَّهُؐ وَلَوْ كُنــتُ أَعْلَمُ ۴لْغَيْــبَ لاَسْتَكْثَرْتتتُ مِــنَ ۰لْخَيْرۣؐ وَمَا مَسَّنِــيَ ۰لسُّوٓءُؐ اِ۬نننَ اَنَاإِلاَّ نَذِيرٌؐ وَبَشِيرٌ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 189, 'هُوَ ۰ﻟ﮲ خَلَقَكُم مِّن نَّفْسٍ وَ؛حِدَةٍ وَجَعَـلَ مِنْهَا زَوْجَهَا لِيَسْكُنَ إِلَيْهَاؐ فَلَمَّا 175 تَغَشّۭيٰهَا حَمَلَــتْ حَمْلٗا خَفِيفاً فَمَرَّتْ بِهِؐ” فَلَمَّآ أَثْقَلَــت دَّعَوَا ۰للَّهَ رَبَّهُمَا لَـئِـــنَ —اتَيْتَنَا صَـٰڤِحاً لَّنَكُونَنَّ مِنَ ۰لشَّـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 190, 'فَلَمَّآ ءَاتۭيٰهُمَا صَـٰڤِحاً جَعَلاَ لَهُ„ شِرْكاً فِيمَآ ءَاتۭيٰهُمَاؐ فَتَعَـٰلَــي ۰للَّهُ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 191, 'أَيُشْرۣكُونَ مَا لاَ يَخْلُقُ شَيْــٔاً وَهُمْ يُخْلَقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 192, 'وَلاَ يَسْتَطِيعُونَ لَهُمْ نَصْراً وَلآَ أَنفُسَهُمْ يَنصُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 193, 'وَإِن تَدْعُوهُمُ; إِلَــي ۰لْهُدۭيٰ لاَ يَتْبَعُوكُمْؐ سَوَآء٘ عَلَيْكُمُ; أَدَعَوْتُمُوهُمُ; أَمَ اَنتُمْ صَـٰمِتُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 194, 'إِنَّ ۰لذِيــنَ تَدْعُونَ مِن دُونِ ۱للَّهِ عِبَــاد٘ اَمْثَالُكُمْؐ فَادْعُوهُمْ فَلْيَسْتَجِيبُواْ لَكُمُ; إِننن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 195, 'أَلَهُمُ; أَرْجُــلٌ يَمْشُونَ بِهَآؐ أَمْ لَهُمُ; أَيْدٍ يَبْطِشُونَ بِهَآؐ أَمْ لَهُمُ; أَعْيُنٌ يُبْصِرُونَ بِهَآؐ أَمْ لَهُمُ; ءَاذَانٌ يَسْمَعُونننَ بِهَاؐ قُــلُ ۶دْعُواْ شُرَكَآءَكُمْ ثُمَّ كِيدُونِ فَلاَ تُنظِرُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 196, 'إِنَّ وَلِـيـيِّـــيَ ۰للَّهُ ۴ﻟ﮲ نَزَّلَ ۰لْكِتَـٰــبَؐ وَهُوَ يَتَوَلَّي ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 197, 'وَالذِيــنَ تَدْعُونَ مِن دُونِهِ” لاَ يَسْتَطِيعُونَ نَصْرَكُمْ وَلآَ أَنفُسَهُمْ يَنصُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 198, 'وَإِننن تَدْعُوهُمُ; إِلَــي ۰لْهُدۭيييٰ لاَ يَسْمَعُواْؐ 176 وَتَرۭيٰهُمْ يَنظُرُونَ إِلَيْــكَ وَهُمْ لاَ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 199, 'خُذِ ۱لْعَفْوَؐ وَامُرْ بِالْعُرْفِؐ وَأَعْرۣضضضْ عَنِ ۱لْجَـٰهِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 200, 'وَإِمَّا يَنزَغَنَّــكَ مِــنَ ۰لشَّيْطَـٰنِ نَزْغٌ فَاسْتَعِذْ بِاللَّهِؐ إِنَّهُ„ سَمِيع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 201, 'اِنَّ ۰لذِيــنَ "تَّقَوۣاْ اِذَا مَسَّهُمْ طَـٰٓئِفٌ مِّــنَ ۰لشَّيْطَـٰنِ تَذَكَّرُواْ فَإِذَا هُم مُّبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 202, 'وَإِخْوَ؛نُهُمْ يُمِدُّونَهُمْ فِى ۱لْغَيﱢّؐ ثُمَّ لاَ يُقْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 203, 'وَإِذَا لَمْ تَاتِهِم بِـَٔايَةٍ قَالُواْ لَوْلاَ "جْتَبَيْتَهَاؐ قُـلِ اِنَّمَآ أَتَّبِعُ مَا يُوحۭيٰٓ إِلَيَّ مِن رَّبِّــــىؐ هَـٰذَا بَصَآئِرُ مِن رَّبِّكُمْ وَهُديً وَرَحْمَةٌ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 204, 'وَإِذَا قُرۣىَٔ ۰لْقُرْءَانُ فَاسْتَمِعُواْ لَهُ„ وَأَنصِتُواْ لَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 205, 'وَاذْكُر رَّبَّــكَ فِى نَفْسِكَ تَضَرُّعاً وَخِيفَةً وَدُونَ ۰لْجَهْرۣ مِــنَ ۰لْقَوْلِ بِالْغُدُوّۣ وَالاَصَالِ وَلاَ تَكُــن مِّنَ ۰لْغَـٰفِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (7, 206, 'إِنَّ ۰لذِينَ عِندَ رَبِّكَ لاَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِ” وَيُسَبِّحُونَهُ„ وَلَهُ„ يَسْجُدُونَ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَسْـَٔلُونَــكَ عَـنِ ۱لاَنفَالِؐ قُـلِ ۱لاَنفَالُ 177 لِلهِ وَالرَّسُولِؐ فَاتَّقُواْ ۴للَّهَ وَأَصْڤِحُواْ ذَاتَ بَيْنِكُمْؐ وَأَطِيعُواْ ۴للَّهَ وَرَسُولَهُ; إِننن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 2, 'إِنَّمَا ۰لْمُومِنُونَ ۰لذِينَ إِذَا ذُكِرَ ۰للَّهُ وَجِلَتْ قُلُوبُهُمْ وَإِذَا تُلِيَــتْ عَلَيْهِمُ; ءَايَـٰتُهُ„ زَادَتْهُمُ; إِيمَـٰناً وَعَلَيٰ رَبِّهِمْ يَتَوَكَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 3, '۰لذِيــنَ يُقِيمُونَ ۰لصَّلَوٰةَ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 4, 'ٱُوْلَئِــكَ هُمُ ۴لْمُومِنُونَ حَقّاًؐ لَّهُمْ دَرَجَـٰــت٘ عِندَ رَبِّهِمْ وَمَغْفِرَةٌ وَرۣزْقٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 5, '¥ كَمَآ أَخْرَجَــكَ رَبُّــكَ مِـنۢ بَـيْتِــكَ بِالْحَقِّ وَإِنَّ فَرۣيقاً مِّــنَ ۰لْمُومِنِينَ لَكَـٰرۣهُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 6, 'يُجَـٰدِلُونَــكَ فِى ۱لْحَـقِّ بَعْدَ مَا تَبَيَّــنَ كَأَنَّمَا يُسَاقُونَ إِلَــي ۰لْمَوْتتتِ وَهُمْ يَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 7, 'وَإِذْ يَعِدُكُمُ ۴للَّهُ إِحْدَي ۰لطَّآئِفَتَيْــنۣ أَنَّهَا لَكُمْ وَتَوَدُّونَ أَنننَّ غَيْرَ ذَاتتتِ ۱لشَّوْكَةِ تَكُونُ لَكُمْؐ وَيُرۣيدُ ۴للَّهُ أَنْ يُّحِقَّ ۰لْحَقَّ بِكَلِمَـٰتِهِ” وَيَقْطَعَ دَابِرَ ۰لْكۭـٰفِـرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 8, 'ڤِيُحِقَّ ۰لْحَقَّ وَيُبْطِلَ ۰لْبَـٰطِلَ وَلَوْ كَرۣهَ ۰ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 9, 'إِذْ تَسْتَغِيثُونَ رَبَّكُمْ فَاسْتَجَابببَ لَكُمُ; أَنِّى مُمِدُّكُم بِأَلْفٍ مِّــنَ ۰لْمَلَئِكَةِ مُرْدَفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 10, 'وَمَا جَعَلَهُ ۴للَّهُ إِلاَّ بُشْرۭيٰ وَلِتَطْمَئِنَّ بِهِ” قُلُوبُكُمْؐ وَمَا ۰لنَّصْرُ إِلاَّ مِنْ عِندِ ۱للَّهِؐ 178 إِنننَّ ۰للَّهَ عَزۣيز٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 11, 'اِذْ يُغْشِيكُمُ ۴لنُّعَاسسسَ أَمَنَةً مِّنْهُ وَيُنَزّۣلُ عَلَيْكُم مِّــنَ ۰لسَّمَآءِ مَآءً لِّيُطَهِّرَكُم بِهِ” وَيُذْهِــبَ عَنكُمْ رۣجْزَ ۰لشَّيْطَـٰنِ وَلِيَرْبِطَ عَلَــيٰ قُلُوبِكُمْ وَيُثَبِّــتَ بِهِ ۱لاَقْدَامَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 12, 'إِذْ يُوحِى رَبُّــكَ إِلَــي ۰لْمَلَئِكَةِ أَنِّى مَعَكُمْ فَثَبِّتُواْ ۴لذِيــنَ ءَامَنُواْؐ سَٱُلْقِى فِى قُلُوبببِ ۱لذِيــنَ كَفَرُواْ ۴لرُّعْــبَؐ فَاضْرۣبُواْ فَوْقَ ۰لاَعْنَاقِ وَاضْرۣبُواْ مِنْهُمْ كُــلَّ بَنَانٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 13, 'ذَ؛لِــكَ بِأَنَّهُمْ شَآقُّواْ ۴للَّهَ وَرَسُولَهُؐ, وَمَـنْ يُّشَاقِـقِ ۱للَّهَ وَرَسُولَهُ„ فَإِنننَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 14, 'ذَ؛لِكُمْ فَذُوقُوهُؐ وَأَنَّ لِلْكۭـٰفِرۣيــنَ عَذَابَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 15, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا لَقِيتُمُ ۴لذِيــنَ كَفَرُواْ زَحْفاً فَلاَ تُوَلُّوهُمُ ۴لاَدْبَـٰرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 16, 'وَمَنْ يُّوَلِّهِمْ يَوْمَئِذٍ دُبُرَهُ; إِلاَّ مُتَحَرّۣفاً لِّقِتَالٖ اَوْ مُتَحَيِّزاٗ اِلَيٰ فِيؕةٍ فَقَدْ بَآءَ بِغَضَــبٍ مِّــنَ ۰للَّهِ وَمَأْوۭيٰهُ جَهَنَّمُؐ وَبِيسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 17, 'فَلَمْ تَقْتُلُوهُمْؐ وَچَكِــنَّ ۰للَّهَ قَتَلَهُمْؐ وَمَا رَمَيْــتَ إِذْ رَمَيْــتَ وَچَكِــنَّ ۰للَّهَ رَمۭيٰؐ وَلِيُبْلِــيَ ۰لْمُومِنِيــنَ مِنْهُ بَلآَءٗ حَسَناٗؐ اِنننَّ ۰للَّهَ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 18, 'ذَ؛لِكُمْ وَأَنننَّ ۰للَّهَ مُوَهِّنٌ 179 كَيْدَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 19, 'إِننن تَسْتَفْتِحُواْ فَقَدْ جَآءَكُمُ ۴ڤْفَتْحُؐ وَإِن تَنتَهُواْ فَهُوَ خَيْرٌ لَّكُمْؐ وَإِن تَعُودُواْ نَعُدْؐ وَلَــن تُغْنِيَ عَنكُمْ فِيؕتُكُمْ شَيْـٔاً وَلَوْ كَثُرَتتتْؐ وَأَنننَّ ۰للَّهَ مَعَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 20, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ أَطِيعُواْ ۴للَّهَ وَرَسُولَهُؐ„ وَلاَ تَوَلَّوْاْ عَنْهُ وَأَنتُمْ تَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 21, 'وَلاَ تَكُونُواْ كَالذِيــنَ قَالُواْ سَمِعْنَا وَهُمْ لاَ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 22, '© إِنَّ شَرَّ ۰لدَّوَآبِّ عِندَ ۰للَّهِ ۱لصُّمُّ ۴لْبُكْمُ ۴لذِيــنَ لاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 23, 'وَلَوْ عَلِمَ ۰للَّهُ فِيهِمْ خَيْراً لَأَّسْمَعَهُمْؐ وَلَوَ اَسْمَعَهُمْ لَتَوَلَّواْ وَّهُم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 24, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èسْتَجِيبُواْ لِلهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْؐ وَاعْلَمُوٓاْ أَنننَّ ۰للَّهَ يَحُولُ بَيْــنَ ۰لْمَرْءِ وَقَلْبِهِ” وَأَنَّهُ; إِلَيْهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 25, 'وَاتَّقُواْ فِتْنَةً لاَّ تُصِيبَنَّ ۰لذِيــنَ ظَلَمُواْ مِنكُمْ خَآصَّةًؐ وَاعْلَمُوٓاْ أَنننَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 26, 'وَاذْكُرُوٓاْ إِذَ اَنتُمْ قَلِيــلٌ مُّسْتَضْعَفُونَ فِى ۱لاَرْضِ تَخَافُونَ أَنننْ يَّتَخَطَّفَكُمُ ۴لنَّاسسسُ فَــَٔاوۭيٰكُمْ وَأَيَّدَكُم بِنَصْرۣهِ” وَرَزَقَكُم مِّــنَ ۰لطَّيِّبَـٰــتِ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 27, '180 يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَخُونُواْ ۴للَّهَ وَالرَّسُولَ وَتَخُونُوٓاْ أَمَـٰنَـٰتِكُمْ وَأَنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 28, 'وَاعْلَمُوٓاْ أَنَّمَآ أَمْوَ؛لُكُمْ وَأَوْچَدُكُمْ فِتْنَةٌ وَأَنَّ ۰للَّهَ عِندَهُ; أَجْر٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 29, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِننن تَتَّقُواْ ۴للَّهَ يَجْعَــل لَّكُمْ فُرْقَاناً وَيُكَفِّرْ عَنكُمْ سَيِّـَٔاتِكُمْ وَيَغْفِرْ لَكُمْؐ وَاللَّهُ ذُو ۴لْفَضْلِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 30, 'وَإِذْ يَمْكُرُ بِــكَ ۰لذِيــنَ كَفَرُواْ لِيُثْبِتُوكككَ أَوْ يَقْتُلُوكككَ أَوْ يُخْرۣجُوكككَؐ وَيَمْكُرُونَ وَيَمْكُرُ ۴للَّهُؐ وَاللَّهُ خَيْرُ ۴لْمَـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 31, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُنَا قَالُواْ قَدْ سَمِعْنَا لَوْ نَشَآءُ لَقُلْنَا مِثْــلَ هَـٰذَآ إِنننْ هَـٰذَآ إِلٓاَّ أَسَـٰطِيرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 32, 'وَإِذْ قَالُواْ ۴للَّهُمَّ إِننن كَانَ هَـٰذَا هُوَ ۰لْحَـقَّ مِـنْ عِندِكككَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِّــنَ ۰لسَّمَآءِ اَ۬وۣ ''يتِنَا بِعَذَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 33, 'وَمَا كَانننَ ۰للَّهُ لِيُعَذِّبَهُمْ وَأَنــتَ فِيهِمْؐ وَمَا كَانننَ ۰للَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 34, 'وَمَا لَهُمُ; أَلاَّ يُعَذِّبَهُمُ ۴للَّهُ وَهُمْ يَصُدُّونَ عَـنِ ۱ڤْمَسْجِدِ ۱لْحَرَامِ وَمَا كَانُوٓاْ أَوْلِيَآءَهُؐ; إِنَ اَوْلِيَآؤُهُ; إِلاَّ ۰لْمُتَّقُونَؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 35, '181 وَمَا كَانننَ صَلاَتُهُمْ عِندَ ۰لْبَيْــتِ إِلاَّ مُكَآءً وَتَصْدِيَةًؐ فَذُوقُواْ ۴لْعَذَابببَ بِمَا كُنتُمْ تَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 36, 'إِنننَّ ۰لذِيــنَ كَفَرُواْ يُنفِقُونَ أَمْوَ؛لَهُمْ لِيَصُدُّواْ عَــن سَبِيـلِ ۱للَّهِؐ فَسَيُنفِقُونَهَا ثُمَّ تَكُونُ عَلَيْهِمْ حَسْرَةً ثُمَّ يُغْلَبُونَؐ وَالذِيــنَ كَفَرُوٓاْ إِلَيٰ جَهَنَّمَ يُحْشَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 37, 'لِيَمِيزَ ۰للَّهُ ۴لْخَبِيــثَ مِــنَ ۰لطَّيِّــِبِ وَيَجْعَلَ ۰لْخَبِيــثَ بَعْضَهُ„ عَلَيٰ بَعْـضٍ فَـيَرْكُمَهُ„ جَمِيعاً فَيَجْعَلَهُ„ فِى جَهَنَّمَؐ ٱُوْلَئِــكَ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 38, 'قُل لِّلذِيــنَ كَفَرُوٓاْ إِنْ يَّنتَهُواْ يُغْفَرْ لَهُم مَّا قَدْ سَلَفَؐ وَإِنْ يَّعُودُواْ فَقَدْ مَضَــتْ سُنَّــتُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 39, 'وَقَـٰتِلُوهُمْ حَتَّــيٰ لاَ تَكُونَ فِتْنَةٌ وَيَكُونَ ۰لدِّيــنُ كُلُّهُ„ لِلهِؐ فَإِنِ ''نتَهَوْاْ فَإِنننَّ ۰للَّهَ بِمَا يَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 40, 'وَإِن تَوَلَّوْاْ فَاعْلَمُوٓاْ أَنننَّ ۰للَّهَ مَوْلۭيٰكُمْؐ نِعْمَ ۰لْمَوْلۭيٰؐ وَنِعْمَ ۰لنَّصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 41, '¤ وَاعْلَمُوٓاْ أَنَّمَا غَنِمْتُم مِّــن شَيْءٍ فَأَنَّ لِلهِ خُمُسَهُ„ وَلِلرَّسُولِ وَلِذِى ۱لْقُرْبۭيٰ وَالْيَتَـٰمۭيٰ وَالْمَسَـٰكِينِ وَابْنِ ۱لسَّبِيلِ إِن كُنتُمُ; ءَامَنتُم بِاللَّهِ وَمَآ أَنزَلْنَا عَلَــيٰ عَبْدِنَا يَوْمَ ۰لْفُرْقَانِ يَوْمَ "لْتَقَي ۰لْجَمْعَـٰنِؐ وَاللَّهُ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 42, '182 اِذَ اَنتُم بِالْعُدْوَةِ ۱لدُّنْيۭا وَهُم بِالْعُدْوَةِ ۱لْقُصْوۭيٰ وَالرَّكْــبُ أَسْفَـلَ مِنكُمْؐ وَلَوْ تَوَاعَدتُّمْ لاَخْتَلَفْتُمْ فِى ۱لْمِيعَـٰدِؐ وَچَكِــن لِّــيَقْضِــيَ ۰للَّهُ أَمْراً كَانَ مَفْعُولًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 43, 'لِّيَهْلِــكَ مَنْ هَلَكَ عَنۢ بَيِّنَةٍ وَيَحْيۭيٰ مَنْ حَيـيِـــيَ عَنۢ بَيِّنَةٍؐ وَإِنننَّ ۰للَّهَ لَسَمِيع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 44, 'اِذْ يُرۣيكَهُمُ ۴للَّهُ فِى مَنَامِــكَ قَلِيلًؐا وَلَوَ اَرۭيٰكَهُمْ كَثِيراً لَّفَشِلْتُمْ وَلَتَنَـٰزَعْتُمْ فِى ۱لاَمْرۣؐ وَچَكِــنَّ ۰للَّهَ سَلَّمَؐ إِنَّهُ„ عَلِيمٛ بِذَاتتتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 45, 'وَإِذْ يُرۣيكُمُوهُمُ; إِذِ ''لْتَقَيْتُمْ فِىٓ أَعْيُنِكُمْ قَلِيلًا وَيُقَلِّلُكُمْ فِىٓ أَعْيُنِهِمْ لِيَقْضِــيَ ۰للَّهُ أَمْراً كَانَ مَفْعُولًؐا وَإِلَــي ۰للَّهِ تُرْجَعُ ۴لاُمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 46, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا لَقِيتُمْ فِيؕةً فَاثْبُتُواْ وَاذْكُرُواْ ۴للَّهَ كَثِيراً لَّعَلَّكُمْ تُفْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 47, 'وَأَطِيعُواْ ۴للَّهَ وَرَسُولَهُؐ„ وَلاَ تَنَـٰزَعُواْ فَتَفْشَلُواْ وَتَذْهَبَ رۣيحُكُمْؐ وَاصْبِرُوٓاْؐ إِنننَّ ۰للَّهَ مَعَ ۰لصَّـٰبِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 48, 'وَلاَ تَكُونُواْ كَالذِينَ خَرَجُواْ مِــن دِيۭـٰرۣهِم بَطَراً وَرۣيؕآءَ ۰لنَّاسِ وَيَصُدُّونَ عَــن سَبِيلِ ۱للَّهِؐ وَاللَّهُ بِمَا يَعْمَلُونَ مُحِيطٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 49, 'وَإِذْ زَيَّــنَ لَهُمُ ۴لشَّيْطَـٰــنُ أَعْمَـٰلَهُمْ وَقَالَ لاَ غَالِــبَ 18 لَكُمُ ۴لْيَوْمَ مِــنَ ۰لنَّاسِ وَإِنِّى جَارٌ لَّكُمْؐ فَلَمَّا تَرَآءَتتتِ ۱لْفِيؕتَـٰنِ نَكَــصَ عَلَــيٰ عَقِبَيْهِ وَقَالَ إِنِّى بَرۣىٓءٌ مِّنكُمُ; إِنِّيَ أَرۭيٰ مَا لاَ تَرَوْنَ إِنِّــيَ أَخَافُ ۴للَّهَؐ وَاللَّهُ شَدِيدُ ۴لْعِقَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 50, 'إِذْ يَقُولُ ۴لْمُنَـٰفِقُونَ وَالذِيــنَ فِى قُلُوبِهِم مَّرَضضض٘ غَرَّ هَـٰٓؤُلآَءِ دِينُهُمْؐ وَمَـنْ يَّتَوَكَّلْ عَلَــي ۰للَّهِ فَإِنننَّ ۰للَّهَ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 51, 'وَلَوْ تَرۭيٰٓ إِذْ يَتَوَفَّــي ۰لذِيــنَ كَفَرُواْؐ ۴لْمَلَئِكَةُ يَضْرۣبُونَ وُجُوهَهُمْ وَأَدْبَـٰرَهُمْ وَذُوقُواْ عَذَابَ ۰لْحَرۣيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 52, 'ذَ؛لِــكَ بِمَا قَدَّمَــتَ اَيْدِيكُمْ وَأَنننَّ ۰للَّهَ لَيْـسَ بِظَڦَّـمٍ لِّلْعَبِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 53, 'كَدَأْبببِ ءَالِ فِرْعَوْنَؐ وَالذِينَ مِن قَبْلِهِمْ كَفَرُواْ بِـَٔايَـٰــتِ ۱للَّهِ فَأَخَذَهُمُ ۴للَّهُ بِذُنُوبِهِمُؐ; إِنننَّ ۰للَّهَ قَوۣيٌّ شَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 54, 'ذَ؛لِــكَ بِأَنننَّ ۰للَّهَ لَمْ يَــكُ مُغَيِّراً نِّعْمَةٗ اَنْعَمَهَا عَلَيٰ قَوْمٖ حَتَّيٰ يُغَيِّرُواْ مَا بِأَنفُسِهِمْ وَأَنننَّ ۰للَّهَ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 55, 'كَدَأْبِ ءَالِ فِرْعَوْنَؐ وَالذِينَ مِن قَبْلِهِمْ كَذَّبُواْ بِـَٔايَـٰــتِ رَبِّهِمْ فَأَهْلَكْنَـٰهُم بِذُنُوبِهِمْؐ وَأَغْرَقْنَآ ءَالَ فِرْعَوْنَؐ وَكُلٌّ كَانُواْ ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 56, 'إِنَّ شَرَّ ۰لدَّوَآبببِّ عِندَ ۰للَّهِ ۱لذِينَ 184 كَفَرُواْ فَهُمْ لاَ يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 57, '۰لذِيــنَ عَـٰهَدتتتَّ مِنْهُمْ ثُمَّ يَنقُضُونَ عَهْدَهُمْ فِى كُلِّ مَرَّةٍ وَهُمْ لاَ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 58, 'فَإِمَّا تَثْقَفَنَّهُمْ فِى ۱لْحَرْبببِ فَشَرّۣدْ بِهِم مَّــنْ خَلْفَهُمْ لَعَلَّهُمْ يَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 59, 'وَإِمَّا تَخَافَــنَّ مِـن قَوْمٖ خِيَانَةً فَانۢبِذِ اِلَيْهِمْ عَلَــيٰ سَوَآءٖؐ اِنننَّ ۰للَّهَ لاَ يُحِــبُّ ۴لْخَآئِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 60, 'وَلاَ تَحْسِبَنَّ ۰لذِيــنَ كَفَرُواْ سَبَقُوٓاْؐ إِنَّهُمْ لاَ يُعْجِزُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 61, '© وَأَعِدُّواْ لَهُم مَّا "سْتَطَعْتُم مِّن قُوَّةٍ وَمِن رّۣبَاطِ ۱لْخَيْلِؐ تُرْهِبُونَ بِهِ” عَدُوَّ ۰للَّهِ وَعَدُوَّكُمْ وَءَاخَرۣيــنَ مِن دُونِهِمْ لاَ تَعْلَمُونَهُمُؐ ۴للَّهُ يَعْلَمُهُمْؐ وَمَا تُنفِقُواْ مِــن شَيْءٍ فِى سَبِيـلِ ۱للَّهِ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لاَ تُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 62, 'وَإِننن جَنَحُواْ لِلسَّلْمِ فَاجْنَحْ لَهَا وَتَوَكَّلْ عَلَي ۰للَّهِؐ إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 63, 'وَإِنْ يُّرۣيدُوٓاْ أَنننْ يَّخْدَعُوكككَ فَإِنننَّ حَسْبَكَ ۰للَّهُؐ هُوَ ۰ﻟـذِىٓ أَيَّدَكككَ بِنَصْرۣهِ” وَبِالْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 64, 'وَأَلَّفَ بَيْــنَ قُلُوبِهِمْؐ لَوَ اَنفَقْــتَ مَا فِى ۱لاَرْضضضِ جَمِيعاً مَّآ أَلَّفْــتَ بَيْــنَ قُلُوبِهِمْؐ وَچَكِنَّ ۰للَّهَ أَلَّفَ بَيْنَهُمُؐ; إِنَّهُ„ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 65, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ 185 حَسْبُكَ ۰للَّهُؐ وَمَـنِ ''تَّبَعَــكَ مِــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 66, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ حَرّۣضضضِ ۱لْمُومِنِيــنَ عَلَــي ۰لْقِتَالِؐ إِنننْ يَّكُــن مِّنكُمْ عِشْرُونَ صَـٰبِرُونَ يَغْلِبُواْ مِاْيؕتَيْنِؐ وَإِن تَكُــن مِّنكُم مِّاْيؕةٌ يَغْلِبُوٓاْ أَلْفاً مِّنَ ۰لذِيــنَ كَفَرُواْ بِأَنَّهُمْ قَوْمٌ لاَّ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 67, '۰چَــنَ خَفَّفَ ۰للَّهُ عَنكُمْ وَعَلِمَ أَنَّ فِـيكُمْ ضُعْفاًؐ فَإِننن تَكُــن مِّنكُم مِّاْيؕةٌ صَابِرَةٌ يَغْلِبُواْ مِاْيؕتَيْنِؐ وَإِنْ يَّكُن مِّنكُمُ; أَلْفٌ يَغْلِبُوٓاْ أَلْفَيْـنِ بِــإِذْنِ ۱للَّهِؐ وَاللَّهُ مَعَ ۰لصَّـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 68, 'مَا كَانَ لِنَبِىٓءٖ اَنننْ يَّكُونَ لَهُ; أَسْرۭيٰ حَتَّــيٰ يُثْخِنَ فِى ۱لاَرْضِؐ تُرۣيدُونَ عَرَضَ ۰لدُّنْيۭاؐ وَاللَّهُ يُرۣيدُ ۴لاَخِرَةَؐ وَاللَّهُ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 69, 'لَّوْلاَ كِتَـٰــبٌ مِّــنَ ۰للَّهِ سَبَــقَ لَمَسَّكُمْ فِيمَآ أَخَذتُّمْ عَذَاب٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 70, 'فَكُلُواْ مِمَّا غَنِمْتُمْ حَچَلًا طَيِّباًؐ وَاتَّقُواْ ۴للَّهَؐ إِنننَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 71, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ قُل لِّمَن فِىٓ أَيْدِيكُم مِّنَ ۰لاَسْرۭيٰٓ إِنننْ يَّعْلَمِ ۱للَّهُ فِى قُلُوبِكُمْ خَيْراً يُوتِكُمْ خَيْراً مِّمَّآ ٱُخِذَ مِنكُمْ وَيَغْفِرْ لَكُمْؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 72, 'وَإِنْ يُّرۣيدُواْ خِيَانَتَــكَ فَقَدْ خَانُواْ ۴للَّهَ مِــن قَـبْلُ فَأَمْكَــنَ مِنْهُمْؐ 186 وَاللَّهُ عَلِيم٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 73, 'اِنننَّ ۰لذِينَ ءَامَنُواْ وَهَاجَرُواْ وَجَـٰهَدُواْ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْ فِى سَبِيلِ ۱للَّهِ وَالذِينَ ءَاوَواْ وَّنَصَرُوٓاْ ٱُوْلَئِــكَ بَعْضُهُمُ; أَوْلِيَآءُ بَعْضٍؐ وَالذِيــنَ ءَامَنُواْ وَلَمْ يُهَاجِرُواْ مَا لَكُم مِّنْ وَّچَيَتِهِم مِّن شَيْءٖ حَتَّيٰ يُهَاجِرُواْؐ وَإِنِ ''سْتَنصَرُوكُمْ فِى ۱لدِّينِ فَعَلَيْكُمُ ۴لنَّصْرُ إِلاَّ عَلَيٰ قَوْمٙ بَيْنَكُمْ وَبَيْنَهُم مِّيثَـٰقٌؐ وَاللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 74, 'وَالذِيــنَ كَفَرُواْ بَعْضُهُمُ; أَوْلِيَآءُ بَعْـضٖؐ اِلاَّ تَفْعَلُوهُ تَكُـن فِتْنَةٌ فِى ۱لاَرْضِ وَفَسَادٌ كَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 75, 'وَالذِيــنَ ءَامَنُواْ وَهَاجَرُواْ وَجَـٰهَدُواْ فِى سَبِيـلِ ۱للَّهِ وَالذِيــنَ ءَاوَواْ وَّنَصَرُوٓاْ ٱُوْلَئِــكَ هُمُ ۴لْمُومِنُونَ حَقّاًؐ لَّهُم مَّغْفِرَةٌ وَرۣزْقٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (8, 76, 'وَالذِيــنَ ءَامَنُواْ مِنۢ بَعْدُ وَهَاجَرُواْ وَجَـٰهَدُواْ مَعَكُمْ فَٱُوْلَئِــكَ مِنكُمْؐ وَٱُوْلُواْ ۴لاَرْحَامِ بَعْضُهُمُ; أَوْلۭيٰ بِبَعْضٍ فِى كِتَـٰبِ ۱للَّهِؐ إِنننَّ ۰للَّهَ بِكُلِّ شَيْءٖ عَلِيمٛ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 1, '187 بَرَآءَةٌ مِّــنَ ۰للَّهِ وَرَسُولِهِ“ إِلَي ۰لذِيـنَ عَـٰهَدتُّم مِّــنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 2, 'فَسِيحُواْ فِى ۱لاَرْضِ أَرْبَعَةَ أَشْهُرٍؐ وَاعْلَمُوٓاْ أَنَّكُمْ غَيْرُ مُعْجِزۣى ۱للَّهِ وَأَنننَّ ۰للَّهَ مُخْزۣى ۱لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 3, 'وَأَذَ؛نٌ مِّــنَ ۰للَّهِ وَرَسُولِهِ“ إِلَــي ۰لنَّاسِ يَوْمَ ۰لْحَجِّ ۱لاَكْبَرۣأَنننَّ ۰للَّهَ بَرۣىٓءٌ مِّــنَ ۰لْمُشْرۣكِينَ وَرَسُولُهُؐ, فَإِننن تُـبْتُمْ فَهُوَ خَيْرٌ لَّكُمْؐ وَإِن تَوَلَّيْتُمْ فَاعْلَمُوٓاْ أَنَّكُمْ غَيْرُمُعْجِزۣى ۱للَّهِؐ وَبَشِّرۣ ۱لذِيــنَ كَفَرُواْ بِعَذَابببٖ اَلِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 4, 'اِلاَّ ۰لذِيــنَ عَـٰهَدتُّم مِّــنَ ۰لْمُشْرۣكِينَ ثُمَّ لَمْ يَنقُصُوكُمْ شَيْـٔاً وَلَمْ يُظَـٰهِرُواْ عَلَيْكُمُ; أَحَداً فَأَتِمُّوٓاْ إِلَيْهِمْ عَهْدَهُمُ; إِلَــيٰ مُدَّتِهِمُؐ; إِنننَّ ۰للَّهَ يُحِــبُّ ۴لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 5, '¥ فَإِذَا "نسَلَخَ ۰لاَشْهُرُ۴لْحُرُمُ فَاقْتُلُواْ ۴لْمُشْرۣكِينَ حَيْــثُ وَجَدتُّمُوهُمْ وَخُذُوهُمْ وَاحْصُرُوهُمْ وَاقْعُدُواْ لَهُمْ كُلَّ مَرْصَدٍؐ فَإِن تَابُواْ وَأَقَامُواْ ۴لصَّلَوٰةَ وَءَاتَوُاْ ۴لزَّكَوٰةَ فَخَلُّواْ سَبِيلَهُمُؐ; إِنننَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 6, 'وَإِنننَ اَحَدٌ مِّــنَ ۰لْمُشْرۣكِيــنَ "سْتَجَارَكككَ فَأَجِرْهُ حَتَّــيٰ يَسْمَعَ كَچَمَ ۰للَّهِ ثُمَّ أَبْلِغْهُ مَامَنَهُؐ, ذَ؛لِكَ بِأَنَّهُمْ قَوْمٌ لاَّ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 7, 'كَيْفَ يَكُونُ لِلْمُشْرۣكِيــنَ عَهْد٘ 188 عِندَ ۰للَّهِ وَعِندَ رَسُولِهِ“ إِلاَّ ۰لذِيــنَ عَـٰهَدتُّمْ عِندَ ۰لْمَسْجِدِ ۱لْحَرَامِ فَمَا "سْتَقَـٰمُواْ لَكُمْ فَاسْتَقِيمُواْ لَهُمُؐ; إِنننَّ ۰للَّهَ يُحِــبُّ ۴لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 8, 'كَيْفَ وَإِنْ يَّظْهَرُواْ عَلَيْكُمْ لاَ يَرْقُبُواْ فِيكُمُ; إِلًاّ وَلاَ ذِمَّةًؐ يُرْضُونَكُم بِأَفْوَ؛هِهِمْ وَتَابۭيٰ قُلُوبُهُمْ وَأَكْثَرُهُمْ فَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 9, '"شْتَرَوْاْ بِـَٔايَـٰــتِ ۱للَّهِ ثَمَناً قَلِيلًا فَصَدُّواْ عَــن سَبِيلِهِؐ“ إِنَّهُمْ سَآءَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 10, 'لاَ يَرْقُبُونَ فِى مُومِــن۫ اِلًاّ وَلاَ ذِمَّةًؐ وَٱُوْلَئِــكَ هُمُ ۴لْمُعْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 11, 'فَإِننن تَـابُواْ وَأَقَامُواْ ۴لصَّلَوٰةَ وَءَاتَوُاْ ۴لزَّكَوٰةَ فَإِخْوَ؛نُكُمْ فِى ۱لدِّينِؐ وَنُفَصِّــلُ ۴لاَيَـٰــتِ لِقَوْمٍ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 12, 'وَإِننن نَّكَثُوٓاْ أَيْمَـٰنَهُم مِّنۢ بَعْدِ عَهْدِهِمْ وَطَعَنُواْ فِى دِينِكُمْ فَقَـٰتِلُوٓاْ أَئمَّةَ ۰لْكُفْرۣؐ إِنَّهُمْ لآَ أَيْمَـٰــنَ لَهُمْ لَعَلَّهُمْ يَنتَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 13, 'أَلاَ تُقَـٰتِلُونَ قَوْماً نَّكَثُوٓاْ أَيْمَـٰنَهُمْ وَهَمُّواْ بِإِخْرَاجِ ۱لرَّسُولِ وَهُم بَدَءُوكُمُ; أَوَّلَ مَرَّةٖ اَتَخْشَوْنَهُمْؐ فَاللَّهُ أَحَقُّ أَن تَخْشَوْهُ إِننن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 14, 'قَـٰتِلُوهُمْ يُعَذِّبْهُمُ ۴للَّهُ بِأَيْدِيكُمْ وَيُخْزۣهِمْ وَيَنصُرْكُمْ 189 عَلَيْهِمْ وَيَشْفِ صُدُورَ قَوْمٍ مُّومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 15, 'وَيُذْهِبْ غَيْظَ قُلُوبِهِمْؐ وَيَتُوبُ ۴للَّهُ عَلَيٰ مَنْ يَّشَآءُؐ وَاللَّهُ عَلِيم٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 16, 'اَمْ حَسِبْتُمُ; أَن تُتْرَكُواْ وَلَمَّا يَعْلَمِ ۱للَّهُ ۴لذِينَ جَـٰهَدُواْ مِنكُمْ وَلَمْ يَتَّخِذُواْ مِن دُونِ ۱للَّهِ وَلاَ رَسُولِهِ” وَلاَ ۰لْمُومِنِينَ وَلِيجَةًؐ وَاللَّهُ خَبِيرٛ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 17, 'مَا كَانَ لِلْمُشْرۣكِينَ أَنْ يَّعْمُرُواْ مَسَـٰجِدَ ۰للَّهِ شَـٰهِدِيــنَ عَلَيٰٓ أَنفُسِهِم بِالْكُفْرۣؐ ٱُوْلَئِــكَ حَبِطَــتَ اَعْمَـٰلُهُمْ وَفِى ۱لنّۭارۣ هُمْ خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 18, 'إِنَّمَا يَعْمُرُ مَسَـٰجِدَ ۰للَّهِ مَــنَ —امَنَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَأَقَامَ ۰لصَّلَوٰةَ وَءَاتَــي ۰لزَّكَوٰةَ وَلَمْ يَخْشَ إِلاَّ ۰للَّهَ فَعَسۭيٰٓ ٱُوْلَئِــكَ أَنْ يَّكُونُواْ مِنَ ۰لْمُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 19, '© أَجَعَلْتُمْ سِقَايَةَ ۰لْحَآجِّ وَعِمَارَةَ ۰لْمَسْجِدِ ۱لْحَرَامِ كَمَــنَ —امَنَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَجَـٰهَدَ فِى سَبِيلِ ۱للَّهِؐ لاَ يَسْتَوُﹼنَ عِندَ ۰للَّهِؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 20, '۰لذِيــنَ ءَامَنُواْ وَهَاجَرُواْ وَجَـٰهَدُواْ فِى سَبِيلِ ۱للَّهِ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمُ; أَعْظَمُ دَرَجَةٗ عِندَ ۰للَّهِؐ وَٱُوْلَئِــكَ هُمُ ۴لْفَآئِزُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 21, 'يُبَشِّرُهُمْ رَبُّهُم بِرَحْمَةٍ مِّنْهُ وَرۣضْوَ؛نٍ وَجَنَّـٰــتٍ لَّهُمْ فِيهَا 190 نَعِيمٌ مُّقِيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 22, 'خَـٰلِدِينَ فِيهَآ أَبَداٗؐ اِنننَّ ۰للَّهَ عِندَهُ; أَجْر٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 23, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَتَّخِذُوٓاْ ءَابَآءَكُمْ وَإِخْوَ؛نَكُمُ; أَوْلِيَآءَ اۭنِ ''سْتَحَبُّواْ ۴لْكُفْرَ عَلَي ۰لِايمَـٰنِؐ وَمَنْ يَّتَوَلَّهُم مِّنكُمْ فَٱُوْلَئِــكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 24, 'قُلِ اِن كَانننَ ءَابَآؤُكُمْ وَأَبْنَآؤُكُمْ وَإِخْوَ؛نُكُمْ وَأَزْوَ؛جُكُمْ وَعَشِيرَتُكُمْ وَأَمْوَ؛ل٘ ''قْتَرَفْتُمُوهَا وَتِجَـٰرَةٌ تَخْشَوْنننَ كَسَادَهَا وَمَسَـٰكِنُ تَرْضَوْنَهَآ أَحَــبَّ إِلَيْكُم مِّــنَ ۰للَّهِ وَرَسُولِهِ” وَجِهَادٍ فِى سَبِيلِهِ” فَتَرَبَّصُواْ حَتَّــيٰ يَاتِــيَ ۰للَّهُ بِأَمْرۣهِؐ” وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 25, 'لَقَدْ نَصَرَكُمُ ۴للَّهُ فِى مَوَاطِــنَ كَثِيرَةٍ وَيَوْمَ حُنَيْــن۫ اِذَ اَعْجَبَتْكُمْ كَثْرَتُكُمْ فَلَمْ تُغْــنۣ عَنكُمْ شَيْـٔاً وَضَاقَــتْ عَلَيْكُمُ ۴لاَرْضضضُ بِمَا رَحُبَــتْ ثُمَّ وَلَّيْتُم مُّدْبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 26, 'ثُمَّ أَنزَلَ ۰للَّهُ سَكِينَتَهُ„ عَلَيٰ رَسُولِهِ” وَعَلَــي ۰لْمُومِنِينَ وَأَنزَلَ جُنُوداً لَّمْ تَرَوْهَا وَعَذَّبببَ ۰لذِيــنَ كَفَرُواْؐ وَذَ؛لِــكَ جَزَآءُ ۴لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 27, 'ثُمَّ يَتُوبُ ۴للَّهُ مِـنۢ بَعْدِ ذَ؛لِــكَ عَلَيٰ مَنْ يَّشَآءُؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 28, '191  يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِنَّمَا ۰لْمُشْرۣكُونَ نَجَسٌ فَلاَ يَقْرَبُواْ ۴ڤْمَسْجِدَ ۰لْحَرَامَ بَعْدَ عَامِهِمْ هَـٰذَاؐ وَإِنْ خِفْتُمْ عَيْلَةً فَسَوْفَ يُغْنِيكُمُ ۴للَّهُ مِـن فَضْلِهِ“ إِننن شَآءَؐ اۭنننَّ ۰للَّهَ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 29, 'قَـٰتِلُواْ ۴لذِيــنَ لاَ يُومِنُونَ بِاللَّهِ وَلاَ بِالْيَوْمِ ۱لاَخِرۣ وَلاَ يُحَرّۣمُونَ مَا حَرَّمَ ۰للَّهُ وَرَسُولُهُ„ وَلاَ يَدِينُونَ دِيــنَ ۰لْحَـقِّ مِنَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَـٰــبَ حَتَّــيٰ يُعْطُواْ ۴لْجِزْيَةَ عَـنْ يَّدٍ وَهُمْ صَـٰغِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 30, 'وَقَالَــتِ ۱لْيَهُودُ عُزَيْرُ èبْــنُ ۴للَّهِؐ وَقَالَــتِ ۱لنَّصَـٰرَي ۰لْمَسِيحُ èبْنُ ۴للَّهِؐ ذَ؛لِــكَ قَوْلُهُم بِأَفْوَ؛هِهِمْ يُضَـٰهُونَ قَوْلَ ۰لذِيــنَ كَفَرُواْ مِــن قَـبْلُؐ قَـٰتَلَهُمُ ۴للَّهُؐ أَنّۭـيٰ يُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 31, '"تَّخَذُوٓاْ أَحْبَارَهُمْ وَرُهْبَـٰنَهُمُ; أَرْبَاباً مِّن دُونِ ۱للَّهِ وَالْمَسِيحَ "بْنَ مَرْيَمَؐ وَمَآ ٱُمِرُوٓاْ إِلاَّ لِيَعْبُدُوٓاْ إِچَهاً وَ؛حِداًؐ لٓاَّ إِچَهَ إِلاَّ هُوَؐ سُبْحَـٰنَهُ„ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 32, 'يُرۣيدُونَ أَنننْ يُّطْفِـُٔواْ نُورَ ۰للَّهِ بِأَفْوَ؛هِهِمْ وَيَابَــي ۰للَّهُ إِلٓاَّ أَنْ يُّتِمَّ نُورَهُ„ وَلَوْ كَرۣهَ ۰لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 33, 'هُوَ ۰ﻟـذِىٓ أَرْسَلَ رَسُولَهُ„ بِالْهُدۭيٰ وَدِيـنِ ۱لْحَقِّ لِيُظْهِرَهُ„ عَلَي ۰لدِّيــنۣ كُلِّهِ” وَلَوْ 192 كَرۣهَ ۰لْمُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 34, '¤ يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِنَّ كَثِيراً مِّــنَ ۰لاَحْبۭارۣ وَالرُّهْبَانِ لَيَاكُلُونَ أَمْوَ؛لَ ۰لنَّاسِ بِالْبَـٰطِلِ وَيَصُدُّونَ عَن سَبِيلِ ۱للَّهِؐ وَالذِينَ يَكْنِزُونَ ۰لذَّهَــبَ وَالْفِضَّةَ وَلاَ يُنفِقُونَهَا فِى سَبِيلِ ۱للَّهِ فَبَشِّرْهُم بِعَذَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 35, 'يَوْمَ يُحْمۭــيٰ عَلَيْهَا فِى نۭارۣ جَهَنَّمَ فَتُكْوۭيٰ بِهَا جِبَاهُهُمْ وَجُنُوبُهُمْ وَظُهُورُهُمْ هَـٰذَا مَا كَنَزْتُمْ لَأِنفُسِكُمْ فَذُوقُواْ مَا كُنتُمْ تَكْنِزُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 36, 'إِنَّ عِدَّةَ ۰لشُّهُورۣ عِندَ ۰للَّهِ ''ثْنَا عَشَرَ شَهْراً فِى كِتَـٰــبِ ۱للَّهِ يَوْمَ خَلَــقَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضضضَؐ مِنْهَآ أَرْبَعَة٘ حُرُمٌؐ ذَ؛لِــكَ ۰لدِّينُ ۴لْقَيِّمُؐ فَلاَ تَظْلِمُواْ فِيهِــنَّ أَنفُسَكُمْؐ وَقَـٰتِلُواْ ۴لْمُشْرۣكِينَ كَآفَّةً كَمَا يُقَـٰتِلُونَكُمْ كَآفَّةًؐ وَاعْلَمُوٓاْ أَنننَّ ۰للَّهَ مَعَ ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 37, 'إِنَّمَا ۰لنَّسِيُّ زۣيَادَةٌ فِى ۱لْكُفْرۣ يَضِلُّ بِهِ ۱لذِيــنَ كَفَرُواْ يُحِلُّونَهُ„ عَاماً وَيُحَرّۣمُونَهُ„ عَاماً لِّيُوَاطِـُٔواْ عِدَّةَ مَا حَرَّمَ ۰للَّهُ فَيُحِلُّواْ مَا حَرَّمَ ۰للَّهُؐ زُيِّــنَ لَهُمْ سُوٓءُ اَ۬عْمَـٰلِهِمْؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 38, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ 19 مَا لَكُمُ; إِذَا قِيــلَ لَكُمُ èنفِرُواْ فِى سَبِيلِ ۱للَّهِ ''ثَّاقَلْتُمُ; إِلَي ۰لاَرْضِؐ أَرَضِيتُم بِالْحَيَوٰةِ ۱لدُّنْيۭا مِنَ ۰لاَخِرَةِؐ فَمَا مَتَـٰعُ ۴لْحَيَوٰةِ ۱لدُّنْيۭا فِى ۱لاَخِرَةِ إِلاَّ قَلِيــل٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 39, 'اِلاَّ تَنفِرُواْ يُعَذِّبْكُمْ عَذَاباٗ اَلِيماً وَيَسْتَبْدِلْ قَوْماٗ غَيْرَكُمْ وَلاَ تَضُرُّوهُ شَيْـٔاًؐ وَاللَّهُ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 40, 'اِلاَّ تَنصُرُوهُ فَقَدْ نَصَرَهُ ۴للَّهُ إِذَ اَخْرَجَهُ ۴لذِيــنَ كَفَرُواْ ثَانِيَ "ثْنَيْنِ إِذْ هُمَا فِى ۱لْغۭارۣ إِذْ يَقُولُ ڤِصَـٰحِبِهِ” لاَ تَحْزَنِ اِنننَّ ۰للَّهَ مَعَنَاؐ فَأَنزَلَ ۰للَّهُ سَكِينَتَهُ„ عَلَيْهِؐ وَأَيَّدَهُ„ بِجُنُودٍ لَّمْ تَرَوْهَاؐ وَجَعَــلَ كَلِمَةَ ۰لذِيــنَ كَفَرُواْ ۴لسُّفْلۭيٰؐ وَكَلِمَةُ ۴للَّهِ هِــيَ ۰لْعُلْيۭاؐ وَاللَّهُ عَزۣيز٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 41, '''نفِرُواْ خِفَافاً وَثِقَالًا وَجَـٰهِدُواْ بِأَمْوَ؛لِكُمْ وَأَنفُسِكُمْ فِى سَبِيلِ ۱للَّهِؐ ذَ؛لِكُمْ خَيْرٌ لَّكُمُ; إِننن كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 42, 'لَوْ كَانننَ عَرَضاً قَرۣيباً وَسَفَراً قَاصِداً لاَّتَّبَعُوكككَ وَچَكِنۢ بَعُدَتتتْ عَلَيْهِمُ ۴لشُّقَّةُؐ وَسَيَحْلِفُونَ بِاللَّهِ لَوۣ ''سْتَطَعْنَا لَخَرَجْنَا مَعَكُمْؐ يُهْلِكُونَ أَنفُسَهُمْؐ وَاللَّهُ يَعْلَمُ إِنَّهُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 43, 'عَفَا ۰للَّهُ عَنــكَ لِمَ أَذِنــتَ لَهُمْ حَتَّيٰ يَتَبَيَّــنَ لَــكَ ۰لذِيــنَ صَدَقُواْ 194 وَتَعْلَمَ ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 44, 'لاَ يَسْتَـٰذِنُــكَ ۰لذِينَ يُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ أَنْ يُّجَـٰهِدُواْ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْؐ وَاللَّهُ عَلِيمٛ بِالْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 45, 'إِنَّمَا يَسْتَـٰذِنُــكَ ۰لذِيــنَ لاَ يُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَارْتَابَــتْ قُلُوبُهُمْ فَهُمْ فِى رَيْبِهِمْ يَتَرَدَّدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 46, '© وَلَوَ اَرَادُواْ ۴لْخُرُوجَ لَأَعَدُّواْ لَهُ„ عُدَّةًؐ وَچَكِــن كَرۣهَ ۰للَّهُ èنۢبِعَاثَهُمْ فَثَبَّطَهُمْ وَقِيــلَ ۸قْعُدُواْ مَعَ ۰لْقَـٰعِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 47, 'لَوْ خَرَجُواْ فِيكُم مَّا زَادُوكُمُ; إِلاَّ خَبَالًا وَلَأَوْضَعُواْ خِچَلَكُمْ يَبْغُونَكُمُ ۴لْفِتْنَةَ وَفِيكُمْ سَمَّـٰعُونَ لَهُمْؐ وَاللَّهُ عَلِيمٛ بِالظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 48, 'لَقَدِ ''بْتَغَوُاْ ۴لْفِتْنَةَ مِــن قَـبْلُ وَقَلَّبُواْ لَــكَ ۰لاُمُورَ حَتَّيٰ جَآءَ ۰لْحَقُّ وَظَهَرَ أَمْرُ ۴للَّهِ وَهُمْ كَـٰرۣهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 49, 'وَمِنْهُم مَّـنْ يَّقُولُ èيذَن لِّى وَلاَ تَفْتِنِّىٓؐ أَلاَ فِى ۱لْفِتْنَةِ سَقَطُواْؐ وَإِنَّ جَهَنَّمَ ڤَمُحِيطَةٛ بِالْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 50, 'إِن تُصِبْــكَ حَسَنَةٌ تَسُؤْهُمْؐ وَإِن تُصِبْــكَ مُصِيبَةٌ يَقُولُواْ قَدَ اَخَذْنَآ أَمْرَنَا مِــن قَـبْلُ وَيَتَوَلَّواْ وَّهُمْ فَرۣحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 51, 'قُل لَّنْ يُّصِيبَنَآ إِلاَّ مَا كَتَــبَ ۰للَّهُ لَنَاؐ هُوَ مَوْلۭيٰنَاؐ وَعَلَــي ۰للَّهِ فَلْيَتَوَكَّلِ 195 ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 52, 'قُلْ هَلْ تَرَبَّصُونَ بِنَآ إِلٓاَّ إِحْدَييي ۰لْحُسْنَيَيْنِؐ وَنَحْنُ نَتَرَبَّصُ بِكُمُ; أَنْ يُّـصِيبَكُمُ ۴للَّهُ بِعَذَابببٍ مِّنْ عِندِهِ“ أَوْ بِأَيْدِينَاؐ فَتَرَبَّصُوٓاْؐ إِنَّا مَعَكُم مُّتَرَبِّصُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 53, 'قُلَ اَنفِقُواْ طَوْعاٗ اَوْ كَرْهاً لَّنْ يُّتَقَبَّــلَ مِنكُمُؐ; إِنَّكُمْ كُنتُمْ قَوْماً فَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 54, 'وَمَا مَنَعَهُمُ; أَننن تُقْبَـلَ مِنْهُمْ نَفَقَـٰتُهُمُ; إِلٓاَّ أَنَّهُمْ كَفَرُواْ بِاللَّهِ وَبِرَسُولِهِ” وَلاَ يَاتُونَ ۰لصَّلَوٰةَ إِلاَّ وَهُمْ كُسَالۭيٰ وَلاَ يُنفِقُونَ إِلاَّ وَهُمْ كَـٰرۣهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 55, 'فَلاَ تُعْجِبْــكَ أَمْوَ؛لُهُمْ وَلآَ أَوْچَدُهُمُؐ; إِنَّمَا يُرۣيدُ ۴للَّهُ لِيُعَذِّبَهُم بِهَا فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَتَزْهَــقَ أَنفُسُهُمْ وَهُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 56, 'وَيَحْلِفُونَ بِاللَّهِ إِنَّهُمْ لَمِنكُمْ وَمَا هُم مِّنكُمْ وَچَكِنَّهُمْ قَوْمٌ يَفْرَقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 57, 'لَوْ يَجِدُونَ مَڤْجَــٔاٗ اَوْ مَغَـٰرَ؛تتتٖ اَوْ مُدَّخَلًا لَّوَلَّوۣاْ اِلَيْهِ وَهُمْ يَـجْمَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 58, 'وَمِنْهُم مَّنْ يَّلْمِزُكككَ فِى ۱لصَّدَقَـٰــتِ فَإِنننُ ۷عْطُواْ مِنْهَا رَضُواْ وَإِن لَّمْ يُعْطَوْاْ مِنْهَآ إِذَا هُمْ يَسْخَطُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 59, 'وَلَوَ اَنَّهُمْ رَضُواْ مَآ ءَاتۭيٰهُمُ ۴للَّهُ وَرَسُولُهُ„ وَقَالُواْ حَسْبُنَا ۰للَّهُ سَيُوتِينَا ۰للَّهُ مِن فَضْلِهِ” وَرَسُولُهُؐ; إِنَّـآ إِلَــي ۰للَّهِ رَ؛غِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 60, '196 إِنَّمَا ۰لصَّدَقَـٰــتُ لِلْفُقَرَآءِ وَالْمَسَـٰكِينِ وَالْعَـٰمِلِيــنَ عَلَيْهَا وَالْمُوَ۬لَّفَةِ قُلُوبُهُمْ وَفِى ۱لرّۣقَابببِ وَالْغَـٰرۣمِينَ وَفِى سَبِيلِ ۱للَّهِ وَابْـنِ ۱لسَّبِيلِ فَرۣيضَةً مِّــنَ ۰للَّهِؐ وَاللَّهُ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 61, '¥ وَمِنْهُمُ ۴لذِينَ يُوذُونَ ۰لنَّبِىٓءَ وَيَقُولُونَ هُوَ ٱُذْنٌؐ قُــلُ ۷ذْنُ خَيْرٍ لَّكُمْ يُومِنُ بِاللَّهِ وَيُومِـنُ لِلْمُومِنِينَ وَرَحْمَةٌ لِّلذِيــنَ ءَامَنُواْ مِنكُمْؐ وَالذِينَ يُوذُونَ رَسُولَ ۰للَّهِ لَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 62, 'يَحْلِفُونَ بِاللَّهِ لَكُمْ لِيُرْضُوكُمْ وَاللَّهُ وَرَسُولُهُ; أَحَقُّ أَنْ يُّرْضُوهُ إِننن كَانُواْ مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 63, 'أَلَمْ يَعْلَمُوٓاْ أَنَّهُ„ مَنْ يُّحَادِدِ ۱للَّهَ وَرَسُولَهُ„ فَأَنننَّ لَهُ„ نَارَ جَهَنَّمَ خَـٰلِداً فِيهَاؐ ذَ؛لِكَ ۰لْخِزْيُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 64, 'يَحْذَرُ ۴لْمُنَـٰفِقُونَ أَن تُنَزَّلَ عَلَيْهِمْ سُورَةٌ تُنَبِّيؖهُم بِمَا فِى قُلُوبِهِمْؐ قُلِ ''سْتَهْزۣءُوٓاْؐ إِنننَّ ۰للَّهَ مُخْرۣجٌ مَّا تَحْذَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 65, 'وَلَـئِــن سَأَلْتَهُمْ لَيَقُولُنَّ إِنَّمَا كُنَّا نَخُوضُ وَنَلْعَبُؐ قُـلَ اَبِاللَّهِ وَءَايَـٰتِهِ” وَرَسُولِهِ” كُنتُمْ تَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 66, 'لاَ تَعْتَذِرُواْؐ قَدْ كَفَرْتُم بَعْدَ إِيمَـٰنِكُمُؐ; إِنْ يُّعْفَ عَــن طَآئِفَةٍ مِّنكُمْ تُعَذَّبْ طَآئِفَةٛ بِأَنَّهُمْ كَانُواْ مُجْرۣمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 67, '197 ۰لْمُنَـٰفِقُونَ وَالْمُنَـٰفِقَـٰــتُ بَعْضُهُم مِّـنۢ بَعْـضٍ يَامُرُونَ بِالْمُنكَرۣ وَيَنْهَوْنَ عَـنِ ۱لْمَعْرُوفِ وَيَقْبِضُونَ أَيْدِيَهُمْ نَسُواْ ۴للَّهَ فَنَسِيَهُمُؐ; إِنننَّ ۰لْمُنَـٰفِقِيــنَ هُمُ ۴لْفَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 68, 'وَعَدَ ۰للَّهُ ۴لْمُنَـٰفِقِينَ وَالْمُنَـٰفِقَـٰــتِ وَالْكُفَّارَ نَارَ جَهَنَّمَ خَـٰلِدِينَ فِيهَاؐ هِــيَ حَسْبُهُمْؐ وَلَعَنَهُمُ ۴للَّهُؐ وَلَهُمْ عَذَابببٌ مُّقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 69, 'كَالذِيــنَ مِـن قَبْلِكُمْ كَانُوٓاْ أَشَدَّ مِنكُمْ قُوَّةً وَأَكْثَرَ أَمْوَ؛لًا وَأَوْچَداً فَاسْتَمْتَعُواْ بِخَچَقِهِمْ فَاسْتَمْتَعْتُم بِخَچَقِكُمْ كَمَا "سْتَمْتَعَ ۰لذِينَ مِن قَبْلِكُم بِخَچَقِهِمْ وَخُضْتُمْ كَاﻟ﮲ خَاضُوٓاْؐ ٱُوْلَئِكَ حَبِطَــتَ اَعْمَـٰلُهُمْ فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَٱُوْلَئِكَ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 70, 'أَلَمْ يَاتِهِمْ نَبَٱُ ۴لذِيــنَ مِـن قَبْلِهِمْ قَوْمِ نُوحٍ وَعَادٍ وَثَمُودَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 71, 'وَقَوْمِ إِبْرَ؛هِيمَ وَأَصْحَـٰــبِ مَدْيَنَ وَالْمُوتَفِكَـٰــتِؐ أَتَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰــتِؐ فَمَا كَانَ ۰للَّهُ لِيَظْلِمَهُمْؐ وَچَكِن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 72, 'وَالْمُومِنُونَ وَالْمُومِنَـٰــتُ بَعْضُهُمُ; أَوْلِيَآءُ بَعْضٍؐ يَامُرُونَ بِالْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ۱لْمُنكَرۣ وَيُقِيمُونَ ۰لصَّلَوٰةَ وَيُوتُونَ ۰لزَّكَوٰةَ وَيُطِيعُونننَ ۰للَّهَ 198 وَرَسُولَهُؐ; ٱُوْلَئِــكَ سَيَرْحَمُهُمُ ۴للَّهُؐ إِنننَّ ۰للَّهَ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 73, 'وَعَدَ ۰للَّهُ ۴لْمُومِنِينَ وَالْمُومِنَـٰتِ جَنَّـٰــتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِيــنَ فِـيهَا وَمَسَـٰكِــنَ طَيِّبَةً فِى جَنَّـٰــتِ عَدْنٍؐ وَرۣضْوَ؛نٌ مِّــنَ ۰للَّهِ أَكْبَرُؐ ذَ؛لِــكَ هُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 74, 'يَـٰٓأَيُّهَا ‏ ۰لنَّبِىٓءُ جَـٰهِدِ ۱لْكُفَّارَ وَالْمُنَـٰفِقِينَ وَاغْلُظْ عَلَيْهِمْؐ وَمَأْوۭيٰهُمْ جَهَنَّمُؐ وَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 75, 'يَحْلِفُونَ بِاللَّهِ مَا قَالُواْؐ وَلَقَدْ قَالُواْ كَلِمَةَ ۰لْكُفْرۣ وَكَفَرُواْ بَعْدَ إِسْچَمِهِمْ وَهَمُّواْ بِمَا لَمْ يَنَالُواْؐ وَمَا نَقَمُوٓاْ إِلٓاَّ أَنَ اَغْنۭيٰهُمُ ۴للَّهُ وَرَسُولُهُ„ مِن فَضْلِهِؐ” فَإِنْ يَّتُوبُواْ يَــكُ خَيْراً لَّهُمْؐ وَإِنْ يَّتَوَلَّوْاْ يُعَذِّبْهُمُ ۴للَّهُ عَذَاباٗ اَلِيماً فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَمَا لَهُمْ فِى ۱لاَرْضضضِ مِنْ وَّلِيٍّ وَلاَ نَصِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 76, '© وَمِنْهُم مَّــنْ عَـٰهَدَ ۰للَّهَ لَـئِــنَ —اتۭيٰنَا مِن فَضْلِهِ” لَنَصَّدَّقَنَّ وَلَنَكُونَــنَّ مِـنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 77, 'فَلَمَّآ ءَاتۭيٰهُم مِّن فَضْلِهِ” بَخِلُواْ بِهِ” وَتَوَلَّواْ وَّهُم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 78, 'فَأَعْقَبَهُمْ نِفَاقاً فِى قُلُوبِهِمُ; إِلَيٰ يَوْمِ يَلْقَوْنَهُ„ بِمَآ أَخْلَفُواْ ۴للَّهَ مَا وَعَدُوهُ وَبِمَا كَانُواْ يَكْذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 79, 'أَلَمْ يَعْلَمُوٓاْ أَنننَّ ۰للَّهَ 199 يَعْلَمُ سِرَّهُمْ وَنَجْوۭيٰهُمْ وَأَنننَّ ۰للَّهَ عَچَّمُ ۴لْغُيُوبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 80, '۱لذِينَ يَلْمِزُونَ ۰لْمُطَّوّۣعِينَ مِنَ ۰لْمُومِنِينَ فِى ۱لصَّدَقَـٰــتِ وَالذِينَ لاَ يَجِدُونَ إِلاَّ جُهْدَهُمْ فَيَسْخَرُونَ مِنْهُمْ سَخِرَ ۰للَّهُ مِنْهُمْؐ وَلَهُمْ عَذَاب٘ اَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 81, '''سْتَغْفِرْ لَهُمُ; أَوْ لاَ تَسْتَغْفِرْ لَهُمُؐ; إِننن تَسْتَغْفِرْ لَهُمْ سَبْعِيــنَ مَرَّةً فَلَنْ يَّغْفِرَ ۰للَّهُ لَهُمْؐ ذَ؛لِــكَ بِأَنَّهُمْ كَفَرُواْ بِاللَّهِ وَرَسُولِهِؐ” وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 82, 'فَرۣحَ ۰ڤْمُخَلَّفُونَ بِمَقْعَدِهِمْ خِچَفَ رَسُولِ ۱للَّهِ وَكَرۣهُوٓاْ أَنْ يُّجَـٰهِدُواْ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْ فِى سَبِيلِ ۱للَّهِ وَقَالُواْ لاَ تَنفِرُواْ فِى ۱لْحَرّۣؐ قُلْ نَارُ جَهَنَّمَ أَشَدُّ حَرّاً لَّوْ كَانُواْ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 83, 'فَڤْيَضْحَكُواْ قَلِيلًا وَلْيَبْكُواْ كَثِيراً جَزَآءَۢ بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 84, 'فَإِن رَّجَعَكَ ۰للَّهُ إِلَــيٰ طَآئِفَةٍ مِّنْهُمْ فَاسْتَـٰذَنُوكككَ ڤِڤْخُرُوجِ فَقُل لَّن تَخْرُجُواْ مَعِــيَ أَبَداً وَلَــن تُقَـٰتِلُواْ مَعِى عَدُوّاٗؐ اِنَّكُمْ رَضِيتُم بِالْقُعُودِ أَوَّلَ مَرَّةٍؐ فَاقْعُدُواْ مَعَ ۰لْخَـٰلِفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 85, 'وَلاَ تُصَــلّۣ عَلَيٰٓ أَحَدٍ مِّنْهُم مَّاتتتَ أَبَداً وَلاَ تَقُمْ عَلَيٰ قَبْرۣهِؐ“ إِنَّهُمْ كَفَرُواْ بِاللَّهِ وَرَسُولِهِ” وَمَاتُواْ وَهُمْ 200 فَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 86, 'وَلاَ تُعْجِبْــكَ أَمْوَ؛لُهُمْ وَأَوْچَدُهُمُؐ; إِنَّمَا يُرۣيدُ ۴للَّهُ أَنْ يُّعَذِّبَهُم بِهَا فِى ۱لدُّنْيۭا وَتَزْهَــقَ أَنفُسُهُمْ وَهُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 87, 'وَإِذَآ ٱُنزۣلَــتْ سُورَة٘ اَنَ —امِنُواْ بِاللَّهِ وَجَـٰهِدُواْ مَعَ رَسُولِهِ ''سْتَـٰذَنَــكَ ٱُوْلُواْ ۴لطَّوْلِ مِنْهُمْ وَقَالُواْ ذَرْنَا نَكُن مَّعَ ۰لْقَـٰعِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 88, 'رَضُواْ بِأَنْ يَّكُونُواْ مَعَ ۰لْخَوَالِـفِؐ وَطُبِعَ عَلَــيٰ قُلُوبِهِمْ فَهُمْ لاَ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 89, 'چَكِنِ ۱لرَّسُولُ وَالذِيــنَ ءَامَنُواْ مَعَهُ„ جَـٰهَدُواْ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْؐ وَٱُوْلَئِــكَ لَهُمُ ۴لْخَيْرَ؛تتتُؐ وَٱُوْلَئِــكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 90, 'أَعَدَّ ۰للَّهُ لَهُمْ جَنَّـٰــتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَاؐ ذَ؛لِكَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 91, 'وَجَآءَ ۰لْمُعَذِّرُونَ مِــنَ ۰لاَعْرَابِ لِيُوذَنَ لَهُمْ وَقَعَدَ ۰لذِيــنَ كَذَبُواْ ۴للَّهَ وَرَسُولَهُؐ, سَيُصِيــبُ ۴لذِيــنَ كَفَرُواْ مِنْهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 92, 'لَّيْــسَ عَلَي ۰لضُّعَفَآءِ وَلاَ عَلَي ۰لْمَرْضۭيٰ وَلاَ عَلَــي ۰لذِيــنَ لاَ يَجِدُونَ مَا يُنفِقُونَ حَرَج٘ اِذَا نَصَحُواْ لِلهِ وَرَسُولِهِؐ” مَا عَلَــي ۰ڤْمُحْسِنِينَ مِن سَبِيلٍؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 93, 'وَلاَ عَلَــي ۰لذِيــنَ إِذَا مَآ أَتَوْكَ ڤِتَحْمِلَهُمْ قُلْتَ 201 لآَ أَجِدُ مَآ أَحْمِلُكُمْ عَلَيْهِؐ تَوَلَّواْ وَّأَعْيُنُهُمْ تَفِيضُ مِنَ ۰لدَّمْعِ حَزَناٗ اَلاَّ يَجِدُواْ مَا يُنفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 94, '¤ إِنَّمَا ۰لسَّبِيلُ عَلَي ۰لذِينَ يَسْتَـٰذِنُونَــكَ وَهُمُ; أَغْنِيَآءُؐ رَضُواْ بِأَنْ يَّكُونُواْ مَعَ ۰لْخَوَالِفِؐ وَطَبَعَ ۰للَّهُ عَلَــيٰ قُلُوبِهِمْ فَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 95, 'يَعْتَذِرُونَ إِلَيْكُمُ; إِذَا رَجَعْتُمُ; إِلَيْهِمْؐ قُــل لاَّ تَعْتَذِرُواْ لَن نُّومِــنَ لَكُمْؐ قَدْ نَبَّأَنَا ۰للَّهُ مِــنَ اَخْبۭارۣكُمْؐ وَسَيَرَييي ۰للَّهُ عَمَلَكُمْ وَرَسُولُهُؐ„ ثُمَّ تُرَدُّونَ إِلَــيٰ عَـٰلِمِ ۱لْغَيْــبِ وَالشَّهَـٰدَةِ فَيُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 96, 'سَيَحْلِفُونَ بِاللَّهِ لَكُمُ; إِذَا "نقَلَبْتُمُ; إِلَيْهِمْ لِتُعْرۣضُواْ عَنْهُمْؐ فَأَعْرۣضُواْ عَنْهُمُؐ; إِنَّهُمْ رۣجْسٌؐ وَمَأْوۭيٰهُمْ جَهَنَّمُؐ جَزَآءَۢ بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 97, 'يَحْلِفُونَ لَكُمْ لِتَرْضَوْاْ عَنْهُمْ فَإِن تَرْضَوْاْ عَنْهُمْ فَإِنننَّ ۰للَّهَ لاَ يَرْضۭيٰ عَنِ ۱لْقَوْمِ ۱لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 98, '۰لاَعْرَابُ أَشَدُّ كُفْراً وَنِفَاقاً وَأَجْدَرُ أَلاَّ يَعْلَمُواْ حُدُودَ مَآ أَنزَلَ ۰للَّهُ عَلَيٰ رَسُولِهِؐ” وَاللَّهُ عَلِيـم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 99, 'وَمِــنَ ۰لاَعْرَابببِ مَــنْ يَّتَّخِذُ مَا يُنفِقُ مَغْرَماً وَيَتَرَبَّصُ بِكُمُ ۴لدَّوَآئِرَؐ عَلَيْهِمْ دَآئِرَةُ ۴لسَّوْءِؐ وَاللَّهُ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 100, '202 وَمِــنَ ۰لاَعْرَابببِ مَنْ يُّومِـنُ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ وَيَتَّخِذُ مَا يُنفِقُ قُرُبَـٰــتٖ عِندَ ۰للَّهِ وَصَلَوَ؛تتتِ ۱لرَّسُولِؐ أَلآَ إِنَّهَا قُرُبَةٌ لَّهُمْؐ سَيُدْخِلُهُمُ ۴للَّهُ فِى رَحْمَتِهِؐ“ إِنننَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 101, 'وَالسَّـٰبِقُونَ ۰لاَوَّلُونَ مِــنَ ۰ڤْمُهَـٰجِرۣيـنَ وَالاَنصۭارۣ وَالذِينَ "تَّبَعُوهُم بِإِحْسَـٰنٍ رَّضِــيَ ۰للَّهُ عَنْهُمْ وَرَضُواْ عَنْهُؐ وَأَعَدَّ لَهُمْ جَنَّـٰــتٍ تَجْرۣى تَحْتَهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَداًؐ ذَ؛لِــكَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 102, 'وَمِمَّنْ حَوْلَكُم مِّــنَ ۰لاَعْرَابِ مُنَـٰفِقُونَؐ وَمِــنَ اَهْلِ ۱لْمَدِينَةِ مَرَدُواْ عَلَي ۰لنِّفَاقِ لاَ تَعْلَمُهُمْؐ نَحْــنُ نَعْلَمُهُمْؐ سَنُعَذِّبُهُم مَّرَّتَيْنِ ثُمَّ يُرَدُّونَ إِلَــيٰ عَذَابٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 103, 'وَءَاخَرُونَ "عْتَرَفُواْ بِذُنُوبِهِمْ خَلَطُواْ عَمَلًا صَـٰڤِحاً وَءَاخَرَ سَيِّيؗاٗ عَسَــي ۰للَّهُ أَنننْ يَّتُوبببَ عَلَيْهِمُؐ; إِنننَّ ۰للَّهَ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 104, 'خُذْ مِنَ اَمْوَ؛لِهِمْ صَدَقَةً تُطَهِّرُهُمْ وَتُزَكِّيهِم بِهَا وَصَــلّۣ عَلَيْهِمُؐ; إِنننَّ صَلَوَ؛تِــكَ سَكَــنٌ لَّهُمْؐ وَاللَّهُ سَمِيع٘ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 105, 'اَلَمْ يَعْلَمُوٓاْ أَنننَّ ۰للَّهَ هُوَ يَقْبَلُ ۴لتَّوْبَةَ عَنْ عِبَادِهِ” وَيَاخُذُ ۴لصَّدَقَـٰــتِ وَأَنَّ ۰للَّهَ هُوَ ۰لتَّوَّابُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 106, '20 وَقُـلِ ''عْمَلُواْ فَسَيَرَي ۰للَّهُ عَمَلَكُمْ وَرَسُولُهُ„ وَالْمُومِنُونَؐ وَسَتُرَدُّونَ إِلَيٰ عَـٰلِمِ ۱لْغَيْــبِ وَالشَّهَـٰدَةِ فَيُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 107, 'وَءَاخَرُونَ مُرْجَوْنَ لَأِمْرۣ ۱للَّهِ إِمَّــا يُعَذِّبُهُمْ وَإِمَّا يَتُوبُ عَلَيْهِمْؐ وَاللَّهُ عَلِيم٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 108, '۱لذِيــنَ "تَّخَذُواْ مَسْجِداً ضِرَاراً وَكُفْراً وَتَفْرۣيقاَۢ بَيْــنَ ۰لْمُومِنِينَ وَإِرْصَاداً لِّمَــنْ حَارَبببَ ۰للَّهَ وَرَسُولَهُ„ مِــن قَـبْلُؐ وَڤَيَحْلِفُنَّ إِنَ اَرَدْنَآ إِلاَّ ۰لْحُسْنۭيٰؐ وَاللَّهُ يَشْهَدُ إِنَّهُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 109, 'لاَ تَقُمْ فِيهِ أَبَداًؐ ڤَّمَسْجِد٘ ۷سِّــسَ عَلَي ۰لتَّقْوۭيٰ مِنَ اَوَّلِ يَوْمٖ اَحَقُّ أَن تَقُومَ فِيهِؐ فِيهِ رۣجَالٌ يُحِبُّونَ أَنننْ يَّتَطَهَّرُواْؐ وَاللَّهُ يُحِبُّ ۴لْمُطَّهِّرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 110, 'أَفَمَنُ ۷سِّسَ بُنْيَـٰنُهُ„ عَلَيٰ تَقْوۭيٰ مِـــنَ ۰للَّهِ وَرۣضْوَ؛نٖ خَيْر٘ اَم مَّنُ ۷سِّسَ بُنْيَـٰنُهُ„ عَلَــيٰ شَفَا جُرُفٖ هۭارٍ فَانْهَارَ بِهِ” فِى نۭارۣ جَهَنَّمَؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 111, 'لاَ يَزَالُ بُنْيَـٰنُهُمُ ۴ﻟ﮲ بَنَوْاْ رۣيبَةً فِى قُلُوبِهِمُ; إِلٓاَّ أَننن تُقَطَّعَ قُلُوبُهُمْؐ وَاللَّهُ عَلِيم٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 112, '© اِنننَّ ۰للَّهَ "شْتَرۭيٰ مِــنَ ۰لْمُومِنِيــنَ أَنفُسَهُمْ وَأَمْوَ؛لَهُم بِأَنننَّ لَهُمُ ۴لْجَنَّةَؐ 204 يُقَـٰتِلُونَ فِى سَبِيلِ ۱للَّهِ فَيَقْتُلُونَ وَيُقْتَلُونَ وَعْداٗ عَلَيْهِ حَقّاً فِى ۱لتَّوْرۭيٰةِ وَالِانجِيلِ وَالْقُرْءَانِؐ وَمَنَ اَوْفۭيٰ بِعَهْدِهِ” مِــنَ ۰للَّهِؐ فَاسْتَبْشِرُواْ بِبَيْعِكُمُ ۴ﻟ﮲ بَايَعْتُم بِهِؐ” وَذَ؛لِكَ هُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 113, '۴لتَّـٰٓئِبُونَ ۰لْعَـٰبِدُونَ ۰لْحَـٰمِدُونَ ۰ڤسَّـٰٓئِـحُونَ ۰لرَّ؛كِعُونَ ۰لسَّـٰجِدُونَ ۰لاَمِرُونَ بِالْمَعْرُوفِ وَالنَّاهُونَ عَـنِ ۱لْمُنكَرۣ وَالْحَـٰفِظُونَ لِحُدُودِ ۱للَّهِؐ وَبَشِّرۣ ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 114, 'مَا كَانَ لِلنَّبِىٓءِ وَالذِيــنَ ءَامَنُوٓاْ أَنننْ يَّسْتَغْفِرُواْ لِلْمُشْرۣكِينَ وَلَوْ كَانُوٓاْ ٱُوْلِى قُرْبۭيٰ مِـنۢ بَعْدِ مَا تَبَيَّــنَ لَهُمُ; أَنَّهُمُ; أَصْحَـٰبُ ۴لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 115, 'وَمَا كَانَ "سْتِغْفَارُ إِبْرَ؛هِيمَ لَأِبِيهِ إِلاَّ عَن مَّوْعِدَةٍ وَعَدَهَآ إِيَّاهُؐ فَلَمَّا تَبَيَّــنَ لَهُ; أَنَّهُ„ عَدُوٌّ لِّلهِ تَبَرَّأَ مِنْهُؐ إِنَّ إِبْرَ؛هِيمَ لَأَوَّ؛ه٘ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 116, 'وَمَا كَانَ ۰للَّهُ لِيُضِلَّ قَوْماَۢ بَعْدَ إِذْ هَدۭيٰهُمْ حَتَّيٰ يُبَيِّــنَ لَهُم مَّا يَتَّقُونَؐ إِنننَّ ۰للَّهَ بِكُــلّۣ شَيْءٖ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 117, 'اِنننَّ ۰للَّهَ لَهُ„ مُلْكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ يُحْىِ” وَيُمِيــتُؐ وَمَا لَكُم مِّن دُونِ ۱للَّهِ مِنْ وَّلِيٍّ وَلاَ نَصِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 118, 'لَّقَد تَّابببَ ۰للَّهُ عَلَــي ۰لنَّبِىٓءِ وَاڤْمُهَـٰجِرۣينَ 205 وَالاَنصۭارۣ ۱لذِيــنَ "تَّبَعُوهُ فِى سَاعَةِ ۱لْعُسْرَةِ مِـنۢ بَعْدِ مَــا كَادَ تَزۣيغُ قُلُوبببُ فَرۣيـقٍ مِّنْهُمْ ثُمَّ تَابببَ عَلَيْهِمُ; إِنَّهُ„ بِهِمْ رَءُوفٌ رَّحِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 119, 'وَعَلَــي ۰لثَّچَثَةِ ۱لذِيــنَ خُلِّفُواْؐ حَتَّيٰٓ إِذَا ضَاقَــتْ عَلَيْهِمُ ۴لاَرْضُ بِمَا رَحُبَــتْ وَضَاقَتْ عَلَيْهِمُ; أَنفُسُهُمْ وَظَنُّوٓاْ أَن لاَّ مَلْجَأَ مِــنَ ۰للَّهِ إِلٓاَّ إِلَيْهِ ثُمَّ تَابَ عَلَيْهِمْ لِيَتُوبُوٓاْؐ إِنننَّ ۰للَّهَ هُوَ ۰لتَّوَّابُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 120, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ وَكُونُواْ مَعَ ۰لصَّـٰدِقِـيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 121, 'مَا كَانَ لَأِهْـلِ ۱لْمَدِينَةِ وَمَــنْ حَوْلَهُم مِّــنَ ۰لاَعْرَابِ أَنْ يَّتَخَلَّفُواْ عَن رَّسُولِ ۱للَّهِ وَلاَ يَرْغَبُواْ بِأَنفُسِهِمْ عَــن نَّفْسِهِؐ” ذَ؛لِــكَ بِأَنَّهُمْ لاَ يُصِيبُهُمْ ظَمَاءٌ وَلاَ نَصَــبٌ وَلاَ مَخْمَصَةٌ فِى سَبِيلِ ۱للَّهِ وَلاَ يَطَـُٔونَ مَوْطِيؗاً يَغِيظُ ۴لْكُفَّارَ وَلاَ يَنَالُونَ مِــنْ عَدُوٍّ نَّيْلٗا اِلاَّ كُتِبَ لَهُم بِهِ” عَمَــلٌ صَـٰلِح٘ؐ اِنَّ ۰للَّهَ لاَ يُضِيعُ أَجْرَ ۰ڤْمُحْسِنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 122, 'وَلاَ يُنفِقُونَ نَفَقَةً صَغِيرَةً وَلاَ كَبِيرَةً وَلاَ يَقْطَعُونَ وَادِياٗ اِلاَّ كُتِبَ لَهُمْؐ لِيَجْزۣيَهُمُ ۴للَّهُ أَحْسَــنَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 123, 'وَمَا كَانَ 206 ۰لْمُومِنُونَ لِيَنفِرُواْ كَآفَّةًؐ فَلَوْلاَ نَفَرَ مِــن كُلِّ فِرْقَةٍ مِّنْهُمْ طَــآئِفَةٌ لِّيَتَفَقَّهُــواْ فِى ۱لدِّينِ وَلِيُنذِرُواْ قَوْمَهُــمُ; إِذَا رَجَعُوٓاْ إِلَيْهِمْ لَعَلَّهُمْ يَحْذَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 124, '¥ يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ قَـٰتِلُواْ ۴لذِينَ يَلُونَكُم مِّــنَ ۰لْكُفّۭارۣ وَڤْيَجِدُواْ فِيكُمْ غِلْظَةًؐ وَاعْلَمُوٓاْ أَنننَّ ۰للَّهَ مَعَ ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 125, 'وَإِذَا مَآ ٱُنزۣلَــتْ سُورَةٌ فَمِنْهُم مَّنْ يَّقُولُ أَيُّكُمْ زَادَتْهُ هَـٰذِهِ“ إِيمَـٰناًؐ فَأَمَّا ۰لذِيــنَ ءَامَنُواْ فَزَادَتْهُمُ; إِيمَـٰناً وَهُمْ يَسْتَبْشِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 126, 'وَأَمَّا ۰لذِيــنَ فِى قُلُوبِهِم مَّرَضٌ فَزَادَتْهُمْ رۣجْساٗ اِلَيٰ رۣجْسِهِمْ وَمَاتُواْ وَهُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 127, 'أَوَلاَ يَرَوْنَ أَنَّهُمْ يُفْتَنُونَ فِى كُــلّۣ عَامٍ مَّرَّةٗ اَوْ مَرَّتَيْنِ ثُمَّ لاَ يَتُوبُونَ وَلاَ هُمْ يَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 128, 'وَإِذَا مَآ ٱُنزۣلَــتْ سُورَةٌ نَّظَرَ بَعْضُهُمُ; إِلَيٰ بَعْـضٖ هَلْ يَرۭيٰكُم مِّــنَ اَحَدٍ ثُمَّ "نصَرَفُواْؐ صَرَفَ ۰للَّهُ قُلُوبَهُم بِأَنَّهُمْ قَوْمٌ لاَّ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 129, 'لَقَدْ جَآءَكُمْ رَسُولٌ مِّنَ اَنفُسِكُمْ عَزۣيز٘ عَلَيْهِ مَا عَنِتُّمْؐ حَرۣيــص٘ عَلَيْكُمؐ بِالْمُومِنِينَ رَءُوفٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (9, 130, 'فَإِن تَوَلَّوْاْ فَقُــلْ حَسْبِــيَ ۰للَّهُؐ 207 لآَ إِچَهَ إِلاَّ هُوَؐ عَلَيْهِ تَوَكَّلْــتُؐ وَهُوَ رَبببُّ ۴لْعَرْشِ ۱لْعَظِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓرۭؐ تِلْــكَ ءَايَـٰتُ ۴لْكِتَـٰــبِ ۱لْحَكِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 2, 'أَكَانَ لِلنَّاسسسِ عَجَباٗ اَنَ اَوْحَيْنَآ إِلَيٰ رَجُلٍ مِّنْهُمُ; أَنَ اَنذِرۣ ۱لنَّاسَؐ وَبَشِّرۣ ۱لذِيــنَ ءَامَنُوٓاْ أَنَّ لَهُمْ قَدَمَ صِدْققق۫ عِندَ رَبِّهِمْؐ قَالَ ۰لْكَـٰفِرُونَ إِنننَّ هَـٰذَا ڤَسِحْرٌ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 3, 'اِنَّ رَبَّكُمُ ۴للَّهُ ۴ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضضضَ فِى سِتَّةِ أَيَّامٍ ثُمَّ "سْتَوۭيٰ عَلَــي ۰لْعَرْشِؐ يُدَبِّرُ ۴لاَمْرَؐ مَا مِــن شَفِيعٖ اِلاَّ مِـنۢ بَعْدِ إِذْنِهِؐ” ذَ؛لِكُمُ ۴للَّهُ رَبُّكُمْؐ فَاعْبُدُوهُؐ أَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 4, 'إِلَيْهِ مَرْجِعُكُمْ جَمِيعاًؐ وَعْدَ ۰للَّهِ حَقّاٗؐ اِنَّهُ„ يَبْدَؤُاْ ۴لْخَلْقَ ثُمَّ يُعِيدُهُ„ لِيَجْزۣيَ ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ بِالْقِسْطِؐ وَالذِيــنَ كَفَرُواْ لَهُمْ شَرَابببٌ مِّــنْ حَمِيمٍ وَعَذَاببب٘ اَلِيمٛ بِمَا كَانُواْ يَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 5, 'هُوَ ۰ﻟ﮲ جَعَــلَ ۰لشَّمْـسَ ضِيَآءً وَالْقَمَرَ نُوراً وَقَدَّرَهُ„ مَنَازۣلَ لِتَعْلَمُواْ عَدَدَ ۰لسِّنِينَ وَالْحِسَابببَؐ مَا خَلَــقَ ۰للَّهُ ذَ؛لِــكَ إِلاَّ بِالْحَقﱢّؐ 208 نُفَصِّــلُ ۴لاَيَـٰتِ لِقَوْمٍ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 6, 'إِنَّ فِى ''خْتِچَفِ ۱ليْلِ وَالنَّهۭارۣ وَمَا خَلَــقَ ۰للَّهُ فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِ ءَلاَيَـٰتٍ لِّقَوْمٍ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 7, 'إِنننَّ ۰لذِيــنَ لاَ يَرْجُونَ لِقَآءَنَا وَرَضُواْ بِالْحَيَوٰةِ ۱لدُّنْيۭا وَاطْمَأَنُّواْ بِهَا وَالذِينَ هُمْ عَــنَ —ايَـٰتِنَا غَـٰفِلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 8, 'ٱُوْلَئِــكَ مَأْوۭيٰهُمُ ۴لنَّارُ بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 9, 'إِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ يَهْدِيهِمْ رَبُّهُم بِإِيمَـٰنِهِمْؐ تَجْرۣى مِــن تَحْتِهِمُ ۴لاَنْهَـٰرُ فِى جَنَّـٰــتِ ۱لنَّعِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 10, 'دَعْوۭيٰهُمْ فِيهَا سُبْحَـٰنَــكَ ۰للَّهُمَّؐ وَتَحِيَّتُهُمْ فِيهَا سَچَمٌؐ وَءَاخِرُ دَعْوۭيٰهُمُ; أَنننۣ ۱لْحَمْدُ لِلهِ رَبببِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 11, '© وَلَوْ يُعَجِّــلُ ۴للَّهُ لِلنَّاسسسِ ۱لشَّرَّ "سْتِعْجَالَهُم بِالْخَيْرۣ لَقُضِيَ إِلَيْهِمُ; أَجَلُهُمْؐ فَنَذَرُ ۴لذِيــنَ لاَ يَرْجُونَ لِقَآءَنَا فِى طُغْيَـٰنِــهِــمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 12, 'وَإِذَا مَسَّ ۰لِانسَـٰــنَ ۰لضُّرُّ دَعَانَا لِجَنۢبِهِ“ أَوْ قَاعِداٗ اَوْ قَآئِماًؐ فَلَمَّا كَشَفْنَا عَنْهُ ضُرَّهُ„ مَرَّ كَأَن لَّمْ يَدْعُنَآ إِلَيٰ ضُرٍّ مَّسَّهُؐ, كَذَ؛لِــكَ زُيِّــنَ لِلْمُسْرۣفِيــنَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 13, 'وَلَقَدَ اَهْلَكْنَا ۰لْقُرُونَ مِــن قَـبْلِكُمْ لَمَّا ظَلَمُواْ 209 وَجَآءَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰــتِؐ وَمَا كَانُواْ لِيُومِنُواْؐ كَذَ؛لِــكَ نَجْزۣى ۱لْقَوْمَ ۰ڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 14, 'ثُمَّ جَعَلْنَـٰكُمْ خَلَئِفَ فِى ۱لاَرْضِ مِنۢ بَعْدِهِمْ لِنَنظُرَ كَيْفَ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 15, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَاتُنَا بَـيِّنَـٰــتٍ قَالَ ۰لذِيــنَ لاَ يَرْجُونَ لِقَآءَنَا "يــتِ بِقُرْءَانٖ غَيْرۣ هَـٰذَآ أَوْ بَدِّلْهُؐ قُــلْ مَا يَكُونُ لِــيَ أَنُ ۷بَدِّلَهُ„ مِــن تِلْقَآءِىْ نَفْسِيَؐ إِنَ اَتَّبِعُ إِلاَّ مَا يُوحۭــيٰٓ إِلَيَّؐ إِنِّــيَ أَخَافُ إِنننْ عَصَيْــتُ رَبِّى عَذَابببَ يَوْمٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 16, 'قُل لَّوْ شَآءَ ۰للَّهُ مَا تَلَوْتُهُ„ عَلَيْكُمْ وَلآَ أَدْرۭيٰكُم بِهِؐ” فَقَدْ لَبِثْــتُ فِيكُمْ عُمُراً مِّــن قَـبْلِهِؐ“ أَفَــلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 17, 'فَمَــنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباٗ اَوْ كَذَّبببَ بِـَٔايَـٰتِهِؐ“ إِنَّهُ„ لاَ يُفْلِحُ ۴ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 18, 'وَيَعْبُدُونَ مِن دُونِ ۱للَّهِ مَا لاَ يَضُرُّهُمْ وَلاَ يَنفَعُهُمْ وَيَقُولُونَ هَـٰٓؤُلآَءِ شُفَعَـٰٓؤُنَا عِندَ ۰للَّهِؐ قُلَ اَتُنَبِّـُٔونَ ۰للَّهَ بِمَا لاَ يَعْلَمُ فِى ۱لسَّمَـٰوَ؛تِ وَلاَ فِى ۱لاَرْضضضِؐ سُبْحَـٰنَهُ„ وَتَعَـٰلۭيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 19, 'وَمَا كَانَ ۰لنَّاسسسُ إِلٓاَّ ٱُمَّةً وَ؛حِدَةً فَاخْتَلَفُواْؐ وَلَوْلاَ كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ لَقُضِيَ بَيْنَهُمْ 210 فِيمَا فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 20, 'وَيَقُولُونَ لَوْلآَ ٱُنزۣلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِؐ” فَقُـلِ اِنَّمَا ۰لْغَيْــبُ لِلهِؐ فَانتَظِرُوٓاْؐ إِنِّى مَعَكُم مِّنَ ۰لْمُنتَظِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 21, 'وَإِذَآ أَذَقْنَا ۰لنَّاسَ رَحْمَةً مِّـنۢ بَعْدِ ضَرَّآءَ مَسَّتْهُمُ; إِذَا لَهُم مَّكْرٌ فِىٓ ءَايَاتِنَاؐ قُـلِ ۱للَّهُ أَسْرَعُ مَكْراٗؐ اِنَّ رُسُلَنَا يَكْتُبُونَ مَا تَمْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 22, 'هُوَ ۰ﻟ﮲ يُسَيِّرُكُمْ فِى ۱لْبَرّۣ وَاڤْبَحْرۣؐ حَتَّيٰٓ إِذَا كُنتُمْ فِى ۱لْفُلْــكِ وَجَرَيْــنَ بِهِم بِـرۣيحٍ طَيِّبَةٍ وَفَرۣحُواْ بِهَا جَآءَتْهَا رۣيح٘ عَاصِفٌ وَجَآءَهُمُ ۴لْمَوْجُ مِــن كُــلّۣ مَكَانٍ وَظَنُّوٓاْ أَنَّهُمُ; ٱُحِيطَ بِهِمْ دَعَوُاْ ۴للَّهَ مُخْلِصِيــنَ لَهُ ۴لدِّيــنَ لَـــئِـنَ اَنجَيْتَنَا مِــنْ هَـٰذِهِ” لَنَكُونَنَّ مِنَ ۰لشَّـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 23, 'فَلَمَّآ أَنجۭيٰهُمُ; إِذَا هُمْ يَبْغُونَ فِى ۱لاَرْضِ بِغَيْرۣ ۱لْحَــقّۣؐ يَـٰٓأَيُّهَا ۰لنَّاسُ إِنَّمَا بَغْيُكُمْ عَلَــيٰٓ أَنفُسِكُمؐ مَّتَـٰعُ ۴لْحَيَوٰةِ ۱لدُّنْيۭاؐ ثُمَّ إِلَيْنَا مَرْجِعُكُمْ فَنُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 24, 'إِنَّمَا مَثَــلُ ۴لْحَيَوٰةِ ۱لدُّنْيۭا كَمَآءٖ اَنزَلْنَـٰهُ مِنَ ۰لسَّمَآءِ فَاخْتَلَطَؐ بِهِ” نَبَاتُ ۴لاَرْضضضِ مِمَّا يَاكُــلُ ۴لنَّاسُ وَالاَنْعَـٰمُؐ حَتَّيٰٓ إِذَآ أَخَذَتتتِ ۱لاَرْضُ زُخْرُفَهَا وَازَّيَّنَــتْ 211 وَظَــنَّ أَهْلُهَآ أَنَّهُمْ قَـٰدِرُونَ عَلَيْهَآ أَتۭيٰهَآ أَمْرُنَا لَيْلٗا اَوْ نَهَاراً فَجَعَلْنَـٰهَا حَصِيداً كَأَن لَّمْ تَغْــنَ بِالاَمْسِؐ كَذَ؛لِــكَ نُفَصِّــلُ ۴لاَيَـٰــتِ لِقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 25, 'وَاللَّهُ يَدْعُوٓاْ إِلَيٰ دۭارۣ ۱لسَّچَمِ وَيَهْدِى مَـنْ يَّشَآءُ ﹹلَيٰ صِرَ؛طٍ مُّسْتَقِيــمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 26, '¤ لِّلذِيــنَ أَحْسَنُواْ ۴لْحُسْنۭيٰ وَزۣيَادَةٌؐ وَلاَ يَرْهَقُ وُجُوهَهُمْ قَتَرٌ وَلاَ ذِلَّة٘ؐ ۷وْلَئِــكَ أَصْحَـٰبُ ۴لْجَنَّةِؐ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 27, 'وَالذِيــنَ كَسَبُواْ ۴لسَّيِّـَٔاتتتِ جَزَآءُ سَيِّيؕةٙ بِمِثْلِهَــا وَتَرْهَقُهُمْ ذِلَّةٌ مَّا لَهُم مِّــنَ ۰للَّهِ مِــنْ عَاصِمٍ كَأَنَّمَآ ٱُغْشِيَــتْ وُجُوهُهُمْ قِطَعاً مِّــنَ ۰ليْــلۣ مُظْلِماٗؐ ۷وْلَئِــكَ أَصْحَـٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 28, 'وَيَوْمَ نَحْشُرُهُمْ جَمِيعاً ثُمَّ نَقُولُ لِلذِيــنَ أَشْرَكُواْ مَكَانَكُمُ; أَنتُمْ وَشُرَكَآؤُكُمْ فَزَيَّلْنَا بَيْنَهُمْؐ وَقَالَ شُرَكَآؤُهُم مَّا كُنتُمُ; إِيَّانَا تَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 29, 'فَكَفۭيٰ بِاللَّهِ شَهِيداَۢ بَيْنَنَا وَبَيْنَكُمُ; إِن كُنَّا عَنْ عِبَادَتِكُمْ لَغَـٰفِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 30, 'هُنَالِــكَ تَبْلُواْ كُلُّ نَفْــسٍ مَّـآ أَسْلَفَتْؐ وَرُدُّوٓاْ إِلَــي ۰للَّهِ مَوْلۭيٰهُمُ ۴لْحَقﱢّؐ وَضَــلَّ عَنْهُم مَّا كَانُواْ 212 يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 31, 'قُلْ مَنْ يَّرْزُقُكُم مِّــنَ ۰لسَّمَآءِ وَالاَرْضضضِؐ أَمَّنْ يَّمْلِــكُ ۴لسَّمْعَ وَالاَبْصَـٰرَ وَمَــنْ يُّخْرۣجُ ۴لْحَيَّ مِــنَ ۰لْمَيِّــتِ وَيُخْرۣجُ ۴لْمَيِّــتَ مِــنَ ۰لْحَيِّ وَمَـنْ يُّدَبِّرُ ۴لاَمْرَؐ فَسَيَقُولُونَ ۰للَّهُؐ فَقُـلَ اَفَلاَ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 32, 'فَذَ؛لِكُمُ ۴للَّهُ رَبُّكُمُ ۴لْحَقُّؐ فَمَاذَا بَعْدَ ۰لْحَقِّ إِلاَّ ۰لضَّچَلُؐ فَأَنّۭــيٰ تُصْرَفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 33, 'كَذَ؛لِــكَ حَقَّــتْ كَلِمَـٰــتُ رَبِّكَ عَلَي ۰لذِيــنَ فَسَقُوٓاْ أَنَّهُمْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 34, 'قُلْ هَلْ مِن شُرَكَآئِكُم مَّنْ يَّبْدَؤُاْ ۴لْخَلْقَ ثُمَّ يُعِيدُهُؐ, قُـلِ ۱للَّهُ يَبْدَؤُاْ ۴لْخَلْــقَ ثُمَّ يُعِيدُهُؐ, فَأَنّۭيٰ تُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 35, 'قُلْ هَلْ مِن شُرَكَآئِكُم مَّـنْ يَّهْدِىٓ إِلَي ۰لْحَـقﱢّؐ قُـلِ ۱للَّهُ يَهْدِى ڤِڤْحَــقّۣؐ أَفَمَـنْ يَّهْدِﻯٓ إِلَــي ۰لْحَقِّ أَحَقُّ أَنْ يُّتَّبَعَ أَمَّن لاَّ يَهَدِّځٓ إِلٓاَّ أَنْ يُّهْدۭيٰؐ فَمَا لَكُمْؐ كَيْفَ تَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 36, 'وَمَا يَتَّبِعُ أَكْثَرُهُمُ; إِلاَّ ظَنّاٗؐ اِنَّ ۰لظَّــنَّ لاَ يُغْنِى مِنَ ۰لْحَقِّ شَيْــٔاٗؐ اِنننَّ ۰للَّهَ عَلِيمٛ بِمَا يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 37, 'وَمَا كَانننَ هَـٰذَا ۰لْقُرْءَانُ أَنننْ يُّـفْتَرۭيٰ مِن دُونِ ۱للَّهِؐ وَچَكِــن تَصْدِيــقَ ۰ﻟـذِى بَيْنَ يَدَيْهِ وَتَفْصِيلَ ۰لْكِتَـٰبِ لاَ رَيْــبَ فِيهِ مِن رَّبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 38, 'أَمْ يَقُولُونَ "فْتَرۭيٰهُؐ قُلْ فَاتُواْ بِسُورَةٍ مِّثْلِهِؐ” وَادْعُواْ 21 مَـنِ ''سْتَطَعْتُم مِّن دُونِ ۱للَّهِ إِننن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 39, 'بَلْ كَذَّبُواْ بِمَا لَمْ يُحِيطُواْ بِعِلْمِهِ” وَلَمَّا يَاتِهِمْ تَاوۣيلُهُؐ, كَذَ؛لِــكَ كَذَّبببَ ۰لذِيــنَ مِـن قَبْلِهِمْؐ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 40, 'وَمِنْهُم مَّنْ يُّومِنُ بِهِ” وَمِنْهُم مَّن لاَّ يُومِنُ بِهِؐ” وَرَبُّــكَ أَعْلَمُ بِالْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 41, 'وَإِن كَذَّبُوكككَ فَقُـل لِّى عَمَلِى وَلَكُمْ عَمَلُكُمُ; أَنتُم بَرۣيٓــُٔونَ مِمَّآ أَعْمَلُ وَأَنَا بَرۣىٓءٌ مِّمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 42, 'وَمِنْهُم مَّنْ يَّسْتَمِعُونَ إِلَيْكَؐ أَفَأَنــتَ تُسْمِعُ ۴لصُّمَّ وَلَوْ كَانُواْ لاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 43, 'وَمِنْهُم مَّنْ يَّنظُرُ إِلَيْــكَؐ أَفَأَنتَ تَهْدِى ۱لْعُمْيَ وَلَوْ كَانُواْ لاَ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 44, 'إِنننَّ ۰للَّهَ لاَ يَظْلِمُ ۴لنَّاسَ شَيْـٔاًؐ وَچَكِــنَّ ۰لنَّاسسسَ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 45, 'وَيَوْمَ نَحْشُرُهُمْ كَأَن لَّمْ يَلْبَثُوٓاْ إِلاَّ سَاعَةً مِّــنَ ۰لنَّهۭارۣ يَتَعَارَفُونَ بَيْنَهُمْؐ قَدْ خَسِرَ ۰لذِيــنَ كَذَّبُواْ بِلِقَآءِ ۱للَّهِ وَمَا كَانُواْ مُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 46, 'وَإِمَّا نُرۣيَنَّــكَ بَعْضَ ۰ﻟ﮲ نَعِدُهُمُ; أَوْ نَتَوَفَّيَنَّــكَ فَإِلَيْنَا مَرْجِعُهُمْؐ ثُمَّ ۰للَّهُ شَهِيد٘ عَلَــيٰ مَا يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 47, 'وَلِكُــلّۣ ٱُمَّــةٍ رَّسُولٌؐ فَإِذَا جَآءَ رَسُولُهُمْ 214 قُضِــيَ بَــيْـنَهُم بِالْقِسْطِ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 48, 'وَيَقُولُونَ مَتۭــيٰ هَـٰذَا ۰لْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 49, '© قُــل لٓاَّ أَمْلِكُ لِنَفْسِى ضَرّاً وَلاَ نَفْعاٗ اِلاَّ مَا شَآءَ ۰للَّهُؐ لِكُــلّۣ ٱُمَّـةٖ اَجَل٘ؐ اِذَا جَآءَ اجَلُهُمْ فَلاَ يَسْتَـٰخِرُونَ سَاعَةًؐ وَلاَ يَسْتَقْدِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 50, 'قُلَ اَرَ×يْتُمُ; إِنَ اَتۭيٰكُمْ عَذَابُهُ„ بَيَـٰتاٗ اَوْ نَهَاراً مَّاذَا يَسْتَعْجِـلُ مِنْهُ ۴ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 51, 'أَثُمَّ إِذَا مَا وَقَعَ ءَامَنتُم بِهِؐ“ ءَاچَنَ وَقَدْ كُنتُم بِهِ” تَسْتَعْجِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 52, 'ثُمَّ قِيلَ لِلذِيــنَ ظَلَمُواْ ذُوقُواْ عَذَابَ ۰لْخُلْدِؐ هَلْ تُجْزَوْنَ إِلاَّ بِمَا كُنتُمْ تَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 53, 'وَيَسْتَنۢبِـُٔونَــكَ أَحَقّﹲ هُوَؐ قُلِ اِى وَرَبِّيَ إِنَّهُ„ لَحَقٌّ وَمَآ أَنتُم بِمُعْجِزۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 54, 'وَلَوَ اَنَّ لِكُلِّ نَفْــسٍ ظَلَمَتْ مَا فِى ۱لاَرْضِ لاَفْتَدَتْ بِهِؐ” وَأَسَرُّواْ ۴لنَّدَامَةَ لَمَّا رَأَوُاْ ۴لْعَذَابَ وَقُضِيَ بَيْنَهُم بِالْقِسْطِ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 55, 'أَلآَ إِنننَّ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِؐ أَلآَ إِنَّ وَعْدَ ۰للَّهِ حَقٌّؐ وَچَكِنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 56, 'هُوَ يُحْىِ” وَيُمِيــتُؐ وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 57, 'يَـٰٓأَيُّهَا ۰لنَّاسسسُ قَدْ جَآءَتْكُم مَّوْعِظَةٌ مِّن رَّبِّكُمْ 215 وَشِفَآءٌ لِّمَا فِى ۱لصُّدُورۣ وَهُديً وَرَحْمَةٌ لِّلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 58, 'قُلْ بِفَضْلِ ۱للَّهِ وَبِرَحْمَتِهِ” فَبِذَ؛لِــكَ فَلْيَفْرَحُواْؐ هُوَ خَيْرٌ مِّمَّا يَجْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 59, 'قُلَ اَرَ×يْتُم مَّآ أَنزَلَ ۰للَّهُ لَكُم مِّن رّۣزْقٍ فَجَعَلْتُم مِّنْهُ حَرَاماً وَحَچَلًؐا قُــلَ —آللَّهُ أَذِنَ لَكُمُ; أَمْ عَلَــي ۰للَّهِ تَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 60, 'وَمَا ظَــنُّ ۴لذِيــنَ يَـفْتَرُونَ عَلَــي ۰للَّهِ ۱لْكَذِبَ يَوْمَ ۰لْقِيَـٰمَةِؐ إِنننَّ ۰للَّهَ لَذُو فَضْــل۫ عَلَــي ۰لنَّاسِؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 61, 'وَمَا تَكُونُ فِى شَأْنٍ وَمَا تَتْلُواْ مِنْهُ مِن قُرْءَانٍ وَلاَ تَعْمَلُونَ مِــنْ عَمَــل۫ اِلاَّ كُنَّا عَلَيْكُمْ شُهُوداٗ اِذْ تُفِيضُونَ فِيهِؐ وَمَا يَعْزُبُ عَن رَّبِّــكَ مِــن مِّثْقَالِ ذَرَّةٍ فِى ۱لاَرْضِ وَلاَ فِى ۱لسَّمَآءِؐ وَلآَ أَصْغَرَ مِــن ذَ؛لِــكَ وَلآَ أَكْبَرَ إِلاَّ فِى كِتَـٰــبٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 62, 'اَلآَ إِنَّ أَوْلِيَآءَ ۰للَّهِ لاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 63, '۰لذِيــنَ ءَامَنُواْ وَكَانُواْ يَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 64, 'لَهُمُ ۴لْبُشْرۭيٰ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَفِى ۱لاَخِرَةِؐ لاَ تَبْدِيـلَ لِكَلِمَـٰــتِ ۱للَّهِؐ ذَ؛لِكَ هُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 65, 'وَلاَ يُحْزۣنــكَ قَوْلُهُمُؐ; إِنَّ ۰لْعِزَّةَ لِلهِ جَمِيعاٗؐ هُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 66, 'أَلآَ إِنننَّ لِلهِ 216 مَـن فِى ۱لسَّمَـٰوَ؛تتتِ وَمَـن فِى ۱لاَرْضِؐ وَمَا يَتَّبِعُ ۴لذِيــنَ يَدْعُونَ مِن دُونِ ۱للَّهِ شُرَكَآءَؐ اۭنْ يَّتَّبِعُونَ إِلاَّ ۰لظَّنَّؐ وَإِنْ هُمُ; إِلاَّ يَخْرُصُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 67, 'هُوَ ۰ﻟ﮲ جَعَــلَ لَكُمُ ۴ليْـلَ لِتَسْكُنُواْ فِيهِ وَالنَّهَارَ مُبْصِراٗؐ اِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 68, 'قَالُواْ èتَّخَذَ ۰للَّهُ وَلَداًؐ سُبْحَـٰنَهُؐ, هُوَ ۰لْغَنِيُّؐ لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ إِنْ عِندَكُم مِّــن سُلْطَـٰــنٙ بِهَـٰذَآؐ أَتَقُولُونَ عَلَــي ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 69, 'قُـلِ اِنَّ ۰لذِينَ يَفْتَرُونَ عَلَــي ۰للَّهِ ۱لْكَذِبببَ لاَ يُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 70, 'مَتَـٰعٌ فِى ۱لدُّنْيۭاؐ ثُمَّ إِلَيْنَا مَرْجِعُهُمْ ثُمَّ نُذِيقُهُمُ ۴لْعَذَابببَ ۰لشَّدِيدَ بِمَا كَانُواْ يَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 71, '¥ وَاتْــلُ عَلَيْهِمْ نَبَأَ نُوحٖ اِذْ قَالَ لِقَوْمِهِ” يَـٰقَوْمِ إِننن كَانَ كَبُرَ عَلَيْكُم مَّقَامِى وَتَذْكِيرۣى بِـَٔايَـٰــتِ ۱للَّهِ فَعَلَــي ۰للَّهِ تَوَكَّلْــتُؐ فَأَجْمِعُوٓاْ أَمْرَكُمْ وَشُرَكَآءَكُمْؐ ثُمَّ لاَ يَكُــنَ اَمْرُكُمْ عَلَيْكُمْ غُمَّةًؐ ثُمَّ "قْضُوٓاْ إِلَيَّ وَلاَ تُنظِرُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 72, 'فَإِن تَوَلَّيْتُمْ فَمَا سَأَلْتُكُم مِّنَ اَجْرٖؐ اِنَ اَجْرۣيَ إِلاَّ عَلَــي ۰للَّهِؐ وَٱُمِرْتتتُ أَنَ اَكُونَ مِــنَ ۰لْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 73, 'فَكَذَّبُوهُ فَنَجَّيْنَـٰهُ وَمَــن مَّعَهُ„ فِى ۱لْفُلْكِ 217 وَجَعَلْنَـٰهُمْ خَلَئِفَؐ وَأَغْرَقْنَا ۰لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَــاؐ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لْمُنذَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 74, 'ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِ” رُسُلٗا اِلَيٰ قَوْمِهِمْ فَجَآءُوهُم بِالْبَيِّنَـٰــتِ فَمَا كَانُواْ لِيُومِنُواْ بِمَا كَذَّبُواْ بِهِ” مِــن قَبْــلُؐ كَذَ؛لِــكَ نَطْبَعُ عَلَيٰ قُلُوبِ ۱لْمُعْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 75, 'ثُمَّ بَعَثْنَا مِـنۢ بَعْدِهِم مُّوسۭيٰ وَهَـٰرُونَ إِلَيٰ فِرْعَوْنَ وَمَلْاَئِهِ” بِـَٔايَـٰتِنَا فَاسْتَكْبَرُواْ وَكَانُواْ قَوْماً مُّجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 76, 'فَلَمَّا جَآءَهُمُ ۴لْحَـقُّ مِـنْ عِندِنَا قَالُوٓاْ إِنننَّ هَـٰذَا ڤَسِحْرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 77, 'قَالَ مُوسۭــيٰٓ أَتَقُولُونَ ڤِڤْحَــقّۣ لَمَّا جَآءَكُمُؐ; أَسِحْر٘ هَـٰذَاؐ وَلاَ يُفْلِحُ ۴ڤسَّـٰحِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 78, 'قَالُوٓاْ أَجِيؔتَنَا لِتَلْفِتَنَا عَمَّا وَجَدْنَا عَلَيْهِ ءَابَآءَنَا وَتَكُونَ لَكُمَا ۰لْكِبْرۣيَآءُ فِى ۱لاَرْضِ وَمَا نَحْــنُ لَكُمَا بِمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 79, 'وَقَالَ فِرْعَوْنُ èيتُونِى بِكُلِّ سَـٰحِر۫ عَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 80, 'فَلَمَّا جَآءَ ۰ڤسَّحَرَةُ قَالَ لَهُم مُّوسۭيٰٓ أَلْقُواْ مَآ أَنتُم مُّلْقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 81, 'فَلَمَّآ أَلْقَوْاْ قَالَ مُوسۭــيٰ مَا جِيؔتُم بِهِ ۱ڤسِّحْرُؐ إِنننَّ ۰للَّهَ سَيُبْطِلُهُؐ; إِنننَّ ۰للَّهَ لاَ يُصْلِحُ عَمَــلَ ۰لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 82, 'وَيُحِــقُّ ۴للَّهُ ۴لْحَـقَّ بِكَلِمَـٰتِهِ” وَلَوْ كَرۣهَ ۰ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 83, '218  فَمَآ ءَامَــنَ لِمُوسۭــيٰٓ إِلاَّ ذُرّۣيَّةٌ مِّن قَوْمِهِ” عَلَــيٰ خَوْفٍ مِّن فِرْعَوْنَ وَمَلْاَئِهِمُ; أَنْ يَّـفْتِنَهُمْؐ وَإِنَّ فِرْعَوْنَ لَعَالٍ فِى ۱لاَرْضِؐ وَإِنَّهُ„ لَمِــنَ ۰لْمُسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 84, 'وَقَالَ مُوسۭــيٰ يَـٰقَوْمِ إِننن كُنتُمُ; ءَامَنتُم بِاللَّهِ فَعَلَيْهِ تَوَكَّلُوٓاْ إِننن كُنتُم مُّسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 85, 'فَقَالُواْ عَلَــي ۰للَّهِ تَوَكَّلْنَاؐ رَبَّنَا لاَ تَجْعَلْنَا فِتْنَةً لِّلْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 86, 'وَنَجِّنَا بِرَحْمَتِــكَ مِــنَ ۰لْقَوْمِ ۱لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 87, 'وَأَوْحَيْنَآ إِلَيٰ مُوسۭيٰ وَأَخِيهِ أَن تَبَوَّءَا لِقَوْمِكُمَا بِمِصْرَ بُيُوتاً وَاجْعَلُواْ بُيُوتَكُمْ قِبْلَةً وَأَقِيمُواْ ۴لصَّلَوٰةَؐ وَبَشِّرۣ ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 88, 'وَقَالَ مُوسۭيٰ رَبَّنَآ إِنَّــكَ ءَاتَيْــتَ فِرْعَوْنَ وَمَلَأَهُ„ زۣينَةً وَأَمْوَ؛لًا فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ رَبَّنَا لِيَضِلُّواْ عَــن سَبِيلِــكَؐ رَبَّنَا "طْمِــسْ عَلَيٰٓ أَمْوَ؛لِهِمْ وَاشْدُدْ عَلَيٰ قُلُوبِهِمْ فَلاَ يُومِنُواْ حَتَّيٰ يَرَوُاْ ۴لْعَذَابببَ ۰لاَلِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 89, 'قَالَ قَدُ ۷جِيبَــت دَّعْوَتُكُمَا فَاسْتَقِيمَاؐ وَلاَ تَتَّبِعَـٰٓــنّۣ سَبِيلَ ۰لذِينَ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 90, 'وَجَـٰوَزْنَا بِبَنِىٓ إِسْرَآءِيــلَ ۰ڤْبَحْرَ فَأَتْبَعَهُمْ فِرْعَوْنُ وَجُنُودُهُ„ بَغْياً وَعَدْواٗؐ حَتَّيٰٓ إِذَآ أَدْرَكَهُ ۴لْغَرَقُ قَالَ ءَامَنــتُ أَنَّهُ„ لآَ إِچَهَ إِلاَّ ۰ﻟـذِىٓ ءَامَنَــتْ بِهِ” بَنُوٓاْ إِسْرَآءِيـلَ 219 وَأَنَا مِــنَ ۰لْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 91, 'ءَاچَنَ وَقَدْ عَصَيْــتَ قَبْلُ وَكُنــتَ مِــنَ ۰لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 92, 'فَالْيَوْمَ نُنَجِّيــكَ بِبَدَنِكَ لِتَكُونَ لِمَنْ خَلْفَــكَ ءَايَةًؐ وَإِنَّ كَثِيراً مِّــنَ ۰لنَّاسسسِ عَنَ —ايَـٰتِنَا لَغَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 93, '© وَلَقَدْ بَوَّأْنَا بَنِىٓ إِسْرَآءِيلَ مُبَوَّأَ صِدْقٍ وَرَزَقْنَـٰهُم مِّــنَ ۰لطَّيِّبَـٰــتِ فَمَا "خْتَلَفُواْ حَتَّــيٰ جَآءَهُمُ ۴لْعِلْمُؐ إِنَّ رَبَّكَ يَقْضِى بَيْنَهُمْ يَوْمَ ۰لْقِيَـٰمَةِ فِيمَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 94, 'فَإِن كُنــتَ فِى شَــكٍّ مِّمَّآ أَنزَلْنَآ إِلَيْــكَ فَسْـَٔلِ ۱لـذِينَ يَقْرَءُونَ ۰لْكِتَـٰــبَ مِــن قَـبْلِــكَؐ لَقَدْ جَآءَكككَ ۰لْحَـقُّ مِـن رَّبِّــكَؐ فَلاَ تَكُونَنَّ مِــنَ ۰لْمُمْتَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 95, 'وَلاَ تَكُونَــنَّ مِـنَ ۰لذِيــنَ كَذَّبُواْ بِـَٔايَـٰــتِ ۱للَّهِ فَتَكُونَ مِــنَ ۰لْخَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 96, 'إِنَّ ۰لذِيــنَ حَقَّــتْ عَلَيْهِمْ كَلِمَـٰــتُ رَبِّــكَ لاَ يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 97, 'وَلَوْ جَآءَتْهُمْ كُــلُّ ءَايَةٖ حَتَّيٰ يَرَوُاْ ۴لْعَذَابببَ ۰لاَلِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 98, 'فَلَوْلاَ كَانَــتْ قَرْيَة٘ —امَنَــتْ فَنَفَعَهَآ إِيمَـٰنُهَآ إِلاَّ قَوْمَ يُونُــسَ لَمَّآ ءَامَنُواْ كَشَفْنَا عَنْهُمْ عَذَابَ ۰لْخِزْيِ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَمَتَّعْنَـٰهُمُ; إِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 99, 'وَلَوْ شَآءَ رَبُّــكَ ءَلاَمَــنَ مَـن فِى ۱لاَرْضضضِ كُلُّهُمْ جَمِيعاٗؐ 220 اَفَأَنــتَ تُكْرۣهُ ۴لنَّاسسسَ حَتَّيٰ يَكُونُواْ مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 100, 'وَمَا كَانَ لِنَفْسٖ اَن تُومِنَ إِلاَّ بِإِذْنِ ۱للَّهِؐ وَيَجْعَلُ ۴لرّۣجْــسَ عَلَي ۰لذِينَ لاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 101, 'قُــلُ ۶نظُرُواْ مَاذَا فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضِ وَمَا تُغْنِى ۱لاَيَـٰــتُ وَالنُّذُرُ عَن قَوْمٍ لاَّ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 102, 'فَهَلْ يَنتَظِرُونَ إِلاَّ مِثْـلَ أَيَّامِ ۱لذِيــنَ خَلَوْاْ مِــن قَبْلِهِمْؐ قُلْ فَانتَظِرُوٓاْؐ إِنِّى مَعَكُم مِّــنَ ۰لْمُنتَظِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 103, 'ثُمَّ نُـنَجّىِ رُسُلَنَا وَالذِيــنَ ءَامَنُواْ كَذَ؛لِــكَؐ حَقّاٗ عَلَيْنَا نُنَجِّ ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 104, 'قُـلْ يَـٰٓأَيُّهَا ۰لنَّاسُ إِن كُنتُمْ فِى شَكٍّ مِّن دِينِى فَلآَ أَعْبُدُ ۴لذِيــنَ تَعْبُدُونَ مِن دُونِ ۱للَّهِؐ وَچَكِــنَ اَعْبُدُ ۴للَّهَ ۰ﻟ﮲ يَتَوَفّۭيٰكُمْؐ وَٱُمِرْتتتُ أَنَ اَكُونَ مِــنَ ۰لْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 105, 'وَأَنَ اَقِمْ وَجْهَــكَ لِلدِّيــنۣ حَنِيفاًؐ وَلاَ تَكُونَــنَّ مِـنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 106, 'وَلاَ تَدْعُ مِن دُونِ ۱للَّهِ مَا لاَ يَنفَعُــكَ وَلاَ يَضُرُّكككَؐ فَإِن فَعَلْــتَ فَإِنَّــكَ إِذاً مِّــنَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 107, 'وَإِنننْ يَّـمْسَسْــكَ ۰للَّهُ بِضُرٍّ فَلاَ كَاشِفَ لَهُ; إِلاَّ هُوَؐ وَإِنْ يُّرۣدْكككَ بِخَيْرٍ فَلاَ رَآدَّ لِفَضْلِهِؐ” يُصِيبُ بِهِ” مَنْ يَّشَآءُ مِنْ عِبَادِهِؐ” وَهُوَ 221 ۰لْغَفُورُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 108, 'قُلْ يَـٰٓأَيُّهَا ۰لنَّاسسسُ قَدْ جَآءَكُمُ ۴لْحَقُّ مِن رَّبِّكُمْؐ فَمَـنِ ''هْتَدۭيٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِؐ” وَمَــن ضَــلَّ فَإِنَّمَا يَضِــلُّ عَلَيْهَاؐ وَمَآ أَنَا عَلَيْكُم بِوَكِيلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (10, 109, 'وَاتَّبِعْ مَا يُوحۭيٰٓ إِلَيْــكَ وَاصْبِرْ حَتَّــيٰ يَحْكُمَ ۰للَّهُؐ وَهُوَ خَيْرُ ۴لْحَـٰكِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓرۭؐ كِتَـٰــب٘ ۷حْكِمَتَ —ايَـٰتُهُ„ ثُمَّ فُصِّلَــتْ مِــن لَّدُنْ حَكِيمٖ خَبِير۫');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 2, 'اَلاَّ تَعْبُدُوٓاْ إِلاَّ ۰للَّهَ إِنَّنِى لَكُم مِّنْهُ نَذِيرٌ وَبَشِيرٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 3, 'وَأَنِ ''سْتَغْفِرُواْ رَبَّكُمْ ثُمَّ تُوبُوٓاْ إِلَيْهِ يُمَتِّعْكُم مَّتَـٰعاٗ حَسَناٗ اِلَـيٰٓ أَجَــلٍ مُّسَمّيً وَيُوتِ كُلَّ ذى فَضْــلٍ فَضْلَهُؐ, وَإِن تَوَلَّوْاْ فَإِنِّــيَ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ كَبِيرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 4, 'اِلَــي ۰للَّهِ مَرْجِعُكُمْؐ وَهُوَ عَلَيٰ كُــلّۣ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 5, 'اَلآَ إِنَّهُمْ يَثْنُونَ صُدُورَهُمْ ڤِيَسْتَخْفُواْ مِنْهُؐ أَلاَ حِينَ يَسْتَغْشُونَ ثِيَابَهُمْ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَؐ إِنَّهُ„ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 6, '222 ¤ وَمَا مِــن دَآبَّةٍ فِى ۱لاَرْضِ إِلاَّ عَلَــي ۰للَّهِ رۣزْقُهَا وَيَعْلَمُ مُسْتَقَرَّهَا وَمُسْتَوْدَعَهَاؐ كُــلٌّ فِى كِتَـٰــبٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 7, 'وَهُوَ ۰ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضَ فِى سِتَّةِ أَيَّامٍ وَكَانَ عَرْشُهُ„ عَلَــي ۰لْمَآءِ لِيَبْلُوَكُمُ; أَيُّكُمُ; أَحْسَــنُ عَمَلًؐا وَلَـئِـــن قُلْــتَ إِنَّكُم مَّبْعُوثُونَ مِـنۢ بَعْدِ ۱لْمَوْتتتِ لَيَقُولَــنَّ ۰لذِيــنَ كَفَرُوٓاْ إِنْ هَـٰذَآ إِلاَّ سِحْـرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 8, 'وَلَـئِـــنَ اَخَّرْنَا عَنْهُمُ ۴لْعَذَابببَ إِلَــيٰٓ ٱُمَّةٍ مَّعْدُودَةٍ لَّيَقُولُــنَّ مَا يَحْبِسُهُؐ’ أَلاَ يَوْمَ يَاتِيهِمْ لَيْــسَ مَصْرُوفاٗ عَنْهُمْؐ وَحَاقَ بِهِم مَّا كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 9, 'وَلَـئِــنَ اَذَقْنَا ۰لِانسَـٰــنَ مِنَّا رَحْمَةً ثُمَّ نَزَعْنَـٰهَا مِنْهُ إِنَّهُ„ لَيَـُٔوسسسٌ كَفُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 10, 'وَلَـئِـــنَ اَذَقْنَـٰهُ نَعْمَآءَ بَعْدَ ضَرَّآءَ مَسَّتْهُ لَيَقُولَــنَّ ذَهَــبَ ۰لسَّيِّـَٔاتتتُ عَنِّــيَؐ إِنَّهُ„ لَفَرۣحٌ فَخُور٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 11, 'اِلاَّ ۰لذِيــنَ صَبَرُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ ٱُوْلَئِــكَ لَهُم مَّغْفِرَةٌ وَأَجْرٌ كَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 12, 'فَلَعَلَّــكَ تَارۣكككٛ بَعْــضَ مَا يُوحۭيٰٓ إِلَيْكَ وَضَآئِقٛ بِهِ” صَدْرُكككَ أَنْ يَّقُولُواْ لَوْلآَ ٱُنزۣلَ عَلَيْهِ كَنز٘ اَوْ جَآءَ مَعَهُ„ مَلَــك٘ؐ اِنَّمَآ أَنــتَ نَذِيرٌؐ وَ اللَّهُ عَلَــيٰ كُــلّۣ شَيْءٍ 22 وَكِيل٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 13, 'اَمْ يَقُولُونَ "فْتَرۭيٰهُؐ قُـلْ فَاتُواْ بِعَشْرۣ سُوَرٍ مِّثْلِهِ” مُفْتَرَيَـٰــتٍ وَادْعُواْ مَنِ ''سْتَطَعْتُم مِّن دُونِ ۱للَّهِ إِننن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 14, 'فَإِلَّمْ يَسْتَجِيبُواْ لَكُمْ فَاعْلَمُوٓاْ أَنَّمَآ ٱُنزۣلَ بِعِلْمِ ۱للَّهِ وَأَن لٓاَّ إِچَهَ إِلاَّ هُوَؐ فَهَــلَ اَنتُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 15, 'مَــن كَانَ يُرۣيدُ ۴لْحَيَوٰةَ ۰لدُّنْيۭا وَزۣينَتَهَا نُوَفِّ إِلَيْهِمُ; أَعْمَـٰلَهُمْ فِيهَا وَهُمْ فِيهَا لاَ يُبْخَسُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 16, 'ٱُوْلَئِــكَ ۰لذِينَ لَيْــسَ لَهُمْ فِى ۱لاَخِرَةِ إِلاَّ ۰لنَّارُؐ وَحَبِطَ مَا صَنَعُواْ فِيهَاؐ وَبَـٰطِــلٌ مَّا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 17, 'أَفَمَــن كَانَ عَلَيٰ بَيِّنَةٍ مِّن رَّبِّهِ” وَيَتْلُوهُ شَاهِدٌ مِّنْهُؐ وَمِــن قَبْلِهِ” كِتَـٰــبُ مُوسۭيٰٓ إِمَاماً وَرَحْمَةٗؐ ۷وْلَئِــكَ يُومِنُونَ بِهِؐ” وَمَنْ يَّكْفُرْ بِهِ” مِــنَ ۰لاَحْزَابببِ فَالنَّارُ مَوْعِدُهُؐ, فَلاَ تَكُ فِى مِرْيَةٍ مِّنْهُؐ إِنَّهُ ۴لْحَـقُّ مِـن رَّبِّكَؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 18, 'وَمَــنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباٗؐ ۷وْلَئِــكَ يُعْرَضُونَ عَلَيٰ رَبِّهِمْ وَيَقُولُ ۴لاَشْهَـٰدُ هَـٰٓؤُلآَءِ ۱لذِيــنَ كَذَبُواْ عَلَيٰ رَبِّهِمُؐ; أَلاَ لَعْنَةُ ۴للَّهِ عَلَــي ۰لظَّـٰلِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 19, '۰لذِيــنَ يَصُدُّونَ عَــن سَبِيـلِ ۱للَّهِ 224 وَيَبْغُونَهَا عِوَجاً وَهُم بِالاَخِرَةِ هُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 20, 'ٱُوْلَئِــكَ لَمْ يَكُونُواْ مُعْجِزۣيــنَ فِى ۱لاَرْضِ وَمَا كَانَ لَهُم مِّن دُونِ ۱للَّهِ مِنَ اَوْلِيَآءَؐ يُضَـٰعَفُ لَهُمُ ۴لْعَذَابببُؐ مَا كَانُواْ يَسْتَطِيعُونَ ۰لسَّمْعَ وَمَا كَانُواْ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 21, 'ٱُوْلَئِكَ ۰لذِيــنَ خَسِرُوٓاْ أَنفُسَهُمْ وَضَــلَّ عَنْهُم مَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 22, 'لاَ جَرَمَ أَنَّهُمْ فِى ۱لاَخِرَةِ هُمُ ۴لاَخْسَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 23, 'إِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ وَأَخْبَتُوٓاْ إِلَيٰ رَبِّهِمُ; ٱُوْلَئِــكَ أَصْحَـٰــبُ ۴لْجَنَّةِؐ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 24, '© مَثَلُ ۴لْفَرۣيقَيْــنۣ كَالاَعْمۭيٰ وَالاَصَمِّ وَالْبَصِيرۣ وَالسَّمِيعِؐ هَلْ يَسْتَوۣيَـٰــنۣ مَثَلٗؐا اَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 25, 'وَلَقَدَ اَرْسَلْنَا نُوحاٗ اِلَيٰ قَوْمِهِؐ“ إِنِّى لَكُمْ نَذِيرٌ مُّبِين٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 26, 'اَن لاَّ تَعْبُدُوٓاْ إِلاَّ ۰للَّهَؐ إِنِّــيَ أَخَافُ عَلَيْكُمْ عَذَابببَ يَوْمٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 27, 'فَقَالَ ۰لْمَلُءَ ۴لذِيــنَ كَفَرُواْ مِن قَوْمِهِ” مَا نَرۭيٰكَ إِلاَّ بَشَراً مِّثْلَنَا وَمَا نَرۭيٰكَ "تَّبَعَكَ إِلاَّ ۰لذِينَ هُمُ; أَرَاذِلُنَا بَادِيَ ۰لرَّأْيِؐ وَمَا نَرۭيٰ لَكُمْ عَلَيْنَا مِـن فَضْلٙ بَلْ نَظُنُّكُمْ كَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 28, '225 قَالَ يَـٰقَوْمِ أَرَ×يْتُمُ; إِن كُنتُ عَلَيٰ بَيِّنَةٍ مِّن رَّبِّى وَءَاتۭيٰنِى رَحْمَةً مِّـنْ عِندِهِ” فَعَمِيَــتْ عَلَيْكُمُ; أَنُلْزۣمُكُمُوهَــا وَأَنتُمْ لَهَــا كَـٰرۣهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 29, 'وَيَـٰقَوْمِ لآَ أَسْــَٔلُكُمْ عَلَيْهِ مَالٗؐا اِنَ اَجْرۣيَ إِلاَّ عَلَــي ۰للَّهِؐ وَمَآ أَنَا بِطَارۣدِ ۱لذِيــنَ ءَامَنُوٓاْ إِنَّهُم مُّچَقُواْ رَبِّهِمْؐ وَچَكِنِّيَ أَرۭيٰكُمْ قَوْماً تَجْهَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 30, 'وَيَـٰقَوْمِ مَنْ يَّنصُرُنِى مِــنَ ۰للَّهِ إِن طَرَدتُّهُمُؐ; أَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 31, 'وَلآَ أَقُولُ لَكُمْ عِندِى خَزَآئِـــنُ ۴للَّهِ وَلآَ أَعْلَمُ ۴لْغَيْــبَ وَلآَ أَقُولُ إِنِّى مَلَــكٌؐ وَلآَ أَقُولُ لِلذِينَ تَزْدَرۣىٓ أَعْيُنُكُمْ لَنْ يُّوتِيَهُمُ ۴للَّهُ خَيْراٗؐ ۱للَّهُ أَعْلَمُ بِمَا فِىٓ أَنفُسِهِمُؐ; إِنِّيَ إِذاً لَّمِــنَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 32, 'قَالُواْ يَـٰنُوحُ قَدْ جَـٰدَلْتَنَا فَأَكْثَرْتتتَ جِدَ؛لَنَا فَاتِنَا بِمَا تَعِدُنَآ إِن كُنــتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 33, 'قَالَ إِنَّمَا يَاتِيكُم بِهِ ۱للَّهُ إِن شَآءَ وَمَآ أَنتُم بِمُعْجِزۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 34, 'وَلاَ يَنفَعُكُمْ نُصْحِيَ إِنَ اَرَدتتتُّ أَنَ اَنصَحَ لَكُمُ; إِن كَانننَ ۰للَّهُ يُرۣيدُ أَنْ يُّغْوۣيَكُمْؐ هُوَ رَبُّكُمْؐ وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 35, 'أَمْ يَقُولُونَ "فْتَرۭيٰهُؐ قُلِ اِنِ ''فْتَرَيْتُهُ„ فَعَلَيَّ إِجْرَامِى وَأَنَا بَرۣىٓءٌ مِّمَّا تُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 36, '226 وَٱُوحِيَ إِلَيٰ نُوحٖ اَنَّهُ„ لَنْ يُّومِــنَ مِـن قَوْمِــكَ إِلاَّ مَــن قَدَ —امَنَؐ فَلاَ تَبْتَئِسْ بِمَا كَانُواْ يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 37, 'وَاصْنَعِ ۱لْفُلْكَ بِأَعْيُنِنَا وَوَحْيِنَاؐ وَلاَ تُخَــٰـطِـبْـنِى فِى ۱لذِيــنَ ظَلَمُوٓاْ إِنَّهُم مُّغْرَقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 38, 'وَيَصْنَعُ ۴لْفُلْــكَ وَكُلَّمَا مَرَّ عَلَيْهِ مَلٌءَ مِّن قَوْمِهِ” سَخِرُواْ مِنْهُؐ قَالَ إِن تَسْخَرُواْ مِنَّا فَإِنَّا نَسْخَرُ مِنكُمْ كَمَا تَسْخَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 39, 'فَسَوْفَ تَعْلَمُونَ مَـنْ يَّاتِيهِ عَذَابببٌ يُخْزۣيهِ وَيَحِلُّ عَلَيْهِ عَذَابببٌ مُّقِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 40, 'حَتَّيٰٓ إِذَا جَآءَ امْرُنَا وَفَارَ ۰لتَّنُّورُ قُلْنَا "حْمِـلْ فِيهَا مِــن كُلِّ زَوْجَيْـنِ ''ثْنَيْنِ وَأَهْلَــكَ إِلاَّ مَن سَبَقَ عَلَيْهِ ۱لْقَوْلُ وَمَــنَ —امَنَؐ وَمَآ ءَامَنَ مَعَهُ; إِلاَّ قَلِيــلٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 41, '¥ وَقَالَ "رْكَبُواْ فِيهَا بِسْمِ ۱للَّهِ مُجْرۭيٰهَا وَمُرْسۭيٰهَآؐ إِنَّ رَبِّى لَغَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 42, 'وَهِيَ تَجْرۣى بِهِمْ فِى مَوْجٍ كَالْجِبَالِؐ وَنَادۭيٰ نُوح٘ ''بْنَهُ„ وَكَانَ فِى مَعْزۣلٍ يَـٰبُنَيِّ ''رْكَــبْ مَعَنَا وَلاَ تَكُن مَّعَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 43, 'قَالَ سَـَٔاوۣىٓ إِلَــيٰ جَبَــلٍ يَعْصِمُنِى مِــنَ ۰لْمَآءِؐ قَالَ لاَ عَـٰصِمَ ۰لْيَوْمَ مِنَ اَمْرۣ ۱للَّهِ إِلاَّ مَن رَّحِمَؐ وَحَالَ بَيْنَهُمَا ۰لْمَوْجُ فَكَانَ مِــنَ ۰لْمُغْرَقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 44, 'وَقِيلَ يَـٰٓأَرْضُ 227 èبْلَعِى مَآءَكككِ وَيَـٰسَمَآءُ اَ۬قْلِعِىؐ وَغِيــضَ ۰لْمَآءُ وَقُضِــيَ ۰لاَمْرُ وَاسْتَوَتتتْ عَلَي ۰لْجُودِيﱢّؐ وَقِيـلَ بُعْداً لِّلْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 45, 'وَنَادۭيٰ نُوحٌ رَّبَّهُ„ فَقَالَ رَبببِّ إِنَّ "بْنِى مِنَ اَهْلِى وَإِنَّ وَعْدَكَ ۰لْحَقُّؐ وَأَنــتَ أَحْكَمُ ۴لْحَـٰكِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 46, 'قَالَ يَـٰنُوحُ إِنَّهُ„ لَيْسَ مِــنَ اَهْلِــكَؐ إِنَّهُ„ عَمَــل٘ غَيْرُ صَـٰلِحٍؐ فَلاَ تَسْـَٔلَـــنّۣ” مَا لَيْــسَ لَكَ بِهِ” عِلْم٘ؐ اِنِّيَ أَعِظُــكَ أَن تَكُونَ مِــنَ ۰لْجَـٰهِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 47, 'قَالَ رَبِّ إِنِّيَ أَعُوذُ بِــكَ أَنننَ اَسْـَٔلَــكَ مَا لَيْسَ لِى بِهِ” عِلْمٌؐ وَإِلاَّ تَغْفِرْ لِى وَتَرْحَمْنِىٓ أَكُن مِّنَ ۰لْخَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 48, 'قِيـلَ يَـٰنُوحُ èهْبِطْ بِسَچَمٍ مِّنَّا وَبَرَكَـٰــتٖ عَلَيْــكَ وَعَلَــيٰٓ ٱُمَمٍ مِّمَّــن مَّعَــكَؐ وَٱُمَمٌ سَنُمَتِّعُهُمْ ثُمَّ يَمَسُّهُم مِّنَّا عَذَاببب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 49, 'تِلْــكَ مِــنَ اَنۢبَآءِ ۱لْغَيْبِ نُوحِيهَآ إِلَيْــكَؐ مَا كُنــتَ تَعْلَمُهَآ أَنــتَ وَلاَ قَوْمُــكَ مِــن قَبْلِ هَـٰذَاؐ فَاصْبِـرۣؐ اِنَّ ۰لْعَـٰقِبَةَ لِلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 50, 'وَإِلَــيٰ عَادٖ اَخَاهُمْ هُوداًؐ قَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ; إِنَ اَنتُمُ; إِلاَّ مُفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 51, 'يَـٰقَوْمِ لآَ أَسْـَٔلُكُمْ عَلَيْهِ أَجْراٗؐ اِنَ اَجْرۣيَ إِلاَّ عَلَي ۰ﻟ﮲ فَطَرَنِيَؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 52, '228 وَيَـٰقَوْمِ ''سْتَغْفِرُواْ رَبَّكُمْ ثُمَّ تُوبُوٓاْ إِلَيْهِ يُرْسِـلِ ۱لسَّمَآءَ عَلَيْكُم مِّدْرَاراً وَيَزۣدْكُمْ قُوَّةٗ اِلَيٰ قُوَّتِكُمْ وَلاَ تَتَوَلَّوْاْ مُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 53, 'قَالُواْ يَـٰهُودُ مَا جِيؔتَنَا بِبَيِّنَةٍ وَمَا نَحْنُ بِتَارۣكِىٓ ءَالِهَتِنَا عَن قَوْلِــكَ وَمَا نَحْــنُ لَــكَ بِمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 54, 'إِن نَّقُولُ إِلاَّ "عْتَرۭيٰكَ بَعْــضُ ءَالِهَتِنَا بِسُوٓءٍؐ قَالَ إِنِّــيَ ٱُشْهِدُ ۴للَّهَؐ وَاشْهَدُوٓاْ أَنِّى بَرۣىٓءٌ مِّمَّا تُشْرۣكُونَ مِن دُونِهِؐ” فَكِيدُونِى جَمِيعاً ثُمَّ لاَ تُنظِرُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 55, 'إِنِّى تَوَكَّلْــتُ عَلَــي ۰للَّهِ رَبِّى وَرَبِّكُمؐ مَّا مِن دَآبَّةٖ اِلاَّ هُوَ ءَاخِذٛ بِنَاصِيَتِهَآؐ إِنَّ رَبِّى عَلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 56, 'فَإِن تَوَلَّوْاْ فَقَدَ اَبْلَغْتُكُم مَّآ ٱُرْسِلْــتُ بِهِ“ إِلَيْكُمْؐ وَيَسْتَخْلِفُ رَبِّى قَوْماٗ غَيْرَكُمْ وَلاَ تَضُرُّونَهُ„ شَيْـٔاٗؐ اِنَّ رَبِّى عَلَــيٰ كُــلّۣ شَيْءٖ حَفِيظٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 57, 'وَلَمَّا جَآءَ امْرُنَا نَجَّيْنَا هُوداً وَالذِيــنَ ءَامَنُواْ مَعَهُ„ بِرَحْمَةٍ مِّنَّا وَنَجَّيْنَـٰهُم مِّنْ عَذَابببٖ غَلِيظٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 58, 'وَتِلْــكَ عَادٌ جَحَدُواْ بِـَٔايَـٰــتِ رَبِّهِمْ وَعَصَوْاْ رُسُلَهُ„ وَاتَّبَعُوٓاْ أَمْرَ كُلِّ جَبّۭار۫ عَنِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 59, 'وَٱُتْبِعُواْ فِى هَـٰذِهِ ۱لدُّنْيۭا لَعْنَةً وَيَوْمَ ۰لْقِيَـٰمَةِؐ أَلآَ إِنننَّ عَاداً كَفَرُواْ 229 رَبَّهُمُؐ; أَلاَ بُعْداً لِّعَادٍ قَوْمِ هُودٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 60, 'وَإِلَــيٰ ثَمُودَ أَخَاهُمْ صَـٰڤِحاًؐ قَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ, هُوَ أَنشَأَكُم مِّــنَ ۰لاَرْضِ وَاسْتَعْمَرَكُمْ فِيهَا فَاسْتَغْفِرُوهُ ثُمَّ تُوبُوٓاْ إِلَيْهِؐ إِنَّ رَبِّى قَرۣيــبٌ مُّجِيــبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 61, '© قَالُواْ يَـٰصَـٰلِحُ قَدْ كُنــتَ فِينَا مَرْجُوّاً قَبْــلَ هَـٰذَآ أَتَنْهۭيٰنَآ أَن نَّعْبُدَ مَا يَعْبُدُ ءَابَآؤُنَا وَإِنَّنَا لَفِى شَــكٍّ مِّمَّا تَدْعُونَآ إِلَيْهِ مُرۣيبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 62, 'قَالَ يَـٰقَوْمِ أَرَ×يْتُمُ; إِن كُنتُ عَلَيٰ بَيِّنَةٍ مِّن رَّبِّى وَءَاتۭيٰنِى مِنْهُ رَحْمَةً فَمَـنْ يَّنصُرُنِى مِــنَ ۰للَّهِ إِنننْ عَصَيْتُهُؐ, فَمَا تَزۣيدُونَنِى غَيْرَ تَخْسِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 63, 'وَيَـٰقَوْمِ هَـٰذِهِ” نَاقَةُ ۴للَّهِ لَكُمُ; ءَايَةًؐ فَذَرُوهَا تَاكُـلْ فِىٓ أَرْضضضِ ۱للَّهِؐ وَلاَ تَمَسُّوهَا بِسُوٓءٍ فَيَاخُذَكُمْ عَذَابببٌ قَرۣيــبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 64, 'فَعَقَرُوهَا فَقَالَ تَمَتَّعُواْ فِى دۭارۣكُمْ ثَـچَثَةَ أَيَّامٍؐ ذَ؛لِــكَ وَعْد٘ غَيْرُ مَكْذُوبببٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 65, 'فَلَمَّا جَآءَ امْرُنَا نَجَّيْنَا صَـٰڤِحاً وَالذِيــنَ ءَامَنُواْ مَعَهُ„ بِرَحْمَةٍ مِّنَّا وَمِنْ خِزْيِ يَوْمَئِذٖؐ اِنَّ رَبَّــكَ هُوَ ۰لْقَوۣيُّ ۴لْعَزۣيزُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 66, 'وَأَخَذَ ۰لذِيــــنَ ظَلَمُـواْ ۴ڤصَّيْحَةُ فَأَصْبَحُواْ فِى 20 دِيۭـٰرۣهِمْ جَـٰثِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 67, 'كَأَن لَّمْ يَغْنَوْاْ فِيهَآؐ أَلآَ إِنننَّ ثَمُوداً كَفَرُواْ رَبَّهُمُؐ; أَلاَ بُعْداً لِّثَمُودَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 68, 'وَلَقَدْ جَآءَتْ رُسُلُنَآ إِبْرَ؛هِيمَ بِالْبُشْرۭيٰ قَالُواْ سَچَماًؐ قَالَ سَچَمٌؐ فَمَا لَبِــثَ أَن جَآءَ بِعِجْلٖ حَنِيذٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 69, 'فَلَمَّا رۭءۭآ أَيْدِيَهُمْ لاَ تَصِـلُ إِلَيْهِ نَكِرَهُمْ وَأَوْجَـسَ مِنْهُمْ خِيفَةًؐ قَالُواْ لاَ تَخَـفِؐ اِنَّـآ ٱُرْسِلْنَآ إِلَيٰ قَوْمِ لُوطٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 70, 'وَامْرَأَتُهُ„ قَآئِمَةٌ فَضَحِكَــتْؐ فَبَشَّرْنَـٰهَا بِإِسْحَـٰقَؐ وَمِنْ وَّرَآءِ اسْحَـٰقَ يَعْقُوبببُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 71, 'قَالَتْ يَـٰوَيْلَتۭــيٰٓ ءَالِدُ وَأَنَا عَجُوزٌ وَهَـٰذَا بَعْلِى شَيْخاٗؐ اِنَّ هَـٰذَا لَشَىْء٘ عَجِيبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 72, 'قَالُوٓاْ أَتَعْجَبِيــنَ مِـنَ اَمْرۣ ۱للَّهِؐ رَحْمَــتُ ۴للَّهِ وَبَرَكَـٰتُهُ„ عَلَيْكُمُ; أَهْلَ ۰لْبَيْــتِؐ إِنَّهُ„ حَمِيدٌ مَّجِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 73, 'فَلَمَّا ذَهَبَ عَـنِ اِبْرَ؛هِيمَ ۰لرَّوْعُ وَجَآءَتْهُ ۴لْبُشْرۭيٰ يُجَـٰدِلُنَا فِى قَوْمِ لُوطٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 74, 'اِنَّ إِبْرَ؛هِيمَ لَحَلِيم٘ اَوَّ؛هٌ مُّنِيــبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 75, 'يَـٰٓإِبْرَ؛هِيمُ أَعْرۣضضضْ عَنْ هَـٰذَآؐ إِنَّهُ„ قَدْ جَآءَ امْرُ رَبِّــكَؐ وَإِنَّهُمُ; ءَاتِيهِمْ عَذَاب٘ غَيْرُ مَرْدُودٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 76, 'وَلَمَّا جَآءَتتتْ رُسُلُنَا لُوطاً سـ۬ـىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعاً وَقَالَ هَـٰذَا يَوْم٘ عَصِيــبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 77, '21 وَجَآءَهُ„ قَوْمُهُ„ يُهْرَعُونَ إِلَيْهِ وَمِــن قَبْلُ كَانُواْ يَعْمَلُونَ ۰لسَّيِّـَٔاتتتِؐ قَالَ يَـٰقَوْمِ هَـٰٓؤُلآَءِ بَنَاتِى هُــنَّ أَطْهَرُ لَكُمْ فَاتَّقُواْ ۴للَّهَ وَلاَ تُخْزُونِ فِى ضَيْفِيَؐ أَلَيْـسَ مِنكُمْ رَجُلٌ رَّشِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 78, 'قَالُواْ لَقَدْ عَلِمْــتَ مَا لَنَا فِى بَنَاتِــكَ مِنْ حَقٍّ وَإِنَّــكَ لَتَعْلَمُ مَا نُرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 79, 'قَالَ لَوَ اَنَّ لِى بِكُمْ قُوَّةٗ اَوَ —اوۣىٓ إِلَيٰ رُكْــنٍ شَدِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 80, 'قَالُواْ يَـٰلُوطُ إِنَّا رُسُلُ رَبِّــكَ لَـنْ يَّصِلُوٓاْ إِلَيْــكَؐ فَاسْرۣ بِأَهْلِــكَ بِقِطْعٍ مِّــنَ ۰ليْلِ وَلاَ يَلْتَفِــتْ مِنكُمُ; أَحَد٘ اِلاَّ "مْرَأَتَكَؐ إِنَّهُ„ مُصِيبُهَا مَآ أَصَابَهُمُؐ; إِنَّ مَوْعِدَهُمُ ۴لصُّبْحُؐ أَلَيْسَ ۰لصُّبْحُ بِقَرۣيــبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 81, 'فَلَمَّا جَآءَ امْرُنَا جَعَلْنَا عَـٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهَا حِجَارَةً مِّــن سِجِّيــلٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 82, 'مَّنضُودٍ مُّسَوَّمَةٗ عِندَ رَبِّــكَؐ وَمَا هِيَ مِــنَ ۰لظَّـٰلِمِينَ بِبَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 83, '¤ وَإِلَــيٰ مَدْيَنَ أَخَاهُمْ شُعَيْباًؐ قَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ, وَلاَ تَنقُصُواْ ۴لْمِكْيَالَ وَالْمِيزَانَؐ إِنِّيَ أَرۭيٰكُم بِخَيْرٍ وَإِنِّــيَ أَخَافُ عَلَيْكُمْ عَذَابببَ يَوْمٍ مُّحِيطٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 84, 'وَيَـٰقَوْمِ أَوْفُواْ ۴لْمِكْيَالَ وَالْمِيزَانَ بِالْقِسْطِؐ وَلاَ تَبْخَسُواْ ۴لنَّاسَ 22 أَشْيَآءَهُمْ وَلاَ تَعْثَوْاْ فِى ۱لاَرْضضضِ مُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 85, 'بَقِيَّــتُ ۴للَّهِ خَيْرٌ لَّكُمُ; إِننن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 86, 'وَمَآ أَنَا عَلَيْكُم بِحَفِيظٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 87, 'قَالُواْ يَـٰشُعَيْــبُ أَصَلَوَ؛تُــكَ تَامُرُكَ أَن نَّتْرُكَ مَا يَعْبُدُ ءَابَآؤُنَآ أَوَ اَن نَّفْعَـلَ فِىٓ أَمْوَ؛لِنَا مَا نَشَـٰٓؤُاْؐ اِ۬نَّــكَ لَأَنــتَ ۰لْحَلِيمُ ۴لرَّشِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 88, 'قَالَ يَـٰقَوْمِ أَرَ×يْتُمُ; إِن كُنــتُ عَلَيٰ بَيِّنَةٍ مِّن رَّبِّى وَرَزَقَنِى مِنْهُ رۣزْقاٗ حَسَناًؐ وَمَآ ٱُرۣيدُ أَنُ ۷خَالِفَكُمُ; إِلَيٰ مَآ أَنْهۭيٰكُمْ عَنْهُؐ إِنُ ۷رۣيدُ إِلاَّ ۰لِاصْڦَحَ مَا "سْتَطَعْــتُؐ وَمَا تَوْفِيقِيَ إِلاَّ بِاللَّهِؐ عَلَيْهِ تَوَكَّلْــتُؐ وَإِلَيْهِ ٱُنِيبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 89, 'وَيَـٰقَوْمِ لاَ يَجْرۣمَنَّكُمْ شِقَاقِيَ أَنْ يُّصِيبَكُم مِّثْــلُ مَآ أَصَابببَ قَوْمَ نُوحٖ اَوْ قَوْمَ هُودٖ اَوْ قَوْمَ صَـٰلِحٍؐ وَمَا قَوْمُ لُوطٍ مِّنكُم بِبَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 90, 'وَاسْتَغْفِرُواْ رَبَّكُمْ ثُمَّ تُوبُوٓاْ إِلَيْهِؐ إِنَّ رَبِّى رَحِيمٌ وَدُودٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 91, 'قَالُواْ يَـٰشُعَيْبُ مَا نَفْقَهُ كَثِيراً مِّمَّا تَقُولُ وَإِنَّا لَنَرۭيٰــكَ فِينَا ضَعِيفاً وَلَوْلاَ رَهْطُــكَ لَرَجَمْنَـٰــكَ وَمَآ أَنــتَ عَلَيْنَا بِعَزۣيزٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 92, 'قَالَ يَـٰقَوْمِ أَرَهْطِيَ أَعَزُّ عَلَيْكُم مِّــنَ ۰للَّهِ وَاتَّخَذتُّمُوهُ وَرَآءَكُمْ ظِهْرۣيّاٗؐ 2 اِنَّ رَبِّى بِمَا تَعْمَلُونَ مُحِيطٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 93, 'وَيَـٰقَوْمِ ''عْمَلُواْ عَلَيٰ مَكَانَتِكُمُ; إِنِّى عَـٰمِلٌؐ سَوْفَ تَعْلَمُونَ مَـنْ يَّاتِيهِ عَذَابٌ يُخْزۣيهِ وَمَنْ هُوَ كَـٰذِبببٌؐ وَارْتَقِبُوٓاْؐ إِنِّى مَعَكُمْ رَقِيــبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 94, 'وَلَمَّا جَآءَ امْرُنَا نَجَّيْنَا شُعَيْباً وَالذِيــنَ ءَامَنُواْ مَعَهُ„ بِرَحْمَةٍ مِّنَّاؐ وَأَخَذَتتتِ ۱لذِيــنَ ظَلَمُواْ ۴ڤصَّيْحَةُ فَأَصْبَحُواْ فِى دِيۭـٰرۣهِمْ جَـٰثِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 95, 'كَأَن لَّمْ يَغْنَوْاْ فِيهَآؐ أَلاَ بُعْداً لِّمَدْيَنَ كَمَا بَعِدَتتتْ ثَمُودُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 96, 'وَلَقَدَ اَرْسَلْنَا مُوسۭيٰ بِـَٔايَـٰتِنَا وَسُلْطَـٰنٍ مُّبِينٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 97, 'اِلَيٰ فِرْعَوْنَ وَمَلْاَئِهِ” فَاتَّبَعُوٓاْ أَمْرَ فِرْعَوْنَؐ وَمَآ أَمْرُ فِرْعَوْنَ بِرَشِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 98, 'يَقْدُمُ قَوْمَهُ„ يَوْمَ ۰لْقِيَـٰمَةِ فَأَوْرَدَهُمُ ۴لنَّارَؐ وَبِيسَ ۰لْوۣرْدُ ۴لْمَوْرُودُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 99, 'وَٱُتْبِعُواْ فِى هَـٰذِهِ” لَعْنَةً وَيَوْمَ ۰لْقِيَـٰمَةِؐ بِيسَ ۰لرّۣفْدُ ۴لْمَرْفُودُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 100, 'ذَ؛لِــكَ مِــنَ اَنۢبَآءِ ۱لْقُرۭيٰ نَقُصُّهُ„ عَلَيْــكَ مِنْهَا قَآئِمٌ وَحَصِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 101, 'وَمَا ظَلَمْنَـٰهُمْ وَچَكِــن ظَلَمُوٓاْ أَنفُسَهُمْؐ فَمَآ أَغْنَــتْ عَنْهُمُ; ءَالِهَتُهُمُ ۴لتِى يَدْعُونَ مِن دُونِ ۱للَّهِ مِن شَيْءٍ لَّمَّا جَآءَ امْرُ رَبِّــكَؐ وَمَا زَادُوهُمْ غَيْرَ تَتْبِيــبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 102, 'وَكَذَ؛لِــكَ 24 أَخْذُ رَبِّــكَ إِذَآ أَخَذَ ۰لْقُرۭيٰ وَهِــيَ ظَالِمَة٘ؐ اِنَّ أَخْذَهُ; أَلِيمٌ شَدِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 103, 'اِنَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّمَــنْ خَافَ عَذَابببَ ۰لاَخِرَةِؐ ذَ؛لِــكَ يَوْمٌ مَّجْمُوعٌ لَّهُ ۴لنَّاسُؐ وَذَ؛لِــكَ يَوْمٌ مَّشْهُودٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 104, 'وَمَا نُوَ۬خِّرُهُ; إِلاَّ لَأِجَــلٍ مَّعْدُودٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 105, '© يَوْمَ يَاتِ” لاَ تَكَلَّمُ نَفْـس٘ اِلاَّ بِإِذْنِهِؐ” فَمِنْهُمْ شَقِيٌّ وَسَعِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 106, 'فَأَمَّا ۰لذِينَ شَقُواْ فَفِى ۱لنّۭارۣ لَهُمْ فِيهَا زَفِيرٌ وَشَهِيق٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 107, 'خَـٰلِدِينَ فِيهَا مَا دَامَــتِ ۱لسَّمَـٰوَ؛تتتُ وَالاَرْضُ إِلاَّ مَا شَآءَ رَبُّــكَؐ إِنَّ رَبَّكَ فَعَّالٌ لِّمَا يُرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 108, 'وَأَمَّا ۰لذِيــنَ سَعِدُواْ فَفِى ۱لْجَنَّةِ خَـٰلِدِينَ فِيهَا مَا دَامَــتِ ۱لسَّمَـٰوَ؛تتتُ وَالاَرْضُ إِلاَّ مَا شَآءَ رَبُّكَؐ عَطَآءٗ غَيْرَ مَجْذُوذٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 109, 'فَلاَ تَكُ فِى مِرْيَةٍ مِّمَّا يَعْبُدُ هَـٰٓؤُلآَءِؐ مَا يَعْبُدُونَ إِلاَّ كَمَا يَعْبُدُ ءَابَآؤُهُم مِّــن قَبْلُؐ وَإِنَّا لَمُوَفُّوهُمْ نَصِيبَهُمْ غَيْرَ مَنقُوصٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 110, 'وَلَقَدَ —اتَيْنَا مُوسَــي ۰لْكِتَـٰــبَ فَاخْتُلِفَ فِيهِؐ وَلَوْلاَ كَلِمَةٌ سَبَقَــتْ مِن رَّبِّــكَ لَقُضِــيَ بَيْنَهُمْؐ وَإِنَّهُمْ لَفِى شَــكٍّ مِّنْهُ مُرۣيــبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 111, 'وَإِن كُلًاّ لَّمَا لَيُوَفِّيَنَّهُمْ رَبُّــكَ أَعْمَـٰلَهُمُؐ; إِنَّهُ„ بِمَا يَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 112, '25 فَاسْتَقِمْ كَمَآ ٱُمِرْتتتَ وَمَــن تَابببَ مَعَــكَ وَلاَ تَطْغَوۣاْؐ اِنَّهُ„ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 113, 'وَلاَ تَرْكَنُوٓاْ إِلَــي ۰لذِيــنَ ظَلَمُواْ فَتَمَسَّكُمُ ۴لنَّارُؐ وَمَا لَكُم مِّن دُونِ ۱للَّهِ مِنَ اَوْلِيَآءَؐ ثُمَّ لاَ تُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 114, 'وَأَقِمِ ۱لصَّلَوٰةَ طَرَفَــيۣ ۱لنَّهۭارۣ وَزُلَفاً مِّنَ ۰ليْلِؐ إِنَّ ۰لْحَسَنَـٰــتِ يُذْهِبْــنَ ۰لسَّيِّـَٔاتِؐ ذَ؛لِــكَ ذِكْرۭيٰ لِلذَّ؛كِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 115, 'وَاصْبِرْؐ فَإِنننَّ ۰للَّهَ لاَ يُضِيعُ أَجْرَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 116, 'فَلَوْلاَ كَانَ مِــنَ ۰لْقُرُونِ مِــن قَبْلِكُمُ; ٱُوْلُواْ بَقِيَّةٍ يَنْهَوْنَ عَـنِ ۱لْفَسَادِ فِى ۱لاَرْضضضِ إِلاَّ قَلِيلًا مِّمَّــنَ اَنجَيْنَا مِنْهُمْؐ وَاتَّبَعَ ۰لذِينَ ظَلَمُواْ مَآ ٱُتْرۣفُواْ فِيهِ وَكَانُواْ مُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 117, 'وَمَا كَانَ رَبُّــكَ لِيُهْلِــكَ ۰لْقُرۭيٰ بِظُلْمٍ وَأَهْلُهَا مُصْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 118, 'وَلَوْ شَآءَ رَبُّكَ لَجَعَــلَ ۰لنَّاسسسَ ٱُمَّةً وَ؛حِدَةًؐ وَلاَ يَزَالُونَ مُخْتَلِفِينَ إِلاَّ مَن رَّحِمَ رَبُّــكَؐ وَلِذَ؛لِكَ خَلَقَهُمْؐ وَتَمَّــتْ كَلِمَةُ رَبِّكَ لَأَمْلَأَنَّ جَهَنَّمَ مِــنَ ۰لْجِنَّةِ وَالنَّاسسسِ أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 119, 'وَكُلًاّ نَّقُــصُّ عَلَيْــكَ مِــنَ اَنۢبَآءِ ۱لرُّسُــلۣ مَا نُثَبِّتُ بِهِ” فُؤَادَكَؐ وَجَآءَكككَ فِى هَـٰذِهِ ۱لْحَقُّ وَمَوْعِظَةٌ وَذِكْرۭيٰ لِلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 120, 'وَقُل لِّلذِيــنَ لاَ يُومِنُونَ 26 "عْمَلُواْ عَلَــيٰ مَكَانَتِكُمُ; إِنَّا عَـٰمِلُونَ وَانتَظِرُوٓاْ إِنَّا مُنتَظِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (11, 121, 'وَلِلهِ غَيْــبُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضِؐ وَإِلَيْهِ يُرْجَعُ ۴لاَمْرُ كُلُّهُؐ„ فَاعْبُدْهُ وَتَوَكَّــلْ عَلَيْهِؐ وَمَا رَبُّكَ بِغَـٰفِــل۫ عَمَّا تَعْمَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓرۭؐ تِلْكَ ءَايَـٰــتُ ۴لْكِتَـٰــبِ ۱لْمُبِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 2, 'إِنَّآ أَنزَلْنَـٰهُ قُرْءَ؛ناٗ عَرَبِيّاً لَّعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 3, 'نَحْنُ نَقُــصُّ عَلَيْكَ أَحْسَــنَ ۰لْقَصَـصِ بِمَآ أَوْحَيْنَآ إِلَيْكَ هَـٰذَا ۰لْقُرْءَانَ وَإِن كُنــتَ مِــن قَبْلِهِ” لَمِــنَ ۰لْغَـٰفِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 4, 'إِذْ قَالَ يُوسُفُ لَأِبِيهِ يَـٰٓأَبَــتِ إِنِّى رَأَيْــتُ أَحَدَ عَشَرَ كَوْكَباً وَالشَّمْسَ وَالْقَمَرَؐ رَأَيْتُهُمْ لِى سَـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 5, 'قَالَ يَـٰبُنَيِّ لاَ تَقْصُصْ رُءْيۭاكَ عَلَــيٰٓ إِخْوَتِــكَ فَيَكِيدُواْ لَكَ كَيْداٗؐ اِنننَّ ۰لشَّيْطَـٰنَ لِلِانسَـٰــنۣ عَدُوٌّ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 6, 'وَكَذَ؛لِــكَ يَجْتَبِيــكَ رَبُّــكَ وَيُعَلِّمُكَ مِــن تَاوۣيـلِ ۱لاَحَادِيــثِؐ وَيُتِمُّ نِعْمَتَهُ„ عَلَيْــكَ وَعَلَــيٰٓ ءَالِ يَعْقُوبببَ كَمَآ أَتَمَّهَا عَلَيٰٓ أَبَوَيْكَ مِــن قَبْلُ إِبْرَ؛هِيمَ وَإِسْحَـٰقَؐ إِنَّ رَبَّكَ 27 عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 7, 'لَّقَدْ كَانَ فِى يُوسُفَ وَإِخْوَتِهِ“ ءَايَـٰــتٌ لِّلسَّآئِـلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 8, 'إِذْ قَالُواْ لَيُوسُفُ وَأَخُوهُ أَحَــبُّ إِلَـيٰٓ أَبِينَا مِنَّا وَنَحْــنُ عُصْبَة٘ؐ اِنَّ أَبَانَا لَفِى ضَچَلٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 9, '۶قْتُلُواْ يُوسُفَ أَوۣ ''طْرَحُوهُ أَرْضاً يَخْــلُ لَكُمْ وَجْهُ أَبِيكُمْ وَتَكُونُواْ مِـنۢ بَعْدِهِ” قَوْماً صَـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 10, '¥ قَالَ قَآئِــلٌ مِّنْهُمْ لاَ تَقْتُلُواْ يُوسُفَ وَأَلْقُوهُ فِى غَيَـٰبَـٰــتِ ۱لْجُــبِّ يَلْتَقِطْهُ بَعْــضُ ۴لسَّيَّارَةِ إِن كُنتُمْ فَـٰعِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 11, 'قَالُواْ يَـٰٓأَبَانَا مَا لَــكَ لاَ تَاﯫ عَلَيٰ يُوسُفَ وَإِنَّا لَهُ„ ڤَنَـٰصِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 12, 'أَرْسِلْهُ مَعَنَا غَداً يَرْتَعِ وَيَلْعَــبْ وَإِنَّا لَهُ„ لَحَـٰفِظُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 13, 'قَالَ إِنِّى ڤَيُحْزۣنُنِيَ أَن تَذْهَبُواْ بِهِ” وَأَخَافُ أَنْ يَّاكُلَهُ ۴لذِّيــبُ وَأَنتُمْ عَنْهُ غَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 14, 'قَالُواْ لَـئِـــنَ اَكَلَهُ ۴لذِّيــبُ وَنَحْــنُ عُصْبَة٘ اِنَّآ إِذاً لَّخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 15, 'فَلَمَّا ذَهَبُواْ بِهِ” وَأَجْمَعُوٓاْ أَنننْ يَّجْعَلُوهُ فِى غَيَـٰبَـٰــتِ ۱لْجُــبِّ وَأَوْحَيْنَآ إِلَيْهِ لَتُنَبِّيؕنَّهُم بِأَمْرۣهِمْ هَـٰذَا وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 16, 'وَجَآءُوٓ أَبَاهُمْ عِشَآءً يَبْكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 17, 'قَالُواْ يَـٰٓأَبَانَآ إِنَّا ذَهَبْنَا نَسْتَبِقُ وَتَرَكْنَا يُوسُفَ عِندَ مَتَـٰعِنَا 28 فَأَكَلَهُ ۴لذِّيــبُؐ وَمَآ أَنتَ بِمُومِــنٍ لَّنَا وَلَوْ كُنَّا صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 18, 'وَجَآءُو عَلَيٰ قَمِيصِهِ” بِدَمٍ كَذِبٍؐ قَالَ بَلْ سَوَّلَــتْ لَكُمُ; أَنفُسُكُمُ; أَمْراًؐ فَصَبْرٌ جَمِيلٌؐ وَاللَّهُ ۴لْمُسْتَعَانُ عَلَــيٰ مَا تَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 19, 'وَجَآءَتْ سَيَّارَةٌ فَأَرْسَلُواْ وَارۣدَهُمْ فَأَدْلۭيٰ دَلْوَهُ„ قَالَ يَـٰبُشْرۭ؛يَ هَـٰذَا غُچَمٌؐ وَأَسَرُّوهُ بِضَـٰعَةًؐ وَاللَّهُ عَلِيمٛ بِمَا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 20, 'وَشَرَوْهُ بِثَمَــنٙ بَخْسٍ دَرَ؛هِمَ مَعْدُودَةٍ وَكَانُواْ فِيهِ مِنَ ۰لزَّ؛هِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 21, 'وَقَالَ ۰ﻟ﮲ ''شْتَرۭيٰهُ مِــن مِّصْرَ لِامْرَأَتِهِ“ أَكْرۣمِى مَثْوۭيٰهُ عَسۭيٰٓ أَنْ يَّنفَعَنَآ أَوْ نَتَّخِذَهُ„ وَلَداًؐ وَكَذَ؛لِــكَ مَكَّنَّا لِيُوسُفَ فِى ۱لاَرْضِ وَلِنُعَلِّمَهُ„ مِن تَاوۣيلِ ۱لاَحَادِيــثِؐ وَاللَّهُ غَالِــب٘ عَلَيٰٓ أَمْرۣهِؐ” وَچَكِــنَّ أَكْثَرَ ۰لنَّاسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 22, 'وَلَمَّا بَلَغَ أَشُدَّهُ; ءَاتَيْنَـٰهُ حُكْماً وَعِلْماًؐ وَكَذَ؛لِــكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 23, 'وَرَ؛وَدَتْهُ ۴لتِى هُوَ فِى بَيْتِهَا عَــن نَّفْسِهِ” وَغَلَّقَــتِ ۱لاَبْوَ؛بببَ وَقَالَتْ هِيتَ لَــكَؐ قَالَ مَعَاذَ ۰للَّهِؐ إِنَّهُ„ رَبِّــيَ أَحْسَــنَ مَثْوۭايَؐ إِنَّهُ„ لاَ يُفْلِحُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 24, 'وَلَقَدْ هَمَّــتْ بِهِؐ” وَهَمَّ بِهَا لَوْلآَ أَن رّۭءۭا بُرْهَـٰنَ رَبِّهِؐ” كَذَ؛لِــكَ 29 لِنَصْرۣفَ عَنْهُ ۴لسُّوٓءَ وَاڤْفَحْشَآءَؐ اۭنَّهُ„ مِـنْ عِبَادِنَا ۰ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 25, 'وَاسْتَبَقَا ۰لْبَابببَ وَقَدَّتتتْ قَمِيصَهُ„ مِن دُبُرٍ وَأَلْفَيَا سَيِّدَهَا لَدَا ۰لْبَابببِؐ قَالَــتْ مَا جَزَآءُ مَنَ اَرَادَ بِأَهْلِكَ سُوٓءاٗ اِلٓاَّ أَنْ يُّسْجَنَ أَوْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 26, 'قَالَ هِيَ رَ؛وَدَتْنِى عَن نَّفْسِىؐ وَشَهِدَ شَاهِدٌ مِّــنَ اَهْلِهَآ إِننن كَانَ قَمِيصُهُ„ قُدَّ مِن قُبُلٍ فَصَدَقَــتْ وَهُوَ مِــنَ ۰لْكَـٰذِبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 27, 'وَإِننن كَانَ قَمِيصُهُ„ قُدَّ مِن دُبُرٍ فَكَذَبَــتْؐ وَهُوَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 28, 'فَلَمَّا رۭءۭا قَمِيصَهُ„ قُدَّ مِن دُبُرٍ قَالَ إِنَّهُ„ مِــن كَيْدِكُنَّ إِنَّ كَيْدَكُنَّ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 29, 'يُوسُفُ أَعْرۣضضضْ عَنْ هَـٰذَاؐ وَاسْتَغْفِـرۣى لِذَنۢبِــكِ إِنَّــكِ كُنــتِ مِــنَ ۰لْخَاطِـِٕينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 30, 'وَقَالَ نِسْوَةٌ فِى ۱لْمَدِينَةِ ''مْرَأَتتتُ ۴لْعَزۣيزۣ تُرَ؛وۣدُ فَتۭيٰهَا عَــن نَّفْسِهِ” قَدْ شَغَفَهَا حُبّاٗؐ اِنَّا لَنَرۭيٰهَا فِى ضَچَـلٍ مُّبِـينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 31, 'فَلَمَّا سَمِعَــتْ بِمَكْرۣهِنَّ أَرْسَلَتِ اِلَيْهِنَّ وَأَعْتَدَتْ لَهُــنَّ مُتَّكَـٔاً وَءَاتَــتْ كُلَّ وَ؛حِدَةٍ مِّنْهُنَّ سِكِّيناً وَقَالَتُ ۶خْرُجْ عَلَيْهِـنَّؐ فَلَمَّا رَأَيْنَهُ; أَكْبَرْنَهُ„ وَقَطَّعْنَ أَيْدِيَهُنَّ وَقُلْــنَ حَـٰشَ لِلهِ مَا هَـٰذَا بَشَراٗؐ اِنْ هَـٰذَآ 240 إِلاَّ مَلَــكٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 32, 'قَالَــتْ فَذَ؛لِكُنَّ ۰ﻟ﮲ لُمْتُنَّنِى فِيهِؐ وَلَقَدْ رَ؛وَدتُّهُ„ عَــن نَّفْسِهِ” فَاسْتَعْصَمَؐ وَلَئِن لَّمْ يَفْعَــلْ مَآ ءَامُرُهُ„ ڤَيُسْجَنَنَّ وَلَيَكُوناً مِّــنَ ۰لصَّـٰغِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 33, '© قَالَ رَبِّ ۱لسِّجْنُ أَحَبُّ إِلَــيَّ مِمَّا يَدْعُونَنِىٓ إِلَيْهِ وَإِلاَّ تَصْرۣفْ عَنِّى كَيْدَهُنَّ أَصْبُ إِلَيْهِنَّ وَأَكُــن مِّنَ ۰لْجَـٰهِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 34, 'فَاسْتَجَابَ لَهُ„ رَبُّهُ„ فَصَرَفَ عَنْهُ كَيْدَهُنَّؐ إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 35, 'ثُمَّ بَدَا لَهُم مِّـنۢ بَعْدِ مَا رَأَوُاْ ۴لاَيَـٰــتِ ڤَيَسْجُنُنَّهُ„ حَتَّــيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 36, 'وَدَخَــلَ مَعَهُ ۴لسِّجْــنَ فَتَيَـٰــنۣؐ قَالَ أَحَدُهُمَآ إِنِّيَ أَرۭيٰنِــيَ أَعْصِرُ خَمْراًؐ وَقَالَ ۰لاَخَرُ إِنِّيَ أَرۭيٰنِــيَ أَحْمِلُ فَوْقَ رَأْسِى خُبْزاً تَاكُلُ ۴لطَّيْرُ مِنْهُؐ نَبِّيؔنَا بِتَاوۣيلِهِ“ إِنَّا نَرۭيٰــكَ مِــنَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 37, 'قَالَ لاَ يَاتِيكُمَا طَعَامٌ تُرْزَقَـٰنِهِ“ إِلاَّ نَبَّأْتُكُمَا بِتَاوۣيلِهِ” قَبْلَ أَنْ يَّاتِيَكُمَاؐ ذَ؛لِكُمَا مِمَّا عَلَّمَنِى رَبِّيَؐ إِنِّى تَرَكْــتُ مِلَّةَ قَوْمٍ لاَّ يُومِنُونَ بِاللَّهِ وَهُم بِالاَخِرَةِ هُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 38, 'وَاتَّبَعْــتُ مِلَّةَ ءَابَآءِيَ إِبْرَ؛هِيمَ وَإِسْحَـٰقَ وَيَعْقُوبببَؐ مَا كَانَ لَنَآ أَن نُّشْرۣكككَ بِاللَّهِ مِن شَيْءٍؐ ذَ؛لِــكَ مِـن فَضْـلِ ۱للَّهِ عَلَيْنَا وَعَلَي 241 ۰لنَّاسِؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 39, 'يَـٰصَـٰحِبَيِ ۱ڤسِّجْــنۣ ءَآرْبَابٌ مُّتَفَرّۣقُونَ خَيْر٘ اَمِ ۱للَّهُ ۴لْوَ؛حِدُ ۴لْقَهَّارُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 40, 'مَا تَعْبُدُونَ مِن دُونِهِ“ إِلٓاَّ أَسْمَآءً سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ۰للَّهُ بِهَا مِــن سُلْطَـٰنٖؐ اِنِ ۱لْحُكْمُ إِلاَّ لِلهِؐ أَمَرَ أَلاَّ تَعْبُدُوٓاْ إِلٓاَّ إِيَّاهُؐ ذَ؛لِكَ ۰لدِّيــنُ ۴لْقَيِّمُؐ وَچَكِنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 41, 'يَـٰصَـٰحِبَــيۣ ۱لسِّجْـنِ أَمَّــآ أَحَدُكُمَا فَيَسْقِى رَبَّهُ„ خَمْراًؐ وَأَمَّا ۰لاَخَرُ فَيُصْلَــبُ فَتَاكُلُ ۴لطَّيْرُ مِن رَّأْسِهِؐ” قُضِــيَ ۰لاَمْرُ ۴ﻟ﮲ فِيهِ تَسْتَفْتِيَـٰنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 42, 'وَقَالَ لِلذِى ظَــنَّ أَنَّهُ„ نَاجٍ مِّنْهُمَا ۸ذْكُرْنِى عِندَ رَبِّكَؐ فَأَنسۭيٰهُ ۴لشَّيْطَـٰنُ ذِكْرَ رَبِّهِ” فَلَبِــثَ فِى ۱لسِّجْنِ بِضْعَ سِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 43, 'وَقَالَ ۰لْمَلِــكُ إِنِّيَ أَرۭيٰ سَبْعَ بَقَرَ؛تتتٍ سِمَانٍ يَاكُلُهُــنَّ سَبْع٘ عِجَافٌ وَسَبْعَ سُنۢبُچَــتٖ خُضْرٍ وَٱُخَرَ يَابِسَـٰــتٍؐ يَـٰٓأَيُّهَا ۰لْمَلُءَ اَ۬فْتُونِى فِى رُءْيۭـٰيَ إِن كُنتُمْ لِلرُّءْيۭا تَعْبُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 44, 'قَالُوٓاْ أَضْغَـٰثُ أَحْچَمٍؐ وَمَا نَحْـنُ بِتَاوۣيـلِ ۱لاَحْچَمِ بِعَـٰلِمِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 45, 'وَقَالَ ۰ﻟ﮲ نَجَا مِنْهُمَا وَادَّكَرَ بَعْدَ ٱُمَّةٖ اَنَآ ٱُنَبِّيؖكُم 242 بِتَاوۣيلِهِ” فَأَرْسِلُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 46, 'يُوسُفُ أَيُّهَا ۰لصِّدِّيقُ أَفْتِنَا فِى سَبْعِ بَقَرَ؛تتتٍ سِمَانٍ يَاكُلُهُــنَّ سَبْع٘ عِجَافٌ وَسَبْعِ سُنۢبُچَــتٖ خُضْرٍ وَٱُخَرَ يَابِسَـٰــتٍ لَّعَلِّيَ أَرْجِعُ إِلَــي ۰لنَّاسسسِ لَعَلَّهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 47, 'قَالَ تَزْرَعُونَ سَبْعَ سِنِيــنَ دَأْباًؐ فَمَا حَصَدتُّمْ فَذَرُوهُ فِى سُنۢبُلِهِ“ إِلاَّ قَلِيلًا مِّمَّا تَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 48, 'ثُمَّ يَاتِى مِـنۢ بَعْدِ ذَ؛لِــكَ سَبْعٌ شِدَادٌ يَاكُلْــنَ مَا قَدَّمْتُمْ لَهُــنَّ إِلاَّ قَلِيلًا مِّمَّا تُحْصِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 49, 'ثُمَّ يَاتِى مِـنۢ بَعْدِ ذَ؛لِــكَ عَامٌ فِيهِ يُغَاثُ ۴لنَّاسُ وَفِيهِ يَعْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 50, 'وَقَالَ ۰لْمَلِــكُ èيتُونِى بِهِؐ” فَلَمَّا جَآءَهُ ۴لرَّسُولُ قَالَ "رْجِعِ اِلَيٰ رَبِّــكَ فَسْـَٔلْهُ مَا بَالُ ۴لنِّسْوَةِ ۱لــتِى قَطَّعْنَ أَيْدِيَهُنَّؐ إِنَّ رَبِّى بِكَيْدِهِــنَّ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 51, 'قَالَ مَا خَطْبُكُــنَّ إِذْ رَ؛وَدتُّنَّ يُوسُفَ عَــن نَّفْسِهِؐ” قُلْــنَ حَـٰشَ لِلهِ مَا عَلِمْنَا عَلَيْهِ مِن سُوٓءٍؐ قَالَــتِ ''مْرَأَتتتُ ۴لْعَزۣيزۣ ۱چَـــنَ حَصْحَصَ ۰لْحَــقُّ أَنَا رَ؛وَدتُّهُ„ عَن نَّفْسِهِ” وَإِنَّهُ„ لَمِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 52, 'ذَ؛لِــكَ لِيَعْلَمَ أَنِّى لَمَ اَخُنْهُ بِالْغَيْبِ وَأَنَّ ۰للَّهَ لاَ يَهْدِى كَيْدَ ۰لْخَآئِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 53, '¤ وَمَآ ٱُبَرّۣىُٔ نَفْسِيَؐ إِنَّ ۰لنَّفْــسَ لَأَمَّارَةٛ بِالسُّوٓءِ 24 الاَّ مَا رَحِمَ رَبِّيَؐ إِنَّ رَبِّى غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 54, 'وَقَالَ ۰لْمَلِــكُ èيتُونِى بِهِ“ أَسْتَخْلِصْهُ لِنَفْسِىؐ فَلَمَّا كَلَّمَهُ„ قَالَ إِنَّــكَ ۰لْيَوْمَ لَدَيْنَا مَكِين٘ اَمِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 55, 'قَالَ "جْعَلْنِى عَلَــيٰ خَزَآئِـنِ ۱لاَرْضِ إِنِّى حَفِيظ٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 56, 'وَكَذَ؛لِــكَ مَكَّنَّا لِيُوسُفَ فِى ۱لاَرْضِ يَتَبَوَّٱُ مِنْهَا حَيْــثُ يَشَآءُؐ نُصِيــبُ بِرَحْمَتِنَا مَــن نَّشَــآءُ وَلاَ نُضِيعُ أَجْرَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 57, 'وَلَأَجْرُ ۴لاَخِرَةِ خَيْرٌ لِّلذِينَ ءَامَنُواْ وَكَانُواْ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 58, 'وَجَآءَ اۭخْوَةُ يُوسُفَ فَدَخَلُواْ عَلَيْهِ فَعَرَفَهُمْ وَهُمْ لَهُ„ مُنكِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 59, 'وَلَمَّا جَهَّزَهُم بِجَهَازۣهِمْ قَالَ "يتُونِى بِأَخٍ لَّكُم مِّنَ اَبِيكُمُؐ; أَلاَ تَرَوْنَ أَنِّيَ ٱُوفِى ۱لْكَيْلَ وَأَنَا خَيْرُ ۴لْمُنزۣلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 60, 'فَإِن لَّمْ تَاتُونِى بِهِ” فَلاَ كَيْــلَ لَكُمْ عِندِى وَلاَ تَقْرَبُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 61, 'قَالُواْ سَنُرَ؛وۣدُ عَنْهُ أَبَاهُ وَإِنَّا لَفَـٰعِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 62, 'وَقَالَ لِفِتْيَتِهِ ''جْعَلُواْ بِضَـٰعَتَهُمْ فِى رۣحَالِهِمْ لَعَلَّهُمْ يَعْرۣفُونَهَآ إِذَا "نقَلَبُوٓاْ إِلَــيٰٓ أَهْلِهِمْ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 63, 'فَلَمَّا رَجَعُوٓاْ إِلَـيٰٓ أَبِيهِمْ قَالُواْ يَـٰٓأَبَانَا مُنِعَ مِنَّا ۰لْكَيْلُ فَأَرْسِــلْ مَعَنَآ أَخَانَا نَكْتَلْ وَإِنَّا لَهُ„ لَحَـٰفِظُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 64, '244 قَالَ هَــلَ —امَنُكُمْ عَلَيْهِ إِلاَّ كَمَآ أَمِنتُكُمْ عَلَـيٰٓ أَخِيهِ مِن قَبْـلُؐ فَاللَّهُ خَيْر٘ حِفْظاًؐ وَهُوَ أَرْحَمُ ۴لرَّ؛حِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 65, 'وَلَمَّا فَتَحُواْ مَتَـٰعَهُمْ وَجَدُواْ بِضَـٰعَتَهُمْ رُدَّتتتِ اِلَيْهِمْ قَالُواْ يَـٰٓأَبَانَا مَا نَبْغِىؐ هَـٰذِهِ” بِضَـٰعَتُنَا رُدَّتتتِ اِلَيْنَا وَنَمِيرُ أَهْلَنَا وَنَحْفَظُ أَخَانَا وَنَزْدَادُ كَيْلَ بَعِيرٍؐ ذَ؛لِــكَ كَيْــلٌ يَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 66, 'قَالَ لَنُ ۷رْسِلَهُ„ مَعَكُمْ حَتَّيٰ تُوتُونِ مَوْثِقاً مِّــنَ ۰للَّهِ لَتَاتُنَّنِى بِهِ“ إِلٓاَّ أَنْ يُّحَاطَ بِكُمْؐ فَلَمَّآ ءَاتَوْهُ مَوْثِقَهُمْ قَالَ ۰للَّهُ عَلَيٰ مَا نَقُولُ وَكِيـلٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 67, 'وَقَالَ يَـٰبَنِــيَّ لاَ تَدْخُلُواْ مِـنۢ بَابببٍ وَ؛حِدٍ وَادْخُلُواْ مِنَ اَبْوَ؛بٍ مُّتَفَرّۣقَةٍؐ وَمَآ ٱُغْنِى عَنكُم مِّــنَ ۰للَّهِ مِن شَيْءٖؐ اِنننۣ ۱لْحُكْمُ إِلاَّ لِلهِؐ عَلَيْهِ تَوَكَّلْــتُؐ وَعَلَيْهِ فَلْيَتَوَكَّلِ ۱لْمُتَوَكِّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 68, 'وَلَمَّا دَخَلُواْ مِــنْ حَيْــثُ أَمَرَهُمُ; أَبُوهُم مَّا كَانَ يُغْنِى عَنْهُم مِّــنَ ۰للَّهِ مِن شَيْءٖ اِلاَّ حَاجَةً فِى نَفْسِ يَعْقُوبَ قَضۭيٰهَاؐ وَإِنَّهُ„ لَذُو عِلْمٍ لِّمَا عَلَّمْنَـٰهُؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 69, 'وَلَمَّا دَخَلُواْ عَلَيٰ يُوسُفَ ءَاوۭيٰٓ إِلَيْهِ أَخَاهُؐ قَالَ إِنِّــيَ أَنَآ أَخُوكككَ فَلاَ تَبْتَئِـسْ بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 70, '245 فَلَمَّا جَهَّزَهُم بِجَهَازۣهِمْ جَعَلَ ۰لسِّقَايَةَ فِى رَحْـلِ أَخِيهِ ثُمَّ أَذَّنَ مُوَ۬ذِّن٘ اَيَّتُهَا ۰لْعِيرُ إِنَّكُمْ لَسَـٰرۣقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 71, 'قَالُواْ وَأَقْبَلُواْ عَلَيْهِم مَّاذَا تَفْقِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 72, 'قَالُواْ نَفْقِدُ صُوَاعَ ۰لْمَلِكِؐ وَلِمَـن جَآءَ بِهِ” حِمْلُ بَعِيرٍ وَأَنَا بِهِ” زَعِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 73, 'قَالُواْ تَاللَّهِ لَقَدْ عَلِمْتُم مَّا جِيؔنَا لِنُفْسِدَ فِى ۱لاَرْضِ وَمَا كُنَّا سَـٰرۣقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 74, 'قَالُواْ فَمَا جَزَ×ؤُهُ; إِننن كُنتُمْ كَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 75, 'قَالُواْ جَزَ×ؤُهُ„ مَنْ وُّجِدَ فِى رَحْلِهِ” فَهُوَ جَزَ×ؤُهُؐ, كَذَ؛لِــكَ نَجْزۣى ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 76, 'فَبَدَأَ بِأَوْعِيَتِهِمْ قَبْلَ وۣعَآءِ اَ۬خِيهِ ثُمَّ "سْتَخْرَجَهَا مِنْ وّۣعَآءِ اَ۬خِيهِؐ كَذَ؛لِــكَ كِدْنَا لِيُوسُفَؐ مَا كَانَ لِيَاخُذَ أَخَاهُ فِى دِينِ ۱لْمَلِــكِ إِلٓاَّ أَنْ يَّشَآءَ ۰للَّهُؐ نَرْفَعُ دَرَجَـٰــتِ مَــن نَّشَآءُؐ وَفَوْقَ كُلِّ ذى عِلْمٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 77, '© قَالُوٓاْ إِنْ يَّسْرۣقْ فَقَدْ سَرَقَ أَخٌ لَّهُ„ مِــن قَبْلُؐ فَأَسَرَّهَا يُوسُفُ فِى نَفْسِهِ” وَلَمْ يُبْدِهَا لَهُمْؐ قَالَ أَنتُمْ شَرٌّ مَّكَاناًؐ وَاللَّهُ أَعْلَمُ بِمَا تَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 78, 'قَالُواْ يَـٰٓأَيُّهَا ۰لْعَزۣيزُ إِنَّ لَهُ; أَباً شَيْخاً كَبِيراً فَخُذَ اَحَدَنَا مَكَانَهُ; إِنَّا نَرۭيٰــكَ مِــنَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 79, 'قَالَ مَعَاذَ ۰للَّهِ أَن نَّاخُذَ إِلاَّ مَنْ وَّجَدْنَا 246 مَتَـٰعَنَا عِندَهُ; إِنَّـآ إِذاً لَّظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 80, 'فَلَمَّا "سْتَيْــَٔـسُواْ مِنْهُ خَلَصُواْ نَجِيّاًؐ قَالَ كَبِيرُهُمُ; أَلَمْ تَعْلَمُوٓاْ أَنَّ أَبَاكُمْ قَدَ اَخَذَ عَلَيْكُم مَّوْثِقاً مِّــنَ ۰للَّهِؐ وَمِــن قَبْلُ مَا فَرَّطْتُّمْ فِى يُوسُفَؐ فَلَنَ اَبْرَحَ ۰لاَرْضضضَ حَتَّيٰ يَاذَنَ لِيَ أَبِيَ أَوْ يَحْكُمَ ۰للَّهُ لِىؐ وَهُوَ خَيْرُ ۴لْحَـٰكِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 81, '"رْجِعُوٓاْ إِلَـيٰٓ أَبِيكُمْ فَقُولُواْ يَـٰٓأَبَانَآ إِنَّ "بْنَــكَ سَرَقَؐ وَمَا شَهِدْنَآ إِلاَّ بِمَا عَلِمْنَا وَمَا كُنَّا لِلْغَيْبِ حَـٰفِظِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 82, 'وَسْـَٔلِ ۱لْقَرْيَةَ ۰لتِى كُنَّا فِيهَا وَالْعِيرَ ۰لتِىٓ أَقْبَلْنَا فِيهَا وَإِنَّا لَصَـٰدِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 83, 'قَالَ بَلْ سَوَّلَتْ لَكُمُ; أَنفُسُكُمُ; أَمْراًؐ فَصَبْرٌ جَمِيــل٘ؐ عَسَــي ۰للَّهُ أَنْ يَّاتِيَنِى بِهِمْ جَمِيعاٗؐ اِنَّهُ„ هُوَ ۰لْعَلِيمُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 84, 'وَتَوَلّۭــيٰ عَنْهُمْ وَقَالَ يَـٰٓأَسَفۭــيٰ عَلَيٰ يُوسُفَؐ وَابْيَضَّــتْ عَيْنَـٰهُ مِــنَ ۰لْحُزْنِ فَهُوَ كَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 85, 'قَالُواْ تَاللَّهِ تَفْتَؤُاْ تَذْكُرُ يُوسُفَ حَتَّيٰ تَكُونَ حَرَضاٗ اَوْ تَكُونَ مِــنَ ۰لْهَـٰلِكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 86, 'قَالَ إِنَّمَآ أَشْكُواْ بَثِّى وَحُزْنِيَ إِلَــي ۰للَّهِؐ وَأَعْلَمُ مِــنَ ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 87, 'يَـٰبَنِــيَّ "ذْهَبُواْ فَتَحَسَّسُواْ مِنْ يُّوسُفَ وَأَخِيهِ وَلاَ تَاْيْــَٔـسُواْ مِن 247 رَّوْحِ ۱للَّهِؐ إِنَّهُ„ لاَ يَاْيْـَٔسُ مِن رَّوْحِ ۱للَّهِ إِلاَّ ۰لْقَوْمُ ۴لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 88, 'فَلَمَّا دَخَلُواْ عَلَيْهِ قَالُواْ يَـٰٓأَيُّهَا ۰لْعَزۣيزُ مَسَّنَا وَأَهْلَنَا ۰لضُّرُّ وَجِيؔنَا بِبِضَـٰعَةٍ مُّزْجۭيٰةٍؐ فَأَوْفِ لَنَا ۰لْكَيْلَ وَتَصَدَّقْ عَلَيْنَآؐ إِنننَّ ۰للَّهَ يَجْزۣى ۱لْمُتَصَدِّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 89, 'قَالَ هَلْ عَلِمْتُم مَّا فَعَلْتُم بِيُوسُفَ وَأَخِيهِ إِذَ اَنتُمْ جَـٰهِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 90, 'قَالُوٓاْ أَ.نَّكَ لَأَنــتَ يُوسُفُؐ قَالَ أَنَا يُوسُفُ وَهَـٰذَآ أَخِىؐ قَدْ مَــنَّ ۰للَّهُ عَلَيْنَآؐ إِنَّهُ„ مَنْ يَّتَّقِ وَيَصْبِرْ فَإِنننَّ ۰للَّهَ لاَ يُضِيعُ أَجْرَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 91, 'قَالُواْ تَاللَّهِ لَقَدَ —اثَرَكككَ ۰للَّهُ عَلَيْنَا وَإِن كُنَّا لَخَـٰطِـِٕيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 92, 'قَالَ لاَ تَثْرۣيــبَ عَلَيْكُمُؐ ۴لْيَوْمَ يَغْفِرُ ۴للَّهُ لَكُمْؐ وَهُوَ أَرْحَمُ ۴لرَّ؛حِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 93, '"ذْهَبُواْ بِقَمِيصِى هَـٰذَا فَأَلْقُوهُ عَلَيٰ وَجْهِ أَبِى يَاتِ بَصِيراً وَاتُونِى بِأَهْلِكُمُ; أَجْمَعِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 94, 'وَلَمَّـا فَصَلَــتِ ۱لْعِيرُ قَالَ أَبُوهُمُ; إِنِّى لَأَجِدُ رۣيحَ يُوسُفَ لَوْلآَ أَن تُفَنِّدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 95, 'قَالُواْ تَاللَّهِ إِنَّــكَ لَفِى ضَچَلِــكَ ۰لْقَدِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 96, 'فَلَمَّآ أَن جَآءَ ۰لْبَشِيرُ أَلْقۭيٰهُ عَلَيٰ وَجْهِهِ” فَارْتَدَّ بَصِيراًؐ قَالَ أَلَمَ اَقُــل لَّكُمُ; إِنِّــيَ أَعْلَمُ مِــنَ ۰للَّهِ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 97, '248 قَالُواْ يَـٰٓأَبَانَا "سْتَغْفِرْ لَنَا ذُنُوبَنَآ إِنَّا كُنَّا خَـٰطِـِٕينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 98, 'قَالَ سَوْفَ أَسْتَغْفِرُ لَكُمْ رَبِّــيَؐ إِنَّهُ„ هُوَ ۰لْغَفُورُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 99, 'فَلَمَّا دَخَلُواْ عَلَيٰ يُوسُفَ ءَاوۭيٰٓ إِلَيْهِ أَبَوَيْهِ وَقَالَ ۸دْخُلُواْ مِصْرَ إِن شَآءَ ۰للَّهُ ءَامِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 100, 'وَرَفَعَ أَبَوَيْهِ عَلَي ۰لْعَرْشِ وَخَرُّواْ لَهُ„ سُجَّداًؐ وَقَالَ يَـٰٓأَبَــتِ هَـٰذَا تَاوۣيلُ رُءْيۭـٰــيَ مِـن قَبْلُ قَدْ جَعَلَهَا رَبِّى حَقّاًؐ وَقَدَ اَحْسَــنَ بِـيَ إِذَ اَخْرَجَنِى مِــنَ ۰ڤسِّجْنِ وَجَآءَ بِكُم مِّــنَ ۰لْبَدْوۣ مِـنۢ بَعْدِ أَن نَّزَغَ ۰لشَّيْطَـٰنُ بَيْنِى وَبَيْنَ إِخْوَتِيَؐ إِنَّ رَبِّى لَطِيفٌ لِّمَا يَشَآءُؐ اِ۬نَّهُ„ هُوَ ۰لْعَلِيمُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 101, '¥ رَبِّ قَدَ —اتَيْتَنِى مِــنَ ۰لْمُلْــكِ وَعَلَّمْتَنِى مِــن تَـاوۣيـلِ ۱لاَحَادِيــثِؐ فَاطِرَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضضضِ أَنــتَ وَلِــىِّ” فِى ۱لدُّنْيۭا وَالاَخِرَةِ تَوَفَّنِى مُسْلِماً وَأَلْحِقْنِى بِاڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 102, 'ذَ؛لِكَ مِــنَ اَنۢبَآءِ ۱لْغَيْــبِ نُوحِيهِ إِلَيْــكَؐ وَمَا كُنتَ لَدَيْهِمُ; إِذَ اَجْمَعُوٓاْ أَمْرَهُمْ وَهُمْ يَمْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 103, 'وَمَآ أَكْثَرُ ۴لنَّاسِ وَلَوْ حَرَصْــتَ بِمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 104, 'وَمَا تَسْـَٔلُهُمْ عَلَيْهِ مِــنَ اَجْرٖؐ اِنْ هُوَ إِلاَّ ذِكْرٌ لِّلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 105, 'وَكَأَيِّــن مِّـنَ —ايَةٍ فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضِ يَمُرُّونَ عَلَيْهَا 249 وَهُمْ عَنْهَا مُعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 106, 'وَمَا يُومِــنُ أَكْثَرُهُم بِاللَّهِ إِلاَّ وَهُم مُّشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 107, 'أَفَأَمِنُوٓاْ أَننن تَـاتِيَهُمْ غَـٰشِيَةٌ مِّــنْ عَذَابببِ ۱للَّهِ أَوْ تَاتِيَهُمُ ۴لسَّاعَةُ بَغْتَةً وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 108, 'قُلْ هَـٰذِهِ” سَبِيلِــيَ أَدْعُوٓاْ إِلَــي ۰للَّهِؐ عَلَيٰ بَصِيرَةٖ اَنَا وَمَـنِ ''تَّبَعَنِىؐ وَسُبْحَـٰــنَ ۰للَّهِؐ وَمَآ أَنَا مِــنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 109, 'وَمَآ أَرْسَلْنَا مِــن قَبْلِــكَ إِلاَّ رۣجَالًا يُوحۭيٰٓ إِلَيْهِم مِّــنَ اَهْـلِ ۱لْقُرۭيٰٓؐ أَفَلَمْ يَسِيرُواْ فِى ۱لاَرْضِ فَيَنظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِينَ مِن قَبْلِهِمْؐ وَلَدَارُ ۴لاَخِرَةِ خَيْرٌ لِّلذِيــنَ "تَّقَوَاْؐ اَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 110, 'حَتَّيٰٓ إِذَا "سْتَيْـَٔــسَ ۰لـرُّسُلُ وَظَنُّوٓاْ أَنَّهُمْ قَدْ كُذِّبُواْ جَآءَهُمْ نَصْرُنَا فَنُنِجى مَــن نَّشَآءُؐ وَلاَ يُرَدُّ بَأْسُنَا عَـنِ ۱لْقَوْمِ ۱ڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (12, 111, 'لَقَدْ كَانَ فِى قَصَصِهِمْ عِبْرَةٌ لُءِّوْلِى ۱لاَلْبَـٰــبِؐ مَا كَانَ حَدِيثاً يُفْتَرۭيٰؐ وَچَكِــن تَصْدِيقَ ۰ﻟ﮲ بَيْــنَ يَدَيْهِ وَتَفْصِيــلَ كُــلّۣ شَيْءٍ وَهُديً وَرَحْمَةً لِّقَوْمٍ يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 1, '250 بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓمِؓـرۭؐ تِلْــكَ ءَايَـٰــتُ ۴لْكِتَـٰــبِؐ وَاﻟـذِىٓ ٱُنزۣلَ إِلَيْــكَ مِن رَّبِّــكَ ۰لْحَقُّؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 2, '۰للَّهُ ۴ﻟ﮲ رَفَعَ ۰لسَّمَـٰوَ؛تتتِ بِغَيْرۣ عَمَدٍؐ تَرَوْنَهَاؐ ثُمَّ "سْتَوۭيٰ عَلَــي ۰لْعَرْشِؐ وَسَخَّرَ ۰لشَّمْـسَ وَالْقَمَرَؐ كُلٌّ يَجْرۣى لَأِجَــلٍ مُّسَمّيًؐ يُدَبِّرُ ۴لاَمْرَؐ يُفَصِّــلُ ۴لاَيَـٰــتِ لَعَلَّكُم بِلِقَآءِ رَبِّكُمْ تُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 3, 'وَهُوَ ۰ﻟ﮲ مَدَّ ۰لاَرْضَ وَجَعَـلَ فِيهَا رَوَ؛سِيَ وَأَنْهَـٰراًؐ وَمِــن كُــلّۣ ۱لثَّمَرَ؛تِ جَعَـلَ فِيهَا زَوْجَيْـنِ ''ثْنَيْــنۣؐ يُغْشِى ۱ليْــلَ ۰لنَّهَارَؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 4, 'وَفِى ۱لاَرْضِ قِطَعٌ مُّتَجَـٰوۣرَ؛تتتٌ وَجَنَّـٰــتٌ مِّــنَ اَعْنَـٰــبٍ وَزَرْعٍ وَنَخِيــلٍ صِنْوَانٍ وَغَيْرۣ صِنْوَانٍ تُسْقۭــيٰ بِمَآءٍ وَ؛حِدٍؐ وَنُفَضِّـلُ بَعْضَهَا عَلَيٰ بَعْـضٍ فِى ۱لاُكْلِؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 5, '© وَإِن تَعْجَــبْ فَعَجَــبٌ قَوْلُهُمُ; أَ.ذَا كُنَّا تُرَ؛باٗ اِنَّا لَفِى خَلْـقٍ جَدِيدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 6, '۷وْلَئِــكَ ۰لذِيــنَ كَفَرُواْ بِرَبِّهِمْؐ وَٱُوْلَئِــكَ ۰لاَغْچَـلُ فِىٓ أَعْنَـٰقِهِمْؐ وَٱُوْلَئِــكَ أَصْحَـٰــبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 7, 'وَيَسْتَعْجِلُونَــكَ بِالسَّيِّيؕةِ قَبْــلَ ۰لْحَسَنَةِ وَقَدْ خَلَــتْ 251 مِــن قَبْلِهِمُ ۴لْمَثُچَتُؐ وَإِنَّ رَبَّكَ لَذُو مَغْفِرَةٍ لِّلنَّاسسسِ عَلَيٰ ظُلْمِهِمْؐ وَإِنَّ رَبَّــكَ لَشَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 8, 'وَيَقُولُ ۴لذِينَ كَفَرُواْ لَوْلآَ ٱُنزۣلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِؐ“ إِنَّمَآ أَنتَ مُنذِرٌؐ وَلِكُلِّ قَوْمٖ هَادٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 9, '۱للَّهُ يَعْلَمُ مَا تَحْمِــلُ كُلُّ ٱُنثۭيٰ وَمَا تَغِيــضُ ۴لاَرْحَامُ وَمَا تَزْدَادُؐ وَكُــلُّ شَيْءٖ عِندَهُ„ بِمِقْدۭارٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 10, 'عَـٰلِمُ ۴لْغَيْــبِ وَالشَّهَـٰدَةِؐ ۱لْكَبِيرُ ۴لْمُتَعَالِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 11, 'سَوَآءٌ مِّنكُم مَّــنَ اَسَرَّ ۰لْقَوْلَ وَمَن جَهَرَ بِهِ” وَمَنْ هُوَ مُسْتَخْفٙ بِاليْلِ وَسَارۣبببٛ بِالنَّهۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 12, 'لَهُ„ مُعَقِّبَـٰـــتٌ مِّنۢ بَيْـنِ يَدَيْهِ وَمِــنْ خَلْفِهِ” يَحْفَظُونَهُ„ مِنَ اَمْرۣ ۱للَّهِؐ إِنننَّ ۰للَّهَ لاَ يُغَيِّرُ مَا بِقَوْمٖ حَتَّيٰ يُغَيِّرُواْ مَا بِأَنفُسِهِمْؐ وَإِذَآ أَرَادَ ۰للَّهُ بِقَوْمٍ سُوٓءاً فَلاَ مَرَدَّ لَهُؐ, وَمَا لَهُم مِّن دُونِهِ” مِنْ وَّالٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 13, 'هُوَ ۰ﻟ﮲ يُرۣيكُمُ ۴لْبَرْقَ خَوْفاً وَطَمَعاً وَيُنشِىُٔ ۴ڤسَّحَابَ ۰لثِّقَالللَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 14, 'وَيُسَبِّحُ ۴لرَّعْدُ بِحَمْدِهِ” وَالْمَلَئِكَةُ مِنْ خِيفَتِهِؐ” وَيُرْسِــلُ ۴لصَّوَ؛عِقَ فَيُصِيــبُ بِهَا مَنْ يَّشَآءُ وَهُمْ يُجَـٰدِلُونَ فِى ۱للَّهِ وَهُوَ شَدِيدُ ۴ڤْمِحَالِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 15, 'لَهُ„ دَعْوَةُ ۴لْحَقﱢّؐ وَالذِيــنَ يَدْعُونَ مِن دُونِهِ” 252 لاَ يَسْتَجِيبُونَ لَهُم بِشَىْءٖ اِلاَّ كَبَـٰسِطِ كَفَّيْهِ إِلَــي ۰لْمَآءِ لِيَبْلُغَ فَاهُ وَمَا هُوَ بِبَـٰلِغِهِؐ” وَمَا دُعَآءُ ۴لْكۭـٰفِـرۣينَ إِلاَّ فِى ضَچَــلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 16, 'وَلِلهِ يَسْجُدُ مَـن فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِ طَوْعاً وَكَرْهاً وَظِچَلُهُم بِالْغُدُوّۣ وَالاَصَالِؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 17, 'قُلْ مَن رَّبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ قُلِ ۱للَّهُؐ قُـلَ اَفَاتَّخَذتُّم مِّن دُونِهِ“ أَوْلِيَآءَ لاَ يَمْلِكُونَ لَأِنفُسِهِمْ نَفْعاً وَلاَ ضَرّاًؐ قُلْ هَلْ يَسْتَوۣى ۱لاَعْمۭيٰ وَالْبَصِيرُؐ أَمْ هَــلْ تَسْتَوۣى ۱لظُّلُمَـٰتُ وَالنُّورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 18, 'أَمْ جَعَلُواْ لِلهِ شُرَكَآءَ خَلَقُواْ كَخَلْقِهِ” فَتَشَـٰبَهَ ۰لْخَلْــقُ عَلَيْهِمْؐ قُـلِ ۱للَّهُ خَـٰلِــقُ كُــلّۣ شَيْءٍؐ وَهُوَ ۰لْوَ؛حِدُ ۴لْقَهَّـٰرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 19, 'أَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءً فَسَالَــتَ اَوْدِيَةٛ بِقَدَرۣهَا فَاحْتَمَلَ ۰لسَّيْلُ زَبَداً رَّابِياًؐ وَمِمَّا تُوقِدُونَ عَلَيْهِ فِى ۱لنّۭارۣ ''بْتِغَآءَ حِلْيَةٖ اَوْ مَتَـٰعٍ زَبَدٌ مِّثْلُهُؐ, كَذَ؛لِــكَ يَضْرۣبببُ ۴للَّهُ ۴لْحَقَّ وَالْبَـٰطِلَؐ فَأَمَّا ۰لزَّبَدُ فَيَذْهَــبُ جُفَآءًؐ وَأَمَّا مَا يَنفَعُ ۴لنَّاسَ فَيَمْكُــثُ فِى ۱لاَرْضضضِؐ كَذَ؛لِــكَ يَضْرۣبببُ ۴للَّهُ ۴لاَمْثَالَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 20, 'لِلذِيــنَ "سْتَجَابُواْ لِرَبِّهِمُ ۴لْحُسْنۭيٰؐ وَالذِينَ لَمْ يَسْتَجِيبُواْ لَهُ„ لَوَ اَنَّ لَهُم مَّا فِى 25 ۱لاَرْضضضِ جَمِيعاً وَمِثْلَهُ„ مَعَهُ„ لاَفْتَدَوْاْ بِهِؐ“ ٱُوْلَئِــكَ لَهُمْ سُوٓءُ ۴لْحِسَابببِؐ وَمَأْوۭيٰهُمْ جَهَنَّمُؐ وَبِيسَ ۰لْمِهَادُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 21, '¤ أَفَمَـنْ يَّعْلَمُ أَنَّمَآ ٱُنزۣلَ إِلَيْــكَ مِن رَّبِّــكَ ۰لْحَــقُّ كَمَنْ هُوَ أَعْمۭيٰٓؐ إِنَّمَا يَتَذَكَّرُ ٱُوْلُواْ ۴لاَلْبَـٰــبِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 22, '۱لذِينَ يُوفُونَ بِعَهْدِ ۱للَّهِ وَلاَ يَنقُضُونَ ۰لْمِيثَـٰقَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 23, 'وَالذِينَ يَصِلُونَ مَآ أَمَرَ ۰للَّهُ بِهِ“ أَنْ يُّوصَلَ وَيَخْشَوْنَ رَبَّهُمْ وَيَخَافُونَ سُوٓءَ ۰لْحِسَابِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 24, 'وَالذِيــنَ صَبَرُواْ èبْتِغَآءَ وَجْهِ رَبِّهِمْ وَأَقَامُواْ ۴لصَّلَوٰةَ وَأَنفَقُواْ مِمَّا رَزَقْنَـٰهُمْ سِرّاً وَعَچَنِيَةً وَيَدْرَءُونَ بِالْحَسَنَةِ ۱لسَّيِّيؕةَؐ ٱُوْلَئِكَ لَهُمْ عُقْبَي ۰لدّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 25, 'جَنَّـٰــتُ عَدْنٍ يَدْخُلُونَهَا وَمَــن صَلَحَ مِــنَ —ابَآئِهِمْ وَأَزْوَ؛جِهِمْ وَذُرّۣيَّـٰتِهِمْؐ وَالْمَلَئِكَةُ يَدْخُلُونَ عَلَيْهِم مِّــن كُلِّ بَابٍؐ سَچَم٘ عَلَيْكُم بِمَا صَبَرْتُمْؐ فَنِعْمَ عُقْبَــي ۰لـدّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 26, 'وَالذِيــنَ يَنقُضُونَ عَهْدَ ۰للَّهِ مِـنۢ بَعْدِ مِيثَـٰقِهِ” وَيَقْطَعُونَ مَآ أَمَرَ ۰للَّهُ بِهِ“ أَنْ يُّوصَلَ وَيُفْسِدُونَ فِى ۱لاَرْضِ ٱُوْلَئِكَ لَهُمُ ۴للَّعْنَةُ وَلَهُمْ سُوٓءُ ۴لدّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 27, '۱للَّهُ يَبْسُطُ ۴لرّۣزْقَ لِمَـنْ يَّشَآءُ وَيَقْدِرُؐ 254 وَفَرۣحُواْ بِالْحَيَوٰةِ ۱لدُّنْيۭاؐ وَمَا ۰لْحَيَوٰةُ ۴لدُّنْيۭا فِى ۱لاَخِرَةِ إِلاَّ مَتَـٰعٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 28, 'وَيَقُولُ ۴لذِيــنَ كَفَرُواْ لَوْلآَ ٱُنزۣلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِؐ” قُـلِ اِنَّ ۰للَّهَ يُضِلُّ مَنْ يَّشَآءُ وَيَهْدِ ىٓ إِلَيْهِ مَنَ اَنَابَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 29, '۰لذِيــنَ ءَامَنُواْ وَتَطْمَئِنُّ قُلُوبُهُم بِذِكْرۣ ۱للَّهِؐ أَلاَ بِذِكْرۣ ۱للَّهِ تَطْمَئِـــنُّ ۴لْقُلُوبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 30, '۴لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ طُوبۭــيٰ لَهُمْ وَحُسْــنُ مَـَٔابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 31, 'كَذَ؛لِــكَ أَرْسَلْنَـٰــكَ فِىٓ ٱُمَّةٍ قَدْ خَلَــتْ مِــن قَبْلِهَآ ٱُمَمٌ لِّتَتْلُوَاْ عَلَيْهِمُ ۴ﻟـذِىٓ أَوْحَيْنَآ إِلَيْــكَ وَهُمْ يَكْفُرُونَ بِالرَّحْمَـٰــنۣؐ قُلْ هُوَ رَبِّىؐ لآَ إِچَهَ إِلاَّ هُوَؐ عَلَيْهِ تَوَكَّلْــتُؐ وَإِلَيْهِ مَتَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 32, 'وَلَوَ اَنَّ قُرْءَاناً سُيِّرَتتتْ بِهِ ۱لْجِبَالُ أَوْ قُطِّعَتْ بِهِ ۱لاَرْضُ أَوْ كُلِّمَ بِهِ ۱لْمَوْتۭيٰؐ بَل لِّلهِ ۱لاَمْرُ جَمِيعاٗؐ اَفَلَمْ يَاْيْـَٔـــسِ ۱لـذِيــنَ ءَامَنُوٓاْ أَن لَّوْ يَشَآءُ ۴للَّهُ لَهَدَي ۰لنَّاسَ جَمِيعاًؐ وَلاَ يَزَالُ ۴لذِيــنَ كَفَرُواْ تُصِيبُهُم بِمَا صَنَعُواْ قَارۣعَة٘ اَوْ تَحُلُّ قَرۣيباً مِّن دۭارۣهِمْ حَتَّيٰ يَاتِيَ وَعْدُ ۴للَّهِؐ إِنننَّ ۰للَّهَ لاَ يُخْلِفُ ۴لْمِيعَادَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 33, 'وَلَقَدُ ۶سْتُهْزۣىَٔ بِرُسُلٍ 255 مِّــن قَبْلِــكَ فَأَمْلَيْــتُ لِلذِيــنَ كَفَرُواْ ثُمَّ أَخَذتُّهُمْؐ فَكَيْفَ كَانَ عِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 34, 'أَفَمَنْ هُوَ قَآئِم٘ عَلَــيٰ كُـلِّ نَفْسٙ بِمَــا كَسَبَــتْؐ وَجَعَلُواْ لِلهِ شُرَكَآءَ قُــلْ سَمُّوهُمُؐ; أَمْ تُنَبِّـُٔونَهُ„ بِمَا لاَ يَعْلَمُ فِى ۱لاَرْضِ أَم بِظَـٰهِرٍ مِّنَ ۰لْقَوْلِؐ بَلْ زُيِّنَ لِلذِيــنَ كَفَرُواْ مَكْرُهُمْ وَصَدُّواْ عَـنِ ۱لسَّبِيلِؐ وَمَـنْ يُّضْلِلِ ۱للَّهُ فَمَا لَهُ„ مِــنْ هَادٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 35, 'لَّهُمْ عَذَابببٌ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَلَعَذَابببُ ۴لاَخِرَةِ أَشَقُّؐ وَمَا لَهُم مِّــنَ ۰للَّهِ مِنْ وَّاقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 36, '© مَّثَلُ ۴لْجَنَّةِ ۱لتِى وُعِدَ ۰لْمُتَّقُونَ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ ٱُكْلُهَا دَآئِمٌ وَظِلُّهَاؐ تِلْــكَ عُقْبَــي ۰لذِيــنَ "تَّقَواْؐ وَّعُقْبَي ۰لْكۭـٰفِـرۣيــنَ ۰لنَّارُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 37, 'وَالذِيــنَ ءَاتَيْنَـٰهُمُ ۴لْكِتَـٰــبَ يَفْرَحُونَ بِمَآ ٱُنزۣلَ إِلَيْــكَؐ وَمِــنَ ۰لاَحْزَابِ مَـنْ يُّنكِرُ بَعْضَهُؐ, قُـلِ اِنَّمَآ ٱُمِرْتتتُ أَنننَ اَعْبُدَ ۰للَّهَ وَلآَ ٱُشْرۣكَ بِهِؐ“ إِلَيْهِ أَدْعُواْؐ وَإِلَيْهِ مَـَٔابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 38, 'وَكَذَ؛لِــكَ أَنزَلْنَـٰهُ حُكْماٗ عَرَبِيّاًؐ وَلَـئِـــۣن ''تَّبَعْــتَ أَهْوَآءَهُم بَعْدَ مَا جَآءَكككَ مِــنَ ۰لْعِلْمِ مَا لَــكَ مِــنَ ۰للَّهِ مِنْ وَّلِيٍّ وَلاَ وَاقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 39, 'وَلَقَدَ اَرْسَلْنَا رُسُلًا مِّــن قَبْلِــكَ وَجَعَلْنَا لَهُمُ; 256 أَزْوَ؛جاً وَذُرّۣيَّةًؐ وَمَا كَانَ لِرَسُولٖ اَنْ يَّاتِيَ بِـَٔايَةٖ اِلاَّ بِإِذْنِ ۱للَّهِؐ لِكُــلّۣ أَجَــلٍ كِتَابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 40, 'يَمْحُواْ ۴للَّهُ مَا يَشَآءُ وَيُثَبِّــتُؐ وَعِندَهُ; ٱُمُّ ۴لْكِتَـٰــبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 41, 'وَإِن مَّا نُرۣيَنَّكَ بَعْضَ ۰ﻟ﮲ نَعِدُهُمُ; أَوْ نَتَوَفَّيَنَّــكَ فَإِنَّمَا عَلَيْــكَ ۰لْبَچَغُ وَعَلَيْنَا ۰لْحِسَابببُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 42, 'أَوَلَمْ يَرَوَاْ اَنَّا نَاتِى ۱لاَرْضضضَ نَنقُصُهَا مِــنَ اَطْرَافِهَاؐ وَاللَّهُ يَحْكُمُ لاَ مُعَقِّبَ لِحُكْمِهِؐ” وَهُوَ سَرۣيعُ ۴لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 43, 'وَقَدْ مَكَرَ ۰لذِينَ مِن قَبْلِهِمْ فَلِلهِ ۱لْمَكْرُ جَمِيعاًؐ يَعْلَمُ مَا تَكْسِــبُ كُلُّ نَفْسٍؐ وَسَيَعْلَمُ ۴لْكَـٰفِرُ لِمَــنْ عُقْبَي ۰لدّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (13, 44, 'وَيَقُولُ ۴لذِيــنَ كَفَرُواْ لَسْتَ مُرْسَلًؐا قُــلْ كَفۭــيٰ بِاللَّهِ شَهِيداَۢ بَيْنِى وَبَيْنَكُمْ وَمَـنْ عِندَهُ„ عِلْمُ ۴لْكِتَـٰــبِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓرۭؐ كِتَـٰــب٘ اَنزَلْنَـٰهُ إِلَيْــكَ ڤِتُخْرۣجَ ۰لنَّاسسسَ مِـنَ ۰لظُّلُمَـٰــتِ إِلَي ۰لنُّورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 2, 'بِإِذْنِ رَبِّهِمُ; إِلَيٰ صِرَ؛طِ ۱لْعَزۣيزۣ ۱لْحَمِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 3, '۱للَّهُ ۴ﻟ﮲ لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تتتِ 257 وَمَا فِى ۱لاَرْضِؐ وَوَيْلٌ لِّلْكۭـٰفِـرۣيــنَ مِـنْ عَذَابٍ شَدِيدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 4, '۱لذِيــنَ يَسْتَحِبُّونَ ۰لْحَيَوٰةَ ۰لدُّنْيۭا عَلَــي ۰لاَخِرَةِ وَيَصُدُّونَ عَــن سَبِيـلِ ۱للَّهِ وَيَبْغُونَهَا عِوَجاٗ ۷وْلَئِــكَ فِى ضَچَلٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 5, 'وَمَآ أَرْسَلْنَا مِن رَّسُولٖ اِلاَّ بِلِسَانِ قَوْمِهِ” لِيُبَيِّــنَ لَهُمْؐ فَيُضِــلُّ ۴للَّهُ مَنْ يَّشَآءُ وَيَهْدِى مَـنْ يَّشَآءُؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 6, 'وَلَقَدَ اَرْسَلْنَا مُوسۭــيٰ بِـَٔايَـٰتِنَآ أَنَ اَخْرۣجْ قَوْمَكَ مِنَ ۰لظُّلُمَـٰــتِ إِلَي ۰لنُّورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 7, 'وَذَكِّرْهُم بِأَييَّـٰمِ ۱للَّهِؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّكُــلّۣ صَبّۭارٍ شَكُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 8, 'وَإِذْ قَالَ مُوسۭيٰ لِقَوْمِهِ ۹ذْكُرُواْ نِعْمَةَ ۰للَّهِ عَلَيْكُمُ; إِذَ اَنجۭيٰكُم مِّــنَ —الِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ۰لْعَذَابِ وَيُذَبِّحُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْؐ وَفِى ذَ؛لِكُم بَلآَءٌ مِّن رَّبِّكُمْ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 9, 'وَإِذْ تَأَذَّنَ رَبُّكُمْ لَـئِــن شَكَرْتُمْ لَأَزۣيدَنَّكُمْ وَلَـئِـن كَفَرْتُمُ; إِنَّ عَذَابِى لَشَدِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 10, 'وَقَالَ مُوسۭيٰٓ إِن تَكْفُرُوٓاْ أَنتُمْ وَمَـن فِى ۱لاَرْضضضِ جَمِيعاً فَإِنننَّ ۰للَّهَ لَغَنِــيّﹲ حَمِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 11, 'اَلَمْ يَاتِكُمْ نَبَؤُاْ ۴لذِيــنَ مِـن قَبْلِكُمْ قَوْمِ نُوحٍ وَعَادٍ وَثَمُودَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 12, '258 وَالذِيــنَ مِنۢ بَعْدِهِمْؐ لاَ يَعْلَمُهُمُ; إِلاَّ ۰للَّهُؐ جَآءَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰــتِ فَرَدُّوٓاْ أَيْدِيَهُمْ فِىٓ أَفْوَ؛هِهِمْ وَقَالُوٓاْ إِنَّا كَفَرْنَا بِمَآ ٱُرْسِلْتُم بِهِ” وَإِنَّا لَفِى شَــكٍّ مِّمَّا تَدْعُونَنَآ إِلَيْهِ مُرۣيــبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 13, '¥ قَالَــتْ رُسُلُهُمُ; أَفِى ۱للَّهِ شَــكٌّ فَاطِرۣ ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِ يَدْعُوكُمْ لِيَغْفِرَ لَكُم مِّن ذُنُوبِكُمْ وَيُوَ۬خِّرَكُمُ; إِلَيٰٓ أَجَــلٍ مُّسَمّــيًؐ قَالُوٓاْ إِنَ اَنتُمُ; إِلاَّ بَشَرٌ مِّثْلُنَا تُرۣيدُونَ أَن تَصُدُّونَا عَمَّا كَانَ يَعْبُدُ ءَابَآؤُنَا فَاتُونَا بِسُلْطَـٰنٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 14, 'قَالَــتْ لَهُمْ رُسُلُهُمُ; إِن نَّحْـنُ إِلاَّ بَشَرٌ مِّثْلُكُمْ وَچَكِنَّ ۰للَّهَ يَمُــنُّ عَلَيٰ مَنْ يَّشَآءُ مِنْ عِبَادِهِؐ” وَمَا كَانَ لَنَآ أَن نَّاتِيَكُم بِسُلْطَـٰــنٖ اِلاَّ بِإِذْنِ ۱للَّهِؐ وَعَلَــي ۰للَّهِ فَلْيَتَوَكَّلِ ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 15, 'وَمَا لَنَآ أَلاَّ نَتَوَكَّــلَ عَلَــي ۰للَّهِ وَقَدْ هَدۭيٰنَا سُبُلَنَاؐ وَلَنَصْبِرَنَّ عَلَــيٰ مَآ ءَاذَيْتُمُونَاؐ وَعَلَــي ۰للَّهِ فَلْيَتَوَكَّلِ ۱لْمُتَوَكِّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 16, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ لِرُسُلِهِمْ ڤَنُخْرۣجَنَّكُم مِّنَ اَرْضِنَآ أَوْ لَتَعُودُنَّ فِى مِلَّتِنَاؐ فَأَوْحۭيٰٓ إِلَيْهِمْ رَبُّهُمْ لَنُهْلِكَــنَّ ۰لظَّـٰلِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 17, 'وَلَنُسْكِنَنَّكُمُ ۴لاَرْضَ مِنۢ بَعْدِهِمْؐ 259 ذَ؛لِــكَ لِمَــنْ خَافَ مَقَامِى وَخَافَ وَعِيدِؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 18, 'وَاسْتَفْتَحُواْؐ وَخَابَ كُلُّ جَبّۭار۫ عَنِيدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 19, 'مِّنْ وَّرَآئِهِ” جَهَنَّمُ وَيُسْقۭيٰ مِــن مَّآءٍ صَدِيدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 20, 'يَتَجَرَّعُهُ„ وَلاَ يَكَادُ يُسِيغُهُ„ وَيَاتِيهِ ۱لْمَوْتتتُ مِن كُــلّۣ مَكَانٍ وَمَا هُوَ بِمَيِّــتٍ وَمِنْ وَّرَآئِهِ” عَذَاببب٘ غَلِيظٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 21, 'مَّثَلُ ۴لذِيــنَ كَفَرُواْ بِرَبِّهِمُؐ; أَعْمَـٰلُهُمْ كَرَمَادٖ ''شْتَدَّتْ بِهِ ۱لرّۣيَـٰحُ فِى يَوْمٖ عَاصِفٍ لاَّ يَقْدِرُونَ مِمَّا كَسَبُواْ عَلَيٰ شَيْءٍؐ ذَ؛لِــكَ هُوَ ۰لضَّچَـلُ ۴لْبَعِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 22, 'أَلَمْ تَرَ أَنننَّ ۰للَّهَ خَلَقَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضضضَ بِالْحَـقﱢّؐ إِنْ يَّشَأْ يُذْهِبْكُمْ وَيَاتِ بِخَلْقٍ جَدِيدٍؐ وَمَا ذَ؛لِــكَ عَلَــي ۰للَّهِ بِعَزۣيزٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 23, 'وَبَرَزُواْ لِلهِ جَمِيعاً فَقَالَ ۰لضُّعَفَـٰٓؤُاْ لِلذِيــنَ "سْتَكْبَرُوٓاْ إِنَّا كُنَّا لَكُمْ تَبَعاً فَهَلَ اَنتُم مُّغْنُونَ عَنَّا مِــنْ عَذَابِ ۱للَّهِ مِن شَيْءٍؐ قَالُواْ لَوْ هَدۭيٰنَا ۰للَّهُ لَهَدَيْنَـٰكُمْؐ سَوَآء٘ عَلَيْنَآ أَجَزۣعْنَآ أَمْ صَبَرْنَا مَا لَنَا مِن مَّحِيـصٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 24, 'وَقَالَ ۰لشَّيْطَـٰنُ لَمَّا قُضِــيَ ۰لاَمْرُ إِنَّ ۰للَّهَ وَعَدَكُمْ وَعْدَ ۰لْحَقِّ وَوَعَدتُّكُمْ فَأَخْلَفْتُكُمْ وَمَا كَانَ لِى عَلَيْكُم مِّــن سُلْطَـٰــن۫ اِلٓاَّ أَن 260 دَعَوْتُكُمْ فَاسْتَجَبْتُمْ لِى فَلاَ تَلُومُونِى وَلُومُوٓاْ أَنفُسَكُم مَّآ أَنَا بِمُصْرۣخِكُمْ وَمَآ أَنتُم بِمُصْرۣخِيَّ إِنِّى كَفَرْتتتُ بِمَآ أَشْرَكْتُمُونِ مِــن قَبْلُؐ إِنننَّ ۰لظَّـٰلِمِيــنَ لَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 25, 'وَٱُدْخِلَ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰـــتِ جَنَّـٰـــتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَا بِإِذْنِ رَبِّهِمْؐ تَحِيَّتُهُمْ فِيهَا سَچَم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 26, 'اَلَمْ تَرَ كَيْفَ ضَرَبَ ۰للَّهُ مَثَلًا كَلِمَةً طَيِّبَةً كَشَجَرَةٍ طَيِّبَةٖ اَصْلُهَا ثَابِــتٌ وَفَرْعُهَا فِى ۱لسَّمَآءِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 27, 'تُوتِىٓ ٱُكْلَهَا كُلَّ حِينٙ بِإِذْنِ رَبِّهَاؐ وَيَضْرۣبُ ۴للَّهُ ۴لاَمْثَالَ لِلنَّاسسسِ لَعَلَّهُمْ يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 28, 'وَمَثَــلُ كَلِمَةٖ خَبِيثَةٍ كَشَجَرَةٖ خَبِيثَةٖ ۶جْتُثَّــتْ مِن فَوْقِ ۱لاَرْضضضِ مَا لَهَا مِن قَرۭارٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 29, 'يُثَبِّــتُ ۴للَّهُ ۴لذِيــنَ ءَامَنُواْ بِالْقَوْلِ ۱لثَّابِــتِ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَفِى ۱لاَخِرَةِؐ وَيُضِــلُّ ۴للَّهُ ۴لظَّـٰلِمِينَؐ وَيَفْعَــلُ ۴للَّهُ مَا يَشَآءُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 30, '© اَ۬لَمْ تَرَ إِلَــي ۰لذِيــنَ بَدَّلُواْ نِعْمَــتَ ۰للَّهِ كُفْراً وَأَحَلُّواْ قَوْمَهُمْ دَارَ ۰لْبَوۭارۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 31, 'جَهَنَّمَ يَصْلَوْنَهَاؐ وَبِيسَ ۰لْقَرَارُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 32, 'وَجَعَلُواْ لِلهِ أَندَاداً لِّيُضِلُّواْ عَــن سَبِيلِهِؐ” 261 قُــلْ تَمَتَّعُواْ فَإِنننَّ مَصِيرَكُمُ; إِلَي ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 33, 'قُل لِّعِبَادِيَ ۰لذِيــنَ ءَامَنُواْ يُقِيمُواْ ۴لصَّلَوٰةَ وَيُنفِقُواْ مِمَّا رَزَقْنَـٰهُمْ سِرّاً وَعَچَنِيَةً مِّــن قَبْلِ أَنْ يَّاتِيَ يَوْمٌ لاَّ بَيْعٌ فِيهِ وَلاَ خِچَل٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 34, '۱للَّهُ ۴ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَأَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءً فَأَخْرَجَ بِهِ” مِنَ ۰لثَّمَرَ؛تتتِ رۣزْقاً لَّكُمْؐ وَسَخَّرَ لَكُمُ ۴لْفُلْــكَ ڤِتَجْرۣيَ فِى ۱ڤْبَحْرۣ بِأَمْرۣهِؐ” وَسَخَّرَ لَكُمُ ۴لاَنْهَـٰرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 35, 'وَسَخَّرَ لَكُمُ ۴لشَّمْسَ وَالْقَمَرَ دَآئِبَيْنِؐ وَسَخَّرَ لَكُمُ ۴ليْلَ وَالنَّهَارَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 36, 'وَءَاتۭيٰكُم مِّن كُــلّۣ مَا سَأَلْتُمُوهُؐ وَإِن تَعُدُّواْ نِعْمَتَ ۰للَّهِ لاَ تُحْصُوهَآؐ إِنَّ ۰لِانسَـٰــنَ لَظَلُومٌ كَفَّارٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 37, 'وَإِذْ قَالَ إِبْرَ؛هِيمُ رَبببِّ ''جْعَــلْ هَـٰذَا ۰لْبَلَدَ ءَامِناً وَاجْنُبْنِى وَبَنِيَّ أَن نَّعْبُدَ ۰لاَصْنَامَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 38, 'رَبِّ إِنَّهُــنَّ أَضْلَلْــنَ كَثِيراً مِّــنَ ۰لنَّاسِ فَمَــن تَبِعَنِى فَإِنَّهُ„ مِنِّى وَمَــنْ عَصۭانِى فَإِنَّــكَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 39, 'رَّبَّنَآ إِنِّــيَ أَسْكَنــتُ مِن ذُرّۣيَّتِى بِوَادٖ غَيْرۣ ذى زَرْعٖ عِندَ بَيْتِكَ ۰ڤْمُحَرَّمِؐ رَبَّنَا لِيُقِيمُواْ ۴لصَّلَوٰةَ فَاجْعَلَ اَفْـِٕدَةً مِّــنَ ۰لنَّاسِ تَهْوۣىٓ إِلَيْهِمْ وَارْزُقْهُم مِّــنَ ۰لثَّمَرَ؛تِ لَعَلَّهُمْ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 40, '262 رَبَّنَآ إِنَّكَ تَعْلَمُ مَا نُخْفِى وَمَا نُعْلِنُؐ وَمَا يَخْفۭــيٰ عَلَــي ۰للَّهِ مِن شَيْءٍ فِى ۱لاَرْضِ وَلاَ فِى ۱لسَّمَآءِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 41, '۱لْحَمْدُ لِلهِ ۱ﻟ﮲ وَهَبَ لِى عَلَــي ۰لْكِبَرۣ إِسْمَـٰعِيلَ وَإِسْحَـٰقَؐ إِنَّ رَبِّى لَسَمِيعُ ۴لدُّعَآءِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 42, 'رَبِّ ''جْعَلْنِى مُقِيمَ ۰لصَّلَوٰةِ وَمِن ذُرّۣيَّتِىؐ رَبَّنَا وَتَقَبَّلْ دُعَآءِؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 43, 'رَبَّنَا "غْفِرْ لِى وَلِوَ؛لِدَيَّ وَلِلْمُومِنِيــنَ يَـوْمَ يَقُومُ ۴لْحِسَابُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 44, 'وَلاَ تَحْسِبَــنَّ ۰للَّهَ غَـٰفِلٗا عَمَّا يَعْمَــلُ ۴لظَّـٰلِمُونَؐ إِنَّمَا يُوَ۬خِّرُهُمْ لِيَوْمٍ تَشْخَصُ فِيهِ ۱لاَبْصَـٰرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 45, 'مُهْطِعِينَ مُقْنِعِى رُءُوسِهِمْ لاَ يَرْتَدُّ إِلَيْهِمْ طَرْفُهُمْ وَأَفْـِٕدَتُهُمْ هَوَآءٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 46, 'وَأَنذِرۣ ۱لنَّاسسسَ يَوْمَ يَاتِيهِمُ ۴لْعَذَابببُ فَيَقُولُ ۴لذِينَ ظَلَمُواْ رَبَّنَآ أَخِّرْنَآ إِلَــيٰٓ أَجَلٍ قَرۣيــبٍ نُّجِــبْ دَعْوَتَــكَ وَنَتَّبِعِ ۱لرُّسُلَؐ أَوَلَمْ تَكُونُوٓاْ أَقْسَمْتُم مِّــن قَبْلُ مَا لَكُم مِّن زَوَالٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 47, 'وَسَكَنتُمْ فِى مَسَـٰكِـنِ ۱لذِيــنَ ظَلَمُوٓاْ أَنفُسَهُمْ وَتَبَيَّــنَ لَكُمْ كَيْفَ فَعَلْنَا بِهِمْ وَضَرَبْنَا لَكُمُ ۴لاَمْثَالَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 48, 'وَقَدْ مَكَرُواْ مَكْرَهُمْؐ وَعِندَ ۰للَّهِ مَكْرُهُمْؐ وَإِن كَانَ مَكْرُهُمْ لِتَزُولَ مِنْهُ ۴لْجِبَالُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 49, 'فَلاَ تَحْسِبَــنَّ ۰للَّهَ مُخْلِفَ وَعْدِهِ” رُسُلَهُؐ; إِنننَّ ۰للَّهَ 26 عَزۣيزٌ ذُو èنتِقَامٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 50, 'يَوْمَ تُبَدَّلُ ۴لاَرْضضضُ غَيْرَ ۰لاَرْضِ وَالسَّمَـٰوَ؛تتتُؐ وَبَرَزُواْ لِلهِ ۱لْوَ؛حِدِ ۱لْقَهّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 51, 'وَتَرَي ۰ڤْمُجْرۣمِينَ يَوْمَئِذٍ مُّقَرَّنِيــنَ فِى ۱لاَصْفَادِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 52, 'سَرَابِيلُهُم مِّن قَطِرَانٍ وَتَغْشۭيٰ وُجُوهَهُمُ ۴لنَّارُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 53, 'ڤِيَجْزۣيَ ۰للَّهُ كُلَّ نَفْــسٍ مَّا كَسَبَــتِؐ اِنننَّ ۰للَّهَ سَرۣيعُ ۴لْحِسَابببِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (14, 54, 'هَـٰذَا بَچَغٌ لِّلنَّاسِ وَلِيُنذَرُواْ بِهِ” وَلِيَعْلَمُوٓاْ أَنَّمَا هُوَ إِچَهٌ وَ؛حِدٌ وَلِيَذَّكَّرَ ٱُوْلُواْ ۴لاَلْبَـٰــبِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓرۭؐ تِلْكَ ءَايَـٰتُ ۴لْكِتَـٰبِ وَقُرْءَانٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 2, 'رُّبَمَا يَوَدُّ ۴لذِيــنَ كَفَرُواْ لَوْ كَانُواْ مُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 3, 'ذَرْهُمْ يَاكُلُواْ وَيَتَمَتَّعُواْ وَيُلْهِهِمُ ۴لاَمَلُؐ فَسَوْفَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 4, 'وَمَآ أَهْلَكْنَا مِن قَرْيَةٖ اِلاَّ وَلَهَا كِتَابٌ مَّعْلُومٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 5, 'مَّا تَسْبِقُ مِنُ ۷مَّةٖ اَجَلَهَا وَمَا يَسْتَـٰخِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 6, 'وَقَالُواْ يَـٰٓأَيُّهَا ۰ﻟ﮲ نُزّۣلَ عَلَيْهِ ۱لذِّكْرُ إِنَّكَ ڤَمَجْنُونٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 7, 'لَّوْ مَا تَاتِينَا بِالْمَلَئِكَةِ إِن كُنــتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 8, 'مَا تَنَزَّلُ 264 ۴لْمَلَئِكَةُ إِلاَّ بِالْحَـقﱢّؐ وَمَا كَانُوٓاْ إِذاً مُّنظَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 9, 'إِنَّا نَحْنُ نَزَّلْنَا ۰لذِّكْرَؐ وَإِنَّا لَهُ„ لَحَـٰفِظُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 10, 'وَلَقَدَ اَرْسَلْنَا مِن قَبْلِــكَ فِى شِيَعِ ۱لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 11, 'وَمَا يَاتِيهِم مِّن رَّسُولٖ اِلاَّ كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 12, 'كَذَ؛لِــكَ نَسْلُكُهُ„ فِى قُلُوبِ ۱ڤْمُجْرۣمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 13, 'لاَ يُومِنُونَ بِهِ” وَقَدْ خَلَــتْ سُنَّةُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 14, 'وَلَوْ فَتَحْنَا عَلَيْهِم بَاباً مِّــنَ ۰لسَّمَآءِ فَظَلُّواْ فِيهِ يَعْرُجُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 15, 'لَقَالُوٓاْ إِنَّمَا سُكِّرَتتتَ اَبْصَـٰرُنَا بَلْ نَحْنُ قَوْمٌ مَّسْحُورُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 16, 'وَلَقَدْ جَعَلْنَا فِى ۱لسَّمَآءِ بُرُوجاً وَزَيَّنَّـٰهَا لِلنَّـٰظِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 17, 'وَحَفِظْنَـٰهَا مِن كُلِّ شَيْطَـٰنٍ رَّجِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 18, 'اِلاَّ مَـنِ ''سْتَرَقَ ۰لسَّمْعَ فَأَتْبَعَهُ„ شِهَابٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 19, 'وَالاَرْضضضَ مَدَدْنَـٰهَا وَأَلْقَيْنَا فِيهَا رَوَ؛سِيَ وَأَنۢبَتْنَا فِيهَا مِــن كُلِّ شَيْءٍ مَّوْزُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 20, 'وَجَعَلْنَا لَكُمْ فِيهَا مَعَـٰيِشَؐ وَمَن لَّسْتُمْ لَهُ„ بِرَ؛زۣقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 21, 'وَإِن مِّن شَيْءٖ اِلاَّ عِندَنَا خَزَآئِنُهُؐ„ وَمَا نُنَزّۣلُهُ; إِلاَّ بِقَدَرٍ مَّعْلُومٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 22, 'وَأَرْسَلْنَا ۰لرّۣيَـٰحَ لَوَ؛قِحَ فَأَنزَلْنَا مِــنَ ۰لسَّمَآءِ مَآءً فَأَسْقَيْنَـٰكُمُوهُ وَمَآ أَنتُمْ لَهُ„ 265 بِخَـٰزۣنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 23, 'وَإِنَّا ڤَنَحْنُ نُحْىِ” وَنُمِيــتُ وَنَحْنُ ۴لْوَ؛رۣثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 24, 'وَلَقَدْ عَلِمْنَا ۰لْمُسْتَقْدِمِيــنَ مِنكُمْ وَلَقَدْ عَلِمْنَا ۰ڤْمُسْتَـٰخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 25, 'وَإِنَّ رَبَّــكَ هُوَ يَحْشُرُهُمُؐ; إِنَّهُ„ حَكِيم٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 26, 'وَلَقَدْ خَلَقْنَا ۰لِانسَـٰــنَ مِن صَلْصَـٰلٍ مِّنْ حَمَإٍ مَّسْنُونٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 27, 'وَالْجَآنَّ خَلَقْنَـٰهُ مِــن قَبْلُ مِن نّۭارۣ ۱لسَّمُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 28, 'وَإِذْ قَالَ رَبُّــكَ لِلْمَلَئِكَةِ إِنِّى خَـٰلِقٛ بَشَراً مِّــن صَلْصَـٰلٍ مِّنْ حَمَإٍ مَّسْنُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 29, 'فَإِذَا سَوَّيْتُهُ„ وَنَفَخْــتُ فِيهِ مِن رُّوحِى فَقَعُواْ لَهُ„ سَـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 30, 'فَسَجَدَ ۰لْمَلَئِكَةُ كُلُّهُمُ; أَجْمَعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 31, 'إِلٓاَّ إِبْلِيسَ أَبۭيٰٓ أَنْ يَّكُونَ مَعَ ۰لسَّـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 32, 'قَالَ يَـٰٓإِبْلِيــسُ مَا لَكَ أَلاَّ تَكُونَ مَعَ ۰ڤسَّـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 33, 'قَالَ لَمَ اَكُــن لَأِّسْجُدَ لِبَشَر۫ خَلَقْتَهُ„ مِــن صَلْصَـٰلٍ مِّــنْ حَمَإٍ مَّسْنُونٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 34, 'قَالَ فَاخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 35, 'وَإِنَّ عَلَيْــكَ ۰للَّعْنَةَ إِلَيٰ يَوْمِ ۱لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 36, 'قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَيٰ يَوْمِ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 37, 'قَالَ فَإِنَّــكَ مِــنَ ۰لْمُنظَرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 38, 'إِلَيٰ يَوْمِ ۱لْوَقْــتِ ۱لْمَعْلُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 39, 'قَالَ رَبببِّ بِمَآ أَغْوَيْتَنِى لُءَزَيِّنَــنَّ لَهُمْ فِى ۱لاَرْضِ وَلُءَغْوۣيَنَّهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 40, 'إِلاَّ عِبَادَكككَ مِنْهُمُ 266 ۴ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 41, 'قَالَ هَـٰذَا صِرَ؛ط٘ عَلَــيَّ مُسْتَقِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 42, 'اِنننَّ عِبَادِى لَيْــسَ لَــكَ عَلَيْهِمْ سُلْطَـٰــن٘ اِلاَّ مَـنِ ''تَّبَعَكَ مِنَ ۰لْغَاوۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 43, 'وَإِنَّ جَهَنَّمَ لَمَوْعِدُهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 44, 'لَهَا سَبْعَةُ أَبْوَ؛بببٍؐ لِّكُـلِّ بَابٍ مِّنْهُمْ جُزْءٌ مَّقْسُوم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 45, 'اِنَّ ۰لْمُتَّقِيــنَ فِى جَنَّـٰــتٍ وَعُيُونٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 46, '۶دْخُلُوهَا بِسَچَمٖ —امِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 47, 'وَنَزَعْنَا مَا فِى صُدُورۣهِم مِّنْ غِــ۫لّؐ اِخْوَ؛ناٗ عَلَيٰ سُرُرٍ مُّتَقَـٰبِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 48, 'لاَ يَمَسُّهُمْ فِيهَا نَصَبٌؐ وَمَا هُم مِّنْهَا بِمُخْرَجِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 49, '© نَبِّىْٔ عِبَادِيَ أَنِّــيَ أَنَا ۰لْغَفُورُ ۴لرَّحِيمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 50, 'وَأَنَّ عَذَابِى هُوَ ۰لْعَذَابُ ۴لاَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 51, 'وَنَبِّيؔهُمْ عَــن ضَيْفِ إِبْرَ؛هِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 52, 'إِذْ دَخَلُواْ عَلَيْهِ فَقَالُواْ سَچَماًؐ قَالَ إِنَّا مِنكُمْ وَجِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 53, 'قَالُواْ لاَ تَوْجَـلِ اِنَّا نُبَشِّرُكَ بِغُچَمٖ عَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 54, 'قَالَ أَبَشَّرْتُمُونِى عَلَيٰٓ أَن مَّسَّنِــيَ ۰لْكِبَرُ فَبِمَ تُبَشِّرُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 55, 'قَالُواْ بَشَّرْنَـٰكَ بِالْحَقِّ فَلاَ تَكُن مِّنَ ۰لْقَـٰنِطِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 56, 'قَالَ وَمَنْ يَّقْنَطُ مِن رَّحْمَةِ رَبِّهِ“ إِلاَّ ۰لضَّآلُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 57, 'قَالَ فَمَا خَطْبُكُمُ; أَيُّهَا ۰لْمُرْسَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 58, 'قَالُوٓاْ إِنَّآ ٱُرْسِلْنَآ إِلَيٰ 267 قَوْمٍ مُّجْرۣمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 59, 'إِلٓاَّ ءَالَ لُوطٖؐ اِنَّا ڤَمُنَجُّوهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 60, 'إِلاَّ "مْرَأَتَهُ„ قَدَّرْنَآ إِنَّهَا لَمِــنَ ۰لْغَـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 61, 'فَلَمَّا جَآءَ .الَ لُوطٖ ۱لْمُرْسَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 62, 'قَالَ إِنَّكُمْ قَوْمٌ مُّنكَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 63, 'قَالُواْ بَلْ جِيؔنَـٰــكَ بِمَا كَانُواْ فِيهِ يَمْتَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 64, 'وَأَتَيْنَـٰــكَ بِالْحَقِّ وَإِنَّا لَصَـٰدِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 65, 'فَاسْرۣ بِأَهْلِــكَ بِقِطْعٍ مِّنَ ۰ليْلِ وَاتَّبِعَ اَدْبَـٰرَهُمْ وَلاَ يَلْتَفِتْ مِنكُمُ; أَحَدٌ وَامْضُواْ حَيْــثُ تُومَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 66, 'وَقَضَيْنَآ إِلَيْهِ ذَ؛لِــكَ ۰لاَمْرَ أَنَّ دَابِرَ هَـٰٓؤُلآَءِ مَقْطُوعٌ مُّصْبِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 67, 'وَجَآءَ اهْــلُ ۴لْمَدِينَةِ يَسْتَبْشِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 68, 'قَالَ إِنَّ هَـٰٓؤُلآَءِ ضَيْفِى فَلاَ تَفْضَحُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 69, 'وَاتَّقُواْ ۴للَّهَ وَلاَ تُخْزُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 70, 'قَالُوٓاْ أَوَلَمْ نَنْهَكَ عَنِ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 71, 'قَالَ هَـٰٓؤُلآَءِ بَنَاتِيَ إِن كُنتُمْ فَـٰعِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 72, 'لَعَمْرُكككَ إِنَّهُمْ لَفِى سَكْرَتِهِمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 73, 'فَأَخَذَتْهُمُ ۴ڤصَّيْحَةُ مُشْرۣقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 74, 'فَجَعَلْنَا عَـٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهِمْ حِجَارَةً مِّــن سِجِّيــ۫لؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 75, 'اِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰتٍ لِّلْمُتَوَسِّمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 76, 'وَإِنَّهَا لَبِسَبِيلٍ مُّقِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 77, 'اِنننَّ فِى ذَ؛لِــكَ ءَلاَيَةً 268 لِّلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 78, 'وَإِن كَانننَ أَصْحَـٰــبُ ۴لاَيْكَةِ لَظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 79, 'فَانتَقَمْنَا مِنْهُمْؐ وَإِنَّهُمَا لَبِإِمَامٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 80, 'وَلَقَدْ كَذَّبَ أَصْحَـٰــبُ ۴لْحِجْرۣ ۱لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 81, 'وَءَاتَيْنَـٰهُمُ; ءَايَـٰتِنَا فَكَانُواْ عَنْهَا مُعْرۣضِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 82, 'وَكَانُواْ يَنْحِتُونَ مِنَ ۰لْجِبَالِ بُيُوتاٗ —امِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 83, 'فَأَخَذَتْهُمُ ۴ڤصَّيْحَةُ مُصْبِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 84, 'فَمَآ أَغْنۭــيٰ عَنْهُم مَّا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 85, 'وَمَا خَلَقْنَا ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضَ وَمَا بَيْنَهُمَآ إِلاَّ بِالْحَـقﱢّؐ وَإِنننَّ ۰لسَّاعَةَ ءَلاَتِيَةٌؐ فَاصْفَحِ ۱ڤصَّفْحَ ۰لْجَمِيــلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 86, 'إِنَّ رَبَّــكَ هُوَ ۰لْخَـچَّقُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 87, 'وَلَقَدَ —اتَيْنَـٰكَ سَبْعاً مِّــنَ ۰لْمَثَانِى وَالْقُرْءَانَ ۰لْعَظِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 88, 'لاَ تَمُدَّنَّ عَيْنَيْــكَ إِلَــيٰ مَا مَتَّعْنَا بِهِ“ أَزْوَ؛جاً مِّنْهُمْؐ وَلاَ تَحْزَنْ عَلَيْهِمْؐ وَاخْفِضْ جَنَاحَكَ لِلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 89, 'وَقُلِ اِنِّيَ أَنَا ۰لنَّذِيرُ ۴لْمُبِينُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 90, 'كَمَآ أَنزَلْنَا عَلَي ۰لْمُقْتَسِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 91, '۰لذِيــنَ جَعَلُواْ ۴لْقُرْءَانَ عِضِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 92, 'فَوَرَبِّــكَ لَنَسْـَٔلَنَّهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 93, 'عَمَّا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 94, 'فَاصْدَعْ بِمَا تُومَرُؐ وَأَعْرۣضضضْ عَـنِ ۱لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 95, 'إِنَّا كَفَيْنَـٰــكَ ۰لْمُسْتَهْزۣءِينَ 269');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 96, '۰لذِيــنَ يَجْعَلُونَ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَؐ فَسَوْفَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 97, 'وَلَقَدْ نَعْلَمُ أَنَّــكَ يَضِيــقُ صَدْرُكككَ بِمَا يَقُولُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 98, 'فَسَبِّحْ بِحَمْدِ رَبِّــكَ وَكُــن مِّـنَ ۰لسَّـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (15, 99, 'وَاعْبُدْ رَبَّــكَ حَتَّيٰ يَاتِيَــكَ ۰لْيَقِينُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَتۭيٰٓ أَمْرُ ۴للَّهِ فَلاَ تَسْتَعْجِلُوهُؐ سُبْحَـٰنَهُ„ وَتَعَـٰلۭــيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 2, 'يُنَزّۣلُ ۴لْمَلَئِكَةَ بِالرُّوحِ مِنَ اَمْرۣهِ” عَلَيٰ مَنْ يَّشَآءُ مِـنْ عِبَادِهِ“ أَنَ اَنذِرُوٓاْ أَنَّهُ„ لآَ إِچَهَ إِلٓاَّ أَنَا فَاتَّقُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 3, 'خَلَــقَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضَ بِالْحَـقﱢّؐ تَعَـٰلۭــيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 4, 'خَلَقَ ۰لِانسَـٰــنَ مِـن نُّطْفَةٍ فَإِذَا هُوَ خَصِيمٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 5, 'وَالاَنْعَـٰمَ خَلَقَهَاؐ لَكُمْ فِيهَا دِفْءٌ وَمَنَـٰفِعُ وَمِنْهَا تَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 6, 'وَلَكُمْ فِيهَا جَمَال٘ حِينَ تُرۣيحُونَ وَحِيــنَ تَسْرَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 7, 'وَتَحْمِــلُ أَثْقَالَكُمُ; إِلَيٰ بَلَدٍ لَّمْ تَكُونُواْ بَـٰلِغِيهِ إِلاَّ بِشِقِّ ۱لاَنفُسِؐ إِنَّ رَبَّكُمْ لَرَءُوفٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 8, 'وَالْخَيْلَ وَالْبِغَالَ وَالْحَمِيرَ لِتَرْكَبُوهَا وَزۣينَةًؐ 270 وَيَخْلُقُ مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 9, 'وَعَلَــي ۰للَّهِ قَصْدُ ۴لسَّبِيلِ وَمِنْهَا جَآئِرٌؐ وَلَوْ شَآءَ لَهَدۭيٰكُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 10, 'هُوَ ۰ﻟـذِىٓ أَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءً لَّكُم مِّنْهُ شَرَابببٌ وَمِنْهُ شَجَرٌ فِيهِ تُسِيمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 11, 'يُنۢبِــتُ لَكُم بِهِ ۱لزَّرْعَ وَالزَّيْتُونَ وَاڤنَّخِيلَ وَالاَعْنَـٰــبَ وَمِــن كُــلّۣ ۱لثَّمَرَ؛تِؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 12, 'وَسَخَّرَ لَكُمُ ۴ليْلَ وَالنَّهَارَ وَالشَّمْسَ وَالْقَمَرَ وَالنُّجُومَ مُسَخَّرَ؛تٙ بِأَمْرۣهِؐ“ إِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 13, 'وَمَا ذَرَأَ لَكُمْ فِى ۱لاَرْضضضِ مُخْتَلِفاٗ اَلْوَ؛نُهُؐ; إِنننَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّقَوْمٍ يَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 14, 'وَهُوَ ۰ﻟ﮲ سَخَّرَ ۰ڤْبَحْرَ لِتَاكُلُواْ مِنْهُ لَحْماً طَرۣيّاً وَتَسْتَخْرۣجُواْ مِنْهُ حِلْيَةً تَلْبَسُونَهَاؐ وَتَرَي ۰لْفُلْكَ مَوَاخِرَ فِيهِ وَلِتَبْتَغُواْ مِن فَضْلِهِ” وَلَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 15, 'وَأَلْقۭـيٰ فِى ۱لاَرْضِ رَوَ؛سِيَ أَن تَمِيدَ بِكُمْ وَأَنْهَـٰراً وَسُبُلًا لَّعَلَّكُمْ تَهْتَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 16, 'وَعَچَمَـٰـــتٍؐ وَبِاڤنَّجْمِ هُمْ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 17, 'أَفَمَــنْ يَّخْلُقُ كَمَــن لاَّ يَخْلُقُؐ أَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 18, 'وَإِن تَعُدُّواْ نِعْمَةَ ۰للَّهِ لاَ تُحْصُوهَآؐ إِنننَّ ۰للَّهَ لَغَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 19, '271 وَاللَّهُ يَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 20, 'وَالذِيــنَ تَدْعُونَ مِن دُونِ ۱للَّهِ لاَ يَخْلُقُونَ شَيْـٔاً وَهُمْ يُخْلَقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 21, 'أَمْوَ؛ت٘ غَيْرُ أَحْيَآءٍؐ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 22, 'إِچَهُكُمُ; إِچَهٌ وَ؛حِدٌؐ فَالذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ قُلُوبُهُم مُّنكِرَةٌ وَهُم مُّسْتَكْبِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 23, 'لاَ جَرَمَ أَنننَّ ۰للَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَؐ إِنَّهُ„ لاَ يُحِبُّ ۴لْمُسْتَكْبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 24, 'وَإِذَا قِيــلَ لَهُم مَّاذَآ أَنزَلَ رَبُّكُمْ قَالُوٓاْ أَسَـٰطِيرُ ۴لاَوَّلِيـنَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 25, 'ڤِيَحْمِلُوٓاْ أَوْزَارَهُمْ كَامِلَةً يَوْمَ ۰لْقِيَـٰمَةِ وَمِنَ اَوْزۭارۣ ۱لذِيــنَ يُضِلُّونَهُم بِغَيْرۣ عِلْمٖؐ اَلاَ سَآءَ مَا يَزۣرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 26, 'قَدْ مَكَرَ ۰لذِيــنَ مِـن قَبْلِهِمْ فَأَتَــي ۰للَّهُ بُنْيَـٰنَهُم مِّنَ ۰لْقَوَاعِدِ فَخَرَّ عَلَيْهِمُ ۴لسَّقْفُ مِن فَوْقِهِمْ وَأَتۭيٰهُمُ ۴لْعَذَابُ مِــنْ حَيْــثُ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 27, 'ثُمَّ يَوْمَ ۰لْقِيَـٰمَةِ يُخْزۣيهِمْ وَيَقُولُ أَيْنَ شُرَكَآءِيَ ۰لذِينَ كُنتُمْ تُشَـٰٓـقُّونِ فِيهِمْؐ قَالَ ۰لذِينَ ٱُوتُواْ ۴لْعِلْمَ إِنَّ ۰لْخِزْيَ ۰لْيَوْمَ وَالسُّوٓءَ عَلَــي ۰لْكۭـٰفِـرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 28, '۰لذِيــنَ تَتَوَفّۭيٰهُمُ ۴لْمَلَئِكَةُ ظَالِمِىٓ أَنفُسِهِمْؐ فَأَلْقَوُاْ ۴لسَّلَمَ مَا كُنَّا نَعْمَلُ 272 مِن سُوٓءٙ بَلۭيٰٓؐ إِنَّ ۰للَّهَ عَلِيمٛ بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 29, 'فَادْخُلُوٓاْ أَبْوَ؛بَ جَهَنَّمَ خَـٰلِدِينَ فِيهَاؐ فَلَبِيــسَ مَثْوَي ۰لْمُتَكَبِّرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 30, '© وَقِيلَ لِلذِيــنَ "تَّقَوْاْ مَاذَآ أَنزَلَ رَبُّكُمْ قَالُواْ خَيْراًؐ لِّلذِيــنَ أَحْسَنُواْ فِى هَـٰذِهِ ۱لدُّنْيۭا حَسَنَةٌؐ وَلَدَارُ ۴لاَخِرَةِ خَيْرٌؐ وَلَنِعْمَ دَارُ ۴لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 31, 'جَنَّـٰــتُ عَدْنٍ يَدْخُلُونَهَا تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ لَهُمْ فِيهَا مَا يَشَآءُونَؐ كَذَ؛لِــكَ يَجْزۣى ۱للَّهُ ۴لْمُتَّقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 32, '۰لذِيــنَ تَتَوَفّۭيٰهُمُ ۴لْمَلَئِكَةُ طَيِّبِيــنَؐ يَقُولُونَ سَچَم٘ عَلَيْكُمُ ۶دْخُلُواْ ۴لْجَنَّةَ بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 33, 'هَـلْ يَنظُرُونَ إِلٓاَّ أَن تَاتِيَهُمُ ۴لْمَلَئِكَةُ أَوْ يَاتِــيَ أَمْرُ رَبِّــكَؐ كَذَ؛لِــكَ فَعَلَ ۰لذِيــنَ مِـن قَبْلِهِمْؐ وَمَا ظَلَمَهُمُ ۴للَّهُؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 34, 'فَأَصَابَهُمْ سَيِّـَٔاتُ مَا عَمِلُواْؐ وَحَاقَ بِهِم مَّا كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 35, 'وَقَالَ ۰لذِيــنَ أَشْرَكُواْ لَوْ شَآءَ ۰للَّهُ مَا عَبَدْنَا مِــن دُونِهِ” مِن شَيْءٍ نَّحْنُ وَلآَ ءَابَآؤُنَا وَلاَ حَرَّمْنَا مِن دُونِهِ” مِن شَيْءٍؐ كَذَ؛لِكَ فَعَلَ ۰لذِيــنَ مِن قَبْلِهِمْؐ فَهَــلْ عَلَي ۰لرُّسُلِ 27 إِلاَّ ۰لْبَچَغُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 36, 'وَلَقَدْ بَعَثْنَا فِى كُــلّۣ ٱُمَّةٍ رَّسُولٗا اَنُ ۶عْبُدُواْ ۴للَّهَ وَاجْتَنِبُواْ ۴لطَّـٰغُوتَؐ فَمِنْهُم مَّــنْ هَدَي ۰للَّهُؐ وَمِنْهُم مَّــنْ حَقَّــتْ عَلَيْهِ ۱لضَّچَلَةُؐ فَسِيرُواْ فِى ۱لاَرْضِ فَانظُرُواْ كَيْفَ كَانننَ عَـٰقِبَةُ ۴لْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 37, 'إِن تَحْرۣصْ عَلَيٰ هُدۭيٰهُمْ فَإِنننَّ ۰للَّهَ لاَ يُهْدۭيٰ مَنْ يُّضِلُّؐ وَمَا لَهُم مِّن نَّــٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 38, 'وَأَقْسَمُواْ بِاللَّهِ جَهْدَ أَيْمَـٰنِهِمْ لاَ يَبْعَــثُ ۴للَّهُ مَنْ يَّمُوتُؐ بَلۭيٰ وَعْداٗ عَلَيْهِ حَقّاً وَچَكِــنَّ أَكْثَرَ ۰لنَّاسِ لاَ يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 39, 'لِيُبَيِّــنَ لَهُمُ ۴ﻟ﮲ يَخْتَلِفُونَ فِيهِ وَلِيَعْلَمَ ۰لذِيــنَ كَفَرُوٓاْ أَنَّهُمْ كَانُواْ كَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 40, 'إِنَّمَا قَوْلُنَا لِشَىْءٖ اِذَآ أَرَدْنَـٰهُ أَن نَّقُولَ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 41, 'وَالذِيــنَ هَاجَرُواْ فِى ۱للَّهِ مِـنۢ بَعْدِ مَا ظُلِمُواْ لَنُبَوّۣيؕنَّهُمْ فِى ۱لدُّنْيۭا حَسَنَةًؐ وَلَأَجْرُ ۴لاَخِرَةِ أَكْبَرُ لَوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 42, '۰لذِيــنَ صَبَرُواْ وَعَلَيٰ رَبِّهِمْ يَتَوَكَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 43, 'وَمَآ أَرْسَلْنَا مِن قَبْلِكَ إِلاَّ رۣجَالًا يُوحۭيٰٓ إِلَيْهِمْ فَسْـَٔلُوٓاْ أَهْلَ ۰لذِّكْرۣ إِن كُنتُمْ لاَ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 44, 'بِالْبَيِّنَـٰــتِ وَالزُّبُـرۣؐ وَأَنزَلْنَآ إِلَيْكَ ۰لذِّكْرَ لِتُبَيِّنَ 274 لِلنَّاسسسِ مَا نُزّۣلَ إِلَيْهِمْ وَلَعَلَّهُمْ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 45, 'أَفَأَمِــنَ ۰لذِينَ مَكَرُواْ ۴لسَّيِّـَٔاتِ أَنننْ يَّخْسِفَ ۰للَّهُ بِهِمُ ۴لاَرْضَ أَوْ يَاتِيَهُمُ ۴لْعَذَابببُ مِــنْ حَيْثُ لاَ يَشْعُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 46, 'أَوْ يَاخُذَهُمْ فِى تَقَلُّبِهِمْ فَمَا هُم بِمُعْجِزۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 47, 'أَوْ يَاخُذَهُمْ عَلَيٰ تَخَوُّفٍؐ فَإِنَّ رَبَّكُمْ لَرَءُوفٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 48, 'اَوَلَمْ يَرَوۣاْ اِلَــيٰ مَا خَلَقَ ۰للَّهُ مِن شَيْءٍ يَتَفَيَّؤُاْ ظِچَلُهُ„ عَنِ ۱لْيَمِينِ وَالشَّمَآئِــلۣ سُجَّداً لِّلهِ وَهُمْ دَ؛خِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 49, 'وَلِلهِ يَسْجُدُ مَا فِى ۱لسَّمَـٰوَ؛تتتِ وَمَا فِى ۱لاَرْضِ مِن دَآبَّةٍ وَالْمَلَئِكَةُ وَهُمْ لاَ يَسْتَكْبِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 50, 'يَخَافُونَ رَبَّهُم مِّن فَوْقِهِمْ وَيَفْعَلُونَ مَا يُومَرُونَؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 51, '¤ وَقَالَ ۰للَّهُ لاَ تَتَّخِذُوٓاْ إِچَهَيْـنِ ''ثْنَيْــنۣؐ إِنَّمَا هُوَ إِچَهٌ وَ؛حِدٌؐ فَإِيَّـٰيَ فَارْهَبُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 52, 'وَلَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَلَهُ ۴لدِّينُ وَاصِباٗؐ اَفَغَيْرَ ۰للَّهِ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 53, 'وَمَا بِكُم مِّــن نِّعْمَةٍ فَمِــنَ ۰للَّهِؐ ثُمَّ إِذَا مَسَّكُمُ ۴لضُّرُّ فَإِلَيْهِ تَجْــَٔـرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 54, 'ثُمَّ إِذَا كَشَفَ ۰لضُّرَّ عَنكُمُ; إِذَا فَرۣيـقٌ مِّنكُم بِرَبِّهِمْ يُشْرۣكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 55, 'لِيَكْفُرُواْ بِمَآ ءَاتَيْنَـٰهُمْؐ فَتَمَتَّعُواْؐ فَسَوْفَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 56, 'وَيَجْعَلُونَ لِمَا 275 لاَ يَعْلَمُونَ نَصِيباً مِّمَّا رَزَقْنَـٰهُمْؐ تَاللَّهِ لَتُسْــَٔلُــنَّ عَمَّا كُنتُمْ تَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 57, 'وَيَجْعَلُونَ لِلهِ ۱لْبَنَـٰــتِ سُبْحَـٰنَهُؐ„ وَلَهُم مَّا يَشْتَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 58, 'وَإِذَا بُشِّرَ أَحَدُهُم بِالاُنثۭــيٰ ظَلَّ وَجْهُهُ„ مُسْوَدّاً وَهُوَ كَظِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 59, 'يَتَوَ؛رۭيٰ مِنَ ۰لْقَوْمِ مِن سُوٓءِ مَا بُشِّرَ بِهِؐ“ أَيُمْسِكُهُ„ عَلَيٰ هُونٖ اَمْ يَدُسُّهُ„ فِى ۱لتُّرَابِؐ أَلاَ سَآءَ مَا يَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 60, 'لِلذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ مَثَلُ ۴لسَّوْءِؐ وَلِلهِ ۱لْمَثَــلُ ۴لاَعْلۭيٰؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 61, 'وَلَوْ يُوَ۬اخِذُ ۴للَّهُ ۴لنَّاسسسَ بِظُلْمِهِم مَّا تَرَكَ عَلَيْهَا مِــن دَآبَّةٍؐ وَچَكِنْ يُّوَ۬خِّرُهُمُ; إِلَـيٰٓ أَجَــلٍ مُّسَمّيًؐ فَإِذَا جَآءَ اجَلُهُمْ لاَ يَسْتَـٰخِرُونَ سَاعَةًؐ وَلاَ يَسْتَقْدِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 62, 'وَيَجْعَلُونَ لِلهِ مَا يَكْرَهُونَؐ وَتَصِفُ أَلْسِنَتُهُمُ ۴لْكَذِبببَ أَنننَّ لَهُمُ ۴لْحُسْنۭيٰؐ لاَ جَرَمَ أَنننَّ لَهُمُ ۴لنَّارَ وَأَنَّهُم مُّفْرۣطُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 63, 'تَاللَّهِ لَقَدَ اَرْسَلْنَآ إِلَيٰٓ ٱُمَمٍ مِّــن قَبْلِــكَ فَزَيَّــنَ لَهُمُ ۴لشَّيْطَـٰــنُ أَعْمَـٰلَهُمْ فَهُوَ وَلِيُّهُمُ ۴لْيَوْمَؐ وَلَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 64, 'وَمَآ أَنزَلْنَا عَلَيْكَ ۰لْكِتَـٰــبَ إِلاَّ لِتُبَيِّــنَ لَهُمُ ۴ﻟ﮲ ''خْتَلَفُواْ فِيهِ 276 وَهُديً وَرَحْمَةً لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 65, 'وَاللَّهُ أَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءً فَأَحْيۭا بِهِ ۱لاَرْضضضَ بَعْدَ مَوْتِهَآؐ إِنَّ فِى ذَ؛لِكَ ءَلاَيَةً لِّقَوْمٍ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 66, 'وَإِنَّ لَكُمْ فِى ۱لاَنْعَـٰمِ لَعِبْرَةًؐ نَّسْقِيكُم مِّمَّا فِى بُطُونِهِ” مِنۢ بَيْنِ فَرْثثثٍ وَدَمٍ لَّبَـﻨـاٗ خَالِصاً سَآئِغاً لِّلشَّـٰرۣبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 67, 'وَمِن ثَمَرَ؛تِ ۱لنَّخِيلِ وَالاَعْنَـٰــبِ تَتَّخِذُونننَ مِنْهُ سَكَراً وَرۣزْقاٗ حَسَناٗؐ اِنَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 68, 'وَأَوْحۭيٰ رَبُّــكَ إِلَــي ۰ڤنَّحْلِ أَنِ ''تَّخِذِى مِنَ ۰لْجِبَالِ بُيُوتاً وَمِنَ ۰ڤشَّجَرۣ وَمِمَّا يَعْرۣشُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 69, 'ثُمَّ كُلِى مِــن كُــلّۣ ۱لثَّمَرَ؛تتتِ فَاسْلُكِى سُبُلَ رَبِّــكِ ذُلُلًؐا يَخْرُجُ مِـنۢ بُطُونِهَا شَرَابببٌ مُّخْتَلِف٘ اَلْوَ؛نُهُ„ فِيهِ شِفَآءٌ لِّلنَّاسِؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 70, 'وَاللَّهُ خَلَقَكُمْ ثُمَّ يَتَوَفّۭيٰكُمْؐ وَمِنكُم مَّنْ يُّرَدُّ إِلَيٰٓ أَرْذَلِ ۱لْعُمُرۣ لِكَىْ لاَ يَعْلَمَ بَعْدَ عِلْمٍ شَيْـٔاٗؐ اِنننَّ ۰للَّهَ عَلِيمٌ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 71, '© وَاللَّهُ فَضَّلَ بَعْضَكُمْ عَلَيٰ بَعْضٍ فِى ۱لرّۣزْقِؐ فَمَا ۰لذِيــنَ فُضِّلُواْ بِرَآدِّځ رۣزْقِهِمْ عَلَــيٰ مَا مَلَكَــتَ اَيْمَـٰنُهُمْ فَهُمْ فِيهِ سَوَآء٘ؐ اَفَبِنِعْمَةِ ۱للَّهِ يَجْحَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 72, 'وَاللَّهُ جَعَــلَ لَكُم 277 مِّــنَ اَنفُسِكُمُ; أَزْوَ؛جاً وَجَعَــلَ لَكُم مِّنَ اَزْوَ؛جِكُم بَنِينَ وَحَفَدَةًؐ وَرَزَقَكُم مِّــنَ ۰لطَّيِّبَـٰتِؐ أَفَبِالْبَـٰطِلِ يُومِنُونَ وَبِنِعْمَــتِ ۱للَّهِ هُمْ يَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 73, 'وَيَعْبُدُونَ مِــن دُونِ ۱للَّهِ مَا لاَ يَمْلِــكُ لَهُمْ رۣزْقاً مِّــنَ ۰لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِ شَيْـٔاً وَلاَ يَسْتَطِيعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 74, 'فَلاَ تَضْرۣبُواْ لِلهِ ۱لاَمْثَالَؐ إِنننَّ ۰للَّهَ يَعْلَمُؐ وَأَنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 75, 'ضَرَبَ ۰للَّهُ مَثَلٗا عَبْداً مَّمْلُوكاً لاَّ يَقْدِرُ عَلَيٰ شَيْءٍ وَمَن رَّزَقْنَـٰهُ مِنَّا رۣزْقاٗ حَسَناً فَهُوَ يُنفِـقُ مِنْهُ سِرّاً وَجَهْراٗ هَلْ يَسْتَوُﹼنَؐ ۰لْحَمْدُ لِلهِؐ بَلَ اَكْثَرُهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 76, 'وَضَرَبَ ۰للَّهُ مَثَلًا رَّجُلَيْنِ أَحَدُهُمَآ أَبْكَمُ لاَ يَقْدِرُ عَلَيٰ شَيْءٍ وَهُوَ كَلّﹲ عَلَيٰ مَوْلۭيٰهُ أَيْنَمَا يُوَجِّههُّ لاَ يَاتِ بِخَيْر۫هَلْ يَسْتَوۣى هُوَ وَمَـنْ يَّامُرُ بِالْعَدْلِ وَهُوَ عَلَــيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 77, 'وَلِلهِ غَيْــبُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَمَآ أَمْرُ ۴لسَّاعَةِ إِلاَّ كَڤَمْحِ ۱لْبَصَرۣ أَوْ هُوَ أَقْرَبببُؐ إِنننَّ ۰للَّهَ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 78, 'وَاللَّهُ أَخْرَجَكُم مِّنۢ بُطُونِ ٱُمَّهَـٰتِكُمْ لاَ تَعْلَمُونَ شَيْـٔاًؐ وَجَعَــلَ لَكُمُ ۴لسَّمْعَ 278 وَالاَبْصَـٰرَ وَالاَفْـِٕدَةَ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 79, 'أَلَمْ يَرَوۣاْ اِلَــي ۰لطَّيْرۣ مُسَخَّرَ؛تٍ فِى جَوّۣ ۱لسَّمَآءِ مَا يُمْسِكُهُنَّ إِلاَّ ۰للَّهُؐ إِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 80, 'وَاللَّهُ جَعَلَ لَكُم مِّنۢ بُيُوتِكُمْ سَكَناً وَجَعَــلَ لَكُم مِّن جُلُودِ ۱لاَنْعَـٰمِ بُيُوتاً تَسْتَخِفُّونَهَا يَوْمَ ظَعَنِكُمْ وَيَوْمَ إِقَامَتِكُمْؐ وَمِنَ اَصْوَافِهَا وَأَوْبۭارۣهَا وَأَشْعۭارۣهَآ أَثَـٰثاً وَمَتَـٰعاٗ اِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 81, 'وَاللَّهُ جَعَــلَ لَكُم مِّمَّا خَلَقَ ظِچَلًا وَجَعَــلَ لَكُم مِّنَ ۰لْجِبَالِ أَكْنَـٰناً وَجَعَــلَ لَكُمْ سَرَ؛بِيلَ تَقِيكُمُ ۴لْحَرَّ وَسَرَ؛بِيلَ تَقِيكُم بَأْسَكُمْؐ كَذَ؛لِــكَ يُتِمُّ نِعْمَتَهُ„ عَلَيْكُمْ لَعَلَّكُمْ تُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 82, 'فَإِن تَوَلَّوْاْ فَإِنَّمَا عَلَيْكَ ۰لْبَچَغُ ۴لْمُبِيـنُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 83, 'يَعْرۣفُونَ نِعْمَــتَ ۰للَّهِ ثُمَّ يُنكِرُونَهَاؐ وَأَكْثَرُهُمُ ۴لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 84, 'وَيَوْمَ نَبْعَــثُ مِــن كُــلّۣ ٱُمَّةٍ شَهِيداً ثُمَّ لاَ يُوذَنُ لِلذِينَ كَفَرُواْ وَلاَ هُمْ يُسْتَعْتَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 85, 'وَإِذَا رَءَا ۰لذِينَ ظَلَمُواْ ۴لْعَذَابَ فَلاَ يُخَفَّفُ عَنْهُمْ وَلاَ هُمْ يُنظَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 86, 'وَإِذَا رَءَا ۰لذِيــنَ أَشْرَكُواْ شُرَكَآءَهُمْ قَالُواْ رَبَّنَا 279 هَـٰٓؤُلآَءِ شُرَكَآؤُنَا ۰لذِيــنَ كُنَّا نَدْعُواْ مِــن دُونِــكَؐ فَأَلْقَوۣاْ اِلَيْهِمُ ۴لْقَوْلَ إِنَّكُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 87, 'وَأَلْقَوۣاْ اِلَــي ۰للَّهِ يَوْمَئِذٖ ۱لسَّلَمَؐ وَضَــلَّ عَنْهُم مَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 88, '۰لذِينَ كَفَرُواْ وَصَدُّواْ عَــن سَبِيلِ ۱للَّهِ زۣدْنَـٰهُمْ عَذَاباً فَوْقَ ۰لْعَذَابِ بِمَا كَانُواْ يُفْسِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 89, 'وَيَوْمَ نَبْعَثُ فِى كُلِّ ٱُمَّةٍ شَهِيداٗ عَلَيْهِم مِّــنَ اَنفُسِهِمْ وَجِيؔنَا بِكَ شَهِيداٗ عَلَيٰ هَـٰٓؤُلآَءِؐ وَنَزَّلْنَا عَلَيْــكَ ۰لْكِتَـٰــبَ تِبْيَـٰناً لِّكُــلّۣ شَيْءٍ وَهُديً وَرَحْمَةً وَبُشْرۭيٰ لِلْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 90, '¥ إِنننَّ ۰للَّهَ يَامُرُ بِالْعَدْلِ وَالِاحْسَـٰنِ وَإِيتَآءِىْ ذى ۱لْقُرْبۭيٰؐ وَيَنْهۭــيٰ عَنِ ۱ڤْفَحْشَآءِ وَالْمُنكَرۣ وَالْبَغْيِؐ يَعِظُكُمْ لَعَلَّكُمْ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 91, 'وَأَوْفُواْ بِعَهْدِ ۱للَّهِ إِذَا عَـٰهَدتُّمْؐ وَلاَ تَنقُضُواْ ۴لاَيْمَـٰــنَ بَعْدَ تَوْكِيدِهَا وَقَدْ جَعَلْتُمُ ۴للَّهَ عَلَيْكُمْ كَفِيلٗؐا اِنننَّ ۰للَّهَ يَعْلَمُ مَا تَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 92, 'وَلاَ تَكُونُواْ كَالتِى نَقَضَــتْ غَزْلَهَا مِـنۢ بَعْدِ قُوَّةٖ اَنكَـٰثاً تَتَّخِذُونَ أَيْمَـٰنَكُمْ دَخَلَۢا بَيْنَكُمُ; أَن تَكُونَ ٱُمَّة٘ هِيَ أَرْبۭــيٰ مِنُ ۷مَّةٖؐ اِنَّمَا يَبْلُوكُمُ ۴للَّهُ بِهِؐ” 280 وَلَيُبَيِّنَــنَّ لَكُمْ يَوْمَ ۰لْقِيَـٰمَةِ مَا كُنتُمْ فِيهِ تَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 93, 'وَلَوْ شَآءَ ۰للَّهُ لَجَعَلَكُمُ; ٱُمَّةً وَ؛حِدَةًؐ وَچَكِنْ يُّضِلُّ مَنْ يَّشَآءُ وَيَهْدِى مَـنْ يَّشَآءُؐ وَلَتُسْـَٔلُــنَّ عَمَّا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 94, 'وَلاَ تَتَّخِذُوٓاْ أَيْمَـٰنَكُمْ دَخَلَۢا بَيْنَكُمْ فَتَزۣلَّ قَدَمٛ بَعْدَ ثُبُوتِهَا وَتَذُوقُواْ ۴لسُّوٓءَ بِمَا صَدَدتُّمْ عَــن سَبِيـلِ ۱للَّهِ وَلَكُمْ عَذَاببب٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 95, 'وَلاَ تَشْتَرُواْ بِعَهْدِ ۱للَّهِ ثَمَناً قَلِيلٗؐا اِنَّمَا عِندَ ۰للَّهِ هُوَ خَيْرٌ لَّكُمُ; إِن كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 96, 'مَا عِندَكُمْ يَنفَدُؐ وَمَا عِندَ ۰للَّهِ بَاقٍؐ وَڤَيَجْزۣيَــنَّ ۰لذِيــنَ صَبَرُوٓاْ أَجْرَهُم بِأَحْسَـنِ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 97, 'مَــنْ عَمِــلَ صَـٰڤِحاً مِّن ذَكَر۫ اَوُ ۷نثۭيٰ وَهُوَ مُومِــنٌ فَڤَنُحْيِيَنَّهُ„ حَيَوٰةً طَيِّبَةً وَڤَنَجْزۣيَنَّهُمُ; أَجْرَهُم بِأَحْسَـنِ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 98, 'فَإِذَا قَرَأْتَ ۰لْقُرْءَانَ فَاسْتَعِذْ بِاللَّهِ مِــنَ ۰لشَّيْطَـٰنِ ۱لرَّجِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 99, 'إِنَّهُ„ لَيْــسَ لَهُ„ سُلْطَـٰــن٘ عَلَي ۰لذِيــنَ ءَامَنُواْ وَعَلَيٰ رَبِّهِمْ يَتَوَكَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 100, 'إِنَّمَا سُلْطَـٰنُهُ„ عَلَــي ۰لذِينَ يَتَوَلَّوْنَهُ„ وَالذِينَ هُم بِهِ” مُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 101, 'وَإِذَا بَدَّلْنَآ ءَايَةً مَّكَانَ 281 ءَايَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزّۣلُ قَالُوٓاْ إِنَّمَآ أَنتَ مُفْتَرٙؐ بَلَ اَكْثَرُهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 102, 'قُلْ نَزَّلَهُ„ رُوحُ ۴لْقُدُسِ مِن رَّبِّــكَ بِالْحَقِّ لِيُثَبِّــتَ ۰لذِيــنَ ءَامَنُواْ وَهُديً وَبُشْرۭيٰ لِلْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 103, 'وَلَقَدْ نَعْلَمُ أَنَّهُمْ يَقُولُونَ إِنَّمَا يُعَلِّمُهُ„ بَشَرٌؐ لِّسَانُ ۴ﻟ﮲ يُڤْحِدُونَ إِلَيْهِ أَعْجَمِيٌّ وَهَـٰذَا لِسَان٘ عَرَبِــيٌّ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 104, 'اِنَّ ۰لذِيــنَ لاَ يُومِنُونَ بِـَٔايَـٰــتِ ۱للَّهِ لاَ يَهْدِيهِمُ ۴للَّهُؐ وَلَهُمْ عَذَاب٘ اَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 105, 'اِنَّمَا يَفْتَرۣى ۱لْكَذِبَ ۰لذِينَ لاَ يُومِنُونَ بِـَٔايَـٰتِ ۱للَّهِؐ وَٱُوْلَئِــكَ هُمُ ۴لْكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 106, 'مَن كَفَرَ بِاللَّهِ مِـنۢ بَعْدِ إِيمَـٰنِهِ“ إِلاَّ مَــنُ ۷كْرۣهَ وَقَلْبُهُ„ مُطْمَئِنّٛ بِالِايمَـٰنِؐ وَچَكِــن مَّـن شَرَحَ بِالْكُفْرۣ صَدْراً فَعَلَيْهِمْ غَضَــبٌ مِّــنَ ۰للَّهِؐ وَلَهُمْ عَذَاب٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 107, 'ذَ؛لِــكَ بِأَنَّهُمُ èسْتَحَبُّواْ ۴لْحَيَوٰةَ ۰لدُّنْيۭا عَلَــي ۰لاَخِرَةِ وَأَنننَّ ۰للَّهَ لاَ يَهْدِى ۱لْقَوْمَ ۰لْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 108, 'ٱُوْلَئِــكَ ۰لذِيــنَ طَبَعَ ۰للَّهُ عَلَــيٰ قُلُوبِهِمْ وَسَمْعِهِمْ وَأَبْصۭـٰرۣهِمْؐ وَٱُوْلَئِكَ هُمُ ۴لْغَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 109, 'لاَ جَرَمَ أَنَّهُمْ فِى ۱لاَخِرَةِ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 110, 'ثُمَّ إِنَّ رَبَّكَ 282 لِلذِيــنَ هَاجَرُواْ مِـنۢ بَعْدِ مَا فُتِنُواْ ثُمَّ جَـٰهَدُواْ وَصَبَرُوٓاْ إِنَّ رَبَّــكَ مِـنۢ بَعْدِهَا لَغَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 111, '© يَوْمَ تَاتِى كُلُّ نَفْسٍ تُجَـٰدِلُ عَن نَّفْسِهَا وَتُوَفّۭــيٰ كُلُّ نَفْسٍ مَّا عَمِلَتْ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 112, 'وَضَرَبَ ۰للَّهُ مَثَلًا قَرْيَةً كَانَتَ —امِنَةً مُّطْمَئِنَّةً يَاتِيهَا رۣزْقُهَا رَغَداً مِّــن كُــلّۣ مَكَانٍ فَكَفَرَتْ بِأَنْعُمِ ۱للَّهِ فَأَذَاقَهَا ۰للَّهُ لِبَاسَ ۰لْجُوعِ وَالْخَوْفِ بِمَا كَانُواْ يَصْنَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 113, 'وَلَقَدْ جَآءَهُمْ رَسُولٌ مِّنْهُمْ فَكَذَّبُوهُ فَأَخَذَهُمُ ۴لْعَذَابُ وَهُمْ ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 114, 'فَكُلُواْ مِمَّا رَزَقَكُمُ ۴للَّهُ حَچَلًا طَيِّباًؐ وَاشْكُرُواْ نِعْمَــتَ ۰للَّهِ إِننن كُنتُمُ; إِيَّاهُ تَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 115, 'إِنَّمَا حَرَّمَ عَلَيْكُمُ ۴لْمَيْتَةَ وَالدَّمَ وَلَحْمَ ۰لْخِنزۣيرۣ وَمَآ ٱُهِلَّ لِغَيْرۣ ۱للَّهِ بِهِؐ” فَمَــنُ ۶ضْطُرَّ غَيْرَ بَاغٍ وَلاَ عَادٍ فَإِنننَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 116, 'وَلاَ تَقُولُواْ لِمَا تَصِفُ أَلْسِنَتُكُمُ ۴لْكَذِبَ هَـٰذَا حَچَلٌ وَهَـٰذَا حَرَامٌ لِّتَفْتَرُواْ عَلَــي ۰للَّهِ ۱لْكَذِبببَؐ إِنَّ ۰لذِينَ يَفْتَرُونَ عَلَــي ۰للَّهِ ۱لْكَذِبببَ لاَ يُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 117, 'مَتَـٰعٌ قَلِيلٌؐ وَلَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 118, '28 وَعَلَــي ۰لذِيــنَ هَادُواْ حَرَّمْنَا مَا قَصَصْنَا عَلَيْكَ مِــن قَبْلُؐ وَمَا ظَلَمْنَـٰهُمْؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 119, 'ثُمَّ إِنَّ رَبَّــكَ لِلذِيــنَ عَمِلُواْ ۴لسُّوٓءَ بِجَهَـٰلَةٍ ثُمَّ تَابُواْ مِنۢ بَعْدِ ذَ؛لِكَ وَأَصْڤَحُوٓاْ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 120, 'اِنَّ إِبْرَ؛هِيمَ كَانَ ٱُمَّةً قَانِتاً لِّلهِ حَنِيفاً وَلَمْ يَكُ مِنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 121, 'شَاكِراً لَأِّنْعُمِهِؐ ''جْتَبۭيٰهُ وَهَدۭيٰهُ إِلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 122, 'وَءَاتَيْنَـٰهُ فِى ۱لدُّنْيۭا حَسَنَةًؐ وَإِنَّهُ„ فِى ۱لاَخِرَةِ لَمِــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 123, 'ثُمَّ أَوْحَيْنَآ إِلَيْــكَ أَنِ ''تَّبِعْ مِلَّةَ إِبْرَ؛هِيمَ حَنِيفاًؐ وَمَا كَانَ مِــنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 124, 'إِنَّمَا جُعِلَ ۰لسَّبْــتُ عَلَي ۰لذِينَ "خْتَلَفُواْ فِيهِؐ وَإِنَّ رَبَّــكَ ڤَيَحْكُمُ بَيْنَهُمْ يَوْمَ ۰لْقِيَـٰمَةِ فِيمَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 125, '۸دْعُ إِلَيٰ سَبِيلِ رَبِّــكَ بِالْحِكْمَةِ وَالْمَوْعِظَةِ ۱لْحَسَنَةِ وَجَـٰدِلْهُم بِالتِى هِيَ أَحْسَـنُؐ إِنَّ رَبَّــكَ هُوَ أَعْلَمُ بِمَــن ضَلَّ عَن سَبِيلِهِؐ” وَهُوَ أَعْلَمُ بِالْمُهْتَدِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 126, 'وَإِنْ عَاقَبْتُمْ فَعَاقِبُواْ بِمِثْــلۣ مَا عُوقِبْتُم بِهِؐ” وَلَـئِــن صَبَرْتُمْ لَهُوَ خَيْرٌ لِّلصَّـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 127, 'وَاصْبِرْؐ وَمَا 284 صَبْرُكككَ إِلاَّ بِاللَّهِؐ وَلاَ تَحْزَنْ عَلَيْهِمْ وَلاَ تَــكُ فِى ضَيْقٍ مِّمَّا يَمْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (16, 128, 'إِنننَّ ۰للَّهَ مَعَ ۰لذِينَ "تَّقَواْ وَّالذِيــنَ هُم مُّحْسِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سُبْحَـٰنَ ۰ﻟـذِىٓ أَسْرۭيٰ بِعَبْدِهِ” لَيْلًا مِّــنَ ۰ڤْمَسْجِدِ ۱لْحَرَامِ إِلَــي ۰ڤْمَسْجِدِ ۱لاَقْصَا ۰ﻟ﮲ بَـٰرَكْنَا حَوْلَهُ„ لِنُرۣيَهُ„ مِــنَ —ايَـٰتِنَآؐ إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْبَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 2, 'وَءَاتَيْنَا مُوسَــي ۰لْكِتَـٰــبَ وَجَعَلْنَـٰهُ هُديً لِّبَنِىٓ إِسْرَآءِيــلَ أَلاَّ تَتَّخِذُواْ مِن دُونِى وَكِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 3, 'ذُرّۣيَّةَ مَــنْ حَمَلْنَا مَعَ نُوحٖؐ اِنَّهُ„ كَانَ عَبْداً شَكُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 4, 'وَقَضَيْنَآ إِلَيٰ بَنِىٓ إِسْرَآءِيلَ فِى ۱لْكِتَـٰــبِ لَتُفْسِدُنَّ فِى ۱لاَرْضِ مَرَّتَيْنِ وَلَتَعْلُــنَّ عُلُوّاً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 5, 'فَإِذَا جَآءَ وَعْدُ ٱُولۭيٰهُمَا بَعَثْنَا عَلَيْكُمْ عِبَاداً لَّنَآ ٱُوْلِى بَأْسٍ شَدِيدٍ فَجَاسُواْ خِچَلَ ۰لدِّيۭارۣؐ وَكَانَ وَعْداً مَّفْعُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 6, 'ثُمَّ رَدَدْنَا لَكُمُ ۴لْكَرَّةَ عَلَيْهِمْ وَأَمْدَدْنَـٰكُم بِأَمْوَ؛لٍ وَبَنِينَ وَجَعَلْنَـٰكُمُ; أَكْثَرَ نَفِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 7, 'اِنننَ اَحْسَنتُمُ; أَحْسَنتُمْ 285 لَأِنفُسِكُمْؐ وَإِنَ اَسَأْتُمْ فَلَهَاؐ فَإِذَا جَآءَ وَعْدُ ۴لاَخِرَةِ لِيَسُــٜٓـــُٔواْ وُجُوهَكُمْ وَلِيَدْخُلُواْ ۴ڤْمَسْجِدَ كَمَا دَخَلُوهُ أَوَّلَ مَرَّةٍ وَلِيُتَبِّرُواْ مَا عَلَوْاْ تَتْبِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 8, 'عَسۭيٰ رَبُّكُمُ; أَنْ يَّرْحَمَكُمْؐ وَإِنْ عُدتُّمْ عُدْنَاؐ وَجَعَلْنَا جَهَنَّمَ لِلْكۭـٰفِـرۣيــنَ حَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 9, 'اِنَّ هَـٰذَا ۰لْقُرْءَانَ يَهْدِﻯ لِلتِى هِــيَ أَقْوَمُ وَيُبَشِّرُ ۴لْمُومِنِينَ ۰لذِيــنَ يَعْمَلُونَ ۰ڤصَّـٰڤِحَـٰــتِ أَنَّ لَهُمُ; أَجْراً كَبِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 10, 'وَأَنَّ ۰لذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ أَعْتَدْنَا لَهُمْ عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 11, 'وَيَدْعُ ۴لِانسَـٰنُ بِالشَّرّۣ دُعَآءَهُ„ بِالْخَيْرۣؐ وَكَانَ ۰لِانسَـٰنُ عَجُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 12, 'وَجَعَلْنَا ۰ليْلَ وَالنَّهَارَ ءَايَتَيْــنۣ فَمَحَوْنَآ ءَايَةَ ۰ليْلِ وَجَعَلْنَآ ءَايَةَ ۰لنَّهۭارۣ مُبْصِرَةً لِّتَبْتَغُواْ فَضْلًا مِّن رَّبِّكُمْ وَلِتَعْلَمُواْ عَدَدَ ۰لسِّنِينَ وَالْحِسَابَؐ وَكُــلَّ شَيْءٍ فَصَّلْنَـٰهُ تَفْصِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 13, 'وَكُلَّ إِنسَـٰنٖ اَلْزَمْنَـٰهُ طَـٰٓئِرَهُ„ فِى عُنُقِهِ” وَنُخْرۣجُ لَهُ„ يَوْمَ ۰لْقِيَـٰمَةِ كِتَـٰباً يَلْقۭيٰهُ مَنشُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 14, '''قْرَأْ كِتَـٰبَــكَ كَفۭـيٰ بِنَفْسِــكَ ۰لْيَوْمَ عَلَيْكَ حَسِيباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 15, 'مَّـنِ ''هْتَدۭيٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِؐ” وَمَــن ضَلَّ فَإِنَّمَا يَضِــلُّ عَلَيْهَاؐ 286 وَلاَ تَزۣرُ وَازۣرَةٌ وۣزْرَ ٱُخْرۭيٰؐ وَمَا كُنَّا مُعَذِّبِيــنَ حَتَّيٰ نَبْعَثَ رَسُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 16, 'وَإِذَآ أَرَدْنَآ أَننن نُّهْلِــكَ قَرْيَةٗ اَمَرْنَا مُتْرَفِيهَا فَفَسَقُواْ فِيهَا فَحَــقَّ عَلَيْهَا ۰لْقَوْلُ فَدَمَّرْنَـٰهَا تَدْمِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 17, 'وَكَمَ اَهْلَكْنَا مِــنَ ۰لْقُرُونِ مِـنۢ بَعْدِ نُوحٍؐ وَكَفۭيٰ بِرَبِّــكَ بِذُنُوبِ عِبَادِهِ” خَبِيراَۢ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 18, 'مَّــن كَانَ يُرۣيدُ ۴لْعَاجِلَةَ عَجَّلْنَا لَهُ„ فِيهَا مَا نَشَآءُ لِمَن نُّرۣيدُ ثُمَّ جَعَلْنَا لَهُ„ جَهَنَّمَ يَصْلَيٰهَا مَذْمُوماً مَّدْحُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 19, 'وَمَنَ اَرَادَ ۰لاَخِرَةَ وَسَعۭيٰ لَهَا سَعْيَهَا وَهُوَ مُومِنٌ فَٱُوْلَئِكَ كَانَ سَعْيُهُم مَّشْكُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 20, 'كُلًاّ نُّمِدُّؐ هَـٰٓؤُلآَءِ وَهَـٰٓؤُلآَءِ مِــنْ عَطَآءِ رَبِّكَؐ وَمَا كَانَ عَطَآءُ رَبِّــكَ مَحْظُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 21, '۶نظُرْ كَيْفَ فَضَّلْنَا بَعْضَهُمْ عَلَيٰ بَعْضٍؐ وَلَلاَخِرَةُ أَكْبَرُ دَرَجَـٰــتٍ وَأَكْبَرُ تَفْضِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 22, 'لاَّ تَجْعَلْ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ فَتَقْعُدَ مَذْمُوماً مَّخْذُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 23, '© وَقَضۭيٰ رَبُّكَ أَلاَّ تَعْبُدُوٓاْ إِلٓاَّ إِيَّاهُؐ وَبِالْوَ؛لِدَيْنِ إِحْسَـٰناٗؐ اِمَّا يَبْلُغَنَّ عِندَكككَ ۰لْكِبَرَ أَحَدُهُمَآ أَوْ كِلاَهُمَا فَلاَ تَقُــل لَّهُمَآ ٱُفٍّ وَلاَ تَنْهَرْهُمَاؐ وَقُــل لَّهُمَا 287 قَوْلًا كَرۣيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 24, 'وَاخْفِــضْ لَهُمَا جَنَاحَ ۰لذُّلِّ مِــنَ ۰لرَّحْمَةِؐ وَقُل رَّبِّ ''رْحَمْهُمَا كَمَا رَبَّيَـٰنِى صَغِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 25, 'رَّبُّكُمُ; أَعْلَمُ بِمَا فِى نُفُوسِكُمُؐ; إِن تَكُونُواْ صَـٰڤِحِينَ فَإِنَّهُ„ كَانَ لِلاَوَّ؛بِيــنَ غَفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 26, 'وَءَاتِ ذَا ۰لْقُرْبۭــيٰ حَقَّهُ„ وَالْمِسْكِينَ وَابْــنَ ۰لسَّبِيلِؐ وَلاَ تُبَذِّرْ تَبْذِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 27, 'اِنَّ ۰لْمُبَذِّرۣيــنَ كَانُوٓاْ إِخْوَ؛نَ ۰لشَّيَـٰطِينِؐ وَكَانَ ۰لشَّيْطَـٰنُ لِرَبِّهِ” كَفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 28, 'وَإِمَّا تُعْرۣضَــنَّ عَنْهُمُ èبْتِغَآءَ رَحْمَةٍ مِّن رَّبِّكَ تَرْجُوهَا فَقُل لَّهُمْ قَوْلًا مَّيْسُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 29, 'وَلاَ تَجْعَـلْ يَدَكَ مَغْلُولَةٗ اِلَــيٰ عُنُقِــكَ وَلاَ تَبْسُطْهَا كُلَّ ۰لْبَسْطِ فَتَقْعُدَ مَلُوماً مَّحْسُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 30, 'اِنَّ رَبَّــكَ يَبْسُطُ ۴لرّۣزْقَ لِمَـنْ يَّشَآءُ وَيَقْدِرُؐ إِنَّهُ„ كَانَ بِعِبَادِهِ” خَبِيراَۢ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 31, 'وَلاَ تَقْتُلُوٓاْ أَوْچَدَكُمْ خَشْيَةَ إِمْچَقٍؐ نَّحْنُ نَرْزُقُهُمْ وَإِيَّاكُمُؐ; إِنَّ قَتْلَهُمْ كَانَ خِطْـٔاً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 32, 'وَلاَ تَقْرَبُواْ ۴لزّۣنۭيٰٓ إِنَّهُ„ كَانَ فَـٰحِشَةً وَسَآءَ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 33, 'وَلاَ تَقْتُلُواْ ۴لنَّفْسَ ۰لتِى حَرَّمَ ۰للَّهُ إِلاَّ بِالْحَقﱢّؐ وَمَن قُتِلَ مَظْلُوماً فَقَدْ جَعَلْنَا لِوَلِيِّهِ” سُلْطَـٰناً فَلاَ يُسْرۣف فِّى ۱لْقَتْلِؐ 288 إِنَّهُ„ كَانَ مَنصُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 34, 'وَلاَ تَقْرَبُواْ مَالَ ۰لْيَتِيمِ إِلاَّ بِالتِى هِــيَ أَحْسَــنُ حَتَّيٰ يَبْلُغَ أَشُدَّهُؐ, وَأَوْفُواْ بِالْعَهْدِؐ إِنَّ ۰لْعَهْدَ كَانَ مَسْـُٔولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 35, 'وَأَوْفُواْ ۴لْكَيْـلَ إِذَا كِلْتُمْ وَزۣنُواْ بِالْقُسْطَاسسسِ ۱لْمُسْتَقِيمِؐ ذَ؛لِكَ خَيْرٌ وَأَحْسَنُ تَاوۣيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 36, 'وَلاَ تَقْفُ مَا لَيْــسَ لَــكَ بِهِ” عِلْم٘ؐ اِنَّ ۰لسَّمْعَ وَالْبَصَرَ وَالْفُؤَادَ كُلُّ ٱُوْلَئِــكَ كَانَ عَنْهُ مَسْـُٔولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 37, 'وَلاَ تَمْشِ فِى ۱لاَرْضِ مَرَحاٗؐ اِنَّــكَ لَن تَخْرۣقَ ۰لاَرْضَ وَلَن تَبْلُغَ ۰لْجِبَالَ طُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 38, 'كُلُّ ذَ؛لِــكَ كَانَ سَيِّيؕةٗ عِندَ رَبِّــكَ مَكْرُوهاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 39, 'ذَ؛لِــكَ مِمَّآ أَوْحۭيٰٓ إِلَيْــكَ رَبُّــكَ مِنَ ۰لْحِكْمَةِؐ وَلاَ تَجْعَلْ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ فَتُلْقۭيٰ فِى جَهَنَّمَ مَلُوماً مَّدْحُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 40, 'اَفَأَصْفۭيٰكُمْ رَبُّكُم بِالْبَنِينَ وَاتَّخَذَ مِــنَ ۰لْمَلَئِكَةِ إِنَـٰثاٗؐ اِنَّكُمْ لَتَقُولُونَ قَوْلٗا عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 41, 'وَلَقَدْ صَرَّفْنَا فِى هَـٰذَا ۰لْقُرْءَانِ لِيَذَّكَّرُواْ وَمَا يَزۣيدُهُمُ; إِلاَّ نُفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 42, 'قُل لَّوْ كَانَ مَعَهُ; ءَالِهَةٌ كَمَا تَقُولُونَ إِذاً لاَّبْتَغَوۣاْ اِلَيٰ ذى ۱لْعَرْشِ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 43, 'سُبْحَـٰنَهُ„ وَتَعَـٰلۭــيٰ عَمَّا يَقُولُونَ عُلُوّاً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 44, 'يُسَبِّحُ لَهُ 289 ۴لسَّمَـٰوَ؛تُ ۴لسَّبْعُ وَالاَرْضُ وَمَن فِيهِنَّؐ وَإِن مِّـن شَيْءٖ اِلاَّ يُسَبِّحُ بِحَمْدِهِؐ” وَچَكِــن لاَّ تَفْقَهُونَ تَسْبِيحَهُمُؐ; إِنَّهُ„ كَانَ حَلِيماٗ غَفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 45, 'وَإِذَا قَرَأْتَ ۰لْقُرْءَانَ جَعَلْنَا بَيْنَــكَ وَبَيْنَ ۰لذِينَ لاَ يُومِنُونَ بِالاَخِرَةِ حِجَاباً مَّسْتُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 46, 'وَجَعَلْنَا عَلَــيٰ قُلُوبِهِمُ; أَكِنَّةٗ اَنْ يَّفْقَهُوهُ وَفِىٓ ءَاذَانِهِمْ وَقْراًؐ وَإِذَا ذَكَرْتَ رَبَّــكَ فِى ۱لْقُرْءَانِ وَحْدَهُ„ وَلَّوْاْ عَلَــيٰٓ أَدْبۭـٰرۣهِمْ نُفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 47, 'نَّحْــنُ أَعْلَمُ بِمَا يَسْتَمِعُونَ بِهِ“ إِذْ يَسْتَمِعُونَ إِلَيْــكَ وَإِذْ هُمْ نَجْوۭيٰٓ إِذْ يَقُولُ ۴لظَّـٰلِمُونَ إِننن تَتَّبِعُونَ إِلاَّ رَجُلًا مَّسْحُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 48, '۶نظُرْ كَيْفَ ضَرَبُواْ لَكَ ۰لاَمْثَالَ فَضَلُّواْؐ فَلاَ يَسْتَطِيعُونَ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 49, 'وَقَالُوٓاْ أَ.ذَا كُنَّا عِظَـٰماً وَرُفَـٰتاٗ اِنَّا لَمَبْعُوثُونَ خَلْقاً جَدِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 50, '¥ قُلْ كُونُواْ حِجَارَةٗ اَوْ حَدِيداٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 51, 'اَوْ خَلْقاً مِّمَّا يَكْبُرُ فِى صُدُورۣكُمْؐ فَسَيَقُولُونَ مَنْ يُّعِيدُنَاؐ قُلِ ۱ﻟ﮲ فَطَرَكُمُ; أَوَّلَ مَرَّةٍؐ فَسَيُنْغِضُونَ إِلَيْــكَ رُءُوسَهُمْ وَيَقُولُونَ مَتۭيٰ هُوَؐ قُــلْ عَـسۭيٰٓ أَنْ يَّكُونَ قَرۣيباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 52, 'يَوْمَ يَدْعُوكُمْ فَتَسْتَجِيبُونَ بِحَمْدِهِ” وَتَظُنُّونَ 290 إِن لَّبِثْتُمُ; إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 53, 'وَقُل لِّعِبَادِى يَقُولُواْ ۴لتِى هِيَ أَحْسَنُؐ إِنَّ ۰لشَّيْطَـٰنَ يَنزَغُ بَيْنَهُمُؐ; إِنَّ ۰لشَّيْطَـٰــنَ كَانَ لِلِانسَـٰــنۣ عَدُوّاً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 54, 'رَّبُّكُمُ; أَعْلَمُ بِكُمُ; إِنْ يَّشَأْ يَرْحَمْكُمُ; أَوۣ اِنْ يَّشَأْ يُعَذِّبْكُمْؐ وَمَآ أَرْسَلْنَـٰكَ عَلَيْهِمْ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 55, 'وَرَبُّــكَ أَعْلَمُ بِمَـن فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَلَقَدْ فَضَّلْنَا بَعْــضَ ۰لنَّبِيٓــٕـﯧــنَ عَلَيٰ بَعْضٍ وَءَاتَيْنَا دَاوُﹼدَ زَبُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 56, 'قُــلُ ۶دْعُواْ ۴لذِينَ زَعَمْتُم مِّن دُونِهِ” فَلاَ يَمْلِكُونَ كَشْفَ ۰لضُّرّۣ عَنكُمْ وَلاَ تَحْوۣيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 57, '۷وْلَئِــكَ ۰لذِينَ يَدْعُونَ يَبْتَغُونَ إِلَيٰ رَبِّهِمُ ۴لْوَسِيلَةَ أَيُّهُمُ; أَقْرَبببُ وَيَرْجُونَ رَحْمَتَهُ„ وَيَخَافُونَ عَذَابَهُؐ; إِنَّ عَذَابَ رَبِّكَ كَانَ مَحْذُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 58, 'وَإِن مِّن قَرْيَةٖ اِلاَّ نَحْــنُ مُهْلِكُوهَا قَبْلَ يَوْمِ ۱لْقِيَـٰمَةِ أَوْ مُعَذِّبُوهَا عَذَاباً شَدِيداًؐ كَانَ ذَ؛لِكَ فِى ۱لْكِتَـٰــبِ مَسْطُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 59, 'وَمَا مَنَعَنَآ أَن نُّرْسِلَ بِالاَيَـٰتِ إِلٓاَّ أَن كَذَّبببَ بِهَا ۰لاَوَّلُونَؐ وَءَاتَيْنَا ثَمُودَ ۰لنَّاقَةَ مُبْصِرَةً فَظَلَمُواْ بِهَاؐ وَمَا نُرْسِلُ بِالاَيَـٰتِ إِلاَّ تَخْوۣيفاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 60, '291 وَإِذْ قُلْنَا لَــكَ إِنَّ رَبَّــكَ أَحَاطَ بِالنَّاسِؐ وَمَا جَعَلْنَا ۰لرُّءْيَا ۰لتِىٓ أَرَيْنَـٰــكَ إِلاَّ فِتْنَةً لِّلنَّاسِ وَاڤشَّجَرَةَ ۰لْمَلْعُونَةَ فِى ۱لْقُرْءَانِؐ وَنُخَوّۣفُهُمْ فَمَا يَزۣيدُهُمُ; إِلاَّ طُغْيَـٰناً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 61, 'وَإِذْ قُلْنَا لِلْمَلَئِكَةِ ۹سْجُدُواْ ءَلِادَمَ فَسَجَدُوٓاْؐ إِلٓاَّ إِبْلِيــسَ قَالَ ءَآسْجُدُ لِمَــنْ خَلَقْتَ طِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 62, 'قَالَ أَرَ×يْتَكَ هَـٰذَا ۰ﻟ﮲ كَرَّمْتَ عَلَيَّ لَئِنَ اَخَّرْتَنِ“ إِلَيٰ يَوْمِ ۱لْقِيَـٰمَةِ لَأَحْتَنِكَنَّ ذُرّۣيَّتَهُ; إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 63, 'قَالَ "ذْهَبْ فَمَن تَبِعَكَ مِنْهُمْ فَإِنَّ جَهَنَّمَ جَزَآؤُكُمْ جَزَآءً مَّوْفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 64, 'وَاسْتَفْزۣزْ مَنِ ''سْتَطَعْــتَ مِنْهُم بِصَوْتِــكَ وَأَجْلِــبْ عَلَيْهِم بِخَيْلِــكَ وَرَجْلِــكَ وَشَارۣكْهُمْ فِى ۱لاَمْوَ؛لِ وَالاَوْچَدِ وَعِدْهُمْؐ وَمَا يَعِدُهُمُ ۴لشَّيْطَـٰنُ إِلاَّ غُرُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 65, 'اِنَّ عِبَادِى لَيْــسَ لَــكَ عَلَيْهِمْ سُلْطَـٰنٌؐ وَكَفۭيٰ بِرَبِّــكَ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 66, 'رَّبُّكُمُ ۴ﻟ﮲ يُزْجىِ لَكُمُ ۴لْفُلْــكَ فِى ۱ڤْبَحْرۣ لِتَبْتَغُواْ مِن فَضْلِهِؐ“ إِنَّهُ„ كَانَ بِكُمْ رَحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 67, 'وَإِذَا مَسَّكُمُ ۴لضُّرُّ فِى ۱ڤْبَحْرۣ ضَلَّ مَن تَدْعُونَ إِلٓاَّ إِيَّاهُؐ فَلَمَّا نَجّۭيٰكُمُ; إِلَي ۰لْبَرّۣ أَعْرَضْتُمْؐ 292 وَكَانَ ۰لِانسَـٰــنُ كَفُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 68, 'اَفَأَمِنتُمُ; أَنننْ يَّخْسِفَ بِكُمْ جَانِبَ ۰لْبَرّۣ أَوْ يُرْسِــلَ عَلَيْكُمْ حَاصِباً ثُمَّ لاَ تَجِدُواْ لَكُمْ وَكِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 69, 'اَمَ اَمِنتُمُ; أَنْ يُّعِيدَكُمْ فِيهِ تَارَةٗ ۷خْرۭيٰ فَيُرْسِــلَ عَلَيْكُمْ قَاصِفاً مِّنَ ۰لرّۣيحِ فَيُغْرۣقَكُم بِمَا كَفَرْتُمْ ثُمَّ لاَ تَجِدُواْ لَكُمْ عَلَيْنَا بِهِ” تَبِيعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 70, '© وَلَقَدْ كَرَّمْنَا بَنِىٓ ءَادَمَ وَحَمَلْنَـٰهُمْ فِى ۱لْبَرّۣ وَاڤْبَحْرۣ وَرَزَقْنَـٰهُم مِّنَ ۰لطَّيِّبَـٰــتِ وَفَضَّلْنَـٰهُمْ عَلَــيٰ كَثِيرٍ مِّمَّــنْ خَلَقْنَا تَفْضِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 71, 'يَوْمَ نَدْعُواْ كُــلَّ ٱُنَاسٙ بِإِمَـٰمِهِمْؐ فَمَنُ ۷وتِيَ كِتَـٰبَهُ„ بِيَمِينِهِ” فَٱُوْلَئِــكَ يَقْرَءُونَ كِتَـٰبَهُمْ وَلاَ يُظْلَمُونَ فَتِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 72, 'وَمَــن كَانَ فِى هَـٰذِهِ“ أَعْمۭيٰ فَهُوَ فِى ۱لاَخِرَةِ أَعْمۭيٰ وَأَضَلُّ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 73, 'وَإِن كَادُواْ لَيَفْتِنُونَــكَ عَنِ ۱ﻟـذِىٓ أَوْحَيْنَآ إِلَيْــكَ لِتَفْتَرۣيَ عَلَيْنَا غَيْرَهُؐ, وَإِذاً لاَّتَّخَذُوكككَ خَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 74, 'وَلَوْلآَ أَن ثَبَّتْنَـٰكَ لَقَدْ كِدتَّ تَرْكَـنُ إِلَيْهِمْ شَيْـٔاً قَلِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 75, 'اِذاً لَأَّذَقْنَـٰــكَ ضِعْفَ ۰لْحَيَوٰةِ وَضِعْفَ ۰لْمَمَاتِ ثُمَّ لاَ تَجِدُ لَــكَ عَلَيْنَا نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 76, 'وَإِن كَادُواْ 29 لَيَسْتَفِزُّونَــكَ مِــنَ ۰لاَرْضِ لِيُخْرۣجُوكككَ مِنْهَاؐ وَإِذاً لاَّ يَلْبَثُونَ خَلْفَكَ إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 77, 'سُنَّةَ مَــن قَدَ اَرْسَلْنَا قَبْلَــكَ مِن رُّسُلِنَاؐ وَلاَ تَجِدُ لِسُنَّتِنَا تَحْوۣيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 78, 'اَقِمِ ۱لصَّلَوٰةَ لِدُلُوكِ ۱لشَّمْـسِ إِلَيٰ غَسَقِ ۱ليْلِ وَقُرْءَانَ ۰ڤْفَجْـرۣؐ إِنَّ قُرْءَانننَ ۰ڤْفَجْرۣ كَانَ مَشْهُوداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 79, 'وَمِــنَ ۰ليْــلۣ فَتَهَجَّدْ بِهِ” نَافِلَةً لَّكَ عَسۭيٰٓ أَنْ يَّبْعَثَكَ رَبُّــكَ مَقَاماً مَّحْمُوداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 80, 'وَقُل رَّبببِّ أَدْخِلْنِى مُدْخَلَ صِدْقٍ وَأَخْرۣجْنِى مُخْرَجَ صِدْقٍ وَاجْعَل لِّى مِــن لَّدُنكَ سُلْطَـٰناً نَّصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 81, 'وَقُـلْ جَآءَ ۰لْحَقُّ وَزَهَــقَ ۰لْبَـٰطِلُؐ إِنَّ ۰لْبَـٰطِــلَ كَانَ زَهُوقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 82, 'وَنُنَزّۣلُ مِــنَ ۰لْقُرْءَانِ مَا هُوَ شِفَآءٌ وَرَحْمَةٌ لِّلْمُومِنِينَؐ وَلاَ يَزۣيدُ ۴لظَّـٰلِمِينَ إِلاَّ خَسَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 83, 'وَإِذَآ أَنْعَمْنَا عَلَي ۰لِانسَـٰــنۣ أَعْرَضَ وَنَــۭٔا بِجَانِبِهِؐ” وَإِذَا مَسَّهُ ۴لشَّرُّ كَانَ يَــُٔوساًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 84, 'قُلْ كُلٌّ يَعْمَــلُ عَلَيٰ شَاكِلَتِهِ” فَرَبُّكُمُ; أَعْلَمُ بِمَنْ هُوَ أَهْدۭيٰ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 85, 'وَيَسْـَٔلُونَــكَ عَنِ ۱لرُّوحِؐ قُلِ ۱لرُّوحُ مِــنَ اَمْرۣ رَبِّى وَمَآ ٱُوتِيتُم مِّــنَ ۰لْعِلْمِ إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 86, 'وَلَـئِن شِيؔنَا لَنَذْهَبَنَّ بِاﻟـذِىٓ أَوْحَيْنَآ إِلَيْــكَ ثُمَّ لاَ تَجِدُ لَــكَ بِهِ” 294 عَلَيْنَا وَكِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 87, 'اِلاَّ رَحْمَةً مِّن رَّبِّكَؐ إِنَّ فَضْلَهُ„ كَانَ عَلَيْــكَ كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 88, 'قُل لَّـئِنِ ''جْتَمَعَــتِ ۱لِانسُ وَالْجِــنُّ عَلَيٰٓ أَنْ يَّاتُواْ بِمِثْــلۣ هَـٰذَا ۰لْقُرْءَانِ لاَ يَاتُونَ بِمِثْلِهِ” وَلَوْ كَانَ بَعْضُهُمْ لِبَعْــضٍ ظَهِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 89, 'وَلَقَدْ صَرَّفْنَا لِلنَّاسِ فِى هَـٰذَا ۰لْقُرْءَانِ مِــن كُــلّۣ مَثَلٍ فَأَبۭــيٰٓ أَكْثَرُ ۴لنَّاسِ إِلاَّ كُفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 90, 'وَقَالُواْ لَن نُّومِــنَ لَــكَ حَتَّــيٰ تُفَجِّرَ لَنَا مِــنَ ۰لاَرْضِ يَنۢبُوعاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 91, 'اَوْ تَكُونَ لَــكَ جَنَّةٌ مِّن نَّخِيلٍ وَعِنَــبٍ فَتُفَجِّرَ ۰لاَنْهَـٰرَ خِچَلَهَا تَفْجِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 92, 'اَوْ تُسْقِطَ ۰لسَّمَآءَ كَمَا زَعَمْــتَ عَلَيْنَا كِسَفاٗ اَوْ تَاتِيَ بِاللَّهِ وَالْمَلَئِكَةِ قَبِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 93, 'اَوْ يَكُونَ لَــكَ بَيْــتٌ مِّن زُخْرُفٖ اَوْ تَرْقۭيٰ فِى ۱لسَّمَآءِ وَلَن نُّومِنَ لِرُقِيِّكَ حَتَّــيٰ تُنَزّۣلَ عَلَيْنَا كِتَـٰباً نَّقْرَؤُهُؐ, قُلْ سُبْحَـٰنَ رَبِّى هَــلْ كُنتُ إِلاَّ بَشَراً رَّسُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 94, 'وَمَا مَنَعَ ۰لنَّاسَ أَنْ يُّومِنُوٓاْ إِذْ جَآءَهُمُ ۴لْهُدۭيٰٓ إِلٓاَّ أَن قَالُوٓاْ أَبَعَــثَ ۰للَّهُ بَشَراً رَّسُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 95, 'قُل لَّوْ كَانَ فِى ۱لاَرْضضضِ مَلَئِكَةٌ يَمْشُونَ مُطْمَئِـنِّيــنَ لَنَزَّلْنَا عَلَيْهِم مِّــنَ ۰لسَّمَآءِ مَلَكاً رَّسُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 96, 'قُــلْ كَفۭــيٰ بِاللَّهِ 295 شَهِيداَۢ بَيْنِى وَبَيْنَكُمُؐ; إِنَّهُ„ كَانَ بِعِبَادِهِ” خَبِيراَۢ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 97, 'وَمَـنْ يَّهْدِ ۱للَّهُ فَهُوَ ۰لْمُهْتَدِؐ” وَمَنْ يُّضْلِلْ فَلَن تَجِدَ لَهُمُ; أَوْلِيَآءَ مِن دُونِهِؐ” وَنَحْشُرُهُمْ يَوْمَ ۰لْقِيَـٰمَةِ عَلَيٰ وُجُوهِهِمْ عُمْياً وَبُكْماً وَصُمّاًؐ مَّأْوۭيٰهُمْ جَهَنَّمُؐ كُلَّمَا خَبَتْ زۣدْنَـٰهُمْ سَعِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 98, 'ذَ؛لِــكَ جَزَآؤُهُم بِأَنَّهُمْ كَفَرُواْ بِـَٔايَـٰتِنَا وَقَالُوٓاْ أَ.ذَا كُنَّا عِظَـٰماً وَرُفَـٰتاٗ اِنَّا لَمَبْعُوثُونَ خَلْقاً جَدِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 99, '¤ اَوَلَمْ يَرَوَاْ اَنننَّ ۰للَّهَ ۰ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضضضَ قَادِر٘ عَلَيٰٓ أَنْ يَّخْلُـقَ مِثْلَهُمْ وَجَعَــلَ لَهُمُ; أَجَلًا لاَّ رَيْبَ فِيهِؐ فَأَبَــي ۰لظَّـٰلِمُونَ إِلاَّ كُفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 100, 'قُل لَّوَ اَنتُمْ تَمْلِكُونَ خَزَآئِنَ رَحْمَةِ رَبِّيَ إِذاً لَأَّمْسَكْتُمْ خَشْيَةَ ۰لِانفَاقِؐ وَكَانَ ۰لِانسَـٰــنُ قَتُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 101, 'وَلَقَدَ —اتَيْنَا مُوسۭيٰ تِسْعَ ءَايَـٰــتٙ بَيِّنَـٰــتٍؐ فَسْـَٔلْ بَنِىٓ إِسْرَآءِيلَ إِذْ جَآءَهُمْ فَقَالَ لَهُ„ فِرْعَوْنُ إِنِّى لَأَظُنُّــكَ يَـٰمُوسۭــيٰ مَسْحُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 102, 'قَالَ لَقَدْ عَلِمْــتَ مَآ أَنزَلَ هَـٰٓؤُلآَءِ الاَّ رَبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ بَصَآئِرَؐ وَإِنِّى لَأَظُنُّــكَ يَـٰفِرْعَوْنُ مَثْبُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 103, 'فَأَرَادَ أَنْ 296 يَّسْتَفِزَّهُم مِّــنَ ۰لاَرْضضضِ فَأَغْرَقْنَـٰهُ وَمَــن مَّعَهُ„ جَمِيعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 104, 'وَقُلْنَا مِـنۢ بَعْدِهِ” لِبَنِىٓ إِسْرَآءِيــلَ ۸سْكُنُواْ ۴لاَرْضَؐ فَإِذَا جَآءَ وَعْدُ ۴لاَخِرَةِ جِيؔنَا بِكُمْ لَفِيفاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 105, 'وَبِالْحَــقّۣ أَنزَلْنَـٰهُؐ وَبِالْحَقِّ نَزَلَؐ وَمَآ أَرْسَلْنَـٰــكَ إِلاَّ مُبَشِّراً وَنَذِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 106, 'وَقُرْءَاناً فَرَقْنَـٰهُ لِتَقْرَأَهُ„ عَلَــي ۰لنَّاسسسِ عَلَيٰ مُكْثٍؐ وَنَزَّلْنَـٰهُ تَنزۣيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 107, 'قُلَ —امِنُواْ بِهِ“ أَوْ لاَ تُومِنُوٓاْؐ إِنَّ ۰لذِينَ ٱُوتُواْ ۴لْعِلْمَ مِن قَبْلِهِ“ إِذَا يُتْلۭــيٰ عَلَيْهِمْ يَخِرُّونَ لِلاَذْقَانننۣ سُجَّداً وَيَقُولُونَ سُبْحَـٰنَ رَبِّنَآ إِن كَانَ وَعْدُ رَبِّنَا لَمَفْعُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 108, 'وَيَخِرُّونَ لِلاَذْقَانِ يَبْكُونَ وَيَزۣيدُهُمْ خُشُوعاًؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 109, 'قُــلُ ۶دْعُواْ ۴للَّهَ أَوُ ۶دْعُواْ ۴لرَّحْمَـٰنَؐ أَيّاً مَّا تَدْعُواْ فَلَهُ ۴لاَسْمَآءُ ۴لْحُسْنۭيٰؐ وَلاَ تَجْهَرْ بِصَلاَتِــكَ وَلاَ تُخَافِتْ بِهَا وَابْتَغِ بَيْــنَ ذَ؛لِكَ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (17, 110, 'وَقُـلِ ۱لْحَمْدُ لِلهِ ۱ﻟ﮲ لَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُــن لَّهُ„ شَرۣيــكٌ فِى ۱لْمُلْــكِ وَلَمْ يَكُــن لَّهُ„ وَلِيٌّ مِّنَ ۰لذُّلﱢّؐ وَكَبِّرْهُ تَكْبِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 1, '297  بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۱لْحَمْدُ لِلهِ ۱ﻟـذِىٓ أَنزَلَ عَلَيٰ عَبْدِهِ ۱لْكِتَـٰبَ وَلَمْ يَجْعَل لَّهُ„ عِوَجاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 2, 'قَيِّماً لِّيُنذِرَ بَأْساً شَدِيداً مِّــن لَّدُنْهُ وَيُبَشِّرَ ۰لْمُومِنِيــنَ ۰لذِينَ يَعْمَلُونَ ۰ڤصَّـٰڤِحَـٰتِ أَنَّ لَهُمُ; أَجْراٗ حَسَناً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 3, 'مَّـٰكِثِينَ فِيهِ أَبَداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 4, 'وَيُنذِرَ ۰لذِيــنَ قَالُواْ èتَّخَذَ ۰للَّهُ وَلَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 5, 'مَّا لَهُم بِهِ” مِنْ عِلْمٍ وَلاَ ءَلِابَآئِهِمْؐ كَبُرَتْ كَلِمَةً تَخْرُجُ مِنَ اَفْوَ؛هِهِمُؐ; إِنْ يَّقُولُونَ إِلاَّ كَذِباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 6, 'فَلَعَلَّــكَ بَـٰخِعٌ نَّفْسَكَ عَلَيٰٓ ءَاثۭـٰرۣهِمُ; إِن لَّمْ يُومِنُواْ بِهَـٰذَا ۰لْحَدِيثِ أَسَفاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 7, 'اِنَّا جَعَلْنَا مَا عَلَــي ۰لاَرْضِ زۣينَةً لَّهَا لِنَبْلُوَهُمُ; أَيُّهُمُ; أَحْسَنُ عَمَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 8, 'وَإِنَّا لَجَـٰعِلُونَ مَا عَلَيْهَا صَعِيداً جُرُزاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 9, 'اَمْ حَسِبْتَ أَنَّ أَصْحَـٰبَ ۰لْكَهْفِ وَالرَّقِيمِ كَانُواْ مِــنَ —ايَـٰتِنَا عَجَباٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 10, 'اِذَ اَوَي ۰لْفِتْيَةُ إِلَــي ۰لْكَهْفِ فَقَالُواْ رَبَّنَآ ءَاتِنَا مِــن لَّدُنــكَ رَحْمَةً وَهَيِّىْ لَنَا مِنَ اَمْرۣنَا رَشَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 11, 'فَضَرَبْنَا عَلَيٰٓ ءَاذَانِهِمْ فِى ۱لْكَهْفِ سِنِيــنَ عَدَداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 12, 'ثُمَّ بَعَثْنَـٰهُمْ لِنَعْلَمَ أَيُّ ۴لْحِزْبَيْــنۣ أَحْصۭيٰ لِمَا لَبِثُوٓاْ أَمَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 13, 'نَّحْــنُ نَقُــصُّ عَلَيْكَ 298 نَبَأَهُم بِالْحَقﱢّؐ إِنَّهُمْ فِتْيَة٘ —امَنُواْ بِرَبِّهِمْ وَزۣدْنَـٰهُمْ هُديًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 14, 'وَرَبَطْنَا عَلَيٰ قُلُوبِهِمُ; إِذْ قَامُواْ فَقَالُواْ رَبُّنَا رَبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ لَن نَّدْعُوَاْ مِن دُونِهِ“ إِچَهاً لَّقَدْ قُلْنَآ إِذاً شَطَطاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 15, 'هَـٰٓؤُلآَءِ قَوْمُنَا "تَّخَذُواْ مِــن دُونِهِ“ ءَالِهَةً لَّوْلاَ يَاتُونَ عَلَيْهِم بِسُلْطَـٰنٙ بَيِّنٍؐ فَمَــنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَي ۰للَّهِ كَذِباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 16, 'وَإِذِ ''عْتَزَلْتُمُوهُمْ وَمَا يَعْبُدُونَ إِلاَّ ۰للَّهَ فَأْوُﹽاْ إِلَــي ۰لْكَهْفِ يَنشُرْ لَكُمْ رَبُّكُم مِّن رَّحْمَتِهِ” وَيُهَيِّىْ لَكُم مِّنَ اَمْرۣكُم مَّرْفِقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 17, '© وَتَرَي ۰لشَّمْسَ إِذَا طَلَعَت تَّزَّ؛وَرُ عَــن كَهْفِهِمْ ذَاتَ ۰لْيَمِينِ وَإِذَا غَرَبَت تَّقْرۣضُهُمْ ذَاتَ ۰لشِّمَالِ وَهُمْ فِى فَجْوَةٍ مِّنْهُؐ ذَ؛لِــكَ مِــنَ —ايَـٰــتِ ۱للَّهِؐ مَـنْ يَّهْدِ ۱للَّهُ فَهُوَ ۰لْمُهْتَدِؐ” وَمَنْ يُّضْلِلْ فَلَن تَجِدَ لَهُ„ وَلِيّاً مُّرْشِداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 18, 'وَتَحْسِبُهُمُ; أَيْقَاظاً وَهُمْ رُقُودٌؐ وَنُقَلِّبُهُمْ ذَاتَ ۰لْيَمِينِ وَذَاتَ ۰لشِّمَالِ وَكَلْبُهُم بَـٰسِطٌ ذِرَاعَيْهِ بِالْوَصِيدِؐ لَوۣ ''طَّلَعْتَ عَلَيْهِمْ لَوَلَّيْتَ مِنْهُمْ فِرَاراً وَلَمُلِّيؔتَ مِنْهُمْ رُعْباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 19, 'وَكَذَ؛لِــكَ بَعَثْنَـٰهُمْ لِيَتَسَآءَلُواْ 299 بَيْنَهُمْؐ قَالَ قَآئِــلٌ مِّنْهُمْ كَمْ لَبِثْتُمْؐ قَالُواْ لَبِثْنَا يَوْماٗ اَوْ بَعْضَ يَوْمٍؐ قَالُواْ رَبُّكُمُ; أَعْلَمُ بِمَا لَبِثْتُمْ فَابْعَثُوٓاْ أَحَدَكُم بِوَرۣقِكُمْ هَـٰذِهِ“ إِلَــي ۰لْمَدِينَةِ فَلْيَنظُرَ اَيُّهَآ أَزْكۭيٰ طَعَاماً فَلْيَاتِكُم بِـرۣزْقٍ مِّنْهُ وَلْيَتَلَطَّفْؐ وَلاَ يُشْعِرَنَّ بِكُمُ; أَحَداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 20, 'اِنَّهُمُ; إِنْ يَّظْهَرُواْ عَلَيْكُمْ يَرْجُمُوكُمُ; أَوْ يُعِيدُوكُمْ فِى مِلَّتِهِمْ وَلَــن تُفْڤِحُوٓاْ إِذاٗ اَبَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 21, 'وَكَذَ؛لِــكَ أَعْثَرْنَا عَلَيْهِمْ لِيَعْلَمُوٓاْ أَنَّ وَعْدَ ۰للَّهِ حَقٌّ وَأَنَّ ۰لسَّاعَةَ لاَ رَيْبَ فِيهَآؐ إِذْ يَتَنَـٰزَعُونَ بَيْنَهُمُ; أَمْرَهُمْ فَقَالُواْ èبْنُواْ عَلَيْهِم بُنْيَـٰناًؐ رَّبُّهُمُ; أَعْلَمُ بِهِمْؐ قَالَ ۰لذِيــنَ غَلَبُواْ عَلَيٰٓ أَمْرۣهِمْ ڤَنَتَّخِذَنَّ عَلَيْهِم مَّسْجِداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 22, 'سَيَقُولُونَ ثَـچَثَةٌ رَّابِعُهُمْ كَلْبُهُمْؐ وَيَقُولُونَ خَمْسَةٌ سَادِسُهُمْ كَلْبُهُمْ رَجْماَۢ بِالْغَيْبِؐ وَيَقُولُونَ سَبْعَةٌؐ وَثَامِنُهُمْ كَلْبُهُمْؐ قُل رَّبِّيَ أَعْلَمُ بِعِدَّتِهِمؐ مَّا يَعْلَمُهُمُ; إِلاَّ قَلِيــلٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 23, 'فَلاَ تُمَارۣ فِيهِمُ; إِلاَّ مِرَآءً ظَـٰهِراً وَلاَ تَسْتَفْــتِ فِيهِم مِّنْهُمُ; أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 24, 'وَلاَ تَقُولَنَّ لِشَاْىْءٖ اِنِّى فَاعِلٌ ذَ؛لِــكَ غَداٗ اِلٓاَّ أَنْ يَّشَآءَ ۰للَّهُؐ 00 وَاذْكُر رَّبَّــكَ إِذَا نَسِيــتَؐ وَقُلْ عَسۭيٰٓ أَنْ يَّهْدِيَنِ” رَبِّى لَأِقْرَبببَ مِــنْ هَـٰذَا رَشَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 25, 'وَلَبِثُواْ فِى كَهْفِهِمْ ثَـچَــثَ مِاْيؕةٍ سِنِينَ وَازْدَادُواْ تِسْعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 26, 'قُـلِ ۱للَّهُ أَعْلَمُ بِمَا لَبِثُواْؐ لَهُ„ غَيْــبُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضضضِؐ أَبْصِرْ بِهِ” وَأَسْمِعْؐ مَا لَهُم مِّن دُونِهِ” مِنْ وَّلِي؊ّؐ وَلاَ يُشْرۣكككُ فِى حُكْمِهِ“ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 27, 'وَاتْــلُ مَآ ٱُوحِيَ إِلَيْــكَ مِن كِتَابِ رَبِّــكَ لاَ مُبَدِّلَ لِكَلِمَـٰتِهِؐ” وَلَن تَجِدَ مِن دُونِهِ” مُڤْتَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 28, 'وَاصْبِرْ نَفْسَــكَ مَعَ ۰لذِيــنَ يَدْعُونَ رَبَّهُم بِالْغَدَوٰةِ وَالْعَشِيِّ يُرۣيدُونَ وَجْهَهُؐ, وَلاَ تَعْدُ عَيْنَـٰكَ عَنْهُمْ تُرۣيدُ زۣينَةَ ۰لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَلاَ تُطِعْ مَنَ اَغْفَلْنَا قَلْبَهُ„ عَــن ذِكْرۣنَا وَاتَّبَعَ هَوۭيٰهُ وَكَانننَ أَمْرُهُ„ فُرُطاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 29, 'وَقُـلِ ۱لْحَقُّ مِن رَّبِّكُمْ فَمَــن شَآءَ فَلْيُومِنْ وَّمَــن شَآءَ فَلْيَكْفُرۣؐ اِنَّآ أَعْتَدْنَا لِلظَّـٰلِمِيــنَ نَاراٗ اَحَاطَ بِهِمْ سُرَادِقُهَاؐ وَإِنْ يَّسْتَغِيثُواْ يُغَاثُواْ بِمَآءٍ كَالْمُهْلِ يَشْوۣى ۱لْوُجُوهَؐ بِيسَ ۰لشَّرَابُؐ وَسَآءَتْ مُرْتَفَقاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 30, '¥ اِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ إِنَّا لاَ نُضِيعُ أَجْرَ مَــنَ اَحْسَــنَ عَمَلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 31, '۷وْلَئِــكَ 01 لَهُمْ جَنَّـٰــتُ عَدْنٍ تَجْرۣى مِــن تَحْتِهِمُ ۴لاَنْهَـٰرُ يُحَلَّوْنَ فِيهَا مِــنَ اَسَاوۣرَ مِــن ذَهَــبٍ وَيَلْبَسُونَ ثِيَاباٗ خُضْراً مِّــن سُندُسٍ وَإِسْتَبْرَقٍ مُّتَّكِـِٕينَ فِيهَا عَلَــي ۰لاَرَآئِكِؐ نِعْمَ ۰لثَّوَابُؐ وَحَسُنَتْ مُرْتَفَقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 32, 'وَاضْرۣبببْ لَهُم مَّثَلًا رَّجُلَيْنِ جَعَلْنَا لَأِحَدِهِمَا جَنَّتَيْـنِ مِنَ اَعْنَـٰــبٍ وَحَفَفْنَـٰهُمَا بِنَخْلٍ وَجَعَلْنَا بَيْنَهُمَا زَرْعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 33, 'كِلْتَا ۰لْجَنَّتَيْــنۣ ءَاتَــتُ ۷كْلَهَا وَلَمْ تَظْلِم مِّنْهُ شَيْـٔاًؐ وَفَجَّرْنَا خِچَلَهُمَا نَهَراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 34, 'وَكَانَ لَهُ„ ثُمُرٌؐ فَقَالَ ڤِصَـٰحِبِهِ” وَهُوَ يُحَاوۣرُهُ; أَنَآ أَكْثَرُ مِنــكَ مَالًا وَأَعَزُّ نَفَراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 35, 'وَدَخَـلَ جَنَّتَهُ„ وَهُوَ ظَالِمٌ لِّنَفْسِهِؐ” قَالَ مَآ أَظُنُّ أَن تَبِيدَ هَـٰذِهِ“ أَبَداً وَمَآ أَظُــنُّ ۴لسَّاعَةَ قَآئِمَةً وَلَئِن رُّدِدتُّ إِلَيٰ رَبِّى لَأَجِدَنَّ خَيْراً مِّنْهُمَا مُنقَلَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 36, 'قَالَ لَهُ„ صَـٰحِبُهُ„ وَهُوَ يُحَاوۣرُهُ; أَكَفَرْتَ بِاﻟ﮲ خَلَقَكَ مِن تُرَابٍ ثُمَّ مِن نُّطْفَةٍ ثُمَّ سَوّۭيٰــكَ رَجُلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 37, 'چَّـكِنَّا هُوَ ۰للَّهُ رَبِّى وَلآَ ٱُشْرۣكككُ بِرَبِّــيَ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 38, 'وَلَوْلآَ إِذْ دَخَلْتَ جَنَّتَــكَ قُلْتَ مَا شَآءَ ۰للَّهُ لاَ قُوَّةَ إِلاَّ بِاللَّهِؐ إِن تَرَنِ أَنَآ أَقَلَّ مِنكَ مَالًا وَوَلَداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 39, '02 فَعَسۭيٰ رَبِّيَ أَنْ يُّوتِيَــنۣ” خَيْراً مِّن جَنَّتِــكَ وَيُرْسِــلَ عَلَيْهَا حُسْبَـٰناً مِّــنَ ۰لسَّمَآءِ فَتُصْبِحَ صَعِيداً زَلَقاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 40, 'اَوْ يُصْبِحَ مَآؤُهَا غَوْراً فَلَــن تَسْتَطِيعَ لَهُ„ طَلَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 41, 'وَٱُحِيطَ بِثُمُرۣهِ” فَأَصْبَحَ يُقَلِّبُ كَفَّيْهِ عَلَــيٰ مَآ أَنفَقَ فِيهَا وَهِيَ خَاوۣيَة٘ عَلَيٰ عُرُوشِهَا وَيَقُولُ يَـٰلَيْتَنِى لَمُ ۷شْرۣكْ بِرَبِّــيَ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 42, 'وَلَمْ تَكُــن لَّهُ„ فِـيؕةٌ يَنصُرُونَهُ„ مِن دُونِ ۱للَّهِؐ وَمَا كَانننَ مُنتَصِراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 43, 'هُنَالِــكَ ۰لْوَچَيَةُ لِلهِ ۱لْحَقﱢّؐ هُوَ خَيْرٌ ثَوَاباً وَخَيْر٘ عُقُباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 44, 'وَاضْرۣبْ لَهُم مَّثَــلَ ۰لْحَيَوٰةِ ۱لدُّنْيۭا كَمَآءٖ اَنزَلْنَـٰهُ مِنَ ۰لسَّمَآءِ فَاخْتَلَطَ بِهِ” نَبَاتُ ۴لاَرْضضضِ فَأَصْبَحَ هَشِيماً تَذْرُوهُ ۴لرّۣيَـٰحُؐ وَكَانننَ ۰للَّهُ عَلَيٰ كُلِّ شَيْءٍ مُّقْتَدِراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 45, '۱لْمَالُ وَالْبَنُونَ زۣينَةُ ۴لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَالْبَـٰقِيَـٰــتُ ۴ڤصَّـٰڤِحَـٰــتُ خَيْر٘ عِندَ رَبِّــكَ ثَوَاباً وَخَيْر٘ اَمَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 46, 'وَيَوْمَ نُسَيِّرُ ۴لْجِبَالَ وَتَرَي ۰لاَرْضَ بَارۣزَةً وَحَشَرْنَـٰهُمْ فَلَمْ نُغَادِرْ مِنْهُمُ; أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 47, 'وَعُرۣضُواْ عَلَيٰ رَبِّــكَ صَفّاًؐ لَّقَدْ جِيؔتُمُونَا كَمَا خَلَقْنَـٰكُمُ; أَوَّلَ مَرَّةٙؐ بَلْ زَعَمْتُمُ; أَلَّن نَّجْعَــلَ لَكُم مَّوْعِداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 48, 'وَوُضِعَ 0 ۰لْكِتَـٰبُ فَتَرَي ۰ڤْمُجْرۣمِيــنَ مُشْفِقِيــنَ مِمَّا فِيهِؐ وَيَقُولُونَ يَـٰوَيْلَتَنَا مَالِ هَـٰذَا ۰لْكِتَـٰــبِ لاَ يُغَادِرُ صَغِيرَةً وَلاَ كَبِيرَةٗ اِلٓاَّ أَحْصۭيٰهَاؐ وَوَجَدُواْ مَا عَمِلُواْ حَاضِراًؐ وَلاَ يَظْلِمُ رَبُّكَ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 49, '© وَإِذْ قُلْنَا لِلْمَلَئِكَةِ ۹سْجُدُواْ ءَلِادَمَ فَسَجَدُوٓاْؐ إِلٓاَّ إِبْلِيــسَ كَانَ مِــنَ ۰لْجِــنّۣ فَفَسَقَ عَنَ اَمْرۣ رَبِّهِؐ“ أَفَتَتَّخِذُونَهُ„ وَذُرّۣيَّتَهُ; أَوْلِيَآءَ مِن دُونِى وَهُمْ لَكُمْ عَدُوّٛؐ بِيسَ لِلظَّـٰلِمِينَ بَدَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 50, 'مَّآ أَشْهَدتُّهُمْ خَلْــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضِ وَلاَ خَلْــقَ أَنفُسِهِمْ وَمَا كُنــتُ مُتَّخِذَ ۰لْمُضِلِّيــنَ عَضُداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 51, 'وَيَوْمَ يَقُولُ نَادُواْ شُرَكَآءِيَ ۰لذِينَ زَعَمْتُمْ فَدَعَوْهُمْ فَلَمْ يَسْتَجِيبُواْ لَهُمْ وَجَعَلْنَا بَيْنَهُم مَّوْبِقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 52, 'وَرَءَا ۰ڤْمُجْرۣمُونَ ۰لنَّارَ فَظَنُّوٓاْ أَنَّهُم مُّوَاقِعُوهَا وَلَمْ يَجِدُواْ عَنْهَا مَصْرۣفاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 53, 'وَلَقَدْ صَرَّفْنَا فِى هَـٰذَا ۰لْقُرْءَانِ لِلنَّاسِ مِن كُلِّ مَثَلٍؐ وَكَانَ ۰لِانسَـٰــنُ أَكْثَرَ شَيْءٍ جَدَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 54, 'وَمَا مَنَعَ ۰لنَّاسَ أَنْ يُّومِنُوٓاْ إِذْ جَآءَهُمُ ۴لْهُدۭيٰ وَيَسْتَغْفِرُواْ رَبَّهُمُ; إِلٓاَّ أَن تَاتِيَهُمْ سُنَّةُ ۴لاَوَّلِينَ أَوْ يَاتِيَهُمُ ۴لْعَذَابُ قِبَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 55, '04 وَمَا نُرْسِــلُ ۴لْمُرْسَلِينَ إِلاَّ مُبَشِّرۣينَ وَمُنذِرۣينَؐ وَيُجَـٰدِلُ ۴لذِينَ كَفَرُواْ بِالْبَـٰطِلِ ڤِيُدْحِضُواْ بِهِ ۱لْحَقَّؐ وَاتَّخَذُوٓاْ ءَايَـٰتِى وَمَآ ٱُنذِرُواْ هُزُؤاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 56, 'وَمَــنَ اَظْلَمُ مِمَّــن ذُكِّرَ بِـَٔايَـٰــتِ رَبِّهِ” فَأَعْرَضضضَ عَنْهَا وَنَسِــيَ مَا قَدَّمَتْ يَدَ؛هُؐ إِنَّا جَعَلْنَا عَلَيٰ قُلُوبِهِمُ; أَكِنَّةٗ اَنْ يَّفْقَهُوهُ وَفِىٓ ءَاذَانِهِمْ وَقْراًؐ وَإِن تَدْعُهُمُ; إِلَــي ۰لْهُدۭيٰ فَلَـنْ يَّهْتَدُوٓاْ إِذاٗ اَبَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 57, 'وَرَبُّكَ ۰لْغَفُورُ ذُو ۴لرَّحْمَةِؐ لَوْ يُوَ۬اخِذُهُم بِمَا كَسَبُواْ ڤَعَجَّــلَ لَهُمُ ۴لْعَذَابببَؐ بَــل لَّهُم مَّوْعِدٌ لَّنْ يَّجِدُواْ مِن دُونِهِ” مَوْئِلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 58, 'وَتِلْــكَ ۰لْقُرۭيٰٓ أَهْلَكْنَـٰهُمْ لَمَّا ظَلَمُواْ وَجَعَلْنَا لِمُهْلَكِهِم مَّوْعِداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 59, 'وَإِذْ قَالَ مُوسۭيٰ لِفَتۭيٰهُ لآَ أَبْرَحُ حَتَّيٰٓ أَبْلُغَ مَجْمَعَ ۰ڤْبَحْرَيْنِ أَوَ اَمْضِــيَ حُقُباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 60, 'فَلَمَّا بَلَغَا مَجْمَعَ بَيْنِهِمَا نَسِيَا حُوتَهُمَا فَاتَّخَذَ سَبِيلَهُ„ فِى ۱ڤْبَحْرۣ سَرَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 61, 'فَلَمَّا جَاوَزَا قَالَ لِفَتۭيٰهُ ءَاتِنَا غَدَآءَنَا لَقَدْ لَقِينَا مِــن سَفَرۣنَا هَـٰذَا نَصَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 62, 'قَالَ أَرَ×يْــتَ إِذَ اَوَيْنَآ إِلَــي ۰ڤصَّخْرَةِ فَإِنِّى نَسِيــتُ ۴لْحُوتتتَؐ وَمَآ أَنسۭيٰنِيهِ إِلاَّ ۰لشَّيْطَـٰنُ أَنَ اَذْكُرَهُؐ, وَاتَّخَذَ 05 سَبِيلَهُ„ فِى ۱ڤْبَحْرۣؐ عَجَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 63, 'قَالَ ذَ؛لِــكَ مَا كُنَّا نَبْغِؐ” فَارْتَدَّا عَلَيٰٓ ءَاثۭارۣهِمَا قَصَصاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 64, 'فَوَجَدَا عَبْداً مِّنْ عِبَادِنَآ ءَاتَيْنَـٰهُ رَحْمَةً مِّنْ عِندِنَا وَعَلَّمْنَـٰهُ مِــن لَّدُنَّا عِلْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 65, 'قَالَ لَهُ„ مُوسۭــيٰ هَلَ اَتَّبِعُــكَ عَلَيٰٓ أَن تُعَلِّمَنِ” مِمَّا عُلِّمْتَ رُشْداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 66, 'قَالَ إِنَّــكَ لَــن تَسْتَطِيعَ مَعِى صَبْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 67, 'وَكَيْفَ تَصْبِرُ عَلَــيٰ مَا لَمْ تُحِطْ بِهِ” خُبْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 68, 'قَالَ سَتَجِدُنِيَ إِن شَآءَ ۰للَّهُ صَابِراًؐ وَلآَ أَعْصِى لَــكَ أَمْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 69, 'قَالَ فَإِنِ ''تَّبَعْتَنِى فَلاَ تَسْـَٔلَنِّى عَــن شَيْءٖ حَتَّــيٰٓ ٱُحْدِثَ لَــكَ مِنْهُ ذِكْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 70, 'فَانطَلَقَا حَتَّيٰٓ إِذَا رَكِبَا فِى ۱لسَّفِينَةِ خَرَقَهَاؐ قَالَ أَخَرَقْتَهَا لِتُغْرۣقَ أَهْلَهَا لَقَدْ جِيؔــتَ شَيْـٔاٗ اِمْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 71, 'قَالَ أَلَمَ اَقُـلِ اِنَّــكَ لَــن تَسْتَطِيعَ مَعِى صَبْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 72, 'قَالَ لاَ تُوَ۬اخِذْنِى بِمَا نَسِيتُ وَلاَ تُرْهِقْنِى مِنَ اَمْرۣى عُسْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 73, 'فَانطَلَقَا حَتَّيٰٓ إِذَا لَقِيَا غُچَماً فَقَتَلَهُ„ قَالَ أَقَتَلْــتَ نَفْساً زَ؛كِيَةَۢ بِغَيْرۣ نَفْــسٍ لَّقَدْ جِيؔــتَ شَيْـٔاً نُّكُراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 74, '¤ قَالَ أَلَمَ اَقُل لَّــكَ إِنَّــكَ لَــن تَسْتَطِيعَ مَعِى صَبْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 75, 'قَالَ إِن سَأَلْتُــكَ عَــن شَيْءٙ بَعْدَهَا فَلاَ تُصَـٰحِبْنِى قَدْ بَلَغْــتَ مِن لَّدُنِى 06 عُذْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 76, 'فَانطَلَقَا حَتَّيٰٓ إِذَآ أَتَيَآ أَهْلَ قَرْيَةٖ ''سْتَطْعَمَآ أَهْلَهَا فَأَبَوَاْ اَنْ يُّضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَاراً يُرۣيدُ أَنْ يَّنقَضَّ فَأَقَامَهُؐ, قَالَ لَوْ شِيؔــتَ ڤَتَّخَذتَّ عَلَيْهِ أَجْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 77, 'قَالَ هَـٰذَا فِرَاقُ بَيْنِى وَبَيْنِــكَؐ سَٱُنَبِّيؖــكَ بِتَاوۣيلِ مَا لَمْ تَسْتَطِع عَّلَيْهِ صَبْراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 78, 'اَمَّا ۰لسَّفِينَةُ فَكَانَــتْ لِمَسَـٰكِينَ يَعْمَلُونَ فِى ۱ڤْبَحْرۣ فَأَرَدتُّ أَنَ اَعِيبَهَا وَكَانَ وَرَآءَهُم مَّلِكٌ يَاخُذُ كُلَّ سَفِينَةٖ غَصْباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 79, 'وَأَمَّا ۰لْغُچَمُ فَكَانَ أَبَوَ؛هُ مُومِنَيْنِ فَخَشِينَآ أَنْ يُّرْهِقَهُمَا طُغْيَــٰناً وَكُفْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 80, 'فَأَرَدْنَآ أَنْ يُّبَدِّلَهُمَا رَبُّهُمَا خَيْراً مِّنْهُ زَكَوٰةً وَأَقْرَبَ رُحْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 81, 'وَأَمَّا ۰لْجِدَارُ فَكَانَ لِغُچَمَيْنِ يَتِيمَيْنِ فِى ۱لْمَدِينَةِ وَكَانَ تَحْتَهُ„ كَنزٌ لَّهُمَاؐ وَكَانَ أَبُوهُمَا صَـٰڤِحاً فَأَرَادَ رَبُّكَ أَنْ يَّبْلُغَآ أَشُدَّهُمَا وَيَسْتَخْرۣجَا كَنزَهُمَا رَحْمَةً مِّن رَّبِّــكَؐ وَمَا فَعَلْتُهُ„ عَنَ اَمْرۣىؐ ذَ؛لِــكَ تَاوۣيلُ مَا لَمْ تَسْطِع عَّلَيْهِ صَبْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 82, 'وَيَسْـَٔلُونَــكَ عَن ذى ۱لْقَرْنَيْنِؐ قُلْ سَأَتْلُواْ عَلَيْكُم مِّنْهُ ذِكْراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 83, 'اِنَّا مَكَّنَّا لَهُ„ فِى ۱لاَرْضِ وَءَاتَيْنَــٰهُ مِن كُلِّ شَيْءٍ سَبَباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 84, '07 فَاتَّبَعَ سَبَباٗ حَتَّيٰٓ إِذَا بَلَغَ مَغْرۣبَ ۰لشَّمْسِ وَجَدَهَا تَغْرُبُ فِى عَيْنٖ حَمِيؕةٍ وَوَجَدَ عِندَهَا قَوْماًؐ قُلْنَا يَـٰذَا ۰لْقَرْنَيْنِ إِمَّآ أَن تُعَذِّبببَ وَإِمَّآ أَن تَتَّخِذَ فِيهِمْ حُسْناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 85, 'قَالَ أَمَّا مَن ظَلَمَ فَسَوْفَ نُعَذِّبُهُ„ ثُمَّ يُرَدُّ إِلَيٰ رَبِّهِ” فَيُعَذِّبُهُ„ عَذَاباً نُّكُراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 86, 'وَأَمَّا مَنَ —امَنَ وَعَمِلَ صَـٰڤِحاً فَلَهُ„ جَزَآءُ ۴لْحُسْنۭيٰؐ وَسَنَقُولُ لَهُ„ مِنَ اَمْرۣنَا يُسْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 87, 'ثُمَّ "تَّبَعَ سَبَباٗ حَتَّيٰٓ إِذَا بَلَغَ مَطْلِعَ ۰لشَّمْسِ وَجَدَهَا تَطْلُعُ عَلَيٰ قَوْمٍ لَّمْ نَجْعَل لَّهُم مِّن دُونِهَا سِتْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 88, 'كَذَ؛لِــكَؐ وَقَدَ اَحَطْنَا بِمَا لَدَيْهِ خُبْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 89, 'ثُمَّ "تَّبَعَ سَبَباٗ حَتَّيٰٓ إِذَا بَلَغَ بَيْنَ ۰لسُّدَّيْنِ وَجَدَ مِن دُونِهِمَا قَوْماً لاَّ يَكَادُونَ يَفْقَهُونَ قَوْلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 90, 'قَالُواْ يَــٰذَا ۰لْقَرْنَيْنِ إِنَّ يَاجُوجَ وَمَاجُوجَ مُفْسِدُونَ فِى ۱لاَرْضِ فَهَلْ نَجْعَلُ لَــكَ خَرْجاٗ عَلَـيٰٓ أَن تَجْعَلَ بَيْنَنَا وَبَيْنَهُمْ سُدّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 91, 'قَالَ مَا مَكَّنِّى فِيهِ رَبِّى خَيْرٌؐ فَأَعِينُونِى بِقُوَّةٖ اَجْعَلْ بَيْنَكُمْ وَبَيْنَهُمْ رَدْماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 92, '—اتُونِى زُبَـرَ ۰لْحَدِيدِؐ حَتَّيٰٓ إِذَا سَاوۭيٰ بَيْنَ ۰لصَّدَفَيْنِ قَالَ ۸نفُخُواْؐ حَتَّيٰٓ إِذَا جَعَلَهُ„ نَاراً 08 قَالَ ءَاتُونِىٓ ٱُفْرۣغْ عَلَيْهِ قِطْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 93, 'فَمَا "سْطَـٰعُوٓاْ أَنْ يَّظْهَرُوهُ وَمَا "سْتَطَـٰعُواْ لَهُ„ نَقْباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 94, 'قَالَ هَـٰذَا رَحْمَةٌ مِّن رَّبِّىؐ فَإِذَا جَآءَ وَعْدُ رَبِّى جَعَلَهُ„ دَكّاً وَكَانَ وَعْدُ رَبِّى حَقّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 95, 'وَتَرَكْنَا بَعْضَهُمْ يَوْمَئِذٍ يَمُوجُ فِى بَعْضٍؐ وَنُفِخَ فِى ۱لصُّورۣ فَجَمَعْنَـٰهُمْ جَمْعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 96, 'وَعَرَضْنَا جَهَنَّمَ يَوْمَئِذٍ لِّلْكۭـٰفِرۣينَ عَرْضاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 97, '۱لذِينَ كَانَــتَ اَعْيُنُهُمْ فِى غِطَآءٖ عَن ذِكْرۣى وَكَانُواْ لاَ يَسْتَطِيعُونَ سَمْعاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 98, '© اَفَحَسِــبَ ۰لذِينَ كَفَرُوٓاْ أَنْ يَّتَّخِذُواْ عِبَادِى مِن دُونِيَ أَوْلِيَآءَؐ اۭنَّآ أَعْتَدْنَا جَهَنَّمَ لِلْكۭـٰفِرۣينَ نُزُلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 99, 'قُلْ هَلْ نُنَبِّيؖكُم بِالاَخْسَرۣينَ أَعْمَـٰلٗا ۱لذِينَ ضَلَّ سَعْيُهُمْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَهُمْ يَحْسِبُونَ أَنَّهُمْ يُحْسِنُونَ صُنْعاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 100, '۷وْلَئِــكَ ۰لذِينَ كَفَرُواْ بِـَٔايَــٰــتِ رَبِّهِمْ وَلِقَآئِهِ” فَحَبِطَــتَ اَعْمَــٰلُهُمْ فَلاَ نُقِيمُ لَهُمْ يَوْمَ ۰لْقِيَــٰمَةِ وَزْناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 101, 'ذَ؛لِــكَ جَزَآؤُهُمْ جَهَنَّمُ بِمَا كَفَرُواْ وَاتَّخَذُوٓاْ ءَايَــٰتِى وَرُسُلِى هُزُؤاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 102, 'اِنَّ ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَــٰــتِ كَانَــتْ لَهُمْ جَنَّــٰــتُ ۴لْفِرْدَوْسِ نُزُلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 103, 'خَــٰلِدِينَ 09 فِيهَا لاَ يَبْغُونَ عَنْهَا حِوَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 104, 'قُل لَّوْ كَانَ ۰ڤْبَحْرُ مِدَاداً لِّكَلِمَـٰــتِ رَبِّى لَنَفِدَ ۰ڤْبَحْرُ قَبْلَ أَن تَنفَدَ كَلِمَـٰــتُ رَبِّى وَلَوْ جِيؔنَا بِمِثْلِهِ” مَدَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (18, 105, 'قُلِ اِنَّمَآ أَنَا بَشَرٌ مِّثْلُكُمْ يُوحۭيٰٓ إِلَــيَّ أَنَّمَآ إِچَهُكُمُ; إِچَهٌ وَ؛حِدٌؐ فَمَــن كَانَ يَرْجُواْ لِقَآءَ رَبِّهِ” فَلْيَعْمَــلْ عَمَلًا صَـٰڤِحاً وَلاَ يُشْرۣكككْ بِعِبَادَةِ رَبِّهِ“ أَحَداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ كَٓهۭيۭعَٓصَٓؐ ذِكْرُ رَحْمَــتِ رَبِّــكَ عَبْدَهُ„ زَكَرۣيَّآءَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 2, 'اۭذْ نَادۭيٰ رَبَّهُ„ نِدَآءٗ خَفِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 3, 'قَالَ رَبِّ إِنِّى وَهَنَ ۰لْعَظْمُ مِنِّى وَاشْتَعَلَ ۰لرَّأْسسسُ شَيْباً وَلَمَ اَكُنۢ بِدُعَآئِــكَ رَبِّ شَقِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 4, 'وَإِنِّى خِفْتُ ۴لْمَوَ؛لِيَ مِنْ وَّرَآءِى وَكَانَــتِ ''مْرَأَتِى عَاقِراً فَهَــبْ لِى مِــن لَّدُنــكَ وَلِيّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 5, 'يَرۣثُنِى وَيَرۣثُ مِــنَ —الِ يَعْقُوبَؐ وَاجْعَلْهُ رَبِّ رَضِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 6, 'يَـٰزَكَرۣيَّآءُ اِ۬نَّا نُبَشِّرُكككَ بِغُچَـمٖ ''سْمُهُ„ يَحْيۭيٰ لَمْ نَجْعَل لَّهُ„ مِن قَبْلُ سَمِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 7, 'قَالَ رَبِّ أَنّۭيٰ يَكُونُ لِى غُچَمٌ وَكَانَتِ ''مْرَأَتِى عَاقِراً 10 وَقَدْ بَلَغْتُ مِــنَ ۰لْكِبَرۣ عُتِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 8, 'قَالَ كَذَ؛لِــكَ قَالَ رَبُّــكَ هُوَ عَلَــيَّ هَيِّنٌ وَقَدْ خَلَقْتُــكَ مِــن قَبْلُ وَلَمْ تَكُ شَيْـٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 9, 'قَالَ رَبِّ ''جْعَل لِّيَ ءَايَةًؐ قَالَ ءَايَتُــكَ أَلاَّ تُكَلِّمَ ۰لنَّاسسسَ ثَچَثَ لَيَالٍ سَوۣيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 10, 'فَخَرَجَ عَلَيٰ قَوْمِهِ” مِــنَ ۰ڤْمِحْرَابِ فَأَوْحۭيٰٓ إِلَيْهِمُ; أَن سَبِّحُواْ بُكْرَةً وَعَشِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 11, 'يَـٰيَحْيۭــيٰ خُذِ ۱لْكِتَـٰــبَ بِقُوَّةٍؐ وَءَاتَيْنَـٰهُ ۴لْحُكْمَ صَبِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 12, 'وَحَنَاناً مِّــن لَّدُنَّا وَزَكَوٰةًؐ وَكَانَ تَقِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 13, 'وَبَرّاَۢ بِوَ؛لِدَيْهِ وَلَمْ يَكُن جَبَّاراٗ عَصِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 14, 'وَسَچَم٘ عَلَيْهِ يَوْمَ وُلِدَ وَيَوْمَ يَمُوتُ وَيَوْمَ يُبْعَــثُ حَيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 15, 'وَاذْكُرْ فِى ۱لْكِتَـٰــبِ مَرْيَمَ إِذِ ''نتَبَذَتْ مِــنَ اَهْلِهَا مَكَاناً شَرْقِيّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 16, 'فَاتَّخَذَتْ مِن دُونِهِمْ حِجَاباًؐ فَأَرْسَلْنَآ إِلَيْهَا رُوحَنَا فَتَمَثَّــلَ لَهَا بَشَراً سَوۣيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 17, 'قَالَتِ اِنِّــيَ أَعُوذُ بِالرَّحْمَـٰنِ مِنــكَ إِن كُنــتَ تَقِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 18, 'قَالَ إِنَّمَآ أَنَا رَسُولُ رَبِّــكِ ¡هَبَ لَــكِ غُچَماً زَكِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 19, 'قَالَتَ اَنّۭــيٰ يَكُونُ لِى غُچَمٌ وَلَمْ يَمْسَسْنِى بَشَرٌ وَلَمَ اَكُ بَغِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 20, 'قَالللَ كَذَ؛لِــكِ قَالَ رَبُّــكِ هُوَ عَلَيَّ هَيِّنٌؐ وَڤِنَجْعَلَهُ; ءَايَةً لِّلنَّاسِ وَرَحْمَةً مِّنَّاؐ وَكَانَ أَمْراً مَّقْضِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 21, '11 ¥ فَحَمَلَتْهُ فَانتَبَذَتْ بِهِ” مَكَاناً قَصِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 22, 'فَأَجَآءَهَا ۰ڤْمَخَاضُ إِلَيٰ جِذْعِ ۱لنَّخْلَةِ قَالَتْ يَـٰلَيْتَنِى مِتُّ قَبْــلَ هَـٰذَا وَكُنــتُ نِسْياً مَّنسِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 23, 'فَنَادۭيٰهَا مِــن تَحْتِهَآ أَلاَّ تَحْزَنِى قَدْ جَعَلَ رَبُّــكِ تَحْتَــكِ سَرۣيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 24, 'وَهُزّۣىٓ إِلَيْــكِ بِجِذْعِ ۱ڤنَّخْلَةِ تَسَّـٰقَطْ عَلَيْــكِ رُطَباً جَنِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 25, 'فَكُلِى وَاشْرَبِى وَقَرّۣى عَيْناًؐ فَإِمَّا تَرَيِنَّ مِنَ ۰لْبَشَرۣ أَحَداً فَقُولِىٓ إِنِّى نَذَرْتُ لِلرَّحْمَـٰــنۣ صَوْماً فَلَنُ ۷كَلِّمَ ۰لْيَوْمَ إِنسِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 26, 'فَأَتَتْ بِهِ” قَوْمَهَا تَحْمِلُهُؐ, قَالُواْ يَـٰمَرْيَمُ لَقَدْ جِيؔــتِ شَيْـٔاً فَرۣيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 27, 'يَـٰٓٱُخْــتَ هَـٰرُونَ مَا كَانَ أَبُوكككِ ''مْرَأَ سَوْءٍ وَمَا كَانَــتُ ۷مُّــكِ بَغِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 28, 'فَأَشَارَتِ اِلَيْهِؐ قَالُواْ كَيْفَ نُكَلِّمُ مَــن كَانَ فِى ۱لْمَهْدِ صَبِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 29, 'قَالَ إِنِّى عَبْدُ ۴للَّهِ ءَاتۭيٰنِــيَ ۰لْكِتَـٰبَ وَجَعَلَنِى نَبِيٓــٔاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 30, 'وَجَعَلَنِى مُبَـٰرَكاٗ اَيْــنَ مَا كُنــتُ وَأَوْصۭـٰنِى بِالصَّلَوٰةِ وَالزَّكَوٰةِ مَا دُمْتُ حَيّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 31, 'وَبَرّاَۢ بِوَ؛لِدَتِىؐ وَلَمْ يَجْعَلْنِى جَبَّاراً شَقِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 32, 'وَالسَّچَمُ عَلَيَّ يَوْمَ وُلِدتُّ وَيَوْمَ أَمُوتُ وَيَوْمَ ٱُبْعَثُ حَيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 33, 'ذَ؛لِــكَ عِيسَي "بْنُ مَرْيَمَؐ قَوْلُ ۴لْحَقِّ ۱ﻟ﮲ فِيهِ يَمْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 34, '12 مَا كَانَ لِلهِ أَنْ يَّتَّخِذَ مِنْ وَّلَدٍؐ سُبْحَـٰنَهُؐ; إِذَا قَضۭــيٰٓ أَمْراً فَإِنَّمَا يَقُولُ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 35, 'وَأَنَّ ۰للَّهَ رَبِّى وَرَبُّكُمْ فَاعْبُدُوهُؐ هَـٰذَا صِرَ؛طٌ مُّسْتَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 36, 'فَاخْتَلَفَ ۰لاَحْزَابببُ مِـنۢ بَيْنِهِمْؐ فَوَيْلٌ لِّلذِيــنَ كَفَرُواْ مِــن مَّشْهَدِ يَوْمٖ عَظِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 37, 'اَسْمِعْ بِهِمْ وَأَبْصِرْ يَوْمَ يَاتُونَنَاؐ چَكِنِ ۱لظَّـٰلِمُونَ ۰لْيَوْمَ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 38, 'وَأَنذِرْهُمْ يَوْمَ ۰لْحَسْرَةِ إِذْ قُضِــيَ ۰لاَمْرُ وَهُمْ فِى غَفْلَةٍ وَهُمْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 39, 'إِنَّا نَحْنُ نَرۣثُ ۴لاَرْضَ وَمَنْ عَلَيْهَاؐ وَإِلَيْنَا يُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 40, 'وَاذْكُرْ فِى ۱لْكِتَـٰــبِ إِبْرَ؛هِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 41, 'إِنَّهُ„ كَانَ صِدِّيقاً نَّبِيٓــٔاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 42, 'اِذْ قَالَ لَأِبِيهِ يَـٰٓأَبَــتِ لِمَ تَعْبُدُ مَا لاَ يَسْمَعُ وَلاَ يُبْصِرُ وَلاَ يُغْنِى عَنــكَ شَيْـٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 43, 'يَـٰٓأَبَــتِ إِنِّى قَدْ جَآءَنِى مِــنَ ۰لْعِلْمِ مَا لَمْ يَاتِــكَ فَاتَّبِعْنِىٓ أَهْدِكَ صِرَ؛طاً سَوۣيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 44, 'يَـٰٓأَبَــتِ لاَ تَعْبُدِ ۱لشَّيْطَـٰنَؐ إِنَّ ۰لشَّيْطَـٰــنَ كَانَ لِلرَّحْمَـٰــنۣ عَصِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 45, 'يَـٰٓأَبَــتِ إِنِّــيَ أَخَافُ أَنْ يَّمَسَّــكَ عَذَابٌ مِّنَ ۰لرَّحْمَـٰنِ فَتَكُونَ لِلشَّيْطَـٰنِ وَلِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 46, 'قَالَ أَرَاغِب٘ اَنتَ عَــنَ —الِهَتِىؐ يَـٰٓإِبْرَ؛هِيمُ لَئِن لَّمْ تَنتَهِ 1 لَأَرْجُمَنَّــكَ وَاهْجُرْنِى مَلِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 47, 'قَالَ سَچَم٘ عَلَيْــكَ سَأَسْتَغْفِرُ لَــكَ رَبِّيَ إِنَّهُ„ كَانَ بِى حَفِيّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 48, 'وَأَعْتَزۣلُكُمْ وَمَا تَدْعُونَ مِن دُونِ ۱للَّهِ وَأَدْعُواْ رَبِّى عَسۭــيٰٓ أَلٓاَّ أَكُونَ بِدُعَآءِ رَبِّى شَقِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 49, 'فَلَمَّا "عْتَزَلَهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ۱للَّهِ وَهَبْنَا لَهُ; إِسْحَـٰقَ وَيَعْقُوبَؐ وَكُلًاّ جَعَلْنَا نَبِيٓــٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 50, 'وَوَهَبْنَا لَهُم مِّن رَّحْمَتِنَا وَجَعَلْنَا لَهُمْ لِسَانَ صِدْقٖ عَلِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 51, 'وَاذْكُرْ فِى ۱لْكِتَـٰــبِ مُوسۭيٰٓ إِنَّهُ„ كَانننَ مُخْلِصاً وَكَانَ رَسُولًا نَّبِيٓــٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 52, 'وَنَـٰدَيْنَـٰهُ مِن جَانِــبِ ۱لطُّورۣ ۱لاَيْمَنِ وَقَرَّبْنَـٰهُ نَجِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 53, 'وَوَهَبْنَا لَهُ„ مِن رَّحْمَتِنَآ أَخَاهُ هَـٰرُونَ نَبِيٓــٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 54, 'وَاذْكُرْ فِى ۱لْكِتَـٰــبِ إِسْمَـٰعِيلَ إِنَّهُ„ كَانَ صَادِقَ ۰لْوَعْدِ وَكَانَ رَسُولًا نَّبِيٓــٔاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 55, 'وَكَانَ يَامُرُ أَهْلَهُ„ بِالصَّلَوٰةِ وَالزَّكَوٰةِؐ وَكَانَ عِندَ رَبِّهِ” مَرْضِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 56, 'وَاذْكُرْ فِى ۱لْكِتَـٰــبِ إِدْرۣيـسَ إِنَّهُ„ كَانَ صِدِّيقاً نَّبِيٓـــٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 57, 'وَرَفَعْنَـٰهُ مَكَاناٗ عَلِيّــاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 58, '۷وْلَئِكَ ۰لذِيــنَ أَنْعَمَ ۰للَّهُ عَلَيْهِم مِّنَ ۰لنَّبِيٓــٕـﯧــــنَ مِن ذُرّۣيَّةِ ءَادَمَ وَمِمَّــنْ حَمَلْنَا مَعَ نُوحٍ وَمِن ذُرّۣيَّةِ إِبْرَ؛هِيمَ وَإِسْرَآءِيلَ 14 وَمِمَّنْ هَدَيْنَا وَاجْتَبَيْنَآؐ إِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُ ۴لرَّحْمَـٰنِ خَرُّواْ سُجَّداً وَبُكِيّاًؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 59, '© فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْف٘ اَضَاعُواْ ۴لصَّلَوٰةَ وَاتَّبَعُواْ ۴لشَّهَوَ؛تِ فَسَوْفَ يَلْقَوْنَ غَيّاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 60, 'اِلاَّ مَــن تَابَ وَءَامَنَ وَعَمِــلَ صَـٰڤِحاً فَٱُوْلَئِكَ يَدْخُلُونَ ۰لْجَنَّةَ وَلاَ يُظْلَمُونَ شَيْـٔاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 61, 'جَنَّـٰتِ عَدْنٖ ۱لتِى وَعَدَ ۰لرَّحْمَـٰنُ عِبَادَهُ„ بِالْغَيْــبِؐ إِنَّهُ„ كَانَ وَعْدُهُ„ مَاتِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 62, 'لاَّ يَسْمَعُونَ فِيهَا لَغْواٗؐ اِلاَّ سَچَماًؐ وَلَهُمْ رۣزْقُهُمْ فِيهَا بُكْرَةً وَعَشِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 63, 'تِلْــكَ ۰لْجَنَّةُ ۴لتِى نُورۣثُ مِنْ عِبَادِنَا مَــن كَانَ تَقِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 64, 'وَمَا نَتَنَزَّلُ إِلاَّ بِأَمْرۣ رَبِّــكَؐ لَهُ„ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا وَمَا بَيْــنَ ذَ؛لِــكَؐ وَمَا كَانَ رَبُّــكَ نَسِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 65, 'رَّبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَا فَاعْبُدْهُ وَاصْطَبِرْ لِعِبَـٰدَتِهِؐ” هَلْ تَعْلَمُ لَهُ„ سَمِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 66, 'وَيَقُولُ ۴لِانسَـٰنُ أَ.ذَا مَا مِــتُّ لَسَوْفَ ٱُخْرَجُ حَيّاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 67, 'اَوَلاَ يَذْكُرُ ۴لِانسَـٰــنُ أَنَّا خَلَقْنَـٰهُ مِن قَبْلُ وَلَمْ يَــكُ شَيْـٔاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 68, 'فَوَرَبِّــكَ ڤَنَحْشُرَنَّهُمْ وَالشَّيَـٰطِيــنَ ثُمَّ ڤَنُحْضِرَنَّهُمْ حَوْلَ جَهَنَّمَ جُثِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 69, 'ثُمَّ لَنَنزۣعَــنَّ مِـن كُلِّ شِيعَةٖ اَيُّهُمُ; أَشَدُّ 15 عَلَي ۰لرَّحْمَـٰــنۣ عُتِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 70, 'ثُمَّ ڤَنَحْــنُ أَعْلَمُ بِالذِينَ هُمُ; أَوْلۭيٰ بِهَا صُلِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 71, 'وَإِن مِّنكُمُ; إِلاَّ وَارۣدُهَا كَانننَ عَلَيٰ رَبِّــكَ حَتْماً مَّقْضِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 72, 'ثُمَّ نُـنَجّىِ ۱لذِينَ "تَّقَواْ وَّنَذَرُ ۴لظَّـٰلِمِينَ فِيهَا جُثِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 73, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُنَا بَيِّنَـٰــتٍ قَالَ ۰لذِيــنَ كَفَرُواْ لِلذِيــنَ ءَامَنُوٓاْ أَيُّ ۴لْفَرۣيقَيْــنۣ خَيْرٌ مَّقَاماً وَأَحْسَنُ نَدِيّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 74, 'وَكَمَ اَهْلَكْنَا قَبْلَهُم مِّن قَرْنٖ هُمُ; أَحْسَنُ أَثَـٰثاً وَرۣءْياًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 75, 'قُـلْ مَن كَانَ فِى ۱لضَّچَلَةِ فَلْيَمْدُدْ لَهُ ۴لرَّحْمَـٰــنُ مَدّاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 76, 'حَتَّيٰٓ إِذَا رَأَوْاْ مَا يُوعَدُونَ إِمَّا ۰لْعَذَابَ وَإِمَّا ۰لسَّاعَةَ فَسَيَعْلَمُونَ مَنْ هُوَ شَرٌّ مَّكَاناً وَأَضْعَفُ جُنداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 77, 'وَيَزۣيدُ ۴للَّهُ ۴لذِينَ "هْتَدَوْاْ هُديًؐ وَالْبَـٰقِيَـٰـــتُ ۴ڤصَّـٰڤِحَـٰتُ خَيْر٘ عِندَ رَبِّــكَ ثَوَاباً وَخَيْرٌ مَّرَدّاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 78, 'اَفَرَ×يْتَ ۰ﻟ﮲ كَفَرَ بِـَٔايَـٰتِنَا وَقَالَ لُءَوتَيَــنَّ مَالًا وَوَلَداٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 79, 'اَطَّلَعَ ۰لْغَيْبَ أَمِ ''تَّخَذَ عِندَ ۰لرَّحْمَـٰــنۣ عَهْداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 80, 'كَلؐاَّ سَنَكْتُــبُ مَا يَقُولُ وَنَمُدُّ لَهُ„ مِــنَ ۰لْعَذَابِ مَدّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 81, 'وَنَرۣثُهُ„ مَا يَقُولُ وَيَاتِينَا فَرْداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 82, 'وَاتَّخَذُواْ مِن دُونِ ۱للَّهِ ءَالِهَةً 16 لِّيَكُونُواْ لَهُمْ عِزّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 83, 'كَلؐاَّ سَيَكْفُرُونَ بِعِبَادَتِهِمْ وَيَكُونُونَ عَلَيْهِمْ ضِدّاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 84, 'اَلَمْ تَرَ أَنَّـآ أَرْسَلْنَا ۰لشَّيَـٰطِينَ عَلَــي ۰لْكۭـٰفِـرۣينَ تَؤُزُّهُمُ; أَزّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 85, 'فَلاَ تَعْجَــلْ عَلَيْهِمُؐ; إِنَّمَا نَعُدُّ لَهُمْ عَدّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 86, 'يَوْمَ نَحْشُرُ ۴لْمُتَّقِينَ إِلَي ۰لرَّحْمَـٰنِ وَفْداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 87, 'وَنَسُوقُ ۴ڤْمُجْرۣمِيــنَ إِلَيٰ جَهَنَّمَ وۣرْداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 88, 'لاَّ يَمْلِكُونَ ۰لشَّفَـٰعَةَ إِلاَّ مَـنِ ''تَّخَذَ عِندَ ۰لرَّحْمَـٰــنۣ عَهْداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 89, 'وَقَالُواْ èتَّخَذَ ۰لرَّحْمَـٰنُ وَلَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 90, 'لَّقَدْ جِيؔتُمْ شَيْـٔاٗ اِدّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 91, 'يَكَادُ ۴لسَّمَـٰوَ؛تُ يَتَفَطَّرْنَ مِنْهُ وَتَنشَــقُّ ۴لاَرْضُ وَتَخِرُّ ۴لْجِبَالُ هَدّاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 92, 'اَن دَعَوْاْ لِلرَّحْمَـٰنِ وَلَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 93, 'وَمَا يَنۢبَغِى لِلرَّحْمَـٰنِ أَنْ يَّتَّخِذَ وَلَداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 94, 'اِننن كُلُّ مَن فِى ۱لسَّمَـٰوَ؛تتتِ وَالاَرْضِ إِلٓاَّ ءَاتِى ۱لرَّحْمَـٰنِ عَبْداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 95, 'لَّقَدَ اَحْصۭيٰهُمْ وَعَدَّهُمْ عَدّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 96, 'وَكُلُّهُمُ; ءَاتِيهِ يَوْمَ ۰لْقِيَـٰمَةِ فَرْداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 97, 'اِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ سَيَجْعَــلُ لَهُمُ ۴لرَّحْمَـٰنُ وُدّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 98, 'فَإِنَّمَا يَسَّرْنَـٰهُ بِلِسَانِــكَ لِتُبَشِّرَ بِهِ ۱لْمُتَّقِينَ وَتُنذِرَ بِهِ” قَوْماً لُّدّاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (19, 99, 'وَكَمَ اَهْلَكْنَا قَبْلَهُم مِّن قَرْنٖ هَـلْ تُحِسُّ مِنْهُم مِّــنَ اَحَدٖ اَوْ تَسْمَعُ لَهُمْ رۣكْزاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ طَهۭؐ مَآ أَنزَلْنَا عَلَيْكَ ۰لْقُرْءَانَ لِتَشْقۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 2, 'إِلاَّ تَذْكِرَةً لِّمَــنْ يَّخْشۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 3, 'تَنزۣيلًا مِّمَّــنْ خَلَقَ ۰لاَرْضَ وَالسَّمَـٰوَ؛تِ ۱لْعُلَيؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 4, '۰لرَّحْمَـٰــنُ عَلَــي ۰لْعَرْشِ ''سْتَوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 5, 'لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِ وَمَا بَيْنَهُمَا وَمَا تَحْــتَ ۰لثَّرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 6, 'وَإِن تَجْهَرْ بِالْقَوْلِ فَإِنَّهُ„ يَعْلَمُ ۴لسِّرَّ وَأَخْفَيؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 7, '۰للَّهُ لآَ إِچَهَ إِلاَّ هُوَؐ لَهُ ۴لاَسْمَآءُ ۴لْحُسْنۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 8, 'وَهَلَ اَتۭيٰــكَ حَدِيــثُ مُوسۭــيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 9, 'إِذْ رۭءۭا نَاراً فَقَالَ لَأِهْلِهِ ۹مْكُثُوٓاْ إِنِّيَ ءَانَسْــتُ نَاراً لَّعَلِّــيَ ءَاتِيكُم مِّنْهَا بِقَبَسٖ اَوَ اَجِدُ عَلَي ۰لنّۭارۣ هُديًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 10, 'فَلَمَّآ أَتۭيٰهَا نُودِيَ يَـٰمُوسۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 11, 'إِنِّــيَ أَنَا رَبُّكَ فَاخْلَعْ نَعْلَيْــكَ إِنَّــكَ بِالْوَادِ ۱لْمُقَدَّسسسِ طُوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 12, 'وَأَنَا "خْتَرْتُــكَ فَاسْتَمِعْ لِمَا يُوحۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 13, 'إِنَّنِــيَ أَنَا ۰للَّهُ لآَ إِچَهَ إِلٓاَّ أَنَا فَاعْبُدْنِى وَأَقِمِ ۱لصَّلَوٰةَ لِذِكْرۣيَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 14, 'إِنننَّ ۰لسَّاعَةَ ءَاتِيَة٘ اَكَادُ ٱُخْفِيهَا ڤِتُجْزۭيٰ كُلُّ نَفْسٙ بِمَا تَسْعۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 15, 'فَلاَ يَصُدَّنَّكَ عَنْهَا مَن 18 لاَّ يُومِـنُ بِهَا وَاتَّبَعَ هَوۭيٰهُ فَتَرْدۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 16, 'وَمَا تِلْــكَ بِيَمِينِــكَ يَـٰمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 17, 'قَالَ هِــيَ عَصَايَ أَتَوَكَّؤُاْ عَلَيْهَا وَأَهُشُّ بِهَا عَلَيٰ غَنَمِى وَلِيَ فِيهَا مَـَٔارۣبُ ٱُخْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 18, 'قَالَ أَلْقِهَا يَـٰمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 19, 'فَأَلْقۭيٰهَا فَإِذَا هِــيَ حَيَّةٌ تَسْعۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 20, 'قَالَ خُذْهَا وَلاَ تَخَفْ سَنُعِيدُهَا سِيرَتَهَا ۰لاُولۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 21, 'وَاضْمُمْ يَدَكَ إِلَــيٰ جَنَاحِــكَ تَخْرُجْ بَيْضَآءَ مِــنْ غَيْرۣ سُوٓءٖ —ايَةٗ ۷خْرۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 22, 'لِنُرۣيَــكَ مِــنَ —ايَـٰتِنَا ۰لْكُبْرَيؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 23, '"ذْهَــبِ اِلَيٰ فِرْعَوْنَ إِنَّهُ„ طَغۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 24, 'قَالَ رَبِّ ''شْرَحْ لِى صَدْرۣى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 25, 'وَيَسِّرْ لِيَ أَمْرۣى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 26, 'وَاحْلُــلْ عُقْدَةً مِّن لِّسَانِى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 27, 'يَفْقَهُواْ قَوْلِى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 28, 'وَاجْعَـل لِّى وَزۣيراً مِّــنَ اَهْلِى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 29, 'هَـٰرُونَ أَخِىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 30, '۹شْدُدْ بِهِ“ أَزْرۣى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 31, 'وَأَشْرۣكْهُ فِىٓ أَمْرۣى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 32, 'كَىْ نُسَبِّحَــكَ كَثِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 33, 'وَنَذْكُرَكككَ كَثِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 34, 'اِنَّكَ كُنتَ بِنَا بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 35, 'قَالَ قَدُ ۷وتِيتَ سُؤْلَــكَ يَـٰمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 36, 'وَلَقَدْ مَنَنَّـا عَلَيْــكَ مَرَّةٗ ۷خْرۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 37, 'إِذَ اَوْحَيْنَآ إِلَـيٰٓ ٱُمِّــكَ مَا يُوحۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 38, 'أَنِ ''قْذِفِيهِ فِى ۱لتَّابُوتِ فَاقْذِفِيهِ فِى ۱لْيَمﱢّؐ فَلْيُلْقِهِ ۱لْيَمُّ بِالسَّاحِلِ يَاخُذْهُ عَدُوٌّ لِّى 19 وَعَدُوٌّ لَّهُؐ, وَأَلْقَيْتُ عَلَيْــكَ مَحَبَّةً مِّنِّى');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 39, 'وَلِتُصْنَعَ عَلَيٰ عَيْنِيَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 40, 'إِذْ تَمْشِىٓ ٱُخْتُكَ فَتَقُولُ هَــلَ اَدُلُّكُمْ عَلَيٰ مَنْ يَّكْفُلُهُؐ, فَرَجَعْنَـٰكَ إِلَـيٰٓ ٱُمِّــكَ كَىْ تَقَرَّ عَيْنُهَا وَلاَ تَحْزَنَؐ وَقَتَلْتَ نَفْساً فَنَجَّيْنَـٰــكَ مِــنَ ۰لْغَمِّ وَفَتَنَّـٰــكَ فُتُوناًؐ فَلَبِثْتَ سِنِينَ فِىٓ أَهْــلۣ مَدْيَنَ ثُمَّ جِيؔتَ عَلَــيٰ قَدَرٍ يَـٰمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 41, 'وَاصْطَنَعْتُــكَ لِنَفْسِيَؐ "ذْهَبَ اَنتَ وَأَخُوكَ بِـَٔايَـٰتِى وَلاَ تَنِيَا فِى ذِكْرۣيَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 42, '"ذْهَبَآ إِلَيٰ فِرْعَوْنَ إِنَّهُ„ طَغۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 43, 'فَقُولاَ لَهُ„ قَوْلًا لَّيِّناً لَّعَلَّهُ„ يَتَذَكَّرُ أَوْ يَخْشۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 44, 'قَالاَ رَبَّنَآ إِنَّنَا نَخَافُ أَنْ يَّفْرُطَ عَلَيْنَآ أَوَ اَنْ يَّطْغۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 45, 'قَالَ لاَ تَخَافَآ إِنَّنِى مَعَكُمَآ أَسْمَعُ وَأَرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 46, 'فَاتِيَـٰهُ فَقُولآَ إِنَّا رَسُولاَ رَبِّكَ فَأَرْسِــلْ مَعَنَا بَنِىٓ إِسْرَآءِيلَ وَلاَ تُعَذِّبْهُمْ قَدْ جِيؔنَـٰــكَ بِـَٔايَةٍ مِّن رَّبِّــكَؐ وَالسَّچَمُ عَلَيٰ مَنِ ''تَّبَعَ ۰لْهُدۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 47, 'إِنَّا قَدُ ۷وحِيَ إِلَيْنَآ أَنَّ ۰لْعَذَابَ عَلَيٰ مَن كَذَّبَ وَتَوَلّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 48, 'قَالَ فَمَن رَّبُّكُمَا يَـٰمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 49, 'قَالَ رَبُّنَا ۰ﻟـذِىٓ أَعْطۭــيٰ كُــلَّ شَيْءٖ خَلْقَهُ„ ثُمَّ هَدۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 50, 'قَالَ فَمَا بَالُ ۴لْقُرُونِ ۱لاُولۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 51, 'قَالَ عِلْمُهَا عِندَ رَبِّى فِى كِتَـٰبٍؐ 20 لاَّ يَضِلُّ رَبِّى وَلاَ يَنسَيؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 52, '۰ﻟ﮲ جَعَــلَ لَكُمُ ۴لاَرْضضضَ مِهَـٰداً وَسَلَــكَ لَكُمْ فِيهَا سُبُلًا وَأَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءًؐ فَأَخْرَجْنَا بِهِ“ أَزْوَ؛جاً مِّن نَّبَاتٍ شَتّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 53, 'كُلُواْ وَارْعَوَاْ اَنْعَـٰمَكُمُؐ; إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لُءِّوْلِى ۱لنُّهۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 54, '© مِنْهَا خَلَقْنَـٰكُمْ وَفِيهَا نُعِيدُكُمْ وَمِنْهَا نُخْرۣجُكُمْ تَارَةٗ ۷خْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 55, 'وَلَقَدَ اَرَيْنَـٰهُ ءَايَـٰتِنَا كُلَّهَا فَكَذَّبَ وَأَبۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 56, 'قَالَ أَجِيؔتَنَا ڤِتُخْرۣجَنَا مِنَ اَرْضِنَا بِسِحْرۣكككَ يَـٰمُوسۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 57, 'فَلَنَاتِيَنَّــكَ بِسِحْرٍ مِّثْلِهِؐ” فَاجْعَلْ بَيْنَنَا وَبَيْنَــكَ مَوْعِداً لاَّ نُخْلِفُهُ„ نَحْنُ وَلآَ أَنــتَ مَكَاناً سِويًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 58, 'قَالَ مَوْعِدُكُمْ يَوْمُ ۴لزّۣينَةِ وَأَنْ يُّحْشَرَ ۰لنَّاسسسُ ضُحيًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 59, 'فَتَوَلّۭيٰ فِرْعَوْنُ فَجَمَعَ كَيْدَهُ„ ثُمَّ أَتۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 60, 'قَالللَ لَهُم مُّوسۭيٰ وَيْلَكُمْ لاَ تَفْتَرُواْ عَلَــي ۰للَّهِ كَذِباً فَيَسْحَتَكُم بِعَذَابٍؐ وَقَدْ خَابَ مَنِ ''فْتَرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 61, 'فَتَنَـٰزَعُوٓاْ أَمْرَهُم بَيْنَهُمْ وَأَسَرُّواْ ۴ڤنَّجْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 62, 'قَالُوٓاْ إِنَّ هَـٰذَ؛نِ ڤَسَـٰحِرَ؛نِ يُرۣيدَ؛نِ أَنْ يُّخْرۣجَـٰكُم مِّنَ اَرْضِكُم بِسِحْرۣهِمَا وَيَذْهَبَا بِطَرۣيقَتِكُمُ ۴لْمُثْلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 63, 'فَأَجْمِعُواْ كَيْدَكُمْ ثُمَّ "يتُواْ صَفّاًؐ وَقَدَ اَفْلَحَ ۰لْيَوْمَ مَنِ ''سْتَعْلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 64, '21 قَالُواْ يَـٰمُوسۭيٰٓ إِمَّآ أَن تُلْقِيَ وَإِمَّآ أَن نَّكُونَ أَوَّلَ مَــنَ اَلْقۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 65, 'قَالَ بَــلَ اَلْقُواْؐ فَإِذَا حِبَالُهُمْ وَعِصِيُّهُمْ يُخَيَّلُ إِلَيْهِ مِن سِحْرۣهِمُ; أَنَّهَا تَسْعۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 66, 'فَأَوْجَسَ فِى نَفْسِهِ” خِيفَةً مُّوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 67, 'قُلْنَا لاَ تَخَفِ اِنَّــكَ أَنــتَ ۰لاَعْلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 68, 'وَأَلْقِ مَا فِى يَمِينِــكَ تَلَقَّفْ مَا صَنَعُوٓاْؐ إِنَّمَا صَنَعُواْ كَيْدُ سَـٰحِرٍؐ وَلاَ يُفْلِحُ ۴لسَّاحِرُ حَيْثُ أَتۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 69, 'فَٱُلْقِــيَ ۰ڤسَّحَرَةُ سُجَّداًؐ قَالُوٓاْ ءَامَنَّا بِرَبِّ هَـٰرُونَ وَمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 70, 'قَالَ ءَا۬؛مَنتُمْ لَهُ„ قَبْـلَ أَنَ —اذَنَ لَكُمُ; إِنَّهُ,لَكَبِيرُكُمُ ۴ﻟ﮲ عَلَّمَكُمُ ۴ڤسِّحْرَؐ فَلُءَقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِچَفٍ وَلُءَصَلِّبَنَّكُمْ فِى جُذُوعِ ۱ڤنَّخْلِ وَلَتَعْلَمُنَّ أَيُّنَآ أَشَدُّ عَذَاباً وَأَبْقۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 71, 'قَالُواْ لَن نُّوثِرَكككَ عَلَــيٰ مَا جَآءَنَا مِــنَ ۰لْبَيِّنَـٰــتِ وَاﻟ﮲ فَطَرَنَاؐ فَاقْــضِ مَآ أَنتَ قَاضضضٖؐ اِنَّمَا تَقْضِى هَـٰذِهِ ۱لْحَيَوٰةَ ۰لدُّنْيۭآؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 72, 'إِنَّـآ ءَامَنَّا بِرَبِّنَا لِيَغْفِرَ لَنَا خَطَـٰيۭـٰنَا وَمَآ أَكْرَهْتَنَا عَلَيْهِ مِــنَ ۰ڤسِّحْرۣؐ وَاللَّهُ خَيْرٌ وَأَبْقۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 73, 'إِنَّهُ„ مَنْ يَّاتِ رَبَّهُ„ مُجْرۣماً فَإِنَّ لَهُ„ جَهَنَّمَ لاَ يَمُوتُ فِيهَا وَلاَ يَحْيۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 74, 'وَمَنْ يَّاتِهِ” مُومِناً قَدْ عَمِــلَ ۰ڤصَّـٰڤِحَـٰتِ فَٱُوْلَئِــكَ لَهُمُ ۴لدَّرَجَـٰــتُ 22 ۴لْعُلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 75, 'جَنَّـٰــتُ عَدْنٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَاؐ وَذَ؛لِــكَ جَزَآءُ مَن تَزَكّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 76, 'وَلَقَدَ اَوْحَيْنَآ إِلَيٰ مُوسۭيٰٓ أَنِ ''سْرۣ بِعِبَادِى فَاضْرۣبْ لَهُمْ طَرۣيقاً فِى ۱ڤْبَحْرۣ يَبَساً لاَّ تَخَــٰــفُ دَرَكاً وَلاَ تَخْشۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 77, 'فَأَتْبَعَهُمْ فِرْعَوْنُ بِجُنُودِهِ” فَغَشِيَهُم مِّنَ ۰لْيَمِّ مَا غَشِيَهُمْؐ وَأَضَلَّ فِرْعَوْنُ قَوْمَهُ„ وَمَا هَدۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 78, 'يَـٰبَنِىٓ إِسْرَآءِيــلَ قَدَ اَنجَيْنَـٰكُم مِّــنْ عَدُوّۣكُمْ وَوَ؛عَدْنَـٰكُمْ جَانِبَ ۰لطُّورۣ ۱لاَيْمَنَ وَنَزَّلْنَا عَلَيْكُمُ ۴لْمَنَّ وَالسَّلْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 79, 'كُلُواْ مِــن طَيِّبَـٰتِ مَا رَزَقْنَـٰكُمْ وَلاَ تَطْغَوْاْ فِيهِ فَيَحِلَّ عَلَيْكُمْ غَضَبِىؐ وَمَــنْ يَّحْلِــلْ عَلَيْهِ غَضَبِى فَقَدْ هَوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 80, 'وَإِنِّى لَغَفَّارٌ لِّمَــن تَابَ وَءَامَنَ وَعَمِــلَ صَـٰڤِحاً ثُمَّ "هْتَدۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 81, '¥ وَمَآ أَعْجَلَــكَ عَن قَوْمِــكَ يَـٰمُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 82, 'قَالَ هُمُ; ٱُوْلآَءِ عَلَيٰٓ أَثَرۣى وَعَجِلْتُ إِلَيْــكَ رَبِّ لِتَرْضۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 83, 'قَالَ فَإِنَّا قَدْ فَتَنَّا قَوْمَــكَ مِـنۢ بَعْدِكَ وَأَضَلَّهُمُ ۴لسَّامِرۣيُّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 84, 'فَرَجَعَ مُوسۭيٰٓ إِلَيٰ قَوْمِهِ” غَضْبَـٰنَ أَسِفاًؐ قَالَ يَـٰقَوْمِ أَلَمْ يَعِدْكُمْ رَبُّكُمْ وَعْداٗ حَسَناٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 85, 'اَفَطَالَ عَلَيْكُمُ ۴لْعَهْدُ أَمَ اَرَدتُّمُ; أَنْ يَّحِــلَّ عَلَيْكُمْ 2 غَضَبٌ مِّن رَّبِّكُمْ فَأَخْلَفْتُم مَّوْعِدِىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 86, 'قَالُواْ مَآ أَخْلَفْنَا مَوْعِدَكككَ بِمَلْكِنَا وَچَكِنَّا حُمِّلْنَآ أَوْزَاراً مِّن زۣينَةِ ۱لْقَوْمِ فَقَذَفْنَـٰهَا فَكَذَ؛لِــكَ أَلْقَــي ۰لسَّامِرۣيُّؐ فَأَخْرَجَ لَهُمْ عِجْلًا جَسَداً لَّهُ„ خُوَارٌ فَقَالُواْ هَـٰذَآ إِچَهُكُمْ وَإِچَهُ مُوسۭــيٰ فَنَسِيَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 87, 'أَفَلاَ يَرَوْنَ أَلاَّ يَرْجِعُ إِلَيْهِمْ قَوْلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 88, 'وَلاَ يَمْلِكُ لَهُمْ ضَرّاً وَلاَ نَفْعاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 89, 'وَلَقَدْ قَالَ لَهُمْ هَـٰرُونُ مِــن قَبْلُ يَـٰقَوْمِ إِنَّمَا فُتِنتُم بِهِؐ” وَإِنَّ رَبَّكُمُ ۴لرَّحْمَـٰنُ فَاتَّبِعُونِى وَأَطِيعُوٓاْ أَمْرۣىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 90, 'قَالُواْ لَن نَّبْرَحَ عَلَيْهِ عَـٰكِفِيــنَ حَتَّيٰ يَرْجِعَ إِلَيْنَا مُوسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 91, 'قَالَ يَـٰهَـٰرُونُ مَا مَنَعَــكَ إِذْ رَأَيْتَهُمْ ضَلُّوٓاْ أَلاَّ تَتَّبِعَــنۣ“ أَفَعَصَيْتَ أَمْرۣىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 92, 'قَالَ يَبْنَؤُمَّ لاَ تَاخُذْ بِڤِحْيَتِى وَلاَ بِرَأْسِيَ إِنِّى خَشِيــتُ أَن تَقُولَ فَرَّقْتَ بَيْنَ بَنِىٓ إِسْرَآءِيلَ وَلَمْ تَرْقُبْ قَوْلِىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 93, 'قَالَ فَمَا خَطْبُــكَ يَـٰسَـٰمِرۣيُّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 94, 'قَالَ بَصُرْتُ بِمَا لَمْ يَبْصُرُواْ بِهِ” فَقَبَضْتُ قَبْضَةً مِّنَ اَثَرۣ ۱لرَّسُولِ فَنَبَذْتُهَا وَكَذَ؛لِــكَ سَوَّلَتْ لِى نَفْسِىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 95, 'قَالَ فَاذْهَبْ فَإِنَّ لَكَ فِى ۱لْحَيَوٰةِ أَن تَقُولَ لاَ مِسَاسَؐ 24 وَإِنَّ لَــكَ مَوْعِداً لَّــن تُخْلَفَهُؐ, وَانظُرۣ اِلَيٰٓ إِچَهِــكَ ۰ﻟ﮲ ظَلْتَ عَلَيْهِ عَاكِفاً ڤَّنُحَرّۣقَنَّهُ„ ثُمَّ لَنَنسِفَنَّهُ„ فِى ۱لْيَمِّ نَسْفاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 96, 'اِنَّمَآ إِچَهُكُمُ ۴للَّهُ ۴ﻟ﮲ لآَ إِچَهَ إِلاَّ هُوَؐ وَسِعَ كُلَّ شَيْءٖ عِلْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 97, 'كَذَ؛لِــكَ نَقُــصُّ عَلَيْــكَ مِــنَ اَنۢبَآءِ مَا قَدْ سَبَقَؐ وَقَدَ —اتَيْنَـٰــكَ مِــن لَّدُنَّا ذِكْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 98, 'مَّــنَ اَعْرَضضضَ عَنْهُ فَإِنَّهُ„ يَحْمِلُ يَوْمَ ۰لْقِيَـٰمَةِ وۣزْراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 99, 'خَـٰلِدِينَ فِيهِؐ وَسَآءَ لَهُمْ يَوْمَ ۰لْقِيَـٰمَةِ حِمْلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 100, 'يَوْمَ يُنفَخُ فِى ۱لصُّورۣ وَنَحْشُرُ ۴ڤْمُجْرۣمِينَ يَوْمَئِذٍ زُرْقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 101, 'يَتَخَـٰفَتُونَ بَيْنَهُمُ; إِن لَّبِثْتُمُ; إِلاَّ عَشْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 102, 'نَّحْــنُ أَعْلَمُ بِمَا يَقُولُونَ إِذْ يَقُولُ أَمْثَلُهُمْ طَرۣيقَةٗ اِن لَّبِثْتُمُ; إِلاَّ يَوْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 103, 'وَيَسْـَٔلُونَكَ عَنِ ۱لْجِبَالِ فَقُلْ يَنسِفُهَا رَبِّى نَسْفاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 104, 'فَيَذَرُهَا قَاعاً صَفْصَفاً لاَّ تَرۭيٰ فِيهَا عِوَجاً وَلآَ أَمْتاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 105, 'يَوْمَئِذٍ يَتَّبِعُونَ ۰لدَّاعِــيَ لاَ عِوَجَ لَهُؐ, وَخَشَعَــتِ ۱لاَصْوَاتُ لِلرَّحْمَـٰنِ فَلاَ تَسْمَعُ إِلاَّ هَمْساًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 106, 'يَوْمَئِذٍ لاَّ تَنفَعُ ۴لشَّفَـٰعَةُ إِلاَّ مَنَ اَذِنَ لَهُ ۴لرَّحْمَـٰنُ وَرَضِــيَ لَهُ„ قَوْلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 107, 'يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلاَ يُحِيطُونَ بِهِ” عِلْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 108, '25 © وَعَنَــتِ ۱لْوُجُوهُ ڤِڤْحَــيّۣ ۱لْقَيُّومِؐ وَقَدْ خَابَ مَــنْ حَمَــلَ ظُلْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 109, 'وَمَنْ يَّعْمَلْ مِــنَ ۰ڤصَّـٰڤِحَـٰتِ وَهُوَ مُومِنٌ فَلاَ يَخَافُ ظُلْماً وَلاَ هَضْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 110, 'وَكَذَ؛لِــكَ أَنزَلْنَـٰهُ قُرْءَاناٗ عَرَبِيّاً وَصَرَّفْنَا فِيهِ مِنَ ۰لْوَعِيدِ لَعَلَّهُمْ يَتَّقُونَ أَوْ يُحْدِثُ لَهُمْ ذِكْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 111, 'فَتَعَـٰلَــي ۰للَّهُ ۴لْمَلِــكُ ۴لْحَقُّؐ وَلاَ تَعْجَلْ بِالْقُرْءَانِ مِــن قَبْلِ أَنْ يُّقْضۭيٰٓ إِلَيْــكَ وَحْيُهُؐ, وَقُل رَّبِّ زۣدْنِى عِلْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 112, 'وَلَقَدْ عَهِدْنَآ إِلَيٰٓ ءَادَمَ مِــن قَبْلُ فَنَسِيَ وَلَمْ نَجِدْ لَهُ„ عَزْماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 113, 'وَإِذْ قُلْنَا لِلْمَلَئِكَةِ ۹سْجُدُواْ ءَلِادَمَ فَسَجَدُوٓاْؐ إِلٓاَّ إِبْلِيسَ أَبۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 114, 'فَقُلْنَا يَـٰٓــَٔادَمُ إِنَّ هَـٰذَا عَدُوٌّ لَّــكَ وَلِزَوْجِــكَ فَلاَ يُخْرۣجَنَّكُمَا مِــنَ ۰لْجَنَّةِ فَتَشْقۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 115, 'إِنَّ لَــكَ أَلاَّ تَجُوعَ فِيهَا وَلاَ تَعْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 116, 'وَإِنَّــكَ لاَ تَظْمَؤُاْ فِيهَا وَلاَ تَضْحۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 117, 'فَوَسْوَسَ إِلَيْهِ ۱لشَّيْطَـٰــنُؐ قَالَ يَـٰٓــَٔادَمُ هَــلَ اَدُلُّــكَ عَلَــيٰ شَجَرَةِ ۱لْخُلْدِ وَمُلْــكٍ لاَّ يَبْلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 118, 'فَأَكَلاَ مِنْهَا فَبَدَتتتْ لَهُمَا سَوْءَ؛تُهُمَا وَطَفِقَا يَخْصِفَـٰــنۣ عَلَيْهِمَا مِنْ وَّرَقِ ۱لْجَنَّةِؐ وَعَصۭــيٰٓ ءَادَمُ رَبَّهُ„ فَغَوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 119, 'ثُمَّ "جْتَبۭـٰهُ رَبُّهُ„ فَتَابَ عَلَيْهِ وَهَدۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 120, 'قَالَ "هْبِطَا مِنْهَا جَمِيعاٚؐ 26 بَعْضُكُمْ لِبَعْــضٖ عَدُوٌّؐ فَإِمَّا يَاتِيَنَّكُم مِّنِّى هُديً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 121, 'فَمَنِ ''تَّبَعَ هُدۭايَ فَلاَ يَضِلُّ وَلاَ يَشْقۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 122, 'وَمَــنَ اَعْرَضضضَ عَن ذِكْرۣى فَإِنَّ لَهُ„ مَعِيشَةً ضَنكاً وَنَحْشُرُهُ„ يَوْمَ ۰لْقِيَـٰمَةِ أَعْمۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 123, 'قَالَ رَبِّ لِمَ حَشَرْتَنِــيَ أَعْمۭيٰ وَقَدْ كُنتُ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 124, 'قَالَ كَذَ؛لِــكَ أَتَتْــكَ ءَايَـٰتُنَا فَنَسِيتَهَاؐ وَكَذَ؛لِــكَ ۰لْيَوْمَ تُنسۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 125, 'وَكَذَ؛لِــكَ نَجْزۣى مَــنَ اَسْرَفَ وَلَمْ يُومِـنۢ بِـَٔايَـٰتِ رَبِّهِؐ” وَلَعَذَابُ ۴لاَخِرَةِ أَشَدُّ وَأَبْقۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 126, 'أَفَلَمْ يَهْدِ لَهُمْ كَمَ اَهْلَكْنَا قَبْلَهُم مِّــنَ ۰لْقُرُونِ يَمْشُونَ فِى مَسَـٰكِنِهِمُؐ; إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لُءِّوْلِى ۱لنُّهۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 127, 'وَلَوْلاَ كَلِمَةٌ سَبَقَــتْ مِن رَّبِّكَ لَكَانَ لِزَاماً وَأَجَــلٌ مُّسَمّيًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 128, 'فَاصْبِرْ عَلَــيٰ مَا يَقُولُونَؐ وَسَبِّحْ بِحَمْدِ رَبِّــكَ قَبْــلَ طُلُوعِ ۱لشَّمْسِ وَقَبْلَ غُرُوبِهَاؐ وَمِنَ —انَآءِىْ ۱ليْـلِ فَسَبِّحْ وَأَطْرَافَ ۰لنَّهۭارۣ لَعَلَّكَ تَرْضۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 129, 'وَلاَ تَمُدَّنَّ عَيْنَيْــكَ إِلَــيٰ مَا مَتَّعْنَا بِهِ“ أَزْوَ؛جاً مِّنْهُمْ زَهْرَةَ ۰لْحَيَوٰةِ ۱لدُّنْيۭا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 130, 'لِنَفْتِنَهُمْ فِيهِؐ وَرۣزْقُ رَبِّــكَ خَيْرٌ وَأَبْقۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 131, 'وَامُرَ اَهْلَــكَ بِالصَّلَوٰةِ وَاصْطَبِرْ عَلَيْهَاؐ لاَ نَسْـَٔلُــكَ رۣزْقاًؐ 27 نَّحْنُ نَرْزُقُكَؐ وَالْعَـٰقِبَةُ لِلتَّقْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 132, 'وَقَالُواْ لَوْلاَ يَاتِينَا بِـَٔايَةٍ مِّن رَّبِّهِؐ“ أَوَلَمْ تَاتِهِم بَيِّنَةُ مَا فِى ۱ڤصُّحُفِ ۱لاُولۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 133, 'وَلَوَ اَنَّـآ أَهْلَكْنَـٰهُم بِعَذَابٍ مِّــن قَبْلِهِ” لَقَالُواْ رَبَّنَا لَوْلآَ أَرْسَلْــتَ إِلَيْنَا رَسُولًا فَنَتَّبِعَ ءَايَـٰتِكَ مِــن قَبْلِ أَن نَّذِلَّ وَنَخْزۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (20, 134, 'قُــلْ كُلٌّ مُّتَرَبِّـصٌ فَتَرَبَّصُواْؐ فَسَتَعْلَمُونَ مَــنَ اَصْحَـٰبُ ۴لصِّرَ؛طِ ۱لسَّوۣيِّ وَمَـنِ ''هْتَدَي');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ "قْتَرَبَ لِلنَّاسسسِ حِسَابُهُمْ وَهُمْ فِى غَفْلَةٍ مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 2, 'مَا يَاتِيهِم مِّــن ذِكْرٍ مِّن رَّبِّهِم مُّحْدَثٖ اِلاَّ "سْتَمَعُوهُ وَهُمْ يَلْعَبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 3, 'چَهِيَةً قُلُوبُهُمْؐ وَأَسَرُّواْ ۴ڤنَّجْوَي ۰لذِيــنَ ظَلَمُواْ هَــلْ هَـٰذَآ إِلاَّ بَشَرٌ مِّثْلُكُمُؐ; أَفَتَاتُونَ ۰ڤسِّحْرَ وَأَنتُمْ تُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 4, 'قُل رَّبِّى يَعْلَمُ ۴لْقَوْلَ فِى ۱لسَّمَآءِ وَالاَرْضِؐ وَهُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 5, 'بَلْ قَالُوٓاْ أَضْغَـٰــثُ أَحْچَمٙ بَلِ ''فْتَرۭيٰهُ بَلْ هُوَ شَاعِرٌؐ فَلْيَاتِنَا بِـَٔايَةٍ 28 كَمَآ ٱُرْسِــلَ ۰لاَوَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 6, 'مَآ ءَامَنَتْ قَبْلَهُم مِّن قَرْيَةٖ اَهْلَكْنَـٰهَآؐ أَفَهُمْ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 7, 'وَمَآ أَرْسَلْنَا قَبْلَكَ إِلاَّ رۣجَالًا يُوحۭيٰٓ إِلَيْهِمْ فَسْـَٔلُوٓاْ أَهْلَ ۰لذِّكْرۣ إِن كُنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 8, 'وَمَا جَعَلْنَـٰهُمْ جَسَداً لاَّ يَاكُلُونَ ۰لطَّعَامَؐ وَمَا كَانُواْ خَـٰلِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 9, 'ثُمَّ صَدَقْنَـٰهُمُ ۴لْوَعْدَ فَأَنجَيْنَـٰهُمْ وَمَــن نَّشَآءُ وَأَهْلَكْنَا ۰لْمُسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 10, 'لَقَدَ اَنزَلْنَآ إِلَيْكُمْ كِتَـٰباً فِيهِ ذِكْرُكُمُؐ; أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 11, 'وَكَمْ قَصَمْنَا مِن قَرْيَةٍ كَانَت ظَّالِمَةً وَأَنشَأْنَا بَعْدَهَا قَوْماٗ —اخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 12, 'فَلَمَّآ أَحَسُّواْ بَأْسَنَآ إِذَا هُم مِّنْهَا يَرْكُضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 13, 'لاَ تَرْكُضُواْ وَارْجِعُوٓاْ إِلَــيٰ مَآ ٱُتْرۣفْتُمْ فِيهِ وَمَسَـٰكِنِكُمْ لَعَلَّكُمْ تُسْـَٔلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 14, 'قَالُواْ يَـٰوَيْلَنَآ إِنَّا كُنَّا ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 15, 'فَمَا زَالَت تِّلْكَ دَعْوۭيٰهُمْ حَتَّيٰ جَعَلْنَـٰهُمْ حَصِيداٗ خَـٰمِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 16, 'وَمَا خَلَقْنَا ۰لسَّمَآءَ وَالاَرْضَ وَمَا بَيْنَهُمَا چَعِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 17, 'لَوَ اَرَدْنَآ أَن نَّتَّخِذَ لَهْواً لاَّتَّخَذْنَـٰهُ مِــن لَّدُنَّآؐ إِن كُنَّا فَـٰعِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 18, 'بَلْ نَقْذِفُ بِالْحَقِّ عَلَي ۰لْبَـٰطِلِ فَيَدْمَغُهُ„ 29 فَإِذَا هُوَ زَاهِقٌؐ وَلَكُمُ ۴لْوَيْـلُ مِمَّا تَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 19, 'وَلَهُ„ مَـن فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَمَنْ عِندَهُ„ لاَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِ” وَلاَ يَسْتَحْسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 20, 'يُسَبِّحُونَ ۰ليْلَ وَالنَّهَارَ لاَ يَفْتُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 21, 'أَمِ ''تَّخَذُوٓاْ ءَالِهَةً مِّــنَ ۰لاَرْضضضِ هُمْ يُنشِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 22, 'لَوْ كَانَ فِيهِمَآ ءَالِهَة٘ اِلاَّ ۰للَّهُ لَفَسَدَتَاؐ فَسُبْحَـٰــنَ ۰للَّهِ رَبِّ ۱لْعَرْشِ عَمَّا يَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 23, 'لاَ يُسْـَٔــلُ عَمَّا يَفْعَلُؐ وَهُمْ يُسْـَٔلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 24, 'أَمِ ''تَّخَذُواْ مِن دُونِهِ“ ءَالِهَةًؐ قُــلْ هَاتُواْ بُرْهَـٰنَكُمْؐ هَـٰذَا ذِكْرُ مَن مَّعِى وَذِكْرُ مَن قَبْلِىؐ بَــلَ اَكْثَرُهُمْ لاَ يَعْلَمُونَ ۰لْحَقَّ فَهُم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 25, 'وَمَآ أَرْسَلْنَا مِــن قَبْلِــكَ مِن رَّسُولٖ اِلاَّ يُوحۭيٰٓ إِلَيْهِ أَنَّهُ„ لآَ إِچَهَ إِلٓاَّ أَنَا فَاعْبُدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 26, 'وَقَالُواْ èتَّخَذَ ۰لرَّحْمَـٰنُ وَلَداًؐ سُبْحَـٰنَهُؐ, بَلْ عِبَادٌ مُّكْرَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 27, 'لاَ يَسْبِقُونَهُ„ بِالْقَوْلِ وَهُم بِأَمْرۣهِ” يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 28, 'يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْؐ وَلاَ يَشْفَعُونَ إِلاَّ لِمَنِ ''رْتَضۭيٰ وَهُم مِّــنْ خَشْيَتِهِ” مُشْفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 29, 'وَمَنْ يَّقُلْ مِنْهُمُ; إِنِّـيَ إِچَهٌ مِّن دُونِهِ” فَذَ؛لِــكَ نَجْزۣيهِ جَهَنَّمَؐ كَذَ؛لِــكَ نَجْزۣى ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 30, '0 © أَوَلَمْ يَرَ ۰لذِيــنَ كَفَرُوٓاْ أَنَّ ۰لسَّمَـٰوَ؛تِ وَالاَرْضضضَ كَانَتَا رَتْقاً فَفَتَقْنَـٰهُمَاؐ وَجَعَلْنَا مِــنَ ۰لْمَآءِ كُلَّ شَيْءٖ حَي؉ّؐ اَفَلاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 31, 'وَجَعَلْنَا فِى ۱لاَرْضِ رَوَ؛سِيَ أَن تَمِيدَ بِهِمْؐ وَجَعَلْنَا فِيهَا فِجَاجاً سُبُلًا لَّعَلَّهُمْ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 32, 'وَجَعَلْنَا ۰لسَّمَآءَ سَقْفاً مَّحْفُوظاًؐ وَهُمْ عَــنَ —ايَـٰتِهَا مُعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 33, 'وَهُوَ ۰ﻟ﮲ خَلَقَ ۰ليْلَ وَالنَّهَارَ وَالشَّمْسَ وَالْقَمَرَؐ كُلٌّ فِى فَلَكٍ يَسْبَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 34, 'وَمَا جَعَلْنَا لِبَشَرٍ مِّــن قَبْلِــكَ ۰لْخُلْدَؐ أَفَإِيْن مِّــتَّ فَهُمُ ۴لْخَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 35, 'كُلُّ نَفْــسٍ ذَآئِقَةُ ۴لْمَوْتِؐ وَنَبْلُوكُم بِالشَّرّۣ وَالْخَيْرۣ فِتْنَةًؐ وَإِلَيْنَا تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 36, 'وَإِذَا رۭءۭاكَ ۰لذِيــنَ كَفَرُوٓاْ إِنْ يَّتَّخِذُونَــكَ إِلاَّ هُزُؤاٗؐ اَهَـٰذَا ۰ﻟ﮲ يَذْكُرُ ءَالِهَتَكُمْ وَهُم بِذِكْرۣ ۱لرَّحْمَـٰــنۣ هُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 37, 'خُلِقَ ۰لِانسَـٰنُ مِنْ عَجَــلٍؐ سَٱُوْرۣيكُمُ; ءَايَـٰتِى فَلاَ تَسْتَعْجِلُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 38, 'وَيَقُولُونَ مَتۭــيٰ هَـٰذَا ۰لْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 39, 'لَوْ يَعْلَمُ ۴لذِيــنَ كَفَرُواْ حِيــنَ لاَ يَكُفُّونَ عَنْ وُّجُوهِهِمُ ۴لنَّارَ وَلاَ عَــن ظُهُورۣهِمْ وَلاَ هُمْ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 40, '1 بَـلْ تَاتِيهِم بَغْتَةً فَتَبْهَتُهُمْ فَلاَ يَسْتَطِيعُونَ رَدَّهَا وَلاَ هُمْ يُنظَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 41, 'وَلَقَدُ ۶سْتُهْزۣىَٔ بِرُسُلٍ مِّن قَبْلِكَ فَحَاقَ بِالذِيــنَ سَخِرُواْ مِنْهُم مَّا كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 42, 'قُلْ مَنْ يَّكْلَؤُكُم بِاليْلِ وَالنَّهۭارۣ مِنَ ۰لرَّحْمَـٰنِؐ بَـلْ هُمْ عَن ذِكْرۣ رَبِّهِم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 43, 'أَمْ لَهُمُ; ءَالِهَةٌ تَمْنَعُهُم مِّن دُونِنَاؐ لاَ يَسْتَطِيعُونَ نَصْرَ أَنفُسِهِمْ وَلاَ هُم مِّنَّا يُصْحَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 44, 'بَلْ مَتَّعْنَا هَـٰٓؤُلآَءِ وَءَابَآءَهُمْ حَتَّيٰ طَالَ عَلَيْهِمُ ۴لْعُمُرُؐ أَفَلاَ يَرَوْنَ أَنَّا نَاتِى ۱لاَرْضضضَ نَنقُصُهَا مِنَ اَطْرَافِهَآؐ أَفَهُمُ ۴لْغَـٰلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 45, 'قُـلِ اِنَّمَآ ٱُنذِرُكُم بِالْوَحْيِؐ وَلاَ يَسْمَعُ ۴لصُّمُّ ۴لدُّعَآءَ اۭذَا مَا يُنذَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 46, 'وَلَئِن مَّسَّتْهُمْ نَفْحَةٌ مِّــنْ عَذَابِ رَبِّــكَ لَيَقُولُنَّ يَـٰوَيْلَنَآ إِنَّا كُنَّا ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 47, 'وَنَضَعُ ۴لْمَوَ؛زۣينَ ۰لْقِسْطَ لِيَوْمِ ۱لْقِيَـٰمَةِ فَلاَ تُظْلَمُ نَفْسٌ شَيْـٔاًؐ وَإِن كَانَ مِثْقَالُ حَبَّةٍ مِّنْ خَرْدَلٖ اَتَيْنَا بِهَا وَكَفۭيٰ بِنَا حَـٰسِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 48, 'وَلَقَدَ —اتَيْنَا مُوسۭيٰ وَهَـٰرُونَ ۰لْفُرْقَانَ وَضِيَآءً وَذِكْراً لِّلْمُتَّقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 49, '۰لذِينَ 2 يَخْشَوْنَ رَبَّهُم بِالْغَيْبِ وَهُم مِّــنَ ۰لسَّاعَةِ مُشْفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 50, 'وَهَـٰذَا ذِكْرٌ مُّبَـٰرَككك٘ اَنزَلْنَـٰهُؐ أَفَأَنتُمْ لَهُ„ مُنكِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 51, '¥ وَلَقَدَ —اتَيْنَآ إِبْرَ؛هِيمَ رُشْدَهُ„ مِن قَبْلُ وَكُنَّا بِهِ” عَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 52, 'إِذْ قَالَ لَأِبِيهِ وَقَوْمِهِ” مَا هَـٰذِهِ ۱لتَّمَاثِيلُ ۴لتِىٓ أَنتُمْ لَهَا عَـٰكِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 53, 'قَالُواْ وَجَدْنَآ ءَابَآءَنَا لَهَا عَـٰبِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 54, 'قَالَ لَقَدْ كُنتُمُ; أَنتُمْ وَءَابَآؤُكُمْ فِى ضَچَـلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 55, 'قَالُوٓاْ أَجِيؔتَنَا بِالْحَقِّ أَمَ اَنتَ مِــنَ ۰لچَّـعِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 56, 'قَالَ بَل رَّبُّكُمْ رَبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ ۱ﻟ﮲ فَطَرَهُنَّؐ وَأَنَا عَلَــيٰ ذَ؛لِكُم مِّنَ ۰لشَّـٰهِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 57, 'وَتَاللَّهِ لَأَكِيدَنَّ أَصْنَـٰمَكُم بَعْدَ أَن تُوَلُّواْ مُدْبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 58, 'فَجَعَلَهُمْ جُذَ؛ذاٗ اِلاَّ كَبِيراً لَّهُمْ لَعَلَّهُمُ; إِلَيْهِ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 59, 'قَالُواْ مَـن فَعَلَ هَـٰذَا بِـَٔالِهَتِنَآ إِنَّهُ„ لَمِــنَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 60, 'قَالُواْ سَمِعْنَا فَتيً يَذْكُرُهُمْ يُقَالُ لَهُ; إِبْرَ؛هِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 61, 'قَالُواْ فَاتُواْ بِهِ” عَلَــيٰٓ أَعْيُـنِ ۱لنَّاسسسِ لَعَلَّهُمْ يَشْهَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 62, 'قَالُوٓاْ ءَآنــتَ فَعَلْــتَ هَـٰذَا بِـَٔالِهَتِنَا يَـٰٓإِبْرَ؛هِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 63, 'قَالَ بَلْ فَعَلَهُ„ كَبِيرُهُمْ هَـٰذَا فَسْـَٔلُوهُمُ; إِن كَانُواْ يَنطِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 64, 'فَرَجَعُوٓاْ إِلَــيٰٓ أَنفُسِهِمْ فَقَالُوٓاْ إِنَّكُمُ; أَنتُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 65, 'ثُمَّ نُكِسُواْ عَلَيٰ رُءُوسِهِمْؐ لَقَدْ عَلِمْتَ مَا هَـٰٓؤُلآَءِ يَنطِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 66, 'قَالَ أَفَتَعْبُدُونَ مِن دُونِ ۱للَّهِ مَا لاَ يَنفَعُكُمْ شَيْـٔاً وَلاَ يَضُرُّكُمُؐ; ٱُفٍّ لَّكُمْ وَلِمَا تَعْبُدُونَ مِن دُونِ ۱للَّهِؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 67, 'قَالُواْ حَرّۣقُوهُ وَانصُرُوٓاْ ءَالِهَتَكُمُ; إِن كُنتُمْ فَـٰعِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 68, 'قُلْنَا يَـٰنَارُ كُونِى بَرْداً وَسَچَماٗ عَلَيٰٓ إِبْرَ؛هِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 69, 'وَأَرَادُواْ بِهِ” كَيْداً فَجَعَلْنَـٰهُمُ ۴لاَخْسَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 70, 'وَنَجَّيْنَـٰهُ وَلُوطاٗ اِلَــي ۰لاَرْضِ ۱لتِى بَـٰرَكْنَا فِيهَا لِلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 71, 'وَوَهَبْنَا لَهُ; إِسْحَـٰقَؐ وَيَعْقُوبَ نَافِلَةًؐ وَكُلًاّ جَعَلْنَا صَـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 72, 'وَجَعَلْنَـٰهُمُ; أَئمَّةً يَهْدُونَ بِأَمْرۣنَاؐ وَأَوْحَيْنَآ إِلَيْهِمْ فِعْــلَ ۰لْخَيْرَ؛تِ وَإِقَامَ ۰لصَّلَوٰةِ وَإِيتَآءَ ۰لزَّكَوٰةِؐ وَكَانُواْ لَنَا عَـٰبِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 73, 'وَلُوطاٗ —اتَيْنَـٰهُ حُكْماً وَعِلْماًؐ وَنَجَّيْنَـٰهُ مِــنَ ۰لْقَرْيَةِ ۱لتِى كَانَت تَّعْمَــلُ ۴لْخَبَـٰٓئِثَؐ إِنَّهُمْ كَانُواْ قَوْمَ سَوْءٍ فَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 74, 'وَأَدْخَلْنَـٰهُ فِى رَحْمَتِنَآؐ إِنَّهُ„ مِــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 75, 'وَنُوحاٗ اِذْ نَادۭيٰ مِن قَبْلُ فَاسْتَجَبْنَا لَهُ„ 4 فَنَجَّيْنَـٰهُ وَأَهْلَهُ„ مِــنَ ۰لْكَرْبِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 76, 'وَنَصَرْنَـٰهُ مِنَ ۰لْقَوْمِ ۱لذِيــنَ كَذَّبُواْ بِـَٔايَـٰتِنَآؐ إِنَّهُمْ كَانُواْ قَوْمَ سَوْءٍ فَأَغْرَقْنَـٰهُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 77, 'وَدَاوُﹼدَ وَ سُلَيْمَـٰنَ إِذْ يَحْكُمَـٰنِ فِى ۱لْحَرْثِ إِذْ نَفَشَتْ فِيهِ غَنَمُ ۴لْقَوْمِؐ وَكُنَّا لِحُكْمِهِمْ شَـٰهِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 78, 'فَفَهَّمْنَـٰهَا سُلَيْمَـٰنَؐ وَكُلٗاّ —اتَيْنَا حُكْماً وَعِلْماًؐ وَسَخَّرْنَا مَعَ دَاوُﹼدَ ۰لْجِبَالَ يُسَبِّحْنَ وَالطَّيْرَؐ وَكُنَّا فَـٰعِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 79, 'وَعَلَّمْنَـٰهُ صَنْعَةَ لَبُوسسسٍ لَّكُمْ ڤِيُحْصِنَكُم مِّنۢ بَأْسِكُمْؐ فَهَــلَ اَنتُمْ شَـٰكِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 80, 'وَلِسُلَيْمَـٰنَ ۰لرّۣيحَ عَاصِفَةً تَجْرۣى بِأَمْرۣهِ“ إِلَــي ۰لاَرْضِ ۱لتِى بَـٰرَكْنَا فِيهَاؐ وَكُنَّا بِكُلِّ شَيْءٖ عَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 81, 'وَمِــنَ ۰لشَّيَـٰطِيــنۣ مَنْ يَّغُوصُونَ لَهُ„ وَيَعْمَلُونَ عَمَلًا دُونَ ذَ؛لِــكَؐ وَكُنَّا لَهُمْ حَـٰفِظِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 82, 'وَأَيُّوبَ إِذْ نَادۭيٰ رَبَّهُ; أَنِّى مَسَّنِــيَ ۰لضُّرُّ وَأَنــتَ أَرْحَمُ ۴لرَّ؛حِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 83, 'فَاسْتَجَبْنَا لَهُ„ فَكَشَفْنَا مَا بِهِ” مِــن ضُر؊ّؐ وَءَاتَيْنَـٰهُ أَهْلَهُ„ وَمِثْلَهُم مَّعَهُمْ رَحْمَةً مِّــنْ عِندِنَا وَذِكْرۭيٰ لِلْعَـٰبِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 84, 'وَإِسْمَـٰعِيلَ وَإِدْرۣيسَ وَذَا ۰لْكِفْلِؐ كُـلٌّ مِّنَ ۰لصَّـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 85, '5 وَأَدْخَلْنَـٰهُمْ فِى رَحْمَتِنَآؐ إِنَّهُم مِّــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 86, '© وَذَا ۰لنُّونِ إِذ ذَّهَبَ مُغَـٰضِباً فَظَنَّ أَن لَّــن نَّقْدِرَ عَلَيْهِ فَنَادۭيٰ فِى ۱لظُّلُمَـٰــتِ أَن لٓاَّ إِچَهَ إِلٓاَّ أَنــتَ سُبْحَـٰنَكَ إِنِّى كُنــتُ مِــنَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 87, 'فَاسْتَجَبْنَا لَهُ„ وَنَجَّيْنَـٰهُ مِــنَ ۰لْغَم؋ّؐ وَكَذَ؛لِــكَ نُنجِى ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 88, 'وَزَكَرۣيَّآءَ اۭذْ نَادۭيٰ رَبَّهُ„ رَبِّ لاَ تَذَرْنِى فَرْداً وَأَنــتَ خَيْرُ ۴لْوَ؛رۣثِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 89, 'فَاسْتَجَبْنَا لَهُ„ وَوَهَبْنَا لَهُ„ يَحْيۭيٰ وَأَصْڤَحْنَا لَهُ„ زَوْجَهُؐ; إِنَّهُمْ كَانُواْ يُسَـٰرۣعُونَ فِى ۱لْخَيْرَ؛تتتِ وَيَدْعُونَنَا رَغَباً وَرَهَباً وَكَانُواْ لَنَا خَـٰشِعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 90, 'وَالتِىٓ أَحْصَنَــتْ فَرْجَهَا فَنَفَخْنَا فِيهَا مِن رُّوحِنَا وَجَعَلْنَـٰهَا وَابْنَهَآ ءَايَةً لِّلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 91, 'إِنننَّ هَـٰذِهِ“ ٱُمَّتُكُمُ; ٱُمَّةً وَ؛حِدَةًؐ وَأَنَا رَبُّكُمْ فَاعْبُدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 92, 'وَتَقَطَّعُوٓاْ أَمْرَهُم بَيْنَهُمْؐ كُلّﹲ اِلَيْنَا رَ؛جِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 93, 'فَمَنْ يَّعْمَلْ مِنَ ۰ڤصَّـٰڤِحَـٰــتِ وَهُوَ مُومِنٌ فَلاَ كُفْرَانَ لِسَعْيِهِؐ” وَإِنَّا لَهُ„ كَـٰتِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 94, 'وَحَرَ؛م٘ عَلَيٰ قَرْيَةٖ اَهْلَكْنَـٰهَآ أَنَّهُمْ لاَ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 95, 'حَتَّيٰٓ إِذَا فُتِحَــتْ يَاجُوجُ وَمَاجُوجُ وَهُم 6 مِّــن كُــلّۣ حَدَبٍ يَنسِلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 96, 'وَاقْتَرَبَ ۰لْوَعْدُ ۴لْحَقُّ فَإِذَا هِيَ شَـٰخِصَة٘ اَبْصَـٰرُ ۴لذِيــنَ كَفَرُواْ يَـٰوَيْلَنَا قَدْ كُنَّا فِى غَفْلَةٍ مِّــنْ هَـٰذَا بَــلْ كُنَّا ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 97, 'إِنَّكُمْ وَمَا تَعْبُدُونَ مِن دُونِ ۱للَّهِ حَصَــبُ جَهَنَّمَ أَنتُمْ لَهَا وَ؛رۣدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 98, 'لَوْ كَانَ هَـٰٓؤُلآَءِ -الِهَةً مَّا وَرَدُوهَاؐ وَكُلٌّ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 99, 'لَهُمْ فِيهَا زَفِيرٌ وَهُمْ فِيهَا لاَ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 100, 'إِنَّ ۰لذِينَ سَبَقَتْ لَهُم مِّنَّا ۰لْحُسْنۭيٰٓ ٱُوْلَئِــكَ عَنْهَا مُبْعَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 101, 'لاَ يَسْمَعُونَ حَسِيسَهَا وَهُمْ فِى مَا "شْتَهَتَ اَنفُسُهُمْ خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 102, 'لاَ يَحْزُنُهُمُ ۴لْفَزَعُ ۴لاَكْبَرُؐ وَتَتَلَقّۭيٰهُمُ ۴لْمَلَئِكَةُ هَـٰذَا يَوْمُكُمُ ۴ﻟ﮲ كُنتُمْ تُوعَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 103, 'يَوْمَ نَطْوۣى ۱لسَّمَآءَ كَطَــيّۣ ۱ڤسِّجِلِّ لِلْكِتَـٰـــبِؐ كَمَا بَدَأْنَآ أَوَّلَ خَلْقٍ نُّعِيدُهُؐ, وَعْداٗ عَلَيْنَآؐ إِنَّا كُنَّا فَـٰعِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 104, 'وَلَقَدْ كَتَبْنَا فِى ۱لزَّبُورۣ مِنۢ بَعْدِ ۱لذِّكْرۣ أَنَّ ۰لاَرْضَ يَرۣثُهَا عِبَادِيَ ۰ڤصَّـٰڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 105, 'إِنَّ فِى هَـٰذَا لَبَچَغاً لِّقَوْمٖ عَـٰبِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 106, 'وَمَآ أَرْسَلْنَـٰكَ إِلاَّ رَحْمَةً لِّلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 107, 'قُلِ اِنَّمَا يُوحۭيٰٓ إِلَيَّ أَنَّمَآ إِچَهُكُمُ; إِچَهٌ وَ؛حِدٌؐ 7 فَهَــلَ اَنتُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 108, 'فَإِن تَوَلَّوْاْ فَقُــلَ —اذَنتُكُمْ عَلَيٰ سَوَآءٍؐ وَإِنَ اَدْرۣىٓ أَقَرۣيب٘ اَم بَعِيدٌ مَّا تُوعَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 109, 'إِنَّهُ„ يَعْلَمُ ۴لْجَهْرَ مِــنَ ۰لْقَوْلِ وَيَعْلَمُ مَا تَكْتُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 110, 'وَإِنَ اَدْرۣى لَعَلَّهُ„ فِتْنَةٌ لَّكُمْ وَمَتَـٰع٘ اِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (21, 111, 'قُل رَّبِّ ۹حْكُم بِالْحَقﱢّؐ وَرَبُّنَا ۰لرَّحْمَـٰــنُ ۴لْمُسْتَعَانُ عَلَــيٰ مَا تَصِفُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا ۰لنَّاسُ èتَّقُواْ رَبَّكُمُؐ; إِنَّ زَلْزَلَةَ ۰لسَّاعَةِ شَيْء٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 2, 'يَوْمَ تَرَوْنَهَا تَذْهَــلُ كُلُّ مُرْضِعَةٖ عَمَّآ أَرْضَعَتْ وَتَضَعُ كُلُّ ذَاتِ حَمْــل۫ حَمْلَهَا وَتَرَي ۰لنَّاسسسَ سُكَـٰرۭيٰ وَمَا هُم بِسُكَـٰرۭيٰ وَچَكِــنَّ عَذَابَ ۰للَّهِ شَدِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 3, 'وَمِــنَ ۰لنَّاسسسِ مَـنْ يُّجَـٰدِلُ فِى ۱للَّهِ بِغَيْرۣ عِلْمٍ وَيَتَّبِعُ كُلَّ شَيْطَـٰنٍ مَّرۣيدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 4, 'كُتِــبَ عَلَيْهِ أَنَّهُ„ مَن تَوَلۭاّهُ فَأَنَّهُ„ يُضِلُّهُ„ وَيَهْدِيهِ إِلَــيٰ عَذَابِ ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 5, 'يَـٰٓأَيُّهَا ۰لنَّاسُ إِن كُنتُمْ فِى رَيْــبٍ مِّنَ ۰لْبَعْثِ فَإِنَّا خَلَقْنَـٰكُم مِّن تُرَابٍ 8 ثُمَّ مِــن نُّطْفَةٍ ثُمَّ مِــنْ عَلَقَةٍ ثُمَّ مِــن مُّضْغَةٍ مُّخَلَّقَةٍ وَغَيْرۣ مُخَلَّقَةٍ لِّنُبَيِّــنَ لَكُمْؐ وَنُقِرُّ فِى ۱لاَرْحَامِ مَا نَشَآءُ اِ۬لَيٰٓ أَجَــلٍ مُّسَمّيًؐ ثُمَّ نُخْرۣجُكُمْ طِفْلًا ثُمَّ لِتَبْلُغُوٓاْ أَشُدَّكُمْؐ وَمِنكُم مَّنْ يُّتَوَفّۭيٰ وَمِنكُم مَّنْ يُّرَدُّ إِلَيٰٓ أَرْذَلِ ۱لْعُمُرۣ لِكَيْلاَ يَعْلَمَ مِنۢ بَعْدِ عِلْمٍ شَيْـٔاًؐ وَتَرَي ۰لاَرْضضضَ هَامِدَةً فَإِذَآ أَنزَلْنَا عَلَيْهَا ۰لْمَآءَ "هْتَزَّتْ وَرَبَــتْ وَأَنۢبَتَتْ مِــن كُلِّ زَوْجٙ بَهِيجٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 6, 'ذَ؛لِكَ بِأَنَّ ۰للَّهَ هُوَ ۰لْحَقُّ وَأَنَّهُ„ يُحْىِ ۱لْمَوْتۭيٰ وَأَنَّهُ„ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيرٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 7, 'وَأَنَّ ۰لسَّاعَةَ ءَاتِيَةٌ لاَّ رَيْبَ فِيهَا وَأَنننَّ ۰للَّهَ يَبْعَــثُ مَـن فِى ۱لْقُبُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 8, 'وَمِــنَ ۰لنَّاسِ مَنْ يُّجَـٰدِلُ فِى ۱للَّهِ بِغَيْرۣ عِلْمٍ وَلاَ هُديً وَلاَ كِتَـٰــبٍ مُّنِيرٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 9, 'ثَانِيَ عِطْفِهِ” لِيُضِلَّ عَــن سَبِيـلِ ۱للَّهِؐ لَهُ„ فِى ۱لدُّنْيۭا خِزْيٌؐ وَنُذِيقُهُ„ يَوْمَ ۰لْقِيَـٰمَةِ عَذَابَ ۰لْحَرۣيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 10, 'ذَ؛لِــكَ بِمَا قَدَّمَــتْ يَدَ؛كَ وَأَنننَّ ۰للَّهَ لَيْسَ بِظَچَّـمٍ لِّلْعَبِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 11, 'وَمِــنَ ۰لنَّاسِ مَنْ يَّعْبُدُ ۴للَّهَ عَلَــيٰ حَرْفٍ فَإِنَ اَصَابَهُ„ خَيْر٘ ''طْمَأَنَّ بِهِ” وَإِنَ اَصَابَتْهُ فِتْنَة٘ ''نقَلَبَ عَلَيٰ وَجْهِهِ” خَسِرَ ۰لدُّنْيۭا وَالاَخِرَةَؐ ذَ؛لِكَ هُوَ ۰لْخُسْرَانُ 9 ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 12, 'يَدْعُواْ مِن دُونِ ۱للَّهِ مَا لاَ يَضُرُّهُ„ وَمَا لاَ يَنفَعُهُؐ, ذَ؛لِــكَ هُوَ ۰لضَّچَلُ ۴لْبَعِيدُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 13, 'يَدْعُواْؐ لَمَــن ضَرُّهُ; أَقْرَبُ مِن نَّفْعِهِ” لَبِيــسَ ۰لْمَوْلۭيٰ وَلَبِيــسَ ۰لْعَشِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 14, 'إِنَّ ۰للَّهَ يُدْخِلُ ۴لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ جَنَّـٰــتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُؐ إِنَّ ۰للَّهَ يَفْعَــلُ مَا يُرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 15, 'مَــن كَانَ يَظُنُّ أَن لَّنْ يَّنصُرَهُ ۴للَّهُ فِى ۱لدُّنْيۭا وَالاَخِرَةِ فَلْيَمْدُدْ بِسَبَــبٖ اِلَــي ۰لسَّمَآءِ ثُمَّ لِيَقْطَعْ فَلْيَنظُرْ هَلْ يُذْهِبَنَّ كَيْدُهُ„ مَا يَغِيظُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 16, 'وَكَذَ؛لِــكَ أَنزَلْنَـٰهُ ءَايَـٰــتٙ بَيِّنَـٰــتٍؐ وَأَنَّ ۰للَّهَ يَهْدِى مَنْ يُّرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 17, 'إِنَّ ۰لذِيــنَ ءَامَنُواْ وَالذِيــنَ هَادُواْ وَالصَّـٰبِينَ وَالنَّصَـٰرۭيٰ وَالْمَجُوسَ وَالذِيــنَ أَشْرَكُوٓاْ إِنَّ ۰للَّهَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ۰لْقِيَـٰمَةِؐ إِنَّ ۰للَّهَ عَلَيٰ كُــلّۣ شَيْءٍ شَهِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 18, 'اَلَمْ تَرَ أَنَّ ۰للَّهَ يَسْجُدُ لَهُ„ مَـن فِى ۱لسَّمَـٰوَ؛تِ وَمَـن فِى ۱لاَرْضِ وَالشَّمْسُ وَالْقَمَرُ وَاڤنُّجُومُ وَالْجِبَالُ وَاڤشَّجَرُ وَالدَّوَآبُّ وَكَثِيرٌ مِّــنَ ۰لنَّاسِؐ وَكَثِير٘ حَقَّ عَلَيْهِ ۱لْعَذَابُؐ وَمَنْ يُّهِـنِ ۱للَّهُ فَمَا لَهُ„ مِــن مُّكْرۣمٖؐ اِنَّ ۰للَّهَ يَفْعَلُ مَا يَشَآءُؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 19, '© هَـٰذَ؛نننۣ خَصْمَـٰنِ ''خْتَصَمُواْ فِى رَبِّهِمْؐ 40 فَالذِيــنَ كَفَرُواْ قُطِّعَــتْ لَهُمْ ثِيَابٌ مِّــن نّۭـارٍ يُصَبُّ مِن فَوْقِ رُءُوسِهِمُ ۴لْحَمِيمُ يُصْهَرُ بِهِ” مَا فِى بُطُونِهِمْ وَالْجُلُودُؐ وَلَهُم مَّقَـٰمِعُ مِنْ حَدِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 20, 'كُلَّمَآ أَرَادُوٓاْ أَنْ يَّخْرُجُواْ مِنْهَا مِنْ غَمّٖ ۷عِيدُواْ فِيهَاؐ وَذُوقُواْ عَذَابَ ۰لْحَرۣيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 21, 'إِنَّ ۰للَّهَ يُدْخِلُ ۴لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ يُحَلَّوْنَ فِيهَا مِــنَ اَسَاوۣرَ مِن ذَهَبٍ وَلُؤْلُؤاًؐ وَلِبَاسُهُمْ فِيهَا حَرۣيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 22, 'وَهُدُوٓاْ إِلَي ۰لطَّيِّبِ مِــنَ ۰لْقَوْلِؐ وَهُدُوٓاْ إِلَيٰ صِرَ؛طِ ۱لْحَمِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 23, 'إِنَّ ۰لذِيــنَ كَفَرُواْ وَيَصُدُّونَ عَــن سَبِيـلِ ۱للَّهِ وَاڤْمَسْجِدِ ۱لْحَرَامِ ۱ﻟ﮲ جَعَلْنَـٰهُ لِلنَّاسِ سَوَآء٘ ۱لْعَـٰكِفُ فِيهِ وَالْبَادِؐ” وَمَنْ يُّرۣدْ فِيهِ بِإِلْحَادٙ بِظُلْمٍ نُّذِقْهُ مِــنْ عَذَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 24, 'وَإِذْ بَوَّأْنَا لِإِبْرَ؛هِيمَ مَكَانَ ۰لْبَيْــتِ أَن لاَّ تُشْرۣكككْ بِى شَيْـٔاًؐ وَطَهِّرْ بَيْتِــيَ لِلطَّآئِفِينَ وَالْقَآئِمِينَ وَالرُّكَّعِ ۱لسُّجُودِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 25, 'وَأَذِّن فِى ۱لنَّاسِ بِالْحَجِّ يَاتُوكككَ رۣجَالًا وَعَلَــيٰ كُــلّۣ ضَامِرٍ يَاتِيــنَ مِـن كُلِّ فَجّٖ عَمِيقٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 26, 'لِّيَشْهَدُواْ مَنَـٰفِعَ لَهُمْ وَيَذْكُرُواْ èسْمَ ۰للَّهِ 41 فِىٓ أَيَّامٍ مَّعْلُومَـٰتٖ عَلَــيٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ۱لاَنْعَـٰمِؐ فَكُلُواْ مِنْهَا وَأَطْعِمُواْ ۴لْبَآئِسَ ۰لْفَقِيرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 27, 'ثُمَّ لِيَقْضُواْ تَفَثَهُمْ وَلْيُوفُواْ نُذُورَهُمْ وَلْيَطَّوَّفُواْ بِالْبَيْــتِ ۱لْعَتِيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 28, 'ذَ؛لِكَؐ وَمَـنْ يُّعَظِّمْ حُرُمَـٰــتِ ۱للَّهِ فَهُوَ خَيْرٌ لَّهُ„ عِندَ رَبِّهِؐ” وَٱُحِلَّتْ لَكُمُ ۴لاَنْعَـٰمُ إِلاَّ مَا يُتْلۭــيٰ عَلَيْكُمْؐ فَاجْتَنِبُواْ ۴لرّۣجْسَ مِنَ ۰لاَوْثَـٰنِ وَاجْتَنِبُواْ قَوْلَ ۰لزُّورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 29, 'حُنَفَآءَ لِلهِ غَيْرَ مُشْرۣكِينَ بِهِؐ” وَمَنْ يُّشْرۣكككْ بِاللَّهِ فَكَأَنَّمَا خَرَّ مِــنَ ۰لسَّمَآءِ فَتَخَطَّفُهُ ۴لطَّيْرُ أَوْ تَهْوۣى بِهِ ۱لرّۣيحُ فِى مَكَانٍ سَحِيقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 30, 'ذَ؛لِــكَؐ وَمَنْ يُّعَظِّمْ شَعَـٰٓئِرَ ۰للَّهِ فَإِنَّهَا مِــن تَقْوَي ۰لْقُلُوبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 31, 'لَكُمْ فِيهَا مَنَـٰفِعُ إِلَيٰٓ أَجَــلٍ مُّسَمّيً ثُمَّ مَحِلُّهَآ إِلَي ۰لْبَيْتِ ۱لْعَتِيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 32, 'وَلِكُــلّۣ ٱُمَّةٍ جَعَلْنَا مَنسَكاً لِّيَذْكُرُواْ èسْمَ ۰للَّهِ عَلَيٰ مَا رَزَقَهُم مِّـنۢ بَهِيمَةِ ۱لاَنْعَـٰمِؐ فَإِچَهُكُمُ; إِچَهٌ وَ؛حِدٌؐ فَلَهُ; أَسْلِمُواْؐ وَبَشِّرۣ ۱ڤْمُخْبِتِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 33, '۰لذِينَ إِذَا ذُكِرَ ۰للَّهُ وَجِلَتْ قُلُوبُهُمْ وَالصَّـٰبِـرۣيــنَ عَلَــيٰ مَآ أَصَابَهُمْ وَالْمُقِيمِى ۱لصَّلَوٰةِ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 34, 'وَالْبُدْنَ جَعَلْنَـٰهَا لَكُم مِّن 42 شَعَـٰٓئِرۣ ۱للَّهِ لَكُمْ فِيهَا خَيْرٌؐ فَاذْكُرُواْ èسْمَ ۰للَّهِ عَلَيْهَا صَوَآفَّؐ فَإِذَا وَجَبَــتْ جُنُوبُهَا فَكُلُواْ مِنْهَا وَأَطْعِمُواْ ۴لْقَانِعَ وَالْمُعْتَرَّؐ كَذَ؛لِــكَ سَخَّرْنَـٰهَا لَكُمْ لَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 35, 'لَنْ يَّنَالَ ۰للَّهَ لُحُومُهَا وَلاَ دِمَآؤُهَا وَچَكِـنْ يَّنَالُهُ ۴لتَّقْوۭيٰ مِنكُمْؐ كَذَ؛لِــكَ سَخَّرَهَا لَكُمْ لِتُكَبِّرُواْ ۴للَّهَ عَلَيٰ مَا هَدۭيٰكُمْؐ وَبَشِّرۣ ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 36, '¥ إِنَّ ۰للَّهَ يُدَ؛فِعُ عَـنِ ۱لذِينَ ءَامَنُوٓاْؐ إِنَّ ۰للَّهَ لاَ يُحِــبُّ كُلَّ خَوَّانٍ كَفُورٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 37, '۷ذِنَ لِلذِينَ يُقَـٰتَلُونَ بِأَنَّهُمْ ظُلِمُواْؐ وَإِنننَّ ۰للَّهَ عَلَــيٰ نَصْرۣهِمْ لَقَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 38, '۱لذِيــنَ ٱُخْرۣجُواْ مِن دِيۭـٰرۣهِم بِغَيْرۣ حَقّٖ اِلٓاَّ أَنْ يَّقُولُواْ رَبُّنَا ۰للَّهُؐ وَلَوْلاَ دِفَـٰعُ ۴للَّهِ ۱لنَّاسسسَ بَعْضَهُم بِبَعْــضٍ لَّهُدِمَــتْ صَوَ؛مِعُ وَبِيَعٌ وَصَلَوَ؛تٌ وَمَسَـٰجِدُ يُذْكَرُ فِيهَا "سْمُ ۴للَّهِ كَثِيراًؐ وَلَيَنصُرَنَّ ۰للَّهُ مَـنْ يَّنصُرُهُؐ; إِنَّ ۰للَّهَ لَقَوۣيّﹲ عَزۣيز٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 39, '۱لذِينَ إِن مَّكَّنَّـٰهُمْ فِى ۱لاَرْضضضِ أَقَامُواْ ۴لصَّلَوٰةَ وَءَاتَوُاْ ۴لزَّكَوٰةَ وَأَمَرُواْ بِالْمَعْرُوفِ وَنَهَوْاْ عَـنِ ۱لْمُنكَرۣؐ وَلِلهِ عَـٰقِبَةُ ۴لاُمُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 40, 'وَإِنْ يُّكَذِّبُوكككَ فَقَدْ كَذَّبَــتْ قَبْلَهُمْ قَوْمُ نُوحٍ 4 وَعَادٌ وَثَمُودُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 41, 'وَقَوْمُ إِبْرَ؛هِيمَ وَقَوْمُ لُوطٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 42, 'وَأَصْحَـٰبُ مَدْيَنَؐ وَكُذِّبَ مُوسۭيٰؐ فَأَمْلَيْتُ لِلْكۭـٰفِـرۣينَ ثُمَّ أَخَذتُّهُمْؐ فَكَيْفَ كَانَ نَكِيرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 43, 'فَكَأَيِّــن مِّـن قَرْيَةٖ اَهْلَكْنَـٰهَا وَهِيَ ظَالِمَةٌ فَهِــيَ خَاوۣيَة٘ عَلَيٰ عُرُوشِهَا وَبِيرٍ مُّعَطَّلَةٍ وَقَصْرٍ مَّشِيدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 44, 'اَفَلَمْ يَسِيرُواْ فِى ۱لاَرْضضضِ فَتَكُونَ لَهُمْ قُلُوبٌ يَعْقِلُونَ بِهَآ أَوَ —اذَانٌ يَسْمَعُونَ بِهَاؐ فَإِنَّهَا لاَ تَعْمَي ۰لاَبْصَـٰرُ وَچَكِــن تَعْمَــي ۰لْقُلُوبُ ۴لتِى فِى ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 45, 'وَيَسْتَعْجِلُونَــكَ بِالْعَذَابِؐ وَلَــنْ يُّخْلِفَ ۰للَّهُ وَعْدَهُؐ, وَإِنَّ يَوْماٗ عِندَ رَبِّــكَ كَأَلْفِ سَنَةٍ مِّمَّا تَعُدُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 46, 'وَكَأَيِّن مِّـن قَرْيَةٖ اَمْلَيْــتُ لَهَا وَهِــيَ ظَالِمَةٌ ثُمَّ أَخَذتُّهَاؐ وَإِلَــيَّ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 47, 'قُلْ يَـٰٓأَيُّهَا ۰لنَّاسُ إِنَّمَآ أَنَا لَكُمْ نَذِيرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 48, 'فَالذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ لَهُم مَّغْفِرَةٌ وَرۣزْقٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 49, 'وَالذِيــنَ سَعَوْاْ فِىٓ ءَايَـٰتِنَا مُعَـٰجِزۣينَ ٱُوْلَئِــكَ أَصْحَـٰبُ ۴لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 50, 'وَمَآ أَرْسَلْنَا مِــن قَبْلِــكَ مِن رَّسُولٍ وَلاَ نَبِىٓءٖ اِلٓاَّ إِذَا تَمَنّۭيٰٓ أَلْقَــي ۰لشَّيْطَـٰنُ فِىٓ ٱُمْنِيَّتِهِ” فَيَنسَخُ ۴للَّهُ مَا يُلْقِى ۱لشَّيْطَـٰنُ 44 ثُمَّ يُحْكِمُ ۴للَّهُ ءَايَـٰتِهِ” وَاللَّهُ عَلِيم٘ حَكِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 51, 'ڤِّيَجْعَلَ مَا يُلْقِى ۱لشَّيْطَـٰنُ فِتْنَةً لِّلذِينَ فِى قُلُوبِهِم مَّرَضٌ وَالْقَاسِيَةِ قُلُوبُهُمْؐ وَإِنَّ ۰لظَّـٰلِمِينَ لَفِى شِقَاقٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 52, 'وَلِيَعْلَمَ ۰لذِينَ ٱُوتُواْ ۴لْعِلْمَ أَنَّهُ ۴لْحَـقُّ مِن رَّبِّــكَ فَيُومِنُواْ بِهِ” فَتُخْبِــتَ لَهُ„ قُلُوبُهُمْؐ وَإِنَّ ۰للَّهَ لَهَادِ ۱لذِيــنَ ءَامَنُوٓاْ إِلَــيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 53, 'وَلاَ يَزَالُ ۴لذِيــنَ كَفَرُواْ فِى مِرْيَةٍ مِّنْهُ حَتَّــيٰ تَاتِيَهُمُ ۴لسَّاعَةُ بَغْتَةٗ اَوْ يَاتِيَهُمْ عَذَابُ يَوْمٖ عَقِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 54, '۱لْمُلْــكُ يَوْمَئِذٍ لِّلهِؐ يَحْكُمُ بَيْنَهُمْؐ فَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ فِى جَنَّـٰــتِ ۱لنَّعِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 55, 'وَالذِيــنَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَـٰتِنَا فَٱُوْلَئِــكَ لَهُمْ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 56, 'وَالذِيــنَ هَاجَرُواْ فِى سَبِيـلِ ۱للَّهِ ثُمَّ قُتِلُوٓاْ أَوْ مَاتُواْ لَيَرْزُقَنَّهُمُ ۴للَّهُ رۣزْقاٗ حَسَناًؐ وَإِنننَّ ۰للَّهَ لَهُوَ خَيْرُ ۴لرَّ؛زۣقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 57, 'لَيُدْخِلَنَّهُم مَّدْخَلًا يَرْضَوْنَهُؐ, وَإِنننَّ ۰للَّهَ لَعَلِيم٘ حَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 58, '© ذَ؛لِــكَؐ وَمَــنْ عَاقَبَ بِمِثْــلۣ مَا عُوقِــبَ بِهِ” ثُمَّ بُغِــيَ عَلَيْهِ لَيَنصُرَنَّهُ ۴للَّهُؐ إِنننَّ ۰للَّهَ لَعَفُوّﹲ غَفُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 59, 'ذَ؛لِــكَ بِأَنننَّ ۰للَّهَ يُولِجُ ۴ليْلَ فِى ۱لنَّهۭارۣ وَيُولِجُ ۴لنَّهَارَ 45 فِى ۱ليْلِ وَأَنَّ ۰للَّهَ سَمِيعٛ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 60, 'ذَ؛لِــكَ بِأَنننَّ ۰للَّهَ هُوَ ۰لْحَقُّ وَأَنَّ مَا تَدْعُونَ مِــن دُونِهِ” هُوَ ۰لْبَـٰطِلُ وَأَنَّ ۰للَّهَ هُوَ ۰لْعَلِيُّ ۴لْكَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 61, 'أَلَمْ تَرَ أَنَّ ۰للَّهَ أَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءً فَتُصْبِحُ ۴لاَرْضضضُ مُخْضَرَّةٗؐ اِنَّ ۰للَّهَ لَطِيف٘ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 62, 'لَّهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَإِنَّ ۰للَّهَ لَهُوَ ۰لْغَنِــيُّ ۴لْحَمِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 63, 'أَلَمْ تَرَ أَنَّ ۰للَّهَ سَخَّرَ لَكُم مَّا فِى ۱لاَرْضِ وَالْفُلْــكَ تَجْرۣى فِى ۱ڤْبَحْرۣ بِأَمْرۣهِؐ” وَيُمْسِــكُ ۴لسَّمَآءَ ان تَقَعَ عَلَــي ۰لاَرْضِ إِلاَّ بِإِذْنِهِؐ“ إِنَّ ۰للَّهَ بِالنَّاسِ لَرَءُوفٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 64, 'وَهُوَ ۰ﻟـذِىٓ أَحْيۭاكُمْ ثُمَّ يُمِيتُكُمْؐ ثُمَّ يُحْيِيكُمُؐ; إِنَّ ۰لِانسَـٰــنَ لَكَفُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 65, 'لِّكُلِّ ٱُمَّةٍ جَعَلْنَا مَنسَكاٗ هُمْ نَاسِكُوهُؐ فَلاَ يُنَـٰزۣعُنَّكَ فِى ۱لاَمْرۣؐ وَادْعُ إِلَيٰ رَبِّكَؐ إِنَّــكَ لَعَلَــيٰ هُديً مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 66, 'وَإِن جَـٰدَلُوكككَ فَقُـلِ ۱للَّهُ أَعْلَمُ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 67, '۰للَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ۰لْقِيَـٰمَةِ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 68, 'أَلَمْ تَعْلَمَ اَنَّ ۰للَّهَ يَعْلَمُ مَا فِى ۱لسَّمَآءِ وَالاَرْضِؐ إِنَّ ذَ؛لِكَ فِى كِتَـٰبٖؐ اِنَّ ذَ؛لِكَ عَلَــي ۰للَّهِ يَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 69, 'وَيَعْبُدُونَ مِن دُونِ ۱للَّهِ مَا 46 لَمْ يُنَزّۣلْ بِهِ” سُلْطَـٰناً وَمَا لَيْــسَ لَهُم بِهِ” عِلْمٌؐ وَمَا لِلظَّـٰلِمِينَ مِــن نَّصِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 70, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُنَا بَيِّنَـٰتٍ تَعْرۣفُ فِى وُجُوهِ ۱لذِيــنَ كَفَرُواْ ۴لْمُنكَرَ يَكَادُونَ يَسْطُونَ بِالذِينَ يَتْلُونَ عَلَيْهِمُ; ءَايَـٰتِنَاؐ قُلَ اَفَٱُنَبِّيؖكُم بِشَرٍّ مِّــن ذَ؛لِكُمُؐ ۴لنَّارُ وَعَدَهَا ۰للَّهُ ۴لذِيــنَ كَفَرُواْؐ وَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 71, 'يَـٰٓأَيُّهَا ۰لنَّاسسسُ ضُرۣبَ مَثَلٌ فَاسْتَمِعُواْ لَهُؐ; إِنَّ ۰لذِيــنَ تَدْعُونَ مِــن دُونِ ۱للَّهِ لَــنْ يَّخْلُقُواْ ذُبَاباً وَلَوۣ ''جْتَمَعُواْ لَهُؐ, وَإِنْ يَّسْلُبْهُمُ ۴لذُّبَابُ شَيْـٔاً لاَّ يَسْتَنقِذُوهُ مِنْهُؐ ضَعُفَ ۰لطَّالِــبُ وَالْمَطْلُوبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 72, 'مَا قَدَرُواْ ۴للَّهَ حَــقَّ قَدْرۣهِؐ“ إِنَّ ۰للَّهَ لَقَوۣيّﹲ عَزۣيز٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 73, '۱للَّهُ يَصْطَفِى مِــنَ ۰لْمَلَئِكَةِ رُسُلًا وَمِــنَ ۰لنَّاسِؐ إِنَّ ۰للَّهَ سَمِيعٛ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 74, 'يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْؐ وَإِلَي ۰للَّهِ تُرْجَعُ ۴لاُمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 75, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èرْكَعُواْ وَاسْجُدُواْ وَاعْبُدُواْ رَبَّكُمْ وَافْعَلُواْ ۴لْخَيْرَ لَعَلَّكُمْ تُفْلِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (22, 76, 'وَجَـٰهِدُواْ فِى ۱للَّهِ حَقَّ جِهَادِهِؐ” هُوَ "جْتَبۭيٰكُمْؐ وَمَا جَعَــلَ عَلَيْكُمْ فِى ۱لدِّينِ مِنْ حَرَجٍؐ مِّلَّةَ أَبِيكُمُ; إِبْرَ؛هِيمَؐ 47 هُوَ سَمّۭيٰكُمُ ۴لْمُسْلِمِينَ مِن قَبْلُ وَفِى هَـٰذَا لِيَكُونَ ۰لرَّسُولُ شَهِيداٗ عَلَيْكُمْ وَتَكُونُواْ شُهَدَآءَ عَلَــي ۰لنَّــاسِؐ فَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَاعْتَصِمُواْ بِاللَّهِؐ هُوَ مَوْلۭيٰكُمْؐ فَنِعْمَ ۰لْمَوْلۭيٰؐ وَنِعْمَ ۰لنَّصِيرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قَدَ اَفْلَحَ ۰لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 2, '۰لذِينَ هُمْ فِى صَلاَتِهِمْ خَـٰشِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 3, 'وَالذِينَ هُمْ عَـنِ ۱للَّغْوۣ مُعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 4, 'وَالذِينَ هُمْ لِلزَّكَوٰةِ فَـٰعِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 5, 'وَالذِينَ هُمْ لِفُرُوجِهِمْ حَـٰفِظُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 6, 'إِلاَّ عَلَيٰٓ أَزْوَ؛جِهِمُ; أَوْ مَا مَلَكَتَ اَيْمَـٰنُهُمْ فَإِنَّهُمْ غَيْرُ مَلُومِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 7, 'فَمَنِ ''بْتَغۭيٰ وَرَآءَ ذَ؛لِــكَ فَٱُوْلَئِــكَ هُمُ ۴لْعَادُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 8, 'وَالذِيــنَ هُمْ لَأِمَـٰنَـٰتِهِمْ وَعَهْدِهِمْ رَ؛عُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 9, 'وَالذِينَ هُمْ عَلَــيٰ صَلَوَ؛تِهِمْ يُحَافِظُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 10, 'ٱُوْلَئِــكَ هُمُ ۴لْوَ؛رۣثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 11, '۰لذِينَ يَرۣثُونَ ۰لْفِرْدَوْسَؐ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 12, 'وَلَقَدْ خَلَقْنَا ۰لِانسَـٰنَ 48 مِــن سُچَلَةٍ مِّن طِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 13, 'ثُمَّ جَعَلْنَـٰهُ نُطْفَةً فِى قَرۭارٍمَّكِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 14, 'ثُمَّ خَلَقْنَا ۰لنُّطْفَةَ عَلَقَةً فَخَلَقْنَا ۰لْعَلَقَةَ مُضْغَةً فَخَلَقْنَا ۰لْمُضْغَةَ عِظَـٰماً فَكَسَوْنَا ۰لْعِظَـٰمَ لَحْماً ثُمَّ أَنشَأْنَـٰهُ خَلْقاٗ —اخَرَؐ فَتَبَـٰرَكككَ ۰للَّهُ أَحْسَــنُ ۴لْخَـٰلِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 15, 'ثُمَّ إِنَّكُم بَعْدَ ذَ؛لِــكَ لَمَيِّتُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 16, 'ثُمَّ إِنَّكُمْ يَوْمَ ۰لْقِيَـٰمَةِ تُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 17, 'وَلَقَدْ خَلَقْنَا فَوْقَكُمْ سَبْعَ طَرَآئِقَؐ وَمَا كُنَّا عَـنِ ۱لْخَلْــقۣ غَـٰفِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 18, 'وَأَنزَلْنَا مِــنَ ۰لسَّمَآءِ مَآءَۢ بِقَدَرٍ فَأَسْكَنَّـٰهُ فِى ۱لاَرْضِؐ وَإِنَّا عَلَــيٰ ذَهَابٙ بِهِ” لَقَـٰدِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 19, 'فَأَنشَأْنَا لَكُم بِهِ” جَنَّـٰتٍ مِّن نَّخِيلٍ وَأَعْنَـٰبٍ لَّكُمْ فِيهَا فَوَ؛كِهُ كَثِيرَةٌ وَمِنْهَا تَاكُلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 20, 'وَشَجَرَةً تَخْرُجُ مِن طُورۣ سِينَآءَ تَنۢبُــتُ بِالدُّهْنِ وَصِبْغٍ لِّلاَكِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 21, 'وَإِنَّ لَكُمْ فِى ۱لاَنْعَـٰمِ لَعِبْرَةًؐ نَّسْقِيكُم مِّمَّا فِى بُطُونِهَاؐ وَلَكُمْ فِيهَا مَنَـٰفِعُ كَثِيرَةٌ وَمِنْهَا تَاكُلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 22, 'وَعَلَيْهَا وَعَلَي ۰لْفُلْــكِ تُحْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 23, 'وَلَقَدَ اَرْسَلْنَا نُوحاٗ اِلَيٰ قَوْمِهِ” فَقَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ مَا لَكُم مِّنِ اِچَهٖ غَيْرُهُؐ; أَفَلاَ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 24, 'فَقَالَ ۰لْمَلَؤُاْ 49 ۴لذِيــنَ كَفَرُواْ مِن قَوْمِهِ” مَا هَـٰذَآ إِلاَّ بَشَرٌ مِّثْلُكُمْ يُرۣيدُ أَنْ يَّتَفَضَّــلَ عَلَيْكُمْ وَلَوْ شَآءَ ۰للَّهُ لَأَنزَلَ مَلَئِكَةً مَّا سَمِعْنَا بِهَـٰذَا فِىٓ ءَابَآئِنَا ۰لاَوَّلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 25, 'إِنْ هُوَ إِلاَّ رَجُلٛ بِهِ” جِنَّةٌ فَتَرَبَّصُواْ بِهِ” حَتَّيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 26, 'قَالَ رَبِّ ۹نصُرْنِى بِمَا كَذَّبُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 27, 'فَأَوْحَيْنَآ إِلَيْهِ أَنِ ''صْنَعِ ۱لْفُلْــكَ بِأَعْيُنِنَا وَوَحْيِنَاؐ فَإِذَا جَآءَ امْرُنَا وَفَارَ ۰لتَّنُّورُ فَاسْلُــكْ فِيهَا مِــن كُلِّ زَوْجَيْنِ ''ثْنَيْنِ وَأَهْلَكَ إِلاَّ مَــن سَبَــقَ عَلَيْهِ ۱لْقَوْلُ مِنْهُمْؐ وَلاَ تُخَــٰـطِـبْـنِى فِى ۱لذِيــنَ ظَلَمُوٓاْ إِنَّهُم مُّغْرَقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 28, 'فَإِذَا "سْتَوَيْــتَ أَنتَ وَمَــن مَّعَــكَ عَلَي ۰لْفُلْــكِ فَقُـلِ ۱لْحَمْدُ لِلهِ ۱ﻟ﮲ نَجّۭيٰنَا مِــنَ ۰لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 29, 'وَقُل رَّبِّ أَنزۣلْنِى مُنزَلًا مُّبَـٰرَكاً وَأَنتَ خَيْرُ ۴لْمُنزۣلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 30, 'إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍؐ وَإِن كُنَّا لَمُبْتَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 31, 'ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قَرْناٗ —اخَرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 32, 'فَأَرْسَلْنَا فِيهِمْ رَسُولًا مِّنْهُمُ; أَنُ ۶عْبُدُواْ ۴للَّهَ مَا لَكُم مِّـنِ اِچَهٖ غَيْرُهُؐ; أَفَلاَ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 33, 'وَقَالَ ۰لْمَلُءَ مِن قَوْمِهِ ۱لذِيــنَ كَفَرُواْ وَكَذَّبُواْ بِلِقَآءِ ۱لاَخِرَةِ وَأَتْرَفْنَـٰهُمْ 50 فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا مَا هَـٰذَآ إِلاَّ بَشَرٌ مِّثْلُكُمْ يَاكُـلُ مِمَّا تَاكُلُونَ مِنْهُ وَيَشْرَبُ مِمَّا تَشْرَبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 34, 'وَلَـئِـــنَ اَطَعْتُم بَشَراً مِّثْلَكُمُ; إِنَّكُمُ; إِذاً لَّخَـٰسِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 35, 'أَيَعِدُكُمُ; أَنَّكُمُ; إِذَا مِتُّمْ وَكُنتُمْ تُرَاباً وَعِظَـٰماٗ اَنَّكُم مُّخْرَجُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 36, 'هَيْهَاتَ هَيْهَاتَ لِمَا تُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 37, 'إِنْ هِيَ إِلاَّ حَيَاتُنَا ۰لدُّنْيۭا نَمُوتُ وَنَحْيۭا وَمَا نَحْنُ بِمَبْعُوثِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 38, 'إِنْ هُوَ إِلاَّ رَجُل٘ ''فْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباً وَمَا نَحْــنُ لَهُ„ بِمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 39, '© قَالَ رَبِّ ۹نصُرْنِى بِمَا كَذَّبُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 40, 'قَالَ عَمَّا قَلِيــلٍ ڤَّيُصْبِحُنَّ نَـٰدِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 41, 'فَأَخَذَتْهُمُ ۴ڤصَّيْحَةُ بِالْحَقِّ فَجَعَلْنَـٰهُمْ غُثَآءًؐ فَبُعْداً لِّلْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 42, 'ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قُرُوناٗ —اخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 43, 'مَا تَسْبِقُ مِـنُ ۷مَّةٖ اَجَلَهَا وَمَا يَسْتَـٰخِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 44, 'ثُمَّ أَرْسَلْنَا رُسُلَنَا تَتْرۭاؐ كُلَّ مَا جَآءَ ا*مَّةً رَّسُولُهَا كَذَّبُوهُؐ فَأَتْبَعْنَا بَعْضَهُم بَعْضاً وَجَعَلْنَـٰهُمُ; أَحَادِيثَؐ فَبُعْداً لِّقَوْمٍ لاَّ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 45, 'ثُمَّ أَرْسَلْنَا مُوسۭيٰ وَأَخَاهُ هَـٰرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 46, 'بِـَٔايَـٰتِنَا وَسُلْطَـٰنٍ مُّبِينٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 47, 'اِلَيٰ فِرْعَوْنَ وَمَلْاَئِهِ” فَاسْتَكْبَرُواْ 51 وَكَانُواْ قَوْماٗ عَالِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 48, 'فَقَالُوٓاْ أَنُومِنُ لِبَشَرَيْنِ مِثْلِنَا وَقَوْمُهُمَا لَنَا عَـٰبِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 49, 'فَكَذَّبُوهُمَا فَكَانُواْ مِنَ ۰لْمُهْلَكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 50, 'وَلَقَدَ —اتَيْنَا مُوسَــي ۰لْكِتَـٰبَ لَعَلَّهُمْ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 51, 'وَجَعَلْنَا "بْنَ مَرْيَمَ وَٱُمَّهُ; ءَايَةًؐ وَءَاوَيْنَـٰهُمَآ إِلَيٰ رُبْوَةٍ ذَاتِ قَرۭارٍ وَمَعِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 52, 'يَـٰٓأَيُّهَا ۰لرُّسُــلُ كُلُواْ مِنَ ۰لطَّيِّبَـٰتِ وَاعْمَلُواْ صَـٰڤِحاٗؐ اِنِّى بِمَا تَعْمَلُونَ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 53, 'وَأَنَّ هَـٰذِهِ“ ٱُمَّتُكُمُ; ٱُمَّةً وَ؛حِدَةًؐ وَأَنَا رَبُّكُمْ فَاتَّقُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 54, 'فَتَقَطَّعُوٓاْ أَمْرَهُم بَيْنَهُمْ زُبُراًؐ كُلُّ حِزْبٙ بِمَا لَدَيْهِمْ فَرۣحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 55, 'فَذَرْهُمْ فِى غَمْرَتِهِمْ حَتَّيٰ حِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 56, 'اَيَحْسِبُونَ أَنَّمَا نُمِدُّهُم بِهِ” مِــن مَّالٍ وَبَنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 57, 'نُسَارۣعُ لَهُمْ فِى ۱لْخَيْرَ؛تِؐ بَـل لاَّ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 58, 'إِنَّ ۰لذِيــنَ هُم مِّــنْ خَشْيَةِ رَبِّهِم مُّشْفِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 59, 'وَالذِيــنَ هُم بِـَٔايَـٰــتِ رَبِّهِمْ يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 60, 'وَالذِيــنَ هُم بِرَبِّهِمْ لاَ يُشْرۣكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 61, 'وَالذِينَ يُوتُونَ مَآ ءَاتَواْ وَّقُلُوبُهُمْ وَجِلَة٘ اَنَّهُمُ; إِلَيٰ رَبِّهِمْ رَ؛جِعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 62, 'ٱُوْلَئِــكَ يُسَـٰرۣعُونَ فِى ۱لْخَيْرَ؛تِؐ وَهُمْ لَهَا سَـٰبِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 63, 'وَلاَ نُكَلِّفُ نَفْساٗ اِلاَّ وُسْعَهَاؐ وَلَدَيْنَا كِتَـٰــبٌ 52 يَنطِقُ بِالْحَقِّ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 64, 'بَلْ قُلُوبُهُمْ فِى غَمْرَةٍ مِّــنْ هَـٰذَاؐ وَلَهُمُ; أَعْمَـٰلٌ مِّن دُونِ ذَ؛لِــكَؐ هُمْ لَهَا عَـٰمِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 65, 'حَتَّيٰٓ إِذَآ أَخَذْنَا مُتْرَفِيهِم بِالْعَذَابِ إِذَا هُمْ يَجْــَٔـرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 66, 'لاَ تَجْــَٔـرُواْ ۴لْيَوْمَؐ إِنَّكُم مِّنَّا لاَ تُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 67, 'قَدْ كَانَــتَ —ايَـٰتِى تُتْلۭــيٰ عَلَيْكُمْ فَكُنتُمْ عَلَــيٰٓ أَعْقَـٰبِكُمْ تَنكِصُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 68, 'مُسْتَكْبِـرۣينَ بِهِؐ” سَـٰمِراً تُهْجِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 69, 'أَفَلَمْ يَدَّبَّرُواْ ۴لْقَوْلَ أَمْ جَآءَهُم مَّا لَمْ يَاتِ ءَابَآءَهُمُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 70, 'أَمْ لَمْ يَعْرۣفُواْ رَسُولَهُمْ فَهُمْ لَهُ„ مُنكِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 71, 'أَمْ يَقُولُونَ بِهِ” جِنَّةٛؐ بَلْ جَآءَهُم بِالْحَقﱢّؐ وَأَكْثَرُهُمْ ڤِڤْحَــقّۣ كَـٰرۣهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 72, 'وَلَوۣ ''تَّبَعَ ۰لْحَــقُّ أَهْوَآءَهُمْ لَفَسَدَتِ ۱لسَّمَـٰوَ؛تُ وَالاَرْضُ وَمَن فِيهِــنَّؐ بَلَ اَتَيْنَـٰهُم بِذِكْرۣهِمْؐ فَهُمْ عَن ذِكْرۣهِم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 73, 'أَمْ تَسْـَٔلُهُمْ خَرْجاًؐ فَخَرَاجُ رَبِّــكَ خَيْرٌؐ وَهُوَ خَيْرُ ۴لرَّ؛زۣقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 74, 'وَإِنَّــكَ لَتَدْعُوهُمُ; إِلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 75, 'وَإِنَّ ۰لذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ عَنِ ۱لصِّرَ؛طِ لَنَـٰكِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 76, '¥ وَلَوْ رَحِمْنَـٰهُمْ وَكَشَفْنَا 5 مَا بِهِم مِّــن ضُرٍّ ڤَّڤَجُّواْ فِى طُغْيَـٰنِهِمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 77, 'وَلَقَدَ اَخَذْنَـٰهُم بِالْعَذَابِ فَمَا "سْتَكَانُواْ لِرَبِّهِمْ وَمَا يَتَضَرَّعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 78, 'حَتَّيٰٓ إِذَا فَتَحْنَا عَلَيْهِم بَاباً ذَا عَذَابٍ شَدِيدٖ اِذَا هُمْ فِيهِ مُبْلِسُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 79, 'وَهُوَ ۰ﻟـذِىٓ أَنشَأَ لَكُمُ ۴لسَّمْعَ وَالاَبْصَـٰرَ وَالاَفْـِٕدَةَؐ قَلِيلًا مَّا تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 80, 'وَهُوَ ۰ﻟ﮲ ذَرَأَكُمْ فِى ۱لاَرْضِ وَإِلَيْهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 81, 'وَهُوَ ۰ﻟ﮲ يُحْىِ” وَيُمِيــتُؐ وَلَهُ èخْتِچَفُ ۴ليْلِ وَالنَّهۭارۣؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 82, 'بَــلْ قَالُواْ مِثْــلَ مَا قَالَ ۰لاَوَّلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 83, 'قَالُوٓاْ أَ.ذَا مِتْنَا وَكُنَّا تُرَاباً وَعِظَـٰماٗ اِنَّا لَمَبْعُوثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 84, 'لَقَدْ وُعِدْنَا نَحْنُ وَءَابَآؤُنَا هَـٰذَا مِن قَبْلُؐ إِنْ هَـٰذَآ إِلٓاَّ أَسَـٰطِيرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 85, 'قُل لِّمَنِ ۱لاَرْضُ وَمَن فِيهَآ إِن كُنتُمْ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 86, 'سَيَقُولُونننَ لِلهِؐ قُــلَ اَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 87, 'قُلْ مَن رَّبُّ ۴لسَّمَـٰوَ؛تِ ۱لسَّبْعِ وَرَبُّ ۴لْعَرْشِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 88, 'سَيَقُولُونَ لِلهِؐ قُلَ اَفَلاَ تَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 89, 'قُلْ مَنۢ بِيَدِهِ” مَلَكُوتُ كُــلّۣ شَيْءٍ وَهُوَ يُجِيرُ وَلاَ يُجَارُ عَلَيْهِ إِن كُنتُمْ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 90, 'سَيَقُولُونَ لِلهِؐ قُلْ فَأَنّۭيٰ 54 تُسْحَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 91, 'بَلَ اَتَيْنَـٰهُم بِالْحَقﱢّؐ وَإِنَّهُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 92, 'مَا "تَّخَذَ ۰للَّهُ مِنْ وَّلَدٍؐ وَمَا كَانَ مَعَهُ„ مِنِ اِچَهٖؐ اِذاً لَّذَهَــبَ كُلُّ إِچَهٙ بِمَا خَلَقَ وَلَعَلاَ بَعْضُهُمْ عَلَيٰ بَعْــضٍؐ سُبْحَـٰــنَ ۰للَّهِ عَمَّا يَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 93, 'عَـٰلِمُ ۴لْغَيْبِ وَالشَّهَـٰدَةِؐ فَتَعَـٰلۭــيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 94, 'قُل رَّبِّ إِمَّا تُرۣيَنِّى مَا يُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 95, 'رَبِّ فَلاَ تَجْعَلْنِى فِى ۱لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 96, 'وَإِنَّا عَلَيٰٓ أَن نُّرۣيَكَ مَا نَعِدُهُمْ لَقَـٰدِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 97, '"دْفَعْ بِالتِى هِــيَ أَحْسَــنُ ۴لسَّيِّيؕةَؐ نَحْــنُ أَعْلَمُ بِمَا يَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 98, 'وَقُل رَّبِّ أَعُوذُ بِــكَ مِــنْ هَمَزَ؛تِ ۱لشَّيَـٰطِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 99, 'وَأَعُوذُ بِــكَ رَبِّ أَنْ يَّحْضُرُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 100, 'حَتَّيٰٓ إِذَا جَآءَ احَدَهُمُ ۴لْمَوْتُ قَالَ رَبِّ ''رْجِعُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 101, 'لَعَلِّيَ أَعْمَلُ صَـٰڤِحاً فِيمَا تَرَكْــتُ كَلٓؐاَّ إِنَّهَا كَلِمَة٘ هُوَ قَآئِلُهَاؐ وَمِنْ وَّرَآئِهِم بَرْزَخ٘ اِلَيٰ يَوْمِ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 102, 'فَإِذَا نُفِخَ فِى ۱لصُّورۣ فَلآَ أَنسَابَ بَيْنَهُمْ يَوْمَئِذٍ وَلاَ يَتَسَآءَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 103, 'فَمَــن ثَقُلَتْ مَوَ؛زۣينُهُ„ فَٱُوْلَئِكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 104, 'وَمَــنْ خَفَّتْ مَوَ؛زۣينُهُ„ فَٱُوْلَئِكَ ۰لذِيــنَ خَسِرُوٓاْ أَنفُسَهُمْ فِى جَهَنَّمَ 55 خَـٰلِدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 105, 'تَڤْفَحُ وُجُوهَهُمُ ۴لنَّارُ وَهُمْ فِيهَا كَـٰڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 106, 'أَلَمْ تَكُــنَ —ايَـٰتِى تُتْلۭــيٰ عَلَيْكُمْ فَكُنتُم بِهَا تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 107, 'قَالُواْ رَبَّنَا غَلَبَتْ عَلَيْنَا شِقْوَتُنَا وَكُنَّا قَوْماً ضَآلِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 108, 'رَبَّنَآ أَخْرۣجْنَا مِنْهَا فَإِنْ عُدْنَا فَإِنَّا ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 109, 'قَالَ "خْسَـُٔواْ فِيهَا وَلاَ تُكَلِّمُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 110, 'إِنَّهُ„ كَانَ فَرۣيقٌ مِّــنْ عِبَادِى يَقُولُونَ رَبَّنَآ ءَامَنَّا فَاغْفِرْ لَنَا وَارْحَمْنَا وَأَنتَ خَيْرُ ۴لرَّ؛حِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 111, 'فَاتَّخَذتُّمُوهُمْ سُخْرۣيّاٗ حَتَّــيٰٓ أَنسَوْكُمْ ذِكْرۣى وَكُنتُم مِّنْهُمْ تَضْحَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 112, 'إِنِّى جَزَيْتُهُمُ ۴لْيَوْمَ بِمَا صَبَرُوٓاْ أَنَّهُمْ هُمُ ۴لْفَآئِزُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 113, 'قَالللَ كَمْ لَبِثْتُمْ فِى ۱لاَرْضضضِ عَدَدَ سِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 114, 'قَالُواْ لَبِثْنَا يَوْماٗ اَوْ بَعْضَ يَوْمٍؐ فَسْـَٔلِ ۱لْعَآدِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 115, 'قَالَ إِن لَّبِثْتُمُ; إِلاَّ قَلِيلًا لَّوَ اَنَّكُمْ كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 116, '© أَفَحَسِبْتُمُ; أَنَّمَا خَلَقْنَـٰكُمْ عَبَثاً وَأَنَّكُمُ; إِلَيْنَا لاَ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 117, 'فَتَعَـٰلَــي ۰للَّهُ ۴لْمَلِكُ ۴لْحَقُّؐ لآَ إِچَهَ إِلاَّ هُوَؐ رَبُّ ۴لْعَرْشِ ۱لْكَرۣيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 118, 'وَمَنْ يَّدْعُ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ لاَ بُرْهَـٰــنَ لَهُ„ بِهِ” فَإِنَّمَا 56 حِسَابُهُ„ عِندَ رَبِّهِؐ“ إِنَّهُ„ لاَ يُفْلِحُ ۴لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (23, 119, 'وَقُل رَّبِّ ''غْفِرْ وَارْحَمْ وَأَنتَ خَيْرُ ۴لرَّ؛حِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سُورَة٘ اَنزَلْنَـٰهَا وَفَرَضْنَـٰهَا وَأَنزَلْنَا فِيهَآ ءَايَـٰتٙ بَـيِّنَـٰــتٍ لَّعَلَّكُمْ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 2, '۰لزَّانِيَةُ وَالزَّانِى فَاجْلِدُواْ كُلَّ وَ؛حِدٍ مِّنْهُمَا مِاْيؕةَ جَلْدَةٍؐ وَلاَ تَاخُذْكُم بِهِمَا رَأْفَةٌ فِى دِينِ ۱للَّهِ إِن كُنتُمْ تُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ وَلْيَشْهَدْ عَذَابَهُمَا طَآئِفَةٌ مِّــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 3, '۰لزَّانِى لاَ يَنكِحُ إِلاَّ زَانِيَةٗ اَوْ مُشْرۣكَةًؐ وَالزَّانِيَةُ لاَ يَنكِحُهَآ إِلاَّ زَانٖ اَوْ مُشْرۣكٌؐ وَحُرّۣمَ ذَ؛لِــكَ عَلَــي ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 4, 'وَالذِينَ يَرْمُونَ ۰ڤْمُحْصَنَـٰــتِ ثُمَّ لَمْ يَاتُواْ بِأَرْبَعَةِ شُهَدَآءَ فَاجْلِدُوهُمْ ثَمَـٰنِيــنَ جَلْدَةًؐ وَلاَ تَقْبَلُواْ لَهُمْ شَهَـٰدَةٗ اَبَداً وَٱُوْلَئِــكَ هُمُ ۴لْفَـٰسِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 5, 'إِلاَّ ۰لذِيــنَ تَابُواْ مِنۢ بَعْدِ ذَ؛لِكَ وَأَصْڤَحُواْ فَإِنَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 6, 'وَالذِينَ يَرْمُونَ أَزْوَ؛جَهُمْ وَلَمْ 57 يَكُــن لَّهُمْ شُهَدَآءُ ﹹلٓاَّ أَنفُسُهُمْ فَشَهَـٰدَةُ أَحَدِهِمُ; أَرْبَعَ شَهَـٰدَ؛تٙ بِاللَّهِ إِنَّهُ„ لَمِــنَ ۰لصَّـٰدِقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 7, 'وَالْخَـٰمِسَةُ أَن لَّعْنَتُ ۴للَّهِ عَلَيْهِ إِن كَانَ مِــنَ ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 8, 'وَيَدْرَؤُاْ عَنْهَا ۰لْعَذَابببَ أَن تَشْهَدَ أَرْبَعَ شَهَـٰدَ؛تٙ بِاللَّهِ إِنَّهُ„ لَمِــنَ ۰لْكَـٰذِبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 9, 'وَالْخَـٰمِسَةُ أَنْ غَضِبَ ۰للَّهُ عَلَيْهَآ إِن كَانَ مِنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 10, 'وَلَوْلاَ فَضْــلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ وَأَنَّ ۰للَّهَ تَوَّاب٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 11, 'اِنَّ ۰لذِينَ جَآءُو بِالِافْــكِ عُصْبَةٌ مِّنكُمْ لاَ تَحْسِبُوهُ شَرّاً لَّكُمؐ بَلْ هُوَ خَيْرٌ لَّكُمْؐ لِكُلِّ ''مْرۣئٍ مِّنْهُم مَّا "كْتَسَــبَ مِنَ ۰لِاثْمِؐ وَاﻟ﮲ تَوَلّۭيٰ كِبْرَهُ„ مِنْهُمْ لَهُ„ عَذَاب٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 12, 'لَّوْلآَ إِذْ سَمِعْتُمُوهُ ظَــنَّ ۰لْمُومِنُونَ وَالْمُومِنَـٰــتُ بِأَنفُسِهِمْ خَيْراً وَقَالُواْ هَـٰذَآ إِفْكٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 13, 'لَّوْلاَ جَآءُو عَلَيْهِ بِأَرْبَعَةِ شُهَدَآءَؐ فَإِذْ لَمْ يَاتُواْ بِالشُّهَدَآءِ فَٱُوْلَئِــكَ عِندَ ۰للَّهِ هُمُ ۴لْكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 14, 'وَلَوْلاَ فَضْــلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ فِى ۱لدُّنْيۭا وَالاَخِرَةِ لَمَسَّكُمْ فِى مَآ أَفَضْتُمْ فِيهِ عَذَاب٘ عَظِيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 15, 'اِذْ تَلَقَّوْنَهُ„ بِأَلْسِنَتِكُمْ 58 وَتَقُولُونَ بِأَفْوَاهِكُم مَّا لَيْــسَ لَكُم بِهِ” عِلْمٌ وَتَحْسِبُونَهُ„ هَيِّناً وَهُوَ عِندَ ۰للَّهِ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 16, 'وَلَوْلآَ إِذْ سَمِعْتُمُوهُ قُلْتُم مَّا يَكُونُ لَنَآ أَن نَّتَكَلَّمَ بِهَـٰذَا سُبْحَـٰنَــكَ هَـٰذَا بُهْتَـٰن٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 17, 'يَعِظُكُمُ ۴للَّهُ أَن تَعُودُواْ لِمِثْلِهِ“ أَبَداٗ اِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 18, 'وَيُبَيِّــنُ ۴للَّهُ لَكُمُ ۴لاَيَـٰتِؐ وَاللَّهُ عَلِيم٘ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 19, 'اِنَّ ۰لذِينَ يُحِبُّونَ أَن تَشِيعَ ۰ڤْفَـٰحِشَةُ فِى ۱لذِينَ ءَامَنُواْ لَهُمْ عَذَاب٘ اَلِيمٌ فِى ۱لدُّنْيۭا وَالاَخِرَةِؐ وَاللَّهُ يَعْلَمُؐ وَأَنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 20, 'وَلَوْلاَ فَضْــلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ وَأَنَّ ۰للَّهَ رَءُوفٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 21, '¤ يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَتَّبِعُواْ خُطْوَ؛تِ ۱لشَّيْطَـٰنِؐ وَمَنْ يَّتَّبِعْ خُطْوَ؛تِ ۱لشَّيْطَـٰنِ فَإِنَّهُ„ يَامُرُ بِاڤْفَحْشَآءِ وَالْمُنكَرۣؐ وَلَوْلاَ فَضْــلُ ۴للَّهِ عَلَيْكُمْ وَرَحْمَتُهُ„ مَا زَكَــيٰ مِنكُم مِّــنَ اَحَدٖ اَبَداًؐ وَچَكِــنَّ ۰للَّهَ يُزَكِّى مَـنْ يَّشَآءُؐ وَاللَّهُ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 22, 'وَلاَ يَاتَلِ ٱُوْلُواْ ۴لْفَضْـلِ مِنكُمْ وَالسَّعَةِ أَنْ يُّوتُوٓاْ ٱُوْلِى ۱لْقُرْبۭيٰ وَالْمَسَـٰكِينَ وَاڤْمُهَـٰجِرۣينَ فِى سَبِيـلِ ۱للَّهِؐ وَلْيَعْفُواْ وَڤْيَصْفَحُوٓاْؐ أَلاَ تُحِبُّونَ أَنْ يَّغْفِرَ ۰للَّهُ لَكُمْؐ 59 وَاللَّهُ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 23, 'اِنَّ ۰لذِينَ يَرْمُونَ ۰ڤْمُحْصَنَـٰتِ ۱لْغَـٰفِچَتِ ۱لْمُومِنَـٰتِ لُعِنُواْ فِى ۱لدُّنْيۭا وَالاَخِرَةِ وَلَهُمْ عَذَاب٘ عَظِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 24, 'يَوْمَ تَشْهَدُ عَلَيْهِمُ; أَلْسِنَتُهُمْ وَأَيْدِيهِمْ وَأَرْجُلُهُم بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 25, 'يَوْمَئِذٍ يُوَفِّيهِمُ ۴للَّهُ دِينَهُمُ ۴لْحَقَّؐ وَيَعْلَمُونَ أَنننَّ ۰للَّهَ هُوَ ۰لْحَقُّ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 26, '۴لْخَبِيثَـٰــتُ ڤِڤْخَبِيثِينَ وَالْخَبِيثُونَ ڤِڤْخَبِيثَـٰــتِؐ وَالطَّيِّبَـٰــتُ لِلطَّيِّبِينَ وَالطَّيِّبُونَ لِلطَّيِّبَـٰــتِؐ ٱُوْلَئِكَ مُبَرَّءُونَ مِمَّا يَقُولُونَؐ لَهُم مَّغْفِرَةٌ وَرۣزْقٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 27, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَدْخُلُواْ بُيُوتاٗ غَيْرَ بُيُوتِكُمْ حَتَّــيٰ تَسْتَانِسُواْ وَتُسَلِّمُواْ عَلَــيٰٓ أَهْلِهَاؐ ذَ؛لِكُمْ خَيْرٌ لَّكُمْ لَعَلَّكُمْ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 28, 'فَإِن لَّمْ تَجِدُواْ فِيهَآ أَحَداً فَلاَ تَدْخُلُوهَا حَتَّيٰ يُوذَنَ لَكُمْؐ وَإِن قِيــلَ لَكُمُ èرْجِعُواْ فَارْجِعُواْ هُوَ أَزْكۭــيٰ لَكُمْؐ وَاللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 29, 'لَّيْــسَ عَلَيْكُمْ جُنَاح٘ اَن تَدْخُلُواْ بُيُوتاٗ غَيْرَ مَسْكُونَةٍ فِيهَا مَتَـٰعٌ لَّكُمْؐ وَاللَّهُ يَعْلَمُ مَا تُبْدُونَ وَمَا تَكْتُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 30, 'قُـل لِّلْمُومِنِينَ يَغُضُّواْ مِنَ اَبْصۭـٰرۣهِمْ 60 وَيَحْفَظُواْ فُرُوجَهُمْ ذَ؛لِــكَ أَزْكۭــيٰ لَهُمُؐ; إِنننَّ ۰للَّهَ خَبِيرٛ بِمَا يَصْنَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 31, 'وَقُل لِّلْمُومِنَـٰــتِ يَغْضُضْنَ مِنَ اَبْصۭـٰرۣهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّؐ وَلاَ يُبْدِينَ زۣينَتَهُنَّ إِلاَّ مَا ظَهَرَ مِنْهَاؐ وَلْيَضْرۣبْــنَ بِخُمُرۣهِــنَّ عَلَــيٰ جُيُوبِهِنَّؐ وَلاَ يُبْدِينَ زۣينَتَهُنَّ إِلاَّ لِبُعُولَتِهِنَّ أَوَ —ابَآئِهِنَّ أَوَ —ابَآءِ بُعُولَتِهِنَّ أَوَ اَبْنَآئِهِنَّ أَوَ اَبْنَآءِ بُعُولَتِهِنَّ أَوۣ اِخْوَ؛نِهِنَّ أَوْ بَنِىٓ إِخْوَ؛نِهِنَّ أَوْ بَنِىٓ أَخَوَ؛تِهِنَّ أَوْ نِسَآئِهِنَّ أَوْ مَا مَلَكَتَ اَيْمَـٰنُهُنَّ أَوۣ ۱لتَّـٰبِعِيــنَ غَيْرۣ ٱُوْلِى ۱لِارْبَةِ مِنَ ۰لرّۣجَالِ أَوۣ ۱لطِّفْلِ ۱لذِينَ لَمْ يَظْهَرُواْ عَلَيٰ عَوْرَ؛تِ ۱لنِّسَآءِؐ وَلاَ يَضْرۣبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِن زۣينَتِهِنَّؐ وَتُوبُوٓاْ إِلَــي ۰للَّهِ جَمِيعاٗ اَيُّهَ ۰لْمُومِنُونَ لَعَلَّكُمْ تُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 32, 'وَأَنكِحُواْ ۴لاَيَـٰمۭيٰ مِنكُمْ وَاڤصَّـٰڤِحِينَ مِنْ عِبَادِكُمْ وَإِمَآئِكُمُؐ; إِنْ يَّكُونُواْ فُقَرَآءَ يُغْنِهِمُ ۴للَّهُ مِـن فَضْلِهِؐ” وَاللَّهُ وَ؛سِع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 33, 'وَلْيَسْتَعْفِفِ ۱لذِيــنَ لاَ يَجِدُونَ نِكَاحاٗ حَتَّيٰ يُغْنِيَهُمُ ۴للَّهُ مِـن فَضْلِهِؐ” وَالذِينَ يَبْتَغُونَ ۰لْكِتَـٰــبَ مِمَّا مَلَكَــتَ اَيْمَـٰنُكُمْ فَكَاتِبُوهُمُ; 61 إِنْ عَلِمْتُمْ فِيهِمْ خَيْراًؐ وَءَاتُوهُم مِّــن مَّالِ ۱للَّهِ ۱ﻟـذِىٓ ءَاتۭيٰكُمْؐ وَلاَ تُكْرۣهُواْ فَتَيَـٰتِكُمْ عَلَي ۰لْبِغَآءِ انَ اَرَدْنَ تَحَصُّناً لِّتَبْتَغُواْ عَرَضضضَ ۰لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَمَنْ يُّكْرۣههُّنَّ فَإِنَّ ۰للَّهَ مِنۢ بَعْدِ إِكْرَ؛هِهِــنَّ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 34, 'وَلَقَدَ اَنزَلْنَآ إِلَيْكُمُ; ءَايَـٰتٍ مُّبَيَّنَـٰــتٍ وَمَثَلًا مِّــنَ ۰لذِيــنَ خَلَوْاْ مِن قَبْلِكُمْ وَمَوْعِظَةً لِّلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 35, '© ۰للَّهُ نُورُ ۴لسَّمَـٰوَ؛تتتِ وَالاَرْضضضِؐ مَثَلُ نُورۣهِ” كَمِشْكَوٰةٍ فِيهَا مِصْبَاح٘ؐ ۱لْمِصْبَاحُ فِى زُجَاجَةٖؐ ۱لزُّجَاجَةُ كَأَنَّهَا كَوْكَــبٌ دُرّۣيٌّ يُوقَدُ مِــن شَجَرَةٍ مُّبَـٰرَكَةٍ زَيْتُونَةٍ لاَّ شَرْقِيَّةٍ وَلاَ غَرْبِيَّةٍ يَكَادُ زَيْتُهَا يُضِىٓءُ وَلَوْ لَمْ تَمْسَسْهُ نَارٌؐ نُّور٘ عَلَيٰ نُورٍؐ يَهْدِى ۱للَّهُ لِنُورۣهِ” مَـنْ يَّشَآءُؐ وَيَضْرۣبُ ۴للَّهُ ۴لاَمْثَـٰلَ لِلنَّاسِؐ وَاللَّهُ بِكُــلّۣ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 36, 'فِى بُيُوتٖ اَذِنننَ ۰للَّهُ أَن تُرْفَعَ وَيُذْكَرَ فِيهَا "سْمُهُ„ يُسَبِّحُ لَهُ„ فِيهَا بِالْغُدُوّۣ وَالاَصَالِ رۣجَالٌ لاَّ تُلْهِيهِمْ تِجَـٰرَةٌ وَلاَ بَيْع٘ عَن ذِكْرۣ ۱للَّهِ وَإِقَامِ ۱لصَّلَوٰةِ وَإِيتَآءِ ۱لزَّكَوٰةِؐ يَخَافُونَ يَوْماً تَتَقَلَّبُ فِيهِ ۱لْقُلُوبُ وَالاَبْصَـٰرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 37, 'ڤِيَجْزۣيَهُمُ ۴للَّهُ أَحْسَــنَ مَا عَمِلُواْ 62 وَيَزۣيدَهُم مِّـن فَضْلِهِؐ” وَاللَّهُ يَرْزُقُ مَـنْ يَّشَآءُ بِغَيْرۣحِسَابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 38, 'وَالذِيــنَ كَفَرُوٓاْ أَعْمَـٰلُهُمْ كَسَرَابٙ بِقِيعَةٍ يَحْسِبُهُ ۴لظَّمْـَٔانُ مَآءٗ حَتَّيٰٓ إِذَا جَآءَهُ„ لَمْ يَجِدْهُ شَيْـٔاً وَوَجَدَ ۰للَّهَ عِندَهُ„ فَوَفّۭيٰهُ حِسَابَهُؐ, وَاللَّهُ سَرۣيعُ ۴لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 39, 'أَوْ كَظُلُمَـٰتٍ فِى بَحْرٍ لُّجِّيٍّ يَغْشۭيٰهُ مَوْجٌ مِّن فَوْقِهِ” مَوْجٌ مِّن فَوْقِهِ” سَحَابٌؐ ظُلُمَـٰتٛ بَعْضُهَا فَوْقَ بَعْضٖؐ اِذَآ أَخْرَجَ يَدَهُ„ لَمْ يَكَدْ يَرۭيٰهَاؐ وَمَن لَّمْ يَجْعَـلِ ۱للَّهُ لَهُ„ نُوراً فَمَا لَهُ„ مِن نُّورٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 40, 'اَلَمْ تَرَ أَنَّ ۰للَّهَ يُسَبِّحُ لَهُ„ مَن فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ وَالطَّيْرُ صَـٰٓفَّـٰــتٍؐ كُــلٌّ قَدْ عَلِمَ صَلاَتَهُ„ وَتَسْبِيحَهُؐ, وَاللَّهُ عَلِيمٛ بِمَا يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 41, 'وَلِلهِ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَإِلَي ۰للَّهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 42, 'أَلَمْ تَرَ أَنننَّ ۰للَّهَ يُزْجِـــى سَحَاباً ثُمَّ يُوَ۬لِّفُ بَيْنَهُ„ ثُمَّ يَجْعَلُهُ„ رُكَاماً فَتَرَي ۰لْوَدْقَ يَخْرُجُ مِنْ خِچَلِهِؐ” وَيُنَزّۣلُ مِنَ ۰لسَّمَآءِ مِن جِبَالٍ فِيهَا مِنۢ بَرَدٍ فَيُصِيبُ بِهِ” مَـنْ يَّشَآءُ وَيَصْرۣفُهُ„ عَن مَّنْ يَّشَآءُؐ يَكَادُ سَنَا بَرْقِهِ” يَذْهَبُ بِالاَبْصۭـٰـرۣؐ يُقَلِّــبُ ۴للَّهُ ۴ليْلَ وَالنَّهَارَؐ إِنَّ فِى ذَ؛لِكَ لَعِبْرَةً 6 لُءِّوْلِى ۱لاَبْصۭـٰـرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 43, 'وَاللَّهُ خَلَــقَ كُــلَّ دَآبَّةٍ مِّــن مَّآءٍؐ فَمِنْهُم مَّنْ يَّمْشِى عَلَيٰ بَطْنِهِؐ” وَمِنْهُم مَّـنْ يَّمْشِى عَلَيٰ رۣجْلَيْنِؐ وَمِنْهُم مَّنْ يَّمْشِى عَلَيٰٓ أَرْبَعٍؐ يَخْلُــقُ ۴للَّهُ مَا يَشَآءُؐ اِ۬نننَّ ۰للَّهَ عَلَيٰ كُــلّۣ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 44, 'لَّقَدَ اَنزَلْنَآ ءَايَـٰتٍ مُّبَيَّنَـٰـــتٍؐ وَاللَّهُ يَهْدِى مَـنْ يَّشَآءُ اِ۬لَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 45, 'وَيَقُولُونَ ءَامَنَّا بِاللَّهِ وَبِالرَّسُولِ وَأَطَعْنَا ثُمَّ يَتَوَلّۭيٰ فَرۣيقٌ مِّنْهُم مِّـنۢ بَعْدِ ذَ؛لِكَؐ وَمَآ ٱُوْلَئِــكَ بِالْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 46, 'وَإِذَا دُعُوٓاْ إِلَــي ۰للَّهِ وَرَسُولِهِ” ڤِيَحْكُمَ بَيْنَهُمُ; إِذَا فَرۣيـقٌ مِّنْهُم مُّعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 47, 'وَإِنْ يَّكُن لَّهُمُ ۴لْحَقُّ يَاتُوٓاْ إِلَيْهِ مُذْعِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 48, 'أَفِى قُلُوبِهِم مَّرَض٘ اَمِ ''رْتَابُوٓاْ أَمْ يَخَافُونَ أَنْ يَّحِيفَ ۰للَّهُ عَلَيْهِمْ وَرَسُولُهُؐ, بَلُ ۷وْلَئِــكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 49, 'إِنَّمَا كَانَ قَوْلَ ۰لْمُومِنِينَ إِذَا دُعُوٓاْ إِلَــي ۰للَّهِ وَرَسُولِهِ” ڤِيَحْكُمَ بَيْنَهُمُ; أَنْ يَّقُولُواْ سَمِعْنَا وَأَطَعْنَاؐ وَٱُوْلَئِكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 50, 'وَمَنْ يُّطِعِ ۱للَّهَ وَرَسُولَهُ„ وَيَخْشَ ۰للَّهَ وَيَتَّقِهِ” فَٱُوْلَئِــكَ هُمُ ۴لْفَآئِزُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 51, '¥ وَأَقْسَمُواْ بِاللَّهِ جَهْدَ أَيْمَـٰنِهِمْ لَـئِــنَ اَمَرْتَهُمْ ڤَيَخْرُجُنَّؐ 64 قُــل لاَّ تُقْسِمُواْؐ طَاعَةٌ مَّعْرُوفَة٘ؐ اِنَّ ۰للَّهَ خَبِيرٛ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 52, 'قُلَ اَطِيعُواْ ۴للَّهَ وَأَطِيعُواْ ۴لرَّسُولَؐ فَإِن تَوَلَّوْاْ فَإِنَّمَا عَلَيْهِ مَا حُمِّلَ وَعَلَيْكُم مَّا حُمِّلْتُمْؐ وَإِن تُطِيعُوهُ تَهْتَدُواْؐ وَمَا عَلَي ۰لرَّسُولِ إِلاَّ ۰لْبَچَغُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 53, 'وَعَدَ ۰للَّهُ ۴لذِينَ ءَامَنُواْ مِنكُمْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰـــتِ ڤَيَسْتَخْلِفَنَّهُمْ فِى ۱لاَرْضِ كَمَا "سْتَخْلَفَ ۰لذِينَ مِن قَبْلِهِمْ وَلَيُمَكِّنَــنَّ لَهُمْ دِينَهُمُ ۴ﻟ﮲ ''رْتَضۭــيٰ لَهُمْ وَلَيُبَدِّلَنَّهُم مِّـنۢ بَعْدِ خَوْفِهِمُ; أَمْناًؐ يَعْبُدُونَنِى لاَ يُشْرۣكُونَ بِى شَيْـٔاًؐ وَمَــن كَفَرَ بَعْدَ ذَ؛لِكَ فَٱُوْلَئِــكَ هُمُ ۴لْفَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 54, 'وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَأَطِيعُواْ ۴لرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 55, 'لاَ تَحْسِبَنَّ ۰لذِيــنَ كَفَرُواْ مُعْجِزۣيــنَ فِى ۱لاَرْضِؐ وَمَأْوۭيٰهُمُ ۴لنَّارُؐ وَلَبِيسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 56, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لِيَسْتَـٰذِنكُمُ ۴لذِينَ مَلَكَــتَ اَيْمَـٰنُكُمْ وَالذِينَ لَمْ يَبْلُغُواْ ۴لْحُلُمَ مِنكُمْ ثَـچَـــثَ مَرَّ؛تٍ مِّــن قَبْلِ صَلَوٰةِ ۱ڤْفَجْرۣ وَحِيــنَ تَضَعُونَ ثِيَابَكُم مِّنَ ۰لظَّهِيرَةِ وَمِنۢ بَعْدِ صَلَوٰةِ ۱لْعِشَآءِؐ ثَـچَـثُ عَوْرَ؛تٍ لَّكُمْؐ 65 لَيْــسَ عَلَيْكُمْ وَلاَ عَلَيْهِمْ جُنَاحٛ بَعْدَهُــنَّؐ طَوَّ؛فُونَ عَلَيْكُمؐ بَعْضُكُمْ عَلَيٰ بَعْــضٍؐ كَذَ؛لِــكَ يُبَيِّــنُ ۴للَّهُ لَكُمُ ۴لاَيَـٰــتِؐ وَاللَّهُ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 57, 'وَإِذَا بَلَغَ ۰لاَطْفَـٰلُ مِنكُمُ ۴لْحُلُمَ فَلْيَسْتَـٰذِنُواْ كَمَا "سْتَـٰذَنَ ۰لذِينَ مِن قَبْلِهِمْؐ كَذَ؛لِــكَ يُبَيِّنُ ۴للَّهُ لَكُمُ; ءَايَـٰتِهِؐ” وَاللَّهُ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 58, 'وَالْقَوَ؛عِدُ مِنَ ۰لنِّسَآءِ ۱لــتِى لاَ يَرْجُونَ نِكَاحاً فَلَيْــسَ عَلَيْهِنَّ جُنَاح٘ اَنْ يَّضَعْنَ ثِيَابَهُــنَّ غَيْرَ مُتَبَرّۣجَـٰــتٙ بِـزۣيـنَـةٍؐ وَأَنْ يَّسْتَعْفِفْــنَ خَيْرٌ لَّهُنَّؐ وَاللَّهُ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 59, 'لَّيْــسَ عَلَــي ۰لاَعْمۭيٰ حَرَجٌ وَلاَ عَلَــي ۰لاَعْرَجِ حَرَجٌ وَلاَ عَلَــي ۰لْمَرۣيــضِ حَرَجٌ وَلاَ عَلَــيٰٓ أَنفُسِكُمُ; أَننن تَاكُلُواْ مِـنۢ بُيُوتِكُمُ; أَوْ بُيُوتتتِ ءَابَآئِكُمُ; أَوْ بُيُوتتتِ ٱُمَّهَـٰتِكُمُ; أَوْ بُيُوتِ إِخْوَ؛نِكُمُ; أَوْ بُيُوتِ أَخَوَ؛تِكُمُ; أَوْ بُيُوتِ أَعْمَـٰمِكُمُ; أَوْ بُيُوتِ عَمَّـٰتِكُمُ; أَوْ بُيُوتِ أَخْوَ؛لِكُمُ; أَوْ بُيُوتِ خَـٰچَتِكُمُ; أَوْ مَا مَلَكْتُم مَّفَاتِحَهُ; أَوْ صَدِيقِكُمْؐ لَيْــسَ عَلَيْكُمْ جُنَاح٘ اَن تَاكُلُواْ جَمِيعاٗ اَوَ اَشْتَاتاًؐ فَإِذَا دَخَلْتُم بُيُوتاً فَسَلِّمُواْ عَلَيٰٓ أَنفُسِكُمْ تَحِيَّةً مِّنْ عِندِ ۱للَّهِ مُبَـٰرَكَةً طَيِّبَةًؐ كَذَ؛لِكَ 66 يُبَيِّــنُ ۴للَّهُ لَكُمُ ۴لاَيَـٰــتِ لَعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 60, 'إِنَّمَا ۰لْمُومِنُونَ ۰لذِيــنَ ءَامَنُواْ بِاللَّهِ وَرَسُولِهِ” وَإِذَا كَانُواْ مَعَهُ„ عَلَيٰٓ أَمْرٍ جَامِعٍ لَّمْ يَذْهَبُواْ حَتَّيٰ يَسْتَـٰذِنُوهُؐ إِنَّ ۰لذِينَ يَسْتَـٰذِنُونَكَ ٱُوْلَئِــكَ ۰لذِينَ يُومِنُونَ بِاللَّهِ وَرَسُولِهِؐ” فَإِذَا "سْتَـٰذَنُوكَ لِبَعْــضِ شَأْنِهِمْ فَاذَن لِّمَن شِيؔــتَ مِنْهُمْ وَاسْتَغْفِرْ لَهُمُ ۴للَّهَؐ إِنَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 61, '© لاَّ تَجْعَلُواْ دُعَآءَ ۰لرَّسُولِ بَيْنَكُمْ كَدُعَآءِ بَعْضِكُم بَعْضاًؐ قَدْ يَعْلَمُ ۴للَّهُ ۴لذِينَ يَتَسَلَّلُونَ مِنكُمْ لِوَاذاًؐ فَڤْيَحْذَرۣ ۱لذِيــنَ يُخَالِفُونَ عَــنَ اَمْرۣهِ“ أَننن تُصِيبَهُمْ فِتْنَة٘ اَوْ يُصِيبَهُمْ عَذَاب٘ اَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (24, 62, 'اَلآَ إِنَّ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِؐ قَدْ يَعْلَمُ مَآ أَنتُمْ عَلَيْهِؐ وَيَوْمَ يُرْجَعُونَ إِلَيْهِ فَيُنَبِّيؖهُم بِمَا عَمِلُواْؐ وَاللَّهُ بِكُــلّۣ شَيْءٖ عَلِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ تَبَـٰرَكَ ۰ﻟ﮲ نَزَّلَ ۰لْفُرْقَانَ عَلَيٰ عَبْدِهِ” لِيَكُونَ لِلْعَـٰلَمِينَ نَذِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 2, '۱ﻟ﮲ لَهُ„ مُلْــكُ ۴لسَّمَـٰوَ؛تِ 67 وَالاَرْضِ وَلَمْ يَتَّخِذْ وَلَداً وَلَمْ يَكُــن لَّهُ„ شَرۣيــكٌ فِى ۱لْمُلْكِؐ وَخَلَــقَ كُــلَّ شَيْءٍ فَقَدَّرَهُ„ تَقْدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 3, 'وَاتَّخَذُواْ مِن دُونِهِ“ ءَالِهَةً لاَّ يَخْلُقُونَ شَيْــٔاً وَهُمْ يُخْلَقُونَ وَلاَ يَمْلِكُونَ لَأِنفُسِهِمْ ضَرّاً وَلاَ نَفْعاً وَلاَ يَمْلِكُونَ مَوْتاً وَلاَ حَيَوٰةً وَلاَ نُشُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 4, 'وَقَالَ ۰لذِيــنَ كَفَرُوٓاْ إِنْ هَـٰذَآ إِلٓاَّ إِفْــك٘ ''فْتَرۭيٰهُ وَأَعَانَهُ„ عَلَيْهِ قَوْم٘ —اخَرُونَؐ فَقَدْ جَآءُو ظُلْماً وَزُوراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 5, 'وَقَالُوٓاْ أَسَـٰطِيرُ ۴لاَوَّلِيــنَ "كْتَتَبَهَا فَهِيَ تُمْلۭيٰ عَلَيْهِ بُكْرَةً وَأَصِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 6, 'قُلَ اَنزَلَهُ ۴ﻟ﮲ يَعْلَمُ ۴لسِّرَّ فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ إِنَّهُ„ كَانَ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 7, 'وَقَالُواْ مَالِ هَـٰذَا ۰لرَّسُولِ يَاكُــلُ ۴لطَّعَامَ وَيَمْشِى فِى ۱لاَسْوَاقِ لَوْلآَ ٱُنزۣلَ إِلَيْهِ مَلَــكٌ فَيَكُونَ مَعَهُ„ نَذِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 8, 'اَوْ يُلْقۭيٰٓ إِلَيْهِ كَنز٘ اَوْ تَكُونُ لَهُ„ جَنَّةٌ يَاكُلُ مِنْهَاؐ وَقَالَ ۰لظَّـٰلِمُونَ إِن تَتَّبِعُونَ إِلاَّ رَجُلًا مَّسْحُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 9, '۶نظُرْ كَيْفَ ضَرَبُواْ لَــكَ ۰لاَمْثَـٰلَ فَضَلُّواْ فَلاَ يَسْتَطِيعُونَ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 10, 'تَبَـٰرَكككَ ۰ﻟـذِىٓ إِن شَآءَ جَعَــلَ لَكَ خَيْراً مِّــن ذَ؛لِكَ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ وَيَجْعَل لَّكَ 68 قُصُوراٚؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 11, 'بَــلْ كَذَّبُواْ بِالسَّاعَةِؐ وَأَعْتَدْنَا لِمَــن كَذَّبَ بِالسَّاعَةِ سَعِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 12, 'اِذَا رَأَتْهُم مِّــن مَّكَانٙ بَعِيدٍ سَمِعُواْ لَهَا تَغَيُّظاً وَزَفِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 13, 'وَإِذَآ ٱُلْقُواْ مِنْهَا مَكَاناً ضَيِّقاً مُّقَرَّنِينَ دَعَوْاْ هُنَالِــكَ ثُبُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 14, 'لاَّ تَدْعُواْ ۴لْيَوْمَ ثُبُوراً وَ؛حِداً وَادْعُواْ ثُبُوراً كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 15, 'قُلَ اَذَ؛لِــكَ خَيْر٘ اَمْ جَنَّةُ ۴لْخُلْدِ ۱لتِى وُعِدَ ۰لْمُتَّقُونَؐ كَانَتْ لَهُمْ جَزَآءً وَمَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 16, 'لَّهُمْ فِيهَا مَا يَشَآءُونَ خَـٰلِدِيــنَؐ كَانَ عَلَيٰ رَبِّــكَ وَعْداً مَّسْـُٔولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 17, 'وَيَوْمَ نَحْشُرُهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ۱للَّهِ فَيَقُولُ ءَآنتُمُ; أَضْلَلْتُمْ عِبَادِى هَـٰٓؤُلآَءِ اَ۬مْ هُمْ ضَلُّواْ ۴لسَّبِيــلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 18, 'قَالُواْ سُبْحَـٰنَــكَ مَا كَانَ يَنۢبَغِى لَنَآ أَن نَّتَّخِذَ مِن دُونِــكَ مِنَ اَوْلِيَآءَؐ وَچَكِــن مَّتَّعْتَهُمْ وَءَابَآءَهُمْ حَتَّــيٰ نَسُواْ ۴لذِّكْرَ وَكَانُواْ قَوْماَۢ بُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 19, 'فَقَدْ كَذَّبُوكُم بِمَا تَقُولُونَ فَمَا يَسْتَطِيعُونَ صَرْفاً وَلاَ نَصْراًؐ وَمَـنْ يَّظْلِم مِّنكُمْ نُذِقْهُ عَذَاباً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 20, 'وَمَآ أَرْسَلْنَا قَبْلَــكَ مِــنَ ۰لْمُرْسَلِينَ إِلٓاَّ إِنَّهُمْ لَيَاكُلُونَ ۰لطَّعَامَ وَيَمْشُونَ فِى ۱لاَسْوَاقِؐ وَجَعَلْنَا بَعْضَكُمْ لِبَعْضٍ 69 فِتْنَةٗؐ اَتَصْبِرُونَؐ وَكَانَ رَبُّــكَ بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 21, '¤ وَقَالَ ۰لذِينَ لاَ يَرْجُونَ لِقَآءَنَا لَوْلآَ ٱُنزۣلَ عَلَيْنَا ۰لْمَلَئِكَةُ أَوْ نَرۭيٰ رَبَّنَاؐ لَقَدِ ''سْتَكْبَرُواْ فِىٓ أَنفُسِهِمْ وَعَتَوْ عُتُوّاً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 22, 'يَوْمَ يَرَوْنَ ۰لْمَلَئِكَةَ لاَ بُشْرۭيٰ يَوْمَئِذٍ ڤِّڤْمُجْرۣمِينَؐ وَيَقُولُونَ حِجْراًؐ مَّحْجُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 23, 'وَقَدِمْنَآ إِلَــيٰ مَا عَمِلُواْ مِــنْ عَمَــلٍ فَجَعَلْنَـٰهُ هَبَآءً مَّنثُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 24, 'اَصْحَـٰبُ ۴لْجَنَّةِ يَوْمَئِذٖ خَيْرٌ مُّسْتَقَرّاً وَأَحْسَــنُ مَقِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 25, 'وَيَوْمَ تَشَّقَّقُ ۴لسَّمَآءُ بِالْغَمَـٰمِ وَنُزّۣلَ ۰لْمَلَئِكَةُ تَنزۣيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 26, '۱لْمُلْــكُ يَوْمَئِذٖ ۱لْحَقُّ لِلرَّحْمَـٰنِؐ وَكَانَ يَوْماٗ عَلَــي ۰لْكۭـٰفِـرۣينَ عَسِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 27, 'وَيَوْمَ يَعَــضُّ ۴لظَّالِمُ عَلَيٰ يَدَيْهِ يَقُولُ يَـٰلَيْتَنِى ''تَّخَذتُّ مَعَ ۰لرَّسُولِ سَبِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 28, 'يَـٰوَيْلَتۭـيٰ لَيْتَنِى لَمَ اَتَّخِذْ فُچَناٗ خَلِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 29, 'لَّقَدَ اَضَلَّنِى عَـنِ ۱لذِّكْرۣ بَعْدَ إِذْ جَآءَنِىؐ وَكَانَ ۰لشَّيْطَـٰنُ لِلِانسَـٰــنۣ خَذُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 30, 'وَقَالَ ۰لرَّسُولُ يَـٰرَبِّ إِنَّ قَوْمِــيَ "تَّخَذُواْ هَـٰذَا ۰لْقُرْءَانَ مَهْجُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 31, 'وَكَذَ؛لِكَ جَعَلْنَا لِكُلِّ نَبِىٓءٖ عَدُوّاً مِّــنَ ۰ڤْمُجْرۣمِينَؐ وَكَفۭيٰ بِرَبِّــكَ هَادِياً وَنَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 32, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ لَوْلاَ نُزّۣلَ عَلَيْهِ ۱لْقُرْءَانُ جُمْلَةً وَ؛حِدَةًؐ 70 كَذَ؛لِــكَ لِنُثَبِّــتَ بِهِ” فُؤَادَكَؐ وَرَتَّلْنَـٰهُ تَرْتِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 33, 'وَلاَ يَاتُونَــكَ بِمَثَــل۫ اِلاَّ جِيؔنَـٰــكَ بِالْحَقِّ وَأَحْسَنَ تَفْسِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 34, '۱لذِينَ يُحْشَرُونَ عَلَيٰ وُجُوهِهِمُ; إِلَــيٰ جَهَنَّمَ ٱُوْلَئِــكَ شَرٌّ مَّكَاناً وَأَضَلُّ سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 35, 'وَلَقَدَ —اتَيْنَا مُوسَــي ۰لْكِتَـٰــبَ وَجَعَلْنَا مَعَهُ; أَخَاهُ هَـٰرُونَ وَزۣيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 36, 'فَقُلْنَا "ذْهَبَآ إِلَــي ۰لْقَوْمِ ۱لذِينَ كَذَّبُواْ بِـَٔايَـٰتِنَاؐ فَدَمَّرْنَـٰهُمْ تَدْمِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 37, 'وَقَوْمَ نُوحٍ لَّمَّا كَذَّبُواْ ۴لرُّسُــلَ أَغْرَقْنَـٰهُمْ وَجَعَلْنَـٰهُمْ لِلنَّاسسسِ ءَايَةًؐ وَأَعْتَدْنَا لِلظَّـٰلِمِيــنَ عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 38, 'وَعَاداً وَثَمُوداً وَأَصْحَـٰــبَ ۰لرَّسِّ وَقُرُوناَۢ بَيْــنَ ذَ؛لِــكَ كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 39, 'وَكُلًاّ ضَرَبْنَا لَهُ ۴لاَمْثَـٰلَؐ وَكُلًاّ تَبَّرْنَا تَتْبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 40, 'وَلَقَدَ اَتَوْاْ عَلَــي ۰لْقَرْيَةِ ۱لتِىٓ ٱُمْطِرَتْ مَطَرَ ۰لسَّوْءِؐ اَ۬فَلَمْ يَكُونُواْ يَرَوْنَهَاؐ بَــلْ كَانُواْ لاَ يَرْجُونَ نُشُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 41, 'وَإِذَا رَأَوْكككَ إِنْ يَّتَّخِذُونَــكَ إِلاَّ هُزُؤاٗؐ اَهَـٰذَا ۰ﻟ﮲ بَعَــثَ ۰للَّهُ رَسُولٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 42, 'اِن كَادَ لَيُضِلُّنَا عَنَ —الِهَتِنَا لَوْلآَ أَن صَبَرْنَا عَلَيْهَاؐ وَسَوْفَ يَعْلَمُونَ حِينَ يَرَوْنَ ۰لْعَذَابَ مَــنَ اَضَلُّ سَبِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 43, 'اَرَ×يْتَ مَنِ ''تَّخَذَ إِچَهَهُ„ 71 هَوۭيٰهُ أَفَأَنتَ تَكُونُ عَلَيْهِ وَكِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 44, 'اَمْ تَحْسِبُ أَنَّ أَكْثَرَهُمْ يَسْمَعُونَ أَوْ يَعْقِلُونَؐ إِنْ هُمُ; إِلاَّ كَالاَنْعَـٰمِ بَلْ هُمُ; أَضَلُّ سَبِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 45, '© اَلَمْ تَرَ إِلَيٰ رَبِّــكَ كَيْفَ مَدَّ ۰لظِّلَّؐ وَلَوْ شَآءَ لَجَعَلَهُ„ سَاكِناًؐ ثُمَّ جَعَلْنَا ۰لشَّمْــسَ عَلَيْهِ دَلِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 46, 'ثُمَّ قَبَضْنَـٰهُ إِلَيْنَا قَبْضاً يَسِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 47, 'وَهُوَ ۰ﻟ﮲ جَعَلَ لَكُمُ ۴ليْـلَ لِبَاساً وَالنَّوْمَ سُبَاتاً وَجَعَــلَ ۰لنَّهَارَ نُشُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 48, 'وَهُوَ ۰لـذِىٓ أَرْسَلَ ۰لرّۣيَـٰحَ نُشُراَۢ بَيْـنَ ¢ رَحْمَتِهِؐ” وَأَنزَلْنَا مِنَ ۰لسَّمَآءِ مَآءً طَهُوراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 49, 'ڤِّنُحْيـيِيَ بِهِ” بَلْدَةً مَّيْتاً وَنُسْقِيَهُ„ مِمَّا خَلَقْنَآ أَنْعَـٰماً وَأَنَاسِــيَّ كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 50, 'وَلَقَدْ صَرَّفْنَـٰهُ بَيْنَهُمْ لِيَذَّكَّرُواْ فَأَبۭــيٰٓ أَكْثَرُ ۴لنَّاسسسِ إِلاَّ كُفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 51, 'وَلَوْ شِيؔنَا لَبَعَثْنَا فِى كُلِّ قَرْيَةٍ نَّذِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 52, 'فَلاَ تُطِعِ ۱لْكۭـٰفِرۣينَؐ وَجَـٰهِدْهُم بِهِ” جِهَاداً كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 53, 'وَهُوَ ۰ﻟ﮲ مَرَجَ ۰ڤْبَحْرَيْــنۣ هَـٰذَا عَذْبٌ فُرَاتٌ وَهَـٰذَا مِلْح٘ ۷جَاجٌؐ وَجَعَلَ بَيْنَهُمَا بَرْزَخاً وَحِجْراً مَّحْجُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 54, 'وَهُوَ ۰ﻟ﮲ خَلَقَ مِنَ ۰لْمَآءِ بَشَراً فَجَعَلَهُ„ نَسَباً وَصِهْراًؐ وَكَانَ رَبُّكَ قَدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 55, 'وَيَعْبُدُونَ 72 مِن دُونِ ۱للَّهِ مَا لاَ يَنفَعُهُمْ وَلاَ يَضُرُّهُمْؐ وَكَانننَ ۰لْكَافِرُ عَلَيٰ رَبِّهِ” ظَهِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 56, 'وَمَآ أَرْسَلْنَـٰــكَ إِلاَّ مُبَشِّراً وَنَذِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 57, 'قُــلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنَ اَجْر۫ اِلاَّ مَــن شَآءَ انْ يَّتَّخِذَ إِلَيٰ رَبِّهِ” سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 58, 'وَتَوَكَّــلْ عَلَي ۰لْحَيِّ ۱ﻟ﮲ لاَ يَمُوتُؐ وَسَبِّحْ بِحَمْدِهِؐ” وَكَفۭيٰ بِهِ” بِذُنُوبِ عِبَادِهِ” خَبِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 59, '۱ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍ ثُمَّ "سْتَوۭيٰ عَلَــي ۰لْعَرْشِؐ ۱لرَّحْمَـٰنُؐ فَسْـَٔلْ بِهِ” خَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 60, 'وَإِذَا قِيــلَ لَهُمُ ۶سْجُدُواْ لِلرَّحْمَـٰــنۣ قَالُواْ وَمَا ۰لرَّحْمَـٰــنُؐ أَنَسْجُدُ لِمَا تَامُرُنَا وَزَادَهُمْ نُفُوراًؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 61, 'تَبَـٰرَكَ ۰ﻟ﮲ جَعَلَ فِى ۱لسَّمَآءِ بُرُوجاً وَجَعَـلَ فِيهَا سِرَ؛جاً وَقَمَراً مُّنِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 62, 'وَهُوَ ۰ﻟ﮲ جَعَلَ ۰ليْلَ وَالنَّهَارَ خِلْفَةً لِّمَنَ اَرَادَ أَنْ يَّذَّكَّرَ أَوَ اَرَادَ شُكُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 63, 'وَعِبَادُ ۴لرَّحْمَـٰنِ ۱لذِينَ يَمْشُونَ عَلَــي ۰لاَرْضِ هَوْناً وَإِذَا خَاطَبَهُمُ ۴لْجَـٰهِلُونَ قَالُواْ سَچَماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 64, 'وَالذِينَ يَبِيتُونَ لِرَبِّهِمْ سُجَّداً وَقِيَـٰماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 65, 'وَالذِينَ يَقُولُونَ رَبَّنَا "صْرۣفْ عَنَّا عَذَابَ جَهَنَّمَ إِنَّ عَذَابَهَا كَانَ غَرَاماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 66, 'اِنَّهَا 7 سَآءَتْ مُسْتَقَرّاً وَمُقَاماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 67, 'وَالذِينَ إِذَآ أَنفَقُواْ لَمْ يُسْرۣفُواْ وَلَمْ يُقْتِرُواْ وَكَانَ بَيْــنَ ذَ؛لِــكَ قَوَاماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 68, 'وَالذِيــنَ لاَ يَدْعُونَ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ وَلاَ يَقْتُلُونَ ۰لنَّفْسَ ۰لتِى حَرَّمَ ۰للَّهُ إِلاَّ بِالْحَقِّ وَلاَ يَزْنُونَؐ وَمَنْ يَّفْعَلْ ذَ؛لِكَ يَلْقَ أَثَاماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 69, 'يُضَـٰعَفْ لَهُ ۴لْعَذَابُ يَوْمَ ۰لْقِيَـٰمَةِ وَيَخْلُدْ فِيهِ مُهَاناٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 70, 'اِلاَّ مَن تَابَ وَءَامَنَ وَعَمِــلَ عَمَلًا صَـٰڤِحاً فَٱُوْلَئِكَ يُبَدِّلُ ۴للَّهُ سَيِّـَٔاتِهِمْ حَسَنَـٰــتٍؐ وَكَانننَ ۰للَّهُ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 71, 'وَمَــن تَابَ وَعَمِــلَ صَـٰڤِحاً فَإِنَّهُ„ يَتُوبُ إِلَــي ۰للَّهِ مَتَاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 72, 'وَالذِينَ لاَ يَشْهَدُونَ ۰لزُّورَ وَإِذَا مَرُّواْ بِاللَّغْوۣ مَرُّواْ كِرَاماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 73, 'وَالذِينَ إِذَا ذُكِّرُواْ بِـَٔايَـٰتِ رَبِّهِمْ لَمْ يَخِرُّواْ عَلَيْهَا صُمّاً وَعُمْيَاناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 74, 'وَالذِينَ يَقُولُونَ رَبَّنَا هَبْ لَنَا مِنَ اَزْوَ؛جِنَا وَذُرّۣيَّـٰتِنَا قُرَّةَ أَعْيُنٍ وَاجْعَلْنَا لِلْمُتَّقِينَ إِمَاماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 75, '۷وْلَئِكَ يُجْزَوْنَ ۰لْغُرْفَةَ بِمَا صَبَرُواْ وَيُلَقَّوْنَ فِيهَا تَحِيَّةً وَسَچَماٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 76, 'خَـٰلِدِينَ فِيهَاؐ حَسُنَتْ مُسْتَقَرّاً وَمُقَاماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (25, 77, 'قُلْ مَا يَعْبَؤُاْ بِكُمْ رَبِّى لَوْلاَ دُعَآؤُكُمْؐ فَقَدْ كَذَّبْتُمْ فَسَوْفَ يَكُونُ لِزَاماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ طَسِٓم؋ّٓؐ تِلْكَ ءَايَـٰتُ ۴لْكِتَـٰبِ ۱لْمُبِيـنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 2, 'لَعَلَّــكَ بَـٰخِعٌ نَّفْسَــكَ أَلاَّ يَكُونُواْ مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 3, 'إِن نَّشَأْ نُنَزّۣلْ عَلَيْهِم مِّــنَ ۰لسَّمَآءِ -ايَةً فَظَلَّــتَ اَعْنَـٰقُهُمْ لَهَا خَـٰضِعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 4, 'وَمَا يَاتِيهِم مِّــن ذِكْرٍ مِّــنَ ۰لرَّحْمَـٰــنۣ مُحْدَثٖ اِلاَّ كَانُواْ عَنْهُ مُعْرۣضِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 5, 'فَقَدْ كَذَّبُواْ فَسَيَاتِيهِمُ; أَنۢبَـٰٓؤُاْ مَا كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 6, 'أَوَلَمْ يَرَوۣاْ اِلَــي ۰لاَرْضِ كَمَ اَنۢبَتْنَا فِيهَا مِــن كُلِّ زَوْجٍ كَرۣيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 7, 'اِنَّ فِى ذَ؛لِكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 8, 'وَإِنَّ رَبَّكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 9, 'وَإِذْ نَادۭيٰ رَبُّــكَ مُوسۭيٰٓ أَنِ ''يــتِ ۱لْقَوْمَ ۰لظَّـٰلِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 10, 'قَوْمَ فِرْعَوْنَؐ أَلاَ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 11, 'قَالَ رَبِّ إِنِّيَ أَخَافُ أَنْ يُّكَذِّبُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 12, 'وَيَضِيقُ صَدْرۣى وَلاَ يَنطَلِقُ لِسَانِى فَأَرْسِلِ اِلَيٰ هَـٰرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 13, 'وَلَهُمْ عَلَــيَّ ذَنۢبٌ فَأَخَافُ أَنْ يَّقْتُلُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 14, 'قَالَ كَلؐاَّ فَاذْهَبَا بِـَٔايَـٰتِنَآ إِنَّا مَعَكُم 75 مُّسْتَمِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 15, 'فَاتِيَا فِرْعَوْنَ فَقُولآَ إِنَّا رَسُولُ رَبِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 16, 'أَنَ اَرْسِــلْ مَعَنَا بَنِىٓ إِسْرَآءِيــلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 17, 'قَالَ أَلَمْ نُرَبِّكَ فِينَا وَلِيداً وَلَبِثْتَ فِينَا مِــنْ عُمُرۣكككَ سِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 18, 'وَفَعَلْتَ فَعْلَتَكَ ۰لتِى فَعَلْتَ وَأَنتَ مِــنَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 19, 'قَالَ فَعَلْتُهَآ إِذاً وَأَنَا مِــنَ ۰لضَّآلِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 20, 'فَفَرَرْتُ مِنكُمْ لَمَّا خِفْتُكُمْ فَوَهَبَ لِى رَبِّى حُكْماً وَجَعَلَنِى مِــنَ ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 21, 'وَتِلْــكَ نِعْمَةٌ تَمُنُّهَا عَلَيَّ أَنْ عَبَّدتَّ بَنِىٓ إِسْرَآءِيــلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 22, 'قَالَ فِرْعَوْنُ وَمَا رَبُّ ۴لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 23, 'قَالَ رَبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَآ إِن كُنتُم مُّوقِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 24, 'قَالَ لِمَنْ حَوْلَهُ; أَلاَ تَسْتَمِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 25, 'قَالَ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 26, 'قَالَ إِنَّ رَسُولَكُمُ ۴ﻟـذِىٓ ٱُرْسِلَ إِلَيْكُمْ ڤَمَجْنُونٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 27, 'قَالَ رَبُّ ۴لْمَشْرۣقِ وَالْمَغْرۣبِ وَمَا بَيْنَهُمَآ إِن كُنتُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 28, 'قَالَ لَـئِنِ ''تَّخَذتَّ إِچَهاٗ غَيْرۣى لَأَجْعَلَنَّــكَ مِنَ ۰ڤْمَسْجُونِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 29, 'قَالَ أَوَلَوْ جِيؔتُــكَ بِشَىْءٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 30, 'قَالَ فَاتِ بِهِ“ إِن كُنتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 31, 'فَأَلْقۭــيٰ عَصَاهُ فَإِذَا هِــيَ ثُعْبَانٌ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 32, 'وَنَزَعَ يَدَهُ„ فَإِذَا 76 هِيَ بَيْضَآءُ لِلنَّـٰظِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 33, 'قَالَ لِلْمَـلإَِ حَوْلَهُ; إِنننَّ هَـٰذَا ڤَسَـٰحِر٘ عَلِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 34, 'يُرۣيدُ أَنْ يُّخْرۣجَكُم مِّنَ اَرْضِكُم بِسِحْرۣهِ” فَمَاذَا تَامُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 35, 'قَالُوٓاْ أَرْجِهِ” وَأَخَاهُ وَابْعَــثْ فِى ۱لْمَدَآئِــنۣ حَـٰشِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 36, 'يَاتُوكككَ بِكُلِّ سَحّۭار۫ عَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 37, 'فَجُمِعَ ۰ڤسَّحَرَةُ لِمِيقَـٰــتِ يَوْمٍ مَّعْلُومٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 38, 'وَقِيـلَ لِلنَّاسسسِ هَلَ اَنتُم مُّجْتَمِعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 39, 'لَعَلَّنَا نَتَّبِعُ ۴ڤسَّحَرَةَ إِن كَانُواْ هُمُ ۴لْغَـٰلِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 40, 'فَلَمَّا جَآءَ ۰ڤسَّحَرَةُ قَالُواْ لِفِرْعَوْنَ أَئــنَّ لَنَا لَأَجْراٗ اِن كُنَّا نَحْــنُ ۴لْغَـٰلِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 41, 'قَالَ نَعَمْ وَإِنَّكُمُ; إِذاً لَّمِــنَ ۰لْمُقَرَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 42, 'قَالَ لَهُم مُّوسۭــيٰٓ أَلْقُواْ مَآ أَنتُم مُّلْقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 43, 'فَأَلْقَوْاْ حِبَالَهُمْ وَعِصِيَّهُمْ وَقَالُواْ بِعِزَّةِ فِرْعَوْنَ إِنَّا ڤَنَحْــنُ ۴لْغَـٰلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 44, 'فَأَلْقۭيٰ مُوسۭــيٰ عَصَاهُ فَإِذَا هِــيَ تَلَقَّفُ مَا يَافِكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 45, 'فَٱُلْقِــيَ ۰ڤسَّحَرَةُ سَـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 46, 'قَالُوٓاْ ءَامَنَّا بِرَبِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 47, 'رَبِّ مُوسۭيٰ وَهَـٰرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 48, 'قَالَ ءَا۬؛مَنتُمْ لَهُ„ قَبْـلَ أَنَ —اذَنَ لَكُمُ; إِنَّهُ„ لَكَبِيرُكُمُ ۴ﻟ﮲ عَلَّمَكُمُ ۴ڤسِّحْرَؐ فَلَسَوْفَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 49, 'لُءَقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِچَفٍ وَلُءَصَلِّبَنَّكُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 50, '77 © قَالُواْ لاَ ضَيْرَؐ إِنَّـآ إِلَيٰ رَبِّنَا مُنقَلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 51, 'إِنَّا نَطْمَعُ أَنْ يَّغْفِرَ لَنَا رَبُّنَا خَطَـٰيۭـٰنَآ أَن كُنَّآ أَوَّلَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 52, 'وَأَوْحَيْنَآ إِلَيٰ مُوسۭيٰٓ أَنِ ''سْرۣ بِعِبَادِيَ إِنَّكُم مُّتَّبَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 53, 'فَأَرْسَلَ فِرْعَوْنُ فِى ۱لْمَدَآئِــنۣ حَـٰشِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 54, 'إِنَّ هَـٰٓؤُلآَءِ لَشِرْذِمَةٌ قَلِيلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 55, 'وَإِنَّهُمْ لَنَــا لَغَآئِظُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 56, 'وَإِنَّا لَجَمِيــع٘ حَذِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 57, 'فَأَخْرَجْنَـٰهُم مِّن جَنَّـٰــتٍ وَعُيُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 58, 'وَكُنُوزٍ وَمَقَامٍ كَرۣيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 59, 'كَذَ؛لِــكَؐ وَأَوْرَثْنَـٰهَا بَنِىٓ إِسْرَآءِيــلَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 60, 'فَأَتْبَعُوهُم مُّشْرۣقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 61, 'فَلَمَّا تَرَ×ءَا ۰لْجَمْعَـٰــنۣ قَالَ أَصْحَـٰــبُ مُوسۭيٰٓ إِنَّا لَمُدْرَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 62, 'قَالَ كَلٓؐاَّ إِنَّ مَعِى رَبِّى سَيَهْدِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 63, 'فَأَوْحَيْنَآ إِلَيٰ مُوسۭيٰٓ أَنِ ''ضْرۣب بِّعَصَاكَ ۰ڤْبَحْرَ فَانفَلَـقَ فَكَانَ كُلُّ فِرْقٍ كَالطَّوْدِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 64, 'وَأَزْلَفْنَا ثَمَّ ۰لاَخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 65, 'وَأَنجَيْنَا مُوسۭيٰ وَمَــن مَّعَهُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 66, 'ثُمَّ أَغْرَقْنَا ۰لاَخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 67, 'إِنَّ فِى ذَ؛لِكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 68, 'وَإِنَّ رَبَّــكَ لَهُوَ ۰لْعَزۣيزُ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 69, 'وَاتْــلُ عَلَيْهِمْ نَبَأَ اۭبْرَ؛هِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 70, 'إِذْ قَالَ لَأِبِيهِ وَقَوْمِهِ” 78 مَا تَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 71, 'قَالُواْ نَعْبُدُ أَصْنَاماً فَنَظَــلُّ لَهَا عَـٰكِفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 72, 'قَالَ هَلْ يَسْمَعُونَكُمُ; إِذْ تَدْعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 73, 'أَوْ يَنفَعُونَكُمُ; أَوْ يَضُرُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 74, 'قَالُواْ بَلْ وَجَدْنَآ ءَابَآءَنَا كَذَ؛لِــكَ يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 75, 'قَالَ أَفَرَ×يْتُم مَّا كُنتُمْ تَعْبُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 76, 'أَنتُمْ وَءَابَآؤُكُمُ ۴لاَقْدَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 77, 'فَإِنَّهُمْ عَدُوٌّ لِّيَؐ إِلاَّ رَبَّ ۰لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 78, '۰ﻟ﮲ خَلَقَنِى فَهُوَ يَهْدِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 79, 'وَاﻟ﮲ هُوَ يُطْعِمُنِى وَيَسْقِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 80, 'وَإِذَا مَرۣضْتُ فَهُوَ يَشْفِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 81, 'وَاﻟ﮲ يُمِيتُنِى ثُمَّ يُحْيِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 82, 'وَاﻟـذِىٓ أَطْمَعُ أَنْ يَّغْفِرَ لِى خَطِيٓــَٔـتِى يَوْمَ ۰لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 83, 'رَبِّ هَــبْ لِى حُكْماً وَأَلْحِقْنِى بِاڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 84, 'وَاجْعَل لِّى لِسَانَ صِدْقٍ فِى ۱لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 85, 'وَاجْعَلْنِى مِنْ وَّرَثَةِ جَنَّةِ ۱لنَّعِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 86, 'وَاغْفِرْ لَأِبِيَ إِنَّهُ„ كَانَ مِــنَ ۰لضَّآلِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 87, 'وَلاَ تُخْزۣنِى يَوْمَ يُبْعَثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 88, 'يَوْمَ لاَ يَنفَعُ مَالٌ وَلاَ بَنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 89, 'إِلاَّ مَنَ اَتَــي ۰للَّهَ بِقَلْبٍ سَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 90, 'وَٱُزْلِفَتِ ۱لْجَنَّةُ لِلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 91, 'وَبُرّۣزَتِ ۱لْجَحِيمُ لِلْغَاوۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 92, 'وَقِيــلَ لَهُمُ; أَيْــنَ مَا كُنتُمْ تَعْبُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 93, 'مِن دُونِ ۱للَّهِؐ هَلْ يَنصُرُونَكُمُ; أَوْ يَنتَصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 94, '79 فَكُبْكِبُواْ فِيهَا هُمْ وَالْغَاوُﹼنَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 95, 'وَجُنُودُ إِبْلِيــسَ أَجْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 96, 'قَالُواْ وَهُمْ فِيهَا يَخْتَصِمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 97, 'تَاللَّهِ إِن كُنَّا لَفِى ضَچَلٍ مُّبِـينٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 98, 'اِذْ نُسَوّۣيكُم بِرَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 99, 'وَمَآ أَضَلَّنَآ إِلاَّ ۰ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 100, 'فَمَا لَنَا مِــن شَـٰفِعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 101, 'وَلاَ صَدِيقٖ حَمِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 102, 'فَلَوَ اَنَّ لَنَا كَرَّةً فَنَكُونَ مِــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 103, 'إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 104, 'وَإِنَّ رَبَّــكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 105, 'كَذَّبَــتْ قَوْمُ نُوحٖ ۱لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 106, 'إِذْ قَالَ لَهُمُ; أَخُوهُمْ نُوح٘ اَلاَ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 107, 'إِنِّى لَكُمْ رَسُول٘ اَمِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 108, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 109, 'وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنَ اَجْرٖؐ اِنَ اَجْرۣيَ إِلاَّ عَلَيٰ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 110, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 111, '¤ قَالُوٓاْ أَنُومِــنُ لَكَ وَاتَّبَعَــكَ ۰لاَرْذَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 112, 'قَالَ وَمَا عِلْمِى بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 113, 'إِنْ حِسَابُهُمُ; إِلاَّ عَلَيٰ رَبِّى لَوْ تَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 114, 'وَمَآ أَنَا بِطَارۣدِ ۱لْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 115, 'إِنَ اَنَا إِلاَّ نَذِيرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 116, 'قَالُواْ لَئِن لَّمْ تَنتَهِ يَـٰنُوحُ لَتَكُونَنَّ مِــنَ ۰لْمَرْجُومِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 117, 'قَالَ رَبِّ إِنَّ قَوْمِى كَذَّبُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 118, 'فَافْتَحْ 80 بَيْنِى وَبَيْنَهُمْ فَتْحاً وَنَجِّنِى وَمَن مَّعِيَ مِـــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 119, 'فَأَنجَيْنَـٰهُ وَمَــن مَّعَهُ„ فِى ۱لْفُلْــكِ ۱ڤْمَشْحُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 120, 'ثُمَّ أَغْرَقْنَا بَعْدُ ۴لْبَاقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 121, 'إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 122, 'وَإِنَّ رَبَّــكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 123, 'كَذَّبَتْ عَاد٘ ۱لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 124, 'إِذْ قَالَ لَهُمُ; أَخُوهُمْ هُود٘ اَلاَ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 125, 'إِنِّى لَكُمْ رَسُول٘ اَمِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 126, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 127, 'وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنَ اَجْرٖؐ اِنَ اَجْرۣيَ إِلاَّ عَلَيٰ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 128, 'أَتَبْنُونَ بِكُلِّ رۣيعٖ —ايَةً تَعْبَثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 129, 'وَتَتَّخِذُونَ مَصَانِعَ لَعَلَّكُمْ تَخْلُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 130, 'وَإِذَا بَطَشْتُم بَطَشْتُمْ جَبّۭارۣيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 131, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 132, 'وَاتَّقُواْ ۴ﻟـذِىٓ أَمَدَّكُم بِمَا تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 133, 'أَمَدَّكُم بِأَنْعَـٰمٍ وَبَنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 134, 'وَجَنَّـٰــتٍ وَعُيُونٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 135, 'اِنِّــيَ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 136, 'قَالُواْ سَوَآء٘ عَلَيْنَآ أَوَعَظْــتَ أَمْ لَمْ تَكُن مِّنَ ۰لْوَ؛عِظِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 137, 'إِنْ هَـٰذَآ إِلاَّ خُلُــقُ ۴لاَوَّلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 138, 'وَمَا نَحْنُ بِمُعَذَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 139, 'فَكَذَّبُوهُ فَأَهْلَكْنَـٰهُمُؐ; إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةًؐ 81 وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 140, 'وَإِنَّ رَبَّكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 141, 'كَذَّبَتْ ثَمُودُ ۴لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 142, 'إِذْ قَالَ لَهُمُ; أَخُوهُمْ صَـٰلِح٘ اَلاَ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 143, 'إِنِّى لَكُمْ رَسُول٘ اَمِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 144, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 145, 'وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِــنَ اَجْرٖؐ اِنَ اَجْرۣيَ إِلاَّ عَلَيٰ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 146, 'أَتُتْرَكُونَ فِى مَا هَـٰهُنَآ ءَامِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 147, 'فِى جَنَّـٰــتٍ وَعُيُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 148, 'وَزُرُوعٍ وَنَخْلٍ طَلْعُهَا هَضِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 149, 'وَتَنْحِتُونَ مِنَ ۰لْجِبَالِ بُيُوتاً فَرۣهِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 150, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 151, 'وَلاَ تُطِيعُوٓاْ أَمْرَ ۰لْمُسْرۣفِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 152, '۰لذِينَ يُفْسِدُونَ فِى ۱لاَرْضِ وَلاَ يُصْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 153, 'قَالُوٓاْ إِنَّمَآ أَنــتَ مِــنَ ۰ڤْمُسَحَّرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 154, 'مَآ أَنتَ إِلاَّ بَشَرٌ مِّثْلُنَا فَاتِ بِـَٔايَةٖ اِن كُنتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 155, 'قَــالَ هَـٰذِهِ” نَاقَةٌ لَّهَا شِرْبٌؐ وَلَكُمْ شِرْبُ يَوْمٍ مَّعْلُومٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 156, 'وَلاَ تَمَسُّوهَا بِسُوٓءٍ فَيَاخُذَكُمْ عَذَابُ يَوْمٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 157, 'فَعَقَرُوهَا فَأَصْبَحُواْ نَـٰدِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 158, 'فَأَخَذَهُمُ ۴لْعَذَابُؐ إِنَّ فِى ذَ؛لِكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 159, '82 وَإِنَّ رَبَّكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 160, 'كَذَّبَتْ قَوْمُ لُوطٖ ۱لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 161, 'إِذْ قَالَ لَهُمُ; أَخُوهُمْ لُوط٘ اَلاَ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 162, 'إِنِّى لَكُمْ رَسُول٘ اَمِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 163, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 164, 'وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنَ اَجْرٖؐ اِنَ اَجْرۣيَ إِلاَّ عَلَيٰ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 165, 'أَتَاتُونَ ۰لذُّكْرَانَ مِــنَ ۰لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 166, 'وَتَذَرُونَ مَا خَلَــقَ لَكُمْ رَبُّكُم مِّنَ اَزْوَ؛جِكُمؐ بَــلَ اَنتُمْ قَوْم٘ عَادُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 167, 'قَالُواْ لَئِن لَّمْ تَنتَهِ يَـٰلُوطُ لَتَكُونَنَّ مِنَ ۰ڤْمُخْرَجِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 168, 'قَالَ إِنِّى لِعَمَلِكُم مِّنَ ۰لْقَالِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 169, 'رَبِّ نَجِّنِى وَأَهْلِى مِمَّا يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 170, 'فَنَجَّيْنَـٰهُ وَأَهْلَهُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 171, 'إِلاَّ عَجُوزاً فِى ۱لْغَـٰبِـرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 172, 'ثُمَّ دَمَّرْنَا ۰لاَخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 173, 'وَأَمْطَرْنَا عَلَيْهِم مَّطَراًؐ فَسَآءَ مَطَرُ ۴لْمُنذَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 174, 'إِنَّ فِى ذَ؛لِكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 175, 'وَإِنَّ رَبَّــكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 176, 'كَذَّبَ أَصْحَـٰبُ لَيْكَةَ ۰لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 177, 'إِذْ قَالَ لَهُمْ شُعَيْب٘ اَلاَ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 178, 'إِنِّى لَكُمْ رَسُول٘ اَمِيـنٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 179, 'فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 180, 'وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنَ اَجْرٖؐ اِنَ اَجْرۣيَ إِلاَّ عَلَيٰ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 181, '8 © أَوْفُواْ ۴لْكَيْلَؐ وَلاَ تَكُونُواْ مِــنَ ۰ڤْمُخْسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 182, 'وَزۣنُواْ بِالْقُسْطَاسسسِ ۱لْمُسْتَقِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 183, 'وَلاَ تَبْخَسُواْ ۴لنَّاسسسَ أَشْيَآءَهُمْؐ وَلاَ تَعْثَوْاْ فِى ۱لاَرْضِ مُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 184, 'وَاتَّقُواْ ۴ﻟ﮲ خَلَقَكُمْ وَالْجِبِلَّةَ ۰لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 185, 'قَالُوٓاْ إِنَّمَآ أَنتَ مِــنَ ۰ڤْمُسَحَّرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 186, 'وَمَآ أَنــتَ إِلاَّ بَشَرٌ مِّثْلُنَا وَإِن نَّظُنُّــكَ لَمِــنَ ۰لْكَـٰذِبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 187, 'فَأَسْقِطْ عَلَيْنَا كِسْفاً مِّــنَ ۰لسَّمَآءِ ان كُنتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 188, 'قَالَ رَبِّــيَ أَعْلَمُ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 189, 'فَكَذَّبُوهُ فَأَخَذَهُمْ عَذَابُ يَوْمِ ۱لظُّلَّةِؐ إِنَّهُ„ كَانَ عَذَابَ يَوْمٖ عَظِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 190, 'اِنَّ فِى ذَ؛لِــكَ ءَلاَيَةًؐ وَمَا كَانَ أَكْثَرُهُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 191, 'وَإِنَّ رَبَّكَ لَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 192, 'وَإِنَّهُ„ لَتَنزۣيلُ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 193, 'نَزَلَ بِهِ ۱لرُّوحُ ۴لاَمِينُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 194, 'عَلَــيٰ قَلْبِــكَ لِتَكُونَ مِــنَ ۰لْمُنذِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 195, 'بِلِسَانٖ عَرَبِيٍّ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 196, 'وَإِنَّهُ„ لَفِى زُبُـرۣ ۱لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 197, 'أَوَلَمْ يَكُــن لَّهُمُ; ءَايَةٗ اَنْ يَّعْلَمَهُ„ عُلَمَـٰٓؤُاْ بَنِىٓ إِسْرَآءِيلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 198, 'وَلَوْ نَزَّلْنَـٰهُ عَلَيٰ بَعْضِ ۱لاَعْجَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 199, 'فَقَرَأَهُ„ عَلَيْهِم مَّا كَانُواْ بِهِ” مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 200, 'كَذَ؛لِــكَ سَلَكْنَـٰهُ فِى قُلُوبِ ۱ڤْمُجْرۣمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 201, '84 لاَ يُومِنُونَ بِهِ” حَتَّيٰ يَرَوُاْ ۴لْعَذَابَ ۰لاَلِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 202, 'فَيَاتِيَهُم بَغْتَةً وَهُمْ لاَ يَشْعُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 203, 'فَيَقُولُواْ هَلْ نَحْنُ مُنظَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 204, 'أَفَبِعَذَابِنَا يَسْتَعْجِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 205, 'أَفَرَ×يْــتَ إِن مَّتَّعْنَـٰهُمْ سِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 206, 'ثُمَّ جَآءَهُم مَّا كَانُواْ يُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 207, 'مَآ أَغْنۭــيٰ عَنْهُم مَّا كَانُواْ يُمَتَّعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 208, 'وَمَآ أَهْلَكْنَا مِن قَرْيَةٖ اِلاَّ لَهَا مُنذِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 209, 'ذِكْرۭيٰؐ وَمَا كُنَّا ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 210, 'وَمَا تَنَزَّلَــتْ بِهِ ۱لشَّيَـٰطِينُ وَمَا يَنۢبَغِى لَهُمْ وَمَا يَسْتَطِيعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 211, 'إِنَّهُمْ عَـنِ ۱لسَّمْعِ لَمَعْزُولُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 212, 'فَلاَ تَدْعُ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ فَتَكُونَ مِــنَ ۰لْمُعَذَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 213, 'وَأَنذِرْ عَشِيرَتَكَ ۰لاَقْرَبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 214, 'وَاخْفِـضْ جَنَاحَــكَ لِمَنِ ''تَّبَعَــكَ مِــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 215, 'فَإِنننْ عَصَوْكككَ فَقُـلِ اِنِّى بَرۣىٓءٌ مِّمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 216, 'فَتَوَكَّــلْ عَلَي ۰لْعَزۣيزۣ ۱لرَّحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 217, '۱ﻟ﮲ يَرۭيٰــكَ حِيــنَ تَقُومُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 218, 'وَتَقَلُّبَــكَ فِى ۱ڤسَّـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 219, 'إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 220, 'هَلُ ۷نَبِّيؖكُمْ عَلَيٰ مَن تَنَزَّلُ ۴لشَّيَـٰطِينُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 221, 'تَنَزَّلُ عَلَــيٰ كُــلّۣ أَفَّاكٖ اَثِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 222, 'يُلْقُونَ ۰لسَّمْعَ وَأَكْثَرُهُمْ كَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 223, 'وَالشُّعَرَآءُ يَتْبَعُهُمُ ۴لْغَاوُﹼنَؐ 85');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 224, 'أَلَمْ تَرَ أَنَّهُمْ فِى كُلِّ وَادٍ يَهِيمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 225, 'وَأَنَّهُمْ يَقُولُونَ مَا لاَ يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (26, 226, 'إِلاَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ وَذَكَرُواْ ۴للَّهَ كَثِيراً وَانتَصَرُواْ مِـنۢ بَعْدِ مَا ظُلِمُواْؐ وَسَيَعْلَمُ ۴لذِيــنَ ظَلَمُوٓاْ أَيَّ مُنقَلَــبٍ يَنقَلِبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ طَـسِٓؐ تِلْــكَ ءَايَـٰــتُ ۴لْقُرْءَانِ وَكِتَابٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 2, 'هُديً وَبُشْرۭيٰ لِلْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 3, '۰لذِينَ يُقِيمُونَ ۰لصَّلَوٰةَ وَيُوتُونَ ۰لزَّكَوٰةَ وَهُم بِالاَخِرَةِ هُمْ يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 4, 'إِنَّ ۰لذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ زَيَّنَّا لَهُمُ; أَعْمَـٰلَهُمْ فَهُمْ يَعْمَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 5, 'ٱُوْلَئِــكَ ۰لذِيــنَ لَهُمْ سُوٓءُ ۴لْعَذَابِ وَهُمْ فِى ۱لاَخِرَةِ هُمُ ۴لاَخْسَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 6, '¥ وَإِنَّــكَ لَتُلَقَّي ۰لْقُرْءَانَ مِن لَّدُنْ حَكِيمٖ عَلِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 7, 'اِذْ قَالَ مُوسۭيٰ لَأِهْلِهِ“ إِنِّيَ ءَانَسْتُ نَاراً سَـَٔاتِيكُم مِّنْهَا بِخَبَر۫ اَوَ —اتِيكُم بِشِهَابِ قَبَــسٍ لَّعَلَّكُمْ تَصْطَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 8, 'فَلَمَّا جَآءَهَا نُودِيَ أَنۢ بُورۣكككَ 86 مَن فِى ۱لنّۭارۣ وَمَنْ حَوْلَهَاؐ وَسُبْحَـٰــنَ ۰للَّهِ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 9, 'يَـٰمُوسۭيٰٓ إِنَّهُ; أَنَا ۰للَّهُ ۴لْعَزۣيزُ ۴لْحَكِيمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 10, 'وَأَلْقِ عَصَاكككَؐ فَلَمَّا رۭءۭاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّ وَلّۭــيٰ مُدْبِراً وَلَمْ يُعَقِّبْؐ يَـٰمُوسۭــيٰ لاَ تَخَـفِؐ اِنِّى لاَ يَخَافُ لَدَيَّ ۰لْمُرْسَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 11, 'إِلاَّ مَن ظَلَمَ ثُمَّ بَدَّلَ حُسْناَۢ بَعْدَ سُوٓءٍ فَإِنِّى غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 12, 'وَأَدْخِلْ يَدَكككَ فِى جَيْبِــكَ تَخْرُجْ بَيْضَآءَ مِــنْ غَيْرۣ سُوٓءٍؐ فِى تِسْعِ ءَايَـٰتٖ اِلَيٰ فِرْعَوْنَ وَقَوْمِهِؐ“ إِنَّهُمْ كَانُواْ قَوْماً فَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 13, 'فَلَمَّا جَآءَتْهُمُ; ءَايَـٰتُنَا مُبْصِرَةً قَالُواْ هَـٰذَا سِحْـرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 14, 'وَجَحَدُواْ بِهَا وَاسْتَيْقَنَتْهَآ أَنفُسُهُمْ ظُلْماً وَعُلُوّاًؐ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 15, 'وَلَقَدَ —اتَيْنَا دَاوُﹼدَ وَسُلَيْمَـٰنَ عِلْماً وَقَالاَ ۰لْحَمْدُ لِلهِ ۱ﻟ﮲ فَضَّلَنَا عَلَــيٰ كَثِيرٍ مِّنْ عِبَادِهِ ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 16, 'وَوَرۣثَ سُلَيْمَـٰنُ دَاوُﹼدَ وَقَالَ يَـٰٓأَيُّهَا ۰لنَّاسسسُ عُلِّمْنَا مَنطِــقَ ۰لطَّيْرۣ وَٱُوتِينَا مِــن كُــلّۣ شَيْءٖؐ اِنَّ هَـٰذَا لَهُوَ ۰لْفَضْــلُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 17, 'وَحُشِرَ لِسُلَيْمَـٰنَ جُنُودُهُ„ مِنَ ۰لْجِنِّ وَالِانسِ وَالطَّيْرۣ فَهُمْ يُوزَعُونَؐ 87');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 18, 'حَتَّيٰٓ إِذَآ أَتَوْاْ عَلَيٰ وَادِ ۱لنَّمْــلۣ قَالَتْ نَمْلَةٌ يَـٰٓأَيُّهَا ۰لنَّمْلُ ۶دْخُلُواْ مَسَـٰكِنَكُمْ لاَ يَحْطِمَنَّكُمْ سُلَيْمَـٰنُ وَجُنُودُهُ„ وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 19, 'فَتَبَسَّمَ ضَاحِكاً مِّن قَوْلِهَا وَقَالَ رَبِّ أَوْزۣعْنِيَ أَنَ اَشْكُرَ نِعْمَتَــكَ ۰لتِىٓ أَنْعَمْتَ عَلَيَّ وَعَلَيٰ وَ؛لِدَيَّ وَأَنَ اَعْمَــلَ صَـٰڤِحاً تَرْضۭيٰهُ وَأَدْخِلْنِى بِرَحْمَتِكَ فِى عِبَادِكككَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 20, 'وَتَفَقَّدَ ۰لطَّيْرَ فَقَالَ مَا لِى لآَ أَرَي ۰لْهُدْهُدَ أَمْ كَانَ مِــنَ ۰لْغَآئِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 21, 'لُءَعَذِّبَنَّهُ„ عَذَاباً شَدِيداٗ اَوْ لَأَاْذْبَحَنَّهُ; أَوْ لَيَاتِيَنِّى بِسُلْطَـٰنٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 22, 'فَمَكُــثَ غَيْرَ بَعِيدٍؐ فَقَالَ أَحَطْــتُّ بِمَا لَمْ تُحِطْ بِهِ” وَجِيؔتُــكَ مِــن سَبَإٙ بِنَبَإٍ يَقِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 23, 'اِنِّى وَجَدتُّ èمْرَأَةً تَمْلِكُهُمْ وَٱُوتِيَتْ مِن كُــلّۣ شَيْءٍؐ وَلَهَا عَرْش٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 24, 'وَجَدتُّهَا وَقَوْمَهَا يَسْجُدُونَ لِلشَّمْـسِ مِن دُونِ ۱للَّهِ وَزَيَّــنَ لَهُمُ ۴لشَّيْطَـٰــنُ أَعْمَـٰلَهُمْ فَصَدَّهُمْ عَـنِ ۱لسَّبِيلِ فَهُمْ لاَ يَهْتَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 25, 'أَلاَّ يَسْجُدُواْ لِلهِ ۱ﻟ﮲ يُخْرۣجُ ۴لْخَبْءَ فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ وَيَعْلَمُ مَا يُخْفُونَ وَمَا يُعْلِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 26, '۰للَّهُ لآَ إِچَهَ إِلاَّ هُوَ رَبُّ 88 ۴لْعَرْشِ ۱لْعَظِيمِؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 27, '© قَالَ سَنَنظُرُ أَصَدَقْتَ أَمْ كُنتَ مِــنَ ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 28, '"ذْهَــب بِّكِتَـٰبِى هَـٰذَا فَأَلْقِهِ“ إِلَيْهِمْ ثُمَّ تَوَلَّ عَنْهُمْ فَانظُرْ مَاذَا يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 29, 'قَالَتْ يَـٰٓأَيُّهَا ۰لْمَلَؤُاْ اِ۬نِّيَ ٱُلْقِيَ إِلَيَّ كِتَـٰبٌ كَرۣيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 30, 'اِنَّهُ„ مِــن سُلَيْمَـٰنَ وَإِنَّهُ„ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 31, 'أَلاَّ تَعْلُواْ عَلَيَّ وَاتُونِى مُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 32, 'قَالَتْ يَـٰٓأَيُّهَا ۰لْمَلَؤُاْ اَ۬فْتُونِى فِىٓ أَمْرۣى مَا كُنتُ قَاطِعَةٗ اَمْراٗ حَتَّــيٰ تَشْهَدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 33, 'قَالُواْ نَحْنُ ٱُوْلُواْ قُوَّةٍ وَٱُوْلُواْ بَأْسسسٍ شَدِيدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 34, 'وَالاَمْرُ إِلَيْــكِ فَانظُرۣى مَاذَا تَامُرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 35, 'قَالَــتِ اِنَّ ۰لْمُلُوكككَ إِذَا دَخَلُواْ قَرْيَةٗ اَفْسَدُوهَا وَجَعَلُوٓاْ أَعِزَّةَ أَهْلِهَآ أَذِلَّةًؐ وَكَذَ؛لِــكَ يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 36, 'وَإِنِّى مُرْسِلَة٘ اِلَيْهِم بِهَدِيَّةٍ فَنَـٰظِرَةٛ بِمَ يَرْجِعُ ۴لْمُرْسَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 37, 'فَلَمَّا جَآءَ سُلَيْمَـٰــنَ قَالَ أَتُمِدُّونَنِ” بِمَالٍ فَمَآ ءَاتۭيٰــنۣﹺ ۰للَّهُ خَيْرٌ مِّمَّآ ءَاتۭيٰكُم بَــلَ اَنتُم بِهَدِيَّتِكُمْ تَفْرَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 38, '"رْجِعِ اِلَيْهِمْ فَلَنَاتِيَنَّهُم بِجُنُودٍ لاَّ قِبَــلَ لَهُم بِهَا وَڤَنُخْرۣجَنَّهُم مِّنْهَآ أَذِلَّةً وَهُمْ صَـٰغِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 39, 'قَالَ يَـٰٓأَيُّهَا ۰لْمَلَؤُاْ اَ۬يُّكُمْ يَاتِينِى بِعَرْشِهَا 89 قَبْـلَ أَنْ يَّاتُونِى مُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 40, 'قَالَ عِفْرۣيتٌ مِّنَ ۰لْجِــنّۣ أَنَآ ءَاتِيكَ بِهِ” قَبْـلَ أَن تَقُومَ مِــن مَّقَامِــكَ وَإِنِّى عَلَيْهِ لَقَوۣيّﹲ اَمِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 41, 'قَالَ ۰ﻟ﮲ عِندَهُ„ عِلْمٌ مِّــنَ ۰لْكِتَـٰــبِ أَنَآ ءَاتِيكَ بِهِ” قَبْلَ أَنْ يَّرْتَدَّ إِلَيْــكَ طَرْفُــكَؐ فَلَمَّا رۭءۭاهُ مُسْتَقِرّاٗ عِندَهُ„ قَالَ هَـٰذَا مِن فَضْلِ رَبِّى لِيَبْلُوَنِــيَ ءَآشْكُرُ أَمَ اَكْفُرُؐ وَمَــن شَكَرَ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِؐ” وَمَــن كَفَرَ فَإِنَّ رَبِّى غَنِــيٌّ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 42, 'قَالَ نَكِّرُواْ لَهَا عَرْشَهَا نَنظُرَ اَتَهْتَدِﻯٓ أَمْ تَكُونُ مِــنَ ۰لذِيــنَ لاَ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 43, 'فَلَمَّا جَآءَتْ قِيــلَ أَهَـٰكَذَا عَرْشُكِ قَالَتْ كَأَنَّهُ„ هُوَؐ وَٱُوتِينَا ۰لْعِلْمَ مِــن قَبْلِهَا وَكُنَّا مُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 44, 'وَصَدَّهَا مَا كَانَــت تَّعْبُدُ مِن دُونِ ۱للَّهِؐ إِنَّهَا كَانَتْ مِن قَوْمٍ كۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 45, 'قِيــلَ لَهَا ۸دْخُلِى ۱لصَّرْحَؐ فَلَمَّا رَأَتْهُ حَسِبَتْهُ لُجَّةً وَكَشَفَتْ عَــن سَاقَيْهَاؐ قَالَ إِنَّهُ„ صَرْحٌ مُّمَرَّدٌ مِّن قَوَارۣيرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 46, 'قَالَتْ رَبِّ إِنِّى ظَلَمْــتُ نَفْسِى وَأَسْلَمْــتُ مَعَ سُلَيْمَـٰنَ لِلهِ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 47, 'وَلَقَدَ اَرْسَلْنَآ إِلَيٰ ثَمُودَ أَخَاهُمْ صَـٰڤِحاٗ اَنُ ۶عْبُدُواْ ۴للَّهَ فَإِذَا هُمْ فَرۣيقَـٰــنۣ يَخْتَصِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 48, '90 قَالَ يَـٰقَوْمِ لِمَ تَسْتَعْجِلُونَ بِالسَّيِّيؕةِ قَبْــلَ ۰لْحَسَنَةِ لَوْلاَ تَسْتَغْفِرُونَ ۰للَّهَ لَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 49, 'قَالُواْ èطَّيَّرْنَا بِــكَ وَبِمَــن مَّعَــكَؐ قَالَ طَـٰٓئِرُكُمْ عِندَ ۰للَّهِؐ بَــلَ اَنتُمْ قَوْمٌ تُفْتَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 50, 'وَكَانَ فِى ۱لْمَدِينَةِ تِسْعَةُ رَهْطٍ يُفْسِدُونَ فِى ۱لاَرْضِ وَلاَ يُصْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 51, 'قَالُواْ تَقَاسَمُواْ بِاللَّهِ لَنُبَيِّتَنَّهُ„ وَأَهْلَهُ„ ثُمَّ لَنَقُولَنَّ لِوَلِيِّهِ” مَا شَهِدْنَا مُهْلَــكَ أَهْلِهِ” وَإِنَّا لَصَـٰدِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 52, 'وَمَكَرُواْ مَكْراً وَمَكَرْنَا مَكْراً وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 53, 'فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ مَكْرۣهِمُؐ; إِنَّا دَمَّرْنَـٰهُمْ وَقَوْمَهُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 54, 'فَتِلْــكَ بُيُوتُهُمْ خَاوۣيَةَۢ بِمَا ظَلَمُوٓاْؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّقَوْمٍ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 55, 'وَأَنجَيْنَا ۰لذِيــنَ ءَامَنُواْ وَكَانُواْ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 56, 'وَلُوطاٗ اِذْ قَالَ لِقَوْمِهِ“ أَتَاتُونَ ۰ڤْفَـٰحِشَةَ وَأَنتُمْ تُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 57, 'أَئنَّكُمْ لَتَاتُونَ ۰لرّۣجَالَ شَهْوَةً مِّن دُونِ ۱لنِّسَآءِؐ بَــلَ اَنتُمْ قَوْمٌ تَجْهَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 58, '¤ فَمَا كَانَ جَوَابَ قَوْمِهِ“ إِلٓاَّ أَن قَالُوٓاْ أَخْرۣجُوٓاْ ءَالَ لُوطٍ مِّن قَرْيَتِكُمُؐ; إِنَّهُمُ; ٱُنَاسٌ يَتَطَهَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 59, 'فَأَنجَيْنَـٰهُ وَأَهْلَهُ; إِلاَّ "مْرَأَتَهُ„ 91 قَدَّرْنَـٰهَا مِــنَ ۰لْغَـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 60, 'وَأَمْطَرْنَا عَلَيْهِم مَّطَراًؐ فَسَآءَ مَطَرُ ۴لْمُنذَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 61, 'قُـلِ ۱لْحَمْدُ لِلهِ وَسَچَم٘ عَلَــيٰ عِبَادِهِ ۱لذِينَ "صْطَفۭــيٰٓؐ ءَآللَّهُ خَيْر٘ اَمَّا تُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 62, 'أَمَّــنْ خَلَقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَأَنزَلَ لَكُم مِّــنَ ۰لسَّمَآءِ مَآءً فَأَنۢبَتْنَا بِهِ” حَدَآئِــقَ ذَاتَ بَهْجَةٍؐ مَّا كَانَ لَكُمُ; أَن تُنۢبِتُواْ شَجَرَهَآؐ أَ.چَهٌ مَّعَ ۰للَّهِؐ بَلْ هُمْ قَوْمٌ يَعْدِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 63, 'أَمَّـن جَعَــلَ ۰لاَرْضَ قَرَاراً وَجَعَـلَ خِچَلَهَآ أَنْهَـٰراً وَجَعَــلَ لَهَا رَوَ؛سِيَ وَجَعَلَ بَيْنَ ۰ڤْبَحْرَيْنِ حَاجِزاٗؐ اَ.چَهٌ مَّعَ ۰للَّهِؐ بَــلَ اَكْثَرُهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 64, 'أَمَّنْ يُّجِيبُ ۴لْمُضْطَرَّ إِذَا دَعَاهُ وَيَكْشِفُ ۴لسُّوٓءَ وَيَجْعَلُكُمْ خُلَفَآءَ ۰لاَرْضضضِؐ أَ.چَهٌ مَّعَ ۰للَّهِؐ قَلِيلًا مَّا تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 65, 'أَمَّـنْ يَّهْدِيكُمْ فِى ظُلُمَـٰــتِ ۱لْبَرّۣ وَاڤْبَحْرۣ وَمَنْ يُّرْسِلُ ۴لرّۣيَـٰحَ نُشُراَۢ بَيْـنَ ¢ رَحْمَتِهِؐ“ أَ.چَهٌ مَّعَ ۰للَّهِؐ تَعَـٰلَــي ۰للَّهُ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 66, 'أَمَّــنْ يَّبْدَؤُاْ ۴لْخَلْقَ ثُمَّ يُعِيدُهُ„ وَمَنْ يَّرْزُقُكُم مِّــنَ ۰لسَّمَآءِ وَالاَرْضِؐ أَ.چَهٌ مَّعَ ۰للَّهِؐ قُــلْ هَاتُواْ بُرْهَـٰنَكُمُ; إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 67, 'قُـل لاَّ يَعْلَمُ مَن فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِ ۱لْغَيْبَ إِلاَّ ۰للَّهُؐ 92 وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 68, 'بَلِ ''دَّ؛رَكَ عِلْمُهُمْ فِى ۱لاَخِرَةِؐ بَلْ هُمْ فِى شَــكٍّ مِّنْهَا بَلْ هُم مِّنْهَا عَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 69, 'وَقَالَ ۰لذِيــنَ كَفَرُوٓاْ إِذَا كُنَّا تُرَ؛باً وَءَابَآؤُنَآ أَئنَّا ڤَمُخْرَجُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 70, 'لَقَدْ وُعِدْنَا هَـٰذَا نَحْنُ وَءَابَآؤُنَا مِن قَبْلُؐ إِنْ هَـٰذَآ إِلٓاَّ أَسَـٰطِيرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 71, 'قُلْ سِيرُواْ فِى ۱لاَرْضِ فَانظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴ڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 72, 'وَلاَ تَحْزَنْ عَلَيْهِمْ وَلاَ تَكُـن فِى ضَيْقٍ مِّمَّا يَمْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 73, 'وَيَقُولُونَ مَتۭــيٰ هَـٰذَا ۰لْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 74, 'قُلْ عَسۭيٰٓ أَنْ يَّكُونَ رَدِفَ لَكُم بَعْضُ ۴ﻟ﮲ تَسْتَعْجِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 75, 'وَإِنَّ رَبَّــكَ لَذُو فَضْــل۫ عَلَي ۰لنَّاسِؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 76, 'وَإِنَّ رَبَّــكَ لَيَعْلَمُ مَا تُكِــنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 77, 'وَمَا مِــنْ غَآئِبَةٍ فِى ۱لسَّمَآءِ وَالاَرْضِ إِلاَّ فِى كِتَـٰبٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 78, 'اِنننَّ هَـٰذَا ۰لْقُرْءَانَ يَقُــصُّ عَلَيٰ بَنِىٓ إِسْرَآءِيــلَ أَكْثَرَ ۰ﻟ﮲ هُمْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 79, 'وَإِنَّهُ„ لَهُديً وَرَحْمَةٌ لِّلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 80, 'إِنَّ رَبَّــكَ يَقْضِى بَيْنَهُم بِحُكْمِهِؐ” وَهُوَ ۰لْعَزۣيزُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 81, 'فَتَوَكَّــلْ عَلَــي ۰للَّهِؐ 9 إِنَّــكَ عَلَــي ۰لْحَـقِّ ۱لْمُبِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 82, 'إِنَّــكَ لاَ تُسْمِعُ ۴لْمَوْتۭيٰ وَلاَ تُسْمِعُ ۴لصُّمَّ ۰لدُّعَآءَ اۭذَا وَلَّوْاْ مُدْبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 83, 'وَمَآ أَنتَ بِهَـٰدِى ۱لْعُمْــيۣ عَن ضَچَلَتِهِمُؐ; إِن تُسْمِعُ إِلاَّ مَنْ يُّومِنُ بِـَٔايَـٰتِنَا فَهُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 84, '© وَإِذَا وَقَعَ ۰لْقَوْلُ عَلَيْهِمُ; أَخْرَجْنَا لَهُمْ دَآبَّةً مِّــنَ ۰لاَرْضضضِ تُكَلِّمُهُمُؐ; إِنَّ ۰لنَّاسسسَ كَانُواْ بِـَٔايَـٰتِنَا لاَ يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 85, 'وَيَوْمَ نَحْشُرُ مِــن كُلِّ ٱُمَّةٍ فَوْجاً مِّمَّنْ يُّكَذِّبُ بِـَٔايَـٰتِنَا فَهُمْ يُوزَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 86, 'حَتَّيٰٓ إِذَا جَآءُو قَالَ أَكَذَّبْتُم بِـَٔايَـٰتِى وَلَمْ تُحِيطُواْ بِهَا عِلْماٗؐ اَمَّاذَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 87, 'وَوَقَعَ ۰لْقَوْلُ عَلَيْهِم بِمَا ظَلَمُواْ فَهُمْ لاَ يَنطِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 88, 'أَلَمْ يَرَوَاْ اَنَّا جَعَلْنَا ۰ليْلَ لِيَسْكُنُواْ فِيهِ وَالنَّهَارَ مُبْصِراٗؐ اِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 89, 'وَيَوْمَ يُنفَخُ فِى ۱لصُّورۣ فَفَزۣعَ مَـن فِى ۱لسَّمَـٰوَ؛تِ وَمَـن فِى ۱لاَرْضضضِ إِلاَّ مَــن شَآءَ ۰للَّهُؐ وَكُــلّﹲ —اتُوهُ دَ؛خِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 90, 'وَتَرَي ۰لْجِبَالَ تَحْسِبُهَا جَامِدَةً وَهِــيَ تَمُرُّ مَرَّ ۰ڤسَّحَابِؐ صُنْعَ ۰للَّهِ ۱ﻟـذِىٓ أَتْقَــنَ كُــلَّ شَيْءٖؐ اِنَّهُ„ خَبِيرٛ بِمَا تَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 91, 'مَـن جَآءَ 94 بِالْحَسَنَةِ فَلَهُ„ خَيْرٌ مِّنْهَا وَهُم مِّن فَزَعِ يَوْمَئِذٖ —امِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 92, 'وَمَن جَآءَ بِالسَّيِّيؕةِ فَكُبَّــتْ وُجُوهُهُمْ فِى ۱لنّۭارۣؐ هَلْ تُجْزَوْنَ إِلاَّ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 93, 'إِنَّمَآ ٱُمِرْتُ أَنَ اَعْبُدَ رَبَّ هَـٰذِهِ ۱لْبَلْدَةِ ۱ﻟ﮲ حَرَّمَهَا وَلَهُ„ كُــلُّ شَيْءٍؐ وَٱُمِرْتُ أَنَ اَكُونَ مِنَ ۰لْمُسْلِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 94, 'وَأَنَ اَتْلُوَاْ ۰لْقُرْءَانَؐ فَمَـنِ ''هْتَدۭيٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِؐ” وَمَــن ضَلَّ فَقُلِ اِنَّمَآ أَنَا مِــنَ ۰لْمُنذِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (27, 95, 'وَقُـلِ ۱لْحَمْدُ لِلهِ سَيُرۣيكُمُ; ءَايَـٰتِهِ” فَتَعْرۣفُونَهَاؐ وَمَا رَبُّــكَ بِغَـٰفِــل۫ عَمَّا تَعْمَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ طَسِٓم؋ّٓؐ تِلْكَ ءَايَـٰــتُ ۴لْكِتَـٰبِ ۱لْمُبِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 2, 'نَتْلُواْ عَلَيْــكَ مِن نَّبَإِ مُوسۭيٰ وَفِرْعَوْنَ بِالْحَقِّ لِقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 3, 'إِنَّ فِرْعَوْنَ عَلاَ فِى ۱لاَرْضِ وَجَعَــلَ أَهْلَهَا شِيَعاً يَسْتَضْعِفُ طَآئِفَةً مِّنْهُمْ يُذَبِّحُ أَبْنَآءَهُمْ وَيَسْتَحْىِ” نِسَآءَهُمُؐ; إِنَّهُ„ كَانَ مِــنَ ۰لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 4, 'وَنُرۣيدُ أَن نَّمُــنَّ عَلَي ۰لذِيــنَ ۸سْتُضْعِفُواْ فِى ۱لاَرْضِ وَنَجْعَلَهُمُ; 95 أَئمَّةً وَنَجْعَلَهُمُ ۴لْوَ؛رۣثِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 5, 'وَنُمَكِّــنَ لَهُمْ فِى ۱لاَرْضِ وَنُرۣيَ فِرْعَوْنَ وَهَامَـٰنَ وَجُنُودَهُمَا مِنْهُم مَّا كَانُواْ يَحْذَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 6, 'وَأَوْحَيْنَآ إِلَيٰٓ ٱُمِّ مُوسۭيٰٓ أَنَ اَرْضِعِيهِ فَإِذَا خِفْتِ عَلَيْهِ فَأَلْقِيهِ فِى ۱لْيَمِّ وَلاَ تَخَافِى وَلاَ تَحْزَنِىٓؐ إِنَّا رَآدُّوهُ إِلَيْكِ وَجَاعِلُوهُ مِــنَ ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 7, 'فَالْتَقَطَهُ; ءَالُ فِرْعَوْنَ لِيَكُونَ لَهُمْ عَدُوّاً وَحَزَناٗؐ اِنَّ فِرْعَوْنَ وَهَامَـٰنَ وَجُنُودَهُمَا كَانُواْ خَـٰطِـِٕينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 8, 'وَقَالَــتِ ''مْرَأَتُ فِرْعَوْنَ قُرَّتُ عَيْــنٍ لِّى وَلَكَ لاَ تَقْتُلُوهُؐ عَسۭيٰٓ أَنْ يَّنفَعَنَآ أَوْ نَتَّخِذَهُ„ وَلَداً وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 9, 'وَأَصْبَحَ فُؤَادُ ٱُمِّ مُوسۭيٰ فَـٰرۣغاٗ اِن كَـٰدَتْ لَتُبْدِى بِهِ” لَوْلآَ أَن رَّبَطْنَا عَلَــيٰ قَلْبِهَا لِتَكُونَ مِــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 10, 'وَقَالَــتْ لُءِخْتِهِ” قُصِّيهِ فَبَصُرَتْ بِهِ” عَن جُنُبٍ وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 11, '¥ وَحَرَّمْنَا عَلَيْهِ ۱لْمَرَاضِعَ مِن قَبْلُ فَقَالَــتْ هَــلَ اَدُلُّكُمْ عَلَـــيٰٓ أَهْلِ بَيْــتٍ يَكْفُلُونَهُ„ لَكُمْ وَهُمْ لَهُ„ نَـٰصِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 12, 'فَرَدَدْنَـٰهُ إِلَـيٰٓ ٱُمِّهِ” كَىْ تَقَرَّ عَيْنُهَا وَلاَ تَحْزَنَ وَلِتَعْلَمَ أَنَّ وَعْدَ ۰للَّهِ حَقٌّؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 13, 'وَلَمَّا بَلَغَ 96 أَشُدَّهُ„ وَاسْتَوۭيٰٓ ءَاتَيْنَـٰهُ حُكْماً وَعِلْماًؐ وَكَذَ؛لِكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 14, 'وَدَخَــلَ ۰لْمَدِينَةَ عَلَيٰ حِيــنۣ غَفْلَةٍ مِّــنَ اَهْلِهَا فَوَجَدَ فِيهَا رَجُلَيْنِ يَقْتَتِچَنِ هَـٰذَا مِن شِيعَتِهِ” وَهَـٰذَا مِنْ عَدُوّۣهِؐ” فَاسْتَغَـٰثَهُ ۴ﻟ﮲ مِن شِيعَتِهِ” عَلَي ۰ﻟ﮲ مِنْ عَدُوّۣهِ” فَوَكَزَهُ„ مُوسۭيٰ فَقَضۭــيٰ عَلَيْهِؐ قَالَ هَـٰذَا مِــنْ عَمَلِ ۱لشَّيْطَـٰنِؐ إِنَّهُ„ عَدُوٌّ مُّضِلٌّ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 15, 'قَالَ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى فَاغْفِرْ لِىؐ فَغَفَرَ لَهُؐ; إِنَّهُ„ هُوَ ۰لْغَفُورُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 16, 'قَالَ رَبِّ بِمَآ أَنْعَمْتَ عَلَيَّ فَلَنَ اَكُونَ ظَهِيراً ڤِّڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 17, 'فَأَصْبَحَ فِى ۱لْمَدِينَةِ خَآئِفاً يَتَرَقَّبُ فَإِذَا ۰ﻟ﮲ ''سْتَنصَرَهُ„ بِالاَمْسِ يَسْتَصْرۣخُهُؐ, قَالَ لَهُ„ مُوسۭيٰٓ إِنَّــكَ لَغَوۣيٌّ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 18, 'فَلَمَّآ أَنَ اَرَادَ أَنْ يَّبْطِشَ بِاﻟ﮲ هُوَ عَدُوٌّ لَّهُمَا قَالَ يَـٰمُوسۭيٰٓ أَتُرۣيدُ أَن تَقْتُلَنِى كَمَا قَتَلْتَ نَفْساَۢ بِالاَمْسِؐ إِن تُرۣيدُ إِلٓاَّ أَن تَكُونَ جَبَّاراً فِى ۱لاَرْضِ وَمَا تُرۣيدُ أَن تَكُونَ مِــنَ ۰ڤْمُصْڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 19, 'وَجَآءَ رَجُلٌ مِّنَ اَقْصَا ۰لْمَدِينَةِ يَسْعۭــيٰؐ قَالَ يَـٰمُوسۭيٰٓ إِنَّ ۰لْمَلَأَ يَاتَمِرُونَ بِــكَ لِيَقْتُلُوكككَ فَاخْرُجِ اِنِّى لَــكَ مِــنَ ۰ڤنَّـٰصِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 20, '97 فَخَرَجَ مِنْهَا خَآئِفاً يَتَرَقَّـــبُؐ قَالَ رَبِّ نَجِّنِى مِــنَ ۰لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 21, 'وَلَمَّا تَوَجَّهَ تِلْقَآءَ مَدْيَــنَ قَالَ عَسۭيٰ رَبِّيَ أَنْ يَّهْدِيَنِى سَوَآءَ ۰لسَّبِيــلۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 22, 'وَلَمَّا وَرَدَ مَآءَ مَدْيَنَ وَجَدَ عَلَيْهِ ٱُمَّةً مِّنَ ۰لنَّاسِ يَسْقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 23, 'وَوَجَدَ مِن دُونِهِمُ èمْرَأَتَيْــنۣ تَذُودَ؛نِؐ قَالَ مَا خَطْبُكُمَاؐ قَالَتَا لاَ نَسْقِى حَتَّيٰ يُصْدِرَ ۰لرّۣعَآءُ وَأَبُونَا شَيْخٌ كَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 24, 'فَسَقۭــيٰ لَهُمَا ثُمَّ تَوَلّۭـيٰٓ إِلَي ۰لظِّــلّۣ فَقَالَ رَبِّ إِنِّى لِمَآ أَنزَلْــتَ إِلَيَّ مِنْ خَيْرٍ فَقِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 25, 'فَجَآءَتْهُ إِحْدۭيٰهُمَا تَمْشِى عَلَي "سْتِحْيَآءٍؐ قَالَــتِ اِنَّ أَبِى يَدْعُوكككَ ڤِيَجْزۣيَــكَ أَجْرَ مَا سَقَيْــتَ لَنَاؐ فَلَمَّا جَآءَهُ„ وَقَــصَّ عَلَيْهِ ۱لْقَصَــصَ قَالَ لاَ تَخَفْ نَجَوْتَ مِــنَ ۰لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 26, 'قَالَــتِ اِحْدۭيٰهُمَا يَـٰٓأَبَتِ ''سْتَـٰجِرْهُؐ إِنَّ خَيْرَ مَنِ ''سْتَـٰجَرْتَ ۰لْقَوۣيُّ ۴لاَمِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 27, 'قَالَ إِنِّيَ ٱُرۣيدُ أَنُ ۷نكِحَــكَ إِحْدَي "بْنَتَــيَّ هَـٰتَيْــنۣ عَلَيٰٓ أَن تَاجُرَنِى ثَمَـٰنِيَ حِجَجٍؐ فَإِنَ اَتْمَمْتَ عَشْراً فَمِنْ عِندِكككَؐ وَمَآ ٱُرۣيدُ أَنَ اَشُــقَّ عَلَيْــكَؐ سَتَجِدُنِيَ إِن شَآءَ ۰للَّهُ مِــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 28, 'قَالَ ذَ؛لِكَ بَيْنِى وَبَيْنَكَؐ أَيَّمَا ۰لاَجَلَيْــنۣ قَضَيْتُ فَلاَ عُدْوَ؛نَ عَلَيَّؐ 98 وَاللَّهُ عَلَــيٰ مَا نَقُولُ وَكِيــلٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 29, '© فَلَمَّا قَضۭيٰ مُوسَــي ۰لاَجَلَ وَسَارَ بِأَهْلِهِ“ ءَانَسَ مِن جَانِبِ ۱لطُّورۣ نَاراًؐ قَالَ لَأِهْلِهِ ۹مْكُثُوٓاْ إِنِّــيَ ءَانَسْــتُ نَاراً لَّعَلِّــيَ ءَاتِيكُم مِّنْهَا بِخَبَر۫ اَوْ جِذْوَةٍ مِّــنَ ۰لنّۭارۣ لَعَلَّكُمْ تَصْطَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 30, 'فَلَمَّآ أَتۭيٰهَا نُودِيَ مِن شَـٰطِئِ ۱لْوَادِ ۱لاَيْمَنِ فِى ۱لْبُقْعَةِ ۱لْمُبَـٰرَكَةِ مِــنَ ۰ڤشَّجَرَةِ أَنْ يَّـٰمُوسۭيٰٓ إِنِّيَ أَنَا ۰للَّهُ رَبُّ ۴لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 31, 'وَأَنَ اَلْقِ عَصَاكككَؐ فَلَمَّا رۭءۭاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّ وَلّۭــيٰ مُدْبِراً وَلَمْ يُعَقِّبْؐ يَـٰمُوسۭيٰٓ أَقْبِلْ وَلاَ تَخَـفِؐ اِنَّــكَ مِــنَ ۰لاَمِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 32, '۸سْلُــكْ يَدَكككَ فِى جَيْبِــكَ تَخْرُجْ بَيْضَآءَ مِــنْ غَيْرۣ سُوٓءٍؐ وَاضْمُمِ اِلَيْــكَ جَنَاحَــكَ مِــنَ ۰لرَّهَبِؐ فَذَ؛نِكَ بُرْهَـٰنَـٰـنِ مِن رَّبِّــكَ إِلَيٰ فِرْعَوْنَ وَمَلْاَئِهِؐ“ إِنَّهُمْ كَانُواْ قَوْماً فَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 33, 'قَالَ رَبِّ إِنِّى قَتَلْــتُ مِنْهُمْ نَفْساً فَأَخَافُ أَنْ يَّقْتُلُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 34, 'وَأَخِى هَـٰرُونُ هُوَ أَفْصَحُ مِنِّى لِسَاناً فَأَرْسِلْهُ مَعِى رۣداً يُصَدِّقْنِىٓؐ إِنِّــيَ أَخَافُ أَنْ يُّكَذِّبُونِؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 35, 'قَالَ سَنَشُدُّ عَضُدَكَ بِأَخِيكَ وَنَجْعَــلُ لَكُمَا سُلْطَـٰناً فَلاَ يَصِلُونَ إِلَيْكُمَا بِـَٔايَـٰتِنَآؐ أَنتُمَا وَمَنِ ''تَّبَعَكُمَا ۰لْغَـٰلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 36, '99 فَلَمَّا جَآءَهُم مُّوسۭـيٰ بِـَٔايَـٰتِنَا بَيِّنَـٰــتٍ قَالُواْ مَا هَـٰذَآ إِلاَّ سِحْـرٌ مُّفْتَريً وَمَا سَمِعْنَا بِهَـٰذَا فِىٓ ءَابَآئِنَا ۰لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 37, 'وَقَالَ مُوسۭيٰ رَبِّــيَ أَعْلَمُ بِمَن جَآءَ بِالْهُدۭيٰ مِــنْ عِندِهِ” وَمَــن تَكُونُ لَهُ„ عَـٰقِبَةُ ۴لدّۭارۣؐ إِنَّهُ„ لاَ يُفْلِحُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 38, 'وَقَالَ فِرْعَوْنُ يَـٰٓأَيُّهَا ۰لْمَلُءَ مَا عَلِمْــتُ لَكُم مِّنِ اِچَهٖ غَيْرۣى فَأَوْقِدْ لِى يَـٰهَامَـٰــنُ عَلَــي ۰لطِّينِ فَاجْعَـل لِّى صَرْحاً لَّعَلِّــيَ أَطَّلِعُ إِلَيٰٓ إِچَهِ مُوسۭيٰ وَإِنِّى لَأَظُنُّهُ„ مِــنَ ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 39, 'وَاسْتَكْبَرَ هُوَ وَجُنُودُهُ„ فِى ۱لاَرْضِ بِغَيْرۣ ۱لْحَقِّ وَظَنُّوٓاْ أَنَّهُمُ; إِلَيْنَا لاَ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 40, 'فَأَخَذْنَـٰهُ وَجُنُودَهُ„ فَنَبَذْنَـٰهُمْ فِى ۱لْيَم؋ّؐ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 41, 'وَجَعَلْنَـٰهُمُ; أَئمَّةً يَدْعُونَ إِلَي ۰لنّۭارۣؐ وَيَوْمَ ۰لْقِيَـٰمَةِ لاَ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 42, 'وَأَتْبَعْنَـٰهُمْ فِى هَـٰذِهِ ۱لدُّنْيۭا لَعْنَةًؐ وَيَوْمَ ۰لْقِيَـٰمَةِ هُم مِّنَ ۰لْمَقْبُوحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 43, 'وَلَقَدَ —اتَيْنَا مُوسَي ۰لْكِتَـٰبَ مِنۢ بَعْدِ مَآ أَهْلَكْنَا ۰لْقُرُونَ ۰لاُولۭـيٰ بَصَآئِرَ لِلنَّاسِ وَهُديً وَرَحْمَةً لَّعَلَّهُمْ يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 44, 'وَمَا كُنــتَ بِجَانِبِ ۱لْغَرْبِيِّ إِذْ قَضَيْنَآ 400 إِلَيٰ مُوسَــي ۰لاَمْرَؐ وَمَا كُنــتَ مِــنَ ۰لشَّـٰهِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 45, 'وَچَكِنَّآ أَنشَأْنَا قُرُوناً فَتَطَاوَلَ عَلَيْهِمُ ۴لْعُمُرُؐ وَمَا كُنــتَ ثَاوۣياً فِىٓ أَهْــلۣ مَدْيَــنَ تَتْلُواْ عَلَيْهِمُ; ءَايَـٰتِنَاؐ وَچَكِنَّا كُنَّا مُرْسِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 46, 'وَمَا كُنــتَ بِجَانِبِ ۱لطُّورۣ إِذْ نَادَيْنَاؐ وَچَكِن رَّحْمَةً مِّن رَّبِّــكَ لِتُنذِرَ قَوْماً مَّآ أَتۭيٰهُم مِّن نَّذِيرٍ مِّن قَبْلِكَ لَعَلَّهُمْ يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 47, 'وَلَوْلآَ أَن تُصِيبَهُم مُّصِيبَةٛ بِمَا قَدَّمَــتَ اَيْدِيهِمْ فَيَقُولُواْ رَبَّنَا لَوْلآَ أَرْسَلْتَ إِلَيْنَا رَسُولًا فَنَتَّبِعَ ءَايَـٰتِــكَ وَنَكُونَ مِــنَ ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 48, 'فَلَمَّا جَآءَهُمُ ۴لْحَقُّ مِـنْ عِندِنَا قَالُواْ لَوْلآَ ٱُوتِـيَ مِثْلَ مَآ ٱُوتِيَ مُوسۭيٰٓؐ أَوَلَمْ يَكْفُرُواْ بِمَآ ٱُوتِيَ مُوسۭيٰ مِـن قَبْلُؐ قَالُواْ سَـٰحِرَ؛نِ تَظَـٰهَرَاؐ وَقَالُوٓاْ إِنَّا بِكُــلٍّ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 49, 'قُلْ فَاتُواْ بِكِتَـٰــبٍ مِّنْ عِندِ ۱للَّهِ هُوَ أَهْدۭيٰ مِنْهُمَآ أَتَّبِعْهُ إِننن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 50, 'فَإِن لَّمْ يَسْتَجِيبُواْ لَكَ فَاعْلَمَ اَنَّمَا يَتَّبِعُونَ أَهْوَآءَهُمْؐ وَمَــنَ اَضَلُّ مِمَّنِ ''تَّبَعَ هَوۭيٰهُ بِغَيْرۣ هُديً مِّــنَ ۰للَّهِؐ إِنَّ ۰للَّهَ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 51, '¤ وَلَقَدْ وَصَّلْنَا لَهُمُ ۴لْقَوْلَ لَعَلَّهُمْ يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 52, '401 ۰لذِيــنَ ءَاتَيْنَـٰهُمُ ۴لْكِتَـٰــبَ مِــن قَبْلِهِ” هُم بِهِ” يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 53, 'وَإِذَا يُتْلۭــيٰ عَلَيْهِمْ قَالُوٓاْ ءَامَنَّا بِهِ“ إِنَّهُ ۴لْحَقُّ مِـن رَّبِّنَآ إِنَّا كُنَّا مِن قَبْلِهِ” مُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 54, 'ٱُوْلَئِــكَ يُوتَوْنَ أَجْرَهُم مَّرَّتَيْنِ بِمَا صَبَرُواْ وَيَدْرَءُونَ بِالْحَسَنَةِ ۱لسَّيِّيؕةَ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 55, 'وَإِذَا سَمِعُواْ ۴للَّغْوَ أَعْرَضُواْ عَنْهُ وَقَالُواْ لَنَآ أَعْمَـٰلُنَا وَلَكُمُ; أَعْمَـٰلُكُمْ سَچَم٘ عَلَيْكُمْ لاَ نَبْتَغِى ۱لْجَـٰهِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 56, 'إِنَّــكَ لاَ تَهْدِى مَــنَ اَحْبَبْتَؐ وَچَكِــنَّ ۰للَّهَ يَهْدِى مَـنْ يَّشَآءُؐ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 57, 'وَقَالُوٓاْ إِن نَّتَّبِعِ ۱لْهُدۭيٰ مَعَكَ نُتَخَطَّفْ مِنَ اَرْضِنَآؐ أَوَلَمْ نُمَكِّــن لَّهُمْ حَرَماٗ —امِناً تُجْبۭيٰٓ إِلَيْهِ ثَمَرَ؛تُ كُــلّۣ شَيْءٍ رّۣزْقاً مِّــن لَّدُنَّاؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 58, 'وَكَمَ اَهْلَكْنَا مِن قَرْيَةٙ بَطِرَتْ مَعِيشَتَهَاؐ فَتِلْكَ مَسَـٰكِنُهُمْ لَمْ تُسْكَن مِّنۢ بَعْدِهِمُ; إِلاَّ قَلِيلًا وَكُنَّا نَحْنُ ۴لْوَ؛رۣثِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 59, 'وَمَا كَانَ رَبُّــكَ مُهْلِــكَ ۰لْقُرۭيٰ حَتَّيٰ يَبْعَثَ فِىٓ ٱُمِّهَا رَسُولًا يَتْلُواْ عَلَيْهِمُ; ءَايَـٰتِنَاؐ وَمَا كُنَّا مُهْلِكِى ۱لْقُرۭيٰٓ إِلاَّ وَأَهْلُهَا ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 60, 'وَمَآ ٱُوتِيتُم مِّن شَيْءٍ 402 فَمَتَـٰعُ ۴لْحَيَوٰةِ ۱لدُّنْيۭا وَزۣينَتُهَاؐ وَمَا عِندَ ۰للَّهِ خَيْرٌ وَأَبْقۭيٰٓؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 61, 'أَفَمَنْ وَّعَدْنَـٰهُ وَعْداٗ حَسَناً فَهُوَ چَقِيهِ كَمَــن مَّتَّعْنَـٰهُ مَتَـٰعَ ۰لْحَيَوٰةِ ۱لدُّنْيۭا ثُمَّ هُوَ يَوْمَ ۰لْقِيَـٰمَةِ مِنَ ۰ڤْمُحْضَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 62, 'وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِيَ ۰لذِيــنَ كُنتُمْ تَزْعُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 63, 'قَالَ ۰لذِيــنَ حَقَّ عَلَيْهِمُ ۴لْقَوْلُ رَبَّنَا هَـٰٓؤُلآَءِ ۱لذِيــنَ أَغْوَيْنَآ أَغْوَيْنَـٰهُمْ كَمَا غَوَيْنَاؐ تَبَرَّأْنَآ إِلَيْــكَؐ مَا كَانُوٓاْ إِيَّانَا يَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 64, 'وَقِيــلَ ۸دْعُواْ شُرَكَآءَكُمْ فَدَعَوْهُمْ فَلَمْ يَسْتَجِيبُواْ لَهُمْ وَرَأَوُاْ ۴لْعَذَابَ لَوَ اَنَّهُمْ كَانُواْ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 65, 'وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ مَاذَآ أَجَبْتُمُ ۴لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 66, 'فَعَمِيَــتْ عَلَيْهِمُ ۴لاَنۢبَآءُ يَوْمَئِذٍ فَهُمْ لاَ يَتَسَآءَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 67, 'فَأَمَّا مَــن تَابَ وَءَامَنَ وَعَمِــلَ صَـٰڤِحاً فَعَسۭيٰٓ أَنْ يَّكُونَ مِــنَ ۰ڤْمُفْڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 68, 'وَرَبُّــكَ يَخْلُــقُ مَا يَشَآءُ وَيَخْتَارُؐ مَا كَانَ لَهُمُ ۴لْخِيَرَةُؐ سُبْحَـٰــنَ ۰للَّهِ وَتَعَـٰلۭــيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 69, 'وَرَبُّــكَ يَعْلَمُ مَا تُكِــنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 70, 'وَهُوَ ۰للَّهُ لآَ إِچَهَ إِلاَّ هُوَؐ لَهُ ۴لْحَمْدُ فِى ۱لاُولۭيٰ وَالاَخِرَةِؐ وَلَهُ ۴لْحُكْمُؐ وَإِلَيْهِ تُرْجَعُونَؐ 40');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 71, 'قُلَ اَرَ×يْتُمُ; إِن جَعَــلَ ۰للَّهُ عَلَيْكُمُ ۴ليْلَ سَرْمَداٗ اِلَيٰ يَوْمِ ۱لْقِيَـٰمَةِ مَنِ اِچَه٘ غَيْرُ ۴للَّهِ يَاتِيكُم بِضِيَآءٖؐ اَفَلاَ تَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 72, 'قُلَ اَرَ×يْتُمُ; إِن جَعَــلَ ۰للَّهُ عَلَيْكُمُ ۴لنَّهَارَ سَرْمَداٗ اِلَيٰ يَوْمِ ۱لْقِيَـٰمَةِ مَـنِ اِچَه٘ غَيْرُ ۴للَّهِ يَاتِيكُم بِلَيْــلٍ تَسْكُنُونَ فِيهِؐ أَفَلاَ تُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 73, 'وَمِن رَّحْمَتِهِ” جَعَــلَ لَكُمُ ۴ليْلَ وَالنَّهَارَ لِتَسْكُنُواْ فِيهِ وَلِتَبْتَغُواْ مِن فَضْلِهِ” وَلَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 74, 'وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِيَ ۰لذِيــنَ كُنتُمْ تَزْعُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 75, 'وَنَزَعْنَا مِــن كُــلّۣ ٱُمَّةٍ شَهِيداً فَقُلْنَا هَاتُواْ بُرْهَـٰنَكُمْ فَعَلِمُوٓاْ أَنَّ ۰لْحَـقَّ لِلهِ وَضَــلَّ عَنْهُم مَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 76, '© إِنَّ قَارُونَ كَانَ مِن قَوْمِ مُوسۭيٰ فَبَغۭــيٰ عَلَيْهِمْؐ وَءَاتَيْنَـٰهُ مِــنَ ۰لْكُنُوزۣ مَآ إِنَّ مَفَاتِحَهُ„ لَتَنُوٓٱُ بِالْعُصْبَةِ ٱُوْلِى ۱لْقُوَّةِؐ إِذْ قَالَ لَهُ„ قَوْمُهُ„ لاَ تَفْرَحِ اِنَّ ۰للَّهَ لاَ يُحِــبُّ ۴لْفَرۣحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 77, 'وَابْتَغِ فِيمَآ ءَاتۭيٰكَ ۰للَّهُ ۴لدَّارَ ۰لاَخِرَةَؐ وَلاَ تَنسَ نَصِيبَــكَ مِــنَ ۰لدُّنْيۭاؐ وَأَحْسِــن كَمَآ أَحْسَــنَ ۰للَّهُ إِلَيْــكَؐ وَلاَ تَبْغِ ۱لْفَسَادَ فِى ۱لاَرْضِؐ إِنَّ ۰للَّهَ لاَ يُحِــبُّ ۴لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 78, '404 قَالَ إِنَّمَآ ٱُوتِيتُهُ„ عَلَيٰ عِلْمٖ عِندِيَؐ أَوَلَمْ يَعْلَمَ اَنننَّ ۰للَّهَ قَدَ اَهْلَكَ مِــن قَبْلِهِ” مِــنَ ۰لْقُرُونِ مَنْ هُوَ أَشَدُّ مِنْهُ قُوَّةً وَأَكْثَرُ جَمْعاًؐ وَلاَ يُسْـَٔـــلُ عَـن ذُنُوبِهِمُ ۴ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 79, 'فَخَرَجَ عَلَيٰ قَوْمِهِ” فِى زۣينَتِهِؐ” قَالَ ۰لذِينَ يُرۣيدُونَ ۰لْحَيَوٰةَ ۰لدُّنْيۭا يَـٰلَيْتَ لَنَا مِثْــلَ مَآ ٱُوتِــيَ قَارُونُ إِنَّهُ„ لَذُو حَظّٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 80, 'وَقَالَ ۰لذِينَ ٱُوتُواْ ۴لْعِلْمَ وَيْلَكُمْ ثَوَابببُ ۴للَّهِ خَيْرٌ لِّمَــنَ —امَنَ وَعَمِــلَ صَـٰڤِحاًؐ وَلاَ يُلَقّۭيٰهَآ إِلاَّ ۰لصَّـٰبِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 81, 'فَخَسَفْنَا بِهِ” وَبِدۭارۣهِ ۱لاَرْضَؐ فَمَا كَانَ لَهُ„ مِن فِيؕةٍ يَنصُرُونَهُ„ مِن دُونِ ۱للَّهِؐ وَمَا كَانَ مِــنَ ۰لْمُنتَصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 82, 'وَأَصْبَحَ ۰لذِينَ تَمَنَّوْاْ مَكَانَهُ„ بِالاَمْسِ يَقُولُونَ وَيْكَأَنَّ ۰للَّهَ يَبْسُطُ ۴لرّۣزْقَ لِمَنْ يَّشَآءُ مِنْ عِبَادِهِ” وَيَقْدِرُؐ لَوْلآَ أَن مَّــنَّ ۰للَّهُ عَلَيْنَا لَخُسِفَ بِنَاؐ وَيْكَأَنَّهُ„ لاَ يُفْلِحُ ۴لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 83, 'تِلْكَ ۰لدَّارُ ۴لاَخِرَةُ نَجْعَلُهَا لِلذِيــنَ لاَ يُرۣيدُونَ عُلُوّاً فِى ۱لاَرْضِ وَلاَ فَسَاداًؐ وَالْعَـٰقِبَةُ لِلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 84, 'مَن جَآءَ بِالْحَسَنَةِ فَلَهُ„ خَيْرٌ مِّنْهَاؐ وَمَن جَآءَ بِالسَّيِّيؕةِ فَلاَ يُجْزَي ۰لذِيــنَ عَمِلُواْ 405 ۴لسَّيِّـَٔاتِ إِلاَّ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 85, 'إِنَّ ۰ﻟ﮲ فَرَضضضَ عَلَيْــكَ ۰لْقُرْءَانَ لَرَآدُّكَ إِلَــيٰ مَعَادٍؐ قُل رَّبِّــيَ أَعْلَمُ مَن جَآءَ بِالْهُدۭيٰ وَمَنْ هُوَ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 86, 'وَمَا كُنــتَ تَرْجُوٓاْ أَنْ يُّلْقۭيٰٓ إِلَيْكَ ۰لْكِتَـٰــبُ إِلاَّ رَحْمَةً مِّن رَّبِّكَؐ فَلاَ تَكُونَــنَّ ظَهِيراً لِّلْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 87, 'وَلاَ يَصُدُّنَّكَ عَــنَ —ايَـٰتِ ۱للَّهِ بَعْدَ إِذُ ۷نزۣلَتِ اِلَيْكَؐ وَادْعُ إِلَيٰ رَبِّكَؐ وَلاَ تَكُونَـنَّ مِنَ ۰لْمُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (28, 88, 'وَلاَ تَدْعُ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَؐ لآَ إِچَهَ إِلاَّ هُوَؐ كُلُّ شَيْءٖ هَالِك٘ اِلاَّ وَجْهَهُؐ, لَهُ ۴لْحُكْمُؐ وَإِلَيْهِ تُرْجَعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓم؋ّٓؐ اَحَسِــبَ ۰لنَّاسُ أَنْ يُّتْرَكُوٓاْ أَنْ يَّقُولُوٓاْ ءَامَنَّا وَهُمْ لاَ يُفْتَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 2, 'وَلَقَدْ فَتَنَّا ۰لذِينَ مِن قَبْلِهِمْؐ فَلَيَعْلَمَــنَّ ۰للَّهُ ۴لذِيــنَ صَدَقُواْ وَلَيَعْلَمَــنَّ ۰لْكَـٰذِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 3, 'أَمْ حَسِــبَ ۰لذِينَ يَعْمَلُونَ ۰لسَّيِّـَٔاتِ أَنْ يَّسْبِقُونَاؐ سَآءَ مَا يَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 4, 'مَــن كَانَ يَرْجُواْ لِقَآءَ ۰للَّهِ فَإِنَّ أَجَــلَ ۰للَّهِ ءَلاَتٍؐ 406 وَهُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 5, 'وَمَن جَـٰهَدَ فَإِنَّمَا يُجَـٰهِدُ لِنَفْسِهِؐ“ إِنَّ ۰للَّهَ لَغَنِــيّﹲ عَنِ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 6, 'وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِــحَـٰــتِ لَنُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَڤَنَجْزۣيَنَّهُمُ; أَحْسَنَ ۰ﻟ﮲ كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 7, '¥ وَوَصَّيْنَا ۰لِانسَـٰنَ بِوَ؛لِدَيْهِ حُسْناًؐ وَإِن جَـٰهَدَ؛كَ لِتُشْرۣكَ بِى مَا لَيْــسَ لَــكَ بِهِ” عِلْمٌ فَلاَ تُطِعْهُمَآؐ إِلَيَّ مَرْجِعُكُمْ فَٱُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 8, 'وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ لَنُدْخِلَنَّهُمْ فِى ۱ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 9, 'وَمِــنَ ۰لنَّاسِ مَنْ يَّقُولُ ءَامَنَّا بِاللَّهِ فَإِذَآ ٱُوذِيَ فِى ۱للَّهِ جَعَلَ فِتْنَةَ ۰لنَّاسسسِ كَعَذَابِ ۱للَّهِؐ وَلَـئِن جَآءَ نَصْرٌ مِّن رَّبِّــكَ لَيَقُولُنَّ إِنَّا كُنَّا مَعَكُمُؐ; أَوَلَيْــسَ ۰للَّهُ بِأَعْلَمَ بِمَا فِى صُدُورۣ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 10, 'وَلَيَعْلَمَــنَّ ۰للَّهُ ۴لذِيــنَ ءَامَنُواْ وَلَيَعْلَمَــنَّ ۰لْمُنَـٰفِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 11, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ لِلذِيــنَ ءَامَنُواْ èتَّبِعُواْ سَبِيلَنَا وَڤْنَحْمِــلْ خَطَـٰيۭـٰكُمْؐ وَمَا هُم بِحَـٰمِلِينَ مِنْ خَطَـٰيۭـٰهُم مِّــن شَيْءٖؐ اِنَّهُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 12, 'وَڤَيَحْمِلُنَّ أَثْقَالَهُمْ وَأَثْقَالًا مَّعَ أَثْقَالِهِمْؐ وَلَيُسْـَٔلُنَّ يَوْمَ ۰لْقِيَـٰمَةِ 407 عَمَّا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 13, 'وَلَقَدَ اَرْسَلْنَا نُوحاٗ اِلَيٰ قَوْمِهِ” فَلَبِثَ فِيهِمُ; أَلْفَ سَنَةٖ اِلاَّ خَمْسِيــنَ عَاماً فَأَخَذَهُمُ ۴لطُّوفَانُ وَهُمْ ظَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 14, 'فَأَنجَيْنَـٰهُ وَأَصْحَـٰبَ ۰لسَّفِينَةِؐ وَجَعَلْنَـٰهَآ ءَايَةً لِّلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 15, 'وَإِبْرَ؛هِيمَ إِذْ قَالَ لِقَوْمِهِ ۹عْبُدُواْ ۴للَّهَ وَاتَّقُوهُؐ ذَ؛لِكُمْ خَيْرٌ لَّكُمُ; إِن كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 16, 'إِنَّمَا تَعْبُدُونَ مِن دُونِ ۱للَّهِ أَوْثَـٰناً وَتَخْلُقُونَ إِفْكاٗؐ اِنَّ ۰لذِينَ تَعْبُدُونَ مِن دُونِ ۱للَّهِ لاَ يَمْلِكُونَ لَكُمْ رۣزْقاًؐ فَابْتَغُواْ عِندَ ۰للَّهِ ۱لرّۣزْقَؐ وَاعْبُدُوهُؐ وَاشْكُرُواْ لَهُؐ; إِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 17, 'وَإِن تُكَذِّبُواْ فَقَدْ كَذَّبَ ٱُمَمٌ مِّن قَبْلِكُمْؐ وَمَا عَلَــي ۰لرَّسُولِ إِلاَّ ۰لْبَچَغُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 18, 'أَوَلَمْ يَرَوْاْ كَيْفَ يُبْدِﻯُٔ ۴للَّهُ ۴لْخَلْقَؐ ثُمَّ يُعِيدُهُؐ; إِنَّ ذَ؛لِكَ عَلَــي ۰للَّهِ يَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 19, 'قُلْ سِيرُواْ فِى ۱لاَرْضِ فَانظُرُواْ كَيْفَ بَدَأَ ۰لْخَلْقَؐ ثُمَّ ۰للَّهُ يُنشِىُٔ ۴لنَّشْأَةَ ۰لاَخِرَةَؐ إِنَّ ۰للَّهَ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 20, 'يُعَذِّبُ مَنْ يَّشَآءُ وَيَرْحَمُ مَنْ يَّشَآءُؐ وَإِلَيْهِ تُقْلَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 21, 'وَمَآ أَنتُم بِمُعْجِزۣينَ فِى ۱لاَرْضِ وَلاَ فِى ۱لسَّمَآءِؐ وَمَا لَكُم مِّن دُونِ ۱للَّهِ مِنْ وَّلِيٍّ 408 وَلاَ نَصِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 22, 'وَالذِيــنَ كَفَرُواْ بِـَٔايَـٰتِ ۱للَّهِ وَلِقَآئِهِ“ ٱُوْلَئِــكَ يَـئِسُواْ مِن رَّحْمَتِىؐ وَٱُوْلَئِــكَ لَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 23, 'فَمَا كَانَ جَوَابَ قَوْمِهِ“ إِلٓاَّ أَن قَالُواْ ۶قْتُلُوهُ أَوْ حَرّۣقُوهُؐ فَأَنجۭيٰهُ ۴للَّهُ مِنَ ۰لنّۭارۣؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 24, 'وَقَالَ إِنَّمَا "تَّخَذتُّم مِّن دُونِ ۱للَّهِ أَوْثَـٰناً مَّوَدَّةَۢ بَيْنَكُمْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ ثُمَّ يَوْمَ ۰لْقِيَـٰمَةِ يَكْفُرُ بَعْضُكُم بِبَعْضٍ وَيَلْعَـنُ بَعْضُكُم بَعْضاًؐ وَمَأْوۭيٰكُمُ ۴لنَّارُ وَمَا لَكُم مِّن نَّـٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 25, '© فَـَٔامَــنَ لَهُ„ لُوطٌؐ وَقَالَ إِنِّى مُهَاجِر٘ اِلَيٰ رَبِّيَؐ إِنَّهُ„ هُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 26, 'وَوَهَبْنَا لَهُ; إِسْحَـٰقَ وَيَعْقُوبَؐ وَجَعَلْنَا فِى ذُرّۣيَّتِهِ ۱لنُّبُوٓءَةَ وَالْكِتَـٰبَؐ وَءَاتَيْنَـٰهُ أَجْرَهُ„ فِى ۱لدُّنْيۭاؐ وَإِنَّهُ„ فِى ۱لاَخِرَةِ لَمِــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 27, 'وَلُوطاٗ اِذْ قَالَ لِقَوْمِهِ“ إِنَّكُمْ لَتَاتُونَ ۰ڤْفَـٰحِشَةَ مَا سَبَقَكُم بِهَا مِنَ اَحَدٍ مِّــنَ ۰لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 28, 'أَئنَّكُمْ لَتَاتُونَ ۰لرّۣجَالَ وَتَقْطَعُونَ ۰لسَّبِيــلَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 29, 'وَتَاتُونَ فِى نَادِيكُمُ ۴لْمُنكَرَؐ فَمَا كَانَ جَوَابَ قَوْمِهِ“ إِلٓاَّ أَن قَالُواْ èيتِنَا بِعَذَابِ ۱للَّهِ إِن كُنتَ مِنَ 409 ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 30, 'قَالَ رَبِّ ۹نصُرْنِى عَلَــي ۰لْقَوْمِ ۱لْمُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 31, 'وَلَمَّا جَآءَتْ رُسُلُنَآ إِبْرَ؛هِيمَ بِالْبُشْرۭيٰ قَالُوٓاْ إِنَّا مُهْلِكُوٓاْ أَهْلِ هَـٰذِهِ ۱لْقَرْيَةِ إِنَّ أَهْلَهَا كَانُواْ ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 32, 'قَالَ إِنَّ فِيهَا لُوطاًؐ قَالُواْ نَحْــنُ أَعْلَمُ بِمَن فِيهَاؐ ڤَنُنَجِّيَــنَّهُ„ وَأَهْلَهُ; إِلاَّ "مْرَأَتَهُ„ كَانَــتْ مِــنَ ۰لْغَـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 33, 'وَلَمَّآ أَن جَآءَتتتْ رُسُلُنَا لُوطاً سـ۬ـىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعاًؐ وَقَالُواْ لاَ تَخَفْ وَلاَ تَحْزَنِ اِنَّا مُنَجُّوكككَ وَأَهْلَــكَ إِلاَّ "مْرَأَتَــكَ كَانَتْ مِــنَ ۰لْغَـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 34, 'إِنَّا مُنزۣلُونَ عَلَــيٰٓ أَهْلِ هَـٰذِهِ ۱لْقَرْيَةِ رۣجْزاً مِّــنَ ۰لسَّمَآءِ بِمَا كَانُواْ يَفْسُقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 35, 'وَلَقَد تَّرَكْنَا مِنْهَآ ءَايَةَۢ بَيِّنَةً لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 36, 'وَإِلَــيٰ مَدْيَــنَ أَخَاهُمْ شُعَيْباً فَقَالَ يَـٰقَوْمِ ۹عْبُدُواْ ۴للَّهَ وَارْجُواْ ۴لْيَوْمَ ۰لاَخِرَ وَلاَ تَعْثَوْاْ فِى ۱لاَرْضِ مُفْسِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 37, 'فَكَذَّبُوهُ فَأَخَذَتْهُمُ ۴لرَّجْفَةُ فَأَصْبَحُواْ فِى دۭارۣهِمْ جَـٰثِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 38, 'وَعَاداً وَثَمُوداً وَقَد تَّبَيَّــنَ لَكُم مِّــن مَّسَـٰكِنِهِمْ وَزَيَّنَ لَهُمُ ۴لشَّيْطَـٰـــنُ أَعْمَـٰلَهُمْ فَصَدَّهُمْ عَـنِ ۱لسَّبِيلِ وَكَانُواْ مُسْتَبْصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 39, 'وَقَارُونَ وَفِرْعَوْنَ وَهَامَـٰنَؐ وَلَقَدْ جَآءَهُم 410 مُّوسۭيٰ بِالْبَيِّنَـٰــتِ فَاسْتَكْبَرُواْ فِى ۱لاَرْضِ وَمَا كَانُواْ سَـٰبِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 40, 'فَكُلٗاّ اَخَذْنَا بِذَنۢبِهِؐ” فَمِنْهُم مَّنَ اَرْسَلْنَا عَلَيْهِ حَاصِباًؐ وَمِنْهُم مَّــنَ اَخَذَتْهُ ۴ڤصَّيْحَةُؐ وَمِنْهُم مَّــنْ خَسَفْنَا بِهِ ۱لاَرْضَؐ وَمِنْهُم مَّــنَ اَغْرَقْنَاؐ وَمَا كَانَ ۰للَّهُ لِيَظْلِمَهُمْؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 41, 'مَثَـلُ ۴لذِيــنَ "تَّخَذُواْ مِن دُونِ ۱للَّهِ أَوْلِيَآءَ كَمَثَـلِ ۱لْعَنكَبُوتِ ''تَّخَذَتْ بَيْتاًؐ وَإِنَّ أَوْهَنَ ۰لْبُيُوتِ لَبَيْتُ ۴لْعَنكَبُوتِ لَوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 42, 'إِنَّ ۰للَّهَ يَعْلَمُ مَا تَدْعُونَ مِن دُونِهِ” مِــن شَيْءٍؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 43, 'وَتِلْــكَ ۰لاَمْثَـٰــلُ نَضْرۣبُهَا لِلنَّاسِؐ وَمَا يَعْقِلُهَآ إِلاَّ ۰لْعَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 44, 'خَلَــقَ ۰للَّهُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضَ بِالْحَقﱢّؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَةً لِّلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 45, '۸تْــلُ مَآ ٱُوحِيَ إِلَيْكَ مِنَ ۰لْكِتَـٰــبِ وَأَقِمِ ۱لصَّلَوٰةَؐ إِنَّ ۰لصَّلَوٰةَ تَنْهۭــيٰ عَنِ ۱ڤْفَحْشَآءِ وَالْمُنكَرۣؐ وَلَذِكْرُ ۴للَّهِ أَكْبَرُؐ وَاللَّهُ يَعْلَمُ مَا تَصْنَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 46, '¤ وَلاَ تُجَـٰدِلُوٓاْ أَهْلَ ۰لْكِتَـٰــبِ إِلاَّ بِالتِى هِــيَ أَحْسَنُؐ إِلاَّ ۰لذِينَ ظَلَمُواْ مِنْهُمْؐ وَقُولُوٓاْ ءَامَنَّا بِاﻟـذِىٓ ٱُنزۣلَ إِلَيْنَا وَٱُنزۣلَ إِلَيْكُمْ 411 وَإِچَهُنَا وَإِچَهُكُمْ وَ؛حِدٌ وَنَحْــنُ لَهُ„ مُسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 47, 'وَكَذَ؛لِــكَ أَنزَلْنَآ إِلَيْــكَ ۰لْكِتَـٰـــبَؐ فَالذِيــنَ ءَاتَيْنَـٰهُمُ ۴لْكِتَـٰــبَ يُومِنُونَ بِهِ” وَمِنْ هَـٰٓؤُلآَءِ مَنْ يُّومِنُ بِهِؐ” وَمَا يَجْحَدُ بِـَٔايَـٰتِنَآ إِلاَّ ۰لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 48, 'وَمَا كُنــتَ تَتْلُواْ مِــن قَبْلِهِ” مِن كِتَـٰبٍ وَلاَ تَخُطُّهُ„ بِيَمِينِــكَؐ إِذاً لاَّرْتَابَ ۰لْمُبْطِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 49, 'بَلْ هُوَ ءَايَـٰتٛ بَيِّنَـٰتٌ فِى صُدُورۣ ۱لذِينَ ٱُوتُواْ ۴لْعِلْمَؐ وَمَا يَجْحَدُ بِـَٔايَـٰتِنَآ إِلاَّ ۰لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 50, 'وَقَالُواْ لَوْلآَ ٱُنزۣلَ عَلَيْهِ ءَايَـٰتٌ مِّن رَّبِّهِؐ” قُلِ اِنَّمَا ۰لاَيَـٰتُ عِندَ ۰للَّهِ وَإِنَّمَآ أَنَا نَذِيرٌ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 51, 'اَوَلَمْ يَكْفِهِمُ; أَنَّـآ أَنزَلْنَا عَلَيْــكَ ۰لْكِتَـٰبَ يُتْلۭــيٰ عَلَيْهِمُؐ; إِنَّ فِى ذَ؛لِــكَ لَرَحْمَةً وَذِكْرۭيٰ لِقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 52, 'قُــلْ كَفۭـيٰ بِاللَّهِ بَيْنِى وَبَيْنَكُمْ شَهِيداًؐ يَعْلَمُ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَالذِيــنَ ءَامَنُواْ بِالْبَـٰطِلِ وَكَفَرُواْ بِاللَّهِ ٱُوْلَئِكَ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 53, 'وَيَسْتَعْجِلُونَــكَ بِالْعَذَابِؐ وَلَوْلآَ أَجَــلٌ مُّسَمّيً لَّجَآءَهُمُ ۴لْعَذَابُ وَلَيَاتِيَنَّهُم بَغْتَةً وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 54, 'يَسْتَعْجِلُونَــكَ بِالْعَذَابِؐ وَإِنَّ جَهَنَّمَ ڤَمُحِيطَةٛ بِالْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 55, '412 يَوْمَ يَغْشۭيٰهُمُ ۴لْعَذَابُ مِن فَوْقِهِمْ وَمِــن تَحْتِ أَرْجُلِهِمْ وَيَقُولُ ذُوقُواْ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 56, 'يَـٰعِبَادِيَ ۰لذِينَ ءَامَنُوٓاْ إِنَّ أَرْضِى وَ؛سِعَةٌ فَإِيَّـٰيَ فَاعْبُدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 57, 'كُلُّ نَفْسٍ ذَآئِقَةُ ۴لْمَوْتِؐ ثُمَّ إِلَيْنَا تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 58, 'وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ لَنُبَوّۣيؕنَّهُم مِّنَ ۰لْجَنَّةِ غُرَفاً تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَاؐ نِعْمَ أَجْرُ ۴لْعَـٰمِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 59, '۰لذِينَ صَبَرُواْ وَعَلَيٰ رَبِّهِمْ يَتَوَكَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 60, 'وَكَأَيِّن مِّن دَآبَّةٍ لاَّ تَحْمِلُ رۣزْقَهَا ۰للَّهُ يَرْزُقُهَا وَإِيَّاكُمْؐ وَهُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 61, 'وَلَـئِــن سَأَلْتَهُم مَّــنْ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَسَخَّرَ ۰لشَّمْسَ وَالْقَمَرَ لَيَقُولُــنَّ ۰للَّهُؐ فَأَنّۭيٰ يُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 62, '۰للَّهُ يَبْسُطُ ۴لرّۣزْقَ لِمَنْ يَّشَآءُ مِنْ عِبَادِهِ” وَيَقْدِرُ لَهُؐ; إِنَّ ۰للَّهَ بِكُــلّۣ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 63, 'وَلَـئِــن سَأَلْتَهُم مَّن نَّزَّلَ مِــنَ ۰لسَّمَآءِ مَآءً فَأَحْيۭا بِهِ ۱لاَرْضضضَ مِـنۢ بَعْدِ مَوْتِهَا لَيَقُولُــنَّ ۰للَّهُؐ قُـلِ ۱لْحَمْدُ لِلهِؐ بَــلَ اَكْثَرُهُمْ لاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 64, 'وَمَا هَـٰذِهِ ۱لْحَيَوٰةُ ۴لدُّنْيۭآ إِلاَّ لَهْوٌ وَلَعِبٌؐ وَإِنَّ ۰لدَّارَ ۰لاَخِرَةَ لَهِــيَ ۰لْحَيَوَانُ لَوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 65, 'فَإِذَا رَكِبُواْ 41 فِى ۱لْفُلْكِ دَعَوُاْ ۴للَّهَ مُخْلِصِيــنَ لَهُ ۴لدِّينَؐ فَلَمَّا نَجّۭيٰهُمُ; إِلَي ۰لْبَرّۣ إِذَا هُمْ يُشْرۣكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 66, 'لِيَكْفُرُواْ بِمَآ ءَاتَيْنَـٰهُمْؐ وَلِيَتَمَتَّعُواْ فَسَوْفَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 67, 'أَوَلَمْ يَرَوَاْ اَنَّا جَعَلْنَا حَرَماٗ —امِناً وَيُتَخَطَّفُ ۴لنَّاسُ مِنْ حَوْلِهِمُؐ; أَفَبِالْبَـٰطِلِ يُومِنُونَ وَبِنِعْمَةِ ۱للَّهِ يَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 68, 'وَمَنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباٗ اَوْ كَذَّبَ بِالْحَــقّۣ لَمَّا جَآءَهُؐ; أَلَيْسَ فِى جَهَنَّمَ مَثْويً لِّلْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (29, 69, 'وَالذِينَ جَـٰهَدُواْ فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَاؐ وَإِنَّ ۰للَّهَ لَمَعَ ۰ڤْمُحْسِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓم؋ّٓؐ غُلِبَتِ ۱لرُّومُ فِىٓ أَدْنَــي ۰لاَرْضِ وَهُم مِّـنۢ بَعْدِ غَلَبِهِمْ سَيَغْلِبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 2, 'فِى بِضْعِ سِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 3, 'لِلهِ ۱لاَمْرُ مِن قَبْلُ وَمِـنۢ بَعْدُؐ وَيَوْمَئِذٍ يَفْرَحُ ۴لْمُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 4, 'بِنَصْرۣ ۱للَّهِؐ يَنصُرُ مَنْ يَّشَآءُؐ وَهُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 5, 'وَعْدَ ۰للَّهِ لاَ يُخْلِفُ ۴للَّهُ وَعْدَهُؐ„ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَؐ 414');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 6, 'يَعْلَمُونَ ظَـٰهِراً مِّــنَ ۰لْحَيَوٰةِ ۱لدُّنْيۭا وَهُمْ عَـنِ ۱لاَخِرَةِ هُمْ غَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 7, 'أَوَلَمْ يَتَفَكَّرُواْ فِىٓ أَنفُسِهِمؐ مَّا خَلَــقَ ۰للَّهُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضَ وَمَا بَيْنَهُمَآ إِلاَّ بِالْحَقِّ وَأَجَــلٍ مُّسَمّيًؐ وَإِنَّ كَثِيراً مِّــنَ ۰لنَّاسِ بِلِقَآءِ رَبِّهِمْ لَكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 8, '© أَوَلَمْ يَسِيرُواْ فِى ۱لاَرْضِ فَيَنظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِينَ مِــن قَبْلِهِمْ كَانُوٓاْ أَشَدَّ مِنْهُمْ قُوَّةً وَأَثَارُواْ ۴لاَرْضَؐ وَعَمَرُوهَآ أَكْثَرَ مِمَّا عَمَرُوهَا وَجَآءَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰتِؐ فَمَا كَانَ ۰للَّهُ لِيَظْلِمَهُمْؐ وَچَكِــن كَانُوٓاْ أَنفُسَهُمْ يَظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 9, 'ثُمَّ كَانَ عَـٰقِبَةُ ۴لذِيــنَ أَسَـٰٓـُٔواْ ۴لسُّوٓأۭيٰٓ أَننن كَذَّبُواْ بِـَٔايَـٰــتِ ۱للَّهِ وَكَانُواْ بِهَا يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 10, '۰للَّهُ يَبْدَؤُاْ ۴لْخَلْــقَ ثُمَّ يُعِيدُهُ„ ثُمَّ إِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 11, 'وَيَوْمَ تَقُومُ ۴لسَّاعَةُ يُبْلِسُ ۴ڤْمُجْرۣمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 12, 'وَلَمْ يَكُــن لَّهُم مِّــن شُرَكَآئِهِمْ شُفَعَـٰٓؤُاْ وَكَانُواْ بِشُرَكَآئِهِمْ كۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 13, 'وَيَوْمَ تَقُومُ ۴لسَّاعَةُ يَوْمَئِذٍ يَتَفَرَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 14, 'فَأَمَّا ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ فَهُمْ فِى رَوْضَةٍ يُحْبَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 15, 'وَأَمَّا ۰لذِيــنَ كَفَرُواْ وَكَذَّبُواْ 415 بِـَٔايَـٰتِنَا وَلِقَآءِ ۱لاَخِرَةِ فَٱُوْلَئِــكَ فِى ۱لْعَذَابِ مُحْضَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 16, 'فَسُبْحَـٰــنَ ۰للَّهِ حِيــنَ تُمْسُونَ وَحِيــنَ تُصْبِحُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 17, 'وَلَهُ ۴لْحَمْدُ فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ وَعَشِيّاً وَحِيــنَ تُظْهِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 18, 'يُخْرۣجُ ۴لْحَيَّ مِنَ ۰لْمَيِّــتِ وَيُخْرۣجُ ۴لْمَيِّتَ مِــنَ ۰لْحَيِّ وَيُحْىِ ۱لاَرْضضضَ بَعْدَ مَوْتِهَاؐ وَكَذَ؛لِــكَ تُخْرَجُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 19, 'وَمِــنَ —ايَـٰتِهِ“ أَنْ خَلَقَكُم مِّن تُرَابٍ ثُمَّ إِذَآ أَنتُم بَشَرٌ تَنتَشِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 20, 'وَمِنَ —ايَـٰتِهِ“ أَنْ خَلَــقَ لَكُم مِّــنَ اَنفُسِكُمُ; أَزْوَ؛جاً لِّتَسْكُنُوٓاْ إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةً وَرَحْمَةٗؐ اِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 21, 'وَمِنَ —ايَـٰتِهِ” خَلْــقُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَاخْتِچَفُ أَلْسِنَتِكُمْ وَأَلْوَ؛نِكُمُؐ; إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٍ لِّلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 22, 'وَمِــنَ —ايَـٰتِهِ” مَنَامُكُم بِاليْلِ وَالنَّهۭارۣ وَابْتِغَآؤُكُم مِّـن فَضْلِهِؐ“ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 23, 'وَمِنَ —ايَـٰتِهِ” يُرۣيكُمُ ۴لْبَرْقَ خَوْفاً وَطَمَعاً وَيُنَزّۣلُ مِــنَ ۰لسَّمَآءِ مَآءً فَيُحْىِ” بِهِ ۱لاَرْضضضَ بَعْدَ مَوْتِهَآؐ إِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 24, 'وَمِــنَ —ايَـٰتِهِ“ أَن تَقُومَ ۰لسَّمَآءُ وَالاَرْضُ 416 بِأَمْرۣهِؐ” ثُمَّ إِذَا دَعَاكُمْ دَعْوَةً مِّــنَ ۰لاَرْضضضِ إِذَآ أَنتُمْ تَخْرُجُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 25, 'وَلَهُ„ مَن فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِؐ كُلٌّ لَّهُ„ قَـٰنِتُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 26, 'وَهُوَ ۰ﻟ﮲ يَبْدَؤُاْ ۴لْخَلْقَ ثُمَّ يُعِيدُهُ„ وَهُوَ أَهْوَنننُ عَلَيْهِؐ وَلَهُ ۴لْمَثَــلُ ۴لاَعْلۭيٰ فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 27, 'ضَرَبَ لَكُم مَّثَلًا مِّــنَ اَنفُسِكُمْ هَــل لَّكُم مِّن مَّا مَلَكَتَ اَيْمَـٰنُكُم مِّــن شُرَكَآءَ فِى مَا رَزَقْنَـٰكُمْ فَأَنتُمْ فِيهِ سَوَآءٌ تَخَافُونَهُمْ كَخِيفَتِكُمُ; أَنفُسَكُمْؐ كَذَ؛لِــكَ نُفَصِّلُ ۴لاَيَـٰــتِ لِقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 28, 'بَلِ ''تَّبَعَ ۰لذِيــنَ ظَلَمُوٓاْ أَهْوَآءَهُم بِغَيْرۣ عِلْمٍؐ فَمَـنْ يَّهْدِى مَــنَ اَضَــلَّ ۰للَّهُؐ وَمَا لَهُم مِّــن نَّـٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 29, '¥ فَأَقِمْ وَجْهَــكَ لِلدِّيــنۣ حَنِيفاً فِطْرَتَ ۰للَّهِ ۱لتِى فَطَرَ ۰لنَّاسسسَ عَلَيْهَا لاَ تَبْدِيــلَ لِـخَلْـقِ ۱للَّهِ ذَ؛لِكَ ۰لدِّيــنُ ۴لْقَيِّمُ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 30, 'مُنِيبِينَ إِلَيْهِ وَاتَّقُوهُ وَأَقِيمُواْ ۴لصَّلَوٰةَ وَلاَ تَكُونُواْ مِــنَ ۰لْمُشْرۣكِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 31, 'مِــنَ ۰لذِينَ فَرَّقُواْ دِينَهُمْ وَكَانُواْ شِيَعاًؐ كُلُّ حِزْبٙ بِمَا لَدَيْهِمْ فَرۣحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 32, 'وَإِذَا مَــسَّ ۰لنَّاسسسَ ضُرٌّ دَعَوْاْ رَبَّهُم مُّنِيبِينَ إِلَيْهِؐ 417 ثُمَّ إِذَآ أَذَاقَهُم مِّنْهُ رَحْمَةٗ اِذَا فَرۣيقٌ مِّنْهُم بِرَبِّهِمْ يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 33, 'لِيَكْفُرُواْ بِمَآ ءَاتَيْنَـٰهُمْؐ فَتَمَتَّعُواْ فَسَوْفَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 34, 'أَمَ اَنزَلْنَا عَلَيْهِمْ سُلْطَـٰناً فَهُوَ يَتَكَلَّمُ بِمَا كَانُواْ بِهِ” يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 35, 'وَإِذَآ أَذَقْنَا ۰لنَّاسَ رَحْمَةً فَرۣحُواْ بِهَاؐ وَإِن تُصِبْهُمْ سَيِّيؕةٛ بِمَا قَدَّمَــتَ اَيْدِيهِمُ; إِذَا هُمْ يَقْنَطُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 36, 'أَوَلَمْ يَرَوَاْ اَنَّ ۰للَّهَ يَبْسُطُ ۴لرّۣزْقَ لِمَنْ يَّشَآءُ وَيَقْدِرُؐ إِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 37, 'فَـَٔاتِ ذَا ۰لْقُرْبۭــيٰ حَقَّهُ„ وَالْمِسْكِينَ وَابْــنَ ۰لسَّبِيلِؐ ذَ؛لِكَ خَيْرٌ لِّلذِينَ يُرۣيدُونَ وَجْهَ ۰للَّهِؐ وَٱُوْلَئِــكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 38, 'وَمَآ ءَاتَيْتُم مِّن رّۣباً لِّتُرْبُواْ فِىٓ أَمْوَ؛لِ ۱لنَّاسِ فَلاَ يَرْبُواْ عِندَ ۰للَّهِؐ وَمَآ ءَاتَيْتُم مِّن زَكَوٰةٍ تُرۣيدُونَ وَجْهَ ۰للَّهِ فَٱُوْلَئِــكَ هُمُ ۴لْمُضْعِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 39, '۰للَّهُ ۴ﻟ﮲ خَلَقَكُمْ ثُمَّ رَزَقَكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْؐ هَلْ مِن شُرَكَآئِكُم مَّنْ يَّفْعَلُ مِن ذَ؛لِكُم مِّــن شَيْءٍؐ سُبْحَـٰنَهُ„ وَتَعَـٰلۭــيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 40, 'ظَهَرَ ۰لْفَسَادُ فِى ۱لْبَرّۣ وَاڤْبَحْرۣ بِمَا كَسَبَتَ اَيْدِى ۱لنَّاسِ 418 لِيُذِيقَهُم بَعْضَ ۰ﻟ﮲ عَمِلُواْ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 41, 'قُلْ سِيرُواْ فِى ۱لاَرْضِ فَانظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِينَ مِن قَبْــلُؐ كَانَ أَكْثَرُهُم مُّشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 42, 'فَأَقِمْ وَجْهَكَ لِلدِّيـنِ ۱لْقَيِّمِ مِن قَبْلِ أَنْ يَّاتِيَ يَوْمٌ لاَّ مَرَدَّ لَهُ„ مِــنَ ۰للَّهِؐ يَوْمَئِذٍ يَصَّدَّعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 43, 'مَــن كَفَرَ فَعَلَيْهِ كُفْرُهُؐ, وَمَنْ عَمِــلَ صَـٰڤِحاً فَلَأِنفُسِهِمْ يَمْهَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 44, 'ڤِيَجْـزۣيَ ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ مِن فَضْلِهِؐ“ إِنَّهُ„ لاَ يُحِبُّ ۴لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 45, 'وَمِــنَ —ايَـٰتِهِ“ أَنْ يُّرْسِلَ ۰لرّۣيَاحَ مُبَشِّرَ؛تٍ وَلِيُذِيقَكُم مِّن رَّحْمَتِهِ” وَڤِتَجْرۣيَ ۰لْفُلْــكُ بِأَمْرۣهِ” وَلِتَبْتَغُواْ مِـن فَضْلِهِ” وَلَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 46, 'وَلَقَدَ اَرْسَلْنَا مِــن قَبْلِــكَ رُسُلٗا اِلَيٰ قَوْمِهِمْ فَجَآءُوهُم بِالْبَيِّنَـٰتِ فَانتَقَمْنَا مِنَ ۰لذِيــنَ أَجْرَمُواْؐ وَكَانَ حَقّاٗ عَلَيْنَا نَصْرُ ۴لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 47, '۰للَّهُ ۴ﻟ﮲ يُرْسِلُ ۴لرّۣيَـٰحَ فَتُثِيرُ سَحَاباً فَيَبْسُطُهُ„ فِى ۱لسَّمَآءِ كَيْفَ يَشَآءُ وَيَجْعَلُهُ„ كِسَفاً فَتَرَي ۰لْوَدْقَ يَخْرُجُ مِنْ خِچَلِهِؐ” فَإِذَآ أَصَابَ بِهِ” مَنْ يَّشَآءُ مِنْ عِبَادِهِ“ إِذَا هُمْ يَسْتَبْشِرُونَؐ 419');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 48, 'وَإِن كَانُواْ مِــن قَبْـلِ أَنْ يُّنَزَّلَ عَلَيْهِم مِّــن قَبْلِهِ” لَمُبْلِسِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 49, 'فَانظُرۣ اِلَيٰٓ أَثَرۣ رَحْمَــتِ ۱للَّهِ كَيْفَ يُحْىِ ۱لاَرْضضضَ بَعْدَ مَوْتِهَآؐ إِنَّ ذَ؛لِــكَ ڤَمُحْىِ ۱لْمَوْتۭيٰؐ وَهُوَ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 50, 'وَلَئِنَ اَرْسَلْنَا رۣيحاً فَرَأَوْهُ مُصْفَرّاً لَّظَلُّواْ مِـنۢ بَعْدِهِ” يَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 51, 'فَإِنَّــكَ لاَ تُسْمِعُ ۴لْمَوْتۭيٰ وَلاَ تُسْمِعُ ۴لصُّمَّ ۰لدُّعَآءَ اۭذَا وَلَّوْاْ مُدْبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 52, 'وَمَآ أَنتَ بِهَـٰدِ ۱لْعُمْيِ عَن ضَچَلَتِهِمُؐ; إِن تُسْمِعُ إِلاَّ مَنْ يُّومِنُ بِـَٔايَـٰتِنَا فَهُم مُّسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 53, '© ۰للَّهُ ۴ﻟ﮲ خَلَقَكُم مِّــن ضُعْفٍ ثُمَّ جَعَلَ مِنۢ بَعْدِ ضُعْفٍ قُوَّةً ثُمَّ جَعَلَ مِنۢ بَعْدِ قُوَّةٍ ضُعْفاً وَشَيْبَةًؐ يَخْلُــقُ مَا يَشَآءُؐ وَهُوَ ۰لْعَلِيمُ ۴لْقَدِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 54, 'وَيَوْمَ تَقُومُ ۴لسَّاعَةُ يُقْسِمُ ۴ڤْمُجْرۣمُونَ مَا لَبِثُواْ غَيْرَ سَاعَةٍؐ كَذَ؛لِــكَ كَانُواْ يُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 55, 'وَقَالَ ۰لذِينَ ٱُوتُواْ ۴لْعِلْمَ وَالِايمَـٰــنَ لَقَدْ لَبِثْتُمْ فِى كِتَـٰبِ ۱للَّهِ إِلَيٰ يَوْمِ ۱لْبَعْثِؐ فَهَـٰذَا يَوْمُ ۴لْبَعْــثِ وَچَكِنَّكُمْ كُنتُمْ لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 56, 'فَيَوْمَئِذٍ لاَّ تَنفَعُ ۴لذِيــنَ ظَلَمُواْ مَعْذِرَتُهُمْ وَلاَ هُمْ يُسْتَعْتَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 57, 'وَلَقَد ضَّرَبْنَا لِلنَّاسِ فِى هَـٰذَا ۰لْقُرْءَانِ 420 مِــن كُــلّۣ مَثَلٍؐ وَلَـئِن جِيؔتَهُم بِـَٔايَةٍ لَّيَقُولَــنَّ ۰لذِيــنَ كَفَرُوٓاْ إِنَ اَنتُمُ; إِلاَّ مُبْطِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 58, 'كَذَ؛لِكَ يَطْبَعُ ۴للَّهُ عَلَيٰ قُلُوبِ ۱لذِيــنَ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (30, 59, 'فَاصْبِـرۣؐ اِنَّ وَعْدَ ۰للَّهِ حَقٌّؐ وَلاَ يَسْتَخِفَّنَّكَ ۰لذِينَ لاَ يُوقِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ أَلَٓم؋ّٓؐ تِلْكَ ءَايَـٰتُ ۴لْكِتَـٰبِ ۱لْحَكِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 2, 'هُديً وَرَحْمَةً ڤِّڤْمُحْسِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 3, '۰لذِينَ يُقِيمُونَ ۰لصَّلَوٰةَ وَيُوتُونَ ۰لزَّكَوٰةَ وَهُم بِالاَخِرَةِ هُمْ يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 4, 'ٱُوْلَئِــكَ عَلَــيٰ هُديً مِّن رَّبِّهِمْؐ وَٱُوْلَئِــكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 5, 'وَمِنَ ۰لنَّاسِ مَنْ يَّشْتَرۣى لَهْوَ ۰لْحَدِيثِ لِيُضِلَّ عَن سَبِيـلِ ۱للَّهِ بِغَيْرۣ عِلْمٍ وَيَتَّخِذُهَا هُزُؤاٗؐ ۷وْلَئِــكَ لَهُمْ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 6, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِ ءَايَـٰتُنَا وَلّۭــيٰ مُسْتَكْبِراً كَأَن لَّمْ يَسْمَعْهَا كَأَنَّ فِىٓ ٱُذْنَيْهِ وَقْراًؐ فَبَشِّرْهُ بِعَذَابٖ اَلِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 7, 'اِنَّ ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ لَهُمْ جَنَّـٰتُ ۴لنَّعِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 8, '421 خَـٰلِدِينَ فِيهَاؐ وَعْدَ ۰للَّهِ حَقّاًؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 9, 'خَلَــقَ ۰لسَّمَـٰوَ؛تِ بِغَيْرۣ عَمَدٍؐ تَرَوْنَهَاؐ وَأَلْقۭيٰ فِى ۱لاَرْضِ رَوَ؛سِيَ أَن تَمِيدَ بِكُمْ وَبَثَّ فِيهَا مِــن كُــلّۣ دَآبَّةٍؐ وَأَنزَلْنَا مِنَ ۰لسَّمَآءِ مَآءً فَأَنۢبَتْنَا فِيهَا مِــن كُلِّ زَوْجٍ كَرۣيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 10, 'هَـٰذَا خَلْــقُ ۴للَّهِؐ فَأَرُونِى مَاذَا خَلَــقَ ۰لذِينَ مِن دُونِهِؐ” بَلِ ۱لظَّـٰلِمُونَ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 11, 'وَلَقَدَ —اتَيْنَا لُقْمَـٰنَ ۰لْحِكْمَةَ أَنُ ۶شْكُرْ لِلهِؐ وَمَنْ يَّشْكُرْ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِؐ” وَمَــن كَفَرَ فَإِنَّ ۰للَّهَ غَنِــيّﹲ حَمِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 12, 'وَإِذْ قَالَ لُقْمَـٰنُ لِابْنِهِ” وَهُوَ يَعِظُهُ„ يَـٰبُنَــيّۣ لاَ تُشْرۣكككْ بِاللَّهِؐ إِنَّ ۰لشِّرْكككَ لَظُلْم٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 13, 'وَوَصَّيْنَا ۰لِانسَـٰنَ بِوَ؛لِدَيْهِؐ حَمَلَتْهُ ٱُمُّهُ„ وَهْناٗ عَلَيٰ وَهْنٍؐ وَفِصَـٰلُهُ„ فِى عَامَيْنِؐ أَنُ ۶شْكُرْ لِى وَلِوَ؛لِدَيْكَؐ إِلَيَّ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 14, 'وَإِن جَـٰهَدَ؛كَ عَلَيٰٓ أَن تُشْرۣكككَ بِى مَا لَيْــسَ لَــكَ بِهِ” عِلْمٌ فَلاَ تُطِعْهُمَاؐ وَصَاحِبْهُمَا فِى ۱لدُّنْيۭا مَعْرُوفاًؐ وَاتَّبِعْ سَبِيلَ مَنَ اَنَابَ إِلَيَّؐ ثُمَّ إِلَيَّ مَرْجِعُكُمْ فَٱُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 15, 'يَـٰبُنَيِّ إِنَّهَآ إِن تَكُ مِثْقَالُ حَبَّةٍ 422 مِّنْ خَرْدَلٍ فَتَكُـن فِى صَخْرَةٖ اَوْ فِى ۱لسَّمَـٰوَ؛تِ أَوْ فِى ۱لاَرْضِ يَاتِ بِهَا ۰للَّهُؐ إِنَّ ۰للَّهَ لَطِيف٘ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 16, 'يَـٰبُنَيِّ أَقِمِ ۱لصَّلَوٰةَؐ وَامُرْ بِالْمَعْرُوفِؐ وَانْهَ عَـنِ ۱لْمُنكَرۣؐ وَاصْبِرْ عَلَيٰ مَآ أَصَابَــكَؐ إِنَّ ذَ؛لِكَ مِنْ عَزْمِ ۱لاُمُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 17, 'وَلاَ تُصَـٰعِرْ خَدَّكَ لِلنَّاسِؐ وَلاَ تَمْشِ فِى ۱لاَرْضِ مَرَحاٗؐ اِنَّ ۰للَّهَ لاَ يُحِــبُّ كُــلَّ مُخْتَالٍ فَخُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 18, 'وَاقْصِدْ فِى مَشْيِــكَؐ وَاغْضُضْ مِن صَوْتِــكَؐ إِنَّ أَنكَرَ ۰لاَصْوَ؛تِ لَصَوْتُ ۴لْحَمِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 19, 'أَلَمْ تَرَوَاْ اَنَّ ۰للَّهَ سَخَّرَ لَكُم مَّا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِ وَأَسْبَغَ عَلَيْكُمْ نِعَمَهُ„ ظَـٰهِرَةً وَبَاطِنَةًؐ وَمِــنَ ۰لنَّاسِ مَنْ يُّجَـٰدِلُ فِى ۱للَّهِ بِغَيْرۣ عِلْمٍ وَلاَ هُديً وَلاَ كِتَـٰــبٍ مُّنِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 20, 'وَإِذَا قِيــلَ لَهُمُ èتَّبِعُواْ مَآ أَنزَلَ ۰للَّهُ قَالُواْ بَلْ نَتَّبِعُ مَا وَجَدْنَا عَلَيْهِ ءَابَآءَنَآؐ أَوَلَوْ كَانَ ۰لشَّيْطَـٰنُ يَدْعُوهُمُ; إِلَــيٰ عَذَابببِ ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 21, '¤ وَمَـنْ يُّسْلِمْ وَجْهَهُ; إِلَــي ۰للَّهِ وَهُوَ مُحْسِنٌ فَقَدِ ''سْتَمْسَــكَ بِالْعُرْوَةِ ۱لْوُثْقۭيٰؐ وَإِلَــي ۰للَّهِ عَـٰقِبَةُ ۴لاُمُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 22, 'وَمَــن كَفَرَ فَلاَ يُحْزۣنكَ كُفْرُهُؐ; إِلَيْنَا مَرْجِعُهُمْ 42 فَنُنَبِّيؖهُم بِمَا عَمِلُوٓاْؐ إِنَّ ۰للَّهَ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 23, 'نُمَتِّعُهُمْ قَلِيلًا ثُمَّ نَضْطَرُّهُمُ; إِلَــيٰ عَذَابببٖ غَلِيظٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 24, 'وَلَـئِــن سَأَلْتَهُم مَّــنْ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ لَيَقُولُــنَّ ۰للَّهُؐ قُلِ ۱لْحَمْدُ لِلهِؐ بَــلَ اَكْثَرُهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 25, 'لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ إِنَّ ۰للَّهَ هُوَ ۰لْغَنِــيُّ ۴لْحَمِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 26, 'وَلَوَ اَنَّمَا فِى ۱لاَرْضِ مِن شَجَرَةٖ اَقْچَمٌ وَاڤْبَحْرُ يَمُدُّهُ„ مِـنۢ بَعْدِهِ” سَبْعَةُ أَبْحُرٍ مَّا نَفِدَتْ كَلِمَـٰتُ ۴للَّهِؐ إِنَّ ۰للَّهَ عَزۣيز٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 27, 'مَّا خَلْقُكُمْ وَلاَ بَعْثُكُمُ; إِلاَّ كَنَفْسٍ وَ؛حِدَةٖؐ اِنَّ ۰للَّهَ سَمِيعٛ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 28, 'اَلَمْ تَرَ أَنَّ ۰للَّهَ يُولِجُ ۴ليْلَ فِى ۱لنَّهۭارۣ وَيُولِجُ ۴لنَّهَارَ فِى ۱ليْلِ وَسَخَّرَ ۰لشَّمْسَ وَالْقَمَرَ كُلٌّ يَجْرۣىٓ إِلَيٰٓ أَجَــلٍ مُّسَمّيً وَأَنَّ ۰للَّهَ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 29, 'ذَ؛لِــكَ بِأَنَّ ۰للَّهَ هُوَ ۰لْحَقُّ وَأَنَّ مَا تَدْعُونَ مِن دُونِهِ ۱لْبَـٰطِلُ وَأَنَّ ۰للَّهَ هُوَ ۰لْعَلِــيُّ ۴لْكَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 30, 'أَلَمْ تَرَ أَنَّ ۰لْفُلْــكَ تَجْرۣى فِى ۱ڤْبَحْرۣ بِنِعْمَتِ ۱للَّهِ لِيُرۣيَكُم مِّــنَ —ايَـٰتِهِؐ“ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لِّكُــلّۣ صَبّۭارٍ شَكُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 31, 'وَإِذَا غَشِيَهُم مَّوْجٌ كَالظُّلَــلۣ دَعَوُاْ ۴للَّهَ مُخْلِصِيــنَ لَهُ 424 ۴لدِّيــنَؐ فَلَمَّا نَجّۭيٰهُمُ; إِلَي ۰لْبَرّۣ فَمِنْهُم مُّقْتَصِدٌؐ وَمَا يَجْحَدُ بِـَٔايَـٰتِنَآ إِلاَّ كُلُّ خَتّۭارٍكَفُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 32, 'يَـٰٓأَيُّهَا ۰لنَّاسُ èتَّقُواْ رَبَّكُمْ وَاخْشَوْاْ يَوْماً لاَّ يَجْزۣى وَالِد٘ عَنْ وَّلَدِهِ” وَلاَ مَوْلُود٘ هُوَ جَاز۫ عَنْ وَّالِدِهِ” شَيْـٔاٗؐ اِنَّ وَعْدَ ۰للَّهِ حَقٌّؐ فَلاَ تَغُرَّنَّكُمُ ۴لْحَيَوٰةُ ۴لدُّنْيۭاؐ وَلاَ يَغُرَّنَّكُم بِاللَّهِ ۱لْغَرُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (31, 33, 'إِنَّ ۰للَّهَ عِندَهُ„ عِلْمُ ۴لسَّاعَةِؐ وَيُنَزّۣلُ ۴لْغَيْثَؐ وَيَعْلَمُ مَا فِى ۱لاَرْحَامِؐ وَمَا تَدْرۣى نَفْــسٌ مَّاذَا تَكْسِبُ غَداًؐ وَمَا تَدْرۣى نَفْسٛ بِأَيِّ أَرْضضضٍ تَمُوتُؐ إِنَّ ۰للَّهَ عَلِيم٘ خَبِير٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اَلَٓم؋ّٓؐ تَنزۣيلُ ۴لْكِتَـٰبِ لاَ رَيْــبَ فِيهِ مِن رَّبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 2, 'أَمْ يَقُولُونَ "فْتَرۭيٰهُؐ بَلْ هُوَ ۰لْحَقُّ مِن رَّبِّكَ لِتُنذِرَ قَوْماً مَّآ أَتۭيٰهُم مِّن نَّذِيرٍ مِّن قَبْلِكَ لَعَلَّهُمْ يَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 3, '۰للَّهُ ۴ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍ ثُمَّ "سْتَوۭيٰ عَلَــي ۰لْعَرْشِؐ مَا لَكُم مِّن 425 دُونِهِ” مِنْ وَّلِيٍّ وَلاَ شَفِيعٖؐ اَفَلاَ تَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 4, 'يُدَبِّرُ ۴لاَمْرَ مِــنَ ۰لسَّمَآءِ الَــي ۰لاَرْضِ ثُمَّ يَعْرُجُ إِلَيْهِ فِى يَوْمٍ كَانَ مِقْدَارُهُ; أَلْفَ سَنَةٍ مِّمَّا تَعُدُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 5, 'ذَ؛لِــكَ عَـٰلِمُ ۴لْغَيْبِ وَالشَّهَـٰدَةِ ۱لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 6, '۴ﻟـذِىٓ أَحْسَــنَ كُــلَّ شَيْءٖ خَلَقَهُ„ وَبَدَأَ خَلْقَ ۰لِانسَـٰنِ مِن طِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 7, 'ثُمَّ جَعَــلَ نَسْلَهُ„ مِــن سُچَلَةٍ مِّــن مَّآءٍ مَّهِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 8, 'ثُمَّ سَوّۭيٰهُ وَنَفَخَ فِيهِ مِن رُّوحِهِؐ” وَجَعَلَ لَكُمُ ۴لسَّمْعَ وَالاَبْصَـٰرَ وَالاَفْـِٕدَةَؐ قَلِيلًا مَّا تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 9, 'وَقَالُوٓاْ أَ.ذَا ضَلَلْنَا فِى ۱لاَرْضِ إِنَّا لَفِى خَلْقٍ جَدِيدٙؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 10, 'بَلْ هُم بِلِقَآءِ رَبِّهِمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 11, '© قُلْ يَتَوَفّۭيٰكُم مَّلَكُ ۴لْمَوْتِ ۱ﻟ﮲ وُكِّلَ بِكُمْ ثُمَّ إِلَيٰ رَبِّكُمْ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 12, 'وَلَوْ تَرۭيٰٓ إِذِ ۱ڤْمُجْرۣمُونَ نَاكِسُواْ رُءُوسِهِمْ عِندَ رَبِّهِمْ رَبَّنَآ أَبْصَرْنَا وَسَمِعْنَا فَارْجِعْنَا نَعْمَــلْ صَـٰڤِحاٗ اِنَّا مُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 13, 'وَلَوْ شِيؔنَا ءَلاَتَيْنَا كُلَّ نَفْسٖ هُدۭيٰهَاؐ وَچَكِــنْ حَــقَّ ۰لْقَوْلُ مِنِّى لَأَمْلَأَنَّ جَهَنَّمَ مِنَ ۰لْجِنَّةِ وَالنَّاسِ أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 14, 'فَذُوقُواْ بِمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَآ إِنَّا نَسِينَـٰكُمْؐ 426 وَذُوقُواْ عَذَابَ ۰لْخُلْدِ بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 15, 'إِنَّمَا يُومِـنُ بِـَٔايَـٰتِنَا ۰لذِينَ إِذَا ذُكِّرُواْ بِهَا خَرُّواْ سُجَّداً وَسَبَّحُواْ بِحَمْدِ رَبِّهِمْ وَهُمْ لاَ يَسْتَكْبِرُونَؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 16, 'تَتَجَافۭيٰ جُنُوبُهُمْ عَـنِ ۱لْمَضَاجِعِ يَدْعُونَ رَبَّهُمْ خَوْفاً وَطَمَعاً وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 17, 'فَلاَ تَعْلَمُ نَفْــسٌ مَّآ ٱُخْفِيَ لَهُم مِّن قُرَّةِ أَعْيُنٍ جَزَآءَۢ بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 18, 'أَفَمَن كَانَ مُومِناً كَمَن كَانَ فَاسِقاًؐ لاَّ يَسْتَوُﹼنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 19, 'أَمَّا ۰لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ فَلَهُمْ جَنَّـٰتُ ۴لْمَأْوۭيٰ نُزُلَۢا بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 20, 'وَأَمَّا ۰لذِينَ فَسَقُواْ فَمَأْوۭيٰهُمُ ۴لنَّارُؐ كُلَّمَآ أَرَادُوٓاْ أَنْ يَّخْرُجُواْ مِنْهَآ ٱُعِيدُواْ فِيهَا وَقِيلَ لَهُمْ ذُوقُواْ عَذَابَ ۰لنّۭارۣ ۱ﻟ﮲ كُنتُم بِهِ” تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 21, 'وَلَنُذِيقَنَّهُم مِّــنَ ۰لْعَذَابِ ۱لاَدْنۭيٰ دُونَ ۰لْعَذَابِ ۱لاَكْبَرۣ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 22, 'وَمَــنَ اَظْلَمُ مِمَّــن ذُكِّرَ بِـَٔايَـٰتِ رَبِّهِ” ثُمَّ أَعْرَضضضَ عَنْهَآؐ إِنَّا مِــنَ ۰ڤْمُجْرۣمِيــنَ مُنتَقِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 23, 'وَلَقَدَ —اتَيْنَا مُوسَــي ۰لْكِتَـٰــبَؐ فَلاَ تَكُن فِى مِرْيَةٍ مِّن 427 لِّقَآئِهِؐ” وَجَعَلْنَـٰهُ هُديً لِّبَنِىٓ إِسْرَآءِيــلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 24, 'وَجَعَلْنَا مِنْهُمُ; أَئمَّةً يَهْدُونَ بِأَمْرۣنَا لَمَّا صَبَرُواْؐ وَكَانُواْ بِـَٔايَـٰتِنَا يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 25, 'إِنَّ رَبَّــكَ هُوَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ۰لْقِيَـٰمَةِ فِيمَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 26, 'أَوَلَمْ يَهْدِ لَهُمْ كَمَ اَهْلَكْنَا مِن قَبْلِهِم مِّــنَ ۰لْقُرُونِ يَمْشُونَ فِى مَسَـٰكِنِهِمُؐ; إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰــتٖؐ اَفَلاَ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 27, 'أَوَلَمْ يَرَوَاْ اَنَّا نَسُوقُ ۴لْمَآءَ اۭلَــي ۰لاَرْضِ ۱لْجُرُزۣ فَنُخْرۣجُ بِهِ” زَرْعاً تَاكُـلُ مِنْهُ أَنْعَـٰمُهُمْ وَأَنفُسُهُمُؐ; أَفَلاَ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 28, 'وَيَقُولُونَ مَتۭــيٰ هَـٰذَا ۰ڤْفَتْحُ إِننن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 29, 'قُلْ يَوْمَ ۰ڤْفَتْحِ لاَ يَنفَعُ ۴لذِيــنَ كَفَرُوٓاْ إِيمَـٰنُهُمْ وَلاَ هُمْ يُنظَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (32, 30, 'فَأَعْرۣضضضْ عَنْهُمْ وَانتَظِرۣؐ اِنَّهُم مُّنتَظِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ èتَّقِ ۱للَّهَؐ وَلاَ تُطِعِ ۱لْكۭـٰفِـرۣينَ وَالْمُنَـٰفِقِينَؐ إِنَّ ۰للَّهَ كَانَ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 2, 'وَاتَّبِعْ مَا يُوحۭيٰٓ إِلَيْــكَ مِن رَّبِّــكَؐ إِنَّ ۰للَّهَ كَانَ بِمَا تَعْمَلُونَ 428 خَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 3, 'وَتَوَكَّــلْ عَلَــي ۰للَّهِؐ وَكَفۭيٰ بِاللَّهِ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 4, 'مَّا جَعَــلَ ۰للَّهُ لِرَجُلٍ مِّن قَلْبَيْنِ فِى جَوْفِهِؐ” وَمَا جَعَلَ أَزْوَ؛جَكُمُ ۴ﹾ تَظَّهَّرُونَ مِنْهُــنَّ ٱُمَّهَـٰتِكُمْؐ وَمَا جَعَــلَ أَدْعِيَآءَكُمُ; أَبْنَآءَكُمْؐ ذَ؛لِكُمْ قَوْلُكُم بِأَفْوَ؛هِكُمْؐ وَاللَّهُ يَقُولُ ۴لْحَقَّؐ وَهُوَ يَهْدِى ۱لسَّبِيــلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 5, '۸دْعُوهُمْ ءَلِابَآئِهِمْ هُوَ أَقْسَطُ عِندَ ۰للَّهِؐ فَإِن لَّمْ تَعْلَمُوٓاْ ءَابَآءَهُمْ فَإِخْوَ؛نُكُمْ فِى ۱لدِّينِ وَمَوَ؛لِيكُمْؐ وَلَيْــسَ عَلَيْكُمْ جُنَاحٌ فِيمَآ أَخْطَأْتُم بِهِؐ” وَچَكِن مَّا تَعَمَّدَتْ قُلُوبُكُمْؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 6, '۱لنَّبِىٓءُ اَ۬وْلۭـيٰ بِالْمُومِنِينَ مِنَ اَنفُسِهِمْؐ وَأَزْوَ؛جُهُ; ٱُمَّهَـٰتُهُمْؐ وَٱُوْلُواْ ۴لاَرْحَامِ بَعْضُهُمُ; أَوْلۭيٰ بِبَعْـضٍ فِى كِتَـٰبِ ۱للَّهِ مِنَ ۰لْمُومِنِينَ وَاڤْمُهَـٰجِرۣينَ إِلٓاَّ أَن تَفْعَلُوٓاْ إِلَيٰٓ أَوْلِيَآئِكُم مَّعْرُوفاًؐ كَانَ ذَ؛لِكَ فِى ۱لْكِتَـٰبِ مَسْطُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 7, 'وَإِذَ اَخَذْنَا مِــنَ ۰لنَّبِيٓــٕـﯧنَ مِيثَـٰقَهُمْ وَمِنــكَ وَمِن نُّوحٍ وَإِبْرَ؛هِيمَ وَمُوسۭيٰ وَعِيسَي "بْنِ مَرْيَمَؐ وَأَخَذْنَا مِنْهُم مِّيثَـٰقاٗ غَلِيظاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 8, 'لِّيَسْـَٔــلَ ۰لصَّـٰدِقِيــنَ عَن صِدْقِهِمْؐ وَأَعَدَّ لِلْكۭـٰفِـرۣينَ 429 عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 9, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ ۶ذْكُرُواْ نِعْمَةَ ۰للَّهِ عَلَيْكُمُ; إِذْ جَآءَتْكُمْ جُنُودٌ فَأَرْسَلْنَا عَلَيْهِمْ رۣيحاً وَجُنُوداً لَّمْ تَرَوْهَاؐ وَكَانَ ۰للَّهُ بِمَا تَعْمَلُونَ بَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 10, 'اِذْ جَآءُوكُم مِّن فَوْقِكُمْ وَمِــنَ اَسْفَـلَ مِنكُمْؐ وَإِذْ زَاغَتِ ۱لاَبْصَـٰرُ وَبَلَغَتِ ۱لْقُلُوبُ ۴لْحَنَاجِرَ وَتَظُنُّونَ بِاللَّهِ ۱لظُّنُونَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 11, 'هُنَالِــكَ ۸بْتُلِــيَ ۰لْمُومِنُونَ وَزُلْزۣلُواْ زۣلْزَالًا شَدِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 12, 'وَإِذْ يَقُولُ ۴لْمُنَـٰفِقُونَ وَالذِينَ فِى قُلُوبِهِم مَّرَضٌ مَّا وَعَدَنَا ۰للَّهُ وَرَسُولُهُ; إِلاَّ غُرُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 13, 'وَإِذْ قَالَت طَّآئِفَةٌ مِّنْهُمْ يَـٰٓأَهْلَ يَثْرۣبَ لاَ مَقَامَ لَكُمْ فَارْجِعُواْؐ وَيَسْتَـٰذِنُ فَرۣيقٌ مِّنْهُمُ ۴لنَّبِىٓءَ يَقُولُونَ إِنَّ بُيُوتَنَا عَوْرَةٌ وَمَا هِيَ بِعَوْرَةٖؐ اِنْ يُّرۣيدُونَ إِلاَّ فِرَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 14, 'وَلَوْ دُخِلَتْ عَلَيْهِم مِّــنَ اَقْطۭارۣهَا ثُمَّ سُئِلُواْ ۴لْفِتْنَةَ لَأَتَوْهَا وَمَا تَلَبَّثُواْ بِهَآ إِلاَّ يَسِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 15, 'وَلَقَدْ كَانُواْ عَـٰهَدُواْ ۴للَّهَ مِــن قَبْــلُ لاَ يُوَلُّونَ ۰لاَدْبَـٰرَؐ وَكَانَ عَهْدُ ۴للَّهِ مَسْـُٔولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 16, 'قُل لَّنْ يَّنفَعَكُمُ ۴لْفِرَارُ إِن فَرَرْتُم مِّــنَ ۰لْمَوْتِ أَوۣ ۱لْقَتْلِؐ وَإِذاً لاَّ تُمَتَّعُونَ 40 إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 17, 'قُلْ مَن ذَا ۰ﻟ﮲ يَعْصِمُكُم مِّــنَ ۰للَّهِ إِنَ اَرَادَ بِكُمْ سُوٓءاٗ اَوَ اَرَادَ بِكُمْ رَحْمَةًؐ وَلاَ يَجِدُونَ لَهُم مِّن دُونِ ۱للَّهِ وَلِيّاً وَلاَ نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 18, '© قَدْ يَعْلَمُ ۴للَّهُ ۴لْمُعَوّۣقِينَ مِنكُمْ وَالْقَآئِـلِينَ لِإِخْوَ؛نِهِمْ هَلُمَّ إِلَيْنَا وَلاَ يَاتُونَ ۰لْبَأْسَ إِلاَّ قَلِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 19, 'اَشِحَّةٗ عَلَيْكُمْؐ فَإِذَا جَآءَ ۰لْخَوْفُ رَأَيْتَهُمْ يَنظُرُونَ إِلَيْــكَ تَدُورُ أَعْيُنُهُمْ كَاﻟ﮲ يُغْشۭــيٰ عَلَيْهِ مِــنَ ۰لْمَوْتِؐ فَإِذَا ذَهَبَ ۰لْخَوْفُ سَلَقُوكُم بِأَلْسِنَةٖ حِدَادٖ اَشِحَّةٗ عَلَي ۰لْخَيْرۣؐ ٱُوْلَئِــكَ لَمْ يُومِنُواْ فَأَحْبَطَ ۰للَّهُ أَعْمَـٰلَهُمْؐ وَكَانَ ذَ؛لِــكَ عَلَي ۰للَّهِ يَسِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 20, 'يَحْسِبُونَ ۰لاَحْزَابَ لَمْ يَذْهَبُواْؐ وَإِنْ يَّاتِ ۱لاَحْزَابُ يَوَدُّواْ لَوَ اَنَّهُم بَادُونَ فِى ۱لاَعْرَابِؐ يَسْـَٔلُونَ عَــنَ اَنۢبَآئِكُمْ وَلَوْ كَانُواْ فِيكُم مَّا قَـٰتَلُوٓاْ إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 21, 'لَّقَدْ كَانَ لَكُمْ فِى رَسُولِ ۱للَّهِ إِسْوَة٘ حَسَنَةٌ لِّمَــن كَانَ يَرْجُواْ ۴للَّهَ وَالْيَوْمَ ۰لاَخِرَ وَذَكَرَ ۰للَّهَ كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 22, 'وَلَمَّا رَءَا ۰لْمُومِنُونَ ۰لاَحْزَابَ قَالُواْ هَـٰذَا مَا وَعَدَنَا ۰للَّهُ وَرَسُولُهُ„ وَصَدَقققَ ۰للَّهُ وَرَسُولُهُؐ, وَمَا زَادَهُمُ; إِلٓاَّ إِيمَـٰناً وَتَسْلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 23, '41 مِّــنَ ۰لْمُومِنِينَ رۣجَالٌ صَدَقُواْ مَا عَـٰهَدُواْ ۴للَّهَ عَلَيْهِؐ فَمِنْهُم مَّــن قَضۭــيٰ نَحْبَهُ„ وَمِنْهُم مَّنْ يَّنتَظِرُؐ وَمَا بَدَّلُواْ تَبْدِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 24, 'ڤِّيَجْزۣيَ ۰للَّهُ ۴لصَّـٰدِقِينَ بِصِدْقِهِمْ وَيُعَذِّبَ ۰لْمُنَـٰفِقِينَ إِن شَآءَ اوْ يَتُوبَ عَلَيْهِمُؐ; إِنَّ ۰للَّهَ كَانَ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 25, 'وَرَدَّ ۰للَّهُ ۴لذِيــنَ كَفَرُواْ بِغَيْظِهِمْ لَمْ يَنَالُواْ خَيْراًؐ وَكَفَــي ۰للَّهُ ۴لْمُومِنِينَ ۰لْقِتَالَؐ وَكَانَ ۰للَّهُ قَوۣيّاٗ عَزۣيزاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 26, 'وَأَنزَلَ ۰لذِينَ ظَـٰهَرُوهُم مِّــنَ اَهْلِ ۱لْكِتَـٰبِ مِــن صَيَاصِيهِمْ وَقَذَفَ فِى قُلُوبِهِمُ ۴لرُّعْبَؐ فَرۣيقاً تَقْتُلُونَ وَتَاسِرُونَ فَرۣيقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 27, 'وَأَوْرَثَكُمُ; أَرْضَهُمْ وَدِيَـٰرَهُمْ وَأَمْوَ؛لَهُمْ وَأَرْضاً لَّمْ تَطَـُٔوهَاؐ وَكَانَ ۰للَّهُ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 28, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ قُل لَأِّزْوَ؛جِكَ إِن كُنتُنَّ تُرۣدْنَ ۰لْحَيَوٰةَ ۰لدُّنْيۭا وَزۣينَتَهَا فَتَعَالَيْــنَ ٱُمَتِّعْكُنَّ وَٱُسَرّۣحْكُنَّ سَرَاحاً جَمِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 29, 'وَإِننن كُنتُنَّ تُرۣدْنَ ۰للَّهَ وَرَسُولَهُ„ وَالدَّارَ ۰لاَخِرَةَ فَإِنَّ ۰للَّهَ أَعَدَّ ڤِڤْمُحْسِنَـٰتِ مِنكُنَّ أَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 30, 'يَـٰنِسَآءَ ۰لنَّبِىٓءِ مَنْ يَّاتِ مِنكُــنَّ بِفَـٰحِشَةٍ مُّبَيِّنَةٍ يُضَـٰعَفْ لَهَا ۰لْعَذَابُ ضِعْفَيْنِؐ وَكَانننَ ذَ؛لِــكَ عَلَــي ۰للَّهِ يَسِيراًؐ 42');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 31, '¤ وَمَـنْ يَّقْنُتْ مِنكُــنَّ لِلهِ وَرَسُولِهِ” وَتَعْمَــلْ صَـٰڤِحاً نُّوتِهَآ أَجْرَهَا مَرَّتَيْنِ وَأَعْتَدْنَا لَهَا رۣزْقاً كَرۣيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 32, 'يَـٰنِسَآءَ ۰لنَّبِىٓءِ لَسْتُــنَّ كَأَحَدٍ مِّنَ ۰لنِّسَآءِ انِ ''تَّقَيْتُنَّؐ فَلاَ تَخْضَعْنَ بِالْقَوْلِ فَيَطْمَعَ ۰ﻟ﮲ فِى قَلْبِهِ” مَرَضٌ وَقُلْنَ قَوْلًا مَّعْرُوفاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 33, 'وَقَرْنَ فِى بُيُوتِكُنَّؐ وَلاَ تَبَرَّجْنَ تَبَرُّجَ ۰لْجَـٰهِلِيَّةِ ۱لاُولۭيٰؐ وَأَقِمْنَ ۰لصَّلَوٰةَ وَءَاتِينَ ۰لزَّكَوٰةَؐ وَأَطِعْــنَ ۰للَّهَ وَرَسُولَهُؐ; إِنَّمَا يُرۣيدُ ۴للَّهُ لِيُذْهِبَ عَنكُمُ ۴لرّۣجْــسَ أَهْلَ ۰لْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 34, 'وَاذْكُرْنَ مَا يُتْلۭيٰ فِى بُيُوتِكُــنَّ مِـنَ —ايَـٰتِ ۱للَّهِ وَالْحِكْمَةِؐ إِنَّ ۰للَّهَ كَانَ لَطِيفاٗ خَبِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 35, 'اِنَّ ۰لْمُسْلِمِينَ وَالْمُسْلِمَـٰتِ وَالْمُومِنِينَ وَالْمُومِنَـٰتِ وَالْقَـٰنِتِينَ وَالْقَـٰنِتَـٰتِ وَالصَّـٰدِقِينَ وَالصَّـٰدِقَـٰتِ وَالصَّـٰبِـرۣينَ وَالصَّـٰبِرَ؛تِ وَالْخَـٰشِعِينَ وَالْخَـٰشِعَـٰتِ وَالْمُتَصَدِّقِينَ وَالْمُتَصَدِّقَـٰتِ وَالصَّـٰٓئِمِينَ وَالصَّـٰٓئِمَـٰتِ وَالْحَـٰفِظِينَ فُرُوجَهُمْ وَالْحَـٰفِظَـٰتِ وَالذَّ؛كِرۣيــنَ ۰للَّهَ كَثِيراً وَالذَّ؛كِرَ؛تِ أَعَدَّ ۰للَّهُ لَهُم مَّغْفِرَةً وَأَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 36, 'وَمَا كَانَ لِمُومِنٍ وَلاَ مُومِنَةٖ 4 اِذَا قَضَــي ۰للَّهُ وَرَسُولُهُ; أَمْراٗ اَن تَكُونَ لَهُمُ ۴لْخِيَرَةُ مِنَ اَمْرۣهِمْؐ وَمَنْ يَّعْـصِ ۱للَّهَ وَرَسُولَهُ„ فَقَد ضَّــلَّ ضَچَلًا مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 37, 'وَإِذْ تَقُولُ لِلذِىٓ أَنْعَمَ ۰للَّهُ عَلَيْهِ وَأَنْعَمْــتَ عَلَيْهِ أَمْسِــكْ عَلَيْــكَ زَوْجَــكَ وَاتَّقِ ۱للَّهَ وَتُخْفِى فِى نَفْسِــكَ مَا ۰للَّهُ مُبْدِيهِ وَتَخْشَــي ۰لنَّاسَ وَاللَّهُ أَحَقُّ أَن تَخْشۭيٰهُؐ  فَلَمَّا قَضۭيٰ زَيْدٌ مِّنْهَا وَطَراً زَوَّجْنَـٰكَهَا لِكَىْ لاَ يَكُونَ عَلَــي ۰لْمُومِنِينَ حَرَجٌ فِىٓ أَزْوَ؛جِ أَدْعِيَآئِهِمُ; إِذَا قَضَوْاْ مِنْهُنَّ وَطَراًؐ وَكَانَ أَمْرُ ۴للَّهِ مَفْعُولًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 38, 'مَّا كَانَ عَلَــي ۰لنَّبِىٓءِ مِنْ حَرَجٍ فِيمَا فَرَضضضَ ۰للَّهُ لَهُؐ, سُنَّةَ ۰للَّهِ فِى ۱لذِيــنَ خَلَوْاْ مِن قَبْلُؐ وَكَانَ أَمْرُ ۴للَّهِ قَدَراً مَّقْدُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 39, '۱لذِينَ يُبَلِّغُونَ رۣسَـٰچَتِ ۱للَّهِ وَيَخْشَوْنَهُ„ وَلاَ يَخْشَوْنَ أَحَداٗ اِلاَّ ۰للَّهَؐ وَكَفۭيٰ بِاللَّهِ حَسِيباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 40, 'مَّا كَانَ مُحَمَّد٘ اَبَآ أَحَدٍ مِّن رّۣجَالِكُمْؐ وَچَكِن رَّسُولَ ۰للَّهِ وَخَاتِمَ ۰لنَّبِيٓــٕـﯧنَؐ وَكَانَ ۰للَّهُ بِكُــلّۣ شَيْءٖ عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 41, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ ۶ذْكُرُواْ ۴للَّهَ ذِكْراً كَثِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 42, 'وَسَبِّحُوهُ بُكْرَةً وَأَصِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 43, 'هُوَ ۰ﻟ﮲ يُصَلِّى عَلَيْكُمْ وَمَلَئِكَتُهُ„ ڤِيُخْرۣجَكُم 44 مِّــنَ ۰لظُّلُمَـٰتِ إِلَي ۰لنُّورۣؐ وَكَانَ بِالْمُومِنِينَ رَحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 44, 'تَحِيَّتُهُمْ يَوْمَ يَلْقَوْنَهُ„ سَچَمٌؐ وَأَعَدَّ لَهُمُ; أَجْراً كَرۣيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 45, 'يَـٰٓأَيُّهَا ۰لنَّبِىٓءُ اِ۬نَّـآ أَرْسَلْنَـٰــكَ شَـٰهِداً وَمُبَشِّراً وَنَذِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 46, 'وَدَاعِياٗ اِلَــي ۰للَّهِ بِإِذْنِهِ” وَسِرَاجاً مُّنِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 47, 'وَبَشِّرۣ ۱لْمُومِنِينَ بِأَنَّ لَهُم مِّــنَ ۰للَّهِ فَضْلًا كَبِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 48, 'وَلاَ تُطِعِ ۱لْكۭـٰفِـرۣينَ وَالْمُنَـٰفِقِينَؐ وَدَعَ اَذۭيٰهُمْؐ وَتَوَكَّــلْ عَلَــي ۰للَّهِؐ وَكَفۭيٰ بِاللَّهِ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 49, '© يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا نَكَحْتُمُ ۴لْمُومِنَـٰــتِ ثُمَّ طَلَّقْتُمُوهُنَّ مِن قَبْـلِ أَن تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَاؐ فَمَتِّعُوهُنَّ وَسَرّۣحُوهُنَّ سَرَاحاً جَمِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 50, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ اِ۬نَّآ أَحْلَلْنَا لَــكَ أَزْوَ؛جَــكَ ۰لــتِىٓ ءَاتَيْتَ ٱُجُورَهُنَّ وَمَا مَلَكَتْ يَمِينُــكَ مِمَّآ أَفَآءَ ۰للَّهُ عَلَيْــكَ وَبَنَاتِ عَمِّــكَ وَبَنَاتِ عَمَّـٰتِــكَ وَبَنَاتِ خَالِــكَ وَبَنَاتِ خَـٰچَتِــكَ ۰لـــتِى هَاجَرْنَ مَعَــكَ وَامْرَأَةً مُّومِنَةٗ اِنْ وَّهَبَتْ نَفْسَهَا لِلنَّبِىٓءِ انَ اَرَادَ‏ ۰لنَّبِىٓءُ اَ۬نْ يَّسْتَنكِحَهَاؐ خَالِصَةً لَّــكَ مِن دُونِ ۱لْمُومِنِينَؐ قَدْ عَلِمْنَا مَا فَرَضْنَا عَلَيْهِمْ فِىٓ أَزْوَ؛جِهِمْ وَمَا مَلَكَتَ 45 اَيْمَـٰنُهُمْ لِكَيْلاَ يَكُونَ عَلَيْــكَ حَرَجٌؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 51, 'تُرْجىِ مَن تَشَآءُ مِنْهُنَّ وَتُـْٔوۣىٓ إِلَيْــكَ مَــن تَشَآءُؐ وَمَنِ ''بْتَغَيْتَ مِمَّنْ عَزَلْــتَ فَلاَ جُنَاحَ عَلَيْــكَؐ ذَ؛لِــكَ أَدْنۭيٰٓ أَن تَقَرَّ أَعْيُنُهُنَّ وَلاَ يَحْزَنَّ وَيَرْضَيْنَ بِمَآ ءَاتَيْتَهُــنَّ كُلُّهُـنَّؐ وَاللَّهُ يَعْلَمُ مَا فِى قُلُوبِكُمْؐ وَكَانَ ۰للَّهُ عَلِيماٗ حَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 52, 'لاَّ يَحِلُّ لَــكَ ۰لنِّسَآءُ مِنۢ بَعْدُ وَلآَ أَن تَبَدَّلَ بِهِنَّ مِنَ اَزْوَ؛جٍ وَلَوَ اَعْجَبَــكَ حُسْنُهُنَّ إِلاَّ مَا مَلَكَتْ يَمِينُــكَؐ وَكَانَ ۰للَّهُ عَلَــيٰ كُــلّۣ شَيْءٍ رَّقِيباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 53, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَدْخُلُواْ بُيُوتَ ۰لنَّبِىٓءِ الٓاَّ أَنْ يُّوذَنَ لَكُمُ; إِلَــيٰ طَعَامٖ غَيْرَ نَـٰظِرۣينَ إِنۭيٰهُؐ وَچَكِنِ اِذَا دُعِيتُمْ فَادْخُلُواْ فَإِذَا طَعِمْتُمْ فَانتَشِرُواْ وَلاَ مُسْتَـٰنِسِينَ لِحَدِيثٖؐ اِنَّ ذَ؛لِكُمْ كَانَ يُوذى ۱لنَّبِىٓءَ فَيَسْتَحْىِ” مِنكُمْؐ وَاللَّهُ لاَ يَسْتَحْىِ” مِــنَ ۰لْحَقﱢّؐ وَإِذَا سَأَلْتُمُوهُــنَّ مَتَـٰعاً فَسْـَٔلُوهُنَّ مِنْ وَّرَآءِ حِجَابٍؐ ذَ؛لِكُمُ; أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّؐ وَمَا كَانَ لَكُمُ; أَن تُوذُواْ رَسُولَ ۰للَّهِ وَلآَ أَن تَنكِحُوٓاْ أَزْوَ؛جَهُ„ مِـنۢ بَعْدِهِ“ أَبَداٗؐ اِنَّ ذَ؛لِكُمْ كَانَ عِندَ ۰للَّهِ عَظِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 54, '46 اِن تُبْدُواْ شَيْـٔاٗ اَوْ تُخْفُوهُ فَإِنَّ ۰للَّهَ كَانَ بِكُــلّۣ شَيْءٖ عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 55, 'لاَّ جُنَاحَ عَلَيْهِنَّ فِىٓ ءَابَآئِهِنَّ وَلآَ أَبْنَآئِهِنَّ وَلآَ إِخْوَ؛نِهِنَّ وَلآَ أَبْنَآءِ اخْوَ؛نِهِنَّ وَلآَ أَبْنَآءِ اَ۬خَوَ؛تِهِنَّ وَلاَ نِسَآئِهِنَّ وَلاَ مَا مَلَكَتَ اَيْمَـٰنُهُنَّؐ وَاتَّقِيــنَ ۰للَّهَؐ إِنننَّ ۰للَّهَ كَانَ عَلَــيٰ كُــلّۣ شَيْءٍ شَهِيداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 56, 'اِنَّ ۰للَّهَ وَمَلَئِكَتَهُ„ يُصَلُّونَ عَلَــي ۰لنَّبِىٓءِؐ يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ صَلُّواْ عَلَيْهِ وَسَلِّمُواْ تَسْلِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 57, 'اِنَّ ۰لذِينَ يُوذُونَ ۰للَّهَ وَرَسُولَهُ„ لَعَنَهُمُ ۴للَّهُ فِى ۱لدُّنْيۭا وَالاَخِرَةِ وَأَعَدَّ لَهُمْ عَذَاباً مُّهِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 58, 'وَالذِينَ يُوذُونَ ۰لْمُومِنِينَ وَالْمُومِنَـٰــتِ بِغَيْرۣ مَا "كْتَسَبُواْ فَقَدِ ''حْتَمَلُواْ بُهْتَـٰناً وَإِثْماً مُّبِيناًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 59, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ قُل لَأِّزْوَ؛جِــكَ وَبَنَاتِــكَ وَنِسَآءِ ۱لْمُومِنِينَ يُدْنِيــنَ عَلَيْهِنَّ مِن جَچَبِيبِهِنَّؐ ذَ؛لِكَ أَدْنۭيٰٓ أَنْ يُّعْرَفْــنَ فَلاَ يُوذَيْنَؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 60, '¥ لَّئِن لَّمْ يَنتَهِ ۱لْمُنَـٰفِقُونَ وَالذِينَ فِى قُلُوبِهِم مَّرَضٌ وَالْمُرْجِفُونَ فِى ۱لْمَدِينَةِ لَنُغْرۣيَنَّكَ بِهِمْ ثُمَّ لاَ يُجَاوۣرُونَكَ فِيهَآ إِلاَّ قَلِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 61, 'مَّلْعُونِينَؐ أَيْنَمَا ثُقِفُوٓاْ ٱُخِذُواْ وَقُتِّلُواْ تَقْتِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 62, '47 سُنَّةَ ۰للَّهِ فِى ۱لذِيــنَ خَلَوْاْ مِــن قَبْلُؐ وَلَن تَجِدَ لِسُنَّةِ ۱للَّهِ تَبْدِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 63, 'يَسْـَٔلُكَ ۰لنَّاسسسُ عَنِ ۱لسَّاعَةِؐ قُـلِ اِنَّمَا عِلْمُهَا عِندَ ۰للَّهِؐ وَمَا يُدْرۣيــكَؐ لَعَــلَّ ۰لسَّاعَةَ تَكُونُ قَرۣيباٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 64, 'اِنَّ ۰للَّهَ لَعَنَ ۰لْكۭـٰفِـرۣينَ وَأَعَدَّ لَهُمْ سَعِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 65, 'خَـٰلِدِينَ فِيهَآ أَبَداً لاَّ يَجِدُونَ وَلِيّاً وَلاَ نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 66, 'يَوْمَ تُقَلَّبُ وُجُوهُهُمْ فِى ۱لنّۭارۣ يَقُولُونَ يَـٰلَيْتَنَآ أَطَعْنَا ۰للَّهَ وَأَطَعْنَا ۰لرَّسُولؐاَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 67, 'وَقَالُواْ رَبَّنَآ إِنَّآ أَطَعْنَا سَادَتَنَا وَكُبَرَآءَنَا فَأَضَلُّونَا ۰لسَّبِيلؐاَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 68, 'رَبَّنَآ ءَاتِهِمْ ضِعْفَيْنِ مِـنَ ۰لْعَذَابِ وَالْعَنْهُمْ لَعْناً كَثِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 69, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَكُونُواْ كَالذِينَ ءَاذَوْاْ مُوسۭيٰ فَبَرَّأَهُ ۴للَّهُ مِمَّا قَالُواْؐ وَكَانَ عِندَ ۰للَّهِ وَجِيهاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 70, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ وَقُولُواْ قَوْلًا سَدِيداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 71, 'يُصْلِحْ لَكُمُ; أَعْمَـٰلَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْؐ وَمَنْ يُّطِعِ ۱للَّهَ وَرَسُولَهُ„ فَقَدْ فَازَ فَوْزاٗ عَظِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 72, 'اِنَّا عَرَضْنَا ۰لاَمَانَةَ عَلَــي ۰لسَّمَـٰوَ؛تِ وَالاَرْضِ وَالْجِبَالِ فَأَبَيْنَ أَنْ يَّحْمِلْنَهَا وَأَشْفَقْنَ مِنْهَاؐ وَحَمَلَهَا ۰لِانسَـٰنُ 48 إِنَّهُ„ كَانَ ظَلُوماً جَهُولًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (33, 73, 'لِّيُعَذِّبَ ۰للَّهُ ۴لْمُنَـٰفِقِينَ وَالْمُنَـٰفِقَـٰتِ وَالْمُشْرۣكِينَ وَالْمُشْرۣكَـٰتِ وَيَتُوبَ ۰للَّهُ عَلَــي ۰لْمُومِنِينَ وَالْمُومِنَـٰتِؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۱لْحَمْدُ لِلهِ ۱ﻟ﮲ لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَلَهُ ۴لْحَمْدُ فِى ۱لاَخِرَةِؐ وَهُوَ ۰لْحَكِيمُ ۴لْخَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 2, 'يَعْلَمُ مَا يَلِجُ فِى ۱لاَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزۣلُ مِــنَ ۰لسَّمَآءِ وَمَا يَعْرُجُ فِيهَاؐ وَهُوَ ۰لرَّحِيمُ ۴لْغَفُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 3, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ لاَ تَاتِينَا ۰لسَّاعَةُؐ قُلْ بَلۭيٰ وَرَبِّى لَتَاتِيَنَّكُمْؐ عَـٰلِمُ ۴لْغَيْبِ لاَ يَعْزُبُ عَنْهُ مِثْقَالُ ذَرَّةٍ فِى ۱لسَّمَـٰوَ؛تِ وَلاَ فِى ۱لاَرْضِؐ وَلآَ أَصْغَرُ مِــن ذَ؛لِكَ وَلآَ أَكْبَرُ إِلاَّ فِى كِتَـٰــبٍ مُّبِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 4, 'ڤِّيَجْزۣيَ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِؐ ٱُوْلَئِــكَ لَهُم مَّغْفِرَةٌ وَرۣزْقٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 5, 'وَالذِينَ سَعَوْ فِىٓ ءَايَـٰتِنَا مُعَـٰجِزۣينَ ٱُوْلَئِــكَ لَهُمْ عَذَابٌ مِّن رّۣجْز۫ 49 اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 6, 'وَيَرَي ۰لذِينَ ٱُوتُواْ ۴لْعِلْمَ ۰ﻟـذِىٓ ٱُنزۣلَ إِلَيْــكَ مِن رَّبِّــكَ هُوَ ۰لْحَقَّ وَيَهْدِﻯٓ إِلَـيٰ صِرَ؛طِ ۱لْعَزۣيـزۣ ۱لْحَمِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 7, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ هَــلْ نَدُلُّكُمْ عَلَيٰ رَجُلٍ يُنَبِّيؖكُمُ; إِذَا مُزّۣقْتُمْ كُــلَّ مُمَزَّقٖ اِنَّكُمْ لَفِى خَلْقٍ جَدِيدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 8, 'اَفْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباٗ اَم بِهِ” جِنَّةٛؐ بَلِ ۱لذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ فِى ۱لْعَذَابِ وَالضَّچَلِ ۱لْبَعِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 9, 'أَفَلَمْ يَرَوۣاْ اِلَــيٰ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُم مِّــنَ ۰لسَّمَآءِ وَالاَرْضِؐ إِن نَّشَأْ نَخْسِفْ بِهِمُ ۴لاَرْضَ أَوْ نُسْقِطْ عَلَيْهِمْ كِسْفاً مِّــنَ ۰لسَّمَآءِؐ انَّ فِى ذَ؛لِكَ ءَلاَيَةً لِّكُلِّ عَبْدٍ مُّنِيبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 10, '© وَلَقَدَ —اتَيْنَا دَاوُﹼدَ مِنَّا فَضْلًا يَـٰجِبَالُ أَوّۣبِى مَعَهُ„ وَالطَّيْرَؐ وَأَلَنَّا لَهُ ۴لْحَدِيدَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 11, 'أَنِ ''عْمَلْ سَـٰبِغَـٰــتٍ وَقَدِّرْ فِى ۱لسَّرْدِؐ وَاعْمَلُواْ صَـٰڤِحاٗؐ اِنِّى بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 12, 'وَلِسُلَيْمَـٰنَ ۰لرّۣيحَ غُدُوُّهَا شَهْرٌ وَرَوَاحُهَا شَهْرٌؐ وَأَسَلْنَا لَهُ„ عَيْنَ ۰لْقِطْرۣؐ وَمِنَ ۰لْجِــنّۣ مَنْ يَّعْمَلُ بَيْنَ يَدَيْهِ بِإِذْنِ رَبِّهِؐ” وَمَنْ يَّزۣغْ مِنْهُمْ عَنَ اَمْرۣنَا نُذِقْهُ مِــنْ عَذَابِ ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 13, 'يَعْمَلُونَ لَهُ„ مَا يَشَآءُ مِــن مَّحَـٰرۣيبَ وَتَمَـٰثِيلَ وَجِفَانٍ 440 كَالْجَوَابِ” وَقُدُورٍ رَّاسِيَـٰتٖؐ ''عْمَلُوٓاْ ءَالَ دَاوُﹼدَؐ شُكْراًؐ وَقَلِيلٌ مِّنْ عِبَادِيَ ۰لشَّكُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 14, 'فَلَمَّا قَضَيْنَا عَلَيْهِ ۱لْمَوْتَ مَا دَلَّهُمْ عَلَيٰ مَوْتِهِ“ إِلاَّ دَآبَّةُ ۴لاَرْضضضِ تَاكُلُ مِنسَاتَهُؐ, فَلَمَّا خَرَّ تَبَيَّنَتِ ۱لْجِنُّ أَن لَّوْ كَانُواْ يَعْلَمُونَ ۰لْغَيْبَ مَا لَبِثُواْ فِى ۱لْعَذَابِ ۱لْمُهِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 15, 'لَقَدْ كَانَ لِسَبَإٍ فِى مَسَـٰكِنِهِمُ; ءَايَةٌؐ جَنَّتَـٰــنۣ عَنْ يَّمِينٍ وَشِمَالٍؐ كُلُواْ مِن رّۣزْقِ رَبِّكُمْ وَاشْكُرُواْ لَهُؐ, بَلْدَةٌ طَيِّبَةٌ وَرَبّﹲ غَفُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 16, 'فَأَعْرَضُواْ فَأَرْسَلْنَا عَلَيْهِمْ سَيْــلَ ۰لْعَرۣمِؐ وَبَدَّلْنَـٰهُم بِجَنَّتَيْهِمْ جَنَّتَيْنِ ذَوَاتَــيُ ۷كْــل۫ خَمْطٍ وَأَثْلٍ وَشَيْءٍ مِّن سِدْرٍ قَلِيــلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 17, 'ذَ؛لِكَ جَزَيْنَـٰهُم بِمَا كَفَرُواْؐ وَهَلْ يُجَـٰزۭيٰٓ إِلاَّ ۰لْكَفُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 18, 'وَجَعَلْنَا بَيْنَهُمْ وَبَيْنَ ۰لْقُرَي ۰لتِى بَـٰرَكْنَا فِيهَا قُريً ظَـٰهِرَةً وَقَدَّرْنَا فِيهَا ۰لسَّيْرَؐ سِيرُواْ فِيهَا لَيَالِيَ وَأَيَّاماٗ —امِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 19, 'فَقَالُواْ رَبَّنَا بَـٰعِدْ بَيْــنَ أَسْفۭارۣنَا وَظَلَمُوٓاْ أَنفُسَهُمْ فَجَعَلْنَـٰهُمُ; أَحَادِيثَ وَمَزَّقْنَـٰهُمْ كُلَّ مُمَزَّقٖؐ اِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لِّكُــلّۣ صَبّۭارٍ شَكُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 20, 'وَلَقَدْ صَدَقَ عَلَيْهِمُ; إِبْلِيــسُ ظَنَّهُ„ فَاتَّبَعُوهُ إِلاَّ فَرۣيقاً مِّنَ 441 ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 21, 'وَمَا كَانَ لَهُ„ عَلَيْهِم مِّــن سُلْطَـٰــن۫ اِلاَّ لِنَعْلَمَ مَنْ يُّومِـنُ بِالاَخِرَةِ مِمَّنْ هُوَ مِنْهَا فِى شَكّؐ؊ وَرَبُّــكَ عَلَــيٰ كُلِّ شَيْءٖ حَفِيظٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 22, 'قُــلُ ۶دْعُواْ ۴لذِينَ زَعَمْتُم مِّن دُونِ ۱للَّهِؐ لاَ يَمْلِكُونَ مِثْقَالَ ذَرَّةٍ فِى ۱لسَّمَـٰوَ؛تِ وَلاَ فِى ۱لاَرْضِؐ وَمَا لَهُمْ فِيهِمَا مِن شِرْكككٍؐ وَمَا لَهُ„ مِنْهُم مِّــن ظَهِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 23, 'وَلاَ تَنفَعُ ۴لشَّفَـٰعَةُ عِندَهُ; إِلاَّ لِمَنَ اَذِنَ لَهُؐ, حَتَّيٰٓ إِذَا فُزّۣعَ عَــن قُلُوبِهِمْ قَالُواْ مَاذَا قَالَ رَبُّكُمْ قَالُواْ ۴لْحَقَّؐ وَهُوَ ۰لْعَلِيُّ ۴لْكَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 24, '¤ قُلْ مَنْ يَّرْزُقُكُم مِّــنَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضِ قُلِ ۱للَّهُؐ وَإِنَّآ أَوۣ اِيَّاكُمْ لَعَلَــيٰ هُديٗ اَوْ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 25, 'قُل لاَّ تُسْـَٔلُونَ عَمَّآ أَجْرَمْنَا وَلاَ نُسْـَٔــلُ عَمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 26, 'قُلْ يَجْمَعُ بَيْنَنَا رَبُّنَا ثُمَّ يَفْتَحُ بَيْنَنَا بِالْحَقﱢّؐ وَهُوَ ۰لْفَتَّاحُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 27, 'قُلَ اَرُونِــيَ ۰لذِيــنَ أَلْحَقْتُم بِهِ” شُرَكَآءَ كَلؐاَّ بَلْ هُوَ ۰للَّهُ ۴لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 28, 'وَمَآ أَرْسَلْنَـٰــكَ إِلاَّ كَآفَّةً لِّلنَّاسِ بَشِيراً وَنَذِيراًؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 29, 'وَيَقُولُونَ مَتۭيٰ هَـٰذَا ۰لْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 30, 'قُــل لَّكُم مِّيعَادُ يَوْمٍ 442 لاَّ تَسْتَـٰخِرُونَ عَنْهُ سَاعَةً وَلاَ تَسْتَقْدِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 31, 'وَقَالَ ۰لذِينَ كَفَرُواْ لَن نُّومِنَ بِهَـٰذَا ۰لْقُرْءَانِ وَلاَ بِاﻟ﮲ بَيْنَ يَدَيْهِؐ وَلَوْ تَرۭيٰٓ إِذِ ۱لظَّـٰلِمُونَ مَوْقُوفُونَ عِندَ رَبِّهِمْ يَرْجِعُ بَعْضُهُمُ; إِلَيٰ بَعْـضٖ ۱لْقَوْلَؐ يَقُولُ ۴لذِيــنَ ۸سْتُضْعِفُواْ لِلذِينَ "سْتَكْبَرُواْ لَوْلآَ أَنتُمْ لَكُنَّا مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 32, 'قَالَ ۰لذِيـنَ "سْتَكْبَرُواْ لِلذِينَ ۸سْتُضْعِفُوٓاْ أَنَحْــنُ صَدَدْنَـٰكُمْ عَـنِ ۱لْهُدۭيٰ بَعْدَ إِذْ جَآءَكُم بَــلْ كُنتُم مُّجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 33, 'وَقَالَ ۰لذِيــنَ ۸سْتُضْعِفُواْ لِلذِيـنَ "سْتَكْبَرُواْ بَــلْ مَكْرُ ۴ليْلِ وَالنَّهۭارۣ إِذْ تَامُرُونَنَآ أَن نَّكْفُرَ بِاللَّهِ وَنَجْعَلَ لَهُ; أَندَاداًؐ وَأَسَرُّواْ ۴لنَّدَامَةَ لَمَّا رَأَوُاْ ۴لْعَذَابَؐ وَجَعَلْنَا ۰لاَغْچَلَ فِىٓ أَعْنَاقِ ۱لذِيــنَ كَفَرُواْؐ هَلْ يُجْزَوْنَ إِلاَّ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 34, 'وَمَآ أَرْسَلْنَا فِى قَرْيَةٍ مِّن نَّذِير۫ اِلاَّ قَالَ مُتْرَفُوهَآ إِنَّا بِمَآ ٱُرْسِلْتُم بِهِ” كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 35, 'وَقَالُواْ نَحْــنُ أَكْثَرُ أَمْوَ؛لًا وَأَوْچَداً وَمَا نَحْـنُ بِمُعَذَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 36, 'قُلِ اِنَّ رَبِّى يَبْسُطُ ۴لرّۣزْقَ لِمَنْ يَّشَآءُ وَيَقْدِرُؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 37, 'وَمَآ أَمْوَ؛لُكُمْ وَلآَ أَوْچَدُكُم بِالتِى تُقَرّۣبُكُمْ 44 عِندَنَا زُلْفۭيٰٓ إِلاَّ مَــنَ —امَنَ وَعَمِــلَ صَـٰڤِحاً فَٱُوْلَئِــكَ لَهُمْ جَزَآءُ ۴لضِّعْفِ بِمَا عَمِلُواْ وَهُمْ فِى ۱لْغُرُفَـٰتِ ءَامِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 38, 'وَالذِينَ يَسْعَوْنَ فِىٓ ءَايَـٰتِنَا مُعَـٰجِزۣينَ ٱُوْلَئِــكَ فِى ۱لْعَذَابِ مُحْضَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 39, 'قُلِ اِنَّ رَبِّى يَبْسُطُ ۴لرّۣزْقَ لِمَنْ يَّشَآءُ مِنْ عِبَادِهِ” وَيَقْدِرُ لَهُؐ, وَمَآ أَنفَقْتُم مِّــن شَيْءٍ فَهُوَ يُخْلِفُهُؐ, وَهُوَ خَيْرُ ۴لرَّ؛زۣقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 40, 'وَيَوْمَ نَحْشُرُهُمْ جَمِيعاً ثُمَّ نَقُولُ لِلْمَلَئِكَةِ أَهَـٰٓؤُلآَءِ ايَّاكُمْ كَانُواْ يَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 41, 'قَالُواْ سُبْحَـٰنَــكَ أَنتَ وَلِيُّنَا مِن دُونِهِمؐ بَــلْ كَانُواْ يَعْبُدُونَ ۰لْجِــنَّؐ أَكْثَرُهُم بِهِم مُّومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 42, 'فَالْيَوْمَ لاَ يَمْلِــكُ بَعْضُكُمْ لِبَعْضٍ نَّفْعاً وَلاَ ضَرّاً وَنَقُولُ لِلذِيــنَ ظَلَمُواْ ذُوقُواْ عَذَابَ ۰لنّۭارۣ ۱لتِى كُنتُم بِهَا تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 43, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُنَا بَيِّنَـٰتٍ قَالُواْ مَا هَـٰذَآ إِلاَّ رَجُلٌ يُرۣيدُ أَنْ يَّصُدَّكُمْ عَمَّا كَانننَ يَعْبُدُ ءَابَآؤُكُمْ وَقَالُواْ مَا هَـٰذَآ إِلٓاَّ إِفْــكٌ مُّفْتَريًؐ وَقَالَ ۰لذِينَ كَفَرُواْ ڤِڤْحَــقّۣ لَمَّا جَآءَهُمُ; إِنْ هَـٰذَآ إِلاَّ سِحْـرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 44, 'وَمَآ ءَاتَيْنَـٰهُم مِّــن كُتُــبٍ يَدْرُسُونَهَاؐ وَمَآ أَرْسَلْنَآ إِلَيْهِمْ 444 قَبْلَــكَ مِن نَّذِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 45, 'وَكَذَّبَ ۰لذِينَ مِن قَبْلِهِمْ وَمَا بَلَغُواْ مِعْشَارَ مَآ ءَاتَيْنَـٰهُمْؐ فَكَذَّبُواْ رُسُلِىؐ فَكَيْفَ كَانَ نَكِيرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 46, '© قُلِ اِنَّمَآ أَعِظُكُم بِوَ؛حِدَةٖؐ اَن تَقُومُواْ لِلهِ مَثْنۭيٰ وَفُرَ؛دۭيٰ ثُمَّ تَتَفَكَّرُواْؐ مَا بِصَـٰحِبِكُم مِّن جِنَّةٖؐ اِنْ هُوَ إِلاَّ نَذِيرٌ لَّكُم بَيْـنَ ¢ عَذَابٍ شَدِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 47, 'قُــلْ مَا سَأَلْتُكُم مِّنَ اَجْرٍ فَهُوَ لَكُمُؐ; إِنَ اَجْرۣيَ إِلاَّ عَلَــي ۰للَّهِؐ وَهُوَ عَلَيٰ كُــلّۣ شَيْءٍ شَهِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 48, 'قُـلِ اِنَّ رَبِّى يَقْذِفُ بِالْحَقﱢّؐ عَچَّمُ ۴لْغُيُوبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 49, 'قُـلْ جَآءَ ۰لْحَقُّ وَمَا يُبْدِىُٔ ۴لْبَـٰطِلُ وَمَا يُعِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 50, 'قُلِ اِن ضَلَلْتُ فَإِنَّمَآ أَضِــلُّ عَلَيٰ نَفْسِى وَإِنِ ''هْتَدَيْــتُ فَبِمَا يُوحِىٓ إِلَيَّ رَبِّيَؐ إِنَّهُ„ سَمِيعٌ قَرۣيبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 51, 'وَلَوْ تَرۭيٰٓ إِذْ فَزۣعُواْ فَلاَ فَوْتَ وَٱُخِذُواْ مِــن مَّكَانٍ قَرۣيــبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 52, 'وَقَالُوٓاْ ءَامَنَّا بِهِؐ” وَأَنّۭــيٰ لَهُمُ ۴لتَّنَاوُشُ مِن مَّكَانٙ بَعِيدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 53, 'وَقَدْ كَفَرُواْ بِهِ” مِن قَبْلُؐ وَيَقْذِفُونَ بِالْغَيْبِ مِــن مَّكَانٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (34, 54, 'وَحِيلَ بَيْنَهُمْ وَبَيْــنَ مَا يَشْتَهُونَ كَمَا فُعِلَ بِأَشْيَاعِهِم مِّن قَبْلُ إِنَّهُمْ كَانُواْ فِى شَكٍّ مُّرۣيبٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۱لْحَمْدُ لِلهِ فَاطِرۣ ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِ جَاعِـلِ ۱لْمَلَئِكَةِ رُسُلٗا ۷وْلِىٓ أَجْنِحَةٍ مَّثْنۭيٰ وَثُـچَثَ وَرُبَـٰعَؐ يَزۣيدُ فِى ۱لْخَلْــقۣ مَا يَشَآءُؐ اِ۬نَّ ۰للَّهَ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 2, 'مَّا يَفْتَحِ ۱للَّهُ لِلنَّاسِ مِن رَّحْمَةٍ فَلاَ مُمْسِــكَ لَهَاؐ وَمَا يُمْسِــكْ فَلاَ مُرْسِلَ لَهُ„ مِـنۢ بَعْدِهِؐ” وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 3, 'يَـٰٓأَيُّهَا ۰لنَّاسسسُ ۶ذْكُرُواْ نِعْمَتَ ۰للَّهِ عَلَيْكُمْؐ هَلْ مِنْ خَـٰلِــق۫ غَيْرُ ۴للَّهِ يَرْزُقُكُم مِّــنَ ۰لسَّمَآءِ وَالاَرْضضضِؐ لآَ إِچَهَ إِلاَّ هُوَؐ فَأَنّۭيٰ تُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 4, 'وَإِنْ يُّكَذِّبُوكَ فَقَدْ كُذِّبَتْ رُسُــلٌ مِّن قَبْلِــكَؐ وَإِلَــي ۰للَّهِ تُرْجَعُ ۴لاُمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 5, 'يَـٰٓأَيُّهَا ۰لنَّاسُ إِنَّ وَعْدَ ۰للَّهِ حَقٌّؐ فَلاَ تَغُرَّنَّكُمُ ۴لْحَيَوٰةُ ۴لدُّنْيۭاؐ وَلاَ يَغُرَّنَّكُم بِاللَّهِ ۱لْغَرُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 6, 'إِنننَّ ۰لشَّيْطَـٰــنَ لَكُمْ عَدُوٌّ فَاتَّخِذُوهُ عَدُوّاٗؐ اِنَّمَا يَدْعُواْ حِزْبَهُ„ لِيَكُونُواْ مِــنَ اَصْحَـٰبِ ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 7, '۱لذِيــنَ كَفَرُواْ لَهُمْ عَذَابٌ شَدِيدٌؐ وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ 446 ۴ڤصَّـٰڤِحَـٰتِ لَهُم مَّغْفِرَةٌ وَأَجْرٌ كَبِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 8, 'اَفَمَن زُيِّــنَ لَهُ„ سُوٓءُ عَمَلِهِ” فَرۭءۭاهُ حَسَناًؐ فَإِنَّ ۰للَّهَ يُضِلُّ مَنْ يَّشَآءُ وَيَهْدِى مَنْ يَّشَآءُؐ فَلاَ تَذْهَبْ نَفْسُــكَ عَلَيْهِمْ حَسَرَ؛تٖؐ اِنننَّ ۰للَّهَ عَلِيمٛ بِمَا يَصْنَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 9, 'وَاللَّهُ ۴ﻟـذِىٓ أَرْسَلَ ۰لرّۣيَـٰحَ فَتُثِيرُ سَحَاباً فَسُقْنَـٰهُ إِلَيٰ بَلَدٍ مَّيِّتٍ فَأَحْيَيْنَا بِهِ ۱لاَرْضَ بَعْدَ مَوْتِهَاؐ كَذَ؛لِــكَ ۰لنُّشُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 10, 'مَــن كَانَ يُرۣيدُ ۴لْعِزَّةَ فَلِلهِ ۱لْعِزَّةُ جَمِيعاٗؐ اِلَيْهِ يَصْعَدُ ۴لْكَلِمُ ۴لطَّيِّبُؐ وَالْعَمَــلُ ۴لصَّـٰلِحُ يَرْفَعُهُؐ, وَالذِينَ يَمْكُرُونَ ۰لسَّيِّـَٔاتِ لَهُمْ عَذَابٌ شَدِيدٌؐ وَمَكْرُ ٱُوْلَئِــكَ هُوَ يَبُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 11, 'وَاللَّهُ خَلَقَكُم مِّن تُرَابٍ ثُمَّ مِــن نُّطْفَةٍ ثُمَّ جَعَلَكُمُ; أَزْوَ؛جاًؐ وَمَا تَحْمِلُ مِنُ ۷نثۭيٰ وَلاَ تَضَعُ إِلاَّ بِعِلْمِهِؐ” وَمَا يُعَمَّرُ مِــن مُّعَمَّرٍ وَلاَ يُنقَصُ مِنْ عُمُرۣهِ“ إِلاَّ فِى كِتَـٰــبٖؐ اِنَّ ذَ؛لِــكَ عَلَــي ۰للَّهِ يَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 12, 'وَمَا يَسْتَوۣى ۱ڤْبَحْرَ؛نِؐ هَـٰذَا عَذْبٌ فُرَاتٌ سَآئِغٌ شَرَابُهُ„ وَهَـٰذَا مِلْح٘ ۷جَاجٌؐ وَمِن كُــلٍّ تَاكُلُونَ لَحْماً طَرۣيّاً وَتَسْتَخْرۣجُونَ حِلْيَةً تَلْبَسُونَهَاؐ وَتَرَي ۰لْفُلْــكَ فِيهِ مَوَاخِرَ لِتَبْتَغُواْ مِن فَضْلِهِ” وَلَعَلَّكُمْ تَشْكُرُونَؐ 447');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 13, 'يُولِجُ ۴ليْلَ فِى ۱لنَّهۭارۣ وَيُولِجُ ۴لنَّهَارَ فِى ۱ليْلِؐ وَسَخَّرَ ۰لشَّمْسَ وَالْقَمَرَؐ كُلٌّ يَجْرۣى لَأِجَــلٍ مُّسَمّيًؐ ذَ؛لِكُمُ ۴للَّهُ رَبُّكُمْ لَهُ ۴لْمُلْــكُؐ وَالذِيــنَ تَدْعُونَ مِن دُونِهِ” مَا يَمْلِكُونَ مِن قِطْمِيرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 14, 'اِن تَدْعُوهُمْ لاَ يَسْمَعُواْ دُعَآءَكُمْ وَلَوْ سَمِعُواْ مَا "سْتَجَابُواْ لَكُمْؐ وَيَوْمَ ۰لْقِيَـٰمَةِ يَكْفُرُونَ بِشِرْكِكُمْؐ وَلاَ يُنَبِّيؖــكَ مِثْلُ خَبِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 15, '¥ يَـٰٓأَيُّهَا ۰لنَّاسسسُ أَنتُمُ ۴لْفُقَرَآءُ اِ۬لَي ۰للَّهِؐ وَاللَّهُ هُوَ ۰لْغَنِــيُّ ۴لْحَمِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 16, 'إِنْ يَّشَأْ يُذْهِبْكُمْ وَيَاتِ بِخَلْقٍ جَدِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 17, 'وَمَا ذَ؛لِــكَ عَلَــي ۰للَّهِ بِعَزۣيزٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 18, 'وَلاَ تَزۣرُ وَازۣرَةٌ وۣزْرَ ٱُخْرۭيٰؐ وَإِن تَدْعُ مُثْقَلَة٘ اِلَيٰ حِمْلِهَا لاَ يُحْمَلْ مِنْهُ شَيْءٌ وَلَوْ كَانَ ذَا قُرْبۭيٰٓؐ إِنَّمَا تُنذِرُ ۴لذِيــنَ يَخْشَوْنَ رَبَّهُم بِالْغَيْــبِ وَأَقَامُواْ ۴لصَّلَوٰةَؐ وَمَن تَزَكّۭيٰ فَإِنَّمَا يَتَزَكّۭيٰ لِنَفْسِهِؐ” وَإِلَي ۰للَّهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 19, 'وَمَا يَسْتَوۣى ۱لاَعْمۭيٰ وَالْبَصِيرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 20, 'وَلاَ ۰لظُّلُمَـٰـــتُ وَلاَ ۰لنُّورُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 21, 'وَلاَ ۰لظِّلُّ وَلاَ ۰لْحَرُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 22, 'وَمَا يَسْتَوۣى ۱لاَحْيَآءُ وَلاَ ۰لاَمْوَ؛تُؐ إِنَّ ۰للَّهَ يُسْمِعُ مَنْ يَّشَآءُؐ وَمَآ أَنتَ بِمُسْمِعٍ مَّن فِى ۱لْقُبُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 23, 'إِنَ اَنتَ إِلاَّ نَذِير٘ؐ 448');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 24, 'اِنَّآ أَرْسَلْنَـٰكَ بِالْحَقِّ بَشِيراً وَنَذِيراًؐ وَإِن مِّــنُ ۷مَّةٖ اِلاَّ خَلاَ فِيهَا نَذِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 25, 'وَإِنْ يُّكَذِّبُوكككَ فَقَدْ كَذَّبَ ۰لذِينَ مِــن قَبْلِهِمْ جَآءَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰتِ وَبِالزُّبُرۣ وَبِالْكِتَـٰبِ ۱لْمُنِيرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 26, 'ثُمَّ أَخَذتُّ ۴لذِيــنَ كَفَرُواْؐ فَكَيْفَ كَانَ نَكِيرۣؐ“');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 27, 'أَلَمْ تَرَ أَنَّ ۰للَّهَ أَنزَلَ مِــنَ ۰لسَّمَآءِ مَآءً فَأَخْرَجْنَا بِهِ” ثَمَرَ؛تٍ مُّخْتَلِفاٗ اَلْوَ؛نُهَاؐ وَمِنَ ۰لْجِبَالِ جُدَدٛ بِيضٌ وَحُمْرٌ مُّخْتَلِف٘ اَلْوَ؛نُهَا وَغَرَابِيبُ سُودٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 28, 'وَمِــنَ ۰لنَّاسِ وَالدَّوَآبِّ وَالاَنْعَـٰمِ مُخْتَلِف٘ اَلْوَ؛نُهُ„ كَذَ؛لِــكَؐ إِنَّمَا يَخْشَــي ۰للَّهَ مِنْ عِبَادِهِ ۱لْعُلَمَـٰٓؤُاْؐ اِ۬نَّ ۰للَّهَ عَزۣيز٘ غَفُور٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 29, 'اِنَّ ۰لذِينَ يَتْلُونَ كِتَـٰبَ ۰للَّهِ وَأَقَامُواْ ۴لصَّلَوٰةَ وَأَنفَقُواْ مِمَّا رَزَقْنَـٰهُمْ سِرّاً وَعَچَنِيَةً يَرْجُونَ تِجَـٰرَةً لَّن تَبُورَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 30, 'لِيُوَفِّيَهُمُ; ٱُجُورَهُمْ وَيَزۣيدَهُم مِّن فَضْلِهِؐ“ إِنَّهُ„ غَفُورٌ شَكُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 31, 'وَاﻟـذِىٓ أَوْحَيْنَآ إِلَيْــكَ مِــنَ ۰لْكِتَـٰبِ هُوَ ۰لْحَــقُّ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِؐ إِنَّ ۰للَّهَ بِعِبَادِهِ” لَخَبِيرٛ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 32, 'ثُمَّ أَوْرَثْنَا ۰لْكِتَـٰــبَ ۰لذِينَ "صْطَفَيْنَا مِنْ عِبَادِنَاؐ فَمِنْهُمْ ظَالِمٌ 449 لِّنَفْسِهِؐ” وَمِنْهُم مُّقْتَصِدٌؐ وَمِنْهُمْ سَابِـقٛ بِالْخَيْرَ؛تِ بِإِذْنِ ۱للَّهِؐ ذَ؛لِــكَ هُوَ ۰لْفَضْــلُ ۴لْكَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 33, 'جَنَّـٰتُ عَدْنٍ يَدْخُلُونَهَا يُحَلَّوْنَ فِيهَا مِــنَ اَسَاوۣرَ مِــن ذَهَبٍ وَلُؤْلُؤاًؐ وَلِبَاسُهُمْ فِيهَا حَرۣيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 34, 'وَقَالُواْ ۴لْحَمْدُ لِلهِ ۱ﻟـذِىٓ أَذْهَبَ عَنَّا ۰لْحَزَنَ إِنَّ رَبَّنَا لَغَفُورٌ شَكُور٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 35, '۱ﻟـذِىٓ أَحَلَّنَا دَارَ ۰لْمُقَامَةِ مِن فَضْلِهِ” لاَ يَمَسُّنَا فِيهَا نَصَــبٌ وَلاَ يَمَسُّنَا فِيهَا لُغُوبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 36, 'وَالذِيــنَ كَفَرُواْ لَهُمْ نَارُ جَهَنَّمَ لاَ يُقْضۭــيٰ عَلَيْهِمْ فَيَمُوتُواْ وَلاَ يُخَفَّفُ عَنْهُم مِّــنْ عَذَابِهَاؐ كَذَ؛لِكَ نَجْزۣى كُلَّ كَفُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 37, 'وَهُمْ يَصْطَرۣخُونَ فِيهَا رَبَّنَآ أَخْرۣجْنَا نَعْمَــلْ صَـٰڤِحاٗ غَيْرَ ۰ﻟ﮲ كُنَّا نَعْمَلُؐ أَوَلَمْ نُعَمِّرْكُم مَّا يَتَذَكَّرُ فِيهِ مَــن تَذَكَّرَ وَجَآءَكُمُ ۴لنَّذِيرُؐ فَذُوقُواْؐ فَمَا لِلظَّـٰلِمِينَ مِن نَّصِيرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 38, 'اِنَّ ۰للَّهَ عَـٰلِمُ غَيْبِ ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ إِنَّهُ„ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 39, 'هُوَ ۰ﻟ﮲ جَعَلَكُمْ خَلَئِفَ فِى ۱لاَرْضِؐ فَمَــن كَفَرَ فَعَلَيْهِ كُفْرُهُؐ, وَلاَ يَزۣيدُ ۴لْكۭـٰفِرۣيــنَ كُفْرُهُمْ عِندَ رَبِّهِمُ; إِلاَّ مَقْتاًؐ وَلاَ يَزۣيدُ ۴لْكۭـٰفِرۣيــنَ كُفْرُهُمُ; إِلاَّ خَسَاراًؐ 450');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 40, 'قُلَ اَرَ×يْتُمْ شُرَكَآءَكُمُ ۴لذِيــنَ تَدْعُونَ مِن دُونِ ۱للَّهِ أَرُونِى مَاذَا خَلَقُواْ مِــنَ ۰لاَرْضِ أَمْ لَهُمْ شِرْكككٌ فِى ۱لسَّمَـٰوَ؛تِؐ أَمَ —اتَيْنَـٰهُمْ كِتَـٰباً فَهُمْ عَلَيٰ بَيِّنَـٰتٍ مِّنْهُؐ بَلِ اِنْ يَّعِدُ ۴لظَّـٰلِمُونَ بَعْضُهُم بَعْضاٗ اِلاَّ غُرُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 41, '© اِنَّ ۰للَّهَ يُمْسِــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضَ أَن تَزُولؐاَ وَلَئِن زَالَتَـآ إِنَ اَمْسَكَهُمَا مِــنَ اَحَدٍ مِّنۢ بَعْدِهِؐ“ إِنَّهُ„ كَانَ حَلِيماٗ غَفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 42, 'وَأَقْسَمُواْ بِاللَّهِ جَهْدَ أَيْمَـٰنِهِمْ لَـئِن جَآءَهُمْ نَذِيرٌ لَّيَكُونُــنَّ أَهْدۭيٰ مِـنِ اِحْدَي ۰لاُمَمِؐ فَلَمَّا جَآءَهُمْ نَذِيرٌ مَّا زَادَهُمُ; إِلاَّ نُفُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 43, '''سْتِكْبَاراً فِى ۱لاَرْضِ وَمَكْرَ ۰لسَّيِّئِؐ وَلاَ يَحِيقُ ۴لْمَكْرُ ۴لسَّيِّىُ اِ۬لاَّ بِأَهْلِهِؐ” فَهَلْ يَنظُرُونَ إِلاَّ سُنَّتَ ۰لاَوَّلِينَؐ فَلَن تَجِدَ لِسُنَّتِ ۱للَّهِ تَبْدِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 44, 'وَلَن تَجِدَ لِسُنَّتِ ۱للَّهِ تَحْوۣيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 45, 'اَوَلَمْ يَسِيرُواْ فِى ۱لاَرْضِ فَيَنظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِينَ مِن قَبْلِهِمْ وَكَانُوٓاْ أَشَدَّ مِنْهُمْ قُوَّةًؐ وَمَا كَانَ ۰للَّهُ لِيُعْجِزَهُ„ مِن شَيْءٍ فِى ۱لسَّمَـٰوَ؛تِ وَلاَ فِى ۱لاَرْضِؐ إِنَّهُ„ كَانَ عَلِيماً 451 قَدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (35, 46, 'وَلَوْ يُوَ۬اخِذُ ۴للَّهُ ۴لنَّاسسسَ بِمَا كَسَبُواْ مَا تَرَكَ عَلَــيٰ ظَهْرۣهَا مِــن دَآبَّةٍؐ وَچَكِنْ يُّوَ۬خِّرُهُمُ; إِلَـيٰٓ أَجَلٍ مُّسَمّيًؐ فَإِذَا جَآءَ اجَلُهُمْ فَإِنَّ ۰للَّهَ كَانَ بِعِبَادِهِ” بَصِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَسِٓؐ وَالْقُرْءَانِ ۱لْحَكِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 2, 'إِنَّكَ لَمِــنَ ۰لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 3, 'عَلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 4, 'تَنزۣيلُ ۴لْعَزۣيزۣ ۱لرَّحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 5, 'لِتُنذِرَ قَوْماً مَّآ ٱُنذِرَ ءَابَآؤُهُمْ فَهُمْ غَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 6, 'لَقَدْ حَقَّ ۰لْقَوْلُ عَلَــيٰٓ أَكْثَرۣهِمْ فَهُمْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 7, 'إِنَّا جَعَلْنَا فِىٓ أَعْنَـٰقِهِمُ; أَغْچَلًا فَهِيَ إِلَي ۰لاَذْقَانِ فَهُم مُّقْمَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 8, 'وَجَعَلْنَا مِنۢ بَيْنِ أَيْدِيهِمْ سُدّاً وَمِــنْ خَلْفِهِمْ سُدّاً فَأَغْشَيْنَـٰهُمْ فَهُمْ لاَ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 9, 'وَسَوَآء٘ عَلَيْهِمُ; ءَآنذَرْتَهُمُ; أَمْ لَمْ تُنذِرْهُمْ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 10, 'إِنَّمَا تُنذِرُ مَنِ ''تَّبَعَ ۰لذِّكْرَ وَخَشِيَ ۰لرَّحْمَـٰنَ بِالْغَيْبِ فَبَشِّرْهُ بِمَغْفِرَةٍ وَأَجْرٍ كَرۣيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 11, 'اِنَّا نَحْنُ نُحْىِ ۱لْمَوْتۭـيٰ 452 وَنَكْتُبُ مَا قَدَّمُواْ وَءَاثَـٰرَهُمْؐ وَكُــلَّ شَيْءٖ اَحْصَيْنَـٰهُ فِىٓ إِمَامٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 12, 'وَاضْرۣبْ لَهُم مَّثَلٗا اَصْحَـٰبَ ۰لْقَرْيَةِ إِذْ جَآءَهَا ۰لْمُرْسَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 13, 'إِذَ اَرْسَلْنَآ إِلَيْهِمُ èثْنَيْنِ فَكَذَّبُوهُمَا فَعَزَّزْنَا بِثَالِثٍ فَقَالُوٓاْ إِنَّـآ إِلَيْكُم مُّرْسَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 14, 'قَالُواْ مَآ أَنتُمُ; إِلاَّ بَشَرٌ مِّثْلُنَا وَمَآ أَنزَلَ ۰لرَّحْمَـٰنُ مِن شَيْءٖ اِنَ اَنتُمُ; إِلاَّ تَكْذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 15, 'قَالُواْ رَبُّنَا يَعْلَمُ إِنَّآ إِلَيْكُمْ لَمُرْسَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 16, 'وَمَا عَلَيْنَآ إِلاَّ ۰لْبَچَغُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 17, 'قَالُوٓاْ إِنَّا تَطَيَّرْنَا بِكُمْ لَئِن لَّمْ تَنتَهُواْ لَنَرْجُمَنَّكُمْ وَلَيَمَسَّنَّكُم مِّنَّا عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 18, 'قَالُواْ طَـٰٓئِرُكُم مَّعَكُمُ; أَئــن ذُكِّرْتُمؐ بَــلَ اَنتُمْ قَوْمٌ مُّسْرۣفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 19, 'وَجَآءَ مِــنَ اَقْصَا ۰لْمَدِينَةِ رَجُلٌ يَسْعۭيٰؐ قَالَ يَـٰقَوْمِ ''تَّبِعُواْ ۴لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 20, '"تَّبِعُواْ مَــن لاَّ يَسْـَٔلُكُمُ; أَجْراً وَهُم مُّهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 21, 'وَمَا لِــيَ لآَ أَعْبُدُ ۴ﻟ﮲ فَطَرَنِى وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 22, 'ءَآتَّخِذُ مِن دُونِهِ“ ءَالِهَةٗ اِنْ يُّرۣدْنِ ۱لرَّحْمَـٰنُ بِضُرٍّ لاَّ تُغْــنۣ عَنِّى شَفَـٰعَتُهُمْ شَيْـٔاً وَلاَ يُنقِذُونِؐ“');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 23, 'إِنِّيَ إِذاً لَّفِى ضَچَلٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 24, 'اِنِّــيَ ءَامَنتُ بِرَبِّكُمْ 45 فَاسْمَعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 25, 'قِيــلَ ۸دْخُلِ ۱لْجَنَّةَؐ قَالَ يَـٰلَيْتَ قَوْمِى يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 26, 'بِمَا غَفَرَ لِى رَبِّى وَجَعَلَنِى مِنَ ۰لْمُكْرَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 27, '¤ وَمَآ أَنزَلْنَا عَلَيٰ قَوْمِهِ” مِنۢ بَعْدِهِ” مِـن جُندٍ مِّــنَ ۰لسَّمَآءِ وَمَا كُنَّا مُنزۣلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 28, 'إِن كَانَــتِ اِلاَّ صَيْحَةً وَ؛حِدَةً فَإِذَا هُمْ خَـٰمِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 29, 'يَـٰحَسْرَةٗ عَلَــي ۰لْعِبَادِؐ مَا يَاتِيهِم مِّن رَّسُولٖ اِلاَّ كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 30, 'أَلَمْ يَرَوْاْ كَمَ اَهْلَكْنَا قَبْلَهُم مِّنَ ۰لْقُرُونِ أَنَّهُمُ; إِلَيْهِمْ لاَ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 31, 'وَإِن كُــلٌّ لَّمَا جَمِيعٌ لَّدَيْنَا مُحْضَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 32, 'وَءَايَةٌ لَّهُمُ ۴لاَرْضضضُ ۴لْمَيِّتَةُ أَحْيَيْنَـٰهَا وَأَخْرَجْنَا مِنْهَا حَبّاً فَمِنْهُ يَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 33, 'وَجَعَلْنَا فِيهَا جَنَّـٰــتٍ مِّن نَّخِيلٍ وَأَعْنَـٰبٍ وَفَجَّرْنَا فِيهَا مِــنَ ۰لْعُيُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 34, 'لِيَاكُلُواْ مِــن ثَمَرۣهِ” وَمَا عَمِلَتْهُ أَيْدِيهِمُؐ; أَفَلاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 35, 'سُبْحَـٰنَ ۰ﻟ﮲ خَلَقَ ۰لاَزْوَ؛جَ كُلَّهَا مِمَّا تُنۢبِتُ ۴لاَرْضُ وَمِــنَ اَنفُسِهِمْ وَمِمَّا لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 36, 'وَءَايَةٌ لَّهُمُ ۴ليْــلُ نَسْلَخُ مِنْهُ ۴لنَّهَارَ فَإِذَا هُم مُّظْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 37, 'وَالشَّمْسُ تَجْرۣى لِمُسْتَقَرٍّ لَّهَاؐ ذَ؛لِــكَ تَقْدِيرُ ۴لْعَزۣيزۣ ۱لْعَلِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 38, 'وَالْقَمَرُ قَدَّرْنَـٰهُ 454 مَنَازۣلَ حَتَّــيٰ عَادَ كَالْعُرْجُونِ ۱لْقَدِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 39, 'لاَ ۰لشَّمْسُ يَنۢبَغِى لَهَآ أَن تُدْرۣكَ ۰لْقَمَرَ وَلاَ ۰ليْــلُ سَابِقُ ۴لنَّهۭارۣؐ وَكُلٌّ فِى فَلَكٍ يَسْبَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 40, 'وَءَايَةٌ لَّهُمُ; أَنَّا حَمَلْنَا ذُرّۣيَّـٰتِهِمْ فِى ۱لْفُلْــكِ ۱ڤْمَشْحُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 41, 'وَخَلَقْنَا لَهُم مِّن مِّثْلِهِ” مَا يَرْكَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 42, 'وَإِن نَّشَأْ نُغْرۣقْهُمْ فَلاَ صَرۣيخَ لَهُمْ وَلاَ هُمْ يُنقَذُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 43, 'إِلاَّ رَحْمَةً مِّنَّا وَمَتَـٰعاٗ اِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 44, 'وَإِذَا قِيــلَ لَهُمُ èتَّقُواْ مَا بَيْــنَ أَيْدِيكُمْ وَمَا خَلْفَكُمْ لَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 45, 'وَمَا تَاتِيهِم مِّــنَ —ايَةٍ مِّــنَ —ايَـٰتِ رَبِّهِمُ; إِلاَّ كَانُواْ عَنْهَا مُعْرۣضِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 46, 'وَإِذَا قِيــلَ لَهُمُ; أَنفِقُواْ مِمَّا رَزَقَكُمُ ۴للَّهُ قَالَ ۰لذِيــنَ كَفَرُواْ لِلذِيــنَ ءَامَنُوٓاْ أَنُطْعِمُ مَن لَّوْ يَشَآءُ ۴للَّهُ أَطْعَمَهُ; إِنَ اَنتُمُ; إِلاَّ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 47, 'وَيَقُولُونَ مَتۭيٰ هَـٰذَا ۰لْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 48, 'مَا يَنظُرُونَ إِلاَّ صَيْحَةً وَ؛حِدَةً تَاخُذُهُمْ وَهُمْ يَخَصِّمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 49, 'فَلاَ يَسْتَطِيعُونَ تَوْصِيَةً وَلآَ إِلَــيٰٓ أَهْلِهِمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 50, 'وَنُفِخَ فِى ۱لصُّورۣ فَإِذَا هُم مِّــنَ ۰لاَجْدَاثثثِ إِلَيٰ رَبِّهِمْ يَنسِلُونَؐ 455');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 51, 'قَالُواْ يَـٰوَيْلَنَا مَـنۢ بَعَثَنَا مِن مَّرْقَدِنَاؐ هَـٰذَا مَا وَعَدَ ۰لرَّحْمَـٰنُ وَصَدَقَ ۰لْمُرْسَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 52, 'إِن كَانَتِ اِلاَّ صَيْحَةً وَ؛حِدَةً فَإِذَا هُمْ جَمِيعٌ لَّدَيْنَا مُحْضَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 53, 'فَالْيَوْمَ لاَ تُظْلَمُ نَفْسٌ شَيْـٔاً وَلاَ تُجْزَوْنَ إِلاَّ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 54, 'إِنَّ أَصْحَـٰبَ ۰لْجَنَّةِ ۱لْيَوْمَ فِى شُغْلٍ فَـٰكِهُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 55, 'هُمْ وَأَزْوَ؛جُهُمْ فِى ظِچَــل۫ عَلَي ۰لاَرَآئِــكِ مُتَّكِـُٔونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 56, 'لَهُمْ فِيهَا فَـٰكِهَةٌؐ وَلَهُم مَّا يَدَّعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 57, 'سَچَمٌؐ قَوْلًا مِّن رَّبٍّ رَّحِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 58, 'وَامْتَـٰزُواْ ۴لْيَوْمَ أَيُّهَا ۰ڤْمُجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 59, '© أَلَمَ اَعْهَدِ اِلَيْكُمْ يَـٰبَنِىٓ ءَادَمَ أَن لاَّ تَعْبُدُواْ ۴لشَّيْطَـٰنَ إِنَّهُ„ لَكُمْ عَدُوٌّ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 60, 'وَأَنُ ۶عْبُدُونِىؐ هَـٰذَا صِرَ؛طٌ مُّسْتَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 61, 'وَلَقَدَ اَضَلَّ مِنكُمْ جِبِلًاّ كَثِيراٗؐ اَفَلَمْ تَكُونُواْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 62, 'هَـٰذِهِ” جَهَنَّمُ ۴لتِى كُنتُمْ تُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 63, '"صْلَوْهَا ۰لْيَوْمَ بِمَا كُنتُمْ تَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 64, '۰لْيَوْمَ نَخْتِمُ عَلَيٰٓ أَفْوَ؛هِهِمْ وَتُكَلِّمُنَآ أَيْدِيهِمْ وَتَشْهَدُ أَرْجُلُهُم بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 65, 'وَلَوْ نَشَآءُ لَطَمَسْنَا عَلَــيٰٓ أَعْيُنِهِمْ فَاسْتَبَقُواْ ۴لصِّرَ؛طَ فَأَنّۭيٰ 456 يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 66, 'وَلَوْ نَشَآءُ ڤَمَسَخْنَـٰهُمْ عَلَــيٰ مَكَانَتِهِمْ فَمَا "سْتَطَـٰعُواْ مُضِيّاً وَلاَ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 67, 'وَمَــن نُّعَمِّرْهُ نَنكُسْهُ فِى ۱لْخَلْقِؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 68, 'وَمَا عَلَّمْنَـٰهُ ۴لشِّعْرَ وَمَا يَنۢبَغِى لَهُؐ; إِنْ هُوَ إِلاَّ ذِكْرٌ وَقُرْءَانٌ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 69, 'لِّتُنذِرَ مَــن كَانَ حَيّاً وَيَحِقَّ ۰لْقَوْلُ عَلَــي ۰لْكۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 70, 'أَوَلَمْ يَرَوَاْ اَنَّا خَلَقْنَا لَهُم مِّمَّا عَمِلَتَ اَيْدِينَآ أَنْعَـٰماً فَهُمْ لَهَا مَـٰلِكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 71, 'وَذَلَّلْنَـٰهَا لَهُمْ فَمِنْهَا رَكُوبُهُمْ وَمِنْهَا يَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 72, 'وَلَهُمْ فِيهَا مَنَـٰفِعُ وَمَشَارۣبُؐ أَفَلاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 73, 'وَاتَّخَذُواْ مِن دُونِ ۱للَّهِ ءَالِهَةً لَّعَلَّهُمْ يُنصَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 74, 'لاَ يَسْتَطِيعُونَ نَصْرَهُمْ وَهُمْ لَهُمْ جُندٌ مُّحْضَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 75, 'فَلاَ يُحْزۣنــكَ قَوْلُهُمُؐ; إِنَّا نَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 76, 'أَوَلَمْ يَرَ ۰لِانسَـٰــنُ أَنَّا خَلَقْنَـٰهُ مِــن نُّطْفَةٍ فَإِذَا هُوَ خَصِيمٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 77, 'وَضَرَبَ لَنَا مَثَلًا وَنَسِــيَ خَلْقَهُؐ, قَالَ مَنْ يُّحْىِ ۱لْعِظَـٰمَ وَهِيَ رَمِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 78, 'قُلْ يُحْيِيهَا ۰ﻟـذِىٓ أَنشَأَهَآ أَوَّلَ مَرَّةٍ وَهُوَ بِكُــلّۣ خَلْقٖ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 79, '۱ﻟ﮲ جَعَلَ 457 لَكُم مِّــنَ ۰ڤشَّجَرۣ ۱لاَخْضَرۣ نَاراً فَإِذَآ أَنتُم مِّنْهُ تُوقِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 80, 'أَوَلَيْسَ ۰ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ بِقَـٰدِر۫ عَلَيٰٓ أَنْ يَّخْلُـقَ مِثْلَهُمؐ بَلۭيٰ وَهُوَ ۰لْخَــچَّـــقُ ۴لْعَلِـيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 81, 'إِنَّمَآ أَمْرُهُ; إِذَآ أَرَادَ شَيْـٔاٗ اَنْ يَّقُولَ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (36, 82, 'فَسُبْحَـٰنَ ۰ﻟ﮲ بِيَدِهِ” مَلَكُوتُ كُــلّۣ شَيْءٍ وَإِلَيْهِ تُرْجَعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالصَّـٰٓـفَّـٰتِ صَفّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 2, 'فَالزَّ؛جِرَ؛تِ زَجْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 3, 'فَالتَّـٰلِيَـٰتِ ذِكْراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 4, 'اِنَّ إِچَهَكُمْ لَوَ؛حِدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 5, 'رَّبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَا وَرَبُّ ۴لْمَشَـٰرۣقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 6, 'إِنَّا زَيَّنَّا ۰لسَّمَآءَ ۰لدُّنْيۭا بِـزۣينَةِ ۱لْكَوَاكِبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 7, 'وَحِفْظاً مِّــن كُلِّ شَيْطَـٰــنٍ مَّارۣدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 8, 'لاَّ يَسْمَعُونَ إِلَــي ۰لْمَلِإَ ۱لاَعْلۭيٰ وَيُقْذَفُونَ مِن كُلِّ جَانِبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 9, 'دُحُوراًؐ وَلَهُمْ عَذَابٌ وَاصِب٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 10, 'اِلاَّ مَــنْ خَطِفَ ۰لْخَطْفَةَ فَأَتْبَعَهُ„ شِهَابٌ ثَاقِبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 11, 'فَاسْتَفْتِهِمُ; أَهُمُ; أَشَدُّ خَلْقاٗ اَم مَّــنْ خَلَقْنَآؐ 458 إِنَّا خَلَقْنَـٰهُم مِّن طِينٍ چَّـزۣبٙؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 12, 'بَلْ عَجِبْــتَ وَيَسْخَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 13, 'وَإِذَا ذُكِّرُواْ لاَ يَذْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 14, 'وَإِذَا رَأَوَاْ —ايَةً يَسْتَسْخِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 15, 'وَقَالُوٓاْ إِنْ هَـٰذَآ إِلاَّ سِحْرٌ مُّبِين٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 16, 'اَ.ذَا مِتْنَا وَكُنَّا تُرَاباً وَعِظَـٰماٗ اِنَّا لَمَبْعُوثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 17, 'أَوَءَابَآؤُنَا ۰لاَوَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 18, 'قُــلْ نَعَمْ وَأَنتُمْ دَ؛خِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 19, 'فَإِنَّمَا هِيَ زَجْرَةٌ وَ؛حِدَةٌ فَإِذَا هُمْ يَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 20, 'وَقَالُواْ يَـٰوَيْلَنَا هَـٰذَا يَوْمُ ۴لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 21, 'هَـٰذَا يَوْمُ ۴لْفَصْلِ ۱ﻟ﮲ كُنتُم بِهِ” تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 22, '¥ ۸حْشُرُواْ ۴لذِيــنَ ظَلَمُواْ وَأَزْوَ؛جَهُمْ وَمَا كَانُواْ يَعْبُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 23, 'مِن دُونِ ۱للَّهِ فَاهْدُوهُمُ; إِلَيٰ صِرَ؛طِ ۱لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 24, 'وَقِفُوهُمُ; إِنَّهُم مَّسْـُٔولُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 25, 'مَا لَكُمْ لاَ تَنَاصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 26, 'بَلْ هُمُ ۴لْيَوْمَ مُسْتَسْلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 27, 'وَأَقْبَلَ بَعْضُهُمْ عَلَيٰ بَعْـضٍ يَتَسَآءَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 28, 'قَالُوٓاْ إِنَّكُمْ كُنتُمْ تَاتُونَنَا عَنِ ۱لْيَمِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 29, 'قَالُواْ بَل لَّمْ تَكُونُواْ مُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 30, 'وَمَا كَانَ لَنَا عَلَيْكُم مِّــن سُلْطَـٰنٙ بَلْ كُنتُمْ قَوْماً طَـٰغِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 31, 'فَحَــقَّ عَلَيْنَا قَوْلُ رَبِّنَآ إِنَّا لَذَآئِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 32, 'فَأَغْوَيْنَـٰكُمُ; إِنَّا كُنَّا غَـٰوۣينَؐ 459');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 33, 'فَإِنَّهُمْ يَوْمَئِذٍ فِى ۱لْعَذَابِ مُشْتَرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 34, 'إِنَّا كَذَ؛لِــكَ نَفْعَلُ بِاڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 35, 'إِنَّهُمْ كَانُوٓاْ إِذَا قِيــلَ لَهُمْ لآَ إِچَهَ إِلاَّ ۰للَّهُ يَسْتَكْبِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 36, 'وَيَقُولُونَ أَئنَّا لَتَارۣكُوٓاْ ءَالِهَتِنَا لِشَاعِرٍ مَّجْنُونٙؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 37, 'بَلْ جَآءَ بِالْحَقِّ وَصَدَّقَ ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 38, 'إِنَّكُمْ لَذَآئِقُواْ ۴لْعَذَابِ ۱لاَلِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 39, 'وَمَا تُجْزَوْنَ إِلاَّ مَا كُنتُمْ تَعْمَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 40, 'إِلاَّ عِبَادَ ۰للَّهِ ۱ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 41, 'ٱُوْلَئِــكَ لَهُمْ رۣزْقٌ مَّعْلُومٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 42, 'فَوَ؛كِهُؐ وَهُم مُّكْرَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 43, 'فِى جَنَّـٰتِ ۱لنَّعِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 44, 'عَلَيٰ سُرُرٍ مُّتَقَـٰبِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 45, 'يُطَافُ عَلَيْهِم بِكَأْسٍ مِّن مَّعِينٙ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 46, 'بَيْضَآءَ لَذَّةٍ لِّلشَّـٰرۣبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 47, 'لاَ فِيهَا غَوْلٌ وَلاَ هُمْ عَنْهَا يُنزَفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 48, 'وَعِندَهُمْ قَـٰصِرَ؛تُ ۴لطَّرْفِ عِيـنٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 49, 'كَأَنَّهُنَّ بَيْــضٌ مَّكْنُونٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 50, 'فَأَقْبَلَ بَعْضُهُمْ عَلَيٰ بَعْضٍ يَتَسَآءَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 51, 'قَالَ قَآئِلٌ مِّنْهُمُ; إِنِّى كَانَ لِى قَرۣينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 52, 'يَقُولُ أَ.نَّــكَ لَمِــنَ ۰لْمُصَدِّقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 53, 'أَ.ذَا مِتْنَا وَكُنَّا تُرَاباً وَعِظَـٰماٗ اِنَّا لَمَدِينُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 54, 'قَالَ هَــلَ اَنتُم مُّطَّلِعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 55, 'فَاطَّلَعَ فَرۭءۭاهُ فِى سَوَآءِ 460 ۱لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 56, 'قَالَ تَاللَّهِ إِن كِدتَّ لَتُرْدِينِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 57, 'وَلَوْلاَ نِعْمَةُ رَبِّى لَكُنتُ مِــنَ ۰ڤْمُحْضَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 58, 'أَفَمَا نَحْنُ بِمَيِّتِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 59, 'إِلاَّ مَوْتَتَنَا ۰لاُولۭيٰ وَمَا نَحْنُ بِمُعَذَّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 60, 'إِنَّ هَـٰذَا لَهُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 61, 'لِمِثْــلۣ هَـٰذَا فَلْيَعْمَـلِ ۱لْعَـٰمِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 62, 'أَذَ؛لِــكَ خَيْرٌ نُّزُلٗا اَمْ شَجَرَةُ ۴لزَّقُّومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 63, 'إِنَّا جَعَلْنَـٰهَا فِتْنَةً لِّلظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 64, 'إِنَّهَا شَجَرَةٌ تَخْرُجُ فِىٓ أَصْـلِ ۱لْجَحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 65, 'طَلْعُهَا كَأَنَّهُ„ رُءُوسسسُ ۴لشَّيَـٰطِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 66, 'فَإِنَّهُمْ ءَلاَكِلُونَ مِنْهَا فَمَالِـُٔونَ مِنْهَا ۰لْبُطُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 67, 'ثُمَّ إِنننَّ لَهُمْ عَلَيْهَا لَشَوْباً مِّــنْ حَمِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 68, 'ثُمَّ إِنَّ مَرْجِعَهُمْ لِإَلَــي ۰لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 69, 'إِنَّهُمُ; أَلْفَوَاْ —ابَآءَهُمْ ضَآلِّينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 70, 'فَهُمْ عَلَــيٰٓ ءَاثۭـٰرۣهِمْ يُهْرَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 71, 'وَلَقَد ضَّلَّ قَبْلَهُمُ; أَكْثَرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 72, 'وَلَقَدَ اَرْسَلْنَا فِيهِم مُّنذِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 73, 'فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لْمُنذَرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 74, 'إِلاَّ عِبَادَ ۰للَّهِ ۱ڤْمُخْلَصِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 75, 'وَلَقَدْ نَادۭيٰنَا نُوحٌؐ فَلَنِعْمَ ۰ڤْمُجِيبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 76, 'وَنَجَّيْنَـٰهُ وَأَهْلَهُ„ مِــنَ ۰لْكَرْبِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 77, 'وَجَعَلْنَا ذُرّۣيَّتَهُ„ هُمُ ۴لْبَاقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 78, 'وَتَرَكْنَا عَلَيْهِ فِى ۱لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 79, '461 سَچَم٘ عَلَيٰ نُوحٍ فِى ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 80, 'إِنَّا كَذَ؛لِكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 81, 'إِنَّهُ„ مِنْ عِبَادِنَا ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 82, 'ثُمَّ أَغْرَقْنَا ۰لاَخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 83, '© وَإِنَّ مِن شِيعَتِهِ” لِإَبْرَ؛هِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 84, 'إِذْ جَآءَ رَبَّهُ„ بِقَلْــبٍ سَلِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 85, 'اِذْ قَالَ لَأِبِيهِ وَقَوْمِهِ” مَاذَا تَعْبُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 86, 'أَئفْكاٗ —الِهَةً دُونَ ۰للَّهِ تُرۣيدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 87, 'فَمَا ظَنُّكُم بِرَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 88, 'فَنَظَرَ نَظْرَةً فِى ۱ڤنُّجُومِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 89, 'فَقَالَ إِنِّى سَقِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 90, 'فَتَوَلَّوْاْ عَنْهُ مُدْبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 91, 'فَرَاغَ إِلَــيٰٓ ءَالِهَتِهِمْ فَقَالَ أَلاَ تَاكُلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 92, 'مَا لَكُمْ لاَ تَنطِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 93, 'فَرَاغَ عَلَيْهِمْ ضَرْباَۢ بِالْيَمِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 94, 'فَأَقْبَلُوٓاْ إِلَيْهِ يَزۣفُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 95, 'قَالَ أَتَعْبُدُونَ مَا تَنْحِتُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 96, 'وَاللَّهُ خَلَقَكُمْ وَمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 97, 'قَالُواْ èبْنُواْ لَهُ„ بُنْيَـٰناً فَأَلْقُوهُ فِى ۱لْجَحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 98, 'فَأَرَادُواْ بِهِ” كَيْداً فَجَعَلْنَـٰهُمُ ۴لاَسْفَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 99, 'وَقَالَ إِنِّى ذَاهِب٘ اِلَيٰ رَبِّى سَيَهْدِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 100, 'رَبِّ هَبْ لِى مِــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 101, 'فَبَشَّرْنَـٰهُ بِغُچَمٖ حَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 102, 'فَلَمَّا بَلَغَ مَعَهُ ۴لسَّعْيَ قَالَ يَـٰبُنَيِّ إِنِّيَ أَرۭيٰ فِى ۱لْمَنَامِ أَنِّــيَ أَذْبَحُكَ فَانظُرْ مَاذَا تَرۭيٰؐ 462 قَالَ يَـٰٓأَبَتِ ''فْعَــلْ مَا تُومَرُؐ سَتَجِدُنِيَ إِن شَآءَ ۰للَّهُ مِــنَ ۰لصَّـٰبِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 103, 'فَلَمَّآ أَسْلَمَا وَتَلَّهُ„ ڤِڤْجَبِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 104, 'وَنَـٰدَيْنَـٰهُ أَنْ يَّـٰٓإِبْرَ؛هِيمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 105, 'قَدْ صَدَّقْتَ ۰لرُّءْيۭآؐ إِنَّا كَذَ؛لِــكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 106, 'إِنَّ هَـٰذَا لَهُوَ ۰لْبَـ£ـؤُاْ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 107, 'وَفَدَيْنَـٰهُ بِذِبْحٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 108, 'وَتَرَكْنَا عَلَيْهِ فِى ۱لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 109, 'سَچَم٘ عَلَيٰٓ إِبْرَ؛هِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 110, 'كَذَ؛لِــكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 111, 'إِنَّهُ„ مِنْ عِبَادِنَا ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 112, 'وَبَشَّرْنَـٰهُ بِإِسْحَـٰقَ نَبِيٓــٔاً مِّــنَ ۰ڤصَّـٰڤِحِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 113, 'وَبَـٰرَكْنَا عَلَيْهِ وَعَلَيٰٓ إِسْحَـٰقَؐ وَمِن ذُرّۣيَّتِهِمَا مُحْسِنٌ وَظَالِمٌ لِّنَفْسِهِ” مُبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 114, 'وَلَقَدْ مَنَـنَّا عَلَيٰ مُوسۭيٰ وَهَـٰرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 115, 'وَنَجَّيْنَـٰهُمَا وَقَوْمَهُمَا مِــنَ ۰لْكَرْبِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 116, 'وَنَصَرْنَـٰهُمْ فَكَانُواْ هُمُ ۴لْغَـٰلِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 117, 'وَءَاتَيْنَـٰهُمَا ۰لْكِتَـٰبَ ۰لْمُسْتَبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 118, 'وَهَدَيْنَـٰهُمَا ۰لصِّرَ؛طَ ۰لْمُسْتَقِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 119, 'وَتَرَكْنَا عَلَيْهِمَا فِى ۱لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 120, 'سَچَم٘ عَلَيٰ مُوسۭيٰ وَهَـٰرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 121, 'إِنَّا كَذَ؛لِــكَ نَجْزۣﻯ ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 122, 'إِنَّهُمَا مِنْ عِبَادِنَا ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 123, 'وَإِنَّ إِلْيَاسَ لَمِنَ ۰لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 124, 'إِذْ قَالَ لِقَوْمِهِ“ أَلاَ تَتَّقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 125, '46 أَتَدْعُونَ بَعْلًا وَتَذَرُونَ أَحْسَــنَ ۰لْخَـٰلِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 126, '۰للَّهُ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 127, 'فَكَذَّبُوهُ فَإِنَّهُمْ ڤَمُحْضَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 128, 'إِلاَّ عِبَادَ ۰للَّهِ ۱ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 129, 'وَتَرَكْنَا عَلَيْهِ فِى ۱لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 130, 'سَچَم٘ عَلَــيٰٓ ءَالِ يَاسِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 131, 'إِنَّا كَذَ؛لِــكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 132, 'إِنَّهُ„ مِــنْ عِبَادِنَا ۰لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 133, 'وَإِنَّ لُوطاً لَّمِــنَ ۰لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 134, 'إِذْ نَجَّيْنَـٰهُ وَأَهْلَهُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 135, 'إِلاَّ عَجُوزاً فِى ۱لْغَـٰبِـرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 136, 'ثُمَّ دَمَّرْنَا ۰لاَخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 137, 'وَإِنَّكُمْ لَتَمُرُّونَ عَلَيْهِم مُّصْبِحِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 138, 'وَبِاليْلِؐ أَفَلاَ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 139, 'وَإِنَّ يُونُسَ لَمِنَ ۰لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 140, 'إِذَ اَبَقَ إِلَي ۰لْفُلْكِ ۱ڤْمَشْحُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 141, 'فَسَاهَمَ فَكَانَ مِــنَ ۰ڤْمُدْحَضِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 142, 'فَالْتَقَمَهُ ۴لْحُوتُ وَهُوَ مُلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 143, 'فَلَوْلآَ أَنَّهُ„ كَانَ مِنَ ۰ڤْمُسَبِّحِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 144, 'لَلَبِثَ فِى بَطْنِهِ“ إِلَيٰ يَوْمِ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 145, '¤ فَنَبَذْنَـٰهُ بِالْعَرَآءِ وَهُوَ سَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 146, 'وَأَنۢبَتْنَا عَلَيْهِ شَجَرَةً مِّـنْ يَّقْطِيـنٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 147, 'وَأَرْسَلْنَـٰهُ إِلَيٰ مِاْيؕةِ أَلْفٖ اَوْ يَزۣيدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 148, 'فَـــَٔامَنُواْ فَمَتَّعْنَـٰهُمُ; إِلَيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 149, 'فَاسْتَفْتِهِمُ; أَلِرَبِّكَ 464 ۰لْبَنَاتُ وَلَهُمُ ۴لْبَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 150, 'أَمْ خَلَقْنَا ۰لْمَلَئِكَةَ إِنَـٰثاً وَهُمْ شَـٰهِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 151, 'أَلآَ إِنَّهُم مِّنِ اِفْكِهِمْ لَيَقُولُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 152, 'وَلَدَ ۰للَّهُ وَإِنَّهُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 153, 'أَصْطَفَي ۰لْبَنَاتِ عَلَي ۰لْبَنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 154, 'مَا لَكُمْؐ كَيْفَ تَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 155, 'أَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 156, 'أَمْ لَكُمْ سُلْطَـٰنٌ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 157, 'فَاتُواْ بِكِتَـٰبِكُمُ; إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 158, 'وَجَعَلُواْ بَيْنَهُ„ وَبَيْنَ ۰لْجِنَّةِ نَسَباًؐ وَلَقَدْ عَلِمَتِ ۱لْجِنَّةُ إِنَّهُمْ ڤَمُحْضَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 159, 'سُبْحَـٰــنَ ۰للَّهِ عَمَّا يَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 160, 'إِلاَّ عِبَادَ ۰للَّهِ ۱ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 161, 'فَإِنَّكُمْ وَمَا تَعْبُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 162, 'مَآ أَنتُمْ عَلَيْهِ بِفَـٰتِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 163, 'إِلاَّ مَنْ هُوَ صَالِ ۱لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 164, 'وَمَا مِنَّآ إِلاَّ لَهُ„ مَقَامٌ مَّعْلُومٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 165, 'وَإِنَّا ڤَنَحْــنُ ۴لصَّآفُّونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 166, 'وَإِنَّا ڤَنَحْــنُ ۴ڤْمُسَبِّحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 167, 'وَإِن كَانُواْ لَيَقُولُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 168, 'لَوَ اَنَّ عِندَنَا ذِكْراً مِّــنَ ۰لاَوَّلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 169, 'لَكُنَّا عِبَادَ ۰للَّهِ ۱ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 170, 'فَكَفَرُواْ بِهِؐ” فَسَوْفَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 171, 'وَلَقَدْ سَبَقَتْ كَلِمَتُنَا لِعِبَادِنَا ۰لْمُرْسَلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 172, 'إِنَّهُمْ لَهُمُ ۴لْمَنصُورُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 173, 'وَإِنَّ جُندَنَا لَهُمُ ۴لْغَـٰلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 174, '465 فَتَوَلَّ عَنْهُمْ حَتَّيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 175, 'وَأَبْصِرْهُمْ فَسَوْفَ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 176, 'أَفَبِعَذَابِنَا يَسْتَعْجِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 177, 'فَإِذَا نَزَلَ بِسَاحَتِهِمْ فَسَآءَ صَبَاحُ ۴لْمُنذَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 178, 'وَتَوَلَّ عَنْهُمْ حَتَّيٰ حِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 179, 'وَأَبْصِرْ فَسَوْفَ يُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 180, 'سُبْحَـٰنَ رَبِّــكَ رَبِّ ۱لْعِزَّةِ عَمَّا يَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 181, 'وَسَچَم٘ عَلَــي ۰لْمُرْسَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (37, 182, 'وَالْحَمْدُ لِلهِ رَبِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ صَٓؐ وَالْقُرْءَانِ ذى ۱لذِّكْرۣؐ بَلِ ۱لذِيــنَ كَفَرُواْ فِى عِزَّةٍ وَشِقَاقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 2, 'كَمَ اَهْلَكْنَا مِــن قَبْلِهِم مِّن قَرْنٍ فَنَادَواْ وَّلاَتَ حِيــنَ مَنَاصٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 3, 'وَعَجِبُوٓاْ أَن جَآءَهُم مُّنذِرٌ مِّنْهُمْؐ وَقَالَ ۰لْكَـٰفِرُونَ هَـٰذَا سَـٰحِرٌ كَذَّاب٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 4, 'اَجَعَـلَ ۰لاَلِهَةَ إِچَهاً وَ؛حِداٗ اِنننَّ هَـٰذَا لَشَىْء٘ عُجَابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 5, 'وَانطَلَــقَ ۰لْمَلُءَ مِنْهُمُ; أَنِ ''مْشُواْ وَاصْبِرُواْ عَلَــيٰٓ ءَالِهَتِكُمُ; إِنَّ هَـٰذَا لَشَىْءٌ يُرَادُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 6, 'مَا سَمِعْنَا بِهَـٰذَا فِى ۱لْمِلَّةِ ۱لاَخِرَةِ إِنْ هَـٰذَآ إِلاَّ "خْتِچَق٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 7, 'اَ.نزۣلَ عَلَيْهِ ۱لذِّكْرُ مِنۢ بَيْنِنَاؐ 466 بَــلْ هُمْ فِى شَــكٍّ مِّــن ذِكْرۣى بَــل لَّمَّا يَذُوقُواْ عَذَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 8, 'أَمْ عِندَهُمْ خَزَآئِنُ رَحْمَةِ رَبِّكَ ۰لْعَزۣيزۣ ۱لْوَهَّابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 9, 'أَمْ لَهُم مُّلْكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَاؐ فَلْيَرْتَقُواْ فِى ۱لاَسْبَـٰبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 10, 'جُندٌ مَّا هُنَالِــكَ مَهْزُومٌ مِّــنَ ۰لاَحْزَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 11, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَعَادٌ وَفِرْعَوْنُ ذُو ۴لاَوْتَادِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 12, 'وَثَمُودُ وَقَوْمُ لُوطٍ وَأَصْحَـٰبُ لَيْكَةَؐ ٱُوْلَئِكَ ۰لاَحْزَابُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 13, 'إِن كُلّﹲ اِلاَّ كَذَّبَ ۰لرُّسُــلَ فَحَقَّ عِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 14, 'وَمَا يَنظُرُ هَـٰٓؤُلآَءِ الاَّ صَيْحَةً وَ؛حِدَةً مَّا لَهَا مِن فَوَاقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 15, 'وَقَالُواْ رَبَّنَا عَجِّــل لَّنَا قِطَّنَا قَبْلَ يَوْمِ ۱لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 16, '''صْبِرْ عَلَــيٰ مَا يَقُولُونَؐ وَاذْكُرْ عَبْدَنَا دَاوُﹼدَ ذَا ۰لاَيْدِؐ إِنَّهُ; أَوَّاب٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 17, 'اِنَّا سَخَّرْنَا ۰لْجِبَالَ مَعَهُ„ يُسَبِّحْنَ بِالْعَشِيِّ وَالِاشْرَاقِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 18, 'وَالطَّيْرَ مَحْشُورَةًؐ كُلٌّ لَّهُ; أَوَّابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 19, 'وَشَدَدْنَا مُلْكَهُ„ وَءَاتَيْنَـٰهُ ۴لْحِكْمَةَ وَفَصْلَ ۰لْخِطَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 20, '© وَهَلَ اَتۭيٰــكَ نَبَؤُاْ ۴لْخَصْمِ إِذْ تَسَوَّرُواْ ۴ڤْمِحْرَابَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 21, 'إِذْ دَخَلُواْ عَلَيٰ دَاوُﹼدَ فَفَزۣعَ مِنْهُمْ قَالُواْ لاَ تَخَفْؐ 467 خَصْمَـٰنِ بَغۭيٰ بَعْضُنَا عَلَـيٰ بَعْـضٍ فَاحْكُم بَيْنَنَا بِالْحَقِّ وَلاَ تُشْطِطْؐ وَاهْدِنَآ إِلَيٰ سَوَآءِ ۱لصِّرَ؛طِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 22, 'إِنَّ هَـٰذَآ أَخِى لَهُ„ تِسْعٌ وَتِسْعُونَ نَعْجَةً وَلِى نَعْجَةٌ وَ؛حِدَةٌ فَقَالَ أَكْفِلْنِيهَا وَعَزَّنِى فِى ۱لْخِطَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 23, 'قَالَ لَقَد ظَّلَمَكَ بِسُؤَالِ نَعْجَتِــكَ إِلَيٰ نِعَاجِهِؐ” وَإِنَّ كَثِيراً مِّــنَ ۰لْخُلَطَآءِ لَيَبْغِى بَعْضُهُمْ عَلَيٰ بَعْضٖ اِلاَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِؐ وَقَلِيــلٌ مَّا هُمْؐ وَظَــنَّ دَاوُﹼدُ أَنَّمَا فَتَنَّـٰهُ فَاسْتَغْفَرَ رَبَّهُ„ وَخَرَّ رَاكِعاً وَأَنَابَؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 24, 'فَغَفَرْنَا لَهُ„ ذَ؛لِــكَؐ وَإِنَّ لَهُ„ عِندَنَا لَزُلْفۭيٰ وَحُسْــنَ مَـَٔابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 25, 'يَـٰدَاوُﹼدُ إِنَّا جَعَلْنَـٰكَ خَلِيفَةً فِى ۱لاَرْضِ فَاحْكُم بَيْــنَ ۰لنَّاسِ بِالْحَقِّ وَلاَ تَتَّبِعِ ۱لْهَوۭيٰ فَيُضِلَّــكَ عَــن سَبِيـلِ ۱للَّهِؐ إِنَّ ۰لذِينَ يَضِلُّونَ عَــن سَبِيـلِ ۱للَّهِ لَهُمْ عَذَابٌ شَدِيدٛ بِمَا نَسُواْ يَوْمَ ۰لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 26, 'وَمَا خَلَقْنَا ۰لسَّمَآءَ وَالاَرْضَ وَمَا بَيْنَهُمَا بَـٰطِلًؐا ذَ؛لِــكَ ظَــنُّ ۴لذِينَ كَفَرُواْؐ فَوَيْلٌ لِّلذِيــنَ كَفَرُواْ مِــنَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 27, 'أَمْ نَجْعَلُ ۴لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ كَالْمُفْسِدِينَ فِى ۱لاَرْضِؐ 468 أَمْ نَجْعَــلُ ۴لْمُتَّقِيــنَ كَاڤْفُجّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 28, 'كِتَـٰب٘ اَنزَلْنَـٰهُ إِلَيْكَ مُبَـٰرَكككٌ لِّيَدَّبَّرُوٓاْ ءَايَـٰتِهِ” وَلِيَتَذَكَّرَ ٱُوْلُواْ ۴لاَلْبَـٰبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 29, 'وَوَهَبْنَا لِدَاوُﹼدَ سُلَيْمَـٰنَؐ نِعْمَ ۰لْعَبْدُؐ إِنَّهُ; أَوَّاب٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 30, 'اِذْ عُرۣضضضَ عَلَيْهِ بِالْعَشِيِّ ۱لصَّـٰفِنَـٰتُ ۴لْجِيَادُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 31, 'فَقَالَ إِنِّــيَ أَحْبَبْتُ حُــبَّ ۰لْخَيْرۣ عَــن ذِكْرۣ رَبِّى حَتَّيٰ تَوَارَتْ بِالْحِجَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 32, 'رُدُّوهَا عَلَـيَّ فَطَفِقَ مَسْحاَۢ بِالسُّوقِ وَالاَعْنَاقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 33, 'وَلَقَدْ فَتَنَّا سُلَيْمَـٰنَ وَأَلْقَيْنَا عَلَــيٰ كُرْسِيِّهِ” جَسَداً ثُمَّ أَنَابَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 34, 'قَالَ رَبِّ ''غْفِرْ لِى وَهَبْ لِى مُلْكاً لاَّ يَنۢبَغِى لَأِحَدٍ مِّنۢ بَعْدِيَؐ إِنَّــكَ أَنتَ ۰لْوَهَّابُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 35, 'فَسَخَّرْنَا لَهُ ۴لرّۣيحَ تَجْرۣى بِأَمْرۣهِ” رُخَآءٗ حَيْــثُ أَصَابَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 36, 'وَالشَّيَـٰطِيــنَ كُلَّ بَنَّآءٍ وَغَوَّاصٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 37, 'وَءَاخَرۣيــنَ مُقَرَّنِينَ فِى ۱لاَصْفَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 38, 'هَـٰذَا عَطَآؤُنَا فَامْنُنَ اَوَ اَمْسِــكْ بِغَيْرۣ حِسَابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 39, 'وَإِنننَّ لَهُ„ عِندَنَا لَزُلْفۭيٰ وَحُسْــنَ مَـَٔابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 40, 'وَاذْكُرْ عَبْدَنَآ أَيُّوبَ إِذْ نَادۭيٰ رَبَّهُ; أَنِّى مَسَّنِــيَ ۰لشَّيْطَـٰنُ بِنُصْبٍ وَعَذَابٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 41, '۶رْكُضْ بِـرۣجْلِــكَؐ هَـٰذَا مُغْتَسَلٛ بَارۣدٌ وَشَرَابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 42, 'وَوَهَبْنَا لَهُ; أَهْلَهُ„ 469 وَمِثْلَهُم مَّعَهُمْ رَحْمَةً مِّنَّا وَذِكْرۭيٰ لُءِوْلِى ۱لاَلْبَـٰبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 43, 'وَخُذْ بِيَدِكَ ضِغْثاً فَاضْرۣب بِّهِ” وَلاَ تَحْنَثِؐ اِنَّا وَجَدْنَـٰهُ صَابِراًؐ نِّعْمَ ۰لْعَبْدُؐ إِنَّهُ; أَوَّابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 44, 'وَاذْكُرْ عِبَـٰدَنَـآ إِبْرَ؛هِيمَ وَإِسْحَـٰقَ وَيَعْقُوبَ ٱُوْلِى ۱لاَيْدِى وَالاَبْصۭـٰرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 45, 'إِنَّآ أَخْلَصْنَـٰهُم بِخَالِصَةِ ذِكْرَي ۰لدّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 46, 'وَإِنَّهُمْ عِندَنَا لَمِــنَ ۰لْمُصْطَفَيْــنَ ۰لاَخْيۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 47, 'وَاذْكُرۣ اِسْمَـٰعِيلَ وَالْيَسَعَ وَذَا ۰لْكِفْلِؐ وَكُلٌّ مِّنَ ۰لاَخْيۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 48, 'هَـٰذَا ذِكْرٌؐ وَإِنَّ لِلْمُتَّقِيــنَ لَحُسْــنَ مَـَٔابٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 49, 'جَنَّـٰتِ عَدْنٍ مُّفَتَّحَةً لَّهُمُ ۴لاَبْوَ؛بُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 50, 'مُتَّكِـِٕينَ فِيهَا يَدْعُونَ فِيهَا بِفَـٰكِهَةٍ كَثِيرَةٍ وَشَرَابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 51, '¥ وَعِندَهُمْ قَـٰصِرَ؛تُ ۴لطَّرْفِ أَتْرَاب٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 52, 'هَـٰذَا مَا تُوعَدُونَ لِيَوْمِ ۱لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 53, 'إِنَّ هَـٰذَا لَرۣزْقُنَا مَا لَهُ„ مِــن نَّفَادٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 54, 'هَـٰذَا وَإِنَّ لِلطَّـٰغِينَ لَشَرَّ مَـَٔابٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 55, 'جَهَنَّمَ يَصْلَوْنَهَاؐ فَبِيسَ ۰لْمِهَادُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 56, 'هَـٰذَا فَلْيَذُوقُوهُ حَمِيمٌ وَغَسَاقٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 57, 'وَءَاخَرُ مِــن شَكْلِهِ“ أَزْوَ؛ج٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 58, 'هَـٰذَا فَوْجٌ مُّقْتَحِمٌ مَّعَكُمْؐ لاَ مَرْحَباَۢ بِهِمُؐ; 470 إِنَّهُمْ صَالُواْ ۴لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 59, 'قَالُواْ بَــلَ اَنتُمْ لاَ مَرْحَباَۢ بِكُمُ; أَنتُمْ قَدَّمْتُمُوهُ لَنَاؐ فَبِيــسَ ۰لْقَرَارُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 60, 'قَالُواْ رَبَّنَا مَن قَدَّمَ لَنَا هَـٰذَا فَزۣدْهُ عَذَاباً ضِعْفاً فِى ۱لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 61, 'وَقَالُواْ مَا لَنَا لاَ نَرۭيٰ رۣجَالًا كُنَّا نَعُدُّهُم مِّــنَ ۰لاَشْرۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 62, 'أَتَّخَذْنَـٰهُمْ سُخْرۣيّاٗ اَمْ زَاغَتْ عَنْهُمُ ۴لاَبْصَـٰرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 63, 'إِنَّ ذَ؛لِكَ لَحَقٌّ تَخَاصُمُ أَهْلِ ۱لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 64, 'قُلِ اِنَّمَآ أَنَا مُنذِرٌؐ وَمَا مِنِ اِچَهٖ اِلاَّ ۰للَّهُ ۴لْوَ؛حِدُ ۴لْقَهَّارُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 65, 'رَبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَاؐ ۰لْعَزۣيزُ ۴لْغَفَّـٰرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 66, 'قُلْ هُوَ نَبَؤ٘اْ عَظِيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 67, 'اَنتُمْ عَنْهُ مُعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 68, 'مَا كَانَ لِى مِنْ عِلْمٙ بِالْمَلِإَ ۱لاَعْلۭيٰٓ إِذْ يَخْتَصِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 69, 'إِنْ يُّوحۭيٰٓ إِلَيَّ إِلٓاَّ أَنَّمَآ أَنَا نَذِيرٌ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 70, 'اِذْ قَالَ رَبُّــكَ لِلْمَلَئِكَةِ إِنِّى خَـٰلِقٛ بَشَراً مِّن طِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 71, 'فَإِذَا سَوَّيْتُهُ„ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُواْ لَهُ„ سَـٰجِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 72, 'فَسَجَدَ ۰لْمَلَئِكَةُ كُلُّهُمُ; أَجْمَعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 73, 'إِلٓاَّ إِبْلِيسَ "سْتَكْبَرَ وَكَانَ مِنَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 74, 'قَالَ يَـٰٓإِبْلِيــسُ مَا مَنَعَكَ أَن تَسْجُدَ لِمَا خَلَقْتُ بِيَدَيَّ أَسْتَكْبَرْتَ أَمْ كُنتَ مِــنَ ۰لْعَالِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 75, 'قَالَ أَنَا خَيْرٌ مِّنْهُ 471 خَلَقْتَنِى مِن نّۭارٍ وَخَلَقْتَهُ„ مِن طِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 76, 'قَالَ فَاخْرُجْ مِنْهَا فَإِنَّــكَ رَجِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 77, 'وَإِنَّ عَلَيْــكَ لَعْنَتِيَ إِلَيٰ يَوْمِ ۱لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 78, 'قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَيٰ يَوْمِ يُبْعَثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 79, 'قَالَ فَإِنَّــكَ مِــنَ ۰لْمُنظَرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 80, 'إِلَيٰ يَوْمِ ۱لْوَقْتِ ۱لْمَعْلُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 81, 'قَالَ فَبِعِزَّتِــكَ لُءَغْوۣيَنَّهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 82, 'إِلاَّ عِبَادَكككَ مِنْهُمُ ۴ڤْمُخْلَصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 83, 'قَالَ فَالْحَقَّ وَالْحَــقَّ أَقُولُؐ لَأَمْلَأَنَّ جَهَنَّمَ مِنــكَ وَمِمَّن تَبِعَــكَ مِنْهُمُ; أَجْمَعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 84, 'قُــلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِــنَ اَجْرٍ وَمَآ أَنَا مِــنَ ۰لْمُتَكَلِّفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 85, 'إِنْ هُوَ إِلاَّ ذِكْرٌ لِّلْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (38, 86, 'وَلَتَعْلَمُنَّ نَبَأَهُ„ بَعْدَ حِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ تَنزۣيــلُ ۴لْكِتَـٰبِ مِــنَ ۰للَّهِ ۱لْعَزۣيزۣ ۱لْحَكِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 2, 'إِنَّـآ أَنزَلْنَآ إِلَيْــكَ ۰لْكِتَـٰبَ بِالْحَقِّ فَاعْبُدِ ۱للَّهَ مُخْلِصاً لَّهُ ۴لدِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 3, 'أَلاَ لِلهِ ۱لدِّيــنُ ۴لْخَالِصُؐ وَالذِينَ "تَّخَذُواْ مِن دُونِهِ“ أَوْلِيَآءَ مَا نَعْبُدُهُمُ; إِلاَّ لِيُقَرّۣبُونَآ إِلَي ۰للَّهِ زُلْفۭيٰٓؐ إِنننَّ ۰للَّهَ يَحْكُمُ بَيْنَهُمْ فِى مَا هُمْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 4, '472 إِنَّ ۰للَّهَ لاَ يَهْدِى مَنْ هُوَ كَـٰذِبٌ كَفَّارٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 5, 'لَّوَ اَرَادَ ۰للَّهُ أَنْ يَّتَّخِذَ وَلَداً لاَّصْطَفۭيٰ مِمَّا يَخْلُــقُ مَا يَشَآءُؐ سُبْحَـٰنَهُؐ, هُوَ ۰للَّهُ ۴لْوَ؛حِدُ ۴لْقَهَّارُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 6, 'خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ بِالْحَقﱢّؐ يُكَوّۣرُ ۴ليْــلَ عَلَي ۰لنَّهۭارۣ وَيُكَوّۣرُ ۴لنَّهَارَ عَلَي ۰ليْلِؐ وَسَخَّرَ ۰لشَّمْسَ وَالْقَمَرَؐ كُلٌّ يَجْرۣى لَأِجَــلٍ مُّسَمّــيٗؐ اَلاَ هُوَ ۰لْعَزۣيزُ ۴لْغَفَّـٰرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 7, 'خَلَقَكُم مِّن نَّفْسٍ وَ؛حِدَةٍ ثُمَّ جَعَـلَ مِنْهَا زَوْجَهَاؐ وَأَنزَلَ لَكُم مِّــنَ ۰لاَنْعَـٰمِ ثَمَـٰنِيَةَ أَزْوَ؛جٍؐ يَخْلُقُكُمْ فِى بُطُونِ ٱُمَّهَـٰتِكُمْ خَلْقاً مِّنۢ بَعْدِ خَلْقٍ فِى ظُلُمَـٰتٍ ثَـچَثٍؐ ذَ؛لِكُمُ ۴للَّهُ رَبُّكُمْ لَهُ ۴لْمُلْكُؐ لآَ إِچَهَ إِلاَّ هُوَؐ فَأَنّۭــيٰ تُصْرَفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 8, 'إِن تَكْفُرُواْ فَإِنننَّ ۰للَّهَ غَنِــيّﹲ عَنكُمْؐ وَلاَ يَرْضۭـيٰ لِعِبَادِهِ ۱لْكُفْرَؐ وَإِن تَشْكُرُواْ يَرْضَهُ لَكُمْؐ وَلاَ تَزۣرُ وَازۣرَةٌ وۣزْرَ ٱُخْرۭيٰؐ ثُمَّ إِلَيٰ رَبِّكُم مَّرْجِعُكُمْ فَيُنَبِّيؖكُم بِمَا كُنتُمْ تَعْمَلُونَؐ إِنَّهُ„ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 9, '© وَإِذَا مَسَّ ۰لِانسَـٰــنَ ضُرٌّ دَعَا رَبَّهُ„ مُنِيباٗ اِلَيْهِؐ ثُمَّ إِذَا خَوَّلَهُ„ نِعْمَةً مِّنْهُ نَسِــيَ مَا كَانَ يَدْعُوٓاْ إِلَيْهِ مِن قَبْلُ وَجَعَلَ لِلهِ أَندَاداً لِّيُضِلَّ عَن سَبِيلِهِؐ” 47 قُــلْ تَمَتَّعْ بِكُفْرۣكككَ قَلِيلٗا اِنَّــكَ مِــنَ اَصْحَـٰبِ ۱لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 10, 'أَمَنْ هُوَ قَـٰنِت٘ —انَآءَ ۰ليْــلۣ سَاجِداً وَقَآئِماً يَحْذَرُ ۴لاَخِرَةَ وَيَرْجُواْ رَحْمَةَ رَبِّهِؐ” قُلْ هَلْ يَسْتَوۣى ۱لذِيــنَ يَعْلَمُونَ وَالذِيــنَ لاَ يَعْلَمُونَؐ إِنَّمَا يَتَذَكَّرُ ٱُوْلُواْ ۴لاَلْبَـٰبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 11, 'قُلْ يَـٰعِبَادِ ۱لذِيــنَ ءَامَنُواْ èتَّقُواْ رَبَّكُمْؐ لِلذِيــنَ أَحْسَنُواْ فِى هَـٰذِهِ ۱لدُّنْيۭا حَسَنَةٌؐ وَأَرْضُ ۴للَّهِ وَ؛سِعَة٘ؐ اِنَّمَا يُوَفَّــي ۰لصَّـٰبِرُونَ أَجْرَهُم بِغَيْرۣ حِسَابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 12, 'قُلِ اِنِّيَ ٱُمِرْتُ أَنننَ اَعْبُدَ ۰للَّهَ مُخْلِصاً لَّهُ ۴لدِّينَ وَٱُمِرْتُ لَأِنَ اَكُونَ أَوَّلَ ۰لْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 13, 'قُلِ اِنِّيَ أَخَافُ إِنْ عَصَيْتُ رَبِّى عَذَابَ يَوْمٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 14, 'قُـلِ ۱للَّهَ أَعْبُدُ مُخْلِصاً لَّهُ„ دِينِىؐ فَاعْبُدُواْ مَا شِيؔتُم مِّن دُونِهِؐ” قُلِ اِنَّ ۰لْخَـٰسِرۣيــنَ ۰لذِيــنَ خَسِرُوٓاْ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ۰لْقِيَـٰمَةِؐ أَلاَ ذَ؛لِكَ هُوَ ۰لْخُسْرَانُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 15, 'لَهُم مِّن فَوْقِهِمْ ظُلَلٌ مِّنَ ۰لنّۭارۣ وَمِن تَحْتِهِمْ ظُلَلٌؐ ذَ؛لِــكَ يُخَوّۣفُ ۴للَّهُ بِهِ” عِبَادَهُؐ, يَـٰعِبَادِ فَاتَّقُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 16, 'وَالذِيــنَ "جْتَنَبُواْ ۴لطَّـٰغُوتَ أَنْ يَّعْبُدُوهَا وَأَنَابُوٓاْ إِلَــي ۰للَّهِ لَهُمُ ۴لْبُشْرۭيٰؐ فَبَشِّرْ عِبَادِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 17, '۱لذِينَ يَسْتَمِعُونَ ۰لْقَوْلَ 474 فَيَتَّبِعُونَ أَحْسَنَهُؐ; ٱُوْلَئِــكَ ۰لذِيــنَ هَدۭيٰهُمُ ۴للَّهُؐ وَٱُوْلَئِكَ هُمُ; ٱُوْلُواْ ۴لاَلْبَـٰبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 18, 'أَفَمَــنْ حَقَّ عَلَيْهِ كَلِمَةُ ۴لْعَذَابِ أَفَأَنتَ تُنقِذُ مَن فِى ۱لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 19, 'چَكِـنِ ۱لذِينَ "تَّقَوْاْ رَبَّهُمْ لَهُمْ غُرَفٌ مِّن فَوْقِهَا غُرَفٌ مَّبْنِيَّةٌ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُؐ وَعْدَ ۰للَّهِؐ لاَ يُخْلِفُ ۴للَّهُ ۴لْمِيعَادَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 20, 'أَلَمْ تَرَ أَنَّ ۰للَّهَ أَنزَلَ مِنَ ۰لسَّمَآءِ مَآءً فَسَلَكَهُ„ يَنَـٰبِيعَ فِى ۱لاَرْضضضِ ثُمَّ يُخْرۣجُ بِهِ” زَرْعاً مُّخْتَلِفاٗ اَلْوَ؛نُهُ„ ثُمَّ يَهِيجُ فَتَرۭيٰهُ مُصْفَرّاً ثُمَّ يَجْعَلُهُ„ حُطَـٰماٗؐ اِنَّ فِى ذَ؛لِــكَ لَذِكْرۭيٰ لُءِوْلِى ۱لاَلْبَـٰـــبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 21, 'أَفَمَن شَرَحَ ۰للَّهُ صَدْرَهُ„ لِلِاسْچَمِ فَهُوَ عَلَيٰ نُورٍ مِّن رَّبِّهِؐ” فَوَيْلٌ لِّلْقَـٰسِيَةِ قُلُوبُهُم مِّن ذِكْرۣ ۱للَّهِؐ ٱُوْلَئِــكَ فِى ضَچَلٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 22, '۱للَّهُ نَزَّلَ أَحْسَــنَ ۰لْحَدِيثِ كِتَـٰباً مُّتَشَـٰبِهاً مَّثَانِيَؐ تَقْشَعِرُّ مِنْهُ جُلُودُ ۴لذِيــنَ يَخْشَوْنَ رَبَّهُمْ ثُمَّ تَلِينُ جُلُودُهُمْ وَقُلُوبُهُمُ; إِلَـيٰ ذِكْرۣ ۱للَّهِؐ ذَ؛لِكَ هُدَييي ۰للَّهِ يَهْدِى بِهِ” مَنْ يَّشَآءُؐ وَمَنْ يُّضْلِـلِ ۱للَّهُ فَمَا لَهُ„ مِــنْ هَادٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 23, 'اَفَمَنْ يَّتَّقِى بِوَجْهِهِ” سُوٓءَ ۰لْعَذَابِ يَوْمَ ۰لْقِيَـٰمَةِؐ وَقِيلَ لِلظَّـٰلِمِينَ ذُوقُواْ مَا كُنتُمْ 475 تَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 24, 'كَذَّبَ ۰لذِينَ مِن قَبْلِهِمْ فَأَتۭيٰهُمُ ۴لْعَذَابُ مِــنْ حَيْثُ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 25, 'فَأَذَاقَهُمُ ۴للَّهُ ۴لْخِزْيَ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَلَعَذَابُ ۴لاَخِرَةِ أَكْبَرُ لَوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 26, 'وَلَقَد ضَّرَبْنَا لِلنَّاسسسِ فِى هَـٰذَا ۰لْقُرْءَانِ مِــن كُــلّۣ مَثَلٍ لَّعَلَّهُمْ يَتَذَكَّرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 27, 'قُرْءَاناٗ عَرَبِيّاٗ غَيْرَ ذى عِوَجٍ لَّعَلَّهُمْ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 28, 'ضَرَبَ ۰للَّهُ مَثَلًا رَّجُلًا فِيهِ شُرَكَآءُ مُتَشَـٰكِسُونَ وَرَجُلًا سَلَماً لِّرَجُلٖؐ هَلْ يَسْتَوۣيَـٰــنۣ مَثَلٗؐا ۱لْحَمْدُ لِلهِؐ بَــلَ اَكْثَرُهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 29, 'إِنَّــكَ مَيِّتٌ وَإِنَّهُم مَّيِّتُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 30, 'ثُمَّ إِنَّكُمْ يَوْمَ ۰لْقِيَـٰمَةِ عِندَ رَبِّكُمْ تَخْتَصِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 31, '¤ فَمَــنَ اَظْلَمُ مِمَّــن كَذَبَ عَلَــي ۰للَّهِ وَكَذَّبَ بِالصِّدْقِ إِذْ جَآءَهُؐ; أَلَيْـسَ فِى جَهَنَّمَ مَثْويً لِّلْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 32, 'وَاﻟ﮲ جَآءَ بِالصِّدْقِ وَصَدَّقَ بِهِ“ ٱُوْلَئِــكَ هُمُ ۴لْمُتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 33, 'لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْؐ ذَ؛لِــكَ جَزَ×ؤُاْ ۴ڤْمُحْسِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 34, 'لِيُكَفِّرَ ۰للَّهُ عَنْهُمُ; أَسْوَأَ ۰ﻟ﮲ عَمِلُواْ وَيَجْزۣيَهُمُ; أَجْرَهُم بِأَحْسَنِ ۱ﻟ﮲ كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 35, 'أَلَيْــسَ ۰للَّهُ بِكَافٖ عَبْدَهُؐ, وَيُخَوّۣفُونَــكَ بِالذِينَ 476 مِن دُونِهِؐ” وَمَنْ يُّضْلِـلِ ۱للَّهُ فَمَا لَهُ„ مِــنْ هَادٍؐ وَمَنْ يَّهْدِ ۱للَّهُ فَمَا لَهُ„ مِــن مُّضِل؉ّؐ اَلَيْــسَ ۰للَّهُ بِعَزۣيزٍ ذى ''نتِقَامٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 36, 'وَلَئِن سَأَلْتَهُم مَّــنْ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ لَيَقُولُــنَّ ۰للَّهُؐ قُلَ اَفَرَ×يْتُم مَّا تَدْعُونَ مِن دُونِ ۱للَّهِ إِنَ اَرَادَنِــيَ ۰للَّهُ بِضُرّٖ هَلْ هُنَّ كَـٰشِفَـٰتُ ضُرّۣهِ“ أَوَ اَرَادَنِى بِرَحْمَةٖ هَلْ هُنَّ مُمْسِكَـٰتُ رَحْمَتِهِؐ” قُــلْ حَسْبِــيَ ۰للَّهُؐ عَلَيْهِ يَتَوَكَّــلُ ۴لْمُتَوَكِّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 37, 'قُلْ يَـٰقَوْمِ ''عْمَلُواْ عَلَــيٰ مَكَانَتِكُمُ; إِنِّى عَـٰمِلٌؐ فَسَوْفَ تَعْلَمُونَ مَـنْ يَّاتِيهِ عَذَابٌ يُخْزۣيهِ وَيَحِــلُّ عَلَيْهِ عَذَابٌ مُّقِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 38, 'اِنَّـآ أَنزَلْنَا عَلَيْــكَ ۰لْكِتَـٰبَ لِلنَّاسِ بِالْحَقﱢّؐ فَمَنِ ''هْتَدۭيٰ فَلِنَفْسِهِؐ” وَمَــن ضَلَّ فَإِنَّمَا يَضِــلُّ عَلَيْهَاؐ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 39, '۱للَّهُ يَتَوَفَّــي ۰لاَنفُـسَ حِينَ مَوْتِهَا وَالتِى لَمْ تَمُتْ فِى مَنَامِهَاؐ فَيُمْسِــكُ ۴لتِى قَضۭــيٰ عَلَيْهَا ۰لْمَوْتَ وَيُرْسِــلُ ۴لاُخْرۭيٰٓ إِلَـيٰٓ أَجَلٍ مُّسَمّيٗؐ اِنَّ فِى ذَ؛لِكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 40, 'أَمِ ''تَّخَذُواْ مِن دُونِ ۱للَّهِ شُفَعَآءَؐ قُلَ اَوَلَوْ كَانُواْ لاَ يَمْلِكُونَ شَيْـٔاً وَلاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 41, 'قُل لِّلهِ ۱لشَّفَـٰعَةُ جَمِيعاًؐ لَّهُ„ مُلْكُ 477 ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ ثُمَّ إِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 42, 'وَإِذَا ذُكِرَ ۰للَّهُ وَحْدَهُ èشْمَأَزَّتْ قُلُوبُ ۴لذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِؐ وَإِذَا ذُكِرَ ۰لذِينَ مِن دُونِهِ“ إِذَا هُمْ يَسْتَبْشِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 43, 'قُلِ ۱للَّهُمَّ فَاطِرَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضضضِ عَـٰلِمَ ۰لْغَيْــبِ وَالشَّهَـٰدَةِ أَنتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِى مَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 44, 'وَلَوَ اَنَّ لِلذِيــنَ ظَلَمُواْ مَا فِى ۱لاَرْضِ جَمِيعاً وَمِثْلَهُ„ مَعَهُ„ لاَفْتَدَوْاْ بِهِ” مِن سُوٓءِ ۱لْعَذَابِ يَوْمَ ۰لْقِيَـٰمَةِؐ وَبَدَا لَهُم مِّــنَ ۰للَّهِ مَا لَمْ يَكُونُواْ يَحْتَسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 45, 'وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا كَسَبُواْؐ وَحَاقَ بِهِم مَّاكَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 46, 'فَإِذَا مَسَّ ۰لِانسَـٰــنَ ضُرٌّ دَعَانَا ثُمَّ إِذَا خَوَّلْنَـٰهُ نِعْمَةً مِّنَّا قَالَ إِنَّمَآ ٱُوتِيتُهُ„ عَلَيٰ عِلْمٙؐ بَلْ هِيَ فِتْنَةٌؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 47, 'قَدْ قَالَهَا ۰لذِينَ مِن قَبْلِهِمْ فَمَآ أَغْنۭيٰ عَنْهُم مَّا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 48, 'فَأَصَابَهُمْ سَيِّـَٔاتُ مَا كَسَبُواْؐ وَالذِيــنَ ظَلَمُواْ مِنْ هَـٰٓؤُلآَءِ سَيُصِيبُهُمْ سَيِّـَٔاتُ مَا كَسَبُواْ وَمَا هُم بِمُعْجِزۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 49, 'أَوَلَمْ يَعْلَمُوٓاْ أَنَّ ۰للَّهَ 478 يَبْسُطُ ۴لرّۣزْقَ لِمَـنْ يَّشَآءُ وَيَقْدِرُؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 50, 'قُلْ يَـٰعِبَادِيَ ۰لذِيــنَ أَسْرَفُواْ عَلَــيٰٓ أَنفُسِهِمْ لاَ تَقْنَطُواْ مِن رَّحْمَةِ ۱للَّهِؐ إِنَّ ۰للَّهَ يَغْفِرُ ۴لذُّنُوبَ جَمِيعاٗؐ اِنَّهُ„ هُوَ ۰لْغَفُورُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 51, '© وَأَنِيبُوٓاْ إِلَيٰ رَبِّكُمْ وَأَسْلِمُواْ لَهُ„ مِن قَبْلِ أَنْ يَّاتِيَكُمُ ۴لْعَذَابُ ثُمَّ لاَ تُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 52, 'وَاتَّبِعُوٓاْ أَحْسَــنَ مَآ ٱُنزۣلَ إِلَيْكُم مِّن رَّبِّكُم مِّن قَبْلِ أَنْ يَّاتِيَكُمُ ۴لْعَذَابُ بَغْتَةً وَأَنتُمْ لاَ تَشْعُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 53, 'أَن تَقُولَ نَفْــسٌ يَـٰحَسْرَتۭيٰ عَلَــيٰ مَا فَرَّطْتُّ فِى جَنۢبِ ۱للَّهِ وَإِن كُنتُ لَمِــنَ ۰ڤسَّـٰخِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 54, 'أَوْ تَقُولَ لَوَ اَنَّ ۰للَّهَ هَدۭيٰنِى لَكُنتُ مِــنَ ۰لْمُتَّقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 55, 'أَوْ تَقُولَ حِينَ تَرَي ۰لْعَذَابَ لَوَ اَنَّ لِى كَرَّةً فَأَكُونَ مِــنَ ۰ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 56, 'بَلۭــيٰ قَدْ جَآءَتْــكَ ءَايَـٰتِى فَكَذَّبْتَ بِهَا وَاسْتَكْبَرْتَ وَكُنتَ مِــنَ ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 57, 'وَيَوْمَ ۰لْقِيَـٰمَةِ تَرَي ۰لذِيــنَ كَذَبُواْ عَلَي ۰للَّهِ وُجُوهُهُم مُّسْوَدَّة٘ؐ اَلَيْسَ فِى جَهَنَّمَ مَثْويً لِّلْمُتَكَبِّـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 58, 'وَيُنَجّىِ ۱للَّهُ ۴لذِينَ "تَّقَوْاْ بِمَفَازَتِهِمْ لاَ يَمَسُّهُمُ ۴لسُّوٓءُ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 59, '۰للَّهُ خَـٰلِــقُ كُلِّ شَيْءٍؐ وَهُوَ عَلَــيٰ كُلِّ 479 شَيْءٍ وَكِيلٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 60, 'لَّهُ„ مَقَالِيدُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَالذِينَ كَفَرُواْ بِـَٔايَـٰتِ ۱للَّهِ ٱُوْلَئِــكَ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 61, 'قُـلَ اَفَغَيْرَ ۰للَّهِ تَامُرُونِــيَ أَعْبُدُ أَيُّهَا ۰لْجَـٰهِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 62, 'وَلَقَدُ ۷وحِيَ إِلَيْكَ وَإِلَي ۰لذِينَ مِن قَبْلِــكَ لَئِنَ اَشْرَكْتَ ڤَيَحْبَطَــنَّ عَمَلُــكَ وَلَتَكُونَنَّ مِــنَ ۰لْخَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 63, 'بَـلِ ۱للَّهَ فَاعْبُدْ وَكُن مِّنَ ۰لشَّـٰكِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 64, 'وَمَا قَدَرُواْ ۴للَّهَ حَقَّ قَدْرۣهِ” وَالاَرْضُ جَمِيعاً قَبْضَتُهُ„ يَوْمَ ۰لْقِيَـٰمَةِ وَالسَّمَـٰوَ؛تُ مَطْوۣيَّـٰتٛ بِيَمِينِهِؐ” سُبْحَـٰنَهُ„ وَتَعَـٰلۭــيٰ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 65, 'وَنُفِخَ فِى ۱لصُّورۣ فَصَعِقَ مَن فِى ۱لسَّمَـٰوَ؛تِ وَمَن فِى ۱لاَرْضِ إِلاَّ مَــن شَآءَ ۰للَّهُؐ ثُمَّ نُفِخَ فِيهِ ٱُخْرۭيٰ فَإِذَا هُمْ قِيَامٌ يَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 66, 'وَأَشْرَقَتِ ۱لاَرْضُ بِنُورۣ رَبِّهَا وَوُضِعَ ۰لْكِتَـٰبُ وَجِـــىٓءَ بِالنَّبِيٓــٕـﯧنَ وَالشُّهَدَآءِ وَقُضِيَ بَيْنَهُم بِالْحَقِّ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 67, 'وَوُفِّيَتْ كُلُّ نَفْسٍ مَّا عَمِلَتْ وَهُوَ أَعْلَمُ بِمَا يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 68, 'وَسِيقَ ۰لذِيــنَ كَفَرُوٓاْ إِلَيٰ جَهَنَّمَ زُمَراٗؐ حَتَّيٰٓ إِذَا جَآءُوهَا فُتِّحَتَ اَبْوَ؛بُهَا وَقَالَ لَهُمْ خَزَنَتُهَآ أَلَمْ يَاتِكُمْ رُسُلٌ مِّنكُمْ يَتْلُونَ 480 عَلَيْكُمُ; ءَايَـٰتِ رَبِّكُمْ وَيُنذِرُونَكُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَاؐ قَالُواْ بَلۭيٰ وَچَكِــنْ حَقَّتْ كَلِمَةُ ۴لْعَذَابِ عَلَــي ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 69, 'قِيــلَ ۸دْخُلُوٓاْ أَبْوَ؛بَ جَهَنَّمَ خَـٰلِدِينَ فِيهَاؐ فَبِيــسَ مَثْوَي ۰لْمُتَكَبِّـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 70, 'وَسِيــقَ ۰لذِينَ "تَّقَوْاْ رَبَّهُمُ; إِلَي ۰لْجَنَّةِ زُمَراٗؐ حَتَّيٰٓ إِذَا جَآءُوهَا وَفُتِّحَــتَ اَبْوَ؛بُهَا وَقَالَ لَهُمْ خَزَنَتُهَا سَچَم٘ عَلَيْكُمْ طِبْتُمْ فَادْخُلُوهَا خَـٰلِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 71, 'وَقَالُواْ ۴لْحَمْدُ لِلهِ ۱ﻟ﮲ صَدَقَنَا وَعْدَهُ„ وَأَوْرَثَنَا ۰لاَرْضضضَ نَتَبَوَّٱُ مِــنَ ۰لْجَنَّةِ حَيْثُ نَشَآءُ فَنِعْمَ أَجْرُ ۴لْعَـٰمِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (39, 72, 'وَتَرَي ۰لْمَلَئِكَةَ حَآفِّيــنَ مِنْ حَوْلِ ۱لْعَرْشِ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْؐ وَقُضِيَ بَيْنَهُم بِالْحَقﱢّؐ وَقِيــلَ ۰لْحَمْدُ لِلهِ رَبِّ ۱لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓؐ تَنزۣيلُ ۴لْكِتَـٰبِ مِــنَ ۰للَّهِ ۱لْعَزۣيزۣ ۱لْعَلِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 2, 'غَافِـرۣ ۱لذَّنۢبِ وَقَابِـلِ ۱لتَّوْبِ شَدِيدِ ۱لْعِقَابِ ذى ۱لطَّوْلِؐ لآَ إِچَهَ إِلاَّ هُوَؐ إِلَيْهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 3, '481 مَا يُجَـٰدِلُ فِىٓ ءَايَـٰتِ ۱للَّهِ إِلاَّ ۰لذِيــنَ كَفَرُواْؐ فَلاَ يَغْرُرْكَ تَقَلُّبُهُمْ فِى ۱لْبِچَدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 4, 'كَذَّبَــتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَالاَحْزَابُ مِـنۢ بَعْدِهِمْؐ وَهَمَّتْ كُلُّ ٱُمَّةٙ بِرَسُولِهِمْ لِيَاخُذُوهُؐ وَجَـٰدَلُواْ بِالْبَـٰطِلِ لِـيُدْحِضُواْ بِهِ ۱لْحَقَّ فَأَخَذتُّهُمْؐ فَكَيْفَ كَانَ عِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 5, 'وَكَذَ؛لِــكَ حَقَّتْ كَلِمَـٰتُ رَبِّكَ عَلَي ۰لذِينَ كَفَرُوٓاْ أَنَّهُمُ; أَصْحَـٰبُ ۴لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 6, '۱لذِيــنَ يَحْمِلُونَ ۰لْعَرْشَ وَمَنْ حَوْلَهُ„ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيُومِنُونَ بِهِ” وَيَسْتَغْفِرُونَ لِلذِيــنَ ءَامَنُواْؐ رَبَّنَا وَسِعْتَ كُــلَّ شَيْءٍ رَّحْمَةً وَعِلْماً فَاغْفِرْ لِلذِيــنَ تَابُواْ وَاتَّبَعُواْ سَبِيلَــكَ وَقِهِمْ عَذَابَ ۰لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 7, 'رَبَّنَا وَأَدْخِلْهُمْ جَنَّـٰتِ عَدْنٖ ۱لتِى وَعَدتَّهُمْ وَمَــن صَلَحَ مِــنَ —ابَآئِهِمْ وَأَزْوَ؛جِهِمْ وَذُرّۣيَّـٰتِهِمُؐ; إِنَّكَ أَنتَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 8, 'وَقِهِمُ ۴لسَّيِّـَٔاتِؐ وَمَن تَقِ ۱لسَّيِّـَٔاتِ يَوْمَئِذٍ فَقَدْ رَحِمْتَهُؐ, وَذَ؛لِكَ هُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 9, 'إِنَّ ۰لذِينَ كَفَرُواْ يُنَادَوْنَ لَمَقْتُ ۴للَّهِ أَكْبَرُ مِــن مَّقْتِكُمُ; أَنفُسَكُمُ; إِذْ تُدْعَوْنَ إِلَي ۰لِايمَـٰنِ فَتَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 10, 'قَالُواْ رَبَّنَآ 482 أَمَتَّنَا "ثْنَتَيْنِ وَأَحْيَيْتَنَا "ثْنَتَيْنِ فَاعْتَرَفْنَا بِذُنُوبِنَا فَهَلِ اِلَيٰ خُرُوجٍ مِّــن سَبِيلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 11, 'ذَ؛لِكُم بِأَنَّهُ; إِذَا دُعِــيَ ۰للَّهُ وَحْدَهُ„ كَفَرْتُمْ وَإِنْ يُّشْرَكككْ بِهِ” تُومِنُواْؐ فَالْحُكْمُ لِلهِ ۱لْعَلِـيِّ ۱لْكَبِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 12, 'هُوَ ۰ﻟ﮲ يُرۣيكُمُ; ءَايَـٰتِهِ” وَيُنَزّۣلُ لَكُم مِّــنَ ۰لسَّمَآءِ رۣزْقاًؐ وَمَا يَتَذَكَّرُ إِلاَّ مَنْ يُّنِيــبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 13, 'فَادْعُواْ ۴للَّهَ مُخْلِصِينَ لَهُ ۴لدِّينَ وَلَوْ كَرۣهَ ۰لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 14, 'رَفِيعُ ۴لدَّرَجَـٰتِ ذُو ۴لْعَرْشِؐ يُلْقِى ۱لرُّوحَ مِنَ اَمْرۣهِ” عَلَيٰ مَنْ يَّشَآءُ مِنْ عِبَادِهِ” لِيُنذِرَ يَوْمَ ۰لتَّچَقِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 15, 'يَوْمَ هُم بَـٰرۣزُونَؐ لاَ يَخْفۭــيٰ عَلَي ۰للَّهِ مِنْهُمْ شَيْءٌؐ لِّمَـنِ ۱لْمُلْــكُ ۴لْيَوْمَؐ لِلهِ ۱لْوَ؛حِدِ ۱لْقَهّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 16, '۱لْيَوْمَ تُجْزۭيٰ كُلُّ نَفْـسٙ بِمَا كَسَبَتْؐ لاَ ظُلْمَ ۰لْيَوْمَؐ إِنَّ ۰للَّهَ سَرۣيعُ ۴لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 17, 'وَأَنذِرْهُمْ يَوْمَ ۰لاَزۣفَةِ إِذِ ۱لْقُلُوبُ لَدَي ۰لْحَنَاجِرۣ كَـٰظِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 18, 'مَا لِلظَّـٰلِمِينَ مِنْ حَمِيمٍ وَلاَ شَفِيعٍ يُطَاعُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 19, 'يَعْلَمُ خَآئِنَةَ ۰لاَعْيُنِ وَمَا تُخْفِى ۱لصُّدُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 20, 'وَاللَّهُ يَقْضِى بِالْحَقﱢّؐ وَالذِيــنَ تَدْعُونَ مِن دُونِهِ” لاَ يَقْضُونَ بِشَىْءٖؐ اِنَّ ۰للَّهَ هُوَ ۰لسَّمِيعُ ۴لْبَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 21, '© أَوَلَمْ يَسِيرُواْ فِى 48 ۱لاَرْضضضِ فَيَنظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِيــنَ كَانُواْ مِن قَبْلِهِمْؐ كَانُواْ هُمُ; أَشَدَّ مِنْهُمْ قُوَّةً وَءَاثَاراً فِى ۱لاَرْضِ فَأَخَذَهُمُ ۴للَّهُ بِذُنُوبِهِمْؐ وَمَا كَانَ لَهُم مِّــنَ ۰للَّهِ مِنْ وَّاقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 22, 'ذَ؛لِــكَ بِأَنَّهُمْ كَانَت تَّاتِيهِمْ رُسُلُهُم بِالْبَيِّنَـٰتِ فَكَفَرُواْ فَأَخَذَهُمُ ۴للَّهُؐ إِنَّهُ„ قَوۣيٌّ شَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 23, 'وَلَقَدَ اَرْسَلْنَا مُوسۭـيٰ بِـَٔايَـٰتِنَا وَسُلْطَـٰنٍ مُّبِينٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 24, 'اِلَيٰ فِرْعَوْنَ وَهَامَـٰنَ وَقَارُونَ فَقَالُواْ سَـٰحِرٌ كَذَّابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 25, 'فَلَمَّا جَآءَهُم بِالْحَقِّ مِنْ عِندِنَا قَالُواْ ۶قْتُلُوٓاْ أَبْنَآءَ ۰لذِيــنَ ءَامَنُواْ مَعَهُ„ وَاسْتَحْيُواْ نِسَآءَهُمْؐ وَمَا كَيْدُ ۴لْكۭـٰفِـرۣينَ إِلاَّ فِى ضَچَلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 26, 'وَقَالَ فِرْعَوْنُ ذَرُونِىٓ أَقْتُلْ مُوسۭيٰ وَلْيَدْعُ رَبَّهُ; إِنِّيَ أَخَافُ أَنْ يُّبَدِّلَ دِينَكُمْ وَأَنْ يُّظْهِرَ فِى ۱لاَرْضِ ۱لْفَسَادَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 27, 'وَقَالَ مُوسۭيٰٓ إِنِّى عُذْتُ بِرَبِّى وَرَبِّكُم مِّــن كُــلّۣ مُتَكَبِّرٍ لاَّ يُومِنُ بِيَوْمِ ۱لْحِسَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 28, 'وَقَالَ رَجُلٌ مُّومِنٌ مِّنَ —الِ فِرْعَوْنَ يَكْتُمُ إِيمَـٰنَهُ; أَتَقْتُلُونَ رَجُلٗا اَنْ يَّقُولَ رَبِّــيَ ۰للَّهُ وَقَدْ جَآءَكُم بِالْبَيِّنَـٰتِ مِن رَّبِّكُمْ وَإِنْ يَّــكُ كَـٰذِباً فَعَلَيْهِ كَذِبُهُ, 484 وَإِنْ يَّــكُ صَادِقاً يُصِبْكُم بَعْضُ ۴ﻟ﮲ يَعِدُكُمُؐ; إِنَّ ۰للَّهَ لاَ يَهْدِى مَنْ هُوَ مُسْرۣفٌ كَذَّابٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 29, 'يَـٰقَوْمِ لَكُمُ ۴لْمُلْــكُ ۴لْيَوْمَ ظَـٰهِرۣيــنَ فِى ۱لاَرْضِ فَمَنْ يَّنصُرُنَا مِنۢ بَأْسِ ۱للَّهِ إِن جَآءَنَاؐ قَالَ فِرْعَوْنُ مَآ ٱُرۣيكُمُ; إِلاَّ مَآ أَرۭيٰ وَمَآ أَهْدِيكُمُ; إِلاَّ سَبِيلَ ۰لرَّشَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 30, 'وَقَالَ ۰ﻟـذِىٓ ءَامَنَ يَـٰقَوْمِ إِنِّــيَ أَخَافُ عَلَيْكُم مِّثْلَ يَوْمِ ۱لاَحْزَابِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 31, 'مِثْلَ دَأْبِ قَوْمِ نُوحٍ وَعَادٍ وَثَمُودَ وَالذِينَ مِنۢ بَعْدِهِمْؐ وَمَا ۰للَّهُ يُرۣيدُ ظُلْماً لِّلْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 32, 'وَيَـٰقَوْمِ إِنِّيَ أَخَافُ عَلَيْكُمْ يَوْمَ ۰لتَّنَادِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 33, 'يَوْمَ تُوَلُّونَ مُدْبِـرۣيــنَ مَا لَكُم مِّــنَ ۰للَّهِ مِــنْ عَـٰصِمٍؐ وَمَنْ يُّضْلِلِ ۱للَّهُ فَمَا لَهُ„ مِــنْ هَادٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 34, 'وَلَقَدْ جَآءَكُمْ يُوسُفُ مِن قَبْلُ بِالْبَيِّنَـٰتِ فَمَا زۣلْتُمْ فِى شَــكٍّ مِّمَّا جَآءَكُم بِهِ” حَتَّيٰٓ إِذَا هَلَــكَ قُلْتُمْ لَنْ يَّبْعَثَ ۰للَّهُ مِنۢ بَعْدِهِ” رَسُولًؐا كَذَ؛لِكَ يُضِــلُّ ۴للَّهُ مَنْ هُوَ مُسْرۣفٌ مُّرْتَاب٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 35, '۱لذِينَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِ ۱للَّهِ بِغَيْرۣ سُلْطَـٰن؉ اَتۭيٰهُمْؐ كَبُرَ مَقْتاٗ عِندَ ۰للَّهِ وَعِندَ ۰لذِينَ ءَامَنُواْؐ كَذَ؛لِــكَ يَطْبَعُ ۴للَّهُ عَلَــيٰ كُـلِّ قَلْبِ مُتَكَبِّرٍ جَبّۭارٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 36, '485 وَقَالَ فِرْعَوْنُ يَـٰهَامَـٰنُ èبْنِ لِى صَرْحاً لَّعَلِّيَ أَبْلُغُ ۴لاَسْبَـٰبَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 37, 'أَسْبَـٰبَ ۰لسَّمَـٰوَ؛تِ فَأَطَّلِعُ إِلَيٰٓ إِچَهِ مُوسۭيٰ وَإِنِّى لَأَظُنُّهُ„ كَـٰذِباًؐ وَكَذَ؛لِــكَ زُيِّنَ لِـفِرْعَوْنَ سُوٓءُ عَمَلِهِ” وَصَدَّ عَـنِ ۱لسَّبِيلِؐ وَمَا كَيْدُ فِرْعَوْنَ إِلاَّ فِى تَبَابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 38, 'وَقَالَ ۰ﻟـذِىٓ ءَامَنَ يَـٰقَوْمِ ''تَّبِعُونِ أَهْدِكُمْ سَبِيلَ ۰لرَّشَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 39, 'يَـٰقَوْمِ إِنَّمَا هَـٰذِهِ ۱لْحَيَوٰةُ ۴لدُّنْيۭا مَتَـٰعٌؐ وَإِنَّ ۰لاَخِرَةَ هِيَ دَارُ ۴لْقَرۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 40, 'مَــنْ عَمِــلَ سَـيِّيؕـةً فَلاَ يُجْزۭيٰٓ إِلاَّ مِثْلَهَاؐ وَمَــنْ عَمِــلَ صَـٰڤِحاً مِّــن ذَكَر۫ اَوُ ۷نثۭيٰ وَهُوَ مُومِنٌ فَٱُوْلَئِكَ يَدْخُلُونَ ۰لْجَنَّةَ يُرْزَقُونَ فِيهَا بِغَيْرۣ حِسَابٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 41, '¤ وَيَـٰقَوْمِ مَا لِــيَ أَدْعُوكُمُ; إِلَــي ۰لنَّجَوٰةِ وَتَدْعُونَنِىٓ إِلَي ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 42, 'تَدْعُونَنِى لَأِكْفُرَ بِاللَّهِ وَٱُشْرۣكككَ بِهِ” مَا لَيْـسَ لِى بِهِ” عِلْمٌ وَأَنَآ أَدْعُوكُمُ; إِلَــي ۰لْعَزۣيزۣ ۱لْغَفّۭـٰرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 43, 'لاَ جَرَمَ أَنَّمَا تَدْعُونَنِىٓ إِلَيْهِ لَيْــسَ لَهُ„ دَعْوَةٌ فِى ۱لدُّنْيۭا وَلاَ فِى ۱لاَخِرَةِ وَأَنَّ مَرَدَّنَـآ إِلَــي ۰للَّهِ وَأَنَّ ۰لْمُسْرۣفِيــنَ هُمُ; أَصْحَـٰبُ ۴لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 44, 'فَسَتَذْكُرُونَ مَآ أَقُولُ لَكُمْؐ وَٱُفَوّۣضضضُ أَمْرۣيَ إِلَــي ۰للَّهِؐ 486 إِنَّ ۰للَّهَ بَصِيرٛ بِالْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 45, 'فَوَقۭيٰهُ ۴للَّهُ سَيِّـَٔاتِ مَا مَكَرُواْؐ وَحَاقَ بِـَٔالِ فِرْعَوْنَ سُوٓءُ ۴لْعَذَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 46, '۱لنَّارُ يُعْرَضُونَ عَلَيْهَا غُدُوّاً وَعَشِيّاًؐ وَيَوْمَ تَقُومُ ۴لسَّاعَةُ أَدْخِلُوٓاْ ءَالَ فِرْعَوْنَ أَشَدَّ ۰لْعَذَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 47, 'وَإِذْ يَتَحَآجُّونَ فِى ۱لنّۭارۣ فَيَقُولُ ۴لضُّعَفَـٰٓؤُاْ لِلذِينَ "سْتَكْبَرُوٓاْ إِنَّا كُنَّا لَكُمْ تَبَعاً فَهَلَ اَنتُم مُّغْنُونَ عَنَّا نَصِيباً مِّنَ ۰لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 48, 'قَالَ ۰لذِيــنَ "سْتَكْبَرُوٓاْ إِنَّا كُلٌّ فِيهَآ إِنَّ ۰للَّهَ قَدْ حَكَمَ بَيْــنَ ۰لْعِبَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 49, 'وَقَالَ ۰لذِينَ فِى ۱لنّۭارۣ لِخَزَنَةِ جَهَنَّمَ ۸دْعُواْ رَبَّكُمْ يُخَفِّفْ عَنَّا يَوْماً مِّنَ ۰لْعَذَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 50, 'قَالُوٓاْ أَوَلَمْ تَكُ تَاتِيكُمْ رُسُلُكُم بِالْبَيِّنَـٰــتِ قَالُواْ بَلۭــيٰ قَالُواْ فَادْعُواْؐ وَمَا دُعَـٰٓؤُاْ ۴لْكۭـٰفِـرۣينَ إِلاَّ فِى ضَچَلٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 51, 'اِنَّا لَنَنصُرُ رُسُلَنَا وَالذِيــنَ ءَامَنُواْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَيَوْمَ يَقُومُ ۴لاَشْهَـٰدُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 52, 'يَوْمَ لاَ يَنفَعُ ۴لظَّـٰلِمِينَ مَعْذِرَتُهُمْ وَلَهُمُ ۴للَّعْنَةُ وَلَهُمْ سُوٓءُ ۴لدّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 53, 'وَلَقَدَ —اتَيْنَا مُوسَــي ۰لْهُدۭيٰ وَأَوْرَثْنَا بَنِىٓ إِسْرَآءِيلَ ۰لْكِتَـٰبَ هُديً وَذِكْرۭيٰ لُءِوْلِى ۱لاَلْبَـٰــبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 54, 'فَاصْبِـرۣ اِنَّ وَعْدَ ۰للَّهِ حَقٌّؐ 487 وَاسْتَغْفِرْ لِذَنۢبِــكَ وَسَبِّحْ بِحَمْدِ رَبِّــكَ بِالْعَشِيِّ وَالِابْكۭـٰـرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 55, 'إِنَّ ۰لذِيــنَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِ ۱للَّهِ بِغَيْرۣ سُلْطَـٰن؉ اَتۭيٰهُمُ; إِن فِى صُدُورۣهِمُ; إِلاَّ كِبْرٌ مَّا هُم بِبَـٰلِغِيهِؐ فَاسْتَعِذْ بِاللَّهِؐ إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْبَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 56, 'لَخَلْــقُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ أَكْبَرُ مِــنْ خَلْـقِ ۱لنَّاسِؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 57, 'وَمَا يَسْتَوۣى ۱لاَعْمۭيٰ وَالْبَصِيرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 58, 'وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ وَلاَ ۰لْمُسِىٓءُؐ قَلِيلًا مَّا يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 59, 'إِنَّ ۰لسَّاعَةَ ءَلاَتِيَةٌ لاَّ رَيْبَ فِيهَاؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 60, 'وَقَالَ رَبُّكُمُ ۶دْعُونِىٓ أَسْتَجِبْ لَكُمُؐ; إِنَّ ۰لذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِى سَيَدْخُلُونَ جَهَنَّمَ دَاخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 61, '۰للَّهُ ۴ﻟ﮲ جَعَـلَ لَكُمُ ۴ليْـلَ لِتَسْكُنُواْ فِيهِ وَالنَّهَارَ مُبْصِراٗؐ اِنَّ ۰للَّهَ لَذُو فَضْــل۫ عَلَي ۰لنَّاسِؐ وَچَكِنَّ أَكْثَرَ ۰لنَّاسسسِ لاَ يَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 62, 'ذَ؛لِكُمُ ۴للَّهُ رَبُّكُمْؐ خَـٰلِقُ كُــلّۣ شَيْءٍؐ لٓاَّ إِچَهَ إِلاَّ هُوَؐ فَأَنّۭيٰ تُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 63, 'كَذَ؛لِكَ يُوفَكُ ۴لذِيــنَ كَانُواْ بِـَٔايَـٰتِ ۱للَّهِ يَجْحَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 64, '488 ۰للَّهُ ۴ﻟ﮲ جَعَــلَ لَكُمُ ۴لاَرْضضضَ قَـرَاراً وَالسَّمَآءَ بِنَآءً وَصَوَّرَكُمْ فَأَحْسَــنَ صُوَرَكُمْ وَرَزَقَكُم مِّــنَ ۰لطَّيِّبَـٰتِؐ ذَ؛لِكُمُ ۴للَّهُ رَبُّكُمْؐ فَتَبَـٰرَكككَ ۰للَّهُ رَبُّ ۴لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 65, 'هُوَ ۰لْحَيُّؐ لآَ إِچَهَ إِلاَّ هُوَؐ فَادْعُوهُ مُخْلِصِيــنَ لَهُ ۴لدِّيــنَؐ ۰لْحَمْدُ لِلهِ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 66, '© قُـلِ اِنِّى نُهِيتُ أَنَ اَعْبُدَ ۰لذِيــنَ تَدْعُونَ مِن دُونِ ۱للَّهِ لَمَّا جَآءَنِيَ ۰لْبَيِّنَـٰــتُ مِن رَّبِّى وَٱُمِرْتُ أَنُ ۷سْلِمَ لِرَبِّ ۱لْعَـٰلَمِيــنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 67, 'هُوَ ۰ﻟ﮲ خَلَقَكُم مِّن تُرَابٍ ثُمَّ مِــن نُّطْفَةٍ ثُمَّ مِــنْ عَلَقَةٍ ثُمَّ يُخْرۣجُكُمْ طِفْلًا ثُمَّ لِتَبْلُغُوٓاْ أَشُدَّكُمْ ثُمَّ لِتَكُونُواْ شُيُوخاًؐ وَمِنكُم مَّنْ يُّتَوَفّۭيٰ مِن قَبْلُ وَلِتَبْلُغُوٓاْ أَجَلًا مُّسَمّيً وَلَعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 68, 'هُوَ ۰ﻟ﮲ يُحْىِ” وَيُمِيــتُؐ فَإِذَا قَضۭيٰٓ أَمْراً فَإِنَّمَا يَقُولُ لَهُ„ كُنؐ فَيَكُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 69, 'أَلَمْ تَرَ إِلَــي ۰لذِينَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِ ۱للَّهِ أَنّۭيٰ يُصْرَفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 70, '۰لذِينَ كَذَّبُواْ بِالْكِتَـٰــبِ وَبِمَآ أَرْسَلْنَا بِهِ” رُسُلَنَا فَسَوْفَ يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 71, 'إِذِ ۱لاَغْچَلُ فِىٓ أَعْنَـٰقِهِمْ وَالسَّچَسِــلُؐ يُسْحَبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 72, 'فِى ۱لْحَمِيمِ ثُمَّ فِى ۱لنّۭارۣ يُسْجَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 73, 'ثُمَّ قِيــلَ لَهُمُ; أَيْــنَ مَا كُنتُمْ 489 تُشْرۣكُونَ مِن دُونِ ۱للَّهِؐ قَالُواْ ضَلُّواْ عَنَّا بَل لَّمْ نَكُــن نَّدْعُواْ مِن قَبْلُ شَيْـٔاًؐ كَذَ؛لِــكَ يُضِــلُّ ۴للَّهُ ۴لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 74, 'ذَ؛لِكُم بِمَا كُنتُمْ تَفْرَحُونَ فِى ۱لاَرْضِ بِغَيْرۣ ۱لْحَقِّ وَبِمَا كُنتُمْ تَمْرَحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 75, '۸دْخُلُوٓاْ أَبْوَ؛بَ جَهَنَّمَ خَـٰلِدِينَ فِيهَاؐ فَبِيــسَ مَثْوَي ۰لْمُتَكَبِّـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 76, 'فَاصْبِـرۣ اِنَّ وَعْدَ ۰للَّهِ حَقٌّؐ فَإِمَّا نُرۣيَنَّكَ بَعْضَ ۰ﻟ﮲ نَعِدُهُمُ; أَوْ نَتَوَفَّيَنَّــكَ فَإِلَيْنَا يُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 77, 'وَلَقَدَ اَرْسَلْنَا رُسُلًا مِّــن قَبْلِــكَ مِنْهُم مَّــن قَصَصْنَا عَلَيْكَ وَمِنْهُم مَّن لَّمْ نَقْصُــصْ عَلَيْــكَؐ وَمَا كَانَ لِرَسُولٖ اَنْ يَّاتِيَ بِـَٔايَةٖ اِلاَّ بِإِذْنِ ۱للَّهِؐ فَإِذَا جَآءَ امْرُ ۴للَّهِ قُضِيَ بِالْحَقِّ وَخَسِرَ هُنَالِــكَ ۰لْمُبْطِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 78, '۰للَّهُ ۴ﻟ﮲ جَعَــلَ لَكُمُ ۴لاَنْعَـٰمَ لِتَرْكَبُواْ مِنْهَا وَمِنْهَا تَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 79, 'وَلَكُمْ فِيهَا مَنَـٰفِعُؐ وَلِتَبْلُغُواْ عَلَيْهَا حَاجَةً فِى صُدُورۣكُمْؐ وَعَلَيْهَاوَعَلَـي ۰لْفُلْكِ تُحْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 80, 'وَيُرۣيكُمُ; ءَايَـٰتِهِؐ” فَأَيَّ ءَايَـٰتِ ۱للَّهِ تُنكِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 81, 'أَفَلَمْ يَسِيرُواْ فِى ۱لاَرْضِ فَيَنظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِينَ مِن قَبْلِهِمْؐ كَانُوٓاْ 490 أَكْثَرَ مِنْهُمْ وَأَشَدَّ قُوَّةً وَءَاثَاراً فِى ۱لاَرْضِ فَمَآ أَغْنۭيٰ عَنْهُم مَّاكَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 82, 'فَلَمَّاجَآءَتْهُمْ رُسُلُهُم بِالْبَيِّنَـٰــتِ فَرۣحُواْ بِمَا عِندَهُم مِّــنَ ۰لْعِلْمِؐ وَحَاقَ بِهِم مَّا كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 83, 'فَلَمَّا رَأَوْاْ بَأْسَنَا قَالُوٓاْ ءَامَنَّا بِاللَّهِ وَحْدَهُ„ وَكَفَرْنَا بِمَا كُنَّا بِهِ” مُشْرۣكِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (40, 84, 'فَلَمْ يَكُ يَنفَعُهُمُ; إِيمَـٰنُهُمْ لَمَّا رَأَوْاْ بَأْسَنَاؐ سُنَّتَ ۰للَّهِ ۱لتِى قَدْ خَلَتْ فِى عِبَادِهِؐ” وَخَسِرَ هُنَالِــكَ ۰لْكَـٰفِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓؐ تَنزۣيلٌ مِّنَ ۰لرَّحْمَـٰنِ ۱لرَّحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 2, 'كِتَـٰبٌ فُصِّلَتَ —ايَـٰتُهُ„ قُرْءَاناٗ عَرَبِيّاً لِّقَوْمٍ يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 3, 'بَشِيراً وَنَذِيراًؐ فَأَعْرَضضضَ أَكْثَرُهُمْ فَهُمْ لاَ يَسْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 4, 'وَقَالُواْ قُلُوبُنَا فِىٓ أَكِنَّةٍ مِّمَّا تَدْعُونَآ إِلَيْهِ وَفِىٓ ءَاذَانِنَا وَقْرٌ وَمِـنۢ بَــيْنِنَا وَبَيْنِــكَ حِجَابٌ فَاعْمَلِ اِنَّنَا عَـٰمِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 5, 'قُلِ اِنَّمَآ أَنَا بَشَرٌ مِّثْلُكُمْ يُوحۭيٰٓ إِلَيَّ أَنَّمَآ إِچَهُكُمُ; إِچَهٌ وَ؛حِدٌ 491 فَاسْتَقِيمُوٓاْ إِلَيْهِ وَاسْتَغْفِرُوهُؐ وَوَيْلٌ لِّلْمُشْرۣكِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 6, '۰لذِيــنَ لاَ يُوتُونَ ۰لزَّكَوٰةَ وَهُم بِالاَخِرَةِ هُمْ كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 7, 'إِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ لَهُمُ; أَجْر٘ غَيْرُ مَمْنُونٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 8, '¥ قُلَ اَئنَّكُمْ لَتَكْفُرُونَ بِاﻟ﮲ خَلَــقَ ۰لاَرْضَ فِى يَوْمَيْنِ وَتَجْعَلُونَ لَهُ; أَندَاداًؐ ذَ؛لِــكَ رَبُّ ۴لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 9, 'وَجَعَلَ فِيهَا رَوَ؛سِيَ مِن فَوْقِهَا وَبَـٰرَكككَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَ؛تَهَا فِىٓ أَرْبَعَةِ أَيَّامٍ سَوَآءً لِّلسَّآئِـلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 10, 'ثُمَّ "سْتَوۭيٰٓ إِلَــي ۰لسَّمَآءِ وَهِــيَ دُخَانٌ فَقَالَ لَهَا وَلِلاَرْضِ ''يتِيَا طَوْعاٗ اَوْ كَرْهاًؐ قَالَتَآ أَتَيْنَا طَآئِعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 11, 'فَقَضۭيٰهُــنَّ سَبْعَ سَمَـٰوَاتٍ فِى يَوْمَيْنِ وَأَوْحۭيٰ فِى كُــلّۣ سَمَآءٖ اَمْرَهَاؐ وَزَيَّنَّا ۰لسَّمَآءَ ۰لدُّنْيۭا بِمَصَـٰبِيحَؐ وَحِفْظاًؐ ذَ؛لِــكَ تَقْدِيرُ ۴لْعَزۣيزۣ ۱لْعَلِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 12, 'فَإِنَ اَعْرَضُواْ فَقُــلَ اَنذَرْتُكُمْ صَـٰعِقَةً مِّثْــلَ صَـٰعِقَةِ عَادٍ وَثَمُودَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 13, 'إِذْ جَآءَتْهُمُ ۴لرُّسُلُ مِنۢ بَيْنِ أَيْدِيهِمْ وَمِــنْ خَلْفِهِمُ; أَلاَّ تَعْبُدُوٓاْ إِلاَّ ۰للَّهَؐ قَالُواْ لَوْ شَآءَ رَبُّنَا لَأَنزَلَ مَلَئِكَةً فَإِنَّا بِمَآ ٱُرْسِلْتُم بِهِ” كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 14, 'فَأَمَّا عَادٌ فَاسْتَكْبَرُواْ 492 فِى ۱لاَرْضِ بِغَيْرۣ ۱لْحَقِّ وَقَالُواْ مَــنَ اَشَدُّ مِنَّا قُوَّةٗؐ اَوَلَمْ يَرَوَاْ اَنَّ ۰للَّهَ ۰ﻟ﮲ خَلَقَهُمْ هُوَ أَشَدُّ مِنْهُمْ قُوَّةًؐ وَكَانُواْ بِـَٔايَـٰتِنَا يَجْحَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 15, 'فَأَرْسَلْنَا عَلَيْهِمْ رۣيحاً صَرْصَراً فِىٓ أَيَّامٍ نَّحْسَاتٍ لِّنُذِيقَهُمْ عَذَابَ ۰لْخِزْيِ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَلَعَذَابُ ۴لاَخِرَةِ أَخْزۭيٰ وَهُمْ لاَ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 16, 'وَأَمَّا ثَمُودُ فَهَدَيْنَـٰهُمْ فَاسْتَحَبُّواْ ۴لْعَمۭــيٰ عَلَــي ۰لْهُدۭيٰ فَأَخَذَتْهُمْ صَـٰعِقَةُ ۴لْعَذَابِ ۱لْهُونِ بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 17, 'وَنَجَّيْنَا ۰لذِيــنَ ءَامَنُواْ وَكَانُواْ يَتَّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 18, 'وَيَوْمَ نَحْشُرُ أَعْدَآءَ ۰للَّهِ إِلَي ۰لنّۭارۣ فَهُمْ يُوزَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 19, 'حَتَّيٰٓ إِذَا مَا جَآءُوهَا شَهِدَ عَلَيْهِمْ سَمْعُهُمْ وَأَبْصَـٰرُهُمْ وَجُلُودُهُم بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 20, 'وَقَالُواْ لِجُلُودِهِمْ لِمَ شَهِدتُّمْ عَلَيْنَاؐ قَالُوٓاْ أَنطَقَنَا ۰للَّهُ ۴ﻟـذِىٓ أَنطَــقَ كُلَّ شَيْءٍؐ وَهُوَ خَلَقَكُمُ; أَوَّلَ مَرَّةٍ وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 21, 'وَمَا كُنتُمْ تَسْتَتِرُونَ أَنْ يَّشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلآَ أَبْصَـٰرُكُمْ وَلاَ جُلُودُكُمْؐ وَچَكِن ظَنَنتُمُ; أَنَّ ۰للَّهَ لاَ يَعْلَمُ كَثِيراً مِّمَّا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 22, '49 وَذَ؛لِكُمْ ظَنُّكُمُ ۴ﻟ﮲ ظَنَنتُم بِرَبِّكُمُ; أَرْدۭيٰكُمْ فَأَصْبَحْتُم مِّــنَ ۰لْخَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 23, 'فَإِنْ يَّصْبِرُواْ فَالنَّارُ مَثْويً لَّهُمْؐ وَإِنْ يَّسْتَعْتِبُواْ فَمَا هُم مِّــنَ ۰لْمُعْتَبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 24, '© وَقَيَّضْنَا لَهُمْ قُرَنَآءَ فَزَيَّنُواْ لَهُم مَّا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْؐ وَحَقَّ عَلَيْهِمُ ۴لْقَوْلُ فِىٓ ٱُمَمٍ قَدْ خَلَتْ مِــن قَـبْلِهِم مِّنَ ۰لْجِنِّ وَالِانسِؐ إِنَّهُمْ كَانُواْ خَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 25, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ لاَ تَسْمَعُواْ لِهَـٰذَا ۰لْقُرْءَانِ وَالْغَوْاْ فِيهِ لَعَلَّكُمْ تَغْلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 26, 'فَلَنُذِيقَنَّ ۰لذِيــنَ كَفَرُواْ عَذَاباً شَدِيداً وَلَنَجْزۣيَنَّهُمُ; أَسْوَأَ ۰ﻟ﮲ كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 27, 'ذَ؛لِــكَ جَزَآءُ اَ۬عْدَآءِ ۱للَّهِ ۱لنَّارُؐ لَهُمْ فِيهَا دَارُ ۴لْخُلْدِؐ جَزَآءَۢ بِمَا كَانُواْ بِـَٔايَـٰتِنَا يَجْحَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 28, 'وَقَالَ ۰لذِينَ كَفَرُواْ رَبَّنَآ أَرۣنَا ۰لذَيْــنۣ أَضَچَّـنَا مِــنَ ۰لْجِنِّ وَالِانسِ نَجْعَلْهُمَا تَحْتَ أَقْدَامِنَا لِيَكُونَا مِــنَ ۰لاَسْفَلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 29, 'إِنَّ ۰لذِيــنَ قَالُواْ رَبُّنَا ۰للَّهُ ثُمَّ "سْتَقَـٰمُواْ تَتَنَزَّلُ عَلَيْهِمُ ۴لْمَلَئِكَةُ أَلاَّ تَخَافُواْ وَلاَ تَحْزَنُواْ وَأَبْشِرُواْ بِالْجَنَّةِ ۱لتِى كُنتُمْ تُوعَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 30, 'نَحْنُ أَوْلِيَآؤُكُمْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا وَفِى ۱لاَخِرَةِؐ وَلَكُمْ فِيهَا 494 مَا تَشْتَهِىٓ أَنفُسُكُمْ وَلَكُمْ فِيهَا مَا تَدَّعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 31, 'نُزُلًا مِّنْ غَفُورٍ رَّحِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 32, 'وَمَــنَ اَحْسَنُ قَوْلًا مِّمَّــن دَعَآ إِلَــي ۰للَّهِ وَعَمِلَ صَـٰڤِحاً وَقَالَ إِنَّنِى مِــنَ ۰لْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 33, 'وَلاَ تَسْتَوۣى ۱لْحَسَنَةُ وَلاَ ۰لسَّيِّيؕةُؐ èدْفَعْ بِالتِى هِــيَ أَحْسَنُ فَـإِذَا ۰ﻟ﮲ بَيْنَــكَ وَبَيْنَهُ„ عَدَ؛وَةٌ كَأَنَّهُ„ وَلِــيّﹲ حَمِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 34, 'وَمَا يُلَقّۭيٰهَآ إِلاَّ ۰لذِينَ صَبَرُواْؐ وَمَا يُلَقّۭيٰهَآ إِلاَّ ذُو حَظّٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 35, 'وَإِمَّا يَنزَغَنَّــكَ مِــنَ ۰لشَّيْطَـٰنِ نَزْغٌ فَاسْتَعِذْ بِاللَّهِؐ إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 36, 'وَمِــنَ —ايَـٰتِهِ ۱ليْلُ وَالنَّهَارُ وَالشَّمْسُ وَالْقَمَرُؐ لاَ تَسْجُدُواْ لِلشَّمْسِ وَلاَ لِلْقَمَرۣؐ وَاسْجُدُواْ لِلهِ ۱ﻟ﮲ خَلَقَهُنَّ إِن كُنتُمُ; إِيَّاهُ تَعْبُدُونَؐ ¦');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 37, 'فَإِنِ ''سْتَكْبَرُواْ فَالذِينَ عِندَ رَبِّكَ يُسَبِّحُونَ لَهُ„ بِاليْلِ وَالنَّهۭارۣ وَهُمْ لاَ يَسْـَٔمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 38, 'وَمِــنَ —ايَــٰتِهِ“ أَنَّــكَ تَرَي ۰لاَرْضضضَ خَـٰشِعَةً فَإِذَآ أَنزَلْنَا عَلَيْهَا ۰لْمَآءَ "هْتَزَّتْ وَرَبَتِؐ اِنَّ ۰ﻟـذِىٓ أَحْيۭاهَا ڤَمُحْــىِ ۱لْمَوْتۭيٰٓؐ إِنَّهُ„ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 39, 'اِنَّ ۰لذِيــنَ يُڤْحِدُونَ فِىٓ ءَايَـٰتِنَا لاَ يَخْفَوْنَ عَلَيْنَآؐ أَفَمَنْ يُّلْقۭيٰ فِى ۱لنّۭارۣ خَيْر٘ اَم مَّنْ يَّاتِىٓ ءَامِناً 495 يَوْمَ ۰لْقِيَـٰمَةِؐ ''عْمَلُواْ مَا شِيؔتُمُؐ; إِنَّهُ„ بِمَا تَعْمَلُونَ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 40, 'اِنَّ ۰لذِيــنَ كَفَرُواْ بِالذِّكْرۣ لَمَّا جَآءَهُمْ وَإِنَّهُ„ لَكِتَـٰب٘ عَزۣيزٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 41, 'لاَّ يَاتِيهِ ۱لْبَـٰطِلُ مِنۢ بَيْـنِ يَدَيْهِ وَلاَ مِــنْ خَلْفِهِؐ” تَنزۣيلٌ مِّنْ حَكِيمٖ حَمِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 42, 'مَّا يُقَالُ لَــكَ إِلاَّ مَا قَدْ قِيلَ لِلرُّسُلِ مِن قَبْلِــكَؐ إِنَّ رَبَّــكَ لَذُو مَغْفِرَةٍ وَذُو عِقَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 43, 'وَلَوْ جَعَلْنَـٰهُ قُرْءَاناٗ اَعْجَمِيّاً لَّقَالُواْ لَوْلاَ فُصِّلَتَ —ايَـٰتُهُؐ; ءَآعْجَمِيٌّ وَعَرَبِــيٌّؐ قُلْ هُوَ لِلذِيــنَ ءَامَنُواْ هُديً وَشِفَآءٌؐ وَالذِينَ لاَ يُومِنُونَ فِىٓ ءَاذَانِهِمْ وَقْرٌ وَهُوَ عَلَيْهِمْ عَميٗؐ ۷وْلَئِكَ يُنَادَوْنَ مِــن مَّكَانٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 44, 'وَلَقَدَ —اتَيْنَا مُوسَــي ۰لْكِتَـٰبَ فَاخْتُلِفَ فِيهِؐ وَلَوْلاَ كَلِمَةٌ سَبَقَتْ مِن رَّبِّــكَ لَقُضِيَ بَيْنَهُمْؐ وَإِنَّهُمْ لَفِى شَــكٍّ مِّنْهُ مُرۣيبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 45, 'مَّــنْ عَمِــلَ صَـٰڤِحاً فَلِنَفْسِهِؐ” وَمَــنَ اَسَآءَ فَعَلَيْهَاؐ وَمَا رَبُّــكَ بِظَچَّمٍ لِّلْعَبِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 46, '¤ إِلَيْهِ يُرَدُّ عِلْمُ ۴لسَّاعَةِؐ وَمَا تَخْرُجُ مِن ثَمَرَ؛تٍ مِّــنَ اَكْمَامِهَا وَمَا تَحْمِلُ مِنُ ۷نثۭيٰ وَلاَ تَضَعُ إِلاَّ بِعِلْمِهِؐ” وَيَوْمَ يُنَادِيهِمُ; أَيْنَ شُرَكَآءِى قَالُوٓاْ ءَاذَنَّـٰــكَ مَامِنَّا مِــن شَهِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 47, 'وَضَــلَّ عَنْهُم مَّا كَانُواْ 496 يَدْعُونَ مِــن قَبْلُ وَظَنُّواْؐ مَا لَهُم مِّن مَّحِيصٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 48, 'لاَّ يَسْـَٔمُ ۴لِانسَـٰنُ مِن دُعَآءِ ۱لْخَيْرۣؐ وَإِن مَّسَّهُ ۴لشَّرُّ فَيَـُٔوسسسٌ قَنُوطٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 49, 'وَلَـئِــنَ اَذَقْنَـٰهُ رَحْمَةً مِّنَّا مِـنۢ بَعْدِ ضَرَّآءَ مَسَّتْهُ لَيَقُولَنَّ هَـٰذَا لِى وَمَآ أَظُــنُّ ۴لسَّاعَةَ قَآئِمَةً وَلَئِن رُّجِعْتُ إِلَيٰ رَبِّيَ إِنَّ لِى عِندَهُ„ ڤَڤْحُسْنۭـيٰؐ فَلَنُنَبِّيؕــنَّ ۰لذِيــنَ كَفَرُواْ بِمَا عَمِلُواْ وَلَنُذِيقَنَّهُم مِّــنْ عَذَابٖ غَلِيظٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 50, 'وَإِذَآ أَنْعَمْنَا عَلَي ۰لِانسَـٰــنۣ أَعْرَضَ وَنَـۭٔا بِجَانِبِهِؐ” وَإِذَا مَسَّهُ ۴لشَّرُّ فَذُو دُعَآءٖ عَرۣيضٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 51, 'قُلَ اَرَ×يْتُمُ; إِن كَانَ مِنْ عِندِ ۱للَّهِ ثُمَّ كَفَرْتُم بِهِ” مَــنَ اَضَـلُّ مِمَّنْ هُوَ فِى شِقَاقٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 52, 'سَنُرۣيهِمُ; ءَايَـٰتِنَا فِى ۱لاَفَاقِ وَفِىٓ أَنفُسِهِمْ حَتَّـيٰ يَتَبَيَّــنَ لَهُمُ; أَنَّهُ ۴لْحَقُّؐ أَوَلَمْ يَكْفِ بِرَبِّكَ أَنَّهُ„ عَلَــيٰ كُـلِّ شَيْءٍ شَهِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (41, 53, 'اَلٓاَ إِنَّهُمْ فِى مِرْيَةٍ مِّن لِّقَآءِ رَبِّهِمُؐ; أَلآَ إِنَّهُ„ بِكُـلِّ شَيْءٍ مُّحِيط٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓ عَٓسِٓقَٓؐ كَذَ؛لِكَ يُوحِىٓ إِلَيْكَ 497 وَإِلَـي ۰لذِيـنَ مِن قَبْلِــكَ ۰للَّهُ ۴لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 2, 'لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَهُوَ ۰لْعَلِــيُّ ۴لْعَظِيــمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 3, 'يَكَادُ ۴لسَّمَـٰوَ؛تُ يَتَفَطَّرْنَ مِن فَوْقِهِنَّؐ وَالْمَلَئِكَةُ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيَسْتَغْفِرُونَ لِمَـن فِى ۱لاَرْضضضِؐ أَلآَ إِنَّ ۰للَّهَ هُوَ ۰لْغَفُورُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 4, 'وَالذِيـنَ "تَّخَذُواْ مِن دُونِهِ“ أَوْلِيَآءَ ۰للَّهُ حَفِيظ٘ عَلَيْهِمْؐ وَمَآ أَنتَ عَلَيْهِم بِوَكِيــلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 5, 'وَكَذَ؛لِــكَ أَوْحَيْنَآ إِلَيْكَ قُرْءَاناٗ عَرَبِيّاً لِّتُنذِرَ ٱُمَّ ۰لْقُرۭيٰ وَمَنْ حَوْلَهَا وَتُنذِرَ يَوْمَ ۰لْجَمْعِ لاَ رَيْبَ فِيهِؐ فَرۣيـقٌ فِى ۱لْجَنَّةِؐ وَفَرۣيـقٌ فِى ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 6, 'وَلَوْ شَآءَ ۰للَّهُ لَجَعَلَهُمُ; ٱُمَّةً وَ؛حِدَةًؐ وَچَكِنْ يُّدْخِـلُ مَنْ يَّشَآءُ فِى رَحْمَتِهِؐ” وَالظَّـٰلِمُونَ مَا لَهُم مِّنْ وَّلِيٍّ وَلاَ نَصِيرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 7, 'اَمِ ''تَّخَذُواْ مِن دُونِهِ“ أَوْلِيَآءَؐ فَاللَّهُ هُوَ ۰لْوَلِيُّؐ وَهُوَ يُحْىِ ۱لْمَوْتۭيٰؐ وَهُوَ عَلَــيٰ كُـلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 8, 'وَمَا "خْتَلَفْتُمْ فِيهِ مِـن شَيْءٍ فَحُكْمُهُ; إِلَــي ۰للَّهِؐ ذَ؛لِكُمُ ۴للَّهُ رَبِّىؐ عَلَيْهِ تَوَكَّلْتُؐ وَإِلَيْهِ ٱُنِيبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 9, 'فَاطِرُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ جَعَــلَ لَكُم مِّــنَ اَنفُسِكُمُ; أَزْوَ؛جاً وَمِــنَ ۰لاَنْعَـٰمِ 498 أَزْوَ؛جاً يَذْرَؤُكُمْ فِيهِؐ لَيْــسَ كَمِثْلِهِ” شَيْءٌؐ وَهُوَ ۰لسَّمِيعُ ۴لْبَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 10, 'لَهُ„ مَقَالِيدُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ يَبْسُطُ ۴لرّۣزْقَ لِمَنْ يَّشَآءُ وَيَقْدِرُؐ إِنَّهُ„ بِكُــلّۣ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 11, '© شَرَعَ لَكُم مِّنَ ۰لدِّيــنۣ مَا وَصّۭيٰ بِهِ” نُوحاً وَاﻟـذِىٓ أَوْحَيْنَآ إِلَيْــكَ وَمَا وَصَّيْنَا بِهِ“ إِبْرَ؛هِيمَ وَمُوسۭيٰ وَعِيسۭيٰٓ أَنَ اَقِيمُواْ ۴لدِّينَ وَلاَ تَتَفَرَّقُواْ فِيهِؐ كَبُرَ عَلَــي ۰لْمُشْرۣكِيــنَ مَا تَدْعُوهُمُ; إِلَيْهِؐ ۱للَّهُ يَجْتَبِىٓ إِلَيْهِ مَنْ يَّشَآءُ وَيَهْدِ ىٓ إِلَيْهِ مَنْ يُّنِيبُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 12, 'وَمَا تَفَرَّقُوٓاْ إِلاَّ مِـنۢ بَعْدِ مَا جَآءَهُمُ ۴لْعِلْمُؐ بَغْياَۢ بَيْنَهُمْؐ وَلَوْلاَ كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ إِلَـيٰٓ أَجَــلٍ مُّسَمّــيً لَّقُضِيَ بَيْنَهُمْؐ وَإِنَّ ۰لذِينَ ٱُورۣثُواْ ۴لْكِتَـٰبَ مِنۢ بَعْدِهِمْ لَفِى شَــكٍّ مِّنْهُ مُرۣيــبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 13, 'فَلِذَ؛لِــكَ فَادْعُ وَاسْتَقِمْ كَمَآ ٱُمِرْتَ وَلاَ تَتَّبِعَ اَهْوَآءَهُمْؐ وَقُــلَ —امَنتُ بِمَآ أَنزَلَ ۰للَّهُ مِــن كِتَـٰبٍ وَٱُمِرْتُ لَأِعْدِلَ بَيْنَكُمُؐ ۴للَّهُ رَبُّنَا وَرَبُّكُمْؐ لَنَآ أَعْمَـٰلُنَا وَلَكُمُ; أَعْمَـٰلُكُمْؐ لاَ حُجَّةَ بَيْنَنَا وَبَيْنَكُمُؐ ۴للَّهُ يَجْمَعُ بَيْنَنَاؐ وَإِلَيْهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 14, 'وَالذِيــنَ يُحَآجُّونَ فِى ۱للَّهِ مِنۢ بَعْدِ مَا ۸سْتُجِيبَ لَهُ„ حُجَّتُهُمْ دَاحِضَة٘ عِندَ رَبِّهِمْ 499 وَعَلَيْهِمْ غَضَبٌؐ وَلَهُمْ عَذَابٌ شَدِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 15, '۱للَّهُ ۴ﻟـذِىٓ أَنزَلَ ۰لْكِتَـٰبَ بِالْحَقِّ وَالْمِيزَانَؐ وَمَا يُدْرۣيــكَؐ لَعَــلَّ ۰لسَّاعَةَ قَرۣيبٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 16, 'يَسْتَعْجِلُ بِهَا ۰لذِيــنَ لاَ يُومِنُونَ بِهَاؐ وَالذِيــنَ ءَامَنُواْ مُشْفِقُونَ مِنْهَا وَيَعْلَمُونَ أَنَّهَا ۰لْحَقُّؐ أَلآَ إِنَّ ۰لذِيــنَ يُمَارُونَ فِى ۱لسَّاعَةِ لَفِى ضَچَلٙ بَعِيدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 17, '۱للَّهُ لَطِيفٛ بِعِبَادِهِؐ” يَرْزُقُ مَنْ يَّشَآءُؐ وَهُوَ ۰لْقَوۣيُّ ۴لْعَزۣيزُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 18, 'مَــن كَانَ يُرۣيدُ حَرْثَ ۰لاَخِرَةِ نَزۣدْ لَهُ„ فِى حَرْثِهِؐ” وَمَــن كَانَ يُرۣيدُ حَرْثَ ۰لدُّنْيۭا نُوتِهِ” مِنْهَاؐ وَمَا لَهُ„ فِى ۱لاَخِرَةِ مِــن نَّصِيبٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 19, 'اَمْ لَهُمْ شُرَكَـٰٓؤُاْ شَرَعُواْ لَهُم مِّــنَ ۰لدِّيــنۣ مَا لَمْ يَاذَنۢ بِهِ ۱للَّهُؐ وَلَوْلاَ كَلِمَةُ ۴لْفَصْــلۣ لَقُضِيَ بَيْنَهُمْؐ وَإِنَّ ۰لظَّـٰلِمِيــنَ لَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 20, 'تَرَي ۰لظَّـٰلِمِيــنَ مُشْفِقِينَ مِمَّا كَسَبُواْ وَهُوَ وَاقِعٛ بِهِمْؐ وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ فِى رَوْضَاتِ ۱لْجَنَّاتِؐ لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْؐ ذَ؛لِــكَ هُوَ ۰لْفَضْــلُ ۴لْكَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 21, 'ذَ؛لِــكَ ۰ﻟ﮲ يُبَشِّرُ ۴للَّهُ عِبَادَهُ ۴لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِؐ قُــل لٓاَّ أَسْـَٔلُكُمْ عَلَيْهِ أَجْراٗ 500 اِلاَّ ۰لْمَوَدَّةَ فِى ۱لْقُرْبۭيٰؐ وَمَنْ يَّقْتَرۣفْ حَسَنَةً نَّزۣدْ لَهُ„ فِيهَا حُسْناٗؐ اِنَّ ۰للَّهَ غَفُورٌ شَكُور٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 22, 'اَمْ يَقُولُونَ "فْتَرۭيٰ عَلَــي ۰للَّهِ كَذِباًؐ فَإِنْ يَّشَإِ ۱للَّهُ يَخْتِمْ عَلَــيٰ قَلْبِكَؐ وَيَمْحُ ۴للَّهُ ۴لْبَـٰطِلَ وَيُحِــقُّ ۴لْحَقَّ بِكَلِمَـٰتِهِؐ“ إِنَّهُ„ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 23, 'وَهُوَ ۰ﻟ﮲ يَقْبَــلُ ۴لتَّوْبَةَ عَنْ عِبَادِهِ” وَيَعْفُواْ عَـنِ ۱لسَّيِّــَٔاتِ وَيَعْلَمُ مَا يَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 24, 'وَيَسْتَجِيــبُ ۴لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ وَيَزۣيدُهُم مِّن فَضْلِهِؐ” وَالْكَـٰفِرُونَ لَهُمْ عَذَابٌ شَدِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 25, '¥ وَلَوْ بَسَطَ ۰للَّهُ ۴لرّۣزْقَ لِعِبَادِهِ” لَبَغَوْاْ فِى ۱لاَرْضِؐ وَچَكِنْ يُّنَزّۣلُ بِقَدَرٍ مَّا يَشَآءُؐ ﹹنَّهُ„ بِعِبَادِهِ” خَبِيرٛ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 26, 'وَهُوَ ۰ﻟ﮲ يُنَزّۣلُ ۴لْغَيْثَ مِنۢ بَعْدِ مَا قَنَطُواْ وَيَنشُرُ رَحْمَتَهُؐ, وَهُوَ ۰لْوَلِــيُّ ۴لْحَمِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 27, 'وَمِــنَ —ايَـٰتِهِ” خَلْــقُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَثَّ فِيهِمَا مِــن دَآبَّةٍؐ وَهُوَ عَلَيٰ جَمْعِهِمُ; إِذَا يَشَآءُ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 28, 'وَمَآ أَصَـٰبَكُم مِّــن مُّصِيبَةٙ بِمَا كَسَبَــتَ اَيْدِيكُمْ وَيَعْفُواْ عَــن كَثِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 29, 'وَمَآ أَنتُم بِمُعْجِزۣينَ فِى ۱لاَرْضِؐ وَمَا لَكُم مِّن دُونِ ۱للَّهِ مِنْ وَّلِيٍّ وَلاَ نَصِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 30, '501 وَمِــنَ —ايَـٰتِهِ ۱لْجَوَارۣ” فِى ۱ڤْبَحْرۣ كَالاَعْچَمِؐ إِنْ يَّشَأْ يُسْكِنِ ۱لرّۣيَـٰحَ فَيَظْلَلْنَ رَوَاكِدَ عَلَــيٰ ظَهْرۣهِ“ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لِّكُلِّ صَبّۭارٍ شَكُور۫');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 31, 'اَوْ يُوبِقْهُنَّ بِمَا كَسَبُواْ وَيَعْفُ عَــن كَثِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 32, 'وَيَعْلَمُ ۴لذِيــنَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِنَا مَا لَهُم مِّن مَّحِيصٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 33, 'فَمَآ ٱُوتِيتُم مِّن شَيْءٍ فَمَتَـٰعُ ۴لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَمَا عِندَ ۰للَّهِ خَيْرٌ وَأَبْقۭيٰ لِلذِيــنَ ءَامَنُواْ وَعَلَيٰ رَبِّهِمْ يَتَوَكَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 34, 'وَالذِيــنَ يَجْتَنِبُونَ كَبَـٰٓئِرَ ۰لِاثْمِ وَالْفَوَ؛حِشَ وَإِذَا مَا غَضِبُواْ هُمْ يَغْفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 35, 'وَالذِينَ "سْتَجَابُواْ لِرَبِّهِمْ وَأَقَامُواْ ۴لصَّلَوٰةَ وَأَمْرُهُمْ شُورۭيٰ بَيْنَهُمْ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 36, 'وَالذِينَ إِذَآ أَصَابَهُمُ ۴لْبَغْيُ هُمْ يَنتَصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 37, 'وَجَزَ×ؤُاْ سَيِّيؕةٍ سَيِّيؕةٌ مِّثْلُهَاؐ فَمَــنْ عَفَا وَأَصْلَحَ فَأَجْرُهُ„ عَلَــي ۰للَّهِؐ إِنَّهُ„ لاَ يُحِبُّ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 38, 'وَلَمَنِ ''نتَصَرَ بَعْدَ ظُلْمِهِ” فَٱُوْلَئِــكَ مَا عَلَيْهِم مِّــن سَبِيلٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 39, 'اِنَّمَا ۰لسَّبِيــلُ عَلَي ۰لذِينَ يَظْلِمُونَ ۰لنَّاسَ وَيَبْغُونَ فِى ۱لاَرْضِ بِغَيْرۣ ۱لْحَقﱢّؐ ٱُوْلَئِكَ لَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 40, 'وَلَمَــن صَبَرَ وَغَفَرَ إِنَّ ذَ؛لِكَ لَمِنْ عَزْمِ ۱لاُمُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 41, '502 وَمَـنْ يُّضْلِـلِ ۱للَّهُ فَمَا لَهُ„ مِنْ وَّلِـيٍّ مِّنۢ بَعْدِهِؐ” وَتَرَي ۰لظَّـٰلِمِينَ لَمَّا رَأَوُاْ ۴لْعَذَابَ يَقُولُونَ هَلِ اِلَيٰ مَرَدٍّ مِّــن سَبِيــلٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 42, 'وَتَرۭيٰهُمْ يُعْرَضُونَ عَلَيْهَا خَـٰشِعِينَؐ مِنَ ۰لذُّلِّ يَنظُرُونَ مِــن طَرْفٖ خَفِيّؐ؊ وَقَالَ ۰لذِيــنَ ءَامَنُوٓاْ إِنَّ ۰لْخَـٰسِرۣيــنَ ۰لذِيــنَ خَسِرُوٓاْ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ۰لْقِيَـٰمَةِؐ أَلآَ إِنَّ ۰لظَّـٰلِمِينَ فِى عَذَابٍ مُّقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 43, 'وَمَا كَانَ لَهُم مِّنَ اَوْلِيَآءَ يَنصُرُونَهُم مِّن دُونِ ۱للَّهِؐ وَمَـنْ يُّضْلِـلِ ۱للَّهُ فَمَا لَهُ„ مِن سَبِيلٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 44, '''سْتَجِيبُواْ لِرَبِّكُم مِّــن قَبْلِ أَنْ يَّاتِيَ يَوْمٌ لاَّ مَرَدَّ لَهُ„ مِــنَ ۰للَّهِؐ مَا لَكُم مِّــن مَّڤْجَإٍ يَوْمَئِذٍؐ وَمَا لَكُم مِّــن نَّكِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 45, 'فَإِنَ اَعْرَضُواْ فَمَآ أَرْسَلْنَـٰكَ عَلَيْهِمْ حَفِيظاٗؐ اِنْ عَلَيْــكَ إِلاَّ ۰لْبَچَغُؐ وَإِنَّـآ إِذَآ أَذَقْنَا ۰لِانسَـٰنَ مِنَّا رَحْمَةً فَرۣحَ بِهَاؐ وَإِن تُصِبْهُمْ سَيِّيؕةٛ بِمَا قَدَّمَــتَ اَيْدِيهِمْ فَإِنَّ ۰لِانسَـٰــنَ كَفُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 46, 'لِّلهِ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضضضِؐ يَخْلُقُ مَا يَشَآءُؐ يَهَبُ لِمَـنْ يَّشَآءُ ﹹنَـٰثاً وَيَهَبُ لِمَنْ يَّشَآءُ ۴لذُّكُورَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 47, 'أَوْ يُزَوّۣجُهُمْ ذُكْرَاناً وَإِنَـٰثاً وَيَجْعَلُ مَنْ يَّشَآءُ عَقِيماٗؐ اِنَّهُ„ عَلِيمٌ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 48, '© وَمَا كَانَ لِبَشَر۫ اَنْ يُّكَلِّمَهُ ۴للَّهُ إِلاَّ 50 وَحْياٗ اَوْ مِنْ وَّرَآءِىْ حِجَابٖ اَوْ يُرْسِلُ رَسُولًا فَيُوحِى بِإِذْنِهِ” مَا يَشَآءُؐ ﹹنَّهُ„ عَلِــيّﹲ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 49, 'وَكَذَ؛لِكَ أَوْحَيْنَآ إِلَيْــكَ رُوحاً مِّنَ اَمْرۣنَاؐ مَا كُنتَ تَدْرۣى مَا ۰لْكِتَـٰبُ وَلاَ ۰لِايمَـٰنُؐ وَچَكِن جَعَلْنَـٰهُ نُوراً نَّهْدِى بِهِ” مَــن نَّشَآءُ مِنْ عِبَادِنَاؐ وَإِنَّكَ لَتَهْدِﻯٓ إِلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (42, 50, 'صِرَ؛طِ ۱للَّهِ ۱ﻟ﮲ لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضضضِؐ أَلآَ إِلَــي ۰للَّهِ تَصِيرُ ۴لاُمُورُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓؐ وَالْكِتَـٰبِ ۱لْمُبِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 2, 'إِنَّا جَعَلْنَـٰهُ قُرْءَ؛ناٗ عَرَبِيّاً لَّعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 3, 'وَإِنَّهُ„ فِىٓ ٱُمِّ ۱لْكِتَـٰبِ لَدَيْنَا لَعَلِــيّﹲ حَكِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 4, 'اَفَنَضْرۣبُ عَنكُمُ ۴لذِّكْرَ صَفْحاٗ اِن كُنتُمْ قَوْماً مُّسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 5, 'وَكَمَ اَرْسَلْنَا مِن نَّبِىٓءٍ فِى ۱لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 6, 'وَمَا يَاتِيهِم مِّن نَّبِىٓءٖ اِلاَّ كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 7, 'فَأَهْلَكْنَآ أَشَدَّ مِنْهُم بَطْشاًؐ وَمَضۭيٰ مَثَــلُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 8, 'وَلَـئِــن سَأَلْتَهُم مَّــنْ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ 504 لَيَقُولُــنَّ خَلَقَهُــنَّ ۰لْعَزۣيزُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 9, '۴ﻟ﮲ جَعَــلَ لَكُمُ ۴لاَرْضَ مِهَـٰداً وَجَعَــلَ لَكُمْ فِيهَا سُبُلًا لَّعَلَّكُمْ تَهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 10, 'وَاﻟ﮲ نَزَّلَ مِــنَ ۰لسَّمَآءِ مَآءَۢ بِقَدَرٍ فَأَنشَرْنَا بِهِ” بَلْدَةً مَّيْتاًؐ كَذَ؛لِــكَ تُخْرَجُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 11, 'وَاﻟ﮲ خَلَــقَ ۰لاَزْوَ؛جَ كُلَّهَا وَجَعَــلَ لَكُم مِّــنَ ۰لْفُلْكِ وَالاَنْعَـٰمِ مَا تَرْكَبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 12, 'لِتَسْتَوُﹼاْ عَلَــيٰ ظُهُورۣهِ” ثُمَّ تَذْكُرُواْ نِعْمَةَ رَبِّكُمُ; إِذَا "سْتَوَيْتُمْ عَلَيْهِ وَتَقُولُواْ سُبْحَـٰنَ ۰ﻟ﮲ سَخَّرَ لَنَا هَـٰذَا وَمَا كُنَّا لَهُ„ مُقْرۣنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 13, 'وَإِنَّـآ إِلَيٰ رَبِّنَا لَمُنقَلِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 14, 'وَجَعَلُواْ لَهُ„ مِنْ عِبَادِهِ” جُزْءاٗؐ اِنَّ ۰لِانسَـٰنَ لَكَفُورٌ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 15, 'اَمِ ''تَّخَذَ مِمَّا يَخْلُقُ بَنَاتٍ وَأَصْفۭيٰكُم بِالْبَنِيـنَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 16, 'وَإِذَا بُشِّرَ أَحَدُهُم بِمَا ضَرَبَ لِلرَّحْمَـٰــنۣ مَثَلًا ظَلَّ وَجْهُهُ„ مُسْوَدّاً وَهُوَ كَظِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 17, 'اَوَمَنْ يَّنشَؤُاْ فِى ۱لْحِلْيَةِ وَهُوَ فِى ۱لْخِصَامِ غَيْرُ مُبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 18, 'وَجَعَلُواْ ۴لْمَلَئِكَةَ ۰لذِينَ هُمْ عِندَ ۰لرَّحْمَـٰنِ إِنَـٰثاٗؐ اَ.شْهِدُواْ خَلْقَهُمْؐ سَتُكْتَــبُ شَهَـٰدَتُهُمْ وَيُسْـَٔلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 19, 'وَقَالُواْ لَوْ شَآءَ ۰لرَّحْمَـٰــنُ مَا عَبَدْنَـٰهُمؐ مَّا لَهُم بِذَ؛لِــكَ مِنْ عِلْمٖؐ اِنْ هُمُ; إِلاَّ يَخْرُصُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 20, '505 أَمَ —اتَيْنَـٰهُمْ كِتَـٰباً مِّن قَبْلِهِ” فَهُم بِهِ” مُسْتَمْسِكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 21, 'بَــلْ قَالُوٓاْ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَــيٰٓ ٱُمَّةٍ وَإِنَّا عَلَــيٰٓ ءَاثۭـٰرۣهِم مُّهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 22, 'وَكَذَ؛لِــكَ مَآ أَرْسَلْنَا مِن قَبْلِكَ فِى قَرْيَةٍ مِّن نَّذِير۫ اِلاَّ قَالَ مُتْرَفُوهَآ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَــيٰٓ ٱُمَّةٍ وَإِنَّا عَلَــيٰٓ ءَاثۭـٰرۣهِم مُّقْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 23, '¤ قُلَ اَوَلَوْ جِيؔتُكُم بِأَهْدۭيٰ مِمَّا وَجَدتُّمْ عَلَيْهِ ءَابَآءَكُمْؐ قَالُوٓاْ إِنَّا بِمَآ ٱُرْسِلْتُم بِهِ” كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 24, 'فَانتَقَمْنَا مِنْهُمْ فَانظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 25, 'وَإِذْ قَالَ إِبْرَ؛هِيمُ لَأِبِيهِ وَقَوْمِهِ“ إِنَّنِى بَرَآءٌ مِّمَّا تَعْبُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 26, 'إِلاَّ ۰ﻟ﮲ فَطَرَنِى فَإِنَّهُ„ سَيَهْدِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 27, 'وَجَعَلَهَا كَلِمَةَۢ بَاقِيَةً فِى عَقِبِهِ” لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 28, 'بَــلْ مَتَّعْتُ هَـٰٓؤُلآَءِ وَءَابَآءَهُمْ حَتَّـيٰ جَآءَهُمُ ۴لْحَقُّ وَرَسُولٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 29, 'وَلَمَّا جَآءَهُمُ ۴لْحَــقُّ قَالُواْ هَـٰذَا سِحْـرٌ وَإِنَّا بِهِ” كَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 30, 'وَقَالُواْ لَوْلاَ نُزّۣلَ هَـٰذَا ۰لْقُرْءَانُ عَلَيٰ رَجُلٍ مِّنَ ۰لْقَرْيَتَيْــنۣ عَظِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 31, 'اَهُمْ يَقْسِمُونَ رَحْمَتَ رَبِّكَؐ نَحْــنُ قَسَمْنَا بَيْنَهُم مَّعِيشَتَهُمْ فِى ۱لْحَيَوٰةِ ۱لدُّنْيۭا 506 وَرَفَعْنَا بَعْضَهُمْ فَوْقَ بَعْضٍ دَرَجَـٰتٍ ڤِّيَتَّخِذَ بَعْضُهُم بَعْضاً سُخْرۣيّاًؐ وَرَحْمَــتُ رَبِّــكَ خَيْرٌ مِّمَّا يَجْمَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 32, 'وَلَوْلآَ أَنْ يَّكُونَ ۰لنَّاسسسُ ٱُمَّةً وَ؛حِدَةً لَّجَعَلْنَا لِمَنْ يَّكْفُرُ بِالرَّحْمَـٰنِ لِبُيُوتِهِمْ سُقُفاً مِّن فِضَّةٍ وَمَعَارۣجَ عَلَيْهَا يَظْهَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 33, 'وَلِبُيُوتِهِمُ; أَبْوَ؛باً وَسُرُراٗ عَلَيْهَا يَتَّكِـُٔونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 34, 'وَزُخْرُفاًؐ وَإِن كُلُّ ذَ؛لِــكَ لَمَا مَتَـٰعُ ۴لْحَيَوٰةِ ۱لدُّنْيۭاؐ وَالاَخِرَةُ عِندَ رَبِّكَ لِلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 35, 'وَمَنْ يَّعْشُ عَن ذِكْرۣ ۱لرَّحْمَـٰــنۣ نُقَيِّــضْ لَهُ„ شَيْطَـٰناً فَهُوَ لَهُ„ قَرۣينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 36, 'وَإِنَّهُمْ لَيَصُدُّونَهُمْ عَـنِ ۱لسَّبِيلِ وَيَحْسِبُونَ أَنَّهُم مُّهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 37, 'حَتَّيٰٓ إِذَا جَآءَ؛نَا قَالَ يَـٰلَيْتَ بَيْنِى وَبَيْنَكَ بُعْدَ ۰لْمَشْرۣقَيْنِؐ فَـبِيــسَ ۰لْقَرۣينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 38, 'وَلَـنْ يَّنفَعَكُمُ ۴لْيَوْمَ إِذ ظَّلَمْتُمُ; أَنَّكُمْ فِى ۱لْعَذَابِ مُشْتَرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 39, 'أَفَأَنتَ تُسْمِعُ ۴لصُّمَّ أَوْ تَهْدِى ۱لْعُمْيَ وَمَــن كَانَ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 40, 'فَإِمَّا نَذْهَبَنَّ بِــكَ فَإِنَّا مِنْهُم مُّنتَقِمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 41, 'أَوْ نُرۣيَنَّــكَ ۰ﻟ﮲ وَعَدْنَـٰهُمْ فَإِنَّا عَلَيْهِم مُّقْتَدِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 42, 'فَاسْتَمْسِــكْ بِاﻟـذِىٓ ٱُوحِيَ إِلَيْــكَؐ إِنَّــكَ عَلَيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 43, 'وَإِنَّهُ„ لَذِكْرٌ لَّــكَ 507 وَلِقَوْمِــكَؐ وَسَوْفَ تُسْـَٔلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 44, 'وَسْـَٔلْ مَنَ اَرْسَلْنَا مِــن قَبْلِكَ مِن رُّسُلِنَآؐ أَجَعَلْنَا مِن دُونِ ۱لرَّحْمَـٰــنۣ ءَالِهَةً يُعْبَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 45, 'وَلَقَدَ اَرْسَلْنَا مُوسۭيٰ بِـَٔايَـٰتِنَآ إِلَيٰ فِرْعَوْنَ وَمَلْاَئِهِ” فَقَالَ إِنِّى رَسُولُ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 46, 'فَلَمَّا جَآءَهُم بِـَٔايَـٰتِنَآ إِذَا هُم مِّنْهَا يَضْحَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 47, 'وَمَا نُرۣيهِم مِّــنَ —ايَةٖ اِلاَّ هِيَ أَكْبَرُ مِــنُ ۷خْتِهَاؐ وَأَخَذْنَـٰهُم بِالْعَذَابِ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 48, 'وَقَالُواْ يَـٰٓأَيُّهَ ۰لسَّاحِرُ ۶دْعُ لَنَا رَبَّــكَ بِمَا عَهِدَ عِندَكككَ إِنَّنَا لَمُهْتَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 49, 'فَلَمَّا كَشَفْنَا عَنْهُمُ ۴لْعَذَابَ إِذَا هُمْ يَنكُثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 50, 'وَنَادۭيٰ فِرْعَوْنُ فِى قَوْمِهِ” قَالَ يَـٰقَوْمِ أَلَيْـسَ لِى مُلْكُ مِصْرَ وَهَـٰذِهِ ۱لاَنْهَـٰرُ تَجْرۣى مِــن تَحْتِيَؐ أَفَلاَ تُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 51, 'أَمَ اَنَا خَيْرٌ مِّــنْ هَـٰذَا ۰ﻟ﮲ هُوَ مَهِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 52, 'وَلاَ يَكَادُ يُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 53, 'فَلَوْلآَ ٱُلْقِــيَ عَلَيْهِ أَسَـٰوۣرَةٌ مِّن ذَهَبٖ اَوْ جَآءَ مَعَهُ ۴لْمَلَئِكَةُ مُقْتَرۣنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 54, 'فَاسْتَخَفَّ قَوْمَهُ„ فَأَطَاعُوهُؐ إِنَّهُمْ كَانُواْ قَوْماً فَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 55, 'فَلَمَّآ ءَاسَفُونَا "نتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَـٰهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 56, '508 فَجَعَلْنَـٰهُمْ سَلَفاً وَمَثَلًا لِّلاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 57, 'وَلَمَّا ضُرۣبَ "بْنُ مَرْيَمَ مَثَلٗا اِذَا قَوْمُــكَ مِنْهُ يَصُدُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 58, 'وَقَالُوٓاْ ءَا۬؛لِهَتُنَا خَيْر٘ اَمْ هُوَؐ مَا ضَرَبُوهُ لَــكَ إِلاَّ جَدَلٚؐا بَلْ هُمْ قَوْم٘ خَصِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 59, 'إِنْ هُوَ إِلاَّ عَبْد٘ اَنْعَمْنَا عَلَيْهِ وَجَعَلْنَـٰهُ مَثَلًا لِّبَنِىٓ إِسْرَآءِيلَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 60, 'وَلَوْ نَشَآءُ لَجَعَلْنَا مِنكُم مَّلَئِكَةً فِى ۱لاَرْضضضِ يَخْلُفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 61, 'وَإِنَّهُ„ لَعِلْمٌ لِّلسَّاعَةِ فَلاَ تَمْتَرُنَّ بِهَاؐ وَاتَّبِعُونِ هَـٰذَا صِرَ؛طٌ مُّسْتَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 62, 'وَلاَ يَصُدَّنَّكُمُ ۴لشَّيْطَـٰنُؐ إِنَّهُ„ لَكُمْ عَدُوٌّ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 63, '© وَلَمَّا جَآءَ عِيسۭيٰ بِالْبَيِّنَـٰتِ قَالَ قَدْ جِيؔتُكُم بِالْحِكْمَةِ وَلُءِبَـيِّــنَ لَكُم بَعْضَ ۰ﻟ﮲ تَخْتَلِفُونَ فِيهِؐ فَاتَّقُواْ ۴للَّهَ وَأَطِيعُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 64, 'إِنَّ ۰للَّهَ هُوَ رَبِّى وَرَبُّكُمْ فَاعْبُدُوهُؐ هَـٰذَا صِرَ؛طٌ مُّسْتَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 65, 'فَاخْتَلَفَ ۰لاَحْزَابُ مِنۢ بَيْنِهِمْؐ فَوَيْلٌ لِّلذِيــنَ ظَلَمُواْ مِــنْ عَذَابِ يَوْمٖ اَلِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 66, 'هَلْ يَنظُرُونَ إِلاَّ ۰لسَّاعَةَ أَن تَاتِيَهُم بَغْتَةً وَهُمْ لاَ يَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 67, '۰لاَخِلٓاَّءُ يَوْمَئِذٙ بَعْضُهُمْ لِبَعْــضٖ عَدُوّﹲ اِلاَّ ۰لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 68, 'يَـٰعِبَادِى لاَ خَوْف٘ 509 عَلَيْكُمُ ۴لْيَوْمَ وَلآَ أَنتُمْ تَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 69, '۰لذِيــنَ ءَامَنُواْ بِـَٔايَـٰتِنَا وَكَانُواْ مُسْلِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 70, '۸دْخُلُواْ ۴لْجَنَّةَ أَنتُمْ وَأَزْوَ؛جُكُمْ تُحْبَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 71, 'يُطَافُ عَلَيْهِم بِصِحَافٍ مِّــن ذَهَبٍ وَأَكْوَابٍؐ وَفِيهَا مَا تَشْتَهِيهِ ۱لاَنفُسُ وَتَلَذُّ ۴لاَعْيُنُؐ وَأَنتُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 72, 'وَتِلْــكَ ۰لْجَنَّةُ ۴لتِىٓ ٱُورۣثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 73, 'لَكُمْ فِيهَا فَـٰكِهَةٌ كَثِيرَةٌ مِّنْهَا تَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 74, 'إِنَّ ۰ڤْمُجْرۣمِينَ فِى عَذَابِ جَهَنَّمَ خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 75, 'لاَ يُفَتَّرُ عَنْهُمْ وَهُمْ فِيهِ مُبْلِسُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 76, 'وَمَا ظَلَمْنَـٰهُمْؐ وَچَكِــن كَانُواْ هُمُ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 77, 'وَنَادَوْاْ يَـٰمَـٰلِــكُ لِيَقْضِ عَلَيْنَا رَبُّــكَؐ قَالَ إِنَّكُم مَّـٰكِثُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 78, 'لَقَدْ جِيؔنَـٰكُم بِالْحَقﱢّؐ وَچَكِــنَّ أَكْثَرَكُمْ ڤِڤْحَــقّۣ كَـٰرۣهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 79, 'أَمَ اَبْرَمُوٓاْ أَمْراً فَإِنَّا مُبْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 80, 'أَمْ يَحْسِبُونَ أَنَّا لاَ نَسْمَعُ سِرَّهُمْ وَنَجْوۭيٰهُم بَلۭيٰؐ وَرُسُلُنَا لَدَيْهِمْ يَكْتُبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 81, 'قُلِ اِن كَانَ لِلرَّحْمَـٰنِ وَلَدٌؐ فَأَنَآ أَوَّلُ ۴لْعَـٰبِدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 82, 'سُبْحَـٰنَ رَبِّ ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ رَبِّ ۱لْعَرْشِ عَمَّا يَصِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 83, 'فَذَرْهُمْ يَخُوضُواْ وَيَلْعَبُواْ 510 حَتَّيٰ يُچَقُواْ يَوْمَهُمُ ۴ﻟ﮲ يُوعَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 84, 'وَهُوَ ۰ﻟ﮲ فِى ۱لسَّمَآءِ اچَهٌ وَفِى ۱لاَرْضِ إِچَهٌؐ وَهُوَ ۰لْحَكِيمُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 85, 'وَتَبَـٰرَكككَ ۰ﻟ﮲ لَهُ„ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَاؐ وَعِندَهُ„ عِلْمُ ۴لسَّاعَةِؐ وَإِلَيْهِ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 86, 'وَلاَ يَمْلِكُ ۴لذِينَ يَدْعُونَ مِن دُونِهِ ۱لشَّفَـٰعَةَ إِلاَّ مَــن شَهِدَ بِالْحَقِّ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 87, 'وَلَـئِــن سَأَلْتَهُم مَّــنْ خَلَقَهُمْ لَيَقُولُــنَّ ۰للَّهُؐ فَأَنّۭيٰ يُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 88, 'وَقِيلَهُ„ يَـٰرَبِّ إِنَّ هَـٰٓؤُلآَءِ قَوْمٌ لاَّ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (43, 89, 'فَاصْفَحْ عَنْهُمْ وَقُــلْ سَچَمٌؐ فَسَوْفَ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓؐ وَالْكِتَـٰبِ ۱لْمُبِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 2, 'إِنَّـآ أَنزَلْنَـٰهُ فِى لَيْلَةٍ مُّبَـٰرَكَةٖ اِنَّا كُنَّا مُنذِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 3, 'فِيهَا يُفْرَقُ كُلُّ أَمْر۫ حَكِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 4, 'اَمْراً مِّنْ عِندِنَآؐ إِنَّا كُنَّا مُرْسِلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 5, 'رَحْمَةً مِّن رَّبِّــكَؐ إِنَّهُ„ هُوَ ۰لسَّمِيعُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 6, 'رَبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَآ إِننن كُنتُم مُّوقِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 7, 'لآَ إِچَهَ إِلاَّ هُوَؐ 511 يُحْىِ” وَيُمِيتُؐ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 8, 'بَلْ هُمْ فِى شَــكٍّ يَلْعَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 9, 'فَارْتَقِبْ يَوْمَ تَاتِى ۱لسَّمَآءُ بِدُخَانٍ مُّبِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 10, 'يَغْشَــي ۰لنَّاسسسَؐ هَـٰذَا عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 11, 'رَّبَّنَا "كْشِفْ عَنَّا ۰لْعَذَابَ إِنَّا مُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 12, 'أَنّۭــيٰ لَهُمُ ۴لذِّكْرۭيٰ وَقَدْ جَآءَهُمْ رَسُولٌ مُّبِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 13, 'ثُمَّ تَوَلَّوْاْ عَنْهُ وَقَالُواْ مُعَلَّمٌ مَّجْنُون٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 14, 'اِنَّا كَاشِفُواْ ۴لْعَذَابِ قَلِيلٗؐا اِنَّكُمْ عَآئِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 15, 'يَوْمَ نَبْطِشُ ۴لْبَطْشَةَ ۰لْكُبْرۭيٰٓؐ إِنَّا مُنتَقِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 16, 'وَلَقَدْ فَتَنَّا قَبْلَهُمْ قَوْمَ فِرْعَوْنَ وَجَآءَهُمْ رَسُولٌ كَرۣيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 17, 'اَنَ اَدُّوٓاْ إِلَيَّ عِبَادَ ۰للَّهِ إِنِّى لَكُمْ رَسُول٘ اَمِينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 18, 'وَأَن لاَّ تَعْلُواْ عَلَــي ۰للَّهِ إِنِّــيَ ءَاتِيكُم بِسُلْطَـٰنٍ مُّبِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 19, 'وَإِنِّى عُذْتُ بِرَبِّى وَرَبِّكُمُ; أَن تَرْجُمُونِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 20, 'وَإِن لَّمْ تُومِنُواْ لِـيَ فَاعْتَزۣلُونِؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 21, 'فَدَعَا رَبَّهُ; أَنَّ هَـٰٓؤُلآَءِ قَوْمٌ مُّجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 22, 'فَاسْرۣ بِعِبَادِى لَيْلٗا اِنَّكُم مُّتَّبَعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 23, 'وَاتْرُكككِ ۱ڤْبَحْرَ رَهْواٗؐ اِنَّهُمْ جُندٌ مُّغْرَقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 24, '¥ كَمْ تَرَكُواْ مِن جَنَّـٰتٍ وَعُيُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 25, 'وَزُرُوعٍ وَمَقَامٍ كَرۣيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 26, 'وَنَعْمَةٍ كَانُواْ فِيهَا 512 فَـٰكِهِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 27, 'كَذَ؛لِكَؐ وَأَوْرَثْنَـٰهَا قَوْماٗ —اخَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 28, 'فَمَا بَكَتْ عَلَيْهِمُ ۴لسَّمَآءُ وَالاَرْضُ وَمَا كَانُواْ مُنظَرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 29, 'وَلَقَدْ نَجَّيْنَا بَنِىٓ إِسْرَآءِيلَ مِنَ ۰لْعَذَابِ ۱لْمُهِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 30, 'مِن فِرْعَوْنَؐ إِنَّهُ„ كَانَ عَالِياً مِّــنَ ۰لْمُسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 31, 'وَلَقَدِ ''خْتَرْنَـٰهُمْ عَلَيٰ عِلْمٖ عَلَــي ۰لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 32, 'وَءَاتَيْنَـٰهُم مِّــنَ ۰لاَيَـٰتِ مَا فِيهِ ﺑَـ£ـؤٌاْ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 33, 'اِنَّ هَـٰٓؤُلآَءِ لَيَقُولُونَ إِنْ هِيَ إِلاَّ مَوْتَتُنَا ۰لاُولۭيٰ وَمَا نَحْنُ بِمُنشَرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 34, 'فَاتُواْ بِـَٔابَآئِنَآ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 35, 'أَهُمْ خَيْر٘ اَمْ قَوْمُ تُبَّعٍؐ وَالذِينَ مِن قَبْلِهِمُ; أَهْلَكْنَـٰهُمُؐ; إِنَّهُمْ كَانُواْ مُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 36, 'وَمَا خَلَقْنَا ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَمَا بَيْنَهُمَا چَعِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 37, 'مَا خَلَقْنَـٰهُمَآ إِلاَّ بِالْحَقﱢّؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 38, 'إِنَّ يَوْمَ ۰لْفَصْلِ مِيقَـٰتُهُمُ; أَجْمَعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 39, 'يَوْمَ لاَ يُغْنِى مَوْلــيٗ عَن مَّوْلــيً شَيْـٔاً وَلاَ هُمْ يُنصَرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 40, 'إِلاَّ مَن رَّحِمَ ۰للَّهُؐ إِنَّهُ„ هُوَ ۰لْعَزۣيزُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 41, 'إِنَّ شَجَرَتَ ۰لزَّقُّومِ طَعَامُ ۴لاَثِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 42, 'كَالْمُهْلِ تَغْلِى فِى ۱لْبُطُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 43, 'كَغَلْـيِ ۱لْحَمِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 44, 'خُذُوهُ فَاعْتُلُوهُ 51 إِلَيٰ سَوَآءِ ۱لْجَحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 45, 'ثُمَّ صُبُّواْ فَوْقَ رَأْسِهِ” مِنْ عَذَابِ ۱لْحَمِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 46, 'ذُقِؐ اِنَّــكَ أَنتَ ۰لْعَزۣيزُ ۴لْكَرۣيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 47, 'إِنننَّ هَـٰذَا مَا كُنتُم بِهِ” تَمْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 48, 'إِنَّ ۰لْمُتَّقِينَ فِى مُقَامٖ اَمِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 49, 'فِى جَنَّـٰتٍ وَعُيُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 50, 'يَلْبَسُونَ مِــن سُندُسٍ وَإِسْتَبْرَقٍ مُّتَقَـٰبِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 51, 'كَذَ؛لِــكَؐ وَزَوَّجْنَـٰهُم بِحُور۫ عِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 52, 'يَدْعُونَ فِيهَا بِكُلِّ فَـٰكِهَةٖ —امِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 53, 'لاَ يَذُوقُونَ فِيهَا ۰لْمَوْتَؐ إِلاَّ ۰لْمَوْتَةَ ۰لاُولۭيٰؐ وَوَقۭيٰهُمْ عَذَابَ ۰لْجَحِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 54, 'فَضْلًا مِّن رَّبِّــكَؐ ذَ؛لِــكَ هُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 55, 'فَإِنَّمَا يَسَّرْنَـٰهُ بِلِسَانِــكَ لَعَلَّهُمْ يَتَذَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (44, 56, 'فَارْتَقِبِؐ اِنَّهُم مُّرْتَقِبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓؐ تَنزۣيلُ ۴لْكِتَـٰبِ مِــنَ ۰للَّهِ ۱لْعَزۣيزۣ ۱لْحَكِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 2, 'إِنَّ فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِ ءَلاَيَـٰــتٍ لِّلْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 3, 'وَفِى خَلْقِكُمْ وَمَا يَبُثُّ مِــن دَآبَّةٖ —ايَـٰتٌ لِّقَوْمٍ يُوقِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 4, 'وَاخْتِچَفِ ۱ليْلِ وَالنَّهۭارۣ وَمَآ أَنزَلَ ۰للَّهُ مِنَ 514 ۰لسَّمَآءِ مِن رّۣزْقٍ فَأَحْيۭا بِهِ ۱لاَرْضَ بَعْدَ مَوْتِهَا وَتَصْرۣيفِ ۱لرّۣيَـٰحِ ءَايَـٰتٌ لِّقَوْمٍ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 5, 'تِلْــكَ ءَايَـٰــتُ ۴للَّهِ نَتْلُوهَا عَلَيْــكَ بِالْحَقﱢّؐ فَبِأَيِّ حَدِيثٙ بَعْدَ ۰للَّهِ وَءَايَـٰتِهِ” يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 6, 'وَيْلٌ لِّكُلِّ أَفَّاكككٖ اَثِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 7, 'يَسْمَعُ ءَايَـٰــتِ ۱للَّهِ تُتْلۭــيٰ عَلَيْهِ ثُمَّ يُصِرُّ مُسْتَكْبِراً كَأَن لَّمْ يَسْمَعْهَاؐ فَبَشِّرْهُ بِعَذَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 8, 'وَإِذَا عَلِمَ مِــنَ —ايَـٰتِنَا شَيْـٔاٗ ''تَّخَذَهَا هُزُؤاٗؐ ۷وْلَئِكَ لَهُمْ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 9, 'مِّنْ وَّرَآئِهِمْ جَهَنَّمُ وَلاَ يُغْنِى عَنْهُم مَّا كَسَبُواْ شَيْـٔاً وَلاَ مَا "تَّخَذُواْ مِن دُونِ ۱للَّهِ أَوْلِيَآءَؐ وَلَهُمْ عَذَاب٘ عَظِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 10, 'هَـٰذَا هُديًؐ وَالذِيــنَ كَفَرُواْ بِـَٔايَـٰــتِ رَبِّهِمْ لَهُمْ عَذَابٌ مِّن رّۣجْز۫ اَلِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 11, '۱للَّهُ ۴ﻟ﮲ سَخَّرَ لَكُمُ ۴ڤْبَحْرَ ڤِتَجْرۣيَ ۰لْفُلْــكُ فِيهِ بِأَمْرۣهِ” وَلِتَبْتَغُواْ مِن فَضْلِهِ” وَلَعَلَّكُمْ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 12, 'وَسَخَّرَ لَكُم مَّا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِ جَمِيعاً مِّنْهُؐ إِنَّ فِى ذَ؛لِــكَ ءَلاَيَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 13, '© قُل لِّلذِيــنَ ءَامَنُواْ يَغْفِرُواْ لِلذِيــنَ لاَ يَرْجُونَ أَيَّامَ ۰للَّهِ ڤِيَجْزۣيَ قَوْماَۢ بِمَا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 14, 'مَــنْ عَمِــلَ صَـٰڤِحاً فَلِنَفْسِهِؐ” 515 وَمَــنَ اَسَآءَ فَعَلَيْهَاؐ ثُمَّ إِلَيٰ رَبِّكُمْ تُرْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 15, 'وَلَقَدَ —اتَيْنَا بَنِىٓ إِسْرَآءِيلَ ۰لْكِتَـٰبَ وَالْحُكْمَ وَالنُّبُوٓءَةَ وَرَزَقْنَـٰهُم مِّنَ ۰لطَّيِّبَـٰتِ وَفَضَّلْنَـٰهُمْ عَلَــي ۰لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 16, 'وَءَاتَيْنَـٰهُم بَيِّنَـٰــتٍ مِّــنَ ۰لاَمْرۣؐ فَمَا "خْتَلَفُوٓاْ إِلاَّ مِنۢ بَعْدِ مَا جَآءَهُمُ ۴لْعِلْمُؐ بَغْياَۢ بَيْنَهُمُؐ; إِنَّ رَبَّكَ يَقْضِى بَيْنَهُمْ يَوْمَ ۰لْقِيَـٰمَةِ فِيمَا كَانُواْ فِيهِ يَخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 17, 'ثُمَّ جَعَلْنَـٰكَ عَلَيٰ شَرۣيعَةٍ مِّنَ ۰لاَمْرۣ فَاتَّبِعْهَاؐ وَلاَ تَتَّبِعَ اَهْوَآءَ ۰لذِيــنَ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 18, 'إِنَّهُمْ لَـنْ يُّغْنُواْ عَنــكَ مِــنَ ۰للَّهِ شَيْـٔاًؐ وَإِنَّ ۰لظَّـٰلِمِينَ بَعْضُهُمُ; أَوْلِيَآءُ بَعْضٍؐ وَاللَّهُ وَلِــيُّ ۴لْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 19, 'هَـٰذَا بَصَـٰٓئِرُ لِلنَّاسِ وَهُديً وَرَحْمَةٌ لِّقَوْمٍ يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 20, 'أَمْ حَسِبَ ۰لذِينَ "جْتَرَحُواْ ۴لسَّيِّـَٔاتِ أَن نَّجْعَلَهُمْ كَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ سَوَآءٌ مَّحْيۭاهُمْ وَمَمَاتُهُمْؐ سَآءَ مَا يَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 21, 'وَخَلَــقَ ۰للَّهُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضَ بِالْحَقﱢّؐ وَلِتُجْزۭيٰ كُلُّ نَفْسٙ بِمَا كَسَبَتْ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 22, 'أَفَرَ×يْتَ مَنِ ''تَّخَذَ إِچَهَهُ„ هَوۭيٰهُ وَأَضَلَّهُ ۴للَّهُ عَلَيٰ عِلْمٍ وَخَتَمَ عَلَــيٰ سَمْعِهِ” وَقَلْبِهِ” 516 وَجَعَــلَ عَلَيٰ بَصَرۣهِ” غِشَـٰوَةً فَمَنْ يَّهْدِيهِ مِـنۢ بَعْدِ ۱للَّهِؐ أَفَلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 23, 'وَقَالُواْ مَاهِيَ إِلاَّ حَيَاتُنَا ۰لدُّنْيۭا نَمُوتُ وَنَحْيۭاوَمَا يُهْلِكُنَآ إِلاَّ ۰لدَّهْرُؐ وَمَا لَهُم بِذَ؛لِــكَ مِنْ عِلْمٖؐ اِنْ هُمُ; إِلاَّ يَظُنُّونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 24, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُنَا بَيِّنَـٰتٍ مَّا كَانَ حُجَّتَهُمُ; إِلٓاَّ أَن قَالُواْ èيتُواْ بِـَٔابَآئِنَآ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 25, 'قُـلِ ۱للَّهُ يُحْيِيكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يَجْمَعُكُمُ; إِلَيٰ يَوْمِ ۱لْقِيَـٰمَةِ لاَ رَيْبَ فِيهِؐ وَچَكِــنَّ أَكْثَرَ ۰لنَّاسِ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 26, 'وَلِلهِ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَيَوْمَ تَقُومُ ۴لسَّاعَةُ يَوْمَئِذٍ يَخْسَرُ ۴لْمُبْطِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 27, 'وَتَرۭيٰ كُــلَّ ٱُمَّةٍ جَاثِيَةًؐ كُــلُّ ٱُمَّةٍ تُدْعۭيٰٓ إِلَيٰ كِتَـٰبِهَاؐ ۰لْيَوْمَ تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 28, 'هَـٰذَا كِتَـٰبُنَا يَنطِــقُ عَلَيْكُم بِالْحَقﱢّؐ إِنَّا كُنَّا نَسْتَنسِخُ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 29, 'فَأَمَّا ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ فَيُدْخِلُهُمْ رَبُّهُمْ فِى رَحْمَتِهِؐ” ذَ؛لِــكَ هُوَ ۰لْفَوْزُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 30, 'وَأَمَّا ۰لذِيــنَ كَفَرُوٓاْ أَفَلَمْ تَكُــنَ —ايَـٰتِى تُتْلۭيٰ عَلَيْكُمْ فَاسْتَكْبَرْتُمْ وَكُنتُمْ قَوْماً مُّجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 31, 'وَإِذَا قِيلَ 517 إِنَّ وَعْدَ ۰للَّهِ حَقٌّ وَالسَّاعَةُ لاَ رَيْبَ فِيهَا قُلْتُم مَّا نَدْرۣى مَا ۰لسَّاعَةُ إِن نَّظُنُّ إِلاَّ ظَنّاً وَمَا نَحْنُ بِمُسْتَيْقِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 32, 'وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا عَمِلُواْؐ وَحَاقَ بِهِم مَّا كَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 33, 'وَقِيلَ ۰لْيَوْمَ نَنسۭيٰكُمْ كَمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَا وَمَأْوۭيٰكُمُ ۴لنَّارُ وَمَا لَكُم مِّــن نَّـٰصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 34, 'ذَ؛لِكُم بِأَنَّكُمُ èتَّخَذتُّمُ; ءَايَـٰتِ ۱للَّهِ هُزُؤاً وَغَرَّتْكُمُ ۴لْحَيَوٰةُ ۴لدُّنْيۭاؐ فَالْيَوْمَ لاَ يُخْرَجُونَ مِنْهَا وَلاَ هُمْ يُسْتَعْتَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 35, 'فَلِلهِ ۱لْحَمْدُ رَبِّ ۱لسَّمَـٰوَ؛تِ وَرَبِّ ۱لاَرْضِ رَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (45, 36, 'وَلَهُ ۴لْكِبْرۣيَآءُ فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ حۭمِٓؐ تَنزۣيــلُ ۴لْكِتَـٰبِ مِــنَ ۰للَّهِ ۱لْعَزۣيزۣ ۱لْحَكِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 2, 'مَا خَلَقْنَا ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَمَا بَيْنَهُمَآ إِلاَّ بِالْحَقِّ وَأَجَــلٍ مُّسَمّيًؐ وَالذِيــنَ كَفَرُواْ عَمَّآ ٱُنذِرُواْ مُعْرۣضُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 3, 'قُلَ اَرَ×يْتُم مَّا تَدْعُونَ مِن دُونِ ۱للَّهِ أَرُونِى مَاذَا خَلَقُواْ 518 مِــنَ ۰لاَرْضِ أَمْ لَهُمْ شِرْكككٌ فِى ۱لسَّمَـٰوَ؛تِؐ ''يتُونِى بِكِتَـٰبٍ مِّــن قَبْلِ هَـٰذَآ أَوَ اَثَــٰرَةٍ مِّنْ عِلْمٖ اِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 4, 'وَمَــنَ اَضَلُّ مِمَّنْ يَّدْعُواْ مِن دُونِ ۱للَّهِ مَــن لاَّ يَسْتَجِيبُ لَهُ; إِلَيٰ يَوْمِ ۱لْقِيَـٰمَةِ وَهُمْ عَــن دُعَآئِهِمْ غَـٰفِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 5, 'وَإِذَا حُشِرَ ۰لنَّاسسسُ كَانُواْ لَهُمُ; أَعْدَآءً وَكَانُواْ بِعِبَادَتِهِمْ كۭـٰفِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 6, 'وَإِذَا تُتْلۭــيٰ عَلَيْهِمُ; ءَايَـٰتُنَا بَيِّنَـٰتٍ قَالَ ۰لذِيــنَ كَفَرُواْ ڤِڤْحَقِّ لَمَّا جَآءَهُمْ هَـٰذَا سِحْـرٌ مُّبِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 7, 'اَمْ يَقُولُونَ "فْتَرۭيٰهُؐ قُلِ اِنِ ''فْتَرَيْتُهُ„ فَلاَ تَمْلِكُونَ لِى مِــنَ ۰للَّهِ شَيْـٔاٗؐ هُوَ أَعْلَمُ بِمَا تُفِيضُونَ فِيهِؐ كَفۭيٰ بِــهِ” شَهِيداَۢ بَيْنِى وَبَيْنَكُمْؐ وَهُوَ ۰لْغَفُورُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 8, 'قُــلْ مَا كُنتُ بِدْعاً مِّنَ ۰لرُّسُلِ وَمَآ أَدْرۣى مَا يُفْعَلُ بِى وَلاَ بِكُمُؐ; إِنَ اَتَّبِعُ إِلاَّ مَا يُوحۭيٰٓ إِلَيَّؐ وَمَآ أَنَا إِلاَّ نَذِيرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 9, 'قُلَ اَرَ×يْتُمُ; إِن كَانَ مِنْ عِندِ ۱للَّهِ وَكَفَرْتُم بِهِ” وَشَهِدَ شَاهِدٌ مِّنۢ بَنِىٓ إِسْرَآءِيــلَ عَلَيٰ مِثْلِهِ” فَـَٔامَنَ وَاسْتَكْبَرْتُمُؐ; إِنَّ ۰للَّهَ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 10, 'وَقَالَ ۰لذِيــنَ كَفَرُواْ لِلذِيــنَ ءَامَنُواْ لَوْ كَانَ خَيْراً مَّا سَبَقُونَآ إِلَيْهِؐ 519 وَإِذْ لَمْ يَهْتَدُواْ بِهِ” فَسَيَقُولُونَ هَـٰذَآ إِفْكٌ قَدِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 11, 'وَمِــن قَـبْلِهِ” كِتَـٰبُ مُوسۭيٰٓ إِمَاماً وَرَحْمَةًؐ وَهَـٰذَا كِتَـٰبٌ مُّصَدِّقٌ لِّسَاناٗ عَرَبِيّاً لِّتُنذِرَ ۰لذِيــنَ ظَلَمُواْ وَبُشْرۭيٰ ڤِڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 12, 'إِنَّ ۰لذِيــنَ قَالُواْ رَبُّنَا ۰للَّهُ ثُمَّ "سْتَقَـٰمُواْ فَلاَ خَوْف٘ عَلَيْهِمْ وَلاَ هُمْ يَحْزَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 13, 'ٱُوْلَئِكَ أَصْحَـٰبُ ۴لْجَنَّةِ خَـٰلِدِينَ فِـيهَاؐ جَزَآءَۢ بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 14, 'وَوَصَّيْنَا ۰لِانسَـٰنَ بِوَ؛لِدَيْهِ حُسْناٗؐ حَمَلَتْهُ ٱُمُّهُ„ كَرْهاً وَوَضَعَتْهُ كَرْهاًؐ وَحَمْلُهُ„ وَفِصَـٰلُهُ„ ثَـچَثُونَ شَهْراٗؐ حَتَّيٰٓ إِذَا بَلَغَ أَشُدَّهُ„ وَبَلَغَ أَرْبَعِيــنَ سَنَةً قَالَ رَبِّ أَوْزۣعْنِيَ أَنَ اَشْكُرَ نِعْمَتَكَ ۰لتِىٓ أَنْعَمْتَ عَلَيَّ وَعَلَيٰ وَ؛لِدَيَّ وَأَنَ اَعْمَــلَ صَـٰڤِحاً تَرْضۭيٰهُؐ وَأَصْلِحْ لِى فِى ذُرّۣيَّتِىٓؐ إِنِّى تُبْتُ إِلَيْــكَ وَإِنِّى مِــنَ ۰لْمُسْلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 15, 'ٱُوْلَئِكَ ۰لذِينَ يُتَقَبَّــلُ عَنْهُمُ; أَحْسَــنُ مَا عَمِلُواْ وَيُتَجَاوَزُ عَــن سَيِّـَٔاتِهِمْ فِىٓ أَصْحَـٰبِ ۱لْجَنَّةِؐ وَعْدَ ۰لصِّدْقِ ۱ﻟ﮲ كَانُواْ يُوعَدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 16, 'وَاﻟ﮲ قَالَ لِوَ؛لِدَيْهِ ٱُفٍّ لَّكُمَآ أَتَعِدَ؛نِنِيَ أَنُ ۷خْرَجَ وَقَدْ خَلَتِ ۱لْقُرُونُ مِن قَبْلِى وَهُمَا يَسْتَغِيثَـٰنِ ۱للَّهَ وَيْلَــكَ ءَامِنِ اِنَّ 520 وَعْدَ ۰للَّهِ حَقٌّ فَيَقُولُ مَا هَـٰذَآ إِلٓاَّ أَسَـٰطِيرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 17, 'ٱُوْلَئِــكَ ۰لذِيــنَ حَقَّ عَلَيْهِمُ ۴لْقَوْلُ فِىٓ ٱُمَمٍ قَدْ خَلَتْ مِن قَبْلِهِم مِّنَ ۰لْجِنِّ وَالِانسِؐ إِنَّهُمْ كَانُواْ خَـٰسِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 18, 'وَلِكُلٍّ دَرَجَـٰتٌ مِّمَّا عَمِلُواْؐ وَلِنُوَفِّيَهُمُ; أَعْمَـٰلَهُمْ وَهُمْ لاَ يُظْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 19, 'وَيَوْمَ يُعْرَضضضُ ۴لذِيــنَ كَفَرُواْ عَلَــي ۰لـنّۭارۣ أَذْهَبْتُمْ طَيِّبَـٰتِكُمْ فِى حَيَاتِكُمُ ۴لدُّنْيۭا وَاسْتَمْتَعْتُم بِهَاؐ فَالْيَوْمَ تُجْزَوْنَ عَذَابَ ۰لْهُونِ بِمَا كُنتُمْ تَسْتَكْبِرُونَ فِى ۱لاَرْضضضِ بِغَيْرۣ ۱لْحَقِّ وَبِمَا كُنتُمْ تَفْسُقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 20, '© وَاذْكُرَ اَخَا عَادٖ اِذَ اَنذَرَ قَوْمَهُ„ بِالاَحْقَافِ وَقَدْ خَلَتِ ۱لنُّذُرُ مِنۢ بَيْـنِ يَدَيْهِ وَمِــنْ خَلْفِهِ“ أَلاَّ تَعْبُدُوٓاْ إِلاَّ ۰للَّهَؐ إِنِّــيَ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 21, 'قَالُوٓاْ أَجِيؔتَنَا لِتَافِكَنَا عَــنَ —الِهَتِنَا فَاتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِــنَ ۰لصَّـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 22, 'قَالَ إِنَّمَا ۰لْعِلْمُ عِندَ ۰للَّهِ وَٱُبَلِّغُكُم مَّآ ٱُرْسِلْتُ بِهِ” وَچَكِنِّيَ أَرۭيٰكُمْ قَوْماً تَجْهَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 23, 'فَلَمَّا رَأَوْهُ عَارۣضاً مُّسْتَقْبِلَ أَوْدِيَتِهِمْ قَالُواْ هَـٰذَا عَارۣضضضٌ مُّمْطِرُنَاؐ بَلْ هُوَ مَا "سْتَعْجَلْتُم بِهِؐ” 521 رۣيحٌ فِيهَا عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 24, 'تُدَمِّرُ كُــلَّ شَيْءٙ بِأَمْرۣ رَبِّهَاؐ فَأَصْبَحُواْ لاَ تَرۭيٰٓ إِلاَّ مَسَـٰكِنَهُمْؐ كَذَ؛لِكَ نَجْزۣى ۱لْقَوْمَ ۰ڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 25, 'وَلَقَدْ مَكَّنَّـٰهُمْ فِيمَآ إِن مَّكَّنَّـٰكُمْ فِيهِ وَجَعَلْنَا لَهُمْ سَمْعاً وَأَبْصَـٰراً وَأَفْـِٕدَةًؐ فَمَآ أَغْنۭــيٰ عَنْهُمْ سَمْعُهُمْ وَلآَ أَبْصَـٰرُهُمْ وَلآَ أَفْـِٕدَتُهُم مِّــن شَيْءٖ اِذْ كَانُواْ يَجْحَدُونَ بِـَٔايَـٰتِ ۱للَّهِؐ وَحَاقَ بِهِم مَّاكَانُواْ بِهِ” يَسْتَهْزۣءُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 26, 'وَلَقَدَ اَهْلَكْنَا مَا حَوْلَكُم مِّنَ ۰لْقُرۭيٰ وَصَرَّفْنَا ۰لاَيَـٰتِ لَعَلَّهُمْ يَرْجِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 27, 'فَلَوْلاَ نَصَرَهُمُ ۴لذِيــنَ "تَّخَذُواْ مِن دُونِ ۱للَّهِ قُرْبَاناٗ —الِهَةٚؐ بَلْ ضَلُّواْ عَنْهُمْؐ وَذَ؛لِــكَ إِفْكُهُمْ وَمَا كَانُواْ يَفْتَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 28, 'وَإِذْ صَرَفْنَآ إِلَيْــكَ نَفَراً مِّنَ ۰لْجِــنّۣ يَسْتَمِعُونَ ۰لْقُرْءَانَ فَلَمَّا حَضَرُوهُ قَالُوٓاْ أَنصِتُواْؐ فَلَمَّا قُضِيَ وَلَّوۣاْ اِلَيٰ قَوْمِهِم مُّنذِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 29, 'قَالُواْ يَـٰقَوْمَنَآ إِنَّا سَمِعْنَا كِتَـٰباٗ ۷نزۣلَ مِنۢ بَعْدِ مُوسۭــيٰ مُصَدِّقاً لِّمَا بَيْنَ يَدَيْهِ يَهْدِىٓ إِلَــي ۰لْحَقِّ وَإِلَيٰ طَرۣيــقٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 30, 'يَـٰقَوْمَنَآ أَجِيبُواْ دَاعِــيَ ۰للَّهِ وَءَامِنُواْ بِهِ” يَغْفِرْ لَكُم مِّــن ذُنُوبِكُمْ 522 وَيُجِرْكُم مِّــنْ عَذَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 31, 'وَمَــن لاَّ يُجِبْ دَاعِــيَ ۰للَّهِ فَلَيْــسَ بِمُعْجِزٍ فِى ۱لاَرْضِ وَلَيْــسَ لَهُ„ مِن دُونِهِ“ أَوْلِيَآءُؐ اوْلَئِــكَ فِى ضَچَــلٍ مُّــبِـينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 32, 'اَوَلَمْ يَرَوَاْ اَنَّ ۰للَّهَ ۰ﻟ﮲ خَلَقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَلَمْ يَعْــيَ بِخَلْقِهِنَّ بِقَـٰدِر۫ عَلَيٰٓ أَنْ يُّحْيـيِـــَي ۰لْمَوْتۭيٰ بَلۭيٰٓؐ إِنَّهُ„ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 33, 'وَيَوْمَ يُعْرَضُ ۴لذِيــنَ كَفَرُواْ عَلَــي ۰لـنّۭارۣ أَلَيْــسَ هَـٰذَا بِالْحَقﱢّؐ قَالُواْ بَلۭيٰ وَرَبِّنَاؐ قَالَ فَذُوقُواْ ۴لْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (46, 34, 'فَاصْبِرْ كَمَا صَبَرَ ٱُوْلُواْ ۴لْعَزْمِ مِنَ ۰لرُّسُلِ وَلاَ تَسْتَعْجِــلؐ لَّهُمْ كَأَنَّهُمْ يَوْمَ يَرَوْنَ مَا يُوعَدُونَ لَمْ يَلْبَثُوٓاْ إِلاَّ سَاعَةً مِّن نَّهۭارۣۢ بَچَغٌؐ فَهَـلْ يُهْلَكُ إِلاَّ ۰لْقَوْمُ ۴لْفَـٰسِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۰لذِيــنَ كَفَرُواْ وَصَدُّواْ عَن سَبِيـلِ ۱للَّهِ أَضَــلَّ أَعْمَـٰلَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 2, 'وَالذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰــتِ وَءَامَنُواْ بِمَا نُزّۣلَ عَلَــيٰ مُحَمَّدٍ وَهُوَ ۰لْحَقُّ مِن 52 رَّبِّهِمْ كَفَّرَ عَنْهُمْ سَيِّـَٔاتِهِمْ وَأَصْلَحَ بَالَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 3, 'ذَ؛لِــكَ بِأَنَّ ۰لذِيــنَ كَفَرُواْ èتَّبَعُواْ ۴لْبَـٰطِلَ وَأَنَّ ۰لذِيــنَ ءَامَنُواْ èتَّبَعُواْ ۴لْحَقَّ مِن رَّبِّهِمْؐ كَذَ؛لِــكَ يَضْرۣبُ ۴للَّهُ لِلنَّاسسسِ أَمْثَـٰلَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 4, 'فَإِذَا لَقِيتُمُ ۴لذِيــنَ كَفَرُواْ فَضَرْبَ ۰لرّۣقَابِؐ حَتَّيٰٓ إِذَآ أَثْخَنتُمُوهُمْ فَشُدُّواْ ۴لْوَثَاقَؐ فَإِمَّا مَنّاَۢ بَعْدُ وَإِمَّا فِدَآءٗ حَتَّيٰ تَضَعَ ۰لْحَرْبُ أَوْزَارَهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 5, 'ذَ؛لِــكَ وَلَوْ يَشَآءُ ۴للَّهُ لاَنتَصَرَ مِنْهُمْؐ وَچَكِن لِّـيَبْلُوَاْ بَعْضَكُم بِبَعْضٍؐ وَالذِيــنَ قَـٰتَلُواْ فِى سَبِيـلِ ۱للَّهِ فَلَنْ يُّضِــلَّ أَعْمَـٰلَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 6, 'سَيَهْدِيهِمْ وَيُصْلِحُ بَالَهُمْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 7, 'وَيُدْخِلُهُمُ ۴لْجَنَّةَ عَرَّفَهَا لَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 8, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِن تَنصُرُواْ ۴للَّهَ يَنصُرْكُمْ وَيُثَبِّتَ اَقْدَامَكُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 9, 'وَالذِيــنَ كَفَرُواْ فَتَعْساً لَّهُمْ وَأَضَــلَّ أَعْمَـٰلَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 10, 'ذَ؛لِــكَ بِأَنَّهُمْ كَرۣهُواْ مَآ أَنزَلَ ۰للَّهُ فَأَحْبَطَ أَعْمَـٰلَهُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 11, '¥ أَفَلَمْ يَسِيرُواْ فِى ۱لاَرْضِ فَــيَـنظُرُواْ كَيْفَ كَانَ عَـٰقِبَةُ ۴لذِينَ مِن قَبْلِهِمْ دَمَّرَ ۰للَّهُ عَلَيْهِمْؐ وَلِلْكۭـٰفِـرۣينَ أَمْثَـٰلُهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 12, 'ذَ؛لِكَ بِأَنَّ ۰للَّهَ مَوْلَــي ۰لذِيــنَ ءَامَنُواْ وَأَنَّ 524 ۰لْكۭـٰفِـرۣيــنَ لاَ مَوْلۭــيٰ لَهُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 13, 'إِنَّ ۰للَّهَ يُدْخِلُ ۴لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُؐ وَالذِيــنَ كَفَرُواْ يَتَمَتَّعُونَ وَيَاكُلُونَ كَمَا تَاكُــلُ ۴لاَنْعَـٰمُ وَالنَّارُ مَثْويً لَّهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 14, 'وَكَأَيِّن مِّن قَرْيَةٖ هِــيَ أَشَدُّ قُوَّةً مِّن قَرْيَتِــكَ ۰لتِىٓ أَخْرَجَتْــكَ أَهْلَكْنَـٰهُمْ فَلاَ نَاصِرَ لَهُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 15, 'أَفَمَــن كَانَ عَلَيٰ بَــيِّـنَةٍ مِّن رَّبِّهِ” كَمَن زُيِّــنَ لَهُ„ سُوٓءُ عَمَلِهِ” وَاتَّبَعُوٓاْ أَهْوَآءَهُمؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 16, 'مَّثَلُ ۴لْجَنَّةِ ۱لتِى وُعِدَ ۰لْمُتَّقُونَ فِيهَآ أَنْهَـٰرٌ مِّــن مَّآءٖ غَيْرۣ ءَاسِنٍ وَأَنْهَـٰرٌ مِّن لَّبَنٍ لَّمْ يَتَغَيَّرْ طَعْمُهُ„ وَأَنْهَـٰرٌ مِّــنْ خَمْرٍ لَّذَّةٍ لِّلشَّـٰرۣبِينَ وَأَنْهَـٰرٌ مِّــنْ عَسَلٍ مُّصَفّيًؐ وَلَهُمْ فِيهَا مِــن كُــلّۣ ۱لثَّمَرَ؛تِ وَمَغْفِرَةٌ مِّن رَّبِّهِمْ كَمَــنْ هُوَ خَـٰلِدٌ فِى ۱لنّۭارۣ وَسُقُواْ مَآءٗ حَمِيماً فَقَطَّعَ أَمْعَآءَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 17, 'وَمِنْهُم مَّنْ يَّسْتَمِعُ إِلَيْــكَ حَتَّيٰٓ إِذَا خَرَجُواْ مِنْ عِندِكَ قَالُواْ لِلذِينَ ٱُوتُواْ ۴لْعِلْمَ مَاذَا قَالَ ءَانِفاٗؐ ۷وْلَئِكَ ۰لذِينَ طَبَعَ ۰للَّهُ عَلَــيٰ قُلُوبِهِمْ وَاتَّبَعُوٓاْ أَهْوَآءَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 18, 'وَالذِينَ "هْتَدَوْاْ زَادَهُمْ هُديً وَءَاتۭيٰهُمْ تَقْوۭيٰهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 19, 'فَهَلْ 525 يَنظُرُونَ إِلاَّ ۰لسَّاعَةَ أَن تَاتِيَهُم بَغْتَةً فَقَدْ جَآءَ اشْرَاطُهَاؐ فَأَنّۭــيٰ لَهُمُ; إِذَا جَآءَتْهُمْ ذِكْرۭيٰهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 20, 'فَاعْلَمَ اَنَّهُ„ لآَ إِچَهَ إِلاَّ ۰للَّهُ وَاسْتَغْفِرْ لِذَنۢبِكَ وَلِلْمُومِنِينَ وَالْمُومِنَـٰتِؐ وَاللَّهُ يَعْلَمُ مُتَقَلَّبَكُمْ وَمَثْوۭيٰكُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 21, 'وَيَقُولُ ۴لذِيــنَ ءَامَنُواْ لَوْلاَ نُزّۣلَتْ سُورَةٌؐ فَإِذَآ ٱُنزۣلَتْ سُورَةٌ مُّحْكَمَةٌ وَذُكِرَ فِيهَا ۰لْقِتَالُ رَأَيْتَ ۰لذِيــنَ فِى قُلُوبِهِم مَّرَضٌ يَنظُرُونَ إِلَيْــكَ نَظَرَ ۰لْمَغْشِــيّۣ عَلَيْهِ مِــنَ ۰لْمَوْتِؐ فَأَوْلۭــيٰ لَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 22, 'طَاعَةٌ وَقَوْلٌ مَّعْرُوفٌؐ فَإِذَا عَزَمَ ۰لاَمْرُ فَلَوْ صَدَقُواْ ۴للَّهَ لَكَانَ خَيْراً لَّهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 23, 'فَهَــلْ عَـسِيتُمُ; إِن تَوَلَّيْتُمُ; أَن تُفْسِدُواْ فِى ۱لاَرْضِ وَتُقَطِّعُوٓاْ أَرْحَامَكُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 24, 'ٱُوْلَئِكَ ۰لذِيــنَ لَعَنَهُمُ ۴للَّهُ فَأَصَمَّهُمْ وَأَعْمۭيٰٓ أَبْصَـٰرَهُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 25, 'أَفَلاَ يَتَدَبَّرُونَ ۰لْقُرْءَانَ أَمْ عَلَيٰ قُلُوبٖ اَقْفَالُهَآؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 26, 'إِنَّ ۰لذِينَ "رْتَدُّواْ عَلَــيٰٓ أَدْبۭـٰرۣهِم مِّنۢ بَعْدِ مَا تَبَيَّــنَ لَهُمُ ۴لْهُدَي ۰لشَّيْطَـٰنُ سَوَّلَ لَهُمْؐ وَأَمْلۭيٰ لَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 27, 'ذَ؛لِكَ بِأَنَّهُمْ قَالُواْ لِلذِيــنَ كَرۣهُواْ مَا نَزَّلَ ۰للَّهُ سَنُطِيعُكُمْ فِى بَعْـضِ ۱لاَمْرۣؐ وَاللَّهُ يَعْلَمُ أَسْرَارَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 28, '526 فَكَيْفَ إِذَا تَوَفَّتْهُمُ ۴لْمَلَئِكَةُ يَضْرۣبُونَ وُجُوهَهُمْ وَأَدْبَـٰرَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 29, 'ذَ؛لِكَ بِأَنَّهُمُ èتَّبَعُواْ مَآ أَسْخَطَ ۰للَّهَ وَكَرۣهُواْ رۣضْوَ؛نَهُ„ فَأَحْبَطَ أَعْمَـٰلَهُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 30, 'أَمْ حَسِبَ ۰لذِينَ فِى قُلُوبِهِم مَّرَض٘ اَن لَّنْ يُّخْرۣجَ ۰للَّهُ أَضْغَـٰنَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 31, 'وَلَوْ نَشَآءُ لَأَرَيْنَـٰكَهُمْ فَلَعَرَفْتَهُم بِسِيمۭـٰهُمْؐ وَلَتَعْرۣفَنَّهُمْ فِى لَحْـنِ ۱لْقَوْلِؐ وَاللَّهُ يَعْلَمُ أَعْمَـٰلَكُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 32, 'وَلَنَبْلُوَنَّكُمْ حَتَّيٰ نَعْلَمَ ۰ڤْمُجَـٰهِدِينَ مِنكُمْ وَالصَّـٰبِرۣينَ وَنَبْلُوَاْ أَخْبَارَكُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 33, 'إِنَّ ۰لذِيــنَ كَفَرُواْ وَصَدُّواْ عَــن سَبِيـلِ ۱للَّهِ وَشَآقُّواْ ۴لرَّسُولَ مِـنۢ بَعْدِ مَا تَبَيَّــنَ لَهُمُ ۴لْهُدۭيٰ لَـنْ يَّضُرُّواْ ۴للَّهَ شَيْـٔاًؐ وَسَيُحْبِطُ أَعْمَـٰلَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 34, '© يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ أَطِيعُواْ ۴للَّهَ وَأَطِيعُواْ ۴لرَّسُولَ وَلاَ تُبْطِلُوٓاْ أَعْمَـٰلَكُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 35, 'إِنننَّ ۰لذِينَ كَفَرُواْ وَصَدُّواْ عَــن سَبِيـلِ ۱للَّهِ ثُمَّ مَاتُواْ وَهُمْ كُفَّارٌ فَلَنْ يَّغْفِرَ ۰للَّهُ لَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 36, 'فَلاَ تَهِنُواْ وَتَدْعُوٓاْ إِلَــي ۰لسَّلْمِ وَأَنتُمُ ۴لاَعْلَوْنَ وَاللَّهُ مَعَكُمْؐ وَلَنْ يَّتِرَكُمُ; أَعْمَـٰلَكُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 37, 'إِنَّمَا ۰لْحَيَوٰةُ ۴لدُّنْيۭا لَعِبٌ وَلَهْوٌؐ وَإِن تُومِنُواْ وَتَتَّقُواْ يُوتِكُمُ; 527 ٱُجُورَكُمْ وَلاَ يَسْـَٔلْكُمُ; أَمْوَ؛لَكُمُؐ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 38, 'إِنننْ يَّسْـَٔلْكُمُوهَا فَيُحْفِكُمْ تَبْخَلُواْ وَيُخْرۣجَ اَضْغَـٰنَكُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (47, 39, 'هَآنتُمْ هَـٰٓؤُلآَءِ تُدْعَوْنَ لِتُنفِقُواْ فِى سَبِيـلِ ۱للَّهِ فَمِنكُم مَّــنْ يَّبْخَلُؐ وَمَــنْ يَّبْخَلْ فَإِنَّمَا يَبْخَلُ عَن نَّفْسِهِؐ” وَاللَّهُ ۴لْغَنِيُّؐ وَأَنتُمُ ۴لْفُقَرَآءُؐ وَإِن تَتَوَلَّوْاْ يَسْتَبْدِلْ قَوْماٗ غَيْرَكُمْ ثُمَّ لاَ يَكُونُوٓاْ أَمْثَـٰلَكُمُ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِنَّا فَتَحْنَا لَكَ فَتْحاً مُّبِيناً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 2, 'لِّيَغْفِرَ لَــكَ ۰للَّهُ مَا تَقَدَّمَ مِــن ذَنۢبِكَ وَمَا تَأَخَّرَ وَيُتِمَّ نِعْمَتَهُ„ عَلَيْــكَ وَيَهْدِيَــكَ صِرَ؛طاً مُّسْتَقِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 3, 'وَيَنصُرَكَ ۰للَّهُ نَصْراٗ عَزۣيزاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 4, 'هُوَ ۰ﻟـذِىٓ أَنزَلَ ۰لسَّكِينَةَ فِى قُلُوبِ ۱لْمُومِنِينَ لِيَزْدَادُوٓاْ إِيمَـٰناً مَّعَ إِيمَـٰنِهِمْؐ وَلِلهِ جُنُودُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَكَانَ ۰للَّهُ عَلِيماٗ حَكِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 5, 'لِّيُدْخِــلَ ۰لْمُومِنِينَ وَالْمُومِنَـٰتِ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِـيهَا وَيُكَفِّرَ عَنْهُمْ سَيِّـَٔاتِهِمْ وَكَانَ ذَ؛لِــكَ عِندَ ۰للَّهِ فَوْزاٗ عَظِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 6, '528 وَيُعَذِّبَ ۰لْمُنَـٰفِقِينَ وَالْمُنَـٰفِقَـٰتِ وَالْمُشْرۣكِينَ وَالْمُشْرۣكَـٰتِ ۱لظَّآنِّينَ بِاللَّهِ ظَــنَّ ۰لسَّوْءِؐ عَلَيْهِمْ دَآئِرَةُ ۴لسَّوْءِؐ وَغَضِــبَ ۰للَّهُ عَلَيْهِمْ وَلَعَنَهُمْ وَأَعَدَّ لَهُمْ جَهَنَّمَؐ وَسَآءَتْ مَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 7, 'وَلِلهِ جُنُودُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَكَانَ ۰للَّهُ عَزۣيزاٗ حَكِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 8, 'اِنَّآ أَرْسَلْنَـٰكَ شَـٰهِداً وَمُبَشِّراً وَنَذِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 9, 'لِّتُومِنُواْ بِاللَّهِ وَرَسُولِهِ” وَتُعَزّۣرُوهُ وَتُوَقِّرُوهُ وَتُسَبِّحُوهُ بُكْرَةً وَأَصِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 10, 'اِنَّ ۰لذِينَ يُـبَايِعُونَــكَ إِنَّمَا يُبَايِعُونَ ۰للَّهَؐ يَدُ ۴للَّهِ فَوْقَ أَيْدِيهِمْؐ فَمَــن نَّكَثَ فَإِنَّمَا يَنكُثُ عَلَيٰ نَفْسِهِؐ” وَمَنَ اَوْفۭيٰ بِمَا عَـٰهَدَ عَلَيْهِ ۱للَّهَ فَسَنُوتِيهِ أَجْراٗ عَظِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 11, 'سَيَقُولُ لَــكَ ۰ڤْمُخَڤَّفُونَ مِــنَ ۰لاَعْرَابِ شَغَلَتْنَآ أَمْوَ؛لُنَا وَأَهْلُونَا فَاسْتَغْفِرْ لَنَاؐ يَقُولُونَ بِأَلْسِنَتِهِم مَّا لَيْـسَ فِى قُلُوبِهِمْؐ قُلْ فَمَنْ يَّمْلِــكُ لَكُم مِّــنَ ۰للَّهِ شَيْـٔاٗ اِنَ اَرَادَ بِكُمْ ضَرّاٗ اَوَ اَرَادَ بِكُمْ نَفْعاٚؐ بَــلْ كَانَ ۰للَّهُ بِمَا تَعْمَلُونَ خَبِيراٚؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 12, 'بَلْ ظَنَنتُمُ; أَن لَّـنْ يَّنقَلِبَ ۰لرَّسُولُ وَالْمُومِنُونَ إِلَــيٰٓ أَهْلِيهِمُ; أَبَداً وَزُيِّــنَ ذَ؛لِكَ فِى قُلُوبِكُمْ وَظَنَنتُمْ ظَنَّ ۰لسَّوْءِ 529 وَكُنتُمْ قَوْماَۢ بُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 13, 'وَمَن لَّمْ يُومِنۢ بِاللَّهِ وَرَسُولِهِ” فَإِنَّآ أَعْتَدْنَا لِلْكۭـٰفِـرۣيــنَ سَعِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 14, 'وَلِلهِ مُلْكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ يَغْفِرُ لِمَـنْ يَّشَآءُ وَيُعَذِّبُ مَنْ يَّشَآءُؐ وَكَانَ ۰للَّهُ غَفُوراً رَّحِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 15, 'سَيَقُولُ ۴لْمُخَلَّفُونَ إِذَا "نطَلَقْتُمُ; إِلَيٰ مَغَانِمَ لِتَاخُذُوهَا ذَرُونَا نَتَّبِعْكُمْؐ يُرۣيدُونَ أَنْ يُّبَدِّلُواْ كَچَمَ ۰للَّهِؐ قُل لَّن تَتَّبِعُونَاؐ كَذَ؛لِكُمْ قَالَ ۰للَّهُ مِن قَبْلُؐ فَسَيَقُولُونَ بَــلْ تَحْسُدُونَنَاؐ بَــلْ كَانُواْ لاَ يَفْقَهُونَ إِلاَّ قَلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 16, 'قُــل ڤِّڤْمُخَلَّفِينَ مِنَ ۰لاَعْرَابِ سَتُدْعَوْنَ إِلَيٰ قَوْمٖ ۷وْلِى بَأْسسسٍ شَدِيدٍ تُقَـٰتِلُونَهُمُ; أَوْ يُسْلِمُونَؐ فَإِن تُطِيعُواْ يُوتِكُمُ ۴للَّهُ أَجْراٗ حَسَناًؐ وَإِن تَتَوَلَّوْاْ كَمَا تَوَلَّيْتُم مِّن قَبْلُ يُعَذِّبْكُمْ عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 17, 'لَّيْــسَ عَلَي ۰لاَعْمۭيٰ حَرَجٌ وَلاَ عَلَــي ۰لاَعْرَجِ حَرَجٌ وَلاَ عَلَــي ۰لْمَرۣيــضِ حَرَجٌؐ وَمَنْ يُّطِعِ ۱للَّهَ وَرَسُولَهُ„ نُدْخِلْهُ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُؐ وَمَـنْ يَّتَوَلَّ نُعَذِّبْهُ عَذَاباٗ اَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 18, '¤ لَّقَدْ رَضِــيَ ۰للَّهُ عَـنِ ۱لْمُومِنِينَ إِذْ يُبَايِعُونَكَ تَحْتَ ۰لشَّجَرَةِ فَعَلِمَ مَا فِى قُلُوبِهِمْ فَأَنزَلَ 50 ۰لسَّكِينَةَ عَلَيْهِمْ وَأَثَـٰبَهُمْ فَتْحاً قَرۣيباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 19, 'وَمَغَانِمَ كَثِيرَةً يَاخُذُونَهَاؐ وَكَانَ ۰للَّهُ عَزۣيزاٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 20, 'وَعَدَكُمُ ۴للَّهُ مَغَانِمَ كَثِيرَةً تَاخُذُونَهَا فَعَجَّــلَ لَكُمْ هَـٰذِهِ” وَكَفَّ أَيْدِيَ ۰لنَّاسسسِ عَنكُمْؐ وَلِتَكُونَ ءَايَةً لِّلْمُومِنِينَ وَيَهْدِيَكُمْ صِرَ؛طاً مُّسْتَقِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 21, 'وَٱُخْرۭيٰ لَمْ تَقْدِرُواْ عَلَيْهَا قَدَ اَحَاطَ ۰للَّهُ بِهَاؐ وَكَانَ ۰للَّهُ عَلَــيٰ كُــلّۣ شَيْءٍ قَدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 22, 'وَلَوْ قَـٰتَلَكُمُ ۴لذِينَ كَفَرُواْ لَوَلَّوُاْ ۴لاَدْبَـٰرَ ثُمَّ لاَ يَجِدُونَ وَلِيّاً وَلاَ نَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 23, 'سُنَّةَ ۰للَّهِ ۱لتِى قَدْ خَلَتْ مِن قَبْلُؐ وَلَن تَجِدَ لِسُنَّةِ ۱للَّهِ تَبْدِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 24, 'وَهُوَ ۰ﻟ﮲ كَفَّ أَيْدِيَهُمْ عَنكُمْ وَأَيْدِيَكُمْ عَنْهُم بِبَطْــنۣ مَكَّةَ مِـنۢ بَعْدِ أَنَ اَظْفَرَكُمْ عَلَيْهِمْؐ وَكَانَ ۰للَّهُ بِمَا تَعْمَلُونَ بَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 25, 'هُمُ ۴لذِيــنَ كَفَرُواْ وَصَدُّوكُمْ عَـنِ ۱ڤْمَسْجِدِ ۱لْحَرَامِ وَالْهَدْيَ مَعْكُوفاٗ اَنْ يَّبْلُغَ مَحِلَّهُؐ, وَلَوْلاَ رۣجَالٌ مُّومِنُونَ وَنِسَآءٌ مُّومِنَـٰــتٌ لَّمْ تَعْلَمُوهُمُ; أَن تَطَـُٔوهُمْ فَتُصِيبَكُم مِّنْهُم مَّعَرَّةٛ بِغَيْرۣ عِلْمٍ لِّيُدْخِــلَ ۰للَّهُ فِى رَحْمَتِهِ” مَنْ يَّشَآءُؐ لَوْ تَزَيَّلُواْ لَعَذَّبْنَا ۰لذِيــنَ كَفَرُواْ مِنْهُمْ عَذَاباٗ اَلِيماٗؐ 51');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 26, 'اِذْ جَعَلَ ۰لذِيــنَ كَفَرُواْ فِى قُلُوبِهِمُ ۴لْحَمِيَّةَ حَمِيَّةَ ۰لْجَـٰهِلِيَّةِؐ فَأَنزَلَ ۰للَّهُ سَكِينَتَهُ„ عَلَيٰ رَسُولِهِ” وَعَلَــي ۰لْمُومِنِينَ وَأَلْزَمَهُمْ كَلِمَةَ ۰لتَّقْوۭيٰ وَكَانُوٓاْ أَحَقَّ بِهَا وَأَهْلَهَاؐ وَكَانَ ۰للَّهُ بِكُــلّۣ شَيْءٖ عَلِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 27, 'لَّقَدْ صَدَقققَ ۰للَّهُ رَسُولَهُ ۴لرُّءْيۭا بِالْحَــقّۣ لَتَدْخُلُــنَّ ۰ڤْمَسْجِدَ ۰لْحَرَامَ إِن شَآءَ ۰للَّهُ ءَامِنِينَ مُحَلِّقِينَ رُءُوسَكُمْ وَمُقَصِّرۣيــنَ لاَ تَخَافُونَؐ فَعَلِمَ مَا لَمْ تَعْلَمُواْ فَجَعَلَ مِن دُونِ ذَ؛لِــكَ فَتْحاً قَرۣيباٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 28, 'هُوَ ۰ﻟـذِىٓ أَرْسَلَ رَسُولَهُ„ بِالْهُدۭيٰ وَدِيـنِ ۱لْحَقِّ لِيُظْهِرَهُ„ عَلَــي ۰لدِّيــنۣ كُلِّهِؐ” وَكَفۭيٰ بِاللَّهِ شَهِيداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (48, 29, 'مُّحَمَّدٌ رَّسُولُ ۴للَّهِؐ وَالذِيــنَ مَعَهُ; أَشِدَّآءُ عَلَــي ۰لْكُفّۭارۣ رُحَمَآءُ بَيْنَهُمْؐ تَرۭيٰهُمْ رُكَّعاً سُجَّداً يَبْتَغُونَ فَضْلًا مِّنَ ۰للَّهِ وَرۣضْوَ؛ناًؐ سِيمۭاهُمْ فِى وُجُوهِهِم مِّنَ اَثَرۣ ۱ڤسُّجُودِؐ ذَ؛لِــكَ مَثَلُهُمْ فِى ۱لتَّوْرۭيٰةِؐ وَمَثَلُهُمْ فِى ۱لِانجِيــلۣ كَزَرْعٖ اَخْرَجَ شَطْـَٔهُ„ فَــَٔازَرَهُ„ فَاسْتَغْلَظَ فَاسْتَوۭيٰ عَلَيٰ سُوقِهِ” يُعْجِبُ ۴لزُّرَّاعَ لِيَغِيظَ بِهِمُ ۴لْكُفَّارَؐ وَعَدَ ۰للَّهُ ۴لذِينَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ مِنْهُم مَّغْفِرَةً وَأَجْراٗ عَظِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 1, '© بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تُقَدِّمُواْ بَيْنَ يَدَيِ ۱للَّهِ وَرَسُولِهِؐ” وَاتَّقُواْ ۴للَّهَؐ إِنَّ ۰للَّهَ سَمِيع٘ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 2, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَرْفَعُوٓاْ أَصْوَ؛تَكُمْ فَوْقَ صَوْتِ ۱لنَّبِىٓءِ وَلاَ تَجْهَرُواْ لَهُ„ بِالْقَوْلِ كَجَهْرۣ بَعْضِكُمْ لِبَعْضٖ اَن تَحْبَطَ أَعْمَـٰلُكُمْ وَأَنتُمْ لاَ تَشْعُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 3, 'إِنَّ ۰لذِيــنَ يَغُضُّونَ أَصْوَ؛تَهُمْ عِندَ رَسُولِ ۱للَّهِ ٱُوْلَئِــكَ ۰لذِينَ "مْتَحَــنَ ۰للَّهُ قُلُوبَهُمْ لِلتَّقْوۭيٰؐ لَهُم مَّغْفِرَةٌ وَأَجْر٘ عَظِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 4, 'اِنَّ ۰لذِينَ يُنَادُونَكَ مِنْ وَّرَآءِ ۱لْحُجُرَ؛تِ أَكْثَرُهُمْ لاَ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 5, 'وَلَوَ اَنَّهُمْ صَبَرُواْ حَتَّــيٰ تَخْرُجَ إِلَيْهِمْ لَكَانَ خَيْراً لَّهُمْؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 6, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِن جَآءَكُمْ فَاسِقٛ بِنَبَإٍ فَتَبَيَّنُوٓاْ أَن تُصِيبُواْ قَوْماَۢ بِجَهَـٰلَةٍ فَتُصْبِحُواْ عَلَــيٰ مَا فَعَلْتُمْ نَـٰدِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 7, 'وَاعْلَمُوٓاْ أَنَّ فِيكُمْ رَسُولَ ۰للَّهِ لَوْ يُطِيعُكُمْ فِى كَثِيرٍ مِّنَ ۰لاَمْرۣ لَعَنِتُّمْؐ وَچَكِنَّ 5 ۰للَّهَ حَبَّــبَ إِلَيْكُمُ ۴لِايمَـٰنَ وَزَيَّنَهُ„ فِى قُلُوبِكُمْ وَكَرَّهَ إِلَيْكُمُ ۴لْكُفْرَ وَالْفُسُوقَ وَالْعِصْيَانَؐ ٱُوْلَئِــكَ هُمُ ۴لرَّ؛شِدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 8, 'فَضْلًا مِّــنَ ۰للَّهِ وَنِعْمَةًؐ وَاللَّهُ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 9, 'وَإِن طَآئِفَتَـٰنِ مِنَ ۰لْمُومِنِينَ "قْتَتَلُواْ فَأَصْڤِحُواْ بَيْنَهُمَاؐ فَإِنۢ بَغَتِ اِحْدۭيٰهُمَا عَلَــي ۰لاُخْرۭيٰ فَقَـٰتِلُواْ ۴لتِى تَبْغِى حَتَّيٰ تَفِىٓءَ اۭلَــيٰٓ أَمْرۣ ۱للَّهِؐ فَإِن فَآءَتْ فَأَصْڤِحُواْ بَيْنَهُمَا بِالْعَدْلِ وَأَقْسِطُوٓاْؐ إِنننَّ ۰للَّهَ يُحِبُّ ۴لْمُقْسِطِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 10, 'إِنَّمَا ۰لْمُومِنُونَ إِخْوَةٌ فَأَصْڤِحُواْ بَيْنَ أَخَوَيْكُمْؐ وَاتَّقُواْ ۴للَّهَ لَعَلَّكُمْ تُرْحَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 11, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ يَسْخَرْ قَوْمٌ مِّن قَوْمٖ عَسۭيٰٓ أَنْ يَّكُونُواْ خَيْراً مِّنْهُمْ وَلاَ نِسَآءٌ مِّــن نِّسَآءٖ عَسۭيٰٓ أَنْ يَّكُــنَّ خَيْراً مِّنْهُنَّؐ وَلاَ تَلْمِزُوٓاْ أَنفُسَكُمْ وَلاَ تَنَابَزُواْ بِالاَلْقَـٰبِؐ بِيسَ ۰لِاسْمُ ۴لْفُسُوقُ بَعْدَ ۰لِايمَـٰنِؐ وَمَن لَّمْ يَتُبْ فَٱُوْلَئِــكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 12, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èجْتَنِبُواْ كَثِيراً مِّــنَ ۰لظَّن؋ّؐ إِنَّ بَعْضَ ۰لظَّنِّ إِثْمٌؐ وَلاَ تَجَسَّسُواْؐ وَلاَ يَغْتَب بَّعْضُكُم بَعْضاٗؐ اَيُحِبُّ أَحَدُكُمُ; أَنْ يَّاكُــلَ لَحْمَ أَخِيهِ مَيِّتاً فَكَرۣهْتُمُوهُؐ وَاتَّقُواْ ۴للَّهَؐ 54 إِنَّ ۰للَّهَ تَوَّابٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 13, 'يَـٰٓأَيُّهَا ۰لنَّاسُ إِنَّا خَلَقْنَـٰكُم مِّن ذَكَرٍ وَٱُنثۭيٰ وَجَعَلْنَـٰكُمْ شُعُوباً وَقَبَآئِلَ لِتَعَارَفُوٓاْؐ إِنَّ أَكْرَمَكُمْ عِندَ ۰للَّهِ أَتْقۭيٰكُمُؐ; إِنَّ ۰للَّهَ عَلِيم٘ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 14, '¥ قَالَتِ ۱لاَعْرَابُ ءَامَنَّا قُل لَّمْ تُومِنُواْ وَچَكِن قُولُوٓاْ أَسْلَمْنَا وَلَمَّا يَدْخُلِ ۱لِايمَـٰنُ فِى قُلُوبِكُمْؐ وَإِن تُطِيعُواْ ۴للَّهَ وَرَسُولَهُ„ لاَ يَلِتْكُم مِّــنَ اَعْمَـٰلِكُمْ شَيْـٔاٗؐ اِنَّ ۰للَّهَ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 15, 'اِنَّمَا ۰لْمُومِنُونَ ۰لذِيــنَ ءَامَنُواْ بِاللَّهِ وَرَسُولِهِ” ثُمَّ لَمْ يَرْتَابُواْ وَجَـٰهَدُواْ بِأَمْوَ؛لِهِمْ وَأَنفُسِهِمْ فِى سَبِيـلِ ۱للَّهِؐ ٱُوْلَئِكَ هُمُ ۴لصَّـٰدِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 16, 'قُــلَ اَتُعَلِّمُونَ ۰للَّهَ بِدِينِكُمْ وَاللَّهُ يَعْلَمُ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَاللَّهُ بِكُــلّۣ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 17, 'يَمُنُّونَ عَلَيْــكَ أَنننَ اَسْلَمُواْؐ قُــل لاَّ تَمُنُّواْ عَلَيَّ إِسْچَمَكُمؐ بَـلِ ۱للَّهُ يَمُنُّ عَلَيْكُمُ; أَنننْ هَدۭيٰكُمْ لِلِايمَـٰنِ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (49, 18, 'إِنننَّ ۰للَّهَ يَعْلَمُ غَيْبَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَاللَّهُ بَصِيرٛ بِمَا تَعْمَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 1, '55 بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قَٓؐ وَالْقُرْءَانِ ۱لْمَجِيدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 2, 'بَــلْ عَجِبُوٓاْ أَن جَآءَهُم مُّنذِرٌ مِّنْهُمْ فَقَالَ ۰لْكَـٰفِرُونَ هَـٰذَا شَيْء٘ عَجِيب٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 3, 'اَ.ذَا مِتْنَا وَكُنَّا تُرَاباً ذَ؛لِــكَ رَجْعٛ بَعِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 4, 'قَدْ عَلِمْنَا مَا تَنقُــصُ ۴لاَرْضُ مِنْهُمْ وَعِندَنَا كِتَـٰب٘ حَفِيظٛؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 5, 'بَــلْ كَذَّبُواْ بِالْحَــقّۣ لَمَّا جَآءَهُمْ فَهُمْ فِىٓ أَمْرٍ مَّرۣيجٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 6, 'اَفَلَمْ يَنظُرُوٓاْ إِلَــي ۰لسَّمَآءِ فَوْقَهُمْ كَيْفَ بَنَيْنَـٰهَا وَزَيَّنَّـٰهَا وَمَا لَهَا مِن فُرُوجٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 7, 'وَالاَرْضضضَ مَدَدْنَـٰهَا وَأَلْقَيْنَا فِيهَا رَوَ؛سِيَ وَأَنۢبَتْنَا فِيهَا مِــن كُلِّ زَوْجٙ بَهِيجٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 8, 'تَبْصِرَةً وَذِكْرۭيٰ لِكُــلّۣ عَـبْـدٍ مُّنِيبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 9, 'وَنَزَّلْنَا مِــنَ ۰لسَّمَآءِ مَآءً مُّبَـٰرَكاً فَأَنۢبَتْنَا بِهِ” جَنَّـٰتٍ وَحَبَّ ۰لْحَصِيدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 10, 'وَاڤنَّخْلَ بَاسِقَـٰتٍ لَّهَا طَلْعٌ نَّضِيدٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 11, 'رّۣزْقاً لِّلْعِبَادِؐ وَأَحْيَيْنَا بِهِ” بَلْدَةً مَّيْتاًؐ كَذَ؛لِــكَ ۰لْخُرُوجُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 12, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَأَصْحَـٰبُ ۴لرَّسِّ وَثَمُودُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 13, 'وَعَادٌ وَفِرْعَوْنُ وَإِخْوَ؛نُ لُوطٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 14, 'وَأَصْحَـٰبُ ۴لاَيْكَةِ وَقَوْمُ تُبَّعٍؐ كُــلٌّ كَذَّبَ ۰لرُّسُــلَ فَحَقَّ وَعِيدِؐ“');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 15, 'أَفَعَيِينَا بِالْخَلْـقِ ۱لاَوَّلِؐ بَــلْ هُمْ فِى لَبْسٍ مِّنْ خَلْقٍ جَدِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 16, '56 وَلَقَدْ خَلَقْنَا ۰لِانسَـٰنَ وَنَعْلَمُ مَا تُوَسْوۣسُ بِــهِ” نَفْسُهُ„ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِــنْ حَبْلِ ۱لْوَرۣيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 17, 'إِذْ يَتَلَقَّــي ۰لْمُتَلَقِّيَـٰنِ عَنِ ۱لْيَمِينِ وَعَـنِ ۱لشِّمَالِ قَعِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 18, 'مَّا يَلْفِظُ مِن قَوْلٖ اِلاَّ لَدَيْهِ رَقِيب٘ عَتِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 19, 'وَجَآءَتْ سَكْرَةُ ۴لْمَوْتِ بِالْحَــقّۣؐ ذَ؛لِكَ مَا كُنتَ مِنْهُ تَحِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 20, 'وَنُفِخَ فِى ۱لصُّورۣؐ ذَ؛لِكَ يَوْمُ ۴لْوَعِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 21, 'وَجَآءَتْ كُلُّ نَفْـــسٍ مَّعَهَا سَآئِقٌ وَشَهِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 22, 'لَّقَدْ كُنتَ فِى غَفْلَةٍ مِّــنْ هَـٰذَا فَكَشَفْنَا عَنــكَ غِطَآءَكككَ فَبَصَرُكَ ۰لْيَوْمَ حَدِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 23, 'وَقَالَ قَرۣينُهُ„ هَـٰذَا مَا لَدَيَّ عَتِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 24, 'اَلْقِيَا فِى جَهَنَّمَ كُــلَّ كَفّۭار۫ عَنِيدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 25, 'مَّنَّاعٍ ڤِّڤْخَيْرۣ مُعْتَدٍ مُّرۣيبٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 26, '۱ﻟ﮲ جَعَلَ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ فَأَلْقِيَـٰهُ فِى ۱لْعَذَابِ ۱لشَّدِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 27, '© قَالَ قَرۣينُهُ„ رَبَّنَا مَآ أَطْغَيْتُهُ„ وَچَكِــن كَانَ فِى ضَچَلٙ بَعِيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 28, 'قَالَ لاَ تَخْتَصِمُواْ لَدَيَّ وَقَدْ قَدَّمْتُ إِلَيْكُم بِالْوَعِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 29, 'مَا يُبَدَّلُ ۴لْقَوْلُ لَدَيَّ وَمَآ أَنَا بِظَچَّمٍ لِّلْعَبِيدِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 30, 'يَوْمَ يَقُولُ لِجَهَنَّمَ هَلِ ''مْتَلْأَتِ وَتَقُولُ هَلْ مِن مَّزۣيدٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 31, 'وَٱُزْلِفَتِ ۱لْجَنَّةُ لِلْمُتَّقِيــنَ غَيْرَ بَعِيدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 32, 'هَـٰذَا مَا تُوعَدُونَ 57 لِكُلِّ أَوَّابٖ حَفِيظٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 33, 'مَّــنْ خَشِيَ ۰لرَّحْمَـٰــنَ بِالْغَيْبِ وَجَآءَ بِقَلْبٍ مُّنِيبٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 34, '۶دْخُلُوهَا بِسَچَمٍؐ ذَ؛لِــكَ يَوْمُ ۴لْخُلُودِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 35, 'لَهُم مَّا يَشَآءُونَ فِيهَاؐ وَلَدَيْنَا مَزۣيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 36, 'وَكَمَ اَهْلَكْنَا قَبْلَهُم مِّن قَرْنٖ هُمُ; أَشَدُّ مِنْهُم بَطْشاً فَنَقَّبُواْ فِى ۱لْبِچَدِؐ هَلْ مِن مَّحِيصٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 37, 'اِنَّ فِى ذَ؛لِــكَ لَذِكْرۭيٰ لِمَــن كَانَ لَهُ„ قَلْب٘ اَوَ اَلْقَي ۰لسَّمْعَ وَهُوَ شَهِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 38, 'وَلَقَدْ خَلَقْنَا ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍ وَمَا مَسَّنَا مِــن لُّغُوبٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 39, 'فَاصْبِرْ عَلَيٰ مَا يَقُولُونَؐ وَسَبِّحْ بِحَمْدِ رَبِّــكَ قَبْــلَ طُلُوعِ ۱لشَّمْسِ وَقَبْــلَ ۰لْغُرُوبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 40, 'وَمِنَ ۰ليْلِ فَسَبِّحْهُ وَإِدْبَـٰرَ ۰ڤسُّجُودِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 41, 'وَاسْتَمِعْ يَوْمَ يُنَادِ ۱لْمُنَادِ” مِــن مَّكَانٍ قَرۣيبٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 42, 'يَوْمَ يَسْمَعُونَ ۰ڤصَّيْحَةَ بِالْحَقﱢّؐ ذَ؛لِــكَ يَوْمُ ۴لْخُرُوجِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 43, 'إِنَّا نَحْنُ نُحْىِ” وَنُمِيــتُ وَإِلَيْنَا ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 44, 'يَوْمَ تَشَّقَّقُ ۴لاَرْضُ عَنْهُمْ سِرَاعاًؐ ذَ؛لِــكَ حَشْر٘ عَلَيْنَا يَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (50, 45, 'نَّحْــنُ أَعْلَمُ بِمَا يَقُولُونَؐ وَمَآ أَنتَ عَلَيْهِم بِجَبّۭارٍؐ فَذَكِّرْ بِالْقُرْءَانِ مَــنْ يَّخَافُ وَعِيدِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 1, '58  بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالذَّ؛رۣيَـٰتِ ذَرْواً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 2, 'فَالْحَـٰمِچَتِ وۣقْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 3, 'فَالْجَـٰرۣيَـٰتِ يُسْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 4, 'فَالْمُقَسِّمَـٰتِ أَمْراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 5, 'اِنَّمَا تُوعَدُونَ لَصَادِقٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 6, 'وَإِنَّ ۰لدِّينَ لَوَ؛قِعٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 7, 'وَالسَّمَآءِ ذَاتِ ۱لْحُبُــكِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 8, 'إِنَّكُمْ لَفِى قَوْلٍ مُّخْتَلِفٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 9, 'يُوفَــكُ عَنْهُ مَنُ ۷فِــكَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 10, 'قُتِــلَ ۰لْخَرَّ؛صُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 11, '۰لذِينَ هُمْ فِى غَمْرَةٍ سَاهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 12, 'يَسْـَٔلُونَ أَيَّانَ يَوْمُ ۴لدِّينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 13, 'يَوْمَ هُمْ عَلَي ۰لنّۭارۣ يُفْتَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 14, 'ذُوقُواْ فِتْنَتَكُمْؐ هَـٰذَا ۰ﻟ﮲ كُنتُم بِهِ” تَسْتَعْجِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 15, 'إِنَّ ۰لْمُتَّقِينَ فِى جَنَّـٰتٍ وَعُيُونٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 16, '—اخِذِيــنَ مَآ ءَاتۭيٰهُمْ رَبُّهُمُؐ; إِنَّهُمْ كَانُواْ قَبْلَ ذَ؛لِــكَ مُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 17, 'كَانُواْ قَلِيلًؐا مِّنَ ۰ليْلِ مَا يَهْجَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 18, 'وَبِالاَسْحۭارۣ هُمْ يَسْتَغْفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 19, 'وَفِىٓ أَمْوَ؛لِهِمْ حَقٌّ لِّلسَّآئِلِ وَاڤْمَحْرُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 20, 'وَفِى ۱لاَرْضضضِ ءَايَـٰتٌ لِّلْمُوقِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 21, 'وَفِىٓ أَنفُسِكُمُؐ; أَفَلاَ تُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 22, 'وَفِى ۱لسَّمَآءِ رۣزْقُكُمْؐ وَمَا تُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 23, 'فَوَرَبِّ ۱لسَّمَآءِ وَالاَرْضِ إِنَّهُ„ لَحَقٌّ مِّثْــلَ مَآ أَنَّكُمْ تَنطِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 24, 'هَلَ اَتۭيٰــكَ حَدِيــثُ ضَيْفِ إِبْرَ؛هِيمَ ۰لْمُكْرَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 25, 'إِذْ دَخَلُواْ عَلَيْهِ فَقَالُواْ سَچَماًؐ قَالَ سَچَمٌؐ 59 قَوْمٌ مُّنكَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 26, 'فَرَاغَ إِلَــيٰٓ أَهْلِهِ” فَجَآءَ بِعِجْــلٍ سَمِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 27, 'فَقَرَّبَهُ; إِلَيْهِمْ قَالَ أَلاَ تَاكُلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 28, 'فَأَوْجَسَ مِنْهُمْ خِيفَةًؐ قَالُواْ لاَ تَخَفْؐ وَبَشَّرُوهُ بِغُچَمٖ عَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 29, 'فَأَقْبَلَتِ ''مْرَأَتُهُ„ فِى صَرَّةٍ فَصَكَّتْ وَجْهَهَا وَقَالَتْ عَجُوز٘ عَقِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 30, 'قَالُواْ كَذَ؛لِكِ قَالَ رَبُّكِؐ إِنَّهُ„ هُوَ ۰لْحَكِيمُ ۴لْعَلِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 31, '¤ قَالَ فَمَا خَطْبُكُمُ; أَيُّهَا ۰لْمُرْسَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 32, 'قَالُوٓاْ إِنَّآ ٱُرْسِلْنَآ إِلَيٰ قَوْمٍ مُّجْرۣمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 33, 'لِنُرْسِــلَ عَلَيْهِمْ حِجَارَةً مِّــن طِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 34, 'مُّسَوَّمَةٗ عِندَ رَبِّــكَ لِلْمُسْرۣفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 35, 'فَأَخْرَجْنَا مَــن كَانَ فِيهَا مِــنَ ۰لْمُومِنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 36, 'فَمَا وَجَدْنَا فِيهَا غَيْرَ بَيْتٍ مِّــنَ ۰لْمُسْلِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 37, 'وَتَرَكْنَا فِيهَآ ءَايَةً لِّلذِيــنَ يَخَافُونَ ۰لْعَذَابَ ۰لاَلِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 38, 'وَفِى مُوسۭيٰٓ إِذَ اَرْسَلْنَـٰهُ إِلَيٰ فِرْعَوْنَ بِسُلْطَـٰــنٍ مُّـبِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 39, 'فَتَوَلّۭيٰ بِرُكْنِهِ” وَقَالَ سَـٰحِر٘ اَوْ مَجْنُونٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 40, 'فَأَخَذْنَـٰهُ وَجُنُودَهُ„ فَنَبَذْنَـٰهُمْ فِى ۱لْيَمِّ وَهُوَ مُلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 41, 'وَفِى عَادٖ اِذَ اَرْسَلْنَا عَلَيْهِمُ ۴لرّۣيحَ ۰لْعَقِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 42, 'مَا تَذَرُ مِن شَيْءٖ اَتَتْ عَلَيْهِ إِلاَّ جَعَلَتْهُ كَالرَّمِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 43, 'وَفِى ثَمُودَ إِذْ قِيــلَ لَهُمْ تَمَتَّعُواْ حَتَّيٰ حِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 44, 'فَعَتَوْاْ 540 عَــنَ اَمْرۣ رَبِّهِمْ فَأَخَذَتْهُمُ ۴لصَّـٰعِقَةُ وَهُمْ يَنظُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 45, 'فَمَا "سْتَطَـٰعُواْ مِن قِيَامٍ وَمَا كَانُواْ مُنتَصِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 46, 'وَقَوْمَ نُوحٍ مِّن قَبْلُؐ إِنَّهُمْ كَانُواْ قَوْماً فَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 47, 'وَالسَّمَآءَ بَنَيْنَـٰهَا بِأَيَيْدٍؐ وَإِنَّا لَمُوسِعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 48, 'وَالاَرْضَ فَرَشْنَـٰهَاؐ فَنِعْمَ ۰لْمَـٰهِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 49, 'وَمِــن كُلِّ شَيْءٖ خَلَقْنَا زَوْجَيْــنۣ لَعَلَّكُمْ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 50, 'فَفِرُّوٓاْ إِلَي ۰للَّهِ إِنِّى لَكُم مِّنْهُ نَذِيرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 51, 'وَلاَ تَجْعَلُواْ مَعَ ۰للَّهِ إِچَهاٗ —اخَرَ إِنِّى لَكُم مِّنْهُ نَذِيرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 52, 'كَذَ؛لِكَؐ مَآ أَتَــي ۰لذِيــنَ مِن قَبْلِهِم مِّن رَّسُولٖ اِلاَّ قَالُواْ سَاحِر٘ اَوْ مَجْنُون٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 53, 'اَتَوَاصَوْاْ بِهِؐ” بَلْ هُمْ قَوْمٌ طَاغُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 54, 'فَتَوَلَّ عَنْهُمْ فَمَآ أَنتَ بِمَلُومٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 55, 'وَذَكِّرْؐ فَإِنَّ ۰لذِّكْرۭيٰ تَنفَعُ ۴لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 56, 'وَمَا خَلَقْــتُ ۴لْجِنَّ وَالِانسَ إِلاَّ لِيَعْبُدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 57, 'مَآ ٱُرۣيدُ مِنْهُم مِّن رّۣزْقٍ وَمَآ ٱُرۣيدُ أَنْ يُّطْعِمُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 58, 'إِنَّ ۰للَّهَ هُوَ ۰لرَّزَّاقُ ذُو ۴لْقُوَّةِ ۱لْمَتِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 59, 'فَإِنَّ لِلذِينَ ظَلَمُواْ ذَنُوباً مِّثْلَ ذَنُوبِ أَصْحَـٰبِهِمْ فَلاَ يَسْتَعْجِلُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (51, 60, 'فَوَيْلٌ لِّلذِيــنَ كَفَرُواْ مِنْ يَّوْمِهِمُ ۴ﻟ﮲ يُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالطُّورۣ وَكِتَـٰبٍ مَّسْطُورٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 2, 'فِى رَقٍّ مَّنشُورٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 3, 'وَالْبَيْتِ ۱لْمَعْمُورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 4, 'وَالسَّقْفِ ۱لْمَرْفُوعِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 5, 'وَاڤْبَحْرۣ ۱ڤْمَسْجُورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 6, 'إِنَّ عَذَابَ رَبِّــكَ لَوَ؛قِعٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 7, 'مَّا لَهُ„ مِــن دَافِعٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 8, 'يَوْمَ تَمُورُ ۴لسَّمَآءُ مَوْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 9, 'وَتَسِيرُ ۴لْجِبَالُ سَيْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 10, 'فَوَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 11, '۰لذِيــنَ هُمْ فِى خَوْضٍ يَلْعَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 12, 'يَوْمَ يُدَعُّونَ إِلَيٰ نۭارۣ جَهَنَّمَ دَعّاٗؐ هَـٰذِهِ ۱لنَّارُ ۴لتِى كُنتُم بِهَا تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 13, 'أَفَسِحْر٘ هَـٰذَآ أَمَ اَنتُمْ لاَ تُبْصِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 14, '"صْلَوْهَا فَاصْبِرُوٓاْ أَوْ لاَ تَصْبِرُواْ سَوَآء٘ عَلَيْكُمُؐ; إِنَّمَا تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 15, 'إِنَّ ۰لْمُتَّقِينَ فِى جَنَّـٰتٍ وَنَعِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 16, 'فَـٰكِهِيــنَ بِمَآ ءَاتۭيٰهُمْ رَبُّهُمْؐ وَوَقۭيٰهُمْ رَبُّهُمْ عَذَابببَ ۰لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 17, 'كُلُواْ وَاشْرَبُواْ هَنِيٓـٔاَۢ بِمَا كُنتُمْ تَعْمَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 18, 'مُتَّكِـِٕينَ عَلَيٰ سُرُرٍ مَّصْفُوفَةٍ وَزَوَّجْنَـٰهُم بِحُور۫ عِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 19, 'وَالذِيــنَ ءَامَنُواْ وَاتَّبَعَتْهُمْ ذُرّۣيَّتُهُم بِإِيمَـٰــن۫ اَلْحَقْنَا بِهِمْ ذُرّۣيَّـٰتِهِمْ وَمَآ 542 أَلَتْنَـٰهُم مِّــنْ عَمَلِهِم مِّــن شَيْءٍؐ كُــلُّ èمْــرۣئٙ بِمَا كَسَــبَ رَهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 20, 'وَأَمْدَدْنَـٰهُم بِفَـٰكِهَةٍ وَلَحْمٍ مِّمَّا يَشْتَهُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 21, 'يَتَنَـٰزَعُونَ فِيهَا كَأْساً لاَّ لَغْوٌ فِيهَا وَلاَ تَاثِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 22, '© وَيَطُوفُ عَلَيْهِمْ غِلْمَانٌ لَّهُمْ كَأَنَّهُمْ لُؤْلُؤٌ مَّكْنُونٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 23, 'وَأَقْبَلَ بَعْضُهُمْ عَلَيٰ بَعْضٍ يَتَسَآءَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 24, 'قَالُوٓاْ إِنَّا كُنَّا قَبْـلُ فِىٓ أَهْلِنَا مُشْفِقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 25, 'فَمَــنَّ ۰للَّهُ عَلَيْنَا وَوَقۭيٰنَا عَذَابَ ۰لسَّمُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 26, 'إِنَّا كُنَّا مِن قَبْــلُ نَدْعُوهُ أَنَّهُ„ هُوَ ۰لْبَرُّ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 27, 'فَذَكِّرْ فَمَآ أَنتَ بِنِعْمَتِ رَبِّــكَ بِكَاهِنٍ وَلاَ مَجْنُونٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 28, 'اَمْ يَقُولُونَ شَاعِرٌ نَّتَرَبَّـصُ بِهِ” رَيْبَ ۰لْمَنُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 29, 'قُلْ تَرَبَّصُواْؐ فَإِنِّى مَعَكُم مِّــنَ ۰لْمُتَرَبِّصِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 30, 'أَمْ تَامُرُهُمُ; أَحْچَمُهُم بِهَـٰذَآ أَمْ هُمْ قَوْمٌ طَاغُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 31, 'أَمْ يَقُولُونَ تَقَوَّلَهُؐ, بَـل لاَّ يُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 32, 'فَلْيَاتُواْ بِحَدِيثٍ مِّثْلِهِ“ إِن كَانُواْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 33, 'أَمْ خُلِقُواْ مِــنْ غَيْرۣ شَيْءٖ اَمْ هُمُ ۴لْخَـٰلِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 34, 'أَمْ خَلَقُواْ ۴لسَّمَـٰوَ؛تِ وَالاَرْضَؐ بَل لاَّ يُوقِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 35, 'أَمْ عِندَهُمْ خَزَآئِنُ رَبِّكَ أَمْ هُمُ ۴لْمُصَيْطِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 36, 'أَمْ لَهُمْ سُلَّمٌ يَسْتَمِعُونَ فِيهِؐ 54 فَلْيَاتِ مُسْتَمِعُهُم بِسُلْطَـٰنٍ مُّبِينٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 37, 'اَمْ لَهُ ۴لْبَنَـٰتُ وَلَكُمُ ۴لْبَنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 38, 'أَمْ تَسْـَٔلُهُمُ; أَجْراً فَهُم مِّــن مَّغْرَمٍ مُّثْقَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 39, 'أَمْ عِندَهُمُ ۴لْغَيْبُ فَهُمْ يَكْتُبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 40, 'أَمْ يُرۣيدُونَ كَيْداًؐ فَالذِيــنَ كَفَرُواْ هُمُ ۴لْمَكِيدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 41, 'أَمْ لَهُمُ; إِچَه٘ غَيْرُ ۴للَّهِؐ سُبْحَـٰــنَ ۰للَّهِ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 42, 'وَإِنْ يَّرَوْاْ كِسْفاً مِّــنَ ۰لسَّمَآءِ سَاقِطاً يَقُولُواْ سَحَابٌ مَّرْكُومٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 43, 'فَذَرْهُمْ حَتَّيٰ يُچَقُواْ يَوْمَهُمُ ۴ﻟ﮲ فِيهِ يَصْعَقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 44, 'يَوْمَ لاَ يُغْنِى عَنْهُمْ كَيْدُهُمْ شَيْـٔاً وَلاَ هُمْ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 45, 'وَإِنَّ لِلذِيــنَ ظَلَمُواْ عَذَاباً دُونَ ذَ؛لِكَؐ وَچَكِــنَّ أَكْثَرَهُمْ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 46, 'وَاصْبِرْ لِحُكْمِ رَبِّكَ فَإِنَّكَ بِأَعْيُنِنَاؐ وَسَبِّحْ بِحَمْدِ رَبِّكَ حِيــنَ تَقُومُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (52, 47, 'وَمِنَ ۰ليْــلۣ فَسَبِّحْهُ وَإِدْبَـٰرَ ۰ڤنُّجُومِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَاڤنَّجْمِ إِذَا هَوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 2, 'مَا ضَلَّ صَـٰحِبُكُمْ وَمَا غَوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 3, 'وَمَا يَنطِــقُ عَنِ ۱لْهَوۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 4, '544 إِنْ هُوَ إِلاَّ وَحْيٌ يُوحۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 5, 'عَلَّمَهُ„ شَدِيدُ ۴لْقُوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 6, 'ذُو مِرَّةٍؐ فَاسْتَوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 7, 'وَهُوَ بِالاُفُـقِ ۱لاَعْلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 8, 'ثُمَّ دَنَا فَتَدَلّۭـيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 9, 'فَكَانَ قَابَ قَوْسَيْنِ أَوَ اَدْنۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 10, 'فَأَوْحۭيٰٓ إِلَيٰ عَبْدِهِ” مَآ أَوْحۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 11, 'مَا كَذَبَ ۰لْفُؤَادُ مَا رۭأۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 12, 'أَفَتُمَـٰرُونَهُ„ عَلَــيٰ مَا يَرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 13, 'وَلَقَدْ رۭءۭاهُ نَزْلَةٗ ۷خْرۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 14, 'عِندَ سِدْرَةِ ۱لْمُنتَهۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 15, 'عِندَهَا جَنَّةُ ۴لْمَأْوۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 16, 'إِذْ يَغْشَــي ۰لسِّدْرَةَ مَا يَغْشۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 17, 'مَا زَاغَ ۰لْبَصَرُ وَمَا طَغۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 18, 'لَقَدْ رۭأۭيٰ مِــنَ —ايَـٰتِ رَبِّهِ ۱لْكُبْرۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 19, 'أَفَرَ×يْتُمُ ۴لچَّـتَ وَالْعُزّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 20, 'وَمَنَوٰةَ ۰لثَّالِثَةَ ۰لاُخْرۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 21, 'أَلَكُمُ ۴لذَّكَرُ وَلَهُ ۴لاُنثۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 22, 'تِلْــكَ إِذاً قِسْمَةٌ ضِيزۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 23, 'إِنْ هِـيَ إِلٓاَّ أَسْمَآءٌ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ۰للَّهُ بِهَا مِن سُلْطَـٰنٖؐ اِنْ يَّتَّبِعُونَ إِلاَّ ۰لظَّنَّ وَمَا تَهْوَي ۰لاَنفُسُؐ وَلَقَدْ جَآءَهُم مِّن رَّبِّهِمُ ۴لْهُدۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 24, 'أَمْ لِلِانسَـٰــنۣ مَا تَمَنّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 25, 'فَلِلهِ ۱لاَخِرَةُ وَالاُولۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 26, '¥ وَكَم مِّــن مَّلَــكٍ فِى ۱لسَّمَـٰوَ؛تِ لاَ تُغْنِى شَفَـٰعَتُهُمْ شَيْـٔاٗ اِلاَّ مِنۢ بَعْدِ أَنْ يَّاذَنننَ ۰للَّهُ لِمَنْ يَّشَآءُ 545 وَيَرْضۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 27, 'إِنَّ ۰لذِيــنَ لاَ يُومِنُونَ بِالاَخِرَةِ لَيُسَمُّونَ ۰لْمَلَئِكَةَ تَسْمِيَةَ ۰لاُنثۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 28, 'وَمَا لَهُم بِهِ” مِــنْ عِلْمٖؐ اِنْ يَّتَّبِعُونَ إِلاَّ ۰لظَّنَّؐ وَإِنَّ ۰لظَّــنَّ لاَ يُغْنِى مِــنَ ۰لْحَــقّۣ شَيْـٔاًؐ فَأَعْرۣضضضْ عَن مَّن تَوَلّۭــيٰ عَن ذِكْرۣنَا وَلَمْ يُرۣدِ اِلاَّ ۰لْحَيَوٰةَ ۰لدُّنْيۭاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 29, 'ذَ؛لِــكَ مَبْلَغُهُم مِّــنَ ۰لْعِلْمِؐ إِنَّ رَبَّــكَ هُوَ أَعْلَمُ بِمَــن ضَلَّ عَــن سَبِيلِهِؐ” وَهُوَ أَعْلَمُ بِمَـنِ ''هْتَدۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 30, 'وَلِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضضضِ ڤِيَجْزۣيَ ۰لذِيــنَ أَسَـٰٓــُٔواْ بِمَا عَمِلُواْ وَيَجْزۣيَ ۰لذِيــنَ أَحْسَنُواْ بِالْحُسْنَيؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 31, '۰لذِيــنَ يَجْتَنِبُونَ كَبَـٰٓئِرَ ۰لِاثْمِ وَالْفَوَ؛حِشَ إِلاَّ ۰للَّمَمَؐ إِنَّ رَبَّــكَ وَ؛سِعُ ۴لْمَغْفِرَةِؐ هُوَ أَعْلَمُ بِكُمُ; إِذَ اَنشَأَكُم مِّــنَ ۰لاَرْضِ وَإِذَ اَنتُمُ; أَجِنَّةٌ فِى بُطُونِ ٱُمَّهَـٰتِكُمْؐ فَلاَ تُزَكُّوٓاْ أَنفُسَكُمْؐ هُوَ أَعْلَمُ بِمَنِ ''تَّقۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 32, 'أَفَرَ×يْتَ ۰ﻟ﮲ تَوَلّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 33, 'وَأَعْطۭيٰ قَلِيلًا وَأَكْدۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 34, 'أَعِندَهُ„ عِلْمُ ۴لْغَيْبِ فَهُوَ يَرۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 35, 'أَمْ لَمْ يُنَبَّأْ بِمَا فِى صُحُفِ مُوسۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 36, 'وَإِبْرَ؛هِيمَ ۰ﻟ﮲ وَفّۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 37, 'أَلاَّ تَزۣرُ وَازۣرَةٌ وۣزْرَ ٱُخْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 38, 'وَأَن لَّيْسَ لِلِانسَـٰنِ إِلاَّ مَا سَعۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 39, 'وَأَنَّ سَعْيَهُ„ سَوْفَ 546 يُرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 40, 'ثُمَّ يُجْزۭيٰهُ ۴لْجَزَآءَ ۰لاَوْفۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 41, 'وَأَنَّ إِلَيٰ رَبِّكَ ۰لْمُنتَهۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 42, 'وَأَنَّهُ„ هُوَ أَضْحَــكَ وَأَبْكۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 43, 'وَأَنَّهُ„ هُوَ أَمَاتَ وَأَحْيۭاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 44, 'وَأَنَّهُ„ خَلَقَ ۰لزَّوْجَيْـنِ ۱لذَّكَرَ وَالاُنثۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 45, 'مِن نُّطْفَةٖ اِذَا تُمْنۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 46, 'وَأَنَّ عَلَيْهِ ۱لنَّشْأَةَ ۰لاُخْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 47, 'وَأَنَّهُ„ هُوَ أَغْنۭيٰ وَأَقْنۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 48, 'وَأَنَّهُ„ هُوَ رَبُّ ۴لشِّعْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 49, 'وَأَنَّهُ; أَهْلَكَ عَاداً ۰لاُّولۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 50, 'وَثَمُوداً فَمَآ أَبْقۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 51, 'وَقَوْمَ نُوحٍ مِّــن قَبْلُؐ إِنَّهُمْ كَانُواْ هُمُ; أَظْلَمَ وَأَطْغۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 52, 'وَالْمُوتَفِكَةَ أَهْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 53, 'فَغَشّۭيٰهَا مَا غَشّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 54, 'فَبِأَيِّ ءَالآَءِ رَبِّكَ تَتَمَارۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 55, 'هَـٰذَا نَذِيرٌ مِّــنَ ۰لنُّذُرۣ ۱لاُولۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 56, 'أَزۣفَتِ ۱لاَزۣفَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 57, 'لَيْــسَ لَهَا مِن دُونِ ۱للَّهِ كَاشِفَة٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 58, 'اَفَمِنْ هَـٰذَا ۰لْحَدِيثِ تَعْجَبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 59, 'وَتَضْحَكُونَ وَلاَ تَبْكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 60, 'وَأَنتُمْ سَـٰمِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (53, 61, 'فَاسْجُدُواْ لِلهِ وَاعْبُدُواْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ èقْتَرَبَتِ ۱لسَّاعَةُ وَانشَــقَّ ۰لْقَمَرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 2, '547 وَإِنْ يَّرَوَاْ —ايَةً يُعْرۣضُواْ وَيَقُولُواْ سِحْـرٌ مُّسْتَمِرٌّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 3, 'وَكَذَّبُواْ وَاتَّبَعُوٓاْ أَهْوَآءَهُمْؐ وَكُلُّ أَمْرٍ مُّسْتَقِرٌّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 4, 'وَلَقَدْ جَآءَهُم مِّــنَ ۰لاَنۢبَآءِ مَا فِيهِ مُزْدَجَر٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 5, 'حِكْمَةٛ بَـٰلِغَةٌؐ فَمَا تُغْنِ ۱لنُّذُرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 6, 'فَتَوَلَّ عَنْهُمْؐ يَوْمَ يَدْعُ ۴لدَّاعِ“ إِلَيٰ شَيْءٍ نُّكُر۫');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 7, 'خُشَّعاٗ اَبْصَـٰرُهُمْ يَخْرُجُونَ مِــنَ ۰لاَجْدَاثِ كَأَنَّهُمْ جَرَادٌ مُّنتَشِرٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 8, 'مُّهْطِعِينَ إِلَي ۰لدَّاعِؐ” يَقُولُ ۴لْكَـٰفِرُونَ هَـٰذَا يَوْم٘ عَسِرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 9, 'كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ فَكَذَّبُواْ عَبْدَنَا وَقَالُواْ مَجْنُونٌ وَازْدُجِرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 10, '© فَدَعَا رَبَّهُ; أَنِّى مَغْلُوبٌ فَانتَصِرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 11, 'فَفَتَحْنَآ أَبْوَ؛بَ ۰لسَّمَآءِ بِمَآءٍ مُّنْهَمِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 12, 'وَفَجَّرْنَا ۰لاَرْضضضَ عُيُوناً فَالْتَقَــي ۰لْمَآءُ عَلَــيٰٓ أَمْرٍ قَدْ قُدِرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 13, 'وَحَمَلْنَـٰهُ عَلَــيٰ ذَاتِ أَلْوَ؛حٍ وَدُسُرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 14, 'تَجْرۣى بِأَعْيُنِنَا جَزَآءً لِّمَــن كَانَ كُفِرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 15, 'وَلَقَد تَّرَكْنَـٰهَآ ءَايَةً فَهَلْ مِن مُّدَّكِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 16, 'فَكَيْفَ كَانَ عَذَابِى وَنُذُرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 17, 'وَلَقَدْ يَسَّرْنَا ۰لْقُرْءَانَ لِلذِّكْرۣ فَهَلْ مِن مُّدَّكِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 18, 'كَذَّبَـتْ عَادٌ فَكَيْفَ كَانَ عَذَابِى وَنُذُرۣؐ“');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 19, 'إِنَّـآ أَرْسَلْنَا عَلَيْهِمْ رۣيحاً صَرْصَراً 548 فِى يَوْمِ نَحْــسٍ مُّسْتَمِرٍّ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 20, 'تَنزۣعُ ۴لنَّاسسسَ كَأَنَّهُمُ; أَعْجَازُ نَخْلٍ مُّنقَعِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 21, 'فَكَيْفَ كَانَ عَذَابِى وَنُذُرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 22, 'وَلَقَدْ يَسَّرْنَا ۰لْقُرْءَانَ لِلذِّكْرۣ فَهَلْ مِن مُّدَّكِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 23, 'كَذَّبَتْ ثَمُودُ بِالنُّذُرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 24, 'فَقَالُوٓاْ أَبَشَراً مِّنَّا وَ؛حِداً نَّتَّبِعُهُ; إِنَّـآ إِذاً لَّفِى ضَچَلٍ وَسُعُر۫');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 25, 'اَ.لْقِيَ ۰لذِّكْرُ عَلَيْهِ مِنۢ بَيْنِنَا بَلْ هُوَ كَذَّاب٘ اَشِرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 26, 'سَيَعْلَمُونَ غَداً مَّنِ ۱لْكَذَّابُ ۴لاَشِرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 27, 'إِنَّا مُرْسِلُواْ ۴لنَّاقَةِ فِتْنَةً لَّهُمْ فَارْتَقِبْهُمْ وَاصْطَبِرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 28, 'وَنَبِّيؔهُمُ; أَنَّ ۰لْمَآءَ قِسْمَةٛ بَيْنَهُمْؐ كُلُّ شِرْبٍ مُّحْتَضَرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 29, 'فَنَادَوْاْ صَـٰحِبَهُمْ فَتَعَاطۭيٰ فَعَقَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 30, 'فَكَيْفَ كَانَ عَذَابِى وَنُذُرۣؐ“');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 31, 'إِنَّـآ أَرْسَلْنَا عَلَيْهِمْ صَيْحَةً وَ؛حِدَةً فَكَانُواْ كَهَشِيمِ ۱ڤْمُحْتَظِرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 32, 'وَلَقَدْ يَسَّرْنَا ۰لْقُرْءَانَ لِلذِّكْرۣ فَهَلْ مِن مُّدَّكِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 33, 'كَذَّبَتْ قَوْمُ لُوطٙ بِالنُّذُرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 34, 'إِنَّـآ أَرْسَلْنَا عَلَيْهِمْ حَاصِباٗ اِلٓاَّ ءَالَ لُوطٍ نَّجَّيْنَـٰهُم بِسَحَرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 35, 'نِّعْمَةً مِّنْ عِندِنَاؐ كَذَ؛لِــكَ نَجْزۣى مَــن شَكَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 36, 'وَلَقَدَ اَنذَرَهُم بَطْشَتَنَا فَتَمَارَوْاْ بِالنُّذُرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 37, 'وَلَقَدْ رَ؛وَدُوهُ 549 عَــن ضَيْفِهِ” فَطَمَسْنَآ أَعْيُنَهُمْ فَذُوقُواْ عَذَابِى وَنُذُرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 38, 'وَلَقَدْ صَبَّحَهُم بُكْرَةٗ عَذَابٌ مُّسْتَقِرٌّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 39, 'فَذُوقُواْ عَذَابِى وَنُذُرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 40, 'وَلَقَدْ يَسَّرْنَا ۰لْقُرْءَانَ لِلذِّكْـرۣ فَهَلْ مِن مُّدَّكِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 41, 'وَلَقَدْ جَآءَ .الَ فِرْعَوْنَ ۰لنُّذُرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 42, 'كَذَّبُواْ بِـَٔايَـٰتِنَا كُلِّهَا فَأَخَذْنَـٰهُمُ; أَخْذَ عَزۣيزٍ مُّقْتَدِرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 43, 'اَكُفَّارُكُمْ خَيْرٌ مِّنُ ۷وْلَئِكُمُ; أَمْ لَكُم بَرَآءَةٌ فِى ۱لزُّبُرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 44, 'أَمْ يَقُولُونَ نَحْـنُ جَمِيعٌ مُّنتَصِرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 45, 'سَيُهْزَمُ ۴لْجَمْعُ وَيُوَلُّونَ ۰لدُّبُرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 46, 'بَـلِ ۱لسَّاعَةُ مَوْعِدُهُمْؐ وَالسَّاعَةُ أَدْهۭيٰ وَأَمَرُّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 47, 'إِنَّ ۰ڤْمُجْرۣمِينَ فِى ضَچَلٍ وَسُعُرٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 48, 'يَوْمَ يُسْحَبُونَ فِى ۱لنّۭارۣ عَلَيٰ وُجُوهِهِمْ ذُوقُواْ مَــسَّ سَقَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 49, 'إِنَّا كُــلَّ شَيْءٖ خَلَقْنَـٰهُ بِقَدَرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 50, 'وَمَآ أَمْرُنَآ إِلاَّ وَ؛حِدَةٌ كَڤَمْحٙ بِالْبَصَرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 51, 'وَلَقَدَ اَهْلَكْنَآ أَشْيَاعَكُمْ فَهَلْ مِن مُّدَّكِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 52, 'وَكُلُّ شَيْءٍ فَعَلُوهُ فِى ۱لزُّبُرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 53, 'وَكُــلُّ صَغِيرٍ وَكَبِيرٍ مُّسْتَطَر٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 54, 'اِنَّ ۰لْمُتَّقِينَ فِى جَنَّـٰتٍ وَنَهَرٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (54, 55, 'فِى مَقْعَدِ صِدْقٖ عِندَ مَلِيــكٍ مُّقْتَدِر۫');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۱لرَّحْمَـٰــنُ عَلَّمَ ۰لْقُرْءَانَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 2, 'خَلَقَ ۰لِانسَـٰــنَ عَلَّمَهُ ۴لْبَيَانَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 3, '۰لشَّمْسُ وَالْقَمَرُ بِحُسْبَانٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 4, 'وَالنَّجْمُ وَاڤشَّجَرُ يَسْجُدَ؛نِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 5, 'وَالسَّمَآءَ رَفَعَهَا وَوَضَعَ ۰لْمِيزَانَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 6, 'أَلاَّ تَطْغَوْاْ فِى ۱لْمِيزَانِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 7, 'وَأَقِيمُواْ ۴لْوَزْنَ بِالْقِسْطِ وَلاَ تُخْسِرُواْ ۴لْمِيزَانَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 8, 'وَالاَرْضَ وَضَعَهَا لِلاَنَامِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 9, 'فِيهَا فَـٰكِهَةٌ وَاڤنَّخْــلُ ذَاتُ ۴لاَكْمَامِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 10, 'وَالْحَبُّ ذُو ۴لْعَصْفِ وَالرَّيْحَانُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 11, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 12, 'خَلَقَ ۰لِانسَـٰنَ مِن صَلْصَـٰــلٍ كَاڤْفَخّۭارۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 13, 'وَخَلَقَ ۰لْجَآنَّ مِن مَّارۣجٍ مِّن نّۭارٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 14, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 15, 'رَبُّ ۴لْمَشْرۣقَيْنِ وَرَبُّ ۴لْمَغْرۣبَيْنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 16, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 17, 'مَرَجَ ۰ڤْبَحْرَيْنِ يَلْتَقِيَـٰنِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 18, 'بَيْنَهُمَا بَرْزَخٌ لاَّ يَبْغِيَـٰنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 19, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 20, 'يُخْرَجُ مِنْهُمَا ۰للُّؤْلُؤُاْ وَالْمَرْجَانُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 21, 'فَبِأَيييّۣ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ 551');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 22, 'وَلَهُ ۴لْجَوَارۣ ۱لْمُنشَأَ؛تُ فِى ۱ڤْبَحْرۣ كَالاَعْچَمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 23, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 24, 'كُلُّ مَنْ عَلَيْهَا فَانٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 25, 'وَيَبْقۭيٰ وَجْهُ رَبِّــكَ ذُو ۴لْجَچَلِ وَالِاكْرَامِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 26, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 27, 'يَسْـَٔلُهُ„ مَـن فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ كُلَّ يَوْمٖ هُوَ فِى شَأْنٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 28, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 29, 'سَنَفْرُغُ لَكُمُ; أَيُّهَ ۰لثَّقَچَنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 30, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 31, 'يَـٰمَعْشَرَ ۰لْجِنِّ وَالِانـسِ إِنِ ''سْتَطَعْتُمُ; أَننن تَنفُذُواْ مِــنَ اَقْطۭارۣ ۱لسَّمَـٰوَ؛تِ وَالاَرْضضضِ فَانفُذُواْؐ لاَ تَنفُذُونَ إِلاَّ بِسُلْطَـٰنٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 32, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 33, 'يُرْسَــلُ عَلَيْكُمَا شُوَاظٌ مِّن نّۭارٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 34, 'وَنُحَاسٌ فَلاَ تَنتَصِرَ؛نِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 35, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 36, 'فَإِذَا "نشَقَّتِ ۱لسَّمَآءُ فَكَانَتْ وَرْدَةً كَالدِّهَانِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 37, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 38, 'فَيَوْمَئِذٍ لاَّ يُسْـَٔلُ عَن ذَنۢبِهِ“ إِنسٌ وَلاَ جَآنٌّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 39, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 40, 'يُعْرَفُ ۴ڤْمُجْرۣمُونَ بِسِيمۭـٰهُمْ فَيُوخَذُ بِالنَّوَ؛صِى وَالاَقْدَامِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 41, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا 552 تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 42, 'هَـٰذِهِ” جَهَنَّمُ ۴لتِى يُكَذِّبُ بِهَا ۰ڤْمُجْرۣمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 43, 'يَطُوفُونَ بَيْنَهَا وَبَيْــنَ حَمِيمٖ —انٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 44, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 45, 'وَلِمَــنْ خَافَ مَقَامَ رَبِّهِ” جَنَّتَـٰنِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 46, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 47, 'ذَوَاتَآ أَفْنَانٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 48, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 49, 'فِيهِمَا عَيْنَـٰنِ تَجْرۣيَـٰنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 50, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 51, 'فِيهِمَا مِــن كُلِّ فَـٰكِهَةٍ زَوْجَـٰنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 52, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَــانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 53, 'مُتَّكِـِٕــينَ عَلَيٰ فُرُشٙ بَطَآئِنُهَا مِـنِ اِسْتَبْرَقٍ وَجَنَا ۰لْجَنَّتَيْــنۣ دَانٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 54, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 55, 'فِيهِــنَّ قَـٰصِــرَ؛تُ ۴لطَّرْفِ لَمْ يَطْمِثْهُــنَّ إِنسٌ قَبْلَهُمْ وَلاَ جَآنٌّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 56, 'فَبِأَيييّۣ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 57, 'كَأَنَّهُنَّ ۰لْيَاقُوتُ وَالْمَرْجَانُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 58, 'فَبِأَيييّۣ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 59, 'هَلْ جَزَآءُ ۴لِاحْسَـٰنِ إِلاَّ ۰لِاحْسَـٰنُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 60, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 61, 'وَمِــن دُونِهِمَا جَنَّتَـٰنِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 62, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 63, 'مُدْهَآمَّتَـٰنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 64, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 65, 'فِيهِمَا عَيْنَـٰــنۣ نَضَّاخَتَـٰــنۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 66, '55 فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 67, 'فِيهِمَا فَـٰكِهَةٌ وَنَخْلٌ وَرُمَّانٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 68, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 69, 'فِيهِنَّ خَيْرَ؛ت٘ حِسَانٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 70, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 71, 'حُورٌ مَّقْصُورَ؛تٌ فِى ۱لْخِيَامِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 72, 'فَبِأَيييّۣ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 73, 'لَمْ يَطْمِثْهُـنَّ إِنسٌ قَبْلَهُمْ وَلاَ جَــآنٌّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 74, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 75, 'مُتَّكِـِٕـيــنَ عَلَيٰ رَفْرَفٖ خُضْرٍ وَعَبْقَرۣيّٖ حِسَانٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 76, 'فَبِأَيِّ ءَالآَءِ رَبِّكُمَا تُكَذِّبَانِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (55, 77, 'تَبَـٰرَكَ "سْمُ رَبِّكَ ذى ۱لْجَچَلِ وَالِاكْرَامِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 1, '© بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا وَقَعَتِ ۱لْوَاقِعَةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 2, 'لَيْسَ لِوَقْعَتِهَا كَـٰذِبَة٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 3, 'خَافِضَةٌ رَّافِعَة٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 4, 'اِذَا رُجَّتِ ۱لاَرْضُ رَجّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 5, 'وَبُسَّتِ ۱لْجِبَالُ بَسّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 6, 'فَكَانَتْ هَبَآءً مُّنۢبَثّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 7, 'وَكُنتُمُ; أَزْوَ؛جاً ثَـچَثَةًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 8, 'فَأَصْحَـٰبُ ۴لْمَيْمَنَةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 9, 'مَآ أَصْحَـٰبُ ۴لْمَيْمَنَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 10, 'وَأَصْحَـٰبُ ۴لْمَشْـَٔـمَةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 11, '554 مَآ أَصْحَـٰبُ ۴لْمَشْـَٔمَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 12, 'وَالسَّـٰبِقُونَ ۰لسَّـٰبِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 13, 'ٱُوْلَئِــكَ ۰لْمُقَرَّبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 14, 'فِى جَنَّـٰتِ ۱لنَّعِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 15, 'ثُلَّةٌ مِّــنَ ۰لاَوَّلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 16, 'وَقَلِيلٌ مِّنَ ۰لاَخِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 17, 'عَلَيٰ سُرُرٍ مَّوْضُونَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 18, 'مُّتَّكِـِٕينَ عَلَيْهَا مُتَقَـٰبِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 19, 'يَطُوفُ عَلَيْهِمْ وۣلْدَ؛نٌ مُّخَلَّدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 20, 'بِأَكْوَابٍ وَأَبَارۣيقَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 21, 'وَكَأْسسسٍ مِّن مَّعِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 22, 'لاَّ يُصَدَّعُونَ عَنْهَا وَلاَ يُنزَفُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 23, 'وَفَـٰكِهَةٍ مِّمَّا يَتَخَيَّرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 24, 'وَلَحْمِ طَيْرٍ مِّمَّا يَشْتَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 25, 'وَحُور٘ عِيــنٌ كَأَمْثَـٰلِ ۱للُّؤْلُوٕ ۱لْمَكْنُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 26, 'جَزَآءَۢ بِمَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 27, 'لاَ يَسْمَعُونَ فِيهَا لَغْواً وَلاَ تَاثِيماٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 28, 'اِلاَّ قِيلًا سَچَماً سَچَماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 29, 'وَأَصْحَـٰبُ ۴لْيَمِينِ مَآ أَصْحَـٰبُ ۴لْيَمِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 30, 'فِى سِدْرٍ مَّخْضُودٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 31, 'وَطَلْحٍ مَّنضُودٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 32, 'وَظِــلٍّ مَّمْدُودٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 33, 'وَمَآءٍ مَّسْكُوبٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 34, 'وَفَـٰكِهَةٍ كَثِيرَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 35, 'لاَّ مَقْطُوعَةٍ وَلاَ مَمْنُوعَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 36, 'وَفُرُشٍ مَّرْفُوعَةٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 37, 'اِنَّـآ أَنشَأْنَـٰهُــنَّ إِنشَآءً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 38, 'فَجَعَلْنَـٰهُنَّ أَبْكَاراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 39, 'عُرُباٗ اَتْرَاباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 40, 'لَأِّصْحَـٰبِ ۱لْيَمِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 41, 'ثُلَّةٌ مِّــنَ ۰لاَوَّلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 42, 'وَثُلَّةٌ مِّــنَ ۰لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 43, 'وَأَصْحَـٰبُ ۴لشِّمَالِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 44, '555 مَآ أَصْحَـٰبُ ۴لشِّمَالِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 45, 'فِى سَمُومٍ وَحَمِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 46, 'وَظِلٍّ مِّنْ يَّحْمُومٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 47, 'لاَّ بَارۣدٍ وَلاَ كَرۣيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 48, 'اِنَّهُمْ كَانُواْ قَبْلَ ذَ؛لِــكَ مُتْرَفِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 49, 'وَكَانُواْ يُصِرُّونَ عَلَي ۰لْحِنثِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 50, 'وَكَانُواْ يَقُولُونَ أَئذَا مِتْنَا وَكُنَّا تُرَاباً وَعِظَـٰماٗ اِنَّا لَمَبْعُوثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 51, 'أَوَءَابَآؤُنَا ۰لاَوَّلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 52, 'قُـلِ اِنَّ ۰لاَوَّلِينَ وَالاَخِرۣيــنَ ڤَمَجْمُوعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 53, 'إِلَيٰ مِيقَـٰتِ يَوْمٍ مَّعْلُومٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 54, 'ثُمَّ إِنَّكُمُ; أَيُّهَا ۰لضَّآلُّونَ ۰لْمُكَذِّبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 55, 'ءَلاَكِلُونَ مِــن شَجَرٍ مِّن زَقُّومٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 56, 'فَمَالِـُٔونَ مِنْهَا ۰لْبُطُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 57, 'فَشَـٰرۣبُونَ عَلَيْهِ مِــنَ ۰لْحَمِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 58, 'فَشَـٰرۣبُونَ شُرْبَ ۰لْهِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 59, 'هَـٰذَا نُزُلُهُمْ يَوْمَ ۰لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 60, 'نَحْــنُ خَلَقْنَـٰكُمْؐ فَلَوْلاَ تُصَدِّقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 61, 'أَفَرَ×يْتُم مَّا تُمْنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 62, 'ءَآنتُمْ تَخْلُقُونَهُ; أَمْ نَحْــنُ ۴لْخَـٰلِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 63, 'نَحْــنُ قَدَّرْنَا بَيْنَكُمُ ۴لْمَوْتَ وَمَا نَحْنُ بِمَسْبُوقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 64, 'عَلَيٰٓ أَن نُّبَدِّلَ أَمْثَـٰلَكُمْ وَنُنشِيؕكُمْ فِى مَا لاَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 65, 'وَلَقَدْ عَلِمْتُمُ ۴لنَّشْأَةَ ۰لاُولۭيٰؐ فَلَوْلاَ تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 66, 'أَفَرَ×يْتُم مَّا تَحْرُثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 67, 'ءَآنتُمْ تَزْرَعُونَهُ; أَمْ نَحْنُ ۴لزَّ؛رۣعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 68, 'لَوْ نَشَآءُ 556 لَجَعَلْنَـٰهُ حُطَـٰماً فَظَلْتُمْ تَفَكَّهُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 69, 'إِنَّا لَمُغْرَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 70, 'بَلْ نَحْنُ مَحْرُومُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 71, 'أَفَرَ×يْتُمُ ۴لْمَآءَ ۰ﻟ﮲ تَشْرَبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 72, 'ءَآنتُمُ; أَنزَلْتُمُوهُ مِــنَ ۰لْمُزْنِ أَمْ نَحْــنُ ۴لْمُنزۣلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 73, 'لَوْ نَشَآءُ جَعَلْنَـٰهُ ٱُجَاجاًؐ فَلَوْلاَ تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 74, 'أَفَرَ×يْتُمُ ۴لنَّارَ ۰لتِى تُورُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 75, 'ءَآنتُمُ; أَنشَأْتُمْ شَجَرَتَهَآ أَمْ نَحْــنُ ۴لْمُنشِـُٔونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 76, 'نَحْـنُ جَعَلْنَـٰهَا تَذْكِرَةً وَمَتَـٰعاً لِّلْمُقْوۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 77, 'فَسَبِّحْ بِاسْمِ رَبِّــكَ ۰لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 78, '¥ فَلآَ ٱُقْسِمُ بِمَوَ؛قِعِ ۱ڤنُّجُومِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 79, 'وَإِنَّهُ„ لَقَسَمٌ لَّوْ تَعْلَمُونَ عَظِيم٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 80, 'اِنَّهُ„ لَقُرْءَانٌ كَرۣيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 81, 'فِى كِتَـٰبٍ مَّكْنُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 82, 'لاَّ يَمَسُّهُ; إِلاَّ ۰لْمُطَهَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 83, 'تَنزۣيلٌ مِّن رَّبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 84, 'أَفَبِهَـٰذَا ۰لْحَدِيــثِ أَنتُم مُّدْهِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 85, 'وَتَجْعَلُونَ رۣزْقَكُمُ; أَنَّكُمْ تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 86, 'فَلَوْلآَ إِذَا بَلَغَتِ ۱لْحُلْقُومَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 87, 'وَأَنتُمْ حِينَئِذٍ تَنظُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 88, 'وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنكُمْ وَچَكِــن لاَّ تُبْصِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 89, 'فَلَوْلآَ إِننن كُنتُمْ غَيْرَ مَدِينِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 90, 'تَرْجِعُونَهَآ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 91, 'فَأَمَّآ إِن كَانَ مِــنَ ۰لْمُقَرَّبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 92, 'فَرَوْحٌ وَرَيْحَانٌ وَجَنَّــتُ نَعِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 93, '557 وَأَمَّآ إِن كَانَ مِــنَ اَصْحَـٰبِ ۱لْيَمِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 94, 'فَسَچَمٌ لَّكَ مِنَ اَصْحَـٰبِ ۱لْيَمِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 95, 'وَأَمَّآ إِن كَانَ مِــنَ ۰لْمُكَذِّبِينَ ۰لضَّآلِّينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 96, 'فَنُزُلٌ مِّــنْ حَمِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 97, 'وَتَصْلِيَةُ جَحِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 98, 'اِنننَّ هَـٰذَا لَهُوَ حَقُّ ۴لْيَقِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (56, 99, 'فَسَبِّحْ بِاسْمِ رَبِّــكَ ۰لْعَظِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سَبَّحَ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 2, 'لَهُ„ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ يُحْىِ” وَيُمِيتُؐ وَهُوَ عَلَــيٰ كُلِّ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 3, 'هُوَ ۰لاَوَّلُ وَالاَخِرُ وَالظَّـٰهِرُ وَالْبَاطِنُؐ وَهُوَ بِكُــلّۣ شَيْءٖ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 4, 'هُوَ ۰ﻟ﮲ خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ فِى سِتَّةِ أَيَّامٍ ثُمَّ "سْتَوۭيٰ عَلَــي ۰لْعَرْشِؐ يَعْلَمُ مَا يَلِجُ فِى ۱لاَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزۣلُ مِــنَ ۰لسَّمَآءِ وَمَا يَعْرُجُ فِيهَاؐ وَهُوَ مَعَكُمُ; أَيْــنَ مَا كُنتُمْؐ وَاللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 5, 'لَّهُ„ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَإِلَــي ۰للَّهِ تُرْجَعُ ۴لاُمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 6, 'يُولِجُ ۴ليْلَ فِى ۱لنَّهۭارۣ وَيُولِجُ 558 ۴لنَّهَارَ فِى ۱ليْلِؐ وَهُوَ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 7, 'ءَامِنُواْ بِاللَّهِ وَرَسُولِهِ” وَأَنفِقُواْ مِمَّا جَعَلَكُم مُّسْتَخْلَفِينَ فِيهِؐ فَالذِيــنَ ءَامَنُواْ مِنكُمْ وَأَنفَقُواْ لَهُمُ; أَجْرٌ كَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 8, 'وَمَا لَكُمْ لاَ تُومِنُونَ بِاللَّهِ وَالرَّسُولُ يَدْعُوكُمْ لِتُومِنُواْ بِرَبِّكُمْ وَقَدَ اَخَذَ مِيثَـٰقَكُمُ; إِن كُنتُم مُّومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 9, 'هُوَ ۰ﻟ﮲ يُنَزّۣلُ عَلَيٰ عَبْدِهِ“ ءَايَـٰتٙ بَيِّنَـٰتٍ ڤِّيُخْرۣجَكُم مِّــنَ ۰لظُّلُمَـٰــتِ إِلَــي ۰لنُّورۣؐ وَإِنَّ ۰للَّهَ بِكُمْ لَرَءُوفٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 10, 'وَمَا لَكُمُ; أَلاَّ تُنفِقُواْ فِى سَبِيـلِ ۱للَّهِ وَلِلهِ مِيرَ؛ثُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضضضِؐ لاَ يَسْتَوۣى مِنكُم مَّــنَ اَنفَـقَ مِن قَبْـلِ ۱ڤْفَتْحِ وَقَـٰتَلَؐ ٱُوْلَئِــكَ أَعْظَمُ دَرَجَةً مِّــنَ ۰لذِينَ أَنفَقُواْ مِـنۢ بَعْدُ وَقَـٰتَلُواْؐ وَكُلًاّ وَعَدَ ۰للَّهُ ۴لْحُسْنۭيٰؐ وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 11, 'مَّــن ذَا ۰ﻟ﮲ يُقْرۣضضضُ ۴للَّهَ قَرْضاٗ حَسَناً فَيُضَـٰعِفُهُ„ لَهُ„ وَلَهُ; أَجْرٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 12, 'يَوْمَ تَرَي ۰لْمُومِنِينَ وَالْمُومِنَـٰتِ يَسْعۭيٰ نُورُهُم بَيْنَ أَيْدِيهِمْ وَبِأَيْمَـٰنِهِمؐ بُشْرۭيٰكُمُ ۴لْيَوْمَ جَنَّـٰتٌ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَاؐ ذَ؛لِكَ هُوَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 13, 'يَوْمَ يَقُولُ ۴لْمُنَـٰفِقُونَ وَالْمُنَـٰفِقَـٰتُ 559 لِلذِيــنَ ءَامَنُواْ ۶نظُرُونَا نَقْتَبِسْ مِن نُّورۣكُمْ قِيلَ "رْجِعُواْ وَرَآءَكُمْ فَالْتَمِسُواْ نُوراًؐ فَضُرۣبَ بَيْنَهُم بِسُورٍ لَّهُ„ بَابٛ بَاطِنُهُ„ فِيهِ ۱لرَّحْمَةُ وَظَـٰهِرُهُ„ مِن قِبَلِهِ ۱لْعَذَابُؐ يُنَادُونَهُمُ; أَلَمْ نَكُــن مَّعَكُمْؐ قَالُواْ بَلۭيٰ وَچَكِنَّكُمْ فَتَنتُمُ; أَنفُسَكُمْ وَتَرَبَّصْتُمْ وَارْتَبْتُمْ وَغَرَّتْكُمُ ۴لاَمَانِــيُّ حَتَّيٰ جَآءَ امْرُ ۴للَّهِ وَغَرَّكُم بِاللَّهِ ۱لْغَرُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 14, 'فَالْيَوْمَ لاَ يُوخَذُ مِنكُمْ فِدْيَةٌ وَلاَ مِــنَ ۰لذِيــنَ كَفَرُواْ مَأْوۭيٰكُمُ ۴لنَّارُ هِيَ مَوْلۭيٰكُمْؐ وَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 15, '© أَلَمْ يَانِ لِلذِيــنَ ءَامَنُوٓاْ أَننن تَخْشَعَ قُلُوبُهُمْ لِذِكْرۣ ۱للَّهِ وَمَا نَزَلَ مِــنَ ۰لْحَقﱢّؐ وَلاَ يَكُونُواْ كَالذِينَ ٱُوتُواْ ۴لْكِتَـٰبَ مِن قَبْلُ فَطَالَ عَلَيْهِمُ ۴لاَمَدُ فَقَسَتْ قُلُوبُهُمْؐ وَكَثِيرٌ مِّنْهُمْ فَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 16, '"عْلَمُوٓاْ أَنَّ ۰للَّهَ يُحْـىِ ۱لاَرْضَ بَعْدَ مَوْتِهَاؐ قَدْ بَيَّنَّا لَكُمُ ۴لاَيَـٰتِ لَعَلَّكُمْ تَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 17, 'إِنَّ ۰لْمُصَّدِّقِينَ وَالْمُصَّدِّقَـٰتِ وَأَقْرَضُواْ ۴للَّهَ قَرْضاٗ حَسَناً يُضَـٰعَفُ لَهُمْ وَلَهُمُ; أَجْرٌ كَرۣيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 18, 'وَالذِيــنَ ءَامَنُواْ بِاللَّهِ وَرُسُلِهِ“ ٱُوْلَئِــكَ هُمُ ۴لصِّدِّيقُونَؐ وَالشُّهَدَآءُ عِندَ رَبِّهِمْؐ 560 لَهُمُ; أَجْرُهُمْ وَنُورُهُمْؐ وَالذِيــنَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَـٰتِنَآ ٱُوْلَئِــكَ أَصْحَـٰبُ ۴لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 19, '''عْلَمُوٓاْ أَنَّمَا ۰لْحَيَوٰةُ ۴لدُّنْيۭا لَعِبٌ وَلَهْوٌ وَزۣينَةٌ وَتَفَاخُرٛ بَيْنَكُمْ وَتَكَاثُرٌ فِى ۱لاَمْوَ؛لِ وَالاَوْچَدِ كَمَثَلِ غَيْثٖ اَعْجَبَ ۰لْكُفَّارَ نَبَاتُهُ„ ثُمَّ يَهِيجُ فَتَرۭيٰهُ مُصْفَرّاً ثُمَّ يَكُونُ حُطَـٰماًؐ وَفِى ۱لاَخِرَةِ عَذَابٌ شَدِيدٌ وَمَغْفِرَةٌ مِّــنَ ۰للَّهِ وَرۣضْوَ؛نٌؐ وَمَا ۰لْحَيَوٰةُ ۴لدُّنْيۭآ إِلاَّ مَتَـٰعُ ۴لْغُرُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 20, 'سَابِقُوٓاْ إِلَــيٰ مَغْفِرَةٍ مِّن رَّبِّكُمْ وَجَنَّةٖ عَرْضُهَا كَعَرْضضضِ ۱لسَّمَآءِ وَالاَرْضِ ٱُعِدَّتْ لِلذِينَ ءَامَنُواْ بِاللَّهِ وَرُسُلِهِؐ” ذَ؛لِــكَ فَضْــلُ ۴للَّهِ يُوتِيهِ مَـنْ يَّشَآءُؐ وَاللَّهُ ذُو ۴لْفَضْـلِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 21, 'مَآ أَصَابَ مِــن مُّصِيبَةٍ فِى ۱لاَرْضِ وَلاَ فِىٓ أَنفُسِكُمُ; إِلاَّ فِى كِتَـٰبٍ مِّن قَبْلِ أَن نَّبْرَأَهَآؐ إِنَّ ذَ؛لِــكَ عَلَــي ۰للَّهِ يَسِيرٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 22, 'لِّكَيْلاَ تَاسَوْاْ عَلَيٰ مَا فَاتَكُمْ وَلاَ تَفْرَحُواْ بِمَآ ءَاتۭيٰكُمْؐ وَاللَّهُ لاَ يُحِبُّ كُلَّ مُخْتَالٍ فَخُورٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 23, '۱لذِيــنَ يَبْخَلُونَ وَيَامُرُونَ ۰لنَّاسَ بِالْبُخْلِؐ وَمَنْ يَّتَوَلَّ فَإِنننَّ ۰للَّهَ ۰لْغَنِــيُّ ۴لْحَمِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 24, 'لَقَدَ اَرْسَلْنَا رُسُلَنَا 561 بِالْبَيِّنَـٰتِ وَأَنزَلْنَا مَعَهُمُ ۴لْكِتَـٰبَ وَالْمِيزَانَ لِيَقُومَ ۰لنَّاسُ بِالْقِسْطِؐ وَأَنزَلْنَا ۰لْحَدِيدَ فِيهِ بَأْسسسٌ شَدِيدٌ وَمَنَـٰفِعُ لِلنَّاسِؐ وَلِيَعْلَمَ ۰للَّهُ مَنْ يَّنصُرُهُ„ وَرُسُلَهُ„ بِالْغَيْبِؐ إِنننَّ ۰للَّهَ قَوۣيّﹲ عَزۣيزٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 25, 'وَلَقَدَ اَرْسَلْنَا نُوحاً وَإِبْرَ؛هِيمَ وَجَعَلْنَا فِى ذُرّۣيَّتِهِمَا ۰لنُّبُوٓءَةَ وَالْكِتَـٰبَؐ فَمِنْهُم مُّهْتَدٍؐ وَكَثِيرٌ مِّنْهُمْ فَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 26, 'ثُمَّ قَفَّيْنَا عَلَــيٰٓ ءَاثۭـٰرۣهِم بِرُسُلِنَا وَقَفَّيْنَا بِعِيسَي "بْنِ مَرْيَمَ وَءَاتَيْنَـٰهُ ۴لِانجِيلَؐ وَجَعَلْنَا فِى قُلُوبِ ۱لذِينَ "تَّبَعُوهُ رَأْفَةً وَرَحْمَةً وَرَهْبَانِيَّةٗ ''بْتَدَعُوهَا مَا كَتَبْنَـٰهَا عَلَيْهِمُ; إِلاَّ "بْتِغَآءَ رۣضْوَ؛نِ ۱للَّهِؐ فَمَا رَعَوْهَا حَقَّ رۣعَايَتِهَاؐ فَـَٔاتَيْنَا ۰لذِيــنَ ءَامَنُواْ مِنْهُمُ; أَجْرَهُمْؐ وَكَثِيرٌ مِّنْهُمْ فَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 27, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ وَءَامِنُواْ بِرَسُولِهِ” يُوتِكُمْ كِفْلَيْنِ مِن رَّحْمَتِهِ” وَيَجْعَــل لَّكُمْ نُوراً تَمْشُونَ بِهِ” وَيَغْفِرْ لَكُمْؐ وَاللَّهُ غَفُورٌ رَّحِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (57, 28, 'لِّيَ۬لاَّ يَعْلَمَ أَهْلُ ۴لْكِتَـٰبِ أَلاَّ يَقْدِرُونَ عَلَيٰ شَيْءٍ مِّـن فَضْـلِ ۱للَّهِ وَأَنَّ ۰لْفَضْلَ بِيَدِ ۱للَّهِ يُوتِيهِ مَنْ يَّشَآءُؐ وَاللَّهُ ذُو ۴لْفَضْـلِ ۱لْعَظِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قَدْ سَمِعَ ۰للَّهُ قَوْلَ ۰لتِى تُجَـٰدِلُــكَ فِى زَوْجِهَا وَتَشْتَكِىٓ إِلَــي ۰للَّهِ وَاللَّهُ يَسْمَعُ تَحَاوُرَكُمَآؐ إِنننَّ ۰للَّهَ سَمِيعٛ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 2, '۱لذِينَ يَظَّهَّرُونَ مِنكُم مِّــن نِّسَآئِهِم مَّا هُــنَّ ٱُمَّهَـٰتِهِمُؐ; إِنُ ۷مَّهَـٰتُهُمُ; إِلاَّ ۰ﹾ وَلَدْنَهُمْؐ وَإِنَّهُمْ لَيَقُولُونَ مُنكَراً مِّــنَ ۰لْقَوْلِ وَزُوراًؐ وَإِنَّ ۰للَّهَ لَعَفُوّﹲ غَفُورٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 3, 'وَالذِينَ يَظَّهَّرُونَ مِن نِّسَآئِهِمْ ثُمَّ يَعُودُونَ لِمَا قَالُواْ فَتَحْرۣيرُ رَقَبَةٍ مِّــن قَبْلِ أَنْ يَّتَمَآسَّاؐ ذَ؛لِكُمْ تُوعَظُونَ بِهِؐ” وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 4, 'فَمَن لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْــنۣ مُتَتَابِعَيْنِ مِــن قَبْلِ أَنْ يَّتَمَآسَّاؐ فَمَن لَّمْ يَسْتَطِعْ فَإِطْعَامُ سِتِّينَ مِسْكِيناًؐ ذَ؛لِــكَ لِتُومِنُواْ بِاللَّهِ وَرَسُولِهِؐ” وَتِلْــكَ حُدُودُ ۴للَّهِؐ وَلِلْكۭـٰفِـرۣينَ عَذَاب٘ اَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 5, 'اِنَّ ۰لذِيــنَ يُحَآدُّونَ ۰للَّهَ وَرَسُولَهُ„ كُبِتُواْ كَمَا كُبِتَ ۰لذِيــنَ مِن قَبْلِهِمْؐ وَقَدَ اَنزَلْنَآ ءَايَـٰتٙ بَيِّنَـٰتٍؐ وَلِلْكۭـٰفِـرۣيــنَ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 6, 'يَوْمَ يَبْعَثُهُمُ ۴للَّهُ جَمِيعاً 56 فَيُنَبِّيؖهُم بِمَا عَمِلُوٓاْؐ أَحْصۭيٰهُ ۴للَّهُ وَنَسُوهُؐ وَاللَّهُ عَلَــيٰ كُلِّ شَيْءٍ شَهِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 7, 'اَلَمْ تَرَ أَنَّ ۰للَّهَ يَعْلَمُ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضضضِؐ مَا يَكُونُ مِن نَّجْوۭيٰ ثَـچَثَةٖ اِلاَّ هُوَ رَابِعُهُمْ وَلاَ خَمْسَةٖ اِلاَّ هُوَ سَادِسُهُمْ وَلآَ أَدْنۭيٰ مِن ذَ؛لِــكَ وَلآَ أَكْثَرَ إِلاَّ هُوَ مَعَهُمُ; أَيْــنَ مَا كَانُواْؐ ثُمَّ يُنَبِّيؖهُم بِمَا عَمِلُواْ يَوْمَ ۰لْقِيَـٰمَةِؐ إِنَّ ۰للَّهَ بِكُــلّۣ شَيْءٖ عَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 8, 'اَلَمْ تَرَ إِلَــي ۰لذِينَ نُهُواْ عَـنِ ۱ڤنَّجْوۭيٰ ثُمَّ يَعُودُونَ لِمَا نُهُواْ عَنْهُ وَيَتَنَـٰجَوْنَ بِالِاثْمِ وَالْعُدْوَ؛نِ وَمَعْصِيَتِ ۱لرَّسُولِؐ وَإِذَا جَآءُوكككَ حَيَّوْكككَ بِمَا لَمْ يُحَيِّــكَ بِهِ ۱للَّهُ وَيَقُولُونَ فِىٓ أَنفُسِهِمْ لَوْلاَ يُعَذِّبُنَا ۰للَّهُ بِمَا نَقُولُؐ حَسْبُهُمْ جَهَنَّمُؐ يَصْلَوْنَهَاؐ فَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 9, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا تَنَـٰجَيْتُمْ فَلاَ تَتَنَـٰجَوْاْ بِالِاثْمِ وَالْعُدْوَ؛نِ وَمَعْصِيَتِ ۱لرَّسُولِؐ وَتَنَـٰجَوْاْ بِالْبِرّۣ وَالتَّقْوۭيٰؐ وَاتَّقُواْ ۴للَّهَ ۰ﻟـذِىٓ إِلَيْهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 10, 'إِنَّمَا ۰لنَّجْوۭيٰ مِــنَ ۰لشَّيْطَـٰنِ ڤِيُحْزۣنَ ۰لذِيــنَ ءَامَنُواْ وَلَيْسَ بِضَآرّۣهِمْ شَيْـٔاٗ اِلاَّ بِإِذْنِ ۱للَّهِؐ وَعَلَــي ۰للَّهِ فَلْيَتَوَكَّـلِ ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 11, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ 564 إِذَا قِيــلَ لَكُمْ تَفَسَّحُواْ فِى ۱ڤْمَجْلِـسِ فَافْسَحُواْ يَفْسَحِ ۱للَّهُ لَكُمْؐ وَإِذَا قِيــلَ ۸نشُزُواْ فَانشُزُواْ يَرْفَــعِ ۱للَّهُ ۴لذِيــنَ ءَامَنُواْ مِنكُمْ وَالذِينَ ٱُوتُواْ ۴لْعِلْمَ دَرَجَـٰتٍؐ وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 12, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا نَـٰجَيْتُمُ ۴لرَّسُولَ فَقَدِّمُواْ بَيْنَ ¢ نَجْوۭيٰكُمْ صَدَقَةًؐ ذَ؛لِــكَ خَيْرٌ لَّكُمْ وَأَطْهَرُؐ فَإِن لَّمْ تَجِدُواْ فَإِنَّ ۰للَّهَ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 13, '—آشْفَقْتُمُ; أَن تُقَدِّمُواْ بَيْنَ ¢ نَجْوۭيٰكُمْ صَدَقَـٰتٍؐ فَإِذْ لَمْ تَفْعَلُواْ وَتَابَ ۰للَّهُ عَلَيْكُمْ فَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَأَطِيعُواْ ۴للَّهَ وَرَسُولَهُؐ, وَاللَّهُ خَبِيرٛ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 14, '© أَلَمْ تَرَ إِلَي ۰لذِينَ تَوَلَّوْاْ قَوْماٗ غَضِبَ ۰للَّهُ عَلَيْهِم مَّا هُم مِّنكُمْ وَلاَ مِنْهُمْ وَيَحْلِفُونَ عَلَــي ۰لْكَذِبِ وَهُمْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 15, 'أَعَدَّ ۰للَّهُ لَهُمْ عَذَاباً شَدِيداٗؐ اِنَّهُمْ سَآءَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 16, '"تَّخَذُوٓاْ أَيْمَـٰنَهُمْ جُنَّةً فَصَدُّواْ عَــن سَبِيـلِ ۱للَّهِ فَلَهُمْ عَذَابٌ مُّهِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 17, 'لَّــن تُغْنِــيَ عَنْهُمُ; أَمْوَ؛لُهُمْ وَلآَ أَوْچَدُهُم مِّــنَ ۰للَّهِ شَيْـٔاٗؐ ۷وْلَئِكَ أَصْحَـٰبُ ۴لنّۭارۣ هُمْ فِيهَا خَـٰلِدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 18, 'يَوْمَ 565 يَبْعَثُهُمُ ۴للَّهُ جَمِيعاً فَيَحْلِفُونَ لَهُ„ كَمَا يَحْلِفُونَ لَكُمْ وَيَحْسِبُونَ أَنَّهُمْ عَلَيٰ شَيْءٖؐ اَلآَ إِنَّهُمْ هُمُ ۴لْكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 19, '"سْتَحْوَذَ عَلَيْهِمُ ۴لشَّيْطَـٰنُ فَأَنسۭيٰهُمْ ذِكْرَ ۰للَّهِؐ ٱُوْلَئِكَ حِزْبُ ۴لشَّيْطَـٰــنۣؐ أَلآَ إِنَّ حِزْبَ ۰لشَّيْطَـٰنِ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 20, 'إِنَّ ۰لذِيــنَ يُحَآدُّونَ ۰للَّهَ وَرَسُولَهُ; ٱُوْلَئِكَ فِى ۱لاَذَلِّيــنَؐ كَتَبَ ۰للَّهُ لَأَغْلِبَــنَّ أَنَا وَرُسُلِيَؐ إِنَّ ۰للَّهَ قَوۣيّﹲ عَزۣيزٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (58, 21, 'لاَّ تَجِدُ قَوْماً يُومِنُونَ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣ يُوَآدُّونَ مَــنْ حَآدَّ ۰للَّهَ وَرَسُولَهُ„ وَلَوْ كَانُوٓاْ ءَابَآءَهُمُ; أَوَ اَبْنَآءَهُمُ; أَوۣ اِخْوَ؛نَهُمُ; أَوْ عَشِيرَتَهُمُؐ; ٱُوْلَئِكَ كَتَبَ فِى قُلُوبِهِمُ ۴لِايمَـٰنَ وَأَيَّدَهُم بِرُوحٍ مِّنْهُ وَيُدْخِلُهُمْ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَاؐ رَضِــيَ ۰للَّهُ عَنْهُمْ وَرَضُواْ عَنْهُؐ ٱُوْلَئِكَ حِزْبُ ۴للَّهِؐ أَلآَ إِنَّ حِزْبَ ۰للَّهِ هُمُ ۴ڤْمُفْڤِحُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 1, '566 بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سَبَّحَ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 2, 'هُوَ ۰ﻟـذِىٓ أَخْرَجَ ۰لذِينَ كَفَرُواْ مِــنَ اَهْلِ ۱لْكِتَـٰبِ مِــن دِيۭـٰرۣهِمْ لَأِوَّلِ ۱لْحَشْرۣؐ مَا ظَنَنتُمُ; أَنْ يَّخْرُجُواْؐ وَظَنُّوٓاْ أَنَّهُم مَّانِعَتُهُمْ حُصُونُهُم مِّــنَ ۰للَّهِؐ فَأَتۭيٰهُمُ ۴للَّهُ مِــنْ حَيْثُ لَمْ يَحْتَسِبُواْؐ  وَقَذَفَ فِى قُلُوبِهِمُ ۴لرُّعْبَؐ يُخْرۣبُونَ بُيُوتَهُم بِأَيْدِيهِمْ وَأَيْدِى ۱لْمُومِنِينَؐ فَاعْتَبِرُواْ يَـٰٓٱُوْلِى ۱لاَبْصۭـٰرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 3, 'وَلَوْلآَ أَننن كَتَبَ ۰للَّهُ عَلَيْهِمُ ۴لْجَلآَءَ لَعَذَّبَهُمْ فِى ۱لدُّنْيۭاؐ وَلَهُمْ فِى ۱لاَخِرَةِ عَذَابُ ۴لنّۭارۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 4, 'ذَ؛لِــكَ بِأَنَّهُمْ شَآقُّواْ ۴للَّهَ وَرَسُولَهُؐ, وَمَنْ يُّشَآقِّ ۱للَّهَ فَإِنَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 5, 'مَا قَطَعْتُم مِّن لِّينَةٖ اَوْ تَرَكْتُمُوهَا قَآئِمَةٗ عَلَــيٰٓ ٱُصُولِهَا فَبِإِذْنِ ۱للَّهِ وَڤِيُخْزۣيَ ۰لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 6, 'وَمَآ أَفَآءَ ۰للَّهُ عَلَيٰ رَسُولِهِ” مِنْهُمْ فَمَآ أَوْجَفْتُمْ عَلَيْهِ مِــنْ خَيْلٍ وَلاَ رۣكَابٍؐ وَچَكِــنَّ ۰للَّهَ يُسَلِّطُ رُسُلَهُ„ عَلَيٰ مَنْ يَّشَآءُؐ وَاللَّهُ عَلَــيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 7, 'مَّآ أَفَآءَ ۰للَّهُ عَلَيٰ رَسُولِهِ” مِــنَ اَهْـلِ ۱لْقُرۭيٰ فَلِلهِ وَلِلرَّسُولِ وَلِذِى ۱لْقُرْبۭيٰ وَالْيَتَـٰمۭيٰ 567 وَالْمَسَـٰكِينِ وَابْـنِ ۱لسَّبِيلِ كَىْ لاَ يَكُونَ دُولَةَۢ بَيْــنَ ۰لاَغْنِيَآءِ مِنكُمْؐ وَمَآ ءَاتۭيٰكُمُ ۴لرَّسُولُ فَخُذُوهُؐ وَمَا نَهۭيٰكُمْ عَنْهُ فَانتَهُواْؐ وَاتَّقُواْ ۴للَّهَؐ إِنَّ ۰للَّهَ شَدِيدُ ۴لْعِقَابِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 8, 'لِلْفُقَرَآءِ ۱ڤْمُهَـٰجِرۣيــنَ ۰لذِينَ ٱُخْرۣجُواْ مِــن دِيۭـٰرۣهِمْ وَأَمْوَ؛لِهِمْ يَبْتَغُونَ فَضْلًا مِّــنَ ۰للَّهِ وَرۣضْوَ؛ناً وَيَنصُرُونَ ۰للَّهَ وَرَسُولَهُؐ; ٱُوْلَئِــكَ هُمُ ۴لصَّـٰدِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 9, 'وَالذِينَ تَبَوَّءُو ۴لدَّارَ وَالِايمَـٰنَ مِن قَبْلِهِمْ يُحِبُّونَ مَــنْ هَاجَرَ إِلَيْهِمْ وَلاَ يَجِدُونَ فِى صُدُورۣهِمْ حَاجَةً مِّمَّآ ٱُوتُواْ وَيُوثِرُونَ عَلَــيٰٓ أَنفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌؐ وَمَنْ يُّوقَ شُحَّ نَفْسِهِ” فَٱُوْلَئِــكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 10, 'وَالذِيــنَ جَآءُو مِـنۢ بَعْدِهِمْ يَقُولُونَ رَبَّنَا "غْفِرْ لَنَا وَلِإِخْوَ؛نِنَا ۰لذِيــنَ سَبَقُونَا بِالِايمَـٰنِ وَلاَ تَجْعَلْ فِى قُلُوبِنَا غِلًاّ لِّلذِيــنَ ءَامَنُواْؐ رَبَّنَآ إِنَّــكَ رَءُوفٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 11, '¥ اَلَمْ تَرَ إِلَي ۰لذِيــنَ نَافَقُواْ يَقُولُونَ لِإِخْوَ؛نِهِمُ ۴لذِيــنَ كَفَرُواْ مِنَ اَهْلِ ۱لْكِتَـٰبِ لَـئِــنُ ۷خْرۣجْتُمْ ڤَنَخْرُجَــنَّ مَعَكُمْ وَلاَ نُطِيعُ فِيكُمُ; أَحَداٗ اَبَداً وَإِن قُوتِلْتُمْ لَنَنصُرَنَّكُمْؐ وَاللَّهُ يَشْهَدُ 568 إِنَّهُمْ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 12, 'لَـئِــنُ ۷خْرۣجُواْ لاَ يَخْرُجُونَ مَعَهُمْؐ وَلَئِن قُوتِلُواْ لاَ يَنصُرُونَهُمْؐ وَلَـئِــن نَّصَرُوهُمْ لَيُوَلُّنَّ ۰لاَدْبَـٰرَ ثُمَّ لاَ يُنصَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 13, 'لَأَنتُمُ; أَشَدُّ رَهْبَةً فِى صُدُورۣهِم مِّــنَ ۰للَّهِؐ ذَ؛لِــكَ بِأَنَّهُمْ قَوْمٌ لاَّ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 14, 'لاَ يُقَـٰتِلُونَكُمْ جَمِيعاٗ اِلاَّ فِى قُريً مُّحَصَّنَةٖ اَوْ مِنْ وَّرَآءِ جُدُرٙؐ بَأْسُهُم بَيْنَهُمْ شَدِيدٌؐ تَحْسِبُهُمْ جَمِيعاً وَقُلُوبُهُمْ شَتّۭيٰؐ ذَ؛لِــكَ بِأَنَّهُمْ قَوْمٌ لاَّ يَعْقِلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 15, 'كَمَثَلِ ۱لذِينَ مِــن قَبْلِهِمْ قَرۣيباًؐ ذَاقُواْ وَبَالَ أَمْرۣهِمْؐ وَلَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 16, 'كَمَثَـلِ ۱لشَّيْطَـٰنِ إِذْ قَالَ لِلِانسَـٰنِ ۹كْفُرْ فَلَمَّا كَفَرَ قَالَ إِنِّى بَرۣىٓءٌ مِّنــكَ إِنِّــيَ أَخَافُ ۴للَّهَ رَبَّ ۰لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 17, 'فَكَانَ عَـٰقِبَتَهُمَآ أَنَّهُمَا فِى ۱لنّۭارۣ خَالِدَيْنِ فِيهَاؐ وَذَ؛لِــكَ جَزَ×ؤُاْ ۴لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 18, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ èتَّقُواْ ۴للَّهَ وَلْتَنظُرْ نَفْــسٌ مَّا قَدَّمَتْ لِغَدٍؐ وَاتَّقُواْ ۴للَّهَؐ إِنَّ ۰للَّهَ خَبِيرٛ بِمَا تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 19, 'وَلاَ تَكُونُواْ كَالذِيــنَ نَسُواْ ۴للَّهَ فَأَنسۭيٰهُمُ; أَنفُسَهُمُؐ; ٱُوْلَئِــكَ هُمُ ۴لْفَـٰسِقُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 20, 'لاَ يَسْتَوۣىٓ أَصْحَـٰبُ 569 ۴لنّۭارۣ وَأَصْحَـٰبُ ۴لْجَنَّةِؐ أَصْحَـٰبُ ۴لْجَنَّةِ هُمُ ۴لْفَآئِزُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 21, 'لَوَ اَنزَلْنَا هَـٰذَا ۰لْقُرْءَانَ عَلَيٰ جَبَلٍ لَّرَأَيْتَهُ„ خَـٰشِعاً مُّتَصَدِّعاً مِّــنْ خَشْيَةِ ۱للَّهِؐ وَتِلْــكَ ۰لاَمْثَـٰــلُ نَضْرۣبُهَا لِلنَّاسسسِ لَعَلَّهُمْ يَتَفَكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 22, 'هُوَ ۰للَّهُ ۴ﻟ﮲ لآَ إِچَهَ إِلاَّ هُوَؐ عَـٰلِمُ ۴لْغَيْبِ وَالشَّهَـٰدَةِؐ هُوَ ۰لرَّحْمَـٰنُ ۴لرَّحِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 23, 'هُوَ ۰للَّهُ ۴ﻟ﮲ لآَ إِچَهَ إِلاَّ هُوَ ۰لْمَلِــكُ ۴لْقُدُّوسسسُ ۴لسَّچَمُ ۴لْمُومِــنُ ۴لْمُهَيْمِنُ ۴لْعَزۣيزُ ۴لْجَبَّارُ ۴لْمُتَكَبِّرُؐ سُبْحَـٰــنَ ۰للَّهِ عَمَّا يُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (59, 24, 'هُوَ ۰للَّهُ ۴لْخَـٰلِقُ ۴لْبَارۣىُٔ ۴لْمُصَوّۣرُؐ لَهُ ۴لاَسْمَآءُ ۴لْحُسْنۭيٰؐ يُسَبِّحُ لَهُ„ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَتَّخِذُواْ عَدُوّۣى وَعَدُوَّكُمُ; أَوْلِيَآءَؐ تُلْقُونَ إِلَيْهِم بِالْمَوَدَّةِ وَقَدْ كَفَرُواْ بِمَا جَآءَكُم مِّــنَ ۰لْحَقﱢّؐ يُخْرۣجُونَ ۰لرَّسُولَ وَإِيَّاكُمُ; أَن تُومِنُواْ بِاللَّهِ رَبِّكُمُؐ; إِن كُنتُمْ خَرَجْتُمْ جِهَـٰداً فِى سَبِيلِى 570 وَابْتِغَآءَ مَرْضَاتِى تُسِرُّونَ إِلَيْهِم بِالْمَوَدَّةِ وَأَنَآ أَعْلَمُ بِمَآ أَخْفَيْتُمْ وَمَآ أَعْلَنتُمْؐ وَمَنْ يَّفْعَلْهُ مِنكُمْ فَقَد ضَّلَّ سَوَآءَ ۰لسَّبِيــلۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 2, 'إِنْ يَّثْقَفُوكُمْ يَكُونُواْ لَكُمُ; أَعْدَآءً وَيَبْسُطُوٓاْ إِلَيْكُمُ; أَيْدِيَهُمْ وَأَلْسِنَتَهُم بِالسُّوٓءِؐ وَوَدُّواْ لَوْ تَكْفُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 3, 'لَــن تَنفَعَكُمُ; أَرْحَامُكُمْ وَلآَ أَوْچَدُكُمْؐ يَوْمَ ۰لْقِيَـٰمَةِ يُفْصَـلُ بَيْنَكُمْؐ وَاللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 4, 'قَدْ كَانَتْ لَكُمُ; إِسْوَة٘ حَسَنَةٌ فِىٓ إِبْرَ؛هِيمَ وَالذِيــنَ مَعَهُ; إِذْ قَالُواْ لِقَوْمِهِمُ; إِنَّا بُرَ؏ؤُاْ مِنكُمْ وَمِمَّا تَعْبُدُونَ مِن دُونِ ۱للَّهِ كَفَرْنَا بِكُمْ وَبَدَا بَيْنَنَا وَبَيْنَكُمُ ۴لْعَدَ؛وَةُ وَالْبَغْضَآءُ اَ۬بَداٗ حَتَّيٰ تُومِنُواْ بِاللَّهِ وَحْدَهُ; إِلاَّ قَوْلَ إِبْرَ؛هِيمَ لَأِبِيهِ لَأَسْتَغْفِرَنَّ لَــكَ وَمَآ أَمْلِــكُ لَــكَ مِــنَ ۰للَّهِ مِن شَيْءٍؐ رَّبَّنَا عَلَيْكَ تَوَكَّلْنَا وَإِلَيْــكَ أَنَبْنَا وَإِلَيْــكَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 5, 'رَبَّنَا لاَ تَجْعَلْنَا فِتْنَةً لِّلذِيــنَ كَفَرُواْؐ وَاغْفِرْ لَنَا رَبَّنَآؐ إِنَّــكَ أَنتَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 6, 'لَقَدْ كَانَ لَكُمْ فِيهِمُ; إِسْوَة٘ حَسَنَةٌ لِّمَــن كَانَ يَرْجُواْ ۴للَّهَ وَالْيَوْمَ ۰لاَخِرَؐ وَمَنْ يَّتَوَلَّ فَإِنننَّ ۰للَّهَ هُوَ ۰لْغَنِــيُّ ۴لْحَمِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 7, '571 © عَسَــي ۰للَّهُ أَنْ يَّجْعَلَ بَيْنَكُمْ وَبَيْــنَ ۰لذِيــنَ عَادَيْتُم مِّنْهُم مَّوَدَّةًؐ وَاللَّهُ قَدِيرٌؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 8, 'لاَّ يَنْهۭيٰكُمُ ۴للَّهُ عَـنِ ۱لذِينَ لَمْ يُقَـٰتِلُوكُمْ فِى ۱لدِّينِ وَلَمْ يُخْرۣجُوكُم مِّــن دِيۭـٰرۣكُمُ; أَن تَبَرُّوهُمْ وَتُقْسِطُوٓاْ إِلَيْهِمُؐ; إِنَّ ۰للَّهَ يُحِــبُّ ۴لْمُقْسِطِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 9, 'إِنَّمَا يَنْهۭيٰكُمُ ۴للَّهُ عَـنِ ۱لذِيــنَ قَـٰتَلُوكُمْ فِى ۱لدِّينِ وَأَخْرَجُوكُم مِّــن دِيۭـٰرۣكُمْ وَظَـٰهَرُواْ عَلَيٰٓ إِخْرَاجِكُمُ; أَن تَوَلَّوْهُمْؐ وَمَنْ يَّتَوَلَّهُمْ فَٱُوْلَئِكَ هُمُ ۴لظَّـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 10, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا جَآءَكُمُ ۴لْمُومِنَـٰتُ مُهَـٰجِرَ؛تٍ فَامْتَحِنُوهُــنَّؐ ۰للَّهُ أَعْلَمُ بِإِيمَـٰنِهِنَّؐ فَإِنْ عَلِمْتُمُوهُنَّ مُومِنَـٰــتٍ فَلاَ تَرْجِعُوهُنَّ إِلَــي ۰لْكُفّۭارۣؐ لاَ هُنَّ حِلٌّ لَّهُمْ وَلاَ هُمْ يَحِلُّونَ لَهُنَّؐ وَءَاتُوهُم مَّآ أَنفَقُواْؐ وَلاَ جُنَاحَ عَلَيْكُمُ; أَن تَنكِحُوهُنَّ إِذَآ ءَاتَيْتُمُوهُــنَّ ٱُجُورَهُنَّؐ وَلاَ تُمْسِكُواْ بِعِصَمِ ۱لْكَوَافِـرۣؐ وَسْـَٔلُواْ مَآ أَنفَقْتُمْ وَلْيَسْـَٔلُواْ مَآ أَنفَقُواْؐ ذَ؛لِكُمْ حُكْمُ ۴للَّهِ يَحْكُمُ بَيْنَكُمْؐ وَاللَّهُ عَلِيم٘ حَكِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 11, 'وَإِن فَاتَكُمْ شَيْءٌ مِّنَ اَزْوَ؛جِكُمُ; إِلَــي ۰لْكُفّۭارۣ 572 فَعَاقَبْتُمْ فَـَٔاتُواْ ۴لذِيــنَ ذَهَبَتَ اَزْوَ؛جُهُم مِّثْــلَ مَآ أَنفَقُواْؐ وَاتَّقُواْ ۴للَّهَ ۰ﻟـذِىٓ أَنتُم بِهِ” مُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 12, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ اِ۬ذَا جَآءَكككَ ۰لْمُومِنَـٰــتُ يُبَايِعْنَــكَ عَلَيٰٓ أَن لاَّ يُشْرۣكْنَ بِاللَّهِ شَيْـٔاً وَلاَ يَسْرۣقْنَ وَلاَ يَزْنِينَ وَلاَ يَقْتُلْنَ أَوْچَدَهُنَّ وَلاَ يَاتِينَ بِبُهْتَـٰنٍ يَفْتَرۣينَهُ„ بَيْنَ أَيْدِيهِنَّ وَأَرْجُلِهِنَّ وَلاَ يَعْصِينَــكَ فِى مَعْرُوفٍ فَبَايِعْهُنَّ وَاسْتَغْفِرْ لَهُــنَّ ۰للَّهَؐ إِنننَّ ۰للَّهَ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (60, 13, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تَتَوَلَّوْاْ قَوْماٗ غَضِبَ ۰للَّهُ عَلَيْهِمْ قَدْ يَـئِسُواْ مِــنَ ۰لاَخِرَةِ كَمَا يَـئِــسَ ۰لْكُفَّارُ مِــنَ اَصْحَـٰبِ ۱لْقُبُورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سَبَّحَ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 2, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لِمَ تَقُولُونَ مَا لاَ تَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 3, 'كَبُرَ مَقْتاٗ عِندَ ۰للَّهِ أَن تَقُولُواْ مَا لاَ تَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 4, 'إِنَّ ۰للَّهَ يُحِــبُّ ۴لذِيــنَ يُقَـٰتِلُونَ فِى سَبِيلِهِ” صَفّاً كَأَنَّهُم بُنْيَـٰنٌ مَّرْصُوصصصٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 5, 'وَإِذْ قَالَ 57 مُوسۭـيٰ لِقَوْمِهِ” يَـٰقَوْمِ لِمَ تُوذُونَنِى وَقَد تَّعْلَمُونَ أَنِّى رَسُولُ ۴للَّهِ إِلَيْكُمْؐ فَلَمَّا زَاغُوٓاْ أَزَاغَ ۰للَّهُ قُلُوبَهُمْؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 6, 'وَإِذْ قَالَ عِيسَي "بْنُ مَرْيَمَ يَـٰبَنِىٓ إِسْرَآءِيلَ إِنِّى رَسُولُ ۴للَّهِ إِلَيْكُم مُّصَدِّقاً لِّمَا بَيْنَ يَدَيَّ مِــنَ ۰لتَّوْرۭيٰةِ وَمُبَشِّراَۢ بِرَسُولٍ يَاتِى مِنۢ بَعْدِيَ "سْمُهُ; أَحْمَدُؐ فَلَمَّا جَآءَهُم بِالْبَيِّنَـٰــتِ قَالُواْ هَـٰذَا سِحْرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 7, 'وَمَــنَ اَظْلَمُ مِمَّنِ ''فْتَرۭيٰ عَلَــي ۰للَّهِ ۱لْكَذِبَ وَهُوَ يُدْعۭيٰٓ إِلَي ۰لِاسْچَمِؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 8, 'يُرۣيدُونَ لِيُطْفِـُٔواْ نُورَ ۰للَّهِ بِأَفْوَ؛هِهِمْ وَاللَّهُ مُتِمٌّ نُّورَهُ„ وَلَوْ كَرۣهَ ۰لْكَـٰفِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 9, 'هُوَ ۰ﻟـذِىٓ أَرْسَلَ رَسُولَهُ„ بِالْهُدۭيٰ وَدِيـنِ ۱لْحَقِّ لِيُظْهِرَهُ„ عَلَــي ۰لدِّيــنۣ كُلِّهِ” وَلَوْ كَرۣهَ ۰لْمُشْرۣكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 10, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ هَــلَ اَدُلُّكُمْ عَلَيٰ تِجَـٰرَةٍ تُنجِيكُم مِّــنْ عَذَابٖ اَلِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 11, 'تُومِنُونَ بِاللَّهِ وَرَسُولِهِ” وَتُجَـٰهِدُونَ فِى سَبِيـلِ ۱للَّهِ بِأَمْوَ؛لِكُمْ وَأَنفُسِكُمْ ذَ؛لِكُمْ خَيْرٌ لَّكُمُ; إِن كُنتُمْ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 12, 'يَغْفِرْ لَكُمْ 574 ذُنُوبَكُمْ وَيُدْخِلْكُمْ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ وَمَسَـٰكِــنَ طَيِّبَةً فِى جَنَّـٰتِ عَدْنٍؐ ذَ؛لِــكَ ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 13, 'وَٱُخْرۭيٰ تُحِبُّونَهَا نَصْرٌ مِّــنَ ۰للَّهِ وَفَتْحٌ قَرۣيبٌؐ وَبَشِّرۣ ۱لْمُومِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (61, 14, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ كُونُوٓاْ أَنصَاراً لِّلهِ كَمَا قَالَ عِيسَي "بْنُ مَرْيَمَ ڤِڤْحَوَارۣيِّــيـيـــنَ مَنَ اَنصَارۣيَ إِلَــي ۰للَّهِؐ قَالَ ۰لْحَوَارۣيُّونَ نَحْــنُ أَنصَارُ ۴للَّهِؐ فَـَٔامَنَت طَّآئِفَةٌ مِّنۢ بَنِىٓ إِسْرَآءِيلَ وَكَفَرَت طَّآئِفَةٌؐ فَأَيَّدْنَا ۰لذِيــنَ ءَامَنُواْ عَلَــيٰ عَدُوّۣهِمْ فَأَصْبَحُواْ ظَـٰهِرۣينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يُسَبِّحُ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى ۱لاَرْضِ ۱لْمَلِــكِ ۱لْقُدُّوسسسِ ۱لْعَزۣيزۣ ۱لْحَكِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 2, 'هُوَ ۰ﻟ﮲ بَعَثَ فِى ۱لاُمِّيِّــيـيـنَ رَسُولًا مِّنْهُمْ يَتْلُواْ عَلَيْهِمُ; ءَايَـٰتِهِ” وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ۴لْكِتَـٰبَ وَالْحِكْمَةَ وَإِن كَانُواْ مِن قَبْلُ لَفِى ضَچَلٍ مُّبِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 3, 'وَءَاخَرۣيــنَ مِنْهُمْ 575 لَمَّا يَڤْحَقُواْ بِهِمْؐ وَهُوَ ۰لْعَزۣيزُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 4, 'ذَ؛لِــكَ فَضْلُ ۴للَّهِ يُوتِيهِ مَنْ يَّشَآءُؐ وَاللَّهُ ذُو ۴لْفَضْـلِ ۱لْعَظِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 5, 'مَثَلُ ۴لذِيــنَ حُمِّلُواْ ۴لتَّوْرۭيٰةَ ثُمَّ لَمْ يَحْمِلُوهَا كَمَثَلِ ۱لْحِمۭارۣ يَحْمِلُ أَسْفَاراٚؐ بِيــسَ مَثَلُ ۴لْقَوْمِ ۱لذِيــنَ كَذَّبُواْ بِـَٔايَـٰــتِ ۱للَّهِؐ وَاللَّهُ لاَ يَهْدِى ۱لْقَوْمَ ۰لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 6, 'قُلْ يَـٰٓأَيُّهَا ۰لذِيــنَ هَادُوٓاْ إِن زَعَمْتُمُ; أَنَّكُمُ; أَوْلِيَآءُ لِلهِ مِن دُونِ ۱لنَّاسِ فَتَمَنَّوُاْ ۴لْمَوْتَ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 7, 'وَلاَ يَتَمَنَّوْنَهُ; أَبَداَۢ بِمَا قَدَّمَتَ اَيْدِيهِمْؐ وَاللَّهُ عَلِيمٛ بِالظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 8, 'قُلِ اِنَّ ۰لْمَوْتَ ۰ﻟ﮲ تَفِرُّونَ مِنْهُ فَإِنَّهُ„ مُچَقِيكُمْ ثُمَّ تُرَدُّونَ إِلَــيٰ عَـٰلِمِ ۱لْغَيْبِ وَالشَّهَـٰدَةِ فَيُنَبِّـﻴُٔـكُم بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 9, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِذَا نُودِيَ لِلصَّلَوٰةِ مِنْ يَّوْمِ ۱لْجُمُعَةِ فَاسْعَوۣاْ اِلَــيٰ ذِكْرۣ ۱للَّهِ وَذَرُواْ ۴لْبَيْعَؐ ذَ؛لِكُمْ خَيْرٌ لَّكُمُ; إِن كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 10, 'فَإِذَا قُضِيَتِ ۱لصَّلَوٰةُ فَانتَشِرُواْ فِى ۱لاَرْضِ وَابْتَغُواْ مِن فَضْـلِ ۱للَّهِ وَاذْكُرُواْ ۴للَّهَ كَثِيراً لَّعَلَّكُمْ تُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (62, 11, 'وَإِذَا رَأَوْاْ تِجَـٰرَةٗ 576 اَوْ لَهْواٗ ''نفَضُّوٓاْ إِلَيْهَا وَتَرَكُوكَ قَآئِماًؐ قُــلْ مَا عِندَ ۰للَّهِ خَيْرٌ مِّــنَ ۰للَّهْوۣ وَمِــنَ ۰ڤتِّجَـٰرَةِؐ وَاللَّهُ خَيْرُ ۴لرَّ؛زۣقِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا جَآءَكككَ ۰لْمُنَـٰفِقُونَ قَالُواْ نَشْهَدُ إِنَّــكَ لَرَسُولُ ۴للَّهِؐ وَاللَّهُ يَعْلَمُ إِنَّكَ لَرَسُولُهُؐ„ وَاللَّهُ يَشْهَدُ إِنَّ ۰لْمُنَـٰفِقِيــنَ لَكَـٰذِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 2, '"تَّخَذُوٓاْ أَيْمَـٰنَهُمْ جُنَّةً فَصَدُّواْ عَــن سَبِيـلِ ۱للَّهِؐ إِنَّهُمْ سَآءَ مَا كَانُواْ يَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 3, 'ذَ؛لِــكَ بِأَنَّهُمُ; ءَامَنُواْ ثُمَّ كَفَرُواْ فَطُبِعَ عَلَــيٰ قُلُوبِهِمْ فَهُمْ لاَ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 4, 'وَإِذَا رَأَيْتَهُمْ تُعْجِبُــكَ أَجْسَامُهُمْؐ وَإِنْ يَّقُولُواْ تَسْمَعْ لِقَوْلِهِمْ كَأَنَّهُمْ خُشُبٌ مُّسَنَّدَةٌؐ يَحْسِبُونَ كُــلَّ صَيْحَةٖ عَلَيْهِمْؐ هُمُ ۴لْعَدُوُّؐ فَاحْذَرْهُمْؐ قَـٰتَلَهُمُ ۴للَّهُؐ أَنّۭيٰ يُوفَكُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 5, 'وَإِذَا قِيــلَ لَهُمْ تَعَالَوْاْ يَسْتَغْفِرْ لَكُمْ رَسُولُ ۴للَّهِ لَوَوْاْ رُءُوسَهُمْ وَرَأَيْتَهُمْ يَصُدُّونَ وَهُم مُّسْتَكْبِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 6, 'سَوَآء٘ عَلَيْهِمُ; أَسْتَغْفَرْتَ لَهُمُ; 577 أَمْ لَمْ تَسْتَغْفِرْ لَهُمْؐ لَـنْ يَّغْفِرَ ۰للَّهُ لَهُمُؐ; إِنَّ ۰للَّهَ لاَ يَهْدِى ۱لْقَوْمَ ۰لْفَـٰسِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 7, 'هُمُ ۴لذِيــنَ يَقُولُونَ لاَ تُنفِقُواْ عَلَيٰ مَنْ عِندَ رَسُولِ ۱للَّهِ حَتَّـيٰ يَنفَضُّواْؐ وَلِلهِ خَزَآئِــنُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَچَكِــنَّ ۰لْمُنَـٰفِقِيــنَ لاَ يَفْقَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 8, 'يَقُولُونَ لَئِن رَّجَعْنَآ إِلَــي ۰لْمَدِينَةِ ڤَيُخْرۣجَــنَّ ۰لاَعَزُّ مِنْهَا ۰لاَذَلَّؐ وَلِلهِ ۱لْعِزَّةُ وَلِرَسُولِهِ” وَلِلْمُومِنِينَؐ وَچَكِــنَّ ۰لْمُنَـٰفِقِينَ لاَ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 9, '© يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ لاَ تُلْهِكُمُ; أَمْوَ؛لُكُمْ وَلآَ أَوْچَدُكُمْ عَــن ذِكْرۣ ۱للَّهِؐ وَمَــنْ يَّفْعَلْ ذَ؛لِكَ فَٱُوْلَئِــكَ هُمُ ۴لْخَـٰسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 10, 'وَأَنفِقُواْ مِــن مَّا رَزَقْنَـٰكُم مِّــن قَبْلِ أَنْ يَّاتِــيَ أَحَدَكُمُ ۴لْمَوْتُ فَيَقُولَ رَبِّ لَوْلآَ أَخَّرْتَنِىٓ إِلَيٰٓ أَجَلٍ قَرۣيبٍ فَأَصَّدَّقَ وَأَكُــن مِّـنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (63, 11, 'وَلَنْ يُّوَ۬خِّرَ ۰للَّهُ نَفْساٗ اِذَا جَآءَ اجَلُهَاؐ وَاللَّهُ خَبِيرٛ بِمَا تَعْمَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يُسَبِّحُ لِلهِ مَا فِى ۱لسَّمَـٰوَ؛تِ وَمَا فِى 578 ۱لاَرْضضضِؐ لَهُ ۴لْمُلْــكُ وَلَهُ ۴لْحَمْدُؐ وَهُوَ عَلَــيٰ كُلِّ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 2, 'هُوَ ۰ﻟ﮲ خَلَقَكُمْ فَمِنكُمْ كَافِرٌ وَمِنكُم مُّومِنٌؐ وَاللَّهُ بِمَا تَعْمَلُونَ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 3, 'خَلَــقَ ۰لسَّمَـٰوَ؛تِ وَالاَرْضَ بِالْحَقِّ وَصَوَّرَكُمْ فَأَحْسَــنَ صُوَرَكُمْؐ وَإِلَيْهِ ۱لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 4, 'يَعْلَمُ مَا فِى ۱لسَّمَـٰوَ؛تِ وَالاَرْضِ وَيَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَؐ وَاللَّهُ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 5, 'أَلَمْ يَاتِكُمْ نَبَؤُاْ ۴لذِيــنَ كَفَرُواْ مِــن قَبْلُ فَذَاقُواْ وَبَالَ أَمْرۣهِمْ وَلَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 6, 'ذَ؛لِــكَ بِأَنَّهُ„ كَانَت تَّاتِيهِمْ رُسُلُهُم بِالْبَيِّنَـٰــتِ فَقَالُوٓاْ أَبَشَرٌ يَهْدُونَنَاؐ فَكَفَرُواْ وَتَوَلَّواْ وَّاسْتَغْنَــي ۰للَّهُؐ وَاللَّهُ غَنِــيّﹲ حَمِيدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 7, 'زَعَمَ ۰لذِيــنَ كَفَرُوٓاْ أَن لَّنْ يُّبْعَثُواْؐ قُلْ بَلۭيٰ وَرَبِّى لَتُبْعَثُنَّ ثُمَّ لَتُنَبَّؤُنَّ بِمَا عَمِلْتُمْؐ وَذَ؛لِــكَ عَلَــي ۰للَّهِ يَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 8, 'فَـَٔامِنُواْ بِاللَّهِ وَرَسُولِهِ” وَالنُّورۣ ۱ﻟـذِىٓ أَنزَلْنَاؐ وَاللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 9, 'يَوْمَ يَجْمَعُكُمْ لِيَوْمِ ۱لْجَمْعِ ذَ؛لِــكَ يَوْمُ ۴لتَّغَابُنِؐ وَمَنْ يُّومِـنۢ بِاللَّهِ وَيَعْمَــلْ صَـٰڤِحاً نُّكَفِّرْ عَنْهُ سَيِّـَٔاتِهِ” وَنُدْخِلْهُ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَداًؐ ذَ؛لِكَ 579 ۰لْفَوْزُ ۴لْعَظِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 10, 'وَالذِيــنَ كَفَرُواْ وَكَذَّبُواْ بِـَٔايَـٰتِنَآ ٱُوْلَئِــكَ أَصْحَـٰبُ ۴لنّۭارۣ خَـٰلِدِينَ فِيهَاؐ وَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 11, 'مَآ أَصَابَ مِــن مُّصِيبَةٖ اِلاَّ بِإِذْنِ ۱للَّهِؐ وَمَنْ يُّومِـنۢ بِاللَّهِ يَهْدِ قَلْبَهُؐ, وَاللَّهُ بِكُــلّۣ شَيْءٖ عَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 12, 'وَأَطِيعُواْ ۴للَّهَ وَأَطِيعُواْ ۴لرَّسُولَؐ فَإِن تَوَلَّيْتُمْ فَإِنَّمَا عَلَيٰ رَسُولِنَا ۰لْبَچَغُ ۴لْمُبِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 13, '۴للَّهُ لآَ إِچَهَ إِلاَّ هُوَؐ وَعَلَــي ۰للَّهِ فَلْيَتَوَكَّلِ ۱لْمُومِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 14, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُوٓاْ إِنَّ مِنَ اَزْوَ؛جِكُمْ وَأَوْچَدِكُمْ عَدُوّاً لَّكُمْ فَاحْذَرُوهُمْؐ وَإِن تَعْفُواْ وَتَصْفَحُواْ وَتَغْفِرُواْ فَإِنَّ ۰للَّهَ غَفُورٌ رَّحِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 15, 'اِنَّمَآ أَمْوَ؛لُكُمْ وَأَوْچَدُكُمْ فِتْنَةٌؐ وَاللَّهُ عِندَهُ; أَجْر٘ عَظِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 16, 'فَاتَّقُواْ ۴للَّهَ مَا "سْتَطَعْتُمْ وَاسْمَعُواْ وَأَطِيعُواْ وَأَنفِقُواْ خَيْراً لَأِّنفُسِكُمْؐ وَمَنْ يُّوقَ شُحَّ نَفْسِهِ” فَٱُوْلَئِــكَ هُمُ ۴ڤْمُفْڤِحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 17, 'إِن تُقْرۣضُواْ ۴للَّهَ قَرْضاٗ حَسَناً يُضَـٰعِفْهُ لَكُمْ وَيَغْفِرْ لَكُمْؐ وَاللَّهُ شَكُور٘ حَلِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (64, 18, 'عَـٰلِمُ ۴لْغَيْبِ وَالشَّهَـٰدَةِؐ ۱لْعَزۣيزُ ۴لْحَكِيمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ اِ۬ذَا طَلَّقْتُمُ ۴لنِّسَآءَ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ وَأَحْصُواْ ۴لْعِدَّةَؐ وَاتَّقُواْ ۴للَّهَ رَبَّكُمْؐ لاَ تُخْرۣجُوهُنَّ مِنۢ بُيُوتِهِنَّؐ وَلاَ يَخْرُجْنَ إِلٓاَّ أَنْ يَّاتِينَ بِفَـٰحِشَةٍ مُّبَيِّنَةٍؐ وَتِلْكَ حُدُودُ ۴للَّهِؐ وَمَنْ يَّتَعَدَّ حُدُودَ ۰للَّهِ فَقَد ظَّلَمَ نَفْسَهُؐ, لاَ تَدْرۣى لَعَــلَّ ۰للَّهَ يُحْدِثُ بَعْدَ ذَ؛لِكَ أَمْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 2, 'فَإِذَا بَلَغْــنَ أَجَلَهُــنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٖ اَوْ فَارۣقُوهُنَّ بِمَعْرُوفٍؐ وَأَشْهِدُواْ ذَوَىْ عَدْلٍ مِّنكُمْؐ وَأَقِيمُواْ ۴لشَّهَـٰدَةَ لِلهِؐ ذَ؛لِكُمْ يُوعَظُ بِهِ” مَــن كَانَ يُومِنُ بِاللَّهِ وَالْيَوْمِ ۱لاَخِرۣؐ وَمَنْ يَّتَّقِ ۱للَّهَ يَجْعَل لَّهُ„ مَخْرَجاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 3, 'وَيَرْزُقْهُ مِــنْ حَيْثُ لاَ يَحْتَسِبُؐ وَمَنْ يَّتَوَكَّــلْ عَلَــي ۰للَّهِ فَهُوَ حَسْبُهُؐ; إِنَّ ۰للَّهَ بَـٰلِغ٘ اَمْرَهُؐ, قَدْ جَعَــلَ ۰للَّهُ لِكُــلّۣ شَيْءٍ قَدْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 4, 'وَاﹾ يَئِسْــنَ مِنَ ۰ڤْمَحِيضِ مِن نِّسَآئِكُمُ; إِنِ ''رْتَبْتُمْ فَعِدَّتُهُنَّ ثَـچَثَةُ أَشْهُرٍ وَاﹾ لَمْ يَحِضْنَؐ وَٱُوْچَتُ ۴لاَحْمَالِ أَجَلُهُنَّ 581 أَنْ يَّضَعْــنَ حَمْلَهُنَّؐ وَمَنْ يَّتَّـقِ ۱للَّهَ يَجْعَل لَّهُ„ مِنَ اَمْرۣهِ” يُسْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 5, 'ذَ؛لِــكَ أَمْرُ ۴للَّهِ أَنزَلَهُ; إِلَيْكُمْؐ وَمَنْ يَّتَّـقِ ۱للَّهَ يُكَفِّرْ عَنْهُ سَيِّـَٔاتِهِ” وَيُعْظِمْ لَهُ; أَجْراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 6, 'اَسْكِنُوهُــنَّ مِنْ حَيْثُ سَكَنتُم مِّنْ وُّجْدِكُمْؐ وَلاَ تُضَآرُّوهُــنَّ لِتُضَيِّقُواْ عَلَيْهِنَّؐ وَإِن كُنَّ ٱُوْچَتِ حَمْــلٍ فَأَنفِقُواْ عَلَيْهِــنَّ حَتَّيٰ يَضَعْــنَ حَمْلَهُنَّؐ فَإِنَ اَرْضَعْــنَ لَكُمْ فَـَٔاتُوهُنَّ ٱُجُورَهُنَّ وَاتَمِرُواْ بَيْنَكُم بِمَعْرُوفٍؐ  وَإِن تَعَاسَرْتُمْ فَسَتُرْضِعُ لَهُ; ٱُخْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 7, 'لِيُنفِقْ ذُو سَعَةٍ مِّــن سَعَتِهِؐ” وَمَن قُدِرَ عَلَيْهِ رۣزْقُهُ„ فَلْيُنفِقْ مِمَّآ ءَاتۭيٰهُ ۴للَّهُؐ لاَ يُكَلِّفُ ۴للَّهُ نَفْساٗ اِلاَّ مَآ ءَاتۭيٰهَاؐ سَيَجْعَــلُ ۴للَّهُ بَعْدَ عُسْرٍ يُسْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 8, 'وَكَأَيِّن مِّن قَرْيَةٖ عَتَتْ عَنَ اَمْرۣ رَبِّهَا وَرُسُلِهِ” فَحَاسَبْنَـٰهَا حِسَاباً شَدِيداً وَعَذَّبْنَـٰهَا عَذَاباً نُّكُراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 9, 'فَذَاقَتْ وَبَالَ أَمْرۣهَاؐ وَكَانَ عَـٰقِبَةُ أَمْرۣهَا خُسْراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 10, 'اَعَدَّ ۰للَّهُ لَهُمْ عَذَاباً شَدِيداًؐ فَاتَّقُواْ ۴للَّهَ يَـٰٓٱُوْلِى ۱لاَلْبَـٰبِؐ ۱لذِيــنَ ءَامَنُواْ قَدَ اَنزَلَ ۰للَّهُ إِلَيْكُمْ ذِكْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 11, 'رَّسُولًا يَتْلُواْ عَلَيْكُمُ; ءَايَـٰتِ ۱للَّهِ مُبَيَّنَـٰتٍ ڤِّيُخْرۣجَ ۰لذِينَ 582 ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ مِــنَ ۰لظُّلُمَـٰتِ إِلَــي ۰لنُّورۣؐ وَمَنْ يُّومِـنۢ بِاللَّهِ وَيَعْمَــلْ صَـٰڤِحاً نُّدْخِلْهُ جَنَّـٰتٍ تَجْرۣى مِن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَداً قَدَ اَحْسَــنَ ۰للَّهُ لَهُ„ رۣزْقاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (65, 12, '۱للَّهُ ۴ﻟ﮲ خَلَقَ سَبْعَ سَمَـٰوَ؛تٍ وَمِــنَ ۰لاَرْضِ مِثْلَهُنَّؐ يَتَنَزَّلُ ۴لاَمْرُ بَيْنَهُــنَّ لِتَعْلَمُوٓاْ أَنَّ ۰للَّهَ عَلَــيٰ كُلِّ شَيْءٍ قَدِيرٌ وَأَنَّ ۰للَّهَ قَدَ اَحَاطَ بِكُــلّۣ شَيْءٖ عِلْماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 1, '© بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ لِمَ تُحَرّۣمُ مَآ أَحَــلَّ ۰للَّهُ لَــكَ تَبْتَغِى مَرْضَاتَ أَزْوَ؛جِــكَؐ وَاللَّهُ غَفُورٌ رَّحِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 2, 'قَدْ فَرَضضضَ ۰للَّهُ لَكُمْ تَحِلَّةَ أَيْمَـٰنِكُمْؐ وَاللَّهُ مَوْلۭيٰكُمْؐ وَهُوَ ۰لْعَلِيمُ ۴لْحَكِيمُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 3, 'وَإِذَ اَسَرَّ‏ ۰لنَّبِىٓءُ اِ۬لَـيٰ بَعْضِ أَزْوَ؛جِهِ” حَدِيثاًؐ فَلَمَّا نَبَّأَتْ بِهِ” وَأَظْهَرَهُ ۴للَّهُ عَلَيْهِ عَرَّفَ بَعْضَهُ„ وَأَعْرَضضضَ عَنۢ بَعْـضٍؐ فَلَمَّا نَبَّأَهَا بِهِ” قَالَتْ مَــنَ اَنۢبَأَكككَ هَـٰذَا قَالَ نَبَّأَنِــيَ ۰لْعَلِيمُ ۴لْخَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 4, 'إِن تَتُوبَآ 58 إِلَــي ۰للَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَاؐ وَإِن تَظَّـٰهَرَا عَلَيْهِ فَإِنَّ ۰للَّهَ هُوَ مَوْلۭيٰهُ وَجِبْرۣيلُ وَصَـٰلِحُ ۴لْمُومِنِينَؐ وَالْمَلَئِكَةُ بَعْدَ ذَ؛لِــكَ ظَهِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 5, 'عَسۭيٰ رَبُّهُ; إِن طَلَّقَكُنَّ أَنْ يُّبَدِّلَهُ; أَزْوَ؛جاٗ خَيْراً مِّنكُــنَّ مُسْلِمَـٰتٍ مُّومِنَـٰتٍ قَـٰنِتَـٰتٍ تَـٰٓئِبَـٰتٖ عَـٰبِدَ؛تٍ سَـٰٓئِـحَـٰتٍ ثَيِّبَـٰتٍ وَأَبْكَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 6, 'يَـٰٓأَيُّهَا ۰لذِينَ ءَامَنُواْ قُوٓاْ أَنفُسَكُمْ وَأَهْلِيكُمْ نَاراً وَقُودُهَا ۰لنَّاسُ وَالْحِجَارَةُ عَلَيْهَا مَلَئِكَة٘ غِچَظٌ شِدَادٌ لاَّ يَعْصُونَ ۰للَّهَ مَآ أَمَرَهُمْ وَيَفْعَلُونَ مَا يُومَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 7, 'يَـٰٓأَيُّهَا ۰لذِينَ كَفَرُواْ لاَ تَعْتَذِرُواْ ۴لْيَوْمَ إِنَّمَا تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 8, 'يَـٰٓأَيُّهَا ۰لذِيــنَ ءَامَنُواْ تُوبُوٓاْ إِلَــي ۰للَّهِ تَوْبَةً نَّصُوحاٗ عَسۭيٰ رَبُّكُمُ; أَنْ يُّكَفِّرَ عَنكُمْ سَيِّـَٔاتِكُمْ وَيُدْخِلَكُمْ جَنَّـٰتٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ يَوْمَ لاَ يُخْزۣى ۱للَّهُ ۴لنَّبِىٓءَ وَالذِيــنَ ءَامَنُواْ مَعَهُ, نُورُهُمْ يَسْعۭيٰ بَيْنَ أَيْدِيهِمْ وَبِأَيْمَـٰنِهِمْؐ يَقُولُونَ رَبَّنَآ أَتْمِمْ لَنَا نُورَنَا وَاغْفِرْ لَنَآؐ إِنَّــكَ عَلَــيٰ كُلِّ شَيْءٍ قَدِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 9, 'يَـٰٓأَيُّهَا‏ ۰لنَّبِىٓءُ جَـٰهِدِ ۱لْكُفَّارَ وَالْمُنَـٰفِقِينَ 584 وَاغْلُظْ عَلَيْهِمْؐ وَمَأْوۭيٰهُمْ جَهَنَّمُؐ وَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 10, 'ضَرَبَ ۰للَّهُ مَثَلًا لِّلذِيــنَ كَفَرُواْ èمْرَأَتَ نُوحٍ وَامْرَأَتَ لُوطٍؐ كَانَتَا تَحْتَ عَبْدَيْـنِ مِنْ عِبَادِنَا صَالِحَيْــنۣ فَخَانَتَـٰهُمَا فَلَمْ يُغْنِيَا عَنْهُمَا مِــنَ ۰للَّهِ شَيْـٔاًؐ وَقِيــلَ ۸دْخُلاَ ۰لنَّارَ مَعَ ۰لدَّ؛خِلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 11, 'وَضَرَبَ ۰للَّهُ مَثَلًا لِّلذِيــنَ ءَامَنُواْ èمْرَأَتَ فِرْعَوْنَ إِذْ قَالَتْ رَبِّ ''بْـنِ لِى عِندَكككَ بَيْتاً فِى ۱لْجَنَّةِ وَنَجِّنِى مِن فِرْعَوْنَ وَعَمَلِهِ” وَنَجِّنِى مِــنَ ۰لْقَوْمِ ۱لظَّـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (66, 12, 'وَمَرْيَمَ "بْنَتَ عِمْرَ؛نَ ۰لتِىٓ أَحْصَنَتْ فَرْجَهَا فَنَفَخْنَا فِيهِ مِن رُّوحِنَا وَصَدَّقَتْ بِكَلِمَـٰتِ رَبِّهَا وَكِتَـٰبِهِ” وَكَانَتْ مِــنَ ۰لْقَـٰنِتِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ تَبَـٰرَكككَ ۰ﻟ﮲ بِيَدِهِ ۱لْمُلْــكُ وَهُوَ عَلَــيٰ كُلِّ شَيْءٍ قَدِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 2, '۱ﻟ﮲ خَلَقَ ۰لْمَوْتَ وَالْحَيَوٰةَ لِيَبْلُوَكُمُ; أَيُّكُمُ; أَحْسَــنُ عَمَلًؐا وَهُوَ ۰لْعَزۣيزُ ۴لْغَفُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 3, '۴ﻟ﮲ خَلَقَ سَبْعَ سَمَـٰوَ؛تٍ طِبَاقاًؐ مَّا تَرۭيٰ فِى خَلْقِ ۱لرَّحْمَـٰنِ 585 مِــن تَفَـٰوُتٍؐ فَارْجِعِ ۱لْبَصَرَ هَلْ تَرۭيٰ مِن فُطُورٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 4, 'ثُمَّ "رْجِعِ ۱لْبَصَرَ كَرَّتَيْنِ يَنقَلِبِ اِلَيْــكَ ۰لْبَصَرُ خَاسِيؗاً وَهُوَ حَسِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 5, 'وَلَقَدْ زَيَّنَّا ۰لسَّمَآءَ ۰لدُّنْيۭا بِمَصَـٰبِيحَ وَجَعَلْنَـٰهَا رُجُوماً لِّلشَّيَـٰطِينِ وَأَعْتَدْنَا لَهُمْ عَذَابَ ۰لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 6, 'وَلِلذِيــنَ كَفَرُواْ بِرَبِّهِمْ عَذَابُ جَهَنَّمَؐ وَبِيــسَ ۰لْمَصِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 7, 'إِذَآ ٱُلْقُواْ فِيهَا سَمِعُواْ لَهَا شَهِيقاً وَهِيَ تَفُورُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 8, 'تَكَادُ تَمَيَّزُ مِــنَ ۰لْغَيْظِؐ كُلَّمَآ ٱُلْقِيَ فِيهَا فَوْجٌ سَأَلَهُمْ خَزَنَتُهَآ أَلَمْ يَاتِكُمْ نَذِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 9, 'قَالُواْ بَلۭــيٰ قَدْ جَآءَنَا نَذِيرٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 10, 'فَكَذَّبْنَا وَقُلْنَا مَا نَزَّلَ ۰للَّهُ مِن شَيْءٖ اِنَ اَنتُمُ; إِلاَّ فِى ضَچَــلٍ كَبِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 11, 'وَقَالُواْ لَوْ كُنَّا نَسْمَعُ أَوْ نَعْقِــلُ مَا كُنَّا فِىٓ أَصْحَـٰبِ ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 12, 'فَاعْتَرَفُواْ بِذَنۢبِهِمْؐ فَسُحْقاً لَأِّصْحَـٰبِ ۱لسَّعِيرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 13, 'إِنَّ ۰لذِيــنَ يَخْشَوْنَ رَبَّهُم بِالْغَيْبِ لَهُم مَّغْفِرَةٌ وَأَجْرٌ كَبِيرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 14, 'وَأَسِرُّواْ قَوْلَكُمُ; أَوۣ ''جْهَرُواْ بِهِؐ“ إِنَّهُ„ عَلِيمٛ بِذَاتِ ۱لصُّدُورۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 15, 'أَلاَ يَعْلَمُ مَــنْ خَلَقَ وَهُوَ ۰للَّطِيفُ ۴لْخَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 16, 'هُوَ ۰ﻟ﮲ جَعَــلَ لَكُمُ ۴لاَرْضَ 586 ذَلُولًا فَامْشُواْ فِى مَنَاكِبِهَا وَكُلُواْ مِن رّۣزْقِهِؐ” وَإِلَيْهِ ۱لنُّشُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 17, 'ءَامِنتُم مَّـن فِى ۱لسَّمَآءِ اَ۬نننْ يَّخْسِفَ بِكُمُ ۴لاَرْضَ فَإِذَا هِــيَ تَمُورُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 18, 'أَمَ اَمِنتُم مَّـن فِى ۱لسَّمَآءِ اَ۬نْ يُّرْسِــلَ عَلَيْكُمْ حَاصِباًؐ فَسَتَعْلَمُونَ كَيْفَ نَذِيرۣؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 19, 'وَلَقَدْ كَذَّبَ ۰لذِيــنَ مِن قَبْلِهِمْؐ فَكَيْفَ كَانَ نَكِيرۣؐ¿');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 20, 'أَوَلَمْ يَرَوۣاْ اِلَــي ۰لطَّيْرۣ فَوْقَهُمْ صَـٰٓفَّـٰتٍ وَيَقْبِضْــنَؐ مَا يُمْسِكُهُنَّ إِلاَّ ۰لرَّحْمَـٰنُؐ إِنَّهُ„ بِكُلِّ شَيْءٙ بَصِير٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 21, 'اَمَّــنْ هَـٰذَا ۰ﻟ﮲ هُوَ جُندٌ لَّكُمْ يَنصُرُكُم مِّن دُونِ ۱لرَّحْمَـٰنِؐ إِنِ ۱لْكَـٰفِرُونَ إِلاَّ فِى غُرُورٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 22, 'اَمَّــنْ هَـٰذَا ۰ﻟ﮲ يَرْزُقُكُمُ; إِنَ اَمْسَكَ رۣزْقَهُؐ, بَل لَّجُّواْ فِى عُتُوٍّ وَنُفُورٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 23, 'اَفَمَنْ يَّمْشِى مُكِبّاٗ عَلَيٰ وَجْهِهِ“ أَهْدۭيٰٓ أَمَّنْ يَّمْشِى سَوۣيّاٗ عَلَـيٰ صِرَ؛طٍ مُّسْتَقِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 24, 'قُلْ هُوَ ۰ﻟـذِىٓ أَنشَأَكُمْ وَجَعَــلَ لَكُمُ ۴لسَّمْعَ وَالاَبْصَـٰرَ وَالاَفْـِٕدَةَؐ قَلِيلًا مَّا تَشْكُرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 25, 'قُلْ هُوَ ۰ﻟ﮲ ذَرَأَكُمْ فِى ۱لاَرْضِ وَإِلَيْهِ تُحْشَرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 26, 'وَيَقُولُونَ مَتۭــيٰ هَـٰذَا ۰لْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 27, 'قُـلِ اِنَّمَا ۰لْعِلْمُ عِندَ ۰للَّهِ 587 وَإِنَّمَآ أَنَا نَذِيرٌ مُّبِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 28, 'فَلَمَّا رَأَوْهُ زُلْفَةً سـ۬ـيٓــَٔـــتْ وُجُوهُ ۴لذِيــنَ كَفَرُواْ وَقِيــلَ هَـٰذَا ۰ﻟ﮲ كُنتُم بِهِ” تَدَّعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 29, 'قُلَ اَرَ×يْتُمُ; إِنننَ اَهْلَكَنِــيَ ۰للَّهُ وَمَــن مَّعِيَ أَوْ رَحِمَنَا فَمَنْ يُّجِيرُ ۴لْكۭـٰفِـرۣيــنَ مِنْ عَذَابٖ اَلِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 30, 'قُلْ هُوَ ۰لرَّحْمَـٰــنُ ءَامَنَّا بِهِ” وَعَلَيْهِ تَوَكَّلْنَاؐ فَسَتَعْلَمُونَ مَنْ هُوَ فِى ضَچَلٍ مُّبِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (67, 31, 'قُلَ اَرَ×يْتُمُ; إِنننَ اَصْبَحَ مَآؤُكُمْ غَوْراً فَمَنْ يَّاتِيكُم بِمَآءٍ مَّعِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ نُّٓؐ وَالْقَلَمِ وَمَا يَسْطُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 2, 'مَآ أَنتَ بِنِعْمَةِ رَبِّــكَ بِمَجْنُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 3, 'وَإِنَّ لَــكَ لَأَجْراٗ غَيْرَ مَمْنُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 4, 'وَإِنَّــكَ لَعَلَــيٰ خُلُقٖ عَظِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 5, 'فَسَتُبْصِرُ وَيُبْصِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 6, 'بِأَييِّكُمُ ۴لْمَفْتُونُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 7, 'إِنَّ رَبَّــكَ هُوَ أَعْلَمُ بِمَــن ضَلَّ عَن سَبِيلِهِؐ” وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 8, 'فَلاَ تُطِعِ ۱لْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 9, 'وَدُّواْ لَوْ تُدْهِنُ فَيُدْهِنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 10, 'وَلاَ تُطِعْ كُلَّ حَچَّفٍ مَّهِينٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 11, 'هَمَّازٍ مَّشَّآءٙ بِنَمِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 12, 'مَّنَّاعٍ ڤِّڤْخَيْرۣ 588 مُعْتَدٖ اَثِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 13, 'عُتُــلّٙ بَعْدَ ذَ؛لِــكَ زَنِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 14, 'اَن كَانَ ذَا مَالٍ وَبَنِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 15, 'إِذَا تُتْلۭــيٰ عَلَيْهِ ءَايَـٰتُنَا قَالَ أَسَـٰطِيرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 16, 'سَنَسِمُهُ„ عَلَــي ۰لْخُرْطُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 17, 'إِنَّا بَلَوْنَـٰهُمْ كَمَا بَلَوْنَآ أَصْحَـٰبَ ۰لْجَنَّةِ إِذَ اَقْسَمُواْ لَيَصْرۣمُنَّهَا مُصْبِحِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 18, 'وَلاَ يَسْتَثْنُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 19, '© فَطَافَ عَلَيْهَا طَآئِفٌ مِّن رَّبِّــكَ وَهُمْ نَآئِمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 20, 'فَأَصْبَحَتْ كَالصَّرۣيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 21, 'فَتَنَادَوْاْ مُصْبِحِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 22, 'أَنُ ۶غْدُواْ عَلَيٰ حَرْثِكُمُ; إِن كُنتُمْ صَـٰرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 23, 'فَانطَلَقُواْ وَهُمْ يَتَخَـٰفَتُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 24, 'أَن لاَّ يَدْخُلَنَّهَا ۰لْيَوْمَ عَلَيْكُم مِّسْكِينٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 25, 'وَغَدَوْاْ عَلَيٰ حَرْدٍ قَـٰدِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 26, 'فَلَمَّا رَأَوْهَا قَالُوٓاْ إِنَّا لَضَآلُّونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 27, 'بَـلْ نَحْنُ مَحْرُومُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 28, 'قَالَ أَوْسَطُهُمُ; أَلَمَ اَقُــل لَّكُمْ لَوْلاَ تُسَبِّحُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 29, 'قَالُواْ سُبْحَـٰنَ رَبِّنَآ إِنَّا كُنَّا ظَـٰلِمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 30, 'فَأَقْبَلَ بَعْضُهُمْ عَلَيٰ بَعْضٍ يَتَچَوَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 31, 'قَالُواْ يَـٰوَيْلَنَآ إِنَّاكُنَّا طَـٰغِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 32, 'عَسۭيٰ رَبُّنَآ أَنْ يُّبَدِّلَنَا خَيْراً مِّنْهَآ إِنَّآ إِلَيٰ رَبِّنَا رَ؛غِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 33, 'كَذَ؛لِــكَ ۰لْعَذَابُؐ 589 وَلَعَذَابُ ۴لاَخِرَةِ أَكْبَرُ لَوْ كَانُواْ يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 34, 'إِنَّ لِلْمُتَّقِيــنَ عِندَ رَبِّهِمْ جَنَّـٰتِ ۱لنَّعِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 35, 'أَفَنَجْعَــلُ ۴لْمُسْلِمِينَ كَاڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 36, 'مَا لَكُمْؐ كَيْفَ تَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 37, 'أَمْ لَكُمْ كِتَـٰبٌ فِيهِ تَدْرُسُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 38, 'إِنَّ لَكُمْ فِيهِ لَمَا تَخَيَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 39, 'أَمْ لَكُمُ; أَيْمَـٰــن٘ عَلَيْنَا بَـٰلِغَة٘ اِلَيٰ يَوْمِ ۱لْقِيَـٰمَةِ إِنَّ لَكُمْ لَمَا تَحْكُمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 40, 'سَلْهُمُ; أَيُّهُم بِذَ؛لِــكَ زَعِيم٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 41, 'اَمْ لَهُمْ شُرَكَآءُ فَلْيَاتُواْ بِشُرَكَآئِهِمُ; إِن كَانُواْ صَـٰدِقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 42, 'يَوْمَ يُكْشَفُ عَن سَاقٍ وَيُدْعَوْنَ إِلَــي ۰ڤسُّجُودِ فَلاَ يَسْتَطِيعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 43, 'خَـٰشِعَةٗ اَبْصَـٰرُهُمْ تَرْهَقُهُمْ ذِلَّةٌؐ وَقَدْ كَانُواْ يُدْعَوْنَ إِلَي ۰ڤسُّجُودِ وَهُمْ سَـٰلِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 44, 'فَذَرْنِى وَمَنْ يُّكَذِّبُ بِهَـٰذَا ۰لْحَدِيثِؐ سَنَسْتَدْرۣجُهُم مِّــنْ حَيْثُ لاَ يَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 45, 'وَٱُمْلِى لَهُمُؐ; إِنننَّ كَيْدِى مَتِين٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 46, 'اَمْ تَسْـَٔلُهُمُ; أَجْراً فَهُم مِّــن مَّغْرَمٍ مُّثْقَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 47, 'أَمْ عِندَهُمُ ۴لْغَيْبُ فَهُمْ يَكْتُبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 48, 'فَاصْبِرْ لِحُكْمِ رَبِّكَ وَلاَ تَكُــن كَصَـٰحِبِ ۱لْحُوتِ إِذْ 590 نَادۭيٰ وَهُوَ مَكْظُومٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 49, 'لَّوْلآَ أَن تَدَ؛رَكَهُ„ نِعْمَةٌ مِّن رَّبِّهِ” لَنُبِذَ بِالْعَرَآءِ وَهُوَ مَذْمُومٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 50, 'فَاجْتَبۭـٰهُ رَبُّهُ„ فَجَعَلَهُ„ مِــنَ ۰ڤصَّـٰڤِحِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 51, 'وَإِنْ يَّكَادُ ۴لذِينَ كَفَرُواْ لَيَزْلِقُونَكَ بِأَبْصۭـٰرۣهِمْ لَمَّا سَمِعُواْ ۴لذِّكْرَ وَيَقُولُونَ إِنَّهُ„ ڤَمَجْنُونٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (68, 52, 'وَمَا هُوَ إِلاَّ ذِكْرٌ لِّلْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۰لْحَآقَّةُ مَا ۰لْحَآقَّةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 2, 'وَمَآ أَدْرۭيٰــكَ مَا ۰لْحَآقَّةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 3, 'كَذَّبَتْ ثَمُودُ وَعَادٛ بِالْقَارۣعَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 4, 'فَأَمَّا ثَمُودُ فَٱُهْلِكُواْ بِالطَّاغِيَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 5, 'وَأَمَّا عَادٌ فَٱُهْلِكُواْ بِـرۣيحٍ صَرْصَر۫ عَاتِيَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 6, 'سَخَّرَهَا عَلَيْهِمْ سَبْعَ لَيَالٍ وَثَمَـٰنِيَةَ أَيَّامٖ حُسُوماًؐ فَتَرَي ۰لْقَوْمَ فِيهَا صَرْعۭيٰ كَأَنَّهُمُ; أَعْجَازُ نَخْلٖ خَاوۣيَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 7, 'فَهَلْ تَرۭيٰ لَهُم مِّنۢ بَاقِيَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 8, 'وَجَآءَ فِرْعَوْنُ وَمَــن قَبْلَهُ„ وَالْمُوتَفِكَـٰتُ بِالْخَاطِيؕةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 9, 'فَعَصَوْاْ رَسُولَ رَبِّهِمْ فَأَخَذَهُمُ; أَخْذَةً 591 رَّابِيَةٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 10, 'اِنَّا لَمَّا طَغَا ۰لْمَآءُ حَمَلْنَـٰكُمْ فِى ۱لْجَارۣيَةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 11, 'ڤِنَجْعَلَهَا لَكُمْ تَذْكِرَةً وَتَعِيَهَآ ٱُذْنٌ وَ؛عِيَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 12, 'فَإِذَا نُفِخَ فِى ۱لصُّورۣ نَفْخَةٌ وَ؛حِدَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 13, 'وَحُمِلَتِ ۱لاَرْضُ وَالْجِبَالُ فَدُكَّتَا دَكَّةً وَ؛حِدَةً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 14, 'فَيَوْمَئِذٍ وَقَعَتِ ۱لْوَاقِعَةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 15, 'وَانشَقَّتِ ۱لسَّمَآءُ فَهِيَ يَوْمَئِذٍ وَاهِيَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 16, 'وَالْمَلَــكُ عَلَيٰٓ أَرْجَآئِهَاؐ وَيَحْمِلُ عَرْشَ رَبِّــكَ فَوْقَهُمْ يَوْمَئِذٍ ثَمَـٰنِيَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 17, 'يَوْمَئِذٍ تُعْرَضُونَ لاَ تَخْفۭيٰ مِنكُمْ خَافِيَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 18, '¥ فَأَمَّا مَنُ ۷وتِيَ كِتَـٰبَهُ„ بِيَمِينِهِ” فَيَقُولُ هَآؤُمُ èقْرَءُواْ كِتَـٰبِيَهْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 19, 'إِنِّى ظَنَنتُ أَنِّى مُچَقٖ حِسَابِيَهْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 20, 'فَهُوَ فِى عِيشَةٍ رَّاضِيَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 21, 'فِى جَنَّةٖ عَالِيَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 22, 'قُطُوفُهَا دَانِيَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 23, 'كُلُواْ وَاشْرَبُواْؐ هَنِيٓـٔاَۢ بِمَآ أَسْلَفْتُمْ فِى ۱لاَيَّامِ ۱لْخَالِيَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 24, 'وَأَمَّا مَنُ ۷وتِيَ كِتَـٰبَهُ„ بِشِمَالِهِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 25, 'فَيَقُولُ يَـٰلَيْتَنِى لَمُ ۷وتَ كِتَـٰبِيَهْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 26, 'وَلَمَ اَدْرۣ مَا حِسَابِيَهْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 27, 'يَـٰلَيْتَهَا كَانَتِ ۱لْقَاضِيَةَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 28, 'مَآ أَغْنۭيٰ عَنِّى مَالِيَهؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 29, 'هَّلَكَ عَنِّى سُلْطَـٰنِيَهْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 30, 'خُذُوهُ فَغُلُّوهُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 31, 'ثُمَّ ۰لْجَحِيمَ 592 صَلُّوهُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 32, 'ثُمَّ فِى سِلْسِلَةٍ ذَرْعُهَا سَبْعُونَ ذِرَاعاً فَاسْلُكُوهُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 33, 'إِنَّهُ„ كَانَ لاَ يُومِنُ بِاللَّهِ ۱لْعَظِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 34, 'وَلاَ يَحُــضُّ عَلَيٰ طَعَامِ ۱لْمِسْكِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 35, 'فَلَيْــسَ لَهُ ۴لْيَوْمَ هَـٰهُنَا حَمِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 36, 'وَلاَ طَعَام٘ اِلاَّ مِــنْ غِسْلِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 37, 'لاَّ يَاكُلُهُ; إِلاَّ ۰لْخَـٰطِـُٔونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 38, 'فَلآَ ٱُقْسِمُ بِمَا تُبْصِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 39, 'وَمَا لاَ تُبْصِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 40, 'إِنَّهُ„ لَقَوْلُ رَسُولٍ كَرۣيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 41, 'وَمَا هُوَ بِقَوْلِ شَاعِرٍ قَلِيلًا مَّا تُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 42, 'وَلاَ بِقَوْلِ كَاهِنٍؐ قَلِيلًا مَّا تَذَّكَّرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 43, 'تَنزۣيلٌ مِّن رَّبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 44, 'وَلَوْ تَقَوَّلَ عَلَيْنَا بَعْــضَ ۰لاَقَاوۣيــلۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 45, 'لَأَخَذْنَا مِنْهُ بِالْيَمِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 46, 'ثُمَّ لَقَطَعْنَا مِنْهُ ۴لْوَتِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 47, 'فَمَا مِنكُم مِّــنَ اَحَدٖ عَنْهُ حَـٰجِزۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 48, 'وَإِنَّهُ„ لَتَذْكِرَةٌ لِّلْمُتَّقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 49, 'وَإِنَّا لَنَعْلَمُ أَنَّ مِنكُم مُّكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 50, 'وَإِنَّهُ„ لَحَسْرَة٘ عَلَــي ۰لْكۭـٰفِـرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 51, 'وَإِنَّهُ„ لَحَــقُّ ۴لْيَقِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (69, 52, 'فَسَبِّحْ بِاسْمِ رَبِّــكَ ۰لْعَظِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 1, '59  بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سَالَ سَآئِــلٛ بِعَذَابٍ وَاقِعٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 2, 'لِّلْكۭـٰفِـرۣينَ لَيْسَ لَهُ„ دَافِعٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 3, 'مِّــنَ ۰للَّهِ ذى ۱لْمَعَارۣجِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 4, 'تَعْرُجُ ۴لْمَلَئِكَةُ وَالرُّوحُ إِلَيْهِ فِى يَوْمٍ كَانَ مِقْدَارُهُ„ خَمْسِيــنَ أَلْفَ سَنَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 5, 'فَاصْبِرْ صَبْراً جَمِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 6, 'اِنَّهُمْ يَرَوْنَهُ„ بَعِيداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 7, 'وَنَرۭيٰهُ قَرۣيباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 8, 'يَوْمَ تَكُونُ ۴لسَّمَآءُ كَالْمُهْـلِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 9, 'وَتَكُونُ ۴لْجِبَالُ كَالْعِهْنِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 10, 'وَلاَ يَسْـَٔلُ حَمِيم٘ حَمِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 11, 'يُبَصَّرُونَهُمْؐ يَوَدُّ ۴ڤْمُجْرۣمُ لَوْ يَفْتَدِى مِــنْ عَذَابِ يَوْمَئِذٙ بِبَنِيهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 12, 'وَصَـٰحِبَتِهِ” وَأَخِيهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 13, 'وَفَصِيلَتِهِ ۱لتِى تُـْٔوۣيهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 14, 'وَمَـن فِى ۱لاَرْضِ جَمِيعاً ثُمَّ يُنجِيهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 15, 'كَلٓؐاَّ إِنَّهَا لَظۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 16, 'نَزَّاعَةٌ لِّلشَّوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 17, 'تَدْعُواْ مَــنَ اَدْبَرَ وَتَوَلّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 18, 'وَجَمَعَ فَأَوْعۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 19, 'إِنَّ ۰لِانسَـٰــنَ خُلِقَ هَلُوعاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 20, 'اِذَا مَسَّهُ ۴لشَّرُّ جَزُوعاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 21, 'وَإِذَا مَسَّهُ ۴لْخَيْرُ مَنُوعاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 22, 'اِلاَّ ۰لْمُصَلِّينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 23, '۰لذِيــنَ هُمْ عَلَيٰ صَلاَتِهِمْ دَآئِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 24, 'وَالذِينَ فِىٓ أَمْوَ؛لِهِمْ حَــقٌّ مَّعْلُومٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 25, 'لِّلسَّآئِلِ وَاڤْمَحْرُومِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 26, 'وَالذِينَ يُصَدِّقُونَ بِيَوْمِ 594 ۱لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 27, 'وَالذِينَ هُم مِّــنْ عَذَابِ رَبِّهِم مُّشْفِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 28, 'إِنَّ عَذَابَ رَبِّهِمْ غَيْرُ مَامُونٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 29, 'وَالذِينَ هُمْ لِفُرُوجِهِمْ حَـٰفِظُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 30, 'إِلاَّ عَلَيٰٓ أَزْوَ؛جِهِمُ; أَوْ مَا مَلَكَتَ اَيْمَـٰنُهُمْ فَإِنَّهُمْ غَيْرُ مَلُومِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 31, 'فَمَنِ ''بْتَغۭيٰ وَرَآءَ ذَ؛لِــكَ فَٱُوْلَئِكَ هُمُ ۴لْعَادُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 32, 'وَالذِينَ هُمْ لَأِمَـٰنَـٰتِهِمْ وَعَهْدِهِمْ رَ؛عُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 33, 'وَالذِينَ هُم بِشَهَـٰدَتِهِمْ قَآئِمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 34, 'وَالذِينَ هُمْ عَلَــيٰ صَلاَتِهِمْ يُحَافِظُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 35, 'ٱُوْلَئِكَ فِى جَنَّـٰتٍ مُّكْرَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 36, 'فَمَالِ ۱لذِيــنَ كَفَرُواْ قِبَلَكَ مُهْطِعِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 37, 'عَنِ ۱لْيَمِينِ وَعَـنِ ۱لشِّمَالِ عِزۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 38, 'أَيَطْمَعُ كُلُّ èمْرۣئٍ مِّنْهُمُ; أَنْ يُّدْخَلَ جَنَّةَ نَعِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 39, 'كَلٓؐاَّ إِنَّا خَلَقْنَـٰهُم مِّمَّا يَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 40, '© فَلآَ ٱُقْسِمُ بِرَبِّ ۱لْمَشَـٰرۣقِ وَالْمَغَـٰرۣبِ إِنَّا لَقَـٰدِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 41, 'عَلَيٰٓ أَن نُّبَدِّلَ خَيْراً مِّنْهُمْ وَمَا نَحْـنُ بِمَسْبُوقِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 42, 'فَذَرْهُمْ يَخُوضُواْ وَيَلْعَبُواْ حَتَّـيٰ يُچَقُواْ يَوْمَهُمُ ۴ﻟ﮲ يُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 43, 'يَوْمَ يَخْرُجُونَ مِــنَ ۰لاَجْدَاثِ سِرَاعاً كَأَنَّهُمُ; 595 إِلَيٰ نَصْبٍ يُوفِضُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (70, 44, 'خَـٰشِعَةٗ اَبْصَـٰرُهُمْ تَرْهَقُهُمْ ذِلَّةٌؐ ذَ؛لِــكَ ۰لْيَوْمُ ۴ﻟ﮲ كَانُواْ يُوعَدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِنَّآ أَرْسَلْنَا نُوحاٗ اِلَيٰ قَوْمِهِ“ أَنَ اَنذِرْ قَوْمَــكَ مِــن قَبْلِ أَنْ يَّاتِيَهُمْ عَذَاب٘ اَلِيمٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 2, 'قَالَ يَـٰقَوْمِ إِنِّى لَكُمْ نَذِيرٌ مُّبِين٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 3, 'اَنُ ۶عْبُدُواْ ۴للَّهَ وَاتَّقُوهُ وَأَطِيعُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 4, 'يَغْفِرْ لَكُم مِّــن ذُنُوبِكُمْ وَيُوَ۬خِّرْكُمُ; إِلَيٰٓ أَجَــلٍ مُّسَمّيٗؐ اِنَّ أَجَــلَ ۰للَّهِ إِذَا جَآءَ لاَ يُوَ۬خَّرُ لَوْ كُنتُمْ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 5, 'قَالَ رَبِّ إِنِّى دَعَوْتُ قَوْمِى لَيْلًا وَنَهَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 6, 'فَلَمْ يَزۣدْهُمْ دُعَآءِيَ إِلاَّ فِرَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 7, 'وَإِنِّى كُلَّمَا دَعَوْتُهُمْ لِتَغْفِرَ لَهُمْ جَعَلُوٓاْ أَصَـٰبِعَهُمْ فِىٓ ءَاذَانِهِمْ وَاسْتَغْشَوْاْ ثِيَابَهُمْ وَأَصَرُّواْ وَاسْتَكْبَرُواْ èسْتِكْبَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 8, 'ثُمَّ إِنِّى دَعَوْتُهُمْ جِهَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 9, 'ثُمَّ إِنِّــيَ أَعْلَنتُ لَهُمْ وَأَسْرَرْتُ لَهُمُ; إِسْرَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 10, 'فَقُلْتُ èسْتَغْفِرُواْ رَبَّكُمُ; إِنَّهُ„ كَانَ 596 غَفَّاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 11, 'يُرْسِـلِ ۱لسَّمَآءَ عَلَيْكُم مِّدْرَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 12, 'وَيُمْدِدْكُم بِأَمْوَ؛لٍ وَبَنِينَ وَيَجْعَــل لَّكُمْ جَنَّـٰتٍ وَيَجْعَــل لَّكُمُ; أَنْهَـٰراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 13, 'مَّا لَكُمْ لاَ تَرْجُونَ لِلهِ وَقَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 14, 'وَقَدْ خَلَقَكُمُ; أَطْوَاراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 15, 'اَلَمْ تَرَوْاْ كَيْفَ خَلَــقَ ۰للَّهُ سَبْعَ سَمَـٰوَ؛تٍ طِبَاقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 16, 'وَجَعَــلَ ۰لْقَمَرَ فِيهِنَّ نُوراً وَجَعَــلَ ۰لشَّمْسَ سِرَاجاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 17, 'وَاللَّهُ أَنۢبَتَكُم مِّــنَ ۰لاَرْضِ نَبَاتاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 18, 'ثُمَّ يُعِيدُكُمْ فِيهَا وَيُخْرۣجُكُمُ; إِخْرَاجاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 19, 'وَاللَّهُ جَعَلَ لَكُمُ ۴لاَرْضَ بِسَاطاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 20, 'لِّتَسْلُكُواْ مِنْهَا سُبُلًا فِجَاجاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 21, 'قَالَ نُوحٌ رَّبِّ إِنَّهُمْ عَصَوْنِى وَاتَّبَعُواْ مَــن لَّمْ يَزۣدْهُ مَالُهُ„ وَوَلَدُهُ; إِلاَّ خَسَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 22, 'وَمَكَرُواْ مَكْراً كُبَّاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 23, 'وَقَالُواْ لاَ تَذَرُنَّ ءَالِهَتَكُمْ وَلاَ تَذَرُنَّ وُدّاً وَلاَ سُوَاعاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 24, 'وَلاَ يَغُوثَ وَيَعُوقَ وَنَسْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 25, 'وَقَدَ اَضَلُّواْ كَثِيراًؐ وَلاَ تَزۣدِ ۱لظَّـٰلِمِينَ إِلاَّ ضَچَلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 26, 'مِّمَّا خَطِيٓــَٔــٰتِهِمُ; ٱُغْرۣقُواْ فَٱُدْخِلُواْ نَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 27, 'فَلَمْ يَجِدُواْ لَهُم مِّن دُونِ ۱للَّهِ أَنصَاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 28, 'وَقَالَ نُوحٌ رَّبِّ لاَ تَذَرْ 597 عَلَــي ۰لاَرْضِ مِنَ ۰لْكۭـٰفِـرۣيــنَ دَيَّاراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 29, 'اِنَّكَ إِن تَذَرْهُمْ يُضِلُّواْ عِبَادَكَ وَلاَ يَلِدُوٓاْ إِلاَّ فَاجِراً كَفَّاراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (71, 30, 'رَّبِّ ''غْفِرْ لِى وَلِوَ؛لِدَيَّ وَلِمَــن دَخَلَ بَيْتِى مُومِناً وَلِلْمُومِنِينَ وَالْمُومِنَـٰتِؐ وَلاَ تَزۣدِ ۱لظَّـٰلِمِينَ إِلاَّ تَبَاراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قُلُ ۷وحِيَ إِلَــيَّ أَنَّهُ èسْتَمَعَ نَفَرٌ مِّــنَ ۰لْجِنِّ فَقَالُوٓاْ إِنَّا سَمِعْنَا قُرْءَاناٗ عَجَباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 2, 'يَهْدِىٓ إِلَي ۰لرُّشْدِ فَــَٔامَنَّا بِهِ” وَلَــن نُّشْرۣكككَ بِرَبِّنَآ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 3, 'وَإِنَّهُ„ تَعَـٰلۭيٰ جَدُّ رَبِّنَا مَا "تَّخَذَ صَـٰحِبَةً وَلاَ وَلَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 4, 'وَإِنَّهُ„ كَانَ يَقُولُ سَفِيهُنَا عَلَــي ۰للَّهِ شَطَطاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 5, 'وَإِنَّا ظَنَنَّآ أَن لَّن تَقُولَ ۰لِانسُ وَالْجِــنُّ عَلَي ۰للَّهِ كَذِباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 6, 'وَإِنَّهُ„ كَانَ رۣجَالٌ مِّــنَ ۰لِانسِ يَعُوذُونَ بِـرۣجَالٍ مِّنَ ۰لْجِنِّ فَزَادُوهُمْ رَهَقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 7, 'وَإِنَّهُمْ ظَنُّواْ كَمَا ظَنَنتُمُ; أَن لَّنْ يَّبْعَثَ ۰للَّهُ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 8, 'وَإِنَّا لَمَسْنَا ۰لسَّمَآءَ فَوَجَدْنَـٰهَا مُلِيؕتْ حَرَساً 598 شَدِيداً وَشُهُباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 9, 'وَإِنَّا كُنَّا نَقْعُدُ مِنْهَا مَقَـٰعِدَ لِلسَّمْعِ فَمَـنْ يَّسْتَمِعِ ۱لاَنَ يَجِدْ لَهُ„ شِهَاباً رَّصَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 10, 'وَإِنَّا لاَ نَدْرۣىٓ أَشَرّﹲ ۷رۣيدَ بِمَن فِى ۱لاَرْضِ أَمَ اَرَادَ بِهِمْ رَبُّهُمْ رَشَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 11, 'وَإِنَّا مِنَّا ۰ڤصَّـٰڤِحُونَ وَمِنَّا دُونَ ذَ؛لِــكَؐ كُنَّا طَرَآئِـقَ قِدَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 12, 'وَإِنَّا ظَنَنَّآ أَن لَّن نُّعْجِزَ ۰للَّهَ فِى ۱لاَرْضِ وَلَــن نُّعْجِزَهُ„ هَرَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 13, 'وَإِنَّا لَمَّا سَمِعْنَا ۰لْهُدۭيٰٓ ءَامَنَّا بِهِؐ” فَمَنْ يُّومِنۢ بِرَبِّهِ” فَلاَ يَخَافُ بَخْساً وَلاَ رَهَـقاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 14, 'وَإِنَّا مِنَّا ۰لْمُسْلِمُونَ وَمِنَّا ۰لْقَـٰسِطُونَؐ فَمَنَ اَسْلَمَ فَٱُوْلَئِــكَ تَحَرَّوْاْ رَشَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 15, 'وَأَمَّا ۰لْقَـٰسِطُونَ فَكَانُواْ لِجَهَنَّمَ حَطَباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 16, 'وَأَن لَّوۣ ''سْتَقَـٰمُواْ عَلَــي ۰لطَّرۣيقَةِ لَأَسْقَيْنَـٰهُم مَّآءٗ غَدَقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 17, 'لِّنَفْتِنَهُمْ فِيهِؐ وَمَنْ يُّعْرۣضضضْ عَن ذِكْرۣ رَبِّهِ” نَسْلُكْهُ عَذَاباً صَعَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 18, 'وَأَنَّ ۰ڤْمَسَـٰجِدَ لِلهِ فَلاَ تَدْعُواْ مَعَ ۰للَّهِ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 19, 'وَإِنَّهُ„ لَمَّا قَامَ عَبْدُ ۴للَّهِ يَدْعُوهُ كَادُواْ يَكُونُونَ عَلَيْهِ لِبَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 20, 'قَالَ إِنَّمَآ أَدْعُواْ رَبِّى وَلآَ ٱُشْرۣكككُ بِهِ“ أَحَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 21, 'قُـلِ اِنِّى لآَ أَمْلِــكُ لَكُمْ ضَرّاً 599 وَلاَ رَشَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 22, 'قُـلِ اِنِّى لَنْ يُّجِيرَنِى مِــنَ ۰للَّهِ أَحَدٌ وَلَنَ اَجِدَ مِن دُونِهِ” مُڤْتَحَداٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 23, 'اِلاَّ بَچَغاً مِّــنَ ۰للَّهِ وَرۣسَـٰچَتِهِؐ”  وَمَنْ يَّعْـصِ ۱للَّهَ وَرَسُولَهُ„ فَإِنَّ لَهُ„ نَارَ جَهَنَّمَ خَـٰلِدِينَ فِيهَآ أَبَداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 24, 'حَتَّـيٰٓ إِذَا رَأَوْاْ مَا يُوعَدُونَ فَسَيَعْلَمُونَ مَــنَ اَضْعَفُ نَاصِراً وَأَقَــلُّ عَدَداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 25, 'قُـلِ اِنَ اَدْرۣىٓ أَقَرۣيبٌ مَّا تُوعَدُونَ أَمْ يَجْعَلُ لَهُ„ رَبِّيَ أَمَداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 26, 'عَـٰلِمُ ۴لْغَيْبِ فَلاَ يُظْهِرُ عَلَيٰ غَيْبِهِ“ أَحَداٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 27, 'اِلاَّ مَنِ ''رْتَضۭيٰ مِن رَّسُولٍ فَإِنَّهُ„ يَسْلُــكُ مِنۢ بَيْـنِ يَدَيْهِ وَمِــنْ خَلْفِهِ” رَصَداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (72, 28, 'لِّيَعْلَمَ أَننن قَدَ اَبْلَغُواْ رۣسَـٰچَتِ رَبِّهِمْ وَأَحَاطَ بِمَا لَدَيْهِمْ وَأَحْصۭــيٰ كُلَّ شَيْءٖ عَدَداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا ۰لْمُزَّمِّلُ قُمِ ۱ليْـلَ إِلاَّ قَلِيلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 2, 'نِّصْفَهُ; أَوُ ۶نقُـصْ مِنْهُ قَلِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 3, 'اَوْ زۣدْ عَلَيْهِ وَرَتِّـلِ ۱لْقُرْءَانَ تَرْتِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 4, 'اِنَّا سَنُلْقِى عَلَيْــكَ قَوْلًا ثَقِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 5, 'اِنَّ نَاشِيؕةَ ۰ليْلِ هِيَ أَشَدُّ وَطْـٔاً وَأَقْوَمُ قِيلٗؐا 600');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 6, 'اِنَّ لَكَ فِى ۱لنَّهۭارۣ سَبْحاً طَوۣيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 7, 'وَاذْكُرۣ ''سْمَ رَبِّكَ وَتَبَتَّلِ اِلَيْهِ تَبْتِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 8, 'رَّبُّ ۴لْمَشْرۣقِ وَالْمَغْرۣبِؐ لآَ إِچَهَ إِلاَّ هُوَؐ فَاتَّخِذْهُ وَكِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 9, 'وَاصْبِرْ عَلَــيٰ مَا يَقُولُونَؐ وَاهْجُرْهُمْ هَجْراً جَمِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 10, 'وَذَرْنِى وَالْمُكَذِّبِينَ ٱُوْلِى ۱لنَّعْمَةِ وَمَهِّلْهُمْ قَلِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 11, 'اِنَّ لَدَيْنَآ أَنكَالًا وَجَحِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 12, 'وَطَعَاماً ذَا غُصَّةٍ وَعَذَاباٗ اَلِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 13, 'يَوْمَ تَرْجُفُ ۴لاَرْضُ وَالْجِبَالُ وَكَانَتِ ۱لْجِبَالُ كَثِيباً مَّهِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 14, 'اِنَّـآ أَرْسَلْنَآ إِلَيْكُمْ رَسُولًا شَـٰهِداٗ عَلَيْكُمْ كَمَآ أَرْسَلْنَآ إِلَيٰ فِرْعَوْنَ رَسُولًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 15, 'فَعَصۭيٰ فِرْعَوْنُ ۴لرَّسُولَ فَأَخَذْنَـٰهُ أَخْذاً وَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 16, 'فَكَيْفَ تَتَّقُونَ إِن كَفَرْتُمْ يَوْماً يَجْعَلُ ۴لْوۣلْدَ؛نَ شِيباٗ ۱لسَّمَآءُ مُنفَطِرٛ بِهِؐ” كَانَ وَعْدُهُ„ مَفْعُولٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 17, 'اِنَّ هَـٰذِهِ” تَذْكِرَةٌؐ فَمَــن شَآءَ "تَّخَذَ إِلَيٰ رَبِّهِ” سَبِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (73, 18, '© اِنَّ رَبَّكَ يَعْلَمُ أَنَّكَ تَقُومُ أَدْنۭـيٰ مِن ثُلُثَيِ ۱ليْلِ وَنِصْفِهِ” وَثُلُثِهِ” وَطَآئِفَةٌ مِّنَ ۰لذِيــنَ مَعَكَؐ وَاللَّهُ يُقَدِّرُ ۴ليْلَ وَالنَّهَارَؐ عَلِمَ أَن لَّن 601 تُحْصُوهُ فَتَابَ عَلَيْكُمْؐ فَاقْرَءُواْ مَا تَيَسَّرَ مِنَ ۰لْقُرْءَانِؐ عَلِمَ أَن سَيَكُونُ مِنكُم مَّرْضۭيٰ وَءَاخَرُونَ يَضْرۣبُونَ فِى ۱لاَرْضِ يَبْتَغُونَ مِن فَضْـلِ ۱للَّهِ وَءَاخَرُونَ يُقَـٰتِلُونَ فِى سَبِيـلِ ۱للَّهِؐ فَاقْرَءُواْ مَا تَيَسَّرَ مِنْهُؐ وَأَقِيمُواْ ۴لصَّلَوٰةَ وَءَاتُواْ ۴لزَّكَوٰةَؐ وَأَقْرۣضُواْ ۴للَّهَ قَرْضاٗ حَسَناًؐ وَمَا تُقَدِّمُواْ لَأِنفُسِكُم مِّنْ خَيْرٍ تَجِدُوهُ عِندَ ۰للَّهِ هُوَ خَيْراً وَأَعْظَمَ أَجْراًؐ وَاسْتَغْفِرُواْ ۴للَّهَؐ إِنننَّ ۰للَّهَ غَفُورٌ رَّحِيمٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ يَـٰٓأَيُّهَا ۰لْمُدَّثِّرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 2, 'قُمْ فَأَنذِرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 3, 'وَرَبَّــكَ فَكَبِّرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 4, 'وَثِيَابَــكَ فَطَهِّرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 5, 'وَالرّۣجْزَ فَاهْجُرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 6, 'وَلاَ تَمْنُــن تَسْتَكْثِرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 7, 'وَلِرَبِّــكَ فَاصْبِرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 8, 'فَإِذَا نُقِرَ فِى ۱لنَّاقُورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 9, 'فَذَ؛لِــكَ يَوْمَئِذٍ يَوْم٘ عَسِير٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 10, 'عَلَــي ۰لْكۭـٰفِـرۣينَ غَيْرُ يَسِيرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 11, 'ذَرْنِى وَمَــنْ خَلَقْتُ وَحِيداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 12, 'وَجَعَلْتُ لَهُ„ مَالًا مَّمْدُوداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 13, 'وَبَنِيــنَ شُهُوداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 14, 'وَمَهَّدتُّ لَهُ„ 602 تَمْـهِيـداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 15, 'ثُمَّ يَطْـمَـعُ أَنَ اَزۣيــدَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 16, 'كَـلٓؐاَّ إِنَّهُ, كَـانَ ءَلِايَـٰتِنَــا عَـنِيـداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 17, 'سَٱُرْهِقُـهُ, صَـعُـوداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 18, 'اِنَّهُ, فَكَّرَ وَقَدَّرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 19, 'فَقُتِــلَ كَيْـفَ قَـدَّرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 20, 'ثُمَّ قُـتِـــلَ كَيْـفَ قَدَّرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 21, 'ثُمَّ نَظَرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 22, 'ثُمَّ عَبَسَ وَبَسَرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 23, 'ثُمَّ أَدْبَرَ وَاسْتَكْبَرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 24, 'فَـقَـالَ إِنْ هَـٰـذَآ إِلَّا سِحْــرٌ يُوثَـرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 25, 'إِنْ هَـٰذَآ إِلاَّ قَــوْلُ ۴لْبَشَرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 26, 'سَاءُصْلِيهِ سَقَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 27, 'وَمَآ أَدْرۭيٰژَ مَا سَقَرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 28, 'لاَ تُبْقِى وَلاَ تَذَرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 29, 'لَوَّاحَةٌ لِّلْبَشَرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 30, 'عَلَيْهَا تِسْعَةَ عَشَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 31, 'وَمَا جَعَلْنَآ أَصْحَـٰــبَ ۰لنّۭارۣ إِلاَّ مَلَئِكَةًؐ وَمَا جَعَلْنَا عِدَّتَهُمُ’ إِلاَّ فِتْنَةً لِّلذِيــنَ كَفَرُواْ لِيَسْتَيْقِــنَ ۰لذِينَ اءُوتُواْ ۴لْكِتَـٰبَ وَيَزْدَادَ ۰لذِيــنَ ءَامَنُوٓاْ إِيمَـٰناً وَلاَ يَرْتَابَ ۰لذِينَ اءُوتُواْ ۴لْكِتَـٰبَ وَالْمُومِنُونَ وَلِيَقُولَ ۰لذِينَ فِى قُلُوبِهِم مَّرَضٌ وَالْكَـٰفِرُونَ مَاذَآ أَرَادَ ۰للَّهُ بِهَـٰذَا مَثَلًؐا كَذَ؛لِكَ يُضِلُّ ۴للَّهُ مَنْ يَّشَـﺂءُ وَيَهْدِى مَنْ يَّشَـﺂءُؐ وَمَا يَعْلَمُ جُنُودَ رَبِّژَ إِلاَّ هُوَؐ وَمَا هِيَ إِلاَّ ذِكْرۭيٰ لِلْبَـشَـرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 32, 'كَـلاَّ وَالْقَـمَـرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 33, 'وَاليْلِ إِذَ اَدْبَـرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 34, 'وَالصُّبْحِ إِذَآ أَسْـفَـرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 35, 'إِنَّهَــا 60 لِإَحْدَي ۰لْكُبَرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 36, 'نَذِيراً لِّلْبَشَرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 37, 'لِمَــن شَآءَ مِنكُمُ; أَنْ يَّتَقَدَّمَ أَوْ يَتَأَخَّرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 38, 'كُلُّ نَفْسٙ بِمَا كَسَبَتْ رَهِينَة٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 39, 'اِلٓاَّ أَصْحَـٰبَ ۰لْيَمِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 40, 'فِى جَنَّـٰتٍ يَتَسَآءَلُونَ عَنِ ۱ڤْمُجْرۣمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 41, 'مَا سَلَكَكُمْ فِى سَقَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 42, 'قَالُواْ لَمْ نَــكُ مِنَ ۰لْمُصَلِّينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 43, 'وَلَمْ نَــكُ نُطْعِمُ ۴لْمِسْكِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 44, 'وَكُنَّا نَخُوضُ مَعَ ۰لْخَآئِضِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 45, 'وَكُنَّا نُكَذِّبُ بِيَوْمِ ۱لدِّينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 46, 'حَتَّـيٰٓ أَتۭيٰنَا ۰لْيَقِينُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 47, 'فَمَا تَنفَعُهُمْ شَفَـٰعَةُ ۴لشَّـٰفِعِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 48, 'فَمَا لَهُمْ عَـنِ ۱لتَّذْكِرَةِ مُعْرۣضِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 49, 'كَأَنَّهُمْ حُمُرٌ مُّسْتَنفَرَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 50, 'فَرَّتْ مِــن قَسْوَرَةٙؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 51, 'بَلْ يُرۣيدُ كُلُّ èمْرۣئٍ مِّنْهُمُ; أَنْ يُّوتۭــيٰ صُحُفاً مُّنَشَّرَةًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 52, 'كَلاَّ بَــل لاَّ يَخَافُونَ ۰لاَخِرَةَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 53, 'كَلٓاَّ إِنَّهُ„ تَذْكِرَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 54, 'فَمَــن شَآءَ ذَكَرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (74, 55, 'وَمَا تَذْكُرُونَ إِلٓاَّ أَنْ يَّشَآءَ ۰للَّهُؐ هُوَ أَهْلُ ۴لتَّقْوۭيٰ وَأَهْــلُ ۴لْمَغْفِرَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 1, '604 ¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِؐ لآَ ٱُقْسِمُ بِيَوْمِ ۱لْقِيَـٰمَةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 2, 'وَلآَ ٱُقْسِمُ بِالنَّفْـسِ ۱للَّوَّامَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 3, 'أَيَحْسِبُ ۴لِانسَـٰــنُ أَلَّن نَّجْمَعَ عِظَامَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 4, 'بَلۭــيٰؐ قَـٰدِرۣيــنَ عَلَيٰٓ أَن نُّسَوّۣيَ بَنَانَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 5, 'بَلْ يُرۣيدُ ۴لِانسَـٰــنُ ڤِيَفْجُرَ أَمَامَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 6, 'يَسْـَٔلُ أَيَّانَ يَوْمُ ۴لْقِيَـٰمَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 7, 'فَإِذَا بَرَقَ ۰لْبَصَرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 8, 'وَخَسَفَ ۰لْقَمَرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 9, 'وَجُمِعَ ۰لشَّمْسُ وَالْقَمَرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 10, 'يَقُولُ ۴لِانسَـٰنُ يَوْمَئِذٖ اَيْــنَ ۰لْمَفَرُّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 11, 'كَلاَّ لاَ وَزَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 12, 'إِلَيٰ رَبِّــكَ يَوْمَئِذٖ ۱لْمُسْتَقَرُّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 13, 'يُنَبَّؤُاْ ۴لِانسَـٰنُ يَـوْمَئِذٙ بِمَا قَدَّمَ وَأَخَّرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 14, 'بَلِ ۱لِانسَـٰنُ عَلَـيٰ نَفْسِهِ” بَصِيرَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 15, 'وَلَوَ اَلْقۭــيٰ مَعَاذِيرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 16, 'لاَ تُحَرّۣكككْ بِهِ” لِسَانَــكَ ڤِتَعْجَلَ بِهِؐ“ إِنَّ عَلَيْنَا جَمْعَهُ„ وَقُرْءَانَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 17, 'فَإِذَا قَرَأْنَـٰهُ فَاتَّبِعْ قُرْءَانَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 18, 'ثُمَّ إِنننَّ عَلَيْنَا بَيَانَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 19, 'كَلاَّ بَلْ تُحِبُّونَ ۰لْعَاجِلَةَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 20, 'وَتَذَرُونَ ۰لاَخِرَةَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 21, 'وُجُوهٌ يَوْمَئِذٍ نَّاضِرَة٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 22, 'اِلَيٰ رَبِّهَا نَاظِرَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 23, 'وَوُجُوهٌ يَوْمَئِذٙ بَاسِرَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 24, 'تَظُنُّ أَنْ يُّفْعَلَ بِهَا فَاقِرَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 25, 'كَلٓاَّ إِذَا بَلَغَتِ ۱لتَّرَاقِيَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 26, 'وَقِيلَ مَن رَّاقٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 27, '605 وَظَــنَّ أَنَّهُ ۴لْفِرَاقُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 28, 'وَالْتَفَّتِ ۱لسَّاقُ بِالسَّاقِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 29, 'إِلَيٰ رَبِّكَ يَوْمَئِذٖ ۱لْمَسَاقُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 30, 'فَلاَ صَدَّقَ وَلاَ صَلّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 31, 'وَچَكِــن كَذَّبَ وَتَوَلّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 32, 'ثُمَّ ذَهَبَ إِلَــيٰٓ أَهْلِهِ” يَتَمَطّۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 33, 'أَوْلۭــيٰ لَــكَ فَأَوْلۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 34, 'ثُمَّ أَوْلۭــيٰ لَــكَ فَأَوْلۭـيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 35, 'أَيَحْسِــبُ ۴لِانسَـٰنُ أَنْ يُّتْرَكككَ سُديٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 36, 'اَلَمْ يَــكُ نُطْفَةً مِّن مَّنِــيٍّ تُمْنۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 37, 'ثُمَّ كَانَ عَلَقَةً فَخَلَقَ فَسَوّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 38, 'فَجَعَـلَ مِنْهُ ۴لزَّوْجَيْـنِ ۱لذَّكَرَ وَالاُنثۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (75, 39, 'أَلَيْسَ ذَ؛لِــكَ بِقَـٰدِر۫ عَلَيٰٓ أَنْ يُّحْــيـِيــيَ ۰لْمَوْتۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ هَلَ اَتۭيٰ عَلَي ۰لِانسَـٰنِ حِينٌ مِّــنَ ۰لدَّهْرۣ لَمْ يَكُــن شَيْـٔاً مَّذْكُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 2, 'اِنَّا خَلَقْنَا ۰لِانسَـٰنَ مِــن نُّطْفَةٖ اَمْشَاجٍ نَّبْتَلِيهِ فَجَعَلْنَـٰهُ سَمِيعاَۢ بَصِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 3, 'اِنَّا هَدَيْنَـٰهُ ۴لسَّبِيلَ إِمَّا شَاكِراً وَإِمَّا كَفُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 4, 'اِنَّـآ أَعْتَدْنَا لِلْكۭـٰفِـرۣيــنَ سَچَسِلًا وَأَغْچَلًا وَسَعِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 5, 'اِنَّ ۰لاَبْرَارَ يَشْرَبُونَ مِــن كَأْسسسٍ كَانَ مِزَاجُهَا كَافُوراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 6, 'عَيْناً يَشْرَبُ 606 بِهَا عِبَادُ ۴للَّهِ يُفَجِّرُونَهَا تَفْجِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 7, 'يُوفُونَ بِالنَّذْرۣ وَيَخَافُونَ يَوْماً كَانَ شَرُّهُ„ مُسْتَطِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 8, 'وَيُطْعِمُونَ ۰لطَّعَامَ عَلَــيٰ حُبِّهِ” مِسْكِيناً وَيَتِيماً وَأَسِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 9, 'اِنَّمَا نُطْعِمُكُمْ لِوَجْهِ ۱للَّهِؐ لاَ نُرۣيدُ مِنكُمْ جَزَآءً وَلاَ شُكُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 10, 'اِنَّا نَخَافُ مِن رَّبِّنَا يَوْماٗ عَبُوساً قَمْطَرۣيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 11, 'فَوَقۭيٰهُمُ ۴للَّهُ شَرَّ ذَ؛لِــكَ ۰لْيَوْمِ وَلَقّۭيٰهُمْ نَضْرَةً وَسُرُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 12, 'وَجَزۭيٰهُم بِمَا صَبَرُواْ جَنَّةً وَحَرۣيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 13, 'مُّتَّكِـِٕينَ فِيهَا عَلَــي ۰لاَرَآئِــكِ لاَ يَرَوْنَ فِيهَا شَمْساً وَلاَ زَمْهَرۣيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 14, 'وَدَانِيَةٗ عَلَيْهِمْ ظِچَلُهَا وَذُلِّلَتْ قُطُوفُهَا تَذْلِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 15, 'وَيُطَافُ عَلَيْهِم بِـَٔانِيَةٍ مِّن فِضَّةٍ وَأَكْوَابٍ كَانَتْ قَوَارۣيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 16, 'قَوَارۣيراً مِّن فِضَّةٍ قَدَّرُوهَا تَقْدِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 17, 'وَيُسْقَوْنَ فِيهَا كَأْساً كَانَ مِزَاجُهَا زَنجَبِيلٗا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 18, 'عَيْناً فِيهَا تُسَمّۭيٰ سَلْسَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 19, '© وَيَطُوفُ عَلَيْهِمْ وۣلْدَ؛نٌ مُّخَلَّدُونَ إِذَا رَأَيْتَهُمْ حَسِبْتَهُمْ لُؤْلُؤاً مَّنثُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 20, 'وَإِذَا رَأَيْتَ ثَمَّ رَأَيْتَ نَعِيماً وَمُلْكاً كَبِيراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 21, 'عَـٰلِيهِمْ ثِيَابُ سُندُسٖ 607 خُضْرٌ وَإِسْتَبْرَقٌؐ وَحُلُّوٓاْ أَسَاوۣرَ مِـن فِضَّةٍؐ وَسَقۭيٰهُمْ رَبُّهُمْ شَرَاباً طَهُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 22, 'اِنَّ هَـٰذَا كَانَ لَكُمْ جَزَآءً وَكَانَ سَعْيُكُم مَّشْكُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 23, 'اِنَّا نَحْنُ نَزَّلْنَا عَلَيْكَ ۰لْقُرْءَانَ تَنزۣيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 24, 'فَاصْبِرْ لِحُكْمِ رَبِّــكَ وَلاَ تُطِعْ مِنْهُمُ; ءَاثِماٗ اَوْ كَفُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 25, 'وَاذْكُرۣ ''سْمَ رَبِّــكَ بُكْرَةً وَأَصِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 26, 'وَمِنَ ۰ليْـلِ فَاسْجُدْ لَهُ„ وَسَبِّحْهُ لَيْلًا طَـوۣيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 27, 'اِنَّ هَـٰٓؤُلآَءِ يُحِبُّونَ ۰لْعَاجِلَةَ وَيَذَرُونَ وَرَآءَهُمْ يَوْماً ثَقِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 28, 'نَّحْــنُ خَلَقْنَـٰهُمْ وَشَدَدْنَآ أَسْرَهُمْ وَإِذَا شِيؔنَا بَدَّلْنَآ أَمْثَـٰلَهُمْ تَبْدِيلٗؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 29, 'اِنَّ هَـٰذِهِ” تَذْكِرَةٌؐ فَمَــن شَآءَ "تَّخَذَ إِلَيٰ رَبِّهِ” سَبِيلًؐا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 30, 'وَمَا تَشَآءُونَ إِلٓاَّ أَنْ يَّشَآءَ ۰للَّهُؐ إِنَّ ۰للَّهَ كَانَ عَلِيماٗ حَكِيماًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (76, 31, 'يُدْخِلُ مَنْ يَّشَآءُ فِى رَحْمَتِهِؐ” وَالظَّـٰلِمِيــنَ أَعَدَّ لَهُمْ عَذَاباٗ اَلِيماً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالْمُرْسَچَتِ عُرْفاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 2, '608 فَالْعَـٰصِفَـٰتِ عَصْفاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 3, 'وَالنَّـٰشِرَ؛تِ نَشْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 4, 'فَالْفَـٰرۣقَـٰتِ فَرْقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 5, 'فَالْمُلْقِيَـٰتِ ذِكْراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 6, 'عُذْراٗ اَوْ نُذُراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 7, 'اِنَّمَا تُوعَدُونَ لَوَ؛قِعٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 8, 'فَإِذَا ۰ڤنُّجُومُ طُمِسَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 9, 'وَإِذَا ۰لسَّمَآءُ فُرۣجَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 10, 'وَإِذَا ۰لْجِبَالُ نُسِفَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 11, 'وَإِذَا ۰لرُّسُلُ ٱُقِّتَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 12, 'لَأِيِّ يَوْمٖ ۷جِّلَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 13, 'لِيَوْمِ ۱لْفَصْلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 14, 'وَمَآ أَدْرۭيٰــكَ مَا يَوْمُ ۴لْفَصْلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 15, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 16, 'أَلَمْ نُهْلِــكِ ۱لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 17, 'ثُمَّ نُتْبِعُهُمُ ۴لاَخِرۣينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 18, 'كَذَ؛لِــكَ نَفْعَلُ بِاڤْمُجْرۣمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 19, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 20, 'أَلَمْ نَخْلُقكُّم مِّــن مَّآءٍ مَّهِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 21, 'فَجَعَلْنَـٰهُ فِى قَرۭارٍ مَّكِينٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 22, 'اِلَــيٰ قَدَرٍ مَّعْلُومٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 23, 'فَقَدَّرْنَاؐ فَنِعْمَ ۰لْقَـٰدِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 24, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 25, 'أَلَمْ نَجْعَـلِ ۱لاَرْضَ كِفَاتاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 26, 'اَحْيَآءً وَأَمْوَ؛تاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 27, 'وَجَعَلْنَا فِيهَا رَوَ؛سِيَ شَـٰمِخَـٰتٍ وَأَسْقَيْنَـٰكُم مَّآءً فُرَاتاًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 28, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 29, '"نطَلِقُوٓاْ إِلَــيٰ مَا كُنتُم بِهِ” تُكَذِّبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 30, '"نطَلِقُوٓاْ إِلَيٰ ظِلٍّ ذى ثَـچَثِ شُعَبٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 31, 'لاَّ ظَلِيلٍ 609 وَلاَ يُغْنِى مِــنَ ۰للَّهَبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 32, 'إِنَّهَا تَرْمِى بِشَرَرٍ كَالْقَصْرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 33, 'كَأَنَّهُ„ جِمَـٰچَتٌ صُفْرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 34, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 35, 'هَـٰذَا يَوْمُ لاَ يَنطِقُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 36, 'وَلاَ يُوذَنُ لَهُمْ فَيَعْتَذِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 37, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 38, 'هَـٰذَا يَوْمُ ۴لْفَصْـلِ جَمَعْنَـٰكُمْ وَالاَوَّلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 39, 'فَإِن كَانَ لَكُمْ كَيْدٌ فَكِيدُونِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 40, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 41, 'إِنننَّ ۰لْمُتَّقِينَ فِى ظِچَلٍ وَعُيُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 42, 'وَفَوَ؛كِهَ مِمَّا يَشْتَهُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 43, 'كُلُواْ وَاشْرَبُواْؐ هَنِيٓـٔاَۢ بِمَا كُنتُمْ تَعْمَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 44, 'إِنَّا كَذَ؛لِــكَ نَجْزۣى ۱ڤْمُحْسِنِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 45, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 46, 'كُلُواْ وَتَمَتَّعُواْ قَلِيلٗا اِنَّكُم مُّجْرۣمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 47, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 48, 'وَإِذَا قِيــلَ لَهُمُ èرْكَعُواْ لاَ يَرْكَعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 49, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (77, 50, 'فَبِأَيِّ حَدِيثٙ بَعْدَهُ„ يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ عَمَّؐ يَتَسَآءَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 2, 'عَـنِ ۱لنَّبَإِ 610 ۱لْعَظِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 3, '۱ﻟ﮲ هُمْ فِيهِ مُخْتَلِفُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 4, 'كَلاَّ سَيَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 5, 'ثُمَّ كَلاَّ سَيَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 6, 'أَلَمْ نَجْعَلِ ۱لاَرْضَ مِهَـٰداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 7, 'وَالْجِبَالَ أَوْتَاداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 8, 'وَخَلَقْنَـٰكُمُ; أَزْوَ؛جاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 9, 'وَجَعَلْنَا نَوْمَكُمْ سُبَاتاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 10, 'وَجَعَلْنَا ۰ليْلَ لِبَاساً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 11, 'وَجَعَلْنَا ۰لنَّهَارَ مَعَاشاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 12, 'وَبَنَيْنَا فَوْقَكُمْ سَبْعاً شِدَاداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 13, 'وَجَعَلْنَا سِرَاجاً وَهَّاجاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 14, 'وَأَنزَلْنَا مِــنَ ۰لْمُعْصِرَ؛تِ مَآءً ثَجَّاجاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 15, 'ڤِّنُخْرۣجَ بِهِ” حَبّاً وَنَبَاتاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 16, 'وَجَنَّـٰتٖ اَلْفَافاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 17, 'اِنَّ يَوْمَ ۰لْفَصْــلۣ كَانَ مِيقَـٰتاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 18, 'يَوْمَ يُنفَخُ فِى ۱لصُّورۣ فَتَاتُونَ أَفْوَاجاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 19, 'وَفُتِّحَتِ ۱لسَّمَآءُ فَكَانَتَ اَبْوَ؛باً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 20, 'وَسُيِّرَتِ ۱لْجِبَالُ فَكَانَتْ سَرَاباٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 21, 'اِنَّ جَهَنَّمَ كَانَتْ مِرْصَاداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 22, 'لِّلطَّـٰغِيــنَ مَـَٔاباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 23, 'چَّـبِثِينَ فِيهَآ أَحْقَاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 24, 'لاَّ يَذُوقُونَ فِيهَا بَرْداً وَلاَ شَرَاباٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 25, 'اِلاَّ حَمِيماً وَغَسَاقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 26, 'جَزَآءً وۣفَاقاٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 27, 'اِنَّهُمْ كَانُواْ لاَ يَرْجُونَ حِسَاباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 28, 'وَكَذَّبُواْ بِـَٔايَـٰتِنَا كِذَّاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 29, 'وَكُلَّ شَيْءٖ اَحْصَيْنَـٰهُ كِتَـٰباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 30, 'فَذُوقُواْ 611 فَلَن نَّزۣيدَكُمُ; إِلاَّ عَذَاباٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 31, 'اِنَّ لِلْمُتَّقِيــنَ مَفَازاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 32, 'حَدَآئِقَ وَأَعْنَـٰباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 33, 'وَكَوَاعِبَ أَتْرَاباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 34, 'وَكَأْساً دِهَاقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 35, 'لاَّ يَسْمَعُونَ فِيهَا لَغْواً وَلاَ كِذَّاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 36, 'جَزَآءً مِّن رَّبِّــكَ عَطَآءٗ حِسَاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 37, 'رَّبُّ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِ وَمَا بَيْنَهُمَاؐ ۰لرَّحْمَـٰــنُ لاَ يَمْلِكُونَ مِنْهُ خِطَاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 38, 'يَوْمَ يَقُومُ ۴لرُّوحُ وَالْمَلَئِكَةُ صَفّاً لاَّ يَتَكَلَّمُونَ إِلاَّ مَــنَ اَذِنَ لَهُ ۴لرَّحْمَـٰنُ وَقَالَ صَوَاباًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 39, 'ذَ؛لِكَ ۰لْيَوْمُ ۴لْحَقُّؐ فَمَــن شَآءَ "تَّخَذَ إِلَيٰ رَبِّهِ” مَـَٔاباٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (78, 40, 'اِنَّآ أَنذَرْنَـٰكُمْ عَذَاباً قَرۣيباً يَوْمَ يَنظُرُ ۴لْمَرْءُ مَا قَدَّمَــتْ يَدَ؛هُ وَيَقُولُ ۴لْكَافِرُ يَـٰلَيْتَنِى كُنتُ تُرَ؛باً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالنَّـٰزۣعَـٰتِ غَرْقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 2, 'وَالنَّـٰشِطَـٰتِ نَشْطاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 3, 'وَاڤسَّـٰبِحَـٰتِ سَبْحاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 4, 'فَالسَّـٰبِقَـٰتِ سَبْقاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 5, 'فَالْمُدَبِّرَ؛تِ أَمْراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 6, 'يَوْمَ تَرْجُفُ 612 ۴لرَّاجِفَةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 7, 'تَتْبَعُهَا ۰لرَّادِفَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 8, 'قُلُوبٌ يَوْمَئِذٍ وَاجِفَة٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 9, 'اَبْصَـٰرُهَا خَـٰشِعَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 10, 'يَقُولُونَ أَ.نَّا لَمَرْدُودُونَ فِى ۱لْحَافِرَةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 11, 'إِذَا كُنَّا عِظَـٰماً نَّخِرَةًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 12, 'قَالُواْ تِلْــكَ إِذاً كَرَّة٘ خَاسِرَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 13, 'فَإِنَّمَا هِيَ زَجْرَةٌ وَ؛حِدَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 14, 'فَإِذَا هُم بِالسَّاهِرَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 15, 'هَلَ اَتۭيٰــكَ حَدِيثُ مُوسۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 16, 'إِذْ نَادۭيٰهُ رَبُّهُ„ بِالْوَادِ ۱لْمُقَدَّسسسِ طُوَيؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 17, '"ذْهَبِ اِلَيٰ فِرْعَوْنَ إِنَّهُ„ طَغۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 18, 'فَقُلْ هَل لَّــكَ إِلَـيٰٓ أَن تَزَّكّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 19, 'وَأَهْدِيَــكَ إِلَيٰ رَبِّــكَ فَتَخْشۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 20, 'فَأَرۭيٰهُ ۴لاَيَةَ ۰لْكُبْرۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 21, 'فَكَذَّبَ وَعَصۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 22, 'ثُمَّ أَدْبَرَ يَسْعۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 23, 'فَحَشَرَ فَنَادۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 24, 'فَقَالَ أَنَا رَبُّكُمُ ۴لاَعْلۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 25, 'فَأَخَذَهُ ۴للَّهُ نَكَالَ ۰لاَخِرَةِ وَالاُولۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 26, 'إِنَّ فِى ذَ؛لِكَ لَعِبْرَةً لِّمَنْ يَّخْشۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 27, 'ءَآنتُمُ; أَشَدُّ خَلْقاٗ اَمِ ۱لسَّمَآءُؐ بَنَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 28, 'رَفَعَ سَمْكَهَا فَسَوَّيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 29, 'وَأَغْطَشَ لَيْلَهَا وَأَخْرَجَ ضُحَيٰهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 30, 'وَالاَرْضضضَ بَعْدَ ذَ؛لِــكَ دَحَيٰهَآ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 31, 'أَخْرَجَ مِنْهَا مَآءَهَا وَمَرْعَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 32, 'وَالْجِبَالَ أَرْسَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 33, '61 مَتَـٰعاً لَّكُمْ وَلَأِنْعَـٰمِكُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 34, 'فَإِذَا جَآءَتِ ۱لطَّآمَّةُ ۴لْكُبْرۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 35, 'يَوْمَ يَتَذَكَّرُ ۴لِانسَـٰــنُ مَا سَعۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 36, 'وَبُرّۣزَتِ ۱لْجَحِيمُ لِمَنْ يَّرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 37, 'فَأَمَّا مَــن طَغۭيٰ وَءَاثَرَ ۰لْحَيَوٰةَ ۰لدُّنْيۭا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 38, 'فَإِنَّ ۰لْجَحِيمَ هِــيَ ۰لْمَأْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 39, 'وَأَمَّا مَــنْ خَافَ مَقَامَ رَبِّهِ” وَنَهَــي ۰لنَّفْسَ عَنِ ۱لْهَوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 40, 'فَإِنَّ ۰لْجَنَّةَ هِيَ ۰لْمَأْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 41, '© يَسْـَٔلُونَــكَ عَـنِ ۱لسَّاعَةِ أَيَّانَ مُرْسَيٰهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 42, 'فِيمَ أَنتَ مِــن ذِكْرۭيٰهَآؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 43, 'إِلَيٰ رَبِّكَ مُنتَهَيٰهَآؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 44, 'إِنَّمَآ أَنتَ مُنذِرُ مَــنْ يَّخْشَيٰهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (79, 45, 'كَأَنَّهُمْ يَوْمَ يَرَوْنَهَا لَمْ يَلْبَثُوٓاْ إِلاَّ عَشِيَّةٗ اَوْ ضُحَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ عَبَسَ وَتَوَلّۭـيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 2, 'أَن جَآءَهُ ۴لاَعْمۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 3, 'وَمَا يُدْرۣيــكَؐ لَعَلَّهُ„ يَزَّكّۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 4, 'أَوْ يَذَّكَّرُ فَتَنفَعُهُ ۴لذِّكْرۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 5, 'أَمَّا مَنِ ''سْتَغْنۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 6, 'فَأَنتَ لَهُ„ تَصَّدّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 7, 'وَمَا عَلَيْــكَ أَلاَّ يَزَّكّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 8, 'وَأَمَّا مَن جَآءَكككَ 614 يَسْعۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 9, 'وَهُوَ يَخْشۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 10, 'فَأَنتَ عَنْهُ تَلَهّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 11, 'كَلٓؐاَّ إِنَّهَا تَذْكِرَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 12, 'فَمَــن شَآءَ ذَكَرَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 13, 'فِى صُحُفٍ مُّكَرَّمَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 14, 'مَّرْفُوعَةٍ مُّطَهَّرَةٙ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 15, 'بِأَيْدِى سَفَرَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 16, 'كِرَامٙ بَرَرَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 17, 'قُتِلَ ۰لِانسَـٰــنُ مَآ أَكْفَرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 18, 'مِنَ اَيِّ شَيْءٖ خَلَقَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 19, 'مِــن نُّطْفَةٖ خَلَقَهُ„ فَقَدَّرَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 20, 'ثُمَّ ۰لسَّبِيلَ يَسَّرَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 21, 'ثُمَّ أَمَاتَهُ„ فَأَقْبَرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 22, 'ثُمَّ إِذَا شَآءَ انشَرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 23, 'كَلاَّ لَمَّا يَقْــضِ مَآ أَمَرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 24, 'فَلْيَنظُرۣ ۱لِانسَـٰنُ إِلَيٰ طَعَامِهِؐ“');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 25, 'إِنَّا صَبَبْنَا ۰لْمَآءَ صَبّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 26, 'ثُمَّ شَقَقْنَا ۰لاَرْضضضَ شَقّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 27, 'فَأَنۢبَتْنَا فِيهَا حَبّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 28, 'وَعِنَباً وَقَضْباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 29, 'وَزَيْتُوناً وَنَخْلًا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 30, 'وَحَدَآئِــقَ غُلْباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 31, 'وَفَـٰكِهَةً وَأَبّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 32, 'مَّتَـٰعاً لَّكُمْ وَلَأِنْعَـٰمِكُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 33, 'فَإِذَا جَآءَتِ ۱لصَّآخَّةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 34, 'يَوْمَ يَفِرُّ ۴لْمَرْءُ مِنَ اَخِيهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 35, 'وَٱُمِّهِ” وَأَبِيهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 36, 'وَصَـٰحِبَتِهِ” وَبَنِيهِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 37, 'لِكُلِّ ''مْرۣئٍ مِّنْهُمْ يَوْمَئِذٍ شَأْنٌ يُغْنِيهِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 38, 'وُجُوهٌ يَوْمَئِذٍ مُّسْفِرَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 39, 'ضَاحِكَةٌ مُّسْتَبْشِرَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 40, 'وَوُجُوهٌ يَوْمَئِذٖ عَلَيْهَا غَبَرَةٌ 615');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 41, 'تَرْهَقُهَا قَتَرَة٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (80, 42, '۷وْلَئِــكَ هُمُ ۴لْكَفَرَةُ ۴لْفَجَرَةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا ۰لشَّمْــسُ كُوّۣرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 2, 'وَإِذَا ۰ڤنُّجُومُ èنكَدَرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 3, 'وَإِذَا ۰لْجِبَالُ سُيِّرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 4, 'وَإِذَا ۰لْعِشَارُ عُطِّلَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 5, 'وَإِذَا ۰لْوُحُوشُ حُشِرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 6, 'وَإِذَا ۰ڤْبِحَارُ سُجِّرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 7, 'وَإِذَا ۰لنُّفُوسُ زُوّۣجَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 8, 'وَإِذَا ۰لْمَوْءُﹼدَةُ سُــئِــلَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 9, 'بِأَيِّ ذَنۢـــبٍ قُتِلَــــتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 10, 'وَإِذَا ۰ڤصُّحُفُ نُشِرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 11, 'وَإِذَا ۰لسَّمَآءُ كُشِطَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 12, 'وَإِذَا ۰لْجَحِيمُ سُعِّرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 13, 'وَإِذَا ۰لْجَنَّةُ ٱُزْلِفَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 14, 'عَلِمَتْ نَفْــسٌ مَّآ أَحْضَرَتْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 15, 'فَلآَ ٱُقْسِمُ بِالْخُنَّسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 16, '۱لْجَوَارۣ ۱لْكُنَّسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 17, 'وَاليْلِ إِذَا عَسْعَسَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 18, 'وَاڤصُّبْحِ إِذَا تَنَفَّسَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 19, 'إِنَّهُ„ لَقَوْلُ رَسُولٍ كَرۣيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 20, 'ذى قُوَّةٖ عِندَ ذى ۱لْعَرْشِ مَكِينٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 21, 'مُّطَاعٍ ثَمَّ أَمِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 22, 'وَمَا صَـٰحِبُكُم بِمَجْنُونٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 23, 'وَلَقَدْ رۭءۭاهُ بِالاُفُـقِ ۱لْمُبِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 24, 'وَمَا هُوَ عَلَــي ۰لْغَيْبِ 616 بِضَنِينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 25, 'وَمَا هُوَ بِقَوْلِ شَيْطَـٰنٍ رَّجِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 26, 'فَأَيْنَ تَذْهَبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 27, 'إِنْ هُوَ إِلاَّ ذِكْرٌ لِّلْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 28, 'لِمَــن شَآءَ مِنكُمُ; أَنْ يَّسْتَقِيمَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (81, 29, 'وَمَا تَشَآءُونَ إِلٓاَّ أَنْ يَّشَآءَ ۰للَّهُ رَبُّ ۴لْعَـٰلَمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا ۰لسَّمَآءُ èنفَطَرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 2, 'وَإِذَا ۰لْكَوَاكِبُ èنتَثَرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 3, 'وَإِذَا ۰ڤْبِحَارُ فُجِّرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 4, 'وَإِذَا ۰لْقُبُورُ بُعْثِرَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 5, 'عَلِمَتْ نَفْــسٌ مَّا قَدَّمَتْ وَأَخَّرَتْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 6, 'يَـٰٓأَيُّهَا ۰لِانسَـٰــنُ مَا غَرَّكككَ بِرَبِّــكَ ۰لْكَرۣيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 7, '۱ﻟ﮲ خَلَقَــكَ فَسَوّۭيٰــكَ فَعَدَّلَــكَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 8, 'فِىٓ أَيِّ صُورَةٍ مَّا شَآءَ رَكَّبَــكَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 9, 'كَلاَّ بَــلْ تُكَذِّبُونَ بِالدِّينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 10, 'وَإِنَّ عَلَيْكُمْ لَحَـٰفِظِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 11, 'كِرَاماً كَـٰتِبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 12, 'يَعْلَمُونَ مَا تَفْعَلُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 13, 'إِنَّ ۰لاَبْرَارَ لَفِى نَعِيمٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 14, 'وَإِنَّ ۰ڤْفُجَّارَ لَفِى جَحِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 15, 'يَصْلَوْنَهَا يَوْمَ ۰لدِّينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 16, 'وَمَا هُمْ عَنْهَا بِغَآئِبِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 17, 'وَمَآ أَدْرۭيٰــكَ مَا يَوْمُ ۴لدِّينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 18, 'ثُمَّ مَآ أَدْرۭيٰــكَ مَا يَوْمُ ۴لدِّينِؐ 617');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (82, 19, 'يَوْمَ لاَ تَمْلِــكُ نَفْسٌ لِّنَفْـسٍ شَيْـٔاًؐ وَالاَمْرُ يَوْمَئِذٍ لِّلهِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِؐ وَيْــلٌ لِّلْمُطَفِّفِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 2, '۰لذِيــنَ إِذَا "كْتَالُواْ عَلَــي ۰لنَّاسسسِ يَسْتَوْفُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 3, 'وَإِذَا كَالُوهُمُ; أَو وَّزَنُوهُمْ يُخْسِرُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 4, 'أَلاَ يَظُنُّ ٱُوْلَئِــكَ أَنَّهُم مَّبْعُوثُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 5, 'لِيَوْمٖ عَظِيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 6, 'يَوْمَ يَقُومُ ۴لنَّاسُ لِرَبِّ ۱لْعَـٰلَمِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 7, 'كَلٓاَّ إِنَّ كِتَـٰبَ ۰ڤْفُجّۭارۣ لَفِى سِجِّينٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 8, 'وَمَآ أَدْرۭيٰكَ مَا سِجِّينٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 9, 'كِتَـٰبٌ مَّرْقُومٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 10, 'وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 11, '۰لذِينَ يُكَذِّبُونَ بِيَوْمِ ۱لدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 12, 'وَمَا يُكَذِّبُ بِهِ“ إِلاَّ كُــلُّ مُعْتَدٖ اَثِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 13, 'اِذَا تُتْلۭــيٰ عَلَيْهِ ءَايَـٰتُنَا قَالَ أَسَـٰطِيرُ ۴لاَوَّلِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 14, 'كَلاَّ بَل رَّانَ عَلَــيٰ قُلُوبِهِم مَّا كَانُواْ يَكْسِبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 15, 'كَلٓاَّ إِنَّهُمْ عَن رَّبِّهِمْ يَوْمَئِذٍ ڤَّمَحْجُوبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 16, 'ثُمَّ إِنَّهُمْ لَصَالُواْ ۴لْجَحِيمِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 17, 'ثُمَّ يُقَالُ هَـٰذَا ۰ﻟ﮲ كُنتُم بِهِ” تُكَذِّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 18, 'كَلٓاَّ إِنَّ كِتَـٰبَ 618 ۰لاَبْرۭارۣ لَفِى عِلِّيِّينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 19, 'وَمَآ أَدْرۭيٰــكَ مَا عِلِّيُّونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 20, 'كِتَـٰبٌ مَّرْقُومٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 21, 'يَشْهَدُهُ ۴لْمُقَرَّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 22, 'إِنَّ ۰لاَبْرَارَ لَفِى نَعِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 23, 'عَلَــي ۰لاَرَآئِــكِ يَنظُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 24, 'تَعْرۣفُ فِى وُجُوهِهِمْ نَضْرَةَ ۰لنَّعِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 25, 'يُسْقَوْنَ مِن رَّحِيقٍ مَّخْتُومٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 26, 'خِتَـٰمُهُ„ مِسْكٌؐ وَفِى ذَ؛لِــكَ فَلْيَتَنَافَـسِ ۱لْمُتَنَـٰفِسُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 27, 'وَمِزَاجُهُ„ مِــن تَسْنِيمٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 28, 'عَيْناً يَشْرَبُ بِهَا ۰لْمُقَرَّبُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 29, 'إِنَّ ۰لذِينَ أَجْرَمُواْ كَانُواْ مِــنَ ۰لذِيــنَ ءَامَنُواْ يَضْحَكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 30, 'وَإِذَا مَرُّواْ بِهِمْ يَتَغَامَزُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 31, 'وَإِذَا "نقَلَبُوٓاْ إِلَيٰٓ أَهْلِهِمُ èنقَلَبُواْ فَـٰكِهِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 32, 'وَإِذَا رَأَوْهُمْ قَالُوٓاْ إِنَّ هَـٰٓؤُلآَءِ لَضَآلُّونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 33, 'وَمَآ ٱُرْسِلُواْ عَلَيْهِمْ حَـٰفِظِينَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 34, 'فَالْيَوْمَ ۰لذِيــنَ ءَامَنُواْ مِــنَ ۰لْكُفّۭارۣ يَضْحَكُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 35, 'عَلَــي ۰لاَرَآئِــكِؐ يَنظُرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (83, 36, 'هَلْ ثُوّۣبَ ۰لْكُفَّارُ مَا كَانُواْ يَفْعَلُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا ۰لسَّمَآءُ èنشَقَّتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 2, 'وَأَذِنَتْ 619 لِرَبِّهَا وَحُقَّتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 3, 'وَإِذَا ۰لاَرْضضضُ مُدَّتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 4, 'وَأَلْقَتْ مَا فِيهَا وَتَخَلَّتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 5, 'وَأَذِنَتْ لِرَبِّهَا وَحُقَّتْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 6, 'يَـٰٓأَيُّهَا ۰لِانسَـٰنُ إِنَّــكَ كَادِح٘ اِلَيٰ رَبِّــكَ كَدْحاً فَمُچَقِيهِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 7, 'فَأَمَّا مَنُ ۷وتِيَ كِتَـٰبَهُ„ بِيَمِينِهِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 8, 'فَسَوْفَ يُحَاسَبُ حِسَاباً يَسِيراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 9, 'وَيَنقَلِبُ إِلَــيٰٓ أَهْلِهِ” مَسْرُوراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 10, 'وَأَمَّا مَنُ ۷وتِيَ كِتَـٰبَهُ„ وَرَآءَ ظَهْرۣهِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 11, 'فَسَوْفَ يَدْعُواْ ثُبُوراً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 12, 'وَيُصَلَّــيٰ سَعِيراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 13, 'اِنَّهُ„ كَانَ فِىٓ أَهْلِهِ” مَسْرُوراٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 14, 'اِنَّهُ„ ظَنَّ أَن لَّــنْ يَّحُورَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 15, 'بَلۭيٰٓؐ إِنَّ رَبَّهُ„ كَانَ بِهِ” بَصِيراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 16, '© فَلآَ ٱُقْسِمُ بِالشَّفَقِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 17, 'وَاليْلِ وَمَا وَسَقَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 18, 'وَالْقَمَرۣ إِذَا "تَّسَقَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 19, 'لَتَرْكَبُــنَّ طَبَقاٗ عَــن طَبَقٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 20, 'فَمَا لَهُمْ لاَ يُومِنُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 21, 'وَإِذَا قُرۣىَٔ عَلَيْهِمُ ۴لْقُرْءَانُ لاَ يَسْجُدُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 22, 'بَلِ ۱لذِيــنَ كَفَرُواْ يُكَذِّبُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 23, 'وَاللَّهُ أَعْلَمُ بِمَا يُوعُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 24, 'فَبَشِّرْهُم بِعَذَابٖ اَلِيمٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (84, 25, 'اِلاَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ لَهُمُ; أَجْر٘ غَيْرُ مَمْنُونٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالسَّمَآءِ ذَاتِ ۱لْبُرُوجِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 2, 'وَالْيَوْمِ ۱لْمَوْعُودِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 3, 'وَشَاهِدٍ وَمَشْهُودٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 4, 'قُتِلَ أَصْحَـٰبُ ۴لاُخْدُودِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 5, '۱لنّۭارۣ ذَاتِ ۱لْوَقُودِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 6, 'إِذْ هُمْ عَلَيْهَا قُعُودٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 7, 'وَهُمْ عَلَــيٰ مَا يَفْعَلُونَ بِالْمُومِنِينَ شُهُودٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 8, 'وَمَا نَقَمُواْ مِنْهُمُ; إِلٓاَّ أَنْ يُّومِنُواْ بِاللَّهِ ۱لْعَزۣيزۣ ۱لْحَمِيدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 9, '۱ﻟ﮲ لَهُ„ مُلْــكُ ۴لسَّمَـٰوَ؛تِ وَالاَرْضِؐ وَاللَّهُ عَلَــيٰ كُلِّ شَيْءٍ شَهِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 10, 'اِنَّ ۰لذِيــنَ فَتَنُواْ ۴لْمُومِنِينَ وَالْمُومِنَـٰتِ ثُمَّ لَمْ يَتُوبُواْ فَلَهُمْ عَذَابُ جَهَنَّمَ وَلَهُمْ عَذَابُ ۴لْحَرۣيقِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 11, 'إِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ لَهُمْ جَنَّـٰتٌ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُؐ ذَ؛لِــكَ ۰لْفَوْزُ ۴لْكَبِيرُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 12, 'إِنَّ بَطْشَ رَبِّكَ لَشَدِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 13, 'اِنَّهُ„ هُوَ يُبْدِىُٔ وَيُعِيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 14, 'وَهُوَ ۰لْغَفُورُ ۴لْوَدُودُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 15, 'ذُو ۴لْعَرْشِؐ ۱ڤْمَجِيدُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 16, 'فَعَّالٌ لِّمَا يُرۣيدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 17, '621 هَلَ اَتۭيٰكَ حَدِيثُ ۴لْجُنُودِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 18, 'فِرْعَوْنَ وَثَمُودَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 19, 'بَـلِ ۱لذِيــنَ كَفَرُواْ فِى تَكْذِيبٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 20, 'وَاللَّهُ مِنْ وَّرَآئِهِم مُّحِيطٛؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 21, 'بَلْ هُوَ قُرْءَانٌ مَّجِيدٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (85, 22, 'فِى لَوْحٍ مَّحْفُوظٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالسَّمَآءِ وَالطَّارۣقِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 2, 'وَمَآ أَدْرۭيٰــكَ مَا ۰لطَّارۣقُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 3, '۴ڤنَّجْمُ ۴لثَّاقِــبُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 4, 'إِننن كُلُّ نَفْــسٍ لَّمَا عَلَيْهَا حَافِظٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 5, 'فَلْيَنظُرۣ ۱لِانسَـٰنُ مِمَّ خُلِقَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 6, 'خُلِقَ مِــن مَّآءٍ دَافِقٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 7, 'يَخْرُجُ مِنۢ بَيْنِ ۱لصُّلْبِ وَالتَّرَآئِبِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 8, 'إِنَّهُ„ عَلَيٰ رَجْعِهِ” لَقَادِرٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 9, 'يَوْمَ تُبْلَــي ۰لسَّرَآئِرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 10, 'فَمَا لَهُ„ مِن قُوَّةٍ وَلاَ نَاصِرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 11, 'وَالسَّمَآءِ ذَاتِ ۱لرَّجْعِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 12, 'وَالاَرْضِ ذَاتِ ۱لصَّدْعِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 13, 'إِنَّهُ„ لَقَوْلٌ فَصْلٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 14, 'وَمَا هُوَ بِالْهَزْلِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 15, 'إِنَّهُمْ يَكِيدُونَ كَيْداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 16, 'وَأَكِيدُ كَيْداًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (86, 17, 'فَمَهِّـلِ ۱لْكۭـٰفِـرۣيــنَ أَمْهِلْهُمْ رُوَيْداً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 1, '¤ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ سَبِّحِ ''سْمَ رَبِّــكَ ۰لاَعْلَي');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 2, '۰ﻟ﮲ خَلَقَ فَسَوّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 3, 'وَاﻟ﮲ قَدَّرَ فَهَدۭيييٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 4, 'وَاﻟـذِىٓ أَخْرَجَ ۰لْمَرْعۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 5, 'فَجَعَلَهُ„ غُثَآءٗ اَحْوۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 6, 'سَنُقْرۣيؖــكَ فَلاَ تَنسۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 7, 'إِلاَّ مَا شَآءَ ۰للَّهُؐ إِنَّهُ„ يَعْلَمُ ۴لْجَهْرَ وَمَا يَخْفۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 8, 'وَنُيَسِّرُكككَ لِلْيُسْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 9, 'فَذَكِّرۣ اِن نَّفَعَتِ ۱لذِّكْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 10, 'سَيَذَّكَّرُ مَــنْ يَّخْشۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 11, 'وَيَتَجَنَّبُهَا ۰لاَشْقَي');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 12, '۰ﻟ﮲ يَصْلَــي ۰لنَّارَ ۰لْكُبْرۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 13, 'ثُمَّ لاَ يَمُوتُ فِيهَا وَلاَ يَحْيۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 14, 'قَدَ اَفْلَحَ مَن تَزَكّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 15, 'وَذَكَرَ "سْمَ رَبِّهِ” فَصَلّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 16, 'بَلْ تُوثِرُونَ ۰لْحَيَوٰةَ ۰لدُّنْيۭا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 17, 'وَالاَخِرَةُ خَيْرٌ وَأَبْقۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 18, 'إِنَّ هَـٰذَا لَفِى ۱ڤصُّحُفِ ۱لاُولۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (87, 19, 'صُحُفِ إِبْرَ؛هِيمَ وَمُوسۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 1, '62 بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ هَلَ اَتۭيٰــكَ حَدِيثُ ۴لْغَـٰشِيَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 2, 'وُجُوهٌ يَوْمَئِذٖ خَـٰشِعَة٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 3, 'عَامِلَةٌ نَّاصِبَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 4, 'تَصْلَيٰ نَاراٗ حَامِيَةً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 5, 'تُسْقۭيٰ مِنْ عَيْــن۫ —انِيَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 6, 'لَّيْــسَ لَهُمْ طَعَام٘ اِلاَّ مِن ضَرۣيعٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 7, 'لاَّ يُسْمِنُ وَلاَ يُغْنِى مِن جُوعٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 8, 'وُجُوهٌ يَوْمَئِذٍ نَّاعِمَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 9, 'لِّسَعْيِهَا رَاضِيَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 10, 'فِى جَنَّةٖ عَالِيَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 11, 'لاَّ تُسْمَعُ فِيهَا چَغِيَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 12, 'فِيهَا عَيْــنٌ جَارۣيَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 13, 'فِيهَا سُرُرٌ مَّرْفُوعَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 14, 'وَأَكْوَابٌ مَّوْضُوعَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 15, 'وَنَمَارۣقُ مَصْفُوفَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 16, 'وَزَرَابِيُّ مَبْثُوثَة٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 17, 'اَفَلاَ يَنظُرُونَ إِلَي ۰لِابِــلۣ كَيْفَ خُلِقَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 18, 'وَإِلَــي ۰لسَّمَآءِ كَيْفَ رُفِعَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 19, 'وَإِلَي ۰لْجِبَالِ كَيْفَ نُصِبَتْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 20, 'وَإِلَــي ۰لاَرْضضضِ كَيْفَ سُطِحَتْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 21, 'فَذَكِّرۣ اِنَّمَآ أَنتَ مُذَكِّرٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 22, 'لَّسْتَ عَلَيْهِم بِمُصَيْطِرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 23, 'اِلاَّ مَن تَوَلّۭيٰ وَكَفَرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 24, 'فَيُعَذِّبُهُ ۴للَّهُ ۴لْعَذَابَ ۰لاَكْبَرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 25, 'إِنَّ إِلَيْنَآ إِيَابَهُمْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (88, 26, 'ثُمَّ إِنَّ عَلَيْنَا حِسَابَهُمْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَاڤْفَجْرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 2, 'وَلَيَالٖ عَشْرٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 3, 'وَالشَّفْعِ وَالْوَتْرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 4, 'وَاليْلِ إِذَا يَسْرۣ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 5, 'هَلْ فِى ذَ؛لِــكَ قَسَمٌ لِّذِى حِجْـرٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 6, 'اَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّــكَ بِعَادٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 7, 'اِرَمَ ذَاتِ ۱لْعِمَادِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 8, '۱لتِى لَمْ يُخْلَقْ مِثْلُهَا فِى ۱لْبِچَدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 9, 'وَثَمُودَ ۰لذِينَ جَابُواْ ۴ڤصَّخْرَ بِالْوَادِ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 10, 'وَفِرْعَوْنَ ذى ۱لاَوْتَادِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 11, '۱لذِيــنَ طَغَوْاْ فِى ۱لْبِچَدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 12, 'فَأَكْثَرُواْ فِيهَا ۰لْفَسَادَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 13, 'فَصَبَّ عَلَيْهِمْ رَبُّــكَ سَوْطَ عَذَابٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 14, 'اِنَّ رَبَّكَ لَبِالْمِرْصَادِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 15, 'فَأَمَّا ۰لِانسَـٰنُ إِذَا مَا "بْتَلۭيٰهُ رَبُّهُ„ فَأَكْرَمَهُ„ وَنَعَّمَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 16, 'فَيَقُولُ رَبِّــيَ أَكْرَمَنِؐ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 17, 'وَأَمَّآ إِذَا مَا "بْتَلۭيٰهُ فَقَدَرَ عَلَيْهِ رۣزْقَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 18, 'فَيَقُولُ رَبِّــيَ أَهَـٰنَــنۣ”');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 19, 'كَلؐاَّ بَــل لاَّ تُكْرۣمُونَ ۰لْيَتِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 20, 'وَلاَ تَحُضُّونَ عَلَــيٰ طَعَامِ ۱لْمِسْكِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 21, 'وَتَاكُلُونَ ۰لتُّرَاثَ أَكْلًا لَّمّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 22, 'وَتُحِبُّونَ ۰لْمَالَ حُبّاً جَمّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 23, 'كَلٓؐاَّ إِذَا دُكَّتِ 625 ۱لاَرْضضضُ دَكّاً دَكّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 24, 'وَجَآءَ رَبُّــكَ وَالْمَلَــكُ صَفّاً صَفّاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 25, 'وَجىِٓءَ يَوْمَئِذٙ بِجَهَنَّمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 26, 'يَوْمَئِذٍ يَتَذَكَّرُ ۴لِانسَـٰنُ وَأَنّۭــيٰ لَهُ ۴لذِّكْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 27, 'يَقُولُ يَـٰلَيْتَنِى قَدَّمْتُ لِحَيَاتِىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 28, 'فَيَوْمَئِذٍ لاَّ يُعَذِّبُ عَذَابَهُ; أَحَدٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 29, 'وَلاَ يُوثِقُ وَثَاقَهُ; أَحَدٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 30, 'يَـٰٓأَيَّتُهَا ۰لنَّفْــسُ ۴لْمُطْمَئِنَّةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 31, 'èرْجِعِىٓ إِلَيٰ رَبِّــكِ رَاضِيَةً مَّرْضِيَّةً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (89, 32, 'فَادْخُلِى فِى عِبَـٰدِى وَادْخُلِى جَنَّتِىؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 1, '© بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِؐ لآَ ٱُقْسِمُ بِهَـٰذَا ۰لْبَلَدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 2, 'وَأَنتَ حِلّٛ بِهَـٰذَا ۰لْبَلَدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 3, 'وَوَالِدٍ وَمَا وَلَدَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 4, 'لَقَدْ خَلَقْنَا ۰لِانسَـٰنَ فِى كَبَدٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 5, 'اَيَحْسِبُ أَن لَّنْ يَّقْدِرَ عَلَيْهِ أَحَدٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 6, 'يَقُولُ أَهْلَكْتُ مَالًا لُّبَداٗؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 7, 'اَيَحْسِبُ أَن لَّمْ يَرَهُ; أَحَد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 8, 'اَلَمْ نَجْعَل لَّهُ„ عَيْنَيْنِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 9, 'وَلِسَاناً وَشَفَتَيْنِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 10, 'وَهَدَيْنَـٰهُ ۴ڤنَّجْدَيْنِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 11, 'فَلاَ "قْتَحَمَ ۰لْعَقَبَةَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 12, 'وَمَآ أَدْرۭيٰــكَ مَا ۰لْعَقَبَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 13, 'فَــكُّ رَقَبَةٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 14, '626 اَوۣ اِطْعَامٌ فِى يَوْمٍ ذى مَسْغَبَةٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 15, 'يَتِيماً ذَا مَقْرَبَةٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 16, 'اَوْ مِسْكِيناً ذَا مَتْرَبَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 17, 'ثُمَّ كَانَ مِنَ ۰لذِينَ ءَامَنُواْ وَتَوَاصَوْاْ بِالصَّبْرۣ وَتَوَاصَوْاْ بِالْمَرْحَمَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 18, 'ٱُوْلَئِكَ أَصْحَـٰبُ ۴لْمَيْمَنَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 19, 'وَالذِيــنَ كَفَرُواْ بِـَٔايَـٰتِنَا هُمُ; أَصْحَـٰبُ ۴لْمَشْـَٔمَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (90, 20, 'عَلَيْهِمْ نَارٌ مُّوصَدَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالشَّمْسِ وَضُحَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 2, 'وَالْقَمَرۣ إِذَا تَلَيٰهَـا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 3, 'وَالنَّهۭارۣ إِذَا جَـلَّيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 4, 'وَالـيْـلِ إِذَا يَغْشَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 5, 'وَالسَّمَآءِ وَمَا بَنَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 6, 'وَالاَرْضِ وَمَا طَحَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 7, 'وَنَفْسٍ وَمَا سَوَّيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 8, 'فَأَلْهَمَهَا فُجُورَهَا وَتَقْوَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 9, 'قَدَ اَفْلَحَ مَن زَكَّيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 10, 'وَقَدْ خَابَ مَن دَسَّيٰهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 11, 'كَذَّبَتْ ثَمُودُ بِطَغْوَيٰهَآ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 12, 'إِذِ ''نۢبَعَثَ أَشْقَيٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 13, 'فَقَالَ لَهُمْ رَسُولُ ۴للَّهِ نَاقَةَ ۰للَّهِ وَسُقْيَاهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 14, 'فَكَذَّبُوهُ فَعَقَرُوهَا فَدَمْدَمَ عَلَيْهِمْ 627 رَبُّهُم بِذَنۢبِهِمْ فَسَوَّيٰهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (91, 15, 'فَلاَ يَخَافُ عُقْبَـٰهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَاليْلِ إِذَا يَغْشۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 2, 'وَالنَّهۭارۣ إِذَا تَجَلّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 3, 'وَمَا خَلَقَ ۰لذَّكَرَ وَالاُنثۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 4, 'إِنَّ سَعْيَكُمْ لَشَتّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 5, 'فَأَمَّا مَــنَ اَعْطۭيٰ وَاتَّقۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 6, 'وَصَدَّقَ بِالْحُسْنۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 7, 'فَسَنُيَسِّرُهُ„ لِلْيُسْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 8, 'وَأَمَّا مَنۢ بَخِلَ وَاسْتَغْنۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 9, 'وَكَذَّبَ بِالْحُسْنۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 10, 'فَسَنُيَسِّرُهُ„ لِلْعُسْرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 11, 'وَمَا يُغْنِى عَنْهُ مَالُهُ; إِذَا تَرَدّۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 12, 'إِنَّ عَلَيْنَا لَلْهُدۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 13, 'وَإِنَّ لَنَا لَلاَخِرَةَ وَالاُولۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 14, 'فَأَنذَرْتُكُمْ نَاراً تَلَظّۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 15, 'لاَ يَصْلَيٰهَآ إِلاَّ ۰لاَشْقَي');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 16, '۰ﻟ﮲ كَذَّبَ وَتَوَلّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 17, 'وَسَيُجَنَّبُهَا ۰لاَتْقَي');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 18, '۰ﻟ﮲ يُوتِى مَالَهُ„ يَتَزَكّۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 19, 'وَمَا لَأِحَدٖ عِندَهُ„ مِن نِّعْمَةٍ تُجْزۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 20, 'إِلاَّ "بْتِغَآءَ وَجْهِ رَبِّهِ ۱لاَعْلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (92, 21, 'وَلَسَوْفَ يَرْضۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَاڤضُّحۭـيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 2, 'وَاليْلِ إِذَا سَجۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 3, 'مَا وَدَّعَــكَ رَبُّــكَ وَمَا قَلۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 4, 'وَلَلاَخِرَةُ خَيْرٌ لَّكَ مِــنَ ۰لاُولۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 5, 'وَلَسَوْفَ يُعْطِيــكَ رَبُّــكَ فَتَرْضۭـيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 6, 'أَلَمْ يَجِدْكككَ يَتِيماً فَـَٔاوۭيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 7, 'وَوَجَدَكككَ ضَآلًاّ فَهَدۭيييٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 8, 'وَوَجَدَكككَ عَآئِلًا فَأَغْنۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 9, 'فَأَمَّا ۰لْيَتِيمَ فَلاَ تَقْهَرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 10, 'وَأَمَّا ۰لسَّآئِلَ فَلاَ تَنْهَرْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (93, 11, 'وَأَمَّا بِنِعْمَةِ رَبِّــكَ فَحَدِّثَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 1, '¥ بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اَلَمْ نَشْرَحْ لَــكَ صَدْرَكَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 2, 'وَوَضَعْنَا عَنكَ وۣزْرَكَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 3, '۰ﻟـذِىٓ أَنقَضَ ظَهْرَكَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 4, 'وَرَفَعْنَا لَكَ ذِكْرَكككَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 5, 'فَإِنَّ مَعَ ۰لْعُسْرۣ يُسْراٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 6, 'اِنَّ مَعَ ۰لْعُسْرۣ يُسْراًؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 7, 'فَإِذَا فَرَغْتَ فَانصَبْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (94, 8, 'وَإِلَيٰ رَبِّكَ فَارْغَــــبْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالتِّينِ وَالزَّيْتُونِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 2, 'وَطُورۣ سِينِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 3, 'وَهَـٰذَا ۰لْبَلَدِ ۱لاَمِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 4, 'لَقَدْ خَلَقْنَا ۰لِانسَـٰنَ فِىٓ أَحْسَــنۣ تَقْوۣيمٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 5, 'ثُمَّ رَدَدْنَـٰهُ أَسْفَلَ سَـٰفِلِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 6, 'إِلاَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ فَلَهُمُ; أَجْر٘ غَيْرُ مَمْنُونٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 7, 'فَمَا يُكَذِّبُكَ بَعْدُ بِالدِّينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (95, 8, 'أَلَيْــسَ ۰للَّهُ بِأَحْكَمِ ۱لْحَـٰكِمِينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ "قْرَأْ بِاسْمِ رَبِّــكَ ۰ﻟ﮲ خَلَقَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 2, 'خَلَقَ ۰لِانسَـٰنَ مِنْ عَلَقٖؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 3, '''قْرَأْ وَرَبُّــكَ ۰لاَكْرَمُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 4, '۴ﻟ﮲ عَلَّمَ بِالْقَلَمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 5, 'عَلَّمَ ۰لِانسَـٰــنَ مَا لَمْ يَعْلَمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 6, 'كَلٓاَّ إِنَّ ۰لِانسَـٰنَ لَيَطْغۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 7, 'أَن رّۭءۭاهُ èسْتَغْنۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 8, 'إِنَّ إِلَيٰ رَبِّــكَ ۰لرُّجْعۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 9, 'أَرَ×يْتَ ۰ﻟ﮲ يَنْهۭـيٰ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 10, 'عَبْداٗ اِذَا صَلّۭيٰٓؐ 60');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 11, 'أَرَ×يْتَ إِن كَانَ عَلَــي ۰لْهُدۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 12, 'أَوَ اَمَرَ بِالتَّقْوۭيٰٓؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 13, 'أَرَ×يْتَ إِن كَذَّبَ وَتَوَلّۭيٰٓ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 14, 'أَلَمْ يَعْلَم بِأَنننَّ ۰للَّهَ يَرۭيٰؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 15, 'كَلاَّ لَـئِــن لَّمْ يَنتَهِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 16, 'لَنَسْفَعاَۢ بِالنَّاصِيَةِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 17, 'نَاصِيَةٍ كَـٰذِبَةٖ خَاطِيؕةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 18, 'فَلْيَدْعُ نَادِيَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 19, 'سَنَدْعُ ۴لزَّبَانِيَةَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (96, 20, 'كَلاَّ لاَ تُطِعْهُ وَاسْجُدْ وَاقْتَرۣبِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (97, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اِنَّـآ أَنزَلْنَـٰهُ فِى لَيْلَةِ ۱لْقَدْرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (97, 2, 'وَمَآ أَدْرۭيٰــكَ مَا لَيْلَةُ ۴لْقَدْرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (97, 3, 'لَيْلَةُ ۴لْقَدْرۣ خَيْرٌ مِّنَ اَلْفِ شَهْرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (97, 4, 'تَنَزَّلُ ۴لْمَلَئِكَةُ وَالرُّوحُ فِيهَا بِإِذْنِ رَبِّهِم مِّــن كُلِّ أَمْرٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (97, 5, 'سَچَم٘ هِيَ حَتَّــيٰ مَطْلَعِ ۱ڤْفَجْرۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ لَمْ يَكُـنِ ۱لذِيــنَ كَفَرُواْ مِنَ 61 اَهْـلِ ۱لْكِتَـٰبِ وَالْمُشْرۣكِيــنَ مُنفَكِّيــنَ حَتَّيٰ تَاتِيَهُمُ ۴لْبَيِّنَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 2, 'رَسُولٌ مِّــنَ ۰للَّهِ يَتْلُواْ صُحُفاً مُّطَهَّرَةً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 3, 'فِيهَا كُتُبٌ قَيِّمَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 4, 'وَمَا تَفَرَّقَ ۰لذِينَ ٱُوتُواْ ۴لْكِتَـٰبَ إِلاَّ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ۴لْبَيِّنَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 5, 'وَمَآ ٱُمِرُوٓاْ إِلاَّ لِيَعْبُدُواْ ۴للَّهَ مُخْلِصِيــنَ لَهُ ۴لدِّيــنَ حُنَفَآءَ وَيُقِيمُواْ ۴لصَّلَوٰةَ وَيُوتُواْ ۴لزَّكَوٰةَؐ وَذَ؛لِــكَ دِيــنُ ۴لْقَيِّمَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 6, 'إِنَّ ۰لذِيــنَ كَفَرُواْ مِــنَ اَهْلِ ۱لْكِتَـٰبِ وَالْمُشْرۣكِينَ فِى نۭارۣ جَهَنَّمَ خَـٰلِدِينَ فِيهَآؐ ٱُوْلَئِــكَ هُمْ شَرُّ ۴لْبَرۣيٓــَٔةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 7, 'إِنَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ ٱُوْلَئِكَ هُمْ خَيْرُ ۴لْبَرۣيٓــَٔةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (98, 8, 'جَزَآؤُهُمْ عِندَ رَبِّهِمْ جَنَّـٰتُ عَدْنٍ تَجْرۣى مِــن تَحْتِهَا ۰لاَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَداًؐ رَّضِــيَ ۰للَّهُ عَنْهُمْ وَرَضُواْ عَنْهُؐ ذَ؛لِكَ لِمَنْ خَشِيَ رَبَّهُ;');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 1, '62 بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا زُلْزۣلَتِ ۱لاَرْضُ زۣلْزَالَهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 2, 'وَأَخْرَجَتِ ۱لاَرْضضضُ أَثْقَالَهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 3, 'وَقَالَ ۰لِانسَـٰنُ مَا لَهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 4, 'يَوْمَئِذٍ تُحَدِّثُ أَخْبَارَهَا');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 5, 'بِأَنَّ رَبَّكَ أَوْحۭــيٰ لَهَاؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 6, 'يَوْمَئِذٍ يَصْدُرُ ۴لنَّاسسسُ أَشْتَاتاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 7, 'لِّيُرَوَاْ اَعْمَـٰلَهُمْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 8, 'فَمَنْ يَّعْمَـلْ مِثْقَالَ ذَرَّةٖ خَيْراً يَرَهُؐ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (99, 9, 'وَمَـنْ يَّعْمَـلْ مِثْقَالَ ذَرَّةٍ شَرّاً يَرَهُ,');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالْعَـٰدِيَـٰتِ ضَبْحاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 2, 'فَالْمُورۣيَـٰتِ قَدْحاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 3, 'فَالْمُغِيرَ؛تِ صُبْحاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 4, 'فَأَثَرْنَ بِهِ” نَقْعاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 5, 'فَوَسَطْنَ بِهِ” جَمْعاٗ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 6, 'اِنَّ ۰لِانسَـٰنَ لِرَبِّهِ” لَكَنُودٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 7, 'وَإِنَّهُ„ عَلَيٰ ذَ؛لِــكَ لَشَهِيدٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 8, 'وَإِنَّهُ„ لِحُبِّ ۱لْخَيْرۣ لَشَدِيد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 9, '© اَفَلاَ يَعْلَمُ إِذَا بُعْثِرَ مَا فِى ۱لْقُبُورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 10, 'وَحُصِّلَ مَا فِى ۱لصُّدُورۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (100, 11, 'إِنَّ رَبَّهُم بِهِمْ يَوْمَئِذٍ لَّخَبِير٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ ۱لْقَارۣعَةُ مَا ۰لْقَارۣعَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 2, 'وَمَآ أَدْرۭيٰكَ مَا ۰لْقَارۣعَةُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 3, 'يَوْمَ يَكُونُ ۴لنَّاسُ كَالْفَرَاشِ ۱لْمَبْثُوثِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 4, 'وَتَكُونُ ۴لْجِبَالُ كَالْعِهْنِ ۱لْمَنفُوشِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 5, 'فَأَمَّا مَــن ثَقُلَتْ مَوَ؛زۣينُهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 6, 'فَهُوَ فِى عِيشَةٍ رَّاضِيَةٍؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 7, 'وَأَمَّا مَــنْ خَفَّتْ مَوَ؛زۣينُهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 8, 'فَٱُمُّهُ„ هَاوۣيَةٌؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 9, 'وَمَآ أَدْرۭيٰكَ مَا هِيَهْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (101, 10, 'نَار٘ حَامِيَة٘');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اَلْهۭيٰكُمُ ۴لتَّكَاثُرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 2, 'حَتَّيٰ زُرْتُمُ ۴لْمَقَابِرَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 3, 'كَلاَّ سَوْفَ تَعْلَمُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 4, 'ثُمَّ 64 كَلاَّ سَوْفَ تَعْلَمُونَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 5, 'كَلاَّ لَوْ تَعْلَمُونَ عِلْمَ ۰لْيَقِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 6, 'لَتَرَوُنَّ ۰لْجَحِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 7, 'ثُمَّ لَتَرَوُنَّهَا عَيْنَ ۰لْيَقِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (102, 8, 'ثُمَّ لَتُسْـَٔلُنَّ يَوْمَئِذٖ عَنِ ۱لنَّعِيمِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (103, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ وَالْعَصْرۣ إِنَّ ۰لِانسَـٰنَ لَفِى خُسْر۫');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (103, 2, 'اِلاَّ ۰لذِيــنَ ءَامَنُواْ وَعَمِلُواْ ۴ڤصَّـٰڤِحَـٰتِ وَتَوَاصَوْاْ بِالْحَقِّ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (103, 3, 'وَتَوَاصَوْاْ بِالصَّبْرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِؐ وَيْــلٌ لِّكُــلّۣ هُمَزَةٍ لُّمَزَةٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 2, '۱ﻟ﮲ جَمَعَ مَالًا وَعَدَّدَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 3, 'يَحْسِبُ أَنَّ مَالَهُ; أَخْلَدَهُ„');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 4, 'كَلؐاَّ لَيُنۢبَذَنَّ فِى ۱لْحُطَمَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 5, 'وَمَآ أَدْرۭيٰــكَ مَا ۰لْحُطَمَةُؐ 65');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 6, 'نَارُ ۴للَّهِ ۱لْمُوقَدَةُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 7, '۴لتِى تَطَّلِعُ عَلَــي ۰لاَفْـِٕدَةِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 8, 'إِنَّهَا عَلَيْهِم مُّوصَدَةٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (104, 9, 'فِى عَمَدٍ مُّمَدَّدَةٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (105, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّكَ بِأَصْحَـٰبِ ۱لْفِيــلۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (105, 2, 'أَلَمْ يَجْعَــلْ كَيْدَهُمْ فِى تَضْلِيلٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (105, 3, 'وَأَرْسَــلَ عَلَيْهِمْ طَيْراٗ اَبَابِيـلَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (105, 4, 'تَرْمِيهِم بِحِجَارَةٍ مِّــن سِجِّيــلٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (105, 5, 'فَجَعَلَهُمْ كَعَصْفٍ مَّاكُولٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (106, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ لِإِّيچَفِ قُرَيْشٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (106, 2, 'اِﯦچَفِهِمْ رۣحْلَةَ ۰لشِّتَآءِ وَالصَّيْفِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (106, 3, 'فَلْيَعْبُدُواْ رَبَّ هَـٰذَا ۰لْبَيْتِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (106, 4, '۱ﻟـذِىٓ أَطْعَمَهُم مِّن جُوعٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (106, 5, 'وَءَامَنَهُم مِّــنْ خَوْفٖ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (107, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ اَرَ×يْتَ ۰ﻟ﮲ يُكَذِّبُ بِالدِّيــنۣ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (107, 2, 'فَذَ؛لِكَ ۰ﻟ﮲ يَدُعُّ ۴لْيَتِيمَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (107, 3, 'وَلاَ يَحُــضُّ عَلَــيٰ طَعَامِ ۱لْمِسْكِينِؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (107, 4, 'فَوَيْلٌ لِّلْمُصَلِّينَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (107, 5, '۰لذِيــنَ هُمْ عَــن صَلاَتِهِمْ سَاهُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (107, 6, '۰لذِينَ هُمْ يُرَآءُونَ وَيَمْنَعُونَ ۰لْمَاعُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (108, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِنَّآ أَعْطَيْنَـٰــكَ ۰لْكَوْثَرَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (108, 2, 'فَصَلِّ لِرَبِّكَ وَانْحَـرۣؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (108, 3, 'اِنَّ شَانِيؕكَ هُوَ ۰لاَبْتَرُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (109, 1, '67 بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قُـلْ يَـٰٓأَيُّهَا ۰لْكَـٰفِرُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (109, 2, 'لآَ أَعْبُدُ مَا تَعْبُدُونَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (109, 3, 'وَلآَ أَنتُمْ عَـٰبِدُونَ مَآ أَعْبُدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (109, 4, 'وَلآَ أَنَا عَابِدٌ مَّا عَبَدتُّمْ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (109, 5, 'وَلآَ أَنتُمْ عَـٰبِدُونَ مَآ أَعْبُدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (109, 6, 'لَكُمْ دِينُكُمْ وَلِيَ دِينِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (110, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ إِذَا جَآءَ نَصْرُ ۴للَّهِ وَاڤْفَتْحُ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (110, 2, 'وَرَأَيْتَ ۰لنَّاسَ يَدْخُلُونَ فِى دِيـنِ ۱للَّهِ أَفْوَاجاً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (110, 3, 'فَسَبِّحْ بِحَمْدِ رَبِّكَ وَاسْتَغْفِرْهُؐ إِنَّهُ„ كَانَ تَوَّاباً');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (111, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ تَبَّتْ يَدَآ أَبِى لَهَبٍ وَتَبَّؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (111, 2, 'مَآ أَغْنۭيٰ عَنْهُ مَالُهُ„ وَمَا كَسَبَؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (111, 3, 'سَيَصْلَــيٰ نَاراً ذَاتَ لَهَبٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (111, 4, 'وَامْرَأَتُهُؐ, حَمَّالَةُ ۴لْحَطَبِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (111, 5, 'فِى جِيدِهَا حَبْلٌ مِّن مَّسَدٍ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (112, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قُلْ هُوَ ۰للَّهُ أَحَد٘ؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (112, 2, '۱للَّهُ ۴لصَّمَدُؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (112, 3, 'لَمْ يَلِدْ وَلَمْ يُولَدْؐ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (112, 4, 'وَلَمْ يَكُــن لَّهُ„ كُفُؤاٗ اَحَدٌ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (113, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قُــلَ اَعُوذُ بِرَبِّ ۱لْفَلَقِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (113, 2, 'مِن شَرّۣ مَا خَلَقَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (113, 3, 'وَمِن شَرّۣ غَاسِقٖ اِذَا وَقَبَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (113, 4, 'وَمِن شَرّۣ ۱لنَّفَّـٰثَـٰتِ فِى ۱لْعُقَدِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (113, 5, 'وَمِن شَرّۣ حَاسِدٖ اِذَا حَسَدَ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (114, 1, 'بِسْمِ ۱للَّهِ ۱لرَّحْمَـٰنِ ۱لرَّحِيمِ قُــلَ اَعُوذُ بِرَبِّ ۱لنَّاسسسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (114, 2, 'مَلِــكِ ۱لنَّاسسسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (114, 3, 'إِچَهِ ۱لنَّاسسسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (114, 4, 'مِن شَرّۣ ۱لْوَسْوَاسسسِ ۱لْخَنَّاسسسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (114, 5, '۱ﻟ﮲ يُوَسْوۣسُ فِى صُدُورۣ ۱لنَّاسسسِ');
INSERT INTO ayahs (surah_id, ayah_number, text_warsh) VALUES (114, 6, 'مِنَ ۰لْجِنَّةِ وَالنَّاسسسِؐ');
