CREATE TABLE IF NOT EXISTS surahs (
    id INTEGER PRIMARY KEY,
    name_arabic TEXT NOT NULL,
    verses_count INTEGER NOT NULL
);

CREATE TABLE IF NOT EXISTS ayahs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    surah_id INTEGER NOT NULL,
    ayah_number INTEGER NOT NULL,
    text_warsh TEXT NOT NULL,
    FOREIGN KEY (surah_id) REFERENCES surahs (id),
    UNIQUE(surah_id, ayah_number)
);

-- This index is crucial for mobile performance
CREATE INDEX IF NOT EXISTS idx_surah_ayah ON ayahs(surah_id, ayah_number);

CREATE TABLE IF NOT EXISTS quran_divisions (
    hizb_number INTEGER NOT NULL,
    thumun_number INTEGER NOT NULL, -- 1 to 8 for each Hizb
    start_surah_id INTEGER NOT NULL,
    start_ayah_number INTEGER NOT NULL,
    end_surah_id INTEGER NOT NULL,
    end_ayah_number INTEGER NOT NULL,
    PRIMARY KEY (hizb_number, thumun_number),
    FOREIGN KEY (start_surah_id) REFERENCES surahs (id),
    FOREIGN KEY (end_surah_id) REFERENCES surahs (id)
);


